INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(7, 11, '3 DAYS MAKASAR TOUR', 'SOUTH SULAWESI', '3d2n-makasar-tour', '<h3 style=\"text-align:justify;\"><strong>Makassar Gateway: Pelarian Singkat ke Labirin Karst &amp; Sejarah Maritim&nbsp;</strong></h3><p style=\"text-align:justify;\">Ingin liburan singkat namun berkesan? Paket <strong>Makassar Gateway</strong> ini adalah pilihan sempurna bagi Anda yang ingin menikmati perpaduan harmonis antara kekayaan sejarah dan keajaiban alam prasejarah Sulawesi Selatan dalam waktu yang efisien. Dari pelabuhan kuno hingga pegunungan kapur yang megah, setiap sudut Makassar siap memukau mata Anda.</p><p style=\"text-align:justify;\">Perjalanan ini akan membawa Anda menelusuri jejak pelaut ulung di <strong>Pelabuhan Paotere</strong> dan kemegahan kolonial di <strong>Fort Rotterdam</strong>, sebelum ditutup dengan momen matahari terbenam yang magis di <strong>Pantai Losari</strong>. Sorotan utama menanti Anda di <strong>Rammang-Rammang</strong>, di mana Anda akan menyusuri sungai dengan perahu kayu tradisional menuju \"hutan batu\" karst terbesar kedua di dunia. Temukan rahasia manusia purba di gua-gua prasejarah dan nikmati ketenangan di perkampungan yang dikelilingi tebing raksasa.</p>', '<h3 style=\"text-align:justify;\"><strong>Makassar Gateway: A Short Escape to Karst Labyrinths &amp; Maritime History</strong></h3><p style=\"text-align:justify;\">Looking for a short yet memorable getaway? This <strong>Makassar Gateway</strong> package is the perfect choice for those who want to enjoy a harmonious blend of rich history and the prehistoric natural wonders of South Sulawesi in an efficient timeframe. From ancient harbors to magnificent limestone mountains, every corner of Makassar is ready to amaze you.</p><p style=\"text-align:justify;\">This journey will take you through the footsteps of master seafarers at <strong>Paotere Harbour</strong> and the colonial grandeur of <strong>Fort Rotterdam</strong>, before ending with a magical sunset at <strong>Losari Beach</strong>. The main highlight awaits at <strong>Rammang-Rammang</strong>, where you will cruise the river by traditional wooden boat to reach the world\'s second-largest karst \"stone forest.\" Discover the secrets of ancient humans in prehistoric caves and enjoy the serenity of a village surrounded by giant cliffs.</p>', '<h3 style=\"text-align:justify;\"><strong>마카사르 게이트웨이: 카르스트 미로와 해양 역사로의 짧은 여정</strong></h3><p style=\"text-align:justify;\">짧지만 인상적인 휴가를 원하시나요? 이 <strong>마카사르 게이트웨이</strong> 패키지는 남부 술라웨시의 풍부한 역사와 선사 시대의 자연 경관을 효율적인 시간 내에 조화롭게 즐기고 싶은 분들에게 완벽한 선택입니다. 고대 항구부터 웅장한 석회암 산에 이르기까지, 마카사르의 모든 구석구석이 여러분을 놀라게 할 준비가 되어 있습니다.</p><p style=\"text-align:justify;\">이번 여정은 <strong>파오테레 항구</strong>에서 노련한 항해사들의 발자취를 따라가고 <strong>로테르담 요새</strong>의 식민지 시대 웅장함을 감상한 뒤, <strong>로사리 해변</strong>의 마법 같은 일몰로 마무리됩니다. 여행의 하이라이트는 <strong>람망람망</strong>에서 기다리고 있습니다. 전통 목조 배를 타고 강을 거슬러 올라가 세계에서 두 번째로 큰 카르스트 \"바위 숲\"에 도착합니다. 선사 시대 동굴에서 고대 인류의 비밀을 발견하고 거대한 절벽으로 둘러싸인 마을에서 평온함을 느껴보세요.</p>', '<h3 style=\"text-align:justify;\"><strong>望加锡门户之旅：喀斯特迷宫与海洋历史的短暂逃离&nbsp;</strong></h3><p style=\"text-align:justify;\">想要一次简短而难忘的旅行吗？这个 <strong>“望加锡门户”</strong> 行程是您的完美选择，适合那些希望在有限时间内尽情享受南苏拉威西丰富历史与史前自然奇观和谐融合的游客。从古老的港口到壮丽的石灰岩山脉，望加锡的每一个角落都准备好让您惊叹不已。</p><p style=\"text-align:justify;\">这段旅程将带您追寻 <strong>波特雷港 (Paotere Harbour)</strong> 航海大师的足迹，感受 <strong>鹿特丹城堡 (Fort Rotterdam)</strong> 的殖民时期宏伟建筑，最后在 <strong>洛萨里海滩 (Losari Beach)</strong> 的魔幻日落中结束一天的行程。行程的重头戏在 <strong>拉曼拉曼 (Rammang-Rammang)</strong> 等待着您，您将乘坐传统木船穿行于河上，抵达世界第二大喀斯特“石林”。在史前洞穴中探索远古人类的秘密，在巨石环绕的村庄中享受那份宁静。</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ea63d0c41bf51089b06f42b7f5105ded4\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e4154924dc0a90bfaf9a0282408e63563\">Hotel in Makassar</li><li data-list-item-id=\"e2ac9d3f248be01f8b9245470e2b53598\">Hotel in Toraja</li><li data-list-item-id=\"ef65c469cab33d6ac806d2ac3f6c45aef\">Meals (B=breakfast) only</li><li data-list-item-id=\"e8e035bdc6d03519455d8aaaf21775617\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"e1bff8b6cc0aed1818c39522aec6e58ff\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"eb0491f1724f7acbac55fb2e6f93855d4\">Tours and activities programmed</li><li data-list-item-id=\"ecf52efa76fd8c628dcb67bd6de64306d\">Local boat (wooden) on Rammang-Rammang program</li><li data-list-item-id=\"ede12dfb7f432f8024d17f376762477a3\">Coffee break 1x on Rammang-Rammang program</li><li data-list-item-id=\"eff93840624d2528a27c8967c92e551c6\">Entrance fees and donations</li><li data-list-item-id=\"e9c85d0e20692517c980702122bed3608\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"e8fea3567523d818b91c281c22081588a\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(not valid during New Year’s Eve)</p></li><li data-list-item-id=\"ecf1541fa007538c8359b18613ae2a52b\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices change from the government.</p></li><li data-list-item-id=\"eb4ab0113c3dbbf983a01b3733a74ba2e\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"History & Heritage\",\"Culinary & Shopping\"]', NULL, 0, NULL, '2026-04-24 03:24:24', '2026-06-02 07:30:45'),
(8, 11, '3 DAYS TORAJA TOUR', 'SOUTH SULAWESI', '3d2n-toraja-tour', '<h3 style=\"text-align:justify;\"><strong>Toraja Express: Penjelajahan Budaya Ikonik di Negeri Para Leluhur&nbsp;</strong></h3><p style=\"text-align:justify;\">Ingin merasakan magisnya Tana Toraja namun hanya memiliki waktu singkat di akhir pekan? Paket <strong>Toraja Express</strong> ini dirancang khusus untuk membawa Anda meresapi inti dari kekayaan budaya Sulawesi Selatan tanpa membuang waktu. Dalam perjalanan ini, Anda akan diajak melintasi panorama pegunungan yang memukau, melewati <strong>Gunung \"Erotis\" Buttu Kabobong</strong>, hingga memasuki gerbang dunia mistis yang penuh pesona.</p><p style=\"text-align:justify;\">Hanya dalam 3 hari, Anda akan mengunjungi mahakarya budaya paling ikonik di Toraja: melihat deretan patung <strong>Tau-tau</strong> yang menatap dari tebing batu <strong>Lemo</strong>, menyentuh keajaiban makam bayi di pohon <strong>Kambira</strong>, hingga menembus kegelapan gua alam <strong>Londa</strong> yang legendaris. Perjalanan Anda akan ditutup dengan kunjungan ke <strong>Ke\'te Kesu</strong>, situs Warisan Dunia UNESCO yang memamerkan kemegahan rumah adat <strong>Tongkonan</strong> dan ukiran kayu yang sarat makna sejarah.</p>', '<h3 style=\"text-align:justify;\"><strong>Toraja Express: Iconic Cultural Exploration in the Land of the Ancestors</strong></h3><p style=\"text-align:justify;\">Want to experience the magic of Tana Toraja but only have a short time over the weekend? This <strong>Toraja Express</strong> package is specifically designed to bring you to the heart of South Sulawesi’s rich culture without wasting a moment. On this journey, you will be invited to cross stunning mountain panoramas, passing the unique <strong>\"Erotic\" Mountain Buttu Kabobong</strong>, and entering the gates of a mystical and charming world.</p><p style=\"text-align:justify;\">In just 3 days, you will visit Toraja\'s most iconic cultural masterpieces: see the rows of <strong>Tau-tau</strong> statues gazing from the <strong>Lemo</strong> stone cliffs, touch the miracle of the baby grave tree in <strong>Kambira</strong>, and venture into the depths of the legendary <strong>Londa</strong> natural caves. Your journey will conclude with a visit to <strong>Ke\'te Kesu</strong>, a UNESCO World Heritage site showcasing the grandeur of <strong>Tongkonan</strong> traditional houses and wood carvings rich in historical meaning.</p>', '<h3 style=\"text-align:justify;\"><strong>토라자 익스프레스: 선조들의 땅에서 즐기는 상징적 문화 탐험&nbsp;</strong></h3><p style=\"text-align:justify;\">주말 동안 짧은 시간 안에 타나 토라자의 마법을 경험하고 싶으신가요? 이 <strong>토라자 익스프레스</strong> 패키지는 한순간도 허비하지 않고 남부 술라웨시의 풍요로운 문화의 핵심으로 여러분을 안내하기 위해 특별히 설계되었습니다. 이번 여정에서 여러분은 환상적인 산악 파노라마를 감상하고, 독특한 <strong>\"에로틱한\" 산 부투 카보봉</strong>을 지나 매혹적이고 신비로운 세계의 관문으로 들어서게 됩니다.</p><p style=\"text-align:justify;\">단 3일 만에 여러분은 토라자의장 상징적인 문화적 걸작들을 방문하게 됩니다. <strong>레모</strong> 절벽에서 응시하는 <strong>타우타우(Tau-tau)</strong> 조각상들을 보고, <strong>캄비라</strong> 나무에 있는 아기 무덤의 신비로움을 접하며, 전설적인 <strong>론다</strong> 천연 동굴의 깊은 곳을 탐험합니다. 여정의 마무리는 유네스코 세계문화유산인 <strong>케테 케수</strong> 방문으로, 이곳에서 장엄한 전통 가옥 <strong>통코난</strong>과 역사적 의미가 담긴 목조각의 진수를 확인하실 수 있습니다.</p>', '<h3 style=\"text-align:justify;\"><strong>托拉雅快线：祖先故土的标志性文化探索&nbsp;</strong></h3><p style=\"text-align:justify;\">想要在周末的短暂时间内感受塔纳托拉雅的魔力吗？这个 <strong>“托拉雅快线”</strong> 行程专为带您领略南苏拉威西丰富文化的核心而设计，绝不浪费每一分一秒。在这段旅程中，您将受邀穿越壮丽的山脉全景，经过独特的 <strong>“色情山”布图卡博博 (Buttu Kabobong)</strong>，步入一个神秘而充满魅力的世界大门。</p><p style=\"text-align:justify;\">在短短 3 天内，您将游览托拉雅最具标志性的文化杰作：在 <strong>莱莫 (Lemo)</strong> 石壁旁观察凝视着的 <strong>木偶雕像 (Tau-tau)</strong>，亲触 <strong>坎比拉 (Kambira)</strong> 树葬的奇迹，并深入探索传奇的 <strong>隆达 (Londa)</strong> 天然洞穴。行程将以参观 <strong>克特克斯 (Ke\'te Kesu)</strong> 完美收官，这个联合国教科文组织世界遗产地展示了宏伟的 <strong>船型屋 (Tongkonan)</strong> 以及蕴含深厚历史意义的精美木雕。</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e8742d2993e5e7ab144a06aa277b50889\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e7d1c256eac7f9c5e8b4da3218fe3b3b3\">Hotel in Makassar &amp; Toraja</li><li data-list-item-id=\"e80f71e3d055db21c9e369d07fe169144\">Meals (B=breakfast) only</li><li data-list-item-id=\"e24ca41da440d47a76b1d2ed1ea149c85\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"eb0111c5794df7813c17d9104b604fb0a\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"e035c769eb8640f6da6130aca78875145\">Tours and activities programmed</li><li data-list-item-id=\"ea10136728aa02a1e5de0481c27b34c9b\">Entrance fees and donations</li><li data-list-item-id=\"eb74d6b2e683723657332495c4767baaf\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"eee6adecab52284ac886083cb7a1c33f0\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(not valid during New Year’s Eve)</p></li><li data-list-item-id=\"e3726dc1de7eea5f64301bbc4cdba52f6\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices change from the government.</p></li><li data-list-item-id=\"e715c26e3b6049f01c5cd37646f3c6ceb\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"Culture\"]', NULL, 0, NULL, '2026-04-24 04:56:30', '2026-06-02 03:34:37'),
(9, 11, '4 DAYS MAKASAR TOUR', 'SOUTH SULAWESI', '4d3n-makasar-tour', '<h3 style=\"text-align:justify;\"><strong>Pesona Makassar &amp; Labirin Karst Purba: Penjelajahan Budaya &amp; Alam&nbsp;</strong></h3><p style=\"text-align:justify;\">Jelajahi sisi eksotis Sulawesi Selatan dalam paket singkat yang penuh kesan. Perjalanan ini akan membawa Anda menelusuri sejarah kejayaan pelaut Bugis-Makassar di <strong>Pelabuhan Paotere</strong> dan kemegahan <strong>Benteng Rotterdam</strong> peninggalan era kolonial. Nikmati momen santai di <strong>Pantai Losari</strong> sambil menyaksikan salah satu pemandangan matahari terbenam paling ikonik di Indonesia.</p><p style=\"text-align:justify;\">Sorotan utama perjalanan ini adalah petualangan menuju <strong>Rammang-Rammang</strong>, kompleks pegunungan karst terbesar kedua di dunia. Anda akan menyusuri <strong>Sungai Pute</strong> dengan perahu kayu tradisional, menembus labirin tebing kapur yang megah, hingga menemukan kampung tersembunyi dan gua prasejarah yang menyimpan lukisan purba ribuan tahun. Tak ketinggalan, Anda akan diajak mengenal lebih dalam sejarah Kerajaan Gowa di <strong>Museum Balla Lompoa</strong> serta berburu kerajinan tangan khas di <strong>Jalan Somba Opu</strong>.</p>', '<h3 style=\"text-align:justify;\"><strong>Charm of Makassar &amp; Ancient Karst Labyrinth: Cultural &amp; Nature Exploration&nbsp;</strong></h3><p style=\"text-align:justify;\">Explore the exotic side of South Sulawesi in a concise yet impressive package. This journey will take you through the historic glory of the Bugis-Makassar seafarers at <strong>Paotere Harbour</strong> and the colonial-era grandeur of <strong>Fort Rotterdam</strong>. Enjoy a relaxing moment at <strong>Losari Beach</strong> while witnessing one of Indonesia\'s most iconic sunset views.</p><p style=\"text-align:justify;\">The highlight of this trip is the adventure to <strong>Rammang-Rammang</strong>, the world\'s second-largest karst mountain complex. You will cruise the <strong>Pute River</strong> by traditional wooden boat, passing through a labyrinth of magnificent limestone cliffs to find hidden villages and prehistoric caves holding ancient paintings from thousands of years ago. Additionally, you will delve deeper into the history of the Gowa Kingdom at the <strong>Balla Lompoa Museum</strong> and hunt for authentic handicrafts on <strong>Somba Opu Street</strong>.</p>', '<h3 style=\"text-align:justify;\"><strong>마카사르의 매력과 고대 카르스트 미로: 문화 및 자연 탐험</strong></h3><p style=\"text-align:justify;\">짧지만 깊은 인상을 남길 실속 있는 패키지로 남부 술라웨시의 이국적인 면모를 탐험해 보세요. 이번 여정은 <strong>파오테레 항구</strong>에서 부기스-마카사르 항해사들의 역사적 영광을 되짚어보고, 식민지 시대의 웅장함이 남아있는 <strong>로테르담 요새</strong>를 둘러봅니다. 인도네시아에서 가장 상징적인 일몰 중 하나인 <strong>로사리 해변</strong>에서 여유로운 순간을 만끽해 보세요.</p><p style=\"text-align:justify;\">이번 여행의 하이라이트는 세계에서 두 번째로 큰 카르스트 산맥 복합체인 <strong>람망람망</strong>으로의 모험입니다. 전통 목조 배를 타고 <strong>푸테 강</strong>을 따라 장엄한 석회암 절벽 미로를 가로지르며, 수천 년 전의 고대 벽화가 보존된 숨겨진 마을과 선사 시대 동굴을 발견하게 됩니다. 또한 <strong>발라 롬포아 박물관</strong>에서 고와 왕국의 역사를 깊이 있게 알아보고, <strong>솜바 오푸 거리</strong>에서 현지 전통 공예품을 쇼핑하는 시간도 가집니다.</p>', '<h3 style=\"text-align:justify;\"><strong>望加锡魅力与古老喀斯特迷宫：文化与自然探索之旅&nbsp;</strong></h3><p style=\"text-align:justify;\">通过这段简短而令人印象深刻的行程，探索南苏拉威西异域风情的一面。旅程将带您前往 <strong>波特雷港 (Paotere Harbour)</strong> 追溯布吉斯-望加锡航海者的历史辉煌，并感受殖民时期 <strong>鹿特丹城堡 (Fort Rotterdam)</strong> 的宏伟。在 <strong>洛萨里海滩 (Losari Beach)</strong> 享受放松时光，同时见证印度尼西亚最标志性的落日余晖。</p><p style=\"text-align:justify;\">本次旅行的重头戏是前往世界第二大喀斯特山脉群 —— <strong>拉曼拉曼 (Rammang-Rammang)</strong> 的冒险。您将乘坐传统木船穿行在 <strong>普特河 (Pute River)</strong> 上，穿越壮丽的石灰岩峭壁迷宫，寻找隐藏的村落和拥有数千年历史古老壁画的史前洞穴。此外, 您还将前往 <strong>巴拉隆坡博物馆 (Balla Lompoa Museum)</strong> 深入了解高和王国的历史，并在 <strong>松巴奥普路 (Jalan Somba Opu)</strong> 搜寻特色手工艺品。</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ea63d0c41bf51089b06f42b7f5105ded4\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e4154924dc0a90bfaf9a0282408e63563\">Hotel in Makassar</li><li data-list-item-id=\"e2ac9d3f248be01f8b9245470e2b53598\">Hotel in Toraja</li><li data-list-item-id=\"ef65c469cab33d6ac806d2ac3f6c45aef\">Meals (B=breakfast) only</li><li data-list-item-id=\"e8e035bdc6d03519455d8aaaf21775617\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"e1bff8b6cc0aed1818c39522aec6e58ff\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"eb0491f1724f7acbac55fb2e6f93855d4\">Tours and activities programmed</li><li data-list-item-id=\"ecf52efa76fd8c628dcb67bd6de64306d\">Local boat (wooden) on Rammang-Rammang program</li><li data-list-item-id=\"ede12dfb7f432f8024d17f376762477a3\">Coffee break 1x on Rammang-Rammang program</li><li data-list-item-id=\"eff93840624d2528a27c8967c92e551c6\">Entrance fees and donations</li><li data-list-item-id=\"e9c85d0e20692517c980702122bed3608\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"efba8c15f291a403dd79a29075ca15835\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(not valid during New Year’s Eve)</p></li><li data-list-item-id=\"e1e1c925e9551e5b6b80ee7b79ae51ab3\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices change from the government.</p></li><li data-list-item-id=\"e7b34b205640c83e0a9b8571c4c34900b\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"Culture\"]', NULL, 0, NULL, '2026-04-24 04:58:10', '2026-06-02 03:42:41'),
(10, 11, '4 DAYS TORAJA TOUR', 'SOUTH SULAWESI', '4d3n-toraja-tour', '<h3 style=\"text-align:justify;\"><strong>Pesona Kilat Tana Toraja: Petualangan Budaya di Negeri Para Raja&nbsp;</strong></h3><p style=\"text-align:justify;\">Ingin merasakan keajaiban Toraja namun memiliki waktu terbatas? Paket eksklusif 4 hari ini adalah jawaban sempurna untuk Anda. Perjalanan dimulai dari kemeriahan kota Makassar menuju dataran tinggi yang legendaris. Anda akan diajak melintasi jalur pegunungan yang ikonik, termasuk singgah di <strong>Bambapuang</strong> untuk mengagumi panorama gunung \"erotis\" Buttu Kabobong yang unik sebelum memasuki gerbang Tana Toraja.</p><p style=\"text-align:justify;\">Dalam perjalanan singkat namun mendalam ini, Anda akan menjelajahi mahakarya budaya Toraja yang mendunia. Mulai dari tebing batu <strong>Lemo</strong> yang dipenuhi patung Tau-tau, hingga misteri makam dalam gua <strong>Londa</strong> dan desa adat <strong>Kete Kesu</strong> yang memesona dengan deretan Tongkonan-nya. Tidak ketinggalan, Anda akan dibawa ke <strong>Batutumonga</strong>, titik tertinggi untuk menikmati sensasi menyeruput kopi di atas awan sambil memandang lembah Rantepao yang spektakuler.</p>', '<h3 style=\"text-align:justify;\"><strong>Charm of Tana Toraja: A Cultural Adventure in the Land of Kings&nbsp;</strong></h3><p style=\"text-align:justify;\">Want to experience the magic of Toraja but have limited time? This exclusive 4-day package is the perfect answer. The journey begins from the vibrant city of Makassar towards the legendary highlands. You will be taken across iconic mountain routes, including a stop at <strong>Bambapuang</strong> to admire the unique panorama of the \"erotic\" mountain, Buttu Kabobong, before entering the gates of Tana Toraja.</p><p style=\"text-align:justify;\">In this brief yet profound journey, you will explore world-renowned Toraja cultural masterpieces. From the <strong>Lemo</strong> stone cliffs filled with Tau-tau statues to the mysteries of the <strong>Londa</strong> cave graves and the enchanting <strong>Kete Kesu</strong> traditional village with its rows of Tongkonan. To top it off, you will be taken to <strong>Batutumonga</strong>, the highest point to enjoy the sensation of sipping coffee above the clouds while overlooking the spectacular Rantepao valley.</p>', '<h3 style=\"text-align:justify;\"><strong>타나 토라자의 매력: 왕들의 땅에서 즐기는 문화 모험</strong></h3><p style=\"text-align:justify;\">제한된 시간 안에 토라자의 마법을 경험하고 싶으신가요? 이 독점 4일 패키지가 완벽한 해답입니다. 활기찬 도시 마카사르에서 시작하여 전설적인 고원 지대로 향합니다. 타나 토라자의 관문에 들어서기 전, \"에로틱한\" 산으로 불리는 부투 카보봉(Buttu Kabobong)의 독특한 파노라마를 감상할 수 있는 <strong>밤바푸앙</strong>을 포함한 상징적인 산악 루트를 통과하게 됩니다.</p><p style=\"text-align:justify;\">짧지만 깊이 있는 이 여정에서 여러분은 세계적으로 유명한 토라자의 문화적 걸작들을 탐험하게 됩니다. 타우타우(Tau-tau) 조각상으로 가득한 <strong>레모</strong> 절벽부터 <strong>론다</strong> 동굴 묘지의 신비, 그리고 통코난이 줄지어 늘어선 매혹적인 <strong>케테 케수</strong> 민속 마을까지 모두 만나보실 수 있습니다. 여정의 대미는 <strong>바투투몽가</strong>에서 장식합니다. 가장 높은 곳에서 구름 위로 커피를 마시며 란테파오 계곡의 환상적인 절경을 감상하는 특별한 경험을 즐겨보세요.</p>', '<h3 style=\"text-align:justify;\"><strong>魅力塔纳托拉雅：国王故土的文化冒险&nbsp;</strong></h3><p style=\"text-align:justify;\">想要在有限的时间内感受托拉雅的魔力吗？这个专属的4天行程是您的完美选择。旅程从充满活力的望加锡出发，前往传奇的高地。在进入塔纳托拉雅的大门之前，您将穿越标志性的山路，并在 <strong>班巴普昂 (Bambapuang)</strong> 稍作停留，欣赏著名的“色情山”布图卡博博 (Buttu Kabobong) 的独特全景。</p><p style=\"text-align:justify;\">在这段短暂而深刻的旅程中，您将探索享誉世界的托拉雅文化杰作。从布满木偶雕像 (Tau-tau) 的 <strong>莱莫 (Lemo)</strong> 石壁，到 <strong>隆达 (Londa)</strong> 洞穴墓穴的神秘，再到拥有成排船型屋 (Tongkonan) 的迷人 <strong>克特克斯 (Kete Kesu)</strong> 古村落。此外，您还将前往最高点 <strong>巴图图蒙加 (Batutumonga)</strong>，体验在云端啜饮咖啡的快感，同时俯瞰兰特帕奥山谷的壮丽景色。</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e8742d2993e5e7ab144a06aa277b50889\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e7d1c256eac7f9c5e8b4da3218fe3b3b3\">Hotel in Makassar &amp; Toraja</li><li data-list-item-id=\"e80f71e3d055db21c9e369d07fe169144\">Meals (B=breakfast) only</li><li data-list-item-id=\"e24ca41da440d47a76b1d2ed1ea149c85\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"eb0111c5794df7813c17d9104b604fb0a\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"e035c769eb8640f6da6130aca78875145\">Tours and activities programmed</li><li data-list-item-id=\"ea10136728aa02a1e5de0481c27b34c9b\">Entrance fees and donations</li><li data-list-item-id=\"eb74d6b2e683723657332495c4767baaf\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"eef3d66b46f38fddd6238741924cc9996\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(not valid during New Year’s Eve)</p></li><li data-list-item-id=\"e609da7d01b51d05974d788c93720e7d1\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices changes from the government.</p></li><li data-list-item-id=\"ee340f337cb7cdf9a8471e846d7cf23a7\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"Culture\",\"Heritage\"]', NULL, 0, NULL, '2026-04-24 04:59:32', '2026-05-30 04:02:33'),
(11, 11, '5 DAYS TORAJA TOUR', 'SOUTH SULAWESI', '5d4n-toraja-tour', '<h3 style=\"text-align:justify;\"><strong>Magis Tana Toraja: Perjalanan Spiritual di Negeri di Atas Awan&nbsp;</strong></h3><p style=\"text-align:justify;\">Jelajahi salah satu destinasi paling eksotis di dunia bersama kami. Perjalanan ini membawa Anda jauh ke jantung <strong>Tana Toraja</strong>, tempat di mana tradisi kuno dan pemandangan alam yang spektakuler menyatu dengan sempurna. Dimulai dari kemegahan pegunungan <strong>Bambapuang</strong>, Anda akan segera memasuki dunia yang penuh keajaiban budaya, mulai dari rumah adat <strong>Tongkonan</strong> yang megah hingga ritual penghormatan leluhur yang tak tertandingi.</p><p style=\"text-align:justify;\">Dalam 5 hari ini, Anda akan menyaksikan keunikan <strong>Lemo</strong> dan <strong>Londa</strong> dengan makam tebingnya, keajaiban pohon makam bayi di <strong>Kambira</strong>, hingga pusat kerajinan tenun tradisional di <strong>Sa’dan</strong>. Puncak perjalanan menanti Anda di <strong>Batutumonga</strong>, di mana Anda dapat menikmati kopi dengan panorama lembah yang berselimut awan.</p>', '<h3 style=\"text-align:justify;\"><strong>Magical Tana Toraja: A Spiritual Journey to the Land Above the Clouds&nbsp;</strong></h3><p style=\"text-align:justify;\">Embark on an expedition to one of the most exotic destinations in the world. This journey takes you deep into the heart of <strong>Tana Toraja</strong>, where ancient traditions and spectacular natural landscapes blend perfectly. Starting from the grandeur of the <strong>Bambapuang</strong> mountains, you will immediately enter a world full of cultural wonders, from the magnificent <strong>Tongkonan</strong> traditional houses to unparalleled rituals of ancestral veneration.</p><p style=\"text-align:justify;\">During these 5 days, you will witness the uniqueness of <strong>Lemo</strong> and <strong>Londa</strong> with their cliffside graves, the miracle of the baby grave tree in <strong>Kambira</strong>, and the center of traditional weaving in <strong>Sa’dan</strong>. The highlight of the trip awaits you in <strong>Batutumonga</strong>, where you can enjoy coffee with a panoramic view of the valley shrouded in clouds. This is not just a sightseeing tour, but a spiritual experience that will leave a lasting impression on your heart.</p>', '<h3 style=\"text-align:justify;\"><strong>신비로운 타나 토라자: 구름 위의 땅으로 떠나는 영적 여정</strong></h3><p style=\"text-align:justify;\">세계에서 가장 이국적인 여행지 중 한 곳으로 탐험을 떠나보세요. 이 여정은 고대 전통과 환상적인 자연경관이 완벽하게 조화를 이루는 <strong>타나 토라자</strong>의 심장부로 여러분을 안내합니다. 웅장한 <strong>밤바푸앙</strong> 산맥에서 시작하여, 장엄한 전통 가옥인 <strong>통코난</strong>부터 비할 데 없는 조상 숭배 의식에 이르기까지 문화적 경이로움으로 가득 찬 세계에 즉시 발을 들여놓게 될 것입니다.</p><p style=\"text-align:justify;\">5일 동안 절벽 묘지가 있는 <strong>레모</strong>와 <strong>론다</strong>의 독특함, <strong>캄비라</strong>의 아기 나무 무덤의 신비, 그리고 <strong>사단</strong>의 전통 직물 센터를 목격하게 됩니다. 이번 여행의 하이라이트는 <strong>바투투몽가</strong>에서 기다리고 있습니다. 이곳에서 구름에 덮인 계곡의 파노라마 뷰를 감상하며 커피 한 잔의 여유를 즐겨보세요. 이것은 단순한 관광이 아니라 여러분의 마음에 영원히 남을 영적인 경험이 될 것입니다.</p>', '<h3 style=\"text-align:justify;\"><strong>梦幻塔纳托拉雅：云端之国的灵魂之旅&nbsp;</strong></h3><p style=\"text-align:justify;\">开启一场前往全球最富异域色彩目的地的探险之旅。这段旅程将带您深入 <strong>塔纳托拉雅 (Tana Toraja)</strong> 的核心地带，在这里，古老的传统与壮丽的自然景观完美融合。从宏伟的 <strong>班巴普昂 (Bambapuang)</strong> 山脉出发，您将立即进入一个充满文化奇迹的世界，从雄伟的 <strong>船型屋 (Tongkonan)</strong> 到无与伦比的祭祖仪式。</p><p style=\"text-align:justify;\">在这5天里，您将见证 <strong>莱莫 (Lemo)</strong> 和 <strong>隆达 (Londa)</strong> 独特的岩壁墓穴、<strong>坎比拉 (Kambira)</strong> 婴儿树葬的奇迹，以及 <strong>萨丹 (Sa’dan)</strong> 的传统织造中心。旅程的高潮在 <strong>巴图图蒙加 (Batutumonga)</strong> 等待着您，在那里您可以一边品尝咖啡，一边俯瞰云雾缭绕的山谷全景。这不仅是一次观光之旅，更是一次触动心灵的深度精神体验。</p>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e8742d2993e5e7ab144a06aa277b50889\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e7d1c256eac7f9c5e8b4da3218fe3b3b3\">Hotel in Makassar &amp; Toraja</li><li data-list-item-id=\"e80f71e3d055db21c9e369d07fe169144\">Meals (B=breakfast) only</li><li data-list-item-id=\"e24ca41da440d47a76b1d2ed1ea149c85\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"eb0111c5794df7813c17d9104b604fb0a\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"e035c769eb8640f6da6130aca78875145\">Tours and activities programmed</li><li data-list-item-id=\"ea10136728aa02a1e5de0481c27b34c9b\">Entrance fees and donations</li><li data-list-item-id=\"eb74d6b2e683723657332495c4767baaf\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"e1d214e7f62b575ac6c04567d66168e10\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(not valid during New Year’s Eve)</p></li><li data-list-item-id=\"e8afa09b5ac3b0dbc8edc2cb5ec72c7ac\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices change from the government.</p></li><li data-list-item-id=\"eb6f1ed00109669718deb2f0734b62612\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"Culture\",\"Local Experience\"]', NULL, 0, NULL, '2026-04-24 05:00:25', '2026-05-30 03:51:16'),
(12, 11, '6 DAYS MAKASAR - TORAJA', 'SOUTH SULAWESI', '6d5n-makasar-toraja', '<h3 style=\"text-align:justify;\"><strong>Jelajahi Jantung Budaya Sulawesi: Eksplorasi Magis Makassar &amp; Toraja</strong></h3><p style=\"text-align:justify;\">Siapkan diri Anda untuk perjalanan yang akan mengubah cara Anda melihat dunia. Mulai dari pesona kota <strong>Makassar</strong> yang bersejarah, Anda akan diajak menyelami keajaiban <strong>Rammang-Rammang</strong>, sebuah lembah karst purba yang dikelilingi persawahan hijau nan puitis. Rasakan ketenangan saat menyusuri Sungai Pute dengan perahu kayu tradisional menuju kampung tersembunyi dan gua prasejarah yang menyimpan rahasia ribuan tahun.</p><p style=\"text-align:justify;\">Petualangan berlanjut ke dataran tinggi <strong>Tana Toraja</strong>, negeri di atas awan yang mendunia karena kekayaan budayanya. Anda akan menyaksikan kemegahan situs pemakaman kuno di <strong>Lemo</strong> dan <strong>Londa</strong>, serta keajaiban pohon makam bayi di <strong>Kambira</strong>. Nikmati momen magis di <strong>Batutumonga</strong> dengan pemandangan lembah Rantepao dari ketinggian yang memukau, sebelum menutup hari di <strong>Kete Kesu</strong>, desa adat yang terkenal dengan arsitektur Tongkonan dan ukiran kayu yang ikonik.</p>', '<h3 style=\"text-align:justify;\"><strong>Explore the Cultural Heart of Sulawesi: Magical Makassar &amp; Toraja Exploration</strong></h3><p style=\"text-align:justify;\">Prepare yourself for a journey that will change the way you see the world. Starting from the historic charm of <strong>Makassar</strong>, you will be invited to dive into the wonders of <strong>Rammang-Rammang</strong>, a poetic ancient karst valley surrounded by lush green rice fields. Feel the tranquility as you cruise the Pute River by traditional wooden boat towards hidden villages and prehistoric caves that hold secrets from thousands of years ago.</p><p style=\"text-align:justify;\">The adventure continues to the <strong>Tana Toraja</strong> highlands, a world-renowned \"land above the clouds\" famous for its rich culture. You will witness the grandeur of ancient burial sites in <strong>Lemo</strong> and <strong>Londa</strong>, as well as the miracle of the baby grave tree in <strong>Kambira</strong>. Enjoy a magical moment in <strong>Batutumonga</strong> with breathtaking views of the Rantepao valley from the heights, before concluding the day at <strong>Kete Kesu</strong>, a traditional village famous for its iconic Tongkonan architecture and woodcarvings.</p>', '<h3 style=\"text-align:justify;\"><strong>술라웨시의 문화적 심장부를 탐험하다: 마법 같은 마카사르 &amp; 토라자 탐방&nbsp;</strong></h3><p style=\"text-align:justify;\">세상을 바라보는 관점을 바꿔줄 여정을 준비하세요. 역사적인 매력이 가득한 <strong>마카사르</strong>에서 시작하여, 푸른 논으로 둘러싸인 시적인 고대 카르스트 계곡인 <strong>람망람망</strong>의 경이로움 속으로 여러분을 초대합니다. 전통 목조 배를 타고 푸테 강을 따라 이동하며 수천 년 전의 비밀을 간직한 숨겨진 마을과 선사 시대 동굴의 평온함을 느껴보세요.</p><p style=\"text-align:justify;\">모험은 풍부한 문화로 세계적으로 유명한 \"구름 위의 땅\" <strong>타나 토라자</strong> 고원 지대로 이어집니다. <strong>레모</strong>와 <strong>론다</strong>의 웅장한 고대 묘지는 물론, <strong>캄비라</strong>에 있는 아기 나무 무덤의 신비로움을 목격하게 될 것입니다. <strong>바투투몽가</strong>의 고지대에서 내려다보는 란테파오 계곡의 환상적인 전망과 함께 마법 같은 순간을 즐기고, 상징적인 통코난 건축물과 목공예로 유명한 전통 마을 <strong>케테 케수</strong>에서 하루를 마무리해 보세요.</p>', '<h3 style=\"text-align:justify;\"><strong>探索苏拉威西的文化核心：梦幻望加锡与托拉雅之旅&nbsp;</strong></h3><p style=\"text-align:justify;\">准备好开启一场将改变您世界观的旅程。从充满历史魅力的<strong>望加锡</strong>出发，我们将带您深入探索**拉曼拉曼（Rammang-Rammang）**的奇迹——这是一个被郁郁葱葱的稻田环绕、充满诗意的古老喀斯特山谷。乘坐传统木船穿行在普特河（Pute River）上，感受前往隐藏村落和拥有数千年秘密的史前洞穴时的那份宁静。</p><p style=\"text-align:justify;\">冒险将继续前往**塔纳托拉雅（Tana Toraja）<strong>高地，这个因其丰富文化而享誉世界的“云端之国”。您将见证</strong>莱莫（Lemo）<strong>和</strong>隆达（Londa）<strong>古老墓地的壮丽，以及</strong>坎比拉（Kambira）<strong>婴儿树葬的奇迹。在</strong>巴图图蒙加（Batutumonga）<strong>的高处欣赏兰特帕奥山谷绝美的壮观景色，感受魔幻时刻，最后在以标志性船型屋（Tongkonan）建筑和木雕闻名的传统村落</strong>克特克斯（Kete Kesu）**结束一天的行程。</p>', 0.00, NULL, 6, 5, NULL, NULL, '<ul><li data-list-item-id=\"ea63d0c41bf51089b06f42b7f5105ded4\">Accommodation at mentioned hotel based on twin/double sharing room</li><li data-list-item-id=\"e4154924dc0a90bfaf9a0282408e63563\">Hotel in Makassar</li><li data-list-item-id=\"e2ac9d3f248be01f8b9245470e2b53598\">Hotel in Toraja</li><li data-list-item-id=\"ef65c469cab33d6ac806d2ac3f6c45aef\">Meals (B=breakfast) only</li><li data-list-item-id=\"e8e035bdc6d03519455d8aaaf21775617\">Private transfers &amp; transportation with AC vehicle</li><li data-list-item-id=\"e1bff8b6cc0aed1818c39522aec6e58ff\">English speaking guide (other spoken languages as per availability)</li><li data-list-item-id=\"eb0491f1724f7acbac55fb2e6f93855d4\">Tours and activities programmed</li><li data-list-item-id=\"ecf52efa76fd8c628dcb67bd6de64306d\">Local boat (wooden) on Rammang-Rammang program</li><li data-list-item-id=\"ede12dfb7f432f8024d17f376762477a3\">Coffee break 1x on Rammang-Rammang program</li><li data-list-item-id=\"eff93840624d2528a27c8967c92e551c6\">Entrance fees and donations</li><li data-list-item-id=\"e9c85d0e20692517c980702122bed3608\">Mineral water during tour</li></ul>', '<ul><li data-list-item-id=\"e523964a9c595e28cafb844e58a4c871b\"><p style=\"text-align:justify;\">Air tickets and porters</p></li><li data-list-item-id=\"e2fc53bfac848581409a34f8a48727e45\"><p style=\"text-align:justify;\">Meals not included (L=lunch; D=dinner)</p></li><li data-list-item-id=\"ebfa0678befb013602f5407d21dfb91db\"><p style=\"text-align:justify;\">Insurance</p></li><li data-list-item-id=\"e8d06d32ff5fb8460bdb3ff904bce59e3\"><p style=\"text-align:justify;\">Personal expenses such as laundry, extra meals and beverages</p></li><li data-list-item-id=\"ea4c55ceeeb294e2f111a8626190b20b6\"><p style=\"text-align:justify;\">Tips &amp; gratuities</p></li><li data-list-item-id=\"e87416ce9f2ab56dd15a9fd370f5f39f1\"><p style=\"text-align:justify;\">Additional services requested</p></li><li data-list-item-id=\"eae178ad97e07176f2266293891724c14\"><p style=\"text-align:justify;\">Expenses not mentioned in the itinerary</p></li></ul>', '<ul><li data-list-item-id=\"eb8bff653b0a9f6d7d9866805f0f0cad6\"><p style=\"text-align:justify;\">Validity immediately up to and including 20th December 2026<br>(Not valid during New Year’s Eve)</p></li><li data-list-item-id=\"e2f7d622c131e94866d46b26870d54ec4\"><p style=\"text-align:justify;\">Rates are quote based Fuel rates as per 20th November 2025, Subject to changes IF there’s any fuel prices change from the government.</p></li><li data-list-item-id=\"eb09900528d1eade684c3b4349da48c7d\"><p style=\"text-align:justify;\">Rates are subject to 1,2% VAT (tax)</p></li></ul>', '[\"Nature\",\"Culture\",\"Local Life & Education\"]', NULL, 0, NULL, '2026-04-24 05:01:22', '2026-05-30 03:44:42'),
(13, 11, '8 DAYS EXOTIC SOUTH SULAWESI', 'SOUTH SULAWESI', '8-days-exotic-south-sulawesi', '<h3 style=\"text-align:justify;\"><strong>Jelajahi Keajaiban Sulawesi: Dari Puncak Toraja hingga Pesisir Bira</strong></h3><p style=\"text-align:justify;\">Nikmati petualangan tak terlupakan melintasi bentang alam Sulawesi yang spektakuler. Mulai dari keajaiban <strong>Lembah Karst Rammang-Rammang</strong> yang puitis , Anda akan dibawa menuju jantung budaya <strong>Tana Toraja</strong> untuk menyaksikan kemegahan situs pemakaman kuno dan desa adat yang mendunia. Rasakan pengalaman magis saat kabut menyelimuti <strong>Batutumonga</strong> di pagi hari, menawarkan pemandangan lembah dari puncak tertinggi yang memukau.</p><p style=\"text-align:justify;\">Tak hanya budaya, perjalanan ini memanjakan Anda dengan relaksasi sempurna di <strong>Pantai Bira</strong> yang berpasir putih kristal serta kunjungan eksklusif ke pusat pembuatan <strong>Kapal Phinisi</strong> yang legendaris. Dari ketenangan <strong>Danau Poso</strong> hingga eksotisme <strong>Desa Terapung</strong> di Danau Tempe, setiap sudut Sulawesi menawarkan cerita yang berbeda. Didampingi pemandu profesional dan fasilitas transportasi pribadi yang nyaman, kami siap mengubah liburan Anda menjadi sebuah ekspedisi penuh makna.</p>', '<h3 style=\"text-align:justify;\"><strong>Explore the Wonders of Sulawesi: From Toraja’s Peaks to Bira’s Coastline</strong></h3><p style=\"text-align:justify;\">Experience an unforgettable adventure across Sulawesi\'s spectacular landscapes. Starting from the poetic <strong>Rammang-Rammang Karst Valley</strong>, you will be journeyed into the cultural heart of <strong>Tana Toraja</strong> to witness the grandeur of world-renowned ancient burial sites and traditional villages. Feel the magic as the morning mist envelopes <strong>Batutumonga</strong>, offering a breathtaking view of the valley from its highest peak.</p><p style=\"text-align:justify;\">Beyond culture, this trip offers pure relaxation on the crystal-clear white sands of <strong>Bira Beach</strong> and an exclusive visit to the legendary <strong>Phinisi boat-building</strong> center. From the tranquility of <strong>Lake Poso</strong> to the exotic <strong>Floating Village</strong> on Lake Tempe, every corner of Sulawesi tells a different story. Accompanied by professional guides and comfortable private transportation, we are ready to turn your holiday into a meaningful expedition.</p>', '<h3 style=\"text-align:justify;\"><strong>술라웨시의 경이로움을 탐험하다: 토라자의 산 정상에서 비라의 해안선까지</strong></h3><p style=\"text-align:justify;\">술라웨시의 환상적인 풍경을 가로지르는 잊지 못할 모험을 경험해 보세요. 시적인 <strong>람망람망 카르스트 계곡</strong>에서 시작하여, 세계적으로 유명한 고대 무덤과 전통 마을이 있는 <strong>타나 토라자</strong>의 문화적 심장부로 여러분을 안내합니다. 아침 안개가 <strong>바투투몽가</strong>를 감싸 안으며 가장 높은 봉우리에서 내려다보는 계곡의 절경은 마치 마법과 같은 순간을 선사할 것입니다.</p><p style=\"text-align:justify;\">문화 탐방뿐만 아니라, 이 여행은 투명한 백사장이 펼쳐진 <strong>비라 해변</strong>에서의 완벽한 휴식과 전설적인 <strong>피니시(Phinisi) 선박</strong> 건조 현장으로의 독점 방문 기회를 제공합니다. 평온한 <strong>포소 호수</strong>부터 템페 호수의 이국적인 <strong>수상 마을</strong>까지, 술라웨시의 모든 구석구석은 저마다의 이야기를 담고 있습니다. 전문 가이드와 편안한 전용 차량 서비스와 함께, 여러분의 휴가를 의미 있는 탐험으로 바꾸어 드립니다.</p>', '<h3 style=\"text-align:justify;\"><strong>探索苏拉威西奇迹：从托拉雅之巅到比拉海岸线</strong></h3><p style=\"text-align:justify;\">开启一场横跨苏拉威西壮丽风景的难忘冒险。从充满诗意的<strong>拉曼拉曼（Rammang-Rammang）喀斯特山谷</strong>出发，您将进入**托拉雅（Tana Toraja）<strong>的文化核心，见证享誉世界的古老墓地和传统村落的宏伟。当晨雾笼罩</strong>巴图图蒙加（Batutumonga）**时，感受那份如梦似幻的魔力，从最高峰俯瞰山谷的绝美壮观。</p><p style=\"text-align:justify;\">除了文化体验，本次旅程还为您提供在<strong>比拉（Bira）海滩</strong>晶莹洁白的沙滩上放松身心的完美时光，并带您独家探访传奇的<strong>菲尼西（Phinisi）造船中心</strong>。从宁静的<strong>波索湖</strong>到温佩湖（Lake Tempe）充满异域风情的<strong>水上村落</strong>，苏拉威西的每一个角落都诉说着不同的故事。在专业导游和舒适私人专车的陪伴下，我们已准备好将您的假期变成一场意义非凡的探险。</p>', 0.00, NULL, 8, 7, NULL, NULL, '<ul><li data-list-item-id=\"ebe411960805a31fffb9b9a59b7597cba\"><p style=\"text-align:justify;\">Accommodation in mentioned hotel or similar. Double/twin/triple share.</p></li><li data-list-item-id=\"eac32a96762a5b4c916a4acaac9805af6\"><p style=\"text-align:justify;\">Breakfast at the hotel</p></li><li data-list-item-id=\"e16b1b659a6dcb65fec78806db38149a5\"><p style=\"text-align:justify;\">Private AC Car</p></li><li data-list-item-id=\"edb7783934eedaf65ba08ee79b25014a6\"><p style=\"text-align:justify;\">Entrance fees and Donations as per program</p></li><li data-list-item-id=\"e13c2c8712d7d6626db52f003fd8bb5e2\"><p style=\"text-align:justify;\">Mineral water during tour</p></li><li data-list-item-id=\"eaa617d3e76e2badd520573c6b3a482c2\"><p style=\"text-align:justify;\">English / Dutch speaking guide (as per availability)</p></li></ul>', '<ul><li data-list-item-id=\"ee3d3fda65e93a3a96ebb103fa8b52fcf\"><p style=\"text-align:justify;\">Domestic and international Flight ticket</p></li><li data-list-item-id=\"e495bcec76e8726f27ea2e347ef4bc2ee\"><p style=\"text-align:justify;\">Domestic and international airport tax</p></li><li data-list-item-id=\"e3c17c61adf328b3ffe6bba70596119ca\"><p style=\"text-align:justify;\">Lunch and Dinner</p></li><li data-list-item-id=\"e3e2b7d0fbac3a7d89a00de46e1212d7c\"><p style=\"text-align:justify;\">Guide and driver tip</p></li><li data-list-item-id=\"e393526e86fc95b6623bfa66aa0716647\"><p style=\"text-align:justify;\">Optional tour &amp; other personal expenses</p></li><li data-list-item-id=\"e07cc013b85b2fa91fe6f4203d6b2de85\"><p style=\"text-align:justify;\">Insurance</p></li></ul>', '<ul><li data-list-item-id=\"e5df750b36fc48af9026669c6a238520b\"><p style=\"text-align:justify;\">The prices above are valid from immediately up to and including 20th December 2026 (not valid during New Year’s Eve 31 December until 02 January)&nbsp;&nbsp;</p></li><li data-list-item-id=\"e949a2bc70dd6deff649afd52b057b646\"><p style=\"text-align:justify;\">The prices above are subject to changes in case of significant increase in exchange rate or national fuel price.</p></li><li data-list-item-id=\"e7e0511fd453fd2d62e106d9661b1a74f\"><p style=\"text-align:justify;\">The itinerary above is flexible and subject to changes in case of extreme weather condition during the trip or any other force majeure.</p></li></ul>', '[\"Nature\",\"Culture\",\"Beach\",\"Social & Local Life\"]', NULL, 0, NULL, '2026-04-24 05:18:01', '2026-05-29 13:55:16');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(14, 11, '9 DAYS ALL OVER SOUTH SULAWESI', 'SOUTH SULAWESI', '9-days-all-over-south-sulawesi', '<p style=\"text-align:justify;\">Tur ini menawarkan penjelajahan menyeluruh di Sulawesi Selatan, dimulai dari <strong>Makassar</strong> menuju lembah karst <strong>Rammang-Rammang</strong> yang memukau, hingga ke dataran tinggi <strong>Toraja</strong> yang ikonik. Di Toraja, Anda akan menyelami kekayaan budaya melalui kunjungan ke situs pemakaman kuno di Lemo dan Londa, serta desa tradisional Kete Kesu yang terkenal dengan ukiran kayunya. Perjalanan juga mencakup pengalaman unik di Batutumonga untuk menikmati pemandangan lembah dari ketinggian dan mengunjungi area megalitikum Bori.</p><p style=\"text-align:justify;\">Selanjutnya, perjalanan berlanjut ke <strong>Sengkang</strong> untuk mengunjungi desa terapung di Danau Tempe dan pusat tenun sutra tradisional Bugis. Tur ini diakhiri dengan relaksasi di pantai berpasir putih <strong>Bira</strong>, melihat proses pembuatan kapal Phinisi di Tana Beru, serta mengunjungi suku pedalaman Kajang yang masih memegang teguh tradisi leluhur. Paket ini sudah mencakup akomodasi hotel, transportasi pribadi ber-AC, dan pemandu profesional untuk menjamin kenyamanan Anda selama ekspedisi.</p>', '<p style=\"text-align:justify;\">This tour offers a comprehensive exploration of <strong>South Sulawesi</strong>, starting from <strong>Makassar</strong> to the breathtaking <strong>Rammang-Rammang</strong> karst valley, and onwards to the iconic <strong>Toraja</strong> highlands. In Toraja, you will immerse yourself in rich culture through visits to ancient burial sites in <strong>Lemo</strong> and <strong>Londa</strong>, as well as the traditional village of <strong>Kete Kesu</strong>, famous for its intricate woodcarvings. The journey also includes unique experiences in <strong>Batutumonga</strong> to enjoy valley views from the heights and a visit to the <strong>Bori</strong> megalithic area.</p><p style=\"text-align:justify;\">Next, the trip continues to <strong>Sengkang</strong> to visit the floating village on <strong>Lake Tempe</strong> and the traditional Bugis silk weaving center. The tour concludes with relaxation on the white sandy beaches of <strong>Bira</strong>, observing the <strong>Phinisi boat-building</strong> process in Tana Beru, and visiting the <strong>Kajang tribe</strong>, who still maintain their ancestral traditions. This package includes hotel accommodation, private air-conditioned transportation, and a professional guide to ensure your comfort throughout the expedition.</p>', '<p style=\"text-align:justify;\">이 투어는 <strong>마카사르</strong>에서 출발하여 환상적인 <strong>람망람망</strong> 카르스트 계곡을 거쳐 상징적인 <strong>토라자</strong> 고원 지대까지 이어지는 <strong>남부 술라웨시</strong> 전역을 포괄적으로 탐험합니다. 토라자에서는 <strong>레모</strong>와 <strong>론다</strong>의 고대 무덤 방문은 물론, 정교한 목공예로 유명한 전통 마을 <strong>케테 케수</strong>를 통해 풍부한 문화에 몰입하게 됩니다. 또한 <strong>바투투몽가</strong>에서 고지대의 계곡 전경을 감상하고 <strong>보리</strong> 거석 지역을 방문하는 특별한 경험이 포함되어 있습니다.</p><p style=\"text-align:justify;\">이어서 여행은 <strong>셍캉</strong>으로 이동하여 <strong>템페 호수</strong>의 수상 마을과 전통 부기스 실크 직물 센터를 방문합니다. 투어는 <strong>비라</strong>의 하얀 모래 사장에서의 휴식, 타나 베루에서의 <strong>피니시 선박</strong> 건조 과정 관람, 그리고 조상의 전통을 고수하며 살아가는 <strong>카장 부족</strong> 방문으로 마무리됩니다. 이 패키지에는 전 일정 편안함을 보장하기 위해 호텔 숙박, 에어컨 시설이 완비된 전용 차량, 전문 가이드 서비스가 포함되어 있습니다.</p>', '<p style=\"text-align:justify;\">本次行程将带您全面探索<strong>南苏拉威西</strong>，从<strong>望加锡</strong>出发，前往迷人的<strong>拉曼拉曼</strong>（Rammang-Rammang）喀斯特山谷，随后前往标志性的<strong>托拉雅</strong>高地 。在托拉雅，您将通过参观<strong>莱莫</strong>（Lemo）和<strong>隆达</strong>（Londa）的古老墓地，以及以精美木雕闻名的传统村落<strong>克特克斯</strong>（Kete Kesu），深入体验当地丰富的文化 。行程还包括在<strong>巴图图蒙加</strong>（Batutumonga）从高处欣赏山谷美景，以及参观<strong>博里</strong>（Bori）巨石阵区域的独特体验 。</p><p style=\"text-align:justify;\">随后，旅程将前往<strong>瓦若</strong>（Sengkang），参观<strong>温佩湖</strong>（Lake Tempe）上的水上村落和传统的布吉斯丝绸编织中心 。行程最后将在<strong>比拉</strong>（Bira）洁白的沙滩上放松身心，参观塔纳贝尔（Tana Beru）著名的<strong>菲尼西船</strong>（Phinisi）建造过程，并拜访仍坚守祖先传统的<strong>卡江</strong>（Kajang）部落 。该套餐已包含酒店住宿、私人空调专车以及专业导游，确保您在整个探险过程中舒适无忧 。</p>', 0.00, NULL, 9, 8, NULL, NULL, '<ul><li data-list-item-id=\"ebe411960805a31fffb9b9a59b7597cba\"><p style=\"text-align:justify;\">Accommodation in mentioned hotel or similar. Double/twin/triple share.</p></li><li data-list-item-id=\"eac32a96762a5b4c916a4acaac9805af6\"><p style=\"text-align:justify;\">Breakfast at the hotel</p></li><li data-list-item-id=\"e16b1b659a6dcb65fec78806db38149a5\"><p style=\"text-align:justify;\">Private AC Car</p></li><li data-list-item-id=\"edb7783934eedaf65ba08ee79b25014a6\"><p style=\"text-align:justify;\">Entrance fees and Donations as per program</p></li><li data-list-item-id=\"e13c2c8712d7d6626db52f003fd8bb5e2\"><p style=\"text-align:justify;\">Mineral water during tour</p></li><li data-list-item-id=\"eaa617d3e76e2badd520573c6b3a482c2\"><p style=\"text-align:justify;\">English / Dutch speaking guide (as per availability)</p></li></ul>', '<ul><li data-list-item-id=\"ee3d3fda65e93a3a96ebb103fa8b52fcf\"><p style=\"text-align:justify;\">Domestic and international Flight ticket</p></li><li data-list-item-id=\"e495bcec76e8726f27ea2e347ef4bc2ee\"><p style=\"text-align:justify;\">Domestic and international airport tax</p></li><li data-list-item-id=\"e3c17c61adf328b3ffe6bba70596119ca\"><p style=\"text-align:justify;\">Lunch and Dinner</p></li><li data-list-item-id=\"e3e2b7d0fbac3a7d89a00de46e1212d7c\"><p style=\"text-align:justify;\">Guide and driver tip</p></li><li data-list-item-id=\"e393526e86fc95b6623bfa66aa0716647\"><p style=\"text-align:justify;\">Optional tour &amp; other personal expenses</p></li><li data-list-item-id=\"e07cc013b85b2fa91fe6f4203d6b2de85\"><p style=\"text-align:justify;\">Insurance</p></li></ul>', '<ul><li data-list-item-id=\"e6f977cb694fd7dcd1acef68c7f543498\"><p style=\"text-align:justify;\">The prices above are valid from immediately up to and including 20th December 2026 (not valid during New Year’s Eve 31 December until 02 January)&nbsp;&nbsp;</p></li><li data-list-item-id=\"ef93cbf6997957eb9f896ac31e748af0f\"><p style=\"text-align:justify;\">The prices above are subject to changes in case of significant increase in exchange rate or national fuel price.</p></li><li data-list-item-id=\"e6416ca7d9a7934d3dfeca5a2a5dadad4\"><p style=\"text-align:justify;\">The itinerary above is flexible and subject to changes in case of extreme weather condition during the trip or any other force majeure.</p></li></ul>', '[\"Nature\",\"Culture\",\"Beach\",\"Social & Local Life\"]', NULL, 0, NULL, '2026-04-24 05:20:27', '2026-05-29 14:28:29'),
(15, 11, '10 DAYS SOUTH CENTRAL SULAWESI', 'SOUTH SULAWESI', '10-days-south-central-sulawesi', '<p style=\"text-align:justify;\">Tur ini menawarkan penjelajahan mendalam melintasi Sulawesi, dimulai dari <strong>Makassar</strong> menuju kawasan pegunungan <strong>Toraja</strong> yang ikonik. Anda akan diajak mengeksplorasi keajaiban alam seperti lembah karst <strong>Rammang-Rammang</strong>, serta menyelami kekayaan budaya pemakaman kuno dan desa tradisional di <strong>Lemo</strong> dan <strong>Kete Kesu</strong>. Perjalanan berlanjut ke arah utara melewati lanskap pegunungan yang asri, perkebunan kelapa sawit, hingga tiba di tepi <strong>Danau Poso</strong> yang tenang.</p><p style=\"text-align:justify;\">Bagian akhir perjalanan difokuskan pada keindahan <strong>Sulawesi Tengah</strong>, mencakup kunjungan ke <strong>air terjun Sulewana</strong> di Tentena serta situs sejarah di Palu. Anda juga akan menikmati waktu santai di pantai berpasir Donggala sebelum mengakhiri tur melalui Bandara Mutiara Palu. Paket ini sudah mencakup akomodasi hotel, transportasi pribadi ber-AC, serta didampingi pemandu untuk memastikan kenyamanan selama ekspedisi.</p><p style=\"text-align:justify;\">Bagaimana, apakah Anda tertarik untuk menjadwalkan perjalanan ini untuk liburan tahun depan?</p>', '<p style=\"text-align:justify;\">This tour offers an in-depth exploration across Sulawesi, starting from <strong>Makassar</strong> to the iconic <strong>Toraja</strong> highlands. You will be invited to explore natural wonders such as the <strong>Rammang-Rammang</strong> karst valley and delve into the rich culture of ancient burial sites and traditional villages in <strong>Lemo</strong> and <strong>Kete Kesu</strong>. The journey continues northward through lush mountain landscapes and palm oil plantations until reaching the serene shores of <strong>Lake Poso</strong>.</p><p style=\"text-align:justify;\">The final part of the trip focuses on the beauty of <strong>Central Sulawesi</strong>, including a visit to the <strong>Sulewana Waterfall</strong> in Tentena and historical sites in <strong>Palu</strong>. You will also enjoy leisure time on the sandy beaches of <strong>Donggala</strong> before concluding the tour via Palu\'s <strong>Mutiara Airport</strong>. This package includes hotel accommodation, private air-conditioned transportation, and a guide to ensure your comfort throughout the expedition.</p>', '<p style=\"text-align:justify;\">이 투어는 <strong>마카사르</strong>에서 출발하여 상징적인 <strong>토라자</strong> 고원 지대까지 이어지는 술라웨시 심층 탐험을 제공합니다. 람망람망(Rammang-Rammang) 카르스트 계곡과 같은 자연의 경이로움을 탐험하고 , 레모(Lemo)와 케테 케스(Kete Kesu)의 고대 무덤 및 전통 마을에서 풍부한 문화를 경험하게 됩니다. 여정은 푸른 산악 경관과 팜유 농장을 지나 평화로운 <strong>포소 호수</strong> 기슭까지 이어집니다.</p><p style=\"text-align:justify;\">여행의 마지막 단계는 텐테나의 <strong>술레와나 폭포</strong>와 팔루의 역사적 명소를 포함한 <strong>중부 술라웨시</strong>의 아름다움에 집중합니다. 또한 <strong>동갈라</strong>의 모래 사장에서 여유로운 시간을 보낸 후 팔루의 <strong>무티아라 공항</strong>을 통해 투어를 마무리하게 됩니다. 이 패키지에는 호텔 숙박 , 에어컨 시설이 완비된 전용 차량 , 그리고 전 일정 편안함을 보장하는 가이드 서비스가 포함되어 있습니다.</p>', '<p style=\"text-align:justify;\">本次行程将带您深入探索苏拉威西岛，从<strong>望加锡</strong>出发，前往标志性的<strong>托拉雅</strong>高地 。您将探索<strong>拉曼拉曼</strong>（Rammang-Rammang）喀斯特山谷等自然奇观 ，并深入了解<strong>莱莫</strong>（Lemo）和<strong>克特克斯</strong>（Kete Kesu）古老墓地与传统村落的丰富文化 。旅程将穿过郁郁葱葱的山区风景和棕榈油种植园一路向北 ，直到抵达宁静的<strong>波索湖</strong>畔 。</p><p style=\"text-align:justify;\">行程的最后阶段重点展示<strong>中苏拉威西</strong>的美景，包括参观丹提那（Tentena）的<strong>苏莱瓦纳瀑布</strong> 和<strong>帕卢</strong>（Palu）的历史遗迹 。在通过帕卢的<strong>穆蒂亚拉机场</strong>结束行程之前 ，您还可以在<strong>栋加拉</strong>（Donggala）的沙滩上享受悠闲时光 。该套餐已包含酒店住宿 、私人空调专车 ，并配备专业导游 ，确保您在整个探险过程中舒适无忧。</p>', 0.00, NULL, 10, 9, NULL, NULL, '<ul><li data-list-item-id=\"ebe411960805a31fffb9b9a59b7597cba\"><p style=\"text-align:justify;\">Accommodation in mentioned hotel or similar. Double/twin/triple share.</p></li><li data-list-item-id=\"eac32a96762a5b4c916a4acaac9805af6\"><p style=\"text-align:justify;\">Breakfast at the hotel</p></li><li data-list-item-id=\"e16b1b659a6dcb65fec78806db38149a5\"><p style=\"text-align:justify;\">Private AC Car</p></li><li data-list-item-id=\"edb7783934eedaf65ba08ee79b25014a6\"><p style=\"text-align:justify;\">Entrance fees and Donations as per program</p></li><li data-list-item-id=\"e13c2c8712d7d6626db52f003fd8bb5e2\"><p style=\"text-align:justify;\">Mineral water during tour</p></li><li data-list-item-id=\"eaa617d3e76e2badd520573c6b3a482c2\"><p style=\"text-align:justify;\">English / Dutch speaking guide (as per availability)</p></li></ul>', '<ul><li data-list-item-id=\"ee3d3fda65e93a3a96ebb103fa8b52fcf\"><p style=\"text-align:justify;\">Domestic and international Flight ticket</p></li><li data-list-item-id=\"e495bcec76e8726f27ea2e347ef4bc2ee\"><p style=\"text-align:justify;\">Domestic and international airport tax</p></li><li data-list-item-id=\"e3c17c61adf328b3ffe6bba70596119ca\"><p style=\"text-align:justify;\">Lunch and Dinner</p></li><li data-list-item-id=\"e3e2b7d0fbac3a7d89a00de46e1212d7c\"><p style=\"text-align:justify;\">Guide and driver tip</p></li><li data-list-item-id=\"e393526e86fc95b6623bfa66aa0716647\"><p style=\"text-align:justify;\">Optional tour &amp; other personal expenses</p></li><li data-list-item-id=\"e07cc013b85b2fa91fe6f4203d6b2de85\"><p style=\"text-align:justify;\">Insurance</p></li></ul>', '<ul><li data-list-item-id=\"e34999afd6fe35acdc56e1f86af0bbb7d\"><p style=\"text-align:justify;\">The prices above are valid from immediately up to and including 20th December 2026 (not valid during New Year’s Eve 31 December until 02 January)&nbsp;&nbsp;</p></li><li data-list-item-id=\"e33a8ab063bc15054ea67ae6acd4a0c34\"><p style=\"text-align:justify;\">The prices above are subject to changes in case of significant increase in exchange rate or national fuel price.</p></li><li data-list-item-id=\"e1a525d2c8f798e1300c2c62f89311871\"><p style=\"text-align:justify;\">The itinerary above is flexible and subject to changes in case of extreme weather condition during the trip or any other force majeure.</p></li></ul>', '[\"Nature\",\"Culture\"]', NULL, 0, NULL, '2026-04-24 05:22:49', '2026-05-30 03:21:05'),
(16, 36, '3 DAYS LUWUK BANGGAI SCENIC ESCAPE', 'CENTRAL SULAWESI', '3-days-luwuk-banggai-scenic-escape', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Permata Tersembunyi Sulawesi: 3D2N Luwuk &amp; Banggai Scenic Escape</strong></h2><p style=\"text-align:justify;\">Bebaskan diri sejenak dari rutinitas dan temukan keajaiban alam yang belum terjamah di timur Sulawesi! Paket <strong>3D2N Luwuk &amp; Banggai Scenic Escape</strong> dirancang khusus untuk Anda yang mendambakan perpaduan sempurna antara petualangan air terjun yang menyegarkan, kejernihan danau yang magis, hingga romansa pemandangan kota dari ketinggian.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"e2346040b556d799e2cab6fcb5570e172\"><p style=\"text-align:justify;\"><strong>Keajaiban Air Terjun Bertingkat:</strong> Rasakan kesegaran alami di <strong>Air Terjun Piala</strong> yang memiliki formasi unik menyerupai tangga alami, dikelilingi rimbunnya hutan asri.</p></li><li data-list-item-id=\"ec2ca61c01a1806b389a9314c6fdf74f3\"><p style=\"text-align:justify;\"><strong>Kejernihan Kristal Danau Paisupok:</strong> Rasakan sensasi menaiki perahu di atas danau alami yang begitu jernih hingga Anda bisa melihat dasar danau dengan mata telanjang.</p></li><li data-list-item-id=\"e2a26d7ae600211211126e94804437281\"><p style=\"text-align:justify;\"><strong>Eksotisme Pantai Pasir Putih:</strong> Bersantai dan <i>snorkeling</i> di <strong>Pantai Poganda</strong>, surga tropis dengan pasir putih yang lembut dan air laut yang tenang.</p></li><li data-list-item-id=\"e48622ef6d218a6dbf85b69a9039a763e\"><p style=\"text-align:justify;\"><strong>City Light yang Memukau:</strong> Nikmati momen santai sore hari di <strong>Bukit Keles</strong> sambil menikmati kopi dan pisang goreng dengan latar belakang lampu kota Luwuk yang gemerlap.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover Sulawesi’s Hidden Gem: 3D2N Luwuk &amp; Banggai Scenic Escape</strong></h2><p style=\"text-align:justify;\">Escape the routine and uncover the untouched natural wonders of East Sulawesi! Our <strong>3D2N Luwuk &amp; Banggai Scenic Escape</strong> is meticulously crafted for those seeking a perfect blend of refreshing waterfalls, magical crystal-clear lakes, and romantic high-altitude city views.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights</strong></h3><ul><li data-list-item-id=\"e8c81a6f918fb95af1d2323eba2480950\"><p style=\"text-align:justify;\"><strong>The Majestic Tiered Waterfall:</strong> Experience the natural freshness of <strong>Piala Waterfall</strong>, a unique limestone formation resembling natural stairs surrounded by lush greenery.</p></li><li data-list-item-id=\"e666227e8a22b86533ea1cc3b7ba7a249\"><p style=\"text-align:justify;\"><strong>The Crystal Waters of Paisupok Lake:</strong> Feel the sensation of floating on <strong>Paisupok Lake</strong>, an enchanting natural lake so clear you can see the bottom with your bare eyes.</p></li><li data-list-item-id=\"e2c4f541aee40d0a77deb38a2c35b67ad\"><p style=\"text-align:justify;\"><strong>Exotic White Sand Beaches:</strong> Relax or go snorkeling at <strong>Poganda Beach</strong>, a tropical paradise featuring soft white sand and calm turquoise waters.</p></li><li data-list-item-id=\"ebd2de8b1b941b6f44e6ba7f0489baa6d\"><p style=\"text-align:justify;\"><strong>Mesmerizing City Lights:</strong> Enjoy a relaxing afternoon at <strong>Keles Hill</strong> with local snacks and coffee, overlooking the sparkling evening lights of Luwuk City.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>술라웨시의 숨겨진 보석: 3박 2일 루욱 &amp; 방가이 시닉 이스케이프</strong></h2><p style=\"text-align:justify;\">일상에서 벗어나 인도네시아 동부 술라웨시의 때묻지 않은 자연을 발견해보세요! <strong>3박 2일 루욱 &amp; 방가이 시닉 이스케이프</strong> 패키지는 시원한 폭포, 신비로운 에메랄드빛 호수, 그리고 낭만적인 도시의 야경을 모두 즐기고 싶은 분들을 위해 준비되었습니다.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트</strong></h3><ul><li data-list-item-id=\"eb3f5b8dbac576c292cfd7393213d2cdb\"><p style=\"text-align:justify;\"><strong>신비로운 계단식 폭포:</strong> 울창한 숲에 둘러싸인 천연 계단 모양의 피알라 폭포(Piala Waterfall)에서 자연의 상쾌함을 느껴보세요.</p></li><li data-list-item-id=\"ef31c336b01498cf113c0c83d6f2d860d\"><p style=\"text-align:justify;\"><strong>투명한 크리스탈, 파이수폭 호수:</strong> 바닥이 훤히 들여다보일 정도로 투명한 파이수폭 호수(Paisupok Lake)에서 마치 물 위를 떠다니는 듯한 마법 같은 경험을 선사합니다.</p></li><li data-list-item-id=\"ef6a83643f311d324dfbb04ece95896e1\"><p style=\"text-align:justify;\"><strong>이국적인 화이트 샌드 비치:</strong> 부드러운 백사장과 잔잔한 바다가 매력적인 포간다 해변(Poganda Beach)에서 휴식을 취하거나 스노클링을 즐겨보세요.</p></li><li data-list-item-id=\"e88eaef1bc676ce7909432cae60e6c9e2\"><p style=\"text-align:justify;\"><strong>황홀한 도시의 야경:</strong> 켈레스 언덕(Keles Hill)에서 현지 간식과 커피를 즐기며 루욱 시내의 반짝이는 야경을 감상해보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索苏拉威西的秘境：三天两夜 卢武克 &amp; 邦盖 绝美之旅</strong></h2><p style=\"text-align:justify;\">远离尘嚣，探索印尼东苏拉威西未遭破坏的自然奇观 ！我们的<strong>三天两夜 卢武克 &amp; 邦盖 绝美之旅 (3D2N Luwuk &amp; Banggai Scenic Escape)</strong> 为您完美结合了清爽的瀑布、梦幻的透明湖泊以及浪漫的高空城市夜景 。</p><h3 style=\"text-align:justify;\"><strong>行程亮点</strong></h3><ul><li data-list-item-id=\"e44ff2ada96d1a811e90d9e671587bfc2\"><p style=\"text-align:justify;\"><strong>壮观的阶梯瀑布：</strong> 在<strong>皮亚拉瀑布 (Piala Waterfall)</strong> 感受大自然的清新，其独特的天然阶梯构造被郁郁葱葱的绿意环绕 。</p></li><li data-list-item-id=\"e6f4cc6077a77c2957c64a1a5f259dee4\"><p style=\"text-align:justify;\"><strong>如水晶般清澈的派苏波湖：</strong> 在<strong>派苏波湖 (Paisupok Lake)</strong> 体验乘船的奇妙感觉，湖水清澈见底，宛如一块巨大的蓝色宝石 。</p></li><li data-list-item-id=\"ece4896862a9e7c3d70b2342e533bf443\"><p style=\"text-align:justify;\"><strong>异域风情的白沙滩：</strong> 在<strong>波甘达海滩 (Poganda Beach)</strong> 尽情放松或浮潜，享受洁白柔软的沙滩和宁静的碧蓝海水 。</p></li><li data-list-item-id=\"e42d2d081d1c4bc7b7dddcb2fef85057a\"><p style=\"text-align:justify;\"><strong>迷人的城市灯火：</strong> 傍晚时分前往<strong>凯莱斯山 (Keles Hill)</strong>，一边品尝当地咖啡和炸香蕉，一边俯瞰卢武克市璀璨的万家灯火 。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e06018fe8bb808857b24b7649182a50da\">Transportasi Full AC sesuai jumlah peserta</li><li data-list-item-id=\"e94cd85dd952503f3c8b8ec350f0ea3ba\">Open trip di hari ke 2</li><li data-list-item-id=\"ea77f626f0da5d3ed84be398d296e7717\">Hotel 2 malam di Luwuk – sekamar berdua</li><li data-list-item-id=\"ef89b9a99304ddec63ddb7ce23908a1d8\">Driver berpengalaman (driver cum guide)</li><li data-list-item-id=\"e1a5d0d2a0dbf5b35084f3600e793d103\">Tiket masuk objek wisata &amp; biaya parkir</li><li data-list-item-id=\"ebf48459f8193e18edf6c1b16f71b5c15\">Pelayanan makan sesuai program</li><li data-list-item-id=\"ed8fb9fec05f8197bfc0ce9ac10b76441\">Pelayanan tour sesuai program</li><li data-list-item-id=\"ead1e6042fde550aa19a4a5c37a4c43c0\">Air mineral 1 botol/pax/hari</li><li data-list-item-id=\"e03cec48869aab715059b47650d4185f6\">Handling service</li></ul>', '<ul><li data-list-item-id=\"e8f0f4a19eaea9b00168e2de5498b2239\">Tiket pesawat&nbsp;</li><li data-list-item-id=\"e11ed989b1f2a271a4f9a35c8235829e0\">Tipping driver</li><li data-list-item-id=\"e7be9806a0642c45efa13b306d1f995d1\">Optional tour</li><li data-list-item-id=\"e832b3029deece9f393048c0be3f63dc7\">Biaya diluar paket (tambahan makan/minum, dll)</li><li data-list-item-id=\"ec17f10ef45c702eda25f14dbe76d2c94\">Porter, airport tax &amp; kelebihan bagasi</li><li data-list-item-id=\"e7318441884dc36acab0e0d018f94113c\">Biaya pribadi (laundry, mini bar, layanan kamar,dll)</li><li data-list-item-id=\"eeff1ff30e7a612c8db3d4ae52e097c54\">Asuransi perjalanan</li><li data-list-item-id=\"e404136b9197dd517fa689c442da3a6f7\">Biaya-biaya lain nya diluar program tour</li></ul>', NULL, '[\"Nature\",\"Beach\",\"Photography\",\"Adventure\",\"Soft Trekking\",\"Local Experience\"]', NULL, 0, NULL, '2026-04-28 06:38:54', '2026-05-29 14:35:07'),
(17, 36, '4 DAYS LUWUK & BANGGAI HIDDEN ESCAPE', 'CENTRAL SULAWESI', '4-days-luwuk-banggai-hidden-escape', '<h2 style=\"text-align:justify;\"><strong>Temukan \"Surga yang Hilang\": Petualangan Magis 4 Hari di Kepulauan Banggai</strong></h2><p style=\"text-align:justify;\">Pernahkah Anda membayangkan berenang di danau yang airnya sebiru kristal, atau melihat ikan langka langsung di habitat aslinya? Paket <strong>4D3N Hidden Escape</strong> kami mengajak Anda menembus batas wisata biasa untuk menemukan keindahan tersembunyi di jantung Sulawesi.&nbsp;</p><h3 style=\"text-align:justify;\"><strong>Keajaiban yang Menanti Anda:</strong></h3><ul><li data-list-item-id=\"e1816fb86c5dfeec27911fa116f81d736\"><p style=\"text-align:justify;\"><strong>The Crystal Lake:</strong> Terpaku pada kejernihan <strong>Danau Paisupok</strong> yang legendaris, di mana perahu Anda tampak melayang di atas air.&nbsp;</p></li><li data-list-item-id=\"ef2bad4b71e8f20c2d1c2142200af8e1c\"><p style=\"text-align:justify;\"><strong>Marine Safari:</strong> Menjelajah dengan <i>speedboat</i> ke <strong>Pantai Bontolan</strong> untuk bertemu dengan <strong>Banggai Cardinal Fish</strong>, permata laut endemik yang hanya ada di wilayah ini.&nbsp;</p></li><li data-list-item-id=\"eb276943ce1028f8df91c47252e47993a\"><p style=\"text-align:justify;\"><strong>Island Hopping:</strong> Menelusuri garis pantai putih <strong>Pantai Pasir Panjang</strong> dan ketenangan <strong>Pantai Oyama</strong>.&nbsp;</p></li><li data-list-item-id=\"e146d5f79df473aa73fe1cfe567ee0918\"><p style=\"text-align:justify;\"><strong>Hidden Waterfall:</strong> Memulai petualangan di <strong>Air Terjun Piala</strong>, sebuah tangga alami di tengah hutan rimbun yang menyegarkan jiwa.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover \"The Lost Paradise\": A Magical 4-Day Journey to the Banggai Islands</strong></h2><p style=\"text-align:justify;\">Have you ever imagined swimming in a lake as blue as crystal, or seeing rare fish directly in their natural habitat? Our <strong>4D3N Hidden Escape</strong> package invites you to go beyond ordinary travel and discover the hidden beauty in the heart of Sulawesi.</p><h3 style=\"text-align:justify;\"><strong>Wonders Awaiting You:</strong></h3><ul><li data-list-item-id=\"ec208b0e95183f002c7547ba7eccbfcb5\"><p style=\"text-align:justify;\"><strong>The Crystal Lake:</strong> Be mesmerized by the legendary <strong>Paisupok Lake</strong>, where your boat appears to float on air due to its extraordinary clarity.</p></li><li data-list-item-id=\"e365966d8101e06def9c9dfdd639ec580\"><p style=\"text-align:justify;\"><strong>Marine Safari:</strong> Explore by speedboat to <strong>Bontolan Beach</strong> to meet the <strong>Banggai Cardinal Fish</strong>, a beautiful endemic sea gem found only in this region.</p></li><li data-list-item-id=\"e86a9955cc46486c840a8019c38877c08\"><p style=\"text-align:justify;\"><strong>Island Hopping:</strong> Trace the endless white shoreline of <strong>Pasir Panjang Beach</strong> and the tranquility of <strong>Oyama Beach</strong>.</p></li><li data-list-item-id=\"e729416652455b17e2ee62d2784f2bec5\"><p style=\"text-align:justify;\"><strong>Hidden Waterfall:</strong> Begin your adventure at <strong>Piala Waterfall</strong>, a natural staircase in the middle of a lush forest that refreshes the soul.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>제목: \"잃어버린 낙원\"을 찾아서: 방가이 제도로 떠나는 3박 4일간의 마법 같은 여정</strong></h2><p style=\"text-align:justify;\">크리스탈처럼 푸른 호수에서 수영하거나, 자연 서식지에서 직접 희귀한 물고기를 만나는 상상을 해보신 적이 있나요? <strong>3박 4일 히든 이스케이프</strong> 패키지는 일반적인 여행을 넘어 술라웨시 심장부에 숨겨진 아름다움을 발견하는 특별한 여정으로 여러분을 초대합니다.</p><h3 style=\"text-align:justify;\"><strong>여러분을 기다리는 놀라운 경험:</strong></h3><ul><li data-list-item-id=\"e40db5c828ffe5337ab957a17cefa245a\"><p style=\"text-align:justify;\"><strong>크리스탈 호수:</strong> 배가 마치 공중에 떠 있는 듯한 착각을 불러일으키는 전설적인 파이수폭 호수(Paisupok Lake)의 투명함에 매료되어 보세요.</p></li><li data-list-item-id=\"e7457a264f3fd9610f409015452d2aee7\"><p style=\"text-align:justify;\"><strong>마린 사파리:</strong> 스피드보트를 타고 본톨란 해변(Bontolan Beach)으로 이동하여 이 지역에서만 볼 수 있는 아름다운 희귀종인 방가이 카디널 피쉬(Banggai Cardinal Fish)를 만나보세요.</p></li><li data-list-item-id=\"ed775452e374b6575cfe3515588c7153b\"><p style=\"text-align:justify;\"><strong>아일랜드 호핑:</strong> 끝없이 펼쳐진 파시르 판장 해변(Pasir Panjang Beach)의 백사장과 평화로운 오야마 해변(Oyama Beach)을 탐험합니다.</p></li><li data-list-item-id=\"e84f1ce8d235d3b9c700edc6d71f71333\"><p style=\"text-align:justify;\"><strong>숨겨진 폭포:</strong> 울창한 숲속의 천연 계단과 같은 피알라 폭포(Piala Waterfall)에서 영혼까지 맑아지는 상쾌함으로 모험을 시작하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>标题：寻找“失落的天堂”：邦盖群岛四天三夜梦幻之旅</strong></h2><p style=\"text-align:justify;\">您是否曾幻想着在如水晶般湛蓝的湖泊中游泳，或者在自然栖息地亲眼目睹稀有鱼类？我们的<strong>四天三夜秘境之旅 (4D3N Hidden Escape)</strong> 诚邀您超越平凡的旅行，去探索苏拉威西中心地带隐藏的美丽 。</p><h3 style=\"text-align:justify;\"><strong>等待您的奇迹：</strong></h3><ul><li data-list-item-id=\"e965fdcf4033497c20bae291b2db7faab\"><p style=\"text-align:justify;\"><strong>水晶之湖：</strong> 陶醉在传奇的<strong>派苏波湖 (Paisupok Lake)</strong> 中，湖水清澈得让您的船只仿佛悬浮在空中 。</p></li><li data-list-item-id=\"e1d88abdd383af80fd06a17db5f3ebd74\"><p style=\"text-align:justify;\"><strong>海洋巡游：</strong> 乘坐快艇前往<strong>邦托兰海滩 (Bontolan Beach)</strong>，邂逅美丽的<strong>邦盖天竺鲷 (Banggai Cardinal Fish)</strong>，这是仅在该地区发现的珍稀原生海洋宝石 。</p></li><li data-list-item-id=\"e4f304a9c393fb10201fe2821eaa304b8\"><p style=\"text-align:justify;\"><strong>跳岛之旅：</strong> 漫步在<strong>长沙滩 (Pasir Panjang Beach)</strong> 无尽的白沙岸边，感受<strong>大山海滩 (Oyama Beach)</strong> 的宁静 。</p></li><li data-list-item-id=\"e93456859af00b257a197557a3f7816c3\"><p style=\"text-align:justify;\"><strong>秘境瀑布：</strong> 在<strong>皮亚拉瀑布 (Piala Waterfall)</strong> 开启您的冒险，这是茂密森林中的天然阶梯，让您的心灵焕然一新 。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e3a0a8575796f80b6d039258dfb88ddfb\">Transportasi Full AC sesuai jumlah peserta</li><li data-list-item-id=\"ef1ebfdad86af90945d3ce4bc2f95824c\">SpeedBoat ke Pulau/Pantai</li><li data-list-item-id=\"e69fd37b2a30158af89cd19215a1f0c03\">Tiket ferry dan kamar (based on availability)</li><li data-list-item-id=\"e47684155a867aa4d3d6d19b9040ecb9a\">Alat snorkeling di day 2 dan 3</li><li data-list-item-id=\"ebbe3a618a6eb0038ff264524be840d6a\">Penginapan 2 malam di Banggai Kepulauan – sekamar berdua</li><li data-list-item-id=\"e540312ce6865f4de06266de2ff6d4ccb\">Hotel 1 malam di Luwuk – sekamar berdua</li><li data-list-item-id=\"efae516a72ae8eb1e249076b70758f9bd\">Driver berpengalaman (driver cum guide)</li><li data-list-item-id=\"e700b007e05a9eddee70a8dd3028ad69a\">Tiket masuk objek wisata &amp; biaya parkir</li><li data-list-item-id=\"e89d90e973d029f74348e5017a9e2e115\">Pelayanan makan sesuai program</li><li data-list-item-id=\"e08f1bed959634fbee397ae7aa4cd9435\">Pelayanan tour sesuai program</li><li data-list-item-id=\"e39664dc7363f80e30998b8e8def03723\">Air mineral 1 botol/pax/hari</li><li data-list-item-id=\"efbb21969905fb1e1f8b10ac186bcb6ec\">Handling service</li></ul>', '<ul><li data-list-item-id=\"e8f0f4a19eaea9b00168e2de5498b2239\">Airline tickets&nbsp;</li><li data-list-item-id=\"e11ed989b1f2a271a4f9a35c8235829e0\">Tipping driver</li><li data-list-item-id=\"e7be9806a0642c45efa13b306d1f995d1\">Optional tour</li><li data-list-item-id=\"e832b3029deece9f393048c0be3f63dc7\">Costs outside the package (additional food/drink, etc.)</li><li data-list-item-id=\"ec17f10ef45c702eda25f14dbe76d2c94\">Porter, airport tax &amp; excess baggage</li><li data-list-item-id=\"e7318441884dc36acab0e0d018f94113c\">Personal expenses (laundry, mini bar, room service, etc.)</li><li data-list-item-id=\"eeff1ff30e7a612c8db3d4ae52e097c54\">Travel insurance</li><li data-list-item-id=\"e404136b9197dd517fa689c442da3a6f7\">Other costs outside the tour program</li></ul>', NULL, '[\"Nature\",\"Beach\",\"Adventure\",\"sNORKELING\",\"ISLAND HOPPING\"]', NULL, 0, NULL, '2026-04-28 07:14:40', '2026-05-29 14:34:20'),
(18, 36, '5 DAYS LUWUK & BANGGAI UNTOUCHED ISLANDS', 'CENTRAL SULAWESI', '5d4n-luwuk-banggai-untouched-islands', '<h2 style=\"text-align:justify;\"><strong>5 Days Banggai Untouched Islands: Liburan Impian di Tengah Kristal Biru Sulawesi</strong></h2><p style=\"text-align:justify;\">Siapkan gaun pantai, kamera, dan <i>drone</i> Anda untuk perjalanan ke destinasi paling estetik dan <i>Instagrammable</i> di Indonesia! Jadilah saksi keindahan \"Hidden Gems\" Banggai yang siap menghiasi galeri foto Anda.</p><ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4b28efcb951ce8bcc7ba0361746c56d9\"><h3 style=\"text-align:justify;\"><strong>Daftar Keindahan untuk Konten Anda:</strong></h3><ul><li data-list-item-id=\"ee5269a35a1a00646115c5bdfbfc598b7\"><p style=\"text-align:justify;\"><strong>[Must-Visit]</strong> Berfoto di atas perahu yang seolah melayang di <strong>Danau Paisupok</strong> yang jernih bak kristal.</p></li><li data-list-item-id=\"ec572b796f77cadfed3e1f357e279568e\"><p style=\"text-align:justify;\"><strong>[Marine Safari]</strong> Temukan keindahan <strong>Banggai Cardinal Fish</strong>, ikan endemik langka yang hanya ada di perairan ini, langsung di habitat aslinya di <strong>Pantai Bontolan</strong>.</p></li><li data-list-item-id=\"e4feca09d653c9c9ec6e37500da2380c3\"><p style=\"text-align:justify;\"><strong>[Beach Life]</strong> Nikmati pasir putih lembut dan air laut biru toska di <strong>Pantai Pasir Panjang</strong> dan <strong>Pantai Poganda</strong>.</p></li><li data-list-item-id=\"e42167e201d38811b8ffd9314909faeaf\"><p style=\"text-align:justify;\"><strong>[Nature Steps]</strong> Abadikan kesegaran <strong>Air Terjun Piala</strong> dengan formasi tangga alaminya yang unik.</p></li></ul></li></ul>', '<h2 style=\"text-align:justify;\"><strong>5 Days Banggai Untouched Islands: Your Dream Vacation Amidst Sulawesi’s Blue Crystals</strong></h2><p style=\"text-align:justify;\">Get your beach dresses, cameras, and drones ready for a journey to Indonesia’s most aesthetic and Instagrammable destination! Witness the beauty of Banggai’s \"Hidden Gems,\" ready to grace your photo gallery.</p><ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4317795d7e707e56fea9f32bb8bbb239\"><h3 style=\"text-align:justify;\"><strong>A Checklist of Beauty for Your Content:</strong></h3><ul><li data-list-item-id=\"e080b899cce8541dfbc9cbc5c8796bf32\"><p style=\"text-align:justify;\"><strong>[Must-Visit]</strong> Capture photos on a boat that appears to float atop the crystal-clear waters of <strong>Paisupok Lake</strong>.</p></li><li data-list-item-id=\"ea48dbbeb31937e7fb3d9811447395ba0\"><p style=\"text-align:justify;\"><strong>[Marine Safari]</strong> Discover the beauty of the <strong>Banggai Cardinal Fish</strong>, a rare endemic species, in its natural habitat at <strong>Bontolan Beach</strong>.</p></li><li data-list-item-id=\"e74c0d4aaabedf0fcd06890088936de4a\"><p style=\"text-align:justify;\"><strong>[Beach Life]</strong> Enjoy soft white sand and turquoise waters at <strong>Pasir Panjang Beach</strong> and <strong>Poganda Beach</strong>.</p></li><li data-list-item-id=\"e1fced3c89a686beaeda4ec225f153025\"><p style=\"text-align:justify;\"><strong>[Nature Steps]</strong> Document the refreshing <strong>Piala Waterfall</strong> with its unique natural tiered formations.</p></li></ul></li></ul>', '<h2 style=\"text-align:justify;\"><strong>제목: 4박 5일 방가이 언터치드 아일랜드: 술라웨시의 푸른 크리스탈 속 꿈같은 휴가</strong></h2><p style=\"text-align:justify;\">인도네시아에서 가장 미학적이고 인스타그래머블한 여행지로 떠날 준비를 하세요! 비치 드레스, 카메라, 드론을 챙겨 여러분의 갤러리를 화려하게 채울 방가이의 \"숨겨진 보석\"들을 직접 확인해보세요.</p><ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0a5fc6cf3b2a722744fbc78c761c321b\"><h3 style=\"text-align:justify;\"><strong>콘텐츠를 위한 뷰티 체크리스트:</strong></h3><ul><li data-list-item-id=\"eaf69532e0c14640b0853fff269ae1ca0\"><p style=\"text-align:justify;\"><strong>[필수 방문]</strong> 마치 공중에 떠 있는 듯한 착각을 주는 투명한 <strong>파이수폭 호수(Paisupok Lake)</strong> 위 보트에서 인생샷을 남겨보세요.</p></li><li data-list-item-id=\"ee65eff1e5944e0c0b630b63acabf1dfd\"><p style=\"text-align:justify;\"><strong>[마린 사파리]</strong> 본톨란 해변(Bontolan Beach)에서 이 지역에서만 볼 수 있는 희귀 토착 어종인 방가이 카디널 피쉬(Banggai Cardinal Fish)를 직접 만나보세요.</p></li><li data-list-item-id=\"ec6013f34e64464a83fb28f29db3dedbb\"><p style=\"text-align:justify;\"><strong>[비치 라이프]</strong> 파시르 판장 해변(Pasir Panjang Beach)과 포간다 해변(Poganda Beach)의 부드러운 백사장과 터키블루 빛 바다를 만끽하세요.</p></li><li data-list-item-id=\"e6a925573df78d87ed51268565308994f\"><p style=\"text-align:justify;\"><strong>[자연의 계단]</strong> 독특한 천연 계단식 지형이 매력적인 피알라 폭포(Piala Waterfall)의 상쾌함을 담아보세요.</p></li></ul></li></ul>', '<h2 style=\"text-align:justify;\"><strong>标题：五天四夜 邦盖纯净群岛之旅：苏拉威西蓝水晶之梦</strong></h2><p style=\"text-align:justify;\">准备好您的沙滩裙、相机和无人机，前往印尼最具美感、最适合拍照打卡的旅行地！亲眼见证邦盖“秘境宝藏”的魅力，让您的照片库焕发光彩 。</p><ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"eb7ca9f9d5a10cd204a915153f478040e\"><h3 style=\"text-align:justify;\"><strong>为您的自媒体内容打造的景观清单：</strong></h3><ul><li data-list-item-id=\"e0dc682cbf0772e9df87b5c9b28e0ca91\"><p style=\"text-align:justify;\"><strong>[必打卡景点]</strong> 在清澈如镜的<strong>派苏波湖 (Paisupok Lake)</strong> 上捕捉仿佛悬浮在空中的小船倩影 。</p></li><li data-list-item-id=\"e22ff62a035e9b0387aa4126048f96af8\"><p style=\"text-align:justify;\"><strong>[海洋巡游]</strong> 在<strong>邦托兰海滩 (Bontolan Beach)</strong> 邂逅美丽的<strong>邦盖天竺鲷 (Banggai Cardinal Fish)</strong>，亲眼目睹这一稀有原生海洋宝石 。</p></li><li data-list-item-id=\"eec4da1e9143b28d824602ec8f3905c0c\"><p style=\"text-align:justify;\"><strong>[海滩生活]</strong> 在<strong>长沙滩 (Pasir Panjang Beach)</strong> 和<strong>波甘达海滩 (Poganda Beach)</strong> 享受洁白柔软的沙滩和如绿松石般的海水 。</p></li><li data-list-item-id=\"e0c1f46025bec02cfe94467b4cd18df63\"><p style=\"text-align:justify;\"><strong>[自然之阶]</strong> 定格具有独特天然阶梯构造的<strong>皮亚拉瀑布 (Piala Waterfall)</strong> 的清爽瞬间 。</p></li></ul></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"ef1e74740734f56627f8c6d5bd97edb77\">Transportasi Full AC sesuai jumlah peserta</li><li data-list-item-id=\"e45a1d95a497f3dfb83f15bb1400a9675\">SpeedBoat ke Pulau/Pantai</li><li data-list-item-id=\"e14e1802422cf38de4b55ad8d1958f5d9\">Tiket ferry dan kamar (based on availability)</li><li data-list-item-id=\"ed9ed8d06b1f02599a23cb81767548edf\">Alat snorkeling di day 2, 3 dan 4</li><li data-list-item-id=\"e577c1cf7c6ea46b8088f2cd99cae6739\">Penginapan 3 malam di Banggai Kepulauan – sekamar berdua</li><li data-list-item-id=\"e902d58fe892ced5fd4b99ee184752551\">Hotel 1 malam di Luwuk – sekamar berdua</li><li data-list-item-id=\"eae43de239f290b82652a1bfc0a9cadd2\">Driver berpengalaman (driver cum guide)</li><li data-list-item-id=\"e1f16b050d797edd42d39649b99a4cefe\">Tiket masuk objek wisata &amp; biaya parkir</li><li data-list-item-id=\"ea959325e2db8c53f0781f118bb50bf18\">Pelayanan makan sesuai program</li><li data-list-item-id=\"e8192cfdb4780a9b2c4ade42282746e12\">Pelayanan tour sesuai program</li><li data-list-item-id=\"e6948417e6e1d96b079eec65efade3128\">Air mineral 1 botol/pax/hari</li><li data-list-item-id=\"ebf431e19c094870cc6a7460676e49ba7\">Handling service</li></ul>', '<ul><li data-list-item-id=\"e8f0f4a19eaea9b00168e2de5498b2239\">Airline tickets&nbsp;</li><li data-list-item-id=\"e11ed989b1f2a271a4f9a35c8235829e0\">Tipping driver</li><li data-list-item-id=\"e7be9806a0642c45efa13b306d1f995d1\">Optional tour</li><li data-list-item-id=\"e832b3029deece9f393048c0be3f63dc7\">Costs outside the package (additional food/drink, etc.)</li><li data-list-item-id=\"ec17f10ef45c702eda25f14dbe76d2c94\">Porter, airport tax &amp; excess baggage</li><li data-list-item-id=\"e7318441884dc36acab0e0d018f94113c\">Personal expenses (laundry, mini bar, room service, etc.)</li><li data-list-item-id=\"eeff1ff30e7a612c8db3d4ae52e097c54\">Travel insurance</li><li data-list-item-id=\"e404136b9197dd517fa689c442da3a6f7\">Other costs outside the tour program</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"Beach\",\"snorkeling\"]', NULL, 1, 'hot', '2026-04-28 07:49:21', '2026-06-01 15:22:58'),
(19, 36, '6 DAYS LUWUK & BANGGAI ISLAND DISCOVERY', 'CENTRAL SULAWESI', '6-days-luwuk-banggai-island-discovery', '<h2 style=\"text-align:justify;\"><strong>Mahakarya Indonesia Timur: 6D5N Luwuk &amp; Banggai Island Discovery</strong></h2><p style=\"text-align:justify;\">Jelajahi keindahan yang tak terbatas dalam ekspedisi terlengkap kami melintasi Kepulauan Banggai. Paket <strong>6D5N Island Discovery</strong> adalah sebuah perjalanan mendalam bagi Anda yang ingin benar-benar \"menghilang\" dalam kemurnian alam Sulawesi yang belum terjamah. Dari danau kristal yang ajaib hingga bukit-bukit hijau yang menenangkan, setiap hari adalah penemuan baru.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Paket Ini Adalah Pilihan Terbaik?</strong></h3><ul><li data-list-item-id=\"e312a5c440cf0c248751c048f99f693dd\"><p style=\"text-align:justify;\"><strong>[The Ultimate Mirror Lake]</strong> Rasakan sensasi perahu melayang di atas <strong>Danau Paisupok</strong>, danau legendaris dengan air yang begitu transparan hingga setiap detail dasarnya terlihat jelas.</p></li><li data-list-item-id=\"e842d3236f093d5a9c3c261863809ec4f\"><p style=\"text-align:justify;\"><strong>[Marine Safari &amp; Biodiversity]</strong> Berenang bersama ikan endemik <strong>Banggai Cardinal Fish</strong> di habitat aslinya di Pantai Bontolan dan nikmati keindahan bawah laut di Kawalu Bay &amp; Ndulubas.</p></li><li data-list-item-id=\"e1298d95df161f9518cf512f49b98c8e5\"><p style=\"text-align:justify;\"><strong>[Tropical Paradise Hopping]</strong> Penjelajahan pantai tanpa henti; mulai dari pasir putih <strong>Pantai Pasir Panjang</strong>, ketenangan <strong>Pantai Oyama</strong>, hingga eksotisme <strong>Pulau Dua Balantak</strong>.</p></li><li data-list-item-id=\"e04a648d71eb50f2d84c9aec95e4f44c9\"><p style=\"text-align:justify;\"><strong>[Nature &amp; City Panorama]</strong> Nikmati perpaduan kesegaran <strong>Air Terjun Piala</strong> yang bertingkat dan romansa pemandangan lampu kota dari ketinggian <strong>Bukit Keles</strong>.</p></li></ul><p style=\"text-align:justify;\"><strong>Jadilah bagian dari sedikit orang yang menyaksikan keajaiban Banggai secara utuh!</strong> <strong>Siapkan kamera, drone, dan semangat petualang Anda.</strong></p>', '<h2 style=\"text-align:justify;\"><strong>The Masterpiece of East Indonesia: 6D5N Luwuk &amp; Banggai Island Discovery</strong></h2><p style=\"text-align:justify;\">Explore boundless beauty in our most comprehensive expedition across the Banggai Islands. The <strong>6D5N Island Discovery</strong> is an immersive journey for those who seek to truly \"disappear\" into the untouched purity of Sulawesi’s nature. From magical crystal lakes to soothing green hills, every day brings a new discovery.</p><h3 style=\"text-align:justify;\"><strong>Why is this package your best choice?</strong></h3><ul><li data-list-item-id=\"e8b08b7ff54b1a19da13e2dfac8c17228\"><p style=\"text-align:justify;\"><strong>[The Ultimate Mirror Lake]</strong> Experience the sensation of floating on air at <strong>Paisupok Lake</strong>, a legendary lake with water so transparent that every detail of the lake floor is crystal clear.</p></li><li data-list-item-id=\"e6d54836d9f5c581119e2b6a8f4a12c8b\"><p style=\"text-align:justify;\"><strong>[Marine Safari &amp; Biodiversity]</strong> Swim with the endemic <strong>Banggai Cardinal Fish</strong> in its natural habitat at Bontolan Beach and enjoy the stunning underwater world of <strong>Kawalu Bay &amp; Ndulubas</strong>.</p></li><li data-list-item-id=\"e735b129316af2cdc5cd873fda346b3d1\"><p style=\"text-align:justify;\"><strong>[Tropical Paradise Hopping]</strong> Endless beach exploration; from the white sands of <strong>Pasir Panjang Beach</strong> and the tranquility of <strong>Oyama Beach</strong> to the exotic charm of <strong>Pulau Dua Balantak</strong>.</p></li><li data-list-item-id=\"edfa6f122a2943bf1bcda0067cd138344\"><p style=\"text-align:justify;\"><strong>[Nature &amp; City Panorama]</strong> Enjoy a blend of the refreshing tiered <strong>Piala Waterfall</strong> and the romantic city lights viewed from the heights of <strong>Keles Hill</strong>.</p></li></ul><p style=\"text-align:justify;\"><strong>Be among the few to witness the wonders of Banggai in their entirety! Prepare your camera, drone, and adventurous spirit.</strong></p>', '<h2 style=\"text-align:justify;\"><strong>동부 인도네시아의 걸작: 5박 6일 루욱 &amp; 방가이 아일랜드 디스커버리</strong></h2><p style=\"text-align:justify;\">방가이 제도를 가로지르는 가장 완벽한 탐험을 통해 끝없는 아름다움을 발견해 보세요. <strong>5박 6일 아일랜드 디스커버리</strong> 패키지는 때 묻지 않은 술라웨시의 자연 속으로 진정한 ‘숨바꼭질’을 원하는 분들을 위한 심층 여행입니다. 마법 같은 크리스탈 호수부터 마음을 차분하게 해주는 푸른 언덕까지, 매일이 새로운 발견의 연속입니다.</p><h3 style=\"text-align:justify;\"><strong>이 패키지가 최고의 선택인 이유는 무엇일까요?</strong></h3><ul><li data-list-item-id=\"e00548ea4a46f4633cb090b1dc7832e44\"><p style=\"text-align:justify;\"><strong>[究極의 거울 호수]</strong> 바닥의 모든 디테일이 선명하게 보일 정도로 투명한 물을 자랑하는 전설적인 <strong>파이수폭 호수(Paisupok Lake)</strong> 위에서 배가 공중에 떠 있는 듯한 신비로운 감각을 경험해 보세요.</p></li><li data-list-item-id=\"eb6f43906f7cf62cdb0f00ce42be30bf5\"><p style=\"text-align:justify;\"><strong>[마린 사파리 &amp; 생물 다양성]</strong> 본톨란 해변(Bontolan Beach)의 자연 서식지에서 희귀 토착 어종인 방가이 카디널 피쉬(Banggai Cardinal Fish)와 함께 수영하고, 카왈루 베이 &amp; 은둘루바스(Kawalu Bay &amp; Ndulubas)의 환상적인 수중 세계를 만끽하세요.</p></li><li data-list-item-id=\"e334d964f2fd4f455a7bde2131e5ec3aa\"><p style=\"text-align:justify;\"><strong>[트로피컬 파라다이스 호핑]</strong> 파시르 판장(Pasir Panjang)의 백사장, 오야마 해변(Oyama Beach)의 평온함, 그리고 풀라우 두아 발란탁(Pulau Dua Balantak)의 이국적인 매력까지, 끝없는 해변 탐험이 이어집니다.</p></li><li data-list-item-id=\"e66111940a19cae45c5e0c086935381fe\"><p style=\"text-align:justify;\"><strong>[자연과 도시의 파노라마]</strong> 계단식으로 떨어지는 상쾌한 피알라 폭포(Piala Waterfall)와 <strong>켈레스 언덕(Keles Hill)</strong> 정상에서 내려다보는 낭만적인 도시의 야경을 동시에 즐겨보세요.</p></li></ul><p style=\"text-align:justify;\"><strong>방가이의 기적을 온전히 목격하는 소수의 주인공이 되어보세요! 카메라, 드론, 그리고 모험심만 준비하시면 됩니다.</strong></p>', '<h2 style=\"text-align:justify;\"><strong>印尼东部的杰作：六天五夜 卢武克 &amp; 邦盖群岛探索之旅</strong></h2><p style=\"text-align:justify;\">加入我们最详尽的邦盖群岛探险之旅，探索无限之美。<strong>六天五夜群岛探索之旅</strong>专为渴望真正“消失”在苏拉威西原始自然中的游客而设计。从梦幻的水晶湖泊到令人心旷神怡的翠绿山峦，每一天都是全新的发现。</p><h3 style=\"text-align:justify;\"><strong>为什么这个行程是您的最佳选择？</strong></h3><ul><li data-list-item-id=\"e935a6e38b7ff54a345b951f7004432b9\"><p style=\"text-align:justify;\"><strong>[极致天空之镜]</strong> 在传奇的<strong>派苏波湖 (Paisupok Lake)</strong> 体验小船仿佛悬浮在空中的奇妙感，湖水清澈透明，湖底的每一处细节都清晰可见。</p></li><li data-list-item-id=\"ebd2da66a2ae2c861d1092f01ac6a7ad5\"><p style=\"text-align:justify;\"><strong>[海洋巡游与生物多样性]</strong> 在<strong>邦托兰海滩 (Bontolan Beach)</strong> 的自然栖息地与特有的<strong>邦盖天竺鲷 (Banggai Cardinal Fish)</strong> 一起游泳，并尽情享受<strong>卡瓦鲁湾 (Kawalu Bay)</strong> 和<strong>恩杜鲁巴斯 (Ndulubas)</strong> 迷人的水下世界。</p></li><li data-list-item-id=\"e1f37251e25b086a278abf4a016d4e206\"><p style=\"text-align:justify;\"><strong>[热带天堂跳岛游]</strong> 永无止境的海滩探索：从<strong>长沙滩 (Pasir Panjang Beach)</strong> 的洁白沙滩、<strong>大山海滩 (Oyama Beach)</strong> 的宁静，到<strong>布劳双岛 (Pulau Dua Balantak)</strong> 的异国风情。</p></li><li data-list-item-id=\"efa8543034bba6150a89318e2962a0381\"><p style=\"text-align:justify;\"><strong>[自然与城市全景]</strong> 感受层叠式<strong>皮亚拉瀑布 (Piala Waterfall)</strong> 的清爽，并从<strong>凯莱斯山 (Keles Hill)</strong> 高处欣赏浪漫迷人的城市灯火。</p></li></ul><p style=\"text-align:justify;\"><strong>成为少数能完整见证邦盖奇迹的幸运儿之一！准备好您的相机、无人机和探险精神，出发吧！</strong></p>', 0.00, NULL, 6, 5, NULL, NULL, '<ul><li data-list-item-id=\"ed92a517e5fe6a279c37092c8b66e317d\">Transportasi Full AC sesuai jumlah peserta</li><li data-list-item-id=\"e02d235444d7baf0562fe26c6aa256040\">SpeedBoat ke Pulau/Pantai</li><li data-list-item-id=\"eca761be6b74dcf970066177ca7166737\">Tiket ferry dan kamar (based on availability)</li><li data-list-item-id=\"e973b45e23e562ebfb9576a90461efd4a\">Alat snorkeling di day 2, 3 dan 4</li><li data-list-item-id=\"e61d2d2159fc81443fae9ce22d3f54167\">Penginapan 3 malam di Banggai Kepulauan – sekamar berdua</li><li data-list-item-id=\"e8085cac7ddf617e013ad836e7d41373d\">Hotel 2 malam di Luwuk – sekamar berdua</li><li data-list-item-id=\"e92a968aea36a6b568975251a5067fdb0\">Driver berpengalaman (driver cum guide)</li><li data-list-item-id=\"e4cf0b26679d32b3a753549908c24526c\">Tiket masuk objek wisata &amp; biaya parkir</li><li data-list-item-id=\"e58815371b036baccad536aa2af210abc\">Pelayanan makan sesuai program</li><li data-list-item-id=\"e5e678441f0e0b78bbabba0382c51a28a\">Pelayanan tour sesuai program</li><li data-list-item-id=\"e87e17d5b4bcd423cd959127440fb0e87\">Air mineral 1 botol/pax/hari</li><li data-list-item-id=\"eb27a761a8dd6d50809c957b91db867e0\">Handling service</li></ul>', '<ul><li data-list-item-id=\"e8f0f4a19eaea9b00168e2de5498b2239\">Airline tickets&nbsp;</li><li data-list-item-id=\"e11ed989b1f2a271a4f9a35c8235829e0\">Tipping driver</li><li data-list-item-id=\"e7be9806a0642c45efa13b306d1f995d1\">Optional tour</li><li data-list-item-id=\"e832b3029deece9f393048c0be3f63dc7\">Costs outside the package (additional food/drink, etc.)</li><li data-list-item-id=\"ec17f10ef45c702eda25f14dbe76d2c94\">Porter, airport tax &amp; excess baggage</li><li data-list-item-id=\"e7318441884dc36acab0e0d018f94113c\">Personal expenses (laundry, mini bar, room service, etc.)</li><li data-list-item-id=\"eeff1ff30e7a612c8db3d4ae52e097c54\">Travel insurance</li><li data-list-item-id=\"e404136b9197dd517fa689c442da3a6f7\">Other costs outside the tour program</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"Beach\",\"snorkeling\",\"Soft Trekking\"]', NULL, 0, NULL, '2026-04-28 08:18:03', '2026-05-29 14:32:58');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(20, 37, '3 DAYS JOGJA CULTURE TOUR', 'YOGYAKARTA', '3-days-jogja-culture-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Budaya Jawa: 3D2N Jogja Culture Tour</strong></h2><p style=\"text-align:justify;\">Nikmati perjalanan mendalam ke pusat sejarah dan seni Indonesia melalui paket <strong>3D2N Jogja Culture</strong>. Dari kemegahan candi Buddha terbesar di dunia hingga kehidupan istana yang masih terjaga keasliannya, kami mengajak Anda menyelami kekayaan tradisi Yogyakarta dalam kenyamanan penuh.</p><h3 style=\"text-align:justify;\"><strong>Sorotan Perjalanan:</strong></h3><ul><li data-list-item-id=\"ed5758aee34942a4557996b917aa68b6a\"><p style=\"text-align:justify;\"><strong>Keajaiban Dunia di Tangan Anda:</strong> Kunjungi struktur megah <strong>Candi Borobudur</strong> (Warisan Dunia UNESCO) hingga lantai strukturnya, serta eksplorasi misteri di Candi Mendut dan Pawon.</p></li><li data-list-item-id=\"eba887481951f13fcb2ec49b186fd9bb3\"><p style=\"text-align:justify;\"><strong>Jejak Sejarah Dinasti:</strong> Masuk ke dalam <strong>Keraton (Sultan Palace)</strong> untuk melihat langsung tata krama kuno yang masih dipraktikkan, serta keindahan arsitektur <strong>Taman Sari Watercastle</strong>.</p></li><li data-list-item-id=\"ef2afb00938add75579fc28f7917cfa13\"><p style=\"text-align:justify;\"><strong>Mahakarya Hindu Terbesar:</strong> Terpukau oleh kemegahan <strong>Candi Prambanan</strong>, kompleks candi pemujaan Dewa Siwa terbesar di Indonesia yang dibangun pada abad ke-10.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover the Heart of Javanese Heritage: 3D2N Jogja Culture Tour</strong></h2><p style=\"text-align:justify;\">Immerse yourself in the profound history and artistic soul of Indonesia with our <strong>3D2N Jogja Culture</strong> package. From the world’s largest Buddhist monument to the living traditions of the Sultan’s palace, we invite you to explore Yogyakarta’s rich heritage in total comfort.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights:</strong></h3><ul><li data-list-item-id=\"e8b3693d9807a0d2f1c93e4243b4fb52c\"><p style=\"text-align:justify;\"><strong>A World Wonder at Your Feet:</strong> Explore the majestic <strong>Borobudur Temple</strong> (a UNESCO World Heritage Site) up to its structural floors.</p></li><li data-list-item-id=\"eda5cdd541a24e6c5801d98e86dfbf4c0\"><p style=\"text-align:justify;\"><strong>Ancient Mysteries:</strong> Discover the stories carved into the walls of Mendut Temple and the sacred Pawon Temple.</p></li><li data-list-item-id=\"e5d6c237f6f16986255c5bbc0e45cf42d\"><p style=\"text-align:justify;\"><strong>Royal Legacy:</strong> Visit the <strong>Sultan Palace (Kraton)</strong>, where centuries-old customs are still practiced today.</p></li><li data-list-item-id=\"ef27695380ecd041dfd17aafba9ebe6ae\"><p style=\"text-align:justify;\"><strong>The Sultan\'s Oasis:</strong> Wander through <strong>Taman Sari Watercastle</strong>, the historic royal recreation garden and bathing pools.</p></li><li data-list-item-id=\"ee7ef63334f78dbc4fdf152196845ed01\"><p style=\"text-align:justify;\"><strong>Grand Hindu Architecture:</strong> Marvel at <strong>Prambanan Temple</strong>, the largest temple compound dedicated to Shiva in Indonesia.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>자바 문화의 심장을 만나다: 3D2N 조그자 문화 투어 (Jogja Culture Tour)</strong></h2><p style=\"text-align:justify;\"><strong>3D2N Jogja Culture</strong> 패키지를 통해 인네도네시아의 깊은 역사와 예술적 영혼에 빠져보세요. 세계 최대의 불교 사원부터 오늘날까지 살아 숨 쉬는 왕실의 전통까지, 요그야카르타의 풍요로운 유산을 가장 편안하게 안내해 드립니다.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트:</strong></h3><ul><li data-list-item-id=\"e7e4bd36f0b00f3a03efe873e579218ba\"><p style=\"text-align:justify;\"><strong>세계 7대 불가사의:</strong> 유네스코 세계문화유산인 <strong>보로부두르 사원</strong>의 상층부까지 직접 올라가 그 웅장함을 느껴보세요.</p></li><li data-list-item-id=\"ed7118622861039b418a61cb117cf11c7\"><p style=\"text-align:justify;\"><strong>고대의 신비:</strong> 섬세한 조각이 살아있는 문두트 사원과 파원 사원을 탐방합니다.</p></li><li data-list-item-id=\"ecf137aa5c78b19d516d2cc0e23bd2e05\"><p style=\"text-align:justify;\"><strong>살아있는 왕실 역사:</strong> 인도네시아 최고의 권위를 자랑하는 술탄 궁전(Kraton)에서 고귀한 전통 의식을 관람하세요.</p></li><li data-list-item-id=\"ed94654ac31e2ed435644a7cf1880e638\"><p style=\"text-align:justify;\"><strong>왕실의 비밀 정원:</strong> 왕과 후궁들의 휴식처였던 아름다운 <strong>타만 사리(Taman Sari) 물의 궁전</strong>을 방문합니다.</p></li><li data-list-item-id=\"e380bc3d226b10719d2b7334601e3fd06\"><p style=\"text-align:justify;\"><strong>힌두교의 정수:</strong> 10세기에 건축된 인도네시아 최대 규모의 힌두 사원인 <strong>프람바난 사원</strong>을 감상하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索爪哇文化之魂：3D2N 日惹文化之旅</strong></h2><p style=\"text-align:justify;\">通过我们的 <strong>3D2N Jogja Culture</strong> 套餐，带您深入领略印度尼西亚的历史底蕴与艺术魅力。从全球最大的佛教遗迹到依然保留传统皇室生活的苏丹王宫，我们将为您开启一场舒适且深刻的文化盛宴。</p><h3 style=\"text-align:justify;\"><strong>行程亮点：</strong></h3><ul><li data-list-item-id=\"e402b3cbc599628bbb5539e73910debe9\"><p style=\"text-align:justify;\"><strong>世界奇迹近在咫尺：</strong> 登上联合国教科文组织世界遗产 —— <strong>婆罗浮屠大寺 (Borobudur)</strong>，亲历其宏伟的建筑结构。</p></li><li data-list-item-id=\"ee223647eef06e15cda48743f27609865\"><p style=\"text-align:justify;\"><strong>探寻古老奥秘：</strong> 参观比婆罗浮屠更古老的门杜寺 (Mendut) 及神秘的巴翁寺 (Pawon)。</p></li><li data-list-item-id=\"e364142d9454a3da779803d9c845599f6\"><p style=\"text-align:justify;\"><strong>皇室传统见证：</strong> 走进<strong>苏丹王宫 (Kraton)</strong>，感受至今仍在传承的古老宫廷礼仪。</p></li><li data-list-item-id=\"e45753df71b1fcc7f5188bf82ec4108d2\"><p style=\"text-align:justify;\"><strong>苏丹的水上乐园：</strong> 游览<strong>水城 (Taman Sari)</strong>，这曾是苏丹皇室休闲与沐浴的秘密花园。</p></li><li data-list-item-id=\"e01c820114b02ac39a0ee7af9cbb91219\"><p style=\"text-align:justify;\"><strong>印度教建筑瑰宝：</strong> 震撼于建于10世纪的<strong>普兰巴南神庙 (Prambanan)</strong>，这是印尼最大的湿婆神庙群。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transport</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel based on TWN/TRP</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Entrance Fee &amp; Parking</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">English Speaking Guide</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Meals as program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\"><p>Mineral water</p><p>&nbsp;</p></li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Flight ticket &amp; Train</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expense</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tour and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Surcharge at high season and National holiday</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Educational\",\"City\"]', NULL, 0, NULL, '2026-04-29 11:55:46', '2026-05-29 14:26:22'),
(21, 37, '3 DAYS JOGJA INSTAGRAMABLE', 'YOGYAKARTA', '3-days-jogja-instagramable', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Sisi Estetik Yogyakarta: Paket 3 Days Jogja Instagramable</strong></h2><p style=\"text-align:justify;\">Siapkan kamera dan gaya terbaik Anda! Yogyakarta bukan hanya tentang sejarah, tapi juga tentang sudut-sudut visual yang memukau mata dunia. Dalam paket <strong>3D2N Jogja Instagramable</strong>, kami mengkurasi destinasi paling tren dan <i>aesthetic</i> untuk memastikan <i>feed</i> media sosial Anda tampil luar biasa.</p><h3 style=\"text-align:justify;\"><strong>Highlight Perjalanan: Dari Samudera hingga Puncak Gunung</strong></h3><ul><li data-list-item-id=\"e3956eb380ddc6aefd040af9eeb5e4a9f\"><p style=\"text-align:justify;\"><strong>Keajaiban Alam Langka:</strong> Kunjungi <strong>Gumuk Pasir</strong>, fenomena padang pasir unik hasil sedimentasi Gunung Merapi yang hanya ada sedikit di dunia.</p></li><li data-list-item-id=\"eb7f4f914629bceb912a54bec86e6d041\"><p style=\"text-align:justify;\"><strong>Sunset di Atas Samudera:</strong> Nikmati momen matahari terbenam yang romantis di <strong>Obelix Seaview</strong> dengan panorama Samudera Hindia yang luas.</p></li><li data-list-item-id=\"ef975d21041718210b10c72e71521e4a5\"><p style=\"text-align:justify;\"><strong>Petualangan Jeep Merapi:</strong> Rasakan sensasi <strong>Lava Tour</strong> menggunakan Jeep 4x4 melintasi museum sisa erupsi, \"batu alien\", dan bunker yang ikonik.</p></li><li data-list-item-id=\"e557255ff250a20bc6b48b9c88a977eb5\"><p style=\"text-align:justify;\"><strong>Spot Foto Kekinian:</strong> Eksplorasi <strong>Pictniq Land Jogja</strong>, destinasi terbaru yang dirancang khusus untuk pecinta foto Instagramable.</p></li><li data-list-item-id=\"e75f217584e5bd082ffbd538ce36e44e4\"><p style=\"text-align:justify;\"><strong>Ikon Kota Yogyakarta:</strong> Belanja sepuasnya dan tangkap suasana khas malam hari di jalan legendaris, <strong>Malioboro</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Capture Your Best Moments: 3D2N Jogja Instagramable Tour</strong></h2><p style=\"text-align:justify;\">Get your cameras and best outfits ready! Yogyakarta is more than just history; it’s a paradise of stunning visual spots. With our <strong>3D2N Jogja Instagramable</strong> package, we’ve curated the trendiest and most aesthetic destinations to ensure your social media feed looks spectacular.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights:</strong></h3><ul><li data-list-item-id=\"e7c4ce8c515c0fe26432bdb22fc94c37c\"><p style=\"text-align:justify;\"><strong>Rare Natural Phenomenon:</strong> Visit the <strong>Gumuk Pasir</strong> sand dunes, a unique desert-like landscape formed by Merapi’s volcanic ash.</p></li><li data-list-item-id=\"e9e937bab0ff45a29bb5c6a9a82b491b0\"><p style=\"text-align:justify;\"><strong>Sunset by the Ocean:</strong> Experience a romantic golden hour at <strong>Obelix Seaview</strong>, offering a breathtaking panorama of the Indian Ocean.</p></li><li data-list-item-id=\"e2c35b48a7a46553900f868fb9732f57a\"><p style=\"text-align:justify;\"><strong>Merapi Jeep Adventure:</strong> Feel the adrenaline on a <strong>Lava Tour</strong> in a 4x4 Jeep, visiting the eruption museum, \"Alien Stone,\" and historic bunkers.</p></li><li data-list-item-id=\"ebd3f4bbef8c15809faff616c4886a954\"><p style=\"text-align:justify;\"><strong>Aesthetic Hotspot:</strong> Explore <strong>Pictniq Land Jogja</strong>, the newest destination designed specifically for photography lovers.</p></li><li data-list-item-id=\"e1dd19a2a63cfaf1727f2fb4e6fc823de\"><p style=\"text-align:justify;\"><strong>Iconic City Vibes:</strong> Enjoy a shopping spree and capture the legendary atmosphere of <strong>Malioboro Street</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>인생샷 보장: 3D2N 조그자 인스타그램 투어 (Jogja Instagramable)</strong></h2><p style=\"text-align:justify;\">카메라와 멋진 의상을 준비하세요! 요그야카르타는 단순한 역사 도시가 아니라, 세계가 주목하는 비주얼 맛집입니다. <strong>3D2N Jogja Instagramable</strong> 패키지는 당신의 SNS 피드를 화려하게 장식할 가장 트렌디하고 미학적인 장소들로 구성되었습니다.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트:</strong></h3><ul><li data-list-item-id=\"e30c5fc80511118331acd3a3f85c3ed6a\"><p style=\"text-align:justify;\"><strong>희귀한 자연 현상:</strong> 메라피 화산의 화산재가 만들어낸 세계적으로 희귀한 사구 지형, 구묵 파시르(Gumuk Pasir)를 방문합니다.</p></li><li data-list-item-id=\"e02839bd7aca40da0ea41f7e57b8a523a\"><p style=\"text-align:justify;\"><strong>대양의 일몰:</strong> 인도양의 탁 트인 파노라마 뷰를 자랑하는 오벨릭스 씨뷰(Obelix Seaview)에서 로맨틱한 선셋을 즐겨보세요.</p></li><li data-list-item-id=\"e99f6d30c1807bcde4c4de2ad06d156fd\"><p style=\"text-align:justify;\"><strong>메라피 지프 어드벤처:</strong> 4x4 지프를 타고 라바 투어(Lava Tour)를 즐기며 화산 박물관, \'외계인 바위\', 벙커를 탐험합니다.</p></li><li data-list-item-id=\"ea4a7f298ce522625794b470f5a11426b\"><p style=\"text-align:justify;\"><strong>신상 핫플레이스:</strong> 사진 애호가들을 위해 설계된 조그자의 최신 명소 픽닉 랜드(Pictniq Land)를 탐방합니다.</p></li><li data-list-item-id=\"e2cd43dcf98b7dcb5c04fdf3be82f274b\"><p style=\"text-align:justify;\"><strong>조그자의 상징:</strong> 활기찬 <strong>말리오보로(Malioboro)</strong> 거리에서 쇼핑을 즐기고 조그자의 밤을 사진에 담아보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>定格最美瞬间：3D2N 日惹网红打卡之旅</strong></h2><p style=\"text-align:justify;\">准备好您的相机和穿搭！日惹不仅有深厚的历史，更有令人惊叹的视觉魅力。通过 <strong>3D2N Jogja Instagramable</strong> 套餐，我们为您精选了最流行、最出片的景点，让您的社交媒体动态脱颖而出。</p><h3 style=\"text-align:justify;\"><strong>行程亮点：</strong></h3><ul><li data-list-item-id=\"eaac8f340334f36a41aead1be2e0efbb8\"><p style=\"text-align:justify;\"><strong>罕见自然景观：</strong> 参观 <strong>Gumuk Pasir</strong> 沙丘，这是由默拉皮火山沉积形成的独特沙漠景观，全球罕见。</p></li><li data-list-item-id=\"e09f18a2561d5a1e7818b0958332f9364\"><p style=\"text-align:justify;\"><strong>印度洋日落：</strong> 在 <strong>Obelix Seaview</strong> 欣赏浪漫的落日，俯瞰壮阔的印度洋全景。</p></li><li data-list-item-id=\"e9484a7d6c6721436832bde26bca24887\"><p style=\"text-align:justify;\"><strong>默拉皮吉普车冒险：</strong> 乘坐 4x4 吉普车开启 <strong>Lava Tour</strong>，探索火山遗址博物馆、“外星石”和地下掩体.</p></li><li data-list-item-id=\"e731c24d36f01a675c2974c8a1e0c9e2e\"><p style=\"text-align:justify;\"><strong>最新拍照圣地：</strong> 探索 <strong>Pictniq Land Jogja</strong>，这是专为摄影爱好者设计的最新网红目的地。</p></li><li data-list-item-id=\"ed373011b63f0758bea5df8de5357b316\"><p style=\"text-align:justify;\"><strong>地标夜色：</strong> 在传奇的 <strong>马里奥勃罗大道 (Malioboro)</strong> 尽情购物，捕捉最地道的日惹人文气息。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Tiket Pesawat &amp; Kereta Api</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Panduan pemberian tip</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Pengeluaran pribadi</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Tur dan makanan opsional</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Biaya tambahan pada high season dan hari libur nasional</li></ul>', NULL, '[\"Nature\",\"Beach\",\"Adventure\",\"City\"]', NULL, 0, NULL, '2026-04-29 12:13:23', '2026-05-29 14:25:11'),
(22, 37, '3 DAYS JOGJA WOW', 'YOGYAKARTA', '3-days-jogja-wow', '<h2 style=\"text-align:justify;\"><strong>🌟 Paket Tour 3D2N Jogja Wow: Petualangan Epik di Kota Istimewa!</strong></h2><p style=\"text-align:justify;\">Rasakan sensasi liburan tak terlupakan dengan paket <strong>3D2N Jogja Wow</strong>! Kami mengkurasi destinasi terbaik—mulai dari fenomena alam langka, petualangan adrenalin di lereng gunung, hingga kemegahan warisan dunia UNESCO—semuanya dalam satu paket perjalanan yang praktis dan berkesan.</p><h3 style=\"text-align:justify;\"><strong>✨ Highlight Perjalanan Anda:</strong></h3><ul><li data-list-item-id=\"e784b7d7054c59a511f979f18182b57c4\"><p style=\"text-align:justify;\"><strong>Keajaiban Alam Langka:</strong> Kunjungi <strong>Gumuk Pasir</strong>, fenomena padang pasir unik hasil sedimentasi material vulkanik Gunung Merapi yang hanya ada sedikit di dunia.</p></li><li data-list-item-id=\"ec73bd9f427e53fd18b12796992ff0eb6\"><p style=\"text-align:justify;\"><strong>Sunset Romantis:</strong> Nikmati momen matahari terbenam yang memukau dengan panorama Samudera Hindia yang luas di <strong>Obelix Seaview</strong>.</p></li><li data-list-item-id=\"ed035c61345ae482b3e662f4477011a15\"><p style=\"text-align:justify;\"><strong>Adrenalin Lava Tour Merapi:</strong> Jelajahi kaki Gunung Merapi menggunakan <strong>Jeep 4x4 WD</strong>, mengunjungi museum sisa erupsi, \"Batu Alien\", dan bunker yang bersejarah.</p></li><li data-list-item-id=\"ebc78e9e3d14bff4bd904df9d9b6aa30b\"><p style=\"text-align:justify;\"><strong>Warisan Dunia UNESCO:</strong> Berdiri di atas kemegahan struktur <strong>Candi Borobudur</strong>, mahakarya arsitektur abad ke-9 yang diakui dunia.</p></li><li data-list-item-id=\"e625f1406e00bffcd12d9d025e91dd3b3\"><p style=\"text-align:justify;\"><strong>Belanja Seru di Malioboro:</strong> Waktu bebas untuk berburu oleh-oleh dan menikmati suasana ikonik pusat kota Yogyakarta.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Experience the Magic: 3D2N Jogja WOW Tour Package</strong></h2><p style=\"text-align:justify;\">Embark on an epic adventure in the Special Region of Yogyakarta! Our <strong>3D2N Jogja WOW</strong> package is professionally curated to bring you the best of Jogja—from rare natural phenomena and adrenaline-pumping mountain tours to the grandeur of a UNESCO World Heritage site.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights:</strong></h3><ul><li data-list-item-id=\"e2e4939b8b707b23de8733adf37269467\"><p style=\"text-align:justify;\"><strong>Rare Desert Phenomenon:</strong> Visit <strong>Gumuk Pasir</strong>, a unique sand dune landscape formed by volcanic sedimentation, one of the few found worldwide.</p></li><li data-list-item-id=\"efc99271894b2a5d8851f64756a2e0de1\"><p style=\"text-align:justify;\"><strong>Stunning Sunset Views:</strong> Witness a breathtaking sunset with a vast panorama of the Indian Ocean at <strong>Obelix Seaview</strong>.</p></li><li data-list-item-id=\"ebe2c7bc08bddcd42095fa4984f36dbea\"><p style=\"text-align:justify;\"><strong>Adrenaline-Fueled Jeep Adventure:</strong> Explore the slopes of Mount Merapi on a <strong>4x4 Jeep Lava Tour</strong>, visiting eruption museums, the \"Alien Stone,\" and historic bunkers.</p></li><li data-list-item-id=\"e0dbc0b59c04ae9cca16e08ac5f3bdc73\"><p style=\"text-align:justify;\"><strong>UNESCO World Heritage Site:</strong> Step onto the majestic stone floors of <strong>Borobudur Temple</strong>, a 9th-century architectural masterpiece.</p></li><li data-list-item-id=\"eb79b0285605d9d5ded75c1869909d7d1\"><p style=\"text-align:justify;\"><strong>Iconic City Vibes:</strong> Enjoy free time for shopping and soaking in the legendary atmosphere of <strong>Malioboro Street</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>잊지 못할 감동: 3D2N 조그자 와우(WOW) 투어 패키지</strong></h2><p style=\"text-align:justify;\">인도네시아 요그야카르타에서 일생에 한 번뿐인 특별한 여행을 시작하세요! <strong>3D2N Jogja WOW</strong> 패키지는 세계적인 희귀 자연 현상, 아드레날린이 솟구치는 화산 투어, 그리고 유네스코 세계문화유산의 웅장함을 모두 담았습니다.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트:</strong></h3><ul><li data-list-item-id=\"edf55eb62a64926d9964d63f56370b461\"><p style=\"text-align:justify;\"><strong>희귀한 사구 지형:</strong> 세계적으로 보기 드문 화산 퇴적물로 형성된 사막, 구묵 파시르(Gumuk Pasir)를 방문합니다.</p></li><li data-list-item-id=\"e21ba6e55fbf94962e5e2b62d052bfed3\"><p style=\"text-align:justify;\"><strong>환상적인 일몰:</strong> 인도양의 드넓은 파노라마 뷰를 감상할 수 있는 오벨릭스 씨뷰(Obelix Seaview)에서 로맨틱한 일몰을 즐겨보세요.</p></li><li data-list-item-id=\"e788585079cfd0b51f7a8526bfd264974\"><p style=\"text-align:justify;\"><strong>메라피 지프 어드벤처:</strong> 4x4 지프를 타고 <strong>메라피 화산 라바 투어</strong>를 즐기며 화산 박물관, \'외계인 바위\', 벙커를 탐험합니다.</p></li><li data-list-item-id=\"eb3424cea6b488990c20c19577ea8a4e6\"><p style=\"text-align:justify;\"><strong>유네스코 세계문화유산:</strong> 9세기에 건립된 인류의 걸작, <strong>보로부두르 사원</strong>의 웅장한 구조물을 직접 거닐어 보세요.</p></li><li data-list-item-id=\"e8fbdffaf8db560ce46f3953bc8ad581b\"><p style=\"text-align:justify;\"><strong>조그자의 상징:</strong> 활기찬 <strong>말리오보로(Malioboro)</strong> 거리에서 쇼핑을 즐기고 현지 분위기를 만끽하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>震撼心灵之旅：3D2N 日惹 WOW 超值打卡套餐</strong></h2><p style=\"text-align:justify;\">开启日惹（Yogyakarta）的史诗级冒险！我们的 <strong>3D2N Jogja WOW</strong> 套餐为您精心打造——从罕见的自然奇观、刺激的火山越野，到宏伟的联合国教科文组织世界遗产，带给您全方位的震撼体验。</p><h3 style=\"text-align:justify;\"><strong>行程亮点：</strong></h3><ul><li data-list-item-id=\"e1c5a2fbfce40f81fd85c02afe2889e15\"><p style=\"text-align:justify;\"><strong>罕见沙漠景观：</strong> 参观 <strong>Gumuk Pasir</strong> 沙丘，这是由火山沉积形成的独特地貌，全球仅有少数地区可见。</p></li><li data-list-item-id=\"e7af85c1f47463a17752324d349de7308\"><p style=\"text-align:justify;\"><strong>绝美日落景观：</strong> 在 <strong>Obelix Seaview</strong> 俯瞰壮阔的印度洋全景，捕捉最动人的夕阳瞬间。</p></li><li data-list-item-id=\"e6eed056b8e3397022d52882b6ea36a5d\"><p style=\"text-align:justify;\"><strong>默拉皮吉普车探险：</strong> 乘坐 4x4 越野吉普车开启 <strong>Lava Tour</strong>，探索火山遗址博物馆、“外星石”和地下掩体。</p></li><li data-list-item-id=\"eb52a9cf25e681c9c16a2b3e093beaa49\"><p style=\"text-align:justify;\"><strong>世界文化遗产：</strong> 亲临 9 世纪建筑奇迹 —— <strong>波罗浮屠大寺 (Borobudur)</strong>，感受跨越千年的文化震撼。</p></li><li data-list-item-id=\"e4a5328dd74a5b4bd699364e34793bb2a\"><p style=\"text-align:justify;\"><strong>日惹地标打卡：</strong> 在传奇的 <strong>马里奥勃罗街 (Malioboro)</strong> 尽情购物，体验最地道的城市风情。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Nature\",\"Beach\",\"Adventure\",\"Culture\",\"HERITAGE\",\"LEISURE\"]', NULL, 0, NULL, '2026-04-29 12:29:31', '2026-06-02 07:46:36'),
(23, 37, '4 DAYS JOGJA SUNSET', 'YOGYAKARTA', '4-days-jogja-sunset', '<h2 style=\"text-align:justify;\"><strong>🌅 Paket 4D3N Jogja Sunset: Harmoni Alam, Budaya, dan Cahaya Senja</strong></h2><p style=\"text-align:justify;\">Jelajahi keajaiban Yogyakarta dalam perjalanan 4 hari 3 malam yang dirancang khusus untuk Anda pemburu momen estetik dan petualangan sejati. Paket ini tidak hanya membawa Anda ke situs bersejarah dunia, tetapi juga menyajikan sisi modern Jogja dengan titik-titik pandang matahari terbenam (<i>sunset</i>) yang paling ikonik.</p><h3 style=\"text-align:justify;\"><strong>✨ Kenapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"e50837f1443fbec452e1061459eb4cd77\"><p style=\"text-align:justify;\"><strong>Pemandangan Sunset Terbaik:</strong> Nikmati panorama matahari terbenam yang memukau dari dua lokasi kekinian: <strong>Obelix Seaview</strong> dengan pemandangan Samudera Hindia yang luas dan <strong>Obelix Hills</strong> yang menawarkan gemerlap cahaya dari ketinggian.</p></li><li data-list-item-id=\"e56f0f686b5119e1e2c85ffa0bf5454ab\"><p style=\"text-align:justify;\"><strong>Petualangan Adrenalin di Merapi:</strong> Rasakan sensasi seru <strong>Lava Tour Merapi</strong> menggunakan Jeep 4x4, mengunjungi \"Batu Alien\", Bunker Merapi, dan museum sisa erupsi yang bersejarah.</p></li><li data-list-item-id=\"e5dfe024837bbd3bb8cec583317f5c00c\"><p style=\"text-align:justify;\"><strong>Keajaiban Dunia &amp; Sejarah:</strong> Kunjungi <strong>Candi Borobudur</strong> (Warisan Dunia UNESCO), Candi Mendut, Pawon, hingga kemegahan Keraton Sultan dan eksotisme Taman Sari Water Castle.</p></li><li data-list-item-id=\"eaf917f1894f31420dfd747d65267d3d4\"><p style=\"text-align:justify;\"><strong>Spot Instagramable Kekinian:</strong> Lengkapi galeri foto Anda dengan latar belakang artistik di <strong>Tebing Breksi</strong> dan fenomena alam langka <strong>Gumuk Pasir</strong> yang menyerupai padang gurun.</p></li><li data-list-item-id=\"eb7c1819fcd54bedca028af806235f0cb\"><p style=\"text-align:justify;\"><strong>Fasilitas Lengkap &amp; Tanpa Ribet:</strong> Liburan makin nyaman dengan transportasi pribadi, hotel pilihan berbintang, pemandu profesional berbahasa Inggris, hingga Jeep Merapi yang sudah termasuk dalam harga.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>🌅Experience the Magic: 4D3N Jogja Sunset &amp; Heritage Tour</strong></h2><p style=\"text-align:justify;\">Discover the wonders of Yogyakarta on a 4-day journey specially designed for aesthetic seekers and true adventurers. This package doesn’t just take you to world-class historical sites; it presents the modern side of Jogja with its most iconic sunset viewpoints.</p><h3 style=\"text-align:justify;\"><strong>✨Why Choose This Package?</strong></h3><ul><li data-list-item-id=\"edbd4cccd79d35571aace26eb1fae2859\"><p style=\"text-align:justify;\"><strong>The Ultimate Sunset Experience:</strong> Enjoy breathtaking golden hours at <strong>Obelix Seaview</strong>, overlooking the vast Indian Ocean, and <strong>Obelix Hills</strong>, offering a stunning city skyline from above.</p></li><li data-list-item-id=\"e8c6d71a03c3441dcbfaa31fa871a939a\"><p style=\"text-align:justify;\"><strong>Merapi Jeep Adventure:</strong> Feel the thrill of a <strong>4x4 Jeep Lava Tour</strong>, visiting the historic \"Alien Stone,\" Merapi Bunker, and the eruption museum.</p></li><li data-list-item-id=\"e42c9d517c39674d57f3a82389c252ab2\"><p style=\"text-align:justify;\"><strong>World Heritage &amp; Culture:</strong> Visit the majestic <strong>Borobudur Temple</strong> (UNESCO World Heritage), the Sultan’s Palace (Kraton), and the enchanting Taman Sari Water Castle.</p></li><li data-list-item-id=\"e9be2909e65d2442593297ee30a9dd95b\"><p style=\"text-align:justify;\"><strong>Instagram-Worthy Spots:</strong> Capture stunning photos at the artistic <strong>Breksi Cliff</strong> and the rare <strong>Gumuk Pasir</strong> sand dunes.</p></li><li data-list-item-id=\"e870c525a50b0c61c2ffcb4d18f1e5e08\"><p style=\"text-align:justify;\"><strong>Seamless Travel Experience:</strong> Enjoy total comfort with private transportation, selected star-rated hotels, professional English-speaking guides, and the Merapi Jeep experience all included.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>🌅감동의 순간: 4D3N 조그자 선셋 &amp; 헤리티지 투어</strong></h2><p style=\"text-align:justify;\">진정한 모험과 아름다운 풍경을 찾는 분들을 위해 설계된 4박 3일 요그야카르타 여행! 이 패키지는 세계적인 역사 유적지뿐만 아니라, 조그자에서 가장 상징적인 일몰 명소를 포함한 현대적인 매력을 선사합니다.</p><h3 style=\"text-align:justify;\"><strong>✨왜 이 패키지를 선택해야 할까요?</strong></h3><ul><li data-list-item-id=\"ece462c08c561323d9f3460c998890a95\"><p style=\"text-align:justify;\"><strong>최고의 일몰 포인트:</strong> 인도양의 파노라마 뷰를 자랑하는 오벨릭스 씨뷰(Obelix Seaview)와 화려한 도시 야경을 감상할 수 있는 오벨릭스 힐즈(Obelix Hills)에서 환상적인 일몰을 즐기세요.</p></li><li data-list-item-id=\"e3a61315b00df8d4d9b5e6bb39fade054\"><p style=\"text-align:justify;\"><strong>메라피 지프 어드벤처:</strong> 4x4 지프를 타고 즐기는 <strong>라바 투어(Lava Tour)</strong>! \'외계인 바위\', 메라피 벙커, 그리고 화산 박물관을 탐험하며 스릴을 만끽하세요.</p></li><li data-list-item-id=\"e479c29e4c756136029eaa791ad958e69\"><p style=\"text-align:justify;\"><strong>세계 유산과 역사:</strong> 유네스코 세계문화유산인 <strong>보로부두르 사원</strong>부터 술탄 궁전, 신비로운 타만 사리 물의 궁전까지 방문합니다.</p></li><li data-list-item-id=\"edd266db4a18ddd75417ee68caacaffe7\"><p style=\"text-align:justify;\"><strong>인생샷 명소:</strong> 예술적인 브렉시 절벽(Breksi Cliff)과 세계적으로 희귀한 사막 지형인 구묵 파시르(Gumuk Pasir)에서 완벽한 사진을 남겨보세요.</p></li><li data-list-item-id=\"e7b83ed50ff0fcfd1f1f7ae0cf227f52b\"><p style=\"text-align:justify;\"><strong>편안하고 완벽한 서비스:</strong> <strong>전용 차량 서비스</strong>, 엄선된 성급 호텔, 전문 가이드, 그리고 메라피 지프 투어가 모두 포함된 품격 있는 여행을 제공합니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>🌅定格绝美瞬间：4D3N 日惹落日与文化遗产之旅</strong></h2><p style=\"text-align:justify;\">专为摄影爱好者与探险者打造的四天三夜日惹深度游！本套餐不仅带您领略世界级历史遗迹，更展现了日惹现代的一面，带您前往最标志性的日落打卡点。</p><h3 style=\"text-align:justify;\"><strong>✨为什么选择这个套餐？</strong></h3><ul><li data-list-item-id=\"e746664d2c05f170c435ffc408e41cb94\"><p style=\"text-align:justify;\"><strong>绝佳日落体验：</strong> 在 <strong>Obelix Seaview</strong> 俯瞰壮丽的印度洋日落，并在 <strong>Obelix Hills</strong> 欣赏高空视角下的璀璨城市夜景。</p></li><li data-list-item-id=\"edc70fc2875b13e7dfe523c0cc71f254e\"><p style=\"text-align:justify;\"><strong>默拉皮吉普车冒险：</strong> 乘坐 4x4 越野吉普车开启 <strong>Lava Tour</strong>，探索著名的“外星石”、默拉皮地下掩体以及火山遗址博物馆。</p></li><li data-list-item-id=\"ee6b940c1d7d2ae836bc9486a4599ae65\"><p style=\"text-align:justify;\"><strong>世界遗产与传统文化：</strong> 亲临<strong>婆罗浮屠 (Borobudur)</strong>（联合国教科文组织世界遗产）、苏丹王宫以及精致的苏丹水宫 (Taman Sari)。</p></li><li data-list-item-id=\"e61850cec80f52f009f363188f8973a55\"><p style=\"text-align:justify;\"><strong>网红摄影圣地：</strong> 在艺术气息浓厚的<strong>布雷希石崖 (Breksi Cliff)</strong> 和世界罕见的<strong>沙丘景观 (Gumuk Pasir)</strong> 拍摄绝佳时尚大片。</p></li><li data-list-item-id=\"e31fc3ac93935f20698fb091671d8db3c\"><p style=\"text-align:justify;\"><strong>全程无忧服务：</strong> 包含<strong>私人交通接送</strong>、精选星级酒店、专业导游以及默拉皮吉普车体验，为您打造舒适省心的旅程。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Culture\",\"HERITAGE\",\"Nature\",\"Adventure\",\"Beach\",\"SUNSET\"]', NULL, 0, NULL, '2026-04-29 12:45:27', '2026-06-02 08:37:51'),
(24, 37, '4 DAYS JOGJA ADRENALINE', 'YOGYAKARTA', '4-days-jogja-adrenaline', '<h2 style=\"text-align:justify;\"><strong>Paket 4D3N Jogja Adrenalin: Taklukkan Tantangan, Temukan Keajaiban!</strong></h2><p style=\"text-align:justify;\">Siap memacu jantung Anda di jantung budaya Jawa? Paket <strong>4D3N Jogja Adrenalin</strong> dirancang khusus bagi Anda yang tidak puas hanya dengan wisata biasa. Kami menggabungkan kemegahan warisan dunia dengan petualangan ekstrem yang akan menjadi cerita tak terlupakan seumur hidup.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda WAJIB Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e4e11a9aca971750bef83028043a04513\"><p style=\"text-align:justify;\"><strong>Petualangan \"Cahaya Surga\" di Gua Jomblang:</strong> Rasakan sensasi menuruni gua vertikal menggunakan teknik <i>Single Rope</i> dan saksikan fenomena cahaya ilahi yang menembus kegelapan perut bumi.</p></li><li data-list-item-id=\"ebe34a46409d79365fd99c7559df34b62\"><p style=\"text-align:justify;\"><strong>Adrenalin di Atas Samudera:</strong> Uji nyali Anda menyeberangi laut selatan yang ganas menggunakan <strong>Gondola Tradisional</strong> di Pantai Timang—pengalaman ikonik yang mendunia.</p></li><li data-list-item-id=\"e8d1f06b60f82b2abe3a6b9beaafce4dc\"><p style=\"text-align:justify;\"><strong>Off-Road Lava Tour Merapi:</strong> Jelajahi jejak erupsi Merapi yang legendaris dengan <strong>Jeep 4x4</strong>, mengunjungi Bunker Merapi dan Museum Sisa Hartaku yang menyentuh hati.</p></li><li data-list-item-id=\"e6cc12d91d76257d2bc0df645cad4c7da\"><p style=\"text-align:justify;\"><strong>Eksotisme Fenomena Langka:</strong> Berfoto di <strong>Gumuk Pasir</strong>, padang pasir unik yang hanya ada sedikit di dunia, dan nikmati sunset romantis dengan panorama samudera luas di <strong>Obelix Seaview</strong>.</p></li><li data-list-item-id=\"e3a6e7bbbbfb167504682e889fa7cdbf8\"><p style=\"text-align:justify;\"><strong>Sentuhan Budaya Dunia:</strong> Tetap terhubung dengan sejarah di <strong>Candi Borobudur</strong>, situs warisan dunia UNESCO yang megah, serta berburu oleh-oleh di sepanjang Jalan Malioboro yang legendaris.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4D3N Jogja Adrenalin: Conquer the Challenges, Discover the Wonders!</strong></h2><p style=\"text-align:justify;\">Ready to get your heart racing in the cultural heart of Java? The <strong>4D3N Jogja Adrenalin</strong> package is specially designed for those who seek more than just a regular holiday. We combine the grandeur of world heritage with extreme adventures that will become lifelong memories.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour:</strong></h3><ul><li data-list-item-id=\"e0cb6d69ad7aade5210f072769265340c\"><p style=\"text-align:justify;\"><strong>The \"Heavenly Light\" at Jomblang Cave:</strong> Experience the thrill of descending into a vertical cave using Single Rope Technique and witness the divine light piercing through the darkness.</p></li><li data-list-item-id=\"e58e628e259be556191da509c2e26f145\"><p style=\"text-align:justify;\"><strong>Adrenaline Above the Ocean:</strong> Test your courage crossing the fierce southern sea on a <strong>Traditional Gondola</strong> at Timang Beach—an world-renowned iconic experience.</p></li><li data-list-item-id=\"e8af76a25627ab82a0877ef70155aae8a\"><p style=\"text-align:justify;\"><strong>Off-Road Merapi Lava Tour:</strong> Explore the legendary eruption trails with a <strong>4x4 Jeep</strong>, visiting the Merapi Bunker and the moving \"Sisa Hartaku\" Museum.</p></li><li data-list-item-id=\"e3747f23bee22fb33443c101e1f8d3de8\"><p style=\"text-align:justify;\"><strong>Rare Natural Phenomena:</strong> Take photos at <strong>Gumuk Pasir</strong>, a unique sand dune found in only a few places worldwide and enjoy a romantic sunset at <strong>Obelix Seaview</strong>.</p></li><li data-list-item-id=\"e820c8fbdfca53d206be09b34601db641\"><p style=\"text-align:justify;\"><strong>World-Class Culture:</strong> Connect with history at the majestic <strong>Borobudur Temple</strong> (UNESCO World Heritage Site) and hunt for souvenirs along the legendary Malioboro Street.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4D3N 조그자 아드레날린 투어: 한계를 넘고 경이로움을 발견하세요!</strong></h2><p style=\"text-align:justify;\">자바의 문화 중심지에서 심장이 뛰는 경험을 할 준비가 되셨나요? <strong>4D3N 조그자 아드레날린</strong> 패키지는 평범한 여행 그 이상을 원하는 분들을 위해 설계되었습니다. 세계 문화유산의 웅장함과 평생 잊지 못할 익스트림 어드벤처를 결합했습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 꼭 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e80a74d20d3ef87768436f2d1963b028b\"><p style=\"text-align:justify;\"><strong>좀블랑 동굴의 \'천사의 빛\':</strong> 싱글 로프 기술을 이용해 수직 동굴로 내려가는 스릴을 느끼고, 어둠을 뚫고 쏟아지는 신비로운 빛을 감상하세요.</p></li><li data-list-item-id=\"e5a1e374f4cb5f06bf0e4880ba3c0db13\"><p style=\"text-align:justify;\"><strong>바다 위에서의 아드레날린:</strong> 티망 해변(Timang Beach)에서 <strong>전통 곤돌라</strong>를 타고 거친 파도 위를 건너며 용기를 시험해 보세요—세계적으로 유명한 조그자만의 상징적인 경험입니다.</p></li><li data-list-item-id=\"ee975c764784c53540e0b52bd05e8a778\"><p style=\"text-align:justify;\"><strong>메라피 화산 라바 투어:</strong> <strong>4x4 지프</strong>를 타고 전설적인 화산 폭발의 흔적을 탐험하며 메라피 벙커와 감동적인 \'내 남은 재산\' 박물관을 방문합니다.</p></li><li data-list-item-id=\"e24245a7d94aabb44d85c406588b4af77\"><p style=\"text-align:justify;\"><strong>희귀한 자연 현상:</strong> 세계적으로 보기 드문 모래 언덕인 구묵 파시르(Gumuk Pasir)에서 인생샷을 남기고, <strong>오벨릭스 씨뷰</strong>에서 로맨틱한 일몰을 즐기세요.</p></li><li data-list-item-id=\"e244c14eef4ac9c3c80c976878fa5b313\"><p style=\"text-align:justify;\"><strong>세계적인 문화유산:</strong> 유네스코 세계문화유산인 <strong>보로부두르 사원</strong>에서 역사를 느끼고, 활기찬 말리오보로 거리에서 쇼핑을 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4D3N 日惹极限挑战之旅：征服险峻，发现奇迹！</strong></h2><p style=\"text-align:justify;\">准备好在爪哇的文化心脏地带开启一场心跳加速之旅了吗？<strong>4D3N 日惹极限挑战 (Jogja Adrenalin)</strong> 套餐专为追求非凡体验的旅者打造。我们将宏伟的世界遗产与极限冒险相结合，为您创造终生难忘的回忆。</p><h3 style=\"text-align:justify;\"><strong>为什么您绝对不能错过这个行程：</strong></h3><ul><li data-list-item-id=\"e371e46e507469132ab3a70484394c3f1\"><p style=\"text-align:justify;\"><strong>洞穴里的“天堂之光”：</strong> 体验使用单绳技术 (SRT) 垂直降入 <strong>Jomblang 洞穴</strong>的快感，亲眼见证神圣之光穿透黑暗的奇迹时刻。</p></li><li data-list-item-id=\"e2c4d681c0e4fafc029f616e5c2cf2a5a\"><p style=\"text-align:justify;\"><strong>海面上的巅峰挑战：</strong> 在 <strong>Timang 海滩</strong>乘坐<strong>传统手工缆车 (Gondola)</strong> 横跨汹涌的南海——这是享誉全球的标志性极限体验。</p></li><li data-list-item-id=\"e81aac3b0c8678b36684a0c3f75583cd8\"><p style=\"text-align:justify;\"><strong>默拉皮火山吉普越野：</strong> 乘坐 <strong>4x4 越野吉普车</strong>探索传奇的火山喷发遗迹，参观默拉皮地下掩体和令人动容的火山遗址博物馆。</p></li><li data-list-item-id=\"e1ddb705c6a777c330b596e9250799bab\"><p style=\"text-align:justify;\"><strong>稀有的自然景观：</strong> 在全球罕见的 <strong>Gumuk Pasir 沙丘</strong>拍摄时尚大片，并在 <strong>Obelix Seaview</strong> 欣赏绝美的印度洋日落。</p></li><li data-list-item-id=\"e7eb95998894f79d3befe7d81da1bd000\"><p style=\"text-align:justify;\"><strong>世界级文化洗礼：</strong> 亲临宏伟的<strong>婆罗浮屠 (Borobudur)</strong>（联合国教科文组织世界遗产），并在传奇的马里奥波罗 (Malioboro) 大街尽情购物。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"e96c898df4e25103ff67c5d2ecda67293\">Jeep Timang</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Adventure\",\"ADRENALINE\",\"Culture\",\"HISTORICAL\",\"Nature\"]', NULL, 0, NULL, '2026-04-29 12:59:38', '2026-06-03 02:21:08'),
(25, 37, '4 DAYS JOGJA CULTURE', 'YOGYAKARTA', '4-days-jogja-culture', '<h2 style=\"text-align:justify;\"><strong>Jogja Aesthetic: Simfoni Sejarah dan Pesona Alam yang Fotogenik</strong></h2><p style=\"text-align:justify;\">Abadikan setiap momen berharga Anda dalam paket wisata yang memanjakan mata. Dari koridor kuno pusat perak hingga gurun pasir yang eksotis, Yogyakarta adalah kanvas sempurna untuk petualangan Anda selanjutnya.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Akan Menyukainya?</strong></h3><ul><li data-list-item-id=\"e04e3225d131dcca7a67d3d7b0b4cb934\"><p style=\"text-align:justify;\"><strong>Snapshot Peradaban:</strong> Dapatkan foto ikonik di Candi Borobudur dan Prambanan, mahakarya arsitektur yang telah diakui dunia.</p></li><li data-list-item-id=\"edce07e9b0be1a77d8a91ca9ad65ea4a1\"><p style=\"text-align:justify;\"><strong>Gurun Pasir di Tropis:</strong> Rasakan sensasi berfoto di Gumuk Pasir, fenomena alam langka yang memberikan atmosfer gurun pasir nyata untuk konten media sosial Anda.</p></li><li data-list-item-id=\"e70f8c565f68542072787ef2787e74f66\"><p style=\"text-align:justify;\"><strong>Estetika Kerajaan:</strong> Jelajahi Taman Sari Watercastle, reruntuhan pemandian raja yang eksotis dengan arsitektur pintu air dan kolam yang menawan.</p></li><li data-list-item-id=\"e076251b431c7706064163e7224295cbd\"><p style=\"text-align:justify;\"><strong>Vibe Kota Klasik:</strong> Temukan sudut-sudut estetik di Malioboro dan Kotagede yang kaya akan detail sejarah dan kerajinan perak.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Jogja Aesthetic: A Symphony of History and Photogenic Nature</strong></h2><p style=\"text-align:justify;\">Capture every precious moment in a tour package designed to please the eye. From the ancient corridors of the silver center to exotic sand dunes, Yogyakarta is the perfect canvas for your next adventure.</p><h3 style=\"text-align:justify;\"><strong>Why You Will Love This:</strong></h3><ul><li data-list-item-id=\"e4efc19cdfdc692f9c3cd15ebf5ec4a9b\"><p style=\"text-align:justify;\"><strong>Snapshots of Civilization:</strong> Get iconic photos at Borobudur and Prambanan Temples, world-recognized architectural masterpieces.</p></li><li data-list-item-id=\"e59ef575eae2db20bdd4fce91e9312f05\"><p style=\"text-align:justify;\"><strong>Tropical Sand Dunes:</strong> Experience a photo session at Gumuk Pasir, a rare natural phenomenon that offers a real desert atmosphere for your social media content.</p></li><li data-list-item-id=\"ee7992acf00b0dc15dba7a04e5d09e827\"><p style=\"text-align:justify;\"><strong>Royal Aesthetics:</strong> Explore Taman Sari Watercastle, an exotic royal bathing ruin featuring charming water gates and pool architecture.</p></li><li data-list-item-id=\"ef86a6311db466c6427f8536fbd8a3e3a\"><p style=\"text-align:justify;\"><strong>Classic City Vibes:</strong> Discover aesthetic corners in Malioboro and Kotagede, rich in historical details and silver craftsmanship.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>조그자 에스테틱: 역사와 포토제닉한 자연의 심포니</strong></h2><p style=\"text-align:justify;\">눈이 즐거워지는 투어 패키지로 당신의 모든 소중한 순간을 담아보세요. 고대 은세공 중심지의 복도부터 이국적인 사구까지, 요그야카르타(조그자)는 당신의 다음 모험을 위한 완벽한 도화지가 될 것입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 사랑하게 될 이유:</strong></h3><ul><li data-list-item-id=\"e444da782c2d90456c3d45363cbbc46ae\"><p style=\"text-align:justify;\"><strong>문명의 찰나:</strong> 세계적으로 인정받는 건축 걸작인 보로부두르와 프람바난 사원에서 상징적인 인생샷을 남겨보세요.</p></li><li data-list-item-id=\"e76a99f11fdbc4067da44110041d6f1da\"><p style=\"text-align:justify;\"><strong>열대의 사구:</strong> 소셜 미디어 콘텐츠에 진짜 사막 분위기를 더해줄 희귀한 자연 현상인 구묵 파시르(Gumuk Pasir)에서 사진 촬영을 경험해 보세요.</p></li><li data-list-item-id=\"ed4711e80dd16c6c3c09f4142c9656a32\"><p style=\"text-align:justify;\"><strong>왕실의 미학:</strong> 매력적인 수문과 수영장 건축이 특징인 이국적인 왕실 목욕탕 유적지, 타만 사리(Taman Sari) 워터캐슬을 탐험해 보세요.</p></li><li data-list-item-id=\"efd4017ea21d945388d6da5dccd778687\"><p style=\"text-align:justify;\"><strong>클래식 시티 바이브:</strong> 역사적인 디테일과 은세공 기술이 풍부한 말리오보로와 코타게데의 미학적인 장소들을 발견해 보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>日惹美学：历史与视觉自然的交响乐</strong></h2><p style=\"text-align:justify;\">在专为视觉享受而设计的旅行计划中，捕捉您的每一个珍贵瞬间。从古老的银器中心走廊到异域风情的沙丘，日惹是您下一次冒险的完美画布。</p><h3 style=\"text-align:justify;\"><strong>为什么您会爱上这里：</strong></h3><ul><li data-list-item-id=\"e7cd1e8bf4ad80c33d15f2194241a46aa\"><p style=\"text-align:justify;\"><strong>文明的身影：</strong> 在世界公认的建筑杰作——婆罗浮屠和普兰巴南寺庙拍摄标志性的照片。</p></li><li data-list-item-id=\"e03de393ad5725a1b766e0e12503e554a\"><p style=\"text-align:justify;\"><strong>热带沙丘：</strong> 在 Gumuk Pasir 体验拍照的乐趣，这种罕见的自然现象为您的社交媒体内容提供了真实的沙漠氛围。</p></li><li data-list-item-id=\"ee8d786f599a6a7c6d2ccd319b21a30ea\"><p style=\"text-align:justify;\"><strong>皇室美学：</strong> 探索水宫 (Taman Sari) ，这是一处充满异国情调的皇家沐浴遗址，拥有迷人的水门和水池建筑。</p></li><li data-list-item-id=\"e6f6c27626a9ac73bc3db18e16b9c442d\"><p style=\"text-align:justify;\"><strong>古典城市风情：</strong> 发现马里奥波罗 (Malioboro) 和哥打格德 (Kotagede) 的美学角落，这里充满了历史细节和精湛的银器工艺。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel berbasis TWN/TRP</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Tiket Pesawat &amp; Kereta Api</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Panduan pemberian tip</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Pengeluaran pribadi</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Tur dan makanan opsional</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Biaya tambahan pada high season dan hari libur nasional</li></ul>', NULL, '[\"HISTORICAL\",\"Nature\",\"Culture\",\"Beach\",\"City\"]', NULL, 0, NULL, '2026-04-29 13:11:45', '2026-06-03 02:54:27');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(26, 37, '4 DAYS JOGJA DIENG', 'CENTRAL JAVA', '4-days-jogja-dieng', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Pesona Legendaris: Paket Tour Jogja - Dieng 4 Hari 3 Malam</strong></h2><p style=\"text-align:justify;\">Nikmati petualangan yang menggabungkan kemegahan budaya, keajaiban alam di atas awan, dan keseruan memacu adrenalin.</p><h3 style=\"text-align:justify;\"><strong>Highlight Perjalanan:</strong></h3><ul><li data-list-item-id=\"eb3b4f3a7a0bbdee743033ce8262fc896\"><p style=\"text-align:justify;\"><strong>Petualangan di Atas Awan:</strong> Jelajahi Dataran Tinggi Dieng yang memukau, mulai dari Kompleks Candi Arjuna, Kawah Sikidang, hingga pesona Telaga Warna.</p></li><li data-list-item-id=\"eba08912b04ed508e6cece31ce7c5adaf\"><p style=\"text-align:justify;\"><strong>Adrenalin Lava Tour Merapi:</strong> Rasakan sensasi berkendara Jeep 4x4 di kaki Gunung Merapi, mengunjungi Museum Sisa Hartaku dan Bunker Merapi.</p></li><li data-list-item-id=\"e4883569b320052560871eb29dfcd2cbb\"><p style=\"text-align:justify;\"><strong>Warisan Budaya Dunia:</strong> Kunjungi Candi Prambanan, kompleks candi Hindu terbesar dan tercantik di Indonesia.</p></li><li data-list-item-id=\"e9a40d54926096ace69f961270fcabb30\"><p style=\"text-align:justify;\"><strong>Eksplorasi Kota &amp; Seni:</strong> Kunjungi pusat kerajinan perak di Kotagede, tebing seni Breksi, dan suasana ikonik Jalan Malioboro.</p></li><li data-list-item-id=\"e5d83f3aa4da568510ef5da87f706cd51\"><p style=\"text-align:justify;\"><strong>Situs Bersejarah:</strong> Melihat keunikan arsitektur pemandian putri raja di Taman Sari.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore Legendary Charms: 4D3N Jogja - Dieng Tour Package</strong></h2><p style=\"text-align:justify;\">Experience an adventure that combines cultural grandeur, natural wonders above the clouds, and an adrenaline-pumping journey.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights:</strong></h3><ul><li data-list-item-id=\"e4a3ae87e71fa88607bfc4b06285d0ed3\"><p style=\"text-align:justify;\"><strong>Adventure Above the Clouds:</strong> Explore the breathtaking Dieng Plateau, including the Arjuna Temple Complex, Sikidang Crater, and the vibrant Color Lake (Telaga Warna).</p></li><li data-list-item-id=\"ec83d25143616e388ff75db7cabb4460e\"><p style=\"text-align:justify;\"><strong>Merapi Lava Tour Adrenaline:</strong> Experience a thrilling 4x4 Jeep ride at the foot of Mount Merapi, visiting the \"Sisa Hartaku\" Museum and Merapi Bunker.</p></li><li data-list-item-id=\"e0ca251065d2820abf4dfa59e20fbbbe7\"><p style=\"text-align:justify;\"><strong>World Heritage Site:</strong> Visit Prambanan Temple, the largest and most beautiful Hindu temple complex in Indonesia.</p></li><li data-list-item-id=\"e774e4927192c1e79502def3da9476e0d\"><p style=\"text-align:justify;\"><strong>Art &amp; City Exploration:</strong> Visit the silver craft center in Kotagede, the artistic Breksi Cliff, and the iconic atmosphere of Malioboro Street.</p></li><li data-list-item-id=\"e3d3a4a9968d0cf9e69e1e9010bed5953\"><p style=\"text-align:justify;\"><strong>Historical Sites:</strong> Discover the unique architecture of the royal bathing palace at Taman Sari.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>전설적인 매력 탐험: 4박 3일 족자카르타 - 디엥 투어 패키지</strong></h2><p style=\"text-align:justify;\">문화적 웅장함, 구름 위의 자연 경관, 그리고 짜릿한 모험이 결합된 특별한 여행을 경험해 보세요.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트:</strong></h3><ul><li data-list-item-id=\"e8d4de36cf64994efcf0fc3714c40fd57\"><p style=\"text-align:justify;\"><strong>구름 위의 어드벤처:</strong> 아르주나 사원 단지, 시키당 화산 분화구, 신비로운 빛깔의 텔라가 와르나(색깔 호수)를 포함한 디엥 고원을 탐험합니다.</p></li><li data-list-item-id=\"e0dabd70b80cc654c375c6d9ebf743f86\"><p style=\"text-align:justify;\"><strong>메라피 화산 라바 투어:</strong> 메라피 산기슭에서 스릴 넘치는 4x4 지프 투어를 즐기며, 에루프시 박물관과 벙커를 방문합니다.</p></li><li data-list-item-id=\"e3e31449c65069e49889a9b1c0a16ef53\"><p style=\"text-align:justify;\"><strong>세계 문화 유산:</strong> 인도네시아에서 가장 크고 아름다운 힌두교 사원인 프람바난 사원을 방문합니다.</p></li><li data-list-item-id=\"e138aeced30ee337178b5c27d576cacf9\"><p style=\"text-align:justify;\"><strong>예술 및 도시 탐방:</strong> 코타게데의 은공예 단지, 예술적인 브렉시 절벽, 그리고 족자카르타의 상징인 말리오보로 거리를 방문합니다.</p></li><li data-list-item-id=\"eeb0b84739b8e5a9c9a37f7d912125194\"><p style=\"text-align:justify;\"><strong>역사 유적지:</strong> 왕실의 목욕궁전인 타만 사리의 독특한 건축미를 감상합니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索传奇魅力：日惹 - 迪昂高原 4天3夜游套餐</strong></h2><p style=\"text-align:justify;\">体验一场结合人文盛景、云端自然奇观与肾上腺素飙升的精彩旅程。</p><h3 style=\"text-align:justify;\"><strong>行程亮点：</strong></h3><ul><li data-list-item-id=\"efdf9ccdf1ea242af715be6ba1bf5a3a3\"><p style=\"text-align:justify;\"><strong>云端冒险：</strong> 探索令人叹为观止的迪昂高原（Dieng Plateau），包括阿周那神庙群（Arjuna Temple）、西基当火山口（Sikidang Crater）和梦幻的五彩湖（Telaga Warna）。</p></li><li data-list-item-id=\"ed4cc5eab3b7881563395236fef945dd7\"><p style=\"text-align:justify;\"><strong>默拉皮火山熔岩之旅：</strong> 在默拉皮山脚下体验惊险刺激的 4x4 吉普车之旅，参观火山博物馆和默拉皮地堡。</p></li><li data-list-item-id=\"e70b78bf1580b3df60f6e1bf938bea716\"><p style=\"text-align:justify;\"><strong>世界文化遗产：</strong> 参观普兰巴南神庙（Prambanan），这是印度尼西亚规模最大且最美丽的印度教神庙群。</p></li><li data-list-item-id=\"e8e152fd24525013d1d94facbe9604730\"><p style=\"text-align:justify;\"><strong>艺术与城市探索：</strong> 参观哥打格德（Kotagede）的银器工艺中心、充满艺术感的布雷希断崖（Breksi Cliff）以及标志性的马里奥波罗大街（Malioboro）。</p></li><li data-list-item-id=\"e26fcafc80a0b4dff420e259ef7bbafb3\"><p style=\"text-align:justify;\"><strong>历史古迹：</strong> 欣赏水宫（Taman Sari）皇家浴池的独特建筑设计。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"Culture\",\"HISTORICAL\"]', NULL, 0, NULL, '2026-04-29 13:27:46', '2026-06-03 03:08:50'),
(27, 37, '4 DAYS JOGJA SEMARANG AMBARAWA', 'CENTRAL JAVA', '4-days-jogja-semarang-ambarawa', '<h2 style=\"text-align:justify;\"><strong>Nikmati perjalanan tak terlupakan melintasi dua kota paling ikonik di Pulau Jawa</strong></h2><p style=\"text-align:justify;\">Dari kemegahan candi kuno hingga pesona arsitektur kolonial, paket <strong>4D3N Jogja - Semarang</strong> ini dirancang khusus untuk Anda yang mendambakan perpaduan sempurna antara sejarah, budaya, dan alam yang asri.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"e1c7ccae751fd132418eeafdd781922fc\"><p style=\"text-align:justify;\"><strong>Destinasi Kelas Dunia:</strong> Kunjungi <strong>Candi Borobudur</strong>, mahakarya Buddha terbesar di dunia yang telah diakui oleh UNESCO.</p></li><li data-list-item-id=\"e7a2ccbc4e9ba58509139f942521a5d88\"><p style=\"text-align:justify;\"><strong>Petualangan Sejarah yang Unik:</strong> Rasakan sensasi \"Seribu Pintu\" di <strong>Lawang Sewu</strong>, jelajahi keindahan akulturasi budaya di <strong>Kelenteng Sam Po Kong</strong>, serta bernostalgia di <strong>Museum Kereta Api Ambarawa</strong>.</p></li><li data-list-item-id=\"eea50762f90903fff318258e13bf73d51\"><p style=\"text-align:justify;\"><strong>Suasana Alam yang Menyegarkan:</strong> Hirup udara pegunungan yang sejuk sambil menikmati pemandangan alami yang eksotis di <strong>Candi Gedongsongo</strong>, lereng Gunung Ungaran.</p></li><li data-list-item-id=\"e9ed3c6db98f76210f3d05ded3bc88310\"><p style=\"text-align:justify;\"><strong>Wisata Estetik &amp; Instagramable:</strong> Abadikan momen di <strong>Kota Lama Semarang</strong> yang kental dengan nuansa Eropa dan <strong>Gereja Blenduk</strong> yang legendaris.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Enjoy an unforgettable journey across the two most iconic cities on the island of Java</strong></h2><p style=\"text-align:justify;\">From the grandeur of ancient temples to the charm of colonial architecture, this <strong>4D3N Jogja - Semarang</strong> package is specially designed for those who crave a perfect blend of history, culture, and lush nature.</p><h3 style=\"text-align:justify;\"><strong>Why Choose This Package?</strong></h3><ul><li data-list-item-id=\"e3c28cc21ed42cb1f61357ddc1b912e8f\"><p style=\"text-align:justify;\"><strong>World-Class Destination:</strong> Visit <strong>Borobudur Temple</strong>, the world\'s largest Buddhist masterpiece and a UNESCO World Heritage site.</p></li><li data-list-item-id=\"e8cb66344e31176f52eb9b88d8c36a639\"><p style=\"text-align:justify;\"><strong>Unique Historical Adventure:</strong> Feel the sensation of \"A Thousand Doors\" at <strong>Lawang Sewu</strong>, explore the beautiful cultural fusion at <strong>Sam Po Kong Temple</strong>, and take a nostalgic trip at the <strong>Ambarawa Railway Museum</strong>.</p></li><li data-list-item-id=\"e301f2bd1f15f31e3c09999c3c10a3cdc\"><p style=\"text-align:justify;\"><strong>Refreshing Natural Atmosphere:</strong> Breathe in the cool mountain air while enjoying exotic natural views at <strong>Gedongsongo Temple</strong> on the slopes of Mount Ungaran.</p></li><li data-list-item-id=\"e493d5c817d9ac91e2aa73a08a8600c10\"><p style=\"text-align:justify;\"><strong>Aesthetic &amp; Instagrammable Spots:</strong> Capture moments in the <strong>Semarang Old Town</strong> with its European vibe and the legendary <strong>Blenduk Church</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>자바섬에서 가장 상징적인 두 도시를 가로지르는 잊지 못할 여행을 즐겨보세요</strong></h2><p style=\"text-align:justify;\">고대 사원의 웅장함부터 식민지 시대 건축물의 매력까지, 이 <strong>4박 3일 조그자(Jogja) - 세마랑(Semarang)</strong> 패키지는 역사, 문화, 그리고 푸른 자연의 완벽한 조화를 갈망하는 분들을 위해 특별히 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>왜 이 패키지를 선택해야 하나요?</strong></h3><ul><li data-list-item-id=\"eb814075e9d1abbaece223fc9aba20d19\"><p style=\"text-align:justify;\"><strong>세계적인 명소:</strong> 유네스코 세계문화유산이자 세계 최대의 불교 예술품인 <strong>보로부두르 사원</strong>을 방문하세요.</p></li><li data-list-item-id=\"e61c13081e6517ff1e7fb350055d98ce5\"><p style=\"text-align:justify;\"><strong>특별한 역사 탐험:</strong> \'천 개의 문\'이라는 뜻의 라왕 세우(Lawang Sewu)에서 신비로움을 느끼고, <strong>삼포공(Sam Po Kong) 사원</strong>에서 아름다운 문화의 융합을 탐험하며, <strong>암바라와 철도 박물관</strong>에서 향수를 느껴보세요.</p></li><li data-list-item-id=\"e1a9cdef39687cfea8b060156afc64925\"><p style=\"text-align:justify;\"><strong>상쾌한 자연 경관:</strong> 웅가란 산기슭에 위치한 <strong>게동송고(Gedongsongo) 사원</strong>에서 시원한 산 공기를 마시며 이국적인 자연 경관을 감상하세요.</p></li><li data-list-item-id=\"e231fba1363c4f18a5600cc3a11ec80bd\"><p style=\"text-align:justify;\"><strong>인생샷 명소:</strong> 유럽의 분위기가 물씬 풍기는 <strong>세마랑 올드타운</strong>과 전설적인 <strong>블렌둑(Blenduk) 교회</strong>에서 소중한 순간을 기록하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>尽情享受横跨爪哇岛两座最具标志性城市的难忘之旅</strong></h2><p style=\"text-align:justify;\">从宏伟的古老寺庙到迷人的殖民时期建筑，这个 <strong>4天3夜 日惹 (Jogja) - 三宝垄 (Semarang)</strong> 套餐专为渴望历史、文化与清新自然完美结合的您精心打造。</p><h3 style=\"text-align:justify;\"><strong>为什么选择这个套餐？</strong></h3><ul><li data-list-item-id=\"e4c2c53a84e61675e88edf433f1c92814\"><p style=\"text-align:justify;\"><strong>世界级景点：</strong> 参观被联合国教科文组织列入名录的世界最大佛教建筑群——<strong>婆罗浮屠寺 (Borobudur Temple)</strong>。</p></li><li data-list-item-id=\"ecfb03731d4af6647856074e7d2d2d0b4\"><p style=\"text-align:justify;\"><strong>独特的历史探险：</strong> 在 <strong>“千门之屋” (Lawang Sewu)</strong> 感受震撼，在 <strong>三保洞 (Sam Po Kong)</strong> 探索多元文化的融合，并在 <strong>安巴拉瓦铁路博物馆 (Ambarawa Railway Museum)</strong> 怀旧往昔。</p></li><li data-list-item-id=\"ed35e1c8690569fa579521fdf2489206a\"><p style=\"text-align:justify;\"><strong>清新的自然氛围：</strong> 在乌加兰山坡上的 <strong>哥冬松果庙 (Gedongsongo Temple)</strong> 呼吸清凉的山间空气，欣赏异国情调的自然美景.</p></li><li data-list-item-id=\"e7cb8ce2527e2cdea95a7e9c10e42be62\"><p style=\"text-align:justify;\"><strong>网红打卡胜地：</strong> 在充满欧洲风情的 <strong>三宝垄老城区 (Old Town)</strong> 和传奇的 <strong>布兰杜克教堂 (Blenduk Church)</strong> 捕捉精彩瞬间。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Nature\",\"Culture\",\"City\",\"Historical\"]', NULL, 0, NULL, '2026-04-30 13:23:50', '2026-06-03 03:13:50'),
(28, 37, '4 DAYS JOGJA SEMARANG LAVA TOUR', 'CENTRAL JAVA', '4-days-jogja-semarang-lava-tour', '<h2 style=\"text-align:justify;\"><strong>Menyusuri Jejak Peradaban di Jantung Jawa</strong></h2><p style=\"text-align:justify;\">Ada alasan mengapa Yogyakarta dan Semarang selalu menjadi magnet bagi pelancong dunia. Ini bukan sekadar perjalanan, melainkan sebuah lorong waktu yang membawa Anda dari kemegahan dinasti kuno menuju romansa kota kolonial.</p><ul><li data-list-item-id=\"eece84ca681ecf7ffd7b498b2181d2d90\"><p style=\"text-align:justify;\"><strong>Saksi Bisu Sejarah:</strong> Berdiri terpaku di hadapan relief <strong>Candi Borobudur</strong> saat mentari mulai meninggi.</p></li><li data-list-item-id=\"e3d202b1be115d89848e7236db0bdc5ea\"><p style=\"text-align:justify;\"><strong>Gemuruh Merapi:</strong> Merasakan hembusan angin pegunungan di atas Jeep terbuka, menyisir sisa-sisa ketangguhan alam di lereng <strong>Gunung Merapi</strong>.</p></li><li data-list-item-id=\"e8a59bddd0a5e279917e9d289fdc5b7da\"><p style=\"text-align:justify;\"><strong>Harmoni Budaya:</strong> Menemukan titik temu budaya di <strong>Klenteng Sam Po Kong</strong> dan lorong-lorong artistik <strong>Kota Lama Semarang</strong>.</p></li><li data-list-item-id=\"e12339e55d56d111456edf5848999bc04\"><p style=\"text-align:justify;\"><strong>Keanggunan Tradisi:</strong> Melihat dari dekat kehidupan keluarga kerajaan di <strong>Keraton Yogyakarta</strong> yang masih lestari hingga kini.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Tracing the Footsteps of Civilization in the Heart of Java</strong></h2><p style=\"text-align:justify;\">There is a reason why Yogyakarta and Semarang have always been magnets for global travelers. This is more than just a trip; it is a journey through a time portal, taking you from the grandeur of ancient dynasties to the romance of colonial cities.</p><ul><li data-list-item-id=\"e5b586e3fd009fb82024771b8e51055da\"><p style=\"text-align:justify;\"><strong>Silent Witness to History:</strong> Stand in awe before the intricate reliefs of <strong>Borobudur Temple</strong> as the morning sun rises.</p></li><li data-list-item-id=\"ee695d4b4dcbdb8c337eefe9d079aba2e\"><p style=\"text-align:justify;\"><strong>The Roar of Merapi:</strong> Feel the mountain breeze on an open-roof Jeep, exploring the remnants of nature’s power on the slopes of <strong>Mount Merapi</strong>.</p></li><li data-list-item-id=\"e0745a8afd878ba697ed06f0684c5c2b2\"><p style=\"text-align:justify;\"><strong>Cultural Harmony:</strong> Discover the meeting point of diverse cultures at <strong>Sam Po Kong Temple</strong> and the artistic alleys of <strong>Semarang Old Town</strong>.</p></li><li data-list-item-id=\"ebf3caa4d8521634336cc49416e15a578\"><p style=\"text-align:justify;\"><strong>Elegant Traditions:</strong> Get an intimate look at royal life within the walls of the <strong>Yogyakarta Palace (Keraton)</strong>, where tradition remains timeless.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>자바의 심장에서 문명의 발자취를 따라가는 여정</strong></h2><p style=\"text-align:justify;\">요그야카르타와 세마랑이 전 세계 여행객들을 매료시키는 데에는 특별한 이유가 있습니다. 이곳은 단순한 여행지를 넘어, 고대 왕조의 웅장함부터 식민지 시대의 낭만까지 아우르는 시간 여행의 통로입니다.</p><ul><li data-list-item-id=\"edd017bf434c082676f895cf69d26232c\"><p style=\"text-align:justify;\"><strong>역사의 침묵하는 증인:</strong> 아침 햇살이 떠오를 때, <strong>보로부두르 사원</strong>의 정교한 부조 앞에서 잊지 못할 감동을 느껴보세요.</p></li><li data-list-item-id=\"eff74c1db84b70b5f023ea3767006c76c\"><p style=\"text-align:justify;\"><strong>메라피의 숨결:</strong> 오픈 지프를 타고 <strong>메라피 화산</strong> 기슭을 달리며 대자연의 경이로움을 온몸으로 느껴보세요.</p></li><li data-list-item-id=\"e3a2277154311b9bc6037e98fa88212d6\"><p style=\"text-align:justify;\"><strong>문화의 조화:</strong> <strong>삼포콩 사원</strong>과 <strong>세마랑 올드타운</strong>의 예술적인 거리에서 다양한 문화가 어우러진 조화를 발견해 보세요.</p></li><li data-list-item-id=\"edf3e1f2b5f4e1b8b42fdc5f82254b1cb\"><p style=\"text-align:justify;\"><strong>전통의 품격:</strong> 오늘날까지 살아 숨 쉬는 요그야카르타 왕궁(Keraton)에서 자바 왕실의 우아한 삶을 가까이서 경험해 보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>追寻爪哇之心：一场穿越文明印记的旅程</strong></h2><p style=\"text-align:justify;\">日惹与三宝垄之所以成为全球旅客心中的向往之地，绝非偶然。这不仅是一次旅行，更是一条穿梭时空的隧道，带您从古老王朝的辉煌走向殖民城市的浪漫。</p><ul><li data-list-item-id=\"eef069119b543b7aec85d25f90ec23b80\"><p style=\"text-align:justify;\"><strong>历史的无声见证：</strong> 在晨曦微露时，伫立于<strong>婆罗浮屠寺</strong>精美绝伦的浮雕前，感受心灵的震撼。</p></li><li data-list-item-id=\"e46de5e10b9de87b06c1f3da8165e0bf1\"><p style=\"text-align:justify;\"><strong>默拉皮的呐喊：</strong> 乘坐敞篷吉普车驰骋在<strong>默拉皮火山</strong>脚下，近距离感受大自然的磅礴力量。</p></li><li data-list-item-id=\"eb1d060f73023c4b76ee0d2d917952687\"><p style=\"text-align:justify;\"><strong>多元文化的交响：</strong> 在<strong>三宝洞</strong>与<strong>三宝垄老城</strong>的艺术街巷中，寻找多元文化交融的痕迹。</p></li><li data-list-item-id=\"e0af65e3f999531e823a565f1ec97cefa\"><p style=\"text-align:justify;\"><strong>皇室传统的优雅：</strong> 走进至今仍散发着生命力的<strong>日惹皇宫 (Keraton)</strong>，领略爪哇皇室传承百年的高贵气质。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Culture\",\"heritage\",\"Adventure\",\"Nature\"]', NULL, 0, NULL, '2026-04-30 14:44:53', '2026-06-03 06:44:26'),
(29, 37, '4 DAYS JOGJA SOLO', 'CENTRAL JAVA', '4-days-jogja-solo', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Budaya Jawa: Paket Tour Eksklusif 4 Hari 3 Malam Jogja - Solo</strong></h2><p style=\"text-align:justify;\">Nikmati perjalanan tak terlupakan melintasi waktu dengan mengunjungi dua kota paling bersejarah di Indonesia. Dari kemegahan candi kuno yang diakui dunia hingga keanggunan istana kerajaan, paket ini dirancang untuk memberikan pengalaman budaya yang mendalam namun tetap santai dan nyaman.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"e46d7beb8bc7c9d2ddd2d2ac7a4e5ad0a\"><p style=\"text-align:justify;\"><strong>Destinasi Kelas Dunia dalam Satu Genggaman:</strong> Kunjungi <strong>Candi Borobudur</strong> (Candi Buddha terbesar di dunia) dan <strong>Candi Prambanan</strong> (Candi Hindu termegah di Indonesia) yang keduanya merupakan Situs Warisan Dunia UNESCO.</p></li><li data-list-item-id=\"e0932c6ef501f58dfd6c4cfbf27393ce0\"><p style=\"text-align:justify;\"><strong>Pengalaman Kerajaan yang Otentik:</strong> Masuki kediaman Sultan di <strong>Keraton Yogyakarta</strong> dan <strong>Istana Mangkunegaran Solo</strong> untuk melihat langsung tradisi Jawa yang masih terjaga hingga kini.</p></li><li data-list-item-id=\"e170ad817d94cf3042624210d068c4237\"><p style=\"text-align:justify;\"><strong>Surga Belanja &amp; Kuliner:</strong> Berburu barang antik unik di <strong>Pasar Triwindu</strong>, koleksi batik terbaik di <strong>Kampoeng Batik Laweyan</strong>, hingga berbelanja di <strong>Pasar Grosir Solo (PGS)</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Cultural Heart of Java: Exclusive 4D3N Jogja - Solo Heritage Tour</strong></h2><p style=\"text-align:justify;\">Experience an unforgettable journey through time as you visit Indonesia’s two most historic cities. From the grandeur of world-renowned ancient temples to the elegance of royal palaces, this tour is designed to offer a deep yet comfortable cultural immersion.</p><h3 style=\"text-align:justify;\"><strong>Why Choose This Tour?</strong></h3><ul><li data-list-item-id=\"ecc8dfe6a43237f9f5b08c25f6b771a1e\"><p style=\"text-align:justify;\"><strong>World-Class Landmarks:</strong> Visit <strong>Borobudur Temple</strong>, the world\'s largest Buddhist temple, and <strong>Prambanan Temple</strong>, Indonesia\'s most magnificent Hindu complex—both UNESCO World Heritage Sites.</p></li><li data-list-item-id=\"e6345a2871556f46073df3a306b1546ef\"><p style=\"text-align:justify;\"><strong>Authentic Royal Experience:</strong> Step into the Sultan’s residences at the <strong>Yogyakarta Palace</strong> and <strong>Solo’s Mangkunegaran Palace</strong> to witness Javanese traditions that remain alive today.</p></li><li data-list-item-id=\"ebacc821f89a05d7f7474b966884dbe94\"><p style=\"text-align:justify;\"><strong>Shopper’s &amp; Foodie’s Paradise:</strong> Hunt for unique treasures at <strong>Triwindu Antique Market</strong>, find premium batik at <strong>Laweyan Batik Village</strong>, and enjoy local shopping at <strong>Pasar Grosir Solo (PGS)</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>자바 문화의 심장을 탐험하다: 단독 4박 3일 족자카르타 - 솔로 헤리티지 투어</strong></h2><p style=\"text-align:justify;\">인도네시아에서 가장 역사적인 두 도시를 방문하며 잊지 못할 시간 여행을 경험해 보세요. 세계적으로 유명한 고대 사원의 웅장함부터 왕궁의 우아함까지, 이 투어는 깊이 있는 문화 체험과 편안한 휴식을 동시에 제공합니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ef2fdf05f1da3e3b63dcdaac9ad5e5f29\"><p style=\"text-align:justify;\"><strong>세계적 수준의 랜드마크:</strong> 유네스코 세계문화유산인 세계 최대 불교 사원 <strong>보로부두르</strong>와 인도네시아에서 가장 아름다운 힌두 사원인 <strong>프람바난</strong>을 방문합니다.</p></li><li data-list-item-id=\"e44aa3afd9f8cedc0ad923d141da73111\"><p style=\"text-align:justify;\"><strong>정통 왕실 체험:</strong> 오늘날까지 자바의 전통이 살아 숨 쉬는 족자카르타 왕궁(Keraton)과 <strong>솔로 망쿠네가란 왕궁</strong>을 직접 관람합니다.</p></li><li data-list-item-id=\"e68971bd8af2c28e5911f9dc0edcf8791\"><p style=\"text-align:justify;\"><strong>쇼핑과 미식의 천국:</strong> <strong>트리윈두 골동품 시장</strong>에서 특별한 보물을 찾고, <strong>라웨얀 바틱 마을</strong>에서 최고급 바틱을 만나보며, 솔로 도매 시장(PGS)에서 즐거운 쇼핑을 즐길 수 있습니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索爪哇文化之魂：独家 4天3夜 日惹 - 三罗 遗产之旅</strong></h2><p style=\"text-align:justify;\">带您跨越时空，造访印度尼西亚最具历史底蕴的两座城市。从享誉世界的古代神庙到高贵典雅的皇室宫殿，本次行程旨在为您提供深度且舒适的文化沉浸体验。</p><h3 style=\"text-align:justify;\"><strong>行程亮点与优势：</strong></h3><ul><li data-list-item-id=\"e4c15a608c677563ce468bb0098d0e688\"><p style=\"text-align:justify;\"><strong>世界级文化地标：</strong> 参观被列入联合国教科文组织世界遗产名录的全球最大佛教寺庙群——<strong>婆罗浮屠</strong>，以及印尼最宏伟的印度教寺庙——<strong>普兰巴南</strong>。</p></li><li data-list-item-id=\"e7ed15cfe4c60a79656a2a600c21cc380\"><p style=\"text-align:justify;\"><strong>正统皇室体验：</strong> 走进<strong>日惹皇宫</strong>与<strong>三罗曼古尼嘉兰皇宫</strong>，亲身领略至今仍在传承的爪哇皇室传统与礼仪。</p></li><li data-list-item-id=\"e338e72ff50c843182173b4e5d598a060\"><p style=\"text-align:justify;\"><strong>购物与艺术天堂：</strong> 在<strong>三轮渡 (Triwindu) 古董市场</strong>淘金，在<strong>拉威延 (Laweyan) 扎染村</strong>选购顶级蜡染艺术品，并在<strong>三罗批发市场 (PGS)</strong> 尽情购物。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Culture\",\"heritage\",\"shopping\",\"art\",\"City\"]', NULL, 0, NULL, '2026-04-30 14:59:09', '2026-06-03 07:10:49'),
(30, 37, '4 DAYS JOGJA TIMANG TOUR', 'YOGYAKARTA', '4-days-jogja-timang-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Magisnya Yogyakarta: Paket Tour 4 Hari 3 Malam Jogja - Timang</strong></h2><p style=\"text-align:justify;\">Nikmati kombinasi sempurna antara petualangan yang memacu adrenalin, kekayaan budaya bersejarah, dan keindahan alam yang tak terlupakan di Yogyakarta. Kami telah merancang perjalanan eksklusif selama 4 hari untuk memastikan Anda merasakan sisi terbaik dari Kota Pelajar ini.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"eee02c14e00639d6e68271c109edadfa9\"><p style=\"text-align:justify;\"><strong>Petualangan Tanpa Batas</strong>: Rasakan sensasi seru <strong>Lava Tour Merapi</strong> dengan mobil <i>jeep 4x4</i> melintasi jejak erupsi yang melegenda.</p></li><li data-list-item-id=\"ebb1b093d9896a808d23c3cd14c0380d4\"><p style=\"text-align:justify;\"><strong>Pengalaman Ikonik di Pantai Timang</strong>: Uji keberanian Anda menyeberangi laut dengan <strong>Gondola Tradisional</strong> yang terkenal di dunia—sebuah pengalaman unik yang dulunya hanya dilakukan oleh nelayan lobster lokal.</p></li><li data-list-item-id=\"e67353668ee3868fc5bbda0ddd19371a9\"><p style=\"text-align:justify;\"><strong>Sentuhan Sejarah Dunia</strong>: Berdiri megah di atas <strong>Candi Borobudur</strong>, mahakarya Dinasti Syailendra abad ke-9 yang telah diakui sebagai Situs Warisan Dunia UNESCO.</p></li><li data-list-item-id=\"eb76b62783b27d23bb73e19c1b162c47a\"><p style=\"text-align:justify;\"><strong>Golden Sunset &amp; Fenomena Langka</strong>: Nikmati matahari terbenam yang memukau di <strong>Obelix Seaview</strong> dengan panorama Samudra Hindia, serta kunjungi <strong>Gumuk Pasir</strong>, fenomena padang pasir langka yang hanya ada sedikit di dunia.</p></li><li data-list-item-id=\"ee47b44a9dc174e842e2397bc24acf127\"><p style=\"text-align:justify;\"><strong>Belanja &amp; Kuliner</strong>: Puaskan hasrat belanja Anda di sepanjang jalan <strong>Malioboro</strong> yang ikonik dan nikmati sajian kuliner lokal lezat yang sudah termasuk dalam paket perjalanan Anda.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4D3N Jogja - Timang Adventure &amp; Culture Package</strong></h2><p style=\"text-align:justify;\">Experience the perfect blend of adrenaline-pumping adventure, rich history, and breathtaking landscapes in Yogyakarta. We have designed this exclusive 4-day journey to ensure you experience the very best of Indonesia\'s cultural heart.</p><ul><li data-list-item-id=\"e92216b8b69b908a5683dd462a7dc30fd\"><p style=\"text-align:justify;\"><strong>Merapi Lava Tour</strong>: Feel the thrill of a 4x4 Jeep ride through the legendary eruption trails of Mount Merapi.</p></li><li data-list-item-id=\"e9d19177dcdf5bc7d1ef57d477df72fa8\"><p style=\"text-align:justify;\"><strong>Timang Beach Gondola</strong>: Test your courage on the world-famous traditional gondola, a unique experience originally used by local lobster fishermen.</p></li><li data-list-item-id=\"e16978bb12198eb7b496c5d4ba1eb29f4\"><p style=\"text-align:justify;\"><strong>Borobudur Temple</strong>: Stand atop the 9th-century masterpiece of the Syailendra Dynasty, a UNESCO World Heritage site.</p></li><li data-list-item-id=\"e637c0a035110a768fe4aeb78f2aebb7b\"><p style=\"text-align:justify;\"><strong>Golden Sunset &amp; Rare Landscapes</strong>: Enjoy a stunning sunset at Obelix Seaview and visit the Gumuk Pasir sand dunes, a rare geological phenomenon.</p></li><li data-list-item-id=\"ee75cb6cdfee914eed60ec68f7fbdad6d\"><p style=\"text-align:justify;\"><strong>Malioboro Street</strong>: Immerse yourself in the iconic shopping and culinary atmosphere of Yogyakarta.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>[4박 3일] 조그자 - 티망 어드벤처 &amp; 문화 체험 패키지</strong></h2><p style=\"text-align:justify;\">인도네시아의 영혼이라 불리는 요그야카르타(조그자)에서 짜릿한 모험과 찬란한 역사, 그리고 환상적인 자연을 만나보세요. 고객님께 최고의 추억을 선사할 최적의 4일 코스를 제안합니다.</p><ul><li data-list-item-id=\"e5eb8c09b336dd946048933fc623774b6\"><p style=\"text-align:justify;\"><strong>메라피 화산 라바 투어</strong>: 4x4 지프를 타고 전설적인 메라피 화산의 폭발 흔적을 가로지르는 스릴을 느껴보세요.</p></li><li data-list-item-id=\"e389b34a3a029f510a3906f4f19ae8340\"><p style=\"text-align:justify;\"><strong>티망 해변 곤돌라</strong>: 세계적으로 유명한 전통 곤돌라를 타고 바다를 건너는 용기에 도전해보세요. 현지 어부들의 삶이 담긴 특별한 경험입니다.</p></li><li data-list-item-id=\"e97c92c60c84d496167cf5aa25ad568c9\"><p style=\"text-align:justify;\"><strong>보로부두르 사원</strong>: 유네스코 세계문화유산이자 9세기 샤일렌드라 왕조의 걸작인 세계 최대 불교 사원을 탐방합니다.</p></li><li data-list-item-id=\"ef66849cceac1d29c7fa07b60a2609210\"><p style=\"text-align:justify;\"><strong>골든 선셋 &amp; 사구 체험</strong>: 오벨릭스 씨뷰에서 감동적인 노을을 감상하고, 세계적으로 희귀한 지형인 구묵 파시르 모래언덕을 방문합니다.</p></li><li data-list-item-id=\"e6cced52208b4843f6856f8ecd1271dca\"><p style=\"text-align:justify;\"><strong>말리오보로 거리</strong>: 요그야카르타의 상징적인 거리에서 쇼핑과 현지 먹거리를 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4天3晚 日惹 - 提芒海滩 探险与文化之旅</strong></h2><p style=\"text-align:justify;\">在日惹感受惊险刺激的探险、深厚的历史底蕴与令人窒息的自然美景。我们为您精心策划了为期4天的专属旅程，带您领略印尼文化之心的独特魅力。</p><ul><li data-list-item-id=\"ee6c74b0d87ee94b082f24a9be8542649\"><p style=\"text-align:justify;\"><strong>默拉皮火山熔岩巡礼</strong>: 搭乘 4x4 越野吉普车，穿梭在默拉皮火山传奇般的喷发遗迹中，感受速度与激情。</p></li><li data-list-item-id=\"ed8772a8a8fccb06b996b16488a04d552\"><p style=\"text-align:justify;\"><strong>提芒海滩木制缆车</strong>: 挑战世界闻名的传统手动缆车（Gondola），在惊涛骇浪上体验当地渔民抓捕龙虾的独特方式。</p></li><li data-list-item-id=\"e3c73f44dc2e95a9196b26c789c16e207\"><p style=\"text-align:justify;\"><strong>婆罗浮屠大佛塔</strong>: 走进联合国教科文组织世界遗产，仰望 9 世纪夏连特拉王朝留下的雄伟建筑瑰宝。</p></li><li data-list-item-id=\"ef7162a58aacfa81843602678410ebeb0\"><p style=\"text-align:justify;\"><strong>绝美夕阳与沙漠奇观</strong>: 在 Obelix Seaview 欣赏壮丽的海上日落，并探访南半球罕见的 Gumuk Pasir 海边沙丘。</p></li><li data-list-item-id=\"e9f53cd1216532d4e6453fb8597d46506\"><p style=\"text-align:justify;\"><strong>马里奥婆罗大街</strong>: 在日惹标志性的商业街尽情购物，品尝最地道的印尼风味美食。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"e96c898df4e25103ff67c5d2ecda67293\">Jeep Timang</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"Culture\",\"Historical\"]', NULL, 0, NULL, '2026-05-01 08:52:14', '2026-05-29 14:15:41'),
(31, 37, '4 DAYS JOGJA VILLAGE TOUR', 'YOGYAKARTA', '4-days-jogja-village-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Pesona Autentik Yogyakarta: 4D3N Jogja Village Tour</strong></h2><p style=\"text-align:justify;\">Nikmati perjalanan tak terlupakan ke jantung budaya Jawa dengan paket eksklusif <strong>4D3N Jogja Village Tour</strong>. Dirancang khusus untuk Anda yang mendambakan perpaduan antara edukasi budaya, petualangan alam yang memacu adrenalin, dan pengalaman lokal yang mendalam.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"ea1d77e622cef46cf010c4b382c699aa3\"><p style=\"text-align:justify;\"><strong>Pengalaman Budaya yang Mendalam</strong>: Jangan hanya melihat, tapi rasakan langsung menjadi bagian dari budaya lokal dengan mengikuti kursus membatik di Desa Wisata Giriloyo yang melegenda.</p></li><li data-list-item-id=\"e83cf7e27aaeef6758e2d7d1afd947fa2\"><p style=\"text-align:justify;\"><strong>Petualangan Alam Ikonik</strong>: Rasakan sensasi \"Cahaya Surga\" di dalam perut bumi Gua Jomblang menggunakan teknik <i>Single Rope</i> dan jelajahi keindahan stalaktit serta stalagmit di dalamnya.</p></li><li data-list-item-id=\"e582d6c69a1c6faa756b5c1c3835f1a9a\"><p style=\"text-align:justify;\"><strong>Tantangan Adrenalin di Pantai Timang</strong>: Uji keberanian Anda menyeberangi laut menuju pulau karang dengan gondola tradisional yang terkenal, sebuah pengalaman unik yang awalnya digunakan nelayan lobster lokal.</p></li><li data-list-item-id=\"edab15f9d0bfbfab9d5089079780fbb0d\"><p style=\"text-align:justify;\"><strong>Eksplorasi Warisan Dunia</strong>: Mengagumi kemegahan Candi Borobudur, mahakarya abad ke-9 dari Dinasti Syailendra yang telah diakui sebagai Situs Warisan Dunia UNESCO.</p></li><li data-list-item-id=\"e6942fffea6978388205039544584f955\"><p style=\"text-align:justify;\"><strong>Sentuhan Pedesaan yang Asri</strong>: Menikmati suasana autentik pedesaan di sekitar Prambanan dengan bersepeda santai melintasi industri rumah tangga tradisional dan berbagai spot foto eksotis.</p></li></ul>', '<h3 style=\"text-align:justify;\"><strong>Discover the Authentic Charms of Yogyakarta: 4D3N Jogja Village Tour</strong></h3><p style=\"text-align:justify;\">Experience an unforgettable journey into the heart of Javanese culture with our exclusive <strong>4D3N Jogja Village Tour</strong>. This package is specially designed for those seeking a perfect blend of cultural education, adrenaline-pumping nature adventures, and deep local experiences.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Try This Tour?</strong></h3><ul><li data-list-item-id=\"e09092383b07f2df037bcc854e04266a6\"><p style=\"text-align:justify;\"><strong>Immersive Cultural Experience</strong>: Don’t just watch—become part of the local culture by taking a traditional Batik course at the legendary Giriloyo Village.</p></li><li data-list-item-id=\"ee65c9d81a43c3969522f45ad85dba151\"><p style=\"text-align:justify;\"><strong>Iconic Natural Adventure</strong>: Witness the \"Light of Heaven\" inside the Jomblang Cave using the Single Rope Technique, guided by professionals to explore stunning stalactites and stalagmites.</p></li><li data-list-item-id=\"e4d8f3b5b2807500ee1462d5c9cb735db\"><p style=\"text-align:justify;\"><strong>Adrenaline Rush at Timang Beach</strong>: Test your courage by crossing the ocean to a rocky island on a traditional wooden gondola, a unique experience originally used by local lobster fishermen.</p></li><li data-list-item-id=\"e4d14682834af7392e79da668cf61db83\"><p style=\"text-align:justify;\"><strong>World Heritage Exploration</strong>: Marvel at the grandeur of Borobudur Temple, a 9th-century masterpiece of the Sailendra Dynasty and a UNESCO World Heritage Site.</p></li><li data-list-item-id=\"e9128182b54c220e89f13cf7df6d00947\"><p style=\"text-align:justify;\"><strong>Serene Village Atmosphere</strong>: Enjoy the authentic rural vibes around Prambanan by cycling through traditional home industries and picturesque photo spots.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>요그야카르타의 진정한 매력 발견: 4박 3일 족자 빌리지 투어</strong></h2><p style=\"text-align:justify;\">독점적인 <strong>4박 3일 족자 빌리지 투어</strong>와 함께 자바 문화의 심장부로 떠나는 잊지 못할 여행을 경험해 보세요. 이 패키지는 문화 교육, 아드레날린이 솟구치는 자연 모험, 그리고 깊이 있는 현지 체험의 완벽한 조화를 원하는 분들을 위해 특별히 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e8873be8652b2e4d6f03a39f833cce095\"><p style=\"text-align:justify;\"><strong>몰입형 문화 체험</strong>: 단순히 보는 것에 그치지 않고, 전설적인 기릴로요(Giriloyo) 마을에서 전통 바틱(Batik) 코스를 배우며 현지 문화의 일부가 되어보세요.</p></li><li data-list-item-id=\"e64b487659807713756d5e778dd5b57be\"><p style=\"text-align:justify;\"><strong>상징적인 자연 모험</strong>: 전문가의 도움을 받아 싱글 로프 기술로 좀블랑(Jomblang) 동굴 내부의 \"천국의 빛\"을 감상하고 환상적인 종유석과 석순을 탐험하세요.</p></li><li data-list-item-id=\"e9e595fcdad51fd95ab7f621df8833f52\"><p style=\"text-align:justify;\"><strong>티망 해변의 스릴</strong>: 원래 현지 랍스터 어부들이 사용하던 전통 나무 곤돌라를 타고 바다를 건너 바위섬으로 이동하며 용기를 시험해 보세요.</p></li><li data-list-item-id=\"e9d52b8e206cf1cb23fc5eb73b4a05833\"><p style=\"text-align:justify;\"><strong>세계 유산 탐방</strong>: 9세기 샤일렌드라 왕조의 걸작이자 유네스코 세계문화유산인 보로부두르 사원의 웅장함에 감탄해 보세요.</p></li><li data-list-item-id=\"e1df4d86d3c45ef1b23463b2befdd88c7\"><p style=\"text-align:justify;\"><strong>평화로운 시골 분위기</strong>: 전통 가내 공업 단지와 아름다운 포토존을 지나며 자전거를 타고 프람바난 주변의 진정한 시골 정취를 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索日惹的纯正魅力：4天3夜 日惹乡村之旅</strong></h2><p style=\"text-align:justify;\">加入我们专属的 <strong>4天3夜 日惹乡村之旅</strong>，开启一段难忘的爪哇文化核心之旅。该套餐专为追求文化教育、刺激自然冒险和深度当地体验的游客量身定制。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"e11dfd6a50e2bb476f4e9a42e77540805\"><p style=\"text-align:justify;\"><strong>沉浸式文化体验</strong>：不仅是参观，您还可以在传奇的 Giriloyo 村参加传统蜡染 (Batik) 课程，亲身感受当地文化。</p></li><li data-list-item-id=\"ec113d94ba5b1e1262fe7ea54b1efb7af\"><p style=\"text-align:justify;\"><strong>标志性自然探险</strong>：在专业人士的协助下，使用单绳技术进入 Jomblang 洞穴，见证震撼的“天堂之光”，并探索壮观的钟乳石和石笋。</p></li><li data-list-item-id=\"e8641edfcdc3b4d38adc67ac8b485179b\"><p style=\"text-align:justify;\"><strong>天芒海滩的极限挑战</strong>：乘坐传统的木制贡多拉（原为当地渔民捕捞龙虾所用）横跨大海前往礁石岛，挑战您的胆量。</p></li><li data-list-item-id=\"e10dfd72cfca1384936cd1998e9ecf152\"><p style=\"text-align:justify;\"><strong>世界遗产探索</strong>：瞻仰婆罗浮屠寺庙的宏伟，这座 9 世纪夏连特拉王朝的杰作已被列入联合国教科文组织世界遗产名录。</p></li><li data-list-item-id=\"ed3cfe18ee1c579b410fc38d0f0afa159\"><p style=\"text-align:justify;\"><strong>宁静的乡村气息</strong>：骑自行车穿越普兰巴南周边的传统家庭手工业区和风景如画的拍照点，享受最纯粹的田园风光。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"e96c898df4e25103ff67c5d2ecda67293\">Jeep Timang</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Air mineral</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Plane &amp; Train Tickets</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Tipping guide</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Personal expenses</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Optional tours and meals</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Additional fees during high season and national holidays</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"Culture\",\"HERITAGE\"]', NULL, 0, NULL, '2026-05-01 09:21:33', '2026-05-29 14:14:26'),
(32, 37, '5 DAYS JOGJA DIENG', 'CENTRAL JAVA', '5-days-jogja-dieng', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Keajaiban Budaya &amp; Alam: 5D4N Jogja Dieng Experience</strong></h2><p style=\"text-align:justify;\">Nikmati perjalanan tak terlupakan melintasi jantung budaya Jawa hingga ke \"Negeri di Atas Awan\". Paket eksklusif ini dirancang khusus bagi Anda yang mendambakan perpaduan sempurna antara petualangan alam yang menakjubkan dan warisan sejarah yang megah.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"edc448af8cb44e307ffe9c2f4c2904990\"><p style=\"text-align:justify;\"><strong>Petualangan \"Negeri di Atas Awan\":</strong> Rasakan sensasi udara dingin yang menyegarkan di Dataran Tinggi Dieng, kunjungi kompleks Candi Arjuna yang mistis, serta saksikan keajaiban alam di Kawah Sikidang dan keindahan gradasi warna di Telaga Warna.</p></li><li data-list-item-id=\"e1b207867ec33f5281725ae34ee807cdd\"><p style=\"text-align:justify;\"><strong>Sentuhan Sejarah Dunia:</strong> Berdiri megah di atas stupa Candi Borobudur, situs warisan dunia UNESCO yang legendaris, serta jelajahi jejak sejarah Kerajaan Mataram di Candi Mendut dan Candi Pawon.</p></li><li data-list-item-id=\"e92f017a4af670b2226789c5b2788b78e\"><p style=\"text-align:justify;\"><strong>Eksplorasi Budaya Autentik:</strong> Rasakan kemewahan Keraton Yogyakarta dan keunikan Taman Sari Watercastle. Anda juga akan diajak bersepeda santai melintasi pedesaan asri untuk melihat langsung kreativitas industri rumah tangga lokal.</p></li><li data-list-item-id=\"eaebade4b4f469c25923d4d856258fde3\"><p style=\"text-align:justify;\"><strong>Spot Foto Instagramable:</strong> Abadikan momen terbaik Anda di spot ikonik \"Tangan Raksasa\" Hutan Pinus Pengger dan nikmati panorama kota Yogyakarta yang memukau dari ketinggian Heha Skyview.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore Cultural &amp; Natural Wonders: 5D4N Jogja Dieng Experience</strong></h2><p style=\"text-align:justify;\">Experience an unforgettable journey through the cultural heart of Java to the \"Land Above the Clouds.\" This exclusive package is specially designed for those seeking a perfect blend of breathtaking natural adventures and majestic historical heritage.</p><h3 style=\"text-align:justify;\"><strong>Why Should You Choose This Package?</strong></h3><ul><li data-list-item-id=\"e1d38944543747de2fb822e94d004b4b8\"><p style=\"text-align:justify;\"><strong>\"Land Above the Clouds\" Adventure:</strong> Feel the refreshing cool breeze of the Dieng Plateau, visit the mystical Arjuna Temple complex, and witness the natural wonders of Sikidang Crater and the stunning color gradations of Telaga Warna (Color Lake).</p></li><li data-list-item-id=\"eaa0b8b889a613f30adc5dbf85f90f708\"><p style=\"text-align:justify;\"><strong>A Touch of World History:</strong> Stand in awe atop the stupas of Borobudur Temple, a legendary UNESCO World Heritage site, and explore the remnants of the Mataram Kingdom at Mendut and Pawon Temples.</p></li><li data-list-item-id=\"eb80acfaba9facc9e5236fbc0adbfda04\"><p style=\"text-align:justify;\"><strong>Authentic Cultural Exploration:</strong> Experience the grandeur of the Yogyakarta Royal Palace (Keraton) and the unique Water Castle (Taman Sari). You will also enjoy a leisurely bicycle ride through charming villages to see the creativity of local home industries firsthand.</p></li><li data-list-item-id=\"e5d906fccdbd7b64c6b07dd054ffde846\"><p style=\"text-align:justify;\"><strong>Instagrammable Photo Spots:</strong> Capture your best moments at the iconic \"Giant Hand\" of Pinus Pengger Forest and enjoy the breathtaking panoramic view of Yogyakarta city from the heights of Heha Skyview.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>문화와 자연의 경이로움: 5박 4일 족자카르타 &amp; 디엥 익스피리언스</strong></h2><p style=\"text-align:justify;\">자바 문화의 심장부에서 \"구름 위의 땅\"까지 잊지 못할 여정을 떠나보세요. 이 익스클루시브 패키지는 환상적인 자연 모험과 웅장한 역사 유산의 완벽한 조화를 원하는 분들을 위해 특별히 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 패키지를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e648f62adafd5bd847b7d4a3642cd3808\"><p style=\"text-align:justify;\"><strong>\"구름 위의 땅\" 어드벤처:</strong> 디엥 고원(Dieng Plateau)의 상쾌하고 시원한 공기를 느끼며 신비로운 아르주나 사원 단지를 방문해 보세요. 시키당 화산 분화구와 오묘한 빛깔을 자랑하는 텔라가 와르나(색깔 호수)의 경이로움을 만끽할 수 있습니다.</p></li><li data-list-item-id=\"e7f4f2773b3d5a8c1f80b0a65455250c1\"><p style=\"text-align:justify;\"><strong>세계 역사의 숨결:</strong> 유네스코 세계문화유산인 전설적인 보로부두르 사원 스투파 위에 서서 압도적인 경관을 감상하고, 문둣 사원과 파원 사원에서 마타람 왕국의 발자취를 탐험합니다.</p></li><li data-list-item-id=\"ee489271cd6e246c450c4609f2eb0288d\"><p style=\"text-align:justify;\"><strong>정통 문화 체험:</strong> 족자카르타 왕궁(Keraton)의 화려함과 타만 사리(Taman Sari) 물의 궁전의 독특함을 경험해 보세요. 또한 평화로운 시골 마을을 자전거로 달리며 현지 가내 공업의 창의적인 현장을 직접 확인하실 수 있습니다.</p></li><li data-list-item-id=\"ebb232d32aa5fb18d13dd13615690b61c\"><p style=\"text-align:justify;\"><strong>인생샷 명소:</strong> 피누스 펭게르(Pinus Pengger) 숲의 상징인 \'거인의 손\'에서 최고의 순간을 기록하고, 헤하 스카이뷰(Heha Skyview)에서 내려다보는 족자카르타 시내의 환상적인 파노라마 뷰를 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索文化与自然的奇迹：5天4夜 日惹 &amp; 迪恩高原之旅</strong></h2><p style=\"text-align:justify;\">开启一段从爪哇文化核心地带走向“云端之城”的难忘旅程。此专属行程专为渴望将惊叹的自然冒险与宏伟历史遗迹完美结合的人士量身打造。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"e644650d0bde4b5a271235b12368e1b16\"><p style=\"text-align:justify;\"><strong>“云端之上”的冒险：</strong> 感受迪恩高原（Dieng Plateau）清爽宜人的凉爽空气，参观神秘的阿周那神庙群（Arjuna Temple），见证西基当火山口（Sikidang Crater）的自然奇观以及色彩斑斓的五彩湖（Telaga Warna）。</p></li><li data-list-item-id=\"ee9c0f179f54f499973cf1e5c70fe0ef8\"><p style=\"text-align:justify;\"><strong>触碰世界历史：</strong> 登上被列入联合国教科文组织世界遗产名录的婆罗浮屠寺（Borobudur Temple），感受这座传奇古迹的震撼，并探索门都神庙（Mendut）和帕翁神庙（Pawon）中的马打兰王国足迹。</p></li><li data-list-item-id=\"e5d71bb55d37d82cab67d9684661b720b\"><p style=\"text-align:justify;\"><strong>地道的文化探索：</strong> 领略日惹苏丹皇宫（Keraton）的奢华与水宫（Taman Sari）的独特魅力。您还将体验悠闲的乡村单车之旅，亲眼见证当地家庭手工业的匠心创意。</p></li><li data-list-item-id=\"e719081c005883f2ca45aa4aade721067\"><p style=\"text-align:justify;\"><strong>网红打卡圣地：</strong> 在松林（Pinus Pengger）标志性的“巨人手掌”拍下最美瞬间，并在 Heha Skyview 的高处俯瞰日惹市壮丽的全景。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Mineral udara</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Tiket Pesawat &amp; Kereta Api</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Panduan pemberian tip</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Pengeluaran pribadi</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Tur dan makanan opsional</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Biaya tambahan saat high season dan hari libur nasional</li></ul>', NULL, '[\"Culture\",\"HERITAGE\",\"Nature\"]', NULL, 0, NULL, '2026-05-01 10:44:37', '2026-05-29 14:13:27');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(33, 37, '5 DAYS JOGJA SEMARANG', 'CENTRAL JAVA', '5-days-jogja-semarang', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Warisan Jawa: 5D4N Jogja Semarang Heritage &amp; Adventure</strong></h2><p style=\"text-align:justify;\">Rasakan perpaduan sempurna antara kemegahan sejarah, petualangan yang memacu adrenalin, dan panorama modern yang memukau. Dari keunikan arsitektur di Semarang hingga kemegahan Borobudur di Yogyakarta, paket ini dirancang khusus untuk membawa Anda melintasi waktu dan menikmati kekayaan budaya Jawa yang tak tertandingi.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e1b00e84b47da11fa786fd18d96367e79\"><p style=\"text-align:justify;\"><strong>Eksplorasi Dua Kota Ikonik Sekaligus:</strong> Nikmati kemudahan akses mengunjungi landmark terbaik di Semarang seperti Lawang Sewu dan Kota Lama, sekaligus menjelajahi jantung budaya di Yogyakarta dalam satu rangkaian perjalanan yang efisien.</p></li><li data-list-item-id=\"e58d921d1fc805aaa7ea4dce939f6692f\"><p style=\"text-align:justify;\"><strong>Petualangan Jeep Merapi yang Seru:</strong> Rasakan sensasi memacu adrenalin dengan Jeep 4x4 di jalur lava Gunung Merapi, mengunjungi Bunker Kaliadem, \"Alien Rock\", dan museum sisa erupsi untuk pengalaman yang mendalam.</p></li><li data-list-item-id=\"e1b6c29827f4bef0e02ca5d5585fe78ce\"><p style=\"text-align:justify;\"><strong>Akses ke Situs Warisan Dunia UNESCO:</strong> Berdiri di atas stupa Candi Borobudur, candi Buddha terbesar di dunia, serta jelajahi jejak sejarah Kerajaan Mataram di Candi Mendut dan Candi Pawon.</p></li><li data-list-item-id=\"eaad6a3fbc0ac70597d0886c40fd07be5\"><p style=\"text-align:justify;\"><strong>Eksplorasi Budaya Autentik:</strong> Masuki area Keraton Yogyakarta yang masih memegang teguh adat istiadat dan jelajahi keunikan arsitektur Taman Sari Watercastle, tempat peristirahatan keluarga Sultan.</p></li><li data-list-item-id=\"e4cc87191499e0162db49b978834c4568\"><p style=\"text-align:justify;\"><strong>Spot Foto Instagramable &amp; Kekinian:</strong> Abadikan momen terbaik Anda di spot ikonik \"Tangan Raksasa\" Hutan Pinus Pengger dan nikmati panorama kota Yogyakarta yang spektakuler dari ketinggian Heha Skyview.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Heritage of Java: 5D4N Jogja Semarang Heritage &amp; Adventure</strong></h2><p style=\"text-align:justify;\">Experience the perfect blend of majestic history, adrenaline-pumping adventures, and breathtaking modern panoramas. From the unique architecture of Semarang to the grandeur of Borobudur in Yogyakarta, this package is specially designed to take you back in time and enjoy the unrivaled cultural richness of Java.</p><h3 style=\"text-align:justify;\"><strong>Why Choose This Package?</strong></h3><ul><li data-list-item-id=\"e0a44ad222e230124eda03ec3f3aff7c9\"><p style=\"text-align:justify;\"><strong>Explore Two Iconic Cities At Once:</strong> Enjoy easy access to Semarang\'s best landmarks, such as Lawang Sewu and the Old Town, while exploring the cultural heart of Yogyakarta in one efficient journey.</p></li><li data-list-item-id=\"e0a8385c31b03c2e0d8574a1104bef8c0\"><p style=\"text-align:justify;\"><strong>Thrilling Merapi Lava Tour:</strong> Feel the adrenaline rush in a 4x4 Jeep across the Mount Merapi lava path, visiting the Kaliadem Bunker, \"Alien Rock,\" and a museum of eruption remnants for a profound experience.</p></li><li data-list-item-id=\"ed393428f7b410dd305bcbb896000bea0\"><p style=\"text-align:justify;\"><strong>UNESCO World Heritage Access:</strong> Stand atop the stupas of Borobudur Temple, the world\'s largest Buddhist temple, and explore the Mataram Kingdom\'s history at Mendut and Pawon Temples.</p></li><li data-list-item-id=\"e06961b814d18799b1e2822fc1a3c124f\"><p style=\"text-align:justify;\"><strong>Authentic Cultural Exploration:</strong> Enter the Yogyakarta Sultan\'s Palace, where ancient traditions are still practiced, and explore the unique architecture of Taman Sari Watercastle, the former royal recreation garden.</p></li><li data-list-item-id=\"e6a5dcb5dbc6cb09362bb8a3726bb7729\"><p style=\"text-align:justify;\"><strong>Instagrammable &amp; Trendy Spots:</strong> Capture your best moments at the iconic \"Giant Hand\" of Pinus Pengger Forest and enjoy a spectacular panoramic view of Yogyakarta from the heights of Heha Skyview.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>자바의 유산: 5박 4일 족자카르타 &amp; 세마랑 헤리티지 어드벤처</strong></h2><p style=\"text-align:justify;\">웅장한 역사와 아드레날린이 솟구치는 모험, 그리고 현대적인 파노라마 뷰의 완벽한 조화를 경험해 보세요. 세마랑의 독특한 건축물부터 족자카르타 보로부두르의 장엄함까지, 이 패키지는 자바의 타의 추종을 불허하는 풍부한 문화를 즐길 수 있도록 특별히 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 패키지를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e9de124944a69455c6bcdfc478cdd7a30\"><p style=\"text-align:justify;\"><strong>두 개의 상징적인 도시를 한 번에:</strong> 세마랑의 라왕 세우(Lawang Sewu)와 올드타운 같은 최고의 명소를 방문하는 동시에, 자바 문화의 중심지인 족자카르타를 한 번에 효율적으로 여행할 수 있습니다.</p></li><li data-list-item-id=\"e2cab10d86c68a3528ea5263dbddcda28\"><p style=\"text-align:justify;\"><strong>스릴 넘치는 메라피 라바 투어:</strong> 4x4 지프를 타고 메라피 화산의 용암 길을 달리는 짜릿함을 느껴보세요. 칼리아뎀 벙커, \'외계인 바위\', 그리고 화산 폭발의 흔적이 담긴 박물관을 방문하며 깊은 감동을 선사합니다.</p></li><li data-list-item-id=\"ea4033305287211442b0b06b5564efbbf\"><p style=\"text-align:justify;\"><strong>유네스코 세계문화유산 탐방:</strong> 세계 최대 불교 사원인 보로부두르 사원의 스투파 위에 서서 장관을 감상하고, 문둣 사원과 파원 사원에서 마타람 왕국의 역사를 탐험해 보세요.</p></li><li data-list-item-id=\"e59c8eeb052e515d9615103c6211dffd0\"><p style=\"text-align:justify;\"><strong>정통 문화 체험:</strong> 고대 관습이 여전히 살아 숨 쉬는 족자카르타 왕궁(Keraton)을 관람하고, 왕실의 휴양지였던 타만 사리(Taman Sari) 물의 궁전의 독특한 건축미를 감상해 보세요.</p></li><li data-list-item-id=\"ecb3e083d9d63990859883d42c36d930c\"><p style=\"text-align:justify;\"><strong>인생샷 명소와 트렌디한 스팟:</strong> 피누스 펭게르(Pinus Pengger) 숲의 상징인 \'거인의 손\'에서 최고의 순간을 기록하고, 헤하 스카이뷰(Heha Skyview)에서 내려다보는 족자카르타의 환상적인 전경을 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>爪哇遗产：5天4夜 日惹 &amp; 三宝垄 历史与冒险之旅</strong></h2><p style=\"text-align:justify;\">感受宏伟历史、惊险冒险与现代壮丽全景的完美结合。从三宝垄独特的建筑风格到日惹婆罗浮屠的雄伟壮观，此行程专为带您穿越时空，领略爪哇无可比拟的文化底蕴而设计。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"ebcb27626d46a95ca967b62e12c7cb093\"><p style=\"text-align:justify;\"><strong>一次游览两座标志性城市：</strong> 在一趟高效的旅程中，既能轻松游览三宝垄的最佳地标（如千门大楼和老城区），又能深入探索日惹的文化核心。</p></li><li data-list-item-id=\"ea693aec86a2f4e4900fff18a833f3608\"><p style=\"text-align:justify;\"><strong>惊险刺激的默拉皮火山熔岩之旅：</strong> 乘坐 4x4 越野吉普车驰骋在默拉皮火山的熔岩路径上，参观卡里亚德姆地堡、“外星石”以及火山喷发遗迹博物馆，获得深刻的体验。</p></li><li data-list-item-id=\"ef99add5357941e77ef8b71f8b47c3ee0\"><p style=\"text-align:justify;\"><strong>探访联合国教科文组织世界遗产：</strong> 登上世界最大的佛教寺庙——婆罗浮屠寺的佛塔，并探索门都神庙和帕翁神庙中马打兰王国的历史足迹。</p></li><li data-list-item-id=\"ee698f88e8b99e7c45f956dbb0036e330\"><p style=\"text-align:justify;\"><strong>地道的文化探索：</strong> 走进至今仍沿袭古老习俗的日惹苏丹皇宫，探索曾作为皇室休闲花园的水宫（Taman Sari）那独特的建筑艺术。</p></li><li data-list-item-id=\"e8cad29cabf228f642526e7caa241ee98\"><p style=\"text-align:justify;\"><strong>网红打卡与流行景点：</strong> 在松林（Pinus Pengger）标志性的“巨人手掌”拍下最美瞬间，并在 Heha Skyview 的高处俯瞰日惹市壮丽的全景。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e176377e9f9f3bb890a37350fc6200480\">Transportasi</li><li data-list-item-id=\"e37e17202ede7e2bce9c7cc0f7ebdcdbe\">Hotel Berbasis TWN/TRP</li><li data-list-item-id=\"ef639c2ab639dae2695feba0d2a915065\">Jeep Merapi</li><li data-list-item-id=\"eae15976a6558c985d59afc5e2c04a4b0\">Biaya Masuk &amp; Parkir</li><li data-list-item-id=\"ee70633c2d19ec3a3f680a1fde9db15e8\">Panduan Berbahasa Inggris</li><li data-list-item-id=\"eb77fc78052822acd44af7307bfd30648\">Makanan sesuai program</li><li data-list-item-id=\"e090af7bba2fe2602fd028ad7644fae42\">Mineral udara</li></ul>', '<ul><li data-list-item-id=\"e5065c3c281d87ebc2516d08b3a438c92\">Tiket Pesawat &amp; Kereta Api</li><li data-list-item-id=\"e5a30950afa0f4232a3480ad53ca5d9f4\">Panduan pemberian tip</li><li data-list-item-id=\"ea34c6f9dc36d6ded8f1f6d7bdb4a890e\">Pengeluaran pribadi</li><li data-list-item-id=\"e4bfbad70d192c8cc672a6aaf957f496c\">Tur dan makanan opsional</li><li data-list-item-id=\"ea926810a217f2c223347cd34680e4e5a\">Biaya tambahan saat high season dan hari libur nasional</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"HERITAGE\",\"LEISURE\"]', NULL, 0, NULL, '2026-05-01 11:01:05', '2026-05-29 14:12:19'),
(34, 38, '3 DAYS ORANG UTAN TOUR', 'NORTH SUMATRA', '3-days-orang-utan-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Sumatra: Petualangan Menegangkan Bersama Orang Utan!</strong></h2><p style=\"text-align:justify;\">Pernahkah Anda bermimpi menembus lebatnya hutan hujan tropis dan bertemu langsung dengan salah satu primata paling cerdas di dunia? Paket <strong>3D2N Orang Utan Tour</strong> kami mengajak Anda meninggalkan hiruk-pikuk kota menuju kedamaian Bukit Lawang, rumah bagi Orang Utan Sumatra yang megah.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e35f3227c2dff886ba9fdacabcfd0ae0d\"><p style=\"text-align:justify;\"><strong>Pengalaman \"Face-to-Face\" yang Tak Terlupakan</strong>: Nikmati trekking selama 3 jam di jantung Taman Nasional di mana Anda berkesempatan melihat Orang Utan secara langsung di habitat aslinya.</p></li><li data-list-item-id=\"e06ddee5927d893cfc8b1c1373d6cf9c5\"><p style=\"text-align:justify;\"><strong>Keanekaragaman Hayati yang Kaya</strong>: Selain Orang Utan, jika beruntung Anda dapat menjumpai <i>Leaf Monkey</i>, Macaque, Siamang, hingga berbagai spesies burung eksotis yang hanya ada di hutan Sumatra.</p></li><li data-list-item-id=\"eb13d96c4eb42e5f6275723472adb3daf\"><p style=\"text-align:justify;\"><strong>Petualangan yang Fleksibel</strong>: Tidak perlu khawatir dengan stamina Anda; kecepatan trekking akan disesuaikan dengan kondisi fisik Anda agar perjalanan tetap nyaman dan menyenangkan.</p></li><li data-list-item-id=\"e701493151afebad2ad2ec966a995482e\"><p style=\"text-align:justify;\"><strong>Pemandu Profesional &amp; Berpengalaman</strong>: Perjalanan Anda akan didampingi oleh pemandu berbahasa Inggris yang ahli, memastikan keamanan dan memberikan wawasan mendalam tentang flora serta fauna hutan tropis.</p></li><li data-list-item-id=\"ee19b61494aa1d6b96dd6f45a7323d948\"><p style=\"text-align:justify;\"><strong>Fasilitas Lengkap &amp; Nyaman</strong>: Kami menyediakan transportasi ber-AC, akomodasi bernuansa alam yang otentik, serta air mineral selama perjalanan.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Heart of Sumatra: An Unforgettable Adventure with Orangutans!</strong></h2><p style=\"text-align:justify;\">Have you ever dreamed of stepping into a lush tropical rainforest and meeting one of the world\'s most intelligent primates face-to-face? Our <strong>3D2N Orang Utan Tour</strong> takes you away from the city\'s hustle and bustle to the serene Bukit Lawang, the majestic home of the Sumatran Orangutan.</p><h3 style=\"text-align:justify;\"><strong>Why Choose This Tour?</strong></h3><ul><li data-list-item-id=\"ef5b07476baa263dc39570541209d1118\"><p style=\"text-align:justify;\"><strong>Up-Close Encounter</strong>: Experience a 3-hour jungle trek to see semi-wild or wild Orangutans in their natural habitat.</p></li><li data-list-item-id=\"eea029f5738c156cfdde6d71d2b86ecc4\"><p style=\"text-align:justify;\"><strong>Rich Biodiversity</strong>: Discover indigenous flora and fauna, including leaf monkeys, macaques, gibbons, and vibrant birdlife.</p></li><li data-list-item-id=\"e2995ab7ee64045fe776f56c22801cac1\"><p style=\"text-align:justify;\"><strong>Flexible &amp; Personal</strong>: Trekking paces are adjusted to your stamina, ensuring a comfortable journey for everyone.</p></li><li data-list-item-id=\"eb1b9344805f87ff9ff1a8a2fd80ea0b0\"><p style=\"text-align:justify;\"><strong>Hassle-Free Travel</strong>: Includes English-speaking guides, air-conditioned transport, and cozy nature-themed accommodations.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>수마트라의 심장을 탐험하세요: 오랑우탄과 함께하는 잊지 못할 모험!</strong></h2><p style=\"text-align:justify;\">울창한 열대우림 속으로 들어가 세계에서 가장 영리한 영장류 중 하나를 직접 만나는 꿈을 꾸어본 적이 있나요? <strong>3D2N 오랑우탄 투어</strong>는 도시의 소음에서 벗어나 수마트라 오랑우탄의 고향인 평화로운 부낏 라왕(Bukit Lawang)으로 여러분을 초대합니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ecd80109466d1e3d2b737c6155e3b9545\"><p style=\"text-align:justify;\"><strong>생생한 야생 체험</strong>: 3시간 동안의 정글 트레킹을 통해 자연 서식지에서 살고 있는 야생 오랑우탄을 직접 관찰할 수 있습니다.</p></li><li data-list-item-id=\"e2c02a6ef2bc5936c219d584a286d2055\"><p style=\"text-align:justify;\"><strong>풍부한 생태계</strong>: 오랑우탄뿐만 아니라 리프 원숭이, 마카크, 기번, 그리고 다양한 희귀 조류들을 만날 기회가 주어집니다.</p></li><li data-list-item-id=\"e5fabf2ec2701014dea9fa007331b83c6\"><p style=\"text-align:justify;\"><strong>맞춤형 트레킹</strong>: 고객님의 체력에 맞춰 트레킹 속도를 조절하므로 누구나 부담 없이 즐길 수 있습니다.</p></li><li data-list-item-id=\"ea2aa14c61781f25f101bd4b3f7cda977\"><p style=\"text-align:justify;\"><strong>편안한 서비스</strong>: 영어 가이드, 에어컨 차량, 그리고 자연 친화적인 숙소가 포함되어 있어 안심하고 여행할 수 있습니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索苏门答腊之心：与红毛猩猩开启难忘的冒险之旅！</strong></h2><p style=\"text-align:justify;\">您是否梦想过深入茂密的热带雨林，与世界上最聪明的灵长类动物面对面？我们的 <strong>3D2N 红毛猩猩之旅</strong> 将带您远离城市喧嚣，前往苏门答腊红毛猩猩的故乡——宁静的武吉拉旺 (Bukit Lawang)。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"e1ff4cb5442350eb17af6228bbce2c8bd\"><p style=\"text-align:justify;\"><strong>近距离接触</strong>: 体验 3 小时的丛林徒步，在自然栖息地观察半野生或野生的红毛猩猩。</p></li><li data-list-item-id=\"eb52ecffc0a6cf25f998a9cbea0ecfb50\"><p style=\"text-align:justify;\"><strong>丰富的生物多样性</strong>: 除了红毛猩猩，您还有机会看到长尾猴、猕猴、长臂猿以及种类繁多的热带鸟类。</p></li><li data-list-item-id=\"ef215d4da64c7d7a1930ea814d1e78d85\"><p style=\"text-align:justify;\"><strong>贴心的徒步安排</strong>: 徒步速度将根据您的体力进行调整，确保旅程既刺激又舒适。</p></li><li data-list-item-id=\"e0d6455538679b51fbee0e3775f1a2363\"><p style=\"text-align:justify;\"><strong>全方位服务</strong>: 包含英文导游、空调专车接送以及极具当地特色的自然民宿。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ea1f84ff2ccc434aacc1502f5b5210d90\">English Spk Guide</li><li data-list-item-id=\"e463e7d158472039a3ea62c3a2f755cf9\">Transportation in air-conditioned transportation</li><li data-list-item-id=\"ee104b9e602f1a145759e8f48600d6885\">All tours &amp; transfers&nbsp;</li><li data-list-item-id=\"e2ce0421534c8adcc29dfc39d18a4f66b\">Entrance fees as per above mentioned program</li><li data-list-item-id=\"e591e0f069ef1fdc95cbaae57d4128a39\">Accommodation&nbsp;at mentioned hotels&nbsp;and&nbsp;b\'fast&nbsp;as per program</li><li data-list-item-id=\"e4ecac6b83d891976c5b1715b5ad266a6\">Mineral water&nbsp;in the car.&nbsp;&nbsp;</li></ul>', '<ul><li data-list-item-id=\"e75ef665428c1bc22d1165834e241ddd0\">Flight tickets</li><li data-list-item-id=\"ec7eea0fd03f044d27b1ce9221ba2ef71\">Airport tax</li><li data-list-item-id=\"e635222216e919e4ad4aeb186cc6baa57\">Insurance</li><li data-list-item-id=\"e00e1e521472ee0f2039fc27d4749c01d\">Meals ( lunch / dinner )&nbsp;outside program</li><li data-list-item-id=\"e025608f4b1a7430cff483baa09186ddb\">other personal expenses outside tour :&nbsp;beverages during meals, laundry, phone etc&nbsp;</li><li data-list-item-id=\"e62cdc225d7537fd66178bc06d2879d1e\">Tipping&nbsp;for guide &amp; driver.</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"WILDLIFE\"]', NULL, 0, NULL, '2026-05-01 11:45:33', '2026-05-29 14:10:08'),
(35, 38, '4 DAYS LAKE TOBA TOUR', 'NORTH SUMATRA', '4-days-lake-toba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Keajaiban Dunia di Danau Toba: Paket Eksklusif 4 Hari 3 Malam!</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk petualangan tak terlupakan menuju jantung Sumatra Utara. Paket <strong>4D3N Lake Toba Tour</strong> kami akan membawa Anda melintasi pemandangan alam yang megah, warisan budaya yang kaya, hingga kesejukan pegunungan yang menenangkan jiwa.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"ee916e8a3a06550efd29dc875647bab59\"><p style=\"text-align:justify;\"><strong>Pengalaman Budaya yang Mendalam</strong>: Kunjungi desa tradisional Batak Toba di Tomok dan Ambarita untuk melihat artefak megalitik kuno dan makam bersejarah Raja Sidabutar.</p></li><li data-list-item-id=\"e68b7d30329747fd466ddc01013a5ceef\"><p style=\"text-align:justify;\"><strong>Keajaiban Alam yang Menakjubkan</strong>: Saksikan kemegahan Air Terjun Sipiso-piso yang jatuh ratusan meter langsung ke Danau Toba, serta nikmati perjalanan menyisir <i>Ring Road</i> Danau Toba dengan pemandangan pinus yang asri.</p></li><li data-list-item-id=\"e7bd32bdbedee1209c6ec209c6736b088\"><p style=\"text-align:justify;\"><strong>Relaksasi Maksimal di Pulau Samosir</strong>: Menginaplah di tepi danau dengan kamar <i>Lake View</i> di Toledo Inn. Anda bebas berenang, berjemur, atau sekadar bersepeda menikmati udara segar pulau di tengah danau vulkanik terbesar di dunia ini.</p></li><li data-list-item-id=\"ebab31f811a626a26371a37591a6fc14e\"><p style=\"text-align:justify;\"><strong>Kenyamanan Perjalanan Terjamin</strong>: Kami menyediakan transportasi ber-AC, pemandu wisata profesional (tersedia dalam bahasa Inggris, Jerman, Belanda, Prancis, dan Spanyol), serta akomodasi hotel bintang 4 di Medan seperti Santika Premiere atau Aryaduta.</p></li><li data-list-item-id=\"e3a9598681f7a1e98c8f0f6dd4e97799a\"><p style=\"text-align:justify;\"><strong>Eksplorasi Kota Medan yang Ikonik</strong>: Tak hanya alam, kami akan membawa Anda mengunjungi kemegahan Istana Maimun dan Mansion Tjong A Fie yang legendaris sebagai penutup perjalanan Anda.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Experience the Magic of Lake Toba: An Exclusive 4-Day 3-Night Journey!</strong></h2><p style=\"text-align:justify;\">Prepare yourself for an unforgettable adventure to the heart of North Sumatra. Our <strong>4D3N Lake Toba Tour</strong> takes you through majestic landscapes, rich cultural heritage, and the refreshing mountain breeze that soothes the soul.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Choose This Tour:</strong></h3><ul><li data-list-item-id=\"e4d6407405b4f02a4c8f08c6d27c8ff7d\"><p style=\"text-align:justify;\"><strong>Deep Cultural Immersion</strong>: Visit traditional Batak Toba villages in Tomok and Ambarita to see ancient megalithic furniture and the historic tomb of King Sidabutar.</p></li><li data-list-item-id=\"e407ac6a0c5e12f15779c5a235f43e95e\"><p style=\"text-align:justify;\"><strong>Breathtaking Natural Wonders</strong>: Witness the grandeur of Sipiso-piso Waterfall dropping hundreds of meters into Lake Toba and enjoy a scenic drive through lush pine forests.</p></li><li data-list-item-id=\"ef0d16a8e258757154c9ea292877b3e33\"><p style=\"text-align:justify;\"><strong>Ultimate Relaxation on Samosir Island</strong>: Stay in a \"Lake View\" room at Toledo Inn, where you can swim, sunbathe, or cycle around the world’s largest volcanic lake island.</p></li><li data-list-item-id=\"ebfe9205ddbc2e8de6d7d25f91429fbd3\"><p style=\"text-align:justify;\"><strong>Premium Travel Comfort</strong>: Enjoy air-conditioned transport and professional guides (available in English, German, Dutch, French, or Spanish).</p></li><li data-list-item-id=\"e2a370de107208d3711f887b3c07d5037\"><p style=\"text-align:justify;\"><strong>Iconic Medan City Exploration</strong>: Discover the royal heritage of Maimun Palace and the legendary Tjong A Fie Mansion.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>세계적인 절경, 토바 호수의 기적: 3박 4일 단독 투어!</strong></h2><p style=\"text-align:justify;\">북수마트라의 심장부로 떠나는 잊지 못할 여정을 시작하세요. <strong>4D3N 토바 호수 투어</strong>는 웅장한 자연 경관과 풍부한 문화 유산, 그리고 영혼을 달래주는 시원한 산바람을 선사합니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e90159a6905f8335167d6be429939d0d0\"><p style=\"text-align:justify;\"><strong>깊이 있는 문화 체험</strong>: 토목(Tomok)과 암바리타(Ambarita)의 바탁 토바 전통 마을을 방문하여 고대 거석 유물과 시다부타르 왕의 유서 깊은 묘지를 관람합니다.</p></li><li data-list-item-id=\"ec5c73a50bb05518947f861f89b180f91\"><p style=\"text-align:justify;\"><strong>경이로운 자연 경관</strong>: 수백 미터 높이에서 토바 호수로 쏟아지는 시피소피소(Sipiso-piso) 폭포의 장관과 울창한 소나무 숲길 드라이브를 즐겨보세요.</p></li><li data-list-item-id=\"e634af398283fd63ea16849017295a43f\"><p style=\"text-align:justify;\"><strong>사모시르 섬에서의 완벽한 휴식</strong>: 톨레도 인(Toledo Inn)의 \"레이크 뷰\" 객실에서 투숙하며, 세계 최대 화산 호수 섬에서 수영, 일광욕 또는 자전거 라이딩을 즐길 수 있습니다.</p></li><li data-list-item-id=\"ece9d395da390f128ed030911bc528358\"><p style=\"text-align:justify;\"><strong>최고의 여행 편의</strong>: 전 일정 에어컨 차량 이동과 전문 가이드(영어, 독일어, 네덜란드어 등 가능)가 동행합니다.</p></li><li data-list-item-id=\"e789d44cf2754d4990737e32aa4f268ce\"><p style=\"text-align:justify;\"><strong>메단 시내 탐방</strong>: 역사적인 마이문 궁전과 전설적인 종아피(Tjong A Fie) 저택을 방문하며 여행을 완벽하게 마무리합니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索多巴湖的神奇魅力：尊享 4天3晚 经典之旅！</strong></h2><p style=\"text-align:justify;\">准备好开启一场前往北苏门答腊中心地带的难忘冒险了吗？我们的 <strong>4D3N 多巴湖之旅</strong> 将带您穿越雄伟的自然风光，感受深厚的文化底蕴，在清新的山间空气中放松身心。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"e1855fd95ec63cfe3efbafaa8da5a3887\"><p style=\"text-align:justify;\"><strong>深度文化沉浸</strong>: 访问托莫 (Tomok) 和 安巴里塔 (Ambarita) 的多巴巴塔克传统村庄，参观古代巨石家具及著名的西达布塔尔国王墓。</p></li><li data-list-item-id=\"e821816272d8142f9492d4f00473a8c3c\"><p style=\"text-align:justify;\"><strong>震撼的自然奇观</strong>: 亲眼目睹数百米高的西披披索 (Sipiso-piso) 瀑布直冲多巴湖的壮丽景观，并在郁郁葱葱的松树林间穿行。</p></li><li data-list-item-id=\"eaa5204182f0307c4f6614ceb6a0c93e3\"><p style=\"text-align:justify;\"><strong>萨莫西尔岛的极致放松</strong>: 入住 Toledo Inn 的“湖景房”，在这座世界上最大的火山湖岛上尽情游泳、日光浴或骑行.</p></li><li data-list-item-id=\"ee361f790ee2ea9b2bdd48981b938d86e\"><p style=\"text-align:justify;\"><strong>优质的出行保障</strong>: 全程配备空调专车及多语言专业导游（提供英语、德语、法语、西班牙语等服务）。</p></li><li data-list-item-id=\"e4c4d75e00c5d4937904e6c2317c743f8\"><p style=\"text-align:justify;\"><strong>棉兰标志性城市游</strong>: 参观宏伟的迈蒙皇宫 (Maimun Palace) 和传奇的张阿辉故居 (Tjong A Fie Mansion) ，探索棉兰的独特魅力。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e4e9894f789f0a6bba3707bdd00a0e46a\">English&nbsp;Spk Guide</li><li data-list-item-id=\"ebd3dafaf1dec3785bbe09cb5ccc9dc1c\">Transportation in air-conditioned transportation</li><li data-list-item-id=\"ef92e446711f9f51d3d7e9b9e3d773ab1\">Non AC boat for Samosir Tour</li><li data-list-item-id=\"e1eb732b7825aadef5040718ed5b91d81\">All tours &amp; transfers&nbsp;</li><li data-list-item-id=\"e25fe7d27a354ad3fae97ff5c60e6e1eb\">Entrance fees as per above mentioned program</li><li data-list-item-id=\"e624f1ec2aed83f33197562a3d8fc50c3\">Accommodation&nbsp;at mentioned hotels&nbsp;and&nbsp;b\'fast&nbsp;as per program</li><li data-list-item-id=\"eeea7eaa28df91c68d9faa4412b0d82b3\">Mineral water&nbsp;in the car.&nbsp;&nbsp;<br><br>&nbsp;</li></ul>', '<ul><li data-list-item-id=\"e75ef665428c1bc22d1165834e241ddd0\">Flight tickets</li><li data-list-item-id=\"ec7eea0fd03f044d27b1ce9221ba2ef71\">Airport tax</li><li data-list-item-id=\"e635222216e919e4ad4aeb186cc6baa57\">Insurance</li><li data-list-item-id=\"e00e1e521472ee0f2039fc27d4749c01d\">Meals (lunch / dinner)&nbsp;outside program</li><li data-list-item-id=\"e025608f4b1a7430cff483baa09186ddb\">other personal expenses outside tour:&nbsp;beverages during meals, laundry, phone etc&nbsp;</li><li data-list-item-id=\"e62cdc225d7537fd66178bc06d2879d1e\">Tipping&nbsp;for guide &amp; driver.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"HERITAGE\"]', NULL, 0, NULL, '2026-05-01 12:01:15', '2026-06-02 03:58:31'),
(36, 38, '5 DAYS LAKE TOBA TOUR', 'NORTH SUMATRA', '5-days-lake-toba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Kemegahan Danau Toba: Petualangan Eksklusif 5 Hari 4 Malam!</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk melarikan diri dari hiruk-pikuk kota dan temukan keajaiban alam serta budaya di jantung Sumatra Utara. Paket <strong>5D4N Lake Toba Tour</strong> kami dirancang khusus untuk memberikan pengalaman mendalam bagi Anda yang mendambakan ketenangan pegunungan, keindahan danau vulkanik terbesar di dunia, serta kekayaan sejarah yang tak lekang oleh waktu.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Memilih Paket Ini?</strong></h3><ul><li data-list-item-id=\"eb02c416df0070fdfccafd92f620f9596\"><p style=\"text-align:justify;\"><strong>Pemandangan Alam yang Magis</strong>: Nikmati keindahan tiada tara dari <strong>Air Terjun Sipiso-piso</strong> yang jatuh ratusan meter langsung ke Danau Toba.</p></li><li data-list-item-id=\"ee5f66c679e42302e591bf0da7badcbdb\"><p style=\"text-align:justify;\"><strong>Lanskap Hijau yang Memukau</strong>: Susuri rute <i>Ring Road</i> dengan panorama hutan pinus, perkebunan karet, kelapa sawit, serta sawah terasering yang hijau subur.</p></li><li data-list-item-id=\"e3bc91a437f2f4cd173646a46ef736159\"><p style=\"text-align:justify;\"><strong>Pengalaman Budaya Autentik</strong>: Kami membawa Anda kembali ke masa lalu dengan mengunjungi <strong>Desa Tradisional Tomok &amp; Ambarita</strong> untuk melihat makam batu kuno Raja Sidabutar dan kursi megalitik yang unik langsung di depan rumah adat Batak.</p></li><li data-list-item-id=\"e8c56f227d2934e4a3425dab18345ba8c\"><p style=\"text-align:justify;\"><strong>Relaksasi Maksimal di Pulau Samosir</strong>: Nikmati ketenangan di tengah danau dengan menginap di kamar tipe <i>Lake View</i>, di mana Anda bisa langsung merasakan kesejukan air, berenang, atau bersepeda santai menikmati keindahan pulau.</p></li><li data-list-item-id=\"e7853050335a860ad88924cbb469e9fb3\"><p style=\"text-align:justify;\"><strong>Eksplorasi Kota &amp; Sejarah</strong>: Kunjungi kemegahan <strong>Istana Maimun</strong> peninggalan Sultan Deli, <strong>Kuil Gunung Timur</strong>, serta <strong>Pagoda Shwedagon</strong> emas di Taman Lumbini yang memukau.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Experience the Majesty of Lake Toba: An Exclusive 5-Day 4-Night Adventure!</strong></h2><p style=\"text-align:justify;\">Escape the city\'s hustle and discover the natural wonders and rich culture in the heart of North Sumatra. Our <strong>5D4N Lake Toba Tour</strong> is specially designed for those seeking the tranquility of the mountains, the beauty of the world’s largest volcanic lake, and timeless historical heritage.</p><h3 style=\"text-align:justify;\"><strong>Why Choose This Tour?</strong></h3><ul><li data-list-item-id=\"ec805a1d46ee3dfbdac9f11f66b2de199\"><p style=\"text-align:justify;\"><strong>Magical Natural Scenery</strong>: Witness the unparalleled beauty of <strong>Sipiso-piso Waterfall</strong>, which plunges hundreds of meters directly towards Lake Toba.</p></li><li data-list-item-id=\"e212a8fd219424eaa515d06b97dfbcea1\"><p style=\"text-align:justify;\"><strong>Stunning Green Landscapes</strong>: Travel along the <i>Ring Road</i> with panoramic views of pine forests, rubber and palm oil plantations, and lush green paddy terraces.</p></li><li data-list-item-id=\"e13d3de487ae68a022735266babc90943\"><p style=\"text-align:justify;\"><strong>Authentic Cultural Experience</strong>: Journey back in time with a visit to the <strong>Traditional Villages of Tomok &amp; Ambarita</strong> to see the ancient stone tomb of King Sidabutar and unique megalithic furniture.</p></li><li data-list-item-id=\"e66b24e96b5f88bd215870525e1aae776\"><p style=\"text-align:justify;\"><strong>Ultimate Relaxation on Samosir Island</strong>: Enjoy the serenity of the lake while staying in a \"Lake View\" room, where you can feel the cool breeze, swim, or cycle around the island.</p></li><li data-list-item-id=\"e86d248e2ea0a5dd37de6db3e2d5c0425\"><p style=\"text-align:justify;\"><strong>City &amp; Historical Exploration</strong>: Visit the grand <strong>Maimoon Palace</strong> of the old Deli Sultanate, the <strong>East Mountain Temple</strong>, and the stunning golden <strong>Shwedagon Pagoda</strong> at Taman Lumbini.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>웅장한 토바 호수의 매력: 4박 5일 전용 어드벤처!</strong></h2><p style=\"text-align:justify;\">도시의 소란함을 벗어나 북수마트라의 심장부에서 자연의 경이로움과 풍부한 문화를 발견해 보세요. <strong>5D4N 토바 호수 투어</strong>는 평온한 산의 기운, 세계 최대 화산 호수의 아름다움, 그리고 시대를 초월한 역사적 유산을 갈망하는 분들을 위해 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e51b7a29abb0f1926a9a18fce088b7ec5\"><p style=\"text-align:justify;\"><strong>마법 같은 자연 경관</strong>: 수백 미터 높이에서 토바 호수로 직접 떨어지는 <strong>시피소피소(Sipiso-piso) 폭포</strong>의 타의 추종을 불허하는 아름다움을 감상하세요.</p></li><li data-list-item-id=\"ec5d1a2ec3da8df0b0e0af22fd9f17ed8\"><p style=\"text-align:justify;\"><strong>눈부신 초록의 파노라마</strong>: 소나무 숲, 고무 및 야자수 농장, 그리고 푸른 계단식 논이 펼쳐지는 *링 로드(Ring Road)*를 따라 여행하세요.</p></li><li data-list-item-id=\"e72ec99a925ae04ba36021cc53e074e81\"><p style=\"text-align:justify;\"><strong>정통 문화 체험</strong>: <strong>토목(Tomok) 및 암바리타(Ambarita) 전통 마을</strong>을 방문하여 시다부타르 왕의 고대 석묘와 독특한 거석 유물들을 관람하며 과거로의 여행을 떠나보세요.</p></li><li data-list-item-id=\"e28b8061b296a9276ccc2f356f0c7a29d\"><p style=\"text-align:justify;\"><strong>사모시르 섬에서의 완벽한 휴식</strong>: \"레이크 뷰\" 객실에 머물며 호수의 평온함을 즐기고, 시원한 물놀이나 섬 주변 자전거 라이딩을 즐겨보세요.</p></li><li data-list-item-id=\"e9e53cb7f3a100e6cb25a0b889a95b141\"><p style=\"text-align:justify;\"><strong>도시와 역사의 탐험</strong>: 옛 델리 술탄국의 화려한 <strong>마이문 궁전(Maimoon Palace)</strong>, <strong>동산사(Kuil Gunung Timur)</strong>, 그리고 타만 룸비니의 눈부신 황금 <strong>쉐다곤 파고다</strong>를 방문합니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>领略多巴湖的雄伟壮丽：5天4晚 尊享之旅！</strong></h2><p style=\"text-align:justify;\">远离城市的喧嚣，探索北苏门答腊中心地带的自然奇观与深厚文化。我们的 <strong>5D4N 多巴湖之旅</strong> 专为向往山间宁静、全球最大火山湖美景以及永恒历史遗产的您而设计。</p><h3 style=\"text-align:justify;\"><strong>为什么选择此行程？</strong></h3><ul><li data-list-item-id=\"ebeef66e5d8c549cdb9fabce00acf1398\"><p style=\"text-align:justify;\"><strong>梦幻般的自然奇观</strong>: 亲眼见证 <strong>西披披索 (Sipiso-piso) 瀑布</strong> 从数百米高处直冲多巴湖的绝美景观。</p></li><li data-list-item-id=\"e2c9262303c497f223440f59bb74017a4\"><p style=\"text-align:justify;\"><strong>震撼的绿色画卷</strong>: 沿着“环湖公路”行驶，将松树林、橡胶园、油棕园以及郁郁葱葱的梯田美景尽收眼底。</p></li><li data-list-item-id=\"ec18ada6aec12933034bf6fd6eed1343b\"><p style=\"text-align:justify;\"><strong>深度文化沉浸</strong>: 访问 <strong>托莫 (Tomok) 和 安巴里塔 (Ambarita) 传统村庄</strong>，参观古老的西达布塔尔国王石墓和独具特色的巨石家具，开启一场穿越时空的旅程。</p></li><li data-list-item-id=\"e1be2f32e0917717740ea4bc4e66a3f6f\"><p style=\"text-align:justify;\"><strong>萨莫西尔岛的极致放松</strong>: 入住“湖景房”，在湖中心享受宁静，您可以尽情游泳、感受清凉的湖风，或骑行环岛游览。</p></li><li data-list-item-id=\"efbc63e863236d169fb06a0009bc6f863\"><p style=\"text-align:justify;\"><strong>城市与历史探索</strong>: 参观古德里苏丹国的宏伟 <strong>迈蒙皇宫 (Maimoon Palace) 、东方山庙 (Kuil Gunung Timur)</strong> 以及位于蓝毗尼园 (Taman Lumbini) 令人惊叹的金金色 <strong>大金塔</strong>。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e4e9894f789f0a6bba3707bdd00a0e46a\">English&nbsp;Speaking Guide</li><li data-list-item-id=\"ebd3dafaf1dec3785bbe09cb5ccc9dc1c\">Transportation in air-conditioned transportation</li><li data-list-item-id=\"ef92e446711f9f51d3d7e9b9e3d773ab1\">Non-AC boat for Samosir Tour</li><li data-list-item-id=\"e1eb732b7825aadef5040718ed5b91d81\">All tours &amp; transfers&nbsp;</li><li data-list-item-id=\"e25fe7d27a354ad3fae97ff5c60e6e1eb\">Entrance fees as per above mentioned program</li><li data-list-item-id=\"e624f1ec2aed83f33197562a3d8fc50c3\">Accommodation&nbsp;at mentioned hotels&nbsp;and&nbsp;b\'fast&nbsp;as per program</li><li data-list-item-id=\"eeea7eaa28df91c68d9faa4412b0d82b3\">Mineral water&nbsp;in the car.&nbsp;&nbsp;</li></ul>', '<ul><li data-list-item-id=\"e75ef665428c1bc22d1165834e241ddd0\">Flight tickets</li><li data-list-item-id=\"ec7eea0fd03f044d27b1ce9221ba2ef71\">Airport tax</li><li data-list-item-id=\"e635222216e919e4ad4aeb186cc6baa57\">Insurance</li><li data-list-item-id=\"e00e1e521472ee0f2039fc27d4749c01d\">Meals (lunch / dinner)&nbsp;outside program</li><li data-list-item-id=\"e025608f4b1a7430cff483baa09186ddb\">other personal expenses outside tour:&nbsp;beverages during meals, laundry, phone etc&nbsp;</li><li data-list-item-id=\"e62cdc225d7537fd66178bc06d2879d1e\">Tipping&nbsp;for guide &amp; driver.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"HERITAGE\"]', NULL, 0, NULL, '2026-05-01 12:50:24', '2026-05-29 14:07:34'),
(37, 38, '6 DAYS ORANG UTAN & LAKE TOBA TOUR', 'NORTH SUMATRA', '6-days-orang-utan-lake-toba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Sumatera: Petualangan Liar di Bukit Lawang &amp; Ketenangan Magis Danau Toba</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk perjalanan epik selama 6 hari 5 malam melintasi lanskap Sumatera yang paling ikonik. Dari rimbunnya hutan hujan tropis yang menjadi rumah bagi Orang Utan, hingga kemegahan kawah vulkanik terbesar di dunia, paket ini adalah perpaduan sempurna antara petualangan memacu adrenalin dan relaksasi budaya yang mendalam.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Tour Ini?</strong></h3><p style=\"text-align:justify;\"><strong>1. Pertemuan Tak Terlupakan dengan Orang Utan di Habitat Aslinya</strong>&nbsp;</p><p style=\"text-align:justify;\">Masuki kawasan Bohorok, Bukit Lawang, untuk pengalaman <i>jungle trekking</i> yang mendebarkan. Anda tidak hanya sekadar berjalan di hutan, tetapi berkesempatan bertemu langsung dengan Orang Utan Sumatera yang langka, serta berbagai primata eksotis lainnya seperti Thomas Leaf Monkey dan Siamang di tengah vegetasi hutan hujan yang lebat.</p><p style=\"text-align:justify;\"><strong>2. Keajaiban Danau Toba &amp; Pulau Samosir</strong>&nbsp;</p><p style=\"text-align:justify;\">Rasakan sensasi menyeberangi Danau Toba, sebuah mahakarya alam yang menakjubkan. Anda akan menginap di Pulau Samosir, sebuah pulau vulkanik di tengah danau, di mana udara sejuk dan pemandangan air biru yang tenang akan menghapus segala kepenatan Anda.</p><p style=\"text-align:justify;\"><strong>3. Jejak Megalitikum &amp; Budaya Batak yang Autentik</strong>&nbsp;</p><p style=\"text-align:justify;\">Telusuri sejarah Kerajaan Batak dengan mengunjungi Desa Ambarita yang memiliki kursi batu megalitikum kuno, serta Makam Raja Sidabutar di Tomok. Setiap sudut destinasi ini bercerita tentang kekayaan tradisi yang masih terjaga hingga saat ini.</p><p style=\"text-align:justify;\"><strong>4. Keindahan Alam yang Memukau di Setiap Perjalanan</strong>&nbsp;</p><p style=\"text-align:justify;\">Dari gemuruh Air Terjun Sipisopiso setinggi 120-meter yang menghadap langsung ke Danau Toba, hingga kemegahan Pagoda Emas Taman Lumbini di Brastagi yang berlatar pegunungan, mata Anda akan dimanjakan oleh panorama yang luar biasa di sepanjang jalan.</p><p style=\"text-align:justify;\"><strong>5. Keberagaman Ikon Kota Medan</strong>&nbsp;</p><p style=\"text-align:justify;\">Akhiri petualangan Anda dengan menyerap sejarah lokal di Istana Maimoon yang megah, bukti kejayaan Kesultanan Deli, dan rasakan harmoni budaya di kuil-kuil unik yang menghiasi Kota Medan.</p>', '<h2 style=\"text-align:justify;\"><strong>Explore the Heart of Sumatra: Wild Adventure in Bukit Lawang &amp; Magic Serenity of Lake Toba</strong></h2><p style=\"text-align:justify;\">Prepare yourself for an epic 6-day 5-night journey across North Sumatra\'s most iconic landscapes. From the lush tropical rainforests that house the Orangutans, to the grandeur of the world\'s largest volcanic crater, this package is a perfect blend of adrenaline-pumping adventure and deep cultural relaxation.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Try This Tour Package?</strong></h3><p style=\"text-align:justify;\"><strong>1. Unforgettable Encounter with Orangutans in Their Natural Habitat</strong>&nbsp;</p><p style=\"text-align:justify;\">Enter the Bohorok area, Bukit Lawang, for a thrilling jungle trekking experience. You won\'t just walk through the forest; you\'ll have the chance to directly meet the rare Sumatran Orangutans and other exotic primates like the Thomas Leaf Monkey and Siamang amidst the dense rainforest vegetation.</p><p style=\"text-align:justify;\"><strong>2. The Magic of Lake Toba &amp; Samosir Island</strong>&nbsp;</p><p style=\"text-align:justify;\">Feel the sensation of crossing Lake Toba, a stunning natural masterpiece. You will stay on Samosir Island, a volcanic island in the middle of the lake, where the cool air and calm blue water will wash away all your fatigue.</p><p style=\"text-align:justify;\"><strong>3. Megalithic Traces &amp; Authentic Batak Culture</strong>&nbsp;</p><p style=\"text-align:justify;\">Trace the history of the Batak Kingdom by visiting Ambarita Village, which features ancient megalithic stone chairs, and the Tomb of King Sidabutar in Tomok. Every corner of this destination tells a story of well-preserved rich traditions.</p><p style=\"text-align:justify;\"><strong>4. Stunning Natural Beauty on Every Journey</strong>&nbsp;</p><p style=\"text-align:justify;\">From the thunderous 120-meter high Sipisopiso Waterfall facing directly towards Lake Toba, to the grandeur of the Golden Pagoda at Taman Lumbini in Brastagi set against a mountain backdrop, your eyes will be pampered by extraordinary panoramas along the way.</p><p style=\"text-align:justify;\"><strong>5. Diversity of Medan City Icons</strong>&nbsp;</p><p style=\"text-align:justify;\">End your adventure by absorbing local history at the majestic Maimoon Palace, a testament to the glory of the Deli Sultanate, and feel the cultural harmony at the unique temples adorning Medan City.</p>', '<h2 style=\"text-align:justify;\"><strong>수마트라의 심장을 탐험하다: 부킷 라왕의 야생 어드벤처 &amp; 단아우 토바의 마법 같은 평온함</strong></h2><p style=\"text-align:justify;\">북수마트라에서 가장 상징적인 풍경을 가로지르는 서사적인 5박 6일 여정을 준비하세요. 오랑우탄의 서식지인 울창한 열대우림부터 세계 최대 화산 분화구의 웅장함까지, 이 패키지는 아드레날린이 솟구치는 모험과 깊은 문화적 휴식의 완벽한 조화입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어 패키지를 꼭 선택해야 하는 이유는 무엇인가요?</strong></h3><p style=\"text-align:justify;\"><strong>1. 야생 서식지에서 즐기는 오랑우탄과의 잊지 못할 만남</strong> 스릴 넘치는 정글 트레킹 경험을 위해 부킷 라왕 보호록 지역으로 들어갑니다. 단순히 숲을 걷는 것이 아니라, 울창한 열대우림 한가운데서 희귀한 수마트라 오랑우탄과 토마스 리프 원숭이, 샤망과 같은 이국적인 영장류를 직접 만날 기회를 얻게 됩니다.</p><p style=\"text-align:justify;\"><strong>2. 단아우 토바와 사모시르 섬의 마법</strong> 놀라운 자연의 걸작인 단아우 토바를 건너는 전율을 느껴보세요. 호수 한가운데 있는 화산섬인 사모시르 섬에서 숙박하며, 시원한 공기와 고요한 푸른 물결이 당신의 모든 피로를 씻어줄 것입니다.</p><p style=\"text-align:justify;\"><strong>3. 거석 유적과 정통 바탁 문화</strong> 고대 거석 의자가 있는 암바리타 마을과 토목의 시다부타 왕 묘를 방문하여 바탁 왕국의 역사를 추적해 보세요. 이 여행지의 모든 구석구석은 오늘날까지 보존된 풍부한 전통 이야기를 들려줍니다.</p><p style=\"text-align:justify;\"><strong>4. 모든 여정에서 만나는 눈부신 자연미</strong> 단아우 토바를 정면으로 마주하는 120m 높이의 웅장한 시피소피소 폭포부터 산을 배경으로 한 브라스따기 타만 룸비니의 황금 파고다까지, 여행 내내 놀라운 파노라마가 당신의 눈을 즐겁게 할 것입니다.</p><p style=\"text-align:justify;\"><strong>5. 메단시 아이콘의 다양성</strong> 델리 술탄국의 영광을 증명하는 웅장한 마이문 궁전에서 현지 역사를 흡수하고, 메단시를 장식하는 독특한 사원들에서 문화적 조화를 느끼며 모험을 마무리하세요.</p>', '<h2 style=\"text-align:justify;\"><strong>探索苏门答腊的心脏：武吉拉旺的野性冒险与多巴湖的神奇宁静</strong></h2><p style=\"text-align:justify;\">准备好开启一段跨越北苏门答腊最经典景观的6天5晚史诗之旅。从红毛猩猩栖息的茂密热带雨林，到全球最大火山坑的壮丽景观，本套餐是惊险刺激的冒险与深度文化放松的完美结合。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须尝试这个旅游套餐？</strong></h3><p style=\"text-align:justify;\"><strong>1. 在自然栖息地与红毛猩猩难忘相遇</strong> 进入武吉拉旺的波和록（Bohorok）地区，体验令人心跳加速的丛林徒步。您不仅是在森林中漫步，更有机会在茂密的热带雨林中直接遇见稀有的苏门答腊红毛猩猩，以及托马斯叶猴和长臂猿等异国灵长类动物。</p><p style=\"text-align:justify;\"><strong>2. 多巴湖与萨摩西岛的魔力</strong> 感受横渡多巴湖的震撼，这是一件令人惊叹的大自然杰作。您将入住湖中心的火山岛——萨摩西岛，清新的空气和宁静的蓝色湖水将洗去您所有的疲惫。</p><p style=\"text-align:justify;\"><strong>3. 巨石足迹与正宗巴塔克文化</strong> 通过参观拥有古老巨石石椅的安巴里塔村（Ambarita）和托莫克（Tomok）的西达布塔国王墓，追溯巴塔克王国的历史。这个目的地的每个角落都讲述着至今仍保存完好的丰富传统故事。</p><p style=\"text-align:justify;\"><strong>4. 每一段旅程中令人叹为观止的自然美景</strong> 从直面多巴湖、高达120米的西比索比索瀑布的轰鸣声，到以群山为背景的马达山（Brastagi）大金塔的壮丽，沿途非凡的全景将让您的眼睛得到极大的享受。</p><p style=\"text-align:justify;\"><strong>5. 棉兰市标志性景点的多样性</strong> 在宏伟的迈蒙皇宫（Maimoon Palace）汲取当地历史，它是德里苏丹国辉煌的见证；并在装饰着棉兰市的独特寺庙中感受文化的和谐，为您的冒险之旅画上圆满句号。</p>', 0.00, NULL, 6, 5, NULL, NULL, '<ul><li data-list-item-id=\"e4e9894f789f0a6bba3707bdd00a0e46a\">English&nbsp;Speaking Guide</li><li data-list-item-id=\"ebd3dafaf1dec3785bbe09cb5ccc9dc1c\">Transportation in air-conditioned transportation</li><li data-list-item-id=\"ef92e446711f9f51d3d7e9b9e3d773ab1\">Non-AC boat for Samosir Tour</li><li data-list-item-id=\"e1eb732b7825aadef5040718ed5b91d81\">All tours &amp; transfers&nbsp;</li><li data-list-item-id=\"e25fe7d27a354ad3fae97ff5c60e6e1eb\">Entrance fees as per above mentioned program</li><li data-list-item-id=\"e624f1ec2aed83f33197562a3d8fc50c3\">Accommodation&nbsp;at mentioned hotels&nbsp;and&nbsp;b\'fast&nbsp;as per program</li><li data-list-item-id=\"eeea7eaa28df91c68d9faa4412b0d82b3\">Mineral water&nbsp;in the car.&nbsp;&nbsp;</li></ul>', '<ul><li data-list-item-id=\"e75ef665428c1bc22d1165834e241ddd0\">Flight tickets</li><li data-list-item-id=\"ec7eea0fd03f044d27b1ce9221ba2ef71\">Airport tax</li><li data-list-item-id=\"e635222216e919e4ad4aeb186cc6baa57\">Insurance</li><li data-list-item-id=\"e00e1e521472ee0f2039fc27d4749c01d\">Meals (lunch / dinner)&nbsp;outside program</li><li data-list-item-id=\"e025608f4b1a7430cff483baa09186ddb\">other personal expenses outside tour:&nbsp;beverages during meals, laundry, phone etc.&nbsp;</li><li data-list-item-id=\"e62cdc225d7537fd66178bc06d2879d1e\">Tipping&nbsp;for guide &amp; driver.</li></ul>', NULL, '[\"Nature\",\"WILDLIFE\",\"Culture\",\"HERITAGE\",\"Adventure\",\"City\",\"LEISURE\"]', NULL, 0, NULL, '2026-05-01 13:16:32', '2026-06-02 05:18:19');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(38, 38, '8 DAYS ORANG UTAN SUMATRA OVERLAND TOUR', 'NORTH SUMATRA', '8-days-orang-utan-sumatra-overland-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Sumatera: Petualangan Epik 8 Hari 7 Malam dari Rimba Tropis hingga Warisan Minangkabau</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk sebuah petualangan <i>overland</i> yang akan mengubah cara Anda melihat dunia. Paket tour <strong>8 Hari 7 Malam</strong> ini membawa Anda melintasi pedalaman Sumatera, menggabungkan pertemuan emosional dengan satwa liar langka, kemegahan alam pegunungan, hingga jejak sejarah kerajaan kuno yang eksotis.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Tour Ini?</strong></h3><p style=\"text-align:justify;\"><strong>1. Tatap Muka Langsung dengan Orang Utan di Habitat Aslinya</strong></p><p style=\"text-align:justify;\">Masuki hutan hujan tropis Sumatera yang rimbun di <strong>Bohorok, Bukit Lawang</strong>. Rasakan sensasi mendebarkan saat melakukan <i>jungle trekking</i> dan berkesempatan bertemu langsung dengan Orang Utan yang semi-liar atau liar, serta fauna endemik lainnya seperti Siamang dan Macaque tepat di depan mata Anda.</p><p style=\"text-align:justify;\"><strong>2. Magisnya Danau Toba &amp; Pulau Samosir</strong></p><p style=\"text-align:justify;\">Nikmati ketenangan luar biasa di kawah vulkanik terbesar di dunia. Anda akan menyeberang ke <strong>Pulau Samosir</strong>, tempat di mana waktu seolah berhenti. Jelajahi desa tradisional <strong>Tomok</strong> dan <strong>Ambarita</strong>, temukan rahasia kuno di makam raja-raja, dan saksikan kursi batu megalitikum yang masih berdiri kokoh hingga saat ini.</p><p style=\"text-align:justify;\"><strong>3. Simfoni Air Terjun &amp; Panorama Alam yang Megah</strong></p><p style=\"text-align:justify;\">Sepanjang perjalanan, mata Anda akan dimanjakan oleh <strong>Air Terjun Sipisopiso</strong> setinggi 120-meter yang menghadap langsung ke Danau Toba, serta <strong>Air Terjun Aek Sijornih</strong> yang unik. Dari dataran tinggi Brastagi yang sejuk hingga lembah-lembah hijau di Padang Sidempuan, setiap kilometer perjalanan adalah kartu pos nyata.</p><p style=\"text-align:justify;\"><strong>4. Melintasi Garis Khatulistiwa di Tugu Bonjol</strong></p><p style=\"text-align:justify;\">Abadikan momen langka saat Anda berdiri tepat di tengah-tengah dunia. <strong>Tugu Khatulistiwa di Bonjol</strong> memberikan pengalaman unik untuk mencatatkan rekor pribadi dalam perjalanan hidup Anda saat melintasi garis imajiner yang membelah utara dan selatan bumi.</p><p style=\"text-align:justify;\"><strong>5. Kemegahan Budaya Matrilineal Minangkabau</strong></p><p style=\"text-align:justify;\">Akhiri petualangan Anda di <strong>Bukittinggi</strong>, jantung budaya Minangkabau. Saksikan <strong>Lembah Ngarai Sianok</strong> yang fenomenal, jelajahi terowongan bersejarah sisa Perang Dunia II, dan kagumi <strong>Istano Basa Pagaruyung</strong>—sebuah mahakarya arsitektur kayu dengan atap tanduk yang ikonis, tempat di mana sejarah sistem kekerabatan matrilineal masih sangat kental terasa.</p>', '<h2 style=\"text-align:justify;\"><strong>Explore the Heart of Sumatra: Epic 8-Day 7-Night Adventure from Tropical Jungle to Minangkabau Heritage</strong></h2><p style=\"text-align:justify;\">Prepare yourself for an overland adventure that will change the way you see the world. This <strong>8-Day 7-Night</strong> tour package takes you across the hinterlands of Sumatra, combining emotional encounters with rare wildlife, the grandeur of mountain nature, and the exotic traces of ancient royal history.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Try This Tour Package?</strong></h3><p style=\"text-align:justify;\"><strong>1. Face-to-Face with Orangutans in Their Natural Habitat</strong> Enter the lush Sumatran tropical rainforest in <strong>Bohorok, Bukit Lawang</strong>. Feel the thrilling sensation of jungle trekking and get the chance to directly meet semi-wild or wild Orangutans, as well as other endemic fauna like Siamangs and Macaques right before your eyes.</p><p style=\"text-align:justify;\"><strong>2. The Magic of Lake Toba &amp; Samosir Island</strong> Enjoy extraordinary tranquility in the world\'s largest volcanic crater. You will cross to <strong>Samosir Island</strong>, a place where time seems to stand still. Explore the traditional villages of <strong>Tomok</strong> and <strong>Ambarita</strong>, discover ancient secrets at the royal tombs, and witness the megalithic stone chairs that still stand firm today.</p><p style=\"text-align:justify;\"><strong>3. Symphony of Waterfalls &amp; Majestic Natural Panoramas</strong> Throughout the journey, your eyes will be pampered by the 120-meter high <strong>Sipisopiso Waterfall</strong> facing directly towards Lake Toba, as well as the unique <strong>Aek Sijornih Waterfall</strong>. From the cool Brastagi highlands to the green valleys of Padang Sidempuan, every kilometer of the journey is a real-life postcard.</p><p style=\"text-align:justify;\"><strong>4. Crossing the Equator at the Bonjol Monument</strong> Capture a rare moment as you stand right in the middle of the world. The <strong>Equator Monument in Bonjol</strong> provides a unique experience to record a personal milestone in your life\'s journey as you cross the imaginary line dividing the north and south of the earth.</p><p style=\"text-align:justify;\"><strong>5. The Grandeur of Minangkabau Matrilineal Culture</strong> End your adventure in <strong>Bukittinggi</strong>, the cultural heart of Minangkabau. Witness the phenomenal <strong>Sianok Canyon Valley</strong>, explore the historic tunnel remnants of World War II, and admire <strong>Istano Basa Pagaruyung</strong>—an architectural masterpiece of wood with iconic horn-shaped roofs, where the history of the matrilineal kinship system is still deeply felt.</p>', '<h2 style=\"text-align:justify;\"><strong>수마트라의 심장을 탐험하다: 열대 우림에서 미낭카바우 유산까지 7박 8일의 서사적 모험</strong></h2><p style=\"text-align:justify;\">세상을 바라보는 시각을 바꿔줄 오버랜드 어드벤처를 준비하세요. 이 <strong>7박 8일</strong> 투어 패키지는 수마트라의 오지를 가로지르며 희귀 야생 동물과의 감동적인 만남, 웅장한 산악 자연, 그리고 이국적인 고대 왕실 역사의 흔적을 결합합니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어 패키지를 꼭 선택해야 하는 이유는 무엇인가요?</strong></h3><p style=\"text-align:justify;\"><strong>1. 야생 서식지에서 즐기는 오랑우탄과의 대면</strong> <strong>부킷 라왕 보호록</strong>의 울창한 수마트라 열대 우림으로 들어갑니다. 스릴 넘치는 정글 트레킹을 경험하고, 반야생 또는 야생 오랑우탄은 물론 샤망, 마카크와 같은 다른 엔데믹 동물을 눈앞에서 직접 만날 기회를 얻으세요.</p><p style=\"text-align:justify;\"><strong>2. 단아우 토바와 사모시르 섬의 마법</strong> 세계 최대 화산 분화구에서 특별한 평온함을 즐겨보세요. 시간이 멈춘 듯한 곳, <strong>사모시르 섬</strong>으로 건너갑니다. <strong>토목</strong>과 <strong>암바리타</strong> 전통 마을을 탐험하고, 왕실 묘지에서 고대 비밀을 발견하며, 오늘날까지 굳건히 서 있는 거석 의자를 확인해 보세요.</p><p style=\"text-align:justify;\"><strong>3. 폭포의 교향곡과 웅장한 자연 파노라마</strong> 여행 내내 단아우 토바를 정면으로 마주하는 120m 높이의 <strong>시피소피소 폭포</strong>와 독특한 <strong>아엑 시조르니 폭포</strong>가 눈을 즐겁게 할 것입니다. 시원한 브라스따기 고원부터 빠당 시뎀뿌안의 푸른 계곡까지, 여정의 모든 킬로미터가 실제 엽서와 같습니다.</p><p style=\"text-align:justify;\"><strong>4. 본졸 기념비에서 적도 횡단</strong> 세상의 정중앙에 서 있는 희귀한 순간을 포착하세요. <strong>본졸의 적도 기념비</strong>는 지구의 북쪽과 남쪽을 나누는 가상의 선을 넘으며 인생 여정의 개인적인 기록을 남길 수 있는 특별한 경험을 제공합니다.</p><p style=\"text-align:justify;\"><strong>5. 미낭카바우 모계 문화의 웅장함</strong> 미낭카바우 문화의 중심지인 <strong>부키팅기</strong>에서 모험을 마무리하세요. 경이로운 <strong>시아녹 계곡</strong>, 제2차 세계 대전의 유적지인 역사적인 터널을 둘러보고, 아이코닉한 뿔 모양 지붕을 가진 목조 건축의 걸작 <strong>이스타노 바사 파가루융</strong>을 감상해 보세요. 이곳은 모계 친족 체계의 역사가 여전히 깊게 느껴지는 곳입니다.</p>', '<h2 style=\"text-align:justify;\"><strong>探索苏门答腊的心脏：从热带雨林到米南加保遗产的8天7晚史诗之旅</strong></h2><p style=\"text-align:justify;\">准备好开启一段将改变您看待世界方式的陆路冒险。这套 <strong>8天7晚</strong> 的旅游套餐带您穿越苏门答腊的内陆，融合了与稀有野生动物的情感邂逅、壮丽的山岳自然，以及异国古代皇家历史的足迹。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须尝试这个旅游套餐？</strong></h3><p style=\"text-align:justify;\"><strong>1. 在自然栖息地与红毛猩猩面对面</strong> 进入 <strong>武吉拉旺波和록 (Bohorok)</strong> 茂密的苏门答腊热带雨林。体验令人心跳加速的丛林徒步，并有机会在您眼前直接遇见半野生或野生的红毛猩猩，以及长臂猿和猕猴等其他特有动物。</p><p style=\"text-align:justify;\"><strong>2. 多巴湖与萨摩西岛的魔力</strong> 在全球最大的火山坑中享受非凡的宁静。您将前往 <strong>萨摩西岛</strong>，一个时间仿佛静止的地方。探索 <strong>托莫克 (Tomok)</strong> 和 <strong>安巴里塔 (Ambarita)</strong> 传统村庄，在皇家陵墓中发现古老的秘密，并见证至今依然屹立的巨石石椅。</p><p style=\"text-align:justify;\"><strong>3. 瀑布交响乐与壮丽的自然全景</strong> 在整个旅程中，您的眼睛将尽情欣赏直面多巴湖的120米高 <strong>西比索比索瀑布</strong>，以及独特的 <strong>阿克西佐尼 (Aek Sijornih) 瀑布</strong>。从凉爽的马达山高地到巴东实武安的绿色山谷，旅途中的每一公里都像是一张真实的明信片。</p><p style=\"text-align:justify;\"><strong>4. 在本佐尔纪念碑跨越赤道</strong> 捕捉站在世界正中心的稀有时刻。<strong>本佐尔 (Bonjol) 的赤道纪念碑</strong> 提供了一次独特的体验，当您跨越划分地球南北的虚拟线时，为您的人生旅程留下个人记录。</p><p style=\"text-align:justify;\"><strong>5. 米南加保母系文化的宏伟</strong> 在米南加保文化中心 <strong>布基丁宜</strong> 结束您的冒险。见证壮观的 <strong>仙诺峡谷 (Ngarai Sianok)</strong>，探索第二次世界大战留下的历史地道，并欣赏 <strong>帕加鲁永皇宫 (Istano Basa Pagaruyung)</strong>——这是一件带有标志性牛角屋顶的木结构建筑杰作，在这里，母系亲属制的历史依然让人深有感触。</p>', 0.00, NULL, 8, 7, NULL, NULL, '<ul><li data-list-item-id=\"e4e9894f789f0a6bba3707bdd00a0e46a\">English&nbsp;Speaking Guide</li><li data-list-item-id=\"ebd3dafaf1dec3785bbe09cb5ccc9dc1c\">Transportation in air-conditioned transportation</li><li data-list-item-id=\"ef92e446711f9f51d3d7e9b9e3d773ab1\">Non-AC boat for Samosir Tour</li><li data-list-item-id=\"e1eb732b7825aadef5040718ed5b91d81\">All tours &amp; transfers&nbsp;</li><li data-list-item-id=\"e25fe7d27a354ad3fae97ff5c60e6e1eb\">Entrance fees as per above mentioned program</li><li data-list-item-id=\"e624f1ec2aed83f33197562a3d8fc50c3\">Accommodation&nbsp;at mentioned hotels&nbsp;and&nbsp;b\'fast&nbsp;as per program</li><li data-list-item-id=\"eeea7eaa28df91c68d9faa4412b0d82b3\">Mineral water&nbsp;in the car.&nbsp;</li></ul>', '<ul><li data-list-item-id=\"e75ef665428c1bc22d1165834e241ddd0\">Flight tickets</li><li data-list-item-id=\"ec7eea0fd03f044d27b1ce9221ba2ef71\">Airport tax</li><li data-list-item-id=\"e635222216e919e4ad4aeb186cc6baa57\">Insurance</li><li data-list-item-id=\"e00e1e521472ee0f2039fc27d4749c01d\">Meals (lunch / dinner)&nbsp;outside program</li><li data-list-item-id=\"e025608f4b1a7430cff483baa09186ddb\">other personal expenses outside tour:&nbsp;beverages during meals, laundry, phone etc.&nbsp;</li><li data-list-item-id=\"e62cdc225d7537fd66178bc06d2879d1e\">Tipping&nbsp;for guide &amp; driver.</li></ul>', NULL, '[\"Nature\",\"WILDLIFE\",\"Culture\",\"HERITAGE\",\"Adventure\"]', NULL, 0, NULL, '2026-05-01 13:43:18', '2026-06-02 05:55:49'),
(39, 39, '3 DAYS TANJUNG PUTING TOUR', 'CENTRAL KALIMANTAN', '3-days-tanjung-puting-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Kalimantan: Petualangan Magis di Taman Nasional Tanjung Puting</strong></h2><p style=\"text-align:justify;\">Nikmati pengalaman sekali seumur hidup menembus rimbunnya hutan hujan tropis Kalimantan. Selama tiga hari, Anda akan diajak meninggalkan hiruk-pikuk dunia modern untuk menyatu dengan alam liar yang murni, menyusuri sungai yang tenang, dan bertemu langsung dengan penghuni asli hutan ini: Orangutan.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e64034086805bfa31710875ca32706588\"><p style=\"text-align:justify;\"><strong>Interaksi Dekat dengan Orangutan:</strong> Kunjungi pusat konservasi kelas dunia seperti <strong>Camp Leakey</strong>, di mana Anda bisa menyaksikan langsung perilaku orangutan di habitat aslinya selama waktu makan.</p></li><li data-list-item-id=\"e434483f82f63487f20fd399831d9c488\"><p style=\"text-align:justify;\"><strong>Sensasi Menginap di Atas Klotok:</strong> Rasakan romansa petualangan unik dengan tinggal dan bermalam di atas <strong>Kapal Klotok tradisional</strong>. Tidur di bawah atap langit hutan dengan ditemani suara alami malam adalah pengalaman yang tak terlupakan.</p></li><li data-list-item-id=\"e648e39b395166ca839e4569905a3b272\"><p style=\"text-align:justify;\"><strong>Keajaiban Alam \"Black River\":</strong> Susuri aliran sungai hitam yang tenang, yang memantulkan bayangan hutan hujan dengan sempurna layaknya cermin raksasa—sebuah pemandangan yang sangat memukau bagi pecinta fotografi.</p></li><li data-list-item-id=\"ec3ac5b1a57a0d1ed0607d2fa571176d7\"><p style=\"text-align:justify;\"><strong>Makan Malam di Bawah Ribuan Kunang-Kunang:</strong> Tutup petualangan Anda dengan momen magis <strong>Firefly Dinner</strong>, di mana tepian sungai akan berkelap-kelip indah oleh ribuan kunang-kunang yang menerangi kegelapan hutan.</p></li><li data-list-item-id=\"e434e0a2f0b216884df073cd7f7628327\"><p style=\"text-align:justify;\"><strong>Warisan Budaya Dayak:</strong> Tak hanya alam, Anda juga akan diajak mengenal lebih dekat kekayaan budaya lokal melalui kunjungan ke <strong>Rumah Betang</strong>, rumah tradisional suku Dayak Tomun yang penuh sejarah.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Heart of Borneo: A Magical Adventure in Tanjung Puting National Park</strong></h2><p style=\"text-align:justify;\">Experience a once-in-a-lifetime journey deep into the lush tropical rainforest of Kalimantan. For three days, you will leave the hustle and bustle of the modern world behind to unite with pure wilderness, cruising calm rivers, and meeting the forest\'s original inhabitants: the Orangutans.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Buy This Package:</strong></h3><ul><li data-list-item-id=\"ec6fb5ce6f98ad16c0c9e5c938c2d355b\"><p style=\"text-align:justify;\"><strong>Close Encounters with Orangutans:</strong> Visit world-class conservation centers like <strong>Camp Leakey</strong>, where you can witness orangutan behavior firsthand in their natural habitat during feeding time.</p></li><li data-list-item-id=\"ea39d5c146a0dc36a75dee58b75d22968\"><p style=\"text-align:justify;\"><strong>The Klotok Living Experience:</strong> Feel the romance of a unique adventure by staying and sleeping aboard a <strong>traditional Klotok houseboat</strong>. Sleeping under the forest canopy accompanied by the natural sounds of the night is an unforgettable experience.</p></li><li data-list-item-id=\"eb23e48628f4ee6285437067f78093f13\"><p style=\"text-align:justify;\"><strong>The \"Black River\" Marvel:</strong> Sail through serene tea-colored streams that perfectly reflect the rainforest like a giant mirror—a breathtaking sight for photography enthusiasts.</p></li><li data-list-item-id=\"ed322dc08a9ac202ed234dc20256697e7\"><p style=\"text-align:justify;\"><strong>Dinner Under Thousands of Fireflies:</strong> End your adventure with a magical <strong>Firefly Dinner</strong>, where the riverbanks sparkle with thousands of fireflies illuminating the dark jungle.</p></li><li data-list-item-id=\"e6e4fcd20bcfadbdb765465fce53e267b\"><p style=\"text-align:justify;\"><strong>Dayak Cultural Heritage:</strong> Beyond nature, get closer to local cultural richness with a visit to the <strong>Rumah Betang</strong>, a traditional longhouse of the Dayak Tomun tribe steeped in history.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>보르네오의 심장을 탐험하세요: 탄중 푸팅 국립공원에서의 마법 같은 모험</strong></h2><p style=\"text-align:justify;\">칼리만탄의 무성한 열대 우림 속으로 떠나는 일생일대의 여정을 경험해 보세요. 3일 동안 현대 세계의 분주함을 뒤로하고 순수한 야생과 하나가 되어 잔잔한 강을 항해하며 숲의 주인인 오랑우탄을 만나게 됩니다.</p><h3 style=\"text-align:justify;\"><strong>이 패키지를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e8c33986b158dccd95190907ae2c1e178\"><p style=\"text-align:justify;\"><strong>오랑우탄과의 가까운 만남:</strong> 캠프 리키(Camp Leakey)와 같은 세계적인 보존 센터를 방문하여 급식 시간 동안 자연 서식지에서 오랑우탄의 행동을 직접 관찰하세요.</p></li><li data-list-item-id=\"e59d601b4e52b954b8b1a7bc1cee6a6c1\"><p style=\"text-align:justify;\"><strong>전통 배 \'클로톡(Klotok)\'에서의 숙박:</strong> <strong>전통 클로톡 하우스보트</strong>에서 머물며 잠드는 독특한 모험의 낭만을 느껴보세요. 밤의 자연 소리를 들으며 숲의 캐노피 아래에서 잠드는 것은 잊지 못할 경험이 될 것입니다.</p></li><li data-list-item-id=\"eadbefa7fea44ffaac42dadb8c7f90561\"><p style=\"text-align:justify;\"><strong>신비로운 \'블랙 리버(Black River)\':</strong> 거대한 거울처럼 열대 우림을 완벽하게 투영하는 고요한 찻빛 줄기를 따라 항해하세요. 사진 애호가들에게는 놓칠 수 없는 절경입니다.</p></li><li data-list-item-id=\"e173689f341197ca9cba13766027c2dac\"><p style=\"text-align:justify;\"><strong>수천 마리 반딧불이 아래에서의 저녁 식사:</strong> 어두운 정글을 밝히는 수천 마리의 반딧불이가 강변을 수놓는 마법 같은 <strong>반딧불이 디너</strong>로 모험을 마무리하세요.</p></li><li data-list-item-id=\"e430d7fbfc508e28c6e07e1e6a875dcce\"><p style=\"text-align:justify;\"><strong>다야크(Dayak) 문화 유산:</strong> 자연뿐만 아니라 역사가 깊은 다야크 토문(Dayak Tomun) 부족의 전통 가옥인 루마 베탕(Rumah Betang)을 방문하여 현지의 풍요로운 문화를 가까이서 느껴보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索婆罗洲之心：丹绒普廷国家公园的神奇冒险</strong></h2><p style=\"text-align:justify;\">体验一场深入加里曼丹茂密热带雨林的终生难忘之旅。在为期三天的行程中，您将抛开现代世界的喧嚣，回归纯净的荒野，穿梭在平静的河流中，结识森林的原住民——红毛猩猩。</p><h3 style=\"text-align:justify;\"><strong>为什么要购买此套餐：</strong></h3><ul><li data-list-item-id=\"e90e317d98aaa36d92de2515abd502ee0\"><p style=\"text-align:justify;\"><strong>与红毛猩猩近距离接触：</strong> 参观世界级的保护中心，如 <strong>Camp Leakey（李奇营）</strong>，在喂食时间亲眼目睹红毛猩猩在自然栖息地的真实生活。</p></li><li data-list-item-id=\"e9de74ec61464b947a35975284b5ee4a6\"><p style=\"text-align:justify;\"><strong>传统的 Klotok 船宿体验：</strong> 住在并睡在 <strong>传统 Klotok 船屋</strong> 上，感受独特冒险的浪漫。在森林天蓬下，伴随着夜晚的大自然声音入眠，是一段难以忘怀的经历。</p></li><li data-list-item-id=\"e647edd2a03926414afbd9cc543b2a31d\"><p style=\"text-align:justify;\"><strong>“黑河”奇观：</strong> 航行在宁静的茶色溪流中，它像一面巨大的镜子完美地倒映着雨林，是摄影爱好者的绝佳取景地。</p></li><li data-list-item-id=\"e444f7ec53798d992d1bf44d93c97bb4f\"><p style=\"text-align:justify;\"><strong>万千萤火虫下的晚餐：</strong> 以神奇的 <strong>萤火虫晚餐</strong> 结束您的冒险，河岸边成千上万只萤火虫闪烁微光，点亮黑暗的丛林。</p></li><li data-list-item-id=\"ea358dafcd533bb789d47467fe7d21609\"><p style=\"text-align:justify;\"><strong>达雅族文化遗产：</strong> 除了自然风光，您还将参观 <strong>Rumah Betang（长屋）</strong>，深入了解富有历史底蕴的达雅托门族（Dayak Tomun）传统文化。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"eac041288dec1b7647210e1a4666d6a46\">Airport / Hotel Pick-up &amp; Drop-off</li><li data-list-item-id=\"e7b4f13a9180aae5d9f314d94a5dfc6b7\">Expert Guide &amp; Ranger Donation</li><li data-list-item-id=\"e1e946abe4f3df8de896380c401c93867\">2 Nights Houseboat Accommodation</li><li data-list-item-id=\"e96a3bb1b6875808dd472797d3e8c098a\">Full Board Meals &amp; Snacks (Onboard)</li><li data-list-item-id=\"ee5d3691c5b4fe68ccd31a8899ecae4f7\">National Park Entrance Fees</li><li data-list-item-id=\"ebec41587397d813b55f5371cdc74ef49\">Visits to 3 Orangutan Feeding Camps</li></ul>', '<ul><li data-list-item-id=\"edb9ab7af9cb1943314865e494b9d2cbf\">Domestic and international flight ticket</li><li data-list-item-id=\"e498c85a8c54ba796871dc2806c2c6856\">Domestic and international airport tax</li><li data-list-item-id=\"efb87e58562f649509f6b65e8f24c2706\">Guide and driver tip</li><li data-list-item-id=\"ea10196abc092410204b215be6a83e887\">Optional tour &amp; other personal expense</li><li data-list-item-id=\"ec7bb9a0f06320f2f2e68cd7cfdd1763d\">Insurance</li></ul><p><br>&nbsp;</p>', NULL, '[\"Nature\",\"Adventure\",\"WILDLIFE\",\"Culture\",\"ECOTOURISM\"]', NULL, 0, NULL, '2026-05-02 00:40:53', '2026-05-29 14:39:05'),
(40, 39, '4 DAYS TANJUNG PUTING TOUR', 'CENTRAL KALIMANTAN', '4-days-tanjung-puting-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Jantung Kalimantan: Petualangan Magis 4 Hari di Taman Nasional Tanjung Puting</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk perjalanan melintasi waktu ke salah satu hutan hujan tropis paling murni di dunia. Selama 4 hari, Anda akan meninggalkan kebisingan kota dan memasuki dunia liar yang tenang, menyusuri sungai legendaris, dan bertatap muka langsung dengan orangutan di habitat asli mereka. Ini bukan sekadar liburan, ini adalah petualangan yang akan mengubah perspektif hidup Anda.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Mencoba Petualangan Ini?</strong></h3><ul><li data-list-item-id=\"ec0cd1750eb82211d3dc25d21bd0c8109\"><p style=\"text-align:justify;\"><strong>Interaksi Intim dengan Orangutan:</strong> Kunjungi tiga pusat pemberian makan yang berbeda, termasuk <strong>Camp Leakey</strong> yang legendaris, tempat penelitian orangutan paling terkenal di dunia.</p></li><li data-list-item-id=\"ec7565e39d1629ad79cdb13535c6d52f8\"><p style=\"text-align:justify;\"><strong>Keajaiban Sungai Hitam (Black River):</strong> Rasakan ketenangan luar biasa saat menyusuri sungai dengan air yang tenang seperti cermin, memantulkan rimbunnya hutan Kalimantan dengan sempurna—sebuah surga bagi fotografer.</p></li><li data-list-item-id=\"efa179dd0d1a8771914cbb34531cd10ec\"><p style=\"text-align:justify;\"><strong>Akomodasi Houseboat yang Unik:</strong> Menginap selama 3 malam di atas <strong>Kapal Klotok tradisional</strong>. Tidur di bawah atap langit hutan dengan kenyamanan kasur dan kelambu, ditemani harmoni suara alam yang menenangkan.</p></li><li data-list-item-id=\"e059759deee2135ea0bab9e5adc98bcfc\"><p style=\"text-align:justify;\"><strong>Eksplorasi Rimba Siang &amp; Malam:</strong> Rasakan sensasi <i>Long Trekking</i> ke dalam hutan rimba dan <i>Night Trekking</i> yang mendebarkan untuk menemukan satwa nokturnal yang misterius.</p></li><li data-list-item-id=\"eb5dcfc8fcbba10c2ca0ae0ce5316e642\"><p style=\"text-align:justify;\"><strong>Malam Magis Bersama Kunang-Kunang:</strong> Nikmati <strong>Firefly Dinner</strong> yang spektakuler, di mana ribuan kunang-kunang akan menerangi tepian sungai seperti hiasan lampu natal alami.</p></li><li data-list-item-id=\"edd2f988385b98dd7c1f51122bf6b4ecc\"><p style=\"text-align:justify;\"><strong>Kedekatan dengan Budaya Dayak:</strong> Kunjungi <strong>Desa Sekonyer</strong> dan <strong>Rumah Betang</strong> di Pasir Panjang untuk mengenal lebih dekat gaya hidup dan kearifan lokal suku Dayak Tomun yang ramah.</p></li><li data-list-item-id=\"e0a6920efeaced6171149686c82be5d18\"><p style=\"text-align:justify;\"><strong>Pengalaman Kano yang Damai:</strong> Rasakan kedekatan langsung dengan air dan hutan melalui aktivitas berkano yang menenangkan di aliran sungai.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Heart of Borneo: A Magical 4-Day Adventure in Tanjung Puting National Park</strong></h2><p style=\"text-align:justify;\">Prepare yourself for a journey through time into one of the world\'s most pristine tropical rainforests. For 4 days, you will leave the city noise behind and enter a serene wild world, cruising legendary rivers and coming face-to-face with orangutans in their natural habitat. This is not just a holiday; it is an adventure that will change your perspective on life.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Adventure:</strong></h3><ul><li data-list-item-id=\"e9a5c1d3784dc632106797231399a506b\"><p style=\"text-align:justify;\"><strong>Intimate Encounters with Orangutans:</strong> Visit three different feeding stations, including the legendary <strong>Camp Leakey</strong>, the world\'s most famous orangutan research center.</p></li><li data-list-item-id=\"ee56b40c8cdfc7bc0d63827f298161a9d\"><p style=\"text-align:justify;\"><strong>The Magic of the Black River:</strong> Experience extraordinary tranquility while cruising a river with water as calm as a mirror, perfectly reflecting the lush Borneo jungle—a paradise for photographers.</p></li><li data-list-item-id=\"e5ec8e183e87c53fc57bcda41c2a27c81\"><p style=\"text-align:justify;\"><strong>Unique Houseboat Accommodation:</strong> Stay for 3 nights aboard a <strong>traditional Klotok boat</strong>. Sleep under the forest canopy on comfortable mattresses with mosquito nets, accompanied by the soothing harmony of nature.</p></li><li data-list-item-id=\"e55b54c1809bb0fb491ceb503039530cf\"><p style=\"text-align:justify;\"><strong>Day &amp; Night Jungle Exploration:</strong> Feel the thrill of <strong>Long Trekking</strong> deep into the wilderness and exciting <strong>Night Trekking</strong> to discover mysterious nocturnal wildlife.</p></li><li data-list-item-id=\"e610d480805c1a375e7173129328c16dc\"><p style=\"text-align:justify;\"><strong>Magical Nights with Fireflies:</strong> Enjoy a spectacular <strong>Firefly Dinner</strong>, where thousands of fireflies illuminate the riverbanks like natural Christmas lights.</p></li><li data-list-item-id=\"e16dd85dccfa9469597221ed9e1440f98\"><p style=\"text-align:justify;\"><strong>Deep Connection with Dayak Culture:</strong> Visit <strong>Sekonyer Village</strong> and the <strong>Rumah Betang</strong> in Pasir Panjang to get closer to the lifestyle and local wisdom of the friendly Dayak Tomun tribe.</p></li><li data-list-item-id=\"ed81defeed8982358717e6eddc3d6870c\"><p style=\"text-align:justify;\"><strong>Peaceful Canoeing Experience:</strong> Feel a direct connection with the water and the forest through a calming <strong>Canoeing</strong> activity along the river.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>보르네오의 심장을 탐험하세요: 탄중 푸팅 국립공원에서의 마법 같은 4일간의 모험</strong></h2><p style=\"text-align:justify;\">세계에서 가장 원시적인 열대 우림 중 하나로 떠나는 시간 여행을 준비하세요. 4일 동안 도시의 소음을 뒤로하고 평온한 야생의 세계로 들어가 전설적인 강을 항해하며 자연 서식지에서 오랑우탄을 직접 마주하게 됩니다. 이것은 단순한 휴가가 아니라 인생의 관점을 바꿔줄 모험입니다.</p><h3 style=\"text-align:justify;\"><strong>이 모험을 반드시 경험해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e86c67b8fa165e07e1186c2c3e1fff9ab\"><p style=\"text-align:justify;\"><strong>오랑우탄과의 친밀한 만남:</strong> 세계적으로 유명한 오랑우탄 연구 센터인 캠프 리키(Camp Leakey)를 포함하여 세 곳의 서로 다른 급식소를 방문합니다.</p></li><li data-list-item-id=\"e8d4493b5cca0cbb13c581beca3d22f7b\"><p style=\"text-align:justify;\"><strong>블랙 리버(Black River)의 마법:</strong> 거대한 거울처럼 고요한 강을 항해하며 보르네오의 무성한 정글을 완벽하게 투영하는 비현실적인 평온함을 경험하세요. 사진가들에게는 천국과도 같은 곳입니다.</p></li><li data-list-item-id=\"e482963a3603fd7943f738056e1314d4f\"><p style=\"text-align:justify;\"><strong>독특한 하우스보트 숙박:</strong> <strong>전통 클로톡(Klotok) 보트</strong>에서 3박을 머뭅니다. 편안한 매트리스와 모기장이 갖춰진 숲의 캐노피 아래에서 대자연의 화모니를 들으며 잠을 청해보세요.</p></li><li data-list-item-id=\"ebe7880536e2f9a634bf2f20cf87557cd\"><p style=\"text-align:justify;\"><strong>낮과 밤의 정글 탐험:</strong> 야생 깊숙이 들어가는 롱 트레킹(Long Trekking)과 신비로운 야행성 야생 동물을 발견하는 스릴 넘치는 나이트 트레킹(Night Trekking)을 즐겨보세요.</p></li><li data-list-item-id=\"ee361db61b4e39fab5e751494a0a583a1\"><p style=\"text-align:justify;\"><strong>반딧불이와 함께하는 마법 같은 밤:</strong> 수천 마리의 반딧불이가 천연 크리스마스 조명처럼 강변을 밝히는 환상적인 <strong>반딧불이 디너</strong>를 즐겨보세요.</p></li><li data-list-item-id=\"e4d851cc20e88d93e74b5547c25c2b521\"><p style=\"text-align:justify;\"><strong>다야크(Dayak) 문화와의 깊은 교감:</strong> <strong>세코니에르(Sekonyer) 마을</strong>과 파시르 판장(Pasir Panjang)의 루마 베탕(Rumah Betang)을 방문하여 친절한 다야크 토문 부족의 생활 방식과 지혜를 가까이서 느껴보세요.</p></li><li data-list-item-id=\"ea2f916ce7d9c8f8b5cf399083c557620\"><p style=\"text-align:justify;\"><strong>평화로운 카누 체험:</strong> 강을 따라 흐르는 차분한 <strong>카누(Canoeing)</strong> 활동을 통해 물과 숲을 직접 느껴보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索婆罗洲之心：丹绒普廷国家公园 4 日梦幻之旅</strong></h2><p style=\"text-align:justify;\">准备好踏上一场穿越时空的旅程，进入世界上最原始的热带雨林之一 。在 4 天的时间里，您将远离城市喧嚣，进入宁静的野生世界，巡游传奇河流，在自然栖息地与红毛猩猩面对面 。这不仅是一次假期，更是一场将改变您人生观的冒险 。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须体验这场冒险：</strong></h3><ul><li data-list-item-id=\"ec3b44b6a050caf856fb9f6e938a16342\"><p style=\"text-align:justify;\"><strong>与红毛猩猩亲密接触：</strong> 参观三个不同的喂食站，包括传奇的 <strong>Camp Leakey（李奇营）</strong>，这是世界上最著名的红毛猩猩研究中心 。</p></li><li data-list-item-id=\"e7b136fbad06ed82a99dcabcfb2838fa8\"><p style=\"text-align:justify;\"><strong>黑河（Black River）的神奇：</strong> 巡游在如镜面般平静的河面上，完美倒映着茂密的婆罗洲丛林，体验非凡的宁静——这里是摄影师的天堂 。</p></li><li data-list-item-id=\"e7cd98e4ce089325a3bfa4f3729a5977c\"><p style=\"text-align:justify;\"><strong>独特的船屋住宿：</strong> 在 <strong>传统 Klotok 船</strong> 上度过 3 个夜晚 。躺在配备舒适床垫和蚊帐的森林天蓬下，在大自然和谐的乐章中入眠 。</p></li><li data-list-item-id=\"eb08cd49077820b982c7dd5b9e7752b43\"><p style=\"text-align:justify;\"><strong>昼夜丛林探索：</strong> 感受深入荒野的 <strong>长途徒步（Long Trekking）</strong> 以及发现神秘夜间野生动物的刺激 <strong>夜间徒步（Night Trekking）</strong> 。</p></li><li data-list-item-id=\"ee27f81578d1aa46db366587800ec4be6\"><p style=\"text-align:justify;\"><strong>萤火虫之夜：</strong> 享受壮观的 <strong>萤火虫晚餐</strong>，成千上万只萤火虫像天然圣诞灯饰一样点亮河岸 。</p></li><li data-list-item-id=\"e3edfa5a37b1b633f0b9249372a0ba34a\"><p style=\"text-align:justify;\"><strong>深度的达雅文化连接：</strong> 访问 <strong>Sekonyer 村</strong> 和位于 Pasir Panjang 的 <strong>Rumah Betang（长屋）</strong>，近距离接触友好的达雅托门族（Dayak Tomun）的生活方式和地方智慧 。</p></li><li data-list-item-id=\"e55c0f5ceb6c7086c8b7f5a77cccde384\"><p style=\"text-align:justify;\"><strong>宁静的划艇体验：</strong> 通过沿着河流进行的平静 <strong>划艇（Canoeing）</strong> 活动，感受与水和森林的直接连接 。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e4de977303654c8d83bb966467e998d3e\">Airport / Hotel Pick-up &amp; Drop-off</li><li data-list-item-id=\"e9fbe84d263b65e36ef9367c72fc4fa59\">3 Nights Houseboat Accommodation</li><li data-list-item-id=\"e2821d6298d22e7c8c74e26d1dad60aec\">All Meals, Snacks, and Mineral Water (Onboard)</li><li data-list-item-id=\"e04469b62c92608e7eb8c58904870202c\">Expert Guide &amp; Ranger Donation</li><li data-list-item-id=\"e6c081ef6d2724ba2f32febd96de68b07\">National Park Entrance Fees</li><li data-list-item-id=\"e4256df11541df36b2bbb87148779eb48\">Visits to 3 Orangutan Feeding Camps</li><li data-list-item-id=\"e5573f5bc062d87ba585b57180f15e86d\">Night Trekking &amp; Long Jungle Trekking</li><li data-list-item-id=\"eae848116c37c704de7996d18e97ca696\">Canoeing Experience</li></ul>', '<ul><li data-list-item-id=\"ebdf7bbbfc83c02b75ac08c7c0b201e2e\">Domestic and international flight ticket</li><li data-list-item-id=\"e7124e8c6dc3ac0d155dbe722518910a6\">Domestic and international airport tax</li><li data-list-item-id=\"e4b7d02078e126c3411fc53abc20fc8a3\">Guide and driver tip</li><li data-list-item-id=\"e83073d00dfbf0c4c7af897f4e37dc888\">Optional tour &amp; other personal expense</li><li data-list-item-id=\"ec9636c2047eb47c1a2396ca8ab65a736\">Insurance</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"WILDLIFE\",\"HERITAGE\",\"ECOTOURISM\"]', NULL, 1, 'popular', '2026-05-02 01:52:02', '2026-06-01 15:24:04'),
(41, 40, '3 DAYS LABUAN BAJO TOUR', 'NUSA TENGGARA TIMUR', '3-days-labuan-bajo-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tersembunyi: 3D2N Labuan Bajo Adventure</strong></h2><p style=\"text-align:justify;\">Rasakan petualangan tak terlupakan di jantung Flores! Paket tour 3 hari 2 malam ini akan membawa Anda menembus batas keindahan alam Indonesia, mulai dari gua prasejarah hingga berenang bersama biota laut raksasa di perairan kristal Taman Nasional Komodo.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"edffad30767c442c311c476661a1d43fe\"><p style=\"text-align:justify;\"><strong>Puncak Dunia di Pulau Padar:</strong> Berdirilah di titik tertinggi Pulau Padar dan saksikan mahakarya alam berupa perbukitan hijau yang membelah tiga teluk dengan warna air yang kontras—sebuah panorama ikonik yang hanya ada di sini.</p></li><li data-list-item-id=\"ebe3a3f6a86d8692e16fcbdb9458f15f4\"><p style=\"text-align:justify;\"><strong>Bertemu Sang Naga Purba:</strong> Masuki habitat asli Komodo, kadal raksasa terakhir di dunia. Dipandu oleh ranger profesional, Anda akan melihat dari dekat keajaiban evolusi ini di lingkungan alaminya yang liar namun eksotis.</p></li><li data-list-item-id=\"e8120a5b06368a006a6f270e25c3d2e9e\"><p style=\"text-align:justify;\"><strong>Keajaiban Bawah Laut Manta Point:</strong> Rasakan sensasi mendebarkan saat snorkeling berdampingan dengan Manta Ray yang megah. Kejernihan air di Manta Point dan Taka Makassar memberikan jarak pandang sempurna untuk melihat kemegahan bawah laut ini.</p></li><li data-list-item-id=\"e4094f0721fe3b781eb1983361a8db0f2\"><p style=\"text-align:justify;\"><strong>Relaksasi di Long Pink Beach:</strong> Manjakan mata Anda dengan hamparan pasir berwarna merah muda yang langka. Kontras antara pasir pink, air laut biru toska, dan bukit savana menciptakan latar belakang foto yang luar biasa.</p></li><li data-list-item-id=\"ed559a573f8ee56b29638f195d60d1085\"><p style=\"text-align:justify;\"><strong>Goa Batu Cermin &amp; Golden Sunset:</strong> Jelajahi misteri stalaktit dan stalagmit di Goa Batu Cermin, lalu tutup hari Anda dengan berburu matahari terbenam terbaik di Puncak Waringin yang menyuguhkan pemandangan pelabuhan Labuan Bajo dari ketinggian.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover Hidden Paradise: 3D2N Labuan Bajo Adventure</strong></h2><p style=\"text-align:justify;\">Embark on an unforgettable journey to the heart of Flores! This 3-day, 2-night tour takes you beyond the limits of Indonesia\'s natural beauty, from prehistoric caves to swimming alongside giant marine life in the crystal-clear waters of Komodo National Park.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Trip:</strong></h3><ul><li data-list-item-id=\"ee7475598397874d5615b22660b6a126b\"><p style=\"text-align:justify;\"><strong>The Peak of the World at Padar Island:</strong> Stand at the highest point of Padar Island and witness a natural masterpiece—green hills dividing three bays with contrasting watercolors.</p></li><li data-list-item-id=\"e7bd6ad93d71ea78399b428d9b0c67133\"><p style=\"text-align:justify;\"><strong>Encounter the Ancient Dragon:</strong> Enter the natural habitat of the Komodo Dragon, the world\'s last giant lizard, guided by professional Rangers.</p></li><li data-list-item-id=\"ef5fff7c40a205cab84c3be3703ede844\"><p style=\"text-align:justify;\"><strong>Underwater Magic at Manta Point:</strong> Experience the thrill of snorkeling alongside majestic Manta Rays in crystal-clear waters.</p></li><li data-list-item-id=\"e2c33cbee56949adcbc8b97dd90b2ac6c\"><p style=\"text-align:justify;\"><strong>Relaxation at Long Pink Beach:</strong> Pamper your eyes with rare pink sands, turquoise waters, and savanna hills that create the ultimate photo backdrop.</p></li><li data-list-item-id=\"eef7fad6146f7ec02b7c02802d4eb19f5\"><p style=\"text-align:justify;\"><strong>Batu Cermin Cave &amp; Golden Sunset:</strong> Explore the mysterious stalactites of Batu Cermin Cave and end your day with the best sunset at Puncak Waringin.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>숨겨진 낙원을 찾아서: 3박 2일 라부안 바조 어드벤처</strong></h2><p style=\"text-align:justify;\">플로레스의 심장부로 떠나는 잊지 못할 여행! 이 3박 2일 투어는 선사 시대 동굴부터 코모도 국립공원의 투명한 바다에서 거대 해양 생물과 함께하는 수영까지, 인도네시아 자연미의 한계를 뛰어넘는 경험을 선사합니다.</p><h3 style=\"text-align:justify;\"><strong>이 여행을 반드시 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e15ee1b9250794915af3a839b081ac185\"><p style=\"text-align:justify;\"><strong>파다르 섬의 절경:</strong> 파다르 섬의 가장 높은 곳에 서서 세 개의 만이 대조적인 물빛을 띠며 펼쳐지는 대자연의 걸작을 감상하세요.</p></li><li data-list-item-id=\"e5bc9c3a4f6a90b1992453aae78e8de9e\"><p style=\"text-align:justify;\"><strong>고대 드래곤과의 만남:</strong> 전문 레인저의 안내를 받으며 세계 마지막 거대 도마뱀인 코모도 드래곤의 야생 서식지를 탐험하세요.</p></li><li data-list-item-id=\"eef6780a33bbdfeed579bd0a3dc13c5f9\"><p style=\"text-align:justify;\"><strong>만타 포인트의 수중 마법:</strong> 맑고 투명한 바다 속에서 거대한 만타 가오리와 함께 스노클링을 즐기는 짜릿한 전율을 느껴보세요.</p></li><li data-list-item-id=\"e0c2e70c9c24ff56cc4e7848a9ae8f088\"><p style=\"text-align:justify;\"><strong>롱 핑크 비치에서의 휴식:</strong> 희귀한 분홍빛 모래사장과 에메랄드빛 바다가 어우러진 환상적인 풍경 속에서 인생 사진을 남겨보세요.</p></li><li data-list-item-id=\"e104ca68b19c3f52a94dcf24039b6b960\"><p style=\"text-align:justify;\"><strong>바투 처민 동굴 &amp; 황금빛 일몰:</strong> 신비로운 종유석 동굴을 탐험하고, 푸작 와링인에서 라부안 바조 최고의 일몰로 하루를 마무리하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索隐藏的乐园：3天2夜 科莫多岛（拉布안巴佐）探险之旅</strong></h2><p style=\"text-align:justify;\">开启一场前往弗洛勒斯核心地带的难忘之旅！这趟3天2夜的行程将带您超越印度尼西亚自然美景的极限，从史前洞穴到在科莫多国家公园清澈见底的海水中与巨型海洋生物共泳。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须体验此行程：</strong></h3><ul><li data-list-item-id=\"ed1e04311cfe66ff7838e24ebe8e5e8c9\"><p style=\"text-align:justify;\"><strong>帕达尔岛的世界之巅：</strong> 登上帕达尔岛的最高点，见证大自然的杰作——翠绿的山丘将三种不同水色的海湾完美分割。</p></li><li data-list-item-id=\"ec9b9fff56e7da6aefe1565117512e373\"><p style=\"text-align:justify;\"><strong>邂逅远古巨龙：</strong> 在专业护林员的带领下，走进世界最后一种巨型蜥蜴——科莫多龙的天然栖息地。</p></li><li data-list-item-id=\"ef878ef2ed6fc12f8e7b0d1456c282e2c\"><p style=\"text-align:justify;\"><strong>曼塔角的深海魔力：</strong> 在清澈的海水中与雄伟的曼塔鳐鱼（魔鬼鱼）一同浮潜，感受心跳加速的震撼体验。</p></li><li data-list-item-id=\"e335682c26b879bec715535003f829f4a\"><p style=\"text-align:justify;\"><strong>漫步粉红沙滩：</strong> 沉浸在稀有的粉红色沙滩中，青绿色的海水与稀树草原山丘交织成绝佳的摄影背景。</p></li><li data-list-item-id=\"e5a9e88cab1339481db99a8964f47aba1\"><p style=\"text-align:justify;\"><strong>镜石洞与黄金日落：</strong> 探索镜石洞神秘的钟乳石，并在普查瓦林因（Puncak Waringin）欣赏拉布安巴佐最美的日落。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ef526409527a99fd38b41ad9e73a770b7\">Full AC transportation</li><li data-list-item-id=\"eb461b0d20e184ac0c890348e4df4c972\">Life Jacket &amp; snorkeling equipment</li><li data-list-item-id=\"ed53b179481757cd6a84707096d30bf9d\">Hotel Accommodation (according to choice)</li><li data-list-item-id=\"e54a7ef58cefb37f668eb36e000338e41\">Guide as driver (according to number of guests)</li><li data-list-item-id=\"e6053583e3d5e48533dd419b7c163edb1\">Entrance ticket to Batu Cermin Cave</li><li data-list-item-id=\"ed51d6935c1576bb6a4bfc18d52beed00\">Speedboat tour 6 islands</li><li data-list-item-id=\"e11d5dbef3fd4c9b2cc70cd4187b94e96\">Meals according to the program</li><li data-list-item-id=\"efd2a58d820477be1fd374078a649e0c3\">Mineral water 1 bottle/day/person</li></ul>', '<ul><li data-list-item-id=\"e0d65d18429cc8508a5d067beefa4ab1e\">Flight tickets</li><li data-list-item-id=\"e4b2e8c3da9f721f3be966a9aa79090a6\">Optional tours &amp; personal expenses</li><li data-list-item-id=\"e9b1b040d16560ac5fbd4a553c9adea5e\">Travel insurance</li><li data-list-item-id=\"eb5eeda73c50aba5588c25ba197531df9\">Additional meals and beverages</li><li data-list-item-id=\"e06fadda33e91b56f11641d35ae847256\">Extra hotel services (telephone, laundry, spa, etc.)</li><li data-list-item-id=\"ea69f485cab2bd4b2169430c11ddf9a41\">Guide tipping&nbsp;</li><li data-list-item-id=\"ebeabe4d887d403301346df458db6a382\">Komodo National Park entrance fees (Foreigner: 500,000 IDR/pax; Local/Domestic: 250,000 IDR/pax)</li><li data-list-item-id=\"eae04dd7b5d722adc2389f336e18f26df\">Documentation</li></ul>', NULL, '[\"Nature\",\"WILDLIFE\",\"Beach\",\"Adventure\",\"TREKKING\"]', NULL, 0, NULL, '2026-05-02 07:57:09', '2026-05-29 14:53:51'),
(42, 40, '4 DAYS LABUAN BAJO TOUR', 'NUSA TENGGARA TIMUR', '4-days-labuan-bajo-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Dunia: 4D3N Labuan Bajo Komodo Adventure</strong></h2><p style=\"text-align:justify;\">Ingin merasakan pengalaman sekali seumur hidup di salah satu destinasi paling spektakuler di dunia? Paket eksklusif 4 hari 3 malam ini akan membawa Anda menembus keajaiban alam Taman Nasional Komodo dan keindahan tersembunyi di daratan Flores. Dari puncak bukit ikonik hingga kolam air asin rahasia di dalam gua, setiap detik perjalanan ini adalah mahakarya alam yang menunggu untuk Anda jelajahi.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Membeli Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"ea901411276371afbc682ba7522c33ab6\"><p style=\"text-align:justify;\"><strong>Eksplorasi Lengkap 6 Destinasi Ikonik dalam Sehari:</strong> Rasakan sensasi membelah lautan dengan <i>speedboat</i> menuju <strong>Pulau Padar</strong> untuk melihat panorama tiga teluk yang fenomenal, bersantai di <strong>Long Pink Beach</strong> yang pasirnya berwarna merah muda langka, dan snorkeling bersama <strong>Manta Ray</strong> di habitat aslinya.</p></li><li data-list-item-id=\"e73456450f23eb30ea02b2ccfa4e2f634\"><p style=\"text-align:justify;\"><strong>Bertemu Langsung dengan Sang Naga Purba:</strong> Dapatkan kesempatan langka mengunjungi <strong>Pulau Komodo</strong>, rumah bagi kadal raksasa purba terakhir di dunia, langsung di habitat alaminya dengan panduan ranger profesional.</p></li><li data-list-item-id=\"ee41f2d94315224929153409d5b8cd9c7\"><p style=\"text-align:justify;\"><strong>Sensasi Berenang di Kolam Alami Goa Rangko:</strong> Rasakan ketenangan luar biasa saat berenang di dalam gua dengan air biru kristal yang jernih dan kolam air asin alami yang eksotis—sebuah pengalaman \"permata tersembunyi\" yang tidak terlupakan.</p></li><li data-list-item-id=\"e670d15804610ad5e68d323f5ea48478d\"><p style=\"text-align:justify;\"><strong>Keindahan Daratan yang Menakjubkan:</strong> Jelajahi <strong>Goa Batu Cermin</strong> yang memantulkan cahaya layaknya cermin, nikmati <i>golden sunset</i> yang dramatis dari <strong>Bukit Sylvia</strong> dan <strong>Puncak Waringin</strong>, hingga mengenal kedekatan budaya di <strong>Rumah Tenun Baku Peduli</strong>.</p></li><li data-list-item-id=\"e994d0c20ceff2b766308080ac6be5d49\"><p style=\"text-align:justify;\"><strong>Wisata Pulau Tanpa Batas:</strong> Nikmati jernihnya air di <strong>Pulau Kanawa</strong> dan keunikan gundukan pasir putih di tengah laut <strong>Taka Makassar</strong> yang akan membuat foto-foto Anda tampak seperti di negeri dongeng.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>The Ultimate Escape: 4D3N Labuan Bajo &amp; Komodo Adventure</strong></h2><p style=\"text-align:justify;\">Dreaming of a once-in-a-lifetime experience in one of the world’s most spectacular destinations? This exclusive 4-day, 3-night package takes you through the natural wonders of Komodo National Park and the hidden gems of Flores. From iconic hilltops to secret saltwater cave pools, every second of this journey is a natural masterpiece waiting to be explored.</p><h3 style=\"text-align:justify;\"><strong>Why You Should Book This Tour:</strong></h3><ul><li data-list-item-id=\"e79781b61ccba0e37131545cc5cb19831\"><p style=\"text-align:justify;\"><strong>Complete Exploration of 6 Iconic Spots in One Day:</strong> Experience the thrill of a speedboat ride to <strong>Padar Island</strong> for the phenomenal three-bay view, relax at the rare <strong>Long Pink Beach</strong>, and snorkel with <strong>Manta Rays</strong> in their natural habitat.</p></li><li data-list-item-id=\"e4d8f016cca81e3ddc72c2fb18e809a4a\"><p style=\"text-align:justify;\"><strong>Meet the Ancient Dragons:</strong> Seize the rare opportunity to visit <strong>Komodo Island</strong>, home to the world’s last ancient giant lizards, guided by professional rangers.</p></li><li data-list-item-id=\"e79e0858bc78f7498c9a5bdf229479855\"><p style=\"text-align:justify;\"><strong>Swim in the Natural Pool of Rangko Cave:</strong> Feel the ultimate tranquility swimming in a cave with crystal-clear blue water and an exotic natural saltwater pool—an unforgettable \"hidden gem\" experience.</p></li><li data-list-item-id=\"e20fe95c173a8a4581e0eb3fc56f35a42\"><p style=\"text-align:justify;\"><strong>Stunning Mainland Beauty:</strong> Explore <strong>Batu Cermin Cave</strong> with its mirror-like reflections, witness dramatic golden sunsets from <strong>Sylvia Hill</strong> and <strong>Waringin Peak</strong>, and connect with local heritage at the <strong>Baku Peduli Weaving House</strong>.</p></li><li data-list-item-id=\"e20e31365c07dfb355b0808707fe3a155\"><p style=\"text-align:justify;\"><strong>Limitless Island Hopping:</strong> Enjoy the pristine waters of <strong>Kanawa Island</strong> and the unique white sandbar of <strong>Taka Makassar</strong>, making your photos look like a fairy tale.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>궁극의 파라다이스: 3박 4일 라부안 바조 &amp; 코모도 어드벤처</strong></h2><p style=\"text-align:justify;\">세계에서 가장 환상적인 여행지 중 하나에서 일생일대의 경험을 꿈꾸시나요? 이 특별한 3박 4일 패키지는 코모도 국립공원의 자연 경관과 플로레스의 숨겨진 보석 같은 곳들을 안내합니다. 상징적인 언덕 꼭대기부터 비밀스러운 해수 동굴 수영장까지, 이 여정의 매 순간은 탐험을 기다리는 대자연의 걸작입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 예약해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e414823571502e98814ce308a47fb6b91\"><p style=\"text-align:justify;\"><strong>하루 만에 즐기는 6대 명소 완전 정복:</strong> 스피드보트를 타고 <strong>파다르 섬</strong>으로 이동해 환상적인 세 개의 만을 감상하고, 희귀한 <strong>롱 핑크 비치</strong>에서 휴식을 취하며, <strong>만타 포인트</strong>에서 만타 가오리와 함께 스노클링을 즐겨보세요.</p></li><li data-list-item-id=\"e295f6a67b1dc7a7d3b163ed1500e5d11\"><p style=\"text-align:justify;\"><strong>고대 드래곤과의 만남:</strong> 전문 레인저의 안내를 받으며 세계 마지막 고대 거대 도마뱀인 코모도 드래곤의 서식지, <strong>코모도 섬</strong>을 방문하는 특별한 기회를 잡으세요.</p></li><li data-list-item-id=\"e610631149f43682c731a45dc983c2dba\"><p style=\"text-align:justify;\"><strong>랑코 동굴의 천연 수영장:</strong> 수정처럼 맑은 푸른 물과 이국적인 천연 해수 풀이 있는 동굴 속에서 즐기는 수영—잊지 못할 \"숨겨진 보물\" 같은 경험을 선사합니다.</p></li><li data-list-item-id=\"e383d444eeedab60168dbab22e167ea9f\"><p style=\"text-align:justify;\"><strong>눈부신 육지 투어:</strong> 거울처럼 빛을 반사하는 <strong>바투 처민 동굴</strong>을 탐험하고, <strong>실비아 언덕</strong>과 <strong>와링인 봉우리</strong>에서 극적인 황금빛 일몰을 감상하며, <strong>바쿠 페둘리 직물 센터</strong>에서 현지 전통을 느껴보세요.</p></li><li data-list-item-id=\"eeeff4d87fb80da3d5160a1e8905e9c7b\"><p style=\"text-align:justify;\"><strong>무궁무진한 아일랜드 호핑:</strong> <strong>카나와 섬</strong>의 깨끗한 바다와 <strong>타카 마카사르</strong>의 유니크한 모래사장에서 동화 같은 인생 사진을 남겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>终极世外桃源：4天3夜 科莫多岛（拉布安巴佐）探险之旅</strong></h2><p style=\"text-align:justify;\">渴望在世界上最壮丽的目的地之一开启一场终生难忘的旅行吗？这个专属的4天3夜行程将带您穿越科莫多国家公园的自然奇观和弗洛勒斯岛的隐藏秘境。从标志性的山顶到神秘的洞穴咸水池，旅程中的每一秒都是等待您去探索的大自然杰作。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须体验此行程：</strong></h3><ul><li data-list-item-id=\"e55b567ea4d331183b560d0a32d22abb2\"><p style=\"text-align:justify;\"><strong>一日之内游览六大标志性景点：</strong> 乘坐快艇前往 <strong>帕达尔岛</strong> 俯瞰绝美三湾全景，在稀有的 <strong>粉红沙滩</strong> 悠闲放松，并前往 <strong>曼塔角</strong> 与曼塔鳐鱼一同浮潜。</p></li><li data-list-item-id=\"e4754a9aac7b09bf582ba46eda7997a4c\"><p style=\"text-align:justify;\"><strong>近距离接触远古巨龙：</strong> 在专业护林员的带领下，获得难得的机会前往 <strong>科莫多岛</strong>，探访世界上最后一种远古巨型蜥蜴的家园。</p></li><li data-list-item-id=\"e726316158dcb28ec0ef85cd9e1ac04ca\"><p style=\"text-align:justify;\"><strong>在郎科洞（Rangko Cave）天然泳池畅游：</strong> 在晶莹剔透的蓝色海水和充满异国情调的天然咸水洞穴池中游泳，感受无与伦比的宁静——这是一段难以忘怀的“隐世珍宝”体验。</p></li><li data-list-item-id=\"e2353faabd3ea7be6f467cc86e3a0e577\"><p style=\"text-align:justify;\"><strong>惊艳的陆地之美：</strong> 探索如镜面般反射光芒的 <strong>镜石洞</strong>，在 <strong>西尔维亚山</strong> 和 <strong>普查瓦林因</strong> 欣赏壮丽的金黄日落，并前往 <strong>Baku Peduli 织布屋</strong> 感受当地文化。</p></li><li data-list-item-id=\"e0c0b6426dad822e424ad2e3ee2fcdb2e\"><p style=\"text-align:justify;\"><strong>无限精彩的海岛游：</strong> 在 <strong>卡纳瓦岛</strong> 清澈的海水中嬉戏，并在 <strong>塔卡马卡萨</strong> 独特的白沙洲上漫步，让您的照片宛如置身童话世界。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ef526409527a99fd38b41ad9e73a770b7\">Full AC transportation</li><li data-list-item-id=\"eb461b0d20e184ac0c890348e4df4c972\">Life Jacket &amp; snorkeling equipment</li><li data-list-item-id=\"ed53b179481757cd6a84707096d30bf9d\">Hotel Accommodation (according to choice)</li><li data-list-item-id=\"e54a7ef58cefb37f668eb36e000338e41\">Guide as driver (according to number of guests)</li><li data-list-item-id=\"e6053583e3d5e48533dd419b7c163edb1\">Entrance ticket to Batu Cermin Cave</li><li data-list-item-id=\"ec49910aeed31d51b3109a218377ef58a\">Entrance tickets to Goa Rangko &amp; boat rangko</li><li data-list-item-id=\"ed51d6935c1576bb6a4bfc18d52beed00\">Speedboat tour 6 islands</li><li data-list-item-id=\"e11d5dbef3fd4c9b2cc70cd4187b94e96\">Meals according to the program</li><li data-list-item-id=\"efd2a58d820477be1fd374078a649e0c3\">Mineral water 1 bottle/day/person</li></ul><p>&nbsp;</p>', '<ul><li data-list-item-id=\"e0d65d18429cc8508a5d067beefa4ab1e\">Flight tickets</li><li data-list-item-id=\"e4b2e8c3da9f721f3be966a9aa79090a6\">Optional tours &amp; personal expenses</li><li data-list-item-id=\"e9b1b040d16560ac5fbd4a553c9adea5e\">Travel insurance</li><li data-list-item-id=\"eb5eeda73c50aba5588c25ba197531df9\">Additional meals and beverages</li><li data-list-item-id=\"e06fadda33e91b56f11641d35ae847256\">Extra hotel services (telephone, laundry, spa, etc.)</li><li data-list-item-id=\"ea69f485cab2bd4b2169430c11ddf9a41\">Guide tipping&nbsp;</li><li data-list-item-id=\"ebeabe4d887d403301346df458db6a382\">Komodo National Park entrance fees (Foreigner: 500,000 IDR/pax; Local/Domestic: 250,000 IDR/pax)</li><li data-list-item-id=\"eae04dd7b5d722adc2389f336e18f26df\">Documentation</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"TREKKING\",\"Beach\"]', NULL, 0, NULL, '2026-05-02 08:29:35', '2026-05-29 14:52:46');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(43, 40, '3 DAYS SUMBA TOUR', 'NUSA TENGGARA TIMUR', '3-days-sumba-tour', '<h2 style=\"text-align:justify;\"><strong>Magic of Sumba: Petualangan Eksotis di Pulau Megalitik (3 Hari 2 Malam)</strong></h2><p style=\"text-align:justify;\">Ingin melarikan diri ke destinasi yang masih murni dan penuh misteri? Sumba adalah jawabannya. Selama 3 hari, kami akan membawa Anda melintasi waktu untuk menyaksikan harmoni antara alam yang dramatis dan budaya leluhur yang masih terjaga kuat. Dari perbukitan hijau yang ikonik hingga danau air payau yang jernih, setiap sudut Sumba adalah mahakarya alam yang menanti untuk Anda jelajahi.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e8c710eb826b88b554549443a4ac4b409\"><p style=\"text-align:justify;\"><strong>Pemandangan \"Teletubbies\" di Dunia Nyata:</strong> Berdiri di atas <strong>Bukit Lendongara</strong> dan saksikan sejauh mata memandang hamparan perbukitan hijau nan estetik yang akan membuat galeri foto Anda luar biasa.</p></li><li data-list-item-id=\"e4e0d4127873f692dd1598beda3a19329\"><p style=\"text-align:justify;\"><strong>Keajaiban Danau Waekuri:</strong> Rasakan sensasi berenang di danau air payau yang luas dengan kejernihan air kristal—sebuah <i>landmark</i> tak terlupakan yang hanya bisa Anda temukan di Sumba.</p></li><li data-list-item-id=\"e9b60b0c6ef74548a7f491d6dece1f46f\"><p style=\"text-align:justify;\"><strong>Eksplorasi Budaya di Kampung Praijing:</strong> Masuki gerbang masa lalu di kampung adat paling terkenal di Sumba Barat, rumah bagi 38 bangunan tradisional yang sarat akan makna sejarah.</p></li><li data-list-item-id=\"e5ad1f32861d8db03fa57a07e8f485897\"><p style=\"text-align:justify;\"><strong>Senja Magis di Pantai Pero:</strong> Tutup hari Anda dengan momen <i>sunset hunting</i> yang spektakuler di <strong>Pantai Pero</strong>, sebuah titik terbaik untuk melihat matahari tenggelam tepat di cakrawala.</p></li><li data-list-item-id=\"e4e95f05c428192aafa7fdb77079e15b9\"><p style=\"text-align:justify;\"><strong>Pantai Pribadi yang Tenang:</strong> Nikmati kesunyian dan hamparan pasir putih yang meluas di <strong>Pantai Mananga Aba</strong> dan <strong>Pantai Mandorak</strong>, tempat terbaik untuk melepas penat dari keramaian kota.</p></li></ul>', '<h3 style=\"text-align:justify;\"><strong>Magic of Sumba: An Exotic Adventure on the Megalithic Island (3 Days 2 Nights)</strong></h3><p style=\"text-align:justify;\">Looking for an escape to a pristine and mysterious destination? Sumba is the answer. Over 3 days, we will take you through time to witness the harmony between dramatic nature and ancient ancestral cultures that remain strongly preserved. From iconic green hills to crystal-clear brackish lakes, every corner of Sumba is a natural masterpiece waiting for you to explore.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Adventure:</strong></h3><ul><li data-list-item-id=\"e2e17bec2641866e40f5eabf2d5f17231\"><p style=\"text-align:justify;\"><strong>Real-Life \"Teletubbies\" Scenery:</strong> Stand atop <strong>Lendongara Hill</strong> and witness the aesthetic expanse of green rolling hills that will make your photo gallery extraordinary.</p></li><li data-list-item-id=\"e81b8d605e6f276250fd3cd7762a6053b\"><p style=\"text-align:justify;\"><strong>The Magic of Waekuri Lake:</strong> Feel the sensation of swimming in a vast brackish lake with crystal-clear water—an unforgettable landmark unique to Sumba.</p></li><li data-list-item-id=\"e3f3cd5cf8cd847039c543ed87e1cae56\"><p style=\"text-align:justify;\"><strong>Cultural Exploration at Praijing Village:</strong> Step into the past at West Sumba’s most famous traditional village, home to 38 traditional houses rich in historical meaning.</p></li><li data-list-item-id=\"e1b070370f77642bfed9910cc1e388ea3\"><p style=\"text-align:justify;\"><strong>Magical Sunset at Pero Beach:</strong> End your day with a spectacular sunset hunting session at <strong>Pero Beach</strong>, one of the best spots to watch the sun dip below the horizon.</p></li><li data-list-item-id=\"ea78982661db5f0c7a90087eb132dad65\"><p style=\"text-align:justify;\"><strong>Peaceful Private Beaches:</strong> Enjoy the silence and vast white sands of <strong>Mananga Aba Beach</strong> and <strong>Mandorak Beach</strong>, perfect places to unwind from the city crowd.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>숨바의 마법: 거석문화의 섬에서의 이국적인 모험 (3박 2일)</strong></h2><p style=\"text-align:justify;\">태초의 순수함과 신비로움이 가득한 곳으로 떠나고 싶으신가요? 숨바가 그 정답입니다. 3일 동안 극적인 자연과 여전히 강하게 보존되어 온 조상의 문화 사이의 조화를 목격하는 시간 여행으로 여러분을 안내합니다. 상징적인 초록빛 언덕부터 수정처럼 맑은 기수 호수까지, 숨바의 모든 구석구석은 여러분의 탐험을 기다리는 자연의 걸작입니다.</p><h3 style=\"text-align:justify;\"><strong>이 모험을 반드시 경험해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ea5a6c65a209158aefb7971f7db9311dd\"><p style=\"text-align:justify;\"><strong>현실판 \"텔레토비\" 풍경:</strong> 렌동가라 언덕(Lendongara Hill)에 서서 끝없이 펼쳐진 미학적인 초록빛 구릉지를 감상하세요. 당신의 사진 갤러리를 특별하게 만들어 줄 것입니다.</p></li><li data-list-item-id=\"e855fe5a2f5ac6ac4f79a737bdf1f6f6d\"><p style=\"text-align:justify;\"><strong>와이쿠리 호수(Waekuri Lake)의 마법:</strong> 수정처럼 맑은 물을 자랑하는 거대한 기수 호수에서 수영하는 기분을 느껴보세요. 오직 숨바에서만 만날 수 있는 잊지 못할 랜드마크입니다.</p></li><li data-list-item-id=\"e8681a51e17801ea3e2197e1e98b51909\"><p style=\"text-align:justify;\"><strong>프라이징 마을(Praijing Village) 문화 탐방:</strong> 역사적 의미가 깊은 38채의 전통 가옥이 있는 서숨바에서 가장 유명한 전통 마을에서 과거로 발을 내디뎌 보세요.</p></li><li data-list-item-id=\"e4bc0859917efc2490a69809b9b5d1543\"><p style=\"text-align:justify;\"><strong>페로 해변(Pero Beach)의 마법 같은 노을:</strong> 수평선 너머로 지는 해를 감상하기 가장 좋은 명소 중 하나인 <strong>페로 해변</strong>에서 환상적인 일몰을 사냥하며 하루를 마무리하세요.</p></li><li data-list-item-id=\"e7173bfe735f75810dfe730ef55ae8100\"><p style=\"text-align:justify;\"><strong>평화로운 프라이빗 비치:</strong> 도시의 인파에서 벗어나 휴식을 취하기에 완벽한 마낭가 아바 해변(Mananga Aba Beach)과 만도락 해변(Mandorak Beach)의 고요함과 광활한 백사장을 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>梦幻松巴：巨石文化之岛的异域冒险（3天2夜）</strong></h2><p style=\"text-align:justify;\">想要逃离城市，前往一个原始而神秘的目的地吗？松巴岛（Sumba）就是您的答案。在 3 天的行程中，我们将带您穿梭时空，见证壮丽自然与完好保存的古老祖先文化之间的和谐共生。从标志性的翠绿山丘到清澈见底的咸淡水湖，松巴岛的每个角落都是等待您去探索的自然杰作。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须体验这场冒险：</strong></h3><ul><li data-list-item-id=\"e05403a64dfb08300c1696bee1c0d8c67\"><p style=\"text-align:justify;\"><strong>现实版“天线宝宝”景观：</strong> 站在 <strong>Lendongara 山丘</strong> 上，尽情领略美轮美奂的翠绿连绵山峦，让您的相册从此与众不同。</p></li><li data-list-item-id=\"e1e964449caa1d988036ad8ec5e9b402d\"><p style=\"text-align:justify;\"><strong>Waekuri 湖的神奇：</strong> 在水质清澈如晶的巨大咸淡水湖中畅游——这是松巴岛独有的、令人难忘的标志性景点。</p></li><li data-list-item-id=\"e7dd14187b15144075cee9cffa5f68a0d\"><p style=\"text-align:justify;\"><strong>Praijing 村的文化探索：</strong> 走进西松巴岛最著名的传统村落，这里拥有 38 栋富有历史意义的传统房屋，带您重回过去。</p></li><li data-list-item-id=\"e60b0be0a7e7fed1c33028f1080ecd05e\"><p style=\"text-align:justify;\"><strong>Pero 海滩的梦幻日落：</strong> 在 <strong>Pero 海滩</strong> 捕捉壮观的日落，这里是观赏太阳落入地平线的绝佳地点之一，为您的一天画上完美句号。</p></li><li data-list-item-id=\"eb969539872206f3032486b15ce7cf8f5\"><p style=\"text-align:justify;\"><strong>宁静的私人海滩：</strong> 在 <strong>Mananga Aba 海滩</strong> 和 <strong>Mandorak 海滩</strong> 享受静谧时光与广阔的白沙滩，这是远离城市喧嚣、放松身心的理想之地。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e5b463f9dac3a35b577b963ef566ece05\"><strong>AC Land Transportation</strong></li><li data-list-item-id=\"ea19469a54019cedb571949bbfde032ef\"><strong>Accommodations</strong>: 2 night\'s stay in West Sumba</li><li data-list-item-id=\"e838195b982a80a7e1b90fcc3552a8c3a\"><strong>Meals</strong>: Provided according to the tour program</li><li data-list-item-id=\"e7a653bae08d35bc2f84de22fa579989d\"><strong>Entrance Fees</strong>: Admission tickets for all listed tourist attractions</li><li data-list-item-id=\"ed099fa2d57821abd04b08ecde5ff59d9\"><strong>Mineral Water</strong>: Provided during the tour</li><li data-list-item-id=\"e3881e6cc29feba25a7d3d02a1f6771f0\"><strong>Guide as Driver</strong>: Professional assistance adjusted to the number of guests</li></ul>', '<ul><li data-list-item-id=\"e78ce29a077f0dfec5dd3002fa91bb904\"><strong>Flight Tickets</strong>: Airfare is not included in the package.</li><li data-list-item-id=\"eab1895ee8d1b7efd40005a1e1fc6e4f5\"><strong>Guide Tipping</strong>: Gratuities for the guide are not included.</li><li data-list-item-id=\"e03165e23d72b0b6bda8b883e86468f39\"><strong>Travel Insurance</strong>: Insurance coverage is not provided.</li><li data-list-item-id=\"e035e0f04c25666bad21f74aca685c3dc\"><strong>Personal Expenses</strong>: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e04afc296aa304d8ee332983b742af114\"><strong>Additional Meals &amp; Beverages</strong>: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"e7292168161ae99f7bb5757811e65bd0b\"><strong>Hotel Facilities</strong>: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\"]', NULL, 0, NULL, '2026-05-02 09:13:44', '2026-05-29 14:52:04'),
(44, 40, '4 DAYS SUMBA TOUR', 'NUSA TENGGARA TIMUR', '4-days-sumba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Eksotisme Pulau Sumba: 4D3N Sumba Tour Adventure</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk melangkah ke dalam dunia yang seolah berhenti berdetak di Pulau Sumba. Paket eksklusif 4 hari 3 malam ini akan membawa Anda melintasi batas waktu, menjelajahi perbukitan sabana yang tak berujung hingga pantai-pantai sunyi yang keindahannya masih sangat murni. Dari tradisi megalitik yang masih hidup hingga fenomena alam yang ajaib, setiap sudut Sumba adalah undangan untuk sebuah petualangan yang autentik.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Membeli Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"ebc2da870beab7c5414c6a2de3c777a14\"><p style=\"text-align:justify;\"><strong>Menjelajahi Negeri di Atas Awan Sumba:</strong> Rasakan sensasi berdiri di tengah <strong>Bukit Lendongara</strong> dan <strong>Bukit Wairinding</strong> yang fenomenal. Hamparan sabana hijau luas di musim hujan atau kuning keemasan di musim kemarau akan membuat Anda merasa seperti berada di dalam film <i>Teletubbies</i>.</p></li><li data-list-item-id=\"e95cc9d165bbe9c7dfa4d3f0d58eaab34\"><p style=\"text-align:justify;\"><strong>Keajaiban Air Payau Danau Waekuri:</strong> Kunjungi landmark paling ikonik di Sumba, <strong>Danau Waekuri</strong>, sebuah danau air payau yang sangat luas dengan kejernihan air yang memukau.</p></li><li data-list-item-id=\"e28a87021133aff47320e7e2b660a090c\"><p style=\"text-align:justify;\"><strong>Perjalanan Menembus Waktu di Kampung Adat:</strong> Temukan kearifan lokal di <strong>Kampung Adat Praijing</strong> dan <strong>Kampung Ratenggaro</strong>. Lihatlah langsung puluhan rumah tradisional dengan menara tinggi yang ikonik, simbol penghormatan kepada leluhur yang masih terjaga hingga kini.</p></li><li data-list-item-id=\"e2e87c0c7ef3959b23946c410d1e32cb0\"><p style=\"text-align:justify;\"><strong>Fenomena Pohon \"Menari\" di Pantai Walakiri:</strong> Nikmati salah satu matahari terbenam paling puitis di Indonesia di <strong>Pantai Walakiri</strong>, di mana deretan pohon bakau dengan bentuk unik yang tersusun rapi menjadi latar foto terbaik Anda.</p></li><li data-list-item-id=\"e9b4cd01071bc8fb2065f8a957845b379\"><p style=\"text-align:justify;\"><strong>Pantai-Pantai Tersembunyi yang Tenang:</strong> Temukan ketenangan sejati di <strong>Pantai Mananga Aba (Pantai Kita)</strong> yang sunyi dengan pasir putih meluas, serta <strong>Pantai Pero</strong> yang eksotis.</p></li><li data-list-item-id=\"e7f464dc53eb8efbb34c0e2b05f5c1ca4\"><p style=\"text-align:justify;\"><strong>Edukasi dan Warisan Budaya:</strong> Pelajari sejarah panjang pulau ini di <strong>Rumah Budaya</strong> dan kunjungi pusat oleh-oleh khas Sumba untuk membawa pulang potongan kecil keindahan pulau ini.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover the Exoticism of Sumba: 4D3N Sumba Tour Adventure</strong></h2><p style=\"text-align:justify;\">Prepare yourself to step into a world that seems to stand still on the island of Sumba. This exclusive 4-day, 3-night package will take you across boundaries, exploring endless savanna hills and pristine, quiet beaches. From living megalithic traditions to magical natural phenomena, every corner of Sumba is an invitation to an authentic adventure.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour:</strong></h3><ul><li data-list-item-id=\"e77af176bcd4fea61ca77e18b46a9eaa2\"><p style=\"text-align:justify;\"><strong>Explore Sumba’s \"Land Above the Clouds\":</strong> Experience the sensation of standing amidst the phenomenal <strong>Lendongara Hill</strong> and <strong>Wairinding Hill</strong>. The vast savanna, green in the rainy season or golden yellow in the dry season, will make you feel like you are in a \"Teletubbies\" movie.</p></li><li data-list-item-id=\"e6a465ebf3e571a055fb49e1e497e2c0f\"><p style=\"text-align:justify;\"><strong>The Miraculous Brackish Water of Waekuri Lake:</strong> Visit Sumba\'s most iconic landmark, <strong>Waekuri Lake</strong>, a wide brackish water lake with stunningly clear water.</p></li><li data-list-item-id=\"e3bcf5a5943f2fa5556422dfb2c49e399\"><p style=\"text-align:justify;\"><strong>A Journey Through Time in Traditional Villages:</strong> Discover local wisdom at <strong>Praijing Traditional Village</strong> and <strong>Ratenggaro Village</strong>. Witness dozens of iconic high-towered traditional houses, symbols of respect for ancestors that are still well-preserved today.</p></li><li data-list-item-id=\"e92ffe572545b38084697721995aac086\"><p style=\"text-align:justify;\"><strong>The Phenomenon of \"Dancing Trees\" at Walakiri Beach:</strong> Enjoy one of Indonesia\'s most poetic sunsets at <strong>Walakiri Beach</strong>, where uniquely shaped mangrove trees arranged neatly provide the best backdrop for your photos.</p></li><li data-list-item-id=\"e36708ffe2947e31a159f25a28a766ac8\"><p style=\"text-align:justify;\"><strong>Serene Hidden Beaches:</strong> Find true peace at the quiet <strong>Mananga Aba Beach (Kita Beach)</strong> with its expansive white sand, and the exotic <strong>Pero Beach</strong>.</p></li><li data-list-item-id=\"e84a37f73ed36867fce4c013b3812c50d\"><p style=\"text-align:justify;\"><strong>Heritage and Cultural Education:</strong> Learn about the island\'s long history at the <strong>Cultural House</strong> and visit Sumba\'s souvenir centers to bring home a piece of this beautiful island.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>숨바섬의 이국적인 매력 발견: 3박 4일 숨바 투어 어드벤처</strong></h2><p style=\"text-align:justify;\">시간이 멈춘 듯한 섬, 숨바(Sumba)의 세계로 발을 들일 준비를 하세요. 이 독점적인 3박 4일 패키지는 끝없이 펼쳐진 사바나 언덕과 때 묻지 않은 고요한 해변을 탐험하며 여러분을 새로운 세상으로 안내합니다. 살아있는 거석 전통부터 마법 같은 자연 현상까지, 숨바의 모든 구석구석은 진정한 모험으로의 초대입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 예약해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ede54bcb93da583cf0a16068a17ced6ef\"><p style=\"text-align:justify;\"><strong>숨바의 \'구름 위 마을\' 탐험:</strong> 경이로운 렌동아라 언덕(Lendongara Hill)과 <strong>와이린딩 언덕(Wairinding Hill)</strong> 한가운데 서 있는 기분을 느껴보세요. 우기에는 초록빛으로, 건기에는 황금빛으로 물드는 드넓은 사바나는 마치 영화 \'텔레토비\' 속에 들어온 듯한 착각을 불러일으킵니다.</p></li><li data-list-item-id=\"e758d83375f9b3b199a8cddaa00f384f7\"><p style=\"text-align:justify;\"><strong>와에쿠리 호수의 기적 같은 기수(汽水):</strong> 숨바의 가장 상징적인 랜드마크인 와에쿠리 호수(Waekuri Lake)를 방문하세요. 이곳은 놀라울 정도로 맑은 물을 자랑하는 드넓은 기수 호수입니다.</p></li><li data-list-item-id=\"e2c09acf99dafbc8d825ecb10d97765ee\"><p style=\"text-align:justify;\"><strong>전통 마을에서의 시간 여행:</strong> 프라이징 전통 마을(Praijing Village)과 라텡가로 마을(Ratenggaro Village)에서 현지의 지혜를 발견해 보세요. 오늘날까지도 잘 보존되어 있는 조상에 대한 존경의 상징인 높은 탑 모양의 전통 가옥 수십 채를 직접 볼 수 있습니다.</p></li><li data-list-item-id=\"e4a8d9b12a67f67a0aa7cb7f379234045\"><p style=\"text-align:justify;\"><strong>와라키리 해변의 \'춤추는 나무\' 현상:</strong> 인도네시아에서 가장 시적인 일몰 중 하나를 와라키리 해변(Walakiri Beach)에서 즐겨보세요. 독특한 모양의 맹그로브 나무들이 가지런히 배열되어 최고의 사진 배경을 제공합니다.</p></li><li data-list-item-id=\"ea5428d9e9f776dbf6d4684a5c9b87eb4\"><p style=\"text-align:justify;\"><strong>고요한 숨겨진 해변:</strong> 넓게 펼쳐진 백사장이 있는 조용한 마낭가 아바 해변(키타 해변)과 이국적인 <strong>페로 해변</strong>에서 진정한 평화를 찾아보세요.</p></li><li data-list-item-id=\"e0b37f084b79d039aa3774b8ad513e8f7\"><p style=\"text-align:justify;\"><strong>유산 및 문화 교육:</strong> 문화의 집(Rumah Budaya)에서 섬의 긴 역사를 배우고, 숨바 기념품 센터를 방문하여 이 아름다운 섬의 조각을 집으로 가져가세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索松巴岛的异域风情：4天3夜松巴岛探险之旅</strong></h2><p style=\"text-align:justify;\">准备好踏入松巴岛（Sumba）那个仿佛时间静止的世界了吗？这个专属的4天3夜行程将带您跨越边界，探索无尽的萨瓦纳（Savanna）丘陵和纯净宁静的海滩。从活生生的巨石传统到神奇的自然现象，松巴岛的每个角落都在邀请您开启一场真实的冒险。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须预订此行程：</strong></h3><ul><li data-list-item-id=\"e414ae0a88d77486bb8a8e013474d1192\"><p style=\"text-align:justify;\"><strong>探索松巴岛的“云端之地”：</strong> 感受站在绝美的 <strong>Lendongara 山丘</strong> 和 <strong>Wairinding 山丘</strong> 之间的震撼。雨季时翠绿盎然，旱季时金黄灿烂的广阔萨瓦纳，会让您觉得自己置身于《天线宝宝》的电影场景中。</p></li><li data-list-item-id=\"ea6af098d038f43396c39013b8374a6fc\"><p style=\"text-align:justify;\"><strong>湖水奇观——丹奥·瓦库里（Waekuri Lake）：</strong> 参观松巴岛最标志性的景点 <strong>丹奥·瓦库里</strong>。这是一个湖水清澈见底、面积广阔的咸淡水湖。</p></li><li data-list-item-id=\"e8ac89688e0657181996f1431b61da9ea\"><p style=\"text-align:justify;\"><strong>传统村落的穿梭时光之旅：</strong> 在 <strong>Praijing 传统村落</strong> 和 <strong>Ratenggaro 村</strong> 发现当地的智慧。亲眼见证数十座标志性的高塔式传统房屋，这些房屋是至今仍保存完好的对祖先尊敬的象征。</p></li><li data-list-item-id=\"e3274ad96c4a959b136db268b4c2f98c5\"><p style=\"text-align:justify;\"><strong>瓦拉基里海滩（Walakiri Beach）的“跳舞树”奇观：</strong> 在瓦拉基里海滩欣赏印度尼西亚最富诗意的日落之一。造型独特的红树林整齐排列，为您提供绝佳的照片背景。</p></li><li data-list-item-id=\"e89a38a4e95e95bf7525c8d3e474854d9\"><p style=\"text-align:justify;\"><strong>静谧的秘境海滩：</strong> 在拥有广阔白沙滩的 <strong>Mananga Aba 海滩（Kita 海滩）</strong> 和充满异国情调的 <strong>Pero 海滩</strong> 寻找真正的宁静。</p></li><li data-list-item-id=\"eebd9006cd620db1c3b58db94dc597aec\"><p style=\"text-align:justify;\"><strong>遗产与文化教育：</strong> 在 <strong>文化之家（Rumah Budaya）</strong> 了解这座岛屿悠久的历史，并前往松巴岛纪念品中心，带走一小块关于这座美丽岛屿的回忆。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"ea965135bc093df43b4b176ae2afdb03a\"><strong>AC Land Transportation</strong></li><li data-list-item-id=\"e0178536552da4e40a5988cf4ca17a3d9\"><strong>Accommodations</strong>: 2 night\'s stay in West Sumba and 1 nights in East Sumba</li><li data-list-item-id=\"e536c0a38f5c431908b2cc3592f1f689c\"><strong>Meals</strong>: Provided according to the tour program</li><li data-list-item-id=\"e6043f7ef8e0029657261c1db1879e2bb\"><strong>Entrance Fees</strong>: Admission tickets for all listed tourist attractions</li><li data-list-item-id=\"ee4a0553f2265ee1a920226aef7cb41f3\"><strong>Mineral Water</strong>: Provided during the tour</li><li data-list-item-id=\"e0d916c1b22db5c5effba25263f9c0602\"><strong>Guide as Driver</strong>: Professional assistance adjusted to the number of guests</li></ul>', '<ul><li data-list-item-id=\"e340c8722506c3dbf3a952e926667a96e\"><strong>Flight Tickets</strong>: Airfare is not included in the package.</li><li data-list-item-id=\"eb8594c6c1579599f49e62aecc69e31c8\"><strong>Guide Tipping</strong>: Gratuities for the guide are not included.</li><li data-list-item-id=\"e8ff52b3dbad2d47a4b19d197f8fb5ae9\"><strong>Travel Insurance</strong>: Insurance coverage is not provided.</li><li data-list-item-id=\"e0a80a1a63fce428ebf833f90c463297c\"><strong>Personal Expenses</strong>: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e54e00207981e7cda3c1d8e62f312cd0c\"><strong>Additional Meals &amp; Beverages</strong>: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"ec5651850b202403a3841a4d987586f76\"><strong>Hotel Facilities</strong>: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"HERITAGE\"]', NULL, 0, NULL, '2026-05-02 09:29:37', '2026-05-29 14:50:51'),
(45, 40, '5 DAYS SUMBA TOUR', 'NUSA TENGGARA TIMUR', '5-days-sumba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tersembunyi Indonesia: 5D4N Magical Sumba Tour Adventure</strong></h2><p style=\"text-align:justify;\">Pernahkah Anda membayangkan melangkah ke dalam dunia yang seolah berhenti berdetak? Selamat datang di <strong>Sumba</strong>, sebuah pulau di mana tradisi megalitik yang megah bertemu dengan bentang alam yang ajaib dan tak tersentuh. Melalui paket eksklusif 5 hari 4 malam ini, kami mengundang Anda untuk menembus batas imajinasi dan menemukan alasan mengapa Sumba wajib ada dalam <i>bucket list</i> perjalanan seumur hidup Anda.</p><h3 style=\"text-align:justify;\"><strong>Kenapa Anda Wajib Merasakan Petualangan Ini?</strong></h3><ul><li data-list-item-id=\"e15dc5a0ffb564fb1f21c6dbaf070c058\"><p style=\"text-align:justify;\"><strong>Menyentuh Awan di Sabana Tanpa Batas:</strong> Rasakan sensasi berdiri di puncak <strong>Bukit Wairinding</strong> dan <strong>Bukit Lendongara</strong>. Anda akan disuguhi permadani rumput luas yang berubah warna dari hijau subur hingga emas kuning yang eksotis sesuai musimnya—persis seperti dalam film fantasi.</p></li><li data-list-item-id=\"e3fe5fecf62e6d6105f9f1406a09bedcd\"><p style=\"text-align:justify;\"><strong>Keajaiban Air Payau Danau Waekuri:</strong> Selami kejernihan kristal <strong>Danau Waekuri</strong>, landmark paling ikonik di Sumba. Danau air payau yang sangat luas ini menawarkan ketenangan yang tidak akan Anda temukan di belahan bumi mana pun.</p></li><li data-list-item-id=\"ebe7e7a539734ab5bc1db7a28a9676de1\"><p style=\"text-align:justify;\"><strong>Perjalanan Menembus Waktu di Kampung Adat:</strong> Kunjungi <strong>Kampung Praijing</strong> dan <strong>Kampung Ratenggaro</strong>, di mana rumah-rumah tradisional beratap menara tinggi berdiri kokoh di pinggir laut sebagai simbol penghormatan leluhur yang masih hidup. Ini bukan sekadar wisata, ini adalah pertemuan budaya yang autentik.</p></li><li data-list-item-id=\"e45f50cca05f8d5e9c967b634fbf71300\"><p style=\"text-align:justify;\"><strong>Keanggunan Alam yang Megah:</strong> Dari gemuruh <strong>Air Terjun Lapopu</strong> yang merupakan air terjun tertinggi di NTT, hingga kolam pirus alami yang dikelilingi tebing di <strong>Air Terjun Waimarang</strong>, setiap detik adalah kemegahan alam murni.</p></li><li data-list-item-id=\"ecbbec7ee9c9b401e1b5db45f7a054c5a\"><p style=\"text-align:justify;\"><strong>Matahari Terbenam Paling Puitis di Dunia:</strong> Di <strong>Pantai Walakiri</strong>, saksikan fenomena pohon bakau \"menari\" yang tersusun rapi di atas pasir putih yang meluas. Siluet pohon-pohon unik ini saat matahari terbenam adalah pemandangan yang akan tersimpan selamanya dalam ingatan (dan galeri foto) Anda.</p></li><li data-list-item-id=\"e3c12a93b3308a8f8ac761633dca0cc71\"><p style=\"text-align:justify;\"><strong>Ketenangan yang Sesungguhnya:</strong> Temukan kedamaian di <strong>Pantai Mananga Aba</strong> yang sunyi dan <strong>Pantai Mandorak</strong> yang eksotis, tempat di mana hanya ada Anda, suara ombak, dan pasir putih yang bersih.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore Indonesia\'s Hidden Paradise: 5D4N Magical Sumba Tour Adventure</strong></h2><p style=\"text-align:justify;\">Have you ever imagined stepping into a world where time seems to stand still? Welcome to <strong>Sumba</strong>, an island where grand megalithic traditions meet a magical, untouched landscape. Through this exclusive 5-day, 4-night package, we invite you to transcend the limits of your imagination and discover why Sumba is a must-have on your lifetime travel bucket list.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Adventure?</strong></h3><ul><li data-list-item-id=\"ed51d8f635c2e8a7f609409e2f1e05b4f\"><p style=\"text-align:justify;\"><strong>Touching the Clouds in Endless Savannas:</strong> Feel the sensation of standing atop <strong>Wairinding Hill</strong> and <strong>Lendongara Hill</strong>. You will be treated to a vast carpet of grass that changes color from lush green to exotic golden yellow according to the season—just like in a fantasy movie.</p></li><li data-list-item-id=\"e357210de76a1142695389ec8ccedc469\"><p style=\"text-align:justify;\"><strong>The Brackish Water Magic of Lake Waekuri:</strong> Dive into the crystal clarity of <strong>Lake Waekuri</strong>, Sumba’s most iconic landmark. This vast brackish water lake offers a tranquility you won\'t find anywhere else on Earth.</p></li><li data-list-item-id=\"eed76d8c5bb8743f434f4118bb01bae05\"><p style=\"text-align:justify;\"><strong>A Journey Through Time in Traditional Villages:</strong> Visit <strong>Praijing Village</strong> and <strong>Ratenggaro Village</strong>, where traditional houses with high towering roofs stand firmly by the sea as a living symbol of ancestral respect. This is not just a tour; it is an authentic cultural encounter.</p></li><li data-list-item-id=\"e33a3091b2b62fdd403a5117c05492312\"><p style=\"text-align:justify;\"><strong>Grand Natural Elegance:</strong> From the thunderous <strong>Lapopu Waterfall</strong>, the highest in NTT, to the natural turquoise pools surrounded by cliffs at <strong>Waimarang Waterfall</strong>, every second is pure natural majesty.</p></li><li data-list-item-id=\"ec6d556830aede253564a774c538e17a0\"><p style=\"text-align:justify;\"><strong>The Most Poetic Sunset in the World:</strong> At <strong>Walakiri Beach</strong>, witness the phenomenon of \"dancing\" mangrove trees neatly arranged on the vast white sand. The silhouettes of these unique trees at sunset are a sight that will stay in your memory (and photo gallery) forever.</p></li><li data-list-item-id=\"e0c8eceed70c8f95169a4b610f7b80750\"><p style=\"text-align:justify;\"><strong>True Serenity:</strong> Find peace at the quiet <strong>Mananga Aba Beach</strong> and the exotic <strong>Mandorak Beach</strong>, where there is only you, the sound of the waves, and clean white sand.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>인도네시아의 숨겨진 낙원 탐험: 4박 5일 마법 같은 숨바 투어 어드벤처</strong></h2><p style=\"text-align:justify;\">시간이 멈춘 듯한 세상으로 발을 들이는 상상을 해보신 적이 있나요? 웅장한 거석 전통과 마법처럼 손상되지 않은 자연경관이 만나는 섬, 숨바(Sumba)에 오신 것을 환영합니다. 이번 단독 4박 5일 패키지를 통해 상상의 한계를 넘어 숨바가 왜 인생 버킷 리스트에 꼭 있어야 하는지 확인해 보세요.</p><h3 style=\"text-align:justify;\"><strong>이 모험을 꼭 경험해야 하는 이유</strong></h3><ul><li data-list-item-id=\"edffd0f86ace60e2d992cd942f061f6d6\"><p style=\"text-align:justify;\"><strong>끝없는 사바나에서 구름에 닿기:</strong> 와이린딩 언덕(Wairinding Hill)과 <strong>렌동가라 언덕(Lendongara Hill)</strong> 정상에 서는 짜릿함을 느껴보세요. 계절에 따라 싱그러운 초록빛에서 이국적인 황금빛으로 변하는 광활한 풀밭은 마치 판타지 영화의 한 장면 같습니다.</p></li><li data-list-item-id=\"eb6f7e976f19262aa373599115ff4c5f7\"><p style=\"text-align:justify;\"><strong>와이쿠리 호수의 신비로운 염수:</strong> 숨바의 가장 상징적인 랜드마크인 와이쿠리 호수(Lake Waekuri)의 투명한 물속으로 뛰어들어 보세요. 이 넓은 염수 호수는 지구상 어디에서도 찾을 수 없는 평온함을 선사합니다.</p></li><li data-list-item-id=\"efa4e014b398464a697beb7d3fdd87dd1\"><p style=\"text-align:justify;\"><strong>전통 마을로의 시간 여행:</strong> 높은 탑 모양의 지붕을 가진 전통 가옥들이 바닷가에 굳건히 서 있는 프라이징 마을(Praijing Village)과 라텡가로 마을(Ratenggaro Village)을 방문해 보세요. 이것은 단순한 관광이 아닌 진정한 문화적 조우입니다.</p></li><li data-list-item-id=\"eb537e8c388f05362d3f72405d887a397\"><p style=\"text-align:justify;\"><strong>웅장한 자연의 우아함:</strong> NTT 주에서 가장 높은 라포푸 폭포(Lapopu Waterfall)의 굉음부터 절벽으로 둘러싸인 와이마랑 폭포(Waimarang Waterfall)의 천연 터쿼이즈 풀까지, 매 순간이 순수한 자연의 위엄입니다.</p></li><li data-list-item-id=\"ebf6723072a0b9f365ca5bbcefeedb067\"><p style=\"text-align:justify;\"><strong>세계에서 가장 시적인 일몰:</strong> 와라키리 해변(Walakiri Beach)에서 넓은 백사장 위에 가지런히 배열된 \"춤추는\" 맹그로브 나무의 현상을 목격하세요. 일몰 때 이 독특한 나무들의 실루엣은 당신의 기억(과 사진첩)에 영원히 남을 풍경입니다.</p></li><li data-list-item-id=\"e75b229bb2d1b9b75813b810838e0d538\"><p style=\"text-align:justify;\"><strong>진정한 평온함:</strong> 고요한 마낭가 아바 해변(Mananga Aba Beach)과 이국적인 만도락 해변(Mandorak Beach)에서 파도 소리와 깨끗한 백사장, 그리고 오직 당신만이 존재하는 평화를 찾아보세요.</p></li></ul>', '<h3 style=\"text-align:justify;\"><strong>探索印尼隐藏的天堂：5天4夜 梦幻松巴岛冒险之旅</strong></h3><p style=\"text-align:justify;\">您是否曾想象过踏入一个时间仿佛静止的世界？欢迎来到<strong>松巴岛 (Sumba)</strong>，这是一个宏伟的巨石传统与神奇、未受破坏的自然景观交汇的岛屿。通过这个专属的5天4夜行程，我们邀请您超越想象的边界，发现为什么松巴岛是您人生必去清单上的首选。</p><p style=\"text-align:justify;\"><strong>为什么您必须体验这次冒险？</strong></p><ul><li data-list-item-id=\"eaed94adc408faff4657136d08de9b11e\"><p style=\"text-align:justify;\"><strong>在无尽的萨瓦纳触碰云端：</strong> 体验站在 <strong>Wairinding 丘陵</strong> 和 <strong>Lendongara 丘陵</strong> 顶峰的感觉。您将欣赏到如同奇幻电影般广阔的草地，颜色随季节从翠绿变为充满异域风情的金黄。</p></li><li data-list-item-id=\"e13d40fef4961c7cd38f3403650788cbe\"><p style=\"text-align:justify;\"><strong>Waekuri 湖的神奇咸水：</strong> 潜入松巴岛最标志性的地标——<strong>Waekuri 湖</strong>。这里晶莹剔透。这座广阔的咸水湖提供了一种在地球其他地方都无法找到的宁静。</p></li><li data-list-item-id=\"e8ffab196f10119fe4a846c2f8d650360\"><p style=\"text-align:justify;\"><strong>传统村落的时空穿梭：</strong> 访问 <strong>Praijing 村</strong> 和 <strong>Ratenggaro 村</strong>，在那里，拥有高耸屋顶的传统房屋坚定地屹立在海边，作为对祖先崇敬的活生生象征。这不仅是一次旅行，更是一场真实的文化邂逅。</p></li><li data-list-item-id=\"e05faf03b8b0afbfe22565e2996d93766\"><p style=\"text-align:justify;\"><strong>壮丽的自然优雅：</strong> 从东努沙登加拉省（NTT）最高的 <strong>Lapopu 瀑布</strong> 的轰鸣声，到被悬崖环绕的 <strong>Waimarang 瀑布</strong> 的天然绿松石水池，每一秒都是纯粹的自然奇迹。</p></li><li data-list-item-id=\"ecc9621c4d9f632056c89dde9fa0b06a8\"><p style=\"text-align:justify;\"><strong>世界上最诗意的日落：</strong> 在 <strong>Walakiri 海滩</strong>，见证排列在广阔白沙滩上的红树林“跳舞”的奇观。日落时分，这些独特树木的剪影将永远留在您的记忆（和相册）中。</p></li><li data-list-item-id=\"e20a0dacb8172cea4b1576b3ee1007d57\"><p style=\"text-align:justify;\"><strong>真正的宁静：</strong> 在安静的 <strong>Mananga Aba 海滩</strong> 和充满异国情调的 <strong>Mandorak 海滩</strong> 寻找和平，那里只有您、浪涛声和洁白的沙滩。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"ea965135bc093df43b4b176ae2afdb03a\"><strong>AC Land Transportation</strong></li><li data-list-item-id=\"e0178536552da4e40a5988cf4ca17a3d9\"><strong>Accommodations</strong>: 2 night\'s stay in West Sumba and 2 nights in East Sumba</li><li data-list-item-id=\"e536c0a38f5c431908b2cc3592f1f689c\"><strong>Meals</strong>: Provided according to the tour program</li><li data-list-item-id=\"e6043f7ef8e0029657261c1db1879e2bb\"><strong>Entrance Fees</strong>: Admission tickets for all listed tourist attractions</li><li data-list-item-id=\"ee4a0553f2265ee1a920226aef7cb41f3\"><strong>Mineral Water</strong>: Provided during the tour</li><li data-list-item-id=\"e0d916c1b22db5c5effba25263f9c0602\"><strong>Guide as Driver</strong>: Professional assistance adjusted to the number of guests</li></ul>', '<ul><li data-list-item-id=\"e340c8722506c3dbf3a952e926667a96e\"><strong>Flight Tickets</strong>: Airfare is not included in the package.</li><li data-list-item-id=\"eb8594c6c1579599f49e62aecc69e31c8\"><strong>Guide Tipping</strong>: Gratuities for the guide are not included.</li><li data-list-item-id=\"e8ff52b3dbad2d47a4b19d197f8fb5ae9\"><strong>Travel Insurance</strong>: Insurance coverage is not provided.</li><li data-list-item-id=\"e0a80a1a63fce428ebf833f90c463297c\"><strong>Personal Expenses</strong>: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e54e00207981e7cda3c1d8e62f312cd0c\"><strong>Additional Meals &amp; Beverages</strong>: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"ec5651850b202403a3841a4d987586f76\"><strong>Hotel Facilities</strong>: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"Beach\",\"HERITAGE\"]', NULL, 1, 'popular', '2026-05-02 13:50:28', '2026-05-29 14:50:05'),
(46, 40, '6 DAYS SUMBA TOUR', 'Nusa Tenggara Timur', '6-days-sumba-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Magisnya Pulau Sumba: Petualangan Eksotis 6 Hari 5 Malam</strong></h2><p style=\"text-align:justify;\">Apakah Anda mendambakan pelarian dari hiruk-pikuk kota ke sebuah tempat di mana waktu seakan berhenti? <strong>Paket Tour 6D5N Sumba</strong> adalah jawaban untuk jiwa petualang Anda. Sumba bukan sekadar destinasi; ia adalah perpaduan sempurna antara budaya yang tak lekang oleh waktu, bukit-bukit hijau yang ikonik, dan keajaiban air yang tidak akan Anda temukan di tempat lain di dunia.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Mencoba Pengalaman Ini?</strong></h3><p style=\"text-align:justify;\"><strong>1. Menembus Lorong Waktu di Kampung Adat</strong> Sumba adalah salah satu dari sedikit tempat di mana tradisi megalitikum masih hidup. Anda akan diajak mengunjungi <strong>Kampung Praijing</strong> dengan 38 rumah tradisionalnya yang ikonik serta <strong>Kampung Ratenggaro</strong> yang memiliki menara rumah adat menjulang tinggi, memberikan pengalaman budaya yang mendalam dan magis.</p><p style=\"text-align:justify;\"><strong>2. Lanskap Perbukitan \"Teletubbies\" yang Menakjubkan</strong> Bayangkan berdiri di hamparan padang savana yang luas sejauh mata memandang. Di <strong>Bukit Lendongara</strong>, <strong>Bukit Wairinding</strong>, dan <strong>Bukit Tanarara</strong>, Anda akan disuguhi pemandangan perbukitan hijau (saat musim hujan) atau emas kecokelatan (saat musim kemarau) yang sangat fotogenik dan menenangkan jiwa.</p><p style=\"text-align:justify;\"><strong>3. Keajaiban Air: Dari Danau Air Payau hingga Air Terjun Tertinggi</strong> Nikmati kejernihan <strong>Danau Waekuri</strong>, sebuah danau air payau yang menjadi landmark Sumba. Tak hanya itu, Anda akan menyaksikan kemegahan <strong>Air Terjun Lapopu</strong>, air terjun tertinggi di NTT, serta keunikan <strong>Waikelo Sawah</strong>, kolam air jernih yang memancar dari mulut gua alami.</p><p style=\"text-align:justify;\"><strong>4. Garis Pantai yang Sunyi dan Penuh Karakter</strong> Mulai dari ketenangan <strong>Pantai Mananga Aba</strong> yang berpasir putih luas hingga keunikan <strong>Pantai Walakiri</strong> dengan \"pohon menari\" (bakau) yang tersusun rapi di kala senja, setiap pantai di Sumba menawarkan karakter unik yang tak terlupakan.</p>', '<h2 style=\"text-align:justify;\"><strong>Discover the Magic of Sumba: An Exotic 6-Day 5-Night Adventure</strong></h2><p style=\"text-align:justify;\">Are you longing for an escape where time stands still? The <strong>6D5N Sumba Tour</strong> is the answer for your adventurous soul. Sumba is not just a destination; it is a perfect blend of timeless culture, iconic rolling hills, and aquatic wonders found nowhere else on earth.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This:</strong></h3><ul><li data-list-item-id=\"e43c16945f14ab41debd447e0970eb173\"><p style=\"text-align:justify;\"><strong>A Journey Through Time</strong>: Visit <strong>Ratenggaro</strong> and <strong>Praijing Cultural Villages</strong>, where ancient Megalithic traditions and iconic high-roofed houses still stand tall.</p></li><li data-list-item-id=\"e5c5aa3933771326b03ae09e30daa422d\"><p style=\"text-align:justify;\"><strong>The \"Teletubbies\" Hills</strong>: Stand atop <strong>Wairinding</strong>, <strong>Lendongara</strong>, and <strong>Tanarara Hills</strong> to witness vast, golden or green savannahs stretching as far as the eye can see.</p></li><li data-list-item-id=\"e1e5fcd100fdd219ec49e7616be4e83eb\"><p style=\"text-align:justify;\"><strong>Aquatic Marvels</strong>: Swim in the crystal-clear turquoise waters of <strong>Weekuri Lagoon</strong> and witness the majesty of <strong>Lapopu Waterfall</strong>, the tallest in East Nusa Tenggara.</p></li><li data-list-item-id=\"ec869788af32f81fcb505e7049999e0d6\"><p style=\"text-align:justify;\"><strong>Dreamy Coastlines</strong>: From the pristine white sands of <strong>Mananga Aba</strong> to the famous \"dancing trees\" at <strong>Walakiri Beach</strong> during sunset.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>숨바섬의 마법을 발견하세요: 6박 5일간의 이국적인 모험</strong></h2><p style=\"text-align:justify;\">시간이 멈춘 듯한 곳으로의 탈출을 꿈꾸시나요? <strong>6D5N 숨바 투어</strong>는 모험을 즐기는 당신을 위한 최고의 선택입니다. 숨바는 단순한 여행지가 아닙니다. 시대를 초월한 문화, 상징적인 언덕, 그리고 지구상 어디에서도 볼 수 없는 신비로운 물의 경이로움이 완벽하게 어우러진 곳입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e9d79ea708fe4f699135bc380c99a1092\"><p style=\"text-align:justify;\"><strong>시간 여행을 떠나는 전통 마을</strong>: 거대한 돌무덤과 높은 지붕의 전통 가옥이 보존된 **라텡가로(Ratenggaro)**와 <strong>프라이징(Praijing)</strong> 마을에서 숨바의 살아있는 역사를 만날 수 있습니다.</p></li><li data-list-item-id=\"e8475b0b9e6dd5297208baa5850dcb772\"><p style=\"text-align:justify;\"><strong>\"텔레토비\" 언덕의 장관</strong>: <strong>와이린딩(Wairinding)</strong>, <strong>렌동아라(Lendongara)</strong>, <strong>타나라라(Tanarara)</strong> 언덕 위에서 끝없이 펼쳐지는 황금빛 또는 초록빛 사바나 초원을 감상하세요.</p></li><li data-list-item-id=\"e5688299a34bbd14824bfd997de1a1386\"><p style=\"text-align:justify;\"><strong>신비로운 물의 세계</strong>: 숨바의 랜드마크인 에메랄드빛 <strong>웨쿠리(Weekuri) 호수</strong>와 NTT 주에서 가장 높은 <strong>라포푸(Lapopu) 폭포</strong>의 웅장함을 직접 경험하세요.</p></li><li data-list-item-id=\"e57c8534c4b82b221b6cb9bb720ddd44d\"><p style=\"text-align:justify;\"><strong>환상적인 해변</strong>: **마낭가 아바(Mananga Aba)**의 고요한 백사장부터 일몰 때 \"춤추는 나무\"로 유명한 <strong>왈라키리(Walakiri)</strong> 해변까지, 잊지 못할 풍경을 선사합니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索松巴岛的魔力：6天5夜异国情调冒险之旅</strong></h2><p style=\"text-align:justify;\">您是否渴望逃离尘嚣，去往一个时光凝固的地方？<strong>6天5夜松巴岛之旅 (6D5N Sumba Tour)</strong> 是为您冒险之魂量身打造的答案。松巴岛不仅仅是一个目的地，它完美融合了永恒的传统文化、标志性的连绵山丘以及举世无双的水域奇观。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须尝试：</strong></h3><ul><li data-list-item-id=\"e4b5718bab6dcccea3113756abd933d38\"><p style=\"text-align:justify;\"><strong>穿梭时空的古村落</strong>: 访问 <strong>Ratenggaro</strong> 和 <strong>Praijing</strong> 传统村落，感受巨石文化与标志性高耸屋顶建筑的神秘魅力。</p></li><li data-list-item-id=\"e6dc8a10cd6d8507836950e97dad031ac\"><p style=\"text-align:justify;\"><strong>“天线宝宝”山丘</strong>: 登上 <strong>Wairinding</strong>、<strong>Lendongara</strong> 和 <strong>Tanarara</strong> 山丘，俯瞰如画般的广阔草原，无论是旱季的金黄还是雨季的翠绿都令人沉醉。</p></li><li data-list-item-id=\"e17619943af8bbe087ca25d66d9f5b390\"><p style=\"text-align:justify;\"><strong>神奇的水域奇观</strong>: 在晶莹剔透的 <strong>Weekuri 咸水湖</strong>中畅游，并见证东努沙登加拉省最高的 <strong>Lapopu 瀑布</strong> 的壮丽。</p></li><li data-list-item-id=\"e3eb62c35bf60528663cf51f28d11ba8a\"><p style=\"text-align:justify;\"><strong>充满诗意的海岸线</strong>: 从宁静纯净的 <strong>Mananga Aba</strong> 白沙滩，到夕阳下以“跳舞树”闻名的 <strong>Walakiri 海滩</strong>，每一处都是摄影天堂。</p></li></ul>', 0.00, NULL, 6, 5, NULL, NULL, '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"ea965135bc093df43b4b176ae2afdb03a\"><strong>AC Land Transportation</strong></li><li data-list-item-id=\"e0178536552da4e40a5988cf4ca17a3d9\"><strong>Accommodations</strong>: 3 night\'s stay in West Sumba and 2 nights in East Sumba</li><li data-list-item-id=\"e536c0a38f5c431908b2cc3592f1f689c\"><strong>Meals</strong>: Provided according to the tour program</li><li data-list-item-id=\"e6043f7ef8e0029657261c1db1879e2bb\"><strong>Entrance Fees</strong>: Admission tickets for all listed tourist attractions</li><li data-list-item-id=\"ee4a0553f2265ee1a920226aef7cb41f3\"><strong>Mineral Water</strong>: Provided during the tour</li><li data-list-item-id=\"e0d916c1b22db5c5effba25263f9c0602\"><strong>Guide as Driver</strong>: Professional assistance adjusted to the number of guests</li></ul>', '<ul><li data-list-item-id=\"e340c8722506c3dbf3a952e926667a96e\"><strong>Flight Tickets</strong>: Airfare is not included in the package.</li><li data-list-item-id=\"eb8594c6c1579599f49e62aecc69e31c8\"><strong>Guide Tipping</strong>: Gratuities for the guide are not included.</li><li data-list-item-id=\"e8ff52b3dbad2d47a4b19d197f8fb5ae9\"><strong>Travel Insurance</strong>: Insurance coverage is not provided.</li><li data-list-item-id=\"e0a80a1a63fce428ebf833f90c463297c\"><strong>Personal Expenses</strong>: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e54e00207981e7cda3c1d8e62f312cd0c\"><strong>Additional Meals &amp; Beverages</strong>: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"ec5651850b202403a3841a4d987586f76\"><strong>Hotel Facilities</strong>: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"Heritage\"]', NULL, 0, NULL, '2026-05-03 01:18:28', '2026-05-29 14:48:41'),
(47, 39, '3 DAYS DERAWAN - MARATUA ISLAND', 'EAST KALIMANTAN', '3-days-derawan-maratua-island', '<h2 style=\"text-align:justify;\"><strong>Menjelajahi Simfoni Biru di Kepulauan Derawan &amp; Maratua</strong></h2><p style=\"text-align:justify;\">Lepaskan diri dari rutinitas dan masuki dunia di mana air laut sejernih kristal bertemu dengan kehidupan bawah laut yang spektakuler. Paket perjalanan ini dirancang untuk membawa Anda langsung ke jantung segitiga karang dunia, tempat setiap pulaunya menyimpan rahasia alam yang memukau.</p><h3 style=\"text-align:justify;\"><strong>Daya Tarik Utama:</strong></h3><ul><li data-list-item-id=\"ed591524fba9017e9014453fda21a92d9\"><p style=\"text-align:justify;\"><strong>Danau Kakaban:</strong> Berenang di dalam danau purba yang dihuni oleh empat jenis ubur-ubur tanpa sengat, sebuah fenomena langka yang hanya ada di dua tempat di dunia.</p></li><li data-list-item-id=\"e37f63196af9993feb0c3870f14f6b458\"><p style=\"text-align:justify;\"><strong>Maratua &amp; Goa Halo Tabung:</strong> Temukan kemewahan alam di Maratua dan selami kejernihan kolam alami di dalam Goa Halo Tabung yang memiliki pantulan warna biru safir yang magis.</p></li><li data-list-item-id=\"ef7843ff45106dea9e073a8909313b11a\"><p style=\"text-align:justify;\"><strong>Kehe Daing:</strong> Jelajahi laguna tersembunyi dengan pasir putih halus yang hanya muncul saat air surut, dikelilingi tebing karang yang eksotis.</p></li><li data-list-item-id=\"e1cea7917297f548e651c311e6f8f4752\"><p style=\"text-align:justify;\"><strong>Konservasi Sangalaki:</strong> Kunjungi habitat asli Pari Manta dan lihat langsung upaya pelestarian tukik (anak penyu) di pulau yang asri ini.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Exploring the Blue Symphony: Derawan &amp; Maratua Archipelago</strong></h2><p style=\"text-align:justify;\">Escape the routine and enter a world where crystal-clear waters meet spectacular marine life. This journey is designed to take you directly to the heart of the world\'s Coral Triangle, where every island hides breathtaking natural secrets.</p><h3 style=\"text-align:justify;\"><strong>Top Attractions:</strong></h3><ul><li data-list-item-id=\"ede547c0448f60d3202ceae7e537d34d7\"><p style=\"text-align:justify;\"><strong>Kakaban Lake:</strong> Swim inside an ancient lake inhabited by four species of stingless jellyfish, a rare phenomenon found in only two places in the world.</p></li><li data-list-item-id=\"e772aa9fac9749f58c06f3b5565f5ca26\"><p style=\"text-align:justify;\"><strong>Maratua &amp; Goa Halo Tabung:</strong> Discover the natural luxury of Maratua and dive into the clarity of the natural pool inside Goa Halo Tabung, which features a magical sapphire blue reflection.</p></li><li data-list-item-id=\"e63abbd522d01f51b2e6beb2cfdf26dbc\"><p style=\"text-align:justify;\"><strong>Kehe Daing:</strong> Explore a hidden lagoon with fine white sand that only appears at low tide, surrounded by exotic coral cliffs.</p></li><li data-list-item-id=\"e543aefa88414e1bd77c11710bd95b978\"><p style=\"text-align:justify;\"><strong>Sangalaki Conservation:</strong> Visit the natural habitat of Manta Rays and witness firsthand the conservation efforts for sea turtle hatchlings on this pristine island.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>푸른 교향곡 탐험: 드라완 &amp; 마라투아 제도</strong></h2><p style=\"text-align:justify;\">일상에서 벗어나 투명한 바닷물과 환상적인 해양 생물이 만나는 세상으로 초대합니다. 이 여정은 모든 섬이 숨막히는 자연의 비밀을 간직하고 있는 세계 산호 삼각지대의 심장부로 여러분을 안내합니다.</p><h3 style=\"text-align:justify;\"><strong>주요 명소:</strong></h3><ul><li data-list-item-id=\"ec6bd1e494284e9b63963cdeb310959d1\"><p style=\"text-align:justify;\"><strong>카카반 호수:</strong> 전 세계에서 단 두 곳에서만 볼 수 있는 희귀한 현상으로, 독이 없는 네 종류의 해파리가 서식하는 고대 호수에서 수영을 즐겨보세요.</p></li><li data-list-item-id=\"e544abedf6fca08197b572f185236fb4e\"><p style=\"text-align:justify;\"><strong>마라투아 &amp; 고아 할로 타붕:</strong> 마라투아의 자연적인 사치를 경험하고, 신비로운 사파이어 블루 빛을 발하는 고아 할로 타붕 천연 동굴 수영장의 맑은 물에 빠져보세요.</p></li><li data-list-item-id=\"effd3d126b98c61b6d5028b026342ea69\"><p style=\"text-align:justify;\"><strong>케헤 다잉:</strong> 이국적인 산호 절벽으로 둘러싸인, 조수 간만의 차로 인해 나타나는 고운 백사장의 숨겨진 석호를 탐험해보세요.</p></li><li data-list-item-id=\"e6e8bd88bab454901a8560a792be96835\"><p style=\"text-align:justify;\"><strong>상갈라키 보존지구:</strong> 만타가오리의 자연 서식지를 방문하고 이 청정 섬에서 아기 거북이를 보호하기 위한 보존 노력을 직접 확인해보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>蓝色交响曲之旅：德拉旺与马拉图亚群岛</strong></h2><p style=\"text-align:justify;\">摆脱日常琐事，步入清澈海水与壮丽海洋生物交汇的世界。这段旅程旨在带您直达世界珊瑚三角区的核心，那里的每一座岛屿都隐藏着令人叹为观止的自然奥秘。</p><h3 style=\"text-align:justify;\"><strong>核心景点：</strong></h3><ul><li data-list-item-id=\"eea4c966336d66cee08d1094aa45f93e8\"><p style=\"text-align:justify;\"><strong>卡卡班湖 (Kakaban Lake) ：</strong> 在古老的湖泊中与四种无毒水母一同畅游。这是全球仅有的两处奇观之一。</p></li><li data-list-item-id=\"e00eb1bee5201bc16a29eda53a1826bfa\"><p style=\"text-align:justify;\"><strong>马拉图亚与哈洛塔崩洞穴 (Maratua &amp; Goa Halo Tabung)：</strong> 领略马拉图亚的自然奢华，潜入哈洛塔崩洞穴清澈的天然池水中，感受那如蓝宝石般迷人的倒影。</p></li><li data-list-item-id=\"ee629ecd33eb494533befc0118b7c673d\"><p style=\"text-align:justify;\"><strong>克赫达英 (Kehe Daing)：</strong> 探索被异域珊瑚礁环绕的神秘潟湖，欣赏仅在落潮时出现的细腻白沙滩。</p></li><li data-list-item-id=\"e247ff6ca1a8e968da25479a0fc383660\"><p style=\"text-align:justify;\"><strong>圣加拉奇保护区 (Sangalaki Conservation) ：</strong> 探访曼塔鳐鱼（Manta Ray）的自然栖息地，并在这座纯净的岛屿上亲眼见证海龟宝宝的保育工作。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"e01211eabc4cefce9a5f01ff5d2bbef1f\">Airport Transfer at Kalimarau Tanjung Redeb – Berau (in Out)</li><li data-list-item-id=\"ef093e9b39c8d2494d7fbf8d11cb8cc7a\">Private Car Berau to Tanjung Batu Port (Return)</li><li data-list-item-id=\"e201c9386562e3f0104a5f2e894b55213\">Private Speedboat for Island Hopping (Based on the numbers of participant)</li><li data-list-item-id=\"efc831f7b96f59373e69c04a767bbe001\">Insurance Sea Travel</li><li data-list-item-id=\"e350a2baf7163dbdaa625f3cab57df92d\">Island Hopping According to the Tour program</li><li data-list-item-id=\"e4d9fdfb6ea90fbf9e4bdd52e038d4c5f\">Entrance Fee Island</li><li data-list-item-id=\"e485bcbdfb650bd4100ac9ca632f40ef9\">Accommodation 2 nights at Hotel Base on your choice (Twin / Triple Share)</li><li data-list-item-id=\"e536c0a38f5c431908b2cc3592f1f689c\">Meals provided according to the tour program</li><li data-list-item-id=\"e468df7b6087c8a87f311c761686f41d7\">Rental Snorkeling Gear (Mask + Snorkel)</li><li data-list-item-id=\"ebcbf684ef269349ec781b252e211fac1\">Photo Underwater (Transfer File)</li><li data-list-item-id=\"eab110a5f9674e01e92d538f93a16fad1\">Professional Local Guide</li></ul>', '<ul><li data-list-item-id=\"e340c8722506c3dbf3a952e926667a96e\">Flight Tickets: Airfare is not included in the package.</li><li data-list-item-id=\"eb8594c6c1579599f49e62aecc69e31c8\">Guide Tipping: Gratuities for the guide are not included.</li><li data-list-item-id=\"e8ff52b3dbad2d47a4b19d197f8fb5ae9\">Travel Insurance: Insurance coverage is not provided.</li><li data-list-item-id=\"e0a80a1a63fce428ebf833f90c463297c\">Personal Expenses: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e54e00207981e7cda3c1d8e62f312cd0c\">Additional Meals &amp; Beverages: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"ec5651850b202403a3841a4d987586f76\">Hotel Facilities: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"Beach\",\"WILDLIFE\"]', NULL, 0, NULL, '2026-05-04 12:03:02', '2026-05-29 14:37:20');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(48, 39, '4 DAYS DERAWAN - MARATUA ISLAND', 'EAST KALIMANTAN', '4-days-derawan-maratua-island', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tersembunyi Kalimantan: Petualangan Ajaib di Kepulauan Derawan!</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk petualangan bahari tak terlupakan selama 4 hari 3 malam di salah satu permata tersembunyi Indonesia. Paket tour ini dirancang khusus bagi Anda yang merindukan kejernihan air laut kristal, fenomena alam langka, dan interaksi jarak dekat dengan satwa megah di habitat aslinya.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e3cbb62e6472ac566b1482f8ce7fd871f\"><p style=\"text-align:justify;\"><strong>Momen Langka Bersama Hiu Paus:</strong> Rasakan sensasi mendebarkan dan magis berinteraksi langsung dengan <i>Whale Shark</i> (Hiu Paus) yang megah di pagi hari.</p></li><li data-list-item-id=\"eff2d00c37ade390154fa359ce9c32fac\"><p style=\"text-align:justify;\"><strong>Danau Dua Rasa Labuan Cermin:</strong> Temukan keajaiban Labuan Cermin, danau dengan air yang begitu jernih hingga tampak seperti kaca, di mana air tawar dan air asin bertemu dengan sempurna.</p></li><li data-list-item-id=\"e2a9e1becefec702db1cb5570f080573d\"><p style=\"text-align:justify;\"><strong>Berenang Bersama Ubur-ubur Tanpa Sengat:</strong> Rasakan pengalaman unik berenang di tengah ribuan ubur-ubur yang ramah dan tidak menyengat di Danau Kakaban.</p></li><li data-list-item-id=\"e61116938cd513acfc359794bd31783b4\"><p style=\"text-align:justify;\"><strong>Pesona Maladewa-nya Indonesia:</strong> Nikmati keindahan Pulau Maratua dengan gradasi air laut biru toska yang menawan, serta jelajahi laguna tersembunyi di Kehe Daing dan keunikan kolam alami Goa Halo Tabung.</p></li><li data-list-item-id=\"e50c9050428f72e1ea63f84b6c61175ff\"><p style=\"text-align:justify;\"><strong>Interaksi Satwa di Sangalaki:</strong> Kunjungi Pulau Sangalaki yang mempesona, tempat favorit bagi penyu dan habitat alami bagi pari manta.</p></li><li data-list-item-id=\"e7a4e5bc0b01f78924e406c53e7996a81\"><p style=\"text-align:justify;\"><strong>Relaksasi di Gusung Pasir:</strong> Berjalan di atas hamparan pasir putih lembut yang muncul secara ajaib di tengah laut biru yang jernih.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover Kalimantan’s Hidden Paradise: A Magical Adventure in the Derawan Archipelago!</strong></h2><p style=\"text-align:justify;\">Prepare yourself for an unforgettable 4-day, 3-night maritime adventure in one of Indonesia\'s hidden gems. This tour is specifically designed for those who crave crystal-clear waters, rare natural phenomena, and close encounters with majestic creatures in their natural habitat.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Journey:</strong></h3><ul><li data-list-item-id=\"e222161593b65c9015ba2a52235ec2596\"><p style=\"text-align:justify;\"><strong>Majestic Whale Shark Encounters:</strong> Experience the thrill of interacting directly with magnificent Whale Sharks in the early morning.</p></li><li data-list-item-id=\"e2faa9caa3b7d356c06cfbb09d1812009\"><p style=\"text-align:justify;\"><strong>The Mirrored Waters of Labuan Cermin:</strong> Discover the magic of Labuan Cermin, a unique lake with water so clear it looks like a mirror, were fresh and saltwater meet perfectly.</p></li><li data-list-item-id=\"e5f6523ef5056ea9befdc8f64a02e404b\"><p style=\"text-align:justify;\"><strong>Swim with Stingless Jellyfish:</strong> Enjoy the surreal experience of swimming among thousands of friendly, non-stinging jellyfish at Kakaban Lake.</p></li><li data-list-item-id=\"eeaf5c9c81cf1e25427ea6817bef06d2a\"><p style=\"text-align:justify;\"><strong>The Maldives of Indonesia:</strong> Experience the stunning Maratua Island with its mesmerizing turquoise waters, explore the hidden Kehe Daing lagoon, and the unique sapphire pool of Goa Halo Tabung.</p></li><li data-list-item-id=\"e2fa03cb887bf3a5e086535ed8c81f66b\"><p style=\"text-align:justify;\"><strong>Sangalaki Wildlife Sanctuary:</strong> Visit the enchanting Sangalaki Island, a favorite nesting ground for sea turtles and a natural habitat for Manta Rays.</p></li><li data-list-item-id=\"eea79aa3ae47ca5f0f6a50ef6fb40fc9c\"><p style=\"text-align:justify;\"><strong>Relax at Gusung Pasir:</strong> Walk along a stretch of soft white sand that magically emerges in the middle of the crystal-clear blue sea.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>칼리만탄의 숨겨진 낙원 발견: 드라완 제도의 마법 같은 모험!</strong></h2><p style=\"text-align:justify;\">인도네시아의 숨겨진 보석과도 같은 드라완 제도에서 3박 4일간의 잊지 못할 해양 모험을 준비하세요. 투명한 바다, 희귀한 자연 현상, 그리고 거대한 해양 생물과의 만남을 꿈꾸는 분들을 위한 최고의 여행입니다.</p><h3 style=\"text-align:justify;\"><strong>이 여행을 꼭 떠나야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e59f5893d20c174a6229ca645104c3939\"><p style=\"text-align:justify;\"><strong>고래상어와의 만남:</strong> 이른 아침, 거대하고 경이로운 고래상어와 직접 교감하는 짜릿한 순간을 경험하세요.</p></li><li data-list-item-id=\"e061745b2232e66a10b34f495ad0d3c91\"><p style=\"text-align:justify;\"><strong>거울 호수, 라부안 체르민:</strong> 민물과 바닷물이 만나 거울처럼 맑은 물빛을 자랑하는 라부안 체르민 호수의 마법을 발견해 보세요.</p></li><li data-list-item-id=\"ea131e09e1040292cb0a8ce007b5580fc\"><p style=\"text-align:justify;\"><strong>독 없는 해파리와의 수영:</strong> 카카반 호수에서 수천 마리의 독 없는 해파리들과 함께 유영하는 특별한 경험을 즐겨보세요.</p></li><li data-list-item-id=\"e6cfac2e279d61324e64e089f9110fa6d\"><p style=\"text-align:justify;\"><strong>인도네시아의 몰디브:</strong> 에메랄드빛 바다가 펼쳐진 마라투아 섬, 신비로운 케헤 다잉 석호, 그리고 고아 할로 타붕의 천연 동굴 수영장을 탐험하세요.</p></li><li data-list-item-id=\"e71a2fa7169363bcf0e6f44fb01fc8397\"><p style=\"text-align:justify;\"><strong>상갈라키 야생동물 보호구역:</strong> 거북이들의 산란지이자 만타가오리의 서식지인 아름다운 상갈라키 섬을 방문해 보세요.</p></li><li data-list-item-id=\"e1828542342e248c04cf4a70466f55f39\"><p style=\"text-align:justify;\"><strong>구숭 파시르의 여유:</strong> 투명한 바다 한가운데 마법처럼 나타나는 하얀 모래사장 위를 거닐어 보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索加里曼丹的隐世天堂：德拉旺群岛的奇幻冒险！</strong></h2><p style=\"text-align:justify;\">准备好在印度尼西亚的隐世瑰宝——德拉旺群岛，开启一段难忘的四天三夜海洋之旅。这次旅行专为向往清澈海水、罕见自然奇观以及与海洋巨兽近距离接触的您而设计。</p><h3 style=\"text-align:justify;\"><strong>为什么您不能错过这段旅程：</strong></h3><ul><li data-list-item-id=\"eba7e074a1fb87296316d5f99511d25ff\"><p style=\"text-align:justify;\"><strong>与鲸鲨神圣邂逅：</strong> 体验清晨在自然栖息地与宏伟鲸鲨近距离互动的震撼瞬间。</p></li><li data-list-item-id=\"e2d81deb8487ea76fb86611339f31081c\"><p style=\"text-align:justify;\"><strong>如镜面般的镜湖（Labuan Cermin）：</strong> 探索神奇的镜湖，湖水清澈得宛如明镜，在这里，淡水与咸水完美交汇。</p></li><li data-list-item-id=\"edd2e236774f266c36e24be93760e766f\"><p style=\"text-align:justify;\"><strong>与无毒水母共舞：</strong> 在卡卡班湖享受与数以千计友好、无毒水母一同畅游的超现实体验。</p></li><li data-list-item-id=\"e1a13219d20a4116e82c4e9b4a293df42\"><p style=\"text-align:justify;\"><strong>印度尼西亚的小马尔代夫：</strong> 领略马拉图亚岛迷人的蓝宝石色海水，探索神秘的克赫达英（Kehe Daing）潟湖及哈洛塔崩（Goa Halo Tabung）天然蓝洞。</p></li><li data-list-item-id=\"e9ef07a6e518c5b2f9804c91bdeeb761d\"><p style=\"text-align:justify;\"><strong>圣加拉奇野生动物保护区：</strong> 探访迷人的圣加拉奇岛，这里是海龟的理想家园，也是曼塔鳐鱼（Manta Ray）的自然栖息地。</p></li><li data-list-item-id=\"e89954658b9936e49b93be5dfc280a2c0\"><p style=\"text-align:justify;\"><strong>白沙滩（Gusung Pasir）漫步：</strong> 漫步在晶莹剔透的海中央，感受那段随潮汐出没、如梦似幻的洁白细沙滩。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e01211eabc4cefce9a5f01ff5d2bbef1f\">Airport Transfer at Kalimarau Tanjung Redeb – Berau (in Out)</li><li data-list-item-id=\"ef093e9b39c8d2494d7fbf8d11cb8cc7a\">Private Car Berau to Tanjung Batu Port (Return)</li><li data-list-item-id=\"e201c9386562e3f0104a5f2e894b55213\">Private Speedboat for Island Hopping (Based on the numbers of participant)</li><li data-list-item-id=\"efc831f7b96f59373e69c04a767bbe001\">Insurance Sea Travel</li><li data-list-item-id=\"e350a2baf7163dbdaa625f3cab57df92d\">Island Hopping According to the Tour program</li><li data-list-item-id=\"e4d9fdfb6ea90fbf9e4bdd52e038d4c5f\">Entrance Fee Island</li><li data-list-item-id=\"e485bcbdfb650bd4100ac9ca632f40ef9\">Accommodation 3 nights at Hotel Base on your choice (Twin / Triple Share)</li><li data-list-item-id=\"e536c0a38f5c431908b2cc3592f1f689c\">Meals provided according to the tour program</li><li data-list-item-id=\"e468df7b6087c8a87f311c761686f41d7\">Rental Snorkeling Gear (Mask + Snorkel)</li><li data-list-item-id=\"ebcbf684ef269349ec781b252e211fac1\">Photo Underwater (Transfer File)</li><li data-list-item-id=\"eab110a5f9674e01e92d538f93a16fad1\">Professional Local Guide</li></ul>', '<ul><li data-list-item-id=\"e340c8722506c3dbf3a952e926667a96e\">Flight Tickets: Airfare is not included in the package.</li><li data-list-item-id=\"eb8594c6c1579599f49e62aecc69e31c8\">Guide Tipping: Gratuities for the guide are not included.</li><li data-list-item-id=\"e8ff52b3dbad2d47a4b19d197f8fb5ae9\">Travel Insurance: Insurance coverage is not provided.</li><li data-list-item-id=\"e0a80a1a63fce428ebf833f90c463297c\">Personal Expenses: Any costs incurred outside of the tour program.</li><li data-list-item-id=\"e54e00207981e7cda3c1d8e62f312cd0c\">Additional Meals &amp; Beverages: Any food or drinks ordered beyond the provided menu.</li><li data-list-item-id=\"ec5651850b202403a3841a4d987586f76\">Hotel Facilities: Paid services such as laundry, telephone usage, and other surcharges not covered by the package.</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"Beach\",\"WILDLIFE\"]', NULL, 0, NULL, '2026-05-04 12:14:17', '2026-06-01 15:23:37'),
(49, 42, '6 DAYS BELITUNG LEEBONG TOUR', 'BANGKA BELITUNG', '6-days-belitung-leebong-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tersembunyi Belitung: Paket Eksklusif 6 Hari 5 Malam</strong></h2><p style=\"text-align:justify;\">Nikmati petualangan tak terlupakan di Negeri Laskar Pelangi! Paket tour ini membawa Anda melampaui sekadar liburan biasa, menggabungkan pesona alam tropis yang autentik dengan kenyamanan maksimal. Selama 6 hari, Anda akan dimanjakan oleh kemegahan batu granit raksasa, kejernihan air laut yang kristalin, dan kehangatan budaya lokal yang menyentuh hati.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"ebe80b549dc0ec20fe6b63c8553854ee9\"><p style=\"text-align:justify;\"><strong>Eksklusivitas Pulau Leebong</strong>: Rasakan sensasi memiliki pulau pribadi di Pulau Leebong. Anda bebas bersepeda, bermain <i>kayaking</i> di perairan tenang, atau sekadar bersantai di <i>Chicas Beach</i> yang eksotis.</p></li><li data-list-item-id=\"eaf8332994bf645cc6825192a6aadb2fd\"><p style=\"text-align:justify;\"><strong>Keajaiban Island Hopping &amp; Snorkeling</strong>: Jelajahi pulau-pulau ikonik seperti Pulau Lengkuas yang legendaris, Pulau Batu Berlayar, hingga melihat keunikan <i>Garuda Head’s Rock</i>. Nikmati dunia bawah laut Belitung yang memukau melalui aktivitas snorkeling.</p></li><li data-list-item-id=\"e515a1b867ef32b6f7b56b85e13f61dab\"><p style=\"text-align:justify;\"><strong>Jejak Literasi &amp; Budaya</strong>: Kunjungi langsung lokasi ikonik dari mahakarya Andrea Hirata, mulai dari Replika SD Laskar Pelangi hingga Museum Kata yang penuh warna dan inspiratif.</p></li><li data-list-item-id=\"e0446e96246978e50e59d1aa2e56ceb0c\"><p style=\"text-align:justify;\"><strong>Panorama dari Ketinggian</strong>: Taklukkan puncak Bukit Peramun dan rasakan hembusan angin segar sambil menikmati pemandangan alam Belitung yang spektakuler dari atas <i>Twin Rock</i>.</p></li><li data-list-item-id=\"ea543a1f72998b0d25d8e4e910099efcd\"><p style=\"text-align:justify;\"><strong>Keunikan Alam Danau Kaolin</strong>: Saksikan langsung perpaduan warna biru toska yang kontras dengan daratan putih bersih di Danau Kaolin, spot foto yang wajib ada di galeri media sosial Anda.</p></li><li data-list-item-id=\"e2beef71682d0944d2e727dbe1c159560\"><p style=\"text-align:justify;\"><strong>Kuliner Autentik yang Memanjakan Lidah</strong>: Nikmati sajian khas yang melegenda, Mie Belitung dan kesegaran Es Jeruk Konci, yang memberikan cita rasa lokal tak tertandingi.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Discover the Hidden Paradise of Belitung: Exclusive 6D5N Package</strong></h2><p style=\"text-align:justify;\">Experience an unforgettable adventure in the Land of the Rainbow Troops! This tour package takes you beyond an ordinary vacation, blending authentic tropical charm with maximum comfort. For 6 days, you will be mesmerized by majestic giant granite boulders, crystal-clear turquoise waters, and the heartwarming local culture.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour?</strong></h3><ul><li data-list-item-id=\"ecd478692d65094f2e2d9921bdfdaea44\"><p style=\"text-align:justify;\"><strong>Leebong Island Exclusivity</strong>: Feel the sensation of a private island escape at Leebong Island. Enjoy free activities like cycling, kayaking in calm waters, or relaxing at the exotic Chicas Beach.</p></li><li data-list-item-id=\"e4caad5d934001f938f325dd8aed22e0c\"><p style=\"text-align:justify;\"><strong>Iconic Island Hopping &amp; Snorkeling</strong>: Explore legendary spots such as Lengkuas Island, Batu Berlayar, and the unique Garuda Head’s Rock. Dive into Belitung\'s stunning underwater world with a professional snorkeling session.</p></li><li data-list-item-id=\"e1235d0ce08902a800209fd8af134f88e\"><p style=\"text-align:justify;\"><strong>Literary &amp; Cultural Journey</strong>: Visit the real-life inspirations behind Andrea Hirata’s masterpiece, from the Replica of SD Laskar Pelangi to the vibrant and inspiring Museum Kata.</p></li><li data-list-item-id=\"e441659fe6bc27a985c976735b8b7b67c\"><p style=\"text-align:justify;\"><strong>Breathtaking High-Angle Views</strong>: Conquer the summit of Peramun Hill and witness spectacular panoramic views of Belitung from Twin Rock.</p></li><li data-list-item-id=\"eaa7ae2400cbf94fda75bff6f5c345911\"><p style=\"text-align:justify;\"><strong>The Surreal Kaolin Lake</strong>: Witness the striking contrast of turquoise water against pure white land at Kaolin Lake, a must-have photo spot for your social media.</p></li><li data-list-item-id=\"e9b36ad02ec9445cf0c45afde218b5c2d\"><p style=\"text-align:justify;\"><strong>Authentic Culinary Delights</strong>: Savor legendary local flavors, including Belitung Noodles and the refreshing Konci Orange Ice.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>벨리퉁의 숨겨진 낙원을 찾아서: 6박 5일 단독 패키지</strong></h2><p style=\"text-align:justify;\">\'무지개 부대(Laskar Pelangi)\'의 땅에서 잊지 못할 모험을 경험해 보세요! 본 투어 패키지는 단순한 휴양을 넘어, 정통 열대 지방의 매력과 최고의 편안함을 동시에 선사합니다. 6일 동안 웅장한 거대 화강암 바위, 수정처럼 맑은 에메랄드빛 바다, 그리고 따뜻한 현지 문화에 매료될 것입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 예약해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ec93bb58276ad83be9c016af698c9a2ed\"><p style=\"text-align:justify;\"><strong>리봉 섬(Leebong Island)의 프라이빗한 휴식</strong>: 리봉 섬에서 마치 개인 섬을 소유한 듯한 기분을 느껴보세요. 자전거 타기, 잔잔한 바다에서의 카약킹, 또는 이국적인 치카스 해변(Chicas Beach)에서의 휴식을 자유롭게 즐길 수 있습니다.</p></li><li data-list-item-id=\"eae93491afb2604fa67d825003f7f5117\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑 &amp; 스노클링</strong>: 전설적인 렝쿠아스 섬(Lengkuas Island), 바투 버를라야르(Batu Berlayar), 그리고 독특한 가루다 머리 바위를 탐험하세요. 전문 장비를 갖춘 스노클링을 통해 벨리퉁의 환상적인 수중 세계를 만끽할 수 있습니다.</p></li><li data-list-item-id=\"eba487b9b61e15c33b1d208e23b494cf0\"><p style=\"text-align:justify;\"><strong>문학과 문화의 여정</strong>: 안드레아 히라타의 걸작 \'무지개 부대\'의 실제 배경이 된 학교 복제품부터 색채가 화려한 문학 박물관(Museum Kata)까지 직접 방문해 보세요.</p></li><li data-list-item-id=\"e8df4775d52f6040b54dd2474ab7d0746\"><p style=\"text-align:justify;\"><strong>정상에서 즐기는 파노라마 뷰</strong>: 프라문 힐(Peramun Hill) 정상에 올라 트윈 락(Twin Rock)에서 내려다보는 벨리퉁의 장엄한 자연 경관을 감상하세요.</p></li><li data-list-item-id=\"e63eb893d21c2d0b330b6d3aff5e0bd4a\"><p style=\"text-align:justify;\"><strong>초현실적인 카올린 호수(Kaolin Lake)</strong>: 하얀 대지와 대비되는 선명한 하늘색 물빛이 매력적인 카올린 호수에서 인생 사진을 남겨보세요.</p></li><li data-list-item-id=\"ebc3b71074bc89c97741af8afbb9840c9\"><p style=\"text-align:justify;\"><strong>전통 미식의 즐거움</strong>: 전설적인 벨리퉁 국수와 상큼한 꼰찌 오렌지 주스 등 현지의 맛을 제대로 즐길 수 있습니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索勿里洞隐藏的天堂：6天5夜专属之旅</strong></h2><p style=\"text-align:justify;\">在“彩虹兵团”的故乡开启一场难忘的冒险！本旅游套餐将带您超越普通度假，融合了纯正的热带风情与极致的舒适体验。在6天的行程中，您将被壮丽的巨型花岗岩、晶莹剔透的海水以及淳朴的人文风情所深深吸引。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须选择这个行程？</strong></h3><ul><li data-list-item-id=\"e2a769b034f5dab7d09b2eef96d8398e3\"><p style=\"text-align:justify;\"><strong>利邦岛 (Leebong Island) 的独家私密体验</strong>：在利邦岛感受宛如私人岛屿般的度假体验。您可以随心所欲地骑行、在平静的海面上划皮划艇，或在充满异国情调的奇卡斯海滩 (Chicas Beach) 悠闲放松。</p></li><li data-list-item-id=\"e7df37f00ba94b99f4aad5fb56b705c08\"><p style=\"text-align:justify;\"><strong>经典跳岛游与浮潜</strong>：探索传奇的灯塔岛 (Lengkuas Island)、帆船石 (Batu Berlayar) 以及独特的鹰头岩。在清澈的海水中浮潜，尽情领略勿里洞迷人的水下世界。</p></li><li data-list-item-id=\"e9a508994483b62d0a594c2d40a83463f\"><p style=\"text-align:justify;\"><strong>文学与文化之旅</strong>：亲临安德烈亚·希拉塔名著《彩虹兵团》的取景地，从彩虹小学复制品到色彩斑斓的文字博物馆，感受浓郁的艺术气息。</p></li><li data-list-item-id=\"e4aeca0b342638e136a5c8d69613f0f4d\"><p style=\"text-align:justify;\"><strong>高空俯瞰绝美全景</strong>：征服普拉蒙山 (Peramun Hill) 峰顶，在双子石 (Twin Rock) 上将勿里洞壮阔的自然景观尽收眼底。</p></li><li data-list-item-id=\"e401a60ce5da1ff6da3f253ad3a42673b\"><p style=\"text-align:justify;\"><strong>梦幻高岭湖 (Kaolin Lake)</strong>：目睹高岭湖翠蓝色湖水与洁白大地交相辉映的奇观，这是您社交媒体上不可或缺的打卡圣地。</p></li><li data-list-item-id=\"e28e476c6c514f6fb3f5ad3913e987406\"><p style=\"text-align:justify;\"><strong>地道美食诱惑</strong>：品尝传承多年的特色勿里洞面条和清爽的酸橘冰 (Es Jeruk Konci)，带给您独特的舌尖享受。</p></li></ul>', 0.00, NULL, 6, 5, NULL, NULL, '<ul><li data-list-item-id=\"e6905eec50a6b87ac9c1cef44410859d3\">Pick Up and Airport Transfer</li><li data-list-item-id=\"e72efba8e0fcfc2bba2edae394c68766f\">Hotel (Twin/Triple)</li><li data-list-item-id=\"e4f1febe1019468fc8db13bf840aaf2c7\">Transportation AC</li><li data-list-item-id=\"e9e385621c6b57572f7fbd15c26337412\">Driver/Guide (English/Mandarin Speaking)</li><li data-list-item-id=\"eb09581b5a22bdc897894baa8b48d73f5\">5x breakfast, 5x lunch, 5x dinner</li><li data-list-item-id=\"ecf3dcd99a484ffdad0d8b94ef7eac6f1\">1x Belitung Noodles + Jeruk Konci Ice Drink</li><li data-list-item-id=\"e035b6fc438ec49727eac65058e7ab14a\">1x Snack</li><li data-list-item-id=\"e7fbf620a1d65b718c4aab0b2696ff2ce\">Entrance Fee &amp; Parking Fee</li><li data-list-item-id=\"e8af2978702c302f2c62fb703ec6015b8\">1x Mineral Water 600 ml / pax / day</li><li data-list-item-id=\"efeb95d2ca019619d58e542b6d4916c5f\">Traditional Boat, Life Vest, Snorkeling Gear</li><li data-list-item-id=\"ec5703d7d143e78f2470ef6c683e20861\">Traditional Boat to Leebong Island</li><li data-list-item-id=\"e0ca7355e4caf54e6968545beb72a0b67\">Public Facility at Leebong Island</li><li data-list-item-id=\"ee8b9ba1011584943c042f62324e2ef0d\">Photo Grup &amp; Go Pro Documentation (softcopy) exclude paid destination</li></ul>', '<ul><li data-list-item-id=\"e6327ff0e4e5c0ea4958ed45964448d64\">Airline Tickets</li><li data-list-item-id=\"e8d945fdb5c436bf0148b98aeaca40dc4\">Airport tax &amp; Additional baggage</li><li data-list-item-id=\"e9525b46db865305c5d7978f185b020b4\">Rapid Test / PCR Test if any</li><li data-list-item-id=\"ef339947325ac47cf709302b1c1a04a78\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</li><li data-list-item-id=\"e6519f0e1158d6f42e8d36ae353ac073e\">Travel Insurance</li><li data-list-item-id=\"e911b21a814d0b3a82f025c4c21b83cd0\">Single Supplement&nbsp;</li><li data-list-item-id=\"e92bbe193fd51a3bdede51d738ff51599\">Optional Tour</li><li data-list-item-id=\"e2c65c95ed6662917023dfb551c616a03\">Watersport</li><li data-list-item-id=\"ebe59aff5b5e87ae9aa87a5cc0b18211e\">Tips for Driver/Guide @IDR 50.000/Pax/Day</li><li data-list-item-id=\"e01cef894b9d5730795da718f6105e402\">High Season Surcharge</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Adventure\",\"Beach\",\"CULINARY\"]', NULL, 0, NULL, '2026-05-06 12:14:57', '2026-05-29 14:47:55'),
(50, 42, '5 DAYS BELITUNG TOUR', 'BANGKA BELITUNG', '5-days-belitung-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Pesona Negeri Laskar Pelangi: Paket Eksklusif 5 Hari 4 Malam</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk petualangan visual dan batin di salah satu kepulauan tercantik di Indonesia! Paket tour 5D4N Belitung kami dirancang khusus untuk membawa Anda melampaui sekadar liburan biasa—ini adalah perjalanan menuju keajaiban alam yang autentik dan sejarah literasi yang menyentuh hati.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"e7ce844751ac7b903e34f68476cdc864c\"><p style=\"text-align:justify;\"><strong>Eksplorasi \"Island Hopping\" yang Ikonik</strong>: Rasakan sensasi melintasi air kristal menuju gugusan pulau legendaris seperti <strong>Pulau Lengkuas</strong>, <strong>Pulau Batu Berlayar</strong>, dan melihat keunikan batu granit raksasa berbentuk kepala burung di <strong>Garuda Head’s Rock</strong>.</p></li><li data-list-item-id=\"ee7fbba10db796e6aa4e22d320d850905\"><p style=\"text-align:justify;\"><strong>Jejak Literasi Laskar Pelangi</strong>: Kunjungi langsung lokasi inspiratif mahakarya Andrea Hirata. Mulai dari berfoto di <strong>Replika SD Laskar Pelangi</strong>, hingga meresapi estetika penuh warna di <strong>Museum Kata Andrea Hirata</strong> dan <strong>Kampoeng Fifi</strong>.</p></li><li data-list-item-id=\"eeb2f7c807176e50d656e00aaf030630e\"><p style=\"text-align:justify;\"><strong>Panorama Alam dari Ketinggian</strong>: Taklukkan puncak <strong>Bukit Peramun</strong> melalui aktivitas <i>trekking</i> yang menyegarkan, dan nikmati pemandangan Belitung yang spektakuler dari atas <strong>Twin Rock</strong> serta <strong>Ampar Rock</strong>.</p></li><li data-list-item-id=\"e4332328165e06b14ee574850a0adf1b4\"><p style=\"text-align:justify;\"><strong>Keajaiban Geologi Belitung</strong>: Saksikan kemegahan batu granit purba di <strong>Batu Baginde</strong> dan nikmati ketenangan di pantai-pantai tersembunyi seperti <strong>Pantai Penyabong</strong> dan <strong>Pantai Teluk Gembira</strong>.</p></li><li data-list-item-id=\"ee9f2d7784b5ebd53dc3b1d1f8dd71425\"><p style=\"text-align:justify;\"><strong>Spot Foto Instagramable \"Danau Kaolin\"</strong>: Jangan lewatkan pemandangan magis air biru toska yang kontras dengan daratan putih bersih di <strong>Danau Kaolin</strong>, tempat yang sempurna untuk mempercantik galeri media sosial Anda.</p></li><li data-list-item-id=\"e52d2e704f8e7a39053632ee7da486708\"><p style=\"text-align:justify;\"><strong>Pesta Rasa Kuliner Autentik</strong>: Nikmati kenikmatan legendaris yang tidak boleh dilewatkan: <strong>Mie Belitung</strong> yang hangat dipadukan dengan kesegaran <strong>Es Jeruk Konci</strong> asli, sebuah penutup perjalanan yang sempurna.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Enchanting Land of the Rainbow Troops: Exclusive 5D4N Package</strong></h2><p style=\"text-align:justify;\">Prepare yourself for a visual and soulful adventure in one of Indonesia’s most beautiful archipelagos! Our 5D4N Belitung tour package is specially designed to take you beyond an ordinary vacation—it is a journey toward authentic natural wonders and heart-touching literary history.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour?</strong></h3><ul><li data-list-item-id=\"ed5666a2a8d535f2ced77d47b9f1e3a8b\"><p style=\"text-align:justify;\"><strong>Iconic Island-Hopping Exploration</strong>: Experience the sensation of cruising through crystal-clear waters to legendary island clusters such as <strong>Lengkuas Island</strong>, <strong>Batu Berlayar Island</strong>, and witness the unique giant granite formation shaped like a bird\'s head at <strong>Garuda Head’s Rock</strong>.</p></li><li data-list-item-id=\"e08657d87690b5551dc36db306331f39a\"><p style=\"text-align:justify;\"><strong>Laskar Pelangi Literary Trail</strong>: Visit the inspiring real-life locations of Andrea Hirata’s masterpiece. From taking photos at the <strong>Replica of SD Laskar Pelangi</strong> to absorbing the colorful aesthetics of the <strong>Andrea Hirata Words Museum</strong> and <strong>Kampoeng Fifi</strong>.</p></li><li data-list-item-id=\"eab2dee143f047925e183479ff714c675\"><p style=\"text-align:justify;\"><strong>Spectacular High-Angle Views</strong>: Conquer the summit of <strong>Peramun Hill</strong> through a refreshing trekking activity and enjoy spectacular panoramic views of Belitung from <strong>Twin Rock</strong> and <strong>Ampar Rock</strong>.</p></li><li data-list-item-id=\"e929af04eb31fef1f3acb063452fc5244\"><p style=\"text-align:justify;\"><strong>Belitung’s Geological Wonders</strong>: Witness the majesty of ancient granite boulders at <strong>Batu Baginde</strong> and enjoy the tranquility of hidden gems like <strong>Penyabong Beach</strong> and <strong>Teluk Gembira Beach</strong>.</p></li><li data-list-item-id=\"e37658ffde28db3b88a64c1e86178bd0b\"><p style=\"text-align:justify;\"><strong>Instagrammable \"Kaolin Lake\"</strong>: Don\'t miss the magical view of bright turquoise water contrasting against pure white land at <strong>Kaolin Lake</strong>, the perfect place to beautify your social media gallery.</p></li><li data-list-item-id=\"edc0cc7210d060b056b32ef1286335d8c\"><p style=\"text-align:justify;\"><strong>Authentic Culinary Feast</strong>: Savor legendary local delights that are not to be missed: warm <strong>Belitung Noodles</strong> paired with the refreshing original <strong>Konci Orange Ice</strong>, a perfect end to your journey.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>무지개 부대의 매혹적인 땅을 찾아서: 5박 4일 단독 패키지</strong></h2><p style=\"text-align:justify;\">인도네시아에서 가장 아름다운 군도 중 하나인 벨리퉁에서 시각과 영혼을 깨우는 모험을 준비하세요! 본 5박 4일 벨리퉁 투어 패키지는 단순한 휴양을 넘어, 진정한 자연의 경이로움과 마음을 울리는 문학적 역사로 안내하도록 특별히 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 예약해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e77c103710a397f908898fc29bc320255\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑 탐험</strong>: 수정처럼 맑은 바다를 가르며 <strong>렝쿠아스 섬(Lengkuas Island)</strong>, <strong>바투 버를라야르 섬(Batu Berlayar Island)</strong> 등 전설적인 섬들을 방문하고, 가루다 머리 바위(Garuda Head’s Rock)의 독특한 거대 화강암 형상을 감상해 보세요.</p></li><li data-list-item-id=\"eb8fb53a86b911646e3ad1a8b8746308a\"><p style=\"text-align:justify;\"><strong>무지개 부대(Laskar Pelangi) 문학 탐방</strong>: 안드레아 히라타의 걸작에 영감을 준 실제 장소들을 방문해 보세요. <strong>무지개 부대 초등학교 복제본</strong>에서의 기념 촬영부터 안드레아 히라타 문학 박물관(Museum Kata)과 캄풍 피피(Kampoeng Fifi)의 화려한 미학을 만끽할 수 있습니다.</p></li><li data-list-item-id=\"e6e5b25e9487542fdf5ee272bf0a1531a\"><p style=\"text-align:justify;\"><strong>정상에서 즐기는 파노라마 뷰</strong>: 상쾌한 트레킹을 통해 <strong>프라문 힐(Peramun Hill)</strong> 정상에 올라 트윈 락(Twin Rock)과 암파르 락(Ampar Rock)에서 벨리퉁의 장엄한 자연 경관을 감상하세요.</p></li><li data-list-item-id=\"ef18cd5640fad8d8732e41f7916183a5e\"><p style=\"text-align:justify;\"><strong>벨리퉁의 지질학적 경이로움</strong>: 바투 바긴데(Batu Baginde)의 웅장한 고대 화강암 바위를 목격하고, 픈야붕 해변(Penyabong Beach)과 <strong>틀룩 금비라 해변(Teluk Gembira Beach)</strong> 같은 숨겨진 명소에서 평온함을 즐겨보세요.</p></li><li data-list-item-id=\"e8e939ad75eb88212d30513996600224e\"><p style=\"text-align:justify;\"><strong>인생샷 명소 \"카올린 호수\"</strong>: 순백의 대지와 대비되는 선명한 에메랄드빛 물빛이 매력적인 카올린 호수(Kaolin Lake)에서 SNS를 장식할 최고의 사진을 남겨보세요.</p></li><li data-list-item-id=\"e44b83e3872e4e3cbdd28285dbc512f25\"><p style=\"text-align:justify;\"><strong>정통 미식의 즐거움</strong>: 절대 놓칠 수 없는 전설적인 현지 맛, 따뜻한 <strong>벨리퉁 국수</strong>와 상큼한 <strong>꼰찌 오렌지 주스</strong>의 조합으로 완벽한 여행의 마무리를 경험하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索迷人的彩虹兵团故乡：5天4夜专属之旅</strong></h2><p style=\"text-align:justify;\">准备好在印尼最群岛之一开启一场视觉与心灵的冒险吧！我们的5天4夜勿里洞旅游套餐经过精心设计，带您超越普通度假，迈向纯正的自然奇观和动人的文学历史之旅。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须选择这个行程？</strong></h3><ul><li data-list-item-id=\"e6865be13398137e690c9d72f87ec1504\"><p style=\"text-align:justify;\"><strong>经典的跳岛探险</strong>：感受穿梭在晶莹剔透海水间的快感，前往传说中的<strong>灯塔岛 (Lengkuas Island) 、帆船石 (Batu Berlayar Island) ，</strong>并亲眼见证<strong>鹰头岩 (Garuda Head’s Rock)</strong> 独特的巨型花岗岩奇观。</p></li><li data-list-item-id=\"e6592339afecbb86362fb5c7a1a74792f\"><p style=\"text-align:justify;\"><strong>彩虹兵团文学足迹</strong>：亲临安德烈亚·希拉塔名著的灵感发源地。在<strong>彩虹小学复制品</strong>前合影留念，并沉浸在<strong>安德烈亚·希拉塔文字博物馆</strong>和<strong>菲菲村 (Kampoeng Fifi)</strong> 绚丽夺目的艺术氛围中。</p></li><li data-list-item-id=\"ee95dadf37f3c8fcc0a5af5e9277a06c5\"><p style=\"text-align:justify;\"><strong>高空俯瞰壮丽全景</strong>：通过清爽的徒步活动征服<strong>普拉蒙山 (Peramun Hill)</strong> 峰顶，在<strong>双子石 (Twin Rock)</strong> 和 <strong>安帕尔岩 (Ampar Rock)</strong> 上将勿里洞壮阔的自然景观尽收眼底。</p></li><li data-list-item-id=\"eea4edf8a98aaeb6f0edfd50132ebc3c7\"><p style=\"text-align:justify;\"><strong>勿里洞的地质奇迹</strong>：目睹<strong>巴金德石 (Batu Baginde)</strong> 雄伟的古代花岗岩巨石，并在<strong>喷亚蓬海滩 (Penyabong Beach)</strong> 和<strong>欢喜湾海滩 (Teluk Gembira Beach)</strong> 等隐藏的秘境中享受宁静。</p></li><li data-list-item-id=\"e902efb96584ffcaf588e1b1d17d384a1\"><p style=\"text-align:justify;\"><strong>网红打卡圣地“高岭湖”</strong>：千万不要错过<strong>高岭湖 (Kaolin Lake)</strong> 梦幻的翠蓝色湖水与洁白大地交相辉映的美景，这是美化您社交媒体相册的最佳地点。</p></li><li data-list-item-id=\"e6f12bee28163b908db23e16e91ba00d2\"><p style=\"text-align:justify;\"><strong>地道美食盛宴</strong>：品尝不容错过的传奇地方美味：暖胃的<strong>勿里洞特色面条</strong>搭配清爽解渴的<strong>酸橘冰 (Es Jeruk Konci) ，</strong>为您的旅程画上完美句点。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e498f7d38c17442097ec2c5766de1f03b\"><p style=\"text-align:justify;\">Pick Up and Airport Transfer</p></li><li data-list-item-id=\"ee18192eacba3db866c9d052aab2515e8\"><p style=\"text-align:justify;\">Hotel (Twin/Triple)</p></li><li data-list-item-id=\"e6fc0981b6ce2321bfdc831b4ad826638\"><p style=\"text-align:justify;\">Transportation AC</p></li><li data-list-item-id=\"e8b2de50b2ffbd67c50025e8ccb533f95\"><p style=\"text-align:justify;\">Driver/Guide (English/Mandarin Speaking)</p></li><li data-list-item-id=\"e5bdc118077c776f10567255a0bed296d\"><p style=\"text-align:justify;\">4x breakfast,4x lunch, 4x dinner</p></li><li data-list-item-id=\"e0d69b11e14fec0775792751a24fc2feb\"><p style=\"text-align:justify;\">1x Belitung Noodles + Jeruk Konci Ice Drink</p></li><li data-list-item-id=\"e2a1c0fa694a8d98a0775053048c1c1bc\"><p style=\"text-align:justify;\">1x Snack</p></li><li data-list-item-id=\"eb6b1ec4a79c3d0870cb199e88c016fcd\"><p style=\"text-align:justify;\">Entrance Fee &amp; Parking Fee</p></li><li data-list-item-id=\"ef4643e417547f1aa0ffa306790c83cf7\"><p style=\"text-align:justify;\">1x Mineral Water 600 ml / pax / day</p></li><li data-list-item-id=\"e7e6ac18ceb66188f7d7c59ab58241577\"><p style=\"text-align:justify;\">Traditional Boat, Life Vest, Snorkeling Gear</p></li><li data-list-item-id=\"e4c6c6400cdfd779b2f31a02f64bdcd3e\"><p style=\"text-align:justify;\">Photo Grup &amp; Go Pro Documentation (softcopy) exclude paid destination</p></li></ul>', '<ul><li data-list-item-id=\"e9c151e79b9cdb70b298eed17677951c1\"><p style=\"text-align:justify;\">Airline Tickets</p></li><li data-list-item-id=\"e1ed0d21df2d63bd5c4556a8c3e9f6adb\"><p style=\"text-align:justify;\">Airport tax &amp; Additional baggage</p></li><li data-list-item-id=\"e97f1839487fba431cc3c6d92c4fbb32b\"><p style=\"text-align:justify;\">Rapid Test / PCR Test if any</p></li><li data-list-item-id=\"eab2ac9dd657b87e100a8fd8f4ef1020b\"><p style=\"text-align:justify;\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</p></li><li data-list-item-id=\"ed2383c2e1c5f6ed10f0ca0bd01de84f9\"><p style=\"text-align:justify;\">Travel Insurance</p></li><li data-list-item-id=\"eff772c3552e38d5244eba8abbc09a7f1\"><p style=\"text-align:justify;\">Single Supplement&nbsp;</p></li><li data-list-item-id=\"e55442c90d6f5a88159ac0dd1d9b3df72\"><p style=\"text-align:justify;\">Optional Tour</p></li><li data-list-item-id=\"e331b4a30ee5651a50ca39ca90a550676\"><p style=\"text-align:justify;\">Watersport</p></li><li data-list-item-id=\"edc3e6a77038b0e7ae169ad2aabf05394\"><p style=\"text-align:justify;\">Tips for Driver/Guide @IDR 50.000/Pax/Day</p></li><li data-list-item-id=\"e3918fe58600bbfd050482ee6d78bab87\"><p style=\"text-align:justify;\">High Season Surcharge</p></li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"CULINARY\"]', NULL, 0, NULL, '2026-05-06 12:30:30', '2026-05-29 14:47:12'),
(51, 42, '5 DAYS BELITUNG LEEBONG', 'BANGKA BELITUNG', '5-days-belitung-leebong', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tropis Tersembunyi: Paket Eksklusif 5D4N Belitung Leebong</strong></h2><p style=\"text-align:justify;\">Siapkan koper Anda untuk petualangan visual yang tak terlupakan di Negeri Laskar Pelangi! Paket tour <strong>5 Hari 4 Malam</strong> ini bukan sekadar liburan biasa, melainkan sebuah perjalanan menyeluruh ke jantung keajaiban geologi dan bahari Indonesia yang telah diakui dunia.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Mencoba Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"e23e67f5c2b87d749483649872218982a\"><p style=\"text-align:justify;\"><strong>Eksplorasi Pulau Leebong yang Private &amp; Mewah</strong>: Rasakan sensasi memiliki pulau pribadi dengan fasilitas lengkap, mulai dari bersepeda di tepi pantai, kayaking di air kristal, hingga bersantai di <strong>Chicas Beach</strong> yang eksotis.</p></li><li data-list-item-id=\"e5387d3920bc550b97e2dd16b7dfb28e9\"><p style=\"text-align:justify;\"><strong>Island Hopping Ikonik</strong>: Taklukkan keindahan bawah laut dengan snorkeling di <strong>Pulau Lengkuas</strong>, berfoto di antara formasi granit raksasa <strong>Batu Berlayar</strong>, dan melihat keunikan <strong>Garuda Head’s Rock</strong> yang melegenda.</p></li><li data-list-item-id=\"e27f13f16b4a61b6373ec4b9c32a09eb6\"><p style=\"text-align:justify;\"><strong>Jejak Literasi Laskar Pelangi</strong>: Kunjungi lokasi asli yang menginspirasi dunia di <strong>Replika SD Laskar Pelangi</strong> dan resapi keindahan kata-kata di <strong>Museum Kata Andrea Hirata</strong>.</p></li><li data-list-item-id=\"ee2936304f7caac436dbb8c6c8a82dd68\"><p style=\"text-align:justify;\"><strong>Keajaiban Geologi yang Magis</strong>: Saksikan kemegahan batu granit purba di <strong>Batu Baginde</strong> dan pesona <strong>Danau Kaolin</strong> dengan air biru toska yang sangat <i>instagramable</i>.</p></li><li data-list-item-id=\"eae861da4e63330649251101ab66a4867\"><p style=\"text-align:justify;\"><strong>Harmoni Alam &amp; Kuliner</strong>: Nikmati kesegaran <strong>Es Jeruk Konci</strong> dan kehangatan <strong>Mie Belitung</strong> yang autentik sebagai pelengkap sempurna perjalanan Anda.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore a Hidden Tropical Paradise: Exclusive 5D4N Belitung Leebong Package</strong></h2><p style=\"text-align:justify;\">Pack your bags for an unforgettable visual adventure in the Land of the Rainbow Troops! This <strong>5 Days 4 Nights</strong> tour package is more than just an ordinary vacation—it is a comprehensive journey to the heart of Indonesia\'s globally recognized geological and marine wonders.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Experience This Tour?</strong></h3><ul><li data-list-item-id=\"e8c4cf441777eb42aec29f0596fbe89c9\"><p style=\"text-align:justify;\"><strong>Private &amp; Luxurious Leebong Island Exploration</strong>: Feel the sensation of owning a private island with complete facilities, from cycling along the shore and kayaking in crystal-clear waters to relaxing at the exotic <strong>Chicas Beach</strong>.</p></li><li data-list-item-id=\"e900b6d6dbb4b1df452cfe9a6945b1380\"><p style=\"text-align:justify;\"><strong>Iconic Island Hopping</strong>: Conquer underwater beauty with snorkeling at <strong>Lengkuas Island</strong>, take photos among the artistic giant granite formations of <strong>Batu Berlayar</strong>, and witness the legendary <strong>Garuda Head’s Rock</strong>.</p></li><li data-list-item-id=\"ea51f9dacbb48f91bf02f42d86024f77b\"><p style=\"text-align:justify;\"><strong>Laskar Pelangi Literary Trail</strong>: Visit the original locations that inspired the world at the <strong>SD Laskar Pelangi Replica</strong> and soak in the beauty of words at the <strong>Andrea Hirata Words Museum</strong>.</p></li><li data-list-item-id=\"eb98e2c16dfc52ea2e147163938acaa35\"><p style=\"text-align:justify;\"><strong>Magical Geological Wonders</strong>: Witness the majesty of ancient granite boulders at <strong>Batu Baginde</strong> and the mesmerizing charm of <strong>Kaolin Lake</strong> with its highly \"Instagrammable\" turquoise water.</p></li><li data-list-item-id=\"e1c718c5b8020bc074ae870e928b935a0\"><p style=\"text-align:justify;\"><strong>Harmony of Nature &amp; Culinary</strong>: Enjoy the freshness of <strong>Konci Orange Ice</strong> and the authentic warmth of <strong>Belitung Noodles</strong> as the perfect complement to your journey.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>숨겨진 열대의 낙원을 찾아서: 5박 4일 벨리퉁 리봉 단독 패키지</strong></h2><p style=\"text-align:justify;\">무지개 부대(Laskar Pelangi)의 땅에서 잊지 못할 시각적 모험을 위해 짐을 꾸려보세요! 본 <strong>5박 4일</strong> 투어 패키지는 단순한 휴가를 넘어, 세계적으로 인정받는 인도네시아의 지질학적 및 해양적 경이로움의 심장부로 떠나는 완벽한 여정입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 꼭 경험해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"eeead1c41998968bd2e43620c97bcf1a3\"><p style=\"text-align:justify;\"><strong>프라이빗하고 럭셔리한 리봉 섬 탐험</strong>: 해안가를 따라 즐기는 자전거 타기, 수정처럼 맑은 바다에서의 카약킹, 그리고 이국적인 치카스 해변(Chicas Beach)에서의 휴식까지, 프라이빗 아일랜드를 소유한 듯한 기분을 만끽해 보세요.</p></li><li data-list-item-id=\"ea9b66df446df5262b380bb0d3c027bdd\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑</strong>: 렝쿠아스 섬(Lengkuas Island)에서 스노클링으로 수중 미경을 정복하고, 바투 버를라야르(Batu Berlayar)의 예술적인 거대 화강암 사이에서 사진을 남기며, 전설적인 가루다 머리 바위(Garuda Head’s Rock)를 직접 목격하세요.</p></li><li data-list-item-id=\"e7149f3a07b895d2995b53c2013695517\"><p style=\"text-align:justify;\"><strong>무지개 부대 문학 탐방</strong>: 전 세계에 영감을 준 실제 장소인 <strong>무지개 부대 초등학교 복제본</strong>을 방문하고, <strong>안드레아 히라타 문학 박물관</strong>에서 아름다운 글귀들에 빠져보세요.</p></li><li data-list-item-id=\"e740916463a882406020bee9ae14763cb\"><p style=\"text-align:justify;\"><strong>마법 같은 지질학적 경이로움</strong>: 바투 바긴데(Batu Baginde)의 웅장한 고대 화강암 바위와 \"인생샷\" 명소인 에메랄드빛 <strong>카올린 호수</strong>의 매혹적인 풍경을 감상하세요.</p></li><li data-list-item-id=\"e1fd26b502c68a7baa800c8206638fdaa\"><p style=\"text-align:justify;\"><strong>자연과 미식의 조화</strong>: 여행의 완벽한 마무리를 위해 상큼한 <strong>꼰찌 오렌지 주스</strong>와 깊은 맛의 <strong>벨리퉁 국수</strong>를 맛보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索隐世热带天堂：5天4夜 勿里洞里邦岛 专属之旅</strong></h2><p style=\"text-align:justify;\">带上您的行囊，在“彩虹兵团”的故乡开启一场难忘的视觉冒险！这趟 <strong>5天4夜</strong> 的旅游套餐不仅仅是一次普通度假，更是一场前往印度尼西亚享誉全球的地质与海洋奇观之心的深度之旅。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须体验这个行程？</strong></h3><ul><li data-list-item-id=\"e832792eee6a2e4a325f38e11d2d620f9\"><p style=\"text-align:justify;\"><strong>私密奢华的里邦岛 (Leebong Island) 探险</strong>：感受拥有私人岛屿般的体验，设施一应俱全。您可以沿岸骑行、在清澈见底的海水中划皮划艇，或在充满异国情调的 <strong>Chicas 海滩</strong> 悠闲放松。</p></li><li data-list-item-id=\"e4bcdd4d18e80f3fa030bd7db26c7fb4e\"><p style=\"text-align:justify;\"><strong>经典的跳岛游</strong>：在 <strong>灯塔岛 (Lengkuas Island)</strong> 浮潜挑战水下美景，在 <strong>帆船石 (Batu Berlayar)</strong> 艺术般的巨型花岗岩间合影，并亲眼见证传奇的 <strong>鹰头岩 (Garuda Head’s Rock) 。</strong></p></li><li data-list-item-id=\"e16bb6c6f9251abdfca2e681ac328d706\"><p style=\"text-align:justify;\"><strong>彩虹兵团文学足迹</strong>：参观激发全球灵感的 <strong>彩虹小学复制品</strong> 现场，并在 <strong>安德烈亚·希拉塔文字博物馆</strong> 感受文字的魅力。</p></li><li data-list-item-id=\"ecfd1915144fbb3b5bdedbd42e1eb5e7b\"><p style=\"text-align:justify;\"><strong>魔幻般的地质奇迹</strong>：目睹 <strong>巴金德石 (Batu Baginde)</strong> 雄伟的古代花岗岩巨石，以及拥有梦幻翠蓝色湖水、极具网红打卡潜力的 <strong>高岭湖 (Kaolin Lake) 。</strong></p></li><li data-list-item-id=\"e17f2eecd2f69054181195db13462919e\"><p style=\"text-align:justify;\"><strong>自然与美食的和谐</strong>：品尝清爽的 <strong>酸橘冰 (Es Jeruk Konci)</strong> 和地道暖胃的 <strong>勿里洞特色面条</strong>，为您的旅程画上完美的句点。</p></li></ul>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"e22022194a2f3df8798f3ece47e532359\">Pick Up and Airport Transfer</li><li data-list-item-id=\"e239972f4eeaa7a087ae01a4f881c1db2\">Hotel (Twin/Triple)</li><li data-list-item-id=\"e4155ee85b5c8a7ccbe985a658a231bfa\">Transportation AC</li><li data-list-item-id=\"e6e649e9395d05dde7ba9901199363158\">Driver/Guide (English/Mandarin Speaking)</li><li data-list-item-id=\"e6d67f8173ecdd8b628b6bd676c0d212a\">4x breakfast, 4x lunch, 4x dinner</li><li data-list-item-id=\"e0d95295782dceaa7c559825b8d289b8b\">1x Belitung Noodles + Jeruk Konci Ice Drink</li><li data-list-item-id=\"e13d336be0028eccf377bb4df8b3c3902\">1x Snack</li><li data-list-item-id=\"e5dd27dc07c1e0e16ff2012fac913bb34\">Entrance Fee &amp; Parking Fee</li><li data-list-item-id=\"e0d657e07cfdee85bff4b8d98620dc548\">1x Mineral Water 600 ml / pax / day</li><li data-list-item-id=\"e8ac597224a63566e9ac71e1c1bf48d8b\">Traditional Boat, Life Vest, Snorkeling Gear</li><li data-list-item-id=\"e2d52c4f8a9e9ce306e1b91bdfe5e7290\">Traditional Boat to Leebong Island</li><li data-list-item-id=\"ead213f6d58bc4ee75a32b9ffc41ac8a8\">Public Facility at Leebong Island</li><li data-list-item-id=\"e601e3905fa21ad40c0204abb0d950eb7\">Photo Grup &amp; Go Pro Documentation (softcopy) exclude paid destination</li></ul>', '<ul><li data-list-item-id=\"e2f0d306459700e9cfb9bb6498c631c92\">Airline Tickets</li><li data-list-item-id=\"e77d1c3a1165b4b87aba95c46594ab7d2\">Airport tax &amp; Additional baggage</li><li data-list-item-id=\"e1ea387e7a792a71f0618d435ba8cb78b\">Rapid Test / PCR Test if any</li><li data-list-item-id=\"e5e37cc3e50f92d9e5761e0318a22b5d6\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</li><li data-list-item-id=\"e7b2f161f8badb09e83447e41aa60b242\">Travel Insurance</li><li data-list-item-id=\"ef701613cf471fd01da2a89cd55c12df7\">Single Supplement&nbsp;</li><li data-list-item-id=\"e0e8f3901df81eae64ba05bb1b8e323bf\">Optional Tour</li><li data-list-item-id=\"ea4bd00ae6e6aadee59d6366912c7343d\">Watersport</li><li data-list-item-id=\"eaa69e36a3cd4232bd536ce700500e539\">Tips for Driver/Guide @IDR 50.000/Pax/Day</li><li data-list-item-id=\"e42555a3711ac4e5c0bd08585a9a66d13\">High Season Surcharge</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"Culinary\"]', NULL, 0, NULL, '2026-05-06 12:50:24', '2026-05-29 14:46:19');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(52, 42, '4 DAYS BELITUNG TOUR', 'BANGKA BELITUNG', '4-days-belitung-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Pesona \"Negeri Laskar Pelangi\": Paket Eksklusif 4D3N Belitung Tour</strong></h2><p style=\"text-align:justify;\">Siapkan diri Anda untuk terpesona oleh harmoni alam dan budaya di salah satu surga tropis tercantik di Indonesia! Paket <strong>4 Hari 3 Malam</strong> ini dirancang khusus untuk membawa Anda meresapi setiap sudut keajaiban Belitung—mulai dari jejak literasi yang menginspirasi dunia hingga gugusan pulau granit purba yang magis.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Wajib Memilih Paket Tour Ini?</strong></h3><ul><li data-list-item-id=\"e4b52e3d60dbd7bc9351668e18023a79e\"><p style=\"text-align:justify;\"><strong>Nostalgia Laskar Pelangi yang Autentik</strong>: Kunjungi langsung <strong>Replika SD Laskar Pelangi</strong> dan abadikan momen di <strong>Museum Kata Andrea Hirata</strong> yang penuh warna. Rasakan kedekatan emosional dengan lokasi yang menjadi latar kisah legendaris yang mendunia.</p></li><li data-list-item-id=\"e7097f1c287d7932db7c8fdf04e5e5113\"><p style=\"text-align:justify;\"><strong>Petualangan Island Hopping yang Ikonik</strong>: Taklukkan kejernihan laut Belitung dengan mengunjungi <strong>Pulau Lengkuas</strong>, <strong>Pulau Pasir</strong>, hingga formasi batu artistik <strong>Garuda Head’s Rock</strong> dan <strong>Batu Berlayar</strong>. Jangan lewatkan sensasi menjelajahi misteri <strong>Goa Kelayang</strong> yang eksotis.</p></li><li data-list-item-id=\"e1204c530739dae5df8b71d1cb82e8d62\"><p style=\"text-align:justify;\"><strong>Simfoni Batu Granit Raksasa</strong>: Temukan kemegahan alam di <strong>Batu Baginde</strong>, formasi granit raksasa yang menjadi ikon Belitung Selatan, serta nikmati ketenangan di <strong>Pantai Penyabong</strong> yang memukau.</p></li><li data-list-item-id=\"edb6d826b13f40f9e64c10b3017a0d2a6\"><p style=\"text-align:justify;\"><strong>Keajaiban Visual Danau Kaolin</strong>: Saksikan langsung kontras warna yang luar biasa antara air biru toska dan daratan putih salju di <strong>Danau Kaolin</strong>, destinasi wajib bagi para pencinta fotografi.</p></li><li data-list-item-id=\"e53795d5d7ce50a7033fa2ef1e0d633ba\"><p style=\"text-align:justify;\"><strong>Sensasi Kuliner Legendaris</strong>: Lengkapi perjalanan Anda dengan cita rasa lokal yang autentik. Nikmati kehangatan <strong>Mie Belitung</strong> dan kesegaran <strong>Es Jeruk Konci</strong> yang akan memanjakan lidah Anda setelah seharian bereksplorasi.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Charm of \"The Land of Rainbow Troops\": Exclusive 4D3N Belitung Tour Package</strong></h2><p style=\"text-align:justify;\">Prepare to be mesmerized by the harmony of nature and culture in one of Indonesia’s most beautiful tropical paradises! This <strong>4 Days 3 Nights</strong> package is specially designed to take you through every corner of Belitung\'s wonders—from world-inspiring literary trails to magical ancient granite island clusters.</p><h3 style=\"text-align:justify;\"><strong>Why You Must Choose This Tour?</strong></h3><ul><li data-list-item-id=\"e58509759bda74ea8f67f5c5811c70059\"><p style=\"text-align:justify;\"><strong>Authentic Laskar Pelangi Nostalgia</strong>: Visit the original <strong>Laskar Pelangi Elementary School Replica</strong> and capture colorful moments at the <strong>Andrea Hirata Words Museum</strong>. Feel an emotional connection to the locations of the legendary story that moved the world.</p></li><li data-list-item-id=\"e7f816ff9f9ef34a914bdc00f7036e246\"><p style=\"text-align:justify;\"><strong>Iconic Island-Hopping Adventure</strong>: Conquer the crystal-clear waters of Belitung by visiting <strong>Lengkuas Island</strong>, <strong>Sand Island (Pulau Pasir)</strong>, and the artistic rock formations of <strong>Garuda Head’s Rock</strong> and <strong>Batu Berlayar</strong>. Don\'t miss the sensation of exploring the exotic <strong>Kelayang Cave</strong>.</p></li><li data-list-item-id=\"eb33af99cc5f2c3ce94b7de52443e6379\"><p style=\"text-align:justify;\"><strong>Symphony of Giant Granite Boulders</strong>: Discover natural majesty at <strong>Batu Baginde</strong>, a giant granite formation that stands as an icon of South Belitung and enjoy the serenity of the stunning <strong>Penyabong Beach</strong>.</p></li><li data-list-item-id=\"efbf0b48d0faabeaf73262108da7e6163\"><p style=\"text-align:justify;\"><strong>Visual Wonder of Kaolin Lake</strong>: Witness the extraordinary contrast between turquoise water and snow-white land at <strong>Kaolin Lake</strong>, a must-visit destination for photography enthusiasts.</p></li><li data-list-item-id=\"ead757e6614e1979a87b16e3d3a1f6efd\"><p style=\"text-align:justify;\"><strong>Legendary Culinary Sensation</strong>: Complete your journey with authentic local flavors. Enjoy the warmth of <strong>Belitung Noodles</strong> and the freshness of <strong>Konci Orange Ice</strong>, perfect treats after a day of exploration.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>\"무지개 부대\"의 땅을 탐험하다: 4박 3일 벨리퉁 단독 투어 패키지</strong></h2><p style=\"text-align:justify;\">인도네시아에서 가장 아름다운 열대 낙원 중 한 곳에서 자연과 문화의 조화에 매료될 준비를 하세요! 본 <strong>4박 3일</strong> 패키지는 세계적으로 영감을 준 문학의 발자취부터 신비로운 고대 화강암 섬들까지, 벨리퉁의 모든 매력을 경험할 수 있도록 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e8d3aa23f0d5cfa270f1bfc1cb1b65d65\"><p style=\"text-align:justify;\"><strong>정통 \"무지개 부대(Laskar Pelangi)\"의 향수</strong>: 전 세계에 감동을 준 전설적인 이야기의 배경인 <strong>무지개 부대 초등학교 복제본</strong>을 방문하고, 알록달록한 <strong>안드레아 히라타 문학 박물관</strong>에서 특별한 순간을 기록하세요.</p></li><li data-list-item-id=\"e82eb7fe17c7fbaa23b345436aa8cf6e6\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑 어드벤처</strong>: <strong>렝쿠아스 섬</strong>, <strong>모래 섬(Pulau Pasir)</strong>, 그리고 예술적인 화강암 형상인 <strong>가루다 머리 바위</strong>와 <strong>바투 버를라야르</strong>를 방문하여 벨리퉁의 투명한 바다를 만끽하세요. 이국적인 <strong>끌라양 동굴(Goa Kelayang)</strong> 탐험의 짜릿함도 놓치지 마세요.</p></li><li data-list-item-id=\"ef875f29a140410f0951f932e4750c257\"><p style=\"text-align:justify;\"><strong>거대 화강암의 교향곡</strong>: 남부 벨리퉁의 상징인 거대 화강암 지형 바투 바긴데(Batu Baginde)에서 대자연의 위엄을 발견하고, 환상적인 쁘냐봉 해변(Pantai Penyabong)에서 평화로운 휴식을 즐기세요.</p></li><li data-list-item-id=\"e810cd418acc2461a46c7ed1e8edbcc9f\"><p style=\"text-align:justify;\"><strong>카올린 호수의 시각적 경이로움</strong>: 에메랄드빛 물과 눈처럼 하얀 지면이 대비를 이루는 <strong>카올린 호수</strong>를 직접 확인하세요. 사진 애호가라면 반드시 들러야 할 명소입니다.</p></li><li data-list-item-id=\"e37232cd9b9123041da299ba5f018b4a7\"><p style=\"text-align:justify;\"><strong>전설적인 미식 탐방</strong>: 현지의 정통 맛으로 여행을 완성하세요. 하루의 탐험 끝에 즐기는 따뜻한 <strong>벨리퉁 국수</strong>와 상큼한 <strong>꼰찌 오렌지 주스</strong>는 최고의 즐거움을 선사할 것입니다.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索“彩虹兵团”故乡之美：4天3夜 勿里洞专属之旅</strong></h2><p style=\"text-align:justify;\">准备好被印度尼西亚最热带的天堂之一——自然与文化的和谐之美所震撼吧！这趟 <strong>4天3夜</strong> 的行程专为带您深入探索勿里洞的每一处奇迹而设计：从启发世界的文学足迹，到充满魔力的古代花岗岩岛群。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须选择这个行程？</strong></h3><ul><li data-list-item-id=\"e069f1625bafd779ad9638fe5b5f928ff\"><p style=\"text-align:justify;\"><strong>正宗的彩虹兵团情怀</strong>：亲身前往 <strong>彩虹小学复制品</strong> 现场，并在色彩缤纷的 <strong>安德烈亚·希拉塔文字博物馆</strong> 拍照留念。在这里，您可以感受到这部动人传奇故事背后的深厚情感。</p></li><li data-list-item-id=\"eb41ab2e9f44eedd843d9ca1251856c81\"><p style=\"text-align:justify;\"><strong>标志性的跳岛冒险</strong>：征服勿里洞清澈见底的海水，访问 <strong>灯塔岛 (Lengkuas Island) 、沙岛 (Pulau Pasir) ，</strong>以及充满艺术感的 <strong>鹰头岩 (Garuda Head’s Rock)</strong> 和 <strong>帆船石 (Batu Berlayar)</strong>。千万不要错过探索神秘异域 <strong>里邦岛溶洞 (Goa Kelayang)</strong> 的奇妙体验。</p></li><li data-list-item-id=\"e97cd20227b0cd97cb3d4eb006617b1a5\"><p style=\"text-align:justify;\"><strong>巨型花岗岩的交响乐</strong>：在南勿里洞的标志——<strong>巴金德石 (Batu Baginde)</strong> 发现大自然的雄伟，并在迷人的 <strong>彭亚邦海滩 (Pantai Penyabong)</strong> 享受宁静时光。</p></li><li data-list-item-id=\"e04fd0b012b3b72dd0747982fa2602ccb\"><p style=\"text-align:justify;\"><strong>高岭湖的视觉奇观</strong>：亲眼见证 <strong>高岭湖 (Kaolin Lake)</strong> 翠蓝色湖水与雪白色土地之间的极致对比，这是摄影爱好者绝对不可错过的打卡胜地。</p></li><li data-list-item-id=\"e2de5205b0a3cf64adc082ed29b1f3c4a\"><p style=\"text-align:justify;\"><strong>传奇的美食盛宴</strong>：用最地道的本土滋味开启您的味蕾。在结束一天的行程后，来一碗热气腾腾的 <strong>勿里洞特色面条</strong> 配上清爽的 <strong>酸橘冰 (Es Jeruk Konci) ，</strong>是旅行中最完美的享受。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ed208b2cfc53b7e1cd6120decbc27b53a\"><p style=\"text-align:justify;\">Pick Up and Airport Transfer</p></li><li data-list-item-id=\"e7b46285ad46069a4dbda317d6558b085\"><p style=\"text-align:justify;\">Hotel (Twin/Triple)</p></li><li data-list-item-id=\"edd0549e72edf76d4166d39ac638c1bf7\"><p style=\"text-align:justify;\">Transportation AC</p></li><li data-list-item-id=\"e018bff0322140ca710ca44d7a9e449d9\"><p style=\"text-align:justify;\">Driver/Guide (English/Mandarin Speaking)</p></li><li data-list-item-id=\"e6146b786962db4598d3c2a8a89f1f3b2\"><p style=\"text-align:justify;\">3x breakfast, 3x lunch, 3x dinner</p></li><li data-list-item-id=\"e8a8c864def604330962a4d7eb4c222ea\"><p style=\"text-align:justify;\">1x Belitung Noodles + Jeruk Konci Ice Drink</p></li><li data-list-item-id=\"e8b6d80d13b39d99ab4e96db3ab3f50d0\"><p style=\"text-align:justify;\">1x Snack</p></li><li data-list-item-id=\"ec4c012d0bbe9907ae231cc419a754e8c\"><p style=\"text-align:justify;\">Entrance Fee &amp; Parking Fee</p></li><li data-list-item-id=\"eb5626c8c0b06831be3703a06985b3743\"><p style=\"text-align:justify;\">1x Mineral Water 600 ml / pax / day</p></li><li data-list-item-id=\"efc19752bf475a309f7d643d71dee29bb\"><p style=\"text-align:justify;\">Traditional Boat, Life Vest, Snorkeling Gear</p></li><li data-list-item-id=\"e301ecb58907ac593fa394d9d974b91b0\"><p style=\"text-align:justify;\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destination</p></li></ul>', '<ul><li data-list-item-id=\"ed9f752b7dfdbeaa48a7a712c6879f697\"><p style=\"text-align:justify;\">Airline Tickets</p></li><li data-list-item-id=\"efb1188a8a9ff7846aac59031ce1bea9e\"><p style=\"text-align:justify;\">Airport tax &amp; Additional baggage</p></li><li data-list-item-id=\"ece6adc9f3447ca93ae4b8e067c008eea\"><p style=\"text-align:justify;\">Rapid Test / PCR Test if any</p></li><li data-list-item-id=\"eba9794c776905dea1d41f2d70d8b2680\"><p style=\"text-align:justify;\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</p></li><li data-list-item-id=\"ef12a0f941b084379b405da51c2ba33e6\"><p style=\"text-align:justify;\">Travel Insurance</p></li><li data-list-item-id=\"e1b71f217ac36b059afcb3a6b2be37705\"><p style=\"text-align:justify;\">Single Supplement&nbsp;</p></li><li data-list-item-id=\"e69c8a8f52cde0851566c40f77ae905e5\"><p style=\"text-align:justify;\">Optional Tour</p></li><li data-list-item-id=\"ebda38bf5c7aa37cefa944c7270c93964\"><p style=\"text-align:justify;\">Watersport</p></li><li data-list-item-id=\"e2e68c3357d3057bba278bce66a982119\"><p style=\"text-align:justify;\">Tips for Driver/Guide @IDR 50.000/Pax/Day</p></li><li data-list-item-id=\"e0543e4c5f53386eb93bd2638efb570a0\"><p style=\"text-align:justify;\">High Season Surcharge</p></li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"CULINARY\"]', NULL, 0, 'hot', '2026-05-06 13:05:47', '2026-06-01 15:20:38'),
(53, 42, '4 DAYS BELITUNG LEEBONG TOUR', 'BANGKA BELITUNG', '4-days-belitung-leebong-tour', '<h2 style=\"text-align:justify;\"><strong>4D3N Private Leebong Island &amp; Granite Paradise Adventure</strong></h2><p style=\"text-align:justify;\">Jelajahi sisi paling eksklusif dari Pulau Belitung! Paket <strong>4 Hari 3 Malam</strong> ini adalah undangan bagi Anda yang mendambakan ketenangan di pulau privat, kemegahan formasi geologi purba, dan kejernihan laut yang tak tertandingi. Kami mengombinasikan kenyamanan fasilitas modern dengan kemurnian alam Belitung untuk menciptakan pengalaman liburan yang tak terlupakan.</p><h3 style=\"text-align:justify;\"><strong>Daya Tarik Utama Perjalanan Anda:</strong></h3><ul><li data-list-item-id=\"e7c95af5c26f50ae451b84d5cb4af43c0\"><p style=\"text-align:justify;\"><strong>Eksklusivitas Pulau Leebong</strong>: Rasakan kemewahan di pulau pribadi dengan fasilitas lengkap. Anda bebas menjelajahi hutan mangrove, bersepeda santai, mencoba <i>kayaking</i>, <i>stand paddling</i>, hingga voli pantai di hamparan pasir putih <strong>Chicas Beach</strong>.</p></li><li data-list-item-id=\"ebd267c78e3fd7601898d355c45ca6e8b\"><p style=\"text-align:justify;\"><strong>Keajaiban Geologi Batu Baginde</strong>: Berdiri terpaku di depan kemegahan <strong>Batu Baginde</strong>, batu granit raksasa yang menjadi ikon legendaris dari Belitung Selatan.</p></li><li data-list-item-id=\"e53ffa7735b7313a7f789e833dab4f144\"><p style=\"text-align:justify;\"><strong>Petualangan Island Hopping Ikonik</strong>: Menjelajahi gugusan pulau unik mulai dari <strong>Pulau Pasir</strong> yang muncul saat air surut, <strong>Pulau Batu Berlayar</strong>, hingga melakukan snorkeling di sekitar mercusuar kuno <strong>Pulau Lengkuas</strong>.</p></li><li data-list-item-id=\"e9527a3f1a96b01db184facced6401b65\"><p style=\"text-align:justify;\"><strong>Eksplorasi Goa Kelayang</strong>: Masuki petualangan tersembunyi di <strong>Goa Kelayang</strong>, sebuah formasi batu granit eksotis yang memberikan sensasi berada di dunia lain.</p></li><li data-list-item-id=\"e004c89ee37c46e12f1959bd6a264b831\"><p style=\"text-align:justify;\"><strong>Panorama Danau Kaolin</strong>: Nikmati keindahan visual yang memukau di <strong>Danau Kaolin</strong>, di mana air biru toska bertemu dengan daratan putih bersih, menciptakan latar foto yang sempurna.</p></li><li data-list-item-id=\"efc7dbe03a4030dace56e521390a688c6\"><p style=\"text-align:justify;\"><strong>Warisan Laskar Pelangi</strong>: Mengunjungi lokasi ikonik <strong>Pantai Tanjung Tinggi</strong> dan <strong>Replika SD Laskar Pelangi</strong> untuk merasakan langsung semangat cerita yang menginspirasi dunia.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4D3N Private Leebong Island &amp; Granite Paradise Adventure</strong></h2><p style=\"text-align:justify;\">Explore the most exclusive side of Belitung Island! This <strong>4 Days 3 Nights</strong> package is an invitation for those who long for the tranquility of a private island, the majesty of ancient geological formations, and crystal-clear seas. We combine modern comfort with the pure nature of Belitung to create an unforgettable holiday experience.</p><h3 style=\"text-align:justify;\"><strong>Tour Highlights:</strong></h3><ul><li data-list-item-id=\"eb2c224d771c8c5ed768ce3e1d96562bf\"><p style=\"text-align:justify;\"><strong>Leebong Island Exclusivity</strong>: Experience luxury on a private island with complete facilities. You are free to explore mangrove forests, cycle, try kayaking, stand-up paddling, or play beach volleyball on the white sands of <strong>Chicas Beach</strong>.</p></li><li data-list-item-id=\"e3f2a21984ed096e93448c204826cb3a3\"><p style=\"text-align:justify;\"><strong>Batu Baginde Geological Wonder</strong>: Stand in awe before the grandeur of <strong>Batu Baginde</strong>, a giant granite boulder that is a legendary icon of South Belitung.</p></li><li data-list-item-id=\"eb80f603d4383d0dafdf72aa88a06af6c\"><p style=\"text-align:justify;\"><strong>Iconic Island-Hopping Adventure</strong>: Explore unique island clusters starting from <strong>Sand Island</strong> (Pulau Pasir), <strong>Batu Berlayar Island</strong>, to snorkeling around the ancient lighthouse of <strong>Lengkuas Island</strong>.</p></li><li data-list-item-id=\"ecd2690d5684d3a6d3a362d49c8a3d4c8\"><p style=\"text-align:justify;\"><strong>Kelayang Cave Exploration</strong>: Enter a hidden adventure in <strong>Kelayang Cave</strong>, an exotic granite formation that feels like another world.</p></li><li data-list-item-id=\"e492cdff0e58b0352eae53a19856f3621\"><p style=\"text-align:justify;\"><strong>Kaolin Lake Panorama</strong>: Enjoy the stunning visual beauty of <strong>Kaolin Lake</strong>, where turquoise water meets bright white land, creating a perfect photo backdrop.</p></li><li data-list-item-id=\"ec94b95b0b62b77d6c5921fd5aff93ba4\"><p style=\"text-align:justify;\"><strong>Laskar Pelangi Heritage</strong>: Visit the iconic <strong>Tanjung Tinggi Beach</strong> and the <strong>Laskar Pelangi School Replica</strong> to feel the spirit of the story that inspired the world.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4박 3일 프라이빗 리봉 아일랜드 &amp; 그래니트 파라다이스 어드벤처</strong></h2><p style=\"text-align:justify;\">벨리퉁섬의 가장 독점적인 면을 탐험해 보세요! 이 <strong>4박 3일</strong> 패키지는 프라이빗 아일랜드의 평온함, 고대 지질 형성의 웅장함, 그리고 수정처럼 맑은 바다를 갈망하는 분들을 위한 초대장입니다. 현대적인 편리함과 벨리퉁의 순수한 자연을 결합하여 잊지 못할 휴가 경험을 선사합니다.</p><h3 style=\"text-align:justify;\"><strong>투어 하이라이트:</strong></h3><ul><li data-list-item-id=\"ed0983543e64d2742cc5e7202df75ee83\"><p style=\"text-align:justify;\"><strong>리봉 아일랜드의 독점성</strong>: 완벽한 시설을 갖춘 프라이빗 아일랜드에서 럭셔리함을 경험하세요. 망그로브 숲 탐험, 자전거 타기, 카약, 스탠드업 패들링은 물론 치카스 비치(Chicas Beach)의 하얀 모래사장 위에서 비치 발리볼을 자유롭게 즐길 수 있습니다.</p></li><li data-list-item-id=\"e83ceaf6faffc8129f244f26ecb1e7461\"><p style=\"text-align:justify;\"><strong>바투 바긴데의 지질학적 경이로움</strong>: 남부 벨리퉁의 전설적인 아이콘인 거대 화강암 바위 바투 바긴데(Batu Baginde)의 웅장함 앞에 서보세요.</p></li><li data-list-item-id=\"e28f3501af1698252d8c46df8d84bf5d4\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑 어드벤처</strong>: 바닷길이 열릴 때 나타나는 모래 섬(Pulau Pasir)부터 <strong>바투 버를라야르 섬</strong>, 그리고 고대 등대가 있는 <strong>렝쿠아스 섬</strong> 주변에서의 스노클링까지 독특한 섬들을 탐험합니다.</p></li><li data-list-item-id=\"e660b30da855664298e84e219c5d2e4d3\"><p style=\"text-align:justify;\"><strong>끌라양 동굴 탐험</strong>: 다른 세상에 온 듯한 이국적인 화강암 지형인 끌라양 동굴(Goa Kelayang)에서 숨겨진 모험을 시작하세요.</p></li><li data-list-item-id=\"eab62fe53ec0044764dda94d542591b3a\"><p style=\"text-align:justify;\"><strong>카올린 호수의 파노라마</strong>: 터키석 빛깔의 물과 눈부시게 하얀 지면이 만나 완벽한 사진 배경을 만들어내는 <strong>카올린 호수</strong>의 환상적인 시각적 아름다움을 즐겨보세요.</p></li><li data-list-item-id=\"e790a35ed933bf97dd1a854d266c56770\"><p style=\"text-align:justify;\"><strong>무지개 부대(Laskar Pelangi)의 유산</strong>: 아이코닉한 <strong>탄중 띵기 해변</strong>과 <strong>무지개 부대 학교 복제본</strong>을 방문하여 전 세계에 영감을 준 이야기의 감동을 직접 느껴보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>4天3夜 里邦岛专属之旅与花岗岩天堂冒险</strong></h2><p style=\"text-align:justify;\">探索勿里洞岛最独特的一面！这趟 <strong>4天3夜</strong> 的行程是为那些渴望私密岛屿的宁静、古代地质结构的雄伟以及清澈见底的大海的游客量身定制的。我们将现代舒适与勿里洞的纯净自然相结合，为您打造难忘的度假体验。</p><h3 style=\"text-align:justify;\"><strong>行程亮点：</strong></h3><ul><li data-list-item-id=\"e16e51596cb07702f4ad9faa51d4f9181\"><p style=\"text-align:justify;\"><strong>里邦岛 (Leebong Island) 的专属体验</strong>：在设施齐全的私人岛屿上尽享奢华。您可以自由探索红树林、骑自行车、尝试皮划艇、桨板冲浪，或在 <strong>Chicas Beach</strong> 的白沙滩上打沙滩排球。</p></li><li data-list-item-id=\"e3dce8228bd9991e4b77a1131a0ec709a\"><p style=\"text-align:justify;\"><strong>巴金德石 (Batu Baginde) 地质奇观</strong>：伫立在南勿里洞标志性的巨型花岗岩巨石——<strong>巴金德石</strong>前，感受大自然的雄伟。</p></li><li data-list-item-id=\"e800af75133ff0cfcea873eba0eb19346\"><p style=\"text-align:justify;\"><strong>标志性的跳岛冒险</strong>：探索独特的岛屿群，包括退潮时出现的 <strong>沙岛 (Pulau Pasir) 、帆船石 (Batu Berlayar)</strong>，以及在 <strong>灯塔岛 (Lengkuas Island)</strong> 古老灯塔周围浮潜。</p></li><li data-list-item-id=\"e38d341efd5362b7d51f080422a7f7b1f\"><p style=\"text-align:justify;\"><strong>里邦岛溶洞 (Goa Kelayang) 探险</strong>：进入 <strong>里邦岛溶洞</strong> 开启隐秘冒险，这个充满异国情调的花岗岩构造让您仿佛置身于另一个世界。</p></li><li data-list-item-id=\"e8a6b5c9f7e93454b4e2e8c12401b0fa2\"><p style=\"text-align:justify;\"><strong>高岭湖 (Kaolin Lake) 全景</strong>：欣赏 <strong>高岭湖</strong> 令人惊叹的视觉美景，碧蓝的湖水与雪白的土地交相辉映，构成绝佳的摄影背景。</p></li><li data-list-item-id=\"ea6e4ae8cdc785cb740931f47ffe4c131\"><p style=\"text-align:justify;\"><strong>彩虹兵团 (Laskar Pelangi) 文化遗产</strong>：参观标志性的 <strong>丹绒丁宜海滩 (Tanjung Tinggi Beach)</strong> 和 <strong>彩虹小学复制品</strong>，亲身感受这部启发全球的故事精神。</p></li></ul>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"e1331474a7a1ca1f9619890e65127e226\">Pick Up and Airport Transfer</li><li data-list-item-id=\"ea90e73a083dbb2d4639d71d8717c8912\">Hotel (Twin/Triple)</li><li data-list-item-id=\"e27fc81945459f4f1806b38f011b98b7a\">Transportation AC</li><li data-list-item-id=\"e66ae9efe85d988b1e6117f4b0b2ddf85\">Driver/Guide (English/Mandarin Speaking)</li><li data-list-item-id=\"ed4419b68ee646d75e7bc7318ca9e1af4\">3x breakfast, 3x lunch, 3x dinner</li><li data-list-item-id=\"ed55051200bb56589066ddd04f7d91e85\">1x Belitung Noodles + Jeruk Konci Ice Drink</li><li data-list-item-id=\"ef445d82fd9b62fecded829cd93889175\">1x Snack</li><li data-list-item-id=\"e5a31653a54dbce0790516cbc72dd6e7f\">Entrance Fee &amp; Parking Fee</li><li data-list-item-id=\"ecdddddd8062543330412a0108e5f21c6\">1x Mineral Water 600 ml / pax / day</li><li data-list-item-id=\"e6260d87586fc0088c9f326b4f9895dda\">Traditional Boat, Life Vest, Snorkeling Gear</li><li data-list-item-id=\"e1c941600c11a7cadd2796c45ab7c11d9\">Traditional Boat to Leebong Island</li><li data-list-item-id=\"e16c7b4526a798aabefbb0353ce9399a1\">Public Facility at Leebong Island</li><li data-list-item-id=\"ecc61a6860564e56dbac4f47438864726\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destination</li></ul>', '<ul><li data-list-item-id=\"ea18cbda8dbdd4471ad27ce22fd08c19d\">Airline Tickets</li><li data-list-item-id=\"ed1ba615b7c225652a1f848060d7a09d1\">Airport tax &amp; Additional baggage</li><li data-list-item-id=\"ea9d4edbab47e21e60a925166114b3605\">Rapid Test / PCR Test if any</li><li data-list-item-id=\"e856164842bd5ef0ab25ad0d0c0139b80\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</li><li data-list-item-id=\"ea67bb22a9a42348ef2c9f33e151d62a2\">Travel Insurance</li><li data-list-item-id=\"e2be198a6054dfe90d2eb9e5824a68591\">Single Supplement&nbsp;</li><li data-list-item-id=\"e34e102fff3d630f27902728bd53883fd\">Optional Tour</li><li data-list-item-id=\"ec0abb6265a74e65dc76b1b07c78cca93\">Watersport</li><li data-list-item-id=\"eb956c5aa3e3cce449254d815d3113ad3\">Tips for Driver/Guide @IDR 50.000/Pax/Day</li><li data-list-item-id=\"e588da8f72343f6999dbed80b4bfc20b5\">High Season Surcharge</li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\"]', NULL, 0, NULL, '2026-05-06 13:33:21', '2026-05-29 14:43:54'),
(54, 42, '3 DAYS BELITUNG TOUR', 'BANGKA BELITUNG', '3-days-belitung-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Tropis: 3D2N Belitung Tour – Jejak Laskar Pelangi &amp; Keajaiban Granit</strong></h2><p style=\"text-align:justify;\">Ingin melarikan diri sejenak ke pulau dengan pasir putih selembut bedak dan air laut sebening kristal? Bergabunglah dalam perjalanan <strong>3 Hari 2 Malam</strong> yang tak terlupakan bersama kami untuk mengeksplorasi setiap sudut eksotis Pulau Belitung!</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Mencoba Paket Ini?</strong></h3><p style=\"text-align:justify;\"><strong>1. Hidupkan Kembali Kisah \"Laskar Pelangi\"</strong> Jelajahi sisi emosional dan bersejarah Belitung Timur. Anda akan mengunjungi <strong>Replika SD Laskar Pelangi</strong> yang ikonik, berfoto di <strong>Museum Kata Andrea Hirata</strong> yang penuh warna, hingga singgah di <strong>Kampoeng Fifi</strong>. Ini adalah perjalanan nostalgia yang membawa Anda langsung ke dalam setting film legendaris tersebut.</p><p style=\"text-align:justify;\"><strong>2. Petualangan Island Hopping yang Spektakuler</strong> Siapkan kamera Anda! Kita akan berlayar mengunjungi deretan pulau mungil nan cantik:</p><ul><li data-list-item-id=\"ecca727ee74751a0d0c38bc3aef7a82da\"><p style=\"text-align:justify;\"><strong>Pulau Lengkuas:</strong> Snorkeling di antara terumbu karang dan berfoto dengan latar mercusuar tua yang megah.</p></li><li data-list-item-id=\"e683e5eb3d8673a678f9ad6dac964b73e\"><p style=\"text-align:justify;\"><strong>Batu Garuda &amp; Pulau Batu Berlayar:</strong> Formasi batu granit raksasa yang artistik dan hanya bisa ditemukan di Belitung.</p></li><li data-list-item-id=\"e3aa3b48fda9a944da22e7821f93936ee\"><p style=\"text-align:justify;\"><strong>Goa Kelayang:</strong> Temukan sisi petualang Anda di dalam goa batu yang unik.</p></li></ul><p style=\"text-align:justify;\"><strong>3. Keajaiban Alam yang Fotogenik</strong> Dari fenomena biru toska di <strong>Danau Kaolin</strong> hingga formasi granit raksasa di <strong>Batu Baginde</strong> dan <strong>Pantai Tanjung Tinggi</strong>, setiap sudut Belitung adalah latar foto yang sempurna untuk media sosial Anda.</p><p style=\"text-align:justify;\"><strong>4. Pesta Kuliner Otentik</strong> Tidak hanya mata, lidah Anda pun akan dimanjakan. Nikmati kesegaran <strong>Mie Belitung</strong> yang legendaris dipadukan dengan segarnya <strong>Es Jeruk Konci</strong>, serta jamuan makan malam lokal yang akan melengkapi pengalaman budaya Anda.</p>', '<h2 style=\"text-align:justify;\"><strong>Explore Tropical Paradise: 3D2N Belitung Tour – The Footsteps of Laskar Pelangi &amp; Granite Wonders</strong></h2><p style=\"text-align:justify;\">Dreaming of a getaway to an island with powdery white sand and crystal-clear turquoise waters? Join our unforgettable <strong>3-Day 2-Night</strong> journey to explore every exotic corner of Belitung Island!</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour?</strong></h3><ul><li data-list-item-id=\"e956fba909982e4ade277243db5814246\"><p style=\"text-align:justify;\"><strong>Relive the \"Laskar Pelangi\" Story:</strong> Explore the emotional and historical side of East Belitung by visiting the iconic <strong>Laskar Pelangi Elementary School Replica</strong> and the colorful <strong>Andrea Hirata Words Museum</strong>.</p></li><li data-list-item-id=\"e40bf30be0e56150a058df9734d92305d\"><p style=\"text-align:justify;\"><strong>Spectacular Island Hopping:</strong> Sail through beautiful islets including <strong>Lengkuas Island</strong> for snorkeling, the majestic <strong>Garuda Head’s Rock</strong>, and the unique <strong>Kelayang Cave</strong>.</p></li><li data-list-item-id=\"ebcc686bb1a05363453743570c9688d26\"><p style=\"text-align:justify;\"><strong>Photogenic Natural Wonders:</strong> From the turquoise phenomenon of <strong>Kaolin Lake</strong> to the giant granite formations at <strong>Tanjung Tinggi Beach</strong>, every spot is a perfect backdrop for your social media.</p></li><li data-list-item-id=\"ee52138e19851a08b6a0ba8dbc5b2fc3f\"><p style=\"text-align:justify;\"><strong>Authentic Culinary Feast:</strong> Pamper your taste buds with the legendary <strong>Belitung Noodles</strong> and refreshing <strong>Konci Orange Ice</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>인도네시아의 숨겨진 보석: 3박 2일 벨리퉁 투어 – 무지개 학교와 거대 화강암의 신비</strong></h2><p style=\"text-align:justify;\">파우더처럼 부드러운 하얀 모래와 투명한 에메랄드빛 바다를 꿈꾸시나요? 벨리퉁섬의 모든 이국적인 매력을 발견할 수 있는 특별한 <strong>3박 2일</strong> 여정에 초대합니다!</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e2b6f6a276f791ad7d8cf3020008b9979\"><p style=\"text-align:justify;\"><strong>영화 \'무지개 학교(Laskar Pelangi)\'의 감동:</strong> 아이코닉한 <strong>무지개 학교 복제본</strong>과 알록달록한 <strong>안드레아 히라타 단어 박물관</strong>을 방문하여 영화 속 감동을 직접 느껴보세요.</p></li><li data-list-item-id=\"e14c685db73a979785d2bdb05eddd46b5\"><p style=\"text-align:justify;\"><strong>환상적인 아일랜드 호핑:</strong> 능쿠아스 섬(Pulau Lengkuas)에서 스노클링을 즐기고, 거대한 독수리 모양의 <strong>가루다 바위</strong>와 신비로운 <strong>끌라양 동굴</strong>을 탐험합니다.</p></li><li data-list-item-id=\"e718b7978211003d436ef8cf0a725a247\"><p style=\"text-align:justify;\"><strong>인생샷 보장 명소:</strong> 인스타그램에 딱 어울리는 <strong>카오린 호수</strong>의 푸른 빛과 <strong>탄중 팅기 해변</strong>의 거대 화강암 기암괴석이 여러분을 기다립니다.</p></li><li data-list-item-id=\"e576ed7a749b18015a7c6a802a6ccde28\"><p style=\"text-align:justify;\"><strong>미식의 즐거움:</strong> 벨리퉁의 명물 <strong>벨리퉁 국수</strong>와 상큼한 <strong>콘치 오렌지 주스</strong>로 현지의 맛을 제대로 즐겨보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索热带天堂：3天2夜勿里洞之旅 – 寻访《彩虹战士》与花岗岩奇观</strong></h2><p style=\"text-align:justify;\">想要逃离喧嚣，前往拥有粉末般白沙和清澈见底海水的岛屿吗？加入我们难忘的 <strong>3天2夜</strong> 之旅，探索勿里洞岛（Belitung）的每一个异国角落！</p><h3 style=\"text-align:justify;\"><strong>为什么您必须选择此行程？</strong></h3><ul><li data-list-item-id=\"e855c7da25b976eb56f4342c2089167fc\"><p style=\"text-align:justify;\"><strong>重温《彩虹战士》的故事：</strong> 参观标志性的<strong>彩虹战士小学复制品</strong>和色彩缤纷的<strong>安德烈亚·希拉塔文字博物馆</strong>，感受这部传奇电影的历史与情感。</p></li><li data-list-item-id=\"e0ae820dd212761f14abeb502147afb35\"><p style=\"text-align:justify;\"><strong>壮观的出海跳岛游：</strong> 乘船前往<strong>连阔士岛（Pulau Lengkuas）进行浮潜，欣赏壮丽的鹰头岩</strong>，并探索独特的<strong>格拉扬岩洞</strong>。</p></li><li data-list-item-id=\"ec5b5045de0a83cab0c17b1d4cb9c0e4e\"><p style=\"text-align:justify;\"><strong>极具魅力的自然奇观：</strong> 从蔚蓝的<strong>高岭湖</strong>到<strong>丹绒丁宜海滩</strong>的巨型花岗岩群，每一个角落都是完美的社交媒体背景。</p></li><li data-list-item-id=\"e8ec9f3893f7e6589a45955ad71536048\"><p style=\"text-align:justify;\"><strong>地道的美食盛宴：</strong> 品尝传奇的<strong>勿里洞面条（Mie Belitung）和清爽的酸柑冰（Es Jeruk Konci）</strong>，满足您的味蕾。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ecbebf8d801c5ff62bfcaa36d84a0377c\"><p style=\"text-align:justify;\">Pick Up and Airport Transfer</p></li><li data-list-item-id=\"ec27c41669e9a9917d74a7b5b98c43d0c\"><p style=\"text-align:justify;\">Hotel (Twin/Triple)</p></li><li data-list-item-id=\"e04332354ca9838311ed744241cc0dec0\"><p style=\"text-align:justify;\">Transportation AC</p></li><li data-list-item-id=\"ef5e3b98065b3785d4e736cd66001e6aa\"><p style=\"text-align:justify;\">Driver/Guide (English/Mandarin Speaking)</p></li><li data-list-item-id=\"eeb053fea9643b83b5b025c797475848e\"><p style=\"text-align:justify;\">2x breakfast, 2x lunc, 2x dinner</p></li><li data-list-item-id=\"ec2581ec40d64633b1e29dc64124bd8ce\"><p style=\"text-align:justify;\">1x Belitung Noodles + Jeruk Konci Ice Drink</p></li><li data-list-item-id=\"eccaa130117b335a407e5fbc287f231c7\"><p style=\"text-align:justify;\">1x Snack</p></li><li data-list-item-id=\"e0a61605deb67df61b2782ea3f3ce306d\"><p style=\"text-align:justify;\">Entrance Fee &amp; Parking Fee</p></li><li data-list-item-id=\"eb01dbd111444335fbb72d969d851197b\"><p style=\"text-align:justify;\">1x Mineral Water 600 ml / pax / day</p></li><li data-list-item-id=\"eaac4d431fafa29cb375465a44026c6a6\"><p style=\"text-align:justify;\">Traditional Boat, Life Vest, Snorkeling Gear</p></li><li data-list-item-id=\"e6a622e68784c5d859a07e49875558cc2\"><p style=\"text-align:justify;\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destination</p></li></ul>', '<ul><li data-list-item-id=\"ece83ecf7dd1f41b397cb396fd32ef59a\"><p style=\"text-align:justify;\">Airline Tickets</p></li><li data-list-item-id=\"e3a0e24f20a0e1be15a47f43c9ad9cbbb\"><p style=\"text-align:justify;\">Airport tax &amp; Additional baggage</p></li><li data-list-item-id=\"e25d4bbeb28e45df06feb68f25753ae5e\"><p style=\"text-align:justify;\">Rapid Test / PCR Test if any</p></li><li data-list-item-id=\"ed40d8233c72a1d9d83eff4f0628583cf\"><p style=\"text-align:justify;\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</p></li><li data-list-item-id=\"e4a189a82b20b47ebc8648de6ad76e538\"><p style=\"text-align:justify;\">Travel Insurance</p></li><li data-list-item-id=\"ec03157fa3e4a536f801e1b55754a7ec8\"><p style=\"text-align:justify;\">Single Supplement&nbsp;</p></li><li data-list-item-id=\"ecb40530a1d22d805c99a72a093e0c556\"><p style=\"text-align:justify;\">Optional Tour</p></li><li data-list-item-id=\"ecf60d0ca33f037d7d5790ecb4e27dd37\"><p style=\"text-align:justify;\">Watersport</p></li><li data-list-item-id=\"ea4ca8595d06d925da7f190f1b01157e6\"><p style=\"text-align:justify;\">Tips for Driver/Guide @IDR 50.000/Pax/Day</p></li><li data-list-item-id=\"eb75c6d442ec4e551d517b804a047210b\"><p style=\"text-align:justify;\">High Season Surcharge</p></li></ul>', NULL, '[\"Nature\",\"Culture\",\"Beach\",\"culinary\"]', NULL, 0, NULL, '2026-05-06 13:45:04', '2026-05-29 14:42:27'),
(55, 42, '3 DAYS BELITUNG LEEBONG TOUR', 'BANGKA BELITUNG', '3-days-belitung-leebong-tour', '<h2 style=\"text-align:justify;\"><strong>Rasakan Kemewahan Tropis: 3D2N Belitung Leebong Tour – Petualangan Eksklusif di Pulau Pribadi &amp; Laut Kristal</strong></h2><p style=\"text-align:justify;\">Siap untuk melarikan diri ke destinasi yang menggabungkan ketenangan pulau pribadi dengan petualangan laut yang mendebarkan? Paket <strong>3 Hari 2 Malam</strong> ini dirancang khusus untuk Anda yang mendambakan pelarian sempurna ke \"Maldives-nya Indonesia\".</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"e044c8894a597c8ad06832c4fbdbbed42\"><p style=\"text-align:justify;\"><strong>Eksklusivitas di Pulau Leebong:</strong> Rasakan sensasi memiliki pulau pribadi! Dari bersepeda santai di jalur hutan, bermain <i>kayaking</i> di air tenang, hingga <i>stand paddling</i> saat matahari terbenam, Pulau Leebong menawarkan kemewahan aktivitas yang tak terbatas.</p></li><li data-list-item-id=\"ec1f9d2090ddeb27f14ae41b35bb21899\"><p style=\"text-align:justify;\"><strong>Keajaiban Pulau Pasir &amp; Bintang Laut:</strong> Nikmati momen ajaib berjalan di atas gundukan pasir putih di tengah laut, ditemani oleh bintang laut yang cantik (tergantung cuaca) dalam perjalanan menuju surga tropis Anda.</p></li><li data-list-item-id=\"ebf9a058495d00a51be1ef447ec4d3d26\"><p style=\"text-align:justify;\"><strong>Snorkeling di Perairan Ikonik:</strong> Jelajahi kekayaan bawah laut di sekitar <strong>Pulau Lengkuas</strong> yang legendaris, dan abadikan momen unik dengan latar belakang <strong>Batu Garuda</strong> yang megah serta <strong>Goa Kelayang</strong> yang eksotis.</p></li><li data-list-item-id=\"ef92d8446801c496ee27afb0ac6dc062b\"><p style=\"text-align:justify;\"><strong>Jejak Film Laskar Pelangi:</strong> Kunjungi langsung <strong>Pantai Tanjung Tinggi</strong>, pantai ikonik dengan formasi batu granit raksasa yang menjadi lokasi syuting film legendaris <i>Laskar Pelangi</i>.</p></li><li data-list-item-id=\"e1cdc1417b311fc6f9d43fee31af01daf\"><p style=\"text-align:justify;\"><strong>Fenomena Visual Danau Kaolin:</strong> Tutup perjalanan Anda dengan pemandangan surealis <strong>Danau Kaolin</strong>, perpaduan kontras antara air biru toska yang jernih dan daratan putih bersih yang sangat fotogenik.</p></li><li data-list-item-id=\"e2df55bbe3a23c972764cddb2b819de67\"><p style=\"text-align:justify;\"><strong>Wisata Kuliner Legendaris:</strong> Manjakan lidah Anda dengan cita rasa lokal yang otentik melalui sajian <strong>Mie Belitung</strong> yang gurih dan kesegaran <strong>Es Jeruk Konci</strong> yang melegenda.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Experience Tropical Luxury: 3D2N Belitung Leebong Tour – Exclusive Private Island Adventure &amp; Crystal Waters</strong></h2><p style=\"text-align:justify;\">Ready to escape to a destination that combines the tranquility of a private island with thrilling marine adventures? This <strong>3-Day 2-Night</strong> package is perfectly designed for those seeking a dream getaway to the \"Maldives of Indonesia\".</p><h3 style=\"text-align:justify;\"><strong>Why You Must Book This Tour?</strong></h3><ul><li data-list-item-id=\"ea3febdbbab2bd0adbbc29f5bc1411a5c\"><p style=\"text-align:justify;\"><strong>Exclusivity on Leebong Island:</strong> Feel the sensation of owning a private island! From leisurely cycling through forest paths and kayaking in calm waters to stand-up paddling at sunset, Leebong Island offers endless luxury activities.</p></li><li data-list-item-id=\"e36a386aef57aa3a75607a24ac4f78b70\"><p style=\"text-align:justify;\"><strong>Magic of Sand Island &amp; Starfish:</strong> Experience the magical moment of walking on a white sandbar in the middle of the ocean, accompanied by beautiful starfish (weather permitting) on your way to tropical paradise.</p></li><li data-list-item-id=\"edc71360dff65657dd1f018d755db13e8\"><p style=\"text-align:justify;\"><strong>Snorkeling in Iconic Waters:</strong> Explore the rich underwater world around the legendary <strong>Lengkuas </strong>Island and capture unique moments with the majestic <strong>Garuda Head’s Rock</strong> and exotic <strong>Kelayang Cave</strong> as your backdrop.</p></li><li data-list-item-id=\"e88d00c3fe5a42f337cf496bf1f869b4a\"><p style=\"text-align:justify;\"><strong>Laskar Pelangi Film Trails:</strong> Visit <strong>Tanjung Tinggi Beach</strong>, the iconic location famous for its giant granite rock formations featured in the legendary movie <i>Laskar Pelangi</i>.</p></li><li data-list-item-id=\"e229bb52856b8addaa1b752188971ab4a\"><p style=\"text-align:justify;\"><strong>The Visual Phenomenon of Kaolin Lake:</strong> End your journey with the surreal view of <strong>Kaolin Lake</strong>, featuring a stunning contrast between bright turquoise water and pure white land.</p></li><li data-list-item-id=\"ecb597fa972fd088219748b1fa51d5c1f\"><p style=\"text-align:justify;\"><strong>Legendary Culinary Journey:</strong> Treat your taste buds to authentic local flavors with savory <strong>Belitung Noodles</strong> and the legendary refreshing <strong>Konci Orange Ice</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>열대 낙원의 럭셔리: 3박 2일 벨리퉁 리봉 투어 – 프라이빗 아일랜드 어드벤처와 크리스탈 바다</strong></h2><p style=\"text-align:justify;\">프라이빗 아일랜드의 평온함과 스릴 넘치는 해양 어드벤처가 어우러진 곳으로 떠날 준비가 되셨나요? 이번 <strong>3박 2일</strong> 패키지는 \"인도네시아의 몰디브\"라 불리는 벨리퉁으로의 완벽한 탈출을 꿈꾸는 분들을 위해 설계되었습니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e3c14cbaa4485a375698fc7bc4ee34cd5\"><p style=\"text-align:justify;\"><strong>리봉 섬(Leebong Island)의 독점적 경험:</strong> 마치 섬 전체를 소유한 듯한 기분을 느껴보세요! 숲길 자전거 라이딩, 잔잔한 바다에서의 카약킹, 노을 속의 스탠드업 패들링까지 리봉 섬은 무한한 즐거움을 선사합니다.</p></li><li data-list-item-id=\"e324ec5736629773037cc4aee7858fbdc\"><p style=\"text-align:justify;\"><strong>모래 섬과 불가사리의 마법:</strong> 에메랄드빛 바다 한가운데 나타나는 하얀 모래 언덕 위를 걷고, 예쁜 불가사리들을 만나는 마법 같은 순간을 경험해 보세요 (기상 상황에 따라 다름).</p></li><li data-list-item-id=\"e9974eb3b2a1c4473c021fddd26c2f3e0\"><p style=\"text-align:justify;\"><strong>아이코닉한 바다에서의 스노클링:</strong> 전설적인 <strong>능쿠아스 섬(Lengkuas Island)</strong> 주변의 풍부한 수중 세계를 탐험하고, 거대한 <strong>가루다 바위</strong>와 신비로운 <strong>끌라양 동굴</strong>을 배경으로 특별한 순간을 기록하세요.</p></li><li data-list-item-id=\"e5e3455f8f0696758fb45cc877776827d\"><p style=\"text-align:justify;\"><strong>영화 \'무지개 학교(Laskar Pelangi)\'의 흔적:</strong> 거대 화강암 기암괴석으로 유명한 영화 촬영지, <strong>탄중 팅기 해변</strong>을 직접 방문해 보세요.</p></li><li data-list-item-id=\"ebe7485d26d938f09e32180f9b75e0869\"><p style=\"text-align:justify;\"><strong>카오린 호수의 신비로운 절경:</strong> 초현실적인 푸른 빛의 물과 하얀 땅이 대비를 이루는 <strong>카오린 호수</strong>에서 여행의 마지막 인생샷을 남겨보세요.</p></li><li data-list-item-id=\"e147a92b70a0dd18d458b6ecf7fc73a75\"><p style=\"text-align:justify;\"><strong>전설적인 로컬 미식 투어:</strong> 고소한 <strong>벨리퉁 국수</strong>와 상큼함의 대명사인 <strong>콘치 오렌지 주스</strong>로 벨리퉁의 진정한 맛을 느껴보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>开启热带奢华之旅：3天2夜勿里洞里邦岛之旅 – 私人岛屿冒险与晶莹海域</strong></h2><p style=\"text-align:justify;\">准备好前往一个结合了私人岛屿的宁静与刺激海洋冒险的目的地了吗？这套 <strong>3天2夜</strong> 的行程专为向往“印尼马尔代夫”完美假期的人士而设计。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须选择此行程？</strong></h3><ul><li data-list-item-id=\"ea50a195287456f11e6ffdeedb3695575\"><p style=\"text-align:justify;\"><strong>里邦岛（Leebong Island）的尊享体验：</strong> 感受拥有私人岛屿的震撼！ 从穿越森林小径的悠闲骑行、在平静海面划皮划艇，到夕阳下的立式划桨，里邦岛提供无限的奢华活动体验。</p></li><li data-list-item-id=\"e11e253102d62fab154d74737db329e52\"><p style=\"text-align:justify;\"><strong>沙岛与海星的奇迹：</strong> 在前往热带天堂的途中，体验在海中央纯白沙洲上漫步的奇妙时刻，还能与可爱的海星近距离接触（视天气情况而定）。</p></li><li data-list-item-id=\"e85e69aeeff77db0b01ff94db70a7caec\"><p style=\"text-align:justify;\"><strong>标志性海域浮潜：</strong> 探索传奇的<strong>连阔士岛（Lengkuas Island）周边的丰富水下世界，并在雄伟的鹰头岩</strong>和神秘的<strong>格拉扬岩洞</strong>前留下独特的合影。</p></li><li data-list-item-id=\"e58bea214a810d9f361060121a2c40fc4\"><p style=\"text-align:justify;\"><strong>《彩虹战士》电影足迹：</strong> 亲临<strong>丹绒丁宜海滩</strong>，欣赏作为经典电影《彩虹战士》取景地的巨型花岗岩阵奇观。</p></li><li data-list-item-id=\"eee46478802fada64341486374efabf51\"><p style=\"text-align:justify;\"><strong>高岭湖的视觉盛宴：</strong> 以<strong>高岭湖</strong>的超现实美景结束旅程，欣赏蔚蓝湖水与洁白大地交相辉映的迷人对比。</p></li><li data-list-item-id=\"e632b108c612fad30743b495c28744e4d\"><p style=\"text-align:justify;\"><strong>传奇地道美食：</strong> 尽情品尝正宗的本地风味，包括美味的<strong>勿里洞面条</strong>和传奇般清爽的<strong>酸柑冰（Es Jeruk Konci）</strong>。</p></li></ul>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ea368a7b914304c12f7514a6853a282bd\">Pick Up and Airport Transfer</li><li data-list-item-id=\"e5007ef8463bc2bb0528a24865e312bdb\">Hotel (Twin/Triple)</li><li data-list-item-id=\"e0565470be28b52ffe59ce1022d4d5f2e\">Transportation AC</li><li data-list-item-id=\"ee0ab5b5dbbc48be3b6e604dddd5a4348\">Driver/Guide (English/Mandarin Speaking)</li><li data-list-item-id=\"e618acc088aa1a9cb852aca496407149c\">2x breakfast, 2x lunch, 2x dinner</li><li data-list-item-id=\"e112fb966ca4efa39a09f5200dab4001e\">1x Belitung Noodles + Jeruk Konci Ice Drink</li><li data-list-item-id=\"e50e483b9d850a3dccbd4030979faedda\">1x Snack</li><li data-list-item-id=\"eb522c1d6be123844bda8ff4354ea568c\">Entrance Fee &amp; Parking Fee</li><li data-list-item-id=\"e7ef1da82126a6458e2f2061ff67c33ef\">1x Mineral Water 600 ml / pax / day</li><li data-list-item-id=\"e478796d376392d22776d2d899941a54b\">Traditional Boat, Life Vest, Snorkeling Gear</li><li data-list-item-id=\"eaab7eb009174a7ce921910878a2e7094\">Traditional Boat to Leebong Island</li><li data-list-item-id=\"e398277e6144964dd2321d993bc531c71\">Public Facility at Leebong Island</li><li data-list-item-id=\"edb7e8344f28013637a7515d9e1305c97\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destination</li></ul>', '<ul><li data-list-item-id=\"ed417c525946d0144449146991ec96763\">Airline Tickets</li><li data-list-item-id=\"efe3d31b94b615d8c32bec9cba3f66e57\">Airport tax &amp; Additional baggage</li><li data-list-item-id=\"eabef6fc7c9517f8f1381ce2569c5535b\">Rapid Test / PCR Test if any</li><li data-list-item-id=\"ea238d19e193dce53e025d68bba9463a9\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</li><li data-list-item-id=\"ecbfb239d664e991a1f33ce12a13d17de\">Travel Insurance</li><li data-list-item-id=\"e7db0f67eb5f88f0af368ee30b0a08c69\">Single Supplement&nbsp;</li><li data-list-item-id=\"e103ab779fb4c9b45432dcd7699cd79fb\">Optional Tour</li><li data-list-item-id=\"eebfed9007e53466126afbaf71e48cf4d\">Watersport</li><li data-list-item-id=\"e6856520eff9e36eea02e41f85694caf5\">Tips for Driver/Guide @IDR 50.000/Pax/Day</li><li data-list-item-id=\"ec4ad40f358649e03cdb914789d275e88\">High Season Surcharge</li></ul>', NULL, '[\"Beach\",\"CULINARY\",\"Nature\",\"Culture\"]', NULL, 0, NULL, '2026-05-06 13:57:08', '2026-05-29 14:41:44');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(56, 42, '2 DAYS BELITUNG + ISLAND HOPPING', 'BANGKA BELITUNG', '2-days-belitung-island-hopping', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Surga Granit: 2D1N Belitung Island Hopping – Pelarian Sempurna ke Maladewa-nya Indonesia!</strong></h2><p style=\"text-align:justify;\">Bosan dengan rutinitas kota yang padat? Saatnya Anda mengemas koper dan terbang menuju bentangan pasir putih yang tak berujung serta air laut kristal di Belitung. Paket <strong>2 Hari 1 Malam</strong> kami dirancang untuk memberikan pengalaman liburan yang padat namun sangat berkesan, membawa Anda langsung ke jantung keindahan tropis negeri ini.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Mengambil Paket Ini?</strong></h3><ul><li data-list-item-id=\"ef4c9aaa23851db658d5921933c10e949\"><p style=\"text-align:justify;\"><strong>Keajaiban Island Hopping yang Ikonik:</strong> Rasakan sensasi berdiri di atas gundukan pasir putih yang muncul di tengah laut di <strong>Pulau Pasir</strong>, atau berfoto dengan latar belakang <strong>Batu Garuda</strong> yang megah dan eksotis.</p></li><li data-list-item-id=\"e3201cfaee95d409c4237fd251cc7d61f\"><p style=\"text-align:justify;\"><strong>Petualangan Bawah Laut &amp; Sejarah:</strong> Jelajahi kekayaan bawah laut dengan snorkeling di perairan jernih sekitar <strong>Pulau Lengkuas</strong>, lalu saksikan mercusuar legendaris yang menjulang tinggi menjaga samudera.</p></li><li data-list-item-id=\"ebb0f8480db0bf771d87b897b65a56747\"><p style=\"text-align:justify;\"><strong>Eksplorasi Goa Kelayang:</strong> Rasakan aura misterius nan indah saat menelusuri interior <strong>Goa Kelayang</strong>, sebuah permata tersembunyi yang menawarkan perspektif berbeda dari alam Belitung.</p></li><li data-list-item-id=\"eb550647445664825f3c3b50ba48b41a9\"><p style=\"text-align:justify;\"><strong>Jejak \"Laskar Pelangi\":</strong> Berjalanlah di atas pasir lembut <strong>Pantai Tanjung Tinggi</strong>, tempat formasi batu granit raksasa menciptakan labirin alam yang menjadi latar ikonik film <i>Laskar Pelangi</i>.</p></li><li data-list-item-id=\"e870caf89fae721667d755c479eea165b\"><p style=\"text-align:justify;\"><strong>Visual Spektakuler Danau Kaolin:</strong> Tutup perjalanan Anda dengan melihat fenomena air berwarna biru toska yang kontras dengan daratan putih bersih di <strong>Danau Kaolin</strong>, tempat impian bagi para pecinta fotografi.</p></li><li data-list-item-id=\"e841d7b9db3d26166733ab88162c6cc79\"><p style=\"text-align:justify;\"><strong>Cita Rasa Kuliner Legendaris:</strong> Tidak hanya mata, lidah Anda akan dimanjakan dengan kelezatan <strong>Mie Belitung</strong> yang gurih dan kesegaran <strong>Es Jeruk Konci</strong> yang melegenda.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Granite Paradise: 2D1N Belitung Island Hopping – The Perfect Escape to Indonesia’s Maldives!</strong></h2><p style=\"text-align:justify;\">Bored with the crowded city routine? It’s time to pack your bags and fly to the endless white sands and crystal-clear waters of Belitung! Our <strong>2-Day 1-Night</strong> package is designed to provide a compact yet deeply memorable holiday, taking you straight to the heart of tropical beauty.</p><h3 style=\"text-align:justify;\"><strong>Why Should You Book This Tour?</strong></h3><ul><li data-list-item-id=\"e92a01536f4076fe923b08f9fee49429f\"><p style=\"text-align:justify;\"><strong>Iconic Island-Hopping Magic:</strong> Feel the sensation of standing on a white sandbar that emerges in the middle of the sea at <strong>Sand Island or</strong> take photos with the majestic and exotic <strong>Garuda Head’s Rock</strong> as your backdrop.</p></li><li data-list-item-id=\"e61b6020ff46a13af44fcfb17a8cef5bd\"><p style=\"text-align:justify;\"><strong>Underwater Adventure &amp; History:</strong> Explore rich marine life while snorkeling in the clear waters around <strong>Lengkuas Island</strong>, then witness the legendary lighthouse that stands tall guarding the ocean.</p></li><li data-list-item-id=\"e1bfaa70baf6e2a3656b06dc780587eab\"><p style=\"text-align:justify;\"><strong>Kelayang Cave Exploration:</strong> Experience a mysterious yet beautiful aura while exploring the interior of <strong>Kelayang Cave</strong>, a hidden gem offering a unique perspective of Belitung\'s nature.</p></li><li data-list-item-id=\"ecb732d2b8b446bb8003c184f1438c4fe\"><p style=\"text-align:justify;\"><strong>\"Laskar Pelangi\" Trails:</strong> Walk on the soft sands of <strong>Tanjung Tinggi Beach</strong>, where giant granite formations create a natural labyrinth that served as the iconic setting for the movie <i>Laskar Pelangi</i>.</p></li><li data-list-item-id=\"eefd598a5364c238c0ad4eb728659d57a\"><p style=\"text-align:justify;\"><strong>Spectacular Visuals of Kaolin Lake:</strong> End your trip by witnessing the turquoise water contrasting with the pure white land at <strong>Kaolin Lake</strong>, a dream spot for photography enthusiasts.</p></li><li data-list-item-id=\"e7c16bc6ed45f7f54e7ef714431814c98\"><p style=\"text-align:justify;\"><strong>Legendary Culinary Flavors:</strong> Not just your eyes, but your palate will be pampered with the savory <strong>Belitung Noodles</strong> and the legendary freshness of <strong>Konci Orange Ice</strong>.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>화강암 낙원 탐험: 1박 2일 벨리퉁 아일랜드 호핑 – 인도네시아의 몰디브로 떠나는 완벽한 휴가!</strong></h2><p style=\"text-align:justify;\">답답한 도시의 일상이 지겨우신가요? 이제 짐을 싸서 벨리퉁의 끝없는 화얀 모래사장과 크리스탈처럼 맑은 바다로 날아갈 시간입니다! 본 <strong>1박 2일</strong> 패키지는 짧지만 강렬한 추억을 선사하며, 여러분을 열대 자연의 심장부로 안내합니다.</p><h3 style=\"text-align:justify;\"><strong>이 패키지를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"ed3e741d3c56ff2c2595986155ca0abdc\"><p style=\"text-align:justify;\"><strong>아이코닉한 아일랜드 호핑의 마법:</strong> 바다 한가운데 나타나는 하얀 모래 언덕인 <strong>모래 섬(Sand Island)</strong> 위에 서보는 전율을 느끼거나, 웅장하고 이국적인 <strong>가루다 바위</strong>를 배경으로 인생샷을 남겨보세요.</p></li><li data-list-item-id=\"e58ae2f42ad04db9cdb86dffaf72665ac\"><p style=\"text-align:justify;\"><strong>수중 어드벤처와 역사:</strong> <strong>능쿠아스 섬(Lengkuas Island)</strong> 주변의 투명한 바다에서 스노클링을 즐기며 풍부한 해양 생태계를 탐험하고, 대양을 지키는 전설적인 등대를 감상하세요.</p></li><li data-list-item-id=\"e86c78f9700903b3f5a29cc6ec92ed584\"><p style=\"text-align:justify;\"><strong>끌라양 동굴(Kelayang Cave) 탐험:</strong> 벨리퉁 자연의 색다른 매력을 보여주는 숨겨진 보석, 끌라양 동굴의 내부를 탐험하며 신비롭고 아름다운 분위기를 경험해 보세요.</p></li><li data-list-item-id=\"e4eac37d4b6aa5866c0511fb7009f8f04\"><p style=\"text-align:justify;\"><strong>영화 \'무지개 학교(Laskar Pelangi)\'의 발자취:</strong> 거대한 화강암 기암괴석이 천연 미로를 만들어내는 <strong>탄중 팅기 해변</strong>의 부드러운 모래 위를 걸어보세요. 이곳은 영화 <i>무지개 학교</i>의 상징적인 촬영지입니다.</p></li><li data-list-item-id=\"e5d3538234ebdc0994c719f54740fd230\"><p style=\"text-align:justify;\"><strong>카오린 호수의 환상적인 절경:</strong> 에메랄드빛 호수와 하얀 땅이 극명한 대비를 이루는 <strong>카오린 호수</strong>에서 여행을 마무리하세요. 사진가들에게는 꿈의 장소입니다.</p></li><li data-list-item-id=\"e059b72aad412c838a2223e0de10afbc3\"><p style=\"text-align:justify;\"><strong>전설적인 로컬 미식의 맛:</strong> 눈뿐만 아니라 입안 가득 즐거움을 선사할 고소한 <strong>벨리퉁 국수</strong>와 전설적인 상큼함의 대명사 <strong>콘치 오렌지 주스</strong>를 맛보세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索花岗岩天堂：2天1夜勿里洞跳岛游 – 前往“印尼马尔代夫”的完美避世之旅！</strong></h2><p style=\"text-align:justify;\">厌倦了拥挤的城市生活吗？ 是时候收拾行囊，飞往勿里洞那无边无际的白沙滩和晶莹剔透的海域了！ 我们的 <strong>2天1夜</strong> 行程旨在为您提供充实而难忘的假期，带您直达热带美景的核心。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须尝试此行程？</strong></h3><ul><li data-list-item-id=\"ec4b9353cd62c87e9548bffbf71830c29\"><p style=\"text-align:justify;\"><strong>标志性的跳岛奇迹：</strong> 感受站在海中央浮现的沙岛（Sand Island）<strong>白沙洲上的震撼，或以雄伟而神秘的</strong>鹰头岩（Garuda Head\'s Rock）为背景拍照留念。</p></li><li data-list-item-id=\"e1b8c19f87f954e5b28b4e6fe13361ab2\"><p style=\"text-align:justify;\"><strong>水下冒险与历史：</strong> 在连阔士岛（Lengkuas Island）清澈的海水中浮潜，探索丰富的水下世界，随后参观守护海洋的传奇灯塔。</p></li><li data-list-item-id=\"e290db56344290c0a88c4b59e96b5a28a\"><p style=\"text-align:justify;\"><strong>格拉扬岩洞（Kelayang Cave）探秘：</strong> 走进<strong>格拉扬岩洞</strong>内部，感受那神秘而美丽的氛围，这是一处展现勿里洞自然奇观的隐世瑰宝。</p></li><li data-list-item-id=\"ec1ba85890192d3736ea0a16d8f70c1e8\"><p style=\"text-align:justify;\"><strong>《彩虹战士》足迹：</strong> 漫步在<strong>丹绒丁宜海滩</strong>柔软的沙滩上，巨型花岗岩阵形成的天然迷宫曾是电影《彩虹战士》的经典取景地。</p></li><li data-list-item-id=\"e1c3ecdd2e5f0ac6b5fb221031c31d795\"><p style=\"text-align:justify;\"><strong>高岭湖（Kaolin Lake）的视觉盛宴：</strong> 以<strong>高岭湖</strong>的奇幻美景结束旅程，欣赏蔚蓝湖水与洁白大地构成的强烈对比，这里是摄影爱好者的梦想之地。</p></li><li data-list-item-id=\"eb5d9401da5186103ea79775357900c7d\"><p style=\"text-align:justify;\"><strong>传奇地道风味：</strong> 不仅是视觉享受，您的味蕾也将被咸鲜的<strong>勿里洞面条</strong>和传奇般清爽的酸柑冰（Es Jeruk Konci）所征服。</p></li></ul>', 0.00, NULL, 2, 1, NULL, NULL, '<ul><li data-list-item-id=\"eddafb42ed62fcfb7a79f33c2dc68fdd5\">Pick Up and Airport Transfer</li><li data-list-item-id=\"e3bf094a2a51fcd07d6cd532d57254ce0\">Hotel (Twin/Triple)</li><li data-list-item-id=\"e89bbf919b152774e5fe0aa75e6ec655f\">Transportation AC</li><li data-list-item-id=\"e1bc72bb091840c631e967e864a447b98\">Driver/Guide (English/Mandarin Speaking)</li><li data-list-item-id=\"e1966e5ed26e162f487fadda6e68df556\">1x breakfast, 1x lunch, 1x dinner</li><li data-list-item-id=\"e3900f09011060a93848efc8a16914e3f\">1x Belitung Noodles + Jeruk Konci Ice Drink</li><li data-list-item-id=\"ee3b446c82d66a6e30a836b66d9420eb1\">1x Snack</li><li data-list-item-id=\"ec3b43fee3f3d7c43a400a5d3d534a83c\">Entrance Fee &amp; Parking Fee</li><li data-list-item-id=\"e707b0280757a8d28f300fcd77a165131\">1x Mineral Water 600 ml / pax / day</li><li data-list-item-id=\"e8a235a26307d30de13d2ee6a1d417181\">Traditional Boat, Life Vest, Snorkeling Gear</li><li data-list-item-id=\"e6f8070080cffcd213f52a69240f7fa01\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destination</li></ul>', '<ul><li data-list-item-id=\"ea006cacefa59d2f570e83c8ac86d03f9\">Airline Tickets</li><li data-list-item-id=\"eb4238943e54ae0a770f245a5c02e4107\">Airport tax &amp; Additional baggage</li><li data-list-item-id=\"ed460402a2f1650f6ba55f1cff6217740\">Rapid Test / PCR Test if any</li><li data-list-item-id=\"e1fcc166e282fc5a318c3a37f5999c421\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</li><li data-list-item-id=\"ef6f7b7bb4e25f80b3efc3bdba9e022ae\">Travel Insurance</li><li data-list-item-id=\"e3a097df3632fbe3a5fdc2e908f1907f2\">Single Supplement&nbsp;</li><li data-list-item-id=\"e9c276c499c25cfcfef312ccf90cfb6f6\">Optional Tour</li><li data-list-item-id=\"e93aebb1e184e6bbe6983678540d94532\">Watersport</li><li data-list-item-id=\"e4336b5b515a933f10c02acf0eebeb68f\">Tips for Driver/Guide @IDR 50.000/Pax/Day</li><li data-list-item-id=\"e8210974b8eccd80b02c87f8ac874567b\">High Season Surcharge</li></ul>', NULL, '[\"Nature\",\"Beach\",\"CULINARY\"]', NULL, 0, NULL, '2026-05-06 14:06:30', '2026-05-29 14:40:56'),
(57, 42, '2 DAYS BELITUNG TOUR', 'BANGKA BELITUNG', '2-days-belitung-tour', '<h2 style=\"text-align:justify;\"><strong>Jelajahi Negeri Laskar Pelangi: 2D1N Belitung Tour – Pesona Granit Raksasa &amp; Danau Biru Kristal</strong></h2><p style=\"text-align:justify;\">Ingin melarikan diri sejenak dari hiruk pikuk kota menuju surga tropis yang tenang? Paket <strong>2 Hari 1 Malam</strong> kami adalah jawaban sempurna untuk Anda yang ingin merasakan esensi keindahan Pulau Belitung dalam waktu singkat namun penuh kesan.</p><h3 style=\"text-align:justify;\"><strong>Mengapa Anda Harus Mencoba Paket Ini?</strong></h3><ul><li data-list-item-id=\"eb85f756b754e8cca922b473cbbd79365\"><p style=\"text-align:justify;\"><strong>Eksplorasi Pantai Granit Legendaris:</strong> Rasakan sensasi berjalan di antara formasi batu granit raksasa yang ikonik di <strong>Pantai Tanjung Tinggi</strong>, lokasi asli syuting film <i>Laskar Pelangi</i>, serta nikmati garis pantai memukau di <strong>Pantai Tanjung Kelayang</strong>.</p></li><li data-list-item-id=\"ec88cb6692dabb5a717a81213ef0e7b15\"><p style=\"text-align:justify;\"><strong>Keajaiban Visual Danau Kaolin:</strong> Saksikan langsung kontras warna yang luar biasa antara air biru toska yang jernih dengan daratan putih bersih, menciptakan pemandangan surealis yang menjadi surga bagi para pecinta fotografi.</p></li><li data-list-item-id=\"e6cc4b51644ab12799a98c02335e88b49\"><p style=\"text-align:justify;\"><strong>Petualangan Kuliner Otentik:</strong> Manjakan lidah Anda dengan cita rasa khas lokal yang melegenda, mulai dari gurihnya <strong>Mie Belitung</strong> yang disajikan dengan <strong>Es Jeruk Konci</strong> yang segar, hingga kesempatan mencicipi <strong>Kong Djie Coffee</strong> yang bersejarah.</p></li><li data-list-item-id=\"e7e6712c9406c0302922c67140d29630c\"><p style=\"text-align:justify;\"><strong>Sentuhan Budaya lokal:</strong> Kenali lebih dekat arsitektur dan warisan leluhur masyarakat setempat melalui kunjungan ke <strong>Rumah Adat Belitung</strong>.</p></li><li data-list-item-id=\"e4fe3c53635ce746f4df2efb5be81b7e5\"><p style=\"text-align:justify;\"><strong>Suasana Pesisir yang Menenangkan:</strong> Nikmati momen relaksasi maksimal di <strong>Pantai Bukit Berahu</strong> dan <strong>Pantai Tanjung Pendam</strong> sambil menghirup udara laut yang murni.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>Explore the Land of Laskar Pelangi: 2D1N Belitung Tour – Giant Granite Charm &amp; Crystal Blue Lakes</strong></h2><p style=\"text-align:justify;\">Want to escape the city bustle for a moment to a peaceful tropical paradise? Our <strong>2-Day 1-Night</strong> package is the perfect answer for those who want to experience the essence of Belitung Island\'s beauty in a short yet impressive time.</p><h3 style=\"text-align:justify;\"><strong>Why Should You Try This Tour?</strong></h3><ul><li data-list-item-id=\"ec5c8f07d24fb0e9f491a125b9ce8a985\"><p style=\"text-align:justify;\"><strong>Exploration of Legendary Granite Beaches</strong>: Feel the sensation of walking among the iconic giant granite formations at <strong>Tanjung Tinggi Beach</strong>, the original filming location of <i>Laskar Pelangi</i>, and enjoy the stunning coastline at <strong>Tanjung Kelayang Beach</strong>.</p></li><li data-list-item-id=\"eb379ec47027df65c344336a853642ce3\"><p style=\"text-align:justify;\"><strong>Visual Magic of Kaolin Lake</strong>: Witness the extraordinary contrast between the clear turquoise water and the pure white land, creating a surreal landscape that is a paradise for photography enthusiasts.</p></li><li data-list-item-id=\"e3047583c2ebd48c97f5893a3dde0b799\"><p style=\"text-align:justify;\"><strong>Authentic Culinary Adventure</strong>: Pamper your taste buds with legendary local flavors, from the savory <strong>Belitung Noodles</strong> served with fresh <strong>Konci Orange Ice</strong>, to the opportunity to taste the historic <strong>Kong Djie Coffee</strong>.</p></li><li data-list-item-id=\"e85b11575e57a64eabc156d7ea03624c6\"><p style=\"text-align:justify;\"><strong>A Touch of Local Culture</strong>: Get to know the architecture and ancestral heritage of the local community through a visit to the <strong>Belitung Traditional House</strong>.</p></li><li data-list-item-id=\"ee76123c8ed1cb3d3f95f2ad31a1ae3f0\"><p style=\"text-align:justify;\"><strong>Soothing Coastal Atmosphere</strong>: Enjoy maximum relaxation at <strong>Bukit Berahu Beach</strong> and <strong>Tanjung Pendam Beach</strong> while breathing in the pure sea air.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>무지개 학교의 땅 탐험: 1박 2일 벨리퉁 투어 – 거대 화강암의 매력과 크리스탈 블루 호수</strong></h2><p style=\"text-align:justify;\">답답한 도시를 벗어나 평화로운 열대 낙원으로 잠시 떠나고 싶으신가요? 본 <strong>1박 2일</strong> 패키지는 짧지만 강렬하게 벨리퉁 섬의 아름다움을 정수를 느끼고 싶은 분들을 위한 완벽한 답안입니다.</p><h3 style=\"text-align:justify;\"><strong>이 투어를 선택해야 하는 이유:</strong></h3><ul><li data-list-item-id=\"e95001a94bfac6519aea7a37606ed8cfb\"><p style=\"text-align:justify;\"><strong>전설적인 화강암 해변 탐험</strong>: 영화 *무지개 학교(Laskar Pelangi)*의 실제 촬영지인 <strong>탄중 팅기 해변</strong>의 상징적인 거대 화강암 사이를 거닐어보고, <strong>탄중 끌라양 해변</strong>의 매혹적인 해안선을 즐겨보세요.</p></li><li data-list-item-id=\"e42f4edd2d81ad54e93d7aa26a8a5a324\"><p style=\"text-align:justify;\"><strong>카오린 호수의 환상적인 절경</strong>: 투명한 에메랄드빛 물과 순백의 땅이 이루는 놀라운 대비를 직접 확인하세요. 사진 애호가들에게는 천국과도 같은 초현실적인 풍경을 선사합니다.</p></li><li data-list-item-id=\"e508167acdc1c871ce61c52344c27a958\"><p style=\"text-align:justify;\"><strong>정통 미식 어드벤처</strong>: 상큼한 <strong>콘치 오렌지 주스</strong>와 함께 제공되는 고소한 <strong>벨리퉁 국수</strong>부터 역사적인 콩지 커피(Kong Djie Coffee)까지, 전설적인 로컬 맛으로 입맛을 사로잡으세요.</p></li><li data-list-item-id=\"ee8f89df41436bc4628be2925dfe12f64\"><p style=\"text-align:justify;\"><strong>로컬 문화의 향기</strong>: <strong>벨리퉁 전통 가옥</strong> 방문을 통해 현지 공동체의 건축 양식과 조상의 유산을 가까이에서 느껴보세요.</p></li><li data-list-item-id=\"eed5fa50b8155a254668f443318a2c40a\"><p style=\"text-align:justify;\"><strong>평온한 해안의 정취</strong>: 순수한 바다 공기를 마시며 <strong>부킷 브라후 해변</strong>과 <strong>탄중 펜담 해변</strong>에서 최고의 휴식을 만끽하세요.</p></li></ul>', '<h2 style=\"text-align:justify;\"><strong>探索彩虹战士的故乡：2天1夜勿里洞之旅 – 巨型花岗岩魅力与晶莹蓝湖</strong></h2><p style=\"text-align:justify;\">想要暂时远离城市的喧嚣，前往宁静的热带天堂吗？ 我们的 <strong>2天1夜</strong> 行程是为您量身打造的完美选择，让您在短时间内也能深刻领略勿里洞岛的美丽精髓。</p><h3 style=\"text-align:justify;\"><strong>为什么您必须尝试此行程？</strong></h3><ul><li data-list-item-id=\"e16fe77b395126bb9e84f5cf56f710373\"><p style=\"text-align:justify;\"><strong>探索传奇的花岗岩海滩</strong>: 亲身体验在<strong>丹绒丁宜海滩</strong>那标志性的巨型花岗岩阵中漫步的奇妙感觉，这里是电影《彩虹战士》的取景地；同时欣赏<strong>丹绒格拉扬海滩</strong>迷人的海岸线。</p></li><li data-list-item-id=\"e32c59520bdc2900e77e4108b55270723\"><p style=\"text-align:justify;\"><strong>高岭湖的视觉奇观</strong>: 见证清澈的碧蓝色湖水与洁白的土地之间形成的强烈对比，这如梦似幻的景象绝对是摄影爱好者的天堂。</p></li><li data-list-item-id=\"ecaaaef1f221ef9b3cf268c898a1c9a57\"><p style=\"text-align:justify;\"><strong>正宗美食冒险</strong>: 宠溺您的味蕾，品尝地道的传奇风味，从鲜美的<strong>勿里洞面条</strong>搭配清爽的<strong>酸柑冰（Es Jeruk Konci）</strong>，到有机会品尝历史悠久的<strong>高记咖啡（Kong Djie Coffee）</strong>。</p></li><li data-list-item-id=\"e39e6e6c03a6164dbb27dbb03e02799d3\"><p style=\"text-align:justify;\"><strong>感受当地文化</strong>: 通过参观<strong>勿里洞传统房屋</strong>，近距离了解当地社区的建筑风格和祖先遗产。</p></li><li data-list-item-id=\"ecbfadbf9abebdc0497855a4ce45a3bdb\"><p style=\"text-align:justify;\"><strong>宁静的海岸氛围</strong>: 在<strong>布吉贝拉胡海滩</strong>和<strong>丹绒潘丹海滩</strong>尽情放松，呼吸纯净的海风。</p></li></ul>', 0.00, NULL, 2, 1, NULL, NULL, '<ul><li data-list-item-id=\"e75adfd61335f5182232389f81eb26cd5\"><p style=\"text-align:justify;\">Pick Up and Airport Transfer</p></li><li data-list-item-id=\"eb728289cfb942f201959c2b38b28da09\"><p style=\"text-align:justify;\">Hotel (Twin/Triple)</p></li><li data-list-item-id=\"eb6099bd56c7acdd0d20ad64d20d46d9d\"><p style=\"text-align:justify;\">Transportation AC</p></li><li data-list-item-id=\"ea7e4fc2a9521764b9c373694934538df\"><p style=\"text-align:justify;\">Driver/Guide (English/Mandarin Speaking)</p></li><li data-list-item-id=\"e73c07e123a57f023f9293afab60dadd7\"><p style=\"text-align:justify;\">1x breakfast, 1x lunch, 1x dinner</p></li><li data-list-item-id=\"e7c5dbb5b76db61ae1af259184dad4de9\"><p style=\"text-align:justify;\">1x Belitung Noodles + Jeruk Konci Ice Drink</p></li><li data-list-item-id=\"e351d7403867bbb4f19447c2b67008d97\"><p style=\"text-align:justify;\">1x Snack</p></li><li data-list-item-id=\"e8ff8c57ea88c670788b4a8436a0a9a19\"><p style=\"text-align:justify;\">Entrance Fee &amp; Parking Fee</p></li><li data-list-item-id=\"ef3e3ebecf3487d72b6c2986e6773c6cb\"><p style=\"text-align:justify;\">1x Mineral Water 600 ml / pax / day</p></li><li data-list-item-id=\"e2ab7a43718f7ff2e989cc69b6797e3a2\"><p style=\"text-align:justify;\">Photo Group &amp; Go Pro Documentation (softcopy) exclude paid destinastion</p></li></ul>', '<ul><li data-list-item-id=\"e24309ab29d127e9ca644acd0e7125292\"><p style=\"text-align:justify;\">Airline Tickets</p></li><li data-list-item-id=\"e74354293a7b72ba6a3d38d50fb30d5e8\"><p style=\"text-align:justify;\">Airport tax &amp; Additional baggage</p></li><li data-list-item-id=\"eae8f173388bc15d7dab4d1677f9d6b78\"><p style=\"text-align:justify;\">Rapid Test / PCR Test if any</p></li><li data-list-item-id=\"e26a67a819bce09615f70eb08182c7921\"><p style=\"text-align:justify;\">Personal Expenses&nbsp;<br>(Flash disk, Laundry, Minibar, Telephone &amp; Room Service, Additional meals &amp; drink)</p></li><li data-list-item-id=\"e6bd3779d84fc1b010d0c49915e521192\"><p style=\"text-align:justify;\">Travel Insurance</p></li><li data-list-item-id=\"ea253fd1ccc5b303f2358cfd2048f9f24\"><p style=\"text-align:justify;\">Single Supplement&nbsp;</p></li><li data-list-item-id=\"e53f1fae80c7ff9ffb3a4f3937ec15af6\"><p style=\"text-align:justify;\">Optional Tour,</p></li><li data-list-item-id=\"e7e51bb1bcba8fa5bd1995664f4dd6699\"><p style=\"text-align:justify;\">Traditional Boat, Life Vest, Snorkeling Gear &amp; Fin</p></li><li data-list-item-id=\"ee2f718f703fe6a3206faa35394fdbe17\"><p style=\"text-align:justify;\">Watersport</p></li><li data-list-item-id=\"e9ab91ed8e00ac33ad2f5b4cc88b78bd8\"><p style=\"text-align:justify;\">Tips for Driver/Guide @IDR 50.000/Pax/Day</p></li><li data-list-item-id=\"e654b1b736d3344b1b2923191b242053d\"><p style=\"text-align:justify;\">High Season Surcharge</p></li></ul>', NULL, '[\"Nature\",\"Culture\",\"HERITAGE\"]', NULL, 0, NULL, '2026-05-06 14:16:36', '2026-06-02 02:50:53'),
(58, 45, '7 DAYS LOMBOK SUMBAWA LABUAN BAJO', 'NUSA TENGGARA BARAT', '7-days-lombok-sumbawa-labuan-bajo', '<h2 style=\"text-align:justify;\"><strong>One Trip. All the Bucket List. 🌊🏝️🐋</strong></h2><p style=\"text-align:justify;\">Jelajahi sisi paling ikonik Indonesia dalam 7 hari yang penuh warna—mulai dari chill di Gili dengan air sebening kaca, sunrise vibes di Sembalun yang super aesthetic, sampai petualangan laut epic di Komodo.</p><p style=\"text-align:justify;\">Snorkeling di spot terbaik? ✔️<br>Main ke pulau eksotis? ✔️<br>Swim bareng <strong>Whale Shark</strong>? ✔️ (rare experience!)<br>Trekking view paling viral di Padar? ✔️<br>Ketemu Komodo langsung di habitatnya? ✔️</p><p style=\"text-align:justify;\">Belum lagi pengalaman <strong>live on board</strong>—bangun tidur langsung lihat laut lepas, sunset di tengah samudra, dan langit penuh bintang tanpa polusi. Ini bukan sekadar trip, ini pengalaman yang bakal jadi highlight hidup kamu.</p><p style=\"text-align:justify;\">Kenapa harus ambil paket ini?<br>Karena kamu dapetin <strong>3 destinasi top (Lombok – Sumbawa – Komodo) dalam 1 perjalanan seamless</strong>, tanpa ribet planning, tanpa buang waktu—semua sudah dirancang biar kamu tinggal datang dan enjoy.</p><p style=\"text-align:justify;\">Kalau kamu cari trip yang:</p><ul><li data-list-item-id=\"e4af60f8eec04acbcbd5ab025927a6481\"><p style=\"text-align:justify;\">Instagrammable di setiap spot</p></li><li data-list-item-id=\"ebeb1e3ebd273b44ad1da759d706b86f3\"><p style=\"text-align:justify;\">Penuh experience unik (bukan cuma foto-foto)</p></li><li data-list-item-id=\"e496c2892cae19c7fa10aafd8d27e8aff\"><p style=\"text-align:justify;\">Worth every second &amp; every rupiah</p></li></ul><h3 style=\"text-align:justify;\"><strong>This is the one.</strong></h3><p style=\"text-align:justify;\">Siap upgrade liburan kamu jadi cerita yang gak semua orang punya? 🚀</p>', '<h2 style=\"text-align:justify;\"><strong>One Trip. All the Bucket List. 🌊🏝️🐋</strong></h2><p style=\"text-align:justify;\">Explore the best of Indonesia in 7 unforgettable days—from chilling in the crystal-clear waters of Gili Islands, sunrise views in aesthetic Sembalun, to an epic sea adventure in Komodo.</p><p style=\"text-align:justify;\">Snorkeling in top spots? ✔️<br>Island hopping paradise? ✔️<br>Swim with <strong>Whale Sharks</strong>? ✔️ (rare experience!)<br>Hike the iconic Padar views? ✔️<br>Meet Komodo dragons in the wild? ✔️</p><p style=\"text-align:justify;\">Plus, enjoy the <strong>live on board experience</strong>—wake up to the ocean, catch golden sunsets, and sleep under a sky full of stars.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get <strong>3 top destinations (Lombok – Sumbawa – Komodo) in one seamless journey</strong>—no hassle, no wasted time, just pure experience.</p><p style=\"text-align:justify;\">Looking for a trip that’s:</p><ul><li data-list-item-id=\"ecb82c1e01be3302052392c390a57cd48\"><p style=\"text-align:justify;\">Instagrammable everywhere</p></li><li data-list-item-id=\"e9b63d146f5f29c8bcd6f50fad3e1cdd9\"><p style=\"text-align:justify;\">Full of unique experiences</p></li><li data-list-item-id=\"e0f951f4e74080f1c3d463bca8a6d810b\"><p style=\"text-align:justify;\">Totally worth it</p></li></ul><h3 style=\"text-align:justify;\"><strong>This is the one.</strong></h3><p style=\"text-align:justify;\">Ready to upgrade your holiday into a once-in-a-lifetime story? 🚀</p>', '<h2 style=\"text-align:justify;\"><strong>One Trip. All the Bucket List. 🌊🏝️🐋</strong></h2><p style=\"text-align:justify;\">단 7일 동안 인도네시아 최고의 여행지를 모두 경험하세요—맑고 투명한 길리섬, 감성 가득한 셈발룬의 일출, 그리고 코모도에서의 짜릿한 해양 어드벤처까지!</p><p style=\"text-align:justify;\">스노클링 명소? ✔️<br>환상적인 섬 투어? ✔️<br>고래상어와 수영? ✔️ (희귀한 경험!)<br>파다르섬 인생뷰 트레킹? ✔️<br>코모도 드래곤 직접 보기? ✔️</p><p style=\"text-align:justify;\">또한 <strong>라이브 온보드 경험</strong>으로<br>바다 위에서 눈을 뜨고, 황금빛 선셋을 즐기며, 별이 가득한 밤을 만끽하세요.</p><p style=\"text-align:justify;\">왜 이 여행을 선택해야 할까요?<br><strong>롬복–숨바와–코모도 3대 핵심 지역을 한 번에</strong>, 번거로움 없이 완벽하게 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e8c65fd1f24bcd0561ea634f10e82bd55\"><p style=\"text-align:justify;\">어디서 찍어도 인생샷</p></li><li data-list-item-id=\"efa0714615344ea2213fc916f05b8a888\"><p style=\"text-align:justify;\">특별한 경험 가득</p></li><li data-list-item-id=\"e630e9695932daccb244d907717944a28\"><p style=\"text-align:justify;\">시간과 비용 모두 가치 있는 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>바로 이 여행입니다.</strong></h3><p style=\"text-align:justify;\">당신의 여행을 평생 기억에 남을 이야기로 만들어보세요 🚀</p>', '<h2 style=\"text-align:justify;\"><strong>One Trip. All the Bucket List. 🌊🏝️🐋</strong></h2><p style=\"text-align:justify;\">7天时间，一次玩遍印尼精华——从清澈见底的吉利群岛，到仙境般的Sembalun日出，再到科莫多国家公园的震撼海上探险！</p><p style=\"text-align:justify;\">顶级浮潜体验？✔️<br>梦幻跳岛之旅？✔️<br>与<strong>鲸鲨共游</strong>？✔️（超稀有体验！）<br>打卡帕达尔岛绝美景观？✔️<br>亲眼见到科莫多龙？✔️</p><p style=\"text-align:justify;\">更有超棒的<strong>船宿体验（Live on Board）</strong>：<br>在海上醒来，欣赏绝美日落，在满天星空下入睡。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以在一次旅程中打卡<strong>龙目岛–松巴哇–科莫多三大热门目的地</strong>，无需复杂规划，轻松享受全部精彩。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e6a168b58975698c42f4ee40097cbf71f\"><p style=\"text-align:justify;\">每一站都能拍大片</p></li><li data-list-item-id=\"e589e6674807a7787f745465eab0388bd\"><p style=\"text-align:justify;\">不只是观光，而是真正体验</p></li><li data-list-item-id=\"ed4bcc350ccbb2eb8adf09b41393325e8\"><p style=\"text-align:justify;\">每一刻都值得</p></li></ul><h3 style=\"text-align:justify;\"><strong>那就是这个行程。</strong></h3><p style=\"text-align:justify;\">准备好开启一场难忘的人生旅行了吗？🚀</p>', 0.00, NULL, 7, 6, NULL, NULL, '<p>• Air-conditioned vehicle during your stay in Lombok.<br>• 3 nights in a hotel (2 nights in Senggigi, 1 night in Sembalun).<br>• 3 nights on a liveaboard (private cabin).<br>• Breakfast, lunch, and dinner as per itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Komodo National Park entrance ticket.<br>• Whale Shark Experience and Gili boat tour.</p>', '<p>• Airfare for all routes.<br>• Laundry and minibar at the hotel.<br>• Personal expenses and driver tips.<br>• Travel insurance.</p>', NULL, '[\"Nature\",\"Scenic Landscape\",\"Beach\",\"WILDLIFE\",\"Adventure\"]', NULL, 0, NULL, '2026-05-20 12:15:05', '2026-05-29 13:51:05'),
(59, 45, '5 DAYS ROUND TRIP LOMBOK', 'NUSA TENGGARA BARAT', '5-days-round-trip-lombok', '<h2 style=\"text-align:justify;\"><strong>Lombok in 5 Days. No Boring Moments. 🌊🔥</strong></h2><p style=\"text-align:justify;\">Dari pulau tropis sampai pegunungan estetik—semua dalam satu trip.</p><p style=\"text-align:justify;\">Chill di <strong>Gili Trawangan</strong> dengan air super jernih &amp; island vibes yang addictive.<br>Lanjut ke <strong>Sembalun</strong>, spot hidden gem dengan view lembah Rinjani yang unreal (sunrise-nya wajib!).<br>Tutup perjalanan di <strong>Mandalika</strong>—pantai Tanjung Aan &amp; Bukit Merese dengan panorama laut yang bikin speechless.</p><p style=\"text-align:justify;\">Bonus? Sentuhan budaya lokal di Desa Sade—simple, authentic, dan beda.</p><p style=\"text-align:justify;\">Kenapa harus ambil ini?<br>Karena dalam 5 hari kamu dapet <strong>island + mountain + beach experience sekaligus</strong>—tanpa ribet planning, tinggal datang dan enjoy.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"eecf0d2c48b9edde980135e66a6fc0b2a\"><p style=\"text-align:justify;\">Liburan singkat tapi maksimal</p></li><li data-list-item-id=\"e7da6f6eb61a4f3e549d15866922f3f0e\"><p style=\"text-align:justify;\">Banyak spot aesthetic &amp; viral</p></li><li data-list-item-id=\"e1119ac8d423ef2bf66f152073961c604\"><p style=\"text-align:justify;\">Experience lengkap, bukan cuma jalan-jalan</p></li></ul><h2 style=\"text-align:justify;\"><strong>Short trip. Big memories.</strong> 🚀</h2><p style=\"text-align:justify;\">Ready buat escape ke Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok in 5 Days. No Boring Moments. 🌊🔥</strong></h2><p style=\"text-align:justify;\">From tropical islands to aesthetic mountains—all in one trip.</p><p style=\"text-align:justify;\">Chill in <strong>Gili Trawangan</strong> with crystal-clear water and addictive island vibes.<br>Head to <strong>Sembalun</strong>, a hidden gem with unreal valley views of Rinjani (sunrise is a must!).<br>End your journey in <strong>Mandalika</strong>—Tanjung Aan Beach and Merese Hill with views that will leave you speechless.</p><p style=\"text-align:justify;\">Bonus? A touch of local culture at Sade Village—simple, authentic, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in just 5 days, you get <strong>island + mountain + beach in one seamless experience</strong>—no hassle, just pure enjoyment.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e6337153d6edfc276452ef37bd858ff8e\"><p style=\"text-align:justify;\">A short trip that feels complete</p></li><li data-list-item-id=\"ed3364e63629e5271038bc2199b08802b\"><p style=\"text-align:justify;\">Aesthetic &amp; viral photo spots everywhere</p></li><li data-list-item-id=\"e2a3999c018264d0f3faaf175f41cecdc\"><p style=\"text-align:justify;\">Real experiences, not just sightseeing</p></li></ul><h2 style=\"text-align:justify;\"><strong>Short trip. Big memories.</strong> 🚀</h2><p style=\"text-align:justify;\">Ready to escape to Lombok?</p>', '<h2><strong>5일 만에 즐기는 롬복. 지루할 틈 없이 완벽하게. 🌊🔥</strong></h2><p>트로피컬 섬부터 감성적인 산까지—한 번에 경험하세요.</p><p>맑고 투명한 바다의 <strong>길리 트라왕안</strong>에서 여유로운 힐링,<br>숨겨진 보석 같은 <strong>셈발룬</strong>에서 린자니 계곡의 환상적인 전망 (일출은 필수!),<br>그리고 마지막은 <strong>만달리카</strong>—탄중 안 해변과 메레세 언덕에서 감탄이 절로 나오는 풍경.</p><p>보너스? 사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p>왜 이 여행인가요?<br>단 5일 동안 <strong>섬 + 산 + 해변을 모두 경험할 수 있는 완벽한 코스</strong>이기 때문입니다.</p><p>이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e6ad1c756e5b15cb4712c587850ac3583\">짧지만 알찬 여행</li><li data-list-item-id=\"e235e87d22e71ce907e94485c4ca7ef30\">어디서 찍어도 인생샷</li><li data-list-item-id=\"e48207ef6e16925f6c227c76157c90e1d\">단순 관광이 아닌 진짜 경험</li></ul><h2><strong>짧지만 강렬한 여행. 평생 기억에 남을 순간.</strong> 🚀</h2><p>롬복으로 떠날 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>5天玩转龙目岛，精彩不停歇。🌊🔥</strong></h2><p>从热带海岛到绝美山景，一次全部体验。</p><p>在<strong>吉利特拉旺岸岛</strong>享受清澈见底的海水与轻松岛屿氛围，<br>前往隐藏秘境<strong>Sembalun</strong>，欣赏林贾尼山谷的震撼美景（必看日出！），<br>最后来到<strong>曼达利卡</strong>，打卡Tanjung Aan海滩与Merese山丘的绝美海景。</p><p>加分项？探访Sade传统村庄，感受简单而真实的当地文化。</p><p>为什么选择这个行程？<br>因为只需5天，你就能一次体验<strong>海岛 + 山景 + 海滩</strong>，轻松无压力。</p><p>如果你想要：</p><ul><li data-list-item-id=\"e68981f1df93c6ae7fa584c06b71ae644\">短时间但体验完整</li><li data-list-item-id=\"ed4a03bc3e4d38a8963780819e418d478\">每一站都能拍大片</li><li data-list-item-id=\"e373a185f9da632ffdca5b75b43a1b77a\">不只是观光，而是真正体验</li></ul><h2><strong>短途旅行，大大回忆。</strong> 🚀</h2><p>准备好出发龙目岛了吗？</p>', 0.00, NULL, 5, 4, NULL, NULL, '<p>• Air-conditioned vehicle.<br>• 4 nights at the hotel (twin/double bed).<br>• Breakfast and lunch, as per itinerary.<br>• Entrance fees and parking at tourist attractions.<br>• Round-trip speedboat to Gili Trawangan.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Driver tips.</p>', NULL, '[\"Beach\",\"Nature\",\"Scenic Landscape\",\"Soft Adventure\",\"Cultural Tourism\",\"Leisure & Instagrammable\"]', NULL, 0, NULL, '2026-05-20 12:37:03', '2026-05-29 13:50:35'),
(60, 45, '5 DAYS LOMBOK TOUR', 'NUSA TENGGARA BARAT', '5-days-lombok-tour', '<h2 style=\"text-align:justify;\"><strong>Hidden Lombok. Next Level Escape. 🌊✨</strong></h2><p style=\"text-align:justify;\">Bukan Lombok yang biasa.</p><p style=\"text-align:justify;\">Explore <strong>secret islands</strong> di Gili Nanggu, Tangkong &amp; Kedis—air sebening kaca, sepi, berasa punya pulau sendiri.<br>Lanjut ke <strong>Pink Beach</strong>, salah satu pantai paling langka di dunia—pasir pink + laut super jernih.<br>Naik ke <strong>Sembalun</strong>, valley di kaki Rinjani dengan view gunung &amp; sawah warna-warni yang unreal.<br>Tutup dengan <strong>Mandalika</strong>, dari Bukit Merese sampai garis pantai yang clean banget.</p><p style=\"text-align:justify;\">Kenapa harus ini?<br>Karena kamu dapet <strong>hidden gems + rare spots + epic views</strong> dalam satu trip—bukan yang mainstream.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"eec3450cfaa847038392418975cde8028\"><p style=\"text-align:justify;\">Anti-mainstream destination</p></li><li data-list-item-id=\"e02941dbfee39764a10c1b8a5df45c6c0\"><p style=\"text-align:justify;\">Spot aesthetic yang beda dari yang lain</p></li><li data-list-item-id=\"e7e4a44b7a3e7ddf010fe1e2bbba1b003\"><p style=\"text-align:justify;\">Trip singkat tapi full experience</p></li></ul><h2 style=\"text-align:justify;\"><strong>Less crowd. More wow.</strong> 🚀</h2><p style=\"text-align:justify;\">Siap explore Lombok versi yang gak semua orang tahu?</p>', '<h2 style=\"text-align:justify;\"><strong>Hidden Lombok. Next Level Escape. 🌊✨</strong></h2><p style=\"text-align:justify;\">Not your typical Lombok.</p><p style=\"text-align:justify;\">Explore <strong>secret islands</strong> like Gili Nanggu, Tangkong &amp; Kedis—crystal-clear water, no crowds, feels like your own private island.<br>Head to <strong>Pink Beach</strong>, one of the rarest beaches in the world—pink sand + insanely clear ocean.<br>Climb up to <strong>Sembalun</strong>, a valley at the foot of Rinjani with unreal mountain and colorful field views.<br>Finish in <strong>Mandalika</strong>, from Merese Hill to clean, stunning coastlines.</p><p style=\"text-align:justify;\">Why this trip?<br>Because you get <strong>hidden gems + rare spots + epic views</strong> in one journey—far from the mainstream.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"edd6bf5e82d7c543bbd4ddae046dcae75\"><p style=\"text-align:justify;\">Off-the-beaten-path destinations</p></li><li data-list-item-id=\"e4891f1cba507f345967be0897ff74961\"><p style=\"text-align:justify;\">Unique aesthetic spots</p></li><li data-list-item-id=\"e7304f1ef97bee6ef4f1c459175f487db\"><p style=\"text-align:justify;\">A short trip with full experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>Less crowd. More wow.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the side of Lombok not everyone knows?</p>', '<h2><strong>숨겨진 롬복. 차원이 다른 여행. 🌊✨</strong></h2><p>평범한 롬복이 아닙니다.</p><p><strong>길리 낭구, 탕콩, 케디스</strong> 같은 숨겨진 섬을 탐험하세요—맑고 투명한 바다, 사람 없는 한적함, 마치 나만의 섬 같은 느낌.<br><strong>핑크 비치</strong>—세계적으로도 드문 분홍빛 모래 해변과 완벽하게 맑은 바다.<br><strong>셈발룬</strong>에서는 린자니 산 아래 펼쳐진 계곡과 환상적인 풍경을 만나보세요.<br>마지막은 <strong>만달리카</strong>, 메레세 언덕과 아름다운 해안선까지 완벽한 마무리.</p><p>왜 이 여행인가요?<br><strong>숨겨진 명소 + 희귀한 경험 + 압도적인 풍경</strong>을 한 번에 즐길 수 있기 때문입니다.</p><p>이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"eefac2fab122fb753d665586eca39152d\">남들과 다른 여행지</li><li data-list-item-id=\"eaf19ceedb366e6ee2a12bb7fee6a77c7\">감성적인 인생샷 스팟</li><li data-list-item-id=\"e253cddfb06f86014da06a8445441fb96\">짧지만 꽉 찬 일정</li></ul><h3><strong>사람은 적게, 감동은 크게.</strong> 🚀</h3><p>아직 많은 사람들이 모르는 롬복을 만나보세요.</p>', '<h2><strong>隐藏版龙目岛 · 全新升级体验 🌊✨</strong></h2><p>这不是普通的龙目岛。</p><p>探索<strong>Gili Nanggu、Tangkong、Kedis</strong>这些小众秘境岛屿——海水清澈见底，人少安静，就像拥有自己的私人海岛。<br>前往<strong>粉红沙滩（Pink Beach）</strong>，全球罕见的粉色沙滩 + 超清澈海水。<br>来到<strong>Sembalun</strong>，林贾尼山脚下的绝美山谷与彩色田野景观。<br>最后在<strong>Mandalika</strong>结束旅程，从Merese山丘到纯净海岸线，每一刻都惊艳。</p><p>为什么选择这个行程？<br>因为你可以一次体验<strong>小众秘境 + 稀有景点 + 震撼风景</strong>，远离大众路线。</p><p>如果你想要：</p><ul><li data-list-item-id=\"e2ff798aa8fa5f87c2a91ac1a421f2acb\">与众不同的旅行地</li><li data-list-item-id=\"e648df03ee3bd1aaad1408609851c4530\">高颜值打卡拍照点</li><li data-list-item-id=\"e013b1f5fc70a470a7ba0562eb17c1eff\">短时间但体验丰富</li></ul><h3><strong>人少景美，惊喜更多。</strong> 🚀</h3><p>准备好探索不一样的龙目岛了吗？</p>', 0.00, NULL, 5, 4, NULL, NULL, '<p>• Tour bus according to itinerary<br>• 4 nights at your chosen hotel (twin/double share)<br>• Meals according to the itinerary<br>• Entrance tickets and parking at tourist attractions<br>• Boat for Gili Islands and Pink Beach tours<br>• Local insurance<br>• Tour guide</p>', '<p>• Airfare<br>• Laundry &amp; minibar at the hotel<br>• Additional activities &amp; attractions at tourist attractions<br>• Local transportation at tourist attractions (Mandalika &amp; Gili)<br>• Personal expenses<br>• Tips for guides &amp; drivers</p>', NULL, '[\"Beach\",\"Nature\",\"Soft Adventure\",\"Culture\"]', NULL, 0, NULL, '2026-05-21 06:03:41', '2026-05-29 13:50:07'),
(61, 45, '5 DAYS LOMBOK SASAK - GILI - PINK BEACH', 'NUSA TENGGARA BARAT', 'wm-5days-lombok-sasak-gili-pink-beach', '<h2 style=\"text-align:justify;\"><strong>Lombok: Islands, Pink Beach &amp; Epic Views. All in One Trip. 🌊🔥</strong></h2><p style=\"text-align:justify;\">Ini bukan sekadar liburan—ini upgrade pengalaman.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>, view laut yang clean dan cinematic.<br>Lanjut ke <strong>Gili Trawangan</strong>, island vibes dengan air super jernih + snorkeling di spot terbaik.<br>Masuk ke highlight utama: <strong>Pink Beach</strong>—pantai langka dengan pasir berwarna pink, plus island hopping di tengah laut yang unreal.<br>Ditutup di <strong>Sembalun</strong>, valley di kaki Rinjani dengan panorama sawah warna-warni dan pegunungan yang next level.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet <strong>best of Lombok</strong> dalam satu perjalanan:<br><strong>island life + rare beach + mountain view + culture vibe</strong>—semuanya balance dan gak monoton.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e661e641690e896e54723fc3ef207b202\"><p style=\"text-align:justify;\">Banyak spot aesthetic &amp; beda dari yang lain</p></li><li data-list-item-id=\"e2cc518b05dd078a45f94bb748352d845\"><p style=\"text-align:justify;\">Kombinasi laut + pulau + gunung dalam 1 trip</p></li><li data-list-item-id=\"e72f7784bbd6b58db5d7df8eb8c83340c\"><p style=\"text-align:justify;\">Liburan singkat tapi feel-nya lengkap</p></li></ul><h3 style=\"text-align:justify;\"><strong>One trip. Full experience. Zero boring.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap rasain Lombok yang lebih dari sekadar pantai?</p>', '<h2><strong>Lombok: Islands, Pink Beach &amp; Epic Views. All in One Trip. 🌊🔥</strong></h2><p>Not just a holiday—this is an experience upgrade.</p><p>Start with <strong>Mandalika &amp; Merese Hill</strong>, offering clean, cinematic ocean views.<br>Continue to <strong>Gili Trawangan</strong>, where crystal-clear water and top snorkeling spots create the perfect island vibes.<br>Next highlight: <strong>Pink Beach</strong>—a rare pink-sand beach with unreal island hopping in the open sea.<br>End your journey in <strong>Sembalun</strong>, a valley at the foot of Rinjani with colorful fields and dramatic mountain views.</p><p>Why choose this trip?<br>Because you get the <strong>best of Lombok</strong> in one journey:<br><strong>island life + rare beach + mountain view + cultural touch</strong>—perfectly balanced, never boring.</p><p>Perfect for you if you want:</p><ul><li data-list-item-id=\"ecdbc35333ca6d1f16301f014589be294\">Aesthetic and unique destinations</li><li data-list-item-id=\"e5d2768422753b2d7467f98b4c98c8b69\">Ocean + island + mountain in one trip</li><li data-list-item-id=\"ef90fa9c421ca62590a1aefcd4d6b854a\">A short escape that feels complete</li></ul><h3><strong>One trip. Full experience. Zero boring.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to experience Lombok beyond the ordinary?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복: 섬, 핑크 비치, 그리고 압도적인 풍경. 한 번에. 🌊🔥</strong></h2><p>단순한 여행이 아닌, 한 단계 업그레이드된 경험.</p><p><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—영화 같은 바다 전망.<br><strong>길리 트라왕안</strong>에서는 맑고 투명한 바다와 최고의 스노클링 포인트를 즐기세요.<br>하이라이트는 <strong>핑크 비치</strong>—세계적으로 희귀한 분홍빛 해변과 환상적인 섬 투어.<br>마지막은 <strong>셈발룬</strong>, 린자니 산 아래 펼쳐진 계곡과 드라마틱한 풍경.</p><p>왜 이 여행인가요?<br>한 번의 여행으로 <strong>롬복의 핵심을 모두 경험</strong>할 수 있기 때문입니다:<br><strong>섬 + 희귀한 해변 + 산 + 문화 체험</strong>까지 완벽한 조합.</p><p>이런 여행을 원한다면:</p><ul><li data-list-item-id=\"e0e914b73a7a73e1e5cb6d9dda96f8dc3\">감각적인 인생샷 명소</li><li data-list-item-id=\"ebe1f71f81dc8476927ea0b3896a9a75f\">바다 + 섬 + 산을 한 번에</li><li data-list-item-id=\"eacfe2e9793d630d26308f5b7f3a4d0c8\">짧지만 꽉 찬 여행</li></ul><h3><strong>한 번의 여행, 완벽한 경험. 지루할 틈 없음.</strong> 🚀</h3><p>평범하지 않은 롬복을 경험해보세요.</p>', '<h2><strong>龙目岛：海岛 + 粉红沙滩 + 震撼风景，一次搞定 🌊🔥</strong></h2><p>这不只是旅行，而是一次全面升级的体验。</p><p>从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏电影般的海景。<br>前往<strong>吉利特拉旺岸岛</strong>，清澈海水与顶级浮潜体验带来完美海岛氛围。<br>接着是亮点：<strong>粉红沙滩（Pink Beach）</strong>——世界罕见的粉色沙滩与震撼跳岛之旅。<br>最后来到<strong>Sembalun</strong>，在林贾尼山脚下欣赏壮丽山谷与彩色田野。</p><p>为什么选择这个行程？<br>因为一次旅程就能体验<strong>龙目岛精华</strong>：<br><strong>海岛 + 稀有沙滩 + 山景 + 文化体验</strong>，完美融合，绝不单调。</p><p>如果你想要：</p><ul><li data-list-item-id=\"e23d49450f4a20a1700603f9dc1b4eec8\">高颜值打卡景点</li><li data-list-item-id=\"e9cd45726f25d27f36d4b201591263aa9\">海洋 + 岛屿 + 山景一次拥有</li><li data-list-item-id=\"e1b21d667d5c9be0bcd2bf3d6d45839f2\">短时间但体验完整</li></ul><h3><strong>一次旅行，全部体验。绝不无聊。</strong> 🚀</h3><p>准备好体验不一样的龙目岛了吗？</p>', 0.00, NULL, 5, 4, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 4 nights at your chosen hotel (Twin/Double Bed).<br>• Breakfast and lunch, as per itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Gili Islands and Pink Beach tours.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Lombok souvenir package.<br>• Personal expenses.<br>• Tips for guide &amp; driver.</p>', NULL, '[\"Beach\",\"Nature\",\"Scenic Landscape\",\"Snorkeling Experience\",\"Culture\",\"Soft Adventure\"]', NULL, 0, NULL, '2026-05-21 11:19:33', '2026-05-29 13:49:39');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(62, 45, '4 DAYS RINJANI SUMMIT & CRATER LAKE EXPEDITION', 'NUSA TENGGARA BARAT', '4-days-rinjani-summit-crater-lake-expedition', '<h2 style=\"text-align:justify;\"><strong>Rinjani Trekking: Not Just a Hike. This is a Legend. ⛰️🔥</strong></h2><p style=\"text-align:justify;\">Ini bukan liburan biasa—ini pengalaman yang bakal kamu ceritakan seumur hidup.</p><p style=\"text-align:justify;\">Mulai dari savana luas Sembalun yang cinematic, lanjut naik ke ketinggian dengan view <strong>Danau Segara Anak</strong> dari atas—one of the most iconic views in Indonesia.<br>Puncaknya? <strong>Summit Rinjani (3.726 mdpl)</strong>—sunrise di atas awan dengan panorama Gunung Agung &amp; Tambora di kejauhan. Unreal.</p><p style=\"text-align:justify;\">Belum selesai—turun ke danau, relax di <strong>natural hot spring</strong>, lalu keluar lewat jalur Torean dengan lembah hijau, sungai jernih, dan air terjun yang dramatic banget.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet <strong>full Rinjani experience</strong>:<br><strong>summit + lake + hot spring + epic exit route</strong>—semua dalam satu perjalanan yang lengkap dan berkelas.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e14076fbfb866a6ec5354a21bf723255a\"><p style=\"text-align:justify;\">Challenge + achievement (bukan sekadar liburan)</p></li><li data-list-item-id=\"e56ae49a89994099638b3684f57bbd656\"><p style=\"text-align:justify;\">View paling epic di Indonesia</p></li><li data-list-item-id=\"e8f2f1d9c3d22450afc56b767e6fdea25\"><p style=\"text-align:justify;\">Experience yang gak semua orang berani coba</p></li></ul><h3 style=\"text-align:justify;\"><strong>Climb it. Feel it. Own it.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap menaklukkan Rinjani dan bawa pulang cerita yang gak semua orang punya?</p>', '<h2 style=\"text-align:justify;\"><strong>Rinjani Trekking: Not Just a Hike. This is a Legend. ⛰️🔥</strong></h2><p style=\"text-align:justify;\">This isn’t just a trip—it’s a story you’ll tell for life.</p><p style=\"text-align:justify;\">Start across the cinematic savanna of Sembalun, then climb higher to witness the iconic <strong>Segara Anak Lake</strong> from above—one of Indonesia’s most breathtaking views.<br>The highlight? <strong>Summit Rinjani (3,726m)</strong>—sunrise above the clouds with Mount Agung and Mount Tambora on the horizon. Unreal.</p><p style=\"text-align:justify;\">And it doesn’t stop there—descend to the lake, relax in a <strong>natural hot spring</strong>, then exit via the Torean route with lush valleys, clear rivers, and dramatic waterfalls.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get the <strong>full Rinjani experience</strong>:<br><strong>summit + lake + hot spring + epic exit route</strong>—all in one complete journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e33cd273b1d444ad5133b637f178b08f8\"><p style=\"text-align:justify;\">A real challenge &amp; achievement</p></li><li data-list-item-id=\"e0d0506a8324d5b2d2352e9cc24ed5a5c\"><p style=\"text-align:justify;\">The most epic views in Indonesia</p></li><li data-list-item-id=\"e698cf80a177489427abbfb55e6f051c4\"><p style=\"text-align:justify;\">An experience not everyone can do</p></li></ul><h3 style=\"text-align:justify;\"><strong>Climb it. Feel it. Own it.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to conquer Rinjani and take home a story like no other?</p>', '<h2><strong>린자니 트레킹: 단순한 등산이 아닌 전설 같은 경험 ⛰️🔥</strong></h2><p>이건 단순한 여행이 아니라 평생 기억에 남을 이야기입니다.</p><p>셈발룬의 광활한 사바나를 지나, 정상으로 오르며<br>인도네시아 최고의 절경 중 하나인 <strong>세가라 아낙 호수</strong>를 내려다보세요.<br>하이라이트는 <strong>린자니 정상(3,726m)</strong>—구름 위에서 맞이하는 일출과 함께 아궁산, 탐보라산까지 한눈에 펼쳐지는 장관.</p><p>여기서 끝이 아닙니다—호수로 내려가<br><strong>천연 온천</strong>에서 휴식을 취하고, 토레안 루트를 따라<br>푸른 계곡, 맑은 강, 웅장한 폭포를 지나 하산합니다.</p><p>왜 이 여행인가요?<br><strong>정상 + 호수 + 온천 + 최고의 하산 루트</strong>까지<br>린자니의 모든 것을 한 번에 경험할 수 있기 때문입니다.</p><p>이런 여행을 원한다면:</p><ul><li data-list-item-id=\"ec70886b84c92c1ad13970d539a2a8c19\">도전과 성취감</li><li data-list-item-id=\"e2b71a943bbc522efc8ef6579cfb9859e\">압도적인 자연 풍경</li><li data-list-item-id=\"eba6ed6629d7e3fb74f6358243eee269d\">누구나 쉽게 할 수 없는 특별한 경험</li></ul><h3><strong>오르고, 느끼고, 당신의 것으로 만드세요.</strong> 🚀</h3><p>린자니를 정복할 준비 되셨나요?</p>', '<h2><strong>林贾尼火山徒步：不只是登山，而是一段传奇 ⛰️🔥</strong></h2><p>这不仅是一趟旅行，而是一段你会铭记一生的故事。</p><p>从Sembalun广阔的草原出发，一路攀登，<br>俯瞰印尼最震撼的景色之一——<strong>Segara Anak火山湖</strong>。<br>巅峰时刻是登顶<strong>林贾尼火山（3,726米）</strong>，在云海之上迎接日出，远眺阿贡火山与坦博拉火山，震撼无比。</p><p>精彩还未结束——下山到湖边，<br>在<strong>天然温泉</strong>中放松身心，随后沿着Torean路线离开，<br>穿越绿色山谷、清澈河流与壮观瀑布。</p><p>为什么选择这个行程？<br>因为你可以一次体验<strong>完整的林贾尼之旅</strong>：<br><strong>登顶 + 火山湖 + 温泉 + 最美下山路线</strong>，全部包含。</p><p>如果你想要：</p><ul><li data-list-item-id=\"ea22a4dcc0296552d1448ace4f0afbbfb\">挑战与成就感</li><li data-list-item-id=\"eace0387df4974f5c0c840f3dd6b0bfff\">印尼最震撼的自然风景</li><li data-list-item-id=\"ef4ac234630ff646c9020adeb2b4b87c0\">并非人人都能完成的独特体验</li></ul><h3><strong>去攀登，去感受，让它成为你的故事。</strong> 🚀</h3><p>准备好征服林贾尼了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"eb4b5ad13de247d4405a66a49bb37037f\">Complete transportation from the airport to Sembalun and back from Torean</li><li data-list-item-id=\"ec815332610163419afc2b80a57638e17\">One-night homestay accommodation in Sembalun</li><li data-list-item-id=\"edde4c78ad75f78cd858865974f7620e2\">Official entrance ticket to Mount Rinjani National Park (TNGR)</li><li data-list-item-id=\"e97b824f89606726b2fbf9c2fb5be7fef\">Experienced professional guide and porter services</li><li data-list-item-id=\"e0dd9560f4192185484184735f43e0e9b\">All trekking equipment (tent, sleeping bag, mattress)</li><li data-list-item-id=\"e8235bce26bab8944e1934c239995edd2\">Food and beverages during the climb</li><li data-list-item-id=\"e15dc5a5c70f2ce8aed31e934da8a051d\">As well as documentation support and standard first aid kits.</li></ul>', '<ul><li data-list-item-id=\"e8626b7c4f28b0eae971d2ede16f08392\">Airfare to and from your city of origin</li><li data-list-item-id=\"e91ab98a324eac58d05b05c14da4e0081\">Personal expenses outside the program</li><li data-list-item-id=\"e364c184f1ba838c8859957a704e4585d\">Travel insurance</li><li data-list-item-id=\"e7c2f8b57d867023c6f1f36849ae8d52a\">Tips (gratuities) for guides and porters</li><li data-list-item-id=\"e58b126375c31454a4531c8d6b4acc507\">Additional equipment rental fees or special needs outside the agreed-upon package.</li></ul>', NULL, '[\"Nature\",\"Adventure\",\"TREKKING\"]', NULL, 0, NULL, '2026-05-22 03:03:08', '2026-05-29 13:49:08'),
(63, 45, '4 DAYS LOMBOK TOUR', 'NUSA TENGGARA BARAT', '4-days-lombok-tour', '<h2 style=\"text-align:justify;\"><strong>Lombok in 4 Days: Pink Beach, Epic Views &amp; Island Vibes 🌊🔥</strong></h2><p style=\"text-align:justify;\">Short trip, but full of highlights.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—view laut luas yang clean dan cinematic, salah satu spot sunset terbaik di Lombok.<br>Lanjut ke highlight utama: <strong>Pink Beach</strong>—pantai langka dengan pasir berwarna pink, plus island hopping ke pulau pasir dan snorkeling di air sebening kristal.<br>Hari berikutnya, explore <strong>Sembalun</strong>—lembah di kaki Rinjani dengan panorama sawah warna-warni dan view pegunungan yang dramatic.</p><p style=\"text-align:justify;\">Bukan cuma alam, kamu juga akan merasakan sentuhan lokal di Desa Sade—simple, authentic, dan beda.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam 4 hari kamu dapet <strong>best highlight Lombok</strong>:<br><strong>rare pink beach + crystal clear island + mountain view + cultural touch</strong>—semua tanpa buang waktu.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e6ae1a9bc1d47d40b12420ebd5a584aab\"><p style=\"text-align:justify;\">Trip singkat tapi tetap “dapet semua”</p></li><li data-list-item-id=\"e240603e5fec501c9b1e4ca5e562d277b\"><p style=\"text-align:justify;\">Spot aesthetic &amp; unik (gak mainstream)</p></li><li data-list-item-id=\"ebf0744e38d3b077ac6dfa990d8073823\"><p style=\"text-align:justify;\">Kombinasi laut + pulau + gunung dalam 1 trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Full highlight. Zero wasted time.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore Lombok dengan cara paling maksimal?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok in 4 Days: Pink Beach, Epic Views &amp; Island Vibes 🌊🔥</strong></h2><p style=\"text-align:justify;\">Short trip, big highlights.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views and one of the best sunset spots in Lombok.<br>Next, the main highlight: <strong>Pink Beach</strong>—a rare pink-sand beach, plus island hopping to sandbars and snorkeling in crystal-clear waters.<br>Then explore <strong>Sembalun</strong>—a valley at the foot of Rinjani with colorful fields and dramatic mountain views.</p><p style=\"text-align:justify;\">Not just nature—you’ll also experience local culture at Sade Village: simple, authentic, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in just 4 days, you get the <strong>best of Lombok</strong>:<br><strong>rare pink beach + crystal-clear islands + mountain views + cultural touch</strong>—all without wasting time.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ea7b23a9fb03fe344fca297c671af5999\"><p style=\"text-align:justify;\">A short trip that feels complete</p></li><li data-list-item-id=\"ead3187eae527fe024cb5a209a7548c0d\"><p style=\"text-align:justify;\">Unique, aesthetic destinations</p></li><li data-list-item-id=\"eb74b09ec654ed4b33d274990dcaeed69\"><p style=\"text-align:justify;\">Ocean + island + mountain in one journey</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Full highlight. Zero wasted time.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore Lombok the best way?</p>', '<h2 style=\"text-align:justify;\"><strong>4일 만에 즐기는 롬복: 핑크 비치 &amp; 환상적인 풍경 🌊🔥</strong></h2><p style=\"text-align:justify;\">짧지만 핵심만 담은 완벽한 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망과 최고의 선셋 포인트.<br>다음은 하이라이트 <strong>핑크 비치</strong>—세계적으로 희귀한 분홍빛 해변과 맑은 바다에서의 스노클링, 그리고 섬 투어.<br>이어서 <strong>셈발룬</strong>—린자니 산 아래 펼쳐진 계곡과 다채로운 풍경.</p><p style=\"text-align:justify;\">자연뿐만 아니라, 사데 마을에서 로컬 문화도 경험할 수 있습니다—심플하지만 특별한 순간.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>단 4일 동안 <strong>롬복의 핵심을 모두 경험</strong>할 수 있기 때문입니다:<br><strong>핑크 비치 + 맑은 바다 + 산 풍경 + 문화 체험</strong>까지 완벽하게.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"ea232ab3827a86012d4e11cbfd9761ce4\"><p style=\"text-align:justify;\">짧지만 알찬 여행</p></li><li data-list-item-id=\"e768ae8edf87366f77cdfa0266c02de4d\"><p style=\"text-align:justify;\">감각적인 포토 스팟</p></li><li data-list-item-id=\"e985cc9a4c6cad37e1d9528a0d8326a14\"><p style=\"text-align:justify;\">바다 + 섬 + 산을 한 번에</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 완벽한 여행. 낭비 없는 일정.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복을 제대로 경험할 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>4天玩转龙目岛：粉红沙滩 + 震撼风景 🌊🔥</strong></h2><p style=\"text-align:justify;\">时间不长，但精彩全都有。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且电影感十足的海景与绝美日落。<br>接着是亮点 <strong>粉红沙滩（Pink Beach）</strong>——罕见的粉色沙滩 + 清澈海水浮潜 + 跳岛体验。<br>然后前往<strong>Sembalun</strong>，在林贾尼山脚下欣赏壮丽山谷与彩色田野。</p><p style=\"text-align:justify;\">不仅是自然，还有Sade村庄的在地文化体验——简单、真实又独特。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为仅用4天，你就能体验<strong>龙目岛精华</strong>：<br><strong>粉红沙滩 + 清澈海岛 + 山景 + 文化体验</strong>，高效不浪费时间。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e2494bcb9c30993659db90bde5cc0350b\"><p style=\"text-align:justify;\">时间短但内容丰富</p></li><li data-list-item-id=\"eaa2fc99113faa340a509ad271da7a338\"><p style=\"text-align:justify;\">高颜值打卡地点</p></li><li data-list-item-id=\"e9ddf865ce6f5fe744e107d450067460a\"><p style=\"text-align:justify;\">海洋 + 岛屿 + 山景一次拥有</p></li></ul><h3 style=\"text-align:justify;\"><strong>短时间，大精彩。零浪费。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好出发龙目岛了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<p>• Tour bus according to itinerary<br>• 3 nights at your chosen hotel (Twin/Double)<br>• Meals according to the itinerary<br>• Entrance tickets and parking at tourist attractions<br>• Boat for Gili tours<br>• Local insurance<br>• Tour guide</p>', '<p>• Airfare<br>• Laundry &amp; minibar at the hotel<br>• Additional activities &amp; attractions at tourist attractions<br>• Local transportation at tourist attractions (Mandalika &amp; Gili)<br>• Lombok souvenir package<br>• Personal expenses<br>• Tips for guide &amp; driver</p>', NULL, '[\"Nature\",\"Culture\",\"Beach\"]', NULL, 0, NULL, '2026-05-22 06:05:01', '2026-05-29 13:48:34'),
(64, 45, '4 DAYS LOMBOK SASAK NANGGU', 'NUSA TENGGARA BARAT', '4-days-lombok-sasak-nanggu', '<h2 style=\"text-align:justify;\"><strong>Hidden Lombok Escape: Secret Islands &amp; Epic Views 🌊✨</strong></h2><p style=\"text-align:justify;\">Short trip, but different level.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—view laut luas, clean, dan super cinematic.<br>Lanjut ke pengalaman yang jarang orang tahu: <strong>Gili Nanggu, Tangkong &amp; Kedis</strong>—pulau kecil yang masih sepi, air sebening kaca, snorkeling dengan ikan warna-warni, dan vibes seperti private island.<br>Hari berikutnya, naik ke <strong>Sembalun</strong>—lembah di kaki Rinjani dengan panorama sawah warna-warni dan pegunungan yang dramatic banget.</p><p style=\"text-align:justify;\">Ditambah sentuhan lokal di Desa Sade—simple, authentic, dan beda dari yang lain.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet kombinasi <strong>hidden islands + crystal clear water + epic mountain view</strong> dalam satu trip yang gak mainstream.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e4b70b16a192a85a0aceb3ff31e592e57\"><p style=\"text-align:justify;\">Destinasi anti-crowd &amp; lebih eksklusif</p></li><li data-list-item-id=\"ea3f80f06b64e0f4926b7c43f6f32d9d6\"><p style=\"text-align:justify;\">Spot aesthetic yang beda dari yang lain</p></li><li data-list-item-id=\"e833a4d333f7006396b7f2277dcf696ad\"><p style=\"text-align:justify;\">Short trip tapi tetap full experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>Less crowd. More experience.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore Lombok versi yang lebih eksklusif?</p>', '<h2 style=\"text-align:justify;\"><strong>Hidden Lombok Escape: Secret Islands &amp; Epic Views 🌊✨</strong></h2><p style=\"text-align:justify;\">Short trip, different level.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, clean, cinematic ocean views.<br>Then discover something not many people know: <strong>Gili Nanggu, Tangkong &amp; Kedis</strong>—quiet islands, crystal-clear water, colorful fish, and real private island vibes.<br>Next, head up to <strong>Sembalun</strong>—a valley at the foot of Rinjani with dramatic mountain views and colorful fields.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—simple, authentic, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get <strong>hidden islands + crystal-clear ocean + epic mountain views</strong> in one non-mainstream journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ea25cdf3bf7f3ea6efa04d09c983d4b8c\"><p style=\"text-align:justify;\">Less crowded, more exclusive destinations</p></li><li data-list-item-id=\"e00ad84400357dc3a5969abe4f8466de0\"><p style=\"text-align:justify;\">Unique and aesthetic spots</p></li><li data-list-item-id=\"e6cc00c45c93e6c745d415ed2d272f7f6\"><p style=\"text-align:justify;\">A short trip with full experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>Less crowd. More experience.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore a more exclusive side of Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>숨겨진 롬복 여행: 비밀의 섬과 압도적인 풍경 🌊✨</strong></h2><p style=\"text-align:justify;\">짧지만 차원이 다른 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 깨끗한 시네마틱 바다 전망.<br>이어서 많은 사람들이 모르는 <strong>길리 낭구, 탕콩, 케디스</strong>—한적한 섬, 맑은 바다, 형형색색의 물고기, 그리고 프라이빗 아일랜드 같은 분위기.<br>그리고 <strong>셈발룬</strong>—린자니 산 아래 펼쳐진 계곡과 드라마틱한 풍경.</p><p style=\"text-align:justify;\">또한 사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br><strong>숨겨진 섬 + 맑은 바다 + 압도적인 산 풍경</strong>을 한 번에 경험할 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e954ea327fa25859c08fdc4007b1e6526\"><p style=\"text-align:justify;\">한적하고 특별한 여행지</p></li><li data-list-item-id=\"e5c645ffa968293cc0a19c107705403d3\"><p style=\"text-align:justify;\">감성적인 포토 스팟</p></li><li data-list-item-id=\"ef77b9337d6eddf8ceb57e31a882edbbf\"><p style=\"text-align:justify;\">짧지만 알찬 일정</p></li></ul><h3 style=\"text-align:justify;\"><strong>사람은 적게, 경험은 더 크게.</strong> 🚀</h3><p style=\"text-align:justify;\">더 특별한 롬복을 경험해보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>隐藏版龙目岛之旅：秘境海岛 + 震撼风景 🌊✨</strong></h2><p style=\"text-align:justify;\">时间不长，但体验更高级。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着探索鲜为人知的<strong>Gili Nanggu、Tangkong、Kedis</strong>——人少安静、海水清澈、五彩鱼群，仿佛私人海岛。<br>然后前往<strong>Sembalun</strong>，在林贾尼山脚下感受壮丽山谷与震撼景观。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又独特。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅程就能体验<strong>秘境海岛 + 清澈海水 + 壮丽山景</strong>，远离大众路线。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"eff36280a14e383be2b3d4dc930475b1d\"><p style=\"text-align:justify;\">人少景美的旅行地</p></li><li data-list-item-id=\"ef55a1f34fd66bd506f1e345dfce4d9a5\"><p style=\"text-align:justify;\">高颜值打卡地点</p></li><li data-list-item-id=\"e1d42cecd3b6482395c5824095578b1dd\"><p style=\"text-align:justify;\">短时间但体验丰富</p></li></ul><h3 style=\"text-align:justify;\"><strong>人少一点，体验更多。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索不一样的龙目岛了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 3 nights at your chosen hotel (Twin/Double).<br>• Meals according to the itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Gili Nanggu tour.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Tips for guides &amp; drivers.</p>', NULL, '[\"Beach\",\"Snorkeling\",\"Nature\",\"Scenic\",\"Culture\",\"Soft Adventure\"]', NULL, 0, NULL, '2026-05-22 06:47:12', '2026-05-29 13:48:07'),
(65, 45, '4 DAYS LOMBOK SASAK GILI SEMBALUN', 'NUSA TENGGARA BARAT', '4-days-lombok-sasak-gili-sembalun', '<h2><strong>Lombok Escape: Island Vibes, Epic Views &amp; Local Culture</strong></h2><p>Short trip, full experience.</p><p>Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—panorama laut luas dengan vibes cinematic yang bikin langsung jatuh cinta.<br>Lanjut ke <strong>Gili Trawangan &amp; Gili Air</strong>—air sebening kristal, snorkeling bareng ikan warna-warni, dan island vibes yang santai tapi addictive.<br>Naik ke <strong>Sembalun</strong>—lembah di kaki Rinjani dengan view pegunungan dramatis dan sawah warna-warni yang super aesthetic.</p><p>Ditambah sentuhan budaya di Desa Sade—authentic, simple, dan beda dari yang lain.</p><p>Kenapa harus pilih paket ini?<br>Karena kamu dapet <strong>best combo Lombok</strong> dalam satu trip:<br><strong>island life + crystal clear ocean + epic mountain view + local culture</strong>—semua balance dan gak monoton.</p><p>Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e909ade31e7d05734aef208add50a3145\">Liburan singkat tapi tetap lengkap</li><li data-list-item-id=\"e4fb43d121d92fce57ee9d15f877e5721\">Banyak spot aesthetic &amp; viral</li><li data-list-item-id=\"e55ef6c18bc4aae304798cc5f73985010\">Kombinasi laut + pulau + gunung dalam 1 trip</li></ul><h3><strong>One trip. All the vibes.</strong> 🚀</h3><p>Siap explore Lombok dengan pengalaman paling lengkap?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Escape: Island Vibes, Epic Views &amp; Local Culture&nbsp;</strong></h2><p style=\"text-align:justify;\">Short trip, full experience.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views that instantly impress.<br>Continue to <strong>Gili Trawangan &amp; Gili Air</strong>—crystal-clear waters, snorkeling with colorful fish, and chill island vibes you won’t want to leave.<br>Then head to <strong>Sembalun</strong>—a valley at the foot of Rinjani with dramatic mountain views and aesthetic colorful fields.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—authentic, simple, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get the <strong>best combo of Lombok</strong> in one journey:<br><strong>island life + crystal-clear ocean + epic mountain views + local culture</strong>—perfectly balanced, never boring.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ebcc7ed537edabbb0935a0ee241f4ec56\"><p style=\"text-align:justify;\">A short trip that feels complete</p></li><li data-list-item-id=\"e2cb949362f7058a8a05fd6376589f5c7\"><p style=\"text-align:justify;\">Aesthetic and viral photo spots</p></li><li data-list-item-id=\"e0a4c0ce7f44e968719684d4eb890013e\"><p style=\"text-align:justify;\">Ocean + island + mountain in one trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>One trip. All the vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore Lombok the complete way?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 여행: 섬의 감성, 압도적인 풍경, 그리고 로컬 문화&nbsp;</strong></h2><p style=\"text-align:justify;\">짧지만 완벽한 경험.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망.<br><strong>길리 트라왕안 &amp; 길리 에어</strong>에서는 맑은 바다에서 스노클링과 여유로운 섬 분위기를 즐기세요.<br>이어서 <strong>셈발룬</strong>—린자니 산 아래 펼쳐진 계곡과 감각적인 풍경.</p><p style=\"text-align:justify;\">그리고 사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로 <strong>롬복의 핵심을 모두 경험</strong>할 수 있기 때문입니다:<br><strong>섬 + 바다 + 산 + 문화</strong>까지 완벽한 조합.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e8ca02c779a599c4743c215978e5a039a\"><p style=\"text-align:justify;\">짧지만 알찬 여행</p></li><li data-list-item-id=\"e9c54e08e34fa56aa28899d4f4b1a94d2\"><p style=\"text-align:justify;\">감성적인 인생샷 명소</p></li><li data-list-item-id=\"e84cd77b24a0583933b48110c4960eb65\"><p style=\"text-align:justify;\">바다 + 섬 + 산을 한 번에</p></li></ul><h3 style=\"text-align:justify;\"><strong>한 번의 여행, 모든 감성.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복을 제대로 경험할 준비 되셨나요?</p>', '<h2><strong>龙目岛之旅：海岛氛围 + 震撼风景 + 在地文化&nbsp;</strong></h2><p>时间不长，但体验完整。</p><p>从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着前往<strong>吉利特拉旺岸岛 &amp; 吉利艾尔岛</strong>，享受清澈海水、浮潜与轻松的海岛氛围。<br>然后来到<strong>Sembalun</strong>，在林贾尼山脚下感受壮丽山谷与高颜值风景。</p><p>再加上Sade村庄的在地文化体验——简单、真实又独特。</p><p>为什么选择这个行程？<br>因为一次旅程就能体验<strong>龙目岛精华组合</strong>：<br><strong>海岛 + 海洋 + 山景 + 文化</strong>，完美融合，绝不单调。</p><p>如果你想要：</p><ul><li data-list-item-id=\"e952446ad66bb3f333c8808b279c4f70e\">时间短但内容丰富</li><li data-list-item-id=\"e2712da62d5cfa1babfab9d14435705f6\">高颜值拍照打卡点</li><li data-list-item-id=\"e3cc6c8bcff90ef1b2f40f8e64c6fc3fa\">海洋 + 岛屿 + 山景一次拥有</li></ul><h3><strong>一次旅行，全部体验。</strong> 🚀</h3><p>准备好出发龙目岛了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 3 nights at your chosen hotel (Twin/Double).<br>• Meals according to the itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Gili tours.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Tips for guides &amp; drivers.</p>', NULL, '[\"Beach\",\"SNORKELING\",\"Scenic\",\"Nature\",\"Culture\",\"Soft Adventure\"]', NULL, 0, NULL, '2026-05-22 07:10:08', '2026-05-29 13:47:30'),
(66, 45, '3 DAYS LOMBOK TOUR', 'NUSA TENGGARA BARAT', '3-days-lombok-tour', '<h2 style=\"text-align:justify;\"><strong>Lombok Quick Escape: Island Vibes in 3 Days&nbsp;</strong></h2><p style=\"text-align:justify;\">Short time, maximum vibes.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—panorama laut luas dengan view cinematic yang langsung bikin jatuh cinta.<br>Lanjut ke highlight utama: <strong>Gili Air &amp; Gili Trawangan</strong>—air sebening kristal, snorkeling bareng ikan warna-warni, dan island vibes yang santai tapi addictive.</p><p style=\"text-align:justify;\">Ditambah sentuhan lokal di Desa Sade—authentic, simple, dan beda dari yang lain.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam 3 hari kamu dapet <strong>essence Lombok</strong>:<br><strong>tropical island + crystal clear ocean + iconic coastal view + local culture</strong>—semua tanpa buang waktu.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e8d5c6de8061151c2f69953173a54e582\"><p style=\"text-align:justify;\">Short getaway tapi tetap berasa liburan banget</p></li><li data-list-item-id=\"eb385d7ba0f18558898d0c7729d5560c6\"><p style=\"text-align:justify;\">Spot aesthetic &amp; easy explore</p></li><li data-list-item-id=\"ea7d0c6fdbe18f6c6b02582e322804174\"><p style=\"text-align:justify;\">Island experience tanpa ribet planning</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Big vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap kabur sejenak ke Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Quick Escape: Island Vibes in 3 Days&nbsp;</strong></h2><p style=\"text-align:justify;\">Short time, maximum vibes.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views that instantly impress.<br>Then head to the highlight: <strong>Gili Air &amp; Gili Trawangan</strong>—crystal-clear waters, snorkeling with colorful fish, and chill island vibes you won’t want to leave.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—authentic, simple, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in just 3 days, you get the <strong>essence of Lombok</strong>:<br><strong>tropical islands + crystal-clear ocean + iconic coastal views + local culture</strong>—all without wasting time.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e48c3cd7a9392d11e70eba2b041439b97\"><p style=\"text-align:justify;\">A short getaway that still feels complete</p></li><li data-list-item-id=\"e5a2435f7db7fc573299858101cb73991\"><p style=\"text-align:justify;\">Aesthetic and easy-to-explore destinations</p></li><li data-list-item-id=\"e7f34ceeb4063747b60eeef2d3f3641b3\"><p style=\"text-align:justify;\">Island vibes without complicated planning</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Big vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready for a quick escape to Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>3일 만에 즐기는 롬복: 완벽한 아일랜드 감성&nbsp;</strong></h2><p style=\"text-align:justify;\">짧지만 강렬한 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망.<br>이어서 <strong>길리 에어 &amp; 길리 트라왕안</strong>—맑고 투명한 바다, 형형색색의 물고기와 함께하는 스노클링, 그리고 여유로운 섬 분위기.</p><p style=\"text-align:justify;\">사데 마을에서 만나는 로컬 문화까지—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>단 3일 동안 <strong>롬복의 핵심을 모두 경험</strong>할 수 있기 때문입니다:<br><strong>트로피컬 섬 + 맑은 바다 + 상징적인 해안 풍경 + 문화 체험</strong>까지 완벽하게.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e5847248c61297a55ccbbf0e571159465\"><p style=\"text-align:justify;\">짧지만 알찬 여행</p></li><li data-list-item-id=\"e6553d1de76e6608f8098f7db55b661d4\"><p style=\"text-align:justify;\">감성적인 포토 스팟</p></li><li data-list-item-id=\"e48a1344bf60150f5056a6b0d1c2a7d21\"><p style=\"text-align:justify;\">부담 없이 즐기는 섬 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 강한 여행.</strong> 🚀</h3><p style=\"text-align:justify;\">지금 바로 롬복으로 떠날 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>3天龙目岛快闪之旅：满满海岛氛围&nbsp;</strong></h2><p style=\"text-align:justify;\">时间不长，但精彩满满。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着前往亮点 <strong>吉利艾尔岛 &amp; 吉利特拉旺岸岛</strong>——清澈见底的海水、与热带鱼一起浮潜，以及轻松自在的海岛氛围。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又独特。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为仅用3天，你就能体验<strong>龙目岛精华</strong>：<br><strong>热带海岛 + 清澈海水 + 标志性海岸景观 + 在地文化</strong>，高效又精彩。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"eb5e4673f29f65c54d6e1cc0246c20054\"><p style=\"text-align:justify;\">短时间但体验完整</p></li><li data-list-item-id=\"e0d7ab22ce5385619fd4dbeff902c416f\"><p style=\"text-align:justify;\">高颜值打卡地点</p></li><li data-list-item-id=\"edabb322317b3e858f5610124cd1726e6\"><p style=\"text-align:justify;\">轻松无压力的海岛之旅</p></li></ul><h3 style=\"text-align:justify;\"><strong>短时间，大感受。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好来一场说走就走的龙目岛之旅了吗？</p>', 0.00, NULL, 3, 1, NULL, NULL, '<p>• Tour bus according to itinerary<br>• 2 nights at your chosen hotel (Twin/Double)<br>• Meals according to the itinerary<br>• Entrance tickets and parking at tourist attractions<br>• Boat for Gili tours<br>• Local insurance<br>• Tour guide</p>', '<p>• Airfare<br>• Laundry &amp; minibar at the hotel<br>• Additional activities &amp; attractions at tourist attractions<br>• Local transportation at tourist attractions (Mandalika &amp; Gili)<br>• Personal expenses<br>• Tips for guide &amp; driver</p>', NULL, '[\"Beach\",\"Culture\",\"LEISURE\"]', NULL, 0, NULL, '2026-05-22 07:48:50', '2026-05-29 13:47:02'),
(67, 45, '3 DAYS LOMBOK SASAK - GILI NANGGU', 'NUSA TENGGARA BARAT', '3-days-lombok-sasak-gili-nanggu', '<h2 style=\"text-align:justify;\"><strong>Secret Lombok Escape: Hidden Islands &amp; Clear Water Vibes&nbsp;</strong></h2><p style=\"text-align:justify;\">Short trip, but way more exclusive.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—panorama laut luas dengan view cinematic yang langsung bikin jatuh cinta.<br>Masuk ke highlight utama: <strong>Gili Nanggu, Tangkong &amp; Kedis</strong>—hidden islands yang masih sepi, air sebening kristal, snorkeling bareng ikan warna-warni, dan vibes seperti private island.</p><p style=\"text-align:justify;\">Ditambah sentuhan lokal di Desa Sade—authentic, simple, dan beda dari yang lain.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet <strong>hidden island experience</strong> yang gak semua orang tahu—lebih tenang, lebih eksklusif, dan lebih “real escape”.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e9f01e22876ff721c40db9a1632573209\"><p style=\"text-align:justify;\">Destinasi anti-mainstream</p></li><li data-list-item-id=\"e8ec6b4bcb577a075c5db93a3665eb189\"><p style=\"text-align:justify;\">Air laut super jernih &amp; snorkeling terbaik</p></li><li data-list-item-id=\"e948f8b89550219e38dcff51db159bd84\"><p style=\"text-align:justify;\">Short getaway tapi tetap beda dari yang lain</p></li></ul><h3 style=\"text-align:justify;\"><strong>Less crowd. More paradise.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap kabur ke Lombok versi yang lebih eksklusif?</p>', '<h2 style=\"text-align:justify;\"><strong>Secret Lombok Escape: Hidden Islands &amp; Crystal-Clear Vibes</strong></h2><p style=\"text-align:justify;\">Short trip, but way more exclusive.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views that instantly impress.<br>Then discover the highlight: <strong>Gili Nanggu, Tangkong &amp; Kedis</strong>—hidden islands, peaceful and untouched, crystal-clear waters, snorkeling with colorful fish, and true private island vibes.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—authentic, simple, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get a <strong>hidden island experience</strong> that not everyone knows—more peaceful, more exclusive, and a real escape.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e22154551c2b58f5825d87d6273a96ea3\"><p style=\"text-align:justify;\">Off-the-beaten-path destinations</p></li><li data-list-item-id=\"e48adfb2f59c94ba6597fad7e201537b3\"><p style=\"text-align:justify;\">Super clear water &amp; amazing snorkeling</p></li><li data-list-item-id=\"eab4c949530e57d896e8eb6fed2a31bf6\"><p style=\"text-align:justify;\">A short getaway that feels different</p></li></ul><h3 style=\"text-align:justify;\"><strong>Less crowd. More paradise.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to escape to a more exclusive side of Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>숨겨진 롬복 여행: 비밀의 섬과 맑은 바다&nbsp;</strong></h2><p style=\"text-align:justify;\">짧지만 더 특별한 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망.<br>이어서 하이라이트 <strong>길리 낭구, 탕콩, 케디스</strong>—한적하고 손길이 덜 닿은 숨겨진 섬, 맑고 투명한 바다, 형형색색 물고기와 함께하는 스노클링, 그리고 프라이빗 아일랜드 같은 분위기.</p><p style=\"text-align:justify;\">사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>많은 사람들이 모르는 <strong>숨겨진 섬 경험</strong>을 할 수 있기 때문입니다—더 조용하고, 더 특별한 진짜 힐링 여행.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e7bf7f672b2deb703010db4d7cf20d406\"><p style=\"text-align:justify;\">남들과 다른 여행지</p></li><li data-list-item-id=\"e8d681c1b59ae922eff358df199131f80\"><p style=\"text-align:justify;\">맑은 바다와 최고의 스노클링</p></li><li data-list-item-id=\"e315d230670d0ffaf2063e356bfeafada\"><p style=\"text-align:justify;\">짧지만 색다른 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>사람은 적게, 자연은 더 가까이.</strong> 🚀</h3><p style=\"text-align:justify;\">더 특별한 롬복을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>隐藏版龙目岛之旅：秘境海岛 + 纯净海水&nbsp;</strong></h2><p style=\"text-align:justify;\">时间不长，但更加独特。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着探索亮点 <strong>Gili Nanggu、Tangkong、Kedis</strong>——安静原始的小众岛屿，清澈见底的海水，与五彩鱼群一起浮潜，仿佛置身私人海岛。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又特别。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以体验<strong>不为人知的秘境海岛</strong>——更安静、更独特，真正远离人群的度假体验。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e91201874bdfc6aa242e3265baf04434c\"><p style=\"text-align:justify;\">小众不拥挤的旅行地</p></li><li data-list-item-id=\"e21819b6cfc72ff78b28c57bb68ba36e8\"><p style=\"text-align:justify;\">清澈海水与绝佳浮潜</p></li><li data-list-item-id=\"e74b2dd84e353f94d0943fc92e1dcb7ab\"><p style=\"text-align:justify;\">短时间但与众不同的体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>人少景美，更接近天堂。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索不一样的龙目岛了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 2 nights at your chosen hotel (Twin/Double).<br>• Meals according to the itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Gili Nanggu tour.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Tips for guides &amp; drivers.</p>', NULL, '[\"Beach\",\"Snorkeling\",\"Culture\",\"Leisure\"]', NULL, 0, NULL, '2026-05-22 12:24:37', '2026-05-29 13:46:41'),
(68, 45, '3 DAYS LOMBOK SASAK - GILI TRAWANGAN', 'NUSA TENGGARA BARAT', '3-days-lombok-sasak-gili-trawangan', '<h2 style=\"text-align:justify;\"><strong>Lombok Island Escape: Gili Vibes &amp; Coastal Beauty&nbsp;</strong></h2><p style=\"text-align:justify;\">3 hari, full vibes—tanpa ribet.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—panorama laut luas dengan view cinematic yang langsung bikin jatuh cinta.<br>Masuk ke highlight utama: <strong>Gili Air &amp; Gili Trawangan</strong>—air sebening kristal, snorkeling bareng ikan warna-warni, dan island vibes yang santai tapi addictive.</p><p style=\"text-align:justify;\">Ditambah pengalaman budaya di Desa Sade—authentic, simple, dan beda dari yang lain.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam waktu singkat kamu dapet <strong>best Lombok experience</strong>:<br><strong>tropical islands + crystal clear ocean + iconic coastal view + local culture</strong>—semua dalam satu trip yang simpel tapi berkesan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e1a13b851b03f6f35299498223249f039\"><p style=\"text-align:justify;\">Liburan singkat tapi tetap maksimal</p></li><li data-list-item-id=\"e089b4e8b3793b79c9ab7c3acea9d2874\"><p style=\"text-align:justify;\">Spot aesthetic &amp; easy explore</p></li><li data-list-item-id=\"e841a8ab885e606a8033ed443ef665bc6\"><p style=\"text-align:justify;\">Island vibes tanpa ribet planning</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short escape. Real vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap rasain Lombok yang langsung bikin ketagihan?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Island Escape: Gili Vibes &amp; Coastal Beauty&nbsp;</strong></h2><p style=\"text-align:justify;\">3 days, full vibes—no hassle.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views that instantly impress.<br>Then head to the highlight: <strong>Gili Air &amp; Gili Trawangan</strong>—crystal-clear waters, snorkeling with colorful fish, and chill island vibes you won’t want to leave.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—authentic, simple, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in a short time, you get the <strong>best of Lombok</strong>:<br><strong>tropical islands + crystal-clear ocean + iconic coastal views + local culture</strong>—all in one simple yet unforgettable journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ee390d4099445bdab31b8bb884a038f71\"><p style=\"text-align:justify;\">A short getaway that still feels complete</p></li><li data-list-item-id=\"e2665381905f809e003f1074fb79b4538\"><p style=\"text-align:justify;\">Aesthetic and easy-to-explore spots</p></li><li data-list-item-id=\"e88f30f0a314c9e21d62a277dfbc7a3c6\"><p style=\"text-align:justify;\">Island vibes without complicated planning</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short escape. Real vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to experience Lombok in the best way?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 아일랜드 여행: 길리 감성 &amp; 아름다운 해안&nbsp;</strong></h2><p style=\"text-align:justify;\">3일이면 충분한 완벽한 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망.<br>이어서 하이라이트 <strong>길리 에어 &amp; 길리 트라왕안</strong>—맑은 바다에서의 스노클링과 여유로운 섬 분위기.</p><p style=\"text-align:justify;\">사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>짧은 시간 안에 <strong>롬복의 핵심을 모두 경험</strong>할 수 있기 때문입니다:<br><strong>트로피컬 섬 + 맑은 바다 + 상징적인 해안 풍경 + 문화 체험</strong>까지 완벽하게.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e0a470c14460ee354a86a0141a91c6213\"><p style=\"text-align:justify;\">짧지만 알찬 여행</p></li><li data-list-item-id=\"ed76f4751db3eb6063bc3992ce769ac5b\"><p style=\"text-align:justify;\">감성적인 포토 스팟</p></li><li data-list-item-id=\"ef8705c094349d7dd3f4c9095c5d8f079\"><p style=\"text-align:justify;\">부담 없이 즐기는 섬 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 진짜 여행.</strong> 🚀</h3><p style=\"text-align:justify;\">지금 바로 롬복으로 떠나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>龙目岛之旅：吉利岛氛围 + 绝美海岸线&nbsp;</strong></h2><p style=\"text-align:justify;\">3天时间，满满体验。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着前往亮点 <strong>吉利艾尔岛 &amp; 吉利特拉旺岸岛</strong>——清澈见底的海水、与热带鱼一起浮潜，以及轻松自在的海岛氛围。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又特别。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为在短时间内，你可以体验<strong>龙目岛精华</strong>：<br><strong>热带海岛 + 清澈海水 + 标志性海岸景观 + 在地文化</strong>，简单却难忘。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e232a30124f3dd20fc6fe413d74d1254a\"><p style=\"text-align:justify;\">时间短但体验完整</p></li><li data-list-item-id=\"e5aaa5dbcecec0ced3e812c55895fff7c\"><p style=\"text-align:justify;\">高颜值打卡地点</p></li><li data-list-item-id=\"e19edca55644d1c4c71b5e540164f1734\"><p style=\"text-align:justify;\">轻松无压力的海岛之旅</p></li></ul><h3 style=\"text-align:justify;\"><strong>短途旅行，真实感受。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好出发龙目岛了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 2 nights at your chosen hotel (Twin/Double).<br>• Meals according to the itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Gili tours.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Tips for guides &amp; drivers.</p>', NULL, '[\"Beach\",\"Nature\",\"Culture\",\"Leisure\"]', NULL, 0, NULL, '2026-05-22 12:39:09', '2026-05-29 13:46:19'),
(69, 45, '3 DAYS LOMBOK SASAK - PINK BEACH', 'NUSA TENGGARA BARAT', '3-days-lombok-sasak-pink-beach', '<h2 style=\"text-align:justify;\"><strong>Lombok Pink Beach Escape: Rare Views &amp; Island Adventure&nbsp;</strong></h2><p style=\"text-align:justify;\">Short trip, but unforgettable.</p><p style=\"text-align:justify;\">Mulai dari <strong>Mandalika &amp; Bukit Merese</strong>—panorama laut luas dengan view cinematic yang langsung bikin jatuh cinta.<br>Masuk ke pengalaman yang beda: <strong>Pulau Pasir &amp; Gili Petelu</strong>—fenomena sandbar unik di tengah laut dan snorkeling di air sebening kristal dengan ikan warna-warni.<br>Puncaknya? <strong>Pink Beach</strong>—pantai langka dengan pasir berwarna pink, salah satu yang jarang ada di dunia, dengan view laut yang super clean dan aesthetic.</p><p style=\"text-align:justify;\">Ditambah sentuhan budaya di Desa Sade—authentic, simple, dan tetap terasa lokal.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet <strong>rare experience</strong> dalam waktu singkat:<br><strong>pink beach + sandbar island + crystal clear snorkeling + epic coastal view</strong>—kombinasi yang gak semua destinasi punya.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"efd9fd364dfa901650da46b34b1ba03e9\"><p style=\"text-align:justify;\">Destinasi unik &amp; anti-mainstream</p></li><li data-list-item-id=\"e4dedfda2fa9120df1166c8fc2e9a360b\"><p style=\"text-align:justify;\">Spot aesthetic yang beda dari yang lain</p></li><li data-list-item-id=\"e1acfdeab2fb1d4616b594a9d9eeaf08b\"><p style=\"text-align:justify;\">Short trip tapi tetap “wow”</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Rare experience.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore sisi paling unik dari Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Pink Beach Escape: Rare Views &amp; Island Adventure&nbsp;</strong></h2><p style=\"text-align:justify;\">Short trip, but unforgettable.</p><p style=\"text-align:justify;\">Start with <strong>Mandalika &amp; Merese Hill</strong>—wide, cinematic ocean views that instantly impress.<br>Then dive into a unique experience: <strong>Sandbar Island &amp; Gili Petelu</strong>—a rare sandbank in the middle of the sea and crystal-clear snorkeling with colorful fish.<br>The highlight? <strong>Pink Beach</strong>—one of the rarest pink-sand beaches in the world, with stunning, clean ocean views.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—authentic, simple, and unique.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get a <strong>rare experience in a short time</strong>:<br><strong>pink beach + sandbar island + crystal-clear snorkeling + epic coastal views</strong>—a combination you won’t find everywhere.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ea45801c59e78e63e809d0cb2342a1200\"><p style=\"text-align:justify;\">Unique, off-the-beaten-path destinations</p></li><li data-list-item-id=\"e0f65f7cab4bb6a5a79dc68b2df652e01\"><p style=\"text-align:justify;\">Aesthetic spots that stand out</p></li><li data-list-item-id=\"e1b65146bb7c081a00e63678d404bc438\"><p style=\"text-align:justify;\">A short trip that still feels “wow”</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Rare experience.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the most unique side of Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 핑크 비치 여행: 특별한 풍경과 아일랜드 어드벤처&nbsp;</strong></h2><p style=\"text-align:justify;\">짧지만 잊을 수 없는 여행.</p><p style=\"text-align:justify;\"><strong>만달리카 &amp; 메레세 언덕</strong>에서 시작—넓고 시네마틱한 바다 전망.<br>이어서 특별한 경험: <strong>모래섬(샌드바) &amp; 길리 페텔루</strong>—바다 한가운데 나타나는 모래섬과 맑은 바다에서의 스노클링.<br>하이라이트는 <strong>핑크 비치</strong>—세계적으로도 드문 분홍빛 해변과 아름다운 바다 풍경.</p><p style=\"text-align:justify;\">사데 마을에서 만나는 로컬 문화—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>짧은 시간 안에 <strong>특별한 경험</strong>을 모두 즐길 수 있기 때문입니다:<br><strong>핑크 비치 + 모래섬 + 맑은 바다 스노클링 + 압도적인 해안 풍경</strong>까지.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"ef6f8fa6bd7ccbe03566a12632cc818ed\"><p style=\"text-align:justify;\">특별하고 색다른 여행지</p></li><li data-list-item-id=\"e228e65b23ff65ec71b9c2727452d332e\"><p style=\"text-align:justify;\">감성적인 포토 스팟</p></li><li data-list-item-id=\"e2370665e5a5bd1a299aa47c731cda4dd\"><p style=\"text-align:justify;\">짧지만 강렬한 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 특별한 여행.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복의 가장 특별한 순간을 경험해보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>龙目岛粉红沙滩之旅：稀有美景 + 海岛探险&nbsp;</strong></h2><p style=\"text-align:justify;\">时间不长，但难以忘怀。</p><p style=\"text-align:justify;\">从<strong>曼达利卡 &amp; Merese山丘</strong>开始，欣赏开阔且极具电影感的海景。<br>接着体验独特行程：<strong>沙洲岛（Pulau Pasir） &amp; 吉利佩特鲁岛</strong>——海中央出现的沙洲与清澈见底的浮潜体验。<br>最大亮点是<strong>粉红沙滩（Pink Beach）</strong>——世界少见的粉色沙滩与绝美海景。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又独特。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为在短时间内，你可以体验<strong>稀有且独特的旅行</strong>：<br><strong>粉红沙滩 + 沙洲岛 + 清澈浮潜 + 震撼海岸风景</strong>，这种组合非常难得。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e3fc45fbea3f8129435d2aeeeb1d8ef5f\"><p style=\"text-align:justify;\">小众又特别的旅行地</p></li><li data-list-item-id=\"eef5651630eb0d24dc50670429e05ed47\"><p style=\"text-align:justify;\">高颜值打卡拍照点</p></li><li data-list-item-id=\"e11b48bc4b017eef96b5c35f1e775e427\"><p style=\"text-align:justify;\">短时间但惊艳的体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>短途旅行，稀有体验。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索龙目岛最独特的一面了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<p>• Tour bus according to itinerary.<br>• 2 nights at your chosen hotel (Twin/Double Bed).<br>• Breakfast and lunch, as per itinerary.<br>• Entrance tickets and parking at tourist attractions.<br>• Boat for Pink Beach tours.<br>• Local insurance.<br>• Tour guide.</p>', '<p>• Airfare.<br>• Laundry &amp; minibar at the hotel.<br>• Dinner (optional).<br>• Additional activities &amp; attractions at tourist attractions.<br>• Local transportation at tourist attractions (Mandalika &amp; Gili).<br>• Personal expenses.<br>• Tips for guide &amp; driver.</p>', NULL, '[\"Beach\",\"Snorkeling\",\"Nature\",\"Unique Landscape\",\"Culture\"]', NULL, 0, NULL, '2026-05-22 12:50:47', '2026-05-29 13:45:59');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(70, 45, 'LOMBOK SPECIAL OFFROAD ADVENTURE', 'NUSA TENGGARA BARAT', 'lombok-special-offroad-adventure', '<h2 style=\"text-align:justify;\"><strong>Lombok Off-Road Escape: Wild Adventure &amp; Hidden Views&nbsp;</strong></h2><p style=\"text-align:justify;\">Not your typical tour—this is pure adventure.</p><p style=\"text-align:justify;\">Rasakan sensasi <strong>off-road ride</strong> menembus jalur alam Lombok yang belum banyak dijamah. Dari hutan hingga jalur berbatu, setiap perjalanan adalah experience yang beda dari biasanya.<br>Explore keindahan <strong>Gunung Tunak, Sari Goang, hingga tebing pesisir</strong> dengan view laut dari ketinggian yang super dramatic.<br>Dan saat hari mulai turun—nikmati <strong>sunset</strong> yang langsung menghadap laut lepas. Clean, wild, and unforgettable.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena ini bukan sekadar sightseeing—ini <strong>adventure experience</strong> yang bener-bener beda:<br><strong>off-road + hidden nature + epic coastal view + sunset moment</strong> dalam satu hari.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e4d39682ca29d51d702f5822193d7ea6d\"><p style=\"text-align:justify;\">Experience yang lebih aktif &amp; seru</p></li><li data-list-item-id=\"e937ade6cb770c86450728321f5c88dc3\"><p style=\"text-align:justify;\">Destinasi anti-mainstream</p></li><li data-list-item-id=\"ee0ccead1a19f7d391622d98a1a1443f1\"><p style=\"text-align:justify;\">View alam yang masih raw &amp; untouched</p></li></ul><h3 style=\"text-align:justify;\"><strong>More than a tour. It’s an adventure.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap rasain Lombok yang lebih liar dan beda?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Off-Road Escape: Wild Adventure &amp; Hidden Views&nbsp;</strong></h2><p style=\"text-align:justify;\">Not your typical tour—this is pure adventure.</p><p style=\"text-align:justify;\">Feel the thrill of an <strong>off-road ride</strong> through Lombok’s untouched landscapes. From forest trails to rugged terrain, every ride is a whole new experience.<br>Explore hidden gems like <strong>Gunung Tunak, Sari Goang, and dramatic coastal cliffs</strong> with breathtaking ocean views from above.<br>As the day ends, enjoy a <strong>sunset over the open sea</strong>—raw, clean, and unforgettable.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because this is more than sightseeing—it’s a true <strong>adventure experience</strong>:<br><strong>off-road + hidden nature + epic coastal views + sunset moments</strong> in one journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e65b041292479273725532b64554b56c2\"><p style=\"text-align:justify;\">A more active and exciting trip</p></li><li data-list-item-id=\"e2253e8f3c2e5d2ecdecf76dbab9078e9\"><p style=\"text-align:justify;\">Off-the-beaten-path destinations</p></li><li data-list-item-id=\"eb7e1a88e40f463dfc21d633c663d18b5\"><p style=\"text-align:justify;\">Raw, untouched natural views</p></li></ul><h3 style=\"text-align:justify;\"><strong>More than a tour. It’s an adventure.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the wild side of Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 오프로드 여행: 와일드한 모험과 숨겨진 풍경&nbsp;</strong></h2><p style=\"text-align:justify;\">평범한 여행이 아닌, 진짜 모험입니다.</p><p style=\"text-align:justify;\">롬복의 자연 속을 달리는 <strong>오프로드 드라이브</strong>를 경험하세요. 숲길과 거친 지형을 지나며 색다른 스릴을 느낄 수 있습니다.<br><strong>구눙 투낙, 사리 고앙, 해안 절벽</strong> 등 숨겨진 명소에서 바다를 내려다보는 압도적인 풍경을 즐겨보세요.<br>하루의 끝에는 탁 트인 바다 위로 펼쳐지는 <strong>선셋</strong>—자연 그대로의 감동.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>단순한 관광이 아닌, 진짜 <strong>어드벤처 경험</strong>이기 때문입니다:<br><strong>오프로드 + 숨겨진 자연 + 해안 절경 + 선셋</strong>까지 한 번에.</p><p style=\"text-align:justify;\">이런 여행을 원한다면:</p><ul><li data-list-item-id=\"e9d050df38faf7bbb003cbb1a18a5b9f9\"><p style=\"text-align:justify;\">활동적인 여행</p></li><li data-list-item-id=\"e09a3d11e2bc4d47e6efc6a4274cb66e1\"><p style=\"text-align:justify;\">남들과 다른 여행지</p></li><li data-list-item-id=\"e78589fbcf7291dcf2d1dd2cb9a65b978\"><p style=\"text-align:justify;\">자연 그대로의 풍경</p></li></ul><h3 style=\"text-align:justify;\"><strong>여행 그 이상, 진짜 모험.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복의 새로운 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>龙目岛越野之旅：野性探险 + 秘境风景&nbsp;</strong></h2><p style=\"text-align:justify;\">这不是普通旅行，而是真正的冒险体验。</p><p style=\"text-align:justify;\">体验在龙目岛自然中驰骋的<strong>越野之旅</strong>，穿越森林与崎岖地形，每一段路都充满刺激。<br>探索<strong>Gunung Tunak、Sari Goang和海岸悬崖</strong>等隐藏秘境，从高处俯瞰震撼海景。<br>在一天结束时，欣赏面向大海的<strong>绝美日落</strong>——原始、纯粹、令人难忘。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为这不仅是观光，而是完整的<strong>探险体验</strong>：<br><strong>越野 + 秘境自然 + 震撼海岸风景 + 日落时刻</strong>一次拥有。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e1124f95b7fa2118e11b67de51dcd1115\"><p style=\"text-align:justify;\">更刺激、更有活力的旅行</p></li><li data-list-item-id=\"ea91b665970c2c3d05f201599ae52ccaf\"><p style=\"text-align:justify;\">小众不拥挤的目的地</p></li><li data-list-item-id=\"ec99b21d66de2e6dcc7459d1eb14288b3\"><p style=\"text-align:justify;\">原始自然风景</p></li></ul><h3 style=\"text-align:justify;\"><strong>不只是旅行，而是一场冒险。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索龙目岛更狂野的一面了吗？</p>', 0.00, NULL, 1, 0, NULL, NULL, '<p>• 4x4 Double Cabin Vehicle (3-4 people per vehicle)<br>• Lunch at a Local Restaurant<br>• Coffee &amp; Tea<br>• Tour Guide<br>• Professional Driver<br>• 600ml Mineral Water (During the Program)<br>• Documentation (Photos + Cinematic Video)<br>• Entrance Tickets to Destinations</p>', '<p>• Personal expenses outside the program<br>• Tips for Guides &amp; Drivers</p>', NULL, '[\"Adventure\",\"Off-Road Experience\",\"Nature\",\"Coastal Scenic\"]', NULL, 0, NULL, '2026-05-22 13:05:03', '2026-05-29 13:45:40'),
(71, 45, 'LOMBOK HALF DAY OFFROAD ADVENTURE', 'NUSA TENGGARA BARAT', 'lombok-half-day-offroad-adventure', '<h2 style=\"text-align:justify;\"><strong>Lombok Quick Adventure: Off-Road Escape in Half Day 🚙🔥</strong></h2><p style=\"text-align:justify;\">Short time. Real adventure.</p><p style=\"text-align:justify;\">Rasakan sensasi <strong>off-road ride</strong> menembus jalur alam Lombok—dari hutan, jalur berbatu, hingga hidden spot yang belum banyak dijamah.<br>Explore pilihan destinasi seperti <strong>Gunung Tunak dengan tebing lautnya yang dramatis</strong>, <strong>Benang Setokel dengan air terjun alami</strong>, atau <strong>Gunung Jae dengan suasana danau &amp; hutan yang tenang</strong>.</p><p style=\"text-align:justify;\">Dalam waktu singkat, kamu sudah merasakan kombinasi <strong>wild nature + adrenaline + epic scenery</strong> yang langsung “kena”.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena ini cara paling cepat untuk merasakan <strong>real Lombok adventure</strong> tanpa perlu waktu seharian:<br><strong>off-road + hidden nature + unique landscapes</strong>—semua dalam 1 trip singkat tapi berkesan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e260d31dd3221d2cafd3e4d9f2ee9f9b8\"><p style=\"text-align:justify;\">Adventure cepat tapi tetap seru</p></li><li data-list-item-id=\"e0349bbec1274119150c93874cd3d2392\"><p style=\"text-align:justify;\">Destinasi anti-mainstream</p></li><li data-list-item-id=\"ea49b0d4de86e72dcd835d2520b69f48a\"><p style=\"text-align:justify;\">Experience beda tanpa harus ambil full day tour</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short time. Big adventure.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap gas ke sisi liar Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Quick Adventure: Off-Road Escape in Half Day 🚙🔥</strong></h2><p style=\"text-align:justify;\">Short time. Real adventure.</p><p style=\"text-align:justify;\">Feel the thrill of an <strong>off-road ride</strong> through Lombok’s natural terrain—from forests and rocky tracks to hidden spots rarely explored.<br>Discover destinations like <strong>Gunung Tunak with dramatic coastal cliffs</strong>, <strong>Benang Setokel with natural waterfalls</strong>, or <strong>Gunung Jae with peaceful lakes and forest vibes</strong>.</p><p style=\"text-align:justify;\">In just a few hours, you get a powerful mix of <strong>wild nature + adrenaline + epic scenery</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because it’s the fastest way to experience a <strong>real Lombok adventure</strong> without spending a full day:<br><strong>off-road + hidden nature + unique landscapes</strong>—all in one short but memorable journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"eefbe5953c0c251e3cbcf6596bf96d7c2\"><p style=\"text-align:justify;\">A quick but exciting adventure</p></li><li data-list-item-id=\"e2959c6119cea8d00e6f38575911b4417\"><p style=\"text-align:justify;\">Off-the-beaten-path destinations</p></li><li data-list-item-id=\"ef0c36fc5e78be87fcaac7fb0bec19941\"><p style=\"text-align:justify;\">A unique experience without a full-day commitment</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short time. Big adventure.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the wild side of Lombok?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 퀵 어드벤처: 반나절 오프로드 여행 🚙🔥</strong></h2><p style=\"text-align:justify;\">짧은 시간, 진짜 모험.</p><p style=\"text-align:justify;\">숲길, 거친 도로, 그리고 숨겨진 자연 속을 달리는 <strong>오프로드 드라이브</strong>를 경험해보세요.<br><strong>드라마틱한 해안 절벽의 구눙 투낙</strong>, <strong>자연 폭포의 베낭 세토켈</strong>, <strong>평화로운 호수와 숲의 구눙 자에</strong> 등 다양한 명소를 탐험할 수 있습니다.</p><p style=\"text-align:justify;\">단 몇 시간 만에 <strong>야생 자연 + 스릴 + 압도적인 풍경</strong>을 모두 경험할 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>하루를 다 쓰지 않고도 <strong>진짜 롬복 어드벤처</strong>를 경험할 수 있기 때문입니다:<br><strong>오프로드 + 숨겨진 자연 + 특별한 풍경</strong>까지 한 번에.</p><p style=\"text-align:justify;\">이런 여행을 원한다면:</p><ul><li data-list-item-id=\"e95bc17c2eab53f1cac6184e24e3c3ebc\"><p style=\"text-align:justify;\">짧지만 강렬한 모험</p></li><li data-list-item-id=\"e95af5939f20600e1bd4c5b5daa3dca97\"><p style=\"text-align:justify;\">남들과 다른 여행지</p></li><li data-list-item-id=\"ebc146d2bc7e53d5e70170fb2a01a41d9\"><p style=\"text-align:justify;\">부담 없는 액티비티</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 강한 경험.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복의 또 다른 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>龙目岛快闪探险：半日越野之旅 🚙🔥</strong></h2><p style=\"text-align:justify;\">时间不长，体验真实。</p><p style=\"text-align:justify;\">体验在森林、岩石道路以及隐藏秘境中驰骋的<strong>越野之旅</strong>。<br>探索<strong>Gunung Tunak（壮观海岸悬崖）</strong>、**Benang Setokel（天然瀑布）<strong>或</strong>Gunung Jae（宁静湖泊与森林）**等不同风景。</p><p style=\"text-align:justify;\">短短几小时，就能感受到<strong>原始自然 + 刺激体验 + 震撼景观</strong>的完美结合。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为这是在不花一整天时间的情况下，体验<strong>真正龙目岛探险</strong>的最佳方式：<br><strong>越野 + 秘境自然 + 独特风景</strong>一次拥有。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e3506699997634ed7c218dcd7c3616fe4\"><p style=\"text-align:justify;\">短时间但精彩的冒险</p></li><li data-list-item-id=\"ebda3f829f04755915293c63e1ee0b85f\"><p style=\"text-align:justify;\">小众且不拥挤的目的地</p></li><li data-list-item-id=\"ef8af9c6f144d379755db8524d58bd22e\"><p style=\"text-align:justify;\">轻松但有趣的体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>时间虽短，体验更强。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索龙目岛更狂野的一面了吗？</p>', 0.00, NULL, 1, 0, NULL, NULL, '<p>• 4x4 Double Cabin Vehicle (3-4 people per vehicle)<br>• Lunch at a Local Restaurant<br>• Coffee &amp; Tea<br>• Tour Guide<br>• Professional Driver<br>• 600ml Mineral Water (During the Program)<br>• Documentation (Photos + Cinematic Video)<br>• Entrance Tickets to Destinations</p>', '<p>• Personal expenses outside the program<br>• Tips for Guides &amp; Drivers</p>', NULL, '[\"Off-Road Experience\",\"Adventure\",\"Nature\",\"Coastal Scenic\"]', NULL, 0, NULL, '2026-05-22 13:23:35', '2026-05-29 13:45:18'),
(72, 45, 'LOMBOK PARAGLIDING TOUR', 'NUSA TENGGARA BARAT', 'lombok-paragliding-tour', '<h2 style=\"text-align:justify;\"><strong>Lombok Sky Escape: Paragliding &amp; Coastal Paradise 🪂🌊</strong></h2><p style=\"text-align:justify;\">Not just a tour—this is next level experience.</p><p style=\"text-align:justify;\">Mulai dari momen paling epic: <strong>terbang paragliding dari Bukit Paralayang</strong>, melayang di atas pantai selatan Lombok dengan view laut biru luas dari ketinggian. Pure adrenaline + cinematic view.</p><p style=\"text-align:justify;\">Lanjut ke <strong>Pantai Tanjung Aan &amp; Bukit Merese</strong>—pantai pasir putih dengan air super jernih dan spot view yang aesthetic banget.<br>Tutup dengan hidden gems seperti <strong>Pantai Selong Belanak &amp; Mawi</strong>—vibes lebih tenang, lebih clean, dan perfect buat chill.</p><p style=\"text-align:justify;\">Ditambah sentuhan lokal di Desa Sade—simple, authentic, dan tetap terasa Lombok.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet kombinasi yang jarang ada dalam 1 hari:<br><strong>paragliding experience + iconic beaches + scenic hills + hidden coastline</strong>—semua dalam satu trip yang unforgettable.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"ebdeb940b8961f630164203169df54f79\"><p style=\"text-align:justify;\">Experience unik (bukan sekadar sightseeing)</p></li><li data-list-item-id=\"e89dd45d8a7fd5f6eb35c0fdd4826b816\"><p style=\"text-align:justify;\">View paling epic dari udara</p></li><li data-list-item-id=\"ed1fa0aaf3b279fac8359dde0936d064a\"><p style=\"text-align:justify;\">Kombinasi adventure + beach + aesthetic spot</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fly high. Feel free.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap lihat Lombok dari sudut yang beda?</p>', '<h2 style=\"text-align:justify;\"><strong>Lombok Sky Escape: Paragliding &amp; Coastal Paradise 🪂🌊</strong></h2><p style=\"text-align:justify;\">Not just a tour—this is next-level experience.</p><p style=\"text-align:justify;\">Start with the most epic moment: <strong>paragliding from Bukit Paralayang</strong>, flying above Lombok’s southern coastline with endless blue ocean views. Pure adrenaline meets cinematic scenery.</p><p style=\"text-align:justify;\">Continue to <strong>Tanjung Aan Beach &amp; Merese Hill</strong>—white sand beaches, crystal-clear water, and aesthetic viewpoints that hit different.<br>End your journey at hidden gems like <strong>Selong Belanak &amp; Mawi Beach</strong>—more peaceful, cleaner, and perfect for a chill escape.</p><p style=\"text-align:justify;\">Plus, a touch of local culture at Sade Village—simple, authentic, and uniquely Lombok.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get a rare combo in one day:<br><strong>paragliding + iconic beaches + scenic hills + hidden coastline</strong>—all in one unforgettable journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e314ea274c9669979651fe28ea2f561fb\"><p style=\"text-align:justify;\">A unique experience beyond sightseeing</p></li><li data-list-item-id=\"e01d0a2202e381a7d57045ec18075ebc0\"><p style=\"text-align:justify;\">Epic aerial views</p></li><li data-list-item-id=\"e2e3b7008a47c147a7a7957de968c98d2\"><p style=\"text-align:justify;\">Adventure + beach + aesthetic spots in one trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fly high. Feel free.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to see Lombok from a different perspective?</p>', '<h2 style=\"text-align:justify;\"><strong>롬복 스카이 여행: 패러글라이딩 &amp; 해안 파라다이스 🪂🌊</strong></h2><p style=\"text-align:justify;\">단순한 여행이 아닌, 한 단계 높은 경험.</p><p style=\"text-align:justify;\">가장 특별한 순간으로 시작하세요: <strong>부킷 파라라양에서 패러글라이딩</strong>—롬복 남부 해안을 하늘에서 내려다보는 압도적인 풍경. 짜릿함과 시네마틱 뷰의 완벽한 조합.</p><p style=\"text-align:justify;\">이어서 <strong>딴중 안 해변 &amp; 메레세 언덕</strong>—하얀 모래, 맑은 바다, 감각적인 전망 포인트.<br>마지막으로 <strong>셀롱 블라낙 &amp; 마위 해변</strong>—더 한적하고 깨끗한 숨겨진 해변에서 여유로운 시간.</p><p style=\"text-align:justify;\">사데 마을에서의 로컬 문화 체험까지—심플하지만 특별한 경험.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>하루 만에 <strong>특별한 조합</strong>을 경험할 수 있기 때문입니다:<br><strong>패러글라이딩 + 유명 해변 + 언덕 전망 + 숨겨진 해안</strong>까지.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"eb6aed160c1771936305b262e8158d44c\"><p style=\"text-align:justify;\">색다른 경험</p></li><li data-list-item-id=\"e16a6aa8e64aea32e9fe52227892e3b7a\"><p style=\"text-align:justify;\">하늘에서 보는 절경</p></li><li data-list-item-id=\"e8ac293526c96cd91161d3bf46be080ab\"><p style=\"text-align:justify;\">모험 + 바다 + 감성 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>하늘을 날고, 자유를 느껴보세요.</strong> 🚀</h3><p style=\"text-align:justify;\">롬복을 새로운 시선으로 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>龙目岛天空之旅：滑翔伞 + 海岸天堂 🪂🌊</strong></h2><p style=\"text-align:justify;\">这不仅是旅行，而是全新体验。</p><p style=\"text-align:justify;\">从最震撼的瞬间开始：<strong>在Bukit Paralayang滑翔伞飞行</strong>，从空中俯瞰龙目岛南部海岸与无边蓝海，刺激与美景完美结合。</p><p style=\"text-align:justify;\">接着前往<strong>Tanjung Aan海滩 &amp; Merese山丘</strong>——白色沙滩、清澈海水与绝美观景点。<br>最后探索<strong>Selong Belanak &amp; Mawi海滩</strong>——更安静、更纯净的隐藏海滩，适合放松享受。</p><p style=\"text-align:justify;\">再加上Sade村庄的在地文化体验——简单、真实又独特。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以在一天内体验<strong>独特组合</strong>：<br><strong>滑翔伞 + 标志性海滩 + 山丘美景 + 隐藏海岸</strong>，一次拥有。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e15bef4b43a50f268255cbe6cb89656c9\"><p style=\"text-align:justify;\">不一样的旅行体验</p></li><li data-list-item-id=\"e36265cbafca12be322695ad03f6dd144\"><p style=\"text-align:justify;\">从空中俯瞰绝美风景</p></li><li data-list-item-id=\"ecd3e601701289eb4e0f9d30ba5345f63\"><p style=\"text-align:justify;\">冒险 + 海岛 + 美景结合</p></li></ul><h3 style=\"text-align:justify;\"><strong>飞得更高，感受自由。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好用不同视角看龙目岛了吗？</p>', 0.00, NULL, 1, 0, NULL, NULL, '<p>• Paragliding Tandem Flight<br>• Professional Instructor &amp; Equipment<br>• Air-conditioned Transportation &amp; Fuel<br>• Driver as Guide<br>• Lunch &amp; Mineral Water<br>• Entrance Tickets to Tourist Attractions<br>• Photo Documentation</p>', '<p>• Instructor/Driver Tips<br>• Personal Expenses<br>• Travel Insurance<br>• GoPro Video (Optional)</p>', NULL, '[\"Adventure\",\"Beach\",\"Nature\",\"Culture\"]', NULL, 0, NULL, '2026-05-22 13:35:14', '2026-05-29 13:44:59'),
(74, 46, '4 DAYS JAKARTA CITY TOUR', 'JAKARTA', '4-days-jakarta-city-tour', '<h2 style=\"text-align:justify;\"><strong>Jakarta Urban Escape: Culture, Heritage &amp; Modern City Vibes 🌆✨</strong></h2><p style=\"text-align:justify;\">Rasakan serunya menjelajahi ibu kota Indonesia dalam satu perjalanan lengkap.<br>Explore sisi modern Jakarta di <strong>PIK 2</strong> dengan vibes kota yang trendy, café hits, dan spot waterfront yang iconic. Lanjut menyelami budaya Indonesia di <strong>TMII</strong>, lalu nikmati suasana bersejarah di <strong>Kota Tua</strong>, <strong>Pelabuhan Sunda Kelapa</strong>, dan <strong>Museum Bank Indonesia</strong>—tempat di mana cerita Batavia lama masih terasa hidup.</p><p style=\"text-align:justify;\">Nikmati perpaduan landmark ikonik Jakarta mulai dari <strong>Monas</strong>, <strong>Masjid Istiqlal</strong>, dan <strong>Gereja Katedral</strong>, hingga pengalaman shopping seru di <strong>Thamrin City &amp; Mangga Dua</strong>.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena Jakarta bukan cuma kota besar—tapi perpaduan <strong>history, culture, modern lifestyle, culinary experience, dan urban exploration</strong> dalam satu destinasi.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e9572320f1b2ad1aea8fd3cf171d3fb81\"><p style=\"text-align:justify;\">Experience city tour yang lengkap</p></li><li data-list-item-id=\"ee16caa6f090c49705cb0eccc018a3b84\"><p style=\"text-align:justify;\">Wisata sejarah &amp; budaya ikonik</p></li><li data-list-item-id=\"e2a545f573ac4cf6fc3f70c46593f7c48\"><p style=\"text-align:justify;\">Shopping, kuliner, dan urban vibes modern</p></li></ul><h3 style=\"text-align:justify;\"><strong>One city. Endless experiences.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore sisi paling hidup dari Jakarta?</p>', '<h2 style=\"text-align:justify;\"><strong>Jakarta Urban Escape: Culture, Heritage &amp; Modern City Vibes 🌆✨</strong></h2><p style=\"text-align:justify;\">Experience the energy of Indonesia’s capital in one complete journey.<br>Explore the modern side of Jakarta at <strong>PIK 2</strong> with trendy city vibes, stylish cafés, and iconic waterfront spots. Dive into Indonesia’s rich culture at <strong>TMII</strong>, then continue to the historical charm of <strong>Kota Tua</strong>, <strong>Sunda Kelapa Harbor</strong>, and <strong>Museum Bank Indonesia</strong>—where old Batavia stories still come alive.</p><p style=\"text-align:justify;\">Feel the contrast of Jakarta’s iconic landmarks from <strong>Monas</strong>, <strong>Istiqlal Mosque</strong>, and <strong>Cathedral Church</strong> to the bustling shopping scene at <strong>Thamrin City &amp; Mangga Dua</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because Jakarta is more than just a big city—it’s a mix of <strong>history, culture, modern lifestyle, culinary experiences, and city exploration</strong> all in one destination.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ed4dd32f3c7929df18a5db64d844f5523\"><p style=\"text-align:justify;\">A complete city experience</p></li><li data-list-item-id=\"e96422c970b7429d4cbeba08af3a4b77f\"><p style=\"text-align:justify;\">Historical &amp; cultural landmarks</p></li><li data-list-item-id=\"ecf083764d2ba65bb7e0c51bc650872ca\"><p style=\"text-align:justify;\">Shopping, food, and modern urban vibes</p></li></ul><h3 style=\"text-align:justify;\"><strong>One city. Endless experiences.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to discover the real vibes of Jakarta?</p>', '<h2 style=\"text-align:justify;\"><strong>자카르타 어반 여행: 문화, 역사 그리고 현대적인 도시 감성 🌆✨</strong></h2><p style=\"text-align:justify;\">인도네시아 수도 자카르타의 에너지를 한 번에 경험해보세요.<br>트렌디한 카페와 워터프론트 명소가 있는 <strong>PIK 2</strong>에서 현대적인 자카르타를 즐기고, <strong>TMII</strong>에서 인도네시아의 다양한 문화를 만나보세요. 이어서 <strong>코타 투아</strong>, <strong>순다 끌라파 항구</strong>, <strong>인도네시아 은행 박물관</strong>에서 옛 바타비아의 역사적인 분위기를 느낄 수 있습니다.</p><p style=\"text-align:justify;\">또한 <strong>모나스</strong>, <strong>이스티크랄 모스크</strong>, <strong>가톨릭 대성당</strong> 등 자카르타의 대표 랜드마크와 함께 <strong>탐린 시티 &amp; 망가 두아</strong>에서 쇼핑까지 즐길 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>자카르타는 단순한 대도시가 아니라<br><strong>역사 + 문화 + 현대 라이프스타일 + 미식 + 도시 탐험</strong>이 모두 어우러진 특별한 도시이기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e8f1502b842ffcaec4b0600d74583e5dd\"><p style=\"text-align:justify;\">완벽한 시티 투어</p></li><li data-list-item-id=\"e4045421fee69814a119ce2a9e61ee0fd\"><p style=\"text-align:justify;\">역사와 문화 명소</p></li><li data-list-item-id=\"e6241d98fbdccbd5b0a7d5d24c581c7ac\"><p style=\"text-align:justify;\">쇼핑과 도시 감성</p></li></ul><h3 style=\"text-align:justify;\"><strong>하나의 도시, 끝없는 경험.</strong> 🚀</h3><p style=\"text-align:justify;\">자카르타의 진짜 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>雅加达城市之旅：文化、历史与现代都市氛围 🌆✨</strong></h2><p style=\"text-align:justify;\">一次旅程，感受印尼首都雅加达的活力与魅力。<br>在充满时尚氛围的 <strong>PIK 2</strong> 体验现代都市感，打卡潮流咖啡馆与海滨景点；接着前往 <strong>TMII</strong> 感受印尼丰富多元的文化。<br>继续探索充满历史气息的 <strong>Kota Tua（老城区）</strong>、<strong>Sunda Kelapa港口</strong> 与 <strong>印尼银行博物馆</strong>，感受旧巴达维亚时代的故事。</p><p style=\"text-align:justify;\">同时还能欣赏雅加达标志性地标，如 <strong>Monas国家纪念塔</strong>、<strong>伊斯蒂克拉尔清真寺</strong> 和 <strong>大教堂</strong>，再到 <strong>Thamrin City &amp; Mangga Dua</strong> 享受购物乐趣。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为雅加达不仅仅是一座大城市，<br>更是 <strong>历史、文化、现代生活、美食与城市探索</strong> 的完美结合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"eb1d7eb2c419c14dcc92bee45afb40aaa\"><p style=\"text-align:justify;\">完整的城市体验</p></li><li data-list-item-id=\"e17fc45fd2c1220c1f1ef6a7c714fa6c2\"><p style=\"text-align:justify;\">历史与文化地标</p></li><li data-list-item-id=\"e6f50a177cab7825ec7c8465e6d03e6ae\"><p style=\"text-align:justify;\">购物、美食与都市氛围</p></li></ul><h3 style=\"text-align:justify;\"><strong>一座城市，无限体验。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索真正的雅加达了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"City\",\"Historical\",\"Heritage\",\"Culture\",\"Shopping\"]', NULL, 0, NULL, '2026-05-27 11:45:51', '2026-05-29 13:32:11'),
(75, 46, '3 DAYS JAKARTA CITY TOUR', 'JAKARTA', '3-days-jakarta-city-tour', '<h2 style=\"text-align:justify;\"><strong>Jakarta Essential Escape: Culture, Landmark &amp; Modern City Vibes 🌆✨</strong></h2><p style=\"text-align:justify;\">Short trip, tapi tetap full experience.</p><p style=\"text-align:justify;\">Explore sisi modern Jakarta di <strong>PIK 2</strong>—kawasan hits dengan vibes kota yang trendy, waterfront aesthetic, dan suasana urban yang fresh banget.<br>Lanjut ke <strong>TMII</strong>, tempat terbaik untuk melihat keberagaman budaya Indonesia dalam satu lokasi.<br>Lengkapi perjalanan dengan mengunjungi landmark ikonik Jakarta seperti <strong>Monas</strong>, <strong>Masjid Istiqlal</strong>, dan <strong>Gereja Katedral</strong>, lalu nikmati pengalaman shopping seru di kawasan terkenal <strong>Mangga Dua</strong>.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam waktu singkat kamu bisa merasakan kombinasi terbaik Jakarta:<br><strong>modern city + culture + history + shopping experience</strong> dalam satu perjalanan yang simple tapi lengkap.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e55378e7f44413bddce1b483187214534\"><p style=\"text-align:justify;\">Short city escape yang praktis</p></li><li data-list-item-id=\"ec4d6acebfd1b0b74263f4589b76c174f\"><p style=\"text-align:justify;\">Wisata landmark &amp; budaya ikonik Jakarta</p></li><li data-list-item-id=\"eb1f45d3b3bef789f85e3b512a6c929ab\"><p style=\"text-align:justify;\">Urban vibes, shopping, dan kuliner dalam satu trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Full Jakarta vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore sisi modern dan budaya Jakarta dalam satu perjalanan?</p>', '<h2 style=\"text-align:justify;\"><strong>Jakarta Essential Escape: Culture, Landmark &amp; Modern City Vibes 🌆✨</strong></h2><p style=\"text-align:justify;\">Short trip, full Jakarta experience.</p><p style=\"text-align:justify;\">Explore the modern side of Jakarta at <strong>PIK 2</strong>—trendy city vibes, aesthetic waterfront spots, and a fresh urban atmosphere.<br>Continue to <strong>TMII</strong>, the perfect place to discover Indonesia’s diverse culture in one destination.<br>Complete your journey by visiting Jakarta’s iconic landmarks such as <strong>Monas</strong>, <strong>Istiqlal Mosque</strong>, and <strong>Cathedral Church</strong>, then enjoy shopping time at the famous <strong>Mangga Dua</strong> area.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in a short time, you can experience the best combination of Jakarta:<br><strong>modern city + culture + history + shopping experience</strong> all in one simple yet complete journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e1ae2262585092993024561038eb0af09\"><p style=\"text-align:justify;\">A practical short city escape</p></li><li data-list-item-id=\"e6b70737db388a0a5ed157c80dc726a3f\"><p style=\"text-align:justify;\">Jakarta’s iconic landmarks &amp; culture</p></li><li data-list-item-id=\"e9c4cf68036cebdd0e755b5d68b25bec6\"><p style=\"text-align:justify;\">Urban vibes, shopping, and culinary experiences in one trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>Short trip. Full Jakarta vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the modern and cultural side of Jakarta?</p>', '<h2 style=\"text-align:justify;\"><strong>자카르타 에센셜 여행: 문화, 랜드마크 그리고 현대 도시 감성 🌆✨</strong></h2><p style=\"text-align:justify;\">짧지만 완벽한 자카르타 여행.</p><p style=\"text-align:justify;\">트렌디한 도시 분위기와 감각적인 워터프론트가 있는 <strong>PIK 2</strong>에서 현대적인 자카르타를 경험해보세요.<br>이어서 <strong>TMII</strong>에서 인도네시아의 다양한 문화를 한 곳에서 만나볼 수 있습니다.<br>또한 <strong>모나스</strong>, <strong>이스티크랄 모스크</strong>, <strong>가톨릭 대성당</strong> 등 자카르타 대표 랜드마크를 방문하고, 유명 쇼핑 지역인 <strong>망가 두아</strong>에서 쇼핑까지 즐길 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>짧은 시간 안에 자카르타의 매력을 모두 경험할 수 있기 때문입니다:<br><strong>현대 도시 + 문화 + 역사 + 쇼핑</strong>을 한 번에.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"ec8b79d9f481259d8fff50fd9654fc0dc\"><p style=\"text-align:justify;\">짧지만 알찬 도시 여행</p></li><li data-list-item-id=\"ecca530a7ac2cc314074a175f97cc785f\"><p style=\"text-align:justify;\">자카르타 대표 명소와 문화 체험</p></li><li data-list-item-id=\"e3f550c68557d8a3f3b9bb09b2f387f16\"><p style=\"text-align:justify;\">도시 감성, 쇼핑, 미식 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>짧지만 완벽한 자카르타 감성.</strong> 🚀</h3><p style=\"text-align:justify;\">자카르타의 현대적이고 문화적인 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>雅加达精华之旅：文化、地标与现代都市氛围 🌆✨</strong></h2><p style=\"text-align:justify;\">短时间，也能完整体验雅加达。</p><p style=\"text-align:justify;\">在充满时尚氛围的 <strong>PIK 2</strong> 感受现代雅加达的城市魅力，欣赏海滨景观与潮流生活方式。<br>接着前往 <strong>TMII</strong>，一次体验印尼丰富多元的文化。<br>旅程还包括雅加达著名地标，如 <strong>Monas国家纪念塔</strong>、<strong>伊斯蒂克拉尔清真寺</strong> 和 <strong>大教堂</strong>，最后在知名购物区 <strong>Mangga Dua</strong> 享受购物乐趣。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为在短时间内，你就能感受雅加达最精彩的组合：<br><strong>现代都市 + 文化 + 历史 + 购物体验</strong>一次拥有。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e056c8e36f9ec407ec3c944225db2c9bc\"><p style=\"text-align:justify;\">轻松方便的城市短途旅行</p></li><li data-list-item-id=\"ee3d31aee4270e49475f99bc19fc61218\"><p style=\"text-align:justify;\">雅加达经典地标与文化体验</p></li><li data-list-item-id=\"e865a70076422a9cfbca1d1237bdb0490\"><p style=\"text-align:justify;\">都市氛围、购物与美食</p></li></ul><h3 style=\"text-align:justify;\"><strong>短途旅行，完整雅加达体验。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索雅加达现代与文化的一面了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"City\",\"Culture\",\"Landmark\",\"Shopping\"]', NULL, 0, NULL, '2026-05-27 11:58:54', '2026-05-29 13:31:48'),
(76, 46, '5 DAYS BOGOR BANDUNG CITY TOUR', 'BANDUNG', '5-days-bogor-bandung-city-tour', '<h2 style=\"text-align:justify;\"><strong>Bogor Bandung Escape: Nature, Safari &amp; City Vibes 🌿🌆✨</strong></h2><p style=\"text-align:justify;\">Escape dari hiruk pikuk kota dan nikmati kombinasi terbaik antara alam, lifestyle, dan hidden gems favorit di Bogor &amp; Bandung.<br>Mulai dari udara sejuk <strong>Kebun Raya Bogor</strong> dan hamparan hijau perkebunan teh, lalu rasakan serunya bertemu satwa di <strong>Taman Safari Indonesia</strong>.</p><p style=\"text-align:justify;\">Lanjut ke Bandung dengan suasana yang totally different—mulai dari spot hits seperti <strong>Floating Market / Farmhouse</strong>, vibes klasik di <strong>Jalan Braga &amp; Asia Afrika</strong>, hingga panorama alam super aesthetic di <strong>Kawah Putih, Glamping Lakeside, dan Ranca Upas</strong>.<br>Ditambah shopping dan kuliner khas yang bikin trip makin lengkap.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam satu perjalanan kamu bisa dapetin kombinasi lengkap:<br><strong>nature + safari experience + cool city vibes + instagrammable spots + shopping &amp; culinary</strong> tanpa terasa monoton.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e0f9c84b252e6a5d07a9ae3df782f9096\"><p style=\"text-align:justify;\">Liburan lengkap dan variatif</p></li><li data-list-item-id=\"e5d38d651380cb69b9c27c109d4ec3a86\"><p style=\"text-align:justify;\">Udara sejuk &amp; scenery alam yang fresh</p></li><li data-list-item-id=\"e3022c5c897a18bd8fe56b40dea1411b9\"><p style=\"text-align:justify;\">Banyak spot aesthetic &amp; iconic</p></li></ul><h3 style=\"text-align:justify;\"><strong>One trip. All experiences.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore sisi paling seru dari Bogor &amp; Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>Bogor Bandung Escape: Nature, Safari &amp; City Vibes 🌿🌆✨</strong></h2><p style=\"text-align:justify;\">Escape the busy city life and enjoy the perfect combination of nature, lifestyle, and iconic destinations in Bogor &amp; Bandung.<br>Start with the fresh atmosphere of <strong>Bogor Botanical Garden</strong> and the beautiful green tea plantations, then experience the excitement of meeting wildlife at <strong>Taman Safari Indonesia</strong>.</p><p style=\"text-align:justify;\">Continue to Bandung with totally different vibes—from trendy spots like <strong>Floating Market / Farmhouse</strong>, the classic atmosphere of <strong>Braga Street &amp; Asia Afrika Street</strong>, to breathtaking natural scenery at <strong>Kawah Putih, Glamping Lakeside, and Ranca Upas</strong>.<br>Complete your trip with shopping and local culinary experiences.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in one journey, you get the perfect combination of:<br><strong>nature + safari experience + cool city vibes + instagrammable spots + shopping &amp; culinary experiences</strong> without ever feeling boring.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"eb40a3f8c06e8d5de9dd1508960ee309b\"><p style=\"text-align:justify;\">A complete and varied holiday</p></li><li data-list-item-id=\"e46fcf34755b97f7dc22f136930b91142\"><p style=\"text-align:justify;\">Cool weather &amp; refreshing natural scenery</p></li><li data-list-item-id=\"e801bcf324d99e7f420388de2d9461592\"><p style=\"text-align:justify;\">Iconic and aesthetic destinations</p></li></ul><h3 style=\"text-align:justify;\"><strong>One trip. All experiences.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the best side of Bogor &amp; Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>보고르 &amp; 반둥 여행: 자연, 사파리 그리고 도시 감성 🌿🌆✨</strong></h2><p style=\"text-align:justify;\">복잡한 도시를 벗어나 보고르와 반둥의 자연과 라이프스타일을 한 번에 즐겨보세요.<br>시원한 공기의 <strong>보고르 식물원</strong>과 푸른 차밭에서 시작해, <strong>타만 사파리 인도네시아</strong>에서 다양한 동물을 가까이 만나는 특별한 경험을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">이후 반둥에서는 또 다른 분위기를 경험하게 됩니다.<br><strong>플로팅 마켓 / 팜하우스</strong> 같은 인기 명소부터, 감성적인 <strong>브라가 거리 &amp; 아시아 아프리카 거리</strong>, 그리고 <strong>카와 푸티, 글램핑 레이크사이드, 란차 우파스</strong>의 아름다운 자연 풍경까지 모두 담았습니다.<br>쇼핑과 현지 음식까지 더해져 더욱 완벽한 여행이 됩니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 사파리 체험 + 도시 감성 + 인스타 감성 스팟 + 쇼핑 &amp; 미식</strong>을 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 원한다면:</p><ul><li data-list-item-id=\"ed6c0fa6df4461967b0c4efb9ef2da791\"><p style=\"text-align:justify;\">다양하고 알찬 여행</p></li><li data-list-item-id=\"e430fbb5fb9ebf7825db0d3dd5db1b97e\"><p style=\"text-align:justify;\">시원한 날씨와 자연 풍경</p></li><li data-list-item-id=\"e04a2b21db0671cbf92fc6e87f0a2f6e6\"><p style=\"text-align:justify;\">감성적이고 유명한 포토 스팟</p></li></ul><h3 style=\"text-align:justify;\"><strong>한 번의 여행, 모든 경험.</strong> 🚀</h3><p style=\"text-align:justify;\">보고르와 반둥의 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>茂物万隆之旅：自然、野生动物与城市氛围 🌿🌆✨</strong></h2><p style=\"text-align:justify;\">远离城市喧嚣，体验茂物与万隆最精彩的自然与都市魅力。<br>从空气清新的 <strong>茂物植物园</strong> 和绿色茶园开始，再到 <strong>印尼野生动物园（Taman Safari Indonesia）</strong> 与动物近距离互动，感受特别体验。</p><p style=\"text-align:justify;\">接着前往拥有不同氛围的万隆，打卡热门景点 <strong>Floating Market / Farm House</strong>，感受 <strong>Braga街与Asia Afrika街</strong> 的经典城市气息，以及 <strong>Kawah Putih、Glamping Lakeside 和 Ranca Upas</strong> 的绝美自然风景。<br>再加上购物与当地美食，让旅程更加完整。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>自然 + 野生动物体验 + 城市氛围 + 网红打卡景点 + 购物与美食</strong>，丰富又不单调。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"eb975d679691a514e072b31707fa6da74\"><p style=\"text-align:justify;\">丰富多样的假期体验</p></li><li data-list-item-id=\"ee0338f6277a747ca0e61d80e45af0a59\"><p style=\"text-align:justify;\">凉爽天气与自然景观</p></li><li data-list-item-id=\"ecd398f72058a25d4e724300b69d916ad\"><p style=\"text-align:justify;\">经典又好拍的景点</p></li></ul><h3 style=\"text-align:justify;\"><strong>一次旅行，完整体验。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索茂物与万隆最精彩的一面了吗？</p>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English-Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"Nature\",\"Scenic\",\"Wildlife\",\"Family Adventure Tourism\",\"Urban Leisure\",\"Culture\",\"HERITAGE\",\"Shopping\",\"CULINARY\"]', NULL, 0, NULL, '2026-05-27 12:18:45', '2026-05-29 13:31:24'),
(77, 46, '3 DAYS BOGOR CITY TOUR', 'BOGOR', '3-days-bogor-city-tour', '<h2 style=\"text-align:justify;\"><strong>Bogor Nature Escape: Safari, Tea Hills &amp; Fresh Mountain Vibes 🌿🦁✨</strong></h2><p style=\"text-align:justify;\">Escape sejenak dari panas dan ramainya kota, lalu nikmati suasana hijau dan udara segar khas Bogor &amp; Puncak.<br>Mulai perjalanan di <strong>Kebun Raya Bogor</strong> dengan landscape tropis yang tenang, lanjut menikmati hamparan hijau <strong>perkebunan teh</strong> yang super relaxing dan aesthetic.</p><p style=\"text-align:justify;\">Highlight utamanya?<br>Experience seru di <strong>Taman Safari Indonesia</strong>—lihat satwa dari dekat dalam suasana alam terbuka yang bikin trip terasa lebih hidup dan unforgettable.<br>Ditambah shopping santai di <strong>Tajur Factory Outlet</strong>, bikin perjalanan makin lengkap.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena dalam waktu singkat kamu bisa menikmati kombinasi terbaik:<br><strong>nature + safari adventure + cool weather + relaxing scenery</strong> dalam satu trip yang simple tapi memorable.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e9355e1f053762f8e22aa4e957ecec5b9\"><p style=\"text-align:justify;\">Short escape dengan udara fresh</p></li><li data-list-item-id=\"e00326e2ec51d90b44fb63bff49bcf2de\"><p style=\"text-align:justify;\">Nature trip yang santai tapi tetap seru</p></li><li data-list-item-id=\"eb2cd770d8455b14e432f889a0df2f220\"><p style=\"text-align:justify;\">Family trip atau healing getaway</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Wild adventure. Pure escape.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap recharge diri di alam hijau Bogor?</p>', '<h2 style=\"text-align:justify;\"><strong>Bogor Nature Escape: Safari, Tea Hills &amp; Fresh Mountain Vibes 🌿🦁✨</strong></h2><p style=\"text-align:justify;\">Take a break from the busy city and enjoy the fresh green atmosphere of Bogor &amp; Puncak.<br>Start your journey at <strong>Bogor Botanical Garden</strong> with its peaceful tropical scenery, then continue through the beautiful green <strong>tea plantations</strong> with relaxing and aesthetic mountain views.</p><p style=\"text-align:justify;\">The main highlight?<br>An exciting experience at <strong>Taman Safari Indonesia</strong>—get close to wildlife in an open natural environment that makes the trip more alive and unforgettable.<br>Complete your journey with a fun shopping experience at <strong>Tajur Factory Outlet</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in a short getaway, you can enjoy the perfect combination of:<br><strong>nature + safari adventure + cool weather + relaxing scenery</strong> in one simple yet memorable trip.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e2810e23446978ae700cfe323ff9e9947\"><p style=\"text-align:justify;\">A refreshing short escape</p></li><li data-list-item-id=\"ee2eb6e04705b05fc69e6ef70c0471b75\"><p style=\"text-align:justify;\">A relaxing but exciting nature trip</p></li><li data-list-item-id=\"e4ab36cca4693c8755fa76d4c039c906f\"><p style=\"text-align:justify;\">A family holiday or healing getaway</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Wild adventure. Pure escape.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to recharge yourself in Bogor’s green nature?</p>', '<h2 style=\"text-align:justify;\"><strong>보고르 네이처 여행: 사파리, 차밭 그리고 시원한 산속 감성 🌿🦁✨</strong></h2><p style=\"text-align:justify;\">복잡한 도시를 잠시 벗어나 보고르와 푼착의 신선한 자연을 즐겨보세요.<br>평화로운 열대 풍경의 <strong>보고르 식물원</strong>에서 시작해, 푸르게 펼쳐진 <strong>차밭</strong>과 시원한 산 풍경 속에서 힐링할 수 있습니다.</p><p style=\"text-align:justify;\">가장 큰 하이라이트는?<br>바로 <strong>타만 사파리 인도네시아</strong>에서의 특별한 경험입니다. 자연 속에서 다양한 동물을 가까이 만나며 더욱 생생하고 잊지 못할 시간을 보낼 수 있습니다.<br>마지막으로 <strong>타주르 팩토리 아울렛</strong>에서 쇼핑까지 즐기며 여행을 완성하세요.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>짧은 여행 안에서<br><strong>자연 + 사파리 체험 + 시원한 날씨 + 힐링 풍경</strong>을 모두 경험할 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e064800e0473efa1b00530c771a749767\"><p style=\"text-align:justify;\">짧지만 상쾌한 휴식</p></li><li data-list-item-id=\"ea44964a29af417adc4ccb098bc782df1\"><p style=\"text-align:justify;\">편안하면서도 즐거운 자연 여행</p></li><li data-list-item-id=\"e69505a9aa01efc0f187d836aa39c6c90\"><p style=\"text-align:justify;\">가족 여행 또는 힐링 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>맑은 공기, 야생의 모험, 완벽한 휴식.</strong> 🚀</h3><p style=\"text-align:justify;\">보고르의 푸른 자연 속에서 힐링해보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>茂物自然之旅：野生动物、茶园与清新山景 🌿🦁✨</strong></h2><p style=\"text-align:justify;\">暂时远离城市喧嚣，感受茂物与Puncak清新凉爽的大自然。<br>从宁静的 <strong>茂物植物园</strong> 开始，欣赏热带绿意与舒适氛围，再前往大片绿色 <strong>茶园</strong>，享受放松又治愈的山景风光。</p><p style=\"text-align:justify;\">最大的亮点？<br>当然是 <strong>印尼野生动物园（Taman Safari Indonesia）</strong>！<br>近距离接触各种动物，在开放自然环境中体验更生动、更难忘的旅程。<br>最后还能在 <strong>Tajur Factory Outlet</strong> 享受轻松购物时光。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为短短旅程中，你就能体验：<br><strong>自然风景 + 野生动物体验 + 凉爽天气 + 放松氛围</strong> 的完美结合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e8a2772f1e5e5629c18565ed5e37974c7\"><p style=\"text-align:justify;\">短暂放松的逃离之旅</p></li><li data-list-item-id=\"e36d8f6d13076c92b63176bd362ef9bf3\"><p style=\"text-align:justify;\">轻松又有趣的大自然体验</p></li><li data-list-item-id=\"efe35d5a7d4971c8ca856652977a5802a\"><p style=\"text-align:justify;\">家庭旅行或疗愈假期</p></li></ul><h3 style=\"text-align:justify;\"><strong>清新空气，野性冒险，真正放松。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好在茂物绿色大自然中放松身心了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English-Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"Nature\",\"Family\",\"Leisure\",\"Shopping\"]', NULL, 0, NULL, '2026-05-27 12:33:39', '2026-05-29 13:30:45');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(78, 46, '4 DAYS NORTH BANDUNG TOUR', 'BANDUNG', '4-days-north-bandung-tour', '<h2 style=\"text-align:justify;\"><strong>Bandung Ultimate Escape: Nature, Shopping &amp; Trendy City Vibes 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">Nikmati kombinasi terbaik dari Bandung—udara sejuk pegunungan, spot hits yang aesthetic, dan surganya shopping dalam satu perjalanan lengkap.<br>Explore sisi alam Bandung Utara mulai dari <strong>Tangkuban Perahu</strong>, suasana seru di <strong>Floating Market / Farm House</strong>, hingga vibes unik di <strong>The Great Asia Africa</strong> yang penuh spot foto iconic.</p><p style=\"text-align:justify;\">Belum lengkap tanpa shopping experience khas Bandung—mulai dari <strong>Rumah Mode, Pasar Baru, Riau &amp; Dago Factory Outlet</strong>, sampai wisata kuliner dan oleh-oleh favorit seperti <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Ditambah experience naik <strong>Whoosh High Speed Train</strong> yang modern dan super cepat.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu dapet kombinasi paling lengkap dalam satu trip:<br><strong>nature + shopping paradise + culinary + modern lifestyle + iconic Bandung vibes</strong> tanpa terasa membosankan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"ed439edda0c781cc5a79e9f2abca1593f\"><p style=\"text-align:justify;\">Liburan santai tapi tetap seru</p></li><li data-list-item-id=\"edbab046fcdb9523a2b2d23e49beb6f28\"><p style=\"text-align:justify;\">Shopping &amp; kuliner khas Bandung</p></li><li data-list-item-id=\"e3e520446f3bdad37384c378140c79c40\"><p style=\"text-align:justify;\">Spot aesthetic dan udara sejuk pegunungan</p></li></ul><h3 style=\"text-align:justify;\"><strong>Cool weather. Endless shopping. Perfect escape.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap jatuh cinta sama vibes Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>Bandung Ultimate Escape: Nature, Shopping &amp; Trendy City Vibes 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">Enjoy the best of Bandung—cool mountain air, aesthetic attractions, and a shopping paradise all in one complete journey.<br>Explore the natural beauty of Northern Bandung, from the iconic <strong>Tangkuban Perahu</strong>, the fun atmosphere of <strong>Floating Market / Farm House</strong>, to the unique vibes of <strong>The Great Asia Africa</strong> filled with instagrammable photo spots.</p><p style=\"text-align:justify;\">The trip wouldn’t be complete without Bandung’s famous shopping experience—starting from <strong>Rumah Mode, Pasar Baru, Riau &amp; Dago Factory Outlet</strong>, plus local culinary and souvenir favorites like <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Complete your journey with the modern and exciting experience of riding the <strong>Whoosh High Speed Train</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you get the perfect combination of:<br><strong>nature + shopping paradise + culinary + modern lifestyle + iconic Bandung vibes</strong> all in one unforgettable escape.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e51e39586c1f05feb6ad8df2a573cee23\"><p style=\"text-align:justify;\">A relaxing yet exciting holiday</p></li><li data-list-item-id=\"eac2009f5b35036afea6decb3e01e79dd\"><p style=\"text-align:justify;\">Bandung’s famous shopping &amp; culinary experience</p></li><li data-list-item-id=\"e19bec47530109adb721420797b54a311\"><p style=\"text-align:justify;\">Aesthetic spots with cool mountain weather</p></li></ul><h3 style=\"text-align:justify;\"><strong>Cool weather. Endless shopping. Perfect escape.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to fall in love with Bandung vibes?</p>', '<h2 style=\"text-align:justify;\"><strong>반둥 얼티밋 여행: 자연, 쇼핑 그리고 트렌디한 도시 감성 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">시원한 산 공기, 감성적인 명소, 그리고 쇼핑 천국 반둥을 한 번에 즐겨보세요.<br>북부 반둥의 자연 명소인 <strong>탕쿠반 프라후</strong>, 인기 명소 <strong>플로팅 마켓 / 팜하우스</strong>, 그리고 다양한 포토 스팟이 가득한 <strong>더 그레이트 아시아 아프리카</strong>까지 특별한 분위기를 경험할 수 있습니다.</p><p style=\"text-align:justify;\">또한 <strong>루마 모드, 파사르 바루, 리아우 &amp; 다고 팩토리 아울렛</strong>에서 쇼핑을 즐기고, <strong>카르티카 사리 &amp; 프리마 라사</strong>의 유명 먹거리와 기념품도 놓칠 수 없습니다.<br>마지막으로 현대적이고 빠른 <strong>후시(Whoosh) 고속열차</strong> 탑승 경험까지 더해집니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 쇼핑 + 미식 + 현대 라이프스타일 + 반둥 감성</strong>을 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e1c91bedf9d8bb3f089fd3cd315e6a14c\"><p style=\"text-align:justify;\">편안하면서도 즐거운 휴가</p></li><li data-list-item-id=\"e021724daf5f6182ffb108c54dd9c4f3b\"><p style=\"text-align:justify;\">반둥 스타일 쇼핑과 미식</p></li><li data-list-item-id=\"e65a0d543782b494c63f41871e8d963d4\"><p style=\"text-align:justify;\">감성적인 포토 스팟과 시원한 날씨</p></li></ul><h3 style=\"text-align:justify;\"><strong>시원한 날씨, 끝없는 쇼핑, 완벽한 여행.</strong> 🚀</h3><p style=\"text-align:justify;\">반둥의 매력에 빠질 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>万隆终极之旅：自然、购物与潮流城市氛围 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">一次旅行，尽享万隆最精彩的一面——凉爽山景、网红景点与购物天堂。<br>探索万隆北部自然风光，从著名的 <strong>Tangkuban Perahu火山</strong>、热门景点 <strong>Floating Market / Farm House</strong>，到充满异国风情与拍照打卡点的 <strong>The Great Asia Africa</strong>。</p><p style=\"text-align:justify;\">当然也少不了万隆最有名的购物体验：<br><strong>Rumah Mode、Pasar Baru、Riau &amp; Dago Factory Outlet</strong>，再加上当地经典美食与伴手礼 <strong>Kartika Sari &amp; Prima Rasa</strong>。<br>旅程还包含现代又快速的 <strong>Whoosh高速列车</strong> 体验，让行程更加特别。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以一次拥有：<br><strong>自然风景 + 购物天堂 + 美食 + 现代生活方式 + 万隆经典氛围</strong>。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e8a373420d956e695734b6e27738f6aba\"><p style=\"text-align:justify;\">轻松又丰富的假期</p></li><li data-list-item-id=\"e5da31248747cde6593150c9b1ae15a97\"><p style=\"text-align:justify;\">万隆特色购物与美食</p></li><li data-list-item-id=\"e2c0dd775bf6b0c32d8adab94bbf97fec\"><p style=\"text-align:justify;\">凉爽天气与高颜值景点</p></li></ul><h3 style=\"text-align:justify;\"><strong>凉爽天气，无尽购物，完美假期。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好爱上万隆的魅力了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English-Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"Nature\",\"Mountain Leisure\",\"Shopping\",\"Urban Lifestyle\",\"City\",\"Modern Travel Experience\",\"Culinary\"]', NULL, 0, NULL, '2026-05-27 12:54:30', '2026-05-29 13:30:08'),
(79, 46, '4 DAYS SOUTH BANDUNG TOUR', 'BANDUNG', '4-days-south-bandung-tour', '<h2 style=\"text-align:justify;\"><strong>Bandung South Escape: Nature, Scenic Views &amp; Shopping Paradise 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">Nikmati sisi paling relaxing dan aesthetic dari Bandung Selatan dalam satu perjalanan lengkap.<br>Mulai dari panorama ikonik <strong>Kawah Putih</strong> dengan danau vulkanik berwarna eksotis yang super cinematic, lalu lanjut menikmati suasana tenang di <strong>Glamping Lakeside</strong> dengan view danau dan pegunungan yang fresh banget.</p><p style=\"text-align:justify;\">Rasakan juga pengalaman seru di <strong>Rengganis Suspension Bridge</strong>—jembatan gantung dengan panorama alam hijau yang unforgettable.<br>Lengkapi perjalanan dengan shopping khas Bandung di <strong>Cibaduyut Leather Center</strong>, factory outlet terkenal, hingga wisata kuliner dan oleh-oleh favorit seperti <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Ditambah experience naik <strong>Whoosh High Speed Train</strong> yang modern dan super cepat.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu bisa menikmati kombinasi terbaik:<br><strong>nature + cool weather + scenic landscape + shopping + culinary experience</strong> dalam satu trip yang santai tapi tetap exciting.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e35522335c38f0be9e51feb4ac9185abc\"><p style=\"text-align:justify;\">Healing trip dengan view alam yang aesthetic</p></li><li data-list-item-id=\"e823e45804e7007645f32b4395951bd82\"><p style=\"text-align:justify;\">Udara sejuk &amp; suasana relaxing</p></li><li data-list-item-id=\"eac4649115303d8d5afd6c8cc7ba884f8\"><p style=\"text-align:justify;\">Shopping dan kuliner khas Bandung</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Scenic escape. Endless Bandung vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore sisi paling indah dari Bandung Selatan?</p>', '<h2 style=\"text-align:justify;\"><strong>Bandung South Escape: Nature, Scenic Views &amp; Shopping Paradise 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">Discover the most relaxing and aesthetic side of South Bandung in one complete journey.<br>Start with the iconic beauty of <strong>Kawah Putih</strong>, a stunning volcanic crater lake with surreal colors and cinematic scenery. Continue to <strong>Glamping Lakeside</strong>, where you can enjoy peaceful lake and mountain views with fresh cool air all around.</p><p style=\"text-align:justify;\">Experience the excitement of <strong>Rengganis Suspension Bridge</strong>, surrounded by breathtaking green landscapes and unforgettable panoramic views.<br>Complete your trip with Bandung’s famous shopping experience at <strong>Cibaduyut Leather Center</strong>, popular factory outlets, and local culinary favorites like <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Plus, enjoy the modern and exciting ride on the <strong>Whoosh High Speed Train</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you’ll experience the perfect combination of:<br><strong>nature + cool weather + scenic landscapes + shopping + culinary experiences</strong> in one relaxing yet exciting getaway.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e58c2a06ad59c583a5975c9de9fb26daf\"><p style=\"text-align:justify;\">A healing trip with aesthetic natural views</p></li><li data-list-item-id=\"e69faff1d1ab2f3f3f9c1e4dd326faf99\"><p style=\"text-align:justify;\">Cool weather and relaxing vibes</p></li><li data-list-item-id=\"ef3570ff336c06eaf91c9efe60a5c7bc2\"><p style=\"text-align:justify;\">Bandung shopping and culinary experiences</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Scenic escape. Endless Bandung vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the most beautiful side of South Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>반둥 남부 여행: 자연, 절경 그리고 쇼핑 천국 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">한 번의 여행으로 반둥 남부의 가장 아름답고 힐링되는 분위기를 만나보세요.<br>환상적인 색감의 화산 호수 <strong>카와 푸티(Kawah Putih)</strong> 에서 시작해, 시원한 공기와 호수 전망이 아름다운 <strong>글램핑 레이크사이드</strong>에서 여유로운 시간을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">또한 푸른 자연 속에서 펼쳐지는 <strong>렝가니스 서스펜션 브리지</strong>에서 특별한 풍경과 짜릿한 경험을 느껴보세요.<br>여기에 <strong>치바두윳 가죽 센터</strong>, 유명 팩토리 아울렛, 그리고 <strong>카르티카 사리 &amp; 프리마 라사</strong> 같은 반둥 대표 먹거리 쇼핑까지 더해져 더욱 완벽한 여행이 됩니다.<br>마지막으로 현대적이고 빠른 <strong>후시(Whoosh) 고속열차</strong> 경험도 포함됩니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 시원한 날씨 + 아름다운 풍경 + 쇼핑 + 미식 여행</strong>을 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e5ad5ddb695a5a5fcdd7208244ea3f042\"><p style=\"text-align:justify;\">감성적인 자연 힐링 여행</p></li><li data-list-item-id=\"ec128f4c8d800c31d73927fbda1b538da\"><p style=\"text-align:justify;\">시원하고 편안한 분위기</p></li><li data-list-item-id=\"efc66966c6c65cd88f2c365ab7ffc48f4\"><p style=\"text-align:justify;\">반둥 스타일 쇼핑과 먹거리</p></li></ul><h3 style=\"text-align:justify;\"><strong>맑은 공기, 아름다운 풍경, 끝없는 반둥 감성.</strong> 🚀</h3><p style=\"text-align:justify;\">반둥 남부의 가장 아름다운 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>万隆南部之旅：自然风景、绝美景观与购物天堂 🌿🛍️✨</strong></h2><p style=\"text-align:justify;\">一次旅行，感受万隆南部最放松、最美丽的一面。<br>从著名的 <strong>Kawah Putih火山湖</strong> 开始，欣赏梦幻般的火山湖景色与电影感风光；接着前往 <strong>Glamping Lakeside</strong>，享受湖泊与山景交织的清新氛围。</p><p style=\"text-align:justify;\">还能体验 <strong>Rengganis Suspension Bridge 吊桥</strong>，在绿色大自然中欣赏壮观全景与特别体验。<br>旅程也少不了万隆著名购物体验，包括 <strong>Cibaduyut皮革中心</strong>、热门 Factory Outlet，以及经典伴手礼与美食 <strong>Kartika Sari &amp; Prima Rasa</strong>。<br>再加上现代又快速的 <strong>Whoosh高速列车</strong> 体验，让旅程更加特别。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以一次享受：<br><strong>自然风景 + 凉爽天气 + 绝美景观 + 购物 + 美食体验</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e804eb62840beee79f413bc60b59369e3\"><p style=\"text-align:justify;\">轻松疗愈的自然旅行</p></li><li data-list-item-id=\"e466b410d9729abe4639a2835318dbb79\"><p style=\"text-align:justify;\">凉爽舒适的氛围</p></li><li data-list-item-id=\"e265103ea5695a7de2af1193bf6496d62\"><p style=\"text-align:justify;\">万隆购物与美食体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>清新空气，绝美风景，满满万隆氛围。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索万隆南部最迷人的风景了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English-Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"Nature\",\"Leisure\",\"SCENIC\",\"Family\",\"Shopping\"]', NULL, 0, NULL, '2026-05-27 13:12:57', '2026-05-29 13:29:41'),
(80, 46, '4 DAYS NORTH – SOUTH BANDUNG TOUR', 'BANDUNG', '4-days-north-south-bandung-tour', '<h2 style=\"text-align:justify;\"><strong>Bandung Ultimate Escape: North &amp; South Scenic Journey 🌿✨</strong></h2><p style=\"text-align:justify;\">Rasakan pengalaman Bandung paling lengkap dalam satu perjalanan—mulai dari pegunungan sejuk, spot aesthetic viral, hingga panorama alam yang bikin susah move on.<br>Explore sisi utara Bandung dengan keindahan <strong>Tangkuban Perahu</strong>, vibes seru di <strong>Floating Market / Farmhouse</strong>, dan spot instagrammable favorit di <strong>The Great Asia Africa</strong>.</p><p style=\"text-align:justify;\">Lanjut ke Bandung Selatan dengan pesona alam yang lebih cinematic—mulai dari eksotisnya <strong>Kawah Putih</strong>, tenangnya <strong>Glamping Lakeside</strong>, hingga pengalaman seru di <strong>Rengganis Suspension Bridge</strong> dengan panorama alam hijau yang breathtaking.</p><p style=\"text-align:justify;\">Belum lengkap tanpa shopping khas Bandung di factory outlet terkenal, pusat leather, dan wisata kuliner favorit seperti <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Ditambah experience naik <strong>Whoosh High Speed Train</strong> yang modern, cepat, dan unforgettable.</p><p style=\"text-align:justify;\">Kenapa harus pilih paket ini?<br>Karena kamu bisa menikmati kombinasi terbaik Bandung dalam satu trip:<br><strong>nature + scenic landscape + trendy attractions + shopping + culinary + cool weather</strong> tanpa terasa monoton.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"edddbdbc18e0aa776b61a896b1c57c3dc\"><p style=\"text-align:justify;\">Liburan lengkap dengan banyak destinasi iconic</p></li><li data-list-item-id=\"efdb2b778c5fd5b609b46f3f22e3a7906\"><p style=\"text-align:justify;\">Healing trip dengan udara sejuk &amp; view aesthetic</p></li><li data-list-item-id=\"eb94e2d9c77b804433aed4c132b25790d\"><p style=\"text-align:justify;\">Shopping, kuliner, dan city vibes dalam satu perjalanan</p></li></ul><h3 style=\"text-align:justify;\"><strong>North to South. One trip. Endless Bandung vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Siap explore seluruh sisi terbaik Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>Bandung Ultimate Escape: North &amp; South Scenic Journey 🌿✨</strong></h2><p style=\"text-align:justify;\">Experience the most complete side of Bandung in one unforgettable journey—from cool mountain landscapes and trendy attractions to breathtaking natural scenery.<br>Explore Northern Bandung with the iconic beauty of <strong>Tangkuban Perahu</strong>, the fun atmosphere of <strong>Floating Market / Farmhouse</strong>, and the instagrammable vibes of <strong>The Great Asia Africa</strong>.</p><p style=\"text-align:justify;\">Continue to Southern Bandung with even more cinematic scenery—from the exotic beauty of <strong>Kawah Putih</strong>, the peaceful atmosphere of <strong>Glamping Lakeside</strong>, to the exciting experience of <strong>Rengganis Suspension Bridge</strong> surrounded by stunning green landscapes.</p><p style=\"text-align:justify;\">Complete your trip with Bandung’s famous shopping experiences at factory outlets, leather centers, and culinary favorites like <strong>Kartika Sari &amp; Prima Rasa</strong>.<br>Plus, enjoy the modern and exciting experience of riding the <strong>Whoosh High Speed Train</strong>.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you’ll enjoy the perfect combination of:<br><strong>nature + scenic landscapes + trendy attractions + shopping + culinary + cool weather</strong> all in one journey without ever feeling boring.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e0c7694c0f8cee8fcc4a0e41308249acb\"><p style=\"text-align:justify;\">A complete holiday with iconic destinations</p></li><li data-list-item-id=\"edf855fc22d40d36cf0a5625b9e6b90a5\"><p style=\"text-align:justify;\">A healing trip with cool weather and aesthetic views</p></li><li data-list-item-id=\"e0dfff88b6bc246aee21909a8a7f797ab\"><p style=\"text-align:justify;\">Shopping, culinary, and city vibes in one experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>North to South. One trip. Endless Bandung vibes.</strong> 🚀</h3><p style=\"text-align:justify;\">Ready to explore the best of Bandung?</p>', '<h2 style=\"text-align:justify;\"><strong>반둥 얼티밋 여행: 북부 &amp; 남부 절경 투어 🌿✨</strong></h2><p style=\"text-align:justify;\">시원한 산 풍경부터 감성적인 명소와 아름다운 자연까지, 반둥의 모든 매력을 한 번에 경험해보세요.<br>북부 반둥에서는 <strong>탕쿠반 프라후</strong>, 인기 명소 <strong>플로팅 마켓 / 팜하우스</strong>, 그리고 다양한 포토 스팟이 가득한 <strong>더 그레이트 아시아 아프리카</strong>를 즐길 수 있습니다.</p><p style=\"text-align:justify;\">이어서 남부 반둥에서는 더욱 환상적인 자연 풍경이 펼쳐집니다.<br>신비로운 화산 호수 <strong>카와 푸티</strong>, 평화로운 분위기의 <strong>글램핑 레이크사이드</strong>, 그리고 아름다운 자연 속에서 특별한 경험을 선사하는 <strong>렝가니스 서스펜션 브리지</strong>까지 모두 담았습니다.</p><p style=\"text-align:justify;\">또한 반둥의 유명 팩토리 아울렛, 가죽 센터, 그리고 <strong>카르티카 사리 &amp; 프리마 라사</strong> 같은 인기 먹거리 쇼핑도 즐길 수 있습니다.<br>마지막으로 현대적이고 빠른 <strong>후시(Whoosh) 고속열차</strong> 경험까지 더해집니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 아름다운 풍경 + 트렌디한 명소 + 쇼핑 + 미식 + 시원한 날씨</strong>를 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e98f7dc335f905cd4f057fc02dd49d3c8\"><p style=\"text-align:justify;\">다양한 명소가 포함된 완벽한 여행</p></li><li data-list-item-id=\"e0a4d4d064ef1e58079039177733647b8\"><p style=\"text-align:justify;\">시원한 날씨와 감성적인 자연 풍경</p></li><li data-list-item-id=\"e908ae813e3bf8f3104f98f361e992775\"><p style=\"text-align:justify;\">쇼핑, 먹거리, 도시 감성을 한 번에</p></li></ul><h3 style=\"text-align:justify;\"><strong>북부에서 남부까지, 한 번의 여행으로 완벽한 반둥 감성.</strong> 🚀</h3><p style=\"text-align:justify;\">반둥 최고의 매력을 만나보세요.</p>', '<h2 style=\"text-align:justify;\"><strong>万隆终极之旅：北部与南部绝美风景 🌿✨</strong></h2><p style=\"text-align:justify;\">一次旅行，体验万隆最完整、最精彩的一面——凉爽山景、热门打卡地与震撼自然风光。<br>在万隆北部，探索著名的 <strong>Tangkuban Perahu火山</strong>、充满乐趣的 <strong>Floating Market / Farm House</strong>，以及拥有超多网红拍照点的 <strong>The Great Asia Africa</strong>。</p><p style=\"text-align:justify;\">接着前往万隆南部，欣赏更加梦幻的自然景色。<br>从神秘唯美的 <strong>Kawah Putih火山湖</strong>、宁静放松的 <strong>Glamping Lakeside</strong>，到被绿色山景包围的 <strong>Rengganis Suspension Bridge 吊桥</strong>，每一站都令人难忘。</p><p style=\"text-align:justify;\">旅程当然也少不了万隆著名的购物体验，包括 Factory Outlet、皮革中心，以及经典美食与伴手礼 <strong>Kartika Sari &amp; Prima Rasa</strong>。<br>再加上现代又快速的 <strong>Whoosh高速列车</strong> 体验，让旅程更加特别。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为你可以一次享受：<br><strong>自然风景 + 绝美景观 + 潮流景点 + 购物 + 美食 + 凉爽天气</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e9da76d36e0fbf5393d6e5bc607239de5\"><p style=\"text-align:justify;\">丰富又完整的假期体验</p></li><li data-list-item-id=\"e93b86cee40fc4d606dfbed50238de130\"><p style=\"text-align:justify;\">凉爽天气与高颜值自然景观</p></li><li data-list-item-id=\"e38fd055bc52cb7dd43ddcd9fcf26863c\"><p style=\"text-align:justify;\">购物、美食与城市氛围一次拥有</p></li></ul><h3 style=\"text-align:justify;\"><strong>从北到南，一次旅行，尽享万隆魅力。</strong> 🚀</h3><p style=\"text-align:justify;\">准备好探索万隆最精彩的一面了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"ea1e791a3ff505e34bccc67f66eb0c117\">Transportation service during the tour program</li><li data-list-item-id=\"e98d71334ddd7c918b923104d8c29b481\">1 – 5 persons by small car with Driver cum Guide</li><li data-list-item-id=\"e24cab86406c8e4bb87cb76e11c4a63c4\">Above 5 persons by Hi Ace / Elf Long with Driver and English-Speaking Guide</li><li data-list-item-id=\"e7d78a62938c10d24254245fc35387956\">Hotel accommodation with daily breakfast based on twin sharing</li><li data-list-item-id=\"ef65cca9ce85cad7c229a711c0ab6ccdc\">Meals as per itinerary</li><li data-list-item-id=\"ef211873167cda5775321172d76e25e5c\">Driver, fuel, toll, and parking fees</li><li data-list-item-id=\"e7e5a3c8600118add1fd1f0276a5f8878\">Entrance fees as per itinerary</li><li data-list-item-id=\"e438cf302944ed99eeef5257c935dfa2b\">Travel Insurance</li><li data-list-item-id=\"e0627d6eebc8c16a5d078bda8ef9edd89\">Mineral water 1 bottle per person per day</li></ul>', '<ul><li data-list-item-id=\"ef38a3b1d1cb5f5a197b9c1f880aa9659\">Personal expenses such as hotel minibar, telephone, and laundry</li><li data-list-item-id=\"e2c8f0c7a9997e6840f4621aed4894fec\">Additional tour, meals, or room arrangement outside the program</li><li data-list-item-id=\"e51018fb68168e89bf5d8de6ccfbd164e\">Tips for guide, driver, and co-driver</li></ul>', NULL, '[\"Nature\",\"LEISURE\",\"Shopping\",\"Culinary\",\"Modern Travel Experience\",\"SCENIC\"]', NULL, 0, NULL, '2026-05-27 13:25:45', '2026-05-29 13:29:17'),
(81, 47, '5 DAYS ALAHAN PANJANG - PAYAKUMBUH - BUKITTINGGI', 'WEST SUMATRA', '5-days-alahan-panjang-payakumbuh-bukittinggi', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Ultimate Escape: Nature, Culture &amp; Scenic Highlands&nbsp;</strong></h2><p style=\"text-align:justify;\">Rasakan perjalanan paling lengkap menjelajahi keindahan Sumatera Barat—mulai dari pegunungan hijau, danau yang tenang, lembah megah, hingga budaya Minangkabau yang begitu ikonik.<br>Nikmati panorama spektakuler di <strong>Alahan Panjang</strong>, hamparan hijau perkebunan teh, dan pesona <strong>Danau Diatas &amp; Danau Dibawah</strong> yang super relaxing.</p><p style=\"text-align:justify;\">Lanjut explore destinasi paling famous seperti <strong>Istana Pagaruyung</strong>, megahnya <strong>Lembah Harau</strong>, ikoniknya <strong>Kelok 9</strong>, hingga panorama terbaik <strong>Danau Maninjau</strong> dari ketinggian di Lawang Park.<br>Belum lengkap tanpa city vibes Bukittinggi di <strong>Jam Gadang &amp; Pasar Atas</strong>, serta wisata heritage di Kota Padang dan Pantai Padang yang penuh suasana lokal khas Sumatera Barat.</p><p style=\"text-align:justify;\">Kenapa harus pilih trip ini?<br>Karena dalam satu perjalanan kamu bisa menikmati kombinasi terbaik:<br><strong>nature + culture + scenic road trip + culinary + highland experience</strong> dengan view yang selalu bikin kagum di setiap perjalanan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"ef8d52896935ecb671f9ec5000d345873\"><p style=\"text-align:justify;\">Healing trip dengan panorama alam spektakuler</p></li><li data-list-item-id=\"e43b2a07e3b39542f3a604c93897413db\"><p style=\"text-align:justify;\">Explore budaya dan ikon Minangkabau</p></li><li data-list-item-id=\"ed7801581fd969c4cd55d294955760a44\"><p style=\"text-align:justify;\">Scenic road trip yang aesthetic dan unforgettable</p></li></ul><h3 style=\"text-align:justify;\"><strong>Cool highlands. Rich culture. Endless West Sumatra beauty.</strong>&nbsp;</h3><p style=\"text-align:justify;\">Siap jatuh cinta dengan pesona alam dan budaya Sumatera Barat?</p>', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Ultimate Escape: Nature, Culture &amp; Scenic Highlands</strong></h2><p style=\"text-align:justify;\">Experience the most complete journey through the breathtaking beauty of West Sumatra—from lush green mountains, peaceful lakes, and majestic valleys to the rich and iconic Minangkabau culture.<br>Enjoy the spectacular scenery of <strong>Alahan Panjang</strong>, endless green tea plantations, and the calming beauty of <strong>Danau Diatas &amp; Danau Dibawah</strong>.</p><p style=\"text-align:justify;\">Continue exploring West Sumatra’s most famous attractions such as the magnificent <strong>Pagaruyung Palace</strong>, the stunning cliffs of <strong>Harau Valley</strong>, the iconic <strong>Kelok 9 Bridge</strong>, and the panoramic views of <strong>Lake Maninjau</strong> from Lawang Park.<br>Complete your trip with the lively atmosphere of <strong>Jam Gadang &amp; Pasar Atas</strong> in Bukittinggi, plus heritage and coastal vibes in Padang City and Padang Beach.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in one journey, you’ll experience the perfect combination of:<br><strong>nature + culture + scenic road trip + culinary experiences + highland adventures</strong> with breathtaking views throughout the journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e6892999d881f6bdaa61ee495458d6010\"><p style=\"text-align:justify;\">A healing getaway with spectacular landscapes</p></li><li data-list-item-id=\"e26663cc159bf3518c638561fdc5c09bf\"><p style=\"text-align:justify;\">To explore Minangkabau culture and iconic landmarks</p></li><li data-list-item-id=\"e4a7daba321e115dbe8f69abc0be18a7f\"><p style=\"text-align:justify;\">An aesthetic and unforgettable scenic road trip</p></li></ul><h3 style=\"text-align:justify;\"><strong>Cool highlands. Rich culture. Endless West Sumatra beauty.</strong>&nbsp;</h3><p style=\"text-align:justify;\">Ready to fall in love with the beauty of West Sumatra?</p>', '<h2 style=\"text-align:justify;\"><strong>서부 수마트라 얼티밋 여행: 자연, 문화 그리고 아름다운 고원 풍경&nbsp;</strong></h2><p style=\"text-align:justify;\">푸른 산과 평화로운 호수, 웅장한 계곡 그리고 상징적인 미낭카바우 문화를 모두 경험할 수 있는 완벽한 서부 수마트라 여행을 만나보세요.<br>시원한 자연 풍경의 <strong>알라한 판장</strong>, 끝없이 펼쳐진 차밭, 그리고 아름다운 <strong>다나우 디아타스 &amp; 다나우 디바와</strong>의 평화로운 분위기를 즐길 수 있습니다.</p><p style=\"text-align:justify;\">이어지는 여행에서는 웅장한 <strong>파가루융 궁전</strong>, 절벽 풍경이 인상적인 <strong>하라우 계곡</strong>, 유명한 <strong>끌록 9 다리</strong>, 그리고 라왕 파크에서 내려다보는 아름다운 <strong>마닌자우 호수</strong> 전망까지 모두 담았습니다.<br>또한 부키팅기의 상징인 <strong>잠 가당 &amp; 파사르 아타스</strong>, 그리고 파당 시티와 파당 해변의 현지 분위기와 역사적인 매력도 경험할 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 문화 + 아름다운 로드트립 + 미식 여행 + 고원 풍경</strong>을 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"eab8c04244d2d66a428293e8103f6db49\"><p style=\"text-align:justify;\">아름다운 자연 속 힐링 여행</p></li><li data-list-item-id=\"ed231349e886b8af7e0e90d90708d0b52\"><p style=\"text-align:justify;\">미낭카바우 문화와 대표 명소 탐방</p></li><li data-list-item-id=\"e01154f85775da7432aaa9eec42639122\"><p style=\"text-align:justify;\">감성적이고 잊지 못할 로드트립</p></li></ul><h3 style=\"text-align:justify;\"><strong>시원한 고원, 깊은 문화, 끝없는 서부 수마트라의 아름다움.</strong>&nbsp;</h3><p style=\"text-align:justify;\">서부 수마트라의 매력에 빠질 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>西苏门答腊终极之旅：自然、文化与高原风景&nbsp;</strong></h2><p style=\"text-align:justify;\">开启一场探索西苏门答腊最完整、最震撼的旅程——从绿色高山、宁静湖泊、壮丽山谷，到极具特色的米南加保文化。<br>欣赏 <strong>Alahan Panjang</strong> 清新的高原风景、大片绿色茶园，以及令人放松的 <strong>Danau Diatas &amp; Danau Dibawah</strong> 双湖美景。</p><p style=\"text-align:justify;\">继续探索西苏门答腊最著名的景点，包括雄伟的 <strong>Pagaruyung王宫</strong>、壮观的 <strong>Harau Valley哈劳峡谷</strong>、标志性的 <strong>Kelok 9大桥</strong>，以及在 Lawang Park 俯瞰 <strong>马尼瑙湖（Lake Maninjau）</strong> 的绝美全景。<br>旅程还包含武吉丁宜著名的 <strong>Jam Gadang &amp; Pasar Atas</strong>，以及巴东老城区与巴东海滩的独特城市氛围。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>自然风景 + 米南加保文化 + 风景公路旅行 + 美食体验 + 高原风光</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e59b8ad06a59a9150a1a22a6893ebfcd2\"><p style=\"text-align:justify;\">拥有壮丽风景的疗愈之旅</p></li><li data-list-item-id=\"e03d00a6ecce57d3192f2bea27a27eb75\"><p style=\"text-align:justify;\">深度体验米南加保文化与经典景点</p></li><li data-list-item-id=\"e5ca4268ec690aab075eff58c49701ecc\"><p style=\"text-align:justify;\">高颜值且难忘的风景公路旅行</p></li></ul><h3 style=\"text-align:justify;\"><strong>清凉高原，浓厚文化，无尽西苏门答腊之美。</strong></h3><p style=\"text-align:justify;\">准备好爱上西苏门答腊了吗？</p>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 night in Alahan Panjang + 2 nights in Bukittinggi + 1 night in Padang) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Culture\",\"Heritage\",\"Scenic Road Trip\",\"Culinary\"]', NULL, 0, NULL, '2026-05-28 12:17:58', '2026-05-29 12:28:23'),
(82, 47, '4 DAYS ALAHAN PANJANG - BUKITTINGGI', 'WEST SUMATRA', '4-days-alahan-panjang-bukittinggi', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Escape: Nature, Culture &amp; Scenic Vibes 🌿✨</strong></h2><p style=\"text-align:justify;\">Explore sisi paling cantik dari Sumatera Barat dalam satu perjalanan yang penuh view spektakuler dan vibes yang unforgettable.<br>Nikmati udara sejuk <strong>Alahan Panjang</strong>, hamparan hijau perkebunan teh, dan cantiknya <strong>Danau Diatas &amp; Danau Dibawah</strong> yang super calming.</p><p style=\"text-align:justify;\">Lanjut explore ikon terkenal seperti <strong>Istana Pagaruyung</strong>, megahnya <strong>Lembah Harau</strong>, iconic <strong>Kelok 9</strong>, hingga panorama epic <strong>Danau Maninjau</strong> dari Lawang Park.<br>Belum lengkap tanpa city vibes Bukittinggi di <strong>Jam Gadang</strong>, wisata budaya khas Minangkabau, dan kuliner legendaris yang bikin nagih.</p><p style=\"text-align:justify;\">Kenapa harus pilih trip ini?<br>Karena kamu bisa dapetin kombinasi lengkap:<br><strong>nature + culture + scenic road trip + culinary + aesthetic spots</strong> dalam satu perjalanan yang fun dan nggak bikin bosan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"eba325cf88c9f1bd1ef9a24afee42f90a\"><p style=\"text-align:justify;\">Healing dengan view alam yang keren</p></li><li data-list-item-id=\"edaf0c117175e9a2daeb198987d7a2c13\"><p style=\"text-align:justify;\">Explore budaya &amp; hidden gems Sumatera Barat</p></li><li data-list-item-id=\"e776832aa06f3f4ab382511a846a8f169\"><p style=\"text-align:justify;\">Banyak spot foto aesthetic &amp; cinematic</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Epic scenery. Endless West Sumatra vibes.</strong> 🏞️✨</h3><p style=\"text-align:justify;\">Siap explore keindahan terbaik Sumatera Barat?</p>', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Escape: Nature, Culture &amp; Scenic Vibes 🌿✨</strong></h2><p style=\"text-align:justify;\">Explore the most beautiful side of West Sumatra in one unforgettable journey filled with breathtaking views and amazing vibes.<br>Enjoy the cool atmosphere of <strong>Alahan Panjang</strong>, endless green tea plantations, and the peaceful beauty of <strong>Danau Diatas &amp; Danau Dibawah</strong>.</p><p style=\"text-align:justify;\">Continue to iconic destinations like the magnificent <strong>Pagaruyung Palace</strong>, the stunning <strong>Harau Valley</strong>, the famous <strong>Kelok 9 Bridge</strong>, and the epic panoramic view of <strong>Lake Maninjau</strong> from Lawang Park.<br>Complete your trip with the lively atmosphere of <strong>Jam Gadang</strong>, authentic Minangkabau culture, and legendary local culinary experiences.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because you’ll get the perfect combination of:<br><strong>nature + culture + scenic road trip + culinary + aesthetic spots</strong> in one fun and unforgettable journey.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e9279687684a07688ec295c8722b5fb30\"><p style=\"text-align:justify;\">A healing trip with amazing natural scenery</p></li><li data-list-item-id=\"e77111321f5fdecba80a5945713743e1c\"><p style=\"text-align:justify;\">To explore West Sumatra’s culture &amp; hidden gems</p></li><li data-list-item-id=\"eae80acdbce750e81709f46d4f9838148\"><p style=\"text-align:justify;\">Lots of aesthetic and cinematic photo spots</p></li></ul><h3 style=\"text-align:justify;\"><strong>Fresh air. Epic scenery. Endless West Sumatra vibes.</strong> 🏞️✨</h3><p style=\"text-align:justify;\">Ready to explore the beauty of West Sumatra?</p>', '<h2 style=\"text-align:justify;\"><strong>서부 수마트라 여행: 자연, 문화 그리고 아름다운 풍경 🌿✨</strong></h2><p style=\"text-align:justify;\">멋진 풍경과 특별한 분위기로 가득한 서부 수마트라의 가장 아름다운 매력을 한 번에 경험해보세요.<br>시원한 공기의 <strong>알라한 판장</strong>, 끝없이 펼쳐진 초록빛 차밭, 그리고 평화로운 <strong>다나우 디아타스 &amp; 다나우 디바와</strong>의 풍경이 여행을 더욱 특별하게 만들어줍니다.</p><p style=\"text-align:justify;\">이어지는 여행에서는 웅장한 <strong>파가루융 궁전</strong>, 아름다운 <strong>하라우 계곡</strong>, 유명한 <strong>끌록 9 다리</strong>, 그리고 라왕 파크에서 바라보는 환상적인 <strong>마닌자우 호수</strong> 전망까지 모두 즐길 수 있습니다.<br>또한 <strong>잠 가당</strong>의 활기찬 분위기, 미낭카바우 전통문화, 그리고 유명한 현지 먹거리도 놓칠 수 없습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 문화 + 감성적인 로드트립 + 미식 + 인생샷 명소</strong>를 모두 경험할 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e611525ee587eb9717a3d1c7886b50205\"><p style=\"text-align:justify;\">아름다운 자연 속 힐링 여행</p></li><li data-list-item-id=\"e4b798619d6bc372bbcd2b02ace5c5355\"><p style=\"text-align:justify;\">서부 수마트라의 문화와 숨은 명소 탐방</p></li><li data-list-item-id=\"e067a67134c7fcc718c3b2d7afec960e4\"><p style=\"text-align:justify;\">감성적인 포토 스팟 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>맑은 공기, 환상적인 풍경, 끝없는 서부 수마트라 감성.</strong> 🏞️✨</h3><p style=\"text-align:justify;\">서부 수마트라의 매력에 빠질 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>西苏门答腊之旅：自然、文化与绝美风景 🌿✨</strong></h2><p style=\"text-align:justify;\">一次旅行，探索西苏门答腊最迷人的风景与独特氛围。<br>感受 <strong>Alahan Panjang</strong> 清凉舒适的高原空气、大片绿色茶园，以及宁静唯美的 <strong>Danau Diatas &amp; Danau Dibawah</strong> 双湖景色。</p><p style=\"text-align:justify;\">继续前往西苏门答腊最经典的景点，包括壮观的 <strong>Pagaruyung王宫</strong>、震撼的 <strong>Harau Valley哈劳峡谷</strong>、标志性的 <strong>Kelok 9大桥</strong>，以及在 Lawang Park 欣赏令人惊叹的 <strong>马尼瑙湖全景</strong>。<br>旅程还包含充满活力的 <strong>Jam Gadang</strong>、浓厚的米南加保文化，以及让人回味无穷的当地特色美食。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>自然风景 + 文化体验 + 风景公路旅行 + 美食 + 高颜值打卡景点</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e5534472bd9f1cc225d0f0b2d23b4c73b\"><p style=\"text-align:justify;\">拥有绝美自然风景的疗愈之旅</p></li><li data-list-item-id=\"eefb660bbd0c8e3b347be2859ded865e3\"><p style=\"text-align:justify;\">探索西苏门答腊文化与隐藏美景</p></li><li data-list-item-id=\"e68d853a979ac758bcf3a2da431a2088f\"><p style=\"text-align:justify;\">超多高级感拍照打卡点</p></li></ul><h3 style=\"text-align:justify;\"><strong>清新空气，震撼风景，满满西苏门答腊氛围。</strong> 🏞️✨</h3><p style=\"text-align:justify;\">准备好探索西苏门答腊的魅力了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 night in Alahan Panjang + 2 nights in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Nature\",\"Scenic Highland\",\"Scenic Road Trip\",\"Culinary\",\"Urban Heritage\"]', NULL, 0, NULL, '2026-05-28 12:59:47', '2026-05-29 12:27:08'),
(83, 47, '4 DAYS KAWASAN MANDEH - PADANG - BUKITTINGGI', 'WEST SUMATRA', '4-days-kawasan-mandeh-padang-bukittinggi', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Ultimate Escape: Island, Nature &amp; Culture Adventure 🌊🏞️✨</strong></h2><p style=\"text-align:justify;\">Rasakan perjalanan paling lengkap di Sumatera Barat—mulai dari island hopping tropis, panorama alam spektakuler, hingga budaya Minangkabau yang penuh pesona.<br>Awali adventure seru di <strong>Kawasan Mandeh</strong>, hidden paradise dengan laut biru jernih, snorkeling, cliff jumping, mangrove tour, dan island vibes yang super aesthetic.</p><p style=\"text-align:justify;\">Lanjut explore ikon terbaik Sumatera Barat seperti megahnya <strong>Lembah Harau</strong>, epic view di <strong>Kelok 9</strong>, cantiknya <strong>Ngarai Sianok</strong>, hingga suasana iconic <strong>Jam Gadang</strong> di Bukittinggi.<br>Nikmati juga pengalaman budaya khas Minang di <strong>Istana Pagaruyung</strong>, Desa Pariangan, hingga wisata kuliner legendaris seperti rendang dan Sanjai yang wajib dicoba.</p><p style=\"text-align:justify;\">Kenapa harus pilih trip ini?<br>Karena dalam satu perjalanan kamu bisa menikmati kombinasi terbaik:<br><strong>island hopping + nature + culture + scenic road trip + culinary + aesthetic spots</strong> tanpa terasa monoton.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"ebe8d3b689c359463295a842620818652\"><p style=\"text-align:justify;\">Tropical escape &amp; scenic adventure</p></li><li data-list-item-id=\"ed8bd596297bee401c43c2211b06d0a44\"><p style=\"text-align:justify;\">Healing trip dengan view yang cinematic</p></li><li data-list-item-id=\"e07e4d97a0d542b79603844ada4dd73c5\"><p style=\"text-align:justify;\">Explore budaya dan hidden gems Sumatera Barat</p></li></ul><h3 style=\"text-align:justify;\"><strong>Blue ocean. Epic highlands. Endless West Sumatra vibes.</strong> 🌿🌊✨</h3><p style=\"text-align:justify;\">Siap explore sisi paling seru dari Sumatera Barat?</p>', '<h2 style=\"text-align:justify;\"><strong>West Sumatra Ultimate Escape: Island, Nature &amp; Culture Adventure 🌊🏞️✨</strong></h2><p style=\"text-align:justify;\">Experience the most complete journey in West Sumatra—from tropical island hopping and breathtaking landscapes to the rich beauty of Minangkabau culture.<br>Start your adventure in the stunning <strong>Mandeh Area</strong>, a hidden paradise with crystal-clear blue waters, snorkeling, cliff jumping, mangrove tours, and aesthetic tropical island vibes.</p><p style=\"text-align:justify;\">Continue exploring West Sumatra’s iconic destinations such as the magnificent <strong>Harau Valley</strong>, the epic scenery of <strong>Kelok 9 Bridge</strong>, the breathtaking <strong>Sianok Canyon</strong>, and the iconic atmosphere of <strong>Jam Gadang</strong> in Bukittinggi.<br>Enjoy authentic Minangkabau cultural experiences at <strong>Pagaruyung Palace</strong>, the beautiful <strong>Pariangan Village</strong>, and legendary local culinary delights like rendang and Sanjai chips.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in one journey, you’ll experience the perfect combination of:<br><strong>island hopping + nature + culture + scenic road trip + culinary + aesthetic spots</strong> all in one unforgettable adventure.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"eb1737599519bb306141ece0950174b9f\"><p style=\"text-align:justify;\">A tropical escape &amp; scenic adventure</p></li><li data-list-item-id=\"e49d75d8b934c4fbdb84bd5ccdf3bec44\"><p style=\"text-align:justify;\">A healing trip with cinematic views</p></li><li data-list-item-id=\"ed263630c30967cd7b16156f3038ab960\"><p style=\"text-align:justify;\">To explore West Sumatra’s culture &amp; hidden gems</p></li></ul><h3 style=\"text-align:justify;\"><strong>Blue ocean. Epic highlands. Endless West Sumatra vibes.</strong> 🌿🌊✨</h3><p style=\"text-align:justify;\">Ready to explore the most exciting side of West Sumatra?</p>', '<h2 style=\"text-align:justify;\"><strong>서부 수마트라 얼티밋 여행: 섬, 자연 그리고 문화 어드벤처 🌊🏞️✨</strong></h2><p style=\"text-align:justify;\">열대 섬 여행부터 환상적인 자연 풍경, 그리고 미낭카바우 문화까지 모두 경험할 수 있는 완벽한 서부 수마트라 여행을 만나보세요.<br>맑고 푸른 바다를 자랑하는 숨겨진 천국 <strong>만데 지역(Mandeh Area)</strong> 에서 스노클링, 클리프 점프, 맹그로브 투어와 함께 트로피컬 아일랜드 감성을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">이어서 웅장한 <strong>하라우 계곡</strong>, 장관을 이루는 <strong>끌록 9 다리</strong>, 아름다운 <strong>시아녹 협곡</strong>, 그리고 부키팅기의 상징적인 <strong>잠 가당</strong>까지 서부 수마트라 최고의 명소들을 탐험해보세요.<br>또한 <strong>파가루융 궁전</strong>, 아름다운 <strong>파리앙안 마을</strong>, 그리고 렌당과 산자이 같은 유명 미낭카바우 음식도 경험할 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>아일랜드 호핑 + 자연 + 문화 + 감성적인 로드트립 + 미식 + 포토 스팟</strong>을 모두 즐길 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e74002ace1bfed73c89bf8f571e616cbb\"><p style=\"text-align:justify;\">열대 섬과 자연 어드벤처</p></li><li data-list-item-id=\"e59c61e3113b8f7fc2da1dd4f3444e306\"><p style=\"text-align:justify;\">영화 같은 풍경 속 힐링 여행</p></li><li data-list-item-id=\"e4144bacc54492e41c70986f61ce90037\"><p style=\"text-align:justify;\">서부 수마트라 문화와 숨은 명소 탐방</p></li></ul><h3 style=\"text-align:justify;\"><strong>푸른 바다, 장대한 고원, 끝없는 서부 수마트라 감성.</strong> 🌿🌊✨</h3><p style=\"text-align:justify;\">서부 수마트라의 가장 특별한 매력을 만나볼 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>西苏门答腊终极之旅：海岛、自然与文化探险 🌊🏞️✨</strong></h2><p style=\"text-align:justify;\">开启一场探索西苏门答腊最完整、最精彩的旅程——从热带跳岛、壮丽自然风景，到独特迷人的米南加保文化。<br>首先前往隐藏天堂 <strong>Mandeh海湾</strong>，享受清澈蓝海、浮潜、悬崖跳水、红树林探险，以及超有氛围感的热带海岛体验。</p><p style=\"text-align:justify;\">接着探索西苏门答腊最经典的景点，包括壮观的 <strong>Harau Valley哈劳峡谷</strong>、震撼的 <strong>Kelok 9大桥</strong>、绝美的 <strong>Sianok Canyon锡亚诺克峡谷</strong>，以及武吉丁宜最具代表性的 <strong>Jam Gadang大钟楼</strong>。<br>同时还能深入体验米南加保文化，参观 <strong>Pagaruyung王宫</strong>、世界最美村庄之一的 <strong>Pariangan Village</strong>，并品尝传奇美食 Rendang 与 Sanjai。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>跳岛 + 自然风景 + 文化体验 + 风景公路旅行 + 美食 + 网红打卡景点</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e762e8b50394cfbe9ee2404cc4aed7f3a\"><p style=\"text-align:justify;\">热带海岛与自然探险</p></li><li data-list-item-id=\"e2b48ec69991bbb8753b988ada18c1dbd\"><p style=\"text-align:justify;\">拥有电影感风景的疗愈之旅</p></li><li data-list-item-id=\"eadada1235867142e1ed3f3ae7b6d59b3\"><p style=\"text-align:justify;\">探索西苏门答腊文化与隐藏秘境</p></li></ul><h3 style=\"text-align:justify;\"><strong>蓝色海洋，壮丽高原，无尽西苏门答腊氛围。</strong> 🌿🌊✨</h3><p style=\"text-align:justify;\">准备好探索西苏门答腊最精彩的一面了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 night in Padang + 2 nights in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e2248aea3cc38d664a5a28568a0f51d10\">Life Jacket, Snorkeling &amp; Boat</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Adventure\",\"Beach\",\"Nature\",\"Scenic\",\"Heritage\",\"Culture\",\"Scenic Road Trip\",\"Culinary\"]', NULL, 0, NULL, '2026-05-28 13:28:56', '2026-05-29 12:23:18');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(84, 47, '4 DAYS BUKITTINGGI PADANG', 'WEST SUMATRA', '4-days-bukittinggi-padang', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Padang Escape: Nature, Culture &amp; Scenic Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Temukan keindahan Sumatera Barat melalui perjalanan tak terlupakan yang dipenuhi panorama alam memukau, budaya Minangkabau yang kaya, dan destinasi ikonik.<br>Nikmati suasana segar di <strong>Air Terjun Lembah Anai</strong>, panorama spektakuler <strong>Lembah Harau</strong>, megahnya <strong>Jembatan Kelok 9</strong>, hingga pemandangan indah <strong>Danau Maninjau</strong> dari Lawang Park yang begitu memanjakan mata.</p><p style=\"text-align:justify;\">Lanjutkan perjalanan dengan mengeksplor kekayaan budaya seperti megahnya <strong>Istana Pagaruyung</strong>, Desa Tenun Tradisional <strong>Pandai Sikek</strong>, hingga cantiknya <strong>Desa Pariangan</strong> yang dikenal sebagai salah satu desa terindah di dunia.<br>Lengkapi pengalamanmu dengan suasana ikonik <strong>Jam Gadang</strong> di Bukittinggi, momen sunset di Kota Padang, serta kuliner khas Minang yang legendaris dan selalu bikin rindu.</p><p style=\"text-align:justify;\">Kenapa harus pilih trip ini?<br>Karena dalam satu perjalanan, kamu bisa menikmati kombinasi sempurna antara:<br><strong>alam + budaya + scenic road trip + kuliner + vibes khas Sumatera Barat</strong> dalam pengalaman liburan yang seru dan unforgettable.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"e2ce73a7c22caa8780fb361e36c7eeed5\"><p style=\"text-align:justify;\">Liburan santai dengan panorama alam spektakuler</p></li><li data-list-item-id=\"e170a471221b9bca6194633af9b2a2736\"><p style=\"text-align:justify;\">Explore budaya Minangkabau dan hidden gems Sumatera Barat</p></li><li data-list-item-id=\"ec216f6f02de4de23f4dc3b5b958d3220\"><p style=\"text-align:justify;\">Pengalaman wisata aesthetic dan penuh momen memorable</p></li></ul><h3 style=\"text-align:justify;\"><strong>Panorama epic. Budaya yang kaya. Endless West Sumatra vibes.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">Siap explore keindahan terbaik Sumatera Barat?</p>', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Padang Escape: Nature, Culture &amp; Scenic Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Discover the beauty of West Sumatra through an unforgettable journey filled with breathtaking landscapes, rich Minangkabau culture, and iconic destinations.<br>Enjoy the refreshing atmosphere of <strong>Lembah Anai Waterfall</strong>, the spectacular scenery of <strong>Harau Valley</strong>, the famous <strong>Kelok 9 Bridge</strong>, and the stunning panoramic view of <strong>Lake Maninjau</strong> from Lawang Park.</p><p style=\"text-align:justify;\">Continue exploring cultural treasures such as the majestic <strong>Pagaruyung Palace</strong>, the traditional weaving village of <strong>Pandai Sikek</strong>, and the beautiful <strong>Pariangan Village</strong>, known as one of the most beautiful villages in the world.<br>Complete your trip with the iconic <strong>Jam Gadang</strong> in Bukittinggi, sunset moments in Padang, and legendary Minang culinary experiences that make every journey even more memorable.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in one journey, you can enjoy the perfect combination of:<br><strong>nature + culture + scenic road trip + culinary + iconic West Sumatra vibes</strong> in a fun and unforgettable experience.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"e23f12f3df913dd2feeb1445bd43429a4\"><p style=\"text-align:justify;\">A relaxing getaway with spectacular scenery</p></li><li data-list-item-id=\"e8a3a04edba7306765a40fe0069860d12\"><p style=\"text-align:justify;\">To explore Minangkabau culture and hidden gems</p></li><li data-list-item-id=\"e468c8a7cb6f91a792807d3bdd1d797d0\"><p style=\"text-align:justify;\">Aesthetic and unforgettable travel experiences</p></li></ul><h3 style=\"text-align:justify;\"><strong>Epic scenery. Rich culture. Endless West Sumatra vibes.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">Ready to explore the beauty of West Sumatra?</p>', '<h2 style=\"text-align:justify;\"><strong>부키팅기 &amp; 파당 여행: 자연, 문화 그리고 아름다운 풍경 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">아름다운 자연과 미낭카바우 문화, 그리고 특별한 명소들로 가득한 서부 수마트라 여행을 경험해보세요.<br>시원한 공기의 <strong>렘바 안아이 폭포</strong>, 웅장한 절벽 풍경의 <strong>하라우 계곡</strong>, 유명한 <strong>끌록 9 다리</strong>, 그리고 라왕 파크에서 바라보는 환상적인 <strong>마닌자우 호수</strong> 전망이 여행을 더욱 특별하게 만들어줍니다.</p><p style=\"text-align:justify;\">또한 웅장한 <strong>파가루융 궁전</strong>, 전통 직물 마을 <strong>판다이 시켁</strong>, 그리고 세계에서 가장 아름다운 마을 중 하나로 알려진 <strong>파리앙안 마을</strong>까지 서부 수마트라의 전통과 문화를 깊이 느낄 수 있습니다.<br>마지막으로 부키팅기의 상징인 <strong>잠 가당</strong>, 파당의 아름다운 석양, 그리고 유명한 미낭카바우 음식까지 즐기며 더욱 완벽한 여행을 완성하세요.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>자연 + 문화 + 감성적인 로드트립 + 미식 + 서부 수마트라의 특별한 분위기</strong>를 모두 경험할 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"ed561605747e86e4cf892295b5b6f5098\"><p style=\"text-align:justify;\">아름다운 자연 속 힐링 여행</p></li><li data-list-item-id=\"e1d252cdb405397fef1250660c4342287\"><p style=\"text-align:justify;\">미낭카바우 문화와 숨은 명소 탐방</p></li><li data-list-item-id=\"e4e2c36a0caf292445286009e090a8c1d\"><p style=\"text-align:justify;\">감성적이고 잊지 못할 여행 경험</p></li></ul><h3 style=\"text-align:justify;\"><strong>장대한 풍경, 깊은 문화, 끝없는 서부 수마트라 감성.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">서부 수마트라의 매력을 만나볼 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>武吉丁宜 &amp; 巴东之旅：自然、文化与绝美风景 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">开启一场探索西苏门答腊之美的精彩旅程，感受壮丽自然风景、独特米南加保文化与经典旅游景点。<br>欣赏清凉舒适的 <strong>Lembah Anai瀑布</strong>、壮观的 <strong>Harau Valley哈劳峡谷</strong>、著名的 <strong>Kelok 9大桥</strong>，以及在 Lawang Park 俯瞰令人惊叹的 <strong>马尼瑙湖全景</strong>。</p><p style=\"text-align:justify;\">继续探索西苏门答腊丰富的文化遗产，包括雄伟的 <strong>Pagaruyung王宫</strong>、传统织布村 <strong>Pandai Sikek</strong>，以及被誉为世界最美村庄之一的 <strong>Pariangan Village</strong>。<br>最后别错过武吉丁宜标志性的 <strong>Jam Gadang大钟楼</strong>、巴东迷人的海边日落，以及令人回味无穷的米南加保特色美食。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>自然风景 + 文化体验 + 风景公路旅行 + 美食 + 西苏门答腊经典氛围</strong> 的完美结合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e11da7cfacf099677b58bfe86b574ed53\"><p style=\"text-align:justify;\">拥有壮丽景色的疗愈之旅</p></li><li data-list-item-id=\"ebab63a7cde64649c84b905948c1d1d54\"><p style=\"text-align:justify;\">探索米南加保文化与隐藏秘境</p></li><li data-list-item-id=\"e588ea8ddf3464f97f47d789c4fca2bd5\"><p style=\"text-align:justify;\">高颜值且难忘的旅行体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>震撼风景，深厚文化，无尽西苏门答腊魅力。</strong> ✨🏞️</h3><p style=\"text-align:justify;\">准备好探索西苏门答腊最美的一面了吗？</p>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (2 nights in Bukittinggi + 1 night in Padang) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Nature\",\"Scenic\",\"Heritage\",\"Culture\",\"Scenic Road Trip\",\"Culinary\",\"Urban Heritage\"]', NULL, 0, NULL, '2026-05-28 14:04:01', '2026-05-29 12:22:15'),
(85, 47, '3 DAYS BUKITTINGGI - SAWAHLUNTO', 'WEST SUMATRA', '3-days-bukittinggi-sawahlunto', '<h2 style=\"text-align:justify;\"><strong>Sawahlunto &amp; Bukittinggi Escape: Heritage, Nature &amp; Scenic Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Explore sisi paling unik dari Sumatera Barat dalam perjalanan penuh panorama alam, sejarah, dan budaya Minangkabau yang unforgettable.<br>Mulai dari kota heritage <strong>Sawahlunto</strong>, kota tambang legendaris dengan nuansa klasik yang penuh cerita sejarah, lalu nikmati view spektakuler sepanjang perjalanan di <strong>Sitinjau Laut</strong> yang menghadap langsung ke Samudera Hindia.</p><p style=\"text-align:justify;\">Lanjut explore keindahan alam Sumatera Barat seperti megahnya <strong>Lembah Harau</strong>, iconic <strong>Kelok 9</strong>, dan tenangnya <strong>Danau Singkarak</strong> yang dikelilingi panorama pegunungan hijau.<br>Rasakan juga budaya khas Minang di <strong>Istana Pagaruyung</strong>, Desa Songket <strong>Pandai Sikek</strong>, hingga wisata kuliner legendaris seperti rendang, sanjai, dan Bika Talago yang wajib dicoba.</p><p style=\"text-align:justify;\">Kenapa harus pilih trip ini?<br>Karena dalam satu perjalanan kamu bisa menikmati kombinasi lengkap:<br><strong>heritage + nature + culture + scenic road trip + culinary</strong> dengan suasana yang aesthetic dan nggak membosankan.</p><p style=\"text-align:justify;\">Perfect buat kamu yang mau:</p><ul><li data-list-item-id=\"edc4cbe1a00874177a4aec980cd0077f4\"><p style=\"text-align:justify;\">Healing trip dengan view alam yang epic</p></li><li data-list-item-id=\"ea0890b7e40558f0c5cd73f77ef6edc30\"><p style=\"text-align:justify;\">Explore sejarah dan budaya Minangkabau</p></li><li data-list-item-id=\"ebb112682196444cb7f59b34b72a31355\"><p style=\"text-align:justify;\">Banyak spot foto cinematic &amp; instagrammable</p></li></ul><h3 style=\"text-align:justify;\"><strong>Epic scenery. Rich heritage. Endless West Sumatra vibes.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">Siap explore hidden gems terbaik di Sumatera Barat?</p>', '<h2 style=\"text-align:justify;\"><strong>Sawahlunto &amp; Bukittinggi Escape: Heritage, Nature &amp; Scenic Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Explore the most unique side of West Sumatra through a journey filled with breathtaking landscapes, rich history, and authentic Minangkabau culture.<br>Start your adventure in the heritage city of <strong>Sawahlunto</strong>, a historic mining town with charming colonial vibes and fascinating stories from the past. Along the way, enjoy the spectacular scenery of <strong>Sitinjau Laut</strong>, overlooking the vast Indian Ocean.</p><p style=\"text-align:justify;\">Continue exploring West Sumatra’s natural beauty with the majestic <strong>Harau Valley</strong>, the iconic <strong>Kelok 9 Bridge</strong>, and the peaceful atmosphere of <strong>Lake Singkarak</strong> surrounded by lush green mountains.<br>Experience authentic Minangkabau culture at the magnificent <strong>Pagaruyung Palace</strong>, the traditional weaving village of <strong>Pandai Sikek</strong>, and legendary local culinary delights such as rendang, sanjai chips, and Bika Talago.</p><p style=\"text-align:justify;\">Why choose this trip?<br>Because in one journey, you’ll enjoy the perfect combination of:<br><strong>heritage + nature + culture + scenic road trip + culinary experiences</strong> in a fun and unforgettable atmosphere.</p><p style=\"text-align:justify;\">Perfect for you if you want:</p><ul><li data-list-item-id=\"ecacdf66dd27df00e5fc1ef95da90c22a\"><p style=\"text-align:justify;\">A relaxing getaway with epic natural scenery</p></li><li data-list-item-id=\"ead50bf0ddea0a575785b7ab2c2ebf73e\"><p style=\"text-align:justify;\">To explore the history and culture of Minangkabau</p></li><li data-list-item-id=\"ea946123c4f9731cf60738a3d7b27eaac\"><p style=\"text-align:justify;\">Lots of cinematic and instagrammable photo spots</p></li></ul><h3 style=\"text-align:justify;\"><strong>Epic scenery. Rich heritage. Endless West Sumatra vibes.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">Ready to explore the hidden gems of West Sumatra?</p>', '<h2 style=\"text-align:justify;\"><strong>사와룬토 &amp; 부키팅기 여행: 문화유산, 자연 그리고 아름다운 풍경 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">아름다운 자연 풍경과 역사, 그리고 미낭카바우 문화를 모두 경험할 수 있는 특별한 서부 수마트라 여행을 만나보세요.<br>여행은 역사적인 광산 도시 <strong>사와룬토(Sawahlunto)</strong> 에서 시작됩니다. 클래식한 분위기와 과거의 이야기가 살아있는 도시를 둘러보고, 이어서 인도양이 한눈에 내려다보이는 <strong>시틴자우 라우트(Sitinjau Laut)</strong> 의 멋진 풍경을 감상할 수 있습니다.</p><p style=\"text-align:justify;\">계속해서 웅장한 <strong>하라우 계곡</strong>, 유명한 <strong>끌록 9 다리</strong>, 그리고 푸른 산으로 둘러싸인 평화로운 <strong>싱카라크 호수</strong>까지 서부 수마트라의 대표적인 자연 명소들을 탐험해보세요.<br>또한 웅장한 <strong>파가루융 궁전</strong>, 전통 직물 마을 <strong>판다이 시켁</strong>, 그리고 렌당, 산자이, 비카 탈라고 같은 유명한 미낭카바우 음식도 즐길 수 있습니다.</p><p style=\"text-align:justify;\">왜 이 여행인가요?<br>한 번의 여행으로<br><strong>문화유산 + 자연 + 문화 + 감성적인 로드트립 + 미식 여행</strong>을 모두 경험할 수 있기 때문입니다.</p><p style=\"text-align:justify;\">이런 여행을 찾고 있다면:</p><ul><li data-list-item-id=\"e169d124524d0de0c603b777ed6895672\"><p style=\"text-align:justify;\">아름다운 자연 속 힐링 여행</p></li><li data-list-item-id=\"e8c527d3c8cbea3e4289e909f049fe009\"><p style=\"text-align:justify;\">미낭카바우 역사와 문화 탐방</p></li><li data-list-item-id=\"eb83d6fa1d10c46cc9107981014514573\"><p style=\"text-align:justify;\">감성적인 포토 스팟 여행</p></li></ul><h3 style=\"text-align:justify;\"><strong>장대한 풍경, 깊은 역사, 끝없는 서부 수마트라 감성.</strong> ✨🏞️</h3><p style=\"text-align:justify;\">서부 수마트라의 숨겨진 매력을 만나볼 준비 되셨나요?</p>', '<h2 style=\"text-align:justify;\"><strong>沙瓦伦托 &amp; 武吉丁宜之旅：文化遗产、自然与绝美风景 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">开启一场探索西苏门答腊最独特魅力的旅程，感受壮丽自然风景、丰富历史与米南加保文化。<br>旅程从历史名城 <strong>Sawahlunto（沙瓦伦托）</strong> 开始，这座充满殖民风格与矿业历史故事的小城别具魅力。沿途还能欣赏 <strong>Sitinjau Laut</strong> 壮观景色，俯瞰辽阔的印度洋。</p><p style=\"text-align:justify;\">继续探索西苏门答腊最经典的自然景点，包括壮观的 <strong>Harau Valley哈劳峡谷</strong>、标志性的 <strong>Kelok 9大桥</strong>，以及被青山环绕、宁静优美的 <strong>Singkarak湖</strong>。<br>同时还能深入体验米南加保文化，参观雄伟的 <strong>Pagaruyung王宫</strong>、传统织布村 <strong>Pandai Sikek</strong>，以及品尝传奇美食 Rendang、Sanjai 和 Bika Talago。</p><p style=\"text-align:justify;\">为什么选择这个行程？<br>因为一次旅行就能体验：<br><strong>文化遗产 + 自然风景 + 文化体验 + 风景公路旅行 + 美食</strong> 的完美组合。</p><p style=\"text-align:justify;\">如果你想要：</p><ul><li data-list-item-id=\"e459f252d658d51cdf3562df7146efdc4\"><p style=\"text-align:justify;\">拥有壮丽自然景观的疗愈之旅</p></li><li data-list-item-id=\"edb26461054affc002397f72375e5f28b\"><p style=\"text-align:justify;\">探索米南加保历史与文化</p></li><li data-list-item-id=\"ed6dc1b22744c6ca4402be2386b02c8d3\"><p style=\"text-align:justify;\">超多电影感与网红拍照打卡点</p></li></ul><h3 style=\"text-align:justify;\"><strong>震撼风景，深厚历史，无尽西苏门答腊魅力。</strong> ✨🏞️</h3><p style=\"text-align:justify;\">准备好探索西苏门答腊的隐藏秘境了吗？</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 nights in Sawahlunto + 1 night in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Culture\",\"Heritage\",\"Historical\",\"Nature\",\"Scenic\",\"Scenic Road Trip\",\"Culinary\"]', NULL, 0, NULL, '2026-05-28 14:26:11', '2026-05-29 12:19:47'),
(86, 47, '3 DAYS PAYAKUMBUH - BUKITTINGGI', 'WEST SUMATRA', '3-days-payakumbuh-bukittinggi', '<h2 style=\"text-align:justify;\"><strong>Payakumbuh &amp; Bukittinggi Escape: Nature, Culture &amp; Highland Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Nikmati keindahan terbaik Sumatera Barat dalam perjalanan singkat yang penuh panorama alam spektakuler, budaya Minangkabau yang autentik, dan suasana pegunungan yang menyegarkan.<br>Menginap di kawasan <strong>Lembah Harau</strong>, salah satu destinasi alam paling ikonik di Sumatera Barat, dikelilingi tebing granit raksasa, air terjun alami, dan hamparan hijau yang menenangkan. Nikmati juga kemegahan <strong>Kelok 9</strong>, mahakarya arsitektur yang berdiri di tengah panorama lembah yang luar biasa indah.</p><p style=\"text-align:justify;\">Perjalanan semakin berkesan dengan kunjungan ke <strong>Desa Pariangan</strong>, yang dikenal sebagai salah satu desa terindah di dunia, serta <strong>Istana Pagaruyung</strong>, ikon budaya Minangkabau yang megah dan penuh sejarah. Lengkapi pengalamanmu dengan suasana khas <strong>Bukittinggi</strong>, mulai dari <strong>Jam Gadang</strong>, Panorama Baru, hingga berbagai kuliner legendaris khas Minang yang menggugah selera.</p><h3 style=\"text-align:justify;\">Kenapa harus pilih trip ini?</h3><p style=\"text-align:justify;\">Karena dalam satu perjalanan kamu bisa menikmati kombinasi sempurna antara:</p><p style=\"text-align:justify;\"><strong>nature + culture + scenic highland + local experience + iconic West Sumatra landmarks</strong></p><h3 style=\"text-align:justify;\">Perfect buat kamu yang mau:</h3><ul><li data-list-item-id=\"eb9543d8f9a8ff023fc98d317a2b356b6\"><p style=\"text-align:justify;\">Healing trip dengan udara sejuk dan panorama alam yang luar biasa</p></li><li data-list-item-id=\"e290c4aa3a520a5abfbf438bd55e534f3\"><p style=\"text-align:justify;\">Explore budaya Minangkabau yang autentik</p></li><li data-list-item-id=\"e92c72f58c70942d07d3969d41800cfca\"><p style=\"text-align:justify;\">Menginap di tengah keindahan Lembah Harau yang terkenal</p></li><li data-list-item-id=\"ee545c59f33fad82db74d4c354a268225\"><p style=\"text-align:justify;\">Mengunjungi destinasi ikonik Sumatera Barat dalam waktu singkat</p></li></ul><h3 style=\"text-align:justify;\"><strong>Epic landscapes. Rich culture. Unforgettable West Sumatra experience.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Siap merasakan pesona terbaik Payakumbuh dan Bukittinggi?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>Payakumbuh &amp; Bukittinggi Escape: Nature, Culture &amp; Highland Adventure 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Experience the best of West Sumatra through a short yet unforgettable journey filled with spectacular landscapes, authentic Minangkabau culture, and refreshing mountain scenery.</p><p style=\"text-align:justify;\">Stay in the heart of <strong>Harau Valley</strong>, one of West Sumatra’s most iconic natural destinations, surrounded by towering granite cliffs, beautiful waterfalls, and lush green landscapes that create the perfect atmosphere for relaxation. Witness the impressive <strong>Kelok 9 Bridge</strong>, an architectural masterpiece set amidst breathtaking valley views.</p><p style=\"text-align:justify;\">Your adventure continues with a visit to <strong>Pariangan Village</strong>, recognized as one of the most beautiful villages in the world, and the magnificent <strong>Pagaruyung Palace</strong>, the proud symbol of Minangkabau heritage and history. Complete your journey by exploring the charming town of <strong>Bukittinggi</strong>, home to the iconic <strong>Jam Gadang Clock Tower</strong>, Panorama Park, and legendary Minang culinary delights.</p><h3 style=\"text-align:justify;\">Why choose this trip?</h3><p style=\"text-align:justify;\">Because in one journey, you can enjoy the perfect combination of:</p><p style=\"text-align:justify;\"><strong>nature + culture + scenic highlands + local experiences + iconic West Sumatra landmarks</strong></p><h3 style=\"text-align:justify;\">Perfect for you if you want:</h3><ul><li data-list-item-id=\"e54fed0e19abdb716e171b06f2cf62885\"><p style=\"text-align:justify;\">A relaxing getaway surrounded by stunning natural scenery</p></li><li data-list-item-id=\"e5d52bb8767b07911ae9e9694f904d398\"><p style=\"text-align:justify;\">To discover authentic Minangkabau culture</p></li><li data-list-item-id=\"e731b9c391316fc2e81b9c594ef338f6e\"><p style=\"text-align:justify;\">To stay amidst the beauty of the famous Harau Valley</p></li><li data-list-item-id=\"e01144b28b8a97fd8106a348b2d61f792\"><p style=\"text-align:justify;\">To explore West Sumatra’s most iconic destinations in a short time</p></li></ul><h3 style=\"text-align:justify;\"><strong>Epic landscapes. Rich culture. Unforgettable West Sumatra experience.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Ready to discover the beauty of Payakumbuh and Bukittinggi?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>파야쿰부 &amp; 부키팅기 여행: 자연, 문화 그리고 고원 어드벤처 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">아름다운 자연경관과 진정한 미낭카바우 문화, 그리고 시원한 고원 풍경을 한 번에 즐길 수 있는 특별한 서부 수마트라 여행을 만나보세요.</p><p style=\"text-align:justify;\">서부 수마트라를 대표하는 자연 명소인 <strong>하라우 계곡(Lembah Harau)</strong> 에서 숙박하며, 거대한 화강암 절벽과 아름다운 폭포, 푸른 자연이 만들어내는 평화로운 분위기를 만끽할 수 있습니다. 또한 계곡을 가로지르는 웅장한 <strong>끌록 9 다리(Kelok 9 Bridge)</strong> 의 장관도 감상할 수 있습니다.</p><p style=\"text-align:justify;\">여행은 세계에서 가장 아름다운 마을 중 하나로 알려진 <strong>파리앙안 마을(Pariangan Village)</strong> 과 미낭카바우 왕국의 상징인 <strong>파가루융 궁전(Pagaruyung Palace)</strong> 방문으로 더욱 특별해집니다. 이어서 <strong>잠 가당(Jam Gadang)</strong> 으로 유명한 부키팅기에서 현지 분위기를 느끼고, 다양한 미낭카바우 전통 음식도 즐길 수 있습니다.</p><h3 style=\"text-align:justify;\">왜 이 여행인가요?</h3><p style=\"text-align:justify;\">한 번의 여행으로</p><p style=\"text-align:justify;\"><strong>자연 + 문화 + 아름다운 고원 풍경 + 현지 체험 + 서부 수마트라 대표 명소</strong></p><p style=\"text-align:justify;\">를 모두 경험할 수 있기 때문입니다.</p><h3 style=\"text-align:justify;\">이런 여행을 찾고 있다면:</h3><ul><li data-list-item-id=\"e10b8f29bba229fa49dfd22df88cb1575\"><p style=\"text-align:justify;\">아름다운 자연 속 힐링 여행</p></li><li data-list-item-id=\"e7d0d08ecac84a0fce90b0e2e9a9bb38e\"><p style=\"text-align:justify;\">진정한 미낭카바우 문화 체험</p></li><li data-list-item-id=\"e697fb351bb680beb07a34d109a0b2517\"><p style=\"text-align:justify;\">하라우 계곡의 특별한 자연 속 숙박</p></li><li data-list-item-id=\"e74d87f8b71743966eb20fa8d9b3351fd\"><p style=\"text-align:justify;\">짧은 일정으로 서부 수마트라 핵심 명소 탐방</p></li></ul><h3 style=\"text-align:justify;\"><strong>장대한 풍경. 깊은 문화. 잊을 수 없는 서부 수마트라 여행.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>파야쿰부와 부키팅기의 아름다움을 만나볼 준비 되셨나요?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>巴亚孔布 &amp; 武吉丁宜之旅：自然、文化与高原探险 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">开启一场探索西苏门答腊精华的精彩旅程，感受壮丽自然风光、浓厚米南加保文化以及清新宜人的高原氛围。</p><p style=\"text-align:justify;\">入住著名的 <strong>哈劳峡谷（Harau Valley）</strong>，这里拥有高耸壮观的花岗岩峭壁、天然瀑布以及郁郁葱葱的绿色景观，是放松身心和亲近自然的理想之地。旅途中还将欣赏到著名的 <strong>Kelok 9大桥</strong>，这座宏伟建筑与周围山谷景色完美融合，令人赞叹不已。</p><p style=\"text-align:justify;\">继续前往被誉为世界最美村庄之一的 <strong>Pariangan Village（巴里安岸村）</strong>，以及象征米南加保文化与历史的 <strong>Pagaruyung王宫</strong>。随后探索充满魅力的 <strong>武吉丁宜（Bukittinggi）</strong>，参观著名地标 <strong>Jam Gadang大钟楼</strong>，感受当地风情，并品尝令人难忘的米南加保特色美食。</p><h3 style=\"text-align:justify;\">为什么选择这个行程？</h3><p style=\"text-align:justify;\">因为一次旅行就能体验：</p><p style=\"text-align:justify;\"><strong>自然风景 + 文化体验 + 高原美景 + 当地生活体验 + 西苏门答腊经典地标</strong></p><h3 style=\"text-align:justify;\">如果你想要：</h3><ul><li data-list-item-id=\"e17c89260d406a365d9d7f2aaed291a45\"><p style=\"text-align:justify;\">在壮丽自然中放松身心</p></li><li data-list-item-id=\"ee26505f8b0ad56efa78a485529bb6b01\"><p style=\"text-align:justify;\">深度体验米南加保文化</p></li><li data-list-item-id=\"e8b8a45b05708dbcd2da5efddfd5fcd83\"><p style=\"text-align:justify;\">入住风景优美的哈劳峡谷地区</p></li><li data-list-item-id=\"e294e8353c0edb318cb3718cdfaa5b57c\"><p style=\"text-align:justify;\">在短时间内游览西苏门答腊最具代表性的景点</p></li></ul><h3 style=\"text-align:justify;\"><strong>壮丽风景，深厚文化，难忘的西苏门答腊之旅。</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>准备好探索巴亚孔布与武吉丁宜的迷人魅力了吗？</strong></p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 nights in Lembah Harau &nbsp;+ 1 night in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Nature\",\"Scenic Highland\",\"Heritage\",\"Culture\",\"Scenic Road Trip\",\"Leisure\",\"Family\",\"Culinary\"]', NULL, 0, NULL, '2026-05-29 12:18:30', '2026-05-29 12:18:30'),
(87, 47, '3 DAYS EXCITING PACU JAWI', 'WEST SUMATRA', '3-days-exciting-pacu-jawi', '<h2 style=\"text-align:justify;\"><strong>Exciting Pacu Jawi: Culture, Tradition &amp; Scenic West Sumatra Escape 🐂🌿✨</strong></h2><p style=\"text-align:justify;\">Rasakan pengalaman paling unik di Sumatera Barat dengan menyaksikan langsung <strong>Pacu Jawi</strong>, tradisi ikonik Minangkabau yang hanya bisa ditemukan di tanah Minang. Saksikan para joki berpacu di atas sepasang sapi yang berlari kencang melintasi sawah berlumpur, menciptakan momen spektakuler yang penuh adrenalin dan menjadi salah satu atraksi budaya paling terkenal di Indonesia.</p><p style=\"text-align:justify;\">Perjalanan semakin lengkap dengan mengunjungi megahnya <strong>Istana Pagaruyung</strong>, pusat warisan budaya Minangkabau yang sarat sejarah, serta <strong>Desa Pandai Sikek</strong> yang terkenal dengan keindahan songket tenun tradisionalnya. Nikmati juga kesejukan <strong>Air Terjun Lembah Anai</strong>, suasana khas Bukittinggi dengan ikon <strong>Jam Gadang</strong>, dan berbagai kuliner legendaris Minang yang menggoda selera.</p><h3 style=\"text-align:justify;\">Kenapa harus pilih trip ini?</h3><p style=\"text-align:justify;\">Karena ini bukan sekadar liburan, tetapi kesempatan langka untuk menyaksikan salah satu tradisi paling unik di dunia yang berpadu dengan keindahan alam dan budaya Sumatera Barat.</p><h3 style=\"text-align:justify;\">Perfect buat kamu yang mau:</h3><ul><li data-list-item-id=\"e392a5901d101ce29b76b87f1249a1934\"><p style=\"text-align:justify;\">Menyaksikan atraksi budaya autentik yang tidak bisa ditemukan di tempat lain</p></li><li data-list-item-id=\"e1bba7dec555f4a723a6ef3ba7c94acdd\"><p style=\"text-align:justify;\">Explore sejarah dan tradisi Minangkabau yang kaya</p></li><li data-list-item-id=\"e50398f8a24beaf167bf22d6148b1c8ea\"><p style=\"text-align:justify;\">Menikmati perpaduan alam, budaya, dan kuliner dalam satu perjalanan</p></li><li data-list-item-id=\"e3cad140b08f6c26c0e50b3b110324d6c\"><p style=\"text-align:justify;\">Mendapatkan pengalaman dan foto-foto yang benar-benar berbeda dari destinasi wisata biasa</p></li></ul><h3 style=\"text-align:justify;\"><strong>Authentic culture. Epic traditions. Unforgettable West Sumatra experience.</strong> 🐂✨</h3><p style=\"text-align:justify;\"><strong>Siap merasakan serunya Pacu Jawi dan pesona budaya Minangkabau yang mendunia?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>Exciting Pacu Jawi: Culture, Tradition &amp; Scenic West Sumatra Escape 🐂🌿✨</strong></h2><p style=\"text-align:justify;\">Experience one of West Sumatra’s most unique and unforgettable adventures by witnessing <strong>Pacu Jawi</strong>, the iconic Minangkabau tradition found only in the heart of West Sumatra. Watch skilled jockeys race atop a pair of bulls across muddy rice fields, creating a thrilling spectacle that has become one of Indonesia’s most extraordinary cultural attractions.</p><p style=\"text-align:justify;\">Your journey continues with a visit to the magnificent <strong>Pagaruyung Palace</strong>, the proud symbol of Minangkabau heritage and history. Explore <strong>Pandai Sikek Village</strong>, renowned for its beautiful handwoven songket textiles, and enjoy the refreshing atmosphere of <strong>Lembah Anai Waterfall</strong>. Complete your experience in <strong>Bukittinggi</strong>, home to the iconic <strong>Jam Gadang Clock Tower</strong>, vibrant local culture, and legendary Minang cuisine.</p><h3 style=\"text-align:justify;\">Why choose this trip?</h3><p style=\"text-align:justify;\">Because this is more than just a holiday—it\'s a rare opportunity to witness one of the world\'s most unique cultural traditions while discovering the beauty, history, and charm of West Sumatra.</p><h3 style=\"text-align:justify;\">Perfect for you if you want:</h3><ul><li data-list-item-id=\"eb83a69c45b8ae3b179cdfde0e96ef437\"><p style=\"text-align:justify;\">To experience an authentic cultural attraction found nowhere else</p></li><li data-list-item-id=\"e6031d832c31e3b9c5d341e134d34b2cb\"><p style=\"text-align:justify;\">To explore the rich heritage and traditions of the Minangkabau people</p></li><li data-list-item-id=\"e0ca0447f63af48b5467cdbf1cbdfc862\"><p style=\"text-align:justify;\">To enjoy a perfect blend of culture, nature, and local cuisine</p></li><li data-list-item-id=\"ebe9b0d271eb37f9ccb9edcdbd3a5ffb3\"><p style=\"text-align:justify;\">To capture truly unique and unforgettable travel moments</p></li></ul><h3 style=\"text-align:justify;\"><strong>Authentic culture. Epic traditions. Unforgettable West Sumatra experience.</strong> 🐂✨</h3><p style=\"text-align:justify;\"><strong>Ready to experience the excitement of Pacu Jawi and the world-famous Minangkabau culture?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>익사이팅 파추 자위: 문화, 전통 그리고 아름다운 서부 수마트라 여행 🐂🌿✨</strong></h2><p style=\"text-align:justify;\">서부 수마트라에서만 만날 수 있는 특별한 전통 문화 행사 <strong>파추 자위(Pacu Jawi)</strong> 를 직접 체험해보세요. 진흙 논 위를 질주하는 두 마리의 소 위에서 기수들이 펼치는 역동적인 경주는 놀라움과 감동을 선사하며, 인도네시아를 대표하는 가장 독특한 문화 체험 중 하나로 알려져 있습니다.</p><p style=\"text-align:justify;\">여행은 미낭카바우 문화와 역사의 상징인 웅장한 <strong>파가루융 궁전(Pagaruyung Palace)</strong> 방문으로 이어집니다. 아름다운 전통 송켓 직물로 유명한 <strong>판다이 시켁 마을(Pandai Sikek Village)</strong> 을 둘러보고, 시원한 자연 풍경의 <strong>렘바 안아이 폭포(Lembah Anai Waterfall)</strong> 를 감상해보세요. 또한 <strong>잠 가당(Jam Gadang)</strong> 으로 유명한 부키팅기에서 현지 문화와 다양한 미낭카바우 음식을 즐길 수 있습니다.</p><h3 style=\"text-align:justify;\">왜 이 여행인가요?</h3><p style=\"text-align:justify;\">단순한 관광이 아닌, 세계적으로도 보기 드문 전통 문화를 직접 체험하고 서부 수마트라의 아름다운 자연과 역사를 함께 만날 수 있는 특별한 기회이기 때문입니다.</p><h3 style=\"text-align:justify;\">이런 여행을 찾고 있다면:</h3><ul><li data-list-item-id=\"e8a377d7f7d17b923b10ea072c7ec2562\"><p style=\"text-align:justify;\">다른 곳에서는 볼 수 없는 특별한 문화 체험</p></li><li data-list-item-id=\"e3b9be6a4880be4fa290a7a1d81e7110f\"><p style=\"text-align:justify;\">미낭카바우의 역사와 전통 탐방</p></li><li data-list-item-id=\"ee0e3a1aeae70878e51260df08f90a705\"><p style=\"text-align:justify;\">자연, 문화, 미식을 한 번에 즐기는 여행</p></li><li data-list-item-id=\"e6c2eec8b9fbf2dbb114459982375c429\"><p style=\"text-align:justify;\">특별하고 인상적인 여행 사진과 추억 만들기</p></li></ul><h3 style=\"text-align:justify;\"><strong>진정한 문화. 특별한 전통. 잊지 못할 서부 수마트라 여행.</strong> 🐂✨</h3><p style=\"text-align:justify;\"><strong>파추 자위의 열기와 세계적으로 유명한 미낭카바우 문화를 경험할 준비 되셨나요?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>精彩斗牛赛(Pacu Jawi）：文化、传统与西苏门答腊风景之旅 🐂🌿✨</strong></h2><p style=\"text-align:justify;\">体验西苏门答腊最独特、最令人难忘的文化之旅，亲眼见证著名的 <strong>Pacu Jawi（斗牛赛）</strong>。这是米南加保民族独有的传统活动，骑手站立在两头奔跑的牛背上，在泥泞稻田中疾驰，场面震撼而精彩，被誉为印度尼西亚最具特色的文化盛事之一。</p><p style=\"text-align:justify;\">旅程还将带您参观雄伟壮观的 <strong>Pagaruyung王宫</strong>，深入了解米南加保民族悠久的历史与文化。探索以传统宋吉锦（Songket）闻名的 <strong>Pandai Sikek村</strong>，感受精湛的手工艺魅力；欣赏风景优美的 <strong>Lembah Anai瀑布</strong>，并在 <strong>武吉丁宜（Bukittinggi）</strong> 体验著名的 <strong>Jam Gadang大钟楼</strong>、当地风情以及令人回味无穷的米南加保美食。</p><h3 style=\"text-align:justify;\">为什么选择这个行程？</h3><p style=\"text-align:justify;\">因为这不仅仅是一场旅行，更是一次难得的机会，让您亲身体验世界上独一无二的传统文化，同时探索西苏门答腊壮丽的自然风光与丰富的人文历史。</p><h3 style=\"text-align:justify;\">如果你想要：</h3><ul><li data-list-item-id=\"ef9f6e2eeb18d07562d53e3be8bb45985\"><p style=\"text-align:justify;\">体验其他地方无法看到的独特文化活动</p></li><li data-list-item-id=\"ea1be3cc789729f9cd9132eabffdc5827\"><p style=\"text-align:justify;\">深入了解米南加保文化与传统</p></li><li data-list-item-id=\"e577b60d3f0049dd619e67b5cba6bc27d\"><p style=\"text-align:justify;\">一次享受自然、美食与文化的完美旅程</p></li><li data-list-item-id=\"ea7fe77a71e8747d0ca7738d4c43bcf3c\"><p style=\"text-align:justify;\">收获与众不同、难忘的旅行回忆和照片</p></li></ul><h3 style=\"text-align:justify;\"><strong>真实文化，震撼传统，难忘的西苏门答腊之旅。</strong> 🐂✨</h3><p style=\"text-align:justify;\"><strong>准备好亲身感受Pacu Jawi的激情与世界闻名的米南加保文化了吗？</strong></p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (2 night in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Culture\",\"Heritage\",\"Scenic\",\"Nature\"]', NULL, 0, NULL, '2026-05-29 12:43:36', '2026-05-29 12:43:36'),
(88, 47, '3 DAYS BUKITTINGGI BUNGA RAFLESIA PALUPUAH', 'WEST SUMATRA', '3-days-bukittinggi-bunga-raflesia-palupuah', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Rafflesia Escape: Rare Nature, Culture &amp; Hidden Gem Adventure 🌺🌿✨</strong></h2><p style=\"text-align:justify;\">Temukan pengalaman yang benar-benar berbeda di Sumatera Barat dengan menyaksikan secara langsung <strong>Bunga Rafflesia</strong>, salah satu bunga terbesar dan paling langka di dunia yang hanya mekar pada waktu-waktu tertentu. Perjalanan menuju <strong>Nagari Palupuah</strong> menghadirkan pengalaman eksklusif bagi pecinta alam dan petualang yang ingin melihat keajaiban alam yang tidak bisa ditemukan setiap hari.</p><p style=\"text-align:justify;\">Tak hanya itu, perjalanan ini juga mengajakmu menikmati pesona khas Minangkabau melalui <strong>Desa Pandai Sikek</strong> yang terkenal dengan tenun songket tradisionalnya, ikon <strong>Jam Gadang</strong> yang menjadi simbol Bukittinggi, serta suasana budaya yang masih terjaga hingga saat ini. Lengkapi pengalamanmu dengan melihat langsung proses pembuatan <strong>Rendang khas Minang</strong>, salah satu kuliner terbaik di dunia.</p><h3 style=\"text-align:justify;\">Kenapa harus pilih trip ini?</h3><p style=\"text-align:justify;\">Karena ini bukan sekadar liburan biasa. Ini adalah kesempatan langka untuk menyaksikan <strong>Bunga Rafflesia</strong>, keajaiban alam yang menjadi impian banyak traveler dan fotografer, dipadukan dengan kekayaan budaya Minangkabau yang autentik.</p><h3 style=\"text-align:justify;\">Perfect buat kamu yang mau:</h3><ul><li data-list-item-id=\"ec1d845e223ec020f800c6797f2f69df9\"><p style=\"text-align:justify;\">Melihat langsung bunga langka terbesar di dunia</p></li><li data-list-item-id=\"edae2a24e12c6e396ede836966da98504\"><p style=\"text-align:justify;\">Explore hidden gems Sumatera Barat yang belum banyak diketahui wisatawan</p></li><li data-list-item-id=\"e05ca1a42123408669c6639dfb317c7d5\"><p style=\"text-align:justify;\">Menikmati perpaduan alam, budaya, dan pengalaman lokal yang autentik</p></li><li data-list-item-id=\"ededc1a44e4c9e7702b994ab708e93b58\"><p style=\"text-align:justify;\">Mendapatkan pengalaman dan foto-foto yang unik serta berbeda dari destinasi wisata biasa</p></li></ul><h3 style=\"text-align:justify;\"><strong>Rare nature. Authentic culture. Unforgettable West Sumatra experience.</strong> 🌺✨</h3><p style=\"text-align:justify;\"><strong>Siap menyaksikan keajaiban Bunga Rafflesia dan pesona Bukittinggi yang memikat?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Rafflesia Escape: Rare Nature, Culture &amp; Hidden Gem Adventure 🌺🌿✨</strong></h2><p style=\"text-align:justify;\">Discover a truly unique experience in West Sumatra by witnessing the extraordinary <strong>Rafflesia Flower</strong>, one of the largest and rarest flowers in the world. Since it blooms only at certain times, a visit to <strong>Palupuah Village</strong> offers a rare opportunity to see one of nature’s most remarkable wonders up close.</p><p style=\"text-align:justify;\">Beyond its natural beauty, this journey invites you to experience the rich heritage of the Minangkabau people. Explore <strong>Pandai Sikek Village</strong>, famous for its traditional handwoven songket textiles, visit the iconic <strong>Jam Gadang Clock Tower</strong>, and immerse yourself in the authentic atmosphere of Bukittinggi. Complete your adventure by learning about the traditional process of making <strong>Rendang</strong>, one of the world\'s most celebrated dishes.</p><h3 style=\"text-align:justify;\">Why choose this trip?</h3><p style=\"text-align:justify;\">Because this is more than just a holiday—it’s a rare chance to witness the magnificent <strong>Rafflesia Flower</strong>, a dream destination for nature lovers, photographers, and curious travelers, combined with the rich cultural heritage of West Sumatra.</p><h3 style=\"text-align:justify;\">Perfect for you if you want:</h3><ul><li data-list-item-id=\"ee8ded27794acdbcfa48a1bdab1f37502\"><p style=\"text-align:justify;\">To see one of the world’s rarest and largest flowers</p></li><li data-list-item-id=\"e231d6bfd60b2b7f1d237e5fc2f6d3eac\"><p style=\"text-align:justify;\">To discover hidden gems beyond the usual tourist routes</p></li><li data-list-item-id=\"e3e3fc6ab087ff526ea175f39fa6cc8b2\"><p style=\"text-align:justify;\">To experience authentic Minangkabau culture and local traditions</p></li><li data-list-item-id=\"ebbbc82b8fff7494f00c4dfe821c04a29\"><p style=\"text-align:justify;\">To capture unique and unforgettable travel moments</p></li></ul><h3 style=\"text-align:justify;\"><strong>Rare nature. Authentic culture. Unforgettable West Sumatra experience.</strong> 🌺✨</h3><p style=\"text-align:justify;\"><strong>Ready to witness the wonder of the Rafflesia Flower and the charm of Bukittinggi?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>부키팅기 &amp; 라플레시아 여행: 희귀한 자연과 문화, 숨겨진 명소 탐험 🌺🌿✨</strong></h2><p style=\"text-align:justify;\">서부 수마트라에서만 만날 수 있는 특별한 여행을 경험해보세요. 세계에서 가장 크고 희귀한 꽃 중 하나인 <strong>라플레시아(Rafflesia)</strong> 를 직접 볼 수 있는 특별한 기회가 여러분을 기다립니다. 특정 시기에만 꽃을 피우는 라플레시아는 자연이 선물한 놀라운 기적으로, <strong>팔루푸아(Palupuah)</strong> 에서만 만날 수 있는 특별한 경험입니다.</p><p style=\"text-align:justify;\">여행은 자연뿐만 아니라 미낭카바우 문화의 매력도 함께 선사합니다. 전통 송켓 직물로 유명한 <strong>판다이 시켁 마을</strong>, 부키팅기의 상징인 <strong>잠 가당 시계탑</strong>, 그리고 오랜 전통이 살아있는 지역 문화를 만나보세요. 또한 세계적으로 유명한 음식인 <strong>렌당(Rendang)</strong> 의 전통 제조 과정도 직접 볼 수 있습니다.</p><h3 style=\"text-align:justify;\">왜 이 여행인가요?</h3><p style=\"text-align:justify;\">단순한 관광이 아닌, 세계적으로 희귀한 <strong>라플레시아 꽃</strong>을 직접 보고 서부 수마트라의 전통 문화와 아름다운 자연을 함께 경험할 수 있는 특별한 여행이기 때문입니다.</p><h3 style=\"text-align:justify;\">이런 여행을 찾고 있다면:</h3><ul><li data-list-item-id=\"eeea01c81a93ec53d95019d9202f60e7d\"><p style=\"text-align:justify;\">세계에서 가장 희귀한 꽃 중 하나를 직접 보고 싶은 분</p></li><li data-list-item-id=\"ee55f278de1d411512623a0b596f0a4b6\"><p style=\"text-align:justify;\">잘 알려지지 않은 숨겨진 명소를 탐험하고 싶은 분</p></li><li data-list-item-id=\"e831b067cb12bbd6a95989de310de62a4\"><p style=\"text-align:justify;\">진정한 미낭카바우 문화와 전통을 경험하고 싶은 분</p></li><li data-list-item-id=\"eaa205d80253a6e35ec665b25000df657\"><p style=\"text-align:justify;\">특별하고 인상적인 여행 사진을 남기고 싶은 분</p></li></ul><h3 style=\"text-align:justify;\"><strong>희귀한 자연. 진정한 문화. 잊을 수 없는 서부 수마트라 여행.</strong> 🌺✨</h3><p style=\"text-align:justify;\"><strong>라플레시아의 경이로움과 부키팅기의 매력을 만나볼 준비 되셨나요?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>武吉丁宜 &amp; 大王花之旅：珍稀自然、文化与秘境探索 🌺🌿✨</strong></h2><p style=\"text-align:justify;\">开启一场与众不同的西苏门答腊之旅，亲眼见证世界上最大、最稀有的花朵之一——<strong>大王花（Rafflesia）</strong>。由于大王花只会在特定时期绽放，因此前往 <strong>Palupuah村</strong> 是一次难得而珍贵的机会，让您近距离欣赏这一大自然的奇迹。</p><p style=\"text-align:justify;\">除了独特的自然景观，旅程还将带您深入体验米南加保文化。参观以传统宋吉锦（Songket）闻名的 <strong>Pandai Sikek村</strong>，打卡武吉丁宜最著名的地标 <strong>Jam Gadang大钟楼</strong>，感受浓厚的当地文化氛围。同时，您还可以了解世界知名美食 <strong>仁当牛肉（Rendang）</strong> 的传统制作过程。</p><h3 style=\"text-align:justify;\">为什么选择这个行程？</h3><p style=\"text-align:justify;\">因为这不仅仅是一场普通旅行，更是一次难得的机会，让您亲眼见证珍贵的大王花，同时深入探索西苏门答腊丰富的文化遗产与自然之美。</p><h3 style=\"text-align:justify;\">如果你想要：</h3><ul><li data-list-item-id=\"eb03b33bec6334e0864c087095eca680b\"><p style=\"text-align:justify;\">亲眼欣赏世界上最稀有、最大的花朵之一</p></li><li data-list-item-id=\"eb402d1dde68cc8bcacd855eed52a4883\"><p style=\"text-align:justify;\">探索鲜为人知的西苏门答腊秘境</p></li><li data-list-item-id=\"ee8eeb1b48fb07c66126a977fbfc78738\"><p style=\"text-align:justify;\">深入体验真实的米南加保文化与传统</p></li><li data-list-item-id=\"e8467b56652feef176945b7a0676605bd\"><p style=\"text-align:justify;\">收获独特且难忘的旅行回忆与照片</p></li></ul><h3 style=\"text-align:justify;\"><strong>珍稀自然，真实文化，难忘的西苏门答腊之旅。</strong> 🌺✨</h3><p style=\"text-align:justify;\"><strong>准备好见证大王花的奇迹与武吉丁宜的独特魅力了吗？</strong></p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (2 night in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Nature\",\"Eco & Conservation\",\"Culture\",\"Urban Lifestyle\",\"Culinary\",\"Experiential & Photography\"]', NULL, 0, NULL, '2026-05-29 12:57:51', '2026-05-29 12:58:11');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(89, 47, '3 DAYS BUKITTINGGI', 'WEST SUMATRA', '3-days-bukittinggi', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi Highlights: Nature, Culture &amp; Scenic Highlands Escape 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Jelajahi pesona terbaik Sumatera Barat dalam perjalanan yang memadukan panorama alam spektakuler, budaya Minangkabau yang kaya, dan destinasi ikonik yang memikat. Dari sejuknya <strong>Air Terjun Lembah Anai</strong>, megahnya tebing granit <strong>Lembah Harau</strong>, hingga keindahan arsitektur <strong>Kelok 9</strong> yang membelah lembah hijau, setiap perjalanan menghadirkan pemandangan yang membuat takjub.</p><p style=\"text-align:justify;\">Rasakan kehangatan budaya Minangkabau melalui kunjungan ke <strong>Istana Pagaruyung</strong>, simbol kebesaran kerajaan Minang, dan <strong>Desa Pariangan</strong>, desa tradisional yang dikenal sebagai salah satu desa terindah di dunia. Lengkapi pengalaman dengan suasana khas <strong>Bukittinggi</strong>, ikon <strong>Jam Gadang</strong>, Panorama Baru yang memukau, serta cita rasa kuliner legendaris yang menjadi kebanggaan Sumatera Barat.</p><h3 style=\"text-align:justify;\">Kenapa harus pilih trip ini?</h3><p style=\"text-align:justify;\">Karena dalam satu perjalanan singkat, kamu bisa menikmati kombinasi sempurna antara:</p><p style=\"text-align:justify;\"><strong>panorama alam yang luar biasa + budaya autentik Minangkabau + desa tradisional yang menawan + kuliner legendaris + destinasi ikonik Sumatera Barat</strong></p><h3 style=\"text-align:justify;\">Perfect buat kamu yang mau:</h3><ul><li data-list-item-id=\"e355bdb2eca2e433f9cf6ca2e1fc37496\"><p style=\"text-align:justify;\">Healing dengan udara pegunungan yang sejuk dan pemandangan yang menenangkan</p></li><li data-list-item-id=\"e685753c48b4c08c74efef3ea813f7ca1\"><p style=\"text-align:justify;\">Menjelajahi budaya Minangkabau yang autentik dan kaya sejarah</p></li><li data-list-item-id=\"e2924e8687303e0c7c96a751a6df345d4\"><p style=\"text-align:justify;\">Mengunjungi landmark paling terkenal di Sumatera Barat</p></li><li data-list-item-id=\"e0ed8dac5bab6ed4916ad6b1019835925\"><p style=\"text-align:justify;\">Menikmati pengalaman liburan yang lengkap, santai, dan penuh momen berkesan</p></li></ul><h3 style=\"text-align:justify;\"><strong>Breathtaking landscapes. Authentic culture. Unforgettable West Sumatra journey.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Siap jatuh cinta dengan keindahan Bukittinggi dan pesona Sumatera Barat yang tak terlupakan?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi Highlights: Nature, Culture &amp; Scenic Highlands Escape 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Discover the very best of West Sumatra on a journey that combines breathtaking natural landscapes, rich Minangkabau culture, and iconic destinations. From the refreshing beauty of <strong>Lembah Anai Waterfall</strong>, the majestic granite cliffs of <strong>Harau Valley</strong>, to the impressive architecture of the <strong>Kelok 9 Bridge</strong> stretching across lush green valleys, every moment offers unforgettable views and experiences.</p><p style=\"text-align:justify;\">Immerse yourself in the rich heritage of the Minangkabau people with visits to the magnificent <strong>Pagaruyung Palace</strong>, a symbol of the former Minangkabau Kingdom, and <strong>Pariangan Village</strong>, recognized as one of the most beautiful traditional villages in the world. Complete your journey with the charm of <strong>Bukittinggi</strong>, home to the iconic <strong>Jam Gadang Clock Tower</strong>, the stunning Panorama Park, and legendary Minang cuisine that has earned worldwide recognition.</p><h3 style=\"text-align:justify;\">Why choose this trip?</h3><p style=\"text-align:justify;\">Because in one short journey, you can experience the perfect combination of:</p><p style=\"text-align:justify;\"><strong>spectacular natural scenery + authentic Minangkabau culture + charming traditional villages + legendary cuisine + iconic West Sumatra landmarks</strong></p><h3 style=\"text-align:justify;\">Perfect for you if you want:</h3><ul><li data-list-item-id=\"e90fc05194a98056c54b0c1a3acb4a58c\"><p style=\"text-align:justify;\">A relaxing escape surrounded by cool mountain air and stunning landscapes</p></li><li data-list-item-id=\"eda31dab8543e4fef61c869ac9e576bc8\"><p style=\"text-align:justify;\">To discover the authentic culture and history of the Minangkabau people</p></li><li data-list-item-id=\"e4e10e258507bddce20d3018a0cc5b903\"><p style=\"text-align:justify;\">To visit the most famous attractions in West Sumatra</p></li><li data-list-item-id=\"e74deef6fa3d687af8789124fec059215\"><p style=\"text-align:justify;\">A complete, relaxing, and memorable travel experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>Breathtaking landscapes. Authentic culture. Unforgettable West Sumatra journey.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Ready to fall in love with the beauty of Bukittinggi and the wonders of West Sumatra?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>부키팅기 하이라이트: 자연, 문화 그리고 아름다운 고원 여행 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">서부 수마트라 최고의 자연경관과 미낭카바우 문화, 그리고 대표 명소들을 한 번에 경험할 수 있는 특별한 여행을 만나보세요.</p><p style=\"text-align:justify;\">시원하고 아름다운 <strong>렘바 안아이 폭포</strong>, 웅장한 화강암 절벽으로 둘러싸인 <strong>하라우 계곡</strong>, 그리고 푸른 계곡 위를 가로지르는 인상적인 <strong>끌록 9 다리</strong>까지, 여행 내내 감탄을 자아내는 풍경이 펼쳐집니다.</p><p style=\"text-align:justify;\">또한 미낭카바우 왕국의 상징인 <strong>파가루융 궁전</strong>, 세계에서 가장 아름다운 전통 마을 중 하나로 알려진 <strong>파리앙안 마을</strong>을 방문하며 서부 수마트라의 깊은 역사와 문화를 경험할 수 있습니다. 여행의 마지막은 부키팅기의 상징인 <strong>잠 가당 시계탑</strong>, 아름다운 파노라마 전망대, 그리고 세계적으로 사랑받는 미낭카바우 요리와 함께 더욱 특별해집니다.</p><h3 style=\"text-align:justify;\">왜 이 여행인가요?</h3><p style=\"text-align:justify;\">한 번의 여행으로</p><p style=\"text-align:justify;\"><strong>아름다운 자연경관 + 진정한 미낭카바우 문화 + 전통 마을 + 유명한 현지 음식 + 대표 명소</strong></p><p style=\"text-align:justify;\">를 모두 경험할 수 있기 때문입니다.</p><h3 style=\"text-align:justify;\">이런 여행을 찾고 있다면:</h3><ul><li data-list-item-id=\"ef61b7b4ec3bdda5d2ec6042c8044368f\"><p style=\"text-align:justify;\">시원한 산속에서 힐링하고 싶은 분</p></li><li data-list-item-id=\"e2eb85a089b65157ef158c61f283b5551\"><p style=\"text-align:justify;\">미낭카바우의 역사와 문화를 깊이 경험하고 싶은 분</p></li><li data-list-item-id=\"e74be3e973e032bc613cabc6e2690c935\"><p style=\"text-align:justify;\">서부 수마트라의 대표 관광지를 둘러보고 싶은 분</p></li><li data-list-item-id=\"e867f70346bfe35b2bd9785b85f55dea4\"><p style=\"text-align:justify;\">여유롭고 특별한 여행을 원하는 분</p></li></ul><h3 style=\"text-align:justify;\"><strong>장대한 풍경. 깊은 문화. 잊을 수 없는 서부 수마트라 여행.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>부키팅기와 서부 수마트라의 아름다움에 빠질 준비 되셨나요?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>武吉丁宜精选之旅：自然、文化与高原风光之旅 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">探索西苏门答腊最精彩的魅力，体验壮丽自然风光、深厚米南加保文化以及众多经典地标景点。</p><p style=\"text-align:justify;\">从清新迷人的 <strong>Lembah Anai瀑布</strong>，到壮观的 <strong>Harau Valley哈劳峡谷</strong>，再到横跨翠绿山谷的著名 <strong>Kelok 9大桥</strong>，沿途每一处风景都令人惊叹不已。</p><p style=\"text-align:justify;\">深入了解米南加保文化，参观象征昔日米南加保王国辉煌历史的 <strong>Pagaruyung王宫</strong>，以及被誉为世界最美传统村庄之一的 <strong>Pariangan Village（巴里安岸村）</strong>。随后漫步在充满魅力的 <strong>武吉丁宜（Bukittinggi）</strong>，欣赏标志性的 <strong>Jam Gadang大钟楼</strong>、壮丽的全景观景台，并品尝享誉世界的米南加保特色美食。</p><h3 style=\"text-align:justify;\">为什么选择这个行程？</h3><p style=\"text-align:justify;\">因为一次旅行就能体验：</p><p style=\"text-align:justify;\"><strong>壮丽自然风景 + 地道米南加保文化 + 迷人传统村庄 + 传奇美食 + 西苏门答腊经典地标</strong></p><h3 style=\"text-align:justify;\">如果你想要：</h3><ul><li data-list-item-id=\"e95617af7f32cf544bd95e27bb22301f5\"><p style=\"text-align:justify;\">在清凉舒适的高原环境中放松身心</p></li><li data-list-item-id=\"e9e525361041121da3024f70018523607\"><p style=\"text-align:justify;\">深入探索米南加保文化与历史</p></li><li data-list-item-id=\"ee2b2bf04ac9749a3d232bc7079949045\"><p style=\"text-align:justify;\">打卡西苏门答腊最著名的景点</p></li><li data-list-item-id=\"e2bfe7397aaa1b29af3e6cd6baebc617b\"><p style=\"text-align:justify;\">享受轻松、丰富且难忘的旅行体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>壮丽风景，深厚文化，难忘的西苏门答腊之旅。</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>准备好爱上武吉丁宜和西苏门答腊的迷人风光了吗？</strong></p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (2 night in Bukittinggi) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Nature\",\"Scenic Highland\",\"Culture\",\"Heritage\",\"Scenic Road Trip\",\"Culinary\",\"Leisure\"]', NULL, 0, NULL, '2026-05-29 13:11:18', '2026-05-29 13:11:18'),
(90, 47, '3 DAYS BUKITTINGGI - PADANG', 'WEST SUMATRA', '3-days-bukittinggi-padang', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Padang Escape: The Best of West Sumatra 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Temukan pesona terbaik Sumatera Barat dalam perjalanan yang memadukan keindahan alam, kekayaan budaya, dan destinasi ikonik yang tak terlupakan. Nikmati kesejukan <strong>Air Terjun Lembah Anai</strong>, jelajahi <strong>Lembah Harau</strong> yang terkenal dengan tebing granit raksasa dan air terjunnya yang memukau, serta rasakan pengalaman menyusuri dataran tinggi Minangkabau dengan panorama alam yang begitu memanjakan mata.</p><p style=\"text-align:justify;\">Perjalanan semakin istimewa dengan kunjungan ke <strong>Istana Pagaruyung</strong>, simbol kejayaan budaya Minangkabau, <strong>Desa Pandai Sikek</strong> yang terkenal dengan tenun songket tradisionalnya, serta <strong>Jam Gadang</strong>, ikon paling terkenal di Bukittinggi. Lengkapi pengalamanmu dengan menikmati suasana Kota Tua Padang, Jembatan Siti Nurbaya, hingga keindahan Pantai Padang yang menjadi tempat sempurna untuk menikmati suasana khas pesisir Sumatera Barat.</p><h3 style=\"text-align:justify;\">Kenapa harus pilih trip ini?</h3><p style=\"text-align:justify;\">Karena dalam satu perjalanan singkat, kamu bisa menikmati perpaduan sempurna antara:</p><p style=\"text-align:justify;\"><strong>panorama alam spektakuler + budaya Minangkabau yang autentik + destinasi ikonik + kuliner legendaris + pengalaman lokal yang berkesan</strong></p><h3 style=\"text-align:justify;\">Perfect buat kamu yang mau:</h3><ul><li data-list-item-id=\"e2bbba025c8f4036342b845681451b61e\"><p style=\"text-align:justify;\">Menikmati keindahan alam terbaik Sumatera Barat</p></li><li data-list-item-id=\"ea22498bb1bc363af6d5271a71ee637ff\"><p style=\"text-align:justify;\">Mengenal budaya Minangkabau yang kaya dan unik</p></li><li data-list-item-id=\"e46c6135eebae8c14ffb9faf1b2d7dc9c\"><p style=\"text-align:justify;\">Mengunjungi landmark paling terkenal di Bukittinggi dan Padang</p></li><li data-list-item-id=\"ee30ad36d2840941e0e4f66f37ebf7738\"><p style=\"text-align:justify;\">Merasakan liburan yang lengkap, santai, dan penuh pengalaman berharga</p></li></ul><h3 style=\"text-align:justify;\"><strong>Breathtaking landscapes. Authentic culture. Endless West Sumatra memories.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Siap menjelajahi Bukittinggi dan Padang, dua destinasi terbaik yang menjadi jantung pesona Sumatera Barat?</strong> 🌿✨</p>', '<h2 style=\"text-align:justify;\"><strong>Bukittinggi &amp; Padang Escape: The Best of West Sumatra 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">Discover the very best of West Sumatra through a journey that combines breathtaking natural beauty, rich cultural heritage, and iconic destinations. Enjoy the refreshing atmosphere of <strong>Lembah Anai Waterfall</strong>, explore the magnificent <strong>Harau Valley</strong> with its towering granite cliffs and stunning waterfalls, and experience the charm of the Minangkabau Highlands with spectacular landscapes at every turn.</p><p style=\"text-align:justify;\">Your journey becomes even more memorable with visits to the majestic <strong>Pagaruyung Palace</strong>, the symbol of Minangkabau heritage, the traditional weaving village of <strong>Pandai Sikek</strong>, and the iconic <strong>Jam Gadang Clock Tower</strong>, the landmark of Bukittinggi. Complete your adventure by exploring <strong>Padang Old Town</strong>, the historic <strong>Siti Nurbaya Bridge</strong>, and the beautiful <strong>Padang Beach</strong>, the perfect place to enjoy the coastal atmosphere of West Sumatra.</p><h3 style=\"text-align:justify;\">Why choose this trip?</h3><p style=\"text-align:justify;\">Because in one short journey, you can experience the perfect combination of:</p><p style=\"text-align:justify;\"><strong>spectacular landscapes + authentic Minangkabau culture + iconic landmarks + legendary cuisine + memorable local experiences</strong></p><h3 style=\"text-align:justify;\">Perfect for you if you want:</h3><ul><li data-list-item-id=\"ee5bd8ef7234494666792f0316cf619e1\"><p style=\"text-align:justify;\">To enjoy the best natural attractions of West Sumatra</p></li><li data-list-item-id=\"e568e57bd9d2102f1e2001ad5b4ae7c78\"><p style=\"text-align:justify;\">To discover the rich and unique Minangkabau culture</p></li><li data-list-item-id=\"e0dddab094c1275d80f749d12641ed418\"><p style=\"text-align:justify;\">To visit the most famous landmarks in Bukittinggi and Padang</p></li><li data-list-item-id=\"e78aa72e362ff749380d19ffc4446f6e0\"><p style=\"text-align:justify;\">A complete, relaxing, and unforgettable holiday experience</p></li></ul><h3 style=\"text-align:justify;\"><strong>Breathtaking landscapes. Authentic culture. Endless West Sumatra memories.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>Ready to explore Bukittinggi and Padang, the two destinations that represent the true beauty of West Sumatra?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>부키팅기 &amp; 파당 여행: 서부 수마트라 최고의 매력을 만나다 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">아름다운 자연경관, 풍부한 문화유산, 그리고 대표적인 명소들을 한 번에 경험할 수 있는 서부 수마트라 여행을 만나보세요. 시원하고 아름다운 <strong>렘바 안아이 폭포</strong>, 웅장한 화강암 절벽과 폭포로 유명한 <strong>하라우 계곡</strong>, 그리고 눈부신 풍경이 펼쳐지는 미낭카바우 고원의 매력을 마음껏 즐길 수 있습니다.</p><p style=\"text-align:justify;\">또한 미낭카바우 문화의 상징인 <strong>파가루융 궁전</strong>, 전통 송켓 직물로 유명한 <strong>판다이 시켁 마을</strong>, 그리고 부키팅기의 대표 랜드마크인 <strong>잠 가당 시계탑</strong>을 방문하며 더욱 특별한 경험을 할 수 있습니다. 여행의 마지막은 <strong>파당 구시가지</strong>, 역사적인 <strong>시티 누르바야 다리</strong>, 그리고 아름다운 <strong>파당 해변</strong>에서 서부 수마트라의 해안 풍경을 만끽하며 완성됩니다.</p><h3 style=\"text-align:justify;\">왜 이 여행인가요?</h3><p style=\"text-align:justify;\">한 번의 여행으로</p><p style=\"text-align:justify;\"><strong>장대한 자연경관 + 진정한 미낭카바우 문화 + 대표 명소 + 유명한 현지 음식 + 특별한 현지 체험</strong></p><p style=\"text-align:justify;\">을 모두 경험할 수 있기 때문입니다.</p><h3 style=\"text-align:justify;\">이런 여행을 찾고 있다면:</h3><ul><li data-list-item-id=\"e4adee5fa67d03d911ebaa2065847449b\"><p style=\"text-align:justify;\">서부 수마트라 최고의 자연 명소를 방문하고 싶은 분</p></li><li data-list-item-id=\"e9bd92b24e64542ca3b8ee3b1e4df87c8\"><p style=\"text-align:justify;\">미낭카바우의 독특한 문화와 전통을 경험하고 싶은 분</p></li><li data-list-item-id=\"e662d7e8d375cd59985f32ccce968aaa3\"><p style=\"text-align:justify;\">부키팅기와 파당의 대표 관광지를 둘러보고 싶은 분</p></li><li data-list-item-id=\"eee953dbcb7da10e1e603caf6e607c213\"><p style=\"text-align:justify;\">여유롭고 알찬 여행을 원하는 분</p></li></ul><h3 style=\"text-align:justify;\"><strong>장엄한 풍경. 진정한 문화. 끝없는 서부 수마트라의 추억.</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>서부 수마트라의 아름다움을 대표하는 부키팅기와 파당을 탐험할 준비가 되셨나요?</strong></p>', '<h2 style=\"text-align:justify;\"><strong>武吉丁宜 &amp; 巴东之旅：探索西苏门答腊的精华魅力 🌿🏞️✨</strong></h2><p style=\"text-align:justify;\">开启一场融合壮丽自然风光、深厚文化底蕴和经典地标景点的精彩旅程，探索西苏门答腊最迷人的一面。欣赏清新优美的 <strong>Lembah Anai瀑布</strong>，探索拥有壮观花岗岩峭壁和瀑布景观的 <strong>Harau Valley哈劳峡谷</strong>，并沉浸在米南加保高原令人惊叹的自然美景之中。</p><p style=\"text-align:justify;\">旅程还将带您参观象征米南加保文化辉煌历史的 <strong>Pagaruyung王宫</strong>、以传统宋吉锦（Songket）闻名的 <strong>Pandai Sikek村</strong>，以及武吉丁宜最著名的地标 <strong>Jam Gadang大钟楼</strong>。随后前往 <strong>巴东老城区</strong>、历史悠久的 <strong>Siti Nurbaya大桥</strong>，以及风景优美的 <strong>巴东海滩</strong>，感受西苏门答腊独特的海滨风情。</p><h3 style=\"text-align:justify;\">为什么选择这个行程？</h3><p style=\"text-align:justify;\">因为一次旅行就能体验：</p><p style=\"text-align:justify;\"><strong>壮丽自然风景 + 地道米南加保文化 + 经典地标 + 传奇美食 + 难忘的当地体验</strong></p><h3 style=\"text-align:justify;\">如果你想要：</h3><ul><li data-list-item-id=\"e49dd3fc959e4a9d33ec15c68cb2a484c\"><p style=\"text-align:justify;\">欣赏西苏门答腊最著名的自然景观</p></li><li data-list-item-id=\"efac7d84a3f0e9224c4103cdcea06d5ae\"><p style=\"text-align:justify;\">深入了解独特的米南加保文化与传统</p></li><li data-list-item-id=\"eeaaead4b324e4ae18fd6abf8b7d16058\"><p style=\"text-align:justify;\">打卡武吉丁宜和巴东最具代表性的景点</p></li><li data-list-item-id=\"e8dd3b2acac4fc0f33c651d468dff6ef3\"><p style=\"text-align:justify;\">享受轻松、丰富且难忘的度假体验</p></li></ul><h3 style=\"text-align:justify;\"><strong>壮丽风景，真实文化，无尽的西苏门答腊回忆。</strong> ✨🏞️</h3><p style=\"text-align:justify;\"><strong>准备好探索武吉丁宜与巴东，感受西苏门答腊最迷人的魅力了吗？</strong> 🌿✨</p>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e9664bd88b57b87d5318a4a35be5fc458\">Meals as per program</li><li data-list-item-id=\"e5d4d3f55a6cd9b7f80b7df2ad225a7b5\">Entrance tickets to tourist attractions</li><li data-list-item-id=\"e6941d13e88f741d24628a4a755bcebbe\">Hotel of your choice (1 night in Bukittinggi + 1 night in Padang) TWN/Triple Share</li><li data-list-item-id=\"e5280c2b65d9b84259ed563cb01e572cf\">Tour guide (GIT)/Driver guide (FIT)</li><li data-list-item-id=\"ec63ba254208074ce6ff95f3d312c9a3d\">Mineral water</li><li data-list-item-id=\"ec2b38abf98e2a65d51b8cd799682311e\">Parking</li><li data-list-item-id=\"ea748bfb4ed9267655dae53a0ec524bd9\">Free batik scarf necklace upon arrival</li></ul>', '<ul><li data-list-item-id=\"ed4f03df2efdaf5d52f232d6bfd7db9af\">Personal expenses such as telephone bills, laundry, minibar, etc.</li><li data-list-item-id=\"e3e44822eb1876e7fd36e2ca2324fd53a\">Tips for tour guides and drivers</li><li data-list-item-id=\"eb8098b6d370cbce8d58c7aeb18f0a3e9\">Juice/drinks at local restaurants</li><li data-list-item-id=\"e3500900b51fe0fad0a94a568f286abe5\">Airfare/airport tax/porter at the airport</li><li data-list-item-id=\"eb522a80ff6704b178f251a824d2c1612\">Additional fees for Eid al-Fitr, Christmas, and New Year</li><li data-list-item-id=\"e73b7f0c32e2e925d48554b5ffb735d75\">Additional weekend/holiday fees for hotels in Bukittinggi</li></ul>', NULL, '[\"Scenic Road Trip\",\"Nature\",\"Culture\",\"Urban Heritage\",\"Culinary\",\"Beach\"]', NULL, 0, NULL, '2026-05-29 13:28:09', '2026-05-29 13:28:09'),
(91, 48, 'SOUTH MALANG HIDDEN BEACH', 'SURABAYA', 'south-malang-hidden-beach', '<h2 style=\"text-align:justify;\">South Malang Hidden Beach Private Tour</h2><p style=\"text-align:justify;\">Tinggalkan keramaian kota dan temukan salah satu surga tersembunyi terbaik di Jawa Timur. Pesisir selatan Malang menawarkan deretan pantai eksotis dengan perpaduan perbukitan hijau, air laut berwarna biru kehijauan, tebing-tebing megah, serta panorama Samudera Hindia yang memukau di setiap sudutnya.</p><p style=\"text-align:justify;\">Nikmati keindahan alam yang masih alami, mulai dari panorama pulau-pulau kecil yang menawan hingga hamparan pantai yang tenang dan jauh dari keramaian. Setiap destinasi menghadirkan pesona yang berbeda, menjadikan perjalanan ini pengalaman yang sempurna bagi pecinta alam, fotografi, maupun wisatawan yang ingin menikmati sisi lain Jawa Timur yang belum banyak terjamah.</p><p style=\"text-align:justify;\">Perjalanan semakin berkesan dengan kunjungan ke salah satu ikon wisata pantai paling terkenal di Jawa Timur, di mana keindahan alam berpadu harmonis dengan nilai budaya dan spiritual yang telah menjadi daya tarik wisata selama bertahun-tahun.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi pantai-pantai tersembunyi paling indah di Malang Selatan<br>✅ Menikmati panorama laut dan lanskap pesisir yang spektakuler<br>✅ Mengunjungi spot foto ikonik dengan pemandangan yang memukau<br>✅ Cocok untuk keluarga, pasangan, pecinta alam, dan fotografer<br>✅ Perjalanan privat yang nyaman langsung dari Surabaya<br>✅ Kesempatan menikmati keindahan alam Jawa Timur yang masih alami dan belum terlalu ramai</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari destinasi dengan pemandangan pantai yang luar biasa, suasana yang tenang, dan pengalaman wisata yang berbeda, Malang Selatan adalah pilihan yang tidak boleh dilewatkan.</strong></h3>', '<h2 style=\"text-align:justify;\">South Malang Hidden Beach Private Tour</h2><p style=\"text-align:justify;\">Escape the crowds and uncover one of East Java\'s best-kept secrets. South Malang is a paradise of hidden beaches where emerald hills meet turquoise waters, dramatic cliffs rise above the Indian Ocean, and every viewpoint feels like a postcard come to life.</p><p style=\"text-align:justify;\">From the breathtaking island panorama of Teluk Asmara to the untouched coastal beauty of Tanjung Penyu, every destination offers a unique perspective of Malang\'s spectacular southern shoreline. Feel the ocean breeze, admire endless sea views, and capture stunning photographs at some of the most scenic beaches in Indonesia. The journey becomes even more memorable with a visit to the iconic seaside temple of Balekambang, a landmark that perfectly blends natural beauty with local culture.</p><p style=\"text-align:justify;\">Whether you\'re a nature lover, photographer, couple, family, or adventure seeker, this experience offers the perfect escape from the city and a chance to discover a side of East Java that remains wonderfully unspoiled.</p><h3 style=\"text-align:justify;\">Why Choose This Tour?</h3><p style=\"text-align:justify;\">✅ Explore some of East Java\'s most beautiful hidden beaches in one day<br>✅ Witness spectacular coastal landscapes and panoramic ocean views<br>✅ Visit the famous \"Raja Ampat of East Java\" viewpoint<br>✅ Discover iconic photo spots and untouched natural scenery<br>✅ Enjoy a private and comfortable journey from Surabaya<br>✅ Perfect for families, couples, and travelers seeking unique destinations</p><h3 style=\"text-align:justify;\"><strong>If you\'re searching for breathtaking beaches, stunning photography opportunities, and an unforgettable coastal adventure, South Malang is a destination you simply cannot miss.</strong></h3>', '<h2 style=\"text-align:justify;\">남부 말랑 히든 비치 프라이빗 투어</h2><p style=\"text-align:justify;\">도시의 번잡함을 벗어나 동부 자바의 숨겨진 보석 같은 해안 지역을 만나보세요. 남부 말랑은 에메랄드빛 언덕과 청록색 바다, 웅장한 절벽, 그리고 끝없이 펼쳐지는 인도양의 절경이 어우러진 특별한 여행지입니다.</p><p style=\"text-align:justify;\">아름다운 작은 섬들이 펼쳐진 환상적인 해안 풍경부터 한적하고 자연 그대로의 해변까지, 이곳의 모든 풍경은 방문객들에게 잊지 못할 감동을 선사합니다. 자연을 사랑하는 여행객, 사진 애호가, 그리고 특별한 여행지를 찾는 모든 분들에게 완벽한 경험이 될 것입니다.</p><p style=\"text-align:justify;\">또한 동부 자바를 대표하는 상징적인 해안 명소를 방문하며, 아름다운 자연경관과 지역 문화가 조화를 이루는 특별한 매력을 직접 느껴볼 수 있습니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 남부 말랑의 아름다운 숨은 해변 탐방<br>✅ 장관을 이루는 해안 절경과 탁 트인 바다 전망 감상<br>✅ 인생 사진을 남길 수 있는 최고의 포토 스팟 방문<br>✅ 가족, 커플, 자연 애호가, 사진가에게 추천<br>✅ 수라바야에서 출발하는 편안한 프라이빗 투어<br>✅ 아직 많은 사람들에게 알려지지 않은 천혜의 자연을 경험</p><h3 style=\"text-align:justify;\"><strong>눈부신 해안 풍경과 평온한 분위기, 그리고 특별한 자연 여행을 찾고 있다면 남부 말랑은 반드시 방문해야 할 여행지입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">南玛琅秘境海滩私人之旅</h2><p style=\"text-align:justify;\">远离城市的喧嚣，探索东爪哇最迷人的海岸秘境。南玛琅拥有碧蓝清澈的海水、壮丽的悬崖、翠绿的山丘以及一望无际的印度洋景观，是自然爱好者和摄影爱好者不可错过的天堂。</p><p style=\"text-align:justify;\">这里不仅拥有令人惊叹的海岸风光和原始自然景观，还保留着宁静纯粹的海滩氛围。无论是欣赏海天一色的壮观景色，还是感受海风拂面的惬意时光，每一处风景都令人流连忘返。</p><p style=\"text-align:justify;\">旅程中还将感受东爪哇最具代表性的海岸地标之一，在壮观海景与当地文化魅力交织的环境中，体验与众不同的海滨之旅。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索南玛琅最美丽的秘境海滩<br>✅ 欣赏壮观的海岸线与无敌海景<br>✅ 打卡东爪哇著名摄影胜地<br>✅ 适合家庭、情侣、摄影爱好者及自然探索者<br>✅ 从泗水出发的舒适私人旅程<br>✅ 感受原生态、尚未被过度开发的自然美景</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找令人惊叹的海岸风光、宁静的度假氛围以及难忘的自然体验，那么南玛琅绝对值得列入您的旅行清单。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Nature\",\"Beach\",\"Day Tour\",\"Family\"]', NULL, 0, NULL, '2026-06-01 14:41:23', '2026-06-02 11:32:20'),
(92, 48, 'BROMO MIDNIGHT PRIVATE TOUR', 'SURABAYA', 'bromo-midnight-private-tour', '<h2 style=\"text-align:justify;\">Bromo Midnight Private Tour</h2><p style=\"text-align:justify;\">Rasakan keajaiban <strong>Gunung Bromo</strong>, salah satu ikon wisata alam paling terkenal di Indonesia yang wajib masuk dalam daftar perjalanan Anda. Berdiri megah di tengah bentang alam vulkanik yang luar biasa, Bromo menawarkan perpaduan sempurna antara panorama pegunungan yang dramatis, hamparan lautan pasir yang luas, savana hijau yang menawan, serta salah satu pemandangan matahari terbit terbaik di Asia.</p><p style=\"text-align:justify;\">Saat fajar mulai menyingsing, langit perlahan berubah menjadi gradasi warna keemasan yang memukau, memperlihatkan siluet gunung-gunung yang berdiri megah di cakrawala. Pemandangan yang spektakuler ini menjadikan Bromo sebagai destinasi impian bagi para pencinta alam, fotografer, dan wisatawan dari seluruh dunia.</p><p style=\"text-align:justify;\">Lebih dari sekadar destinasi sunrise, Bromo menawarkan pengalaman yang unik dengan lanskap vulkanik yang eksotis, suasana yang magis, dan keindahan alam yang sulit ditemukan di tempat lain. Setiap sudutnya menghadirkan panorama yang menakjubkan dan pengalaman yang akan selalu dikenang.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menyaksikan salah satu sunrise terbaik di Asia<br>✅ Mengunjungi gunung berapi paling ikonik di Indonesia<br>✅ Menikmati panorama spektakuler Gunung Bromo, Gunung Batok, dan Gunung Semeru<br>✅ Menjelajahi lautan pasir, savana hijau, dan lanskap vulkanik yang unik<br>✅ Cocok untuk keluarga, pasangan, fotografer, dan pecinta alam<br>✅ Perjalanan privat yang nyaman dengan pelayanan profesional dari Surabaya</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari pengalaman alam yang luar biasa dan pemandangan yang tak terlupakan, Gunung Bromo adalah destinasi yang wajib Anda kunjungi setidaknya sekali seumur hidup.</strong></h3>', '<h2 style=\"text-align:justify;\">Bromo Midnight Private Tour</h2><p style=\"text-align:justify;\">Experience the magic of <strong>Mount Bromo</strong>, one of Indonesia’s most iconic natural wonders and a destination that belongs on every travel bucket list. Rising from a vast volcanic landscape, Bromo offers an extraordinary combination of dramatic mountain scenery, endless sea-like sand plains, rolling green savannahs, and one of the most breathtaking sunrises in Southeast Asia.</p><p style=\"text-align:justify;\">As dawn breaks over the horizon, watch the sky transform into shades of gold and orange while revealing a spectacular panorama of volcanoes stretching across the horizon. The surreal landscape, often compared to another planet, creates an unforgettable experience that attracts travelers, photographers, and nature lovers from around the world.</p><p style=\"text-align:justify;\">Beyond its famous sunrise, Bromo captivates visitors with its raw natural beauty, mystical atmosphere, and unique volcanic terrain found nowhere else in Indonesia. Every viewpoint offers a new perspective, making each moment a perfect opportunity to capture memories that will last a lifetime.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Witness one of the most spectacular sunrises in Asia<br>✅ Explore Indonesia’s most famous volcanic landscape<br>✅ Enjoy breathtaking views of Mount Bromo, Mount Batok, and Mount Semeru<br>✅ Discover vast sand seas, lush savannahs, and dramatic mountain scenery<br>✅ Perfect for photographers, families, couples, and nature enthusiasts<br>✅ Comfortable private tour with personalized service from Surabaya</p><h3 style=\"text-align:justify;\"><strong>Whether it\'s your first visit to East Java or a long-awaited bucket-list adventure, Mount Bromo promises an unforgettable journey into one of Indonesia’s most extraordinary landscapes.</strong></h3>', '<h2 style=\"text-align:justify;\">브로모 미드나잇 프라이빗 투어</h2><p style=\"text-align:justify;\">인도네시아를 대표하는 자연 명소 중 하나인 <strong>브로모 화산(Mount Bromo)</strong> 의 경이로운 매력을 직접 경험해 보세요. 광활한 화산 지형 위에 자리한 브로모는 장엄한 산악 풍경, 끝없이 펼쳐진 모래 평원, 푸른 초원, 그리고 아시아 최고의 일출 중 하나로 유명한 특별한 여행지입니다.</p><p style=\"text-align:justify;\">새벽이 밝아오면 하늘은 황금빛과 주황빛으로 물들고, 그 뒤로 브로모와 주변 화산들이 만들어내는 환상적인 풍경이 펼쳐집니다. 마치 다른 행성에 온 듯한 독특한 분위기는 전 세계 여행자와 사진작가들의 마음을 사로잡고 있습니다.</p><p style=\"text-align:justify;\">브로모의 매력은 단순히 일출에만 그치지 않습니다. 신비로운 화산 지형과 압도적인 자연경관은 어디에서도 쉽게 경험할 수 없는 특별한 감동을 선사합니다. 눈앞에 펼쳐지는 모든 풍경이 평생 기억에 남을 소중한 순간이 될 것입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 아시아 최고의 일출 중 하나 감상<br>✅ 인도네시아를 대표하는 화산 명소 방문<br>✅ 브로모, 바톡, 세메루 화산의 장엄한 파노라마 감상<br>✅ 광활한 모래 평원과 아름다운 사바나 탐방<br>✅ 가족, 커플, 자연 애호가, 사진작가에게 추천<br>✅ 수라바야 출발의 편안한 프라이빗 투어</p><h3 style=\"text-align:justify;\"><strong>평생 한 번쯤 꼭 경험해야 할 특별한 자연 여행을 찾고 있다면, 브로모 화산은 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">婆罗摩火山午夜私人之旅</h2><p style=\"text-align:justify;\">探索印度尼西亚最具代表性的自然奇观之一——<strong>婆罗摩火山（Mount Bromo）</strong>。这里以壮丽的火山景观、广阔的沙海、翠绿的草原以及亚洲最令人惊叹的日出景色而闻名，是无数旅行者心中的梦想目的地。</p><p style=\"text-align:justify;\">当黎明到来时，天空逐渐被金色与橙色的光芒染亮，壮观的火山群轮廓缓缓展现在眼前。独特而震撼的火山地貌仿佛来自另一个星球，为游客带来难以忘怀的视觉盛宴。</p><p style=\"text-align:justify;\">除了闻名世界的日出之外，婆罗摩火山还拥有神秘而迷人的自然景观。从辽阔的火山沙海到壮观的山脉全景，每一个角度都令人惊叹不已，是摄影爱好者和自然探索者的天堂。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 欣赏亚洲最壮观的日出之一<br>✅ 探索印度尼西亚最著名的火山景观<br>✅ 观赏婆罗摩火山、巴托克火山和塞梅鲁火山的壮丽全景<br>✅ 感受辽阔沙海与翠绿草原交织的独特风光<br>✅ 适合家庭、情侣、摄影爱好者及自然爱好者<br>✅ 从泗水出发的舒适私人旅程</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一次震撼人心且终生难忘的自然探险之旅，那么婆罗摩火山绝对是您不可错过的目的地。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"ebebc3f97e50e11fd5a1dffeb5ef102f6\">Bromo jeep (max 6 pax/jeep included driver)</li><li data-list-item-id=\"ee2d36152ef68bdb6f5ab1f5c52541140\">Bromo Entrance Ticket</li><li data-list-item-id=\"e7c524f4daafe06344e8b105099d02b82\">Free 1x Breakfast</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano Tour\",\"Nature\",\"Landscape Tour\",\"Photography\",\"Jeep Experience\",\"Adventure\",\"Sunrise\"]', NULL, 0, NULL, '2026-06-01 14:59:06', '2026-06-02 11:32:46'),
(93, 48, 'TUMPAK SEWU WATERFALL ADVENTURE', 'SURABAYA', 'tumpak-sewu-waterfall-adventure', '<h2 style=\"text-align:justify;\">Tumpak Sewu Waterfall Adventure Private Tour</h2><p style=\"text-align:justify;\">Jelajahi salah satu keajaiban alam paling menakjubkan di Indonesia dan rasakan pengalaman petualangan yang tak terlupakan. Tersembunyi di tengah keindahan alam Jawa Timur, <strong>Air Terjun Tumpak Sewu</strong> dikenal sebagai <strong>\"Niagara-nya Indonesia\"</strong> berkat formasi air terjunnya yang unik, dengan ratusan aliran air yang jatuh membentuk tirai raksasa di antara tebing-tebing hijau yang megah.</p><p style=\"text-align:justify;\">Perjalanan ini sangat cocok bagi para pencinta alam dan petualangan yang ingin merasakan lebih dari sekadar wisata biasa. Dikelilingi oleh hutan tropis yang masih alami, lembah yang dramatis, gua-gua alami, serta kolam air jernih yang tersembunyi, setiap langkah akan menghadirkan pemandangan yang luar biasa dan pengalaman yang sulit dilupakan.</p><p style=\"text-align:justify;\">Keindahan alam yang spektakuler dipadukan dengan suasana yang masih asri menjadikan Tumpak Sewu sebagai salah satu destinasi yang wajib dikunjungi saat berada di Jawa Timur. Baik untuk berburu foto menakjubkan maupun menikmati petualangan alam yang sesungguhnya, tempat ini menawarkan pengalaman yang akan selalu dikenang.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengunjungi salah satu air terjun terindah di Indonesia<br>✅ Menikmati petualangan alam yang seru dan berkesan<br>✅ Menjelajahi lembah hijau, hutan tropis, gua alami, dan kolam alami yang memukau<br>✅ Mengabadikan momen di spot foto spektakuler kelas dunia<br>✅ Cocok untuk pecinta alam, fotografer, dan pencari petualangan<br>✅ Perjalanan privat yang nyaman dari Surabaya</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari destinasi yang memadukan keindahan alam, petualangan, dan pemandangan luar biasa, Tumpak Sewu adalah pengalaman yang tidak boleh Anda lewatkan.</strong></h3>', '<h2 style=\"text-align:justify;\">Tumpak Sewu Waterfall Adventure Private Tour</h2><p style=\"text-align:justify;\">Step into one of Indonesia’s most breathtaking natural wonders and experience an adventure unlike any other. Hidden within the lush landscapes of East Java, Tumpak Sewu is a spectacular waterfall often referred to as the <strong>\"Niagara of Indonesia\"</strong> thanks to its massive curtain of cascading water surrounded by towering cliffs and tropical rainforest.</p><p style=\"text-align:justify;\">This journey is perfect for travelers who crave more than just sightseeing. From dramatic viewpoints overlooking the waterfall valley to immersive trekking routes through rivers, cliffs, and untouched nature, every step reveals scenery that feels straight out of a fantasy world. The combination of powerful waterfalls, emerald-green landscapes, hidden caves, and crystal-clear natural pools creates an unforgettable adventure for nature lovers and explorers alike.</p><p style=\"text-align:justify;\">Whether you\'re chasing extraordinary photographs, seeking a thrilling outdoor experience, or simply looking to witness one of Indonesia’s most remarkable landscapes, Tumpak Sewu promises memories that will last a lifetime.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Visit one of the most beautiful waterfalls in Indonesia<br>✅ Experience an unforgettable adventure through stunning natural landscapes<br>✅ Discover dramatic cliffs, tropical forests, hidden caves, and natural pools<br>✅ Capture incredible photographs at world-class scenic viewpoints<br>✅ Perfect for adventure seekers, photographers, and nature enthusiasts<br>✅ Enjoy a private and comfortable journey from Surabaya</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a destination that combines adventure, natural beauty, and unforgettable scenery, Tumpak Sewu is an experience you simply cannot miss.</strong></h3>', '<h2 style=\"text-align:justify;\">뚬빡 세우 폭포 어드벤처 프라이빗 투어</h2><p style=\"text-align:justify;\">인도네시아에서 가장 아름다운 자연 명소 중 하나인 <strong>뚬빡 세우 폭포(Tumpak Sewu Waterfall)</strong> 에서 잊지 못할 모험을 경험해 보세요. \"인도네시아의 나이아가라\"라고 불리는 이 폭포는 수백 갈래의 물줄기가 거대한 절벽을 따라 떨어지는 장관으로 유명하며, 동부 자바를 대표하는 자연 명소로 손꼽힙니다.</p><p style=\"text-align:justify;\">울창한 열대우림과 깊은 계곡, 신비로운 동굴, 그리고 맑은 천연 연못으로 둘러싸인 이곳은 단순한 관광지가 아닌 진정한 자연 탐험의 무대입니다. 눈앞에 펼쳐지는 압도적인 풍경은 자연을 사랑하는 여행객과 사진작가들에게 잊을 수 없는 감동을 선사합니다.</p><p style=\"text-align:justify;\">웅장한 폭포와 원시 자연이 어우러진 이 특별한 여행은 동부 자바의 숨겨진 매력을 발견하고 싶은 분들에게 최고의 선택이 될 것입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 인도네시아 최고의 폭포 중 하나 방문<br>✅ 자연 속에서 즐기는 특별한 어드벤처 경험<br>✅ 열대우림, 계곡, 동굴, 천연 연못 등 다양한 자연경관 감상<br>✅ 환상적인 사진 촬영 명소 방문<br>✅ 자연 애호가, 사진작가, 모험을 즐기는 여행객에게 추천<br>✅ 수라바야 출발의 편안한 프라이빗 투어</p><h3 style=\"text-align:justify;\"><strong>자연의 경이로움과 짜릿한 모험을 동시에 경험하고 싶다면, 뚬빡 세우 폭포는 반드시 방문해야 할 여행지입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">图姆帕克塞乌瀑布探险私人之旅</h2><p style=\"text-align:justify;\">探索印度尼西亚最壮观的自然奇观之一，开启一场难忘的探险之旅。位于东爪哇深处的 <strong>图姆帕克塞乌瀑布（Tumpak Sewu Waterfall）</strong> 因其壮丽的瀑布群景观而被誉为 <strong>“印度尼西亚的尼亚加拉瀑布”</strong>。数百道水流从高耸的悬崖倾泻而下，形成令人震撼的天然水幕，景色美不胜收。</p><p style=\"text-align:justify;\">这里不仅拥有世界级的瀑布景观，还被原始热带雨林、翠绿山谷、天然洞穴以及清澈见底的天然水池所环绕。无论是徒步探索大自然，还是拍摄令人惊艳的风景照片，这里都能带来无与伦比的体验。</p><p style=\"text-align:justify;\">对于热爱自然、摄影以及户外探险的旅行者来说，图姆帕克塞乌瀑布无疑是东爪哇最值得打卡的目的地之一。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探访印度尼西亚最美丽的瀑布之一<br>✅ 体验充满乐趣与挑战的自然探险之旅<br>✅ 欣赏热带雨林、峡谷、天然洞穴和清澈水潭等壮丽景观<br>✅ 打卡世界级摄影胜地，留下难忘回忆<br>✅ 适合自然爱好者、摄影爱好者和探险者<br>✅ 从泗水出发的舒适私人旅程</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找集壮丽自然景观、刺激探险体验与绝佳摄影机会于一体的旅程，那么图姆帕克塞乌瀑布绝对不容错过。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e1e05f8aa97289dd3716feec2efb60589\">Local Guide Tumpak sewu</li><li data-list-item-id=\"e000cd1fcd6eabb3ee2b4a42b4668123d\">Tumpak Sewu Waterfall Entrance Ticket</li><li data-list-item-id=\"e7c524f4daafe06344e8b105099d02b82\">Free 1x Breakfast</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Nature\",\"Waterfall\",\"Photography\",\"Adventure\",\"Landscape\",\"Hiking & Trekking\",\"Hidden Gems\"]', NULL, 0, NULL, '2026-06-01 15:16:04', '2026-06-02 11:32:58'),
(94, 48, 'BROMO MIDNIGHT+TUMPAK SEWU PRIVATE TOUR', 'SURABAYA', 'bromo-midnighttumpak-sewu-private-tour', '<h2 style=\"text-align:justify;\">Bromo Midnight Plus Tumpak Sewu Private Tour</h2><p style=\"text-align:justify;\">Nikmati petualangan terbaik di Jawa Timur dengan mengunjungi dua keajaiban alam paling spektakuler dalam satu perjalanan yang tak terlupakan. Dari lanskap vulkanik Gunung Bromo yang ikonik hingga kemegahan Air Terjun Tumpak Sewu yang memukau, tour ini menghadirkan kombinasi sempurna antara petualangan, keindahan alam, dan pengalaman eksplorasi yang luar biasa.</p><p style=\"text-align:justify;\">Saksikan panorama pegunungan yang menakjubkan saat sinar matahari pertama menyinari hamparan gunung berapi, perbukitan hijau, dan cakrawala yang seolah tanpa batas. Petualangan kemudian berlanjut menuju Air Terjun Tumpak Sewu, salah satu air terjun paling menakjubkan di Indonesia yang dijuluki <strong>\"Niagara-nya Indonesia\"</strong>, berkat formasi air terjunnya yang megah dan pemandangan alam yang luar biasa.</p><p style=\"text-align:justify;\">Dirancang bagi wisatawan yang ingin menikmati destinasi terbaik Jawa Timur dalam waktu yang terbatas, tour ini menawarkan pemandangan spektakuler, pengalaman yang berkesan, dan kesempatan mengabadikan momen di beberapa lokasi paling indah di Indonesia. Mulai dari lautan pasir vulkanik, savana hijau yang luas, hingga lembah tropis yang menyimpan air terjun megah, setiap sudut perjalanan menghadirkan keajaiban alam yang berbeda.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengunjungi dua destinasi alam paling ikonik di Jawa Timur dalam satu perjalanan<br>✅ Menyaksikan sunrise spektakuler di Gunung Bromo<br>✅ Menjelajahi keindahan luar biasa Air Terjun Tumpak Sewu<br>✅ Menikmati perpaduan lanskap gunung berapi, savana, dan air terjun raksasa<br>✅ Spot fotografi terbaik dengan pemandangan yang luar biasa<br>✅ Cocok untuk pecinta alam, fotografer, pasangan, dan pencari petualangan<br>✅ Pilihan terbaik untuk menikmati destinasi unggulan Jawa Timur dalam waktu singkat</p><h3 style=\"text-align:justify;\"><strong>Jika Anda hanya memiliki waktu terbatas di Jawa Timur dan ingin menikmati dua keajaiban alam terbaiknya dalam satu perjalanan, tour ini adalah pilihan yang tidak boleh dilewatkan.</strong></h3>', '<h2 style=\"text-align:justify;\">Bromo Midnight Plus Tumpak Sewu Private Tour</h2><p style=\"text-align:justify;\">Experience the ultimate East Java adventure by combining two of Indonesia’s most spectacular natural wonders in one unforgettable journey. From the otherworldly volcanic landscapes of Mount Bromo to the breathtaking beauty of Tumpak Sewu Waterfall, this tour offers a perfect blend of adventure, scenery, and exploration.</p><p style=\"text-align:justify;\">Witness the dramatic beauty of East Java as golden sunlight illuminates a vast panorama of volcanoes, rolling hills, and endless horizons. Continue your adventure to one of Indonesia’s most awe-inspiring waterfalls, where towering cliffs and countless cascading streams create a scene so extraordinary that it has earned the nickname <strong>\"The Niagara of Indonesia.\"</strong></p><p style=\"text-align:justify;\">Designed for travelers who want to experience the very best of East Java in a single trip, this tour delivers unforgettable landscapes, incredible photography opportunities, and moments that few destinations in the world can match. From volcanic deserts and emerald-green savannahs to majestic waterfalls hidden within lush tropical valleys, every part of this journey showcases the raw beauty of Indonesia’s natural heritage.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Visit East Java’s two most iconic natural attractions in one trip<br>✅ Witness a world-famous volcanic sunrise at Mount Bromo<br>✅ Discover the spectacular beauty of Tumpak Sewu Waterfall<br>✅ Enjoy breathtaking landscapes ranging from volcanoes to tropical valleys<br>✅ Capture incredible photographs at some of Indonesia’s most scenic locations<br>✅ Perfect for adventure seekers, photographers, couples, and nature lovers<br>✅ Maximize your time with a complete East Java bucket-list experience</p><h3 style=\"text-align:justify;\"><strong>If you only have one day in East Java and want to experience its most extraordinary natural wonders, this is the ultimate adventure you simply cannot miss.</strong></h3>', '<h2 style=\"text-align:justify;\">브로모 미드나잇 + 뚬빡 세우 프라이빗 투어</h2><p style=\"text-align:justify;\">동부 자바를 대표하는 두 개의 자연 명소를 한 번에 경험할 수 있는 최고의 모험 여행에 함께하세요. 장엄한 화산 풍경을 자랑하는 <strong>브로모 화산</strong>과 인도네시아에서 가장 아름다운 폭포 중 하나인 <strong>뚬빡 세우 폭포</strong>를 동시에 만날 수 있는 특별한 여정입니다.</p><p style=\"text-align:justify;\">광활한 화산 지형 위로 떠오르는 황금빛 일출은 잊지 못할 감동을 선사하며, 이어지는 여정에서는 거대한 절벽 사이로 수백 갈래의 물줄기가 쏟아지는 장관을 감상할 수 있습니다. \"인도네시아의 나이아가라\"라 불리는 뚬빡 세우 폭포는 자연이 만들어낸 경이로운 풍경으로 많은 여행객들의 버킷리스트에 올라 있습니다.</p><p style=\"text-align:justify;\">화산, 초원, 계곡, 폭포가 어우러진 이 여행은 동부 자바의 가장 아름다운 자연을 하루 만에 경험하고 싶은 여행객에게 완벽한 선택입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바의 대표 자연 명소 두 곳을 한 번에 방문<br>✅ 브로모 화산에서 환상적인 일출 감상<br>✅ 뚬빡 세우 폭포의 압도적인 자연경관 체험<br>✅ 화산 지형과 폭포가 어우러진 특별한 여행<br>✅ 최고의 사진 촬영 명소 방문<br>✅ 자연 애호가, 사진작가, 커플, 모험가에게 추천<br>✅ 짧은 일정으로 동부 자바의 핵심 명소를 모두 경험</p><h3 style=\"text-align:justify;\"><strong>동부 자바에서 단 하루 동안 최고의 자연 명소를 경험하고 싶다면, 이 투어는 가장 완벽한 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">婆罗摩火山午夜 + 图姆帕克塞乌瀑布私人之旅</h2><p style=\"text-align:justify;\">在一次难忘的旅程中，同时探索东爪哇两大最壮观的自然奇观。从举世闻名的 <strong>婆罗摩火山（Mount Bromo）</strong> 到被誉为 <strong>“印度尼西亚尼亚加拉瀑布”</strong> 的 <strong>图姆帕克塞乌瀑布（Tumpak Sewu Waterfall）</strong>，这条线路完美结合了探险、自然美景与深度体验。</p><p style=\"text-align:justify;\">当晨曦洒落在广阔的火山群和连绵山脉之上时，您将欣赏到令人震撼的壮丽景观。随后，前往隐藏在热带山谷中的图姆帕克塞乌瀑布，感受数百道瀑布从高耸悬崖飞流而下的壮观场景，体验大自然最原始、最震撼的魅力。</p><p style=\"text-align:justify;\">这是一场专为希望在有限时间内深入体验东爪哇精华景点的旅行者打造的旅程。从神秘的火山地貌、广阔的绿色草原，到壮丽的瀑布与热带峡谷，每一处景观都令人叹为观止。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程畅游东爪哇两大标志性自然景点<br>✅ 欣赏世界级的婆罗摩火山日出美景<br>✅ 探索被誉为“印度尼西亚尼亚加拉瀑布”的图姆帕克塞乌瀑布<br>✅ 感受火山、草原、峡谷与瀑布交织的壮丽景观<br>✅ 打卡东爪哇最值得拍照的绝美地点<br>✅ 适合自然爱好者、摄影爱好者、情侣及探险者<br>✅ 在有限时间内体验东爪哇最精华的自然景观</p><h3 style=\"text-align:justify;\"><strong>如果您只有短暂时间游览东爪哇，却希望一次体验最震撼的自然奇观，那么这将是您不容错过的终极探险之旅。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"ebebc3f97e50e11fd5a1dffeb5ef102f6\">Bromo jeep (max 6 pax/jeep included driver)</li><li data-list-item-id=\"ee2d36152ef68bdb6f5ab1f5c52541140\">Bromo Entrance Ticket</li><li data-list-item-id=\"e7c524f4daafe06344e8b105099d02b82\">Free 1x Breakfast</li><li data-list-item-id=\"e85b6a4e5589c498c441955fc809ad777\">Local Guide Tumpak sewu</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Waterfall\",\"Photography\",\"Adventure\",\"Nature\",\"landscape\"]', NULL, 0, NULL, '2026-06-02 11:17:36', '2026-06-02 11:33:11');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(95, 48, 'RANU PANI LAKE & BROMO HILLSIDE', 'SURABAYA', 'ranu-pani-lake-bromo-hillside', '<h2 style=\"text-align:justify;\">Ranu Pani Lake &amp; Bromo Hillside Private Tour</h2><p style=\"text-align:justify;\">Temukan sisi lain kawasan Bromo yang belum banyak diketahui wisatawan. Jauh dari keramaian jalur wisata utama, perjalanan ini mengajak Anda menikmati keindahan dataran tinggi Jawa Timur yang dipenuhi danau pegunungan yang tenang, perbukitan hijau yang menawan, hutan pinus yang sejuk, serta panorama alam yang memukau di kawasan Taman Nasional Bromo Tengger Semeru.</p><p style=\"text-align:justify;\">Nikmati udara pegunungan yang segar sambil menyaksikan pemandangan alam yang masih asri dan alami. Danau-danau yang jernih, hamparan perkebunan di dataran tinggi, serta lanskap pedesaan yang damai menciptakan suasana yang sempurna untuk bersantai, melepas penat, dan menikmati keindahan alam jauh dari hiruk pikuk kota.</p><p style=\"text-align:justify;\">Tour ini sangat cocok bagi wisatawan yang ingin merasakan pengalaman berbeda dari Bromo yang biasanya dikenal dengan sunrise dan kawahnya. Dengan kombinasi keindahan alam, suasana pedesaan yang autentik, dan panorama pegunungan yang menenangkan, perjalanan ini menawarkan pengalaman yang lebih santai namun tetap berkesan.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi sisi tersembunyi kawasan Bromo yang jarang dikunjungi wisatawan<br>✅ Menikmati keindahan danau pegunungan, perbukitan hijau, dan panorama alam yang menakjubkan<br>✅ Merasakan suasana pedesaan yang tenang dan udara pegunungan yang menyegarkan<br>✅ Cocok untuk keluarga, pasangan, pecinta alam, dan fotografer<br>✅ Spot foto alam yang indah dan jauh dari keramaian<br>✅ Pengalaman wisata santai yang memadukan alam dan budaya lokal</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari pelarian yang tenang dengan pemandangan alam yang indah dan suasana pegunungan yang menyegarkan, tour ini adalah pilihan sempurna untuk menikmati sisi lain Bromo yang lebih alami dan autentik.</strong></h3>', '<h2 style=\"text-align:justify;\">Ranu Pani Lake &amp; Bromo Hillside Private Tour</h2><p style=\"text-align:justify;\">Discover a different side of Bromo beyond the famous sunrise and volcanic landscapes. Nestled within the breathtaking highlands of East Java, this journey invites you to explore a world of tranquil mountain lakes, rolling green hills, pine forests, and charming rural scenery surrounded by the majestic beauty of Bromo Tengger Semeru National Park.</p><p style=\"text-align:justify;\">Escape the crowds and immerse yourself in the refreshing atmosphere of the highlands, where crystal-clear lakes reflect the surrounding mountains and fertile farmlands stretch across the valleys. The peaceful landscapes, cool mountain air, and spectacular viewpoints create the perfect setting for relaxation, photography, and reconnecting with nature.</p><p style=\"text-align:justify;\">This experience is ideal for travelers seeking a more leisurely and authentic side of East Java. From scenic countryside vistas to hidden natural gems rarely visited by mass tourism, every moment offers a glimpse into the region\'s untouched beauty and local way of life.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover the hidden beauty of the Bromo highlands beyond the typical tourist route<br>✅ Enjoy stunning mountain lakes, green valleys, and panoramic viewpoints<br>✅ Experience the peaceful atmosphere of East Java\'s countryside<br>✅ Perfect for nature lovers, families, couples, and photographers<br>✅ Capture breathtaking landscapes away from the crowds<br>✅ Relax and enjoy the cool mountain climate throughout the journey</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a peaceful escape filled with natural beauty, fresh mountain air, and unforgettable scenery, this tour offers one of East Java\'s most charming hidden experiences.</strong></h3>', '<h2 style=\"text-align:justify;\">라누 파니 호수 &amp; 브로모 힐사이드 프라이빗 투어</h2><p style=\"text-align:justify;\">대부분의 여행객들이 알지 못하는 브로모의 또 다른 매력을 만나보세요. 유명한 일출 명소와 화산 지형을 벗어나, 동부 자바의 아름다운 고원 지대에서 평화로운 산악 호수, 푸른 언덕, 울창한 소나무 숲, 그리고 장엄한 자연 풍경을 경험할 수 있는 특별한 여행입니다.</p><p style=\"text-align:justify;\">맑고 시원한 산 공기를 마시며 자연 그대로의 풍경을 감상해 보세요. 잔잔한 호수와 넓게 펼쳐진 농경지, 그리고 한적한 시골 마을의 풍경은 바쁜 일상에서 벗어나 여유로운 휴식을 선사합니다.</p><p style=\"text-align:justify;\">이 투어는 일반적인 브로모 여행과는 다른 특별한 경험을 원하는 분들에게 이상적입니다. 아름다운 자연과 현지의 소박한 삶, 그리고 평화로운 분위기가 어우러져 잊지 못할 추억을 만들어 줍니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 일반 관광객이 잘 모르는 브로모 고원의 숨겨진 매력 발견<br>✅ 아름다운 산악 호수와 푸른 계곡, 탁 트인 전망 감상<br>✅ 시원한 산 공기와 평화로운 자연 속에서 힐링<br>✅ 가족, 커플, 자연 애호가, 사진작가에게 추천<br>✅ 한적한 자연 속 최고의 사진 촬영 명소 방문<br>✅ 자연과 현지 문화를 함께 경험할 수 있는 여유로운 여행</p><h3 style=\"text-align:justify;\"><strong>평화로운 자연과 아름다운 풍경 속에서 진정한 휴식을 찾고 있다면, 이 투어는 브로모의 또 다른 매력을 발견할 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">拉努帕尼湖与布罗莫山坡私人之旅</h2><p style=\"text-align:justify;\">探索布罗莫地区鲜为人知的另一面。远离热门日出观景点和火山景观，这趟旅程将带您深入东爪哇高原地区，欣赏宁静的高山湖泊、翠绿的山丘、茂密的松树林以及令人心旷神怡的自然风光。</p><p style=\"text-align:justify;\">在清新的高山空气中，感受大自然最纯净的一面。清澈的湖水、广阔的农田以及宁静的乡村景观，共同构成了一幅如诗如画的田园风景，让您远离城市喧嚣，尽情享受放松与宁静。</p><p style=\"text-align:justify;\">对于希望体验不同于传统布罗莫之旅的游客来说，这条线路无疑是最佳选择。这里不仅拥有迷人的自然景观，还能让您感受到当地乡村生活的独特魅力，为您的东爪哇之旅增添更多难忘回忆。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索布罗莫高原鲜为人知的自然秘境<br>✅ 欣赏高山湖泊、绿色山谷与壮丽全景<br>✅ 感受清新凉爽的高原气候与宁静氛围<br>✅ 适合家庭、情侣、自然爱好者及摄影爱好者<br>✅ 打卡远离人潮的绝美自然摄影地点<br>✅ 体验自然风光与当地乡村文化的完美结合</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一场轻松惬意、充满自然魅力的高原之旅，那么这将是探索布罗莫另一面最理想的选择。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Nature\",\"Leisure\",\"Photography\",\"Landscape\",\"Family\"]', NULL, 0, NULL, '2026-06-02 11:30:47', '2026-06-02 11:33:21'),
(96, 48, 'TROWULAN HISTORICAL PRIVATE TOUR', 'SURABAYA', 'trowulan-historical-private-tour', '<h2 style=\"text-align:justify;\">Trowulan Historical Private Tour</h2><p style=\"text-align:justify;\">Lakukan perjalanan menembus waktu dan telusuri jejak kejayaan <strong>Kerajaan Majapahit</strong>, salah satu kerajaan terbesar dan paling berpengaruh dalam sejarah Asia Tenggara. Sebagai pusat pemerintahan dan kebudayaan Majapahit pada masa kejayaannya, Trowulan menyimpan warisan berharga yang mencerminkan kemajuan peradaban Nusantara berabad-abad yang lalu.</p><p style=\"text-align:justify;\">Di kawasan yang kaya akan situs arkeologi dan peninggalan bersejarah ini, Anda akan menemukan kisah tentang kejayaan, kebudayaan, dan pencapaian luar biasa yang pernah menjadikan Majapahit sebagai salah satu kekuatan terbesar di kawasan. Setiap sudut Trowulan menghadirkan cerita yang memperlihatkan kemegahan masa lalu dan warisan budaya yang masih dapat dirasakan hingga saat ini.</p><p style=\"text-align:justify;\">Lebih dari sekadar wisata sejarah, perjalanan ini menawarkan kesempatan untuk memahami akar budaya Indonesia, mengagumi arsitektur kuno yang menakjubkan, serta mengenal lebih dekat nilai-nilai budaya Jawa yang terus hidup dari generasi ke generasi.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menelusuri sejarah Kerajaan Majapahit yang legendaris<br>✅ Mengunjungi salah satu kawasan arkeologi terpenting di Indonesia<br>✅ Mengenal budaya, arsitektur, dan peradaban Jawa kuno<br>✅ Cocok untuk pecinta sejarah, keluarga, pelajar, dan wisatawan budaya<br>✅ Mengunjungi berbagai peninggalan bersejarah yang sarat makna<br>✅ Menambah wawasan tentang kekayaan budaya dan peradaban Indonesia</p><h3 style=\"text-align:justify;\"><strong>Jika Anda tertarik dengan sejarah, budaya, dan warisan peradaban Nusantara, Trowulan menawarkan pengalaman yang unik untuk menyaksikan jejak kejayaan salah satu kerajaan terbesar yang pernah berdiri di Asia Tenggara.</strong></h3>', '<h2 style=\"text-align:justify;\">Trowulan Historical Private Tour</h2><p style=\"text-align:justify;\">Step back in time and uncover the legacy of the legendary <strong>Majapahit Kingdom</strong>, one of the greatest empires in Southeast Asian history. Once the political and cultural heart of a vast kingdom that influenced much of the Indonesian archipelago, Trowulan offers a fascinating journey into a civilization that shaped the region for centuries.</p><p style=\"text-align:justify;\">Surrounded by ancient monuments, archaeological remains, and historical treasures, this experience invites travelers to explore the rich heritage, architectural achievements, and cultural legacy left behind by one of Indonesia’s most remarkable kingdoms. Every site tells a story of power, prosperity, and innovation that once made Majapahit one of the most influential civilizations in the region.</p><p style=\"text-align:justify;\">More than just a historical excursion, this tour offers a deeper understanding of Indonesia’s roots while allowing visitors to appreciate the beauty of ancient architecture, local traditions, and the enduring spirit of Javanese culture.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover the fascinating history of the Majapahit Kingdom<br>✅ Explore one of Indonesia’s most important archaeological regions<br>✅ Learn about the culture, architecture, and heritage of ancient Java<br>✅ Perfect for history enthusiasts, families, students, and cultural travelers<br>✅ Visit remarkable historical landmarks and ancient monuments<br>✅ Gain a deeper appreciation of Indonesia’s rich civilization and traditions</p><h3 style=\"text-align:justify;\"><strong>If you are passionate about history, culture, and heritage, Trowulan offers a unique opportunity to walk through the remnants of a kingdom that once stood among the greatest powers of Southeast Asia.</strong></h3>', '<h2 style=\"text-align:justify;\">트로울란 역사 프라이빗 투어</h2><p style=\"text-align:justify;\">시간을 거슬러 올라가 동남아시아 역사상 가장 위대한 왕국 중 하나인 <strong>마자파힛 왕국(Majapahit Kingdom)</strong> 의 찬란한 유산을 만나보세요. 과거 마자파힛 제국의 정치와 문화의 중심지였던 트로울란은 인도네시아 고대 문명의 위대한 업적과 역사를 간직한 특별한 장소입니다.</p><p style=\"text-align:justify;\">이곳에서는 수백 년 전 번영했던 왕국의 흔적을 통해 당시의 문화, 건축 기술, 그리고 사회적 발전상을 직접 느낄 수 있습니다. 남겨진 유적과 문화유산은 마자파힛이 동남아시아에서 가장 강력한 제국 중 하나였음을 보여줍니다.</p><p style=\"text-align:justify;\">단순한 역사 탐방을 넘어, 이 여행은 인도네시아 문화의 뿌리를 이해하고 자바 전통 문화의 깊이를 경험할 수 있는 특별한 기회를 제공합니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 전설적인 마자파힛 왕국의 역사 탐방<br>✅ 인도네시아에서 가장 중요한 고고학 유적지 방문<br>✅ 고대 자바의 문화와 건축, 문명 이해<br>✅ 역사 애호가, 가족, 학생, 문화 여행객에게 추천<br>✅ 의미 있는 역사 유산과 기념물 탐방<br>✅ 인도네시아 문화와 문명의 깊이를 경험</p><h3 style=\"text-align:justify;\"><strong>역사와 문화에 관심이 있다면, 트로울란은 한때 동남아시아를 지배했던 위대한 왕국의 흔적을 직접 만날 수 있는 특별한 여행지가 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">特罗乌兰历史私人之旅</h2><p style=\"text-align:justify;\">穿越时光，探索东南亚历史上最辉煌的王国之一——<strong>满者伯夷王国（Majapahit Kingdom）</strong> 的传奇遗产。作为昔日满者伯夷帝国的政治与文化中心，特罗乌兰保存着丰富的历史遗迹，见证了印度尼西亚古代文明的辉煌成就。</p><p style=\"text-align:justify;\">这里遍布考古遗址和历史遗迹，每一处都讲述着关于繁荣、文化与创新的故事。曾经强盛一时的满者伯夷王国不仅影响了整个印度尼西亚群岛，也在东南亚历史上留下了深远的印记。</p><p style=\"text-align:justify;\">这不仅是一场历史之旅，更是一次深入了解印度尼西亚文化根源的机会。通过欣赏古老建筑、探索历史遗产以及感受爪哇文化的独特魅力，您将收获一段意义非凡的文化体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索传奇满者伯夷王国的辉煌历史<br>✅ 参观印度尼西亚最重要的考古遗址之一<br>✅ 深入了解古代爪哇文化、建筑与文明<br>✅ 适合历史爱好者、家庭游客、学生及文化旅行者<br>✅ 参观具有重要历史价值的古迹与文化遗产<br>✅ 感受印度尼西亚丰富而悠久的文明历史</p><h3 style=\"text-align:justify;\"><strong>如果您热爱历史、文化与古代文明，那么特罗乌兰将带您走进满者伯夷王国的辉煌时代，亲身感受这段影响东南亚历史的重要篇章。</strong></h3><p style=\"text-align:justify;\">&nbsp;</p>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Historical\",\"Educational\",\"Culture\",\"Heritage Photography\",\"Family\"]', NULL, 0, NULL, '2026-06-02 11:41:31', '2026-06-02 11:41:31'),
(97, 48, 'SURABAYA CITY TOUR', 'SURABAYA', 'surabaya-city-tour', '<h2 style=\"text-align:justify;\">Surabaya City Tour</h2><p style=\"text-align:justify;\">Jelajahi jantung Kota Surabaya melalui perjalanan yang memadukan sejarah, budaya, warisan kolonial, dan kehidupan kota modern. Sebagai kota terbesar kedua di Indonesia, Surabaya bukan hanya pintu gerbang menuju berbagai destinasi wisata di Jawa Timur, tetapi juga sebuah kota yang kaya akan cerita, tradisi, dan keberagaman budaya yang menarik untuk dijelajahi.</p><p style=\"text-align:justify;\">Dikenal sebagai <strong>\"Kota Pahlawan\"</strong>, Surabaya memiliki peran penting dalam perjalanan sejarah bangsa Indonesia. Hingga saat ini, kota ini masih mempertahankan berbagai warisan sejarah yang berpadu harmonis dengan perkembangan modern, menciptakan suasana kota yang dinamis dan penuh karakter.</p><p style=\"text-align:justify;\">Dari kawasan bersejarah yang menawan hingga pusat perbelanjaan modern, Surabaya menawarkan pengalaman yang lengkap bagi para wisatawan. Perpaduan budaya Jawa, Tionghoa, Arab, dan Madura yang hidup berdampingan menjadikan kota ini kaya akan tradisi, kuliner, serta pengalaman lokal yang autentik.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengenal sejarah dan warisan budaya Kota Pahlawan<br>✅ Menikmati perpaduan unik antara budaya tradisional dan kehidupan modern<br>✅ Menjelajahi kawasan bersejarah, landmark budaya, dan kehidupan lokal<br>✅ Berbelanja produk khas serta menikmati pengalaman lokal Jawa Timur<br>✅ Cocok untuk keluarga, wisatawan budaya, dan pengunjung pertama kali ke Surabaya<br>✅ Cara terbaik untuk mengenal karakter dan kehidupan masyarakat Surabaya</p><h3 style=\"text-align:justify;\"><strong>Jika Anda ingin merasakan sisi lain Jawa Timur selain wisata alam, Surabaya menawarkan pengalaman yang kaya akan sejarah, budaya, dan kehidupan kota yang penuh warna.</strong></h3>', '<h2 style=\"text-align:justify;\">Surabaya City Private Tour</h2><p style=\"text-align:justify;\">Discover the vibrant heart of East Java through a journey that blends history, culture, heritage, and modern city life. As Indonesia’s second-largest city, Surabaya is more than just a gateway to famous destinations—it is a fascinating destination in its own right, filled with stories, traditions, and unique cultural influences.</p><p style=\"text-align:justify;\">Known as the <strong>\"City of Heroes,\"</strong> Surabaya played a significant role in Indonesia’s journey to independence. Today, the city showcases a remarkable mix of historical landmarks, colonial architecture, multicultural heritage, bustling shopping districts, and authentic local experiences that reflect the spirit of modern Indonesia.</p><p style=\"text-align:justify;\">From charming heritage quarters and cultural attractions to lively commercial centers and local markets, this tour offers a comprehensive introduction to one of Indonesia’s most dynamic cities. Whether you\'re interested in history, culture, photography, shopping, or simply experiencing local life, Surabaya provides a rich and rewarding travel experience.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover the history and heritage of Indonesia\'s \"City of Heroes\"<br>✅ Experience the unique blend of traditional culture and modern urban life<br>✅ Explore historic districts, cultural landmarks, and local attractions<br>✅ Enjoy shopping, local products, and authentic East Javanese experiences<br>✅ Perfect for families, cultural travelers, and first-time visitors<br>✅ A great introduction to the lifestyle and character of Surabaya</p><h3 style=\"text-align:justify;\"><strong>If you want to experience the true essence of East Java beyond its natural attractions, Surabaya offers a captivating journey through history, culture, and everyday local life.</strong></h3>', '<h2 style=\"text-align:justify;\">수라바야 시티 프라이빗 투어</h2><p style=\"text-align:justify;\">동부 자바의 중심 도시인 수라바야를 탐험하며 역사, 문화, 식민지 시대 유산, 그리고 현대적인 도시의 매력을 한 번에 경험해 보세요. 인도네시아 제2의 도시인 수라바야는 단순히 다른 관광지로 가는 관문이 아니라, 풍부한 역사와 다양한 문화가 살아 숨 쉬는 매력적인 여행지입니다.</p><p style=\"text-align:justify;\">수라바야는 <strong>\"영웅의 도시(City of Heroes)\"</strong> 로 알려져 있으며, 인도네시아 독립 역사에서 매우 중요한 역할을 했습니다. 오늘날에도 도시 곳곳에는 역사적 흔적이 남아 있으며, 현대적인 발전과 조화를 이루며 독특한 도시 분위기를 만들어내고 있습니다.</p><p style=\"text-align:justify;\">자바, 중국계, 아랍계, 마두라 문화가 어우러진 수라바야는 다양한 전통과 생활방식을 경험할 수 있는 곳입니다. 역사적인 거리, 문화 명소, 현대적인 쇼핑 지역까지, 이 도시는 동부 자바를 이해하는 최고의 출발점이 되어줍니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 인도네시아 \"영웅의 도시\"의 역사와 문화 탐방<br>✅ 전통과 현대가 조화를 이루는 도시의 매력 경험<br>✅ 역사 유적, 문화 명소, 현지 생활을 한 번에 체험<br>✅ 쇼핑과 지역 특산품, 동부 자바의 문화 경험 가능<br>✅ 가족, 문화 여행객, 첫 방문객에게 추천<br>✅ 수라바야의 진정한 매력을 발견할 수 있는 최고의 방법</p><h3 style=\"text-align:justify;\"><strong>자연 관광지를 넘어 인도네시아의 역사와 문화, 그리고 현지인의 삶을 경험하고 싶다면 수라바야는 반드시 방문해야 할 도시입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">泗水城市私人之旅</h2><p style=\"text-align:justify;\">探索东爪哇的核心城市——<strong>泗水（Surabaya）</strong>，感受历史、文化、殖民遗产与现代都市生活的完美融合。作为印度尼西亚第二大城市，泗水不仅是通往东爪哇各大景点的重要门户，更是一座充满故事、传统与文化魅力的城市。</p><p style=\"text-align:justify;\">泗水被誉为 <strong>“英雄之城（City of Heroes）”</strong>，在印度尼西亚独立历史中发挥了重要作用。如今，这座城市依然保留着丰富的历史遗迹，同时与现代化发展相结合，展现出独特而充满活力的城市风貌。</p><p style=\"text-align:justify;\">这里汇聚了爪哇、华人、阿拉伯以及马都拉等多元文化，形成了丰富多彩的传统、美食与生活方式。从历史街区到现代商业中心，从文化遗产到本地特色体验，泗水为游客呈现出一个真实而迷人的东爪哇。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 深入了解“英雄之城”的历史与文化遗产<br>✅ 感受传统文化与现代都市生活的完美结合<br>✅ 探索历史街区、文化地标与当地生活风貌<br>✅ 体验购物乐趣与东爪哇特色产品<br>✅ 适合家庭游客、文化爱好者及首次到访者<br>✅ 全面了解泗水城市魅力与当地生活方式</p><h3 style=\"text-align:justify;\"><strong>如果您希望在欣赏自然景观之外，更深入地了解印度尼西亚的历史、文化与城市生活，那么泗水将为您带来一次丰富而难忘的旅程。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"ea88e69cebfc17d6f7b2b5242badd9a89\">Surabaya Old City tour by jeep/mini train</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e66acdd33916e3b55104f60ea1d6e1493\">Free Snack Box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Historical\",\"Culture\",\"City\",\"Shopping\",\"Family\"]', NULL, 0, NULL, '2026-06-02 12:14:13', '2026-06-02 12:14:13'),
(98, 48, 'BANYUWANGI MENJANGAN ISLAND', 'BANYUWANGI', 'banyuwangi-menjangan-island', '<h2 style=\"text-align:justify;\">Banyuwangi Menjangan Island Private Tour</h2><p style=\"text-align:justify;\">Nikmati pelarian sempurna ke surga tropis yang dipenuhi air laut sebening kristal, terumbu karang yang memukau, dan pulau-pulau eksotis berpasir putih. Terletak di antara Pulau Jawa dan Bali, kawasan ini menawarkan pengalaman island hopping dan snorkeling yang tak terlupakan di salah satu destinasi bahari terbaik di Indonesia.</p><p style=\"text-align:justify;\">Rasakan keindahan bawah laut yang kaya akan kehidupan laut berwarna-warni, dengan perairan jernih yang memungkinkan Anda menikmati panorama bawah laut yang menakjubkan. Dari hamparan laut biru kehijauan hingga pantai-pantai yang masih alami, setiap sudut perjalanan menghadirkan pemandangan yang sempurna untuk relaksasi maupun mengabadikan momen indah.</p><p style=\"text-align:justify;\">Tour ini sangat cocok bagi wisatawan yang ingin menikmati suasana tropis, menjelajahi keindahan laut, dan merasakan ketenangan pulau-pulau yang masih alami. Perpaduan antara keindahan pantai, kehidupan bawah laut, dan panorama laut yang memukau menjadikan perjalanan ini pengalaman yang wajib dicoba saat berada di Banyuwangi.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi pulau-pulau tropis terindah di Indonesia<br>✅ Snorkeling di perairan jernih dengan terumbu karang yang masih alami<br>✅ Menikmati pantai berpasir putih dan panorama laut yang memukau<br>✅ Mengunjungi hamparan pasir unik di tengah lautan biru<br>✅ Cocok untuk keluarga, pasangan, pecinta pantai, dan fotografer<br>✅ Pengalaman island hopping yang santai dan jauh dari keramaian</p><h3 style=\"text-align:justify;\"><strong>Jika Anda memimpikan pantai berpasir putih, laut biru yang jernih, dan keindahan bawah laut yang luar biasa, perjalanan ini adalah cara terbaik untuk menikmati surga bahari Banyuwangi.</strong></h3>', '<h2 style=\"text-align:justify;\">Banyuwangi Menjangan Island Private Tour</h2><p style=\"text-align:justify;\">Escape to a tropical paradise where crystal-clear waters, vibrant coral reefs, and pristine white-sand islands create an unforgettable island-hopping experience. Located between the islands of Java and Bali, this hidden marine sanctuary offers some of the most spectacular underwater scenery and coastal landscapes in Indonesia.</p><p style=\"text-align:justify;\">Immerse yourself in a world of turquoise waters and thriving marine life as you explore protected coral ecosystems renowned for their exceptional biodiversity and visibility. Whether you\'re snorkeling among colorful tropical fish, relaxing on secluded beaches, or capturing breathtaking photographs surrounded by endless shades of blue, every moment feels like a scene from a tropical dream.</p><p style=\"text-align:justify;\">This journey is perfect for travelers seeking relaxation, natural beauty, and a memorable ocean adventure. Combining crystal-clear seas, untouched island scenery, and incredible underwater experiences, it offers an ideal escape for families, couples, and nature lovers alike.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover some of Indonesia’s most beautiful tropical islands<br>✅ Snorkel in crystal-clear waters filled with colorful marine life<br>✅ Experience pristine beaches and stunning ocean panoramas<br>✅ Visit spectacular sandbars surrounded by turquoise seas<br>✅ Perfect for families, couples, photographers, and ocean lovers<br>✅ Enjoy a relaxing island-hopping adventure away from the crowds</p><h3 style=\"text-align:justify;\"><strong>If you\'re dreaming of white-sand beaches, vibrant coral reefs, and unforgettable tropical scenery, this island adventure is the perfect way to experience the natural beauty of Banyuwangi\'s marine paradise.</strong></h3>', '<h2 style=\"text-align:justify;\">반유왕이 믄장안 섬 프라이빗 투어</h2><p style=\"text-align:justify;\">수정처럼 맑은 바다, 아름다운 산호초, 그리고 새하얀 모래사장이 펼쳐진 열대 낙원으로 떠나보세요. 자바섬과 발리섬 사이에 위치한 이 해양 지역은 인도네시아에서 가장 아름다운 스노클링과 아일랜드 호핑 경험을 선사하는 숨겨진 보석 같은 여행지입니다.</p><p style=\"text-align:justify;\">맑고 푸른 바닷속에서는 형형색색의 열대어와 건강한 산호초를 가까이에서 감상할 수 있으며, 눈부신 에메랄드빛 바다와 한적한 해변은 완벽한 휴식과 힐링을 제공합니다. 어디를 둘러보아도 그림 같은 풍경이 펼쳐져 잊지 못할 추억을 남길 수 있습니다.</p><p style=\"text-align:justify;\">이 투어는 아름다운 바다를 사랑하는 여행객, 가족, 커플, 그리고 자연을 즐기고 싶은 모든 분들에게 이상적인 선택입니다. 청정한 해양 생태계와 아름다운 섬 풍경이 어우러진 특별한 경험을 만나보세요.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 인도네시아 최고의 열대 섬 탐험<br>✅ 맑은 바다에서 즐기는 환상적인 스노클링<br>✅ 아름다운 백사장과 탁 트인 바다 전망 감상<br>✅ 에메랄드빛 바다 위에 펼쳐진 특별한 모래섬 방문<br>✅ 가족, 커플, 자연 애호가, 사진작가에게 추천<br>✅ 한적하고 여유로운 아일랜드 호핑 여행</p><h3 style=\"text-align:justify;\"><strong>새하얀 해변과 맑고 푸른 바다, 그리고 아름다운 해양 생태계를 꿈꾸고 있다면, 이 여행은 반유왕이의 숨겨진 해양 낙원을 경험할 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">外南梦孟加岸岛私人之旅</h2><p style=\"text-align:justify;\">逃离喧嚣，前往一片拥有水晶般清澈海水、绚丽珊瑚礁和洁白沙滩的热带天堂。位于爪哇岛与巴厘岛之间的这片海域，被誉为印度尼西亚最迷人的海洋秘境之一，为您带来难忘的跳岛与浮潜体验。</p><p style=\"text-align:justify;\">在清澈见底的海水中，您可以欣赏色彩斑斓的热带鱼群和生机勃勃的珊瑚生态系统。湛蓝与碧绿交织的海面、宁静原始的海岛风光，以及令人惊叹的海洋景观，让每一刻都仿佛置身于热带明信片之中。</p><p style=\"text-align:justify;\">无论您是热爱海洋、向往放松假期，还是希望探索原生态海岛风光，这趟旅程都将带给您最纯粹的热带度假体验。迷人的海景、丰富的海洋生物以及宁静的岛屿氛围，共同构成一场难忘的海上冒险。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索印度尼西亚最美丽的热带岛屿之一<br>✅ 在清澈海水中体验精彩浮潜活动<br>✅ 欣赏洁白沙滩与壮丽海景<br>✅ 打卡被碧蓝海水环绕的梦幻沙洲<br>✅ 适合家庭、情侣、海洋爱好者及摄影爱好者<br>✅ 享受轻松惬意、远离人群的跳岛之旅</p><h3 style=\"text-align:justify;\"><strong>如果您向往洁白沙滩、湛蓝海水以及丰富多彩的海底世界，那么这趟旅程将是探索外南梦海洋天堂的最佳方式。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e40d6208cab73b94ed7bbd9ac59520696\">Entrance ticket and snorkeling permit</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"e79d5df941b2636c99f06bad97a6fdeff\">Boat, life jacket, Snorkling set, Underwater Photo</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"ec02c10fff251ffd94c674f80df4df19e\">1x Lunch box</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Island Hopping\",\"Beach\",\"Snorkeling\",\"Photography\",\"Family\",\"Leisure\"]', NULL, 0, NULL, '2026-06-02 12:26:20', '2026-06-02 12:26:20'),
(99, 48, 'IJEN MIDNIGHT PRIVATE TOUR', 'BANYUWANGI', 'ijen-midnight-private-tour', '<h2 style=\"text-align:justify;\">Ijen Midnight Private Tour</h2><p style=\"text-align:justify;\">Mulailah petualangan luar biasa menuju salah satu keajaiban alam paling unik di Indonesia. Terletak di dataran tinggi Jawa Timur, <strong>Gunung Ijen</strong> dikenal di seluruh dunia karena fenomena alamnya yang langka, lanskap vulkanik yang spektakuler, serta pengalaman matahari terbit yang tak terlupakan.</p><p style=\"text-align:justify;\">Perjalanan ini akan membawa Anda ke sebuah dunia yang seolah berbeda dari biasanya, di mana aktivitas vulkanik yang menakjubkan, pegunungan yang megah, dan danau kawah berwarna biru kehijauan berpadu menciptakan pemandangan yang luar biasa. Saat malam perlahan berganti menjadi pagi, panorama pegunungan dan kawah yang memukau akan tersingkap, menghadirkan pengalaman yang sulit ditemukan di tempat lain.</p><p style=\"text-align:justify;\">Selain keindahan alamnya, Gunung Ijen juga menyimpan kisah inspiratif tentang para penambang belerang tradisional yang telah bekerja di kawasan ini selama beberapa generasi. Kehidupan dan semangat mereka menjadi bagian penting dari daya tarik budaya yang menjadikan Ijen semakin istimewa.</p><p style=\"text-align:justify;\">Baik bagi pecinta alam, fotografer, maupun pencari petualangan, Gunung Ijen menawarkan pengalaman sekali seumur hidup yang memperlihatkan keindahan dan keunikan lanskap vulkanik Indonesia.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menyaksikan salah satu fenomena vulkanik paling langka di dunia<br>✅ Menikmati sunrise yang spektakuler di atas lanskap kawah yang menakjubkan<br>✅ Mengagumi danau kawah biru kehijauan yang menjadi ikon Gunung Ijen<br>✅ Mengabadikan momen di salah satu destinasi fotografi terbaik di Indonesia<br>✅ Mengenal kehidupan dan tradisi unik para penambang belerang lokal<br>✅ Cocok untuk pecinta petualangan, fotografer, dan pencinta alam</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari petualangan yang unik, pemandangan yang luar biasa, dan pengalaman yang tidak terlupakan, Gunung Ijen adalah destinasi yang wajib masuk dalam daftar perjalanan Anda.</strong></h3>', '<h2 style=\"text-align:justify;\">Ijen Midnight Private Tour</h2><p style=\"text-align:justify;\">Embark on an extraordinary journey to one of Indonesia’s most fascinating natural wonders. Nestled in the highlands of East Java, Mount Ijen is renowned worldwide for its rare volcanic phenomena, breathtaking crater landscapes, and unforgettable sunrise experiences.</p><p style=\"text-align:justify;\">This adventure takes you into a surreal environment where glowing volcanic activity, dramatic mountain scenery, and one of the world’s most striking crater lakes combine to create an experience unlike any other. As darkness fades into dawn, the surrounding landscape reveals a spectacular panorama of rugged volcanic peaks and vibrant turquoise waters, offering views that leave a lasting impression on every visitor.</p><p style=\"text-align:justify;\">Beyond its natural beauty, Mount Ijen also tells a powerful human story through the resilience and determination of local sulfur miners who have worked on these volcanic slopes for generations. Their enduring traditions add a unique cultural dimension to this remarkable destination.</p><p style=\"text-align:justify;\">Whether you\'re an adventure seeker, photographer, or nature enthusiast, Mount Ijen offers a once-in-a-lifetime experience that showcases the raw beauty and extraordinary diversity of Indonesia’s volcanic landscapes.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Witness one of the world\'s rarest volcanic phenomena<br>✅ Experience a spectacular sunrise above a stunning crater landscape<br>✅ Discover the famous turquoise crater lake of Mount Ijen<br>✅ Capture incredible photographs in one of Indonesia\'s most iconic destinations<br>✅ Learn about the unique traditions of local sulfur miners<br>✅ Perfect for adventure lovers, photographers, and nature enthusiasts</p><h3 style=\"text-align:justify;\"><strong>If you\'re searching for a truly unique adventure filled with dramatic landscapes, rare natural wonders, and unforgettable moments, Mount Ijen is a destination that deserves a place on every travel bucket list.</strong></h3>', '<h2 style=\"text-align:justify;\">이젠 미드나잇 프라이빗 투어</h2><p style=\"text-align:justify;\">인도네시아에서 가장 특별한 자연 경관 중 하나인 <strong>이젠 화산(Mount Ijen)</strong> 으로 떠나는 잊지 못할 모험을 경험해 보세요. 동부 자바의 고지대에 위치한 이젠은 세계적으로 희귀한 자연 현상과 웅장한 화산 풍경, 그리고 환상적인 일출로 유명한 명소입니다.</p><p style=\"text-align:justify;\">이 여행은 신비로운 화산 지형과 눈부신 자연경관이 어우러진 특별한 세계로 여러분을 안내합니다. 어둠이 걷히고 새벽이 밝아오면 거대한 화산 지형과 에메랄드빛 화산호가 모습을 드러내며, 평생 기억에 남을 장관을 선사합니다.</p><p style=\"text-align:justify;\">이젠은 자연의 아름다움뿐만 아니라 수 세대에 걸쳐 화산에서 유황을 채취해 온 현지 광부들의 이야기를 통해 독특한 문화적 가치도 느낄 수 있는 곳입니다. 이들의 강인한 삶은 이젠만의 특별한 매력을 더해 줍니다.</p><p style=\"text-align:justify;\">모험을 즐기는 여행객, 사진작가, 자연 애호가 모두에게 이젠 화산은 인도네시아의 경이로운 자연을 경험할 수 있는 최고의 여행지입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 세계적으로 희귀한 화산 자연 현상 감상<br>✅ 장엄한 화산 풍경 위에서 맞이하는 아름다운 일출<br>✅ 이젠의 상징인 에메랄드빛 화산호 감상<br>✅ 인도네시아 최고의 사진 촬영 명소 방문<br>✅ 유황 광부들의 독특한 문화와 전통 체험<br>✅ 모험가, 자연 애호가, 사진작가에게 추천</p><h3 style=\"text-align:justify;\"><strong>특별한 모험과 놀라운 자연경관을 찾고 있다면, 이젠 화산은 반드시 방문해야 할 버킷리스트 여행지입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">宜珍火山午夜私人之旅</h2><p style=\"text-align:justify;\">开启一场前往印度尼西亚最独特自然奇观之一的非凡旅程。位于东爪哇高原的 <strong>宜珍火山（Mount Ijen）</strong> 以其罕见的火山现象、壮丽的火山景观以及令人难忘的日出而闻名于世。</p><p style=\"text-align:justify;\">这趟旅程将带您进入一个仿佛来自另一个世界的奇幻景观之中。在这里，壮观的火山地貌、神秘的自然现象以及闻名世界的碧蓝火山湖共同构成了一幅震撼人心的画卷。当夜幕逐渐退去，晨光洒向群山时，眼前展开的壮丽景色将成为您旅途中最难忘的回忆之一。</p><p style=\"text-align:justify;\">除了令人惊叹的自然景观之外，宜珍火山还承载着当地硫磺矿工世代传承的故事。他们坚韧不拔的精神与独特的生活方式，为这座火山增添了深厚的人文魅力。</p><p style=\"text-align:justify;\">无论您是热爱探险、热衷摄影，还是钟情于大自然的壮丽景观，宜珍火山都将为您带来一次终生难忘的体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 观赏世界上最罕见的火山自然现象之一<br>✅ 欣赏壮丽火山景观中的绝美日出<br>✅ 探索宜珍火山标志性的碧蓝火山湖<br>✅ 打卡印度尼西亚最受欢迎的摄影胜地之一<br>✅ 了解当地硫磺矿工独特的文化与生活方式<br>✅ 适合探险爱好者、摄影爱好者及自然爱好者</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一次充满震撼景观、独特自然奇观与难忘回忆的探险之旅，那么宜珍火山绝对值得列入您的旅行清单。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e40d6208cab73b94ed7bbd9ac59520696\">Entrance ticket and donation fee</li><li data-list-item-id=\"e6a6dd197e17b07fe61e3af0808df04ed\">Parking &amp; Tol</li><li data-list-item-id=\"ef3959fea80f596bf678cb52f92343b45\">Ijen masker</li><li data-list-item-id=\"e6eeac7b9b93ec4fcfb499b9a6cd5d15a\">Healthy paper document check</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Photography\",\"Adventure\",\"Sunrise\",\"Culture\"]', NULL, 0, NULL, '2026-06-02 12:35:04', '2026-06-02 12:35:49'),
(100, 48, 'BANYUWANGI CITY TOUR', 'BANYUWANGI', 'banyuwangi-city-tour', '<h2 style=\"text-align:justify;\">Banyuwangi City Private Tour</h2><p style=\"text-align:justify;\">Temukan pesona Banyuwangi, sebuah destinasi yang memadukan kekayaan budaya, keindahan alam pedesaan, dan panorama pesisir yang menawan dalam satu perjalanan yang berkesan. Terletak di ujung timur Pulau Jawa, Banyuwangi telah berkembang menjadi salah satu destinasi wisata paling menarik di Indonesia dengan karakter yang autentik dan keindahan alam yang memikat.</p><p style=\"text-align:justify;\">Perjalanan ini mengajak Anda untuk mengenal Banyuwangi lebih dekat, bukan hanya sebagai gerbang menuju Kawah Ijen dan berbagai destinasi alam terkenal lainnya, tetapi juga sebagai daerah yang kaya akan tradisi, keramahan masyarakat lokal, serta lanskap yang indah. Dari hamparan sawah hijau yang menyegarkan hingga pemandangan laut yang menenangkan, setiap sudut Banyuwangi menawarkan pengalaman yang berbeda dan penuh pesona.</p><p style=\"text-align:justify;\">Tour ini sangat cocok bagi wisatawan yang ingin menikmati perjalanan santai sambil mengenal budaya lokal, menikmati keindahan alam, dan merasakan kehidupan masyarakat Banyuwangi yang hangat dan bersahabat.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi perpaduan budaya, alam, dan pesisir Banyuwangi dalam satu hari<br>✅ Mengenal tradisi lokal dan keramahan khas masyarakat Jawa Timur<br>✅ Menikmati panorama pedesaan yang hijau dan pemandangan pantai yang indah<br>✅ Mengunjungi landmark ikonik dan spot foto terbaik di Banyuwangi<br>✅ Cocok untuk keluarga, pasangan, dan wisatawan yang baru pertama kali berkunjung<br>✅ Cara terbaik untuk mengenal Banyuwangi secara lebih mendalam dan santai</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari destinasi yang memadukan budaya, alam, dan pesona lokal yang autentik, Banyuwangi menawarkan pengalaman yang menyegarkan dan berbeda dari destinasi wisata pada umumnya.</strong></h3>', '<h2 style=\"text-align:justify;\">Banyuwangi City Private Tour</h2><p style=\"text-align:justify;\">Discover the vibrant charm of Banyuwangi, a destination where rich cultural traditions, scenic countryside landscapes, and beautiful coastal views come together to create an unforgettable travel experience. Located at the eastern tip of Java Island, Banyuwangi is widely known as one of Indonesia’s most exciting emerging destinations, offering a unique blend of authenticity and natural beauty.</p><p style=\"text-align:justify;\">This journey invites you to experience the heart of Banyuwangi beyond its famous volcanoes and national parks. From lush green landscapes and traditional local culture to picturesque waterfront scenery, every moment reveals the warmth, diversity, and character that make this region so special.</p><p style=\"text-align:justify;\">Perfect for travelers seeking a relaxed and meaningful exploration, this tour offers an opportunity to connect with local life, discover hidden beauty, and enjoy the peaceful atmosphere that has made Banyuwangi increasingly popular among domestic and international visitors alike.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover the cultural and natural highlights of Banyuwangi in one day<br>✅ Experience authentic local traditions and East Javanese hospitality<br>✅ Enjoy beautiful countryside scenery and coastal landscapes<br>✅ Visit some of Banyuwangi\'s most iconic landmarks and photo spots<br>✅ Perfect for families, couples, and first-time visitors<br>✅ A relaxing introduction to one of Indonesia\'s fastest-growing tourism destinations</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a destination that combines culture, nature, and local charm, Banyuwangi offers a refreshing experience that goes far beyond the ordinary.</strong></h3>', '<h2 style=\"text-align:justify;\">반유왕이 시티 프라이빗 투어</h2><p style=\"text-align:justify;\">문화, 자연, 그리고 아름다운 해안 풍경이 조화를 이루는 반유왕이의 매력을 만나보세요. 자바섬의 동쪽 끝에 위치한 반유왕이는 풍부한 전통문화와 아름다운 자연환경을 바탕으로 인도네시아에서 가장 주목받는 여행지 중 하나로 성장하고 있습니다.</p><p style=\"text-align:justify;\">이 여행은 이젠 화산과 국립공원뿐만 아니라 반유왕이의 진정한 매력을 발견할 수 있는 특별한 기회를 제공합니다. 푸른 논밭이 펼쳐진 시골 풍경, 현지 주민들의 따뜻한 환대, 그리고 아름다운 해안 경관은 방문객들에게 편안하고 여유로운 시간을 선사합니다.</p><p style=\"text-align:justify;\">반유왕이의 자연과 문화, 그리고 현지의 삶을 가까이에서 경험할 수 있는 이 투어는 가족 여행객과 문화 탐방을 즐기는 여행객에게 완벽한 선택입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 반유왕이의 문화, 자연, 해안 풍경을 한 번에 경험<br>✅ 동부 자바의 전통문화와 따뜻한 현지 분위기 체험<br>✅ 아름다운 농촌 풍경과 해안 경관 감상<br>✅ 반유왕이의 대표 명소와 사진 촬영 명소 방문<br>✅ 가족, 커플, 첫 방문 여행객에게 추천<br>✅ 반유왕이의 진정한 매력을 발견할 수 있는 최고의 여행</p><h3 style=\"text-align:justify;\"><strong>문화와 자연, 그리고 현지의 매력을 함께 경험하고 싶다면 반유왕이는 특별하고 기억에 남는 여행지를 선사할 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">外南梦城市私人之旅</h2><p style=\"text-align:justify;\">探索外南梦（Banyuwangi）的独特魅力，感受丰富的文化传统、迷人的乡村风光以及壮丽的海岸景观。作为爪哇岛最东端的重要城市，外南梦近年来已发展成为印度尼西亚最具潜力和吸引力的旅游目的地之一，以其纯朴的风情和丰富的自然资源吸引着越来越多的游客。</p><p style=\"text-align:justify;\">这趟旅程不仅带您认识著名景点之外的外南梦，更让您深入体验当地文化、自然风光以及居民的热情好客。从绿意盎然的田园景观到宁静优美的海岸线，每一个角落都展现着这座城市独特的魅力与活力。</p><p style=\"text-align:justify;\">对于希望轻松探索当地文化、欣赏自然美景并体验真实印尼生活方式的游客来说，这是一段充满意义且令人难忘的旅程。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一天内体验外南梦的文化、自然与海岸风光<br>✅ 感受东爪哇独特的传统文化与热情好客<br>✅ 欣赏优美的乡村田园与迷人海景<br>✅ 打卡外南梦最具代表性的地标与摄影景点<br>✅ 适合家庭、情侣及首次到访的游客<br>✅ 深度了解外南梦风土人情的最佳方式</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一个融合文化、自然与当地风情的目的地，那么外南梦将为您带来轻松愉快且充满惊喜的旅行体验。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e3bd768598508c0c2a32a3adb6ccf6d74\">1x Lunch</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Coastal Tour\",\"Family\",\"City\",\"Culture\",\"Nature\"]', NULL, 0, NULL, '2026-06-02 12:44:57', '2026-06-02 12:53:42'),
(101, 48, 'BANYUWANGI BEACH ADVENTURE TOUR', 'BANYUWANGI', 'banyuwangi-beach-adventure-tour', '<h2 style=\"text-align:justify;\">Banyuwangi Beach Adventure Private Tour</h2><p style=\"text-align:justify;\">Jelajahi keindahan alam Banyuwangi melalui perjalanan yang memadukan hutan tropis yang rimbun, pantai-pantai eksotis, air laut yang jernih, serta panorama pesisir yang memukau. Terletak di ujung timur Pulau Jawa, Banyuwangi menyimpan berbagai keajaiban alam yang masih alami dan menawarkan pengalaman sempurna bagi wisatawan yang mencari petualangan sekaligus ketenangan.</p><p style=\"text-align:justify;\">Perjalanan ini menghadirkan perpaduan unik antara hutan hijau yang asri, teluk-teluk tersembunyi, dan pantai-pantai cantik yang belum terlalu ramai dikunjungi. Setiap destinasi menyuguhkan pemandangan yang berbeda, menciptakan pengalaman yang penuh warna dan memberikan kesempatan untuk menikmati keindahan alam Indonesia dari berbagai sudut yang menakjubkan.</p><p style=\"text-align:justify;\">Baik untuk bersantai menikmati suasana pantai, menghirup udara segar alam tropis, maupun mengabadikan momen di lokasi-lokasi yang indah, tour ini menawarkan pengalaman yang berkesan bagi setiap wisatawan.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi pantai-pantai indah dan keajaiban alam Banyuwangi dalam satu perjalanan<br>✅ Menikmati perpaduan sempurna antara hutan tropis dan panorama pesisir<br>✅ Mengagumi teluk-teluk eksotis, pantai alami, dan pemandangan laut yang memukau<br>✅ Spot fotografi terbaik dengan latar belakang alam yang spektakuler<br>✅ Cocok untuk keluarga, pasangan, pecinta alam, dan fotografer<br>✅ Menikmati suasana alam yang tenang jauh dari keramaian wisata massal</p><h3 style=\"text-align:justify;\"><strong>Jika Anda memimpikan pantai yang masih alami, laut biru yang menenangkan, dan petualangan di tengah alam tropis yang memukau, Banyuwangi menawarkan pengalaman yang tidak akan terlupakan.</strong></h3>', '<h2 style=\"text-align:justify;\">Banyuwangi Beach Adventure Private Tour</h2><p style=\"text-align:justify;\">Discover the wild beauty of Banyuwangi through an unforgettable journey that combines tropical forests, hidden beaches, crystal-clear waters, and breathtaking coastal landscapes. Located on the eastern tip of Java, Banyuwangi is home to some of Indonesia’s most pristine natural treasures, offering a perfect escape for travelers seeking both adventure and relaxation.</p><p style=\"text-align:justify;\">From lush greenery and untouched wilderness to secluded bays and spectacular ocean views, this experience showcases the remarkable diversity of Banyuwangi’s natural beauty. Every destination reveals a different side of the region, creating a journey filled with stunning scenery, fresh sea breezes, and countless opportunities to connect with nature.</p><p style=\"text-align:justify;\">Whether you\'re looking to explore hidden coastal gems, enjoy peaceful beach atmospheres, or simply capture incredible photographs of Indonesia’s tropical landscapes, this tour delivers an unforgettable experience for all types of travelers.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover some of Banyuwangi’s most beautiful beaches and natural landscapes<br>✅ Experience a perfect combination of tropical forests and coastal scenery<br>✅ Enjoy stunning ocean views, hidden bays, and pristine beaches<br>✅ Capture amazing photographs at some of East Java’s most scenic locations<br>✅ Perfect for families, couples, nature lovers, and photographers<br>✅ Escape the crowds and experience the authentic beauty of Banyuwangi</p><h3 style=\"text-align:justify;\"><strong>If you dream of turquoise waters, tropical forests, untouched beaches, and unforgettable coastal adventures, Banyuwangi offers one of Indonesia’s most rewarding natural escapes.</strong></h3>', '<h2 style=\"text-align:justify;\">반유왕이 비치 어드벤처 프라이빗 투어</h2><p style=\"text-align:justify;\">울창한 열대우림, 아름다운 해변, 맑고 푸른 바다, 그리고 숨 막히게 아름다운 해안 풍경이 어우러진 반유왕이의 자연을 만나보세요. 자바섬 동쪽 끝에 위치한 반유왕이는 아직 많은 사람들에게 알려지지 않은 천혜의 자연환경을 간직한 특별한 여행지입니다.</p><p style=\"text-align:justify;\">이 여행은 푸른 숲과 한적한 해변, 숨겨진 만(灣), 그리고 눈부신 바다 풍경을 함께 즐길 수 있는 특별한 경험을 제공합니다. 방문하는 곳마다 각기 다른 매력을 지니고 있어 여행 내내 새로운 풍경과 감동을 선사합니다.</p><p style=\"text-align:justify;\">자연 속에서 여유로운 시간을 보내고 싶거나, 아름다운 사진을 남기고 싶거나, 평화로운 해변에서 휴식을 즐기고 싶은 여행객에게 완벽한 선택이 될 것입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 반유왕이 최고의 해변과 자연 명소 탐방<br>✅ 열대우림과 아름다운 해안 풍경을 동시에 경험<br>✅ 숨겨진 해변과 에메랄드빛 바다 감상<br>✅ 최고의 자연 사진 촬영 명소 방문<br>✅ 가족, 커플, 자연 애호가, 사진작가에게 추천<br>✅ 번잡한 관광지에서 벗어나 여유로운 힐링 여행 가능</p><h3 style=\"text-align:justify;\"><strong>깨끗한 해변과 푸른 바다, 그리고 아름다운 열대 자연 속에서 특별한 휴식을 꿈꾼다면 반유왕이는 최고의 여행지가 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">外南梦海滩探险私人之旅</h2><p style=\"text-align:justify;\">探索外南梦壮丽的自然风光，体验热带雨林、原生态海滩、清澈海水与迷人海岸线完美融合的精彩旅程。位于爪哇岛最东端的外南梦，拥有丰富而未被过度开发的自然资源，是寻求放松与探险旅客的理想目的地。</p><p style=\"text-align:justify;\">在这段旅程中，您将感受到郁郁葱葱的热带森林、宁静的海湾以及令人惊叹的海岸景观所带来的独特魅力。每一处风景都展现出不同的自然之美，让您尽情沉浸于印度尼西亚最纯净的自然环境之中。</p><p style=\"text-align:justify;\">无论您是希望放松身心、欣赏壮丽海景，还是寻找绝佳摄影地点，这趟旅程都将带给您难忘的回忆和丰富的旅行体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程探索外南梦最美丽的海滩与自然景观<br>✅ 体验热带雨林与海岸风光的完美结合<br>✅ 欣赏隐秘海湾、原生态海滩和壮丽海景<br>✅ 打卡东爪哇最值得拍照的自然景点之一<br>✅ 适合家庭、情侣、自然爱好者及摄影爱好者<br>✅ 远离人潮，享受宁静而纯粹的自然之旅</p><h3 style=\"text-align:justify;\"><strong>如果您向往碧蓝大海、洁净沙滩以及原始热带风光，那么外南梦将为您带来一场难忘的海岸探险之旅。</strong></h3>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e3bd768598508c0c2a32a3adb6ccf6d74\">1x Lunch</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Coastal & Marine\",\"Nature\",\"Beach\",\"Photography\",\"Family\",\"LEISURE\"]', NULL, 0, NULL, '2026-06-02 12:53:19', '2026-06-02 12:53:19');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(102, 48, 'BANYUWANGI BALURAN SAFARI TOUR', 'BANYUWANGI', 'banyuwangi-baluran-safari-tour', '<h2 style=\"text-align:justify;\">Banyuwangi Baluran Safari Private Tour</h2><p style=\"text-align:justify;\">Rasakan sisi lain Indonesia yang berbeda dari kebanyakan destinasi wisata. Hamparan savana yang luas, satwa liar yang hidup bebas di habitat alaminya, hutan tropis yang hijau, serta panorama pantai yang indah berpadu menciptakan pengalaman yang tak terlupakan di <strong>Taman Nasional Baluran</strong>, yang dikenal sebagai <strong>\"Little Africa of Java\"</strong>.</p><p style=\"text-align:justify;\">Perjalanan ini mengajak Anda menjelajahi salah satu kawasan konservasi paling unik di Indonesia, di mana bentang alam yang luas dan terbuka menghadirkan suasana yang mengingatkan pada sabana Afrika. Keindahan alam yang masih terjaga, dipadukan dengan keberagaman flora dan fauna, menjadikan Baluran sebagai surga bagi pecinta alam, fotografer, dan para pencari pengalaman baru.</p><p style=\"text-align:justify;\">Dari pemandangan savana yang memukau hingga kawasan hutan dan pesisir yang menenangkan, setiap sudut Baluran menawarkan pengalaman yang berbeda dan memperlihatkan kekayaan alam Indonesia yang luar biasa.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi \"Little Africa of Java\" yang terkenal<br>✅ Menikmati pemandangan savana yang luas dan satwa liar di habitat alaminya<br>✅ Mengunjungi salah satu taman nasional paling unik di Indonesia<br>✅ Menikmati perpaduan hutan tropis, savana, dan panorama pantai dalam satu perjalanan<br>✅ Spot fotografi alam yang spektakuler dan berbeda dari destinasi lainnya<br>✅ Cocok untuk keluarga, pecinta alam, dan fotografer</p><h3 style=\"text-align:justify;\"><strong>Jika Anda ingin merasakan petualangan alam yang berbeda dari biasanya, Baluran menawarkan kesempatan langka untuk menikmati keindahan alam liar Indonesia dalam suasana yang menyerupai Afrika.</strong></h3>', '<h2 style=\"text-align:justify;\">Banyuwangi Baluran Safari Private Tour</h2><p style=\"text-align:justify;\">Experience a different side of Indonesia where vast golden savannahs, diverse wildlife, tropical forests, and pristine coastlines come together in one extraordinary destination. Often referred to as <strong>\"Little Africa of Java,\"</strong> Baluran National Park offers a unique landscape unlike anywhere else in the country, making it one of East Java’s most remarkable natural treasures.</p><p style=\"text-align:justify;\">This journey invites you to explore wide-open grasslands framed by dramatic mountain backdrops, where wildlife roams freely and nature remains beautifully untouched. The combination of sweeping savannah views, lush forests, and coastal scenery creates a truly immersive experience for travelers seeking both adventure and relaxation.</p><p style=\"text-align:justify;\">Perfect for families, nature enthusiasts, photographers, and wildlife lovers, this tour showcases the incredible diversity of Banyuwangi’s natural environment. From breathtaking landscapes to unforgettable encounters with nature, every moment offers a glimpse into one of Indonesia’s most unique ecosystems.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Explore the famous \"Little Africa of Java\"<br>✅ Experience stunning savannah landscapes and diverse wildlife<br>✅ Discover one of Indonesia’s most unique national parks<br>✅ Enjoy a perfect combination of forest, grassland, and coastal scenery<br>✅ Capture incredible photographs in spectacular natural settings<br>✅ Ideal for families, photographers, and nature lovers</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for an adventure beyond the ordinary, Baluran offers a rare opportunity to experience the wild beauty of Indonesia in a setting that feels worlds away from the tropical beaches most travelers expect.</strong></h3>', '<h2 style=\"text-align:justify;\">반유왕이 발루란 사파리 프라이빗 투어</h2><p style=\"text-align:justify;\">인도네시아에서 색다른 자연을 경험하고 싶다면 발루란 국립공원으로 떠나보세요. 넓게 펼쳐진 사바나 초원, 야생동물, 울창한 열대우림, 그리고 아름다운 해안 풍경이 어우러진 이곳은 <strong>\"자바의 작은 아프리카(Little Africa of Java)\"</strong> 라는 별명으로 유명합니다.</p><p style=\"text-align:justify;\">광활한 초원과 자연 그대로의 생태계는 마치 아프리카 사파리에 온 듯한 특별한 분위기를 선사합니다. 다양한 동식물이 서식하는 이 국립공원은 자연 애호가와 사진작가들에게 꿈같은 여행지로 손꼽히고 있습니다.</p><p style=\"text-align:justify;\">사바나, 숲, 해변이 하나의 여행 속에 어우러져 있어 인도네시아 자연의 다양한 매력을 한 번에 경험할 수 있는 특별한 기회를 제공합니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 유명한 \"자바의 작은 아프리카\" 탐험<br>✅ 광활한 사바나와 야생동물 관찰<br>✅ 인도네시아에서 가장 독특한 국립공원 방문<br>✅ 숲, 초원, 해안 풍경을 한 번에 경험<br>✅ 환상적인 자연 사진 촬영 명소 방문<br>✅ 가족, 자연 애호가, 사진작가에게 추천</p><h3 style=\"text-align:justify;\"><strong>평범한 관광지를 넘어 특별한 자연 모험을 찾고 있다면, 발루란은 인도네시아에서 가장 독특한 야생 자연을 경험할 수 있는 최고의 여행지입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">外南梦巴鲁兰野生动物园私人之旅</h2><p style=\"text-align:justify;\">探索印度尼西亚与众不同的一面，在广阔的热带草原、原始森林、野生动物以及迷人海岸线之间，感受大自然最真实的魅力。<strong>巴鲁兰国家公园（Baluran National Park）</strong> 因其辽阔的稀树草原景观而被誉为 <strong>“爪哇小非洲（Little Africa of Java）”</strong>，是印度尼西亚最独特的自然保护区之一。</p><p style=\"text-align:justify;\">这里拥有开阔壮丽的草原景观、丰富的野生动物资源以及保存完好的自然生态系统。漫步于这片广袤的自然天地之间，仿佛置身于非洲草原，感受与众不同的生态之旅。</p><p style=\"text-align:justify;\">除了壮观的草原风光，这里还融合了热带森林与海岸景观，让游客能够在一次旅程中体验印度尼西亚丰富多样的自然魅力。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索著名的“爪哇小非洲”<br>✅ 欣赏辽阔草原与野生动物自然生态<br>✅ 参观印度尼西亚最独特的国家公园之一<br>✅ 一次旅程体验森林、草原与海岸风光<br>✅ 打卡东爪哇最具特色的自然摄影胜地<br>✅ 适合家庭、自然爱好者及摄影爱好者</p><h3 style=\"text-align:justify;\"><strong>如果您希望体验不同于传统海岛度假的自然探险，那么巴鲁兰将带您走进一个充满野性魅力与壮丽景观的自然世界。</strong></h3><p style=\"text-align:justify;\">&nbsp;</p>', 0.00, NULL, 1, 0, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li><li data-list-item-id=\"ef0733cd000b9dd64535a45468224e0f7\">Free 1 bottle Mineral water</li><li data-list-item-id=\"e3bd768598508c0c2a32a3adb6ccf6d74\">1x Lunch</li></ul>', '<ul><li data-list-item-id=\"eb1a4e45d00472164518ba4ae21b95bbc\">Hotel</li><li data-list-item-id=\"e65a96bb83f2ab89b4ed62505a80dd75c\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Wildlife\",\"Nature\",\"Adventure\",\"Savannah & Landscape\",\"Photography\",\"Family\"]', NULL, 0, NULL, '2026-06-02 13:02:13', '2026-06-02 13:02:13'),
(103, 48, '2 DAYS HERITAGE TROWULAN SURABAYA TOUR', 'SURABAYA', '2-days-heritage-trowulan-surabaya-tour', '<h2 style=\"text-align:justify;\">2D/1N Heritage Trowulan Surabaya Tour</h2><p style=\"text-align:justify;\">Jelajahi kekayaan sejarah dan budaya Jawa Timur melalui perjalanan yang menghubungkan kejayaan <strong>Kerajaan Majapahit</strong> dengan semangat modern Kota Surabaya. Tour ini menghadirkan pengalaman yang mendalam untuk mengenal peradaban, tradisi, dan perjalanan sejarah yang telah membentuk Indonesia selama berabad-abad.</p><p style=\"text-align:justify;\">Kembali ke masa ketika Majapahit berdiri sebagai salah satu kerajaan terbesar dan paling berpengaruh di Asia Tenggara. Warisan budaya, arsitektur, dan nilai-nilai peradaban yang ditinggalkan hingga kini masih menjadi bagian penting dari identitas bangsa Indonesia. Melalui perjalanan ini, Anda akan mengenal kisah para raja, kejayaan masa lampau, serta peran Majapahit dalam membentuk sejarah Nusantara.</p><p style=\"text-align:justify;\">Perjalanan kemudian berlanjut ke Surabaya, yang dikenal sebagai <strong>\"Kota Pahlawan\"</strong>, tempat sejarah dan kehidupan modern berpadu harmonis. Dari kawasan bersejarah hingga pusat kehidupan kota yang dinamis, Anda akan mendapatkan gambaran yang lebih lengkap tentang perjalanan Indonesia dari masa kejayaan kerajaan hingga menjadi negara modern seperti saat ini.</p><p style=\"text-align:justify;\">Sangat cocok bagi keluarga, pelajar, pencinta budaya, maupun wisatawan yang ingin memahami Indonesia lebih dalam melalui pengalaman yang edukatif dan berkesan.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menelusuri jejak kejayaan Kerajaan Majapahit yang legendaris<br>✅ Mengunjungi destinasi sejarah dan budaya terpenting di Jawa Timur<br>✅ Mengenal warisan budaya, tradisi, dan peradaban Indonesia yang kaya<br>✅ Menikmati perpaduan antara sejarah kuno dan kehidupan kota modern<br>✅ Cocok untuk keluarga, pelajar, pecinta sejarah, dan wisatawan budaya<br>✅ Memberikan pemahaman yang lebih mendalam tentang Indonesia di luar wisata alam</p><h3 style=\"text-align:justify;\"><strong>Jika Anda tertarik pada sejarah, budaya, dan pengalaman autentik, perjalanan ini menawarkan kesempatan langka untuk menyelami warisan peradaban Indonesia sekaligus merasakan pesona Kota Surabaya yang dinamis.</strong></h3>', '<h2 style=\"text-align:justify;\">2D/1N Heritage Trowulan Surabaya Tour</h2><p style=\"text-align:justify;\">Journey through the rich history and cultural heritage of East Java on an unforgettable experience that connects the legacy of the mighty <strong>Majapahit Kingdom</strong> with the vibrant spirit of modern-day Surabaya. This tour offers a fascinating glimpse into the civilizations, traditions, and historical events that have shaped Indonesia over centuries.</p><p style=\"text-align:justify;\">Travel back to an era when Majapahit stood as one of the most powerful kingdoms in Southeast Asia, leaving behind remarkable cultural and architectural achievements that continue to inspire generations today. Discover the stories of kings, ancient traditions, and a civilization that once influenced much of the Indonesian archipelago.</p><p style=\"text-align:justify;\">The experience continues in Surabaya, known as Indonesia’s <strong>\"City of Heroes,\"</strong> where history and modern life blend seamlessly. From colonial heritage and cultural landmarks to bustling city districts, visitors can gain a deeper understanding of the nation\'s journey from its glorious past to its dynamic present.</p><p style=\"text-align:justify;\">Perfect for families, cultural explorers, students, and history enthusiasts, this tour offers far more than sightseeing—it is an opportunity to connect with the roots of Indonesian civilization and experience the enduring legacy of East Java.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Explore the legacy of the legendary Majapahit Kingdom<br>✅ Discover East Java’s most important historical and cultural landmarks<br>✅ Learn about Indonesia’s rich heritage, traditions, and civilization<br>✅ Experience the unique blend of ancient history and modern urban culture<br>✅ Perfect for families, students, cultural travelers, and history enthusiasts<br>✅ Gain a deeper understanding of Indonesia beyond its natural attractions</p><h3 style=\"text-align:justify;\"><strong>If you\'re passionate about history, culture, and authentic local experiences, this journey offers a rare opportunity to walk through centuries of Indonesian heritage while discovering the heart and soul of East Java.</strong></h3>', '<h2 style=\"text-align:justify;\">2일 1박 트로울란 &amp; 수라바야 문화유산 투어</h2><p style=\"text-align:justify;\">동부 자바의 풍부한 역사와 문화를 경험하며, 위대한 <strong>마자파힛 왕국(Majapahit Kingdom)</strong> 의 유산과 현대 도시 수라바야의 매력을 함께 만나보세요. 이 특별한 여행은 수세기에 걸쳐 인도네시아를 형성해 온 역사와 전통, 그리고 문화적 가치를 깊이 있게 이해할 수 있는 기회를 제공합니다.</p><p style=\"text-align:justify;\">한때 동남아시아를 대표하는 강력한 제국이었던 마자파힛 왕국의 흔적을 따라가며, 당시의 문화와 건축, 그리고 인도네시아 역사에 남긴 영향력을 직접 느껴볼 수 있습니다. 왕국의 영광과 전설적인 이야기들은 오늘날에도 인도네시아 문화의 중요한 부분으로 남아 있습니다.</p><p style=\"text-align:justify;\">여정은 이어서 <strong>\"영웅의 도시(City of Heroes)\"</strong> 로 불리는 수라바야로 이어집니다. 역사적인 유산과 현대적인 도시 생활이 공존하는 이곳에서 인도네시아가 과거의 왕국 시대를 지나 현재의 국가로 발전해 온 과정을 더욱 생생하게 경험할 수 있습니다.</p><p style=\"text-align:justify;\">가족 여행객, 학생, 역사 애호가, 문화 탐방객 모두에게 의미 있고 교육적인 여행이 될 것입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 전설적인 마자파힛 왕국의 유산 탐방<br>✅ 동부 자바의 대표 역사·문화 명소 방문<br>✅ 인도네시아의 전통과 문명에 대한 깊이 있는 이해<br>✅ 고대 역사와 현대 도시 문화의 조화로운 경험<br>✅ 가족, 학생, 역사 및 문화 애호가에게 추천<br>✅ 자연 관광을 넘어 인도네시아를 더 깊이 이해할 수 있는 기회</p><h3 style=\"text-align:justify;\"><strong>인도네시아의 역사와 문화에 관심이 있다면, 이 여행은 위대한 문명의 흔적을 따라가며 수라바야의 현대적 매력까지 함께 경험할 수 있는 특별한 기회가 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">2天1夜 特罗乌兰与泗水文化遗产之旅</h2><p style=\"text-align:justify;\">开启一段穿越历史与文化的精彩旅程，探索辉煌的 <strong>满者伯夷王国（Majapahit Kingdom）</strong> 遗产，并感受现代泗水的独特魅力。这趟旅程将带您深入了解塑造印度尼西亚数百年历史的重要文明、传统与文化。</p><p style=\"text-align:justify;\">曾经统治东南亚广大地区的满者伯夷王国，被誉为印度尼西亚历史上最伟大的王国之一。通过探索其留下的文化遗产与历史印记，您将了解这个强大帝国的辉煌成就，以及它对印度尼西亚群岛历史发展的深远影响。</p><p style=\"text-align:justify;\">旅程随后来到被誉为 <strong>“英雄之城（City of Heroes）”</strong> 的泗水。在这里，历史遗产与现代都市生活和谐共存，让您更加全面地了解印度尼西亚从古代王国时代走向现代国家的发展历程。</p><p style=\"text-align:justify;\">这是一趟兼具文化价值与教育意义的旅程，非常适合家庭游客、学生、历史爱好者以及希望深入了解印尼文化的旅行者。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索传奇满者伯夷王国的辉煌遗产<br>✅ 参观东爪哇最重要的历史与文化景点<br>✅ 深入了解印度尼西亚丰富的传统与文明<br>✅ 感受古代历史与现代都市文化的完美结合<br>✅ 适合家庭、学生、历史爱好者及文化旅行者<br>✅ 从更深层次认识印度尼西亚，而不仅仅是自然风光</p><h3 style=\"text-align:justify;\"><strong>如果您热爱历史、文化与真实的人文体验，这趟旅程将带您穿越印尼辉煌的文明历史，同时感受泗水这座现代城市的独特魅力。</strong></h3>', 0.00, NULL, 2, 1, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\">1N at *4 Hotel (Surabaya) included breakfast&nbsp;</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Culture\",\"Historical\",\"Educational\",\"Heritage City Tour\",\"Family\"]', NULL, 0, NULL, '2026-06-02 13:17:12', '2026-06-02 13:17:24'),
(104, 48, '5 DAYS BEST OF EAST JAVA EXPERIENCE', 'SURABAYA', '5-days-best-of-east-java-experience', '<h2 style=\"text-align:justify;\">5D/4N Bromo – Malang Batu – Tumpak Sewu – Surabaya Tour</h2><p style=\"text-align:justify;\">Rasakan petualangan terbaik di Jawa Timur melalui perjalanan yang memadukan lanskap gunung berapi yang menakjubkan, air terjun megah, dataran tinggi yang sejuk, serta kekayaan budaya dan sejarah yang memikat. Dirancang bagi wisatawan yang ingin menikmati sisi terbaik Jawa Timur dalam satu perjalanan, tour ini menghadirkan kombinasi sempurna antara keindahan alam, petualangan, dan pengalaman budaya yang autentik.</p><p style=\"text-align:justify;\">Nikmati panorama pegunungan yang spektakuler, lembah hijau yang mempesona, serta berbagai keajaiban alam yang menjadikan Jawa Timur sebagai salah satu destinasi paling menarik di Indonesia. Setiap destinasi menawarkan pengalaman yang berbeda, mulai dari pemandangan alam yang luar biasa hingga suasana pedesaan dan kota yang penuh karakter.</p><p style=\"text-align:justify;\">Selain keindahan alamnya, perjalanan ini juga membawa Anda lebih dekat dengan budaya lokal, sejarah, dan kehidupan masyarakat Jawa Timur. Perpaduan antara destinasi ikonik dan hidden gems menciptakan pengalaman yang lengkap, beragam, dan berkesan.</p><p style=\"text-align:justify;\">Baik untuk pecinta alam, fotografer, pencari petualangan, pasangan, maupun keluarga, paket ini menawarkan keseimbangan sempurna antara eksplorasi, relaksasi, dan penemuan pengalaman baru setiap harinya.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi destinasi terbaik dan paling populer di Jawa Timur dalam satu perjalanan<br>✅ Menikmati perpaduan gunung berapi, air terjun, dataran tinggi, dan wisata budaya<br>✅ Mengunjungi beberapa lanskap alam paling spektakuler di Indonesia<br>✅ Cocok untuk fotografer, pecinta alam, pasangan, keluarga, dan pencari petualangan<br>✅ Menggabungkan destinasi ikonik dan hidden gems yang jarang ditemukan dalam satu paket<br>✅ Pengalaman perjalanan yang lengkap dengan kombinasi alam, budaya, dan kehidupan lokal</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari pengalaman paling lengkap untuk menjelajahi Jawa Timur, tour ini menawarkan kombinasi sempurna antara petualangan, keindahan alam, budaya, dan pengalaman yang akan selalu dikenang.</strong></h3>', '<h2 style=\"text-align:justify;\">5D/4N Bromo – Malang Batu – Tumpak Sewu – Surabaya Tour</h2><p style=\"text-align:justify;\">Experience the ultimate East Java adventure through a journey that combines breathtaking volcanic landscapes, majestic waterfalls, charming mountain towns, and rich cultural heritage. Designed for travelers who want to discover the very best of East Java in one unforgettable trip, this tour brings together some of Indonesia’s most iconic natural and cultural attractions.</p><p style=\"text-align:justify;\">Witness spectacular mountain scenery, explore dramatic landscapes shaped by volcanic activity, and immerse yourself in the refreshing atmosphere of East Java’s highlands. From panoramic viewpoints and lush valleys to picturesque countryside and vibrant cities, every destination offers a unique perspective on the region’s incredible diversity.</p><p style=\"text-align:justify;\">Beyond its natural beauty, this journey also introduces you to the cultural heart of East Java, where historic districts, local traditions, and authentic experiences provide a deeper connection to the people and stories that define the region.</p><p style=\"text-align:justify;\">Whether you\'re an adventure seeker, photographer, nature lover, or family traveler, this carefully crafted itinerary offers the perfect balance of exploration, relaxation, and discovery. Every day reveals a new landscape, a new experience, and another reason to fall in love with East Java.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover East Java\'s most famous destinations in one complete journey<br>✅ Experience volcanoes, waterfalls, highlands, countryside, and cultural heritage<br>✅ Enjoy some of Indonesia\'s most spectacular natural landscapes<br>✅ Perfect for photographers, adventure lovers, couples, and families<br>✅ Explore hidden gems and iconic attractions beyond the typical tourist route<br>✅ A well-balanced combination of nature, culture, and authentic local experiences</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for the most complete East Java experience, this journey offers an unforgettable blend of adventure, scenic beauty, culture, and discovery that showcases the very best the region has to offer.</strong></h3>', '<h2 style=\"text-align:justify;\">5일 4박 브로모 · 말랑 바투 · 뚬빡 세우 · 수라바야 투어</h2><p style=\"text-align:justify;\">화산, 폭포, 고원 지대, 그리고 풍부한 문화유산이 어우러진 동부 자바 최고의 여행을 경험해 보세요. 이 투어는 동부 자바의 대표적인 자연과 문화를 한 번에 즐길 수 있도록 구성된 특별한 여정으로, 다양한 매력을 가진 명소들을 통해 잊지 못할 추억을 선사합니다.</p><p style=\"text-align:justify;\">장엄한 화산 풍경과 아름다운 계곡, 시원한 고원 지역, 그리고 독특한 현지 문화를 경험하며 동부 자바의 진정한 매력을 발견할 수 있습니다. 여행하는 동안 매일 새로운 풍경과 특별한 경험이 기다리고 있어 지루할 틈이 없습니다.</p><p style=\"text-align:justify;\">자연경관뿐만 아니라 역사와 문화, 그리고 현지인들의 삶을 가까이에서 느낄 수 있는 기회도 제공하여 보다 깊이 있는 여행을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">모험을 좋아하는 여행객, 사진작가, 자연 애호가, 커플, 가족 모두에게 이상적인 여행으로, 탐험과 휴식이 완벽하게 조화를 이루는 일정입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바 최고의 명소를 한 번에 탐방<br>✅ 화산, 폭포, 고원, 문화유산을 모두 경험 가능<br>✅ 인도네시아에서 가장 아름다운 자연경관 감상<br>✅ 사진작가, 자연 애호가, 커플, 가족 여행객에게 추천<br>✅ 유명 관광지와 숨겨진 명소를 함께 탐험<br>✅ 자연과 문화, 현지 생활을 모두 경험할 수 있는 완벽한 일정</p><h3 style=\"text-align:justify;\"><strong>동부 자바를 가장 완벽하게 경험하고 싶다면, 이 투어는 자연의 경이로움과 문화적 매력을 모두 담은 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">5天4晚 布罗莫火山 · 玛琅巴图 · 图姆帕克塞乌瀑布 · 泗水之旅</h2><p style=\"text-align:justify;\">开启一场探索东爪哇精华的精彩旅程，感受壮丽火山、震撼瀑布、清凉高原以及丰富文化遗产所带来的独特魅力。本线路专为希望一次性深入体验东爪哇最佳景点的游客设计，将自然奇观、探险体验与文化探索完美结合。</p><p style=\"text-align:justify;\">在旅途中，您将欣赏壮观的火山景观、翠绿的山谷、高原风光以及充满特色的乡村与城市风貌。每一天都将呈现不同的景色与体验，让您充分感受到东爪哇丰富多样的自然与人文魅力。</p><p style=\"text-align:justify;\">除了令人惊叹的自然景观外，您还将有机会深入了解当地文化、历史传统以及居民的生活方式，从而更全面地认识这片充满活力的土地。</p><p style=\"text-align:justify;\">无论您是自然爱好者、摄影爱好者、探险旅行者、情侣还是家庭游客，这条线路都能为您带来探索、放松与发现并存的难忘旅程。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程探索东爪哇最具代表性的景点<br>✅ 同时体验火山、瀑布、高原与文化遗产<br>✅ 欣赏印度尼西亚最壮观的自然景观之一<br>✅ 适合摄影爱好者、自然爱好者、情侣及家庭游客<br>✅ 结合热门景点与鲜为人知的隐藏秘境<br>✅ 全面体验自然风光、文化传统与当地生活</p><h3 style=\"text-align:justify;\"><strong>如果您希望以最完整的方式探索东爪哇，那么这趟旅程将为您带来集探险、自然、美景与文化于一体的难忘体验。</strong></h3>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>4N at hotel included breakfast:</p><p>1N *4 Hotel (Malang), 1N *3 Hotel (Bromo/Tumpak sewu), 1N *4 Hotel (Banyuwangi) &amp; 1N *4 Hotel (Surabaya)</p><p>Note: Accomodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel&nbsp;</p></li><li data-list-item-id=\"ef906fa2f832b7a3f7fbe60875fe2fef3\">Bromo jeep</li><li data-list-item-id=\"e9637ad611785ce42c18ebb258403e4e1\">Ijen Masker &amp; Healthy form letter</li><li data-list-item-id=\"e2c6dc77b161085c0cabe68a6fd2529d4\">Tumpak Sewu local guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano Adventure\",\"Landscape\",\"Nature\",\"Waterfall\",\"Heritage\",\"Culture\",\"Family\"]', NULL, 0, NULL, '2026-06-02 13:48:50', '2026-06-02 13:48:50'),
(105, 48, '5 DAYS EAST JAVA VOLCANO & WATERFALL ADVENTURE', 'SURABAYA', '5-days-east-java-volcano-waterfall-adventure', '<h2 style=\"text-align:justify;\">5D/4N Bromo – Malang – Tumpak Sewu – Ijen – Surabaya Tour</h2><p style=\"text-align:justify;\">Nikmati petualangan terbaik di Jawa Timur melalui perjalanan luar biasa yang menghadirkan perpaduan sempurna antara gunung berapi yang megah, air terjun spektakuler, kota bersejarah, dan keajaiban alam yang mendunia. Dirancang untuk wisatawan yang ingin merasakan pengalaman paling lengkap di Jawa Timur, tour ini menggabungkan destinasi-destinasi ikonik dengan pengalaman budaya yang autentik dalam satu perjalanan yang tak terlupakan.</p><p style=\"text-align:justify;\">Dari panorama pegunungan yang dramatis hingga lembah tropis yang hijau, setiap hari menghadirkan pemandangan dan pengalaman yang berbeda. Anda akan menyaksikan keindahan alam yang menjadi kebanggaan Indonesia sekaligus menikmati suasana kota yang kaya akan sejarah dan budaya lokal.</p><p style=\"text-align:justify;\">Perjalanan ini menawarkan kombinasi sempurna antara petualangan, eksplorasi, dan relaksasi. Setiap destinasi dipilih secara khusus untuk memberikan pengalaman terbaik, mulai dari lanskap alam yang menakjubkan hingga warisan budaya yang memperkaya perjalanan Anda.</p><p style=\"text-align:justify;\">Sangat cocok bagi pecinta alam, fotografer, pasangan, keluarga, maupun pencari petualangan yang ingin menjelajahi sisi terbaik Jawa Timur dalam satu paket perjalanan yang lengkap.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengunjungi tiga ikon wisata alam paling terkenal di Jawa Timur dalam satu perjalanan<br>✅ Menikmati perpaduan gunung berapi, air terjun, pegunungan, dan wisata budaya<br>✅ Menyaksikan beberapa panorama alam paling spektakuler di Indonesia<br>✅ Mengunjungi destinasi favorit para fotografer dan pencinta alam<br>✅ Kombinasi sempurna antara petualangan, budaya, dan relaksasi<br>✅ Cocok untuk pasangan, keluarga, fotografer, dan wisatawan pencari pengalaman unik</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari perjalanan paling lengkap dan berkesan di Jawa Timur, tour ini menawarkan kombinasi sempurna antara keajaiban alam, kekayaan budaya, dan pengalaman luar biasa yang akan selalu dikenang.</strong></h3>', '<h2 style=\"text-align:justify;\">5D/4N Bromo – Malang – Tumpak Sewu – Ijen – Surabaya Tour</h2><p style=\"text-align:justify;\">Discover the ultimate East Java adventure through an extraordinary journey that showcases Indonesia\'s most spectacular volcanic landscapes, majestic waterfalls, cultural heritage, and unforgettable natural wonders. Designed for travelers seeking the perfect combination of adventure, scenery, and authentic local experiences, this tour brings together the very best that East Java has to offer.</p><p style=\"text-align:justify;\">From dramatic mountain panoramas and lush tropical valleys to charming heritage cities and breathtaking natural phenomena, every day unveils a completely different side of this remarkable region. Experience the thrill of exploring active volcanic landscapes, witness some of Indonesia\'s most iconic scenery, and immerse yourself in the rich culture and history that have shaped East Java for generations.</p><p style=\"text-align:justify;\">This carefully curated itinerary combines world-famous highlights with hidden natural treasures, creating a journey filled with discovery, excitement, and unforgettable moments. Whether you\'re capturing stunning photographs, exploring extraordinary landscapes, or simply enjoying the beauty of nature, every experience has been designed to leave a lasting impression.</p><p style=\"text-align:justify;\">Perfect for adventure seekers, photographers, couples, families, and nature enthusiasts, this tour delivers the most complete East Java experience in a single journey.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Visit East Java\'s three most iconic natural wonders in one trip<br>✅ Experience volcanoes, waterfalls, mountains, and cultural heritage destinations<br>✅ Witness some of Indonesia\'s most breathtaking landscapes and viewpoints<br>✅ Explore destinations recognized among the country\'s top photography locations<br>✅ Enjoy a perfect balance of adventure, nature, culture, and relaxation<br>✅ Ideal for couples, families, photographers, and adventure travelers</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for the most comprehensive and unforgettable journey through East Java, this tour offers an incredible combination of natural wonders, cultural treasures, and once-in-a-lifetime experiences that will stay with you long after the trip ends.</strong></h3>', '<h2 style=\"text-align:justify;\">5일 4박 브로모 · 말랑 · 뚬빡 세우 · 이젠 · 수라바야 투어</h2><p style=\"text-align:justify;\">동부 자바의 가장 아름다운 자연경관과 문화유산을 한 번에 경험할 수 있는 특별한 여행에 참여해 보세요. 웅장한 화산, 장대한 폭포, 역사적인 도시, 그리고 세계적으로 유명한 자연 명소들이 어우러진 이 투어는 동부 자바를 가장 완벽하게 탐험할 수 있는 일정으로 구성되어 있습니다.</p><p style=\"text-align:justify;\">거대한 화산 지형과 푸른 계곡, 열대 자연경관, 그리고 독특한 현지 문화를 경험하며 매일 새로운 감동을 만나게 됩니다. 자연의 경이로움과 함께 동부 자바의 역사와 문화를 깊이 있게 체험할 수 있는 특별한 기회를 제공합니다.</p><p style=\"text-align:justify;\">이 여정은 모험, 휴식, 문화 체험을 균형 있게 결합하여 모든 연령대의 여행객들이 만족할 수 있도록 설계되었습니다. 아름다운 풍경과 특별한 경험이 가득한 여행을 통해 잊지 못할 추억을 만들어 보세요.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바를 대표하는 3대 자연 명소 탐방<br>✅ 화산, 폭포, 산악지대, 문화유산을 한 번에 경험<br>✅ 인도네시아 최고의 자연경관과 전망 감상<br>✅ 사진작가와 자연 애호가들이 사랑하는 명소 방문<br>✅ 모험, 문화, 휴식이 완벽하게 조화를 이루는 일정<br>✅ 커플, 가족, 자연 애호가, 모험 여행객에게 추천</p><h3 style=\"text-align:justify;\"><strong>동부 자바를 가장 완벽하게 경험하고 싶다면, 이 투어는 자연의 경이로움과 문화적 매력을 모두 담은 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">5天4晚 布罗莫火山 · 玛琅 · 图姆帕克塞乌瀑布 · 宜珍火山 · 泗水之旅</h2><p style=\"text-align:justify;\">开启一场探索东爪哇精华景点的非凡旅程，体验壮丽火山、震撼瀑布、历史名城以及世界级自然奇观所带来的独特魅力。本线路专为希望深度体验东爪哇的游客打造，将当地最具代表性的自然与文化景观完美融合于一次难忘的旅行之中。</p><p style=\"text-align:justify;\">从雄伟壮观的火山景观到郁郁葱葱的热带山谷，从迷人的历史文化到令人惊叹的自然奇观，每一天都将带给您全新的视觉震撼与旅行体验。您不仅能够欣赏东爪哇最著名的自然景观，还能深入了解当地丰富的文化与历史底蕴。</p><p style=\"text-align:justify;\">这趟旅程将探险、观光与休闲完美结合，为每位游客带来丰富而充实的体验。无论是壮观的自然风光，还是独特的人文魅力，都将成为您旅途中难以忘怀的精彩回忆。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程探访东爪哇三大标志性自然奇观<br>✅ 同时体验火山、瀑布、山地景观与文化遗产<br>✅ 欣赏印度尼西亚最壮丽的自然景观之一<br>✅ 打卡摄影爱好者和自然爱好者最向往的目的地<br>✅ 完美结合探险、文化体验与休闲度假<br>✅ 适合情侣、家庭、摄影爱好者及探险旅行者</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一次最全面、最精彩的东爪哇之旅，那么这条线路将为您呈现壮丽自然、深厚文化与难忘体验的完美结合，让每一刻都值得珍藏。</strong></h3><p style=\"text-align:justify;\">&nbsp;</p>', 0.00, NULL, 5, 4, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>4N at hotel included breakfast:</p><p>1N *4 Hotel (Malang), 1N *3 Hotel (Bromo/Tumpak sewu), 1N *4 Hotel (Banyuwangi) &amp; 1N *4 Hotel (Surabaya)</p><p>Note: Accomodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel&nbsp;</p></li><li data-list-item-id=\"ef906fa2f832b7a3f7fbe60875fe2fef3\">Bromo jeep</li><li data-list-item-id=\"e9637ad611785ce42c18ebb258403e4e1\">Ijen Masker &amp; Healthy form letter</li><li data-list-item-id=\"e2c6dc77b161085c0cabe68a6fd2529d4\">Tumpak Sewu local guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Waterfall\",\"Adventure\",\"Landscape\",\"Nature\",\"Photography\",\"HERITAGE\",\"Culture\"]', NULL, 0, NULL, '2026-06-02 14:04:41', '2026-06-02 14:04:41'),
(106, 48, '4 DAYS BEST OF BANYUWANGI EXPERIENCE', 'BANYUWANGI', '4-days-best-of-banyuwangi-experience', '<h2 style=\"text-align:justify;\">4D/3N Banyuwangi Adventure Tour</h2><p style=\"text-align:justify;\">Temukan keajaiban Banyuwangi, sebuah destinasi yang menawarkan perpaduan sempurna antara pulau tropis, pantai eksotis, taman nasional yang kaya satwa liar, serta lanskap vulkanik yang spektakuler. Terletak di ujung timur Pulau Jawa, Banyuwangi menjadi salah satu destinasi wisata paling menarik di Indonesia bagi para pencinta alam dan petualangan.</p><p style=\"text-align:justify;\">Perjalanan ini menghadirkan pengalaman yang beragam dan penuh kejutan. Dari laut biru yang jernih, pantai-pantai alami yang menawan, hingga hamparan savana yang luas dan pegunungan yang megah, setiap hari akan membawa Anda menemukan sisi berbeda dari keindahan Banyuwangi.</p><p style=\"text-align:justify;\">Tidak hanya menawarkan panorama alam yang memukau, tour ini juga memberikan kesempatan untuk menikmati aktivitas luar ruangan yang seru, menjelajahi ekosistem yang unik, dan merasakan suasana alam yang masih terjaga keasriannya.</p><p style=\"text-align:justify;\">Sangat cocok bagi pecinta alam, fotografer, pasangan, keluarga, maupun pencari petualangan yang ingin menikmati pengalaman terbaik Banyuwangi dalam satu perjalanan yang lengkap.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menikmati pantai, pulau, satwa liar, dan gunung berapi dalam satu perjalanan<br>✅ Menjelajahi beberapa lanskap pesisir dan laut terindah di Indonesia<br>✅ Mengunjungi ekosistem yang beragam, mulai dari hutan tropis hingga savana terbuka<br>✅ Menikmati pengalaman snorkeling dan keindahan alam kelas dunia<br>✅ Menyaksikan salah satu fenomena vulkanik paling terkenal di Indonesia<br>✅ Cocok untuk fotografer, pecinta alam, pasangan, keluarga, dan pencari petualangan</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari destinasi yang menggabungkan keindahan pantai tropis, petualangan alam, kehidupan liar, dan keajaiban vulkanik dalam satu perjalanan, Banyuwangi menawarkan pengalaman yang sulit ditemukan di tempat lain di Indonesia.</strong></h3>', '<h2 style=\"text-align:justify;\">4D/3N Banyuwangi Adventure Tour</h2><p style=\"text-align:justify;\">Discover the extraordinary diversity of Banyuwangi, a destination where tropical islands, pristine beaches, wildlife-rich national parks, and spectacular volcanic landscapes come together to create one of Indonesia’s most exciting adventure experiences.</p><p style=\"text-align:justify;\">Located on the eastern tip of Java Island, Banyuwangi is a paradise for travelers seeking more than just a typical holiday. This journey combines breathtaking natural beauty, outdoor exploration, and unforgettable encounters with some of the region’s most iconic landscapes. From crystal-clear seas and untouched coastal scenery to dramatic mountain views and unique ecosystems, every day reveals a different side of this remarkable destination.</p><p style=\"text-align:justify;\">Whether you\'re snorkeling in turquoise waters, exploring vast savannahs, discovering hidden beaches, or witnessing world-famous volcanic phenomena, this adventure offers the perfect balance of excitement, relaxation, and discovery.</p><p style=\"text-align:justify;\">Ideal for nature lovers, photographers, couples, families, and adventure seekers, this carefully designed itinerary showcases why Banyuwangi has become one of Indonesia’s fastest-growing tourism destinations and a favorite among both domestic and international travelers.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Experience beaches, islands, wildlife, and volcanoes in one complete journey<br>✅ Discover some of Indonesia’s most beautiful coastal and marine landscapes<br>✅ Explore unique ecosystems ranging from tropical forests to open savannahs<br>✅ Enjoy world-class snorkeling and breathtaking natural scenery<br>✅ Witness one of the most famous volcanic attractions in Indonesia<br>✅ Perfect for photographers, nature lovers, couples, families, and adventure travelers</p><h3 style=\"text-align:justify;\"><strong>If you\'re searching for a destination that combines tropical beauty, wildlife encounters, marine adventures, and extraordinary natural wonders, Banyuwangi offers an unforgettable journey filled with experiences that few places in Indonesia can match.</strong></h3>', '<h2 style=\"text-align:justify;\">4일 3박 반유왕이 어드벤처 투어</h2><p style=\"text-align:justify;\">열대 섬, 아름다운 해변, 야생동물이 서식하는 국립공원, 그리고 웅장한 화산 풍경이 어우러진 반유왕이의 매력을 경험해 보세요. 자바섬 동쪽 끝에 위치한 반유왕이는 자연과 모험을 사랑하는 여행자들에게 최고의 여행지로 손꼽히고 있습니다.</p><p style=\"text-align:justify;\">이 여행은 맑고 푸른 바다, 아름다운 해안선, 광활한 사바나, 그리고 장엄한 화산 풍경까지 다양한 자연의 모습을 한 번에 경험할 수 있는 특별한 기회를 제공합니다. 매일 새로운 풍경과 색다른 경험이 기다리고 있어 여행의 즐거움을 더욱 높여줍니다.</p><p style=\"text-align:justify;\">자연 속에서의 휴식은 물론, 다양한 야외 활동과 독특한 생태계를 탐험하며 반유왕이의 진정한 매력을 발견할 수 있습니다.</p><p style=\"text-align:justify;\">자연 애호가, 사진작가, 커플, 가족, 그리고 모험을 즐기는 모든 여행객에게 이상적인 일정입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 해변, 섬, 야생동물, 화산을 한 번에 경험<br>✅ 인도네시아 최고의 해양 및 해안 풍경 감상<br>✅ 열대우림부터 사바나까지 다양한 생태계 탐방<br>✅ 세계적인 수준의 스노클링과 자연경관 체험<br>✅ 인도네시아를 대표하는 화산 명소 방문<br>✅ 사진작가, 자연 애호가, 가족, 커플, 모험가에게 추천</p><h3 style=\"text-align:justify;\"><strong>열대 해변과 자연 탐험, 야생 생태계, 그리고 특별한 화산 경관을 모두 경험하고 싶다면 반유왕이는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">4天3晚 外南梦探险之旅</h2><p style=\"text-align:justify;\">探索外南梦（Banyuwangi）的非凡魅力，这里汇聚了热带岛屿、迷人海滩、野生动物丰富的国家公园以及壮观的火山景观。作为爪哇岛最东端最受欢迎的旅游目的地之一，外南梦为热爱自然与探险的游客提供了丰富而难忘的旅行体验。</p><p style=\"text-align:justify;\">这趟旅程将带您领略清澈蔚蓝的大海、原生态海岸风光、广阔的热带草原以及壮丽的火山地貌。每天都能发现不同的景观与惊喜，让您全方位感受外南梦丰富多样的自然魅力。</p><p style=\"text-align:justify;\">除了令人赞叹的风景之外，您还可以体验精彩的户外活动，探索独特的生态环境，并沉浸在保存完好的自然世界之中。</p><p style=\"text-align:justify;\">无论您是自然爱好者、摄影爱好者、情侣、家庭游客，还是热衷探险的旅行者，这条线路都将为您带来一次充满惊喜与感动的难忘旅程。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程体验海滩、岛屿、野生动物与火山奇观<br>✅ 探索印度尼西亚最迷人的海岸与海洋景观<br>✅ 体验从热带雨林到辽阔草原的多样生态系统<br>✅ 享受世界级浮潜与壮丽自然风光<br>✅ 参观印度尼西亚最著名的火山景点之一<br>✅ 适合摄影爱好者、自然爱好者、情侣、家庭及探险旅行者</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一个融合热带海岛、自然探险、野生生态与火山奇观的目的地，那么外南梦将为您带来一场精彩而难忘的旅程。</strong></h3>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\">3N at *4 Hotel (Banyuwangi) included breakfast</li><li data-list-item-id=\"e042ec151af76d020653167c917bb53bc\">Boat for Menjangan island tour</li><li data-list-item-id=\"e9637ad611785ce42c18ebb258403e4e1\">Ijen Masker &amp; Healthy form letter</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Island Hopping\",\"Nature\",\"Adventure\",\"Beach\",\"Volcano\",\"Wildlife\",\"Photography\",\"Family\"]', NULL, 0, NULL, '2026-06-02 14:22:34', '2026-06-02 14:22:34'),
(107, 48, '4 DAYS EAST JAVA NATURE EXPLORER', 'SURABAYA', '4-days-east-java-nature-explorer', '<h2 style=\"text-align:justify;\">4D/3N Bromo – Malang Hidden Beach – Batu – Tumpak Sewu Tour</h2><p style=\"text-align:justify;\">Nikmati perjalanan luar biasa yang membawa Anda menjelajahi berbagai lanskap terbaik Jawa Timur dalam satu petualangan yang tak terlupakan. Mulai dari pantai-pantai eksotis yang tersembunyi, air terjun megah yang memukau, pegunungan vulkanik yang ikonik, hingga dataran tinggi yang sejuk dan menenangkan, setiap hari menghadirkan pengalaman yang berbeda dan penuh kejutan.</p><p style=\"text-align:justify;\">Tour ini dirancang bagi wisatawan yang ingin menikmati keindahan alam Jawa Timur secara lebih lengkap, jauh dari sekadar destinasi wisata biasa. Anda akan menemukan pesona garis pantai Samudera Hindia yang dramatis, lembah-lembah hijau yang subur, panorama pegunungan yang menakjubkan, serta berbagai sudut alam yang menawarkan keindahan luar biasa dan pengalaman yang sulit dilupakan.</p><p style=\"text-align:justify;\">Selain menyuguhkan pemandangan spektakuler, perjalanan ini juga memberikan kesempatan untuk menikmati suasana pedesaan, udara pegunungan yang segar, serta berbagai destinasi yang menjadi favorit para fotografer dan pencinta alam.</p><p style=\"text-align:justify;\">Sangat cocok bagi pasangan, keluarga, fotografer, maupun pencari petualangan yang ingin merasakan keberagaman alam Jawa Timur dalam satu perjalanan yang lengkap dan berkesan.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menikmati pantai, air terjun, gunung berapi, dan dataran tinggi dalam satu perjalanan<br>✅ Mengunjungi hidden gems dan destinasi paling ikonik di Jawa Timur<br>✅ Menyaksikan panorama alam yang spektakuler dan sangat fotogenik<br>✅ Menjelajahi berbagai lanskap mulai dari pesisir tropis hingga pegunungan vulkanik<br>✅ Cocok untuk pasangan, keluarga, fotografer, dan pecinta petualangan<br>✅ Kombinasi sempurna antara eksplorasi alam, petualangan, dan relaksasi</p><h3 style=\"text-align:justify;\"><strong>Jika Anda ingin merasakan keindahan Jawa Timur yang sesungguhnya, tour ini menghadirkan perpaduan sempurna antara pantai tersembunyi, air terjun spektakuler, dataran tinggi yang menawan, dan gunung berapi yang mendunia dalam satu perjalanan yang luar biasa.</strong></h3>', '<h2 style=\"text-align:justify;\">4D/3N Bromo – Malang Hidden Beach – Batu – Tumpak Sewu Tour</h2><p style=\"text-align:justify;\">Experience an unforgettable journey through East Java’s most spectacular natural landscapes, where pristine coastlines, towering waterfalls, volcanic wonders, and refreshing mountain highlands come together in one extraordinary adventure.</p><p style=\"text-align:justify;\">This carefully designed tour takes you beyond the typical tourist route, revealing a diverse collection of breathtaking scenery that showcases the incredible beauty of East Java. From hidden tropical beaches and dramatic ocean cliffs to lush valleys and panoramic mountain vistas, every destination offers a completely different experience and a new perspective of Indonesia’s natural richness.</p><p style=\"text-align:justify;\">Along the way, discover charming highland towns, scenic countryside, and some of the region’s most photogenic locations. Whether you\'re watching the sunrise above volcanic peaks, admiring the power of nature at one of Indonesia’s most impressive waterfalls, or simply enjoying the peaceful atmosphere of East Java’s highlands, every moment is designed to inspire and amaze.</p><p style=\"text-align:justify;\">Perfect for nature lovers, photographers, couples, families, and adventure seekers, this tour delivers a balanced combination of exploration, relaxation, and unforgettable scenery.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Experience beaches, waterfalls, volcanoes, and mountain landscapes in one journey<br>✅ Explore some of East Java\'s most beautiful hidden gems and iconic destinations<br>✅ Enjoy spectacular natural scenery and world-class photography opportunities<br>✅ Discover diverse landscapes ranging from tropical coastlines to volcanic highlands<br>✅ Perfect for couples, families, photographers, and adventure travelers<br>✅ A complete East Java experience combining nature, adventure, and relaxation</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for an adventure that showcases the incredible diversity of East Java, this tour offers an unforgettable collection of landscapes and experiences that will leave you with memories for a lifetime.</strong></h3>', '<h2 style=\"text-align:justify;\">4일 3박 브로모 · 말랑 히든 비치 · 바투 · 뚬빡 세우 투어</h2><p style=\"text-align:justify;\">동부 자바의 가장 아름다운 자연을 한 번에 경험할 수 있는 특별한 여행에 여러분을 초대합니다. 숨겨진 열대 해변, 웅장한 폭포, 상징적인 화산 풍경, 그리고 시원한 고원지대가 어우러진 이 여행은 동부 자바의 다채로운 매력을 완벽하게 보여줍니다.</p><p style=\"text-align:justify;\">이 투어는 단순한 관광을 넘어 동부 자바의 다양한 자연경관을 깊이 있게 체험할 수 있도록 설계되었습니다. 드라마틱한 인도양 해안선, 푸른 계곡, 장엄한 산악 풍경, 그리고 자연 그대로의 아름다움이 여러분을 기다리고 있습니다.</p><p style=\"text-align:justify;\">또한 아름다운 풍경뿐만 아니라 한적한 시골 마을의 분위기와 상쾌한 산악 지역의 공기까지 경험할 수 있어 더욱 특별한 여행이 됩니다.</p><p style=\"text-align:justify;\">자연을 사랑하는 여행객, 사진작가, 커플, 가족, 그리고 모험을 즐기는 모든 분들에게 추천하는 최고의 일정입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 해변, 폭포, 화산, 고원지대를 한 번에 경험<br>✅ 동부 자바의 숨겨진 명소와 대표 관광지 탐방<br>✅ 환상적인 자연경관과 최고의 사진 촬영 기회 제공<br>✅ 열대 해안부터 화산 지대까지 다양한 풍경 감상<br>✅ 커플, 가족, 사진작가, 모험 여행객에게 추천<br>✅ 자연 탐험과 휴식이 완벽하게 조화를 이루는 일정</p><h3 style=\"text-align:justify;\"><strong>동부 자바의 진정한 아름다움을 경험하고 싶다면, 이 투어는 숨겨진 해변과 장대한 폭포, 아름다운 고원, 그리고 세계적으로 유명한 화산을 모두 만날 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">4天3晚 布罗莫火山 · 玛琅秘境海滩 · 巴图高原 · 图姆帕克塞乌瀑布之旅</h2><p style=\"text-align:justify;\">踏上一段探索东爪哇壮丽自然风光的精彩旅程，在一次旅行中感受隐秘海滩、壮观瀑布、火山奇观以及清凉高原所带来的独特魅力。每一天都将呈现不同的风景与体验，让您充分领略东爪哇丰富多样的自然之美。</p><p style=\"text-align:justify;\">这条线路专为希望深入探索东爪哇的游客打造，不仅涵盖著名景点，还带您发现许多鲜为人知却令人惊艳的自然秘境。从壮丽的印度洋海岸线到翠绿山谷，从迷人的高原风光到令人震撼的火山景观，每一个角落都展现着东爪哇独特的魅力。</p><p style=\"text-align:justify;\">除了丰富的自然景观之外，您还将感受到宁静的乡村氛围和宜人的高山气候，为旅程增添更多舒适与放松的体验。</p><p style=\"text-align:justify;\">无论您是自然爱好者、摄影爱好者、情侣、家庭游客还是热爱探险的旅行者，这条线路都能为您带来一次难忘而充实的旅行体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程体验海滩、瀑布、火山与高原景观<br>✅ 探索东爪哇最具代表性的景点与隐藏秘境<br>✅ 欣赏壮丽自然风光与绝佳摄影场景<br>✅ 体验从热带海岸到火山山区的丰富地貌变化<br>✅ 适合情侣、家庭、摄影爱好者及探险旅行者<br>✅ 完美结合自然探索、冒险体验与轻松度假</p><h3 style=\"text-align:justify;\"><strong>如果您想深入感受东爪哇最迷人的自然魅力，这趟旅程将带您走进隐秘海滩、壮观瀑布、迷人高原与世界级火山景观，共同谱写一段难忘的旅行回忆。</strong></h3>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>3N at hotel included breakfast:</p><p>1N Hotel (Tumpak sewu), 1N *4 Hotel (Malang), 1N Hotel (Bromo) &amp; 1N *4 Hotel (Banyuwangi)</p><p>Note: Accomodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel&nbsp;</p></li><li data-list-item-id=\"ef906fa2f832b7a3f7fbe60875fe2fef3\">Bromo jeep</li><li data-list-item-id=\"e2c6dc77b161085c0cabe68a6fd2529d4\">Tumpak Sewu local guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Adventure\",\"Waterfall\",\"Beach\",\"Photography\",\"Nature\",\"Family\"]', NULL, 0, NULL, '2026-06-02 14:37:43', '2026-06-02 14:37:43');
INSERT INTO `indonesia_destinations` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `interest_tags`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(108, 48, '4 DAYS EAST JAVA BUCKET LIST EXPERIENCE', 'SURABAYA', '4-days-east-java-bucket-list-experience', '<h2 style=\"text-align:justify;\">4D/3N Bromo – Malang – Tumpak Sewu – Ijen Tour</h2><p style=\"text-align:justify;\">Rasakan petualangan luar biasa menjelajahi keajaiban alam terbaik Jawa Timur, di mana gunung berapi yang megah, air terjun yang spektakuler, panorama pegunungan yang memukau, dan pengalaman matahari terbit yang tak terlupakan berpadu dalam satu perjalanan yang istimewa.</p><p style=\"text-align:justify;\">Tour ini dirancang khusus bagi wisatawan yang ingin menikmati destinasi paling ikonik di Jawa Timur dalam waktu yang efisien tanpa melewatkan pengalaman terbaik yang ditawarkan daerah ini. Setiap hari menghadirkan pemandangan yang berbeda, mulai dari lanskap vulkanik yang dramatis, lembah hijau yang menenangkan, hingga fenomena alam yang terkenal di dunia.</p><p style=\"text-align:justify;\">Selain keindahan alamnya, perjalanan ini juga memberikan kesempatan untuk merasakan keramahan masyarakat lokal, budaya khas Jawa Timur, dan pengalaman autentik yang membuat perjalanan menjadi lebih bermakna. Perpaduan antara petualangan, keindahan alam, dan pengalaman budaya menciptakan perjalanan yang lengkap dan berkesan.</p><p style=\"text-align:justify;\">Baik bagi pecinta alam, fotografer, pasangan, keluarga, maupun pencari petualangan, paket ini menawarkan pengalaman yang akan menjadi salah satu momen terbaik dalam perjalanan Anda di Indonesia.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengunjungi destinasi alam paling terkenal di Jawa Timur dalam satu perjalanan<br>✅ Menikmati perpaduan gunung berapi, air terjun, pegunungan, dan panorama alam yang menakjubkan<br>✅ Menyaksikan lokasi matahari terbit dan spot fotografi terbaik di Indonesia<br>✅ Kombinasi sempurna antara petualangan, alam, dan pengalaman budaya<br>✅ Cocok untuk pasangan, keluarga, fotografer, dan pencinta petualangan<br>✅ Salah satu paket wisata Jawa Timur yang paling lengkap dan populer</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari perjalanan yang dipenuhi pemandangan spektakuler, petualangan tak terlupakan, dan pengalaman yang hanya bisa didapat sekali seumur hidup, tour ini adalah pilihan sempurna untuk menjelajahi keajaiban alam Jawa Timur.</strong></h3>', '<h2 style=\"text-align:justify;\">4D/3N Bromo – Malang – Tumpak Sewu – Ijen Tour</h2><p style=\"text-align:justify;\">Embark on an extraordinary journey through East Java’s most breathtaking natural wonders, where towering volcanoes, dramatic waterfalls, lush mountain landscapes, and unforgettable sunrise experiences come together in one incredible adventure.</p><p style=\"text-align:justify;\">This carefully crafted tour is designed for travelers who want to experience the very best of East Java in a limited time without missing its most iconic highlights. From spectacular panoramic views and refreshing highland scenery to awe-inspiring geological formations and world-renowned natural phenomena, every day offers a new and unforgettable experience.</p><p style=\"text-align:justify;\">Beyond the stunning landscapes, this journey also reveals the unique character of East Java through its rich cultural heritage, welcoming local communities, and authentic travel experiences. The combination of adventure, natural beauty, and cultural discovery creates a perfect balance for travelers seeking more than just sightseeing.</p><p style=\"text-align:justify;\">Whether you\'re chasing epic sunrises, capturing extraordinary photographs, exploring remarkable landscapes, or simply enjoying the beauty of nature, this tour delivers an unforgettable experience from beginning to end.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Explore East Java’s most famous natural attractions in one seamless journey<br>✅ Experience spectacular volcanoes, waterfalls, mountains, and scenic landscapes<br>✅ Witness some of Indonesia’s most iconic sunrise and photography locations<br>✅ Enjoy a perfect blend of adventure, nature, and cultural experiences<br>✅ Ideal for couples, families, photographers, and adventure enthusiasts<br>✅ One of the most complete and popular East Java tour packages available</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a journey filled with stunning scenery, unforgettable adventures, and once-in-a-lifetime experiences, this tour offers the perfect introduction to the natural wonders that make East Java one of Indonesia’s most remarkable destinations.</strong></h3>', '<h2 style=\"text-align:justify;\">4일 3박 브로모 · 말랑 · 뚬빡 세우 · 이젠 투어</h2><p style=\"text-align:justify;\">동부 자바의 가장 아름다운 자연 명소를 탐험하며 웅장한 화산, 장대한 폭포, 아름다운 산악 풍경, 그리고 잊을 수 없는 일출을 경험해 보세요. 이 특별한 여행은 동부 자바의 대표적인 자연경관을 한 번에 즐길 수 있도록 구성된 최고의 어드벤처 투어입니다.</p><p style=\"text-align:justify;\">짧은 일정 안에서도 동부 자바의 핵심 명소를 모두 경험할 수 있도록 설계된 이 여행은 매일 새로운 풍경과 감동을 선사합니다. 웅장한 화산 지형, 푸른 계곡, 아름다운 자연경관, 그리고 세계적으로 유명한 자연 현상까지 다양한 매력을 만날 수 있습니다.</p><p style=\"text-align:justify;\">또한 자연경관뿐만 아니라 동부 자바의 문화와 현지인들의 따뜻한 환대도 함께 경험할 수 있어 더욱 의미 있는 여행이 됩니다. 자연, 모험, 문화가 조화를 이루는 완벽한 일정으로 구성되어 있습니다.</p><p style=\"text-align:justify;\">자연 애호가, 사진작가, 커플, 가족, 그리고 모험을 즐기는 여행객 모두에게 추천하는 최고의 여행입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바 최고의 자연 명소를 한 번에 탐방<br>✅ 화산, 폭포, 산악 풍경과 아름다운 자연경관 체험<br>✅ 인도네시아 최고의 일출 명소와 사진 촬영지 방문<br>✅ 모험, 자연, 문화 체험이 완벽하게 조화를 이루는 일정<br>✅ 커플, 가족, 사진작가, 모험 여행객에게 추천<br>✅ 동부 자바에서 가장 인기 있고 완성도 높은 여행 상품</p><h3 style=\"text-align:justify;\"><strong>장엄한 자연과 특별한 모험, 그리고 평생 기억에 남을 경험을 원한다면 이 투어는 동부 자바의 진정한 매력을 발견할 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">4天3晚 布罗莫火山 · 玛琅 · 图姆帕克塞乌瀑布 · 宜珍火山之旅</h2><p style=\"text-align:justify;\">开启一段探索东爪哇自然奇观的精彩旅程，在壮丽火山、震撼瀑布、迷人山地风光以及难忘日出景色之间，感受大自然最震撼的魅力。这条线路专为希望在有限时间内深度体验东爪哇精华景点的游客打造，将当地最具代表性的自然景观完美结合于一次难忘的旅行之中。</p><p style=\"text-align:justify;\">旅途中，您将欣赏到壮观的火山地貌、翠绿山谷、辽阔自然景观以及世界闻名的自然奇观。每天都能体验截然不同的风景与感受，让旅程充满惊喜与感动。</p><p style=\"text-align:justify;\">除了令人惊叹的自然美景外，您还将感受到东爪哇独特的人文魅力、当地居民的热情好客以及丰富的文化底蕴。探险、自然与文化的完美结合，使这趟旅程更加丰富而有意义。</p><p style=\"text-align:justify;\">无论您是自然爱好者、摄影爱好者、情侣、家庭游客还是热爱探险的旅行者，这条线路都将带给您一次终生难忘的东爪哇体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程探索东爪哇最著名的自然景点<br>✅ 同时体验火山、瀑布、山地景观与壮丽自然风光<br>✅ 参观印度尼西亚最著名的日出观景点与摄影圣地<br>✅ 完美融合探险体验、自然风光与文化探索<br>✅ 适合情侣、家庭、摄影爱好者及探险旅行者<br>✅ 东爪哇最受欢迎且内容最丰富的旅游线路之一</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一场充满壮丽景色、精彩探险以及毕生难忘回忆的旅行，那么这条线路将带您深入探索东爪哇最令人惊叹的自然奇观。</strong></h3>', 0.00, NULL, 4, 3, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>3N at hotel included breakfast:</p><p>1N *4 Hotel (Malang), 1N Hotel (Bromo/Tumpak sewu) &amp; 1N *4 Hotel (Banyuwangi)</p><p>Note: Accomodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel&nbsp;</p></li><li data-list-item-id=\"ef906fa2f832b7a3f7fbe60875fe2fef3\">Bromo jeep</li><li data-list-item-id=\"e9637ad611785ce42c18ebb258403e4e1\">Ijen Masker &amp; Healthy form letter</li><li data-list-item-id=\"e2c6dc77b161085c0cabe68a6fd2529d4\">Tumpak Sewu local guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Adventure\",\"WaterfalL\",\"Nature\",\"Landscape\",\"Photography\",\"Cultural\",\"Sunrise\",\"Family\"]', NULL, 0, NULL, '2026-06-02 14:53:47', '2026-06-02 14:53:47'),
(109, 48, '3 DAYS VOLCANO & WATERFALL ESCAPE', 'SURABAYA', '3-days-volcano-waterfall-escape', '<h2 style=\"text-align:justify;\">3D/2N Tumpak Sewu &amp; Bromo Adventure Tour</h2><p style=\"text-align:justify;\">Temukan dua keajaiban alam paling spektakuler di Jawa Timur dalam satu perjalanan yang tak terlupakan. Tour ini memadukan lanskap vulkanik yang megah, air terjun yang menakjubkan, panorama pegunungan yang indah, serta pengalaman menyaksikan matahari terbit yang terkenal di dunia, menjadikannya pilihan sempurna bagi pecinta alam, fotografer, dan pencari petualangan.</p><p style=\"text-align:justify;\">Dirancang untuk wisatawan yang menginginkan liburan singkat namun penuh pengalaman berkesan, perjalanan ini menampilkan keberagaman alam Jawa Timur yang luar biasa. Dari lembah-lembah yang diselimuti kabut, air terjun yang menjulang tinggi, hingga hamparan lanskap vulkanik yang dramatis, setiap destinasi menawarkan suasana dan pengalaman yang berbeda.</p><p style=\"text-align:justify;\">Baik saat menikmati keindahan salah satu air terjun terbaik di Indonesia, menyaksikan matahari terbit di atas pegunungan vulkanik, maupun sekadar menikmati ketenangan alam yang masih asri, setiap momen dalam perjalanan ini akan memberikan kenangan yang sulit dilupakan.</p><p style=\"text-align:justify;\">Cocok untuk pasangan, keluarga, fotografer, maupun wisatawan yang ingin menikmati petualangan alam terbaik dalam waktu yang singkat.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Mengunjungi dua destinasi alam paling ikonik di Jawa Timur dalam satu perjalanan<br>✅ Menikmati perpaduan air terjun spektakuler, gunung berapi, dan panorama pegunungan<br>✅ Menyaksikan salah satu pengalaman matahari terbit terbaik di Indonesia<br>✅ Mengabadikan momen di berbagai spot fotografi alam kelas dunia<br>✅ Cocok untuk pecinta alam, pasangan, keluarga, dan pencari petualangan<br>✅ Pilihan ideal bagi wisatawan dengan waktu terbatas namun ingin mendapatkan pengalaman maksimal</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari perjalanan singkat yang dipenuhi pemandangan luar biasa, pengalaman tak terlupakan, dan keindahan alam terbaik Indonesia, tour ini adalah pilihan yang sempurna untuk menjelajahi pesona Jawa Timur.</strong></h3>', '<h2 style=\"text-align:justify;\">3D/2N Tumpak Sewu &amp; Bromo Adventure Tour</h2><p style=\"text-align:justify;\">Discover two of East Java\'s most breathtaking natural wonders in one unforgettable adventure. This journey combines dramatic volcanic landscapes, towering waterfalls, lush mountain scenery, and world-famous sunrise experiences, creating the perfect getaway for travelers who love nature, photography, and outdoor exploration.</p><p style=\"text-align:justify;\">Designed for those seeking a short yet rewarding escape, this tour showcases the incredible diversity of East Java\'s landscapes. From misty valleys and cascading waterfalls to vast volcanic plains and panoramic mountain views, every destination offers a completely different atmosphere and a new sense of wonder.</p><p style=\"text-align:justify;\">Whether you\'re standing before one of Indonesia\'s most spectacular waterfalls, watching the first rays of sunlight illuminate a volcanic horizon, or simply taking in the beauty of untouched nature, each moment is filled with unforgettable memories and stunning photo opportunities.</p><p style=\"text-align:justify;\">Perfect for couples, families, photographers, and adventure enthusiasts, this experience offers the ideal balance between exploration, scenic beauty, and comfortable travel.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Explore two of East Java\'s most iconic natural attractions in one trip<br>✅ Experience spectacular waterfalls, volcanoes, mountains, and scenic landscapes<br>✅ Enjoy one of Indonesia\'s most famous sunrise experiences<br>✅ Capture incredible photographs at world-class natural locations<br>✅ Perfect for nature lovers, couples, families, and adventure travelers<br>✅ Ideal short getaway with maximum experiences and minimal travel days</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for an adventure filled with stunning scenery, unforgettable moments, and some of the most beautiful landscapes in Indonesia, this journey offers the perfect introduction to the natural wonders of East Java.</strong></h3>', '<h2 style=\"text-align:justify;\">3일 2박 뚬빡 세우 &amp; 브로모 어드벤처 투어</h2><p style=\"text-align:justify;\">동부 자바를 대표하는 두 개의 자연 명소를 한 번에 경험할 수 있는 특별한 여행에 참여해 보세요. 웅장한 화산 풍경, 장대한 폭포, 아름다운 산악 지형, 그리고 세계적으로 유명한 일출이 어우러진 이 여행은 자연과 사진, 모험을 사랑하는 여행객들에게 최고의 경험을 선사합니다.</p><p style=\"text-align:justify;\">짧은 일정 안에서도 동부 자바의 가장 아름다운 자연을 충분히 즐길 수 있도록 구성된 이 투어는 안개가 드리운 계곡, 거대한 폭포, 그리고 광활한 화산 지형까지 다양한 풍경을 보여줍니다. 매일 새로운 감동과 특별한 경험이 기다리고 있습니다.</p><p style=\"text-align:justify;\">인도네시아를 대표하는 아름다운 폭포를 감상하고, 화산 위로 떠오르는 장엄한 일출을 바라보며, 때묻지 않은 자연 속에서 여유를 즐길 수 있는 특별한 시간이 될 것입니다.</p><p style=\"text-align:justify;\">커플, 가족, 자연 애호가, 사진작가, 모험 여행객 모두에게 추천하는 완벽한 일정입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바 최고의 자연 명소 2곳을 한 번에 탐방<br>✅ 장대한 폭포, 화산, 산악 풍경을 모두 경험<br>✅ 인도네시아 최고의 일출 명소 방문<br>✅ 세계적인 수준의 자연 사진 촬영 기회 제공<br>✅ 자연 애호가, 커플, 가족, 모험 여행객에게 추천<br>✅ 짧은 일정으로 최대의 여행 경험을 누릴 수 있는 최고의 선택</p><h3 style=\"text-align:justify;\"><strong>짧은 일정 속에서도 잊을 수 없는 풍경과 특별한 모험을 경험하고 싶다면, 이 여행은 동부 자바의 아름다움을 가장 효과적으로 만날 수 있는 완벽한 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">3天2晚 图姆帕克塞乌瀑布与布罗莫火山探险之旅</h2><p style=\"text-align:justify;\">在一次难忘的旅程中探索东爪哇最具代表性的两大自然奇观。壮丽的火山景观、震撼的瀑布风光、迷人的山地景色以及世界闻名的日出体验完美结合，为热爱自然、摄影和探险的游客带来精彩难忘的旅行体验。</p><p style=\"text-align:justify;\">本线路专为希望在短时间内深入体验东爪哇自然魅力的游客打造。从云雾缭绕的山谷到气势磅礴的瀑布，再到广阔壮观的火山地貌，每一天都能欣赏到截然不同的自然景观，感受东爪哇丰富多样的自然之美。</p><p style=\"text-align:justify;\">无论是在印度尼西亚最壮观的瀑布前驻足欣赏，还是在火山之巅迎接第一缕晨光，亦或是在原始自然环境中放松身心，每一个瞬间都将成为难忘的回忆。</p><p style=\"text-align:justify;\">非常适合情侣、家庭游客、自然爱好者、摄影爱好者以及热爱探险的旅行者。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程探索东爪哇两大标志性自然景点<br>✅ 同时体验壮观瀑布、火山与山地景观<br>✅ 欣赏印度尼西亚最著名的日出景观之一<br>✅ 打卡世界级自然摄影地点<br>✅ 适合自然爱好者、情侣、家庭及探险旅行者<br>✅ 时间短、体验丰富，是高性价比的东爪哇之旅</p><h3 style=\"text-align:justify;\"><strong>如果您希望在短时间内体验令人惊叹的自然风光与难忘的探险经历，那么这条线路将带您领略东爪哇最精华、最震撼的自然景观。</strong></h3>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>2N at hotel included breakfast:</p><p>1N Hotel (Bromo) &amp; 1N Hotel (Tumpak sewu)</p><p>Note: Accomodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel&nbsp;</p></li><li data-list-item-id=\"ef906fa2f832b7a3f7fbe60875fe2fef3\">Bromo jeep</li><li data-list-item-id=\"e2c6dc77b161085c0cabe68a6fd2529d4\">Tumpak Sewu local guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Waterfall\",\"Adventure\",\"Photography\",\"Nature\",\"Sunrise\",\"Family\"]', NULL, 0, NULL, '2026-06-02 15:06:36', '2026-06-02 15:06:36'),
(110, 48, '3 DAYS RELAXING EAST JAVA EXPERIENCE', 'SURABAYA', '3-days-relaxing-east-java-experience', '<h2 style=\"text-align:justify;\">3D/2N Malang Batu – Surabaya Tour</h2><p style=\"text-align:justify;\">Nikmati perjalanan yang memadukan budaya, sejarah, alam, dan kehidupan kota dalam satu pengalaman yang santai dan berkesan. Tour ini mengajak Anda menjelajahi dua destinasi paling menarik di Jawa Timur, menghadirkan suasana kota bersejarah yang elegan, dataran tinggi yang sejuk, serta kehidupan urban yang dinamis dan penuh pesona.</p><p style=\"text-align:justify;\">Temukan keindahan arsitektur kolonial yang masih terawat dengan baik, nikmati udara pegunungan yang menyegarkan, dan rasakan suasana khas kota-kota yang memiliki peran penting dalam sejarah serta perkembangan Jawa Timur. Sepanjang perjalanan, Anda akan menemukan perpaduan harmonis antara budaya lokal, keindahan alam, kuliner khas, dan keramahan masyarakat yang membuat setiap momen terasa istimewa.</p><p style=\"text-align:justify;\">Dirancang untuk wisatawan yang mengutamakan kenyamanan dan pengalaman yang lebih santai, paket ini menawarkan keseimbangan sempurna antara eksplorasi, relaksasi, dan pengalaman budaya. Setiap destinasi memberikan kesempatan untuk menikmati suasana yang berbeda tanpa terburu-buru, menjadikan perjalanan lebih nyaman dan menyenangkan.</p><p style=\"text-align:justify;\">Sangat cocok bagi keluarga, pasangan, wisatawan senior, maupun pengunjung yang baru pertama kali menjelajahi Jawa Timur.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi kekayaan budaya dan sejarah Jawa Timur dalam satu perjalanan<br>✅ Menikmati udara pegunungan yang sejuk dan suasana yang menenangkan<br>✅ Perpaduan sempurna antara wisata heritage, alam, dan kehidupan kota modern<br>✅ Banyak lokasi menarik untuk fotografi dan bersantai<br>✅ Cocok untuk keluarga, pasangan, wisatawan senior, dan first-time visitors<br>✅ Itinerary nyaman dengan aktivitas ringan dan minim trekking</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari perjalanan yang santai namun tetap kaya akan pengalaman budaya, sejarah, dan keindahan alam, tour ini adalah pilihan sempurna untuk menikmati pesona Jawa Timur dengan nyaman dan berkesan.</strong></h3>', '<h2 style=\"text-align:justify;\">3D/2N Malang Batu – Surabaya Tour</h2><p style=\"text-align:justify;\">Experience the perfect blend of culture, history, nature, and city life on this relaxing journey through two of East Java\'s most fascinating destinations. From charming heritage districts and scenic highland landscapes to vibrant urban attractions, this tour offers a refreshing escape filled with memorable experiences and authentic local charm.</p><p style=\"text-align:justify;\">Discover the elegance of East Java\'s colonial heritage, enjoy the cool mountain atmosphere, and immerse yourself in the unique character of cities that have played an important role in Indonesia\'s history and development. Along the way, you\'ll encounter beautiful architecture, picturesque landscapes, welcoming local communities, and a rich cultural atmosphere that reflects the true spirit of the region.</p><p style=\"text-align:justify;\">Designed for travelers who prefer a comfortable and enjoyable pace, this tour combines sightseeing, cultural exploration, leisure, and relaxation into one well-balanced experience. Whether you\'re traveling with family, friends, or as a couple, every day offers new discoveries and opportunities to create lasting memories.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Discover the cultural and historical highlights of East Java<br>✅ Enjoy the refreshing atmosphere of beautiful mountain landscapes<br>✅ Experience the perfect balance of heritage, nature, and modern city life<br>✅ Explore charming destinations ideal for photography and relaxation<br>✅ Perfect for families, couples, senior travelers, and first-time visitors<br>✅ Comfortable itinerary with minimal trekking and easy-paced sightseeing</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a relaxing yet meaningful journey that combines history, culture, scenic beauty, and local experiences, this tour offers the perfect introduction to the charm and diversity of East Java.</strong></h3>', '<h2 style=\"text-align:justify;\">3일 2박 말랑 · 바투 · 수라바야 투어</h2><p style=\"text-align:justify;\">문화, 역사, 자연, 그리고 도시의 매력을 한 번에 경험할 수 있는 편안하고 여유로운 여행을 만나보세요. 이 투어는 동부 자바를 대표하는 두 도시를 탐방하며 아름다운 문화유산, 시원한 고원지대, 그리고 활기찬 도시 분위기를 함께 즐길 수 있도록 구성되었습니다.</p><p style=\"text-align:justify;\">잘 보존된 식민지 시대 건축물과 아름다운 거리 풍경을 감상하고, 상쾌한 산악 지역의 공기를 느끼며, 동부 자바의 역사와 문화를 깊이 있게 경험할 수 있습니다. 또한 현지의 따뜻한 환대와 독특한 분위기를 통해 더욱 특별한 여행을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">편안한 여행을 선호하는 분들을 위해 설계된 일정으로, 관광과 휴식, 문화 체험이 조화롭게 어우러져 있습니다. 바쁜 일정 없이 여유롭게 여행을 즐기며 다양한 매력을 발견할 수 있습니다.</p><p style=\"text-align:justify;\">가족, 커플, 시니어 여행객, 그리고 처음 동부 자바를 방문하는 여행객에게 특히 추천합니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바의 역사와 문화를 깊이 있게 경험<br>✅ 시원한 고원 지역과 아름다운 자연 풍경 감상<br>✅ 문화유산, 자연, 현대 도시의 매력을 모두 체험<br>✅ 사진 촬영과 여유로운 휴식을 즐기기에 최적<br>✅ 가족, 커플, 시니어 여행객 및 초보 여행자에게 추천<br>✅ 무리 없는 일정과 최소한의 도보 이동으로 편안한 여행</p><h3 style=\"text-align:justify;\"><strong>역사와 문화, 아름다운 풍경을 여유롭게 즐기고 싶다면 이 투어는 동부 자바의 진정한 매력을 편안하게 경험할 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">3天2晚 玛琅 · 巴图 · 泗水之旅</h2><p style=\"text-align:justify;\">开启一段融合文化、历史、自然与都市魅力的轻松旅程，探索东爪哇最具特色的两大目的地。在这里，您将感受到历史文化名城的优雅气息、凉爽宜人的高原风光，以及充满活力的现代都市生活。</p><p style=\"text-align:justify;\">旅途中，您将欣赏保存完好的殖民时期建筑，感受高原地区清新的空气，并深入了解东爪哇丰富的历史与文化底蕴。沿途还能体验当地独特的人文风情和热情好客的民众，让旅程更加丰富而难忘。</p><p style=\"text-align:justify;\">本线路特别适合喜欢舒适节奏旅行的游客，将观光、文化体验与休闲放松完美结合。无需高强度活动，即可轻松享受丰富多彩的旅行体验，发现东爪哇独特的魅力。</p><p style=\"text-align:justify;\">非常适合家庭游客、情侣、长者以及首次到访东爪哇的旅行者。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 深入体验东爪哇丰富的历史与文化魅力<br>✅ 享受凉爽高原气候与优美自然风光<br>✅ 完美融合文化遗产、自然景观与现代城市生活<br>✅ 拥有众多适合摄影与休闲放松的景点<br>✅ 适合家庭、情侣、长者及首次来访的游客<br>✅ 行程轻松舒适，步行和体力消耗较少</p><h3 style=\"text-align:justify;\"><strong>如果您希望以轻松舒适的方式探索东爪哇的历史文化与自然风光，那么这条线路将为您带来一次充满魅力与回忆的精彩旅程。</strong></h3>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\">2N at *4 hotel (Malang) included breakfast</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Heritage\",\"Culture\",\"Highland\",\"Nature\",\"Leisure\",\"Photography\",\"Family\",\"City\"]', NULL, 0, NULL, '2026-06-02 15:17:36', '2026-06-02 15:17:36'),
(111, 48, '3 DAYS BEST OF EAST JAVA ESCAPE', 'SURABAYA', '3-days-best-of-east-java-escape', '<h2 style=\"text-align:justify;\">3D/2N Bromo – Malang Batu – Surabaya Tour</h2><p style=\"text-align:justify;\">Nikmati perjalanan terbaik untuk mengenal pesona Jawa Timur melalui kombinasi sempurna antara keindahan alam, udara pegunungan yang sejuk, warisan budaya yang kaya, dan kehidupan kota yang dinamis. Dirancang untuk wisatawan yang menginginkan pengalaman yang nyaman namun tetap berkesan, paket ini menghadirkan keseimbangan ideal antara petualangan, eksplorasi, dan relaksasi.</p><p style=\"text-align:justify;\">Jelajahi berbagai lanskap menakjubkan yang menjadikan Jawa Timur sebagai salah satu destinasi wisata paling menarik di Indonesia. Dari panorama alam yang memukau hingga suasana kota yang sarat sejarah, setiap destinasi menawarkan pengalaman yang berbeda dan memperlihatkan kekayaan karakter daerah ini.</p><p style=\"text-align:justify;\">Selain menikmati pemandangan yang luar biasa, Anda juga akan merasakan atmosfer lokal yang autentik, budaya yang unik, serta berbagai pengalaman yang mencerminkan kehidupan masyarakat Jawa Timur. Perjalanan ini dirancang untuk memberikan kenangan yang menyenangkan tanpa harus melakukan aktivitas yang terlalu berat.</p><p style=\"text-align:justify;\">Cocok untuk keluarga, pasangan, wisatawan senior, maupun pengunjung yang ingin menikmati destinasi terbaik Jawa Timur dalam waktu yang singkat namun tetap maksimal.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menjelajahi destinasi alam dan budaya paling ikonik di Jawa Timur<br>✅ Perpaduan sempurna antara wisata alam, heritage, dan kehidupan kota<br>✅ Menikmati panorama yang indah dan pengalaman perjalanan yang berkesan<br>✅ Itinerary ramah keluarga dan cocok untuk semua usia<br>✅ Banyak kesempatan untuk fotografi dan eksplorasi budaya lokal<br>✅ Jadwal perjalanan yang nyaman dan tidak terburu-buru</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari liburan singkat yang menghadirkan keindahan alam, pengalaman budaya, dan suasana yang menyenangkan, tour ini adalah cara terbaik untuk menikmati pesona Jawa Timur dalam satu perjalanan yang lengkap dan berkesan.</strong></h3>', '<h2 style=\"text-align:justify;\">3D/2N Bromo – Malang Batu – Surabaya Tour</h2><p style=\"text-align:justify;\">Experience the perfect introduction to East Java through a journey that combines spectacular natural scenery, refreshing mountain landscapes, rich cultural heritage, and vibrant city life. Carefully designed for travelers seeking comfort, exploration, and memorable experiences, this tour offers an ideal balance between adventure and relaxation.</p><p style=\"text-align:justify;\">Travel through some of East Java\'s most beautiful regions while enjoying breathtaking panoramic views, cool highland atmospheres, charming heritage districts, and authentic local experiences. Each destination presents a different side of the region, allowing you to discover the remarkable diversity that makes East Java one of Indonesia\'s most fascinating travel destinations.</p><p style=\"text-align:justify;\">Whether you\'re admiring dramatic landscapes, exploring historical landmarks, enjoying fresh mountain air, or capturing unforgettable photographs, every moment of this journey is designed to create lasting memories. The combination of nature, culture, and family-friendly attractions makes this package suitable for travelers of all ages.</p><p style=\"text-align:justify;\">Perfect for families, couples, first-time visitors, and anyone looking for a comfortable yet rewarding travel experience, this tour showcases the best highlights of East Java in just a few days.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Experience East Java\'s most iconic landscapes and cultural attractions<br>✅ Enjoy the perfect combination of nature, heritage, and city exploration<br>✅ Witness breathtaking scenery and unforgettable travel moments<br>✅ Family-friendly itinerary suitable for all ages<br>✅ Excellent opportunities for photography and cultural discovery<br>✅ Comfortable travel pace with a well-balanced schedule</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a short getaway that combines natural beauty, cultural experiences, and unforgettable scenery, this tour offers one of the most enjoyable ways to discover the charm of East Java.</strong></h3>', '<h2 style=\"text-align:justify;\">3일 2박 브로모 · 말랑 바투 · 수라바야 투어</h2><p style=\"text-align:justify;\">동부 자바의 아름다움을 가장 편안하게 경험할 수 있는 특별한 여행을 만나보세요. 웅장한 자연경관, 시원한 고원지대, 풍부한 문화유산, 그리고 활기찬 도시의 매력을 모두 담아낸 일정으로, 모험과 휴식이 조화롭게 어우러진 여행을 제공합니다.</p><p style=\"text-align:justify;\">동부 자바를 대표하는 다양한 풍경과 문화를 경험하며, 자연의 아름다움과 역사적인 분위기를 동시에 느낄 수 있습니다. 아름다운 경관과 함께 지역 고유의 문화와 생활방식을 접하며 더욱 깊이 있는 여행을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">이 여행은 무리한 일정 없이 편안하게 주요 명소를 둘러볼 수 있도록 구성되어 있어 가족, 커플, 시니어 여행객 모두에게 적합합니다. 자연과 문화, 도시의 매력을 한 번에 경험할 수 있는 최고의 선택입니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바의 대표적인 자연 및 문화 명소 탐방<br>✅ 자연, 문화유산, 도시 관광이 완벽하게 조화를 이루는 일정<br>✅ 아름다운 풍경과 특별한 여행 경험 제공<br>✅ 가족 여행객을 포함한 모든 연령층에게 적합<br>✅ 사진 촬영과 문화 체험을 즐기기에 최적<br>✅ 여유롭고 편안한 일정으로 부담 없는 여행 가능</p><h3 style=\"text-align:justify;\"><strong>짧은 일정 안에서도 동부 자바의 진정한 매력을 경험하고 싶다면, 이 투어는 자연과 문화, 그리고 특별한 추억을 모두 선사하는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">3天2晚 布罗莫火山 · 玛琅巴图 · 泗水之旅</h2><p style=\"text-align:justify;\">开启一段探索东爪哇魅力的精彩旅程，在自然风光、清凉高原、丰富文化遗产以及现代都市生活之间，感受最完整的旅行体验。本线路专为希望轻松舒适旅行的游客设计，将探险、观光与休闲完美融合。</p><p style=\"text-align:justify;\">旅途中，您将欣赏东爪哇最具代表性的自然景观与人文风情，感受壮丽风光与深厚历史文化的独特魅力。每一个目的地都展现出不同的特色，让您更全面地了解这片充满活力与魅力的土地。</p><p style=\"text-align:justify;\">除了迷人的景色之外，您还可以体验当地文化、感受浓厚的人文氛围，并在轻松舒适的节奏中享受旅行的乐趣。无论是与家人同行，还是与伴侣共度美好时光，这趟旅程都能带来难忘的回忆。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 探索东爪哇最具代表性的自然与文化景点<br>✅ 完美结合自然风光、历史文化与城市体验<br>✅ 欣赏壮丽景色并留下难忘回忆<br>✅ 适合家庭、情侣及各年龄层游客<br>✅ 提供丰富的摄影与文化体验机会<br>✅ 行程轻松舒适，不赶时间，体验更从容</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一次兼具自然美景、文化体验与轻松氛围的短途假期，那么这条线路将是探索东爪哇魅力的理想选择。</strong></h3>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\">1N at hotel (Bromo) &amp; 1N at *4 hotel (Malang) included breakfast</li><li data-list-item-id=\"e4eaa533f2c5ecf745debf7ba56bbbbdf\">Bromo jeep</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Volcano\",\"Heritage\",\"Culture\",\"Leisure\",\"Family\",\"Nature\",\"Photography\",\"Sunrise\"]', NULL, 0, NULL, '2026-06-03 06:46:51', '2026-06-03 06:46:51'),
(112, 48, '3 DAYS WATERFALL & HIGHLAND ESCAPE', 'SURABAYA', '3-days-waterfall-highland-escape', '<h2 style=\"text-align:justify;\">3D/2N Batu Malang – Tumpak Sewu Tour</h2><p style=\"text-align:justify;\">Lepaskan diri dari rutinitas dan nikmati keindahan alam Jawa Timur melalui perjalanan yang menghadirkan perpaduan sempurna antara panorama pegunungan yang menyejukkan, air terjun yang spektakuler, taman-taman yang indah, serta pengalaman budaya yang autentik. Dirancang untuk wisatawan yang menginginkan keseimbangan antara petualangan ringan, relaksasi, dan eksplorasi alam, tour ini menawarkan pengalaman yang menyegarkan dan penuh kenangan.</p><p style=\"text-align:justify;\">Jelajahi lembah hijau yang subur, tebing-tebing megah, udara pegunungan yang segar, serta berbagai lanskap menawan yang menjadikan Jawa Timur sebagai salah satu destinasi alam terbaik di Indonesia. Setiap destinasi menghadirkan suasana yang berbeda, memberikan pengalaman yang kaya dan beragam dalam satu perjalanan yang nyaman.</p><p style=\"text-align:justify;\">Selain keindahan alamnya, Anda juga akan merasakan keramahan masyarakat lokal, nuansa budaya yang unik, dan suasana kota yang penuh karakter. Perjalanan ini dirancang untuk memberikan pengalaman yang menyenangkan tanpa aktivitas yang terlalu berat, sehingga cocok untuk berbagai kalangan wisatawan.</p><p style=\"text-align:justify;\">Baik bersama keluarga, pasangan, maupun sahabat, setiap hari akan menghadirkan pengalaman baru yang membuat perjalanan semakin berkesan.</p><h3 style=\"text-align:justify;\">Mengapa Harus Memilih Tour Ini?</h3><p style=\"text-align:justify;\">✅ Menikmati beberapa lanskap alam terbaik di Jawa Timur dalam satu perjalanan<br>✅ Perpaduan sempurna antara air terjun, pegunungan, taman, dan wisata budaya<br>✅ Cocok bagi pecinta alam dan fotografi<br>✅ Itinerary ramah keluarga dengan perjalanan yang nyaman<br>✅ Menggabungkan relaksasi dan petualangan ringan secara seimbang<br>✅ Pilihan ideal untuk pasangan, keluarga, dan wisatawan yang baru pertama kali berkunjung ke Jawa Timur</p><h3 style=\"text-align:justify;\"><strong>Jika Anda mencari liburan yang menyegarkan dengan keindahan alam, suasana yang tenang, dan pengalaman yang berkesan, tour ini menawarkan cara terbaik untuk menikmati pesona Jawa Timur dengan nyaman dan menyenangkan.</strong></h3>', '<h2 style=\"text-align:justify;\">3D/2N Batu Malang – Tumpak Sewu Tour</h2><p style=\"text-align:justify;\">Escape into the natural beauty of East Java on a journey filled with breathtaking landscapes, refreshing mountain air, spectacular waterfalls, and charming cultural experiences. Designed for travelers who seek a balance between adventure, relaxation, and scenic exploration, this tour offers an unforgettable getaway surrounded by some of the region\'s most beautiful natural attractions.</p><p style=\"text-align:justify;\">Discover lush valleys, dramatic cliffs, colorful gardens, and peaceful highland scenery that create a perfect setting for relaxation and exploration. Every destination presents a different perspective of East Java\'s rich natural beauty, making this journey ideal for those who appreciate nature, photography, and authentic local experiences.</p><p style=\"text-align:justify;\">Beyond its stunning landscapes, this tour also introduces travelers to the warm hospitality, cultural heritage, and unique character that make East Java such a rewarding destination. Whether you\'re traveling with family, friends, or a loved one, every day brings new discoveries and memorable moments.</p><p style=\"text-align:justify;\">With its comfortable pace, beautiful scenery, and family-friendly atmosphere, this package is perfect for travelers looking to experience the highlights of East Java without the challenges of extreme adventure activities.</p><h3 style=\"text-align:justify;\">Why You\'ll Love This Tour</h3><p style=\"text-align:justify;\">✅ Experience some of East Java\'s most beautiful natural landscapes<br>✅ Enjoy a perfect combination of waterfalls, mountain scenery, gardens, and cultural attractions<br>✅ Ideal for photography enthusiasts and nature lovers<br>✅ Family-friendly itinerary with comfortable travel arrangements<br>✅ Relaxing atmosphere combined with light adventure experiences<br>✅ Perfect for couples, families, and first-time visitors to East Java</p><h3 style=\"text-align:justify;\"><strong>If you\'re looking for a refreshing escape surrounded by nature, culture, and unforgettable scenery, this journey offers one of the most enjoyable ways to experience the beauty and charm of East Java.</strong></h3>', '<h2 style=\"text-align:justify;\">3일 2박 바투 · 말랑 · 뚬빡 세우 투어</h2><p style=\"text-align:justify;\">일상에서 벗어나 동부 자바의 아름다운 자연 속으로 떠나보세요. 시원한 산악 풍경, 장대한 폭포, 아름다운 정원, 그리고 현지 문화를 함께 경험할 수 있는 이 여행은 가벼운 모험과 휴식, 자연 탐방을 모두 원하는 여행객들에게 완벽한 선택입니다.</p><p style=\"text-align:justify;\">푸른 계곡과 웅장한 절벽, 맑고 상쾌한 산 공기, 그리고 아름다운 자연경관이 어우러진 동부 자바의 매력을 만끽할 수 있습니다. 여행하는 동안 다양한 풍경과 분위기를 경험하며 자연이 선사하는 특별한 감동을 느낄 수 있습니다.</p><p style=\"text-align:justify;\">아름다운 자연뿐만 아니라 지역 주민들의 따뜻한 환대와 독특한 문화적 매력도 함께 경험할 수 있어 더욱 의미 있는 여행이 됩니다. 무리한 일정 없이 편안하게 여행할 수 있도록 구성되어 있어 가족, 커플, 친구들과 함께하기에 좋습니다.</p><h3 style=\"text-align:justify;\">이 투어를 선택해야 하는 이유</h3><p style=\"text-align:justify;\">✅ 동부 자바 최고의 자연경관을 한 번에 경험<br>✅ 폭포, 산악 풍경, 정원, 문화 체험이 완벽하게 조화된 일정<br>✅ 자연 애호가와 사진작가에게 이상적인 여행<br>✅ 가족 여행객에게 적합한 편안한 일정<br>✅ 휴식과 가벼운 모험을 동시에 즐길 수 있는 여행<br>✅ 커플, 가족, 동부 자바 첫 방문 여행객에게 추천</p><h3 style=\"text-align:justify;\"><strong>아름다운 자연 속에서 편안한 휴식과 특별한 경험을 원한다면, 이 투어는 동부 자바의 매력을 가장 즐겁고 여유롭게 만날 수 있는 최고의 선택이 될 것입니다.</strong></h3>', '<h2 style=\"text-align:justify;\">3天2晚 巴图 · 玛琅 · 图姆帕克塞乌瀑布之旅</h2><p style=\"text-align:justify;\">远离繁忙的日常生活，踏上一段探索东爪哇自然之美的精彩旅程。在这趟旅程中，您将欣赏壮丽瀑布、清凉高原、迷人花园以及独特的人文风情，体验探险与休闲完美结合的旅行方式。</p><p style=\"text-align:justify;\">穿越郁郁葱葱的山谷、壮观的悬崖和风景如画的高原地区，感受东爪哇丰富多彩的自然魅力。每一个目的地都展现出不同的风景与氛围，让您在轻松舒适的节奏中收获难忘的旅行回忆。</p><p style=\"text-align:justify;\">除了壮丽的自然景观外，您还将感受到当地居民的热情好客和浓厚的人文气息，使整个旅程更加丰富而有意义。行程安排轻松舒适，无需高强度体力活动，非常适合希望放松身心的游客。</p><p style=\"text-align:justify;\">无论是家庭出游、情侣度假还是与朋友同行，这条线路都能带来充满欢乐与惊喜的旅行体验。</p><h3 style=\"text-align:justify;\">为什么选择这条线路？</h3><p style=\"text-align:justify;\">✅ 一次旅程欣赏东爪哇最迷人的自然景观<br>✅ 完美融合瀑布、高原、花园与文化体验<br>✅ 适合自然爱好者与摄影爱好者<br>✅ 家庭友好型行程，舒适轻松<br>✅ 兼顾休闲放松与轻度探险体验<br>✅ 非常适合情侣、家庭及首次到访东爪哇的游客</p><h3 style=\"text-align:justify;\"><strong>如果您正在寻找一场轻松愉快、充满自然美景与难忘回忆的旅程，那么这条线路将带您深入感受东爪哇最迷人的自然与文化魅力。</strong></h3>', 0.00, NULL, 3, 2, NULL, NULL, '<ul><li data-list-item-id=\"efcbe1d62a5eb8c93a4c3e6d89c2c469f\">Air-conditioned transportation</li><li data-list-item-id=\"e0c30f34aa30335162fe7804d2c3917bd\"><p>1N at hotel (Tumpak sewu) &amp; 1N at *4 hotel (Malang) included breakfast</p><p>Note: Accommodation in Tumpak sewu area is no star hotel but room condition/facility similar with 3-star hotel</p></li><li data-list-item-id=\"e4eaa533f2c5ecf745debf7ba56bbbbdf\">Tumpak Sewu Local Guide</li><li data-list-item-id=\"e56267eebec367f2729969e3b3015c22e\">Entrance Ticket &amp; Donation fee</li><li data-list-item-id=\"e5cba41594d493555cf395e79d1459d9d\">English speaking guide</li></ul>', '<ul><li data-list-item-id=\"e13146d36e76beafa6c496b3eaa85617e\">Flight/Train Ticket</li><li data-list-item-id=\"e87264d61753587ec388915ec799720c6\">Meals</li><li data-list-item-id=\"efb06e42727a00b134ec76d7163409c5d\">Tipping guide/driver</li><li data-list-item-id=\"e4c7aac3001b32c0fc70b84dde139fcc9\">Optional tour</li></ul>', NULL, '[\"Waterfall\",\"Nature\",\"Culture\",\"Highland\",\"Adventure\",\"Heritage\",\"Family\",\"Photography\"]', NULL, 0, NULL, '2026-06-03 07:15:34', '2026-06-03 07:15:34');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(18, 21, 'Bangkok Pattaya Khaoyai 5D4N', NULL, 'bangkok-pattaya-khaoyai-5d4n', '<h3><strong>BANGKOK – PATTAYA – KHAOYAI 5D4N</strong> ✨</h3><p>Nikmati liburan lengkap menjelajahi <strong>kota, pantai, dan pegunungan</strong> di Thailand dalam satu perjalanan seru!</p><p>Mulai dari <strong>Bangkok</strong>, Anda akan mengunjungi ikon terkenal seperti <strong>Wat Arun</strong> dan menikmati suasana <strong>Chao Phraya River</strong>. Lengkapi pengalaman dengan shopping di <strong>Platinum Fashion Mall</strong> dan wisata malam di <strong>Asiatique The Riverfront</strong>.</p><p>Lanjut ke <strong>Pattaya</strong>, nikmati suasana pantai serta kunjungan ke <strong>Nong Nooch Tropical Garden</strong> dengan pertunjukan budaya &amp; gajah, serta spot unik seperti <strong>Khao Chi Chan</strong>.</p><p>Perjalanan dilanjutkan ke <strong>Khao Yai</strong>, di mana Anda bisa menikmati taman bunga cantik di <strong>Hokkaido Flower Park</strong>, suasana ala Eropa di <strong>Toscana Valley</strong>, serta pengalaman seru bermain dengan alpaca di <strong>Khmong Alpaca Khaoyai</strong>.</p><p><strong>Liburan lengkap: city tour, pantai, alam, belanja &amp; hiburan dalam 1 paket! 🇹🇭</strong></p>', NULL, NULL, NULL, 3050000.00, NULL, 5, 4, '[]', NULL, '<p>Highlight Free Toscana Valley, Toy Museum, Hokkaido Flower Park Wat Arun, Nongnooch</p>', '<p>JOIN TRIP SIC LOCAL TRAVEL INSURANCE HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA ALL MENTIONED TOURS AND MEALS ON ITINERARY 1 BOTTLE OF DRINKING WATER PER PERSON DAILY INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</p>', '<p>TIPPING FOR DRIVER &amp; GUIDE 2-14 PAX USD25/PAX TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP USD15/PAX TIPPING MUST BE PAID ON INVOICE BEFORE TOUR ADDITIONAL TOUR EXTEND HOTEL PEAK SEASON SURCHARGE</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/Bw1SuoV410pE0vU4OLqrVWYGq9XBHMq6YypSPycG.pdf', 0, NULL, '2026-04-22 01:54:38', '2026-04-24 04:54:14'),
(19, 21, 'Bangkok Khaoyai Toscana Valley 4D3N', NULL, 'bangkok-khaoyai-toscana-valley-4d3n', '<p><strong>BANGKOK – KHAOYAI 4D3N</strong> ✨</p><p>Nikmati liburan singkat ke <strong>Bangkok</strong> &amp; <strong>Khao Yai</strong> dengan kombinasi wisata kota dan alam!</p><p>Kunjungi taman bunga indah <strong>Hokkaido Flower Park</strong>, berfoto di spot ala Eropa <strong>Toscana Valley</strong>, dan rasakan pengalaman unik bermain dengan alpaca di <strong>Khmong Alpaca Khaoyai</strong>.</p><p>Di Bangkok, jelajahi ikon terkenal <strong>Wat Arun</strong> dan nikmati suasana <strong>Chao Phraya River</strong>. Lengkapi perjalanan dengan <strong>shopping</strong> di <strong>Platinum Fashion Mall</strong> serta hiburan malam di <strong>Asiatique The Riverfront</strong>.</p><p><strong>Liburan singkat, lengkap, dan penuh spot foto Instagramable! 🇹🇭</strong></p>', '<p><strong>BANGKOK – KHAO YAI 4D3N ✨</strong></p><p>Enjoy a short getaway to Bangkok &amp; Khao Yai with a perfect combination of city and nature experiences!</p><p>Visit the beautiful Hokkaido Flower Park, take photos at the European-style Toscana Valley, and enjoy a unique experience interacting with alpacas at Khmong Alpaca 🦙</p><p>In Bangkok, explore the iconic Wat Arun and enjoy the atmosphere along the Chao Phraya River 🚤</p><p>Complete your trip with shopping at Platinum Fashion Mall and nightlife entertainment at Asiatique The Riverfront 🌙</p><p>A short, complete, and Instagrammable holiday experience! 🇹🇭</p>', '<p><strong>방콕 – 카오야이 4일 3박 ✨</strong></p><p>Bangkok과 Khao Yai에서 도시와 자연을 함께 즐기는 짧은 여행!</p><p>아름다운 Hokkaido Flower Park를 방문하고, 유럽풍의 Toscana Valley에서 사진을 찍으며, Khmong Alpaca에서 알파카와 교감하는 특별한 경험을 즐겨보세요 🦙</p><p>방콕에서는 Wat Arun을 방문하고 Chao Phraya River의 분위기를 만끽할 수 있습니다 🚤</p><p>또한 Platinum Fashion Mall에서 쇼핑을 하고 Asiatique The Riverfront에서 야경과 엔터테인먼트를 즐겨보세요 🌙</p><p>짧지만 알찬 인스타 감성 여행! 🇹🇭</p>', '<p><strong>曼谷 – 考艾 4天3晚 ✨</strong></p><p>前往 Bangkok 和 Khao Yai，体验城市与自然相结合的精彩短途旅行！</p><p>参观美丽的 Hokkaido Flower Park，在欧式风格的 Toscana Valley拍照打卡，并在 Khmong Alpaca与羊驼互动 🦙</p><p>在曼谷，参观著名的 Wat Arun，并欣赏 Chao Phraya River的美景 🚤</p><p>最后在 Platinum Fashion Mall购物，并在 Asiatique The Riverfront享受夜生活 🌙</p><p>短途却精彩，充满打卡体验的完美旅程！ 🇹🇭</p>', 2400000.00, NULL, 4, 3, '[]', NULL, '<p>Highlight Free Toscana Valley, Khmong Alpaca, Hokkaido Flower Park, Wat Arun</p>', '<p>JOIN TRIP SIC LOCAL TRAVEL INSURANCE HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK ALL MENTIONED TOURS AND MEALS ON THE ITINERARY 1 BOTTLE OF DRINKING WATER PER PERSON DAILY INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</p>', '<p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX USD20/PAX TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP USD12/PAX TIPPING MUST BE PAID ON INVOICE BEFORE TOUR ADDITIONAL TOUR EXTEND HOTEL PEAK SEASON SURCHARGE</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/O5vKvoAo7zUTzowpnXL5fUpWZbSA5xqsyO86UT78.pdf', 0, NULL, '2026-04-22 02:05:47', '2026-04-29 07:06:25'),
(21, 22, '10D School Holiday Complete Vietnam', NULL, '10d-school-holiday-complete-vietnam', '<h3><strong>10D Complete Vietnam: Saigon – Danang – Sapa – Halong ✨</strong></h3><p>Jelajahi keindahan <strong>Vietnam</strong> dalam paket <strong>10 hari</strong> yang lengkap dari selatan hingga utara. Mulai dari kota modern <strong>Ho Chi Minh City</strong>, pesona budaya <strong>Hoi An</strong>, hingga keindahan alam <strong>Ha Long Bay</strong>.</p><p>Nikmati pengalaman unik di <strong>Cam Thanh Coconut Village</strong>, menjelajahi kota romantis Hoi An dengan lampion, serta kunjungan ke <strong>Ba Na Hills</strong> dengan ikon <strong>Golden Bridge</strong> yang mendunia.</p><p>Lanjutkan petualangan ke pegunungan <strong>Sapa</strong>, mengunjungi desa lokal <strong>Cat Cat Village</strong>, hingga menaklukkan <strong>Fansipan</strong> – “Roof of Indochina”.</p><p>Perjalanan ditutup dengan cruise di Ha Long Bay dan city tour <strong>Hanoi</strong> yang kaya budaya dan sejarah.</p><p>Didukung penerbangan nyaman, hotel pilihan, serta itinerary lengkap, paket ini cocok untuk Anda yang ingin menikmati Vietnam secara menyeluruh dalam satu perjalanan.</p><p><strong>Liburan lengkap, pengalaman tak terlupakan! 🇻🇳✨</strong></p>', NULL, NULL, NULL, 18590000.00, NULL, 9, 8, '[]', NULL, '<p>HIGHLIGHT: CAM THANH COCONUT VILLAGE – HOI AN – BA NA HILL – MEGA GRAND WORLD - CAT CAT VILLAGE - FANSIPAN - HALONG ISLAND TOUR</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International Jakarta-Saigon &amp; Saigon-Jakarta, dan tiket domestik Saigon-Danang-Hanoi-Saigon by Vietnam Airlines, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend) Bagasi sesuai dengan ketentuan Airlines Akomodasi hotel *3 setaraf (Twin / Triple) Transportasi bus Pariwisata &amp; tiket masuk objek wisata Acara Tour &amp; makan sesuai program paket tour diatas Mineral Water 1 Botol Perhari Tour Leader Travel Kits (Luggage Tag) Travel Insurance sampai usia 82 tahun</p>', '<p>Tipping Tour Leader, Local Guide, Driver: Rp1.000.000/ Pax Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll. PCR Test / Rapid Test Antigen Jika dibutuhkan OPTIONAL: Rental Wifi/SIM CARD Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/WvoYJmDLpwtV6n1WDYKSaUBoLtXx58mwaX0hcA4a.pdf', 0, NULL, '2026-04-22 02:37:01', '2026-04-24 04:04:09'),
(22, 20, '7D Shoking Sale Golden Route Japan + Shirakawago', NULL, '7d-shoking-sale-golden-route-japan-shirakawago', '<h3><strong>7D Golden Route Japan + Shirakawago ✨</strong></h3><p>Nikmati perjalanan impian ke <strong>Japan</strong> dalam paket <strong>7 hari</strong> yang mengunjungi rute terbaik: <strong>Osaka</strong>, <strong>Kyoto</strong>, <strong>Shirakawa-go</strong>, <strong>Mount Fuji</strong>, hingga <strong>Tokyo</strong>.</p><p>Kunjungi desa tradisional <strong>Shirakawago</strong> yang ikonik, jelajahi suasana klasik di <strong>Takayama Old Town</strong>, serta nikmati keindahan <strong>Mount Fuji</strong> dan <strong>Lake Kawaguchi</strong>. Lengkapi perjalanan dengan wisata budaya di Kyoto seperti <strong>Fushimi Inari Taisha</strong> serta pengalaman belanja di Osaka &amp; Tokyo.</p><p>Didukung penerbangan nyaman Malaysia Airlines / All Nippon Airways, hotel nyaman, dan itinerary lengkap, paket ini menjadi pilihan terbaik untuk menikmati Jepang dengan harga spesial.</p><p><strong>Wujudkan liburan Jepang impian Anda sekarang! 🇯🇵✨</strong></p>', NULL, NULL, NULL, 19990000.00, NULL, 7, 6, '[]', NULL, '<p>HIGHLIGHT: Shirakawago – Mt. Fuji – Takayama Old Town –<br>SPECIAL PROMOTION GROUP SERIES/OPEN TRIP 2026</p><p>Guarantee Best Price &amp; Service</p>', '<p>Tiket International Jakarta-Osaka/ Narita-Jakarta dengan Malaysia Airlines, Economy termasuk seluruh taxes(Tiket Grup Fixed Date &amp; No Extend) Bagasi 30 kg per orang atau sesuai dengan ketentuan Airlines Akomodasi hotel *3/*4 setaraf (Twin / Triple) Transportasi bus Pariwisata &amp; tiket masuk objek wisata Acara Tour &amp;makan sesuai program paket tour diatas Tour Leader Travel Insurance sampai usia 69 tahun Lugage Tag</p>', '<p>Visa Jepang: Rp.800.000/pax (Domisili Jakarta) Jakarta, Banten, Jawa Barat, Jawa Tengah, Yogyakarta, Kalimantan Tengah, Kalimantan Barat, Sumatera Selatan, Bangka Belitung, Bengkulu, Lampung Visa Jepang Biasa: Rp.1.050.000/pax (Domisili Luar Jakarta) Sulawesi Utara, Gorontalo, Sulawesi Tengah, Sulawesi Tenggara, Sulawesi Selatan, Sulawesi Barat, Maluku Utara, Maluku, Papua (Irian Jaya), Papua Barat Visa Waiver Rp 275.000/pax Tipping Local Guide, Driver, Tour Leader :Rp 800,000 TipsPorter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll. Air Minum Optional Modem Wifi Portable : Rp 70,000/Day</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/AQQHMd4yacJDpbJGtwGDqXcKkRSc2hW8JUmFzu8Y.pdf', 0, NULL, '2026-04-22 02:56:45', '2026-04-24 03:49:14'),
(23, 22, '6D5N Explore Hanoi Sapa', NULL, '6d5n-explore-hanoi-sapa', '<h3><strong>6D5N Explore Hanoi – Sapa &amp; Fansipan Peak ✨</strong></h3><p>Nikmati perjalanan seru ke <strong>Vietnam</strong> dalam paket <strong>6 hari 5 malam</strong> yang memadukan <strong>alam, budaya, dan petualangan</strong>. Jelajahi keindahan <strong>Hanoi</strong>, pesona pegunungan <strong>Sapa</strong>, hingga keajaiban alam <strong>Ha Long Bay</strong>.</p><p>Rasakan pengalaman tak terlupakan menuju <strong>Fansipan</strong> dengan cable car menuju “Roof of Indochina”, serta kunjungi desa tradisional <strong>Cat Cat Village</strong>. Nikmati juga cruise di Ha Long Bay dengan pemandangan gua dan pulau karst yang menakjubkan.</p><p>Lengkapi perjalanan dengan city tour di Hanoi seperti <strong>Hoan Kiem Lake</strong> dan pengalaman unik di <strong>Hanoi Train Street</strong>☕.</p><p>Didukung <strong>hotel bintang 4</strong>, itinerary lengkap, dan pengalaman unik, paket ini cocok untuk Anda yang ingin menikmati Vietnam secara menyeluruh.</p><p><strong>Wujudkan petualangan Anda sekarang! ✨</strong></p>', NULL, NULL, NULL, 12690000.00, NULL, 6, 5, '[]', NULL, '<p>WITH FANSIPAN PEAK<br>Hanoi, Sapa, Halong, Fansipan Peak</p>', '<p>Tiket internasional dengan Vietjet (VJ), rute : Jakarta – Hanoi // Hanoi - Jakarta (Non Re – routable, Non Endorsable, Non Upgrade) Bagasi maksimal 20kg atau sesuai dengan peraturan penerbangan. Akomodasi : Hotel 4*. Base on Availability &amp; Confirmations in Final Itinerary Transportasi Bus ber AC &amp; Admission Fee objek wisata Fuel Surcharge, Tax Int’l Airlines, Airport Tax Jakarta Tour Leader dari Jakarta</p>', '<p>Pengeluaran pribadi : Mini Bar, Phone, Laundry, dll Pengurusan Dokumen Perjalanan : Passport, Visa, Entry Permit, dll Optional / Tour Tambahan Tipping TL selama perjalanan dan Local Guide + Driver Rp. 650.000/pax. Tipping Bell Boy Hotel, Porter Airport Biaya lain yang tidak tercantum di atas Ppn 1.1%</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/BotEqjYgDghwjVRAEZuczlWQYDswHXIaOg7RXo9y.pdf', 0, NULL, '2026-04-22 05:43:18', '2026-04-24 03:34:00'),
(24, 23, '7D6N Wonderful 3 Countries', NULL, '7d6n-wonderful-3-countries', '<h3><strong>7D6N Wonderful 3 Countries – SG, MY &amp; TH ✨</strong></h3><p>Jelajahi <strong>Singapore</strong>, <strong>Malaysia</strong>, dan <strong>Thailand</strong> dalam perjalanan <strong>7 hari 6 malam</strong> bersama Malaysia Airlines.</p><p>Kunjungi ikon populer seperti <strong>Merlion Park</strong>, <strong>Gardens by the Bay</strong>, <strong>Petronas Twin Towers</strong>, dan <strong>Batu Caves</strong>. Lanjutkan ke <strong>Hat Yai</strong> dengan Pantai Samila dan Floating Market.</p><p>Nikmati juga <strong>Genting Cable Car</strong>, shopping, dan pengalaman lintas negara dalam satu trip seru.</p><p><strong>Liburan praktis, hemat, dan penuh pengalaman! ✨</strong></p>', NULL, NULL, NULL, 7480000.00, NULL, 7, 6, '[]', NULL, '<p>Highlight: Singapore – Malaysia – Thailand</p>', '<p>Tiket International Jakarta- Kuala Lumpur - Jakarta Economy Class termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend). Bagasi sesuai dengan ketentuan Airlines. Akomodasi Hotel *3 setaraf (Twin / Triple). Transportasi Bus Pariwisata &amp; Tiket Masuk Objek Wisata. Acara Tour &amp; makan sesuai program paket tour diatas. Mineral Water 1 Botol / Hari / Pax. Tour Leader. FREE GENTING CABLE CAR. Tourism Tax Malaysia.</p>', '<p>Tipping Tour Leader, Local Guide, Driver : Rp. 350.000 / Pax. Biaya dokumen perjalanan : Paspor, Visa, Entry Permit dll. Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll. PCR Test / Rapid Test Antigen Jika dibutuhkan. Travel Insurance (Optional). PPN 1,1%. OPTIONAL: Rental Wifi Portable. CHANG PUAK CAMP HATYAI THB 500 / Pax (Elephant Show).</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/sw1u9a6MvGUOOmS8vqOCHzzWiVKiDmmh98oKhLyz.pdf', 0, NULL, '2026-04-22 05:59:07', '2026-04-24 03:17:19'),
(25, 24, '6D5N Explore Srilanka Tour', NULL, '6d5n-explore-srilanka-tour', '<h3><strong>6D5N Explore Sri Lanka – Nature &amp; Heritage Journey ✨</strong></h3><p>Nikmati petualangan tak terlupakan menjelajahi keindahan <strong>Sri Lanka</strong> dalam perjalanan <strong>6 hari 5 malam</strong> yang memadukan <strong>alam, budaya, dan sejarah</strong>. Perjalanan dimulai dari Jakarta menuju <strong>Colombo</strong> dengan layanan nyaman SriLankan Airlines.</p><p>Kunjungi destinasi ikonik seperti <strong>Pinnawala Elephant Orphanage</strong>, serta situs warisan dunia <strong>Dambulla Cave Temple</strong>. Nikmati pengalaman budaya di <strong>Temple of the Tooth</strong> dan pertunjukan khas Sri Lanka di Kandy.</p><p>Rasakan keindahan alam pegunungan di <strong>Nuwara Eliya</strong> dengan hamparan <strong>Tea Plantation</strong> dan pemandangan <strong>Ramboda Waterfalls</strong> yang memukau. Perjalanan ditutup dengan city tour di Colombo, mengunjungi landmark seperti <strong>Lotus Tower</strong>dan area ikonik kota.</p><p>Didukung <strong>hotel bintang 3</strong>, fasilitas lengkap, serta itinerary nyaman, paket ini cocok untuk Anda yang ingin menikmati Sri Lanka dengan pengalaman lengkap dan berkesan.</p><p><strong>Wujudkan petualangan eksotis Anda sekarang! ✨</strong></p>', NULL, NULL, NULL, 18850000.00, NULL, 6, 5, '[]', NULL, NULL, '<p>Tiket Internasional dengan Srilanka Air ( UL ) kelas ekonomi Rute : CGK – CMB - CGK (Non Refundalble, Non-Reroutable, Non-Endorsable, Non Upgrade) Bagasi Maksimal 20Kg atau sesuai dengan ketentuan Penerbangan Airport Tax International (Subject to Change) Makan (Pagi, Siang, Malam) sesuai dengan yang tercantum di acara perjalanan. Akomodasi menginap di Hotel dengan Kondisi 1 kamar diisi oleh 2 orang dewasa/anak (twin share) Transportasi Bus &amp; Admission Fee objek wisata sesuai dengan yang tercantum di acara perjalanan. Tour Leader Asuransi perjalanan group ( dengan usia tertanggung maksimal 69 tahun ).</p>', '<p>Tipping Rp. 870.000,-/orang Pengeluaran pribadi seperti: porter, mini bar, room service,telepon, laundry,dll. Tips porter di hotel/airport (bila ada) Biaya kelebihan bagasi Pengurusan Dokumen Perjalanan seperti : Passport, Visa, Entry Permit, dll Tour tambahan (optional) yang diadakan selama perjalanan Biaya yang tidak disebutkan diatas PPN 1,1%</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/wlAFU17sTk7QGRZ23rfR8WdZGBEmWNwVZha0yP6N.pdf', 0, NULL, '2026-04-22 06:11:50', '2026-04-24 02:54:00'),
(26, 25, '5D4N Simply Taiwan', NULL, '5d4n-simply-taiwan', '<h3><strong>5D4N Simply Taiwan – Taipei Experience ✨</strong></h3><p>Jelajahi keindahan <strong>Taipei</strong> dalam perjalanan <strong>5 hari 4 malam</strong> yang memadukan <strong>alam, budaya, dan modern lifestyle</strong>. Kunjungi <strong>Jiufen Old Street</strong>, <strong>Shifen Waterfall</strong>, dan rasakan pengalaman unik <strong>Sky Lantern di Shifen Old Street</strong> ✨**.</p><p>Nikmati pemandangan alam di <strong>Qingtiangang Grassland</strong> &amp; <strong>Beitou Thermal Valley</strong>, serta kunjungi ikon modern <strong>Taipei 101</strong>. Lengkapi liburan dengan shopping &amp; kuliner di <strong>Ximending</strong> 🛍️.</p><p>Dengan <strong>hotel bintang 3</strong>, itinerary nyaman, dan <strong>free time di Taipei</strong>, paket ini cocok untuk liburan santai &amp; berkesan.</p><p><strong>Yuk ke Taiwan sekarang! ✨</strong></p>', NULL, NULL, NULL, 12990000.00, NULL, 5, 4, '[]', NULL, NULL, '<p>Tiket internasional dengan China Airlines (CI) / STURLUX (JX) / EVA AIR (BR) dengan rute Jakarta – Taiwan – Jakarta (Non Re – routable, Non Endorsable, Non Upgrade) Airport Tax (masih dapat berubah sewaktu-waktu) Berat maksimum sebesar 20kg untuk 1 bagasi atau sesuai dengan peraturan maskapai penerbangan yang digunakan; dan berat maksimum 5 kg untuk 1 handbag kecil untuk dibawa ke kabin pesawat atau sesuai dengan peraturan maskapai penerbangan yang digunakan. Penginapan di hotel bintang 3*/setaraf berdasarkan minimum 2 (dua) orang dalam 1 kamar (twin sharing). Acara tour, transportasi dan makan sesuai yang tercantum dalam acara perjalanan. (MP – Makan Pagi; MS – Makan Siang; MM – Makan Malam). Biaya asuransi perjalanan group dengan usia tertanggung maksimum 69 tahun Tour Leader dari Jakarta Kunjungan Toko Wajib : Pineapple Cake Shop, Duty Free Shop</p>', '<p>Biaya Pengurusan Dokumen Perjalanan: Passport, Visa, Entry permit dll Pengeluaran pribadi seperti: telepon, room service, laundry, mini bar, tambahan makanan dan minuman serta pengeluaran lainnya. Excess baggage (biaya kelebihan barang bawaan di atas 20 kg), Biaya bea masuk yang dikenakan oleh duane di Jakarta maupun di negara yang dikunjungi. Biaya Single Supplement bagi peserta yang menempati 1 kamar sendiri. Optional / Tour Tambahan Tipping Bell Boy Hotel, Porter Airport Biaya lain yang tidak tercantum di atas Biaya Pengurusan Visa Taiwan sebesar Rp. 1.000.000 per orang ( Single Entry proses biasa ) Tipping untuk tour leader, local guide dan driver sebesar Rp.670.000 per orang Ppn 1,1%</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/ITlnVvG2M1hnDpLsnjSSxSHGxdpkhnlfW5A9AtqJ.pdf', 0, NULL, '2026-04-22 06:43:08', '2026-04-24 02:38:44'),
(27, 26, 'Fun Beijing Tianjin + Brunei 6D', NULL, 'fun-beijing-tianjin-brunei-6d', '<h3><strong>Fun Beijing Tianjin + Brunei 6D – School Holiday ✨</strong></h3><p>Nikmati liburan seru ke <strong>Beijing</strong> dengan transit <strong>Brunei Darussalam</strong> menggunakan <strong>Royal Brunei Airlines</strong>. Kunjungi ikon dunia seperti <strong>Great Wall of China</strong>, <strong>Temple of Heaven</strong>, <strong>Forbidden City</strong>, dan <strong>Tiananmen Square</strong>.</p><p>Rasakan keseruan di <strong>Universal Studios Beijing</strong> 🎢 serta pengalaman naik <strong>Bullet Train</strong> menuju <strong>Tianjin</strong>. Nikmati juga waktu belanja di <strong>Wangfujing Street</strong> dan <strong>Yandaxie Street</strong>.</p><p>Dengan <strong>hotel bintang 4</strong>, fasilitas lengkap, dan itinerary menarik, paket ini cocok untuk <strong>liburan sekolah</strong> yang seru dan berkesan.</p><p><strong>Yuk wujudkan liburan impianmu sekarang! ✨</strong></p>', NULL, NULL, NULL, 11900000.00, NULL, 6, 5, '[]', NULL, '<p>HIGHLIGHT : UNIVERSAL STUDIO BEIJING, JUYONGGUAN GREAT WALL, TEMPLE OF HEAVEN, FORBIDDEN CITY, YANDAXIE STREET, EXPERIENCE BULLET TRAIN CHINA</p>', '<p>Tiket International CGK-PKX, PKX-CGKxBWN by Royal Brunei Airlines International Tax+YQ Bagasi 20Kg sesuai dengan peraturan penerbangan Akomodasi hotel *4 atau setaraf Transportasi bus ber-AC &amp; tiket masuk objek wisata Acara Tour &amp; makan sesuai program paket tour diatas</p>', '<p>Travel Insurance Visa China Pengurusan Document perjalanan : Passport Tips Porter Hotel, Mini Bar, Laundry, Telp dll.</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/6BE3FHHycsi5PXm0kwVRUABGQJRPDM7vnimmqwvL.pdf', 0, NULL, '2026-04-22 07:34:47', '2026-04-24 02:24:40'),
(28, 27, '6D Korea Grand Sale', NULL, '6d-korea-grand-sale', '<h3><strong>6D Korea Grand Sale 2026 – Seoul &amp; Nami Island Experience ✨</strong></h3><p>Nikmati liburan 6 hari 5 malam ke <strong>Seoul</strong> dengan layanan premium <strong>Malaysia Airlines</strong> dari berbagai kota di Indonesia. Jelajahi destinasi ikonik seperti <strong>Nami Island</strong>, <strong>COEX Mall</strong>, <strong>Gyeongbokgung Palace</strong>, hingga <strong>Namsan Seoul Tower</strong>.</p><p>Rasakan pengalaman budaya Korea dengan mengenakan <strong>Hanbok</strong> dan membuat <strong>Kimchi/Kimbap</strong>, serta nikmati waktu belanja di <strong>Myeongdong</strong>, <strong>Dongdaemun</strong>, dan <strong>Hongdae</strong>.</p><p>Dengan <strong>hotel bintang 3</strong> yang nyaman dan fasilitas lengkap, paket ini adalah pilihan terbaik untuk liburan ke Korea dengan <strong>harga terjangkau</strong>.</p><p><strong>Wujudkan perjalanan impian Anda sekarang! 🇰🇷✨</strong></p>', NULL, NULL, NULL, 11990000.00, NULL, 6, 5, '[]', NULL, '<p>HIGHLIGHT: Nami Island, COEX mall, Gyeongbokgung Palace, Namsan Seoul Tower</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International by Malaysia Airlines, Economy termasuk taxes internasional</p><p>Bagasi 20 kg/30 Kg sesuai dengan ketentuan Airlines/Kondisi Booking</p><p>Akomodasi hotel *3 setaraf (Twin / Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program pake tour diatas</p><p>Mineral Water 01 Botol Perhari</p><p>Tour Leader</p><p>Travel Kits (Luggage Tag)</p><p>Travel Insurance</p>', '<p>Administrasi Visa Group Visa Korea (Rp 300.000 (Jika dianggap tidak memenuhi syarat, maka akan diarahkan untuk membuat Visa Individual dengan Biaya Visa Individual Rp 1.075.000)</p><p>Tipping Tour Leader, Local Guide, Driver: Rp. 690.000/Pax</p><p>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p><p>PCR Test / Rapid Test Antigen Jika dibutuhkan</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/QGe0QalXHZTXKJpuwhTZ7emU4mPS5IDGnM5ZkOTf.pdf', 0, NULL, '2026-04-24 01:05:18', '2026-04-24 02:02:20'),
(29, 26, '8D New Super Sale Beijing + Shanghai', NULL, '8d-new-super-sale-beijing-shanghai', '<p>Nikmati perjalanan menjelajahi Tiongkok dari <strong>Beijing</strong> hingga <strong>Shanghai</strong> dengan layanan premium <strong>Malaysia Airlines</strong>. Kunjungi ikon dunia seperti <strong>Temple of Heaven</strong>, <strong>Tiananmen Square</strong>, dan <strong>Great Wall of China</strong>.</p><p>Nikmati keindahan alam di <strong>Suzhou</strong> dan <strong>Hangzhou</strong>, termasuk <strong>West Lake</strong>, serta jelajahi pesona modern Shanghai di <strong>The Bund</strong> dan <strong>Nanjing Road</strong>.</p><p>Didukung <strong>hotel bintang 4</strong>, kuliner khas seperti <strong>Bebek Peking</strong>, serta destinasi belanja favorit, paket ini menghadirkan pengalaman Tiongkok yang lengkap dan berkesan.</p><p><strong>Wujudkan perjalanan impian Anda sekarang! ✨</strong></p>', NULL, NULL, NULL, 12990000.00, NULL, 8, 7, '[]', NULL, '<p>HIGHLIGHT: TEMPLE OF HEAVEN, TIAN AN MEN SQUARE, JUYONGGUAN GREAT WALL, JINJI LAKE, WUZHEN, TV TOWER, THE BUND</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International by Malaysia Airlines, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)</p><p>Bagasi 30 kg sesuai dengan ketentuan Airlines</p><p>Akomodasi hotel *4 lokal atau setaraf (Twin /Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program paket tour diatas</p><p>Mineral Water 01 Botol Perhari</p><p>Tour Leader</p><p>Travel Kits (Luggage Tag)</p><p>Travel Insurance</p>', '<p>Visa Group China Rp 1,000,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China)</p><p>Visa Single China Rp 1,000,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China) // (masuk dalam Konsulat Jakarta)&nbsp;</p><p>Visa Single China Rp 1,200,000 (*Ketentuan dapat</p><p>berubah sewaktu-waktu dari kedutaan besar China)</p><p>// (masuk dalam konsulat Surabaya/Medan)</p><p>Visa Single China Rp 1,300,000 (*Ketentuan dapat</p><p>berubah sewaktu-waktu dari kedutaan besar China)</p><p>// (masuk dalam konsulat Bali)</p><p>•Tipping Tour Leader, Local Guide, Driver:</p><p>Rp100.000/Pax/Day (8HARI) =&gt; Total Rp</p><p>800,000/Pax</p><p>Tips Porter Hotel, Mini Bar, Laundry, Telp,</p><p>Kelebihan bagasi dll.</p><p>PCR Test / Rapid Test Antigen Jika dibutuhkan</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/yCUPGbG4WuUvZm76ulujIwGOWFcsiUc5EM6TIyOM.pdf', 0, NULL, '2026-04-24 01:39:56', '2026-04-24 02:01:26'),
(30, 20, '7D Super Sale Gr Japan + Shirakawago', NULL, '7d-super-sale-gr-japan-shirakawago', '<p><strong>JAPAN GOLDEN ROUTE + SHIRAKAWAGO 7D6N</strong> ✨</p><p>Jelajahi keindahan Jepang dalam perjalanan lengkap mulai dari <strong>Osaka</strong>, <strong>Kyoto</strong>, hingga <strong>Tokyo</strong>!</p><p>Kunjungi desa tradisional <strong>Shirakawa-go</strong> dengan rumah khas gassho-zukuri, nikmati suasana klasik di <strong>Takayama Old Town</strong>, serta rasakan pengalaman berendam onsen khas Jepang.</p><p>Nikmati panorama indah <strong>Mount Fuji</strong> dan berfoto di <strong>Lake Kawaguchi</strong>, dilengkapi waktu bebas menjelajah Tokyo dan berbelanja di kawasan populer.</p><p><strong>Liburan lengkap: budaya, alam, kota modern, dan pengalaman autentik Jepang dalam satu paket! 🇯🇵</strong></p>', NULL, NULL, NULL, 19990000.00, NULL, 7, 6, '[]', NULL, '<p>HIGHLIGHT: Shirakawago – Mt. Fuji – Takayama Old Town –</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International Jakarta-Osaka/ Narita- Jakarta dengan Malaysia Airlines, Economy termasuk seluruh taxes (Tiket Grup Fixed Date &amp; No Extend)</p><p>Bagasi 30 kg per orang atau sesuai dengan ketentuan Airlines</p><p>Akomodasi hotel *3/*4 setaraf (Twin / Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program paket tour diatas</p><p>Tour Leader</p><p>Travel Insurance sampai usia 69 tahun</p><p>Lugage Tag</p>', '<p>Visa Jepang: Rp.800.000/pax (Domisili Jakarta) Jakarta, Banten, Jawa Barat, Jawa Tengah, Yogyakarta, Kalimantan Tengah, Kalimantan Barat, Sumatera Selatan, Bangka Belitung, Bengkulu, Lampung</p><p>Visa Jepang Biasa: Rp.1.050.000/pax (Domisili Luar Jakarta) Sulawesi Utara, Gorontalo, Sulawesi Tengah, Sulawesi Tenggara, Sulawesi Selatan, Sulawesi Barat, Maluku Utara, Maluku, Papua (Irian Jaya), Papua Barat</p><p>Visa Waiver Rp 300.000/pax</p><p>Tipping Local Guide, Driver, Tour Leader: Rp. 805.000</p><p>TipsPorter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p><p>Air Minum</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/4Tdz4ATGYe1GeaxIT6eXKCX1umnRDNNhLwXqEwFl.pdf', 0, NULL, '2026-04-24 13:55:24', '2026-04-24 14:01:25'),
(37, 27, '6D Beautiful New Korea', NULL, '6d-beautiful-new-korea', '<p><strong>6D BEAUTIFUL NEW KOREA – NAMI ISLAND, MT. SORAK &amp; SEOUL</strong> ✨</p><p>Jelajahi pesona Korea Selatan mulai dari romantisnya <strong>Nami Island</strong>, keindahan alam <strong>Seoraksan National Park</strong>, hingga budaya tradisional di <strong>Gyeongbokgung Palace</strong> dan <strong>Eunpyeong Hanok Village</strong>.</p><p>Nikmati juga sisi modern <strong>Seoul</strong> dengan kunjungan ke <strong>Starfield Library</strong>, Hongdae, dan <strong>N Seoul Tower</strong>.</p><p><strong>Perpaduan alam, budaya, dan K-Pop dalam satu perjalanan tak terlupakan!</strong> 🇰🇷</p>', NULL, NULL, NULL, 13590000.00, NULL, 6, 5, '[\"13 May 2026\",\"26 May 2026\",\"4 June 2026\",\"1 Juli 2026\",\"2 Juli 2026\",\"9 Juli 2026\",\"16 Juli 2026\",\"23 Juli 2026\",\"6 Agustus 2026\",\"13 Agustus 2026\"]', NULL, '<p>HIGHLIGHT: Starfield Library, Kimbap Making, Nami Island, Mt. Sorak, Hanbok Wearing at Gyeongbok Palace, Eunpyeong Hanok Village</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International Jakarta-Incheon Asiana Airlines/ Garuda Indonesia/Korean Airlines/Malaysia Airlines Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)</p><p>Bagasi sesuai dengan ketentuan Airlines (Asiana/Korean Air 1pcs Maks 23kg, Garuda Indonesia 30 kg, Malaysia Airlines 30 kg)</p><p>Akomodasi hotel *3 setaraf (Twin / Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program paket tour diatas</p><p>Mineral Water 1 Botol Per Hari</p><p>Tour Leader</p><p>Travel Kits (Luggage Tag)</p><p>Travel Insurance (sampai usia 69 Tahun)</p>', '<p>Biaya Administrasi Visa Group Visa Korea Rp. 300.000 (Jika dianggap tidak memenuhi syarat, maka akan diarahkan untuk membuat Visa Individual dengan Biaya Visa Individual Rp 1.075.000) *Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar Korea</p><p>Tipping Tour Leader, Local Guide, Driver Rp. 115.000/Pax/Day (6HARI) =&gt; Total Rp. 690.000/Pax</p><p>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p><p>PCR Test / Rapid Test Antigen Jika dibutuhkan</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/3461vY3C57BrMcYK7jxMd2btD41tTZ6v4gtW9Pls.pdf', 0, NULL, '2026-04-24 14:17:39', '2026-04-27 08:57:43'),
(38, 27, '6D Shocking Sale Korea', NULL, '6d-shocking-sale-korea', '<p><strong>6D SHOCKING SALE KOREA – NAMI ISLAND &amp; SEOUL</strong> ✨</p><p>Jelajahi pesona Korea Selatan mulai dari romantisnya <strong>Nami Island</strong>, hingga serunya kota modern <strong>Seoul</strong> dengan kunjungan ke <strong>Starfield Library</strong>, Hongdae, dan Myeongdong.</p><p>Rasakan pengalaman budaya dengan mengenakan hanbok di <strong>Gyeongbokgung Palace</strong> serta mencoba membuat kimbap khas Korea.</p><p><strong>Dilengkapi 1 hari free leisure untuk eksplorasi bebas, kombinasi wisata, budaya, dan belanja dalam satu perjalanan hemat!</strong> 🇰🇷</p>', NULL, NULL, NULL, 10999000.00, NULL, 6, 5, '[]', NULL, '<p>HIGHLIGHT: Nami Island, Starfield Library, Kimchi/Kimbap Making, Hanbok Wearing, Starfield Library.</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International Jakarta-Incheon by Premium Direct Flight, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)</p><p>Bagasi sesuai dengan ketentuan Airlines</p><p>Akomodasi hotel *3 setaraf (Twin / Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program paket tour diatas</p><p>Mineral Water 01 Botol Perhari</p><p>Tour Leader</p><p>Travel Insurance</p><p>&nbsp;</p>', '<p>Biaya Administrasi Visa Group Visa Korea Rp. 300.000 (Jika dianggap tidak memenuhi syarat, maka akan diarahkan untuk membuat Visa Individual dengan Biaya Visa Individual Rp 1.050.000) (Wajib-Jika tidak buat visa di kami, tetap</p><p>akan kami kenakan biaya administrasi yang sama)</p><p>Tipping Tour Leader, Local Guide, Driver: Rp. 700,000</p><p>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/lHKOw4aLLjhn8QUtbvI5kYUoDlnfGYu9ifnK5Cuh.pdf', 0, NULL, '2026-04-24 14:46:51', '2026-04-24 14:49:09'),
(39, 27, '6D Halal Tour Korea 2026', NULL, '6d-halal-tour-korea-2026', '<p><strong>6D HALAL TOUR KOREA – ANSAN, NAMI ISLAND &amp; SEOUL</strong> ✨</p><p>Nikmati perjalanan halal-friendly ke Korea Selatan dengan pengalaman lengkap mulai dari alam, budaya, hingga wisata religi di <strong>Seoul</strong> 🇰🇷</p><p>Kunjungi indahnya <strong>Nami Island</strong> yang terkenal sebagai lokasi syuting <i>Winter Sonata</i>, serta jelajahi suasana tradisional di <strong>Eunpyeong Hanok Village</strong>. Rasakan pengalaman budaya dengan mengenakan hanbok di <strong>Gyeongbokgung Palace</strong>.</p><p>Perjalanan ini juga dilengkapi dengan kunjungan ke tempat-tempat ramah Muslim seperti <strong>Ansan Mosque</strong> dan <strong>Seoul Central Mosque</strong>, sehingga ibadah tetap nyaman selama liburan.</p><p>Nikmati juga keindahan kota dari <strong>N Seoul Tower</strong>, serta eksplorasi modern di <strong>Starfield Library</strong> dan pusat belanja populer.</p><p><strong>Perpaduan wisata halal, budaya Korea, dan pengalaman modern dalam satu perjalanan nyaman &amp; berkesan!</strong>✨</p>', NULL, NULL, NULL, 13990000.00, NULL, 6, 1, '[]', NULL, '<p>Ansan Mosque, Itaewon Central Mosque, Bada Hyanggi Theme Park, Nami Island, Eunpyeong Hanok Village, Wearing Hanbok at Gyeongbok Palace</p><p>GUARANTEE BEST PRICE &amp; SERVICE</p>', '<p>Tiket International Jakarta-Incheon by Garuda Indones, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)</p><p>Bagasi sesuai dengan ketentuan Airlines</p><p>Akomodasi hotel *3 setaraf (Twin / Triple)</p><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p><p>Acara Tour &amp; makan sesuai program paket tour diatas</p><p>Mineral Water 01 Botol Perhari</p><p>Tour Leader</p><p>Travel Kits (Luggage Tag)</p><p>Travel Insurance (Berlaku sampai usia 69 Tahun)</p>', '<p>Biaya Administrasi Visa Group Visa Korea Rp. 300.000 (Jika dianggap tidak memenuhi syarat, maka akan diarahkan untuk membuat Visa Individual dengan Biaya Visa Individual Rp. 1.075.000) *Ketentuan dapat berubah sewaktu waktu dari kedutaan besar Korea</p><p>Tipping Tour Leader, Local Guide, Driver : Rp. 115.000/Pax/Day (6HARI) =&gt; Total Rp. 690.000/Pax</p><p>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p><p>PCR Test / Rapid Test Antigen Jika dibutuhkan</p><p>OPTIONAL:</p><p>Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/C29IWavLhQVy4Z5YjM1ur1QwbwQzyXrw20D6IM5y.pdf', 0, NULL, '2026-04-24 15:10:15', '2026-04-24 15:12:39'),
(40, 28, '9D Best Eropa Barat + Titisee + Rhinefalls + Roermond Outlet', NULL, '9d-best-eropa-barat-titisee-rhinefalls-roermond-outlet', '<p><strong>AUTUMN SEASON – 9D BEST EROPA BARAT</strong></p><p>Nikmati perjalanan eksklusif menjelajahi 6 negara terbaik di Eropa dalam 9 hari yang penuh kesan. Rasakan romantisme Paris dengan ikon dunia seperti Eiffel Tower, keindahan kota klasik Belgia dengan Manneken Pis, serta suasana tradisional Belanda di Zaanse Schans.</p><p>Perjalanan dilengkapi panorama alam yang memukau, mulai dari Titisee Lake hingga kemegahan Rhine Falls, dan ditutup dengan pesona elegan kota Milan di Duomo di Milano.</p><p>✧ 6 Negara<br>✧ 9 Hari Perjalanan<br>✧ Ikon Dunia &amp; Kota Klasik<br>✧ Wisata Alam &amp; Belanja Eksklusif</p><p>Satu perjalanan istimewa untuk menghadirkan pengalaman Eropa yang berkelas dan tak terlupakan 🤩✨</p>', '<p><strong>AUTUMN SEASON – 9D BEST OF WESTERN EUROPE</strong></p><p>Enjoy an exclusive journey across 6 of Europe’s finest countries in a memorable 9-day experience. Discover the romance of Paris with iconic landmarks such as the Eiffel Tower, explore the charm of Belgium with Manneken Pis, and immerse yourself in the traditional atmosphere of the Netherlands at Zaanse Schans.</p><p>The journey is enriched with breathtaking natural scenery, from the beauty of Titisee Lake to the grandeur of Rhine Falls, and concludes with the elegance of Milan at the Duomo di Milano.</p><p>✧ 6 Countries<br>✧ 9 Days Journey<br>✧ World Icons &amp; Classic Cities<br>✧ Nature &amp; Exclusive Shopping</p><p>A remarkable journey designed to deliver a truly refined and unforgettable European experience 🤩✨</p>', '<p><strong>가을 시즌 – 서유럽 9일 베스트 여행</strong></p><p>9일 동안 유럽 최고의 6개국을 여행하는 특별한 여정을 경험해 보세요. 에펠탑이 있는 낭만적인 파리, 마네켄 피스로 유명한 벨기에의 매력, 그리고 잔세스칸스에서 느끼는 네덜란드의 전통적인 분위기를 만나보실 수 있습니다.</p><p>티티제 호수의 아름다움부터 라인 폭포의 장엄함까지 이어지는 자연 경관을 감상하고, 마지막으로 밀라노의 두오모에서 우아한 도시의 매력을 경험하며 여정을 마무리합니다.</p><p>✧ 6개국<br>✧ 9일 여행<br>✧ 세계적인 명소 &amp; 클래식 도시<br>✧ 자연과 프리미엄 쇼핑</p><p>품격 있고 잊지 못할 유럽 여행을 선사하는 특별한 일정입니다 🤩✨</p>', '<p><strong>秋季限定 – 西欧9日精华之旅</strong></p><p>开启一段为期9天的尊贵旅程，探索欧洲6大经典国家。感受巴黎的浪漫风情（埃菲尔铁塔）、欣赏比利时的标志性景点小尿童，以及在桑斯安斯风车村体验荷兰的传统魅力。</p><p>行程更包含迷人的自然景观，从滴滴湖的宁静之美到莱茵瀑布的壮丽景色，并以米兰大教堂的优雅魅力为旅程画上完美句号。</p><p>✧ 6个国家<br>✧ 9天行程<br>✧ 世界地标与经典城市<br>✧ 自然风光与精品购物</p><p>一场精致难忘的欧洲之旅，带给您非凡体验 🤩✨</p>', 25850000.00, NULL, 9, 8, '[\"16 - 4 Oktober 2026\",\"7 - 15 Oktober 2026\",\"14 - 22 Oktober 2026\"]', NULL, '<p>HIGHLIHTS: <strong>EIFFEL TOWER – MANEKIN PISS – ZAANSE SCHANS – VOLENDAM - TITISEE LAKE RHINEFALLS – DUOMO DI MILANO – GALLERIA VITTORIO EMANUELLE II</strong></p>', '<p>Tiket internasional : JAKARTA – PARIS | MILAN – JAKARTA By EMIRATES QATAR/ETIHAD Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</p><p>Bagasi sesuai dengan peraturan penerbangan (25/30 kg)</p><p>Akomodasi Hotel 3* nyaman selama 7 malam (based on Twin Sharing)</p><p>Base on Availability &amp; Confirmations in Final Itinerary</p><p>Transportasi Bus ber AC 49 seater</p><p>Fuel surcharge, airport tax Jakarta</p>', '<p>Visa Schengen : 3.875.000 /Pax (Non Refund)</p><p>Internasional Taxes &amp; Surcharges : Rp. 2.950.000/Pax (Wajib)</p><p>Tipping TL, driver, : IDR 2.150.000 /Pax (Wajib)</p><p>City tax Rp. 250.000 /Pax (Wajib)</p><p>Travel Insurance: IDR 600.000 /Pax (Wajib)</p><p>Pengeluaran pribadi : Laundry, Phone, Minibar, dll</p><p>Pengurusan dokumen perjalanan : Passpor, Visa, dll</p><p>Optional Tour ( Mt Titlis : Euro 140/pax, Seine River Rp. 500.000/pax,)</p><p>Biaya kelebihan bagasi, Biaya Extend</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/3yT43XGCGmYi2KKXZVGWq12sDPmECkPPR3Y52TBq.pdf', 0, NULL, '2026-04-24 15:50:33', '2026-04-27 02:14:28'),
(41, 28, '9D Best Eropa Barat + Titisee + Rhinefalls + Roermond Outlet (Sep)', NULL, '9d-best-eropa-barat-titisee-rhinefalls-roermond-outlet-sep', '<h2><strong>AUTUMN SEASON – 9D BEST EROPA BARAT</strong></h2><p><strong>+ Titisee • Rhine Falls • Roermond Outlet</strong><br><i>(6 Negara Terbaik di Eropa)</i></p><p>Nikmati perjalanan istimewa menjelajahi pesona Eropa Barat dalam 9 hari yang dirancang lengkap dan berkelas. Dimulai dari kota romantis Paris dengan ikon dunia Eiffel Tower, perjalanan membawa Anda menyusuri kota-kota klasik Belgia hingga melihat keunikan Manneken Pis.</p><p>Rasakan pengalaman khas Belanda di Zaanse Schans dan desa nelayan Volendam yang penuh nuansa tradisional. Perjalanan semakin lengkap dengan kesempatan berbelanja di Designer Outlet Roermond, salah satu outlet terbesar di Eropa.</p><p>Keindahan alam pun menjadi bagian tak terpisahkan, mulai dari danau menawan Titisee Lake hingga kemegahan Rhine Falls di Swiss. Anda juga dapat menikmati panorama pegunungan Alpen di Mount Titlis (opsional).</p><p>Perjalanan ditutup dengan sentuhan elegan kota mode Milan melalui kunjungan ke Duomo di Milano dan Galleria Vittorio Emanuele II yang ikonik.</p><p>✧ 6 Negara dalam 1 Perjalanan<br>✧ 9 Hari Penuh Pengalaman Berkesan<br>✧ Ikon Dunia &amp; Kota-Kota Klasik<br>✧ Panorama Alam Eropa yang Memukau<br>✧ Shopping di Outlet Terkenal</p><p>Satu perjalanan eksklusif yang menghadirkan perpaduan sempurna antara budaya, keindahan alam, dan gaya hidup Eropa dirancang untuk menjadi pengalaman yang tak terlupakan 🤩✨</p>', '<p><strong>AUTUMN SEASON – 9D BEST OF WESTERN EUROPE</strong></p><ul><li data-list-item-id=\"ea48c9a1d1725d0190dcbddc8c72ceecd\">Titisee • Rhine Falls • Roermond Outlet<br>(6 Best Countries in Europe)</li></ul><p>Enjoy a remarkable journey exploring the charm of Western Europe in a well-designed 9-day experience. Starting from the romantic city of Paris with the world-famous Eiffel Tower, the journey continues through the classic cities of Belgium, featuring the unique Manneken Pis.</p><p>Experience the authentic Dutch atmosphere at Zaanse Schans and the charming fishing village of Volendam. The trip is further enhanced with a shopping experience at Designer Outlet Roermond, one of the largest outlets in Europe.</p><p>Marvel at breathtaking natural scenery, from the beauty of Titisee Lake to the grandeur of Rhine Falls in Switzerland. You may also enjoy the stunning Alps at Mount Titlis (optional).</p><p>The journey concludes with the elegance of Milan, visiting Duomo di Milano and Galleria Vittorio Emanuele II.</p><p>✧ 6 Countries in One Journey<br>✧ 9 Days of Memorable Experience<br>✧ World Icons &amp; Classic Cities<br>✧ Stunning Natural Landscapes<br>✧ Exclusive Shopping Experience</p><p>An exclusive journey combining culture, nature, and European lifestyle—crafted to create unforgettable memories 🤩✨</p>', '<p><strong>가을 시즌 – 서유럽 9일 베스트 여행</strong></p><ul><li data-list-item-id=\"e658ec1ab2c55f28009dc3603bbf7d9c8\">티티제 • 라인 폭포 • 로어몬드 아울렛<br>(유럽 최고의 6개국)</li></ul><p>완벽하게 구성된 9일 일정으로 서유럽의 매력을 경험해 보세요. 낭만적인 파리에서 세계적인 명소인 Eiffel Tower를 시작으로, 벨기에의 클래식한 도시와 Manneken Pis를 만나보실 수 있습니다.</p><p>네덜란드의 전통 마을 Zaanse Schans와 아름다운 어촌 마을 Volendam에서 특별한 경험을 즐기고, Designer Outlet Roermond에서 쇼핑을 만끽해 보세요.</p><p>티티제 호수 Titisee Lake의 아름다움과 스위스의 Rhine Falls의 장관을 감상할 수 있으며, 선택 관광으로 Mount Titlis 알프스의 절경도 즐기실 수 있습니다.</p><p>마지막으로 밀라노에서 Duomo di Milano와 Galleria Vittorio Emanuele II를 방문하며 우아하게 여행을 마무리합니다.</p><p>✧ 6개국 여행<br>✧ 9일간의 특별한 경험<br>✧ 세계적인 명소 &amp; 클래식 도시<br>✧ 아름다운 자연 경관<br>✧ 프리미엄 쇼핑</p><p>문화, 자연, 유럽 라이프스타일이 어우러진 잊지 못할 여행을 선사합니다 🤩✨</p>', '<p><strong>秋季限定 – 西欧9日精华之旅</strong></p><ul><li data-list-item-id=\"eb030521b794b18449192f9bc593edb2d\">滴滴湖 • 莱茵瀑布 • 罗尔蒙德奥特莱斯<br>（欧洲6大经典国家）</li></ul><p>开启一段精心设计的9天旅程，探索西欧的独特魅力。从浪漫之都巴黎及其标志性景点 Eiffel Tower 出发，前往比利时经典城市，欣赏著名的 Manneken Pis。</p><p>随后体验荷兰的传统风情，游览 Zaanse Schans 风车村和美丽的 Volendam 渔村，并在 Designer Outlet Roermond 尽情购物。</p><p>行程还包含迷人的自然景观，从 Titisee Lake 的宁静之美，到瑞士 Rhine Falls 的壮丽景色。您还可选择前往 Mount Titlis 欣赏阿尔卑斯山风光。</p><p>最后在时尚之都米兰，参观 Duomo di Milano 和 Galleria Vittorio Emanuele II，为旅程画上优雅句号。</p><p>✧ 6个国家<br>✧ 9天精彩行程<br>✧ 世界地标与经典城市<br>✧ 壮丽自然风光<br>✧ 精品购物体验</p><p>一场融合文化、自然与欧洲生活方式的高端旅程，为您带来难忘回忆 🤩✨</p>', 25850000.00, NULL, 9, 5, '[\"15 - 23 September 2026\",\"18 - 26 September 2026\",\"22 - 30 September 2026\"]', NULL, '<p>HIGHLIHTS:</p><p style=\"text-align:center;\"><strong>EIFFEL TOWER – MANEKIN PISS – ZAANSE SCHANS – VOLENDAM - TITISEE LAKE – RHINEFALLS – DUOMO DI MILANO – GALLERIA VITTORIO EMANUELLE II</strong></p>', '<p>Tiket internasional : JAKARTA – PARIS | MILAN – JAKARTA By EMIRATES QATAR/ETIHAD Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</p><p>Bagasi sesuai dengan peraturan penerbangan ( 25/30 kg)</p><p>Akomodasi Hotel 3* nyaman selama 7 malam ( based on Twin Sharing) Base on Availability &amp; Confirmations in Final Itinerary</p><p>Transportasi Bus ber AC 49 seater</p><p>Fuel surcharge, airport tax Jakarta</p>', '<p>Visa Schengen : 3.875.000 /Pax (Non Refund)</p><p>Internasional Taxes &amp; Surcharges : Rp 2.950.000/Pax (Wajib)</p><p>Tipping TL, driver, : IDR 2.150.000 /Pax (Wajib)</p><p>City tax Rp. 250.000 /Pax (Wajib)</p><p>Travel Insurance: IDR 600.000 /Pax (Wajib)</p><p>Pengeluaran pribadi : Laundry, Phone, Minibar, dll</p><p>Pengurusan dokumen perjalanan : Passpor, Visa, dll</p><p>Optional Tour ( Mt Titlis : Euro 140/pax, Seine River Rp. 500.000/pax,)</p><p>Biaya kelebihan bagasi, Biaya Extend</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/kv1k1ekOWXqu7Dcw3qth0UGn5lNiRxhLudx70xqA.pdf', 0, NULL, '2026-04-24 17:02:17', '2026-04-27 02:42:55'),
(42, 28, '11D8N Eropa Barat + Lake Brienz + Mt Titlis', NULL, '11d8n-eropa-barat-lake-brienz-mt-titlis', '<h2><strong>UMMER HOLIDAYS – 11D8N BEST EROPA BARAT</strong></h2><p><strong>+ Lake Brienz • Mt. Titlis</strong><br><i>(6 Negara Terbaik di Eropa)</i></p><p>Nikmati perjalanan musim panas yang istimewa menjelajahi pesona Eropa Barat selama 11 hari penuh pengalaman tak terlupakan. Perjalanan dimulai dari kota romantis Paris dengan ikon dunia Eiffel Tower, dilengkapi kunjungan ke landmark bersejarah dan kesempatan menikmati suasana kota yang elegan.</p><p>Anda akan melanjutkan perjalanan ke Belgia untuk melihat ikon unik Manneken Pis, kemudian menuju Belanda untuk merasakan kehidupan tradisional di Zaanse Schans serta desa nelayan Volendam yang penuh pesona.</p><p>Perjalanan semakin kaya dengan nuansa budaya dan sejarah di Jerman dan Prancis, sebelum memasuki keindahan alam Swiss yang menakjubkan. Nikmati panorama danau yang jernih di Lake Brienz serta desa indah Lauterbrunnen yang dikelilingi pegunungan Alpen.</p><p>Di Swiss, Anda juga berkesempatan menikmati pengalaman tak terlupakan di Mount Titlis dengan pemandangan salju abadi (opsional), serta keindahan Lake Lucerne yang menenangkan.</p><p>Perjalanan ditutup dengan sentuhan elegan Italia, mengunjungi Duomo di Milano yang megah dan berbelanja di Galleria Vittorio Emanuele II, serta menikmati keindahan Lake Como yang terkenal di dunia.</p><p>✧ 6 Negara dalam 1 Perjalanan<br>✧ 11 Hari 8 Malam Penuh Pengalaman<br>✧ Ikon Dunia &amp; Kota-Kota Klasik<br>✧ Panorama Danau &amp; Pegunungan Alpen<br>✧ Wisata Budaya &amp; Belanja Eksklusif</p><p>Satu perjalanan premium yang memadukan keindahan alam, kekayaan budaya, dan gaya hidup Eropa dalam satu pengalaman yang berkelas dan tak terlupakan 🤩✨</p>', '<p><strong>SUMMER HOLIDAYS – 11D8N BEST OF WESTERN EUROPE</strong></p><ul><li data-list-item-id=\"e4557271e9d7732721ea2f52f7314bc81\">Lake Brienz • Mt. Titlis<br>(6 Best Countries in Europe)</li></ul><p>Enjoy a remarkable summer journey exploring the charm of Western Europe in an unforgettable 11-day experience. The trip begins in the romantic city of Paris with the iconic Eiffel Tower, along with visits to historic landmarks and elegant city sights.</p><p>Continue to Belgium to see the famous Manneken Pis, then head to the Netherlands to experience traditional life at Zaanse Schans and the charming fishing village of Volendam.</p><p>The journey continues through Germany and France, before entering the breathtaking landscapes of Switzerland. Enjoy the crystal-clear beauty of Lake Brienz and visit the picturesque village of Lauterbrunnen surrounded by the Alps.</p><p>In Switzerland, you will also have the opportunity to visit Mount Titlis (optional) and admire the serene beauty of Lake Lucerne.</p><p>The journey concludes in Italy with the elegance of Milan, visiting Duomo di Milano, shopping at Galleria Vittorio Emanuele II, and exploring the stunning Lake Como.</p><p>✧ 6 Countries in One Journey<br>✧ 11 Days 8 Nights Experience<br>✧ World Icons &amp; Classic Cities<br>✧ Alpine Mountains &amp; Scenic Lakes<br>✧ Culture &amp; Exclusive Shopping</p><p>A premium journey that blends nature, culture, and the European lifestyle into one unforgettable experience 🤩✨</p>', '<p><strong>여름 시즌 – 서유럽 11일 8박 베스트 여행</strong></p><ul><li data-list-item-id=\"e4a5f0e09e21e45a2fc15d0795c3d5cba\">브리엔츠 호수 • 티틀리스 산<br>(유럽 최고의 6개국)</li></ul><p>11일 동안 서유럽의 매력을 만끽할 수 있는 특별한 여정을 경험해 보세요. 낭만적인 파리에서 Eiffel Tower를 시작으로, 다양한 역사적 명소를 방문하며 여행이 시작됩니다.</p><p>벨기에에서는 Manneken Pis를 만나고, 네덜란드에서는 Zaanse Schans와 Volendam에서 전통적인 분위기를 체험할 수 있습니다.</p><p>이후 독일과 프랑스를 지나 스위스의 아름다운 자연으로 이동하여 Lake Brienz와 알프스에 둘러싸인 라우터브루넨 마을을 방문합니다.</p><p>또한 선택 관광으로 Mount Titlis를 방문할 수 있으며, Lake Lucerne의 평화로운 풍경을 감상할 수 있습니다.</p><p>마지막으로 이탈리아 밀라노에서 Duomo di Milano와 Galleria Vittorio Emanuele II를 방문하고, Lake Como의 아름다움을 즐기며 여행을 마무리합니다.</p><p>✧ 6개국 여행<br>✧ 11일 8박 일정<br>✧ 세계적인 명소 &amp; 클래식 도시<br>✧ 알프스 산맥과 아름다운 호수<br>✧ 문화 체험 &amp; 프리미엄 쇼핑</p><p>자연과 문화, 유럽의 라이프스타일이 어우러진 품격 있는 여행을 선사합니다 🤩✨</p>', '<p><strong>夏季限定 – 西欧11天8晚精华之旅</strong></p><ul><li data-list-item-id=\"e15d84c2d3000922b18f1201a346233a4\">布里恩茨湖 • 铁力士山<br>（欧洲6大经典国家）</li></ul><p>开启一段为期11天的精彩旅程，深入探索西欧的独特魅力。从浪漫之都巴黎及其标志性景点 Eiffel Tower 开始，欣赏丰富的历史与文化。</p><p>前往比利时参观 Manneken Pis，随后前往荷兰，游览 Zaanse Schans 风车村和 Volendam 渔村，体验当地传统风情。</p><p>行程将经过德国和法国，进入瑞士壮丽的自然风光，欣赏 Lake Brienz 的清澈湖水，并探访被阿尔卑斯山环绕的劳特布龙嫩小镇。</p><p>此外，您还可选择前往 Mount Titlis，并欣赏 Lake Lucerne 的宁静美景。</p><p>最后在意大利米兰，参观 Duomo di Milano 和 Galleria Vittorio Emanuele II，并游览世界著名的 Lake Como，为旅程画上完美句号。</p><p>✧ 6个国家<br>✧ 11天8晚行程<br>✧ 世界地标与经典城市<br>✧ 阿尔卑斯山与湖泊美景<br>✧ 文化体验与精品购物</p><p>一场融合自然、文化与欧洲生活方式的高品质之旅，为您留下难忘回忆 ✨</p>', 25400000.00, NULL, 11, 10, '[\"8 - 18 Juli 2026\",\"12 - 22 Agustus 2026\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/OgfiZgUVEeVVS4lp3cwQder52ZOFZUsYgfzDKrdP.pdf', 0, NULL, '2026-04-24 17:47:17', '2026-04-27 02:59:41');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(43, 28, '11D8N Eropa Barat + Mt Titlis + Lake Lucerne', NULL, '11d8n-eropa-barat-mt-titlis-lake-lucerne', '<h2><strong>SCHOOL HOLIDAYS – 11D8N EROPA BARAT + MT. TITLIS + LAKE LUCERNE</strong></h2><p><strong>(6 Negara Terbaik di Eropa)</strong></p><p>Nikmati liburan seru menjelajahi Eropa Barat dalam perjalanan 11 hari yang penuh pengalaman tak terlupakan. Dimulai dari Paris dengan ikon dunia Eiffel Tower, dilanjutkan ke Belgia mengunjungi Manneken Pis, hingga Belanda dengan suasana khas di Volendam dan Zaanse Schans.</p><p>Perjalanan semakin memukau saat memasuki Swiss menikmati keindahan Lake Lucerne dan kesempatan mengunjungi Mount Titlis dengan panorama salju abadi. Ditutup dengan pesona Italia di Lake Como, Duomo di Milano, dan Galleria Vittorio Emanuele II.</p><p>✧ 6 Negara dalam 1 Trip<br>✧ Ikon Dunia &amp; Kota Klasik<br>✧ Alpen Swiss &amp; Danau Indah<br>✧ Wisata Belanja &amp; Lifestyle</p><p>Perpaduan sempurna antara alam, budaya, dan gaya hidup Eropa dalam satu perjalanan elegan 🤩✨</p>', '<p><strong>SCHOOL HOLIDAYS – 11D8N WESTERN EUROPE + MT. TITLIS + LAKE LUCERNE</strong><br>(6 Best Countries in Europe)</p><p>Enjoy an exciting holiday exploring Western Europe in an unforgettable 11-day journey. Starting from Paris with the iconic Eiffel Tower, continue to Belgium to visit Manneken Pis, and head to the Netherlands to experience the charm of Volendam and Zaanse Schans.</p><p>The journey becomes even more breathtaking as you enter Switzerland—enjoy the beauty of Lake Lucerne and the opportunity to visit Mount Titlis with its eternal snow panorama.</p><p>End your trip with the elegance of Italy by visiting Lake Como, Duomo di Milano, and Galleria Vittorio Emanuele II.</p><p>✧ 6 Countries in One Trip<br>✧ World Icons &amp; Classic Cities<br>✧ Swiss Alps &amp; Scenic Lakes<br>✧ Shopping &amp; Lifestyle Experience</p><p>A perfect blend of nature, culture, and European lifestyle in one elegant journey 🤩✨</p>', '<p><strong>여름 방학 – 서유럽 11일 8박 + 티틀리스 산 + 루체른 호수</strong><br>(유럽 최고의 6개국)</p><p>잊지 못할 11일간의 여정으로 서유럽을 탐험해보세요. 파리의 상징 Eiffel Tower에서 시작하여, 벨기에의 Manneken Pis를 방문하고, 네덜란드의 Volendam과 Zaanse Schans에서 전통적인 분위기를 경험할 수 있습니다.</p><p>이후 스위스로 이동하여 Lake Lucerne의 아름다움과 Mount Titlis의 설경을 감상할 수 있습니다.</p><p>마지막으로 이탈리아에서 Lake Como, Duomo di Milano, Galleria Vittorio Emanuele II를 방문하며 여행을 마무리합니다.</p><p>✧ 6개국 여행<br>✧ 세계적인 명소 &amp; 클래식 도시<br>✧ 알프스와 아름다운 호수<br>✧ 쇼핑 &amp; 라이프스타일 경험</p><p>자연과 문화, 유럽 라이프스타일이 어우러진 완벽한 여행 🤩✨</p>', '<p><strong>暑期假日 – 西欧11天8晚 + 铁力士山 + 卢塞恩湖</strong><br>（欧洲6大精选国家）</p><p>开启一段难忘的11天西欧之旅。从巴黎标志性景点 Eiffel Tower 开始，前往比利时参观 Manneken Pis，再到荷兰体验 Volendam 和 Zaanse Schans 的独特魅力。</p><p>进入瑞士后，欣赏 Lake Lucerne 的美景，并有机会登上 Mount Titlis 感受雪山风光。</p><p>最后在意大利，游览 Lake Como、Duomo di Milano 以及 Galleria Vittorio Emanuele II，为旅程画上完美句号。</p><p>✧ 6个国家<br>✧ 世界地标与经典城市<br>✧ 阿尔卑斯与湖泊美景<br>✧ 购物与生活方式体验</p><p>融合自然、文化与欧洲生活方式的完美旅程 🤩✨</p>', 25400000.00, NULL, 11, 6, '[\"24 Juni - 4 Juli 2026\",\"27 Juni - 7 Juli 2026\",\"29 Juni - 9 Juli 2026\"]', NULL, '<p>HIGHLIGHTS: <strong>EIFFEL TOWER - MANEKIN PISS - VOLENDAM - ZAANSE SCHANS - LAKE LUCERNE - MT TITLIS - LAKE COMO - DUOMO DI MILANO - GALLERIA VITTORIO EMANUELLE II</strong></p>', '<p>Tiket internasional : JAKARTA – PARIS | MILAN – JAKARTA By EMIRATES QATAR/ETIHAD Economy Class (Non Refundable, Non Re-Routeable,</p><p>Bagasi sesuai dengan peraturan penerbangan (25/30 kg)</p><p>Hotel 3* nyaman selama 7 malam ( based on Twin Sharing) Base on Availability &amp; Confirmations in Final Itinerary</p><p>Transportasi Bus ber AC 49/55 seater</p><p>Fuel surcharge, airport tax Jakarta</p>', '<p>Visa Schengen : 3.875.000/Pax (Non Refund) Internasional Taxes &amp; Surcharges : Rp. 2.950.000/Pax (Wajib)</p><p>Tipping TL, driver, : IDR 2.450.000 /Pax (Wajib)</p><p>Travel Insurance: IDR 1.250.000 /Pax (Wajib)</p><p>Lunch &amp; Dinner (est. Eur 15-30/makan)</p><p>Pengeluaran pribadi : Laundry, Phone, Minibar, dll</p><p>Pengurusan dokumen perjalanan : Passpor, Visa, dll</p><p>Optional Tour (Mt Titlis : Euro 185/pax, Seine River Rp. 450.000/pax, Lake Lucerne Cruise Rp.680.000/pax)</p><p>Biaya kelebihan bagasi, Biaya Extend</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/WWCS4iw9fZSVL6HnJW3eiu0quQABdjTMPpr9uiUk.pdf', 0, NULL, '2026-04-25 01:39:48', '2026-04-27 03:12:07'),
(44, 29, '10D Best Uk + Scotland + Ireland', NULL, '10d-best-uk-scotland-ireland', '<h2><strong>SUMMER SEASON – 10D BEST UK + SCOTLAND + IRELAND</strong></h2><p>Nikmati perjalanan musim panas menjelajahi tiga negara terbaik: Inggris, Skotlandia, dan Irlandia dalam 10 hari penuh pengalaman seru dan berkesan. Dimulai dari kota ikonik London dengan landmark terkenal seperti Big Ben, London Eye, dan Buckingham Palace.</p><p>Perjalanan dilanjutkan ke kota-kota bersejarah Inggris seperti Liverpool dan Manchester dengan kunjungan ke stadion legendaris, hingga kota klasik York. Anda kemudian akan menikmati pesona Skotlandia di Edinburgh dan Glasgow, termasuk berfoto di Edinburgh Castle yang megah.</p><p>Petualangan berlanjut ke Irlandia Utara, menjelajahi keindahan alam unik Giant\'s Causeway dan jalan ikonik The Dark Hedges.</p><p>Perjalanan ditutup di Dublin dengan suasana kota yang hidup dan penuh budaya di Temple Bar.</p><p>✧ 3 Negara dalam 1 Trip<br>✧ Ikon Kota &amp; Landmark Dunia<br>✧ Kota Bersejarah &amp; Budaya Klasik<br>✧ Alam Unik &amp; Lokasi Ikonik</p><p>Perpaduan sempurna antara sejarah, budaya, dan keindahan alam Inggris hingga Irlandia dalam satu perjalanan tak terlupakan 🤩✨</p>', '<p><strong>SUMMER SEASON – 10D BEST UK + SCOTLAND + IRELAND</strong></p><p>Enjoy a summer journey exploring three of the best countries England, Scotland, and Ireland in an exciting and memorable 10-day trip. Begin in iconic London with famous landmarks such as Big Ben, London Eye, and Buckingham Palace.</p><p>Continue to historic English cities like Liverpool and Manchester with visits to legendary stadiums, and the classic city of York. Then experience the charm of Scotland in Edinburgh and Glasgow, including a photo stop at Edinburgh Castle.</p><p>Your adventure continues in Northern Ireland, exploring the natural wonder of Giant\'s Causeway and the iconic road of The Dark Hedges.</p><p>The journey ends in Dublin, enjoying the lively and cultural atmosphere of Temple Bar.</p><p>✧ 3 Countries in One Trip<br>✧ Iconic Cities &amp; World Landmarks<br>✧ Historic Cities &amp; Classic Culture<br>✧ Unique Nature &amp; Iconic Spots</p><p>A perfect blend of history, culture, and natural beauty from England to Ireland in one unforgettable journey 🤩✨</p>', '<p><strong>여름 시즌 – 영국 + 스코틀랜드 + 아일랜드 10일 여행</strong></p><p>영국, 스코틀랜드, 아일랜드 3개국을 10일 동안 여행하며 잊지 못할 여정을 경험해보세요. 런던의 상징적인 명소인 Big Ben, London Eye, Buckingham Palace에서 여행이 시작됩니다.</p><p>리버풀과 맨체스터 같은 역사적인 도시와 요크를 방문한 후, 스코틀랜드의 에든버러와 글래스고를 탐방하며 Edinburgh Castle를 감상합니다.</p><p>이후 북아일랜드로 이동하여 Giant\'s Causeway와 The Dark Hedges의 독특한 자연경관을 경험합니다.</p><p>마지막으로 더블린의 Temple Bar에서 활기찬 문화를 즐기며 여행을 마무리합니다.</p><p>✧ 3개국 여행<br>✧ 세계적인 명소 &amp; 도시<br>✧ 역사와 전통 문화<br>✧ 독특한 자연과 명소</p><p>영국에서 아일랜드까지, 역사와 자연이 어우러진 완벽한 여행 🤩✨</p>', '<p><strong>夏季限定 – 英国 + 苏格兰 + 爱尔兰 10日精选之旅</strong></p><p>开启一段为期10天的精彩旅程，探索英国、苏格兰和爱尔兰三大经典国家。从伦敦标志性景点 Big Ben、London Eye 和 Buckingham Palace 开始您的旅程。</p><p>随后前往利物浦、曼彻斯特等历史名城以及约克，接着探索苏格兰的爱丁堡和格拉斯哥，并参观 Edinburgh Castle。</p><p>旅程继续前往北爱尔兰，欣赏 Giant\'s Causeway 的自然奇观，以及 The Dark Hedges 的经典景点。</p><p>最后在都柏林的 Temple Bar 感受热闹的文化氛围，为旅程画上完美句号。</p><p>✧ 3个国家<br>✧ 世界地标与经典城市<br>✧ 历史文化之旅<br>✧ 独特自然景观</p><p>融合历史、文化与自然美景的完美旅程 🤩✨</p>', 32500000.00, NULL, 10, 9, '[\"25 Juni \\u2013 3 Juli 2026\"]', NULL, NULL, '<p>Tiket internasional : JAKARTA – LONDON | DUBLIN – JAKARTA By QATAR/ETIHAD/EMIRATES Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</p><p>Bagasi sesuai dengan peraturan penerbangan (25/30 kg)</p><p>Akomodasi Hotel&nbsp; Bintang 3* yang nyaman selama 7 malam ( based on Twin Sharing) <i>Base on availability &amp; confirmations in final itinerary</i></p><p>Transportasi bus ber AC 49/55 seater</p><p>Fuel surcharge, airport tax Jakarta</p><p>Tour Leader dari Jakarta</p>', '<p>Visa UK &nbsp;: 4.250.000/Pax (Non Refund)</p><p>Internasional Taxes &amp; Surcharges : Rp 2.850.000/Pax (Wajib)</p><p>Tipping TL, driver + City Tax : IDR 2.450.000 /Pax (Wajib)</p><p>Travel Insurance: IDR 1.500.000 /Pax (Wajib)</p><p>Optional Tour : Thames River Cruise (est. £20)</p><p>Pengeluaran pribadi : Laundry, phone, minibar, dll</p><p>Pengurusan dokumen perjalanan : Passpor, Visa, dll</p><p>&nbsp;Biaya kelebihan bagasi, Biaya extend</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/lbLCDRiPwAArK6wjtf9DGw1c6zpnWZril5Mr2n0p.pdf', 0, NULL, '2026-04-25 02:08:09', '2026-04-27 03:45:28'),
(45, 30, '9D Best Eropa Timur 6 Negara', NULL, '9d-best-eropa-timur-6-negara', '<p><strong>WINTER SEASON – 9D BEST EASTERN EUROPE (6 NEGARA)</strong> 🤩</p><p>Rasakan keindahan musim dingin Eropa Timur dalam perjalanan 9 hari yang membawa Anda menjelajahi <strong>6 negara menawan: Swiss, Austria, Slovakia, Ceko, Hungaria, dan Jerman</strong> ❄️🌍</p><p>Perjalanan dimulai dari kota elegan <strong>Zurich</strong>, dilanjutkan menuju Salzburg dengan kunjungan ke rumah kelahiran Mozart serta taman indah yang menjadi lokasi film legendaris <i>The Sound of Music</i>.</p><p>Anda akan diajak menikmati pesona kota klasik <strong>Prague</strong>, dengan alun-alun bersejarah, jam astronomi ikonik, dan jembatan batu yang romantis. Perjalanan berlanjut ke <strong>Budapest</strong>, kota yang dibelah Sungai Danube dengan panorama kastil megah dan arsitektur menawan.</p><p>Di Austria, nikmati kemewahan istana kerajaan di <strong>Vienna</strong> serta pengalaman berbelanja di outlet ternama. Keindahan alam terbaik akan Anda temukan di desa danau <strong>Hallstatt</strong>, destinasi impian dengan pemandangan bak negeri dongeng.</p><p>Perjalanan ditutup di <strong>Munich</strong>, kota modern di Jerman yang menawarkan perpaduan budaya, teknologi, dan landmark ikonik.</p><p>✧ 6 Negara dalam 1 perjalanan<br>✧ Kota klasik &amp; landmark bersejarah<br>✧ Istana megah &amp; budaya Eropa<br>✧ Pemandangan musim dingin yang memukau</p><p>Perpaduan sempurna antara <strong>sejarah, budaya, dan keindahan alam musim dingin Eropa</strong> dalam satu pengalaman tak terlupakan ✨</p>', '<p><strong>WINTER SEASON – 9D BEST EASTERN EUROPE (6 COUNTRIES)</strong> 🤩</p><p>Experience the beauty of Eastern Europe in winter on a 9-day journey across 6 stunning countries: Switzerland, Austria, Slovakia, Czech Republic, Hungary, and Germany ❄️🌍</p><p>The journey begins in the elegant city of Zurich, continuing to Salzburg with visits to Mozart’s birthplace and the beautiful gardens featured in the legendary film <i>The Sound of Music</i>.</p><p>Discover the charm of the classic city Prague, with its historic square, iconic astronomical clock, and romantic stone bridge. Continue to Budapest, a city divided by the Danube River, showcasing magnificent castles and stunning architecture.</p><p>In Austria, enjoy the grandeur of royal palaces in Vienna and indulge in shopping at a famous outlet. Witness breathtaking scenery in the lakeside village of Hallstatt, a fairytale-like destination.</p><p>The journey concludes in Munich, a modern German city blending culture, technology, and iconic landmarks.</p><p>✧ 6 Countries in One Trip<br>✧ Classic Cities &amp; Historic Landmarks<br>✧ Majestic Palaces &amp; European Culture<br>✧ Stunning Winter Scenery</p><p>A perfect blend of history, culture, and winter beauty in one unforgettable journey ✨</p>', '<p><strong>겨울 시즌 – 동유럽 6개국 9일 여행</strong> 🤩</p><p>스위스, 오스트리아, 슬로바키아, 체코, 헝가리, 독일까지<br>6개국을 여행하는 9일간의 겨울 여행을 경험해보세요 ❄️🌍</p><p>여행은 우아한 도시 Zurich에서 시작하여, 모차르트의 생가와 영화 <i>사운드 오브 뮤직</i> 촬영지로 유명한 정원을 방문하는 잘츠부르크로 이어집니다.</p><p>고풍스러운 도시 Prague에서는 역사적인 광장, 천문시계, 그리고 낭만적인 돌다리를 감상할 수 있습니다. 이어서 도나우 강으로 나뉜 아름다운 도시 Budapest를 방문합니다.</p><p>오스트리아에서는 Vienna의 웅장한 왕궁과 쇼핑을 즐기고, 동화 같은 풍경의 호수 마을 Hallstatt를 방문합니다.</p><p>여행의 마지막은 문화와 기술이 어우러진 도시 Munich에서 마무리됩니다.</p><p>✧ 6개국을 한 번에<br>✧ 클래식 도시와 역사 명소<br>✧ 웅장한 궁전과 유럽 문화<br>✧ 아름다운 겨울 풍경</p><p>잊지 못할 겨울 여행을 경험하세요 ✨</p>', '<p><strong>冬季限定 – 东欧6国9日精彩之旅</strong> 🤩</p><p>开启一段9天旅程，探索瑞士、奥地利、斯洛伐克、捷克、匈牙利和德国6个迷人国家 ❄️🌍</p><p>旅程从优雅的城市 Zurich 开始，随后前往萨尔茨堡，参观莫扎特故居以及电影《音乐之声》的取景花园。</p><p>在经典之城 Prague，您将欣赏历史广场、天文钟以及浪漫的石桥。接着前往被多瑙河分隔的美丽城市 Budapest，感受宏伟城堡与壮丽建筑。</p><p>在奥地利，您将参观 Vienna 的皇家宫殿，并享受购物乐趣，同时探访童话般的湖畔小镇 Hallstatt。</p><p>最后一站来到德国城市 Munich，感受文化与现代科技的融合。</p><p>✧ 一次旅行畅游6个国家<br>✧ 经典城市与历史地标<br>✧ 宏伟宫殿与欧洲文化<br>✧ 迷人冬季风景</p><p>一段融合历史、文化与冬季美景的难忘旅程 ✨</p>', 25350000.00, NULL, 9, 8, '[\"20 - 28 Oktober 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIHTS:</strong></p><p style=\"text-align:center;\"><strong>&nbsp;SWISS– AUSTRIA- SLOVAKIA- CEKO - HUNGARY- GERMANY</strong></p>', '<ul><li data-list-item-id=\"e1eb86b8130531e18b8992a1ea38d5ad6\">Tiket internasional : JAKARTA – ZURICH | MUNICH – JAKARTA By EMIRATES/QATAR/ETIHAD Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</li><li data-list-item-id=\"e8018358b78f2bc3b78848692f7891c57\">Bagasi sesuai dengan peraturan penerbangan ( 25/30 kg)</li><li data-list-item-id=\"ec0ec9849091f8bb60cd8feef3b35928a\">Akomodasi Hotel&nbsp; 3* nyaman selama 7 malam ( based on Twin Sharing) <i>Base on Availability &amp; Confirmations in Final Itinerary</i></li><li data-list-item-id=\"e64fa41825cb3dda8d2d978dcb75f391f\">Transportasi Bus ber AC 49 seater</li><li data-list-item-id=\"ebd45afa0b56d81b8d0a4e838340dbedc\">Fuel surcharge, airport tax Jakarta</li><li data-list-item-id=\"e4fa1280136bb9dfaf36c153315cf2b7c\">Tour Leader dari Jakarta</li><li data-list-item-id=\"e3256eedab718e17895a0b30a84374f4e\">Konten photo/Video by Tour Leader</li></ul>', '<ul><li data-list-item-id=\"e86677aeec6c6d34ecbd9d8a4bf80e5b8\">Visa Schengen &nbsp;: 3.875.000/Pax (Non Refund)</li><li data-list-item-id=\"e902f2627222be068dd9e48a253765ba2\">Internasional Taxes &amp; Surcharges : Rp 2.950.000/Pax (Wajib)</li><li data-list-item-id=\"ebac6b2308927d2da03d317982c5b5225\">Tipping TL, driver : IDR 2.350.000 /Pax (Wajib)</li><li data-list-item-id=\"e316489c385bcf5a378f4e25341ca3112\">City tax Rp. 500.000/pax (Wajib)</li><li data-list-item-id=\"e1b662f5b9e896847bbc6cbdf4a66fd60\">Travel Insurance: IDR 600.000 /Pax (Wajib)</li><li data-list-item-id=\"e249486ecf0523f7d78e58e1425d107e8\">Pengeluaran pribadi : Laundry, Phone, Minibar, dll</li><li data-list-item-id=\"e2e680c7771a295618f1c16d54e8e07c2\">Pengurusan dokumen perjalanan : Passpor, Visa, dll</li><li data-list-item-id=\"e3ac34d0c3bd1a42d29d244c82bd02587\">Optional Tour (Danube River Cruise Rp. 700.000/pax)</li><li data-list-item-id=\"e93adee41e35d3db5d4cb77f3a15e7e92\">Biaya kelebihan bagasi, Biaya Extend</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/diRUs9io2zPadb7AAw4Ib0AIdRFcYX9pv2ymIuPQ.pdf', 0, NULL, '2026-04-27 05:17:13', '2026-04-27 05:22:41'),
(46, 31, 'Auntum Season - 10D Russia Aurora Borealis + Sapsan Train', NULL, '10d-russia-aurora-borealis-sapsan-train', '<p><strong>AUTUMN SEASON – 10D RUSSIA AURORA BOREALIS + SAPSAN TRAIN</strong> 🤩</p><p>Rasakan pengalaman istimewa menjelajahi Rusia dalam 10 hari penuh keajaiban, mulai dari kota megah hingga fenomena alam yang langka 🌌❄️</p><p>Perjalanan dimulai di <strong>Moscow</strong>, kota bersejarah dengan landmark ikonik seperti Red Square, Saint Basil\'s Cathedral, dan Bolshoi Theatre yang megah.</p><p>Petualangan berlanjut ke <strong>Murmansk</strong>, salah satu tempat terbaik di dunia untuk menyaksikan keajaiban <strong>Aurora Borealis</strong>. Nikmati pengalaman berburu cahaya utara yang menakjubkan serta eksplorasi budaya lokal di Saami Village.</p><p>Perjalanan dilanjutkan ke kota elegan <strong>Saint Petersburg</strong>, dengan arsitektur klasik dan istana megah seperti Peterhof Palace serta museum terkenal Hermitage Museum.</p><p>Tak hanya itu, Anda juga akan merasakan pengalaman unik menaiki <strong>Sapsan Train</strong>, kereta cepat yang menghubungkan dua kota besar Rusia dengan nyaman dan modern 🚄</p><p>✧ Aurora Borealis Experience<br>✧ Kota Ikonik Rusia<br>✧ Istana &amp; Arsitektur Megah<br>✧ Pengalaman Kereta Cepat Sapsan</p><p>Perpaduan sempurna antara <strong>budaya, sejarah, dan keajaiban alam</strong> dalam satu perjalanan yang benar-benar tak terlupakan ✨</p>', '<p><strong>AUTUMN SEASON – 10D RUSSIA AURORA BOREALIS + SAPSAN TRAIN</strong> 🤩</p><p>Experience an extraordinary 10-day journey through Russia, from magnificent cities to rare natural wonders 🌌❄️</p><p>Your trip begins in Moscow, a historic city with iconic landmarks such as Red Square, Saint Basil\'s Cathedral, and Bolshoi Theatre.</p><p>The adventure continues to Murmansk, one of the best places in the world to witness the magical <strong>Aurora Borealis</strong>. Enjoy an unforgettable Northern Lights hunting experience along with cultural exploration at Saami Village.</p><p>Next, travel to the elegant city of Saint Petersburg, known for its classical architecture and grand landmarks such as Peterhof Palace and the famous Hermitage Museum.</p><p>You will also enjoy a unique journey aboard the <strong>Sapsan Train</strong>, a high-speed train connecting Russia’s major cities with comfort and modern convenience 🚄</p><p>✧ Aurora Borealis Experience<br>✧ Iconic Russian Cities<br>✧ Grand Palaces &amp; Architecture<br>✧ High-Speed Sapsan Train Experience</p><p>A perfect blend of culture, history, and natural wonders in one truly unforgettable journey ✨</p>', '<p><strong>가을 시즌 – 러시아 오로라 10일 여행 + 사프산 열차</strong> 🤩</p><p>웅장한 도시와 신비로운 자연 현상을 모두 경험할 수 있는 10일간의 특별한 러시아 여행을 만나보세요 🌌❄️</p><p>여행은 Moscow에서 시작되며, Red Square, Saint Basil\'s Cathedral, Bolshoi Theatre 등 대표 명소를 방문합니다.</p><p>이후 북극권 도시 Murmansk로 이동하여 환상적인 **오로라(북극광)**를 감상하고 사미 마을의 문화를 체험합니다.</p><p>다음으로 Saint Petersburg에서 고전적인 건축물과 Peterhof Palace, Hermitage Museum를 방문합니다.</p><p>또한 러시아의 대표 고속열차 **사프산(Sapsan)**을 타고 편안하고 빠른 이동을 경험할 수 있습니다 🚄</p><p>✧ 오로라 체험<br>✧ 러시아 대표 도시 여행<br>✧ 웅장한 궁전과 건축물<br>✧ 고속열차 사프산 체험</p><p>문화와 역사, 자연이 어우러진 잊지 못할 여행 ✨</p>', '<p><strong>秋季限定 – 俄罗斯10日极光之旅 + 萨普桑高铁</strong> 🤩</p><p>开启一段10天精彩旅程，探索俄罗斯的壮丽城市与罕见自然奇观 🌌❄️</p><p>旅程从 Moscow 开始，参观 Red Square、Saint Basil\'s Cathedral 和 Bolshoi Theatre 等著名地标。</p><p>随后前往北极圈城市 Murmansk，欣赏神秘壮观的<strong>北极光（极光）</strong>，并体验萨米文化村。</p><p>接着前往优雅的 Saint Petersburg，参观宏伟的 Peterhof Palace 和世界著名的 Hermitage Museum。</p><p>此外，您还将体验俄罗斯高速列车 <strong>Sapsan</strong>，享受舒适快捷的城市间旅行 🚄</p><p>✧ 极光体验<br>✧ 俄罗斯经典城市<br>✧ 宫殿与历史建筑<br>✧ 高速列车体验</p><p>融合文化、历史与自然奇观的难忘旅程 ✨</p>', 25330000.00, NULL, 10, 9, '[\"28 Oktober \\u2013 6 November 2026\",\"29 Oktober \\u2013 7 November 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIGHTS:</strong></p><p style=\"text-align:center;\"><strong>MOSCOW – MURMANSK – ST. PETERSBURG</strong></p><p style=\"text-align:center;\"><strong>&nbsp;</strong></p>', '<ul><li data-list-item-id=\"ee3ec906008768ed61cf69123b92ff4ac\">Internasional Flight PP by Etihad/Qatar Airways/Turkish Airlines</li><li data-list-item-id=\"e9dda6c7a32c0fa42cb34f96ad60bcafe\">Bagasi 25/30 Kg + 7 Kg (Cabin)</li><li data-list-item-id=\"e4161df673b8c6958de1cfb22ffc7489d\">Hotel Bintang 3* based on twin/double</li><li data-list-item-id=\"e79e1c8ec4e96adc174a7254a6ce6e7f2\">Ticket Domestic Flight 2x :</li><li data-list-item-id=\"e6b8d50d13dd5204baaa0892e70c29059\">Moscow – Murmansk (Exclude Bagasi)</li><li data-list-item-id=\"e44f8ec2b9a366e365e0a7abcfdcc75a8\">Murmansk – St. Petersburg (Exclude Bagasi)</li><li data-list-item-id=\"e8031936e41bdc0c9399c1400943229e0\">Ticket Sapsan Train :</li><li data-list-item-id=\"e6a3dd88bc07294ac0e5a13bd6b6a5ac7\">Economy Class St. Peter - Moscow</li><li data-list-item-id=\"e00882d4264080114ee3554dbb43055bd\">1x Hunting Aurora + Dokumentasi</li><li data-list-item-id=\"ee40ba21d1f8d7e4a8d93641b1194f356\">Transportasi Executive Private Bus AC</li><li data-list-item-id=\"ea62c28baf7707136356e381dff1b5232\">Breakfast di Hotel</li><li data-list-item-id=\"ef374027e249691358f9d13fdabd732b0\">Profesional Guide berbahasa Indonesia</li><li data-list-item-id=\"e92ff1eec2484cc350f872e53f8f129d1\">Tour Leader berpengalaman dari Jakarta</li><li data-list-item-id=\"eac6fe776a02c504bde3e7d092fb8398c\">Konten Video by Tour Leader</li></ul><p>&nbsp;</p>', '<ul><li data-list-item-id=\"e2acb345a4957f28b2e84cad853a62cb3\">Visa Russia : IDR 1.600.000/Pax</li><li data-list-item-id=\"eba3b98b5ba0dc886aa68c6f603111a89\">International Taxes &amp; Surcharges : IDR 2.950.000/Pax</li><li data-list-item-id=\"e06d358ec0848ec65b1ae0c7016a36c04\">Bagasi Domestic Flight 20 Kg (Wajib) : IDR 2.000.000/Pax</li><li data-list-item-id=\"ee098c82b23ea00b12963598974c8be16\">Tipping TL, driver : IDR 2.600.000/Pax (Dibayarkan bersama invoice)</li><li data-list-item-id=\"e5b08b40af4af6702f9f1b2907379af72\">Travel Insurance: IDR 1.150.000/Pax (Wajib)</li><li data-list-item-id=\"ea0f87e5556fd76ef624f74ad0de40502\">Meals (Lunch &amp; Dinner)</li><li data-list-item-id=\"e9ba0fe326eefa5a10cdd6a04a9dabe9d\">Optional Tour</li><li data-list-item-id=\"ecee69e43c0bcfed662d31218d25f00a5\">Personal Expenses</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/VyfiEr9WVPBxxXUKSSxE3CBqfBXSTB3z9zqXDTFK.pdf', 0, NULL, '2026-04-27 06:24:27', '2026-04-27 06:40:58'),
(47, 31, 'Winter Season - 10D Russia Aurora Borealis + Sapsan Train', NULL, 'winter-season-10d-russia-aurora-borealis-sapsan-train', '<p><strong>WINTER SEASON – 10D RUSSIA AURORA BOREALIS + SAPSAN TRAIN</strong> 🤩</p><p>Nikmati pengalaman musim dingin yang luar biasa dalam perjalanan 10 hari menjelajahi Rusia, menggabungkan keindahan kota bersejarah dan keajaiban alam yang langka 🌌❄️</p><p>Perjalanan dimulai dari <strong>Moscow</strong>, kota ikonik dengan landmark terkenal seperti Red Square, Saint Basil\'s Cathedral, dan Bolshoi Theatre yang megah. Anda juga akan menikmati suasana khas Rusia dengan waktu bebas di pasar tradisional.</p><p>Petualangan berlanjut ke wilayah Arktik di <strong>Murmansk</strong>, salah satu destinasi terbaik untuk menyaksikan fenomena <strong>Aurora Borealis</strong>. Rasakan momen magis berburu cahaya utara serta kunjungan ke Saami Village untuk mengenal budaya lokal, lengkap dengan opsi aktivitas musim dingin seperti husky sledding dan snowmobile.</p><p>Perjalanan dilanjutkan ke kota elegan <strong>Saint Petersburg</strong>, yang terkenal dengan arsitektur klasik dan warisan budaya yang kaya. Kunjungi keindahan Peterhof Palace, gereja-gereja megah, hingga museum terkenal dunia seperti Hermitage Museum.</p><p>Tak hanya itu, Anda juga akan merasakan pengalaman unik menaiki <strong>Sapsan Train</strong>, kereta cepat modern yang menghubungkan St. Petersburg dan Moscow dengan nyaman dan efisien 🚄</p><p>✧ Pengalaman berburu Aurora Borealis<br>✧ Kota ikonik &amp; budaya Rusia<br>✧ Istana megah &amp; arsitektur klasik<br>✧ Pengalaman kereta cepat Sapsan</p><p>Perpaduan sempurna antara <strong>petualangan, budaya, dan keajaiban alam musim dingin Rusia</strong> dalam satu perjalanan yang tak terlupakan ✨</p>', '<p><strong>WINTER SEASON – 10D RUSSIA AURORA BOREALIS + SAPSAN TRAIN</strong> 🤩</p><p>Enjoy an extraordinary winter journey across Russia in 10 days, combining iconic cities with one of nature’s rarest wonders 🌌❄️</p><p>Your journey begins in Moscow, a historic city filled with world-famous landmarks such as Red Square, Saint Basil’s Cathedral, and the magnificent Bolshoi Theatre. You will also have time to explore the local atmosphere and traditional markets.</p><p>The adventure continues to Murmansk, one of the best places in the world to witness the magical Aurora Borealis. Experience the breathtaking Northern Lights and explore local culture at Saami Village, with optional winter activities like husky sledding and snowmobiling.</p><p>Next, travel to the elegant city of Saint Petersburg, known for its stunning classical architecture and rich cultural heritage. Visit the beautiful Peterhof Palace, iconic cathedrals, and the world-renowned Hermitage Museum.</p><p>You will also enjoy a unique experience aboard the Sapsan Train, a modern high-speed train connecting Saint Petersburg and Moscow 🚄</p><p>✧ Aurora Borealis experience<br>✧ Iconic Russian cities &amp; culture<br>✧ Grand palaces &amp; classic architecture<br>✧ High-speed Sapsan train experience</p><p>A perfect blend of adventure, culture, and winter magic in one unforgettable journey ✨</p>', '<p><strong>겨울 시즌 – 10일 러시아 오로라 + 삽산 고속열차 여행</strong> 🤩</p><p>10일 동안 러시아의 대표 도시와 자연의 경이로움을 함께 경험하는 특별한 겨울 여행을 즐겨보세요 🌌❄️</p><p>여행은 역사와 문화가 살아 숨 쉬는 모스크바에서 시작됩니다. 붉은 광장, 성 바실리 대성당, 그리고 웅장한 볼쇼이 극장 등 세계적인 랜드마크를 방문합니다. 또한 전통 시장에서 자유 시간을 즐길 수 있습니다.</p><p>이후 세계 최고의 오로라 관측지 중 하나인 무르만스크로 이동합니다. 환상적인 오로라를 감상하고, 사미 마을에서 현지 문화를 체험하며 허스키 썰매와 스노모빌 등 겨울 액티비티도 선택적으로 즐길 수 있습니다.</p><p>다음으로는 아름다운 건축과 풍부한 문화유산으로 유명한 상트페테르부르크를 방문합니다. 페테르호프 궁전과 대성당, 세계적인 에르미타주 미술관을 만나보세요.</p><p>또한 상트페테르부르크와 모스크바를 연결하는 삽산 고속열차를 탑승하는 특별한 경험도 포함되어 있습니다 🚄</p><p>✧ 오로라 체험<br>✧ 러시아 대표 도시 탐방<br>✧ 웅장한 궁전과 클래식 건축<br>✧ 삽산 고속열차 체험</p><p>자연, 문화, 그리고 겨울의 마법이 어우러진 잊지 못할 여행입니다 ✨</p>', '<p><strong>冬季限定 – 10天俄罗斯极光之旅 + 高速列车体验</strong> 🤩</p><p>开启一段为期10天的精彩冬季旅程，探索俄罗斯的经典城市与神秘自然奇观 🌌❄️</p><p>旅程从莫斯科开始，这座历史悠久的城市拥有众多世界著名地标，如红场、圣瓦西里大教堂以及宏伟的莫斯科大剧院。同时，您还可以自由体验当地的传统市场氛围。</p><p>随后前往摩尔曼斯克，这里是世界上观赏北极光的最佳地点之一。您将亲眼目睹梦幻般的极光，并在萨米村体验当地文化，还可选择参与哈士奇雪橇和雪地摩托等冬季活动。</p><p>接着前往优雅的圣彼得堡，这座城市以其精美的古典建筑和深厚的文化底蕴闻名。参观彼得宫、大教堂以及世界著名的冬宫博物馆。</p><p>此外，您还将体验乘坐“萨普桑”高速列车，轻松往返于圣彼得堡与莫斯科之间 🚄</p><p>✧ 极光观赏体验<br>✧ 俄罗斯经典城市<br>✧ 宫殿与古典建筑<br>✧ 高速列车体验</p><p>一段融合自然奇观、历史文化与冬季魅力的难忘旅程 ✨</p>', 25330000.00, NULL, 10, 9, '[\"18 November \\u2013 27 November 2026\",\"24 November \\u2013 3 Desember 2026\",\"5 Desember \\u2013 14 Desember 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIGHTS:</strong></p><p style=\"text-align:center;\"><strong>MOSCOW – MURMANSK – ST. PETERSBURG</strong></p>', '<ul><li data-list-item-id=\"e21d0873c1f4a93d230013a985e8472b0\">Internasional Flight PP by Etihad/Qatar Airways/Turkish Airlines</li><li data-list-item-id=\"ecc93f752fed56acdb8df7661690a747c\">Bagasi 25/30 Kg + 7 Kg (Cabin)</li><li data-list-item-id=\"e4a94d39b17d0e2897453cfe0c155e537\">Hotel Bintang 3* based on twin/double</li><li data-list-item-id=\"e434e39360d56124ad414879fc8f430a6\">Ticket Domestic Flight 2x :</li><li data-list-item-id=\"e2f413b41c7eecf4a21519087a880c6fd\">Moscow – Murmansk (Exclude Bagasi)</li><li data-list-item-id=\"e51c8217071d20472b16b3b512d79c0fa\">Murmansk – St. Petersburg (Exclude Bagasi)</li><li data-list-item-id=\"e9715970c20d24de8a8c11f1b5f9610c8\">Ticket Sapsan Train :</li><li data-list-item-id=\"e3bd42f2fce2eda0b27af75ae23bc0fe6\">Economy Class St. Peter - Moscow</li><li data-list-item-id=\"ef93cfca1cef9cc3b672465c86433ee4f\">1x Hunting Aurora + Dokumentasi</li><li data-list-item-id=\"ea45ab6ee3df9ab0e139780cfe38b1717\">Transportasi Executive Private Bus AC</li><li data-list-item-id=\"ed13f31b7698b31454ce633da041f2d85\">Breakfast di Hotel</li><li data-list-item-id=\"e94fea05afce05b7da35fa36221a3da1a\">Profesional Guide berbahasa Indonesia</li><li data-list-item-id=\"e04bf84d9088cf642e74b54aa8f9a8608\">Tour Leader berpengalaman dari Jakarta</li><li data-list-item-id=\"e6119cce31447df09c10aa24746884d28\">Konten Video by Tour Leader</li></ul>', '<ul><li data-list-item-id=\"e4d08acfa473836da89d90cf2cbaa0bc4\">Visa Russia : IDR 1.600.000/Pax</li><li data-list-item-id=\"e1aeeb8145e4462161327937b62cd6ff8\">International Taxes &amp; Surcharges : IDR 2.950.000/Pax</li><li data-list-item-id=\"eef17a1761facd7d2f3f3a45d0ea3db79\">Bagasi Domestic Flight 20 Kg (Wajib) : IDR 2.000.000/Pax</li><li data-list-item-id=\"ebe6b5e0831f13f603f4184db917f953d\">Tipping TL, driver : IDR 2.600.000/Pax (Dibayarkan bersama invoice)</li><li data-list-item-id=\"e7cdb3cdfe1f26be1acfd3a821565c1ec\">Travel Insurance: IDR 1.150.000/Pax (Wajib)</li><li data-list-item-id=\"e9f0407db5898f6c39250fef9b5335234\">Meals (Lunch &amp; Dinner)</li><li data-list-item-id=\"e62149b7e522947b26a601df64005db40\">Optional Tour</li><li data-list-item-id=\"ec0d016ab3e279cf451232febbad93c09\">Personal Expenses</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/NdRaGQMaB7n7sWn8HQX2BAEVShGmFiIzapPxQLg4.pdf', 0, NULL, '2026-04-27 06:59:22', '2026-04-27 07:04:58'),
(48, 32, '15D Balkan, Montenegro, Transylvania + Istanbul', NULL, '15d-balkan-montenegro-transylvania-istanbul', '<p><strong>SUMMER SEASON – 15D BALKAN, MONTENEGRO, TRANSYLVANIA + ISTANBUL</strong> 🤩</p><p>Rasakan petualangan luar biasa menjelajahi <strong>10 negara Eropa &amp; Balkan</strong> dalam 15 hari penuh pengalaman tak terlupakan 🌍☀️</p><p>Perjalanan dimulai dari kota megah <strong>Istanbul</strong>, pintu gerbang antara Asia dan Eropa, sebelum melanjutkan ke Yunani dan kota pelabuhan cantik <strong>Kavala</strong>, hingga kota bersejarah <strong>Thessaloniki</strong>.</p><p>Anda akan menjelajahi pesona Balkan melalui <strong>Skopje</strong>, <strong>Lake Ohrid</strong> yang indah, hingga ibu kota Albania <strong>Tirana</strong>. Keindahan alam berlanjut di Montenegro melalui <strong>Bay of Kotor</strong>, salah satu teluk terindah di dunia.</p><p>Di Kroasia, Anda akan mengunjungi kota ikonik <strong>Dubrovnik</strong> dengan Old Town yang terkenal, lalu melanjutkan ke Bosnia untuk menikmati keindahan <strong>Mostar</strong> dan jembatan bersejarahnya.</p><p>Perjalanan dilanjutkan ke Serbia dan Romania, termasuk mengunjungi kastil legendaris <strong>Bran Castle</strong> di Transylvania yang penuh misteri.</p><p>Petualangan ditutup dengan mengunjungi Bulgaria dan kembali ke <strong>Istanbul</strong>, menikmati suasana kota yang hidup dan penuh budaya.</p><p>✧ 10 Negara dalam 1 perjalanan<br>✧ Kota bersejarah &amp; budaya Balkan<br>✧ Keindahan alam &amp; teluk ikonik<br>✧ Kastil legendaris Transylvania</p><p>Perpaduan sempurna antara <strong>sejarah, budaya, dan panorama alam Eropa</strong> dalam satu perjalanan epik yang tak terlupakan ✨</p>', '<p><strong>SUMMER SEASON – 15D BALKAN, MONTENEGRO, TRANSYLVANIA + ISTANBUL</strong> 🤩</p><p>Experience an extraordinary journey across <strong>10 European &amp; Balkan countries</strong> in 15 days filled with unforgettable moments 🌍☀️</p><p>Your adventure begins in the magnificent city of Istanbul, the gateway between Asia and Europe, before continuing to Greece with the charming port city of Kavala and the historic city of Thessaloniki.</p><p>Explore the beauty of the Balkans through Skopje, the stunning Lake Ohrid, and the capital of Albania, Tirana. The natural wonders continue in Montenegro with the breathtaking Bay of Kotor, one of the most beautiful bays in the world.</p><p>In Croatia, visit the iconic city of Dubrovnik with its famous Old Town, then continue to Bosnia to admire the beauty of Mostar and its historic bridge.</p><p>The journey continues to Serbia and Romania, including a visit to the legendary Bran Castle in Transylvania, filled with mystery.</p><p>Your adventure concludes with a visit to Bulgaria and a return to Istanbul, enjoying the vibrant atmosphere rich in culture.</p><p>✧ 10 countries in one journey<br>✧ Historic cities &amp; Balkan culture<br>✧ Stunning nature &amp; iconic bays<br>✧ Legendary Transylvania castle</p><p>A perfect blend of history, culture, and breathtaking European landscapes in one epic, unforgettable journey ✨</p>', '<p><strong>여름 시즌 – 15일 발칸, 몬테네그로, 트란실바니아 + 이스탄불</strong> 🤩</p><p>15일 동안 10개 유럽 및 발칸 국가를 여행하며 잊지 못할 특별한 경험을 만나보세요 🌍☀️</p><p>여행은 아시아와 유럽을 잇는 도시 이스탄불에서 시작하여, 그리스의 아름다운 항구 도시 카발라와 역사적인 도시 테살로니키로 이어집니다.</p><p>스코페, 아름다운 오흐리드 호수, 그리고 알바니아의 수도 티라나를 통해 발칸의 매력을 탐험합니다. 이어 몬테네그로의 코토르 만에서는 세계적으로 손꼽히는 절경을 감상할 수 있습니다.</p><p>크로아티아에서는 두브로브니크의 유명한 구시가지를 방문하고, 보스니아의 모스타르에서 역사적인 다리를 감상합니다.</p><p>여행은 세르비아와 루마니아로 이어지며, 신비로운 트란실바니아의 브란 성도 방문합니다.</p><p>마지막으로 불가리아를 거쳐 다시 이스탄불로 돌아와 활기찬 도시 분위기를 즐기며 여행을 마무리합니다.</p><p>✧ 10개국 여행<br>✧ 역사 도시 &amp; 발칸 문화<br>✧ 아름다운 자연과 절경<br>✧ 전설적인 트란실바니아 성</p><p>역사, 문화, 자연이 완벽하게 어우러진 잊지 못할 여행 ✨</p>', '<p><strong>夏季限定 – 15天巴尔干、黑山、特兰西瓦尼亚 + 伊斯坦布尔之旅</strong> 🤩</p><p>开启一段为期15天的精彩旅程，一次畅游10个欧洲及巴尔干国家，留下难忘回忆 🌍☀️</p><p>旅程从横跨欧亚大陆的城市伊斯坦布尔开始，随后前往希腊，游览迷人的港口城市卡瓦拉以及历史悠久的塞萨洛尼基。</p><p>您将探索巴尔干地区的独特魅力，包括斯科普里、美丽的奥赫里德湖，以及阿尔巴尼亚首都地拉那。接着前往黑山，欣赏世界著名的科托尔湾壮丽景色。</p><p>在克罗地亚，您将参观著名的杜布罗夫尼克古城，随后前往波黑欣赏莫斯塔尔及其历史悠久的桥梁。</p><p>旅程继续前往塞尔维亚和罗马尼亚，并参观充满神秘色彩的特兰西瓦尼亚布兰城堡。</p><p>最后经由保加利亚返回伊斯坦布尔，感受这座充满活力与文化气息的城市。</p><p>✧ 一次畅游10个国家<br>✧ 历史名城与巴尔干文化<br>✧ 壮丽自然与经典景观<br>✧ 传奇特兰西瓦尼亚城堡</p><p>融合历史、文化与自然之美的难忘旅程 ✨</p>', 29350000.00, NULL, 15, 14, '[\"19 JUNI \\u2013 3 JULI 2026\",\"27 JUNI \\u2013 11 JULI 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIGHTS:</strong></p><p style=\"text-align:center;\"><strong>TURKEY – GREECE – MACEDONIA – ALBANIA – MONTENEGRO – CROATIA – BOSNIA – SERBIA – BULGARIA -ROMANIA</strong></p>', '<ul><li data-list-item-id=\"ec4e2a93a24d1461967766825a94d047d\">Tiket internasional : JAKARTA – ISTANBUL | ISTANBUL – JAKARTA By EMIRATES Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</li><li data-list-item-id=\"eb28da6888e13033fcacdcc593a844071\">Bagasi sesuai dengan peraturan penerbangan ( 25/30 kg)</li><li data-list-item-id=\"e014fc9f1ae57de3084f7116313043d17\">Akomodasi Hotel&nbsp; Bintang 3* yang nyaman selama 7 malam ( based on Twin Sharing) <i>Base on availability &amp; confirmations in final itinerary</i></li><li data-list-item-id=\"e3b1a12c04ab485eb3f81aae5021c1842\">Transportasi bus ber AC 49/55 seater</li><li data-list-item-id=\"e9ab78dd3d13f0735120ce55baafb709b\">Fuel surcharge, airport tax Jakarta</li><li data-list-item-id=\"e92b167350e6dcf9a5d3f07b2df3b2c12\">Tour Leader dari Jakarta</li></ul>', '<ul><li data-list-item-id=\"ef613b4c5ce6b60cf6f0d5af5709bcf69\">Visa Schengen &nbsp;: 4.000.000/Pax (Non Refund)</li><li data-list-item-id=\"e28f76803141e16609dda6569c1d4fda9\">Internasional Taxes &amp; Surcharges : Rp 2.850.000/Pax (Wajib)</li><li data-list-item-id=\"e57583f0d8de6c3c30f17dba03e09df2a\">Tipping TL, driver, : IDR 2.000.000 /Pax (Wajib)</li><li data-list-item-id=\"e0806b09ef1364a945b6d90dca7f55343\">Travel Insurance: IDR 850.000 /Pax (Wajib)</li><li data-list-item-id=\"e69e18296ebb46781668959fe0a7c9c77\">City tax : IDR 1.900.000/ pax (Wajib)</li><li data-list-item-id=\"ee6257504d16309b5180fb301fae8642a\">Optional Tour</li><li data-list-item-id=\"ee39588bdbb7d0276ee8284dbdf3105a7\">Lunch &amp; Dinner</li><li data-list-item-id=\"e30d7feb10a3fb3c35e8d210705068a89\">Pengeluaran pribadi : Laundry, phone, minibar, dll</li><li data-list-item-id=\"e6b6289eefa62c8d124ecb4b851e627df\">Pengurusan dokumen perjalanan : Passpor, Visa, dll</li><li data-list-item-id=\"e4dc02844145cc81eff86f36bcede21a5\">Biaya kelebihan bagasi, Biaya extend</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/wmo9WzwplEZcDQLhc2YQSjbQ5TOPn2s1jNcdrAO0.pdf', 0, NULL, '2026-04-27 07:35:20', '2026-04-27 07:40:06'),
(49, 33, '11D Grand Switzerland & Mont Blanc', NULL, '11d-grand-switzerland-mont-blanc', '<p><strong>SUMMER SEASON – 11D GRAND SWITZERLAND &amp; MONT BLANC</strong> 🤩</p><p>Nikmati perjalanan eksklusif menjelajahi keindahan <strong>Swiss, Jerman, Prancis, dan Italia</strong> dalam 11 hari penuh panorama alam spektakuler dan kota-kota romantis Eropa 🌍❄️</p><p>Petualangan dimulai dari Zurich, kota modern nan elegan, dilanjutkan menuju air terjun terbesar di Eropa, Rhine Falls, serta keindahan alam di kawasan Lake Titisee.</p><p>Anda akan menikmati suasana romantis Montreux dan Geneva, sebelum melanjutkan ke Annecy yang dijuluki “Venice of the Alps”.</p><p>Perjalanan berlanjut ke kawasan pegunungan megah Mont Blanc di Chamonix, lalu menuju desa bebas kendaraan Zermattdengan panorama pegunungan Alpen yang menakjubkan.</p><p>Nikmati pengalaman Swiss autentik di Bern dan desa cantik Grindelwald, serta kunjungan ke Jungfraujoch yang terkenal sebagai “Top of Europe”.</p><p>Pesona alam berlanjut di Lucerne dengan danau dan jembatan ikoniknya, sebelum menyeberang ke Lugano yang bernuansa Italia.</p><p>Perjalanan ditutup di kota mode dunia, Milan, dengan kunjungan ke landmark ikonik Duomo di Milano.</p><p>✧ Panorama Alpen &amp; Mont Blanc yang memukau<br>✧ Desa-desa indah khas Swiss<br>✧ Kota romantis &amp; danau eksotis<br>✧ Perpaduan budaya Swiss, Prancis, Jerman &amp; Italia</p><p>Perjalanan sempurna menikmati keindahan alam, budaya, dan romantisme Eropa dalam satu pengalaman tak terlupakan ✨</p><p>&nbsp;</p>', '<p><strong>SUMMER SEASON – 11D GRAND SWITZERLAND &amp; MONT BLANC</strong> 🤩</p><p>Enjoy an exclusive journey exploring the beauty of Switzerland, Germany, France, and Italy in 11 days filled with spectacular landscapes and romantic European cities 🌍❄️</p><p>Your adventure begins in Zurich, a modern and elegant city, continuing to the largest waterfall in Europe, Rhine Falls, and the scenic beauty of Lake Titisee.</p><p>Experience the romantic atmosphere of Montreux and Geneva, before heading to Annecy, famously known as the “Venice of the Alps.”</p><p>The journey continues to the majestic Mont Blanc in Chamonix, followed by a visit to the car-free village of Zermatt with breathtaking Alpine views.</p><p>Enjoy authentic Swiss experiences in Bern and the charming village of Grindelwald, including a visit to Jungfraujoch, known as the “Top of Europe.”</p><p>The scenic journey continues in Lucerne with its iconic lake and bridges, before heading to Lugano with its Italian charm.</p><p>The trip concludes in the fashion capital Milan, featuring a visit to the iconic Duomo di Milano.</p><p>✧ Stunning Alpine &amp; Mont Blanc landscapes<br>✧ Charming Swiss villages<br>✧ Romantic cities &amp; scenic lakes<br>✧ A blend of Swiss, French, German &amp; Italian cultures</p><p>A perfect journey to experience Europe’s nature, culture, and romance in one unforgettable adventure ✨</p>', '<p><strong>여름 시즌 – 11일 스위스 &amp; 몽블랑 여행</strong> 🤩</p><p>스위스, 독일, 프랑스, 이탈리아를 11일 동안 여행하며 아름다운 자연과 로맨틱한 유럽 도시를 경험해보세요 🌍❄️</p><p>여행은 취리히에서 시작하여 유럽 최대 폭포인 라인 폭포와 티티제 호수를 방문합니다.</p><p>이어 몽트뢰와 제네바의 낭만적인 분위기를 즐기고, “알프스의 베네치아”라 불리는 안시로 이동합니다.</p><p>몽블랑이 있는 샤모니를 방문한 후, 차량이 없는 마을 체르마트에서 알프스의 절경을 감상합니다.</p><p>베른과 그린델발트에서 스위스의 매력을 느끼고, “유럽의 정상”이라 불리는 융프라우요흐를 방문합니다.</p><p>루체른의 호수와 다리를 감상한 후, 이탈리아 감성이 느껴지는 루가노로 이동합니다.</p><p>마지막으로 패션의 도시 밀라노에서 밀라노 대성당을 방문하며 여행을 마무리합니다.</p><p>✧ 알프스 &amp; 몽블랑 절경<br>✧ 아름다운 스위스 마을<br>✧ 로맨틱 도시 &amp; 호수<br>✧ 다양한 유럽 문화 체험</p><p>자연과 문화, 낭만이 어우러진 잊지 못할 여행 ✨</p>', '<p><strong>夏季限定 – 11天瑞士 &amp; 勃朗峰之旅</strong> 🤩</p><p>开启一段11天的精彩旅程，探索瑞士、德国、法国和意大利的壮丽风光与浪漫城市 🌍❄️</p><p>旅程从 苏黎世 开始，前往欧洲最大的瀑布 莱茵瀑布，以及风景优美的 蒂蒂湖。</p><p>随后前往 蒙特勒 和 日内瓦，再到被誉为“阿尔卑斯威尼斯”的 安纳西。</p><p>行程继续前往 勃朗峰 所在的 霞慕尼，并探访无车小镇 采尔马特，欣赏壮丽的阿尔卑斯山景。</p><p>在 伯尔尼 和 格林德瓦 体验瑞士风情，并前往“欧洲之巅” 少女峰。</p><p>接着游览 卢塞恩 的湖泊与桥梁，再前往充满意大利风情的 卢加诺。</p><p>最后抵达时尚之都 米兰，参观著名的 米兰大教堂，为旅程画上完美句号。</p><p>✧ 壮丽的阿尔卑斯与勃朗峰<br>✧ 迷人的瑞士小镇<br>✧ 浪漫城市与湖泊风光<br>✧ 多元欧洲文化体验</p><p>一段融合自然、美景与文化的难忘欧洲之旅 ✨</p>', 26500000.00, NULL, 11, 5, '[\"22 JUNI \\u2013 2 JULI 2026\",\"1 \\u2013 11 JULI 2026\",\"21\\u2013 31 AGUSTUS 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIGHTS:</strong></p><p style=\"text-align:center;\"><strong>SWITZERLAND – GERMANY – FRANCE – ITALY</strong></p>', '<ul><li data-list-item-id=\"e73427ca7a62ce563dcdf8988656c8ac2\">Tiket internasional : JAKARTA – ZURICH | MILAN – JAKARTA By QATAR/ETIHAD/EMIRATES Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)</li><li data-list-item-id=\"e9a013475767330fcb3443ffaad3fc216\">Bagasi sesuai dengan peraturan penerbangan ( 25/30 kg)</li><li data-list-item-id=\"e6465f1415c10beea4f763ab1f8f79dd5\">Akomodasi Hotel&nbsp; Bintang 3* yang nyaman selama 7 malam ( based on Twin Sharing) <i>Base on availability &amp; confirmations in final itinerary</i></li><li data-list-item-id=\"ec345bf694ded834041b6e6b7fd929154\">Transportasi bus ber AC 49/55 seater</li><li data-list-item-id=\"e2c4af223d19db9312a81ed48bf8d0cb2\">Fuel surcharge, airport tax Jakarta</li><li data-list-item-id=\"ed09afd00341c814fa21b33d9bca146bd\">Tour Leader dari Jakarta</li></ul>', '<ul><li data-list-item-id=\"e50dc31711ad386afec42e80d07f02ae2\">Visa Schengen &nbsp;: 3.750.000/Pax (Non Refund)</li><li data-list-item-id=\"eac84cc610d3b41abfdcd67af552f4e32\">Internasional Taxes &amp; Surcharges : Rp 2.850.000/Pax (Wajib)</li><li data-list-item-id=\"e79a916408e2be9725c0a25f97e1a1c23\">Tipping TL, driver, : IDR 2.150.000 /Pax (Wajib)</li><li data-list-item-id=\"ee948b8465b4e1c529b03b07f950f92a9\">Travel Insurance: IDR 1.550.000 /Pax (Wajib)</li><li data-list-item-id=\"e07d8c4c4f91bf5ff15b72aba50958465\">City Taxes : IDR 1.050.000 (Wajib)</li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed30387da6e534ab87341d51f5d33e822\"><strong>Optional Tour</strong></li><li data-list-item-id=\"eeff1969ddb33bc3397731cc0bbc21322\">Makan Siang &amp; Makan Malam</li><li data-list-item-id=\"e934630ff97014de3fe9228ba91d07465\">Pengeluaran pribadi : Laundry, phone, minibar, dll</li><li data-list-item-id=\"e98e02afd68c5e9d6c760c8548a29b7f5\">Pengurusan dokumen perjalanan : Passpor, Visa, dll</li><li data-list-item-id=\"ee4564eb39b10137715416920e134b219\">Biaya kelebihan bagasi, Biaya extend</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/JOpsEXpNrruDwcsBDv8h96fmePfrm67HURdXBEou.pdf', 0, NULL, '2026-04-27 08:23:14', '2026-04-27 08:29:33'),
(50, 34, '7D Super Sale Australia (Melbourne + Sydney)', NULL, '7d-super-sale-australia-melbourne-sydney', '<p><strong>SYDNEY &amp; MELBOURNE EXPLORER – 7D AUSTRALIA TOUR</strong> 🤩</p><p>Nikmati liburan seru menjelajahi dua kota terbaik di Australia: Sydney &amp; Melbourne dalam 7 hari penuh pengalaman tak terlupakan 🌏☀️</p><p>Petualangan dimulai di Sydney dengan mengunjungi ikon dunia Sydney Opera House, serta kawasan bersejarah The Rocks dan Circular Quay yang menawarkan pemandangan pelabuhan yang indah.</p><p>Anda juga akan menikmati suasana alam di Royal Botanic Garden Sydney, spot ikonik Mrs Macquarie’s Chair, hingga panorama laut di Bondi Beach dan tebing dramatis The Gap.</p><p>Perjalanan berlanjut ke Melbourne, kota penuh seni dan budaya. Anda akan mengunjungi landmark seperti Parliament House Melbourne, St Patrick’s Cathedral Melbourne, serta taman indah Fitzroy Gardens.</p><p>Nikmati pengalaman unik bertemu satwa khas Australia di Moonlit Sanctuary, sebelum menuju pesisir spektakuler The Nobbies untuk menyaksikan koloni anjing laut dan parade penguin yang menggemaskan 🐧</p><p>✧ Ikon dunia Sydney Opera House<br>✧ Pantai eksotis Bondi Beach<br>✧ Kota seni &amp; budaya Melbourne<br>✧ Pengalaman melihat kanguru, koala &amp; penguin<br>✧ Perpaduan city tour &amp; wisata alam Australia</p><p>Perjalanan sempurna menikmati keindahan kota modern, pantai eksotis, dan satwa khas Australia dalam satu pengalaman liburan yang seru dan berkesan ✨</p>', '<p><strong>SYDNEY &amp; MELBOURNE EXPLORER – 7D AUSTRALIA TOUR</strong> 🤩</p><p>Enjoy an exciting holiday exploring two of Australia’s best cities: Sydney &amp; Melbourne in 7 days full of unforgettable experiences 🌏☀️</p><p>Your journey begins in Sydney with a visit to the world-famous Sydney Opera House, along with the historic districts of The Rocks and Circular Quay offering stunning harbour views.</p><p>Enjoy nature at Royal Botanic Garden Sydney, the iconic Mrs Macquarie’s Chair, and breathtaking coastal scenery at Bondi Beach and The Gap.</p><p>The journey continues to Melbourne, a city rich in art and culture. Visit landmarks such as Parliament House Melbourne, St Patrick’s Cathedral Melbourne, and the beautiful Fitzroy Gardens.</p><p>Enjoy a unique wildlife experience at Moonlit Sanctuary, before heading to The Nobbies to witness seal colonies and the adorable penguin parade 🐧</p><p>✧ Iconic Sydney Opera House<br>✧ Exotic Bondi Beach<br>✧ Art &amp; culture of Melbourne<br>✧ Kangaroo, koala &amp; penguin experience<br>✧ Perfect blend of city &amp; nature</p><p>A perfect journey to explore modern cities, stunning beaches, and unique Australian wildlife in one unforgettable trip ✨</p>', '<p><strong>시드니 &amp; 멜버른 7일 호주 여행</strong> 🤩</p><p>호주의 대표 도시 시드니와 멜버른을 7일 동안 여행하며 잊지 못할 추억을 만들어보세요 🌏☀️</p><p>여행은 세계적인 랜드마크 시드니 오페라 하우스 방문으로 시작하며, 더 록스와 서큘러 키에서 아름다운 항구 풍경을 감상합니다.</p><p>로열 보타닉 가든, 맥쿼리 의자, 그리고 본다이 비치와 더 갭의 멋진 해안 절경도 즐길 수 있습니다.</p><p>이후 예술과 문화의 도시 멜버른으로 이동하여 멜버른 국회의사당, 세인트 패트릭 대성당, 피츠로이 가든 등을 방문합니다.</p><p>또한 문릿 생츄어리에서 캥거루와 코알라를 만나고, 노비스에서 바다표범과 펭귄 퍼레이드를 관람합니다 🐧</p><p>✧ 시드니 대표 랜드마크<br>✧ 아름다운 해변<br>✧ 멜버른 문화 체험<br>✧ 호주 야생동물 체험<br>✧ 도시와 자연의 조화</p><p>잊지 못할 호주 여행을 경험해보세요 ✨</p>', '<p><strong>悉尼 &amp; 墨尔本 7日澳大利亚之旅</strong> 🤩</p><p>开启一段精彩的7天旅程，探索 悉尼 和 墨尔本 两大城市，留下难忘回忆 🌏☀️</p><p>旅程从参观世界著名的 悉尼歌剧院 开始，并游览 岩石区 和 环形码头，欣赏迷人的港口景色。</p><p>接着前往 皇家植物园、麦考利夫人座椅，以及 邦迪海滩 和 断崖 的壮丽海景。</p><p>随后前往文化艺术之都墨尔本，参观 墨尔本议会大厦、圣帕特里克大教堂 和 菲茨罗伊花园。</p><p>在 月光野生动物园 近距离接触袋鼠和考拉，并前往 诺比斯角 观赏海豹及可爱的企鹅归巢 🐧</p><p>✧ 世界地标悉尼歌剧院<br>✧ 迷人海滩风光<br>✧ 墨尔本文化艺术<br>✧ 澳大利亚野生动物体验<br>✧ 城市与自然完美结合</p><p>一次融合城市、海滩与自然的难忘旅程 ✨</p>', 20990000.00, NULL, 7, 6, '[\"23 Juli 2026\",\"22 Agustus 2026\",\"22 Oktober 2026\",\"21 November 2026\"]', NULL, '<p><i><strong>HIGHLIGHT:&nbsp; Sydney Opera House, Bondi Beach, Fitzroy Garden, Moonlit Sanctuary, The Nobbies&nbsp;</strong></i></p><p><i><strong>GUARANTEE BEST PRICE &amp; SERVICE&nbsp;</strong></i></p>', '<ul><li data-list-item-id=\"ec9e8470824ecc64d8a3d5394baf4603e\"><p style=\"text-align:justify;\">Tiket International Jakarta – Sydney &amp; Melbourne - Jakarta by <strong>Qantas Airways</strong>, Economy <strong>termasuk taxes internasional </strong>(Tiket Grup Fixed Date &amp; No Extend) Bagasi sesuai dengan ketentuan Airlines</p></li><li data-list-item-id=\"ebb1c7808b9f7bfd614e766c36bf1e9be\"><p style=\"text-align:justify;\">Akomodasi hotel *3 setaraf (Twin / Triple)</p></li><li data-list-item-id=\"e8527159f09469111a4ff6e12f1b733c9\"><p style=\"text-align:justify;\">Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p></li><li data-list-item-id=\"e0273268d95079f41ce54ca730560a94e\"><p style=\"text-align:justify;\">Acara Tour &amp; makan sesuai program paket tour diatas</p></li><li data-list-item-id=\"e183b9baede1f982d59d0b1999f9b75ea\"><p style=\"text-align:justify;\">Mineral Water 01 Botol Perhari</p></li><li data-list-item-id=\"e2625c79fa26d50ddda52a42440cd0fe9\"><p style=\"text-align:justify;\">Tour Leader&nbsp;</p></li><li data-list-item-id=\"e2a903e5705d1ba6a7fceccb3701db34a\"><p style=\"text-align:justify;\">Travel Kits (Luggage Tag)</p></li><li data-list-item-id=\"e12459b9712ad5e5a2c7be22d3be15496\"><p style=\"text-align:justify;\">Travel Insurance</p></li></ul>', '<ul><li data-list-item-id=\"eaffa82f7662c0d113caadcd0bbaf8179\"><p style=\"text-align:justify;\">Biaya <strong>Visa Australia: Rp 2.800.000/ Pax</strong></p></li><li data-list-item-id=\"e9f8698f0605049fbabd21a845202f06e\"><p style=\"text-align:justify;\">Tipping Tour Leader &amp; Driver: <strong>Rp 850.000</strong></p></li><li data-list-item-id=\"e9d619a13fea17665c7afd062259890f4\"><p style=\"text-align:justify;\">Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p></li><li data-list-item-id=\"ea87ec250b1e7c8b1d925201b1c2bc160\"><p style=\"text-align:justify;\">PCR Test / Rapid Test Antigen Jika dibutuhkan</p></li></ul><p style=\"text-align:justify;\">OPTIONAL:</p><p style=\"text-align:justify;\">Rental Wifi Portable</p>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/EW4f54p65uvfHaQPzk7lUFiRZZl4u0LCOZmDj2U6.pdf', 0, NULL, '2026-04-28 03:23:42', '2026-04-28 05:35:36');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(51, 35, 'Turkey Plus Dubai 11D9N', NULL, 'turkiasik-plus-dubai-11d9n', '<p><strong>TURKIASIK PLUS DUBAI – 11D 09N EXOTIC JOURNEY 🤩</strong></p><p>Nikmati perjalanan istimewa menjelajahi dua dunia berbeda: kemewahan modern Dubai dan pesona sejarah Turki dalam 11 hari penuh pengalaman tak terlupakan 🌍✨</p><p>Petualangan dimulai di Dubai, kota futuristik dengan landmark ikonik seperti Burj Khalifa, Dubai Frame, dan Museum of the Future. Anda juga memiliki waktu bebas untuk menikmati berbagai aktivitas seru, termasuk optional Desert Safari di padang pasir yang eksotis 🐪🌅</p><p>Perjalanan berlanjut ke Istanbul, kota yang menghubungkan dua benua, Asia dan Eropa. Anda akan diajak menjelajahi keindahan sejarah seperti Blue Mosque dan Hagia Sophia, serta menikmati pengalaman cruise di Selat Bosphorus yang memukau 🚢</p><p>Eksplorasi Turki semakin lengkap dengan mengunjungi kota-kota menawan seperti Bursa, Ephesus yang penuh sejarah Romawi, hingga keajaiban alam Pamukkale yang terkenal dengan teras putihnya yang unik</p><p>Puncak perjalanan berada di Cappadocia, kawasan magis dengan lanskap bebatuan unik. Di sini Anda bisa menikmati pengalaman tak terlupakan seperti optional hot air balloon dengan pemandangan sunrise yang spektakuler 🎈</p><p>✧ Perpaduan modern &amp; sejarah: Dubai &amp; Turki<br>✧ Landmark dunia &amp; situs bersejarah ikonik<br>✧ Keajaiban alam Pamukkale &amp; Cappadocia<br>✧ Pengalaman Bosphorus Cruise &amp; optional balloon ride<br>✧ One Day Free Program di Dubai &amp; Istanbul</p><p>Perjalanan sempurna bagi Anda yang ingin merasakan kemewahan kota modern, keindahan alam, dan kekayaan sejarah dalam satu paket wisata yang lengkap dan berkesan ✨</p>', '<p><strong>TURKIASIK PLUS DUBAI – 11D 09N EXOTIC JOURNEY 🤩</strong></p><p>Enjoy a remarkable journey exploring two contrasting worlds: the modern luxury of Dubai and the rich historical charm of Turkey in 11 unforgettable days 🌍✨</p><p>Your adventure begins in Dubai, a futuristic city featuring iconic landmarks such as the Burj Khalifa, Dubai Frame, and Museum of the Future. You’ll also have free time to explore and enjoy exciting optional activities like a Desert Safari in the stunning Arabian desert 🐪🌅</p><p>The journey continues to Istanbul, a unique city connecting Asia and Europe. Discover historical masterpieces like the Blue Mosque and Hagia Sophia, and enjoy a scenic Bosphorus Cruise experience 🚢</p><p>Explore more of Turkey with visits to beautiful cities including Bursa, the ancient Roman city of Ephesus, and the natural wonder Pamukkale, famous for its stunning white terraces</p><p>The highlight of the trip is Cappadocia, a magical region known for its unique rock formations. تجربة an unforgettable optional hot air balloon ride at sunrise 🎈</p><p>✧ Perfect blend of modern &amp; historical destinations<br>✧ World-famous landmarks &amp; cultural heritage sites<br>✧ Natural wonders of Pamukkale &amp; Cappadocia<br>✧ Bosphorus Cruise &amp; optional balloon experience<br>✧ One Day Free Program in Dubai &amp; Istanbul</p><p>A perfect journey combining luxury, nature, and history into one unforgettable travel experience ✨</p>', '<p><strong>터키아식 + 두바이 11일 여행 🤩</strong></p><p>현대적인 럭셔리 도시 두바이와 깊은 역사를 지닌 터키를 한 번에 즐기는 11일간의 특별한 여행을 경험하세요 🌍✨</p><p>여행은 미래적인 도시 두바이에서 시작됩니다. 세계적인 랜드마크인 부르즈 할리파, 두바이 프레임, 미래 박물관을 방문하며 자유 시간에는 사막 사파리 등 다양한 옵션 투어를 즐길 수 있습니다 🐪🌅</p><p>이후 아시아와 유럽을 잇는 도시 이스탄불로 이동하여 블루 모스크와 아야 소피아 같은 역사적인 명소를 탐방하고, 보스포러스 해협 크루즈를 경험합니다 🚢</p><p>또한 부르사, 고대 로마 도시 에페소스, 그리고 하얀 석회층으로 유명한 파묵칼레 등 터키의 다양한 매력을 만나볼 수 있습니다</p><p>여행의 하이라이트는 카파도키아로, 독특한 바위 지형과 함께 열기구 체험(옵션)을 통해 환상적인 일출을 감상할 수 있습니다 🎈</p><p>✧ 현대와 역사의 완벽한 조화<br>✧ 세계적인 명소와 문화 유산<br>✧ 파묵칼레 &amp; 카파도키아 자연 절경<br>✧ 보스포러스 크루즈 &amp; 열기구 체험<br>✧ 두바이 &amp; 이스탄불 자유 일정 포함</p><p>럭셔리, 자연, 역사를 모두 경험할 수 있는 완벽한 여행 ✨</p>', '<p><strong>土耳其 + 迪拜 11天9晚梦幻之旅 🤩</strong></p><p>开启一段精彩旅程，一次性探索现代奢华的迪拜与充满历史魅力的土耳其，11天难忘体验 🌍✨</p><p>旅程从未来感十足的迪拜开始，参观世界著名地标如哈利法塔、迪拜相框和未来博物馆，并可自由安排时间体验沙漠冲沙等精彩活动 🐪🌅</p><p>随后前往横跨亚欧大陆的伊斯坦布尔，参观蓝色清真寺和圣索菲亚大教堂，并体验博斯普鲁斯海峡游船之旅 🚢</p><p>继续探索土耳其，游览布尔萨、古罗马遗址以弗所，以及以白色阶梯闻名的自然奇观棉花堡</p><p>行程亮点是卡帕多奇亚，这里以独特的岩石地貌闻名，还可选择热气球体验，欣赏壮丽日出 🎈</p><p>✧ 现代与历史完美结合<br>✧ 世界级地标与文化遗产<br>✧ 棉花堡 &amp; 卡帕多奇亚自然奇观<br>✧ 博斯普鲁斯海峡游船 &amp; 热气球体验<br>✧ 迪拜与伊斯坦布尔自由活动时间</p><p>一次融合奢华、自然与历史的完美旅程，带来难忘回忆 ✨</p>', 22999000.00, NULL, 11, 9, '[\"24 Juni \\u2013 04 Juli 2026 \"]', NULL, '<p style=\"text-align:center;\"><strong>TURKIASIK PLUS DUBAI 11 HARI 09 MALAM</strong></p><p style=\"text-align:center;\"><strong>(ONE DAY FREE PROGRAM IN DUBAI &amp; ISTANBUL)</strong></p>', '<ul><li data-list-item-id=\"e84ac76f564a383d840ae421c98c575c3\"><p style=\"text-align:justify;\">Tiket penerbangan Ekonomi PP dengan <strong>EMIRATES AIRLINES</strong></p></li><li data-list-item-id=\"ee647b1134f78df447aa10f238dfb1f97\"><p style=\"text-align:justify;\">Akomodasi hotel *3 selama 2 malam di Dubai (1 kamar 2 orang)</p></li><li data-list-item-id=\"e6bb5a906bb25aa15fccfd5736041903c\"><p style=\"text-align:justify;\">Akomodasi hotel *4 selama 7 malam di Turki (1 kamar 2 orang)</p></li><li data-list-item-id=\"ee64c95b27e959821333c449a303e7124\"><p style=\"text-align:justify;\">Makan sesuai yang tertera pada itinerary</p></li><li data-list-item-id=\"ef22d1c7644882f5017a9c775df057ec4\"><p style=\"text-align:justify;\">Transportasi &amp; City Tour Dubai sesuai program</p></li><li data-list-item-id=\"eb71718c6e75947a1aa8070f6f110ebb0\"><p style=\"text-align:justify;\">Transportasi, Tour dan tiket masuk tempat wisata di Turki sesuai program</p></li><li data-list-item-id=\"eb7546efcbe280b8e5643be056554b34a\"><p style=\"text-align:justify;\">Asuransi perjalanan (Usia diatas 69 Tahun ada penambahan biaya)</p></li><li data-list-item-id=\"eb64736e38160eb56bb3e79f3ef9c0c10\"><p style=\"text-align:justify;\">Didampingi Tour Leader dari Jakarta</p></li><li data-list-item-id=\"ed9295db2657712985ba5096ab77d821e\"><p style=\"text-align:justify;\">Professional Local Guide</p></li><li data-list-item-id=\"ec3ee3dad0b8a52bb2ee228a37ae102e1\"><p style=\"text-align:justify;\">Bosphorus Tour</p></li><li data-list-item-id=\"ef0fcf5045e21a3544ffa5e5b6d303e9f\"><p style=\"text-align:justify;\">Air mineral 500ml, 2 botol per hari</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e35e3a11ecab3734fd0a4a43bbf159874\"><p style=\"text-align:justify;\"><strong>Komisi Agent IDR. 700,000,- per pax</strong></p></li></ul>', '<ul><li data-list-item-id=\"e0666e6601283482d0f05a3615b1a93c9\"><p style=\"text-align:justify;\">●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Tipping Tour Leader: <strong>USD 3 x 11 Hari = USD 33 per orang</strong></p></li><li data-list-item-id=\"edd117ad1419b1058ad457bb48ccd9a3c\"><p style=\"text-align:justify;\">Tipping Guide &amp; Driver Turkiye: <strong>USD 7 x 7 Hari = USD 49 per orang</strong></p></li><li data-list-item-id=\"e4ca517a3e99aadf952f110ac35e897a5\"><p style=\"text-align:justify;\">Tipping Guide &amp; Driver Dubai: <strong>USD 5 x 3 Hari = USD 15 per pax</strong></p></li><li data-list-item-id=\"e5d819222b4c59028735bc74178ed7997\"><p style=\"text-align:justify;\">Visa Dubai 96 Hours <strong>IDR 1,300,000 per pax</strong> (harga masih bisa dapat berubah-ubah sesuai dengan ketentuan dari penyedia jasa visa)</p></li><li data-list-item-id=\"e5ff6e54d9d37f3e1698fa3bee7d8cd71\"><p style=\"text-align:justify;\">Penambahan biaya Asuransi Perjalanan untuk usia diatas 69 - 75 Tahun IDR. 300.000 (untuk usia diatas 75 tahun harga berbeda dan harap konfirmasi ke kami)</p></li><li data-list-item-id=\"ebdde80d3691ce4f131e16406c61e3a79\"><p style=\"text-align:justify;\">Visa Turki apabila ada</p></li><li data-list-item-id=\"ecb5a0051767dd9732f7b176019bcdd21\"><p style=\"text-align:justify;\">PCR di masing masing destinasi apabila ada</p></li><li data-list-item-id=\"ee3f1fee1f89e7b06a2e6de3dc9eda19e\"><p style=\"text-align:justify;\">Pengeluaran pribadi</p></li><li data-list-item-id=\"e22a027d0c5d38d31e633c72e26dbdc1b\"><p style=\"text-align:justify;\">Tour opsional</p></li><li data-list-item-id=\"eec00e4a64061e1921f4401b2b65808a9\"><p style=\"text-align:justify;\">Karantina mandiri (apabila ada)</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/iHWyz4fQ2ZUCTP74A6GZJaoNEzHUqdhHjV4HlQjl.pdf', 0, NULL, '2026-04-28 06:08:51', '2026-04-29 02:59:04'),
(52, 35, 'Turkey 10D7N', NULL, 'turkiasik-10d7n', '<p><strong>TURKIASIK 10D 07N – EXPLORE TURKEY 🤩</strong></p><p>Rasakan keindahan Turki dalam 10 hari perjalanan penuh sejarah, budaya, dan panorama alam yang memukau 🌍✨</p><p>Petualangan dimulai dengan perjalanan menuju Istanbul, kota unik yang menghubungkan dua benua. Anda akan menikmati pengalaman berlayar di Selat Bosphorus yang ikonik serta menjelajahi pesona kota tua yang kaya sejarah 🚢</p><p>Perjalanan berlanjut ke Bursa, kota bersejarah dengan suasana khas Ottoman, sebelum menuju Kusadasi dan mengunjungi Ephesus, kota kuno peninggalan Romawi yang megah</p><p>Nikmati keajaiban alam di Pamukkale dengan teras putihnya yang unik, sebelum melanjutkan perjalanan ke Cappadociayang terkenal dengan lanskap batuan eksotis dan pengalaman balon udara yang mendunia 🎈</p><p>Di Cappadocia, Anda akan diajak menjelajahi lembah-lembah indah, kota bawah tanah, hingga desa tradisional yang penuh pesona. Perjalanan kemudian kembali ke Istanbul untuk menikmati waktu bebas menjelajahi kota, berbelanja di Grand Bazaar, dan mengunjungi landmark terkenal seperti Blue Mosque dan Hagia Sophia</p><p>✧ Bosphorus Cruise yang ikonik<br>✧ Kota kuno Ephesus yang bersejarah<br>✧ Keajaiban alam Pamukkale<br>✧ Cappadocia dengan balon udara &amp; lanskap unik<br>✧ Free Day di Istanbul untuk eksplorasi bebas</p><p>Perjalanan lengkap menikmati keindahan sejarah, budaya, dan alam Turki dalam satu pengalaman liburan yang tak terlupakan ✨</p>', '<p><strong>TURKIASIK 10D 07N – EXPLORE TURKEY 🤩</strong></p><p>Experience the beauty of Turkey in a 10-day journey filled with history, culture, and breathtaking landscapes 🌍✨</p><p>Your adventure begins in Istanbul, a unique city connecting two continents. Enjoy a scenic Bosphorus Cruise and explore the charm of the historic Old City 🚢</p><p>Continue your journey to Bursa, a historical Ottoman city, then to Kusadasi where you will visit Ephesus, a magnificent ancient Roman city</p><p>Discover the natural wonder of Pamukkale, famous for its stunning white terraces, before heading to Cappadocia, known for its unique rock formations and world-famous hot air balloon experience 🎈</p><p>In Cappadocia, explore beautiful valleys, underground cities, and traditional villages. The journey ends back in Istanbul, where you’ll enjoy free time to explore the city, shop at the Grand Bazaar, and visit iconic landmarks such as the Blue Mosque and Hagia Sophia</p><p>✧ Iconic Bosphorus Cruise<br>✧ Historic Ephesus ancient city<br>✧ Natural wonder of Pamukkale<br>✧ Cappadocia with balloon experience<br>✧ Free Day in Istanbul</p><p>A complete journey combining history, culture, and nature into one unforgettable travel experience ✨</p>', '<p><strong>터키아식 10일 여행 🤩</strong></p><p>역사, 문화, 그리고 아름다운 자연을 한 번에 즐길 수 있는 10일간의 터키 여행을 경험하세요 🌍✨</p><p>여행은 아시아와 유럽을 연결하는 도시 이스탄불에서 시작됩니다. 보스포러스 해협 크루즈를 즐기고 역사적인 구시가지를 탐방합니다 🚢</p><p>이어 오스만 제국의 도시 부르사, 그리고 쿠사다시를 거쳐 고대 로마 유적지 에페소스를 방문합니다</p><p>하얀 석회층으로 유명한 파묵칼레의 자연 경관을 감상한 후, 독특한 바위 지형으로 유명한 카파도키아로 이동합니다. 이곳에서는 열기구 체험(옵션)을 통해 환상적인 풍경을 즐길 수 있습니다 🎈</p><p>카파도키아에서는 계곡, 지하 도시, 전통 마을을 탐방하고, 이후 이스탄불로 돌아와 자유 시간을 즐기며 그랜드 바자르 쇼핑과 블루 모스크, 아야 소피아 등을 방문합니다</p><p>✧ 보스포러스 크루즈<br>✧ 에페소스 고대 유적지<br>✧ 파묵칼레 자연 절경<br>✧ 카파도키아 열기구 체험<br>✧ 이스탄불 자유 일정</p><p>역사와 문화, 자연을 모두 경험할 수 있는 완벽한 여행 ✨</p>', '<p><strong>土耳其10天7晚深度之旅 🤩</strong></p><p>开启一段融合历史、文化与自然美景的10天精彩旅程 🌍✨</p><p>旅程从横跨亚欧大陆的伊斯坦布尔开始，体验博斯普鲁斯海峡游船，并探索充满历史魅力的老城区 🚢</p><p>随后前往布尔萨，这座具有奥斯曼风情的城市，再到库萨达斯参观以弗所古城，这是一座壮观的古罗马遗址</p><p>接着游览以白色阶梯闻名的自然奇观棉花堡，然后前往卡帕多奇亚，这里以独特的岩石地貌和热气球体验而闻名 🎈</p><p>在卡帕多奇亚，您将探索山谷、地下城和传统村庄。最后返回伊斯坦布尔，享受自由活动时间，可前往大巴扎购物，并参观蓝色清真寺和圣索菲亚大教堂</p><p>✧ 博斯普鲁斯海峡游船<br>✧ 以弗所古城遗址<br>✧ 棉花堡自然奇观<br>✧ 卡帕多奇亚热气球体验<br>✧ 伊斯坦布尔自由活动</p><p>一段融合历史、文化与自然的完美旅程，留下难忘回忆 ✨</p>', 19999000.00, NULL, 10, 7, '[\"25 Juni \\u2013 04 Juli 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>TURKIASIK 10 HARI 7 MALAM</strong></p><p style=\"text-align:center;\"><strong>(ONE DAY FREE PROGRAM IN ISTANBUL)</strong></p>', '<ul><li data-list-item-id=\"eba8ca22696dd91e961fb1aadf6522cc7\"><p style=\"text-align:justify;\">Tiket penerbangan Ekonomi PP dengan <strong>EMIRATES AIRLINES</strong></p></li><li data-list-item-id=\"e92d03b498dd8f3874d06bacead0bf217\"><p style=\"text-align:justify;\">Akomodasi hotel *4 selama 7 malam di Turki (1 kamar 2 orang)</p></li><li data-list-item-id=\"ee8abbcdbb9df57370621445831dda895\"><p style=\"text-align:justify;\">Makan sesuai yang tertera pada itinerary</p></li><li data-list-item-id=\"e99fc9a13bdc3082e7aa50093001d6a0d\"><p style=\"text-align:justify;\">Transportasi, Tour dan tiket masuk tempat wisata di Turki sesuai program</p></li><li data-list-item-id=\"ed220755e185fc4fb6675348dce43dc0d\"><p style=\"text-align:justify;\">Asuransi perjalanan (Usia diatas 69 Tahun ada penambahan biaya)</p></li><li data-list-item-id=\"e875a89c4dbdb46d8b6cd2aa2f0946c0c\"><p style=\"text-align:justify;\">Didampingi Tour Leader dari Jakarta</p></li><li data-list-item-id=\"ef49d4efd4d1edfb537922b0adf8d61b5\"><p style=\"text-align:justify;\">Professional Local Guide</p></li><li data-list-item-id=\"e1d913569af685797d1cdf7cef1ebc66e\"><p style=\"text-align:justify;\">Bosphorus Tour</p></li><li data-list-item-id=\"e94c61e6404c99aa23a3895d88ee5749b\"><p style=\"text-align:justify;\">Air mineral 500ml, 2 botol per hari</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ef510d58326e36a81398a88ea4df60f1b\"><p style=\"text-align:justify;\"><strong>Komisi Agent IDR. 700,000,- per pax</strong></p></li></ul>', '<ul><li data-list-item-id=\"e98142208e6c1ee7e610de899fea741f8\"><p style=\"text-align:justify;\">Tipping Tour Leader: <strong>USD 3 x 10 Hari = USD 30 per orang</strong></p></li><li data-list-item-id=\"ea95af8cdc9572c5367cbb2ad4d4edd66\"><p style=\"text-align:justify;\">Tipping Guide &amp; Driver Turkiye: <strong>USD 7 x 7 Hari = USD 49 per orang</strong></p></li><li data-list-item-id=\"e67f57a6382423e619cedd4a06ada8b4b\"><p style=\"text-align:justify;\">Penambahan biaya Asuransi Perjalanan untuk usia diatas 69 - 75 Tahun IDR. 300.000 (untuk usia diatas 75 tahun harga berbeda dan harap konfirmasi ke kami)</p></li><li data-list-item-id=\"e128069a0b80967b78e0df27347273543\"><p style=\"text-align:justify;\">Visa Turki apabila ada</p></li><li data-list-item-id=\"eb9aaed25d83a532ed27f3765c9397794\"><p style=\"text-align:justify;\">PCR di masing masing destinasi apabila ada</p></li><li data-list-item-id=\"eee2e81161b151ad089605a1e58a646e8\"><p style=\"text-align:justify;\">Pengeluaran pribadi</p></li><li data-list-item-id=\"e6f639e593166cae598eeb14991096e9e\"><p style=\"text-align:justify;\">Tour opsional</p></li><li data-list-item-id=\"e51085b23ecd26ff4f121a0f18b024051\"><p style=\"text-align:justify;\">Karantina mandiri (apabila ada)</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/ExbnGOqDo3MfHbTjIWd34TFVd2ofbJYmwkiMImKk.pdf', 0, NULL, '2026-04-28 06:54:35', '2026-04-29 02:59:57'),
(53, 35, 'Turkey 10D7N Periode Juni', NULL, 'turkiasik-10d7n-periode-juni', '<p><strong>TURKIASIK 10D 07N – DISCOVER TURKEY 🤩</strong></p><p>Jelajahi pesona Turki dalam perjalanan 10 hari yang memadukan keindahan alam, kekayaan sejarah, dan budaya khas yang memikat 🌍✨</p><p>Perjalanan dimulai menuju Istanbul, kota unik yang menghubungkan dua benua. Anda akan menikmati pengalaman berlayar di Selat Bosphorus dengan pemandangan kota yang menakjubkan 🚢</p><p>Petualangan berlanjut ke Bursa, kota bersejarah peninggalan Ottoman, sebelum menuju Kusadasi dan menjelajahi Ephesus, kota kuno Romawi yang penuh cerita masa lalu</p><p>Nikmati keajaiban alam Pamukkale dengan teras putih yang unik, lalu lanjut ke Cappadocia yang terkenal dengan lanskap bebatuan eksotis dan pengalaman balon udara yang mendunia 🎈</p><p>Di Cappadocia, Anda akan mengunjungi lembah-lembah indah, kota bawah tanah, serta desa tradisional yang memikat. Perjalanan kembali ke Istanbul memberikan waktu bebas untuk menikmati suasana kota, berbelanja di Grand Bazaar, serta mengunjungi ikon seperti Blue Mosque dan Hagia Sophia</p><p>✧ Bosphorus Cruise yang ikonik<br>✧ Kota kuno Ephesus yang bersejarah<br>✧ Keajaiban alam Pamukkale<br>✧ Cappadocia dengan balon udara<br>✧ Free Day di Istanbul</p><p>Perjalanan lengkap menikmati keindahan alam, budaya, dan sejarah Turki dalam satu pengalaman liburan yang tak terlupakan ✨</p>', '<p><strong>TURKIASIK 10D 07N – DISCOVER TURKEY 🤩</strong></p><p>Explore the beauty of Turkey in a 10-day journey combining stunning landscapes, rich history, and unique cultural experiences 🌍✨</p><p>Your journey begins in Istanbul, a fascinating city that connects two continents. Enjoy a scenic Bosphorus Cruise with breathtaking views of the city 🚢</p><p>Continue to Bursa, a historic Ottoman city, before heading to Kusadasi and visiting the ancient city of Ephesus, one of the best-preserved Roman sites</p><p>Discover the natural wonder of Pamukkale, famous for its stunning white terraces, then travel to Cappadocia, known for its unique rock formations and hot air balloon experience 🎈</p><p>In Cappadocia, explore valleys, underground cities, and charming villages. Return to Istanbul for free time to shop at the Grand Bazaar and visit iconic landmarks such as Blue Mosque and Hagia Sophia</p><p>✧ Iconic Bosphorus Cruise<br>✧ Historic Ephesus<br>✧ Natural wonder Pamukkale<br>✧ Cappadocia hot air balloon experience<br>✧ Free day in Istanbul</p><p>A perfect journey to experience the beauty, culture, and history of Turkey in one unforgettable trip ✨</p>', '<p><strong>TURKIASIK 10일 7박 – 터키 여행 🤩</strong></p><p>아름다운 자연, 풍부한 역사, 독특한 문화를 모두 경험할 수 있는 10일간의 터키 여행을 즐겨보세요 🌍✨</p><p>여행은 두 대륙을 연결하는 도시 Istanbul에서 시작됩니다. 보스포루스 해협 크루즈를 통해 멋진 도시 전경을 감상하세요 🚢</p><p>이어 오스만 제국의 역사 도시 Bursa를 방문하고, 쿠사다시로 이동하여 고대 로마 유적지 Ephesus를 탐방합니다</p><p>하얀 석회층으로 유명한 자연의 경이 Pamukkale를 감상한 후, 독특한 지형과 열기구 체험으로 유명한 Cappadocia로 이동합니다 🎈</p><p>카파도키아에서는 계곡, 지하 도시, 전통 마을을 탐험합니다. 이후 이스탄불로 돌아와 자유시간을 즐기며 그랜드 바자르 쇼핑과 Blue Mosque, Hagia Sophia 등을 방문할 수 있습니다</p><p>✧ 보스포루스 크루즈<br>✧ 에페소스 유적지<br>✧ 파묵칼레 자연 경관<br>✧ 카파도키아 열기구 체험<br>✧ 이스탄불 자유 일정</p><p>터키의 자연과 역사, 문화를 모두 경험할 수 있는 완벽한 여행 ✨</p>', '<p><strong>TURKIASIK 10天7晚 – 土耳其之旅 🤩</strong></p><p>开启一段融合壮丽自然风光、丰富历史文化与独特体验的10天土耳其之旅 🌍✨</p><p>旅程从横跨欧亚大陆的城市 Istanbul开始，搭乘博斯普鲁斯海峡游船，欣赏迷人的城市景观 🚢</p><p>随后前往历史名城 Bursa，再到库萨达斯，参观古罗马遗址 Ephesus</p><p>探索自然奇观 Pamukkale，欣赏独特的白色梯田景观，然后前往以热气球闻名的 Cappadocia 🎈</p><p>在卡帕多奇亚，您将探索山谷、地下城和传统村庄。返回伊斯坦布尔后，可自由活动，逛大巴扎，并参观著名景点 Blue Mosque 和 Hagia Sophia</p><p>✧ 博斯普鲁斯海峡游船<br>✧ 以弗所古城<br>✧ 棉花堡自然奇观<br>✧ 卡帕多奇亚热气球体验<br>✧ 伊斯坦布尔自由活动</p><p>一次完美融合自然、文化与历史的难忘旅程 ✨</p>', 19999000.00, NULL, 10, 7, '[\"28 Juni \\u2013 07 Juli 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>TURKIASIK 10 HARI 7 MALAM</strong></p><p style=\"text-align:center;\"><strong>(ONE DAY FREE PROGRAM IN ISTANBUL)</strong></p>', '<ul><li data-list-item-id=\"eae2e51672ff0f66308e2a4af708899b5\"><p style=\"text-align:justify;\">Tiket penerbangan Ekonomi PP dengan <strong>EMIRATES AIRLINES</strong></p></li><li data-list-item-id=\"e93ff3a912f6ef8b7288aadb45360aee2\"><p style=\"text-align:justify;\">Akomodasi hotel *3 selama 2 malam di Dubai (1 kamar 2 orang)</p></li><li data-list-item-id=\"e5c26b4e6afe3d148a7f28cce7fba4c96\"><p style=\"text-align:justify;\">Akomodasi hotel *4 selama 7 malam di Turki (1 kamar 2 orang)</p></li><li data-list-item-id=\"ebb69cf25d5d5f71204bf291188124d14\"><p style=\"text-align:justify;\">Makan sesuai yang tertera pada itinerary</p></li><li data-list-item-id=\"e8b80cc82c76a2da499edac05248df46b\"><p style=\"text-align:justify;\">Transportasi &amp; City Tour Dubai sesuai program</p></li><li data-list-item-id=\"e333854120994db0769dfa02f70afb19a\"><p style=\"text-align:justify;\">Transportasi</p></li><li data-list-item-id=\"e4ef03a190f054115c6eacd55195a7a55\"><p style=\"text-align:justify;\">Tour dan tiket masuk tempat wisata di Turki sesuai program</p></li><li data-list-item-id=\"e69a7a44eb21ee2b5b57d7c42eded93a1\"><p style=\"text-align:justify;\">Asuransi perjalanan (Usia diatas 69 Tahun ada penambahan biaya)</p></li><li data-list-item-id=\"e30f9a831027e43fc9baab54775002dfd\"><p style=\"text-align:justify;\">Didampingi Tour Leader dari Jakarta</p></li><li data-list-item-id=\"e44a705425d98f440ea62ede5a1a70f11\"><p style=\"text-align:justify;\">Professional Local Guide</p></li><li data-list-item-id=\"eb850a9b0b8f9e498378f79989d8d4ea2\"><p style=\"text-align:justify;\">Bosphorus Tour</p></li><li data-list-item-id=\"e7c5da65b1a37069f4b8a9e4c0315f5d5\"><p style=\"text-align:justify;\">Air mineral 500ml</p></li><li data-list-item-id=\"e64fc771c5dcb57693e2d62427ddb8a7f\"><p style=\"text-align:justify;\">2 botol per hari</p></li><li data-list-item-id=\"e14680507bc5aa0b4d66491d0702df20b\"><p style=\"text-align:justify;\">Komisi Agent IDR. 700.000,- per pax</p></li></ul>', '<ul><li data-list-item-id=\"e37e061ebf4ac81e9f498fc99bfd51cc3\"><p style=\"text-align:justify;\">Tipping Tour Leader: <strong>USD 3 x 10 Hari = USD 30 per orang</strong></p></li><li data-list-item-id=\"e607b68119dc32828ac29deac8d4cfb08\"><p style=\"text-align:justify;\">Tipping Guide &amp; Driver Turkiye: <strong>USD 7 x 7 Hari = USD 49 per orang</strong></p></li><li data-list-item-id=\"ee3ed3dfa825f824a495e36d837eae2da\"><p style=\"text-align:justify;\">Penambahan biaya Asuransi Perjalanan untuk usia diatas 69 - 75 Tahun IDR. 300.000 (untuk usia diatas 75 tahun harga berbeda dan harap konfirmasi ke kami)</p></li><li data-list-item-id=\"e8c776b980ed9d2a2b8f6698c2795ae09\"><p style=\"text-align:justify;\">Visa Turki apabila ada</p></li><li data-list-item-id=\"e4012eaf257dd7d7165d1bad47609bc8f\"><p style=\"text-align:justify;\">PCR di masing masing destinasi apabila ada</p></li><li data-list-item-id=\"ef413e07459a2de5384c164d8638803c9\"><p style=\"text-align:justify;\">Pengeluaran pribadi</p></li><li data-list-item-id=\"e7b4c504b612437c2bb047a72f7548d86\"><p style=\"text-align:justify;\">Tour opsional</p></li><li data-list-item-id=\"e7463e473d23066799a8a529875585a4a\"><p style=\"text-align:justify;\">Karantina mandiri (apabila ada)</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/Ab69YCyehDHBk5dLEShBkzi5e6yTqPjGjpTYqTbG.pdf', 0, NULL, '2026-04-28 07:50:25', '2026-04-29 03:00:20'),
(54, 26, '5D Exciting Sale Complete Guangdong', NULL, '5d-exciting-sale-complete-guangdong', '<p><strong>HONGKONG – SHENZHEN – GUANGZHOU – MACAU EXPLORER 🤩</strong></p><p>Nikmati perjalanan seru 5 hari menjelajahi empat destinasi terbaik di Asia: Hong Kong, Shenzhen, Guangzhou, dan Macau 🌏✨</p><p>Petualangan dimulai di Hong Kong dengan mengunjungi Victoria Peak untuk menikmati panorama kota dari ketinggian, dilanjutkan ke Avenue of Stars yang ikonik di tepi pelabuhan</p><p>Perjalanan berlanjut ke Shenzhen dan Guangzhou, dimana Anda akan merasakan perpaduan kota modern dan budaya lokal, termasuk kunjungan ke Huacheng Square dan taman kota yang indah</p><p>Eksplorasi semakin unik saat mengunjungi Fengjian Water Town, desa air tradisional dengan suasana klasik dan tenang seperti kembali ke masa lalu</p><p>Perjalanan dilanjutkan ke Macau, kota dengan nuansa Eropa yang khas. Anda akan mengunjungi Ruins of St. Paul\'s serta menikmati suasana mewah di The Venetian Macao yang megah</p><p>✧ Panorama kota dari Victoria Peak<br>✧ Ikon hiburan Avenue of Stars<br>✧ Desa air klasik Fengjian Water Town<br>✧ Landmark bersejarah St. Paul Ruins<br>✧ Shopping &amp; lifestyle di Venetian Macau</p><p>Perjalanan lengkap yang memadukan city tour modern, budaya tradisional, dan pengalaman wisata unik dalam satu liburan yang tak terlupakan ✨</p>', '<p><strong>HONG KONG – SHENZHEN – GUANGZHOU – MACAU EXPLORER 🤩</strong></p><p>Enjoy a 5-day journey exploring four iconic destinations in Asia: Hong Kong, Shenzhen, Guangzhou, and Macau 🌏✨</p><p>Start your adventure in Hong Kong with a visit to Victoria Peak for breathtaking skyline views, followed by the famous Avenue of Stars along the harbor</p><p>Continue to Shenzhen and Guangzhou, where modern city life meets rich culture, including visits to Huacheng Square</p><p>Experience the charm of Fengjian Water Town, a peaceful ancient water village</p><p>Then head to Macau to explore Ruins of St. Paul\'s and enjoy luxury shopping at The Venetian Macao</p><p>✧ Victoria Peak skyline<br>✧ Avenue of Stars<br>✧ Fengjian Water Town<br>✧ St. Paul’s Ruins<br>✧ Venetian Macau experience</p><p>A perfect mix of modern city, culture, and unique travel experiences ✨</p>', '<p><strong>홍콩 – 심천 – 광저우 – 마카오 여행 🤩</strong></p><p>홍콩, 심천, 광저우, 마카오까지 4개 도시를 5일 동안 여행하는 특별한 일정 🌏✨</p><p>Hong Kong에서 시작하여 Victoria Peak에서 멋진 전망을 감상하고, Avenue of Stars를 방문합니다</p><p>이후 Shenzhen과 Guangzhou로 이동하여 Huacheng Square 등 현대적인 도시를 체험합니다</p><p>전통적인 분위기의 Fengjian Water Town에서 여유로운 시간을 보내고</p><p>Macau에서 Ruins of St. Paul\'s과 The Venetian Macao를 방문합니다</p><p>✧ 빅토리아 피크 전망<br>✧ 스타의 거리<br>✧ 펑젠 수향 마을<br>✧ 성 바울 유적<br>✧ 베네시안 마카오</p><p>도시, 문화, 특별한 경험을 모두 담은 완벽한 여행 ✨</p>', '<p><strong>香港 – 深圳 – 广州 – 澳门之旅 🤩</strong></p><p>5天畅游亚洲四大城市：香港、深圳、广州、澳门 🌏✨</p><p>从 Hong Kong出发，登上 Victoria Peak欣赏壮丽城市景观，并游览 Avenue of Stars</p><p>前往 Shenzhen 和 Guangzhou，感受现代都市与文化融合，并参观 Huacheng Square</p><p>体验宁静古朴的 Fengjian Water Town水乡风情</p><p>随后前往 Macau，参观 Ruins of St. Paul\'s，并在 The Venetian Macao享受购物与娱乐</p><p>✧ 太平山顶美景<br>✧ 星光大道<br>✧ 逢简水乡<br>✧ 大三巴牌坊<br>✧ 威尼斯人体验</p><p>一次融合城市、文化与特色体验的精彩旅程 ✨</p>', 8990000.00, NULL, 5, 4, '[\"22 Juli 2026\",\"24 Juli 2026 \",\"25 Agustus 2026 \",\"27 Agustus 2026\",\"28 Agustus 2026 \",\"4 September 2026\",\"6 September 2026\",\"11 September 2026\",\"25 September 2026\",\"2 Oktober 2026\",\"9 Oktober 2026\",\"30 Oktober 2026\",\"01 November 2026\",\"4 November 2026\",\"20 November 2026\",\"27 November 2026\",\"5 Desember 2026\",\"12 Desember 2026\",\"16 Desember 2026\"]', NULL, '<p style=\"text-align:center;\"><i><strong>HIGHLIGHT: VICTORIA PEAK – AVENUE OF STAR – HUANGCHENG SQUARE –</strong></i> <i><strong>FENGJIAN WATER TOWN – ST PAUL RUIN – VENETIAN SHOPPING ARCADE</strong></i></p><p style=\"text-align:center;\"><i><strong>GUARANTEE BEST PRICE &amp; SERVICE&nbsp;</strong></i></p>', '<ul><li data-list-item-id=\"e5495729a761b7ff7988d072952742d25\"><p style=\"text-align:justify;\">Tiket International Jakarta - Hongkong &amp; Hongkong - Jakarta by <strong>Malaysia Airlines</strong>, Economy <strong>termasuk taxes internasional </strong>(Tiket Grup Fixed Date &amp; No Extend)&nbsp;</p></li><li data-list-item-id=\"ea7368bc0d0b843b7e47710c71075b8df\"><p style=\"text-align:justify;\">Bagasi 30kg atau sesuai dengan ketentuan Airlines&nbsp;</p></li><li data-list-item-id=\"eef069be474b1ca105a04de1ee78f2ba2\"><p style=\"text-align:justify;\">Akomodasi hotel *4 Lokal atau *3 setaraf (Twin / Triple)</p></li><li data-list-item-id=\"e0a3b608f9eeadcc29b1827a4bdf555e4\"><p style=\"text-align:justify;\">Transportasi bus Pariwisata &amp; tiket masuk objek wisata</p></li><li data-list-item-id=\"e6a9f84247704caaf1b571941d38c7631\"><p style=\"text-align:justify;\">Acara Tour &amp; makan sesuai program paket tour diatas</p></li><li data-list-item-id=\"e281257de61e42b027687a74e5c85ad85\"><p style=\"text-align:justify;\">Mineral Water 1 Botol Perhari</p></li><li data-list-item-id=\"eb1b9a8154023cc49d4ff18f54b07cae8\"><p style=\"text-align:justify;\">Tour Leader&nbsp;</p></li><li data-list-item-id=\"eefa7f66b64d4c534b46013613ee84e46\"><p style=\"text-align:justify;\">Group Visa 144 China (Jika dihapus atau ditangguhkan, maka harus melakukan applikasi visa China)&nbsp;</p></li><li data-list-item-id=\"e8dec5c344175b9fa7e3c431302f5ff6a\"><p style=\"text-align:justify;\">Travel Kits (Luggage Tag)</p></li><li data-list-item-id=\"e2f62efe8f98fa928e2f779aedb2bc354\"><p style=\"text-align:justify;\">Travel Insurance sampai usia 82 tahun</p></li></ul>', '<ul><li data-list-item-id=\"e52a18a844579c1ed306b7de0e3b3aff4\"><p style=\"text-align:justify;\">Tipping Tour Leader, Local Guide, Driver: <strong>Rp650.000/ Pax</strong></p></li><li data-list-item-id=\"eac9d41de1d67b33cb5e5ece3fa70f208\"><p style=\"text-align:justify;\">Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</p></li><li data-list-item-id=\"ee0949fa99b3119183d1fa06bb2c548bb\"><p style=\"text-align:justify;\">PCR Test / Rapid Test Antigen Jika dibutuhkan</p><p style=\"text-align:justify;\">OPTIONAL:</p><p style=\"text-align:justify;\">Rental Wifi/SIM CARD Portable</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/IpJUc5W3qt5KOWdzeLdS1LF5W9m4HlI1HaajbhMy.pdf', 0, NULL, '2026-04-28 08:29:44', '2026-04-28 08:34:05'),
(55, 21, 'Bangkok Ayutthaya Historical Park 4D3N', NULL, 'sic-bangkok-ayutthaya-historical-park-4d3n', '<p><strong>BANGKOK &amp; AYUTTHAYA DISCOVERY – 4D3N 🤩</strong></p><p>Nikmati liburan singkat namun penuh pengalaman di Thailand dengan menjelajahi kota modern Bangkok dan warisan sejarah Ayutthaya 🌏✨</p><p>Perjalanan dimulai di Bangkok, kota yang terkenal dengan perpaduan budaya tradisional dan kehidupan modern yang dinamis. Anda akan menikmati waktu santai setibanya di kota sebelum memulai petualangan seru keesokan harinya</p><p>Eksplorasi berlanjut ke Ayutthaya Historical Park, situs warisan dunia UNESCO yang menyimpan keindahan reruntuhan kerajaan kuno. Kunjungi kuil ikonik seperti Wat Mahathat dengan kepala Buddha di akar pohon, serta Wat Chaiwatthanaram yang megah</p><p>Kembali ke Bangkok, Anda akan mengunjungi landmark terkenal seperti Wat Arun yang indah di tepi sungai, serta menikmati pemandangan kota melalui Chao Phraya River sightseeing 🚤</p><p>Tak lengkap tanpa pengalaman belanja dan kuliner! Anda akan mengunjungi pusat belanja populer seperti Platinum Fashion Mall serta menikmati suasana malam di Jodd Fairs Night Market yang ramai dan penuh pilihan makanan lokal</p><p>✧ Eksplor Ayutthaya UNESCO Heritage<br>✧ Kuil ikonik Wat Arun<br>✧ River sightseeing Chao Phraya<br>✧ Shopping di Platinum Mall<br>✧ Kuliner malam di Jodd Fairs</p><p>Perpaduan sempurna antara sejarah, budaya, wisata kota, dan kuliner dalam satu perjalanan singkat yang berkesan ✨</p>', '<p><strong>BANGKOK &amp; AYUTTHAYA DISCOVERY – 4D3N 🤩</strong></p><p>Enjoy a short yet exciting getaway in Thailand by exploring the vibrant city of Bangkok and the historical wonders of Ayutthaya 🌏✨</p><p>Your journey begins in Bangkok, a dynamic city blending modern lifestyle with rich traditions. Enjoy leisure time upon arrival before continuing your adventure</p><p>Discover the UNESCO World Heritage site Ayutthaya Historical Park, featuring ancient ruins and iconic temples such as Wat Mahathat and Wat Chaiwatthanaram</p><p>Back in Bangkok, visit the famous Wat Arun and enjoy a scenic boat ride along the Chao Phraya River 🚤</p><p>Complete your trip with shopping at Platinum Fashion Mall and explore local street food at Jodd Fairs Night Market</p><p>✧ Ayutthaya UNESCO Heritage<br>✧ Wat Arun landmark<br>✧ Chao Phraya river cruise<br>✧ Platinum Mall shopping<br>✧ Jodd Fairs night market</p><p>A perfect blend of culture, history, and city lifestyle in one memorable trip ✨</p>', '<p><strong>방콕 &amp; 아유타야 여행 4일 3박 🤩</strong></p><p>태국의 대표 도시 Bangkok과 역사 도시 아유타야를 함께 즐기는 특별한 여행 🌏✨</p><p>방콕에서 여행이 시작되며, 현대적인 도시와 전통 문화가 어우러진 분위기를 경험할 수 있습니다</p><p>유네스코 세계문화유산인 Ayutthaya Historical Park를 방문하고 Wat Mahathat, Wat Chaiwatthanaram 등 유명 사원을 탐방합니다</p><p>방콕으로 돌아와 Wat Arun을 방문하고 차오프라야 강 보트 투어를 즐깁니다 🚤</p><p>또한 Platinum Fashion Mall에서 쇼핑하고 Jodd Fairs Night Market에서 다양한 길거리 음식을 즐길 수 있습니다</p><p>✧ 아유타야 유네스코 유적지<br>✧ 왓 아룬 사원<br>✧ 차오프라야 강 투어<br>✧ 플래티넘 쇼핑<br>✧ 야시장 체험</p><p>문화와 역사, 도시의 매력을 모두 담은 완벽한 여행 ✨</p>', '<p><strong>曼谷 &amp; 大城府 4天3晚之旅 🤩</strong></p><p>开启一段精彩的泰国之旅，探索充满活力的 Bangkok 和历史悠久的大城府 🌏✨</p><p>旅程从曼谷开始，这座城市融合了现代与传统文化</p><p>参观世界文化遗产 Ayutthaya Historical Park，游览著名寺庙 Wat Mahathat 和 Wat Chaiwatthanaram</p><p>返回曼谷后，参观 Wat Arun，并体验湄南河游船 🚤</p><p>最后在 Platinum Fashion Mall购物，并前往 Jodd Fairs Night Market品尝当地美食</p><p>✧ 大城府世界遗产<br>✧ 郑王庙<br>✧ 湄南河游船<br>✧ 白金商场购物<br>✧ 夜市美食体验</p><p>一次融合文化、历史与城市体验的完美旅程 ✨</p>', 2750000.00, NULL, 4, 1, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlights: <strong>Buddha In The Tree, Wat Chai Wattanaram, Wat Arun, Jodd Fairs</strong></p><p>&nbsp;</p>', '<ul><li data-list-item-id=\"e5a35d3446bb684d3de40b4e65f39b39c\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"e1ac26e1e764ccf45b2f56b609682501e\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"eb005981790a8d0baa54f179647967184\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"e7358d6759de97708f1349b44a2594df7\"><p>ALL MENTIONED TOURS AND MEALS ON THE ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"ec3bb68850b9007cea4d4925fc7fc3727\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e93afe873dfc793b810d34a672fba7ff7\"><p>INDONESIAN SPEAKING GUIDE</p><p>&nbsp;</p></li><li data-list-item-id=\"e64845aec09acdfb705ea23128a5a07f0\">VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e6a73170146bc284af93c819f93627d34\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD20/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e52aa70b696f7cb62abc3557906f74d4d\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD12/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"edd595db9adb9fca687e4d04b4607ac36\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"edbdd6d55199c7eb046dd5c18bfd5d981\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"eeeb3e54da34af472a932eeab52f47e64\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/TN6cqA3ZoGoq2lzlgZvhosaMm2RWAF7NbJUQvyYg.pdf', 0, NULL, '2026-04-29 02:56:00', '2026-04-29 04:05:42'),
(56, 21, 'Bangkok Dream World Snow Town 4D3N', NULL, 'bangkok-dream-world-snow-town-4d3n', '<p><strong>BANGKOK FUN &amp; DREAM WORLD – 4D3N 🤩</strong></p><p>Nikmati liburan seru di Bangkok dengan perpaduan wisata hiburan, budaya, dan belanja dalam 4 hari yang menyenangkan 🌏✨</p><p>Perjalanan dimulai dengan waktu santai setibanya di Bangkok, sebelum keesokan harinya Anda akan diajak merasakan keseruan di Dream World 🎢 taman hiburan populer dengan berbagai wahana seru seperti Fantasy Land, Adventure Land, hingga Snow Town yang menghadirkan suasana musim dingin di tengah kota tropis</p><p>Petualangan berlanjut dengan city tour mengunjungi Wat Arun, salah satu kuil paling ikonik di Thailand yang terletak di tepi Sungai Chao Phraya. Anda juga akan menikmati river sightseeing dengan boat menyusuri sungai yang membelah kota 🚤</p><p>Lengkapi pengalaman dengan berbelanja di MBK Center dan Platinum Fashion Mall, serta menikmati suasana malam dan kuliner khas di Jodd Fairs Night Market 🌙</p><p>✧ Serunya wahana Dream World<br>✧ Ikon budaya Wat Arun<br>✧ River sightseeing Chao Phraya<br>✧ Shopping di MBK &amp; Platinum Mall<br>✧ Kuliner malam Jodd Fairs</p><p>Perpaduan sempurna antara hiburan, budaya, dan lifestyle dalam satu liburan singkat yang seru dan berkesan ✨</p>', '<p><strong>BANGKOK FUN &amp; DREAM WORLD – 4D3N 🤩</strong></p><p>Enjoy a fun-filled holiday in Bangkok combining entertainment, culture, and shopping in one exciting 4-day trip 🌏✨</p><p>Your journey begins with leisure time upon arrival, followed by a full day of excitement at Dream World 🎢 a popular theme park featuring Fantasy Land, Adventure Land, and Snow Town, bringing a winter experience to a tropical city</p><p>Continue with a city tour visiting Wat Arun, one of Thailand’s most iconic temples located along the Chao Phraya River. Enjoy a scenic river sightseeing boat ride 🚤</p><p>Complete your trip with shopping at MBK Center and Platinum Fashion Mall, and experience local food and nightlife at Jodd Fairs Night Market 🌙</p><p>✧ Exciting Dream World rides<br>✧ Iconic Wat Arun temple<br>✧ Chao Phraya river sightseeing<br>✧ Shopping at MBK &amp; Platinum Mall<br>✧ Jodd Fairs night market</p><p>A perfect mix of fun, culture, and lifestyle in one memorable trip ✨</p>', '<p><strong>방콕 드림월드 4일 3박 여행 🤩</strong></p><p>Bangkok에서 즐기는 재미, 문화, 쇼핑이 어우러진 4일간의 여행 🌏✨</p><p>도착 후 자유 시간을 보낸 뒤, Dream World 🎢에서 다양한 놀이기구와 Snow Town을 즐길 수 있습니다</p><p>이후 시티 투어로 Wat Arun을 방문하고 차오프라야 강 보트 투어를 즐깁니다 🚤</p><p>또한 MBK Center, Platinum Fashion Mall에서 쇼핑을 하고 Jodd Fairs Night Market에서 야시장 음식을 즐길 수 있습니다 🌙</p><p>✧ 드림월드 놀이공원<br>✧ 왓 아룬 사원<br>✧ 강 보트 투어<br>✧ 쇼핑 체험<br>✧ 야시장</p><p>즐거움과 문화, 쇼핑을 모두 경험할 수 있는 완벽한 여행 ✨</p>', '<p><strong>曼谷梦幻世界 4天3晚之旅 🤩</strong></p><p>在 Bangkok体验集娱乐、文化与购物于一体的精彩旅程 🌏✨</p><p>抵达后自由活动，随后前往 Dream World 🎢，体验各种游乐设施与雪城乐园</p><p>城市观光将带您参观 Wat Arun，并乘船游览湄南河 🚤</p><p>同时前往 MBK Center 和 Platinum Fashion Mall购物，并在 Jodd Fairs Night Market体验地道美食 🌙</p><p>✧ 梦幻世界乐园<br>✧ 郑王庙<br>✧ 湄南河游船<br>✧ 购物体验<br>✧ 夜市美食</p><p>一段融合娱乐、文化与生活方式的完美旅程 ✨</p>', 2800000.00, NULL, 4, 3, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Dream World Happy Land, Wat Arun, Platinum Mall, Asiatique</strong></p>', '<ul><li data-list-item-id=\"ef13270fbe91eefebf578decf8ade8982\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"e3eed89718094a7f8a0863981075146e4\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"ee43d93b292a81669d502e4518fbcedb2\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"ebd4f304ff1743c864f9d4989f0ea8d88\"><p>ALL MENTIONED TOURS AND MEALS ON THE ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"ef4d82d1d2aa1f996c56f7ff1aad54c27\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"eec4a60ed3d18c8d426829f3fc162d705\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"ead2f05de08d1931f1764869c3507a0c9\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD20/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"eeaf37f9844181c1222d2fc0aab0b93a3\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD12/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e9f07633d802a2da9eee1f86c95391570\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e5629aaea25a8fd6eb5e69f1706ed12bd\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e7ce5b8bfcb65bad949f0966525e6f077\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/HGaZmxbzroYppCqcD6FQOFleQkA2ZquRl2AXhlp8.pdf', 0, NULL, '2026-04-29 03:39:17', '2026-04-29 04:05:05'),
(57, 21, 'Bangkok Kanchanaburi G Safari Park 4D3N', NULL, 'bangkok-kanchanaburi-g-safari-park-4d3n', '<p><strong>BANGKOK – KANCHANABURI EXPERIENCE 4D3N 🤩</strong></p><p>Nikmati perjalanan seru menjelajahi keindahan Bangkok dan Kanchanaburi dalam paket 4 hari yang memadukan wisata alam, sejarah, budaya, dan hiburan 🌏✨</p><p>Perjalanan dimulai dengan kedatangan di Bangkok dan waktu istirahat di hotel untuk mempersiapkan petualangan seru di hari berikutnya.</p><p>Hari kedua membawa Anda menuju Kanchanaburi, destinasi yang terkenal dengan sejarah dan pemandangan alamnya. Nikmati pengalaman berjalan di Kanchanaburi Skywalk dengan panorama sungai yang menakjubkan, serta mengunjungi jalur bersejarah Death Railway. Perjalanan dilanjutkan dengan naik kereta menuju Tham Krasae Bridgeyang menawarkan pemandangan tebing dan sungai yang dramatis. Anda juga akan menikmati pengalaman unik di Kanchanaburi Safari Park dengan pertunjukan gajah dan interaksi langsung bersama jerapah 🦒</p><p>Hari ketiga diisi dengan city tour Bangkok yang tak kalah menarik. Kunjungi Wat Arun, ikon kota yang megah di tepi sungai, serta nikmati wisata perahu di Chao Phraya River 🚤. Perjalanan dilengkapi dengan kunjungan ke pusat perbelanjaan populer seperti Platinum Fashion Mall, serta pengalaman wisata belanja dan kuliner khas lokal. Malam hari Anda juga dapat memilih menikmati pertunjukan spektakuler di Asiatique The Riverfront 🌙</p><p>Hari terakhir memberikan waktu bebas sebelum kembali ke bandara, menutup perjalanan dengan kenangan indah di Thailand.</p><p>✧ Wisata alam &amp; sejarah Kanchanaburi<br>✧ Pengalaman naik kereta Death Railway<br>✧ Interaksi satwa di Safari Park<br>✧ City tour Bangkok &amp; Wat Arun<br>✧ Shopping &amp; night market experience</p><p>Perjalanan lengkap yang menghadirkan kombinasi petualangan, budaya, dan hiburan dalam satu paket liburan yang berkesan ✨</p>', '<p><strong>BANGKOK – KANCHANABURI EXPERIENCE 4D3N 🤩</strong></p><p>Enjoy an exciting journey exploring Bangkok and Kanchanaburi in a 4-day trip combining nature, history, culture, and entertainment 🌏✨</p><p>Your trip begins with arrival in Bangkok and free time to relax at the hotel.</p><p>On Day 2, travel to Kanchanaburi and experience the stunning views from Kanchanaburi Skywalk. Visit the historic Death Railway and enjoy a scenic train ride to Tham Krasae Bridge. Continue with a fun visit to Kanchanaburi Safari Park where you can watch an elephant show and interact with giraffes 🦒</p><p>Day 3 features a Bangkok city tour, including a visit to Wat Arun and a sightseeing boat ride along the Chao Phraya River🚤. Enjoy shopping at Platinum Fashion Mall and explore local lifestyle experiences. In the evening, you may optionally enjoy a show at Asiatique The Riverfront 🌙</p><p>Day 4 offers free time before your transfer to the airport.</p><p>✧ Nature &amp; history in Kanchanaburi<br>✧ Scenic train ride on Death Railway<br>✧ Wildlife experience at Safari Park<br>✧ Bangkok city tour &amp; Wat Arun<br>✧ Shopping &amp; night market experience</p><p>A complete travel experience blending adventure, culture, and leisure ✨</p>', '<p><strong>방콕 &amp; 칸차나부리 4일 3박 여행 🤩</strong></p><p>Bangkok과 Kanchanaburi를 함께 즐기는 4일간의 여행으로 자연, 역사, 문화, 엔터테인먼트를 모두 경험할 수 있습니다 🌏✨</p><p>첫날은 방콕 도착 후 호텔에서 자유 시간을 보냅니다.</p><p>둘째 날에는 칸차나부리로 이동하여 Kanchanaburi Skywalk에서 아름다운 전망을 감상하고, 역사적인 Death Railway를 방문합니다. 또한 기차를 타고 Tham Krasae Bridge까지 이동하며 멋진 풍경을 즐길 수 있습니다. 이후 Kanchanaburi Safari Park에서 코끼리 쇼와 기린 먹이 주기 체험을 즐깁니다 🦒</p><p>셋째 날에는 방콕 시티 투어로 Wat Arun을 방문하고 Chao Phraya River에서 보트 투어를 즐깁니다 🚤. Platinum Fashion Mall에서 쇼핑을 하고, 저녁에는 Asiatique The Riverfront에서 선택 관광을 즐길 수 있습니다 🌙</p><p>마지막 날은 자유 시간 후 공항으로 이동합니다.</p><p>✧ 자연과 역사 여행<br>✧ 죽음의 철도 기차 체험<br>✧ 사파리 파크 동물 체험<br>✧ 방콕 시티 투어<br>✧ 쇼핑 및 야시장</p><p>다양한 매력을 한 번에 즐길 수 있는 완벽한 여행 ✨</p>', '<p><strong>曼谷 &amp; 北碧府 4天3晚之旅 🤩</strong></p><p>畅游 Bangkok 和 Kanchanaburi，体验融合自然、历史、文化与娱乐的精彩旅程 🌏✨</p><p>第一天抵达曼谷后自由活动并入住酒店休息。</p><p>第二天前往北碧府，参观 Kanchanaburi Skywalk，欣赏壮丽景色，并参观历史悠久的 Death Railway。随后搭乘火车前往 Tham Krasae Bridge，感受沿途美景。接着前往 Kanchanaburi Safari Park，与长颈鹿互动并观看大象表演 🦒</p><p>第三天进行曼谷市区观光，参观 Wat Arun，并乘船游览 Chao Phraya River 🚤。之后前往 Platinum Fashion Mall购物，晚上可选择在 Asiatique The Riverfront体验夜市与表演 🌙</p><p>第四天自由活动后送往机场，结束愉快旅程。</p><p>✧ 自然与历史体验<br>✧ 死亡铁路火车之旅<br>✧ 野生动物互动体验<br>✧ 曼谷城市观光<br>✧ 购物与夜市</p><p>一段融合多种体验的精彩旅程 ✨</p>', 2950000.00, NULL, 4, 3, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Safari Park, Tham Krasae Bridge, Wat Arun, Jodd Fairs</strong></p>', '<ul><li data-list-item-id=\"e5599d23a7daa5f328887b1662c2738c3\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"ed4c7bd07c55e1185a012628f514aad92\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"e3129d4c56ee2746ea0c7f40b85a109e6\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e2ca7aee28ab1c13e526f401de08e3664\"><p>ALL MENTIONED TOURS AND MEALS ON THE ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e98fc8f34874986c30556677aa3dd803f\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eefa800141eeecb56d491e659118796f3\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"ec84902637118e42ae14d0489de639149\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD20/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e685628610dfc3bfa0d3f571bc93b9223\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP</p><p><strong>&nbsp;USD12/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ec7a1497dde5b5750ef40dcfe043275be\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4152a821887920d94d8f903404871a4f\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4b2a8b3284a2ce27c58a1e0e13662d18\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/kzeaxy1SW8Elvofi9iBkxslp0lfgSaha8dyl0otl.pdf', 0, NULL, '2026-04-29 06:03:37', '2026-04-29 06:38:48');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(58, 21, 'Bangkok Safari Marine Park Spy War Show', NULL, 'bangkok-safari-marine-park-spy-war-show', '<p><strong>BANGKOK SAFARI &amp; CITY EXPERIENCE 4D3N 🤩</strong></p><p>Nikmati liburan seru di Bangkok dengan kombinasi wisata hiburan, edukasi, budaya, dan belanja dalam paket perjalanan 4 hari yang penuh pengalaman menarik 🌏✨</p><p>Perjalanan dimulai dengan kedatangan di Bangkok dan waktu istirahat di hotel untuk bersantai sebelum memulai petualangan.</p><p>Hari kedua menghadirkan pengalaman tak terlupakan di Safari World, yang terdiri dari Safari Park dan Marine Park. Saksikan berbagai pertunjukan seru seperti Spy War Show dan Cowboy Show, serta nikmati interaksi langsung dengan satwa dan edukasi tentang kehidupan hewan 🦁🐬. Setelah itu, Anda akan mengunjungi MBK Center dan berjalan santai di kawasan Siam Square. Malam hari diisi dengan pengalaman kuliner dan suasana meriah di Jodd Fairs Night Market 🌙</p><p>Hari ketiga dilanjutkan dengan city tour Bangkok. Anda akan mengunjungi Wat Arun, salah satu ikon kota yang megah, serta menikmati wisata perahu di Chao Phraya River 🚤. Perjalanan juga mencakup kunjungan ke pusat perbelanjaan populer seperti Platinum Fashion Mall, serta kesempatan menikmati hiburan malam opsional di Asiatique The Riverfront</p><p>Hari terakhir memberikan waktu bebas sebelum transfer ke bandara, menutup perjalanan dengan kenangan indah di Bangkok.</p><p>✧ Wisata edukasi &amp; hiburan di Safari World<br>✧ Pertunjukan satwa &amp; interaksi langsung<br>✧ City tour &amp; Wat Arun<br>✧ Wisata sungai Chao Phraya<br>✧ Shopping &amp; night market experience</p><p>Perjalanan lengkap yang memadukan keseruan, budaya, dan gaya hidup kota modern dalam satu liburan yang berkesan ✨</p>', '<p><strong>BANGKOK SAFARI &amp; CITY EXPERIENCE 4D3N 🤩</strong></p><p>Enjoy an exciting holiday in Bangkok combining entertainment, education, culture, and shopping in a 4-day unforgettable journey 🌏✨</p><p>Your trip begins with arrival in Bangkok and free time to relax at the hotel.</p><p>On Day 2, experience a fun adventure at Safari World, including Safari Park and Marine Park. Watch exciting shows such as Spy War Show and Cowboy Show, and enjoy interactive experiences while learning about animals 🦁🐬. Continue your day with shopping at MBK Center and a walk around Siam Square. In the evening, explore local food and nightlife at Jodd Fairs Night Market 🌙</p><p>Day 3 features a Bangkok city tour, visiting Wat Arun and enjoying a sightseeing boat ride along the Chao Phraya River🚤. Continue with shopping at Platinum Fashion Mall and optional entertainment at Asiatique The Riverfront</p><p>Day 4 is free time before transfer to the airport.</p><p>✧ Safari World adventure<br>✧ Animal shows &amp; interaction<br>✧ Bangkok city tour &amp; Wat Arun<br>✧ Chao Phraya river cruise<br>✧ Shopping &amp; night market experience</p><p>A perfect mix of fun, culture, and lifestyle in one memorable trip ✨</p>', '<p><strong>방콕 사파리 &amp; 시티 투어 4일 3박 🤩</strong></p><p>Bangkok에서 즐기는 엔터테인먼트, 교육, 문화, 쇼핑이 어우러진 4일간의 여행 🌏✨</p><p>첫날은 방콕 도착 후 호텔에서 자유 시간을 보냅니다.</p><p>둘째 날에는 Safari World를 방문하여 Safari Park와 Marine Park를 체험합니다. Spy War Show, Cowboy Show 등 다양한 공연을 관람하고 동물들과의 교감 체험을 즐길 수 있습니다 🦁🐬. 이후 MBK Center와 Siam Square에서 쇼핑 및 자유 시간을 즐기고, 저녁에는 Jodd Fairs Night Market에서 야시장을 경험합니다 🌙</p><p>셋째 날에는 방콕 시티 투어로 Wat Arun을 방문하고 Chao Phraya River에서 보트 투어를 즐깁니다 🚤. 이후 Platinum Fashion Mall 쇼핑 및 Asiatique The Riverfront에서 선택 관광이 가능합니다</p><p>마지막 날은 자유 시간 후 공항으로 이동합니다.</p><p>✧ 사파리 월드 체험<br>✧ 동물 쇼 및 체험<br>✧ 방콕 시티 투어<br>✧ 강 보트 투어<br>✧ 쇼핑 &amp; 야시장</p><p>즐거움과 문화가 어우러진 완벽한 여행 ✨</p>', '<p><strong>曼谷野生动物园 &amp; 城市之旅 4天3晚 🤩</strong></p><p>在 Bangkok体验融合娱乐、教育、文化与购物的精彩旅程 🌏✨</p><p>第一天抵达曼谷后自由活动并入住酒店。</p><p>第二天前往 Safari World，参观野生动物园和海洋公园。观看精彩表演（如特工大战、牛仔秀），并体验与动物互动 🦁🐬。随后前往 MBK Center和 Siam Square购物，晚上在 Jodd Fairs Night Market享受美食与夜市氛围 🌙</p><p>第三天进行城市观光，参观 Wat Arun，并乘船游览 Chao Phraya River 🚤。随后前往 Platinum Fashion Mall购物，并可选择在 Asiatique The Riverfront体验夜市与表演</p><p>第四天自由活动后送往机场，结束愉快旅程。</p><p>✧ 野生动物园体验<br>✧ 动物表演与互动<br>✧ 曼谷城市观光<br>✧ 湄南河游船<br>✧ 购物与夜市</p><p>一段充满乐趣与文化体验的完美旅程 ✨</p>', 2800000.00, NULL, 4, 3, '[]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Safari Marine Park, Spy War Show, Cowboy Show, Wat Arun, Platinum Mall, Asiatique</strong></p>', '<ul><li data-list-item-id=\"e5f5606937874b05e5f39f61577fb64ab\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"e678af50297367ac2a5dfc33b7d48ca98\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"e84c3d8448f51aba188e93a9a5d07d63a\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"e2ea6c79fbf03ccaecd783d011e938706\"><p>ALL MENTIONED TOURS AND MEALS ON THE ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"ee408f987e0c94c47ece92c864a862ae4\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e5eec5996af277e947cb6d56b7a441140\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e4abea1c2f180e0c371e7d981e9aafd48\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD20/PAX)</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e94da307b1206caa2388fe97985a6c5e5\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP (<strong>USD12/PAX)</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e4556f63756958b2c997cc85442e59afb\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ef8c4fa37c2fcfcada8d296b64ae87d6e\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e3c04a3b0787cdc7890f9dc1374c9c1c6\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/kpE9HQfqQSTTozw5A7A5uSEqEJ514QhK7kwvzIUh.pdf', 0, NULL, '2026-04-29 06:49:54', '2026-04-29 06:54:28'),
(59, 21, 'Bangkok City Tour 3D2N', NULL, 'bangkok-city-tour-3d2n', '<p><strong>BANGKOK CITY EXPERIENCE 3D2N 🤩</strong></p><p>Nikmati liburan singkat namun berkesan di Bangkok dengan perpaduan wisata budaya, kuliner, dan belanja dalam perjalanan 3 hari yang praktis dan menyenangkan 🌏✨</p><p>Perjalanan dimulai dengan penjemputan di bandara dan transfer menuju hotel untuk beristirahat.</p><p>Hari kedua menghadirkan city tour Bangkok yang penuh pengalaman menarik. Anda akan mengunjungi Wat Arun, salah satu ikon paling terkenal di Thailand yang terletak di tepi sungai. Perjalanan dilanjutkan dengan menikmati wisata perahu di Chao Phraya River 🚤 sambil menikmati panorama kota dari sudut yang berbeda.</p><p>Selain itu, Anda juga akan mengunjungi berbagai tempat menarik seperti pusat oleh-oleh lokal, Honey Bee Farm, serta Gems Gallery. Untuk pengalaman belanja, Anda akan diajak ke Platinum Fashion Mall yang terkenal dengan berbagai pilihan fashion dengan harga terjangkau. Malam hari diisi dengan suasana santai dan hiburan di Asiatique The Riverfront🌙</p><p>Hari terakhir memberikan waktu bebas sebelum transfer ke bandara, menutup perjalanan singkat Anda dengan kenangan indah di Bangkok.</p><p>✧ City tour Bangkok lengkap<br>✧ Kunjungan ke Wat Arun<br>✧ Wisata perahu Chao Phraya<br>✧ Shopping di Platinum Mall<br>✧ Night market Asiatique</p><p>Pilihan tepat untuk liburan singkat yang tetap lengkap dan berkesan ✨</p>', '<p><strong>BANGKOK CITY EXPERIENCE 3D2N 🤩</strong></p><p>Enjoy a short yet memorable getaway in Bangkok with a perfect combination of culture, cuisine, and shopping in a 3-day trip 🌏✨</p><p>Your journey begins with airport pick-up and transfer to the hotel for rest.</p><p>On Day 2, enjoy a Bangkok city tour by visiting the iconic Wat Arun, one of Thailand’s most famous landmarks located along the river. Continue with a sightseeing boat ride along the Chao Phraya River 🚤, offering a unique view of the city.</p><p>You will also visit local specialty shops, Honey Bee Farm, and Gems Gallery. For shopping lovers, explore Platinum Fashion Mall with a wide range of affordable fashion items. In the evening, enjoy the vibrant atmosphere at Asiatique The Riverfront 🌙</p><p>Day 3 is free time before your transfer to the airport.</p><p>✧ Bangkok city tour<br>✧ Visit Wat Arun<br>✧ Chao Phraya river cruise<br>✧ Shopping at Platinum Mall<br>✧ Asiatique night market</p><p>A perfect short escape filled with culture, fun, and lifestyle ✨</p>', '<p><strong>방콕 시티 투어 3일 2박 🤩</strong></p><p>Bangkok에서 문화, 음식, 쇼핑을 모두 즐길 수 있는 짧고 알찬 여행 🌏✨</p><p>첫날은 공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>둘째 날에는 방콕 시티 투어로 Wat Arun을 방문하고 Chao Phraya River에서 보트 투어를 즐깁니다 🚤</p><p>또한 특산품 매장, Honey Bee Farm, Gems Gallery를 방문하며, Platinum Fashion Mall에서 쇼핑을 즐길 수 있습니다. 저녁에는 Asiatique The Riverfront에서 야시장 분위기를 만끽합니다 🌙</p><p>마지막 날은 자유 시간 후 공항으로 이동합니다.</p><p>✧ 방콕 시티 투어<br>✧ 왓 아룬 방문<br>✧ 강 보트 투어<br>✧ 쇼핑<br>✧ 야시장</p><p>짧지만 알찬 완벽한 여행 ✨</p>', '<p><strong>曼谷城市之旅 3天2晚 🤩</strong></p><p>在 Bangkok享受融合文化、美食与购物的精彩短途旅行 🌏✨</p><p>第一天抵达后接机并入住酒店休息。</p><p>第二天进行城市观光，参观著名的 Wat Arun，并乘船游览 Chao Phraya River 🚤</p><p>此外还将参观特产店、Honey Bee Farm、Gems Gallery，并前往 Platinum Fashion Mall购物。晚上可在 Asiatique The Riverfront体验夜市氛围 🌙</p><p>第三天自由活动后送往机场，结束旅程。</p><p>✧ 曼谷城市观光<br>✧ 郑王庙参观<br>✧ 湄南河游船<br>✧ 购物体验<br>✧ 夜市</p><p>一次短暂却精彩的完美旅程 ✨</p>', 1300000.00, NULL, 3, 2, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Wat Arun, Icon Siam, Asiatique, Chaophraya Tourist Boat</strong></p>', '<ul><li data-list-item-id=\"e69e2c7238fdc09df80b2245958a91527\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"e1ff9c7e49f5230b10e5431d3535a7c1a\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"e6893ead56fa37739d32b254518d3a57f\"><p>HOTEL WITH BREAKFAST 2 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"ed7a9e8dfbe25d44cbbd97d5e155c156d\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"ef3c78ce686ee1f6c24318ce61c4546b6\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e97f37752b4369547ed11347cd586da1a\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e1adcdbd36466df7456f7fbb88c05fc1e\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD15/PAX)</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"eead49bfb9e70a6121b6ee7938de4ceeb\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP (<strong>USD9/PAX)</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e5e0674f22b95deaa5a419239eda36450\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"eb24295baa8738490ed81fe911b07bfa8\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed84f29633f2eb2733e2999bab21d38e2\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/TOdioay4IWL8q6X5nw2bRWx6jMCb0F656yQkP281.pdf', 0, NULL, '2026-04-29 07:17:56', '2026-04-29 07:21:38'),
(60, 21, 'Bangkok Damnoen Dinner Cruise 4D3N', NULL, 'bangkok-damnoen-dinner-cruise-4d3n', '<p><strong>BANGKOK FLOATING MARKET &amp; CITY EXPERIENCE 4D3N 🤩</strong></p><p>Nikmati liburan lengkap di Bangkok dengan kombinasi wisata budaya, pasar tradisional unik, kuliner, dan hiburan modern dalam perjalanan 4 hari yang seru dan berkesan 🌏✨</p><p>Perjalanan dimulai dengan kedatangan di Bangkok dan transfer menuju hotel untuk beristirahat.</p><p>Hari kedua membawa Anda menjelajahi pasar tradisional yang ikonik di Thailand. Kunjungi Damnoen Saduak Floating Market dan nikmati pengalaman naik perahu menyusuri kanal selama 45–60 menit 🚤. Lanjutkan ke Maeklong Railway Market, pasar unik yang berada di atas rel kereta api. Setelah kembali ke Bangkok, kunjungi ICONSIAM dan area Sook Siam, sebelum menikmati makan malam romantis di kapal pesiar di Chao Phraya River 🌙</p><p>Hari ketiga diisi dengan city tour Bangkok yang tak kalah menarik. Anda akan mengunjungi Wat Arun, ikon kota yang megah, serta menikmati wisata perahu di sungai Chao Phraya 🚤. Perjalanan dilengkapi dengan kunjungan ke Honey Bee Farm, Gems Gallery, serta pengalaman belanja di Platinum Fashion Mall. Malam hari semakin meriah dengan pertunjukan gratis di Asiatique The Riverfront 🎭</p><p>Hari terakhir memberikan waktu bebas sebelum transfer ke bandara, menutup perjalanan dengan kenangan indah di Thailand.</p><p>✧ Floating market &amp; railway market unik<br>✧ Boat canal tour &amp; dinner cruise<br>✧ City tour &amp; Wat Arun<br>✧ Shopping di ICONSIAM &amp; Platinum Mall<br>✧ Night market &amp; cabaret show</p><p>Perjalanan lengkap yang menggabungkan tradisi, modernitas, dan hiburan dalam satu paket liburan yang tak terlupakan ✨</p>', '<p><strong>BANGKOK FLOATING MARKET &amp; CITY EXPERIENCE 4D3N 🤩</strong></p><p>Enjoy a complete holiday in Bangkok combining culture, unique traditional markets, cuisine, and modern entertainment in a 4-day unforgettable journey 🌏✨</p><p>Your trip begins with arrival in Bangkok and transfer to the hotel for rest.</p><p>On Day 2, explore Thailand’s iconic markets. Visit Damnoen Saduak Floating Market and enjoy a canal boat ride for 45–60 minutes 🚤. Continue to Maeklong Railway Market, a unique market located on railway tracks. Back in Bangkok, visit ICONSIAM and Sook Siam, followed by a dinner cruise along the Chao Phraya River 🌙</p><p>Day 3 features a Bangkok city tour, including a visit to Wat Arun and a sightseeing boat ride along the Chao Phraya River 🚤. Continue to Honey Bee Farm, Gems Gallery, and shopping at Platinum Fashion Mall. In the evening, enjoy a free show at Asiatique The Riverfront 🎭</p><p>Day 4 is free time before transfer to the airport.</p><p>✧ Floating &amp; railway market experience<br>✧ Canal boat tour &amp; dinner cruise<br>✧ Bangkok city tour &amp; Wat Arun<br>✧ Shopping at ICONSIAM &amp; Platinum Mall<br>✧ Night market &amp; cabaret show</p><p>A complete journey blending tradition, modern lifestyle, and entertainment ✨</p>', '<p><strong>방콕 수상시장 &amp; 시티 투어 4일 3박 🤩</strong></p><p>Bangkok에서 전통 시장, 문화, 미식, 현대적인 즐길 거리를 모두 경험할 수 있는 4일간의 여행 🌏✨</p><p>첫날은 방콕 도착 후 호텔로 이동하여 휴식을 취합니다.</p><p>둘째 날에는 Damnoen Saduak Floating Market에서 보트를 타고 수상시장을 체험하고 🚤, Maeklong Railway Market을 방문합니다. 이후 ICONSIAM과 Sook Siam에서 쇼핑을 즐기고, Chao Phraya River에서 디너 크루즈를 즐깁니다 🌙</p><p>셋째 날에는 Wat Arun 방문과 보트 투어를 포함한 시티 투어를 진행합니다 🚤. 이후 Honey Bee Farm, Gems Gallery, Platinum Fashion Mall 쇼핑을 즐기고, 저녁에는 Asiatique The Riverfront에서 공연을 관람합니다 🎭</p><p>마지막 날은 자유 시간 후 공항으로 이동합니다.</p><p>✧ 수상시장 &amp; 기차시장 체험<br>✧ 보트 투어 &amp; 디너 크루즈<br>✧ 방콕 시티 투어<br>✧ 쇼핑<br>✧ 야시장 &amp; 공연</p><p>전통과 현대를 모두 즐길 수 있는 완벽한 여행 ✨</p>', '<p><strong>曼谷水上市场 &amp; 城市之旅 4天3晚 🤩</strong></p><p>在 Bangkok体验融合传统市场、文化、美食与现代娱乐的精彩旅程 🌏✨</p><p>第一天抵达曼谷后入住酒店休息。</p><p>第二天前往 Damnoen Saduak Floating Market体验水上市场并乘船游览 🚤，随后参观 Maeklong Railway Market。返回曼谷后前往 ICONSIAM和 Sook Siam购物，并在 Chao Phraya River享用游船晚餐 🌙</p><p>第三天进行城市观光，参观 Wat Arun并乘船游览湄南河 🚤。随后参观 Honey Bee Farm、Gems Gallery，并前往 Platinum Fashion Mall购物。晚上在 Asiatique The Riverfront观看表演 🎭</p><p>第四天自由活动后送往机场，结束愉快旅程。</p><p>✧ 水上市场与铁路市场体验<br>✧ 运河游船与晚餐游船<br>✧ 曼谷城市观光<br>✧ 购物体验<br>✧ 夜市与表演</p><p>一次融合传统与现代的精彩旅程 ✨</p>', 2250000.00, NULL, 4, 3, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Cabaret Show, Dinner Cruise, Maeklong Railway Market, Boat Damnoen Saduak</strong></p>', '<ul><li data-list-item-id=\"edc8c0fb4c35eafe33af332a2e894b989\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eca4690907056589008201c72c6436cf3\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e567b913f538031f8b91b1de13e94dc9f\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ea1bb2c92609a256330bfa10aa3b57d1f\"><p>ALL MENTIONED TOURS AND MEALS ON THE ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e15d24658c00a55d21e896945f961d3b1\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e9d31c292a86e4fd00d1326dfa20e9cf9\"><p>INDONESIAN SPEAKING GUIDE</p><p>&nbsp;</p></li><li data-list-item-id=\"e2c654399c790a3327aa52884d1eca1e7\">VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e656423b95fc027064f3d7e4ef8f549d9\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD20/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e18ddb35ac847f5ec1e7e82fc95b978f2\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD12/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e3a3557252908027a0358009625cff7eb\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e23b56789e0c3d66c839e9228e95537e9\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0b4d099cbd13f08c05295177c653d57e\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/rT9R776xrbRDSs6KT5cgSh2dULP15AblTIYQ6LPD.pdf', 0, NULL, '2026-04-29 07:54:13', '2026-04-29 08:02:07'),
(61, 21, 'Bangkok Pattaya Dinosaurus Park 4D3N', NULL, 'bangkok-pattaya-dinosaurus-park-4d3n', '<p><strong>SIC 2 CAN GO! BANGKOK – PATTAYA 4D3N 🤩</strong></p><p>Nikmati liburan seru ke Bangkok dan Pattaya dengan kombinasi wisata budaya, hiburan, belanja, dan pantai dalam satu paket lengkap selama 4 hari 3 malam 🌏✨</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok dan transfer ke hotel untuk beristirahat.</p><p>Hari kedua, perjalanan menuju Pattaya dengan berbagai destinasi menarik. Kunjungi Honey Bee Farm, lalu berfoto di Great and Grand Sweet Destination yang penuh warna dan spot Instagramable. Lanjutkan wisata ke Nong Nooch Tropical Garden untuk menikmati pertunjukan budaya Thailand dan atraksi gajah, serta makan siang buffet. Setelah itu, kunjungi Khao Chi Chan yang terkenal dengan ukiran Buddha emas di tebing. Sore hari menikmati suasana pantai di Pattaya Beach, sebelum makan malam dan check-in hotel.</p><p>Hari ketiga kembali ke Bangkok dengan city tour yang tak kalah seru. Kunjungi Gems Gallery dengan pengalaman train ride, lalu lanjut belanja oleh-oleh di pusat produk lokal. Nikmati waktu belanja di Platinum Fashion Mall. Wisata dilanjutkan ke ikon terkenal Wat Arun dan menikmati perjalanan perahu di Sungai Chao Phraya River menuju ICONSIAM serta Sook Siam. Malam hari bebas menikmati suasana di Asiatique The Riverfront 🌙</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar ke bandara untuk perjalanan pulang.</p><p>✧ Wisata Bangkok &amp; Pattaya dalam 1 perjalanan<br>✧ Budaya Thailand &amp; Elephant Show di Nong Nooch<br>✧ Spot foto Instagramable &amp; pantai Pattaya<br>✧ Shopping di Platinum Mall &amp; ICONSIAM<br>✧ Night market &amp; suasana romantis tepi sungai</p><p>Liburan praktis, lengkap, dan penuh pengalaman tak terlupakan ✨</p>', '<p><strong>SIC 2 CAN GO! BANGKOK – PATTAYA 4D3N 🤩</strong></p><p>Enjoy an exciting holiday to Bangkok and Pattaya with a perfect mix of culture, entertainment, shopping, and beach experiences in a 4-day, 3-night trip 🌏✨</p><p>Your journey begins with airport pick-up in Bangkok and transfer to the hotel for rest.</p><p>On Day 2, travel to Pattaya and visit Honey Bee Farm, followed by photo stops at Great and Grand Sweet Destination. Continue to Nong Nooch Tropical Garden to enjoy Thai cultural performances and an elephant show, including buffet lunch. Then visit Khao Chi Chan, and relax at Pattaya Beach before dinner and hotel check-in.</p><p>On Day 3, return to Bangkok and explore Gems Gallery with a unique train ride experience. Continue shopping at local product centers and Platinum Fashion Mall. Visit the iconic Wat Arun and enjoy a boat ride along the Chao Phraya Riverto ICONSIAM and Sook Siam. Spend your evening at Asiatique The Riverfront 🌙</p><p>On Day 4, enjoy free time before transfer to the airport.</p><p>✧ Bangkok &amp; Pattaya in one trip<br>✧ Thai cultural &amp; elephant show<br>✧ Instagrammable spots &amp; beach<br>✧ Shopping at Platinum &amp; ICONSIAM<br>✧ Night market experience</p><p>A complete, fun, and unforgettable holiday ✨</p>', '<p><strong>SIC 2 CAN GO! 방콕 – 파타야 4일 3박 🤩</strong></p><p>Bangkok과 Pattaya를 여행하며 문화, 쇼핑, 해변, 엔터테인먼트를 모두 즐길 수 있는 4일간의 완벽한 일정 🌏✨</p><p>첫날은 공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>둘째 날에는 파타야로 이동하여 Honey Bee Farm 방문 후 Great and Grand Sweet Destination에서 사진 촬영을 합니다. 이어서 Nong Nooch Tropical Garden에서 태국 전통 공연과 코끼리 쇼를 관람하고 뷔페 점심을 즐깁니다. 이후 Khao Chi Chan, Pattaya Beach를 방문합니다.</p><p>셋째 날에는 방콕으로 이동하여 Gems Gallery를 관광하고 쇼핑을 진행합니다. Platinum Fashion Mall 방문 후 Wat Arun을 관광하고, Chao Phraya River에서 보트 투어를 즐깁니다. 이후 ICONSIAM 및 Sook Siam 방문, 저녁에는 Asiatique The Riverfront에서 자유 시간을 보냅니다 🌙</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><p>✧ 방콕 &amp; 파타야 여행<br>✧ 태국 문화 공연 &amp; 코끼리 쇼<br>✧ 포토 스팟 &amp; 해변<br>✧ 쇼핑<br>✧ 야시장 체험</p><p>완벽하고 즐거운 여행 ✨</p>', '<p><strong>SIC 2 CAN GO! 曼谷 – 芭堤雅 4天3晚 🤩</strong></p><p>畅游 Bangkok 与 Pattaya，体验文化、购物、海滩与娱乐相结合的精彩旅程 🌏✨</p><p>第一天抵达曼谷后接机并入住酒店休息。</p><p>第二天前往芭堤雅，参观 Honey Bee Farm，并在 Great and Grand Sweet Destination拍照打卡。随后前往 Nong Nooch Tropical Garden观看泰国文化表演和大象秀，并享用自助午餐。接着参观 Khao Chi Chan以及 Pattaya Beach。</p><p>第三天返回曼谷，参观 Gems Gallery并体验小火车。随后前往当地特产中心及 Platinum Fashion Mall购物。参观 Wat Arun并乘船游览 Chao Phraya River，前往 ICONSIAM和 Sook Siam。晚上可在 Asiatique The Riverfront自由活动 🌙</p><p>第四天自由活动后送机，结束愉快旅程。</p><p>✧ 曼谷与芭堤雅双城体验<br>✧ 泰国文化表演与大象秀<br>✧ 网红打卡与海滩<br>✧ 购物体验<br>✧ 夜市与娱乐</p><p>一次轻松、丰富又难忘的旅行 ✨</p>', 1950000.00, NULL, 4, 0, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Thai Traditional &amp; Elephant Show, Wat Arun, Platinum Mall, Icon Siam, Asiatique</strong></p>', '<ul><li data-list-item-id=\"e147a1a6fe47ee56dfd95e6f1f8b3faa1\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e8796d2df77826569369d33dfeb3b2878\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed93a5f0516e7dc91a2bdfd1017a0d23e\"><p>HOTEL WITH BREAKFAST 2 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ee57209c5c16b200dc8d75846e803af13\"><p>HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed7c639cb2fb1d3d3338b0258266572bf\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ef5c3f10b59930881966f3a0bd9db4c77\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed5667f757ff5227c6575ef191d0627b4\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"ef09e74931628cc300d3e9c996b724423\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD20/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eaa409097a8d7c7ec92f640a8dce0a241\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD12/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e4adf554b37ae9b5c3f632b6fbe5e84d0\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e8f868b9143e05ee9f52e836ff252f742\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e12d3fb892a3d24b458259d1b57aad188\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/mK6na1Vdixa4uVhZUM7pnbyN0AVC0QhAVCloCgy0.pdf', 0, NULL, '2026-04-29 08:32:36', '2026-04-29 08:45:41'),
(62, 21, 'Bangkok Pattaya Safari Marine Park 5D4N', NULL, 'bangkok-pattaya-safari-marine-park-5d4n', '<p><strong>SIC 2 CAN GO! BANGKOK – PATTAYA + SAFARI WORLD 5D4N 🤩</strong></p><p>Nikmati liburan lengkap ke Bangkok dan Pattaya dengan kombinasi wisata kota, budaya, hiburan, belanja, hingga petualangan safari dalam perjalanan 5 hari 4 malam yang seru dan berkesan 🌏✨</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok dan transfer ke hotel untuk beristirahat.</p><p>Hari kedua, perjalanan menuju Pattaya dengan berbagai destinasi menarik. Kunjungi Honey Bee Farm, lalu berfoto di Great and Grand Sweet Destination yang penuh warna dan Instagramable. Lanjutkan ke taman dinosaurus dan Nong Nooch Tropical Garden untuk menikmati pertunjukan budaya Thailand dan atraksi gajah, lengkap dengan makan siang buffet. Setelah itu kunjungi Khao Chi Chan, bersantai di Pattaya Beach, dan bermalam di Pattaya.</p><p>Hari ketiga kembali ke Bangkok untuk city tour. Kunjungi Gems Gallery dengan pengalaman train ride, lanjutkan belanja oleh-oleh dan fashion di Platinum Fashion Mall. Wisata dilanjutkan ke ikon terkenal Wat Arun, kemudian menikmati perjalanan perahu di Chao Phraya River menuju ICONSIAM dan Sook Siam. Malam hari bebas menikmati suasana di Asiatique The Riverfront 🌙</p><p>Hari keempat menghadirkan pengalaman seru di Safari World Bangkok, termasuk Safari Park dan Marine Park dengan berbagai pertunjukan menarik seperti Spy War dan Cowboy Show serta atraksi hewan. Setelah itu, lanjutkan wisata belanja di MBK Center dan nikmati suasana malam di Jodd Fairs Night Market yang terkenal dengan kuliner dan street market-nya.</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar ke bandara untuk perjalanan pulang.</p><p>✧ Bangkok &amp; Pattaya dalam satu paket lengkap<br>✧ Budaya Thailand &amp; Elephant Show<br>✧ Safari World &amp; Marine Park experience<br>✧ Shopping di Platinum Mall, MBK &amp; ICONSIAM<br>✧ Night market &amp; kuliner khas Thailand</p><p>Liburan praktis, seru, dan penuh pengalaman tak terlupakan ✨</p>', '<p><strong>SIC 2 CAN GO! BANGKOK – PATTAYA + SAFARI WORLD 5D4N 🤩</strong></p><p>Enjoy a complete holiday to Bangkok and Pattaya with a perfect combination of city tours, culture, entertainment, shopping, and safari adventure in a 5-day, 4-night trip 🌏✨</p><p>Your journey begins with airport pick-up in Bangkok and transfer to the hotel for rest.</p><p>On Day 2, travel to Pattaya and visit Honey Bee Farm, followed by photo stops at Great and Grand Sweet Destination. Continue to the dinosaur park and Nong Nooch Tropical Garden to enjoy Thai cultural performances and an elephant show, including buffet lunch. Then visit Khao Chi Chan and relax at Pattaya Beach before dinner and hotel check-in.</p><p>On Day 3, return to Bangkok and explore Gems Gallery with a train ride experience. Continue shopping at local product centers and Platinum Fashion Mall. Visit Wat Arun and enjoy a boat ride along the Chao Phraya River to ICONSIAM and Sook Siam. Spend your evening at Asiatique The Riverfront 🌙</p><p>On Day 4, enjoy a fun adventure at Safari World Bangkok, including Safari Park and Marine Park with exciting shows such as Spy War and Cowboy Show, plus animal attractions. Continue shopping at MBK Center and end the day at Jodd Fairs Night Market.</p><p>On Day 5, enjoy free time before transfer to the airport.</p><p>✧ Bangkok &amp; Pattaya in one trip<br>✧ Thai cultural &amp; elephant show<br>✧ Safari World &amp; Marine Park<br>✧ Shopping experience<br>✧ Night market &amp; local cuisine</p><p>A fun, complete, and unforgettable holiday ✨</p>', '<p><strong>SIC 2 CAN GO! 방콕 – 파타야 + 사파리 월드 5일 4박 🤩</strong></p><p>Bangkok과 Pattaya를 여행하며 도시 관광, 문화, 쇼핑, 해변, 사파리 체험까지 즐길 수 있는 5일간의 완벽한 일정 🌏✨</p><p>첫날은 공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>둘째 날에는 파타야로 이동하여 Honey Bee Farm 방문 후 Great and Grand Sweet Destination에서 사진 촬영을 합니다. 이어서 공룡 공원과 Nong Nooch Tropical Garden에서 태국 전통 공연과 코끼리 쇼를 관람하고 뷔페 점심을 즐깁니다. 이후 Khao Chi Chan, Pattaya Beach를 방문합니다.</p><p>셋째 날에는 방콕으로 이동하여 Gems Gallery 관광 후 Platinum Fashion Mall에서 쇼핑을 즐깁니다. Wat Arun 방문 후 Chao Phraya River 보트 투어를 통해 ICONSIAM과 Sook Siam을 방문합니다. 저녁에는 Asiatique The Riverfront에서 자유 시간을 보냅니다 🌙</p><p>넷째 날에는 Safari World Bangkok에서 사파리 파크와 마린 파크를 즐기며 다양한 공연과 동물 쇼를 관람합니다. 이후 MBK Center 쇼핑 및 Jodd Fairs Night Market 방문을 진행합니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><p>✧ 방콕 &amp; 파타야 여행<br>✧ 문화 공연 &amp; 코끼리 쇼<br>✧ 사파리 월드 체험<br>✧ 쇼핑<br>✧ 야시장</p><p>완벽하고 즐거운 여행 ✨</p>', '<p><strong>SIC 2 CAN GO! 曼谷 – 芭堤雅 + 野生动物园 5天4晚 🤩</strong></p><p>畅游 Bangkok 与 Pattaya，体验城市观光、文化、购物、海滩以及野生动物园的精彩旅程 🌏✨</p><p>第一天抵达曼谷后接机入住酒店休息。</p><p>第二天前往芭堤雅，参观 Honey Bee Farm，并在 Great and Grand Sweet Destination拍照打卡。随后前往恐龙公园和 Nong Nooch Tropical Garden观看泰国文化表演和大象秀，并享用自助午餐。接着参观 Khao Chi Chan以及 Pattaya Beach。</p><p>第三天返回曼谷，参观 Gems Gallery并前往 Platinum Fashion Mall购物。随后参观 Wat Arun并乘船游览 Chao Phraya River，前往 ICONSIAM和 Sook Siam。晚上可在 Asiatique The Riverfront自由活动 🌙</p><p>第四天前往 Safari World Bangkok，体验野生动物园与海洋公园，欣赏精彩表演并与动物互动。之后前往 MBK Center购物，并在 Jodd Fairs Night Market享受夜市美食。</p><p>第五天自由活动后送机，结束愉快旅程。</p><p>✧ 曼谷与芭堤雅双城体验<br>✧ 泰国文化与大象表演<br>✧ 野生动物园体验<br>✧ 购物与夜市<br>✧ 美食与娱乐</p><p>一次丰富又难忘的旅程 ✨</p>', 3550000.00, NULL, 5, 4, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Safari Marine Park, Spy War Show, Cowboy Show, Wat Arun, Nongnooch, Asiatique</strong></p>', '<ul><li data-list-item-id=\"ed73490fbfb1d4cef1d0bb4d3c0a0a7ec\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"edae33d9795070ad5e83bd7a705264106\"><p>&nbsp;LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"e6db5fcf8bd062c68f666e680399b675b\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"ef63d2b770b9df7c671a67717b04de775\"><p>HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e991cd2c27d1fe88533676e2755b1dee6\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"eec63eb75caa24ce89ed0ea6b455d4986\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e265704154bba36a8027ef5efa0b091a1\"><p>INDONESIAN SPEAKING GUIDE</p><p>&nbsp;</p></li><li data-list-item-id=\"edb4ba8f6f80a2716fb6462a7e08c6881\">VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"ec61d0606b3c404ec87dc3110cc70953a\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD25/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ef40f808f8ea2c0efc55e1864283e808b\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD15/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e3a70d28d80021152593afb623f3dbb5b\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e47bc7e10737a8111e5f2dbf40c2712b5\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0b8ae9f3033ff1ec3774a2290f8e2a4c\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/syOZ593nxODx94kSdx5ycTR7jamjslpiGjUp6NQt.pdf', 0, NULL, '2026-04-29 09:07:54', '2026-04-29 09:12:49'),
(63, 21, 'Bangkok Pattaya Dream World 5D4N', NULL, 'bangkok-pattaya-dream-world-5d4n', '<p><strong>BANGKOK – PATTAYA + DREAM WORLD 5D4N 🤩</strong></p><p>Nikmati liburan seru ke Bangkok dan Pattaya dengan kombinasi wisata budaya, hiburan, belanja, pantai, hingga taman bermain dalam perjalanan 5 hari 4 malam yang lengkap dan menyenangkan 🌏</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok dan transfer ke hotel untuk beristirahat.</p><p>Hari kedua, perjalanan menuju Pattaya dengan berbagai destinasi menarik. Kunjungi Honey Bee Farm, lalu berfoto di Great and Grand Sweet Destination yang penuh warna dan Instagramable. Lanjutkan ke taman dinosaurus dan Nong Nooch Tropical Garden untuk menikmati pertunjukan budaya Thailand dan atraksi gajah, lengkap dengan makan siang buffet. Setelah itu kunjungi Khao Chi Chan, bersantai di Pattaya Beach, lalu makan malam dan bermalam di Pattaya.</p><p>Hari ketiga kembali ke Bangkok untuk city tour. Kunjungi Gems Gallery dengan pengalaman train ride, lanjutkan belanja oleh-oleh dan fashion di Platinum Fashion Mall. Wisata dilanjutkan ke ikon terkenal Wat Arun, kemudian menikmati perjalanan perahu di Chao Phraya River menuju ICONSIAM serta Sook Siam. Malam hari bebas menikmati suasana di Asiatique The Riverfront 🌙</p><p>Hari keempat menjadi highlight perjalanan dengan kunjungan ke Dream World Bangkok 🎢. Nikmati berbagai wahana seru di Dream Garden, Fantasy Land, Adventure Land, hingga Snow Town yang menghadirkan pengalaman salju di tengah kota tropis. Setelah itu, lanjutkan belanja di MBK Center dan nikmati kuliner malam di Jodd Fairs Night Market.</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar ke bandara untuk perjalanan pulang.</p><p>✧ Bangkok &amp; Pattaya dalam satu perjalanan<br>✧ Budaya Thailand &amp; Elephant Show<br>✧ Theme park seru di Dream World<br>✧ Shopping di Platinum, MBK &amp; ICONSIAM<br>✧ Night market &amp; kuliner khas Thailand</p><p>Liburan praktis, seru, dan penuh pengalaman tak terlupakan ✨</p>', '<p><strong>BANGKOK – PATTAYA + DREAM WORLD 5D4N 🤩</strong></p><p>Enjoy an exciting holiday to Bangkok and Pattaya with a perfect combination of culture, entertainment, shopping, beach, and theme park experiences in a 5-day, 4-night trip 🌏</p><p>Your journey begins with airport pick-up in Bangkok and transfer to the hotel for rest.</p><p>On Day 2, travel to Pattaya and visit Honey Bee Farm, followed by photo stops at Great and Grand Sweet Destination. Continue to the dinosaur park and Nong Nooch Tropical Garden to enjoy Thai cultural performances and an elephant show, including buffet lunch. Then visit Khao Chi Chan and relax at Pattaya Beach before dinner and hotel check-in.</p><p>On Day 3, return to Bangkok and explore Gems Gallery with a train ride experience. Continue shopping at local product centers and Platinum Fashion Mall. Visit Wat Arun and enjoy a boat ride along the Chao Phraya River to ICONSIAM and Sook Siam. Spend your evening at Asiatique The Riverfront 🌙</p><p>On Day 4, enjoy a fun day at Dream World Bangkok 🎢 with unlimited access to Dream Garden, Fantasy Land, Adventure Land, and Snow Town. Continue shopping at MBK Center and end your day at Jodd Fairs Night Market.</p><p>On Day 5, enjoy free time before transfer to the airport.</p><p>✧ Bangkok &amp; Pattaya in one trip<br>✧ Thai cultural &amp; elephant show<br>✧ Theme park experience at Dream World<br>✧ Shopping experience<br>✧ Night market &amp; local cuisine</p><p>A fun, complete, and unforgettable holiday ✨</p>', '<p><strong>방콕 – 파타야 + 드림월드 5일 4박 🤩</strong></p><p>Bangkok과 Pattaya를 여행하며 문화, 쇼핑, 해변, 테마파크까지 즐길 수 있는 5일간의 완벽한 일정 🌏✨</p><p>첫날은 공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>둘째 날에는 파타야로 이동하여 Honey Bee Farm 방문 후 Great and Grand Sweet Destination에서 사진 촬영을 합니다. 이어서 공룡 공원과 Nong Nooch Tropical Garden에서 태국 전통 공연과 코끼리 쇼를 관람하고 뷔페 점심을 즐깁니다. 이후 Khao Chi Chan, Pattaya Beach를 방문합니다.</p><p>셋째 날에는 방콕으로 이동하여 Gems Gallery 관광 후 Platinum Fashion Mall에서 쇼핑을 즐깁니다. Wat Arun 방문 후 Chao Phraya River 보트 투어를 통해 ICONSIAM과 Sook Siam을 방문합니다. 저녁에는 Asiatique The Riverfront에서 자유 시간을 보냅니다 🌙</p><p>넷째 날에는 Dream World Bangkok에서 다양한 놀이기구와 Snow Town을 즐깁니다 🎢. 이후 MBK Center 쇼핑 및 Jodd Fairs Night Market 방문을 진행합니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><p>✧ 방콕 &amp; 파타야 여행<br>✧ 문화 공연 &amp; 코끼리 쇼<br>✧ 드림월드 테마파크<br>✧ 쇼핑<br>✧ 야시장</p><p>완벽하고 즐거운 여행 ✨</p>', '<p><strong>曼谷 – 芭堤雅 + 梦幻世界 5天4晚 🤩</strong></p><p>畅游 Bangkok 与 Pattaya，体验文化、购物、海滩与主题乐园的精彩旅程 🌏</p><p>第一天抵达曼谷后接机入住酒店休息。</p><p>第二天前往芭堤雅，参观 Honey Bee Farm，并在 Great and Grand Sweet Destination拍照打卡。随后前往恐龙公园和 Nong Nooch Tropical Garden观看泰国文化表演和大象秀，并享用自助午餐。接着参观 Khao Chi Chan以及 Pattaya Beach。</p><p>第三天返回曼谷，参观 Gems Gallery并前往 Platinum Fashion Mall购物。随后参观 Wat Arun并乘船游览 Chao Phraya River，前往 ICONSIAM和 Sook Siam。晚上可在 Asiatique The Riverfront自由活动 🌙</p><p>第四天前往 Dream World Bangkok 🎢，畅玩 Dream Garden、Fantasy Land、Adventure Land 和 Snow Town。随后前往 MBK Center购物，并在 Jodd Fairs Night Market享受夜市美食。</p><p>第五天自由活动后送机，结束愉快旅程。</p><p>✧ 曼谷与芭堤雅双城体验<br>✧ 泰国文化与大象表演<br>✧ 主题乐园体验<br>✧ 购物与夜市<br>✧ 美食与娱乐</p><p>一次丰富又难忘的旅程 ✨</p>', 3450000.00, NULL, 5, 4, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Dream World Happy Land, Wat Arun, Platinum Mall, Asiatique, Nongnooch Village</strong></p>', '<ul><li data-list-item-id=\"ef3a90d6da9d103a9e9c9e12d68660584\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ee340674529406ba5be4213be81883564\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e212ee4c93b4a812d7ed3001b6fe291f2\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e0cbd15e41adc4b11e963f1d41a530172\"><p>HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e1abef760b83fa82915d87f13f5b3d70c\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"edfb8f3ed8a63aefae050ade84d2b1b6a\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e42b350662a2073253bb29312f08ca938\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e4d350d7c9cbef1ac2158ad92291e78c5\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD25/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eb153599ed71e7994f92614743ff112b8\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD15/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ee891978c8f555c452f484a57f5eb4ff8\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed67a80aa56eb31dc76bb812141f6e0d1\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0a4eac65fe63442230761ca4c13ffeab\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/vzQNtOlMMurqqpqFFcGme0vbIWGVtynmgh6NAi0D.pdf', 0, NULL, '2026-04-30 02:28:55', '2026-04-30 03:32:27');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(64, 21, 'Bangkok Pattaya Kanchanaburi 5D4N', NULL, 'bangkok-pattaya-kanchanaburi-5d4n', '<p><strong>BANGKOK – PATTAYA – KANCHANABURI 5D4N</strong> 🌏</p><p>Nikmati pengalaman liburan lengkap menjelajahi keindahan Bangkok, Pattaya, hingga Kanchanaburi dalam satu perjalanan seru yang memadukan wisata budaya, alam, sejarah, hingga hiburan modern ✨</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok dan langsung diantar menuju hotel untuk beristirahat, mempersiapkan petualangan seru keesokan harinya.</p><p>Hari kedua, Anda akan menuju Pattaya dengan berbagai destinasi menarik. Kunjungi Honey Bee Farm, lalu nikmati spot foto penuh warna di Great and Grand Sweet Destination. Perjalanan dilanjutkan ke taman dinosaurus sebelum mengunjungi Nong Nooch Tropical Garden yang terkenal dengan pertunjukan budaya Thailand dan atraksi gajah, lengkap dengan makan siang buffet. Setelah itu, kunjungi Khao Chi Chan, bersantai di Pattaya Beach, hingga menikmati makan malam sebelum bermalam di Pattaya.</p><p>Hari ketiga, perjalanan kembali ke Bangkok untuk city tour dan wisata belanja. Kunjungi Gems Gallery dengan pengalaman unik train ride, dilanjutkan ke pusat oleh-oleh dan Platinum Fashion Mall untuk berbelanja. Wisata berlanjut ke ikon terkenal Wat Arun, kemudian menikmati perjalanan menyusuri Chao Phraya River menuju ICONSIAM dan Sook Siam. Malam hari bebas menikmati suasana di Asiatique The Riverfront.</p><p>Hari keempat menjadi pengalaman berbeda dengan perjalanan ke Kanchanaburi. Anda akan mengunjungi Kanchanaburi Skywalk untuk menikmati pemandangan alam dari ketinggian, serta melihat sejarah di Death Railwaydan menaiki kereta menuju Tham Krasae Bridge. Petualangan dilanjutkan ke Safari Park Kanchanaburi, di mana Anda bisa berinteraksi langsung dengan jerapah dan menyaksikan pertunjukan gajah 🐘🦒. Setelah itu kembali ke Bangkok dan menikmati malam kuliner di Jodd Fairs Night Market.</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar kembali ke bandara untuk perjalanan pulang.</p><p>✨ <strong>Highlight Perjalanan:</strong><br>✧ Kombinasi Bangkok, Pattaya &amp; Kanchanaburi dalam 1 trip<br>✧ Wisata budaya &amp; Elephant Show di Nong Nooch<br>✧ Jelajah sejarah Death Railway &amp; naik kereta klasik<br>✧ Interaksi langsung dengan jerapah di Safari Park<br>✧ Shopping &amp; kuliner di mall dan night market terkenal</p><p>Liburan ini cocok untuk Anda yang ingin menikmati Thailand secara lengkap—mulai dari budaya, alam, sejarah, hingga hiburan modern dalam satu paket praktis dan menyenangkan 🌟</p>', '<p><strong>BANGKOK – PATTAYA – KANCHANABURI 5D4N</strong> 🌏</p><p>Enjoy a complete holiday experience exploring the beauty of Bangkok, Pattaya, and Kanchanaburi in one exciting journey that combines cultural, natural, historical, and modern entertainment attractions ✨</p><p>Your journey begins with airport pick-up in Bangkok and transfer to the hotel for check-in and rest, preparing for the exciting days ahead.</p><p>On Day 2, travel to Pattaya with various interesting destinations. Visit Honey Bee Farm, then enjoy colorful photo spots at Great and Grand Sweet Destination. Continue to the Dinosaur Park before visiting Nong Nooch Tropical Garden, famous for its Thai cultural performances and elephant shows, including a buffet lunch. After that, visit Khao Chi Chan, relax at Pattaya Beach, and enjoy dinner before staying overnight in Pattaya.</p><p>On Day 3, return to Bangkok for a city tour and shopping experience. Visit Gems Gallery with a unique train ride experience, followed by a stop at a local product center and shopping at Platinum Fashion Mall. Continue to the iconic Wat Arun, then enjoy a scenic boat ride along Chao Phraya River to ICONSIAM and Sook Siam. In the evening, enjoy free time at Asiatique The Riverfront.</p><p>Day 4 offers a different experience with a trip to Kanchanaburi. Visit Kanchanaburi Skywalk for breathtaking views, explore the historic Death Railway, and take a train to Tham Krasae Bridge. Continue your adventure at Safari Park Kanchanaburi, where you can interact with giraffes and watch an elephant show 🐘🦒. After that, return to Bangkok and enjoy a culinary evening at Jodd Fairs Night Market.</p><p>On the last day, enjoy free time before being transferred to the airport for your departure.</p><p>✨ <strong>Highlights:</strong><br>✧ Combination of Bangkok, Pattaya &amp; Kanchanaburi in one trip<br>✧ Cultural experiences &amp; Elephant Show at Nong Nooch<br>✧ Explore the historic Death Railway &amp; classic train ride<br>✧ Close interaction with giraffes at Safari Park<br>✧ Shopping &amp; culinary experiences at famous malls and night markets</p><p>This trip is perfect for those who want to experience Thailand completely—from culture, nature, and history to modern entertainment—all in one convenient and enjoyable package 🌟</p>', '<p><strong>방콕 – 파타야 – 깐차나부리 5일 4박</strong> 🌏</p><p>Bangkok, Pattaya, Kanchanaburi의 아름다움을 한 번에 즐길 수 있는 완벽한 여행으로, 문화·자연·역사·현대적인 즐거움을 모두 경험할 수 있습니다 ✨</p><p>여행은 방콕 공항 픽업 후 호텔 체크인 및 휴식으로 시작됩니다.</p><p>둘째 날에는 파타야로 이동하여 Honey Bee Farm 방문 후 Great and Grand Sweet Destination에서 사진 촬영을 즐깁니다. 이어 공룡 테마파크와 Nong Nooch Tropical Garden 방문 (태국 전통 공연 및 코끼리 쇼, 뷔페 점심 포함). 이후 Khao Chi Chan과 Pattaya Beach 관광 후 파타야 숙박.</p><p>셋째 날에는 방콕으로 돌아와 Gems Gallery, Platinum Fashion Mall 쇼핑 및 Wat Arun 방문. Chao Phraya River 보트 투어 후 ICONSIAM 및 Sook Siam 자유시간. 저녁에는 Asiatique The Riverfront 방문.</p><p>넷째 날에는 깐차나부리로 이동하여 Kanchanaburi Skywalk, Death Railway 관광 및 기차 탑승 후 Tham Krasae Bridge 방문. 이후 Safari Park Kanchanaburi에서 기린 먹이주기 체험과 코끼리 쇼 관람 🐘🦒. 방콕 복귀 후 Jodd Fairs Night Market 방문.</p><p>마지막 날 자유시간 후 공항 이동.</p><p>✨ <strong>하이라이트:</strong><br>✧ 방콕, 파타야, 깐차나부리 3개 도시 여행<br>✧ 태국 전통 공연 &amp; 코끼리 쇼<br>✧ 역사적인 철도 체험<br>✧ 사파리에서 기린 체험<br>✧ 쇼핑 &amp; 야시장 투어</p>', '<p><strong>曼谷 – 芭提雅 – 北碧府 5天4晚</strong> 🌏</p><p>一次旅程畅游Bangkok、Pattaya和Kanchanaburi，融合文化、自然、历史与现代娱乐的精彩体验 ✨</p><p>行程从曼谷机场接机开始，随后入住酒店休息。</p><p>第二天前往芭提雅，参观蜂蜜农场，并在Great and Grand Sweet Destination拍照打卡。随后游览恐龙公园及Nong Nooch Tropical Garden（包含泰国文化表演、大象表演及自助午餐）。之后参观Khao Chi Chan，在Pattaya Beach放松，并入住芭提雅酒店。</p><p>第三天返回曼谷，参观Gems Gallery，前往Platinum Fashion Mall购物，并游览Wat Arun。乘船游览Chao Phraya River前往ICONSIAM及Sook Siam。晚上可前往Asiatique The Riverfront自由活动。</p><p>第四天前往北碧府，参观Kanchanaburi Skywalk及历史悠久的Death Railway，搭乘火车前往Tham Krasae Bridge。随后前往Safari Park Kanchanaburi与长颈鹿互动并观看大象表演 🐘🦒。之后返回曼谷，在Jodd Fairs Night Market享受美食。</p><p>第五天自由活动后送机。</p><p>✨ <strong>行程亮点：</strong><br>✧ 一次游览曼谷、芭提雅和北碧府<br>✧ 泰国文化表演与大象秀<br>✧ 历史铁路体验<br>✧ 与长颈鹿亲密互动<br>✧ 购物与夜市美食体验</p>', 3550000.00, NULL, 5, 4, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Safari Park, Tham Krasae Bridge, Wat Arun, Jodd Fairs, Nongnooch Village</strong></p>', '<ul><li data-list-item-id=\"ec065f47a81356e48b479cf7721acfa5d\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed26b74787c60aa81eb2ade895f8d8975\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e0a4a5786bebbf0789c259a9f62355a91\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e3d539361445a0b22f0de3fe32681a47d\"><p>HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e966960f8c0bf9cb74a72471c3758d8f2\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ea14fdaf7a9d37c6f8fef961cd1adb2ed\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e9cb5ee2d1f660e0d00a3b5bc1d29f391\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"eae39807282fafbea39b1047117982963\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD25/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e9aac0d31d228579a7aee1a09f4de371c\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD15/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eddc898c2b71a041fb7c1975c60dcb0c6\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e877625b0dbc6dac8826041c2cdd203db\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e160c062d1f885775a40537d5a42a1ae8\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/5UNeNAbFTnZ21cjZbKuXSvSS5vy522cLSYRtBpw6.pdf', 0, NULL, '2026-04-30 03:30:43', '2026-04-30 05:36:02'),
(65, 21, '5D4N Bangkok Pattaya Khaoyai', NULL, '5d4n-bangkok-pattaya-khaoyai', '<h3>BANGKOK – PATTAYA – KHAO YAI 5D4N 🇹🇭</h3><p>Nikmati liburan seru menjelajahi Bangkok, Pattaya, dan Khao Yai dalam satu perjalanan yang memadukan wisata kota, budaya, alam, dan spot foto menarik.</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok, kemudian Anda diantar ke hotel untuk beristirahat.</p><p>Hari kedua, perjalanan menuju Pattaya dengan kunjungan ke Honey Bee Farm, Great and Grand Sweet Destination, serta taman dinosaurus. Dilanjutkan ke Nong Nooch Tropical Garden yang terkenal dengan pertunjukan budaya dan atraksi gajah. Setelah itu, kunjungi Khao Chi Chan dan bersantai di Pattaya Beach.</p><p>Hari ketiga kembali ke Bangkok untuk city tour dan belanja di Platinum Fashion Mall. Kunjungi Wat Arun dan nikmati perjalanan di Sungai Chao Phraya menuju ICONSIAM serta Sook Siam. Malam hari bebas menikmati suasana di Asiatique The Riverfront.</p><p>Hari keempat menuju Khao Yai, mengunjungi Hokkaido Flower Park Khao Yai, berfoto di Toscana Valley, dan bermain dengan alpaca di Khmong Alpaca Khao Yai sebelum kembali ke Bangkok.</p><p>Hari terakhir, waktu bebas sebelum diantar ke bandara.</p><h3>✨ Highlight</h3><p>• Kombinasi 3 destinasi dalam 1 trip<br>• Wisata budaya &amp; atraksi gajah di Nong Nooch<br>• Spot foto menarik di Khao Yai<br>• Pengalaman unik bersama alpaca<br>• Shopping &amp; kuliner di Bangkok</p>', '<h3>BANGKOK – PATTAYA – KHAO YAI 5D4N 🇹🇭</h3><p>Enjoy an exciting trip exploring Bangkok, Pattaya, and Khao Yai in one journey that combines city tours, culture, nature, and photo spots.</p><p>The trip starts with airport pick-up in Bangkok, followed by transfer to the hotel for rest.</p><p>On the second day, travel to Pattaya and visit Honey Bee Farm, Great and Grand Sweet Destination, and the Dinosaur Park. Continue to Nong Nooch Tropical Garden, famous for Thai cultural shows and elephant performances. Then visit Khao Chi Chan and relax at Pattaya Beach.</p><p>On the third day, return to Bangkok for a city tour and shopping at Platinum Fashion Mall. Visit Wat Arun and enjoy a Chao Phraya River cruise to ICONSIAM and Sook Siam. In the evening, enjoy free time at Asiatique The Riverfront.</p><p>On the fourth day, travel to Khao Yai and visit Hokkaido Flower Park Khao Yai, take photos at Toscana Valley, and interact with alpacas at Khmong Alpaca Khao Yai before returning to Bangkok.</p><p>On the last day, enjoy free time before transfer to the airport.</p><h3>✨ Highlights</h3><p>• 3 destinations in 1 trip<br>• Thai cultural &amp; elephant show at Nong Nooch<br>• Beautiful photo spots in Khao Yai<br>• Unique alpaca experience<br>• Shopping &amp; culinary in Bangkok</p>', '<h3>방콕 – 파타야 – 카오야이 5일 4박 🇹🇭</h3><p>방콕, 파타야, 카오야이를 한 번에 즐길 수 있는 여행으로 도시 관광, 문화, 자연, 포토 스팟을 모두 경험할 수 있습니다.</p><p>공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>2일차에는 파타야로 이동하여 Honey Bee Farm, Great and Grand Sweet Destination, 공룡 테마파크를 방문합니다. 이후 Nong Nooch Tropical Garden에서 태국 전통 공연과 코끼리 쇼를 관람합니다. 이어서 Khao Chi Chan과 Pattaya Beach을 방문합니다.</p><p>3일차에는 방콕으로 돌아와 시티투어 및 쇼핑을 즐깁니다. Platinum Fashion Mall 방문 후 Wat Arun 관광, 차오프라야 강 보트를 타고 ICONSIAM과 Sook Siam을 방문합니다. 저녁에는 Asiatique The Riverfront에서 자유시간을 즐깁니다.</p><p>4일차에는 카오야이로 이동하여 Hokkaido Flower Park Khao Yai, Toscana Valley, Khmong Alpaca Khao Yai를 방문합니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><h3>✨ 하이라이트</h3><p>• 한 번에 3개 도시 여행<br>• 태국 전통 공연 &amp; 코끼리 쇼<br>• 카오야이 포토 스팟<br>• 알파카 체험<br>• 방콕 쇼핑 &amp; 먹거리</p>', '<h3>曼谷 – 芭提雅 – 考艾 5天4晚 🇹🇭</h3><p>一次行程畅游曼谷、芭提雅和考艾，结合城市观光、文化体验、自然风景和拍照打卡景点。</p><p>抵达曼谷机场后接机，送往酒店休息。</p><p>第二天前往芭提雅，参观 Honey Bee Farm、Great and Grand Sweet Destination 和恐龙主题公园。随后前往 Nong Nooch Tropical Garden 欣赏泰国文化表演和大象秀，并参观 Khao Chi Chan，在 Pattaya Beach 放松。</p><p>第三天返回曼谷，进行市区观光与购物，前往 Platinum Fashion Mall，参观 Wat Arun，乘船游览湄南河前往 ICONSIAM 和 Sook Siam。晚上可自由活动于 Asiatique The Riverfront。</p><p>第四天前往考艾，游览 Hokkaido Flower Park Khao Yai，在 Toscana Valley 拍照，并在 Khmong Alpaca Khao Yai与羊驼互动。</p><p>最后一天自由活动后送机返程。</p><h3>✨ 行程亮点</h3><p>• 一次畅游三大目的地<br>• 泰国文化与大象表演<br>• 考艾网红拍照景点<br>• 羊驼互动体验<br>• 曼谷购物与美食</p>', 3050000.00, NULL, 5, 4, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Toscana Valley, Toy Museum, Hokkaido Flower Park, Wat Arun, Nongnooch</strong></p>', '<ul><li data-list-item-id=\"e8850e4eddeb37f628fc9cba3d94a85b7\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e187f422a0a48707ed6cc1a46266b8c7d\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eb9f31fc4d174e70952ed96525cd658a7\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed00101714ecf3023354a91ffbb15fb4c\"><p>HOTEL WITH BREAKFAST 1 NIGHT STAY IN PATTAYA</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e5f2592f562ee13a927399d563448a61c\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e8644f14612bd2556e88859deeeb311c8\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e20a3bb5bb52e523be9a94628ef9a5d9a\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e5ebb73a69355096f6ab507997f33b40b\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX (<strong>USD25/PAX)</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e124b528762ca66ff2d7620f6302b331c\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP (<strong>USD15/PAX)</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ec2dc2054d6dcc84cc95c9e84b3620b5e\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0c398f4cc101719b6f56b3ae56946b57\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"eff2d98949c8355ec90d35c32797ce5ad\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/O6kvts0afNwsO3VPmGRFKnayelkwETqDUs72wbUR.pdf', 0, NULL, '2026-04-30 08:11:59', '2026-05-02 13:19:03'),
(66, 21, 'Bangkok Pattaya Coral Island 5D4N', NULL, 'bangkok-pattaya-coral-island-5d4n', '<h3>BANGKOK – PATTAYA – CORAL ISLAND 5D4N 🇹🇭</h3><p>Nikmati liburan seru ke Thailand dengan kombinasi wisata kota, pantai, budaya, dan hiburan dalam satu perjalanan praktis.</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok, kemudian Anda akan diantar menuju hotel untuk beristirahat.</p><p>Hari kedua, perjalanan menuju Pattaya dengan mengunjungi Honey Bee Farm, Great and Grand Sweet Destination, serta taman dinosaurus. Dilanjutkan ke Nong Nooch Tropical Garden yang terkenal dengan pertunjukan budaya Thailand dan atraksi gajah. Setelah itu, kunjungi Khao Chi Chan dan bersantai di Pattaya Beach sebelum bermalam di Pattaya.</p><p>Hari ketiga menjadi highlight perjalanan dengan mengunjungi Coral Island Pattaya menggunakan speed boat. Anda dapat menikmati pantai berpasir putih serta berbagai aktivitas air seperti snorkeling, parasailing, jet ski, dan banana boat (opsional). Setelah itu, city tour Pattaya dilanjutkan dengan kunjungan ke Art in Paradise Pattaya dan berbelanja di Terminal 21 Pattaya. Malam hari bebas menikmati suasana di Walking Street Pattaya.</p><p>Hari keempat kembali ke Bangkok untuk city tour dan belanja di Platinum Fashion Mall. Kunjungi Wat Arun dan nikmati perjalanan menyusuri Sungai Chao Phraya menuju ICONSIAM serta Sook Siam. Malam hari dapat dinikmati di Asiatique The Riverfront.</p><p>Hari terakhir, waktu bebas sebelum diantar kembali ke bandara untuk perjalanan pulang.</p><h3>✨ Highlight</h3><p>• Kunjungan ke Coral Island dengan speed boat<br>• Wisata budaya &amp; Elephant Show di Nong Nooch<br>• Aktivitas air seru di Pattaya<br>• Shopping di Platinum Mall &amp; ICONSIAM<br>• City tour Bangkok &amp; Pattaya</p>', '<h3>BANGKOK – PATTAYA – CORAL ISLAND 5D4N 🇹🇭</h3><p>Enjoy an exciting trip to Thailand combining city tours, beach experiences, culture, and entertainment in one convenient journey.</p><p>The trip begins with airport pick-up in Bangkok, followed by transfer to the hotel for rest.</p><p>On the second day, travel to Pattaya and visit Honey Bee Farm, Great and Grand Sweet Destination, and the Dinosaur Park. Continue to Nong Nooch Tropical Garden, famous for Thai cultural shows and elephant performances. Then visit Khao Chi Chan and relax at Pattaya Beach.</p><p>On the third day, enjoy a highlight trip to Coral Island Pattaya by speed boat. Relax on the white sandy beach or try optional water activities such as snorkeling, parasailing, jet ski, and banana boat. Continue with a Pattaya city tour visiting Art in Paradise Pattaya and shopping at Terminal 21 Pattaya. In the evening, enjoy free time at Walking Street Pattaya.</p><p>On the fourth day, return to Bangkok for shopping at Platinum Fashion Mall. Visit Wat Arun and enjoy a Chao Phraya River cruise to ICONSIAM and Sook Siam. In the evening, enjoy the atmosphere at Asiatique The Riverfront.</p><p>On the last day, enjoy free time before transfer to the airport.</p><h3>✨ Highlights</h3><p>• Coral Island trip by speed boat<br>• Thai cultural &amp; elephant show at Nong Nooch<br>• Fun water activities in Pattaya<br>• Shopping at Platinum Mall &amp; ICONSIAM<br>• Bangkok &amp; Pattaya city tour</p>', '<h3>방콕 – 파타야 – 산호섬 5일 4박 🇹🇭</h3><p>도시 관광, 해변, 문화, 엔터테인먼트를 한 번에 즐길 수 있는 태국 여행입니다.</p><p>공항 픽업 후 호텔로 이동하여 휴식을 취합니다.</p><p>2일차에는 파타야로 이동하여 Honey Bee Farm, Great and Grand Sweet Destination, 공룡 테마파크를 방문합니다. 이어서 Nong Nooch Tropical Garden에서 태국 전통 공연과 코끼리 쇼를 관람하고, Khao Chi Chan과 Pattaya Beach을 방문합니다.</p><p>3일차에는 스피드보트를 타고 Coral Island Pattaya로 이동하여 해변에서 휴식을 즐기거나 스노클링, 패러세일링, 제트스키 등의 해양 액티비티를 선택적으로 체험할 수 있습니다. 이후 Art in Paradise Pattaya, Terminal 21 Pattaya방문 및 Walking Street Pattaya 자유시간을 즐깁니다.</p><p>4일차에는 방콕으로 이동하여 Platinum Fashion Mall 쇼핑 후 Wat Arun 관광, 차오프라야 강 보트를 타고 ICONSIAM과 Sook Siam을 방문합니다. 저녁에는 Asiatique The Riverfront에서 자유시간을 보냅니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><h3>✨ 하이라이트</h3><p>• 산호섬 스피드보트 투어<br>• 태국 전통 공연 &amp; 코끼리 쇼<br>• 파타야 해양 액티비티<br>• 방콕 쇼핑<br>• 방콕 &amp; 파타야 시티투어</p>', '<h3>曼谷 – 芭提雅 – 珊瑚岛 5天4晚 🇹🇭</h3><p>一次行程结合城市观光、海岛度假、文化体验与娱乐活动。</p><p>抵达曼谷机场后接机，送往酒店休息。</p><p>第二天前往芭提雅，参观 Honey Bee Farm、Great and Grand Sweet Destination 和恐龙主题公园。随后前往 Nong Nooch Tropical Garden 欣赏泰国文化表演与大象秀，并参观 Khao Chi Chan，在 Pattaya Beach 放松。</p><p>第三天乘坐快艇前往 Coral Island Pattaya，享受海滩时光或体验浮潜、拖伞、水上摩托等水上活动。之后参观 Art in Paradise Pattaya，在 Terminal 21 Pattaya 购物，并在 Walking Street Pattaya 自由活动。</p><p>第四天返回曼谷，在 Platinum Fashion Mall 购物，参观 Wat Arun，乘船游览湄南河前往 ICONSIAM 和 Sook Siam，晚上可前往 Asiatique The Riverfront。</p><p>最后一天自由活动后送机返程。</p><h3>✨ 行程亮点</h3><p>• 珊瑚岛快艇之旅<br>• 泰国文化与大象表演<br>• 芭提雅海上活动<br>• 曼谷购物体验<br>• 曼谷与芭提雅城市观光</p>', 2900000.00, NULL, 5, 0, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Free Coral Island, 3D Art Paradise, Thai Traditional &amp; Elephant Show, Wat Arun, Platinum Mall</strong></p>', '<ul><li data-list-item-id=\"e29d57d07973dedddf68eb2bd57ba0d55\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"ee48870ae2f19d33d134e5a8fd370dedc\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"ef22e7e7a01cca44920cc9bfe3c944108\"><p>HOTEL WITH BREAKFAST 2 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"e0e927a6db65014db0eca776d254d6b53\"><p>HOTEL WITH BREAKFAST 2 NIGHTS STAY IN PATTAYA</p><p>&nbsp;</p></li><li data-list-item-id=\"e69a5220d27034ac7f50d2a16c26428bf\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"eee8246ce4e367f30fa3cac1541f8b534\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e0cb3cb0d05071e11832cd5caf7c57c04\"><p>INDONESIAN SPEAKING GUIDE</p><p>&nbsp;</p></li><li data-list-item-id=\"ef9b0241ca7a903137bed00be2f4ea1be\">VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e43b1657e4d6069dd3da9d9ea655f406a\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD25/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"ef7b9ca1452eb2ffe73f950087a9c0cff\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD15/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e9a9f8483356ecb3957e73fe3c0b1afd3\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4838d91f17af702bf9d200d529f41ffc\"><p><strong>ADDITIONAL TOUR</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e874984b6ef3ba98a0c27f293ae3fa9df\"><p><strong>EXTEND HOTEL</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0b0ad7fe2c5f5179e818260d8cfb1462\"><strong>PEAK SEASON SURCHARGE</strong></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/x0Rky3x6OYtsGf6LMm1dO3I9vGDUfOKBQH7kRP47.pdf', 0, NULL, '2026-05-02 13:53:37', '2026-05-02 14:10:14'),
(67, 21, 'Bangkok Free Easy 4D3N', NULL, 'bangkok-free-easy-4d3n', '<h3>BANGKOK FREE &amp; EASY 4D3N 🇹🇭</h3><p>Nikmati liburan singkat ke Bangkok dengan konsep <strong>Free &amp; Easy</strong>, perpaduan sempurna antara city tour dan waktu bebas untuk eksplorasi sesuai gaya Anda. Cocok untuk Anda yang ingin liburan santai namun tetap mengunjungi destinasi populer.</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok, kemudian Anda akan diantar menuju hotel untuk beristirahat.</p><p>Hari kedua, Anda akan mengikuti Bangkok City Tour dengan mengunjungi pusat oleh-oleh khas Thailand seperti Dried Food dan Honey Bee Farm. Perjalanan dilanjutkan ke Wat Arun yang terkenal dengan keindahan arsitekturnya di tepi Sungai Chao Phraya. Setelah itu, kunjungi Gems Gallery dan nikmati waktu berbelanja di Platinum Fashion Mall. Malam hari, Anda dapat menikmati suasana santai dan kuliner di Asiatique The Riverfront sebelum kembali ke hotel.</p><p>Hari ketiga merupakan waktu bebas (Free &amp; Easy), di mana Anda dapat menjelajahi Bangkok sesuai keinginan—mulai dari wisata kuliner, belanja, hingga mengunjungi destinasi populer seperti ICONSIAM atau mengikuti optional tour tambahan.</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar kembali ke bandara untuk perjalanan pulang.</p><h3>✨ Highlight</h3><p>• City tour ke Wat Arun<br>• Shopping di Platinum Fashion Mall<br>• Night market di Asiatique The Riverfront<br>• Waktu bebas eksplor Bangkok<br>• Fleksibel &amp; santai (Free &amp; Easy concept)</p>', '<h3>BANGKOK FREE &amp; EASY 4D3N 🇹🇭</h3><p>Enjoy a short getaway to Bangkok with a <strong>Free &amp; Easy</strong> concept, combining city tours and free time to explore at your own pace. Perfect for travelers who want a relaxed yet fulfilling trip.</p><p>Your journey begins with airport pick-up in Bangkok, followed by transfer to the hotel for check-in and rest.</p><p>On the second day, join a Bangkok City Tour visiting local product centers such as Dried Food and Honey Bee Farm. Continue to Wat Arun, a famous riverside temple known for its stunning architecture. Then visit Gems Gallery and enjoy shopping at Platinum Fashion Mall. In the evening, experience the vibrant atmosphere and local cuisine at Asiatique The Riverfront before returning to the hotel.</p><p>On the third day, enjoy your Free &amp; Easy time. Explore Bangkok at your own leisure—shopping, dining, or visiting popular spots such as ICONSIAM, or join an optional tour.</p><p>On the final day, enjoy free time until your transfer to the airport.</p><h3>✨ Highlights</h3><p>• Visit to Wat Arun<br>• Shopping at Platinum Fashion Mall<br>• Night market at Asiatique The Riverfront<br>• Free time to explore Bangkok<br>• Flexible &amp; relaxing itinerary</p>', '<h3>방콕 자유여행 4일 3박 🇹🇭</h3><p>방콕에서 자유롭게 여행할 수 있는 Free &amp; Easy 일정으로, 시티투어와 자유시간을 함께 즐길 수 있는 여행입니다. 여유롭지만 알찬 여행을 원하는 분들에게 적합합니다.</p><p>공항 도착 후 픽업 서비스를 이용하여 호텔로 이동 후 휴식을 취합니다.</p><p>2일차에는 방콕 시티투어로 Dried Food, Honey Bee Farm을 방문한 후 Wat Arun을 관광합니다. 이후 Gems Gallery를 방문하고 Platinum Fashion Mall에서 쇼핑을 즐깁니다. 저녁에는 Asiatique The Riverfront에서 야시장과 식사를 즐긴 후 호텔로 돌아갑니다.</p><p>3일차는 자유시간으로, 쇼핑, 맛집 탐방 또는 ICONSIAM 방문 등 원하는 일정으로 여행을 즐길 수 있습니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><h3>✨ 하이라이트</h3><p>• Wat Arun 관광<br>• Platinum Fashion Mall 쇼핑<br>• Asiatique The Riverfront 야시장<br>• 자유로운 일정<br>• 편안하고 유연한 여행</p>', '<h3>曼谷自由行 4天3晚 🇹🇭</h3><p>本行程采用 Free &amp; Easy 模式，将城市观光与自由活动相结合，让您轻松探索曼谷，享受自在旅行体验。</p><p>抵达曼谷机场后接机，送往酒店办理入住并休息。</p><p>第二天参加曼谷城市观光，参观 Dried Food 和 Honey Bee Farm，随后前往 Wat Arun，欣赏其独特的河畔建筑。之后参观 Gems Gallery，并在 Platinum Fashion Mall 购物。晚上可在 Asiatique The Riverfront 享受夜市与美食。</p><p>第三天为自由活动时间，您可以自由购物、美食探索或前往 ICONSIAM 等热门景点，或参加自费行程。</p><p>最后一天自由活动后送机返程。</p><h3>✨ 行程亮点</h3><p>• Wat Arun 景点参观<br>• Platinum Fashion Mall 购物体验<br>• Asiatique The Riverfront 夜市<br>• 自由行安排<br>• 轻松灵活的行程</p>', 1100000.00, NULL, 4, 3, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Wat Arun, Icon Siam, Asiatique, Platinum Mall</strong></p>', '<ul><li data-list-item-id=\"e8713eac592a418cd3f4075dcbb3f1bfa\"><p>JOIN TRIP SIC</p><p>&nbsp;</p></li><li data-list-item-id=\"e3164c4435b6895185628c5f4d6ed1e4a\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;</p></li><li data-list-item-id=\"e43808f7a3dd2bb25e43691e95ff9061a\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;</p></li><li data-list-item-id=\"e10b37ea421bd3e67d5332370a9a57354\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;</p></li><li data-list-item-id=\"ecbb2029618c56b4446055646a1e0fc8f\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;</p></li><li data-list-item-id=\"e9f769dad0bf5b42181994dae63eedb23\"><p>INDONESIAN SPEAKING GUIDE</p><p>&nbsp;</p></li><li data-list-item-id=\"e8ea1164d260446745d785e00baa457df\">VALID 1 APRIL - 31 OCTOBER 2026</li></ul><p>&nbsp;</p>', '<ul><li data-list-item-id=\"e8613c7dcd00d85b4afcd5fb4729272c0\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD15/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"ecaffaf2da61ed2639993156918463602\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD9/PAX</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"e8e29a8822111e1a27f82a9a3ff5e1dd5\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e7d903de7d70019170b3cd753aaa3418e\"><p><strong>ADDITIONAL TOUR</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ece165b336feeae6e90af0716e39c272d\"><p><strong>EXTEND HOTEL</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e7fc4366cb3ae4a05010f8cb9b739b010\"><strong>PEAK SEASON SURCHARGE</strong></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/jfCKWGwsSUbC5xKsF3uIjcjCkEjyO8T7fui9ecZe.pdf', 0, NULL, '2026-05-02 14:24:47', '2026-05-02 14:54:48'),
(68, 21, 'Bangkok Shopping + Hidden Gem 4D3N', NULL, 'bangkok-shopping-hidden-gem-4d3n', '<h3>BANGKOK EXPLORE &amp; HIDDEN GEM 4D3N 🇹🇭</h3><p>Nikmati pengalaman berbeda menjelajahi Bangkok dengan kombinasi city tour, hidden gem, kuliner lokal, dan waktu santai dalam satu perjalanan yang praktis dan menyenangkan.</p><p>Perjalanan dimulai dengan penjemputan di bandara Bangkok, kemudian Anda akan diantar menuju hotel untuk check-in dan beristirahat.</p><p>Hari kedua, Anda akan mengikuti Bangkok City Tour dengan mengunjungi pusat oleh-oleh khas Thailand seperti Dried Food dan Honey Bee Farm. Dilanjutkan ke Wat Arun yang terkenal sebagai Temple of Dawn, serta menikmati pemandangan Sungai Chao Phraya dengan tourist boat. Setelah makan siang di restoran lokal, perjalanan dilanjutkan ke Gems Gallery dan waktu bebas berbelanja di Platinum Fashion Mall. Malam hari, Anda dapat menikmati suasana santai di Asiatique The Riverfront sebelum kembali ke hotel.</p><p>Hari ketiga menjadi highlight perjalanan dengan eksplorasi <strong>Hidden Gem Bangkok</strong> menggunakan E-Scooter. Anda akan mengunjungi area seni dan budaya seperti Talat Noi yang terkenal dengan street art, menikmati suasana unik di Chinatown Bangkok, serta menjelajahi Song Wat Walking Street yang penuh sejarah. Perjalanan juga dilengkapi dengan kunjungan ke berbagai café populer seperti Mother Roaster, Chocolate Café, dan Hong Sieng Kong. Setelah makan siang di restoran lokal, Anda akan diajak ke Chatuchak Weekend Market—pasar terbesar di Thailand, serta berkunjung ke ICONSIAM untuk menikmati Sook Siam Floating Market di dalam mall. Malam hari bebas atau dapat mengikuti optional dinner cruise.</p><p>Hari terakhir, Anda memiliki waktu bebas sebelum diantar kembali ke bandara untuk perjalanan pulang.</p><h3>✨ Highlight</h3><p>• City tour ke Wat Arun &amp; Sungai Chao Phraya<br>• Hidden gem experience dengan E-Scooter di Talat Noi<br>• Kuliner &amp; suasana lokal di Chinatown Bangkok<br>• Shopping di Chatuchak Weekend Market &amp; Platinum Fashion Mall<br>• Night market experience di Asiatique The Riverfront</p>', '<h3>BANGKOK EXPLORE &amp; HIDDEN GEM 4D3N 🇹🇭</h3><p>Enjoy a unique experience exploring Bangkok with a combination of city tours, hidden gems, local cuisine, and relaxing moments in one practical and enjoyable journey.</p><p>Your trip begins with airport pick-up in Bangkok, followed by transfer to the hotel for check-in and rest.</p><p>On the second day, you will join a Bangkok City Tour visiting local product centers such as Dried Food and Honey Bee Farm. Continue to Wat Arun, also known as the Temple of Dawn, and enjoy sightseeing along the Chao Phraya River by tourist boat. After lunch at a local restaurant, the journey continues to Gems Gallery and free time for shopping at Platinum Fashion Mall. In the evening, enjoy the vibrant atmosphere at Asiatique The Riverfront before returning to the hotel.</p><p>On the third day, experience the highlight of the trip by exploring Bangkok’s hidden gems with an E-Scooter. Visit cultural and artistic areas such as Talat Noi, known for its street art, explore the unique vibe of Chinatown Bangkok, and walk along the historic Song Wat Walking Street. The journey also includes visits to popular cafés such as Mother Roaster, Chocolate Café, and Hong Sieng Kong. After lunch, continue to Chatuchak Weekend Market—the largest market in Thailand—and visit ICONSIAM to experience the Sook Siam Floating Market inside the mall. In the evening, enjoy free time or join an optional dinner cruise.</p><p>On the final day, enjoy free time before your transfer to the airport.</p><h3>✨ Highlights</h3><p>• Visit Wat Arun &amp; Chao Phraya River<br>• Hidden gem experience with E-Scooter at Talat Noi<br>• Local culture &amp; food at Chinatown Bangkok<br>• Shopping at Chatuchak Weekend Market &amp; Platinum Fashion Mall<br>• Night market experience at Asiatique The Riverfront</p>', '<h3>방콕 탐험 &amp; 히든젬 4일 3박 🇹🇭</h3><p>방콕의 시티투어, 숨겨진 명소, 현지 음식, 여유로운 시간을 모두 즐길 수 있는 특별한 여행입니다.</p><p>공항 도착 후 픽업 서비스를 이용하여 호텔로 이동 및 휴식을 취합니다.</p><p>2일차에는 방콕 시티투어로 Dried Food와 Honey Bee Farm을 방문한 후 Wat Arun(새벽사원)을 관광하고, 차오프라야 강을 따라 보트 투어를 즐깁니다. 이후 현지 레스토랑에서 점심 식사 후 Gems Gallery와 Platinum Fashion Mall에서 쇼핑을 즐깁니다. 저녁에는 Asiatique The Riverfront에서 야시장과 분위기를 즐긴 후 호텔로 돌아갑니다.</p><p>3일차에는 E-스쿠터를 타고 방콕의 숨겨진 명소를 탐방합니다. 스트리트 아트로 유명한 Talat Noi, 독특한 분위기의 Chinatown Bangkok, 그리고 역사적인 Song Wat 거리를 방문합니다. 또한 Mother Roaster, Chocolate Café, Hong Sieng Kong 카페를 방문합니다. 점심 후에는 Chatuchak Weekend Market과 ICONSIAM을 방문합니다. 저녁은 자유시간 또는 선택 관광(디너 크루즈) 가능합니다.</p><p>마지막 날은 자유시간 후 공항으로 이동합니다.</p><h3>✨ 하이라이트</h3><p>• Wat Arun &amp; 차오프라야 강 투어<br>• Talat Noi 히든젬 탐방<br>• Chinatown Bangkok 현지 문화 체험<br>• Chatuchak Weekend Market &amp; Platinum Fashion Mall 쇼핑<br>• Asiatique The Riverfront 야시장</p>', '<h3>曼谷探索 &amp; 隐藏景点 4天3晚 🇹🇭</h3><p>本行程结合城市观光、隐藏景点、当地美食与休闲时间，让您轻松畅游曼谷，体验不一样的旅行。</p><p>抵达曼谷机场后接机，前往酒店办理入住并休息。</p><p>第二天参加曼谷城市观光，参观 Dried Food 和 Honey Bee Farm，随后前往 Wat Arun（黎明寺），并乘船游览昭披耶河。午餐后参观 Gems Gallery，并在 Platinum Fashion Mall 购物。晚上可前往 Asiatique The Riverfront 夜市体验当地美食与氛围。</p><p>第三天体验行程亮点——乘坐电动滑板车探索曼谷隐藏景点。参观以街头艺术闻名的 Talat Noi，游览 Chinatown Bangkok，并漫步历史悠久的 Song Wat 街。还将打卡 Mother Roaster、Chocolate Café 和 Hong Sieng Kong 咖啡馆。午餐后前往 Chatuchak Weekend Market（泰国最大市场）以及 ICONSIAM 体验室内水上市场 Sook Siam。晚上自由活动或参加自费晚餐游船。</p><p>最后一天自由活动后送机返程。</p><h3>✨ 行程亮点</h3><p>• Wat Arun &amp; 昭披耶河游览<br>• Talat Noi 隐藏景点探索<br>• Chinatown Bangkok 当地文化体验<br>• Chatuchak Weekend Market &amp; Platinum Fashion Mall 购物<br>• Asiatique The Riverfront 夜市体验</p>', 1700000.00, NULL, 4, 3, '[\"April - Oktober 2026\"]', NULL, '<p style=\"text-align:center;\">Highlight: <strong>Wat Arun, Icon Siam, Asiatique, Platinum Mall, Free E-Scooter Tour</strong></p>', '<ul><li data-list-item-id=\"e4c949469d21e049ee825877425ce4f73\"><p>JOIN TRIP SIC</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e02630d18ba49e9ecae6db7389f6dc249\"><p>LOCAL TRAVEL INSURANCE</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e95b885f0e61e72bb71ef05840c7dc2d0\"><p>HOTEL WITH BREAKFAST 3 NIGHTS STAY IN BANGKOK</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e4651044cef52fc2811f8ae73d296a22d\"><p>ALL MENTIONED TOURS AND MEALS ON ITINERARY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e00891a0e03e6d9bac01524af6050db22\"><p>1 BOTTLE OF DRINKING WATER PER PERSON DAILY</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"ed892df24db974e405db7393f24c002cb\">INDONESIAN SPEAKING GUIDE VALID 1 APRIL - 31 OCTOBER 2026</li></ul>', '<ul><li data-list-item-id=\"e1a5a27afddae7c8700b4477a65509011\"><p>TIPPING FOR DRIVER &amp; GUIDE 2 – 14 PAX <strong>USD20/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e09b2d634576ad9d9c3729c15703a707f\"><p>TIPPING FOR DRIVER &amp; GUIDE 15 PAX UP <strong>USD12/PAX</strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e446278cbd4defec0f0363d0e1c9da249\"><p>TIPPING MUST BE PAID ON INVOICE BEFORE TOUR</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed5a606f6d892bd02d99c6dbe0a3a1793\"><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/16GJ4gSb2msjTmIr91da7rEv8BrISW_1H/view?usp=drive_link\"><strong>ADDITIONAL TOUR</strong></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e9721397a2e2b75178b09a867c6274095\"><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/1BzChaP3taLff8c7O2AjgMdb8vTr1kjiL/view?usp=drive_link\"><strong>EXTEND HOTEL</strong></a><strong> </strong><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://drive.google.com/file/d/11aymzWscMHB6DRB1AEzj6ibgG78yz6Cf/view?usp=drive_link\"><strong>PEAK SEASON SURCHARGE</strong></a></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/EN2RvXcQDEskR9RMQUI0Kpa1kxSQuHSLIlSRf2Z6.pdf', 0, NULL, '2026-05-02 16:22:21', '2026-05-02 16:55:48'),
(69, 43, '12D Usa East Coast + Canada Woodburry Outlet (Free Liberty Cruise)', NULL, '12d-usa-east-coast-canada-woodburry-outlet-free-liberty-cruise', '<h3>FALL SEASON USA EAST COAST + CANADA 12D 🍁</h3><p>Nikmati perjalanan seru menjelajahi kota-kota ikonik Amerika Serikat dan Kanada dalam suasana musim gugur yang indah 🇺🇸🇨🇦✨</p><p>Perjalanan dimulai di New York dengan city tour mengunjungi landmark terkenal seperti Times Square, Wall Street, Empire State Building, hingga pengalaman Liberty Cruise melihat Statue of Liberty 🚢</p><p>Petualangan dilanjutkan ke Woodbury Common Premium Outlet untuk wisata belanja brand internasional terkenal, kemudian menuju Boston dengan kunjungan ke Harvard University dan kawasan bersejarah kota Boston.</p><p>Eksplorasi berlanjut ke Kanada dengan mengunjungi Montreal, Quebec City, Ottawa, dan Toronto yang terkenal dengan suasana kota klasik, landmark ikonik, serta nuansa musim gugur yang cantik 🍁</p><p>Highlight perjalanan adalah menikmati keindahan Niagara Falls Canada Side 🌊 sebelum melanjutkan city tour ke Washington DC untuk melihat White House, Capitol Hill, dan berbagai monument terkenal Amerika.</p><p>✧ Liberty Cruise &amp; Statue of Liberty<br>✧ Shopping di Woodbury Outlet<br>✧ Harvard University &amp; Quebec City<br>✧ Niagara Falls Canada Side<br>✧ Washington DC &amp; White House<br>✧ Suasana musim gugur USA &amp; Canada 🍁</p><p>Perpaduan sempurna antara city tour, shopping, sejarah, dan keindahan alam dalam satu perjalanan yang nyaman dan berkesan ✨</p>', '<h3>FALL SEASON USA EAST COAST + CANADA 12D 🍁</h3><p>Enjoy an unforgettable journey exploring the iconic cities of the United States and Canada during the beautiful autumn season 🇺🇸🇨🇦✨</p><p>The trip begins in New York with a city tour visiting famous landmarks such as Times Square, Wall Street, Empire State Building, and the exciting Liberty Cruise to see the Statue of Liberty 🚢</p><p>Continue your adventure with shopping at Woodbury Common Premium Outlet before heading to Boston to visit Harvard University and the city’s historic attractions.</p><p>The journey continues to Canada with visits to Montreal, Quebec City, Ottawa, and Toronto, known for their classic atmosphere, iconic landmarks, and stunning autumn scenery 🍁</p><p>One of the highlights of the tour is visiting the magnificent Niagara Falls Canada Side 🌊 before continuing to Washington DC to see the White House, Capitol Hill, and other famous American monuments.</p><p>✧ Liberty Cruise &amp; Statue of Liberty<br>✧ Shopping at Woodbury Outlet<br>✧ Harvard University &amp; Quebec City<br>✧ Niagara Falls Canada Side<br>✧ Washington DC &amp; White House<br>✧ Beautiful USA &amp; Canada Fall Season 🍁</p><p>A perfect combination of city tours, shopping, history, and natural beauty in one memorable journey ✨</p>', '<h3>미국 동부 &amp; 캐나다 가을 시즌 12일 🍁</h3><p>아름다운 가을 시즌 동안 미국과 캐나다의 대표 도시들을 여행하는 특별한 일정입니다 🇺🇸🇨🇦✨</p><p>여행은 뉴욕에서 시작되며, 타임스퀘어, 월스트리트, 엠파이어 스테이트 빌딩, 그리고 자유의 여신상을 가까이에서 볼 수 있는 리버티 크루즈를 즐깁니다 🚢</p><p>이후 우드버리 커먼 프리미엄 아울렛에서 쇼핑을 즐기고, 보스턴으로 이동하여 하버드 대학교와 역사적인 명소들을 방문합니다.</p><p>여행은 캐나다의 몬트리올, 퀘벡시티, 오타와, 토론토로 이어지며, 클래식한 분위기와 아름다운 가을 풍경을 만끽할 수 있습니다 🍁</p><p>하이라이트는 웅장한 나이아가라 폭포 캐나다 사이드 🌊 방문이며, 이어서 워싱턴 DC에서 백악관, 국회의사당, 다양한 미국 대표 기념물을 관광합니다.</p><p>✧ 리버티 크루즈 &amp; 자유의 여신상<br>✧ 우드버리 아울렛 쇼핑<br>✧ 하버드 대학교 &amp; 퀘벡시티<br>✧ 나이아가라 폭포 캐나다 사이드<br>✧ 워싱턴 DC &amp; 백악관<br>✧ 미국 &amp; 캐나다 가을 풍경 🍁</p><p>도시 관광, 쇼핑, 역사, 자연을 모두 즐길 수 있는 특별한 여행입니다 ✨</p>', '<h3>美国东海岸 &amp; 加拿大秋季之旅 12天 🍁</h3><p>在美丽的秋季，开启一场精彩的美国与加拿大经典城市之旅 🇺🇸🇨🇦✨</p><p>旅程从纽约开始，游览时代广场、华尔街、帝国大厦，并搭乘自由女神游船近距离欣赏自由女神像 🚢</p><p>随后前往 Woodbury Common Premium Outlet 享受购物乐趣，再继续前往波士顿，参观著名的哈佛大学及历史城区。</p><p>接着前往加拿大，游览蒙特利尔、魁北克市、渥太华和多伦多，感受经典城市氛围与迷人的秋日景色 🍁</p><p>本次旅程亮点之一是欣赏壮观的尼亚加拉大瀑布加拿大段 🌊，随后前往华盛顿 DC，参观白宫、国会山及美国著名纪念建筑。</p><p>✧ 自由女神游船<br>✧ Woodbury Outlet 购物<br>✧ 哈佛大学 &amp; 魁北克市<br>✧ 尼亚加拉大瀑布加拿大段<br>✧ 华盛顿 DC &amp; 白宫<br>✧ 美国与加拿大秋季美景 🍁</p><p>一次融合城市观光、购物、历史与自然风光的难忘旅程 ✨</p>', 39440000.00, NULL, 12, 7, '[\"21 Oktober - 1 November 2026\"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIHTS:</strong></p><p style=\"text-align:center;\"><strong>NEW YORK – BOSTON – MONTREAL – QUEBEC - TORONTO – NIAGARA FALLS – WASHINGTON DC</strong></p>', '<ul><li data-list-item-id=\"eceecb23dd193cff03a34fb9ad22e15d9\"><p>Internasional Flight by Turkish Airlines or Similar Full board Airlines</p><p>&nbsp;</p></li><li data-list-item-id=\"e5d3c1584fbca5a881970c6d28ca7a357\"><p>Bagasi sesuai dengan ketentuan maskapai + Cabin 7 Kg</p><p>&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eec0405d3a96941cb2a84d4d3593d35c0\"><p>Hotel&nbsp; 3* based on QUAD (<i><strong>Sekamar Berempat</strong></i>)</p><p>&nbsp;</p></li><li data-list-item-id=\"e8fd7075a7091a794c0919c407683fc3a\"><p>Breakfast di Hotel</p><p>&nbsp;</p></li><li data-list-item-id=\"e44fe257a94d7c4f96de5f8f38e817b4b\"><p>FREE LIBERTY CRUISE Senilai Rp.1.000.000,-</p><p>&nbsp;&nbsp;</p></li><li data-list-item-id=\"e9c1ba4c2a80af894c7b5d78dbc49b03b\"><p>Transportasi dengan Private Bus AC</p><p>&nbsp;&nbsp;</p></li><li data-list-item-id=\"e82c5c01f400349df43039842f6570e12\"><p>Tour Leader berpengalaman dari Jakarta</p><p>&nbsp;&nbsp;</p></li><li data-list-item-id=\"e6325c938acda8adb81bd307de43afef2\">Konten video by Tour Leader</li></ul>', '<ul><li data-list-item-id=\"e735d1672d660f743b87484a91c49d46c\"><p>Visa USA &nbsp;: IDR 4.250.000 /Pax (Non Refund)</p><p>&nbsp;</p></li><li data-list-item-id=\"e38bee93e77fa2fd628c6924aa86fe0f9\"><p>Visa Canada : IDR 3.500.000 / Pax (Diurus oleh Welcome Manado Tours)</p><p>&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eb1b535c1068226e87859041cddc49bd3\"><p>Internasional Taxes &amp; Surcharges : IDR 2.950.000/Pax (Wajib)</p><p>&nbsp;</p></li><li data-list-item-id=\"e48903fb1e0ebae9633dfc29436dcf034\"><p>Tipping TL, driver, : IDR 1.975.000 /Pax (Wajib)</p><p>&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e7db968b6aacc64e174e2b56f4a592e34\"><p>Travel Insurance: IDR 1.350.000 /Pax (Wajib)</p><p>&nbsp;</p></li><li data-list-item-id=\"ee869e54a01fa111349fd2afad1478330\"><p>Lunch &amp; Dinner</p><p>&nbsp;</p></li><li data-list-item-id=\"effe214c457089d6845d5b4308a718951\"><p>Optional Tour</p><p>&nbsp;</p></li><li data-list-item-id=\"e2fa66d361d05940262e7ce75c8923458\">Personal Expense</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/cokJEo20jl9YioFWPGphB1r7AN51GJDjofBpQDwJ.pdf', 0, NULL, '2026-05-11 07:11:25', '2026-05-11 08:38:30');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(70, 26, '8D Winter School Holiday Beijing Shanghai With Universal Studio', NULL, '8d-winter-school-holiday-beijing-shanghai-with-universal-studio', '<h3>WINTER SCHOOL HOLIDAY BEIJING – SHANGHAI 8D ❄️ &nbsp;</h3><p>Nikmati liburan musim dingin seru menjelajahi kota-kota terbaik di Tiongkok mulai dari Beijing, Suzhou, Hangzhou, Wuzhen, hingga Shanghai ✨</p><p>Perjalanan dimulai dari Beijing dengan mengunjungi landmark terkenal seperti Temple of Heaven, Tian An Men Square, Wangfujing Street, hingga pengalaman seru bermain di Universal Studios Beijing 🎢</p><p>Petualangan dilanjutkan dengan mengunjungi Juyongguan Great Wall, salah satu keajaiban dunia, serta menikmati kuliner khas Bebek Peking dan wisata belanja di Xiushui Market.</p><p>Perjalanan kemudian berlanjut menggunakan Bullet Train menuju Suzhou, Hangzhou, dan Wuzhen untuk menikmati keindahan kota klasik Tiongkok, West Lake, Hefang Street, serta suasana tradisional Wuzhen Water Town 🏮</p><p>Di Shanghai, Anda akan diajak mengunjungi The Bund, Nanjing Road, serta menikmati suasana modern kota metropolitan terbesar di Tiongkok 🌆</p><p>✧ Universal Studios Beijing 🎡<br>✧ Juyongguan Great Wall 🏯<br>✧ West Lake Hangzhou 🚤<br>✧ Wuzhen Water Town 🏮<br>✧ The Bund &amp; Nanjing Road Shanghai 🌃</p><p>Perjalanan lengkap yang memadukan wisata modern, budaya, sejarah, kuliner, dan keindahan kota klasik Tiongkok dalam satu pengalaman yang berkesan ✨</p>', '<h3>WINTER SCHOOL HOLIDAY BEIJING – SHANGHAI 8D ❄️&nbsp;</h3><p>Enjoy an exciting winter holiday exploring the best cities in China, from Beijing, Suzhou, Hangzhou, Wuzhen, to Shanghai ✨</p><p>The journey begins in Beijing by visiting famous landmarks such as the Temple of Heaven, Tian An Men Square, Wangfujing Street, and experiencing the fun of Universal Studios Beijing 🎢</p><p>The adventure continues with a visit to Juyongguan Great Wall, one of the wonders of the world, while also enjoying the famous Peking Duck cuisine and shopping at Xiushui Market.</p><p>The trip then continues by Bullet Train to Suzhou, Hangzhou, and Wuzhen to experience the beauty of China’s classic cities, including West Lake, Hefang Street, and the traditional atmosphere of Wuzhen Water Town 🏮</p><p>In Shanghai, you will visit The Bund and Nanjing Road while enjoying the modern atmosphere of China’s largest metropolitan city 🌆</p><p>✧ Universal Studios Beijing 🎡<br>✧ Juyongguan Great Wall 🏯<br>✧ West Lake Hangzhou 🚤<br>✧ Wuzhen Water Town 🏮<br>✧ The Bund &amp; Nanjing Road Shanghai 🌃</p><p>A complete journey combining modern attractions, culture, history, cuisine, and the beauty of classic Chinese cities in one unforgettable experience ✨</p>', '<h3>베이징 – 상하이 겨울 방학 여행 8일 ❄️&nbsp;</h3><p>베이징, 쑤저우, 항저우, 우전, 상하이까지 중국 최고의 도시들을 여행하는 특별한 겨울 여행을 즐겨보세요 ✨</p><p>여행은 베이징에서 시작되며, 천단공원, 천안문 광장, 왕푸징 거리 등 유명 관광지를 방문하고 유니버설 스튜디오 베이징에서 신나는 시간을 보냅니다 🎢</p><p>이후 세계적인 명소인 주용관 만리장성을 방문하고, 북경오리 요리와 시우슈이 시장 쇼핑도 즐길 수 있습니다.</p><p>여행은 고속열차를 타고 쑤저우, 항저우, 우전으로 이어지며, 서호, 허팡제 거리, 그리고 전통적인 분위기의 우전 수향마을을 감상합니다 🏮</p><p>상하이에서는 더 번드와 난징루를 방문하며 중국 최대 도시의 현대적인 분위기를 경험합니다 🌆</p><p>✧ 유니버설 스튜디오 베이징 🎡<br>✧ 주용관 만리장성 🏯<br>✧ 항저우 서호 🚤<br>✧ 우전 수향마을 🏮<br>✧ 상하이 더 번드 &amp; 난징루 🌃</p><p>현대 관광, 문화, 역사, 미식, 그리고 중국 전통 도시의 아름다움을 모두 경험할 수 있는 특별한 여행입니다 ✨</p>', '<h3>北京 – 上海冬季假期 8天游 ❄️&nbsp;</h3><p>开启一场精彩的中国冬季之旅，探索北京、苏州、杭州、乌镇以及上海等经典城市 ✨</p><p>旅程从北京开始，游览天坛、天安门广场、王府井大街，并前往北京环球影城体验精彩刺激的游乐设施 🎢</p><p>随后前往居庸关长城，感受世界奇迹的壮丽，同时品尝著名的北京烤鸭，并在秀水市场享受购物乐趣。</p><p>接着搭乘高铁前往苏州、杭州和乌镇，欣赏西湖美景、河坊街，以及充满传统韵味的乌镇水乡 🏮</p><p>在上海，您将游览外滩与南京路，感受中国最大国际都市的现代魅力 🌆</p><p>✧ 北京环球影城 🎡<br>✧ 居庸关长城 🏯<br>✧ 杭州西湖 🚤<br>✧ 乌镇水乡 🏮<br>✧ 上海外滩 &amp; 南京路 🌃</p><p>一次融合现代娱乐、文化历史、美食与中国传统城市风光的精彩旅程 ✨</p>', 16990000.00, NULL, 8, 7, '[\"14 Desember 2026 \",\"15 Desember 2026 \",\"16 Desember 2026 \",\"17 Desember 2026 \",\"18 Desember 2026 \"]', NULL, '<p style=\"text-align:center;\"><strong>HIGHLIGHT:</strong> <strong>TEMPLE OF HEAVEN, TIAN AN MEN SQUARE, JUYONGGUAN GREAT WALL, JINJI LAKE, WUZHEN, THE BUND, UNIVERSAL STUDIO BEIJING&nbsp;</strong></p><p style=\"text-align:center;\"><strong>GUARANTEE BEST PRICE &amp; SERVICE</strong></p>', '<ul><li data-list-item-id=\"eeddab89eff0d3dd6845246cf9923ae49\"><p>Tiket International by Malaysia Airlines, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ee9c4a60ce0e98539dbf7a429c24c3cfa\"><p>Bagasi 30 kg sesuai dengan ketentuan Airlines&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ebe471a237cb72d7ea1d7b90e1f73f0f3\"><p>Akomodasi hotel *3 atau *4 local / similar (Twin / Triple)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ec1d940a346c8bc5718e875fe7a970664\"><p>Transportasi bus Pariwisata &amp; tiket masuk objek wisata&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ee77ffced8f416138ee72ba3fa5bce813\"><p>Acara Tour &amp; makan sesuai program paket tour diatas&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e634dac0c5c1fe3b41b34b534cb1cb2a4\"><p>Mineral Water 01 Botol Perhari</p><p>&nbsp;</p></li><li data-list-item-id=\"e8a2e44a3dd52dcc197b5df9588d49018\"><p>Tour Leader</p><p>&nbsp;</p></li><li data-list-item-id=\"e5e8fe0a92f560333f3b1667007de824b\"><p>Travel Kits (Luggage Tag)</p><p>&nbsp;</p></li><li data-list-item-id=\"e3d9d37853a506e0e1fc1daae1d73d3b6\">Travel Insurance</li></ul>', '<ul><li data-list-item-id=\"ec2853a8ce39fe2f7d6a0304089c51cb0\"><p>Visa Group China Rp 1,000,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e03c1d5a927d7295c8c38b98aaa8a4828\"><p>Visa Single China Rp 1,000,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China) // (masuk dalam Konsulat Jakarta)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e972cd8536bb85adb26b1d0e97ee48675\"><p>Visa Single China Rp 1,200,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China) // (masuk dalam konsulat Surabaya/Medan) Visa Single China Rp 1,300,000 (*Ketentuan dapat berubah sewaktu-waktu dari kedutaan besar China) // (masuk dalam konsulat Bali)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e3cf02e15c7331aa271d9663e70e103d5\"><p>Tipping Tour Leader, Local Guide, Driver: Rp 1,000,000/Pax&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ea17e4ffeb933faf53c1d5cb0794afc8c\"><p>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e9c1bf9232ee0bc795b80e9b61ab2b868\"><p>PCR Test / Rapid Test Antigen Jika dibutuhkan&nbsp;</p><p>&nbsp;</p><p>OPTIONAL: Rental Wifi Portable / SIM card</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/OXLQsY1DgnVGacrwJfBOs2P3DCU6rU9EMZ02S38R.pdf', 0, NULL, '2026-05-12 03:01:56', '2026-05-12 03:36:23'),
(71, 35, '10D Signature Turkiye Cappadocia + Bosphorus Cruise', NULL, '10d-signature-turkiye-cappadocia-bosphorus-cruise', '<h3>TURKEY AUTUMN EXPERIENCE 10D ✨</h3><p>Nikmati perjalanan tak terlupakan menjelajahi Turki dengan perpaduan wisata sejarah, budaya, alam, dan kota-kota ikonik 🌍</p><p>Perjalanan dimulai di Istanbul dengan mengunjungi landmark terkenal seperti Blue Mosque, Hippodrome Square, Topkapi Palace, dan Hagia Sophia yang menampilkan kejayaan sejarah Ottoman 🕌</p><p>Petualangan berlanjut ke Bursa, kota bersejarah yang terkenal dengan Grand Mosque, Tophane Clock Tower, dan Silk Market. Perjalanan kemudian dilanjutkan menuju Kusadasi dan Sirince Village yang terkenal dengan suasana tradisional, kebun anggur, dan produk olive oil 🍇</p><p>Di Pamukkale, nikmati keindahan Natural Park dan Cotton Castle yang terkenal dengan teras travertine putih alami serta pemandian air panasnya yang menakjubkan 🤍</p><p>Perjalanan semakin berkesan saat tiba di Cappadocia, di mana Anda akan menjelajahi lembah dan formasi batu unik seperti Pigeon Valley, Uchisar Castle, Goreme Valley, dan Avanos Village yang terkenal dengan kerajinan pottery khas Turki 🎈</p><p>Sebelum kembali ke tanah air, nikmati pengalaman Bosphorus Cruise di Istanbul sambil menyaksikan panorama indah antara benua Asia dan Eropa, dilanjutkan dengan waktu santai di Ortakoy Village dan Taksim Square 🚢✨</p><p>✧ Blue Mosque &amp; Hagia Sophia 🕌<br>✧ Cotton Castle Pamukkale 🤍<br>✧ Cappadocia &amp; Uchisar Castle 🎈<br>✧ Bosphorus Cruise Istanbul 🚢<br>✧ Bursa &amp; Sirince Village ✨</p><p>Perjalanan lengkap yang memadukan sejarah Ottoman, panorama alam yang menakjubkan, budaya khas Turki, dan kehidupan kota modern dalam satu liburan yang berkesan ✨</p>', '<h3>TURKIYE AUTUMN EXPERIENCE 10D ✨</h3><p>Enjoy an unforgettable journey through Turkey with a perfect combination of history, culture, nature, and iconic cities 🌍</p><p>The journey begins in Istanbul, where you will visit famous landmarks such as the Blue Mosque, Hippodrome Square, Topkapi Palace, and Hagia Sophia, showcasing the rich history of the Ottoman Empire 🕌</p><p>The adventure continues to Bursa, a historic city known for the Grand Mosque, Tophane Clock Tower, and Silk Market. The trip then proceeds to Kusadasi and the charming Sirince Village, famous for its traditional atmosphere, vineyards, and olive oil products 🍇</p><p>In Pamukkale, enjoy the breathtaking scenery of the Natural Park and the famous Cotton Castle, known for its stunning white travertine terraces and natural hot springs 🤍</p><p>The journey becomes even more memorable in Cappadocia, where you will explore unique valleys and rock formations including Pigeon Valley, Uchisar Castle, Goreme Valley, and Avanos Village, famous for its traditional pottery art 🎈</p><p>Before returning home, enjoy a relaxing Bosphorus Cruise in Istanbul while admiring the beautiful scenery between Europe and Asia, followed by free time at Ortakoy Village and Taksim Square 🚢✨</p><p>✧ Blue Mosque &amp; Hagia Sophia 🕌<br>✧ Cotton Castle Pamukkale 🤍<br>✧ Cappadocia &amp; Uchisar Castle 🎈<br>✧ Bosphorus Cruise Istanbul 🚢<br>✧ Bursa &amp; Sirince Village ✨</p><p>A complete journey combining Ottoman history, breathtaking natural landscapes, cultural experiences, and modern city life in one unforgettable holiday ✨</p>', '<h3>TURKEY AUTUMN EXPERIENCE 10D ✨</h3><p>역사, 문화, 자연, 그리고 상징적인 도시들을 함께 즐길 수 있는 특별한 터키 여행을 경험해보세요 🌍</p><p>여행은 이스탄불에서 시작되며, 블루 모스크, 히포드롬 광장, 톱카프 궁전, 아야 소피아 등 오스만 제국의 역사를 느낄 수 있는 대표 명소들을 방문합니다 🕌</p><p>이후 역사적인 도시 부르사로 이동하여 그랜드 모스크, 토파네 시계탑, 실크 마켓을 둘러봅니다. 이어서 전통적인 분위기와 포도밭, 올리브 오일로 유명한 쉬린제 마을과 쿠사다시를 방문합니다 🍇</p><p>파묵칼레에서는 아름다운 자연 경관과 함께 하얀 석회층으로 유명한 코튼 캐슬과 천연 온천을 감상할 수 있습니다 🤍</p><p>카파도키아에서는 피전 밸리, 우치사르 캐슬, 괴레메 밸리, 그리고 전통 도자기로 유명한 아바노스 마을 등 독특한 암석 지형과 계곡을 탐험합니다 🎈</p><p>여행의 마지막에는 이스탄불에서 보스포루스 크루즈를 즐기며 유럽과 아시아를 잇는 아름다운 풍경을 감상하고, 오르타쾨이 빌리지와 탁심 광장에서 자유 시간을 보냅니다 🚢✨</p><p>✧ 블루 모스크 &amp; 아야 소피아 🕌<br>✧ 파묵칼레 코튼 캐슬 🤍<br>✧ 카파도키아 &amp; 우치사르 캐슬 🎈<br>✧ 보스포루스 크루즈 🚢<br>✧ 부르사 &amp; 쉬린제 빌리지 ✨</p><p>오스만 역사, 아름다운 자연, 터키 문화, 현대적인 도시 분위기를 모두 즐길 수 있는 특별한 여행입니다 ✨</p>', '<h3>TURKEY AUTUMN EXPERIENCE 10D ✨</h3><p>开启一段难忘的土耳其之旅，感受历史、文化、自然与经典城市的完美结合 🌍</p><p>旅程从伊斯坦布尔开始，您将参观著名景点如蓝色清真寺、竞技场广场、托普卡帕宫以及圣索菲亚大教堂，感受奥斯曼帝国的辉煌历史 🕌</p><p>随后前往历史名城布尔萨，参观大清真寺、托法内钟楼和丝绸市场。之后继续前往库萨达斯与希林杰村，体验传统村庄氛围、葡萄园以及著名的橄榄油产品 🍇</p><p>在帕姆卡莱，您将欣赏著名的棉花堡与天然温泉，感受独特的白色石灰岩梯田景观 🤍</p><p>旅程的精彩部分还包括卡帕多奇亚，您将探索鸽子谷、乌奇萨城堡、格雷梅山谷以及以传统陶艺闻名的阿瓦诺斯小镇 🎈</p><p>返回伊斯坦布尔后，您将体验博斯普鲁斯海峡游船，欣赏横跨欧洲与亚洲的美丽景色，并在奥塔科伊村和塔克西姆广场自由活动 🚢✨</p><p>✧ 蓝色清真寺 &amp; 圣索菲亚大教堂 🕌<br>✧ 帕姆卡莱棉花堡 🤍<br>✧ 卡帕多奇亚 &amp; 乌奇萨城堡 🎈<br>✧ 博斯普鲁斯海峡游船 🚢<br>✧ 布尔萨 &amp; 希林杰村 ✨</p><p>这是一场融合奥斯曼历史、壮丽自然风光、土耳其文化与现代都市魅力的精彩旅程 ✨</p>', 16990000.00, NULL, 10, 9, '[\"1 Oktober 2026\",\"8 Oktober 2026\",\"22 Oktober 2026\",\"29 Oktober 2026\",\"5 November 2026 \",\"12 November 2026 \",\"19 November 2026 \"]', NULL, '<p style=\"text-align:center;\"><i><strong>HIGHLIGHT: NATURAL PARK – COTTON CASTLE – CAPPADOCIA – UCHISAR CASTLE – BOSPHORUS CRUISE</strong></i></p><p style=\"text-align:center;\"><i><strong>GUARANTEE BEST PRICE &amp; SERVICE&nbsp;</strong></i></p><p><br>&nbsp;</p>', '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed88a6c39ec675dc23cadccb10ac666b2\"><p><strong>Tiket International by Singapore Airlines, Economy termasuk taxes internasional (Tiket Grup Fixed Date &amp; No Extend)&nbsp;</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0bee364c75d3db4d69142ba13483fc8c\"><p><strong>Bagasi 25 kg sesuai dengan ketentuan Airlines</strong></p><p><strong>&nbsp;</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e02daee8d70cc7efeb79c0bfc70d85127\"><p><strong>Akomodasi hotel *4 atau setaraf (Twin / Triple)</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ea6834e945ec7cbb5519579745a68b3a1\"><p><strong>Transportasi bus Pariwisata &amp; tiket masuk objek wisata</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ef55f236502f210ac5f7b359a998b93dc\"><p><strong>Acara Tour &amp; makan sesuai program paket tour diatas</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"edcfa89b4122fdbd677c35cb2bd1ee0c6\"><p><strong>Mineral Water 02 Botol Perhari</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e94b70770979a572cd583b7ed32cafc94\"><p><strong>Travel Kits (Luggage Tag)</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"edf4cd3bf2bcfc314fd234c3b6fd39b87\"><strong>Travel Insurance&nbsp;</strong></li></ul>', '<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"effe66e19efb74128473829b7ea53c681\"><p><strong>Tipping Tour Leader, Local Guide, Driver: Rp. 1.600.000/Pax</strong></p><p>&nbsp;</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed0fb5a3f8ba6e3669450befe2c992597\"><p><strong>Tips Porter Hotel, Mini Bar, Laundry, Telp, Kelebihan bagasi dll.</strong></p><p>&nbsp;</p></li><li data-list-item-id=\"eb8f2dd1ccec604a9f3d82967d09a8f96\"><p><strong>PCR Test / Rapid Test Antigen Jika dibutuhkan</strong><br>&nbsp;</p><p><strong>OPTIONAL:</strong><br><strong>Simcard/Esim&nbsp;</strong><br>&nbsp;</p><p><strong>OPTIONAL TOUR:</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e052a3a3193da976afeccdd6b2fdc4755\"><strong>Hot Air Ballon</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"effda25a5385cb1a035c4fd181b951a9a\"><strong>Jeep Safari</strong></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/8wDAdIlFYBOJpXTf6R1Tok4hk0JWIYBS8oApCPRK.pdf', 0, NULL, '2026-05-12 06:02:23', '2026-05-12 06:57:52'),
(72, 26, '(Starting Manado) 10D9N China Tour Guangzhou - Chongqing - Phoenix Town - Zhangjiajiie', 'GUANGZHOU CHONGQING - PHEONIX TOWN - ZHANGJIAJIE', '10d9n-china-tour', '<h3>GUANGZHOU – CHONGQING – PHOENIX TOWN – ZHANGJIAJIE 10D9N ✨</h3><p>Nikmati pengalaman liburan seru menjelajahi keindahan kota modern, budaya tradisional, hingga panorama alam spektakuler di Tiongkok dalam satu perjalanan lengkap 🌏</p><p>Perjalanan dimulai dengan penerbangan langsung dari Manado menuju Guangzhou bersama China Southern Airlines. Setibanya di China, perjalanan dilanjutkan menuju Chongqing menggunakan Bullet Train untuk menikmati suasana kota metropolitan yang terkenal dengan pemandangan malamnya yang unik.</p><p>Di Chongqing, Anda akan mengunjungi berbagai destinasi populer seperti Jiefangbei Street, Hongya Cave, Liziba Light Railway, hingga Ciqikou Ancient Town. Perjalanan juga dilengkapi dengan pertunjukan spektakuler Chongqing 1949 Show serta menikmati kuliner khas Pipayuan Hotpot 🍲</p><p>Petualangan berlanjut menuju Fenghuang Phoenix Town, kota kuno yang terkenal dengan suasana tradisional dan pemandangan malam yang indah di sepanjang Sungai Tuojiang 🏮</p><p>Highlight utama perjalanan akan membawa Anda menjelajahi keajaiban alam Zhangjiajie National Forest Park, lokasi yang menjadi inspirasi film Avatar 🎬. Nikmati keindahan Tianzi Mountain, Yuanjiajie, Bailong Elevator, Golden Whip Stream, hingga pilihan wisata tambahan Tianmen Mountain dan Glass Plank yang terkenal menegangkan 🌄</p><p>Perjalanan ditutup di Guangzhou dengan city tour santai mengunjungi Yuexiu Park, Five Rams Statue, dan waktu bebas berbelanja di Beijing Road 🛍️</p><p>✧ Zhangjiajie Avatar Mountain 🌄<br>✧ Fenghuang Phoenix Ancient Town 🏮<br>✧ Hongya Cave Chongqing 🌃<br>✧ Tianmen Mountain &amp; Glass Plank ✨<br>✧ Bullet Train Experience China 🚄</p><p>Perpaduan sempurna antara wisata alam, budaya, kota modern, kuliner khas, dan pengalaman bullet train dalam satu perjalanan yang berkesan di Tiongkok ✨</p>', '<h3>GUANGZHOU – CHONGQING – PHOENIX TOWN – ZHANGJIAJIE 10D9N ✨</h3><p>Enjoy an exciting holiday experience exploring the beauty of modern cities, traditional culture, and spectacular natural landscapes across China in one complete journey 🌏</p><p>The trip begins with a direct flight from Manado to Guangzhou with China Southern Airlines. Upon arrival in China, the journey continues to Chongqing by Bullet Train, where you can experience the atmosphere of a vibrant metropolitan city famous for its unique night views.</p><p>In Chongqing, you will visit popular destinations such as Jiefangbei Street, Hongya Cave, Liziba Light Railway, and Ciqikou Ancient Town. The journey is also complemented by the spectacular Chongqing 1949 Show and the chance to enjoy the famous Pipayuan Hotpot 🍲</p><p>The adventure continues to Fenghuang Phoenix Town, an ancient town well known for its traditional atmosphere and beautiful night scenery along the Tuojiang River 🏮</p><p>The main highlight of the trip takes you to explore the wonders of Zhangjiajie National Forest Park, the inspiration behind the movie Avatar 🎬. Enjoy the breathtaking scenery of Tianzi Mountain, Yuanjiajie, Bailong Elevator, Golden Whip Stream, as well as optional tours to Tianmen Mountain and the thrilling Glass Plank 🌄</p><p>The journey ends in Guangzhou with a relaxing city tour visiting Yuexiu Park, Five Rams Statue, and free time shopping at Beijing Road 🛍️</p><p>✧ Zhangjiajie Avatar Mountain 🌄<br>✧ Fenghuang Phoenix Ancient Town 🏮<br>✧ Hongya Cave Chongqing 🌃<br>✧ Tianmen Mountain &amp; Glass Plank ✨<br>✧ China Bullet Train Experience 🚄</p><p>A perfect combination of nature, culture, modern cities, local cuisine, and bullet train experiences in one unforgettable journey across China ✨</p>', '<h3>광저우 – 충칭 – 봉황고성 – 장가계 10일 9박 ✨</h3><p>현대적인 도시, 전통 문화, 그리고 장대한 자연 경관까지 중국의 매력을 한 번에 즐길 수 있는 특별한 여행을 경험해보세요 🌏</p><p>여행은 중국남방항공 직항편으로 마나도에서 광저우까지 이동하며 시작됩니다. 중국 도착 후에는 고속열차를 타고 충칭으로 이동하여 화려한 야경으로 유명한 대도시의 분위기를 느껴볼 수 있습니다.</p><p>충칭에서는 제팡베이 거리, 홍야동, 리즈바 경전철, 츠치커우 고진 등 인기 명소를 방문합니다. 또한 웅장한 충칭 1949 공연 관람과 중국 전통 훠궈인 피파위안 훠궈를 맛볼 수 있습니다 🍲</p><p>이후 아름다운 야경과 전통적인 분위기로 유명한 봉황고성으로 이동하여 투오장 강 주변의 매력을 만끽합니다 🏮</p><p>이번 여행의 하이라이트는 영화 아바타의 배경이 된 장가계 국립삼림공원입니다 🎬. 천자산, 원가계, 바이룽 엘리베이터, 금편계곡의 절경을 감상하며, 선택 관광으로 천문산과 아찔한 유리잔도 체험도 가능합니다 🌄</p><p>마지막으로 광저우에서는 웨슈공원, 오양상 조각상, 베이징루 쇼핑거리 등을 방문하며 여행을 마무리합니다 🛍️</p><p>✧ 장가계 아바타 산 🌄<br>✧ 봉황고성 🏮<br>✧ 충칭 홍야동 🌃<br>✧ 천문산 &amp; 유리잔도 ✨<br>✧ 중국 고속열차 체험 🚄</p><p>자연, 문화, 현대 도시, 현지 음식, 그리고 고속열차 체험까지 모두 담은 잊지 못할 중국 여행입니다 ✨</p>', '<h3>广州 – 重庆 – 凤凰古城 – 张家界 10天9晚 ✨</h3><p>开启一场精彩的中国之旅，一次体验现代城市、传统文化与壮丽自然风景的完美结合 🌏</p><p>旅程从搭乘中国南方航空由万鸦老直飞广州开始。抵达中国后，乘坐高铁前往重庆，感受这座以迷人夜景闻名的现代化山城。</p><p>在重庆，您将游览解放碑步行街、洪崖洞、李子坝轻轨、磁器口古镇等热门景点。同时还能欣赏震撼的《重庆1949》演出，并品尝著名的枇杷园火锅 🍲</p><p>随后前往充满传统风情的凤凰古城，欣赏沱江两岸迷人的夜景与古城氛围 🏮</p><p>旅程最大亮点是探索张家界国家森林公园，这里也是电影《阿凡达》的灵感取景地 🎬。您将欣赏天子山、袁家界、百龙电梯、金鞭溪等壮丽景观，还可选择参加天门山与玻璃栈道等刺激体验 🌄</p><p>最后回到广州，轻松游览越秀公园、五羊石像，并在北京路自由购物 🛍️</p><p>✧ 张家界阿凡达山 🌄<br>✧ 凤凰古城 🏮<br>✧ 重庆洪崖洞 🌃<br>✧ 天门山 &amp; 玻璃栈道 ✨<br>✧ 中国高铁体验 🚄</p><p>一次融合自然风光、传统文化、现代城市、美食与高铁体验的难忘中国之旅 ✨</p>', 21410000.00, NULL, 10, 9, '[\"4-13 Juli 2026\",\"9-18 Juli 2026\",\"11-20 Juli 2026\",\"16-25 Juli 2026\",\"18-27 Juli 2026\",\"1-10 Agustus 2026\",\"20- 29 Agustus 2026\",\"22- 31 Agustus 2026\",\"8-17 Agustus 2026\",\"13 - 22 Agustus 2026\",\"15- 24 Agustus 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"e8779afb23b094111da58f08a468661b6\"><p>Akomodasi &amp; kamar 9 malam berdasarkan twin sharing di hotel Bintang 4 &amp; 5 pilihan dengan sarapan setiap hari</p><p>&nbsp;</p></li><li data-list-item-id=\"e40939ae6d381f7c4167c1c482d9c41a4\"><p>Wisata keliling kota diatas sudah termasuk biaya tiket masuk wisata (Kecuali Tour Tambahan)</p><p>&nbsp;</p></li><li data-list-item-id=\"e0ea3791ccc3dd7eee4e7a9a5c36b6f52\"><p>Personal Tour Guide selama trip (Indonesian/English)</p><p>&nbsp;</p></li><li data-list-item-id=\"e92b8921758b2fa3f3760f5c75c4f3b9d\"><p>Makanan seperti yang tercantum pada itinerary</p><p>&nbsp;</p></li><li data-list-item-id=\"e39a88b1d72057ea6625a440bdfb5d140\"><p>Mengikuti tour 4 toko wajib</p><p>&nbsp;</p></li><li data-list-item-id=\"e17f3feb0215a61cc8ddafd35cb376f19\">Bagasi 20 kg+7 kg Hand Carry/pax</li></ul>', '<ul><li data-list-item-id=\"e166d09874d16b27916348a304d5758b3\"><p>Biaya yang bersifat pribadi seperti panggilan telepon, mini bar, dll</p><p>&nbsp;</p></li><li data-list-item-id=\"e91b2d20adc564644dd7b152ffd323ede\"><p>Tipping Guide: IDR 80.000/pax/hari Tipping Tour Leader: IDR 70.000/pax/hari</p><p>&nbsp;</p></li><li data-list-item-id=\"ee681367cb53e8e3f7869e975fe0b7102\"><p>Asuransi Perjalanan: IDR 320.000/Pax</p><p>&nbsp;</p></li><li data-list-item-id=\"ed6f7b7f22d7071b1ff1d7d7908e7d816\"><p>Single supplement (untuk tambahan kamar sendiri): charge IDR 3.800.000/рах</p><p>&nbsp;</p></li><li data-list-item-id=\"e9e01af418ed13558a9b419d57444365b\"><p>Visa:&nbsp;</p><p>Group Visa: IDR 1.000.000/pax</p><p>Regular Visa (8 hari): IDR 1.300.000/pax</p><p>Express Visa (5 hari): IDR 2.500.000/pax</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/5hGn6mnUCVujpEnaWVpVERMft3iGdNYcurqnTLg8.pdf', 0, NULL, '2026-05-13 01:50:40', '2026-05-13 06:03:47'),
(73, 26, '(Starting Manado) 8D7N China Tour Guangzhou - Shenzen - Hongkong - Macau - Zhuhai', 'GUANGZHOU - SHENZHEN - HONGKONG - MACAU - ZHUHAI', '8d7n-china-tour-guangzhou-shenzen-hongkong-macau-zhuhai', '<h3>GUANGZHOU – SHENZHEN – HONGKONG – MACAU – ZHUHAI 8D7N ✨</h3><p>Nikmati perjalanan seru menjelajahi perpaduan kota modern, budaya, hiburan, dan destinasi ikonik di China, Hongkong, dan Macau dalam satu perjalanan lengkap 🌏</p><p>Perjalanan dimulai dengan penerbangan langsung dari Manado menuju Guangzhou bersama China Southern Airlines. Setibanya di China, Anda akan diajak menikmati city tour di Guangzhou sebelum melanjutkan perjalanan menuju Shenzhen, kota modern yang terkenal dengan perkembangan teknologi dan landmark futuristiknya&nbsp;</p><p>Di Shenzhen, Anda akan mengunjungi berbagai destinasi populer seperti Shenzhen OH Bay Park, Bay Glory Ferris Wheel, Twin Tower, hingga Diwang Building. Perjalanan semakin menarik dengan kesempatan mengikuti optional tour ke Window of The World 🎡</p><p>Petualangan berlanjut menuju Hongkong untuk menikmati suasana kota metropolitan dunia dengan kunjungan ke Victoria Harbour, Avenue of Stars, Golden Bauhinia Square, hingga Victoria Peak Viewing Platform 🌃</p><p>Selanjutnya Anda akan diajak mengunjungi Macau, kota yang terkenal dengan perpaduan budaya Portugis dan modern. Nikmati wisata ke Ruins of St. Paul, The Venetian Casino, Wynn Palace Water Show, hingga suasana romantis kota Macau ✨</p><p>Perjalanan juga dilengkapi dengan kunjungan ke Zhuhai, kota pesisir yang indah dengan landmark seperti Love Post Office Lighthouse, Zhuhai Grand Theater, dan Lovers Road 🏖️</p><p>✧ Victoria Peak Hongkong 🌃<br>✧ Ruins of St. Paul Macau 🏛️<br>✧ Shenzhen OH Bay &amp; Ferris Wheel 🎡<br>✧ The Venetian Macau ✨<br>✧ Guangzhou &amp; Beijing Road Shopping 🛍️</p><p>Perjalanan lengkap yang memadukan wisata modern, budaya, city tour, hiburan, dan pengalaman lintas kota paling populer di China, Hongkong, dan Macau ✨</p>', '<h3>GUANGZHOU – SHENZHEN – HONGKONG – MACAU – ZHUHAI 8D7N ✨</h3><p>Enjoy an exciting journey exploring the perfect combination of modern cities, culture, entertainment, and iconic destinations across China, Hong Kong, and Macau in one complete trip 🌏</p><p>The journey begins with a direct flight from Manado to Guangzhou with China Southern Airlines. Upon arrival in China, you will enjoy a city tour in Guangzhou before continuing to Shenzhen, a modern city famous for its advanced technology and futuristic landmarks.</p><p>In Shenzhen, you will visit popular attractions such as Shenzhen OH Bay Park, Bay Glory Ferris Wheel, Twin Tower, and Diwang Building. The trip becomes even more exciting with an optional tour to Window of the World 🎡</p><p>The adventure continues to Hong Kong, where you will experience the atmosphere of a world-class metropolitan city by visiting Victoria Harbour, Avenue of Stars, Golden Bauhinia Square, and Victoria Peak Viewing Platform 🌃</p><p>Next, you will explore Macau, a city famous for its blend of Portuguese heritage and modern lifestyle. Enjoy visits to the Ruins of St. Paul, The Venetian Casino, Wynn Palace Water Show, and the romantic atmosphere of Macau ✨</p><p>The journey is also completed with a visit to Zhuhai, a beautiful coastal city featuring landmarks such as Love Post Office Lighthouse, Zhuhai Grand Theater, and Lovers Road 🏖️</p><p>✧ Victoria Peak Hong Kong 🌃<br>✧ Ruins of St. Paul Macau 🏛️<br>✧ Shenzhen OH Bay &amp; Ferris Wheel 🎡<br>✧ The Venetian Macau ✨<br>✧ Guangzhou &amp; Beijing Road Shopping 🛍️</p><p>A complete journey combining modern attractions, culture, city tours, entertainment, and unforgettable cross-city experiences across China, Hong Kong, and Macau ✨</p>', '<h3>광저우 – 선전 – 홍콩 – 마카오 – 주하이 8일 7박 ✨</h3><p>중국, 홍콩, 마카오의 현대적인 도시와 문화, 엔터테인먼트, 그리고 대표 명소들을 한 번에 즐길 수 있는 특별한 여행을 만나보세요 🌏</p><p>여행은 중국남방항공 직항편으로 마나도에서 광저우까지 이동하며 시작됩니다. 중국 도착 후 광저우 시티투어를 즐기고, 첨단 기술과 미래적인 랜드마크로 유명한 선전으로 이동합니다.</p><p>선전에서는 OH Bay Park, Bay Glory 대관람차, Twin Tower, Diwang Building 등 인기 명소를 방문합니다. 또한 선택 관광으로 Window of the World도 즐길 수 있습니다 🎡</p><p>이후 홍콩으로 이동하여 Victoria Harbour, Avenue of Stars, Golden Bauhinia Square, Victoria Peak 전망대 등 세계적인 도시의 매력을 경험합니다 🌃</p><p>다음으로 포르투갈 문화와 현대적인 분위기가 조화를 이루는 마카오를 방문합니다. Ruins of St. Paul, The Venetian Casino, Wynn Palace Water Show 등 마카오의 대표 명소를 즐길 수 있습니다 ✨</p><p>여행은 아름다운 해안 도시 주하이 방문으로 이어지며, Love Post Office Lighthouse, Zhuhai Grand Theater, Lovers Road 등을 둘러봅니다 🏖️</p><p>✧ 홍콩 빅토리아 피크 🌃<br>✧ 마카오 세인트폴 성당 유적 🏛️<br>✧ 선전 OH Bay &amp; 대관람차 🎡<br>✧ 더 베네시안 마카오 ✨<br>✧ 광저우 &amp; 베이징로드 쇼핑 🛍️</p><p>현대 도시, 문화, 쇼핑, 엔터테인먼트까지 모두 담은 중국·홍콩·마카오 완벽 여행입니다 ✨</p>', '<h3>广州 – 深圳 – 香港 – 澳门 – 珠海 8天7晚 ✨</h3><p>开启一场精彩旅程，一次畅游中国、香港与澳门的现代都市、文化景点、娱乐体验与经典地标 🌏</p><p>旅程从搭乘中国南方航空由万鸦老直飞广州开始。抵达中国后，首先展开广州城市观光，随后前往以高科技与现代化建筑闻名的深圳。</p><p>在深圳，您将游览深圳OH Bay公园、湾区之光摩天轮、双子塔以及地王大厦等热门景点，还可选择参加世界之窗主题公园的自费行程 🎡</p><p>之后前往国际化都市香港，参观维多利亚港、星光大道、金紫荆广场以及太平山观景台，感受迷人的都市夜景 🌃</p><p>接着来到融合葡萄牙文化与现代风情的澳门，游览大三巴牌坊、威尼斯人度假村、永利皇宫音乐喷泉秀等著名景点 ✨</p><p>旅程还将带您前往美丽的海滨城市珠海，参观爱情邮局灯塔、珠海大剧院以及情侣路等地标景点 🏖️</p><p>✧ 香港太平山夜景 🌃<br>✧ 澳门大三巴牌坊 🏛️<br>✧ 深圳OH Bay &amp; 摩天轮 🎡<br>✧ 澳门威尼斯人 ✨<br>✧ 广州北京路购物 🛍️</p><p>一次融合现代城市、文化、购物、美食与娱乐体验的精彩中国·香港·澳门之旅 ✨</p>', 17710000.00, NULL, 8, 7, '[\"4 - 11 Juli 2026\",\"9 - 16 Juli 2026\",\"11 - 18 Juli 2026\",\"18 - 25 Juli 2026\",\"23 - 30 Juli 2026\",\"25 Juli - 1 Agustus 2026\",\"1 - 8 Agustus 2026\",\"3 -10 Agustus 2026\",\"8 - 15 Agustus 2026\",\"10 - 17 Agustus 2026\",\"13 - 20 Agustus 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"e78dde10b6c60fbe8dfb54734378803f4\"><p>Akomodasi &amp; kamar 7 malam berdasarkan twin sharing di hotel Bintang 4 pilihan dengan sarapan setiap hari</p><p>&nbsp;</p></li><li data-list-item-id=\"e1c894f247671c2792375a4b8b9833fa2\"><p>Wisata keliling kota diatas sudah termasuk biaya tiket masuk wisata (Kecuali Tour Tambahan)</p><p>&nbsp;</p></li><li data-list-item-id=\"eba84374ae578ac3ae08196a16900f659\"><p>Personal Tour Guide selama trip (Indonesian/English)</p><p>&nbsp;</p></li><li data-list-item-id=\"e46f5fde82746e73bde382f92469dcfce\"><p>Makanan seperti yang tercantum pada itinerary</p><p>&nbsp;</p></li><li data-list-item-id=\"eddee799f37d2446c2be8d0ba32f816da\">Bagasi 20 kg+7 kg Hand Carry/pax</li></ul>', '<ul><li data-list-item-id=\"e63866ca7b35fad34026fc746aa38dfca\"><p>Biaya yang bersifat pribadi seperti panggilan telepon, mini bar, dll</p><p>&nbsp;</p></li><li data-list-item-id=\"ee4f9cb09109896182fe6d3634a38a364\"><p>Tipping Guide: IDR 80.000/pax/hari&nbsp;</p><p>Tipping Tour Leader: IDR 70.000/pax/hari</p><p>&nbsp;</p></li><li data-list-item-id=\"e1c3ff6794e12ce01b55bc2e6b7074656\"><p>Asuransi Perjalanan: IDR 320.000/Pax</p><p>&nbsp;</p></li><li data-list-item-id=\"e59aab62669a51cf26eda6db01a9428db\"><p>Single supplement (untuk tambahan kamar sendiri): charge IDR 4.300.000/pax</p><p>&nbsp;</p></li><li data-list-item-id=\"e5f9e2600d383b026082b44a26c5d7643\">Visa Group Visa: IDR 1.000.000/pax&nbsp;</li><li data-list-item-id=\"e6108872a09482e4dff646fd3de9a7e7b\">Regular Visa (8 hari): IDR 1.300.000/pax</li><li data-list-item-id=\"e3f931e8a4d4d2b7639a79083d7a0949c\">Express Visa (5 hari): IDR 2.500.000/pax</li></ul>', '<ul><li data-list-item-id=\"eb61cacea285244ba486563bdc6c54c2b\">SYARAT DAN KETENTUAN Uang muka pendaftaran tidak dapat dikembalikan (down payment non-refundable) + biaya visa (jika ada).</li><li data-list-item-id=\"eaa61723052af629d7b14677a0d866bcf\">Airport fax internasional, Fuel surcharge, biaya visa dan asuransi perjalanan pribadi dapat berubah sewaktu-waktu dan akan disesuaikan kepada peserta sebelum keberangkatan.</li><li data-list-item-id=\"ee9d8b2763928d1b8d7f2f60b73e36036\">Dalam hal aplikasi visa (jika ada), peserta bersedia memenuhı kelengkapan persyaratan dokumen sesuai jadwal dan ketentuan dari pihak Kedutaan, dan biaya visa tetap harus dilunasi walaupun visa tıdak dısetujui oleh pihak Kedutaan.</li><li data-list-item-id=\"e0c8659f05f16a8fb1e375b473f986647\">Group akan diberangkatkan apabila mencapai jumlah minimum peserta.</li><li data-list-item-id=\"e37108e1caf803e565b3d2e7013998e41\">Acara perjalanan dapat berubah / diputar berdasarkan kondisi tiap-tiap penerbangan dan hotel di masing-masing kota / negara. Apabila dalam periode tour di kota-kota yang dikunjungi sedang berlangsung pameran / konferensi, atau hotel yang ditawarkan sedang penuh, maka akan diganti dengan hotel-hotel lain yang setaraf di kota terdekat.</li><li data-list-item-id=\"e098ce17b002063a955ddc5b1ff7d2c4f\">Apabila terjadi force majeure (kondisi diluar kendali seperti: kehilangan, kerusakan, gangguan, keterlambatan sarana angkutan / transportasi, bencana alam dII) yang dapat mempengaruhi acara tour akan diubah dan bersifat non-refundable (tidak dapat dikembalikan). Dan biaya tour tidak termasuk segala pengeluaran tambahan yang disebabkan oleh force majeur.</li><li data-list-item-id=\"e9b3b76cd4b8570b903ff718a7c7972c7\">Untuk keep seat dikenakan IDR 3.000.000/Seat (akan di keep setelah masuk pembayaran).</li><li data-list-item-id=\"ebca8b4cc08fd7925be1ec14f2fc39b49\">Setelah keep seat H+3 diwajibkan membayar 50% dari biaya tour.</li><li data-list-item-id=\"ec0bb7ad9001736775380484f18c5f515\">Pelunasan biaya tour paling lambat 1 bulan sebelum tanggal keberangkatan.</li><li data-list-item-id=\"e5a59730c8565403ca4ccb999b6f36548\">Deviasi akan dikenakan biaya sesuai dengan kondisi airlines yang bersangkutan.</li><li data-list-item-id=\"e64248ec89e1c9c6f1ea3a2707979805e\">Pengunduran diri / pindah tanggal/pindah acara tour sebelum tanggal keberangkatan akan dikenakan biaya pembatalan, sbb :&nbsp;</li><li data-list-item-id=\"ebe44b1eb9135c7d7ded88000f9708f6f\">Setelah pendaftaran: vang muka pendaftaran/ keep seat (non-refundable)&nbsp;</li><li data-list-item-id=\"e153be57edbd88fef5574f2c913166078\">Lebih dari 3 hari setelah Pendaftaran (Keep Seat): 50% dari biaya tour.&nbsp;</li><li data-list-item-id=\"e1c8da7f1df6466f185d911fec90779f3\">Kurang dari 30 hari sebelum keberangkatan: 100% dari biaya tour.</li><li data-list-item-id=\"e3b4b6da7588195b4a9fd45d1e7dd0798\">Dengan membayar uang muka pendaftaran biaya tour, anda dianggap telah memahami dan menerima syarat &amp; kondisi diatas.</li><li data-list-item-id=\"e5f980f268a34c71ff29fb62a3b7614cb\">Harap membawa paspor/identitas lain yang sesuai saat mendaftar, jika terjadı kesalahan / kelalaian, merupakan tanggung jawab tamu sepenuhnya.</li><li data-list-item-id=\"e23fb8ce23abeab61a091f06e26c5d687\">Pembayaran DP harus disertai dengan penyerahan data paspor (foto atau scan) untuk pemesanan tiket.</li></ul>', NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/RcjFiCGuzdsI85Ft9lDUHS4qXF7FzGHEnIIhdQ0m.pdf', 0, NULL, '2026-05-13 02:21:16', '2026-05-13 06:23:56'),
(74, 26, '(Starting Manado) 6D5N Amazing China Tour (Guangzhou-Zhaoging-Shenzhen-Zhuhai)', NULL, '6d5n-amazing-china-tour-guangzhou-zhaoging-shenzhen-zhuhai', '<h3>AMAZING CHINA TOUR 6D5N ✨</h3><p><strong>Guangzhou – Zhaoqing – Shenzhen – Zhuhai</strong></p><p>Nikmati pengalaman liburan seru menjelajahi kota modern, budaya tradisional, hingga destinasi populer di Tiongkok dalam satu perjalanan lengkap 🌏</p><p>Perjalanan dimulai dengan penerbangan langsung dari Manado menuju Guangzhou bersama China Southern Airlines. Setibanya di Guangzhou, Anda akan diajak menikmati suasana kota modern sebelum melanjutkan perjalanan menuju Zhaoqing, kota bersejarah yang terkenal dengan nuansa klasik khas Tiongkok 🏯</p><p>Di Zhaoqing, Anda akan mengunjungi Ancient City Wall, Song Dynasty Qilou Street, Micang Alley, hingga Shibeili Cultural Street yang penuh dengan suasana budaya tradisional dan spot foto menarik ✨</p><p>Perjalanan berlanjut menuju Shenzhen, kota futuristik yang terkenal dengan perkembangan teknologi dan landmark modernnya. Anda akan mengunjungi Shenzhen OH Bay Park, Bay Glory Ferris Wheel, Twin Towers, hingga menikmati suasana kota yang modern dan instagramable 🎡</p><p>Petualangan kemudian dilanjutkan menuju Zhuhai, kota pesisir yang indah dengan suasana santai dan pemandangan laut yang memukau. Nikmati kunjungan ke Zhuhai Haibin Lovers Road, Beishan Courtyard, serta Zhuhai Grand Theater yang menjadi ikon kota 🏖️</p><p>Perjalanan juga dilengkapi dengan pengalaman melewati Shenzhen–Zhongshan Bridge serta waktu bebas untuk menikmati shopping dan optional tour menarik selama perjalanan 🛍️</p><p>✧ Shenzhen OH Bay &amp; Ferris Wheel 🎡<br>✧ Zhuhai Lovers Road 🏖️<br>✧ Zhaoqing Ancient City Wall 🏯<br>✧ Beijing Road Guangzhou 🛍️<br>✧ Shenzhen–Zhongshan Bridge 🌉</p><p>Perpaduan sempurna antara wisata kota modern, budaya tradisional, kuliner, dan pengalaman lintas kota terbaik di Tiongkok dalam satu perjalanan yang berkesan ✨</p>', '<h3>AMAZING CHINA TOUR 6D5N ✨</h3><p><strong>Guangzhou – Zhaoqing – Shenzhen – Zhuhai</strong></p><p>Enjoy an exciting holiday experience exploring modern cities, traditional culture, and popular destinations across China in one complete journey 🌏</p><p>The trip begins with a direct flight from Manado to Guangzhou with China Southern Airlines. Upon arrival, you will experience the modern atmosphere of Guangzhou before continuing to Zhaoqing, a historic city known for its classic Chinese charm 🏯</p><p>In Zhaoqing, you will visit the Ancient City Wall, Song Dynasty Qilou Street, Micang Alley, and Shibeili Cultural Street, filled with traditional culture and beautiful photo spots ✨</p><p>The journey continues to Shenzhen, a futuristic city famous for its advanced technology and modern landmarks. Visit Shenzhen OH Bay Park, Bay Glory Ferris Wheel, Twin Towers, and enjoy the vibrant modern city atmosphere 🎡</p><p>The adventure then continues to Zhuhai, a beautiful coastal city with relaxing scenery and stunning sea views. Enjoy visits to Zhuhai Haibin Lovers Road, Beishan Courtyard, and the iconic Zhuhai Grand Theater 🏖️</p><p>The trip is also completed with the experience of crossing the Shenzhen–Zhongshan Bridge and free time for shopping and optional tours during the journey 🛍️</p><p>✧ Shenzhen OH Bay &amp; Ferris Wheel 🎡<br>✧ Zhuhai Lovers Road 🏖️<br>✧ Zhaoqing Ancient City Wall 🏯<br>✧ Beijing Road Guangzhou 🛍️<br>✧ Shenzhen–Zhongshan Bridge 🌉</p><p>A perfect combination of modern city tours, traditional culture, cuisine, and unforgettable cross-city experiences in China ✨</p>', '<h3>AMAZING CHINA TOUR 6D5N ✨</h3><p><strong>광저우 – 자오칭 – 선전 – 주하이</strong></p><p>중국의 현대 도시, 전통 문화, 인기 관광지를 한 번에 즐길 수 있는 특별한 여행을 만나보세요 🌏</p><p>여행은 중국남방항공 직항편으로 마나도에서 광저우까지 이동하며 시작됩니다. 도착 후 현대적인 도시 광저우를 둘러본 뒤, 중국 전통 분위기가 살아있는 역사 도시 자오칭으로 이동합니다 🏯</p><p>자오칭에서는 Ancient City Wall, Song Dynasty Qilou Street, Micang Alley, Shibeili Cultural Street 등을 방문하며 중국 전통 문화와 아름다운 포토 스팟을 즐길 수 있습니다 ✨</p><p>이후 첨단 기술과 미래적인 도시 풍경으로 유명한 선전으로 이동합니다. Shenzhen OH Bay Park, Bay Glory 대관람차, Twin Towers 등을 방문하며 현대적인 도시 분위기를 만끽합니다 🎡</p><p>여행은 아름다운 해안 도시 주하이로 이어집니다. Zhuhai Haibin Lovers Road, Beishan Courtyard, Zhuhai Grand Theater 등 주하이의 대표 명소를 방문하며 여유로운 시간을 보낼 수 있습니다 🏖️</p><p>또한 Shenzhen–Zhongshan Bridge를 건너는 특별한 경험과 쇼핑 및 선택 관광도 즐길 수 있습니다 🛍️</p><p>✧ 선전 OH Bay &amp; 대관람차 🎡<br>✧ 주하이 Lovers Road 🏖️<br>✧ 자오칭 고대 성벽 🏯<br>✧ 광저우 베이징로드 쇼핑 🛍️<br>✧ 선전–중산 대교 🌉</p><p>현대 도시, 전통 문화, 쇼핑, 미식, 그리고 특별한 도시 간 여행이 어우러진 완벽한 중국 여행입니다 ✨</p>', '<h3>AMAZING CHINA TOUR 6天5晚 ✨</h3><p><strong>广州 – 肇庆 – 深圳 – 珠海</strong></p><p>开启一场精彩的中国之旅，一次畅游现代都市、传统文化与热门景点 🌏</p><p>旅程从搭乘中国南方航空由万鸦老直飞广州开始。抵达后，您将感受广州的现代都市氛围，随后前往拥有浓厚历史文化气息的肇庆 🏯</p><p>在肇庆，您将参观古城墙、宋代骑楼街、米仓巷以及石碑里文化街，感受传统中国文化与独特街景 ✨</p><p>之后前往充满未来感的深圳，这里以高科技与现代建筑闻名。您将游览深圳OH Bay公园、湾区之光摩天轮、双子塔等热门景点 🎡</p><p>旅程随后来到美丽的海滨城市珠海，欣赏情侣路、北山大院以及珠海大剧院等城市地标，感受悠闲浪漫的海滨风情 🏖️</p><p>行程还包含穿越深中大桥的特别体验，以及购物和自费景点自由活动时间 🛍️</p><p>✧ 深圳OH Bay摩天轮 🎡<br>✧ 珠海情侣路 🏖️<br>✧ 肇庆古城墙 🏯<br>✧ 广州北京路步行街 🛍️<br>✧ 深中大桥 🌉</p><p>一次融合现代城市、传统文化、美食、购物与跨城市体验的精彩中国之旅 ✨</p>', 13100000.00, NULL, 1, 0, '[\"4 - 9 Juli 2026\",\"11 - 16 Juli 2026\",\"13 - 18 Juli 2026\",\"18 - 23 Juli 2026\",\"1 - 6 Agustus 2026\",\"8 - 13 Agustus 2026\",\"15 - 20 Agustus 2026\",\"17 - 22 Agustus 2026\",\"22 - 27 Agustus 2026\",\"24 - 29 Agustus 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"e89ffb98caf511b2c607d2a25ec40aaf9\"><p>Akomodasi &amp; kamar 5 malam berdasarkan twin sharing di hotel bintang 4 pilihan dengan sarapan setiap hari</p><p>&nbsp;</p></li><li data-list-item-id=\"e78f880e618c2bd50b2e1415b4535859b\"><p>Wisata keliling kota diatas sudah termasuk biaya tiket masuk wisata (kecuali tour wisata tambahan)</p><p>&nbsp;</p></li><li data-list-item-id=\"e4a57cd88de2c633b1aacb9e3237c976c\"><p>Pemadu wisata pribadi selama perjalanan Bahasa Indonesia/Bahasa inggris</p><p>&nbsp;</p></li><li data-list-item-id=\"e563a33817d0abf8b1d6a0ebda8d65d17\"><p>Makanan seperti yang tercantum di dalam itinerary</p><p>&nbsp;</p></li><li data-list-item-id=\"ead1625b114a693669151e559bf22d7c0\">Bagasi 20kg+7kg hand carr/pax</li></ul>', '<ul><li data-list-item-id=\"e620b68f6309797131e1f6cd74c6982e8\">Biaya yang bersifat pribadi seperti panggilan telepon,mini bar, dll</li><li data-list-item-id=\"e9534b3ab4de2f67afb4eb6938c755398\">p</li><li data-list-item-id=\"e5411917eed5a45922d6766b68d8fdf42\">Asuransi perjalanan: Rp.320.000/pax</li><li data-list-item-id=\"e85bf774d5f00eb3850fa2181b00a5d32\">U</li><li data-list-item-id=\"edd372a91fad008d2318ee31c0df1078a\"><p>Single supplement (jika kamar sendiri) ada biaya tambahan Rp.2.500.000/раx</p><p>&nbsp;</p></li><li data-list-item-id=\"ed28acd192ce6e75888c8c71449baec18\">Visa: Visa Group : Rp.1.000.000/pах&nbsp;</li><li data-list-item-id=\"efdd1773fddbd9f8a5aca3825b9773590\">Visa Regular (8hari): Rp.1.300.000/pax&nbsp;</li><li data-list-item-id=\"e5d71ed4b4a38570f4ed2c03072618297\"><p>Visa Express (5hari) : Rp.2.500.000/pax</p><p>&nbsp;</p></li><li data-list-item-id=\"e55e478494a754652ad25d4519d31ca47\"><p>Tips:&nbsp;</p><p>Tipping guide 80.000/pax/day&nbsp;</p><p>Tipping tour leader 70.000/pax/day</p><p>&nbsp;</p></li></ul>', '<ul><li data-list-item-id=\"eac0f1a712c59920f24816becffc1a12d\"><p>Uang muka pendaftaran tidak dapat dikembalikan (down payment non-refundable) + biaya visa (jika ada).&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ea8b263dbf39b89d5f53c115f5f48a38f\"><p>Airport tax internasional, Fuel surcharge, biaya visa dan asuransi perjalanan pribadi dapat berubah sewaktu-waktu dan akan disesuaikan kepada peserta sebelum keberangkatan.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e5153d2aead6303f92c3f6e971563bc0f\"><p>Dalam hal aplikasi visa (jika ada), peserta bersedia memenuhi kelengkapan persyaratan dokumen sesuai jadwal dan ketentuan dari pihak Kedutaan, dan biaya visa tetap harus dilunasi walaupun visa tidak disetujui oleh pihak Kedutaan.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e7be3e1a417fda7e4634ec8aa7bf80c2d\"><p>Group akan diberangkatkan apabila mencapai jumlah minimum peserta.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e2f167875b9e2a56bcf27f7a425f59ca4\"><p>Acara perjalanan dapat berubah / diputar berdasarkan kondisi tiap-tiap penerbangan dan hotel di masing-masing kota / negara. &nbsp;Apabila dalam periode tour di kota-kota yang dikunjungi sedang berlangsung pameran / konferensi, atau hotel yang ditawarkan sedang penuh, maka akan diganti dengan hotel-hotel lain yang setaraf di kota terdekat.</p><p>&nbsp;</p></li><li data-list-item-id=\"e8f44c5def6efde6073ba40778675e420\"><p>Apabila terjadi force majeure (kondisi diluar kendali seperti: kehilangan, kerusakan,gangguan, keterlambatan sarana angkutan /transportasi, bencana alam dll) yang dapat mempengaruhi acara tour akan diubah dan bersifat non-refundable (tidak dapat dikembalikan). Dan biaya tour tidak termasuk segala pengeluaran tambahan yang disebabkan oleh force majeur.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ef8546338236f08a4ac92cd35d2ed168b\"><p>Untuk keep seat dikenakan RP. 3.000.000/Seat (akan di keep setelah masuk pembayaran).&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"eeed342daf31dcbe63175dc41a2f4b56b\"><p>Pelunasan biaya tour paling lambat 1 bulan sebelum tanggal keberangkatan.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e81a8f2e40ed1aa98c5bbc4bed473183a\"><p>Setelah keep seat H+3 diwajibkan membayar 50% dari biaya tour.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e101d999c6567250e7b3d2665e649c406\"><p>Deviasi akan dikenakan biaya sesuai dengan kondisi airlines yang bersangkutan.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ef4ca5bc1afa2dc55f54a1e695ff05791\"><p>Pengunduran diri / pindah tanggal/ pindah acara tour sebelum tanggal keberangkatan akan dikenakan biaya pembatalan, sbb:&nbsp;</p><p>Setelah pendaftaran: uang muka pendaftaran/keep seat (non-refundable)</p><p>&nbsp;Lebih dari 3 hari setelah Pendaftaran (Keep Seat): 50% dari biaya tour.&nbsp;</p><p>Kurang dari 30 hari sebelum keberangkatan : 100% dari biaya tour.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"eca0f1127dcfb66a19163389696cbc444\"><p>Dengan membayar uang muka pendaftaran biaya tour, anda dianggap telah memahami dan menerima syarat &amp; kondisi diatas.&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ebfa771c15d150d0e32c4754bf2396696\"><p>Harap membawa paspor / identitas lain yang sesuai saat mendaftar, jika terjadi kesalahan/ kelalaian, merupakan tanggung jawab tamu sepenuhnya. 14&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ee4798a64c6a05023e8c04611b8bba2d2\">Pembayaran DP harus disertai dengan penyerahan data paspor (foto atau scan) untuk pemesánan tiket.</li></ul>', NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/nVqk0ecZqw2Bf0G85ofESDNc3Te3EthXWFfhsauT.pdf', 0, NULL, '2026-05-13 02:46:49', '2026-05-13 07:38:38');
INSERT INTO `international_tours` (`id`, `category_id`, `title`, `location`, `slug`, `description`, `description_en`, `description_ko`, `description_zh`, `base_price`, `price_usd`, `duration_days`, `duration_nights`, `departure_periods`, `airline_info`, `highlights`, `inclusions`, `exclusions`, `terms_conditions`, `visa_requirements`, `passport_validity`, `itinerary_pdf_path`, `is_featured`, `featured_badge`, `created_at`, `updated_at`) VALUES
(75, 26, '(Starting Manado) 5D4N China Tour Guangzhou - Zhaoqing - Zhuhai', NULL, '5d4n-china-tour-guangzhou-zhaoqing-zhuhai', '<h3>GUANGZHOU – ZHAOQING – ZHUHAI 5D4N ✨</h3><p>Nikmati perjalanan singkat namun penuh pengalaman menjelajahi kota modern, budaya tradisional, dan destinasi ikonik di Tiongkok 🌏</p><p>Perjalanan dimulai dengan penerbangan langsung dari Manado menuju Guangzhou bersama China Southern Airlines. Setibanya di Guangzhou, Anda akan disambut guide dan diantar menuju hotel untuk beristirahat sebelum memulai petualangan seru keesokan harinya ✈️</p><p>Eksplorasi dimulai di Zhaoqing, kota bersejarah yang terkenal dengan nuansa klasik khas Tiongkok. Anda akan mengunjungi Zhaoqing Ancient City Wall, Song Dynasty Qilou Street, Micang Alley, hingga Shibeili Cultural Street yang penuh dengan budaya tradisional dan spot foto menarik 🏯</p><p>Perjalanan dilanjutkan menuju Zhuhai, kota pesisir modern dengan suasana santai dan pemandangan laut yang indah. Nikmati kunjungan ke Zhuhai Haibin Lovers Road, Fisher Girl Statue, Zhuhai Grand Theater, serta panorama megah HZM Bridge 🌉</p><p>Di Guangzhou, Anda akan menikmati city tour ke Haixinsha Asian Games Park, melihat Canton Tower, serta berbelanja di Beijing Road Pedestrian Street yang terkenal sebagai pusat shopping dan kuliner 🛍️</p><p>Perjalanan juga dilengkapi dengan kunjungan budaya seperti Former Residence of Sun Yat Sen, Silk Cultural Centre, hingga pengalaman optional tour menarik selama perjalanan ✨</p><p>✧ Zhaoqing Ancient City Wall 🏯<br>✧ Zhuhai Lovers Road 🌊<br>✧ Canton Tower Guangzhou 🌃<br>✧ Beijing Road Shopping 🛍️<br>✧ Zhuhai Grand Theater 🎭</p><p>Perpaduan sempurna antara wisata kota modern, budaya tradisional, shopping, dan pemandangan indah Tiongkok dalam satu perjalanan yang berkesan ✨</p>', '<h3>GUANGZHOU – ZHAOQING – ZHUHAI 5D4N ✨</h3><p>Enjoy a short yet exciting journey exploring modern cities, traditional culture, and iconic destinations in China 🌏</p><p>The trip begins with a direct flight from Manado to Guangzhou with China Southern Airlines. Upon arrival, you will be welcomed by a tour guide and transferred to the hotel to rest before starting the exciting adventure the next day ✈️</p><p>The exploration begins in Zhaoqing, a historic city famous for its classic Chinese atmosphere. Visit Zhaoqing Ancient City Wall, Song Dynasty Qilou Street, Micang Alley, and Shibeili Cultural Street filled with traditional culture and beautiful photo spots 🏯</p><p>The journey continues to Zhuhai, a modern coastal city with relaxing vibes and beautiful sea views. Enjoy visits to Zhuhai Haibin Lovers Road, Fisher Girl Statue, Zhuhai Grand Theater, and the stunning view of the HZM Bridge 🌉</p><p>In Guangzhou, enjoy a city tour to Haixinsha Asian Games Park, see the famous Canton Tower, and shop at Beijing Road Pedestrian Street, one of the city’s most popular shopping and culinary destinations 🛍️</p><p>The trip is also complemented with cultural visits such as the Former Residence of Sun Yat Sen, Silk Cultural Centre, and exciting optional tours throughout the journey ✨</p><p>✧ Zhaoqing Ancient City Wall 🏯<br>✧ Zhuhai Lovers Road 🌊<br>✧ Canton Tower Guangzhou 🌃<br>✧ Beijing Road Shopping 🛍️<br>✧ Zhuhai Grand Theater 🎭</p><p>A perfect combination of modern city tours, traditional culture, shopping, and beautiful scenery in one unforgettable China journey ✨</p>', '<h3>광저우 – 자오칭 – 주하이 5D4N ✨</h3><p>중국의 현대 도시, 전통 문화, 그리고 대표 관광지를 함께 즐길 수 있는 특별한 여행을 만나보세요 🌏</p><p>여행은 중국남방항공 직항편으로 마나도에서 광저우까지 이동하며 시작됩니다. 도착 후 가이드의 환영을 받고 호텔로 이동하여 휴식을 취한 뒤 본격적인 여행이 시작됩니다 ✈️</p><p>첫 번째 여행지는 중국 전통 분위기가 가득한 역사 도시 자오칭입니다. 자오칭 고대 성벽, 송나라 시대의 기루 거리(Qilou Street), 미창 골목(Micang Alley), 스베이리 문화거리를 방문하며 전통적인 중국의 매력을 느낄 수 있습니다 🏯</p><p>이후 아름다운 해안 도시 주하이로 이동합니다. 주하이 Lovers Road, Fisher Girl Statue, Zhuhai Grand Theater, 그리고 웅장한 HZM 대교 전망을 감상할 수 있습니다 🌉</p><p>광저우에서는 Haixinsha Asian Games Park, 광저우의 랜드마크 Canton Tower, 그리고 쇼핑과 먹거리로 유명한 Beijing Road 보행자 거리를 방문합니다 🛍️</p><p>또한 손중산 옛 거주지, Silk Cultural Centre 등 문화 관광과 다양한 선택 관광도 함께 즐길 수 있습니다 ✨</p><p>✧ 자오칭 고대 성벽 🏯<br>✧ 주하이 Lovers Road 🌊<br>✧ 광저우 Canton Tower 🌃<br>✧ 베이징로드 쇼핑 🛍️<br>✧ 주하이 대극장 🎭</p><p>현대 도시, 전통 문화, 쇼핑, 아름다운 풍경이 어우러진 특별한 중국 여행입니다 ✨</p>', '<h3>广州 – 肇庆 – 珠海 5天4晚 ✨</h3><p>开启一场轻松又精彩的中国之旅，探索现代城市、传统文化与经典景点 🌏</p><p>旅程从搭乘中国南方航空由万鸦老直飞广州开始。抵达后，导游将热情接待并送往酒店休息，为第二天的精彩行程做好准备 ✈️</p><p>首先前往拥有浓厚历史文化气息的肇庆，参观肇庆古城墙、宋代骑楼街、米仓巷以及石碑里文化街，感受传统中国风情 🏯</p><p>随后前往美丽的海滨城市珠海，游览珠海情侣路、渔女雕像、珠海大剧院，并欣赏港珠澳大桥壮观景色 🌉</p><p>在广州，您将游览海心沙亚运公园、外观广州塔，并前往北京路步行街体验购物与美食 🛍️</p><p>行程还包含孙中山故居、丝绸文化中心等文化景点，以及丰富的自费项目选择 ✨</p><p>✧ 肇庆古城墙 🏯<br>✧ 珠海情侣路 🌊<br>✧ 广州塔 🌃<br>✧ 北京路步行街 🛍️<br>✧ 珠海大剧院 🎭</p><p>一次融合现代城市、传统文化、购物与美丽风景的精彩中国之旅 ✨</p>', 12360000.00, NULL, 5, 4, '[\"2 - 6 Juli 2026\",\"9 -13 Juli 2026\",\"16 - 20 Juli 2026\",\"23 - 27 Juli 2026\",\"6 - 10 Agustus 2026\",\"13 - 17 Agustus 2026\",\"20 - 24 Agustus 2026\",\"27 - 31 Agustus 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"edd48f836ff1a3cedfa772817c4c6fa8e\"><p>Akomodasi &amp; kamar 4 malam berdasarkan twin sharing di hotel Bintang 4 pilihan dengan sarapan setiap hari</p><p>&nbsp;</p></li><li data-list-item-id=\"eda78ddac5ef80b82b45c5eae9c007081\"><p>Wisata keliling kota diatas sudah termasuk biaya tiket masuk wisata (Kecuali Tour Tambahan)</p><p>&nbsp;</p></li><li data-list-item-id=\"e6706ab54f9a33c41c4884480ea526082\"><p>Pemandu wisata pribadi selama perjalanan Bahasa Indonesia/Bahasa Inggris</p><p>&nbsp;</p></li><li data-list-item-id=\"e648478a2655b97326a694415d1091d43\"><p>Makanan seperti yang tercantum di dalam itinerary</p><p>&nbsp;</p></li><li data-list-item-id=\"e86f6b46ca2bae9edb552f0cceaa60ea9\">Bagasi 20 kg+7 kg Hand Carry/pax</li></ul>', '<ul><li data-list-item-id=\"ee381d4bc24ec4a859ba4d6031526fe54\"><p>Biaya yang bersifat pribadi seperti panggilan telepon, mini bar, dll</p><p>&nbsp;</p></li><li data-list-item-id=\"eb3bd988d559a2adc9535f6efb1f23f67\"><p>Tips: Tipping Guide 80.000 / pax / day&nbsp;</p><p>Tipping Tour Leader 70.000 / pax / day</p><p>&nbsp;</p></li><li data-list-item-id=\"e55a10f07510aa24f50033d9263b5299e\"><p>Asuransi Perjalanan: Rp. 150.000/Pax</p><p>&nbsp;</p></li><li data-list-item-id=\"ec53b0ce6cc9b171e72089a62dba665ae\"><p>Single Supplement (Jika kamar sendiri) ada biaya tambahan Rp. 2.000.000/pах</p><p>&nbsp;</p></li><li data-list-item-id=\"ed95629ce96fe3d6f246c1da743c52344\">Visa:&nbsp;</li><li data-list-item-id=\"e96fcdb747af320fa2df5c6bd64bf218b\">Visa Group: Rp.1.000.000/pax</li><li data-list-item-id=\"ec46d709ff6d0b2390cd36dd328d47ae2\">&nbsp;Reguler (8hari) : Rp.1.300.000/pax</li><li data-list-item-id=\"e36deca2db743c93530c51e595d9944a4\">Express Visa (5hari): Rp.2.500.000/pах</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/ZvIpJVlBjG8YFUj1OpuEhx0LEiamKKGDG1mDl6gX.pdf', 0, NULL, '2026-05-13 03:08:29', '2026-05-13 07:30:22'),
(76, 33, 'Summer 15D Balkan, Montenegro, Transylvania + Istanbul', NULL, 'summer-15d-balkan-montenegro-transylvania-istanbul', '<h3>BALKAN – MONTENEGRO – TRANSYLVANIA + ISTANBUL 15D ✨</h3><p>Nikmati perjalanan spektakuler menjelajahi keindahan Eropa Timur dan Balkan dengan perpaduan budaya, sejarah, kota klasik, hingga panorama alam yang menakjubkan 🌍</p><p>Perjalanan dimulai dari Istanbul, Turki, sebelum melanjutkan petualangan melintasi berbagai negara eksotis seperti Greece, Macedonia, Albania, Montenegro, Croatia, Bosnia, Serbia, Bulgaria, hingga Romania ✨</p><p>Anda akan diajak mengunjungi berbagai kota bersejarah dan landmark terkenal mulai dari Kavala dan Thessaloniki di Yunani, Skopje di Macedonia, hingga Ohrid yang terkenal dengan danau cantiknya 🏞️</p><p>Petualangan berlanjut ke Albania dan Montenegro dengan menikmati suasana klasik Tirana serta keindahan Bay of Kotor yang menjadi salah satu teluk terindah di Eropa 🌊</p><p>Di Croatia dan Bosnia, Anda akan menjelajahi kota tua Dubrovnik yang ikonik serta Mostar dengan jembatan bersejarahnya yang terkenal di dunia 🏰</p><p>Perjalanan semakin lengkap dengan kunjungan ke Belgrade di Serbia, kota klasik Sibiu di Romania, hingga Bran Castle di Transylvania yang dikenal sebagai kastil legenda Dracula 🧛</p><p>Wisata ditutup dengan city tour Istanbul yang memadukan budaya Asia dan Eropa melalui kunjungan ke Galata Tower dan Taksim Square ✨</p><p>✧ Bay of Kotor Montenegro 🌊<br>✧ Old Town Dubrovnik Croatia 🏰<br>✧ Bran Castle Transylvania 🧛<br>✧ Ohrid Lake Macedonia 🏞️<br>✧ Istanbul &amp; Taksim Square 🇹🇷</p><p>Perjalanan lengkap melintasi 10 negara dengan pengalaman budaya, sejarah, panorama alam, dan kota-kota klasik Eropa yang tak terlupakan ✨</p>', '<h3>BALKAN – MONTENEGRO – TRANSYLVANIA + ISTANBUL 15D ✨</h3><p>Enjoy an unforgettable journey across Eastern Europe and the Balkans, combining rich culture, history, stunning landscapes, and charming old towns in one spectacular trip 🌍</p><p>The adventure begins in Istanbul, Türkiye, before continuing through several beautiful countries including Greece, Macedonia, Albania, Montenegro, Croatia, Bosnia, Serbia, Bulgaria, and Romania ✨</p><p>You will visit famous historical cities and iconic landmarks such as Kavala and Thessaloniki in Greece, Skopje in Macedonia, and the beautiful Lake Ohrid 🏞️</p><p>The journey continues to Albania and Montenegro, where you will experience the classic atmosphere of Tirana and the breathtaking beauty of the Bay of Kotor, one of Europe’s most stunning bays 🌊</p><p>In Croatia and Bosnia, explore the iconic Old Town Dubrovnik and the famous historic bridge area of Mostar 🏰</p><p>The trip becomes even more memorable with visits to Belgrade in Serbia, the charming city of Sibiu in Romania, and Bran Castle in Transylvania, famously known as Dracula’s Castle 🧛</p><p>The tour concludes with an exciting Istanbul city tour, blending Asian and European cultures through visits to Galata Tower and Taksim Square ✨</p><p>✧ Bay of Kotor Montenegro 🌊<br>✧ Old Town Dubrovnik Croatia 🏰<br>✧ Bran Castle Transylvania 🧛<br>✧ Lake Ohrid Macedonia 🏞️<br>✧ Istanbul &amp; Taksim Square 🇹🇷</p><p>A complete multi-country European journey filled with culture, history, breathtaking scenery, and unforgettable experiences ✨</p>', '<h3>발칸 – 몬테네그로 – 트란실바니아 + 이스탄불 15일 ✨</h3><p>동유럽과 발칸반도의 아름다운 문화, 역사, 자연경관, 그리고 클래식한 도시들을 한 번에 경험할 수 있는 특별한 여행을 만나보세요 🌍</p><p>여행은 터키 이스탄불에서 시작되며, 이후 그리스, 북마케도니아, 알바니아, 몬테네그로, 크로아티아, 보스니아, 세르비아, 불가리아, 루마니아까지 다양한 나라를 여행합니다 ✨</p><p>그리스의 카발라와 테살로니키, 북마케도니아의 스코페와 아름다운 오흐리드 호수 등 유명한 역사 도시와 랜드마크를 방문합니다 🏞️</p><p>알바니아와 몬테네그로에서는 티라나의 전통적인 분위기와 유럽에서 가장 아름다운 만 중 하나인 코토르 베이의 절경을 감상할 수 있습니다 🌊</p><p>크로아티아와 보스니아에서는 세계적으로 유명한 두브로브니크 구시가지와 모스타르의 역사적인 다리를 탐방합니다 🏰</p><p>또한 세르비아의 베오그라드, 루마니아의 아름다운 도시 시비우, 그리고 드라큘라 성으로 유명한 트란실바니아의 브란 성도 방문합니다 🧛</p><p>여행의 마지막은 갈라타 타워와 탁심 광장을 방문하며 아시아와 유럽 문화가 공존하는 이스탄불 시티투어로 마무리됩니다 ✨</p><p>✧ 몬테네그로 코토르 베이 🌊<br>✧ 크로아티아 두브로브니크 구시가지 🏰<br>✧ 트란실바니아 브란 성 🧛<br>✧ 북마케도니아 오흐리드 호수 🏞️<br>✧ 이스탄불 &amp; 탁심 광장 🇹🇷</p><p>문화, 역사, 자연경관이 어우러진 특별한 유럽 다국가 여행입니다 ✨</p>', '<h3>巴尔干 – 黑山 – 特兰西瓦尼亚 + 伊斯坦布尔 15天 ✨</h3><p>开启一场精彩的东欧与巴尔干之旅，感受丰富的文化历史、壮丽自然风光以及迷人的欧洲古城 🌍</p><p>旅程从土耳其伊斯坦布尔开始，随后前往希腊、北马其顿、阿尔巴尼亚、黑山、克罗地亚、波黑、塞尔维亚、保加利亚以及罗马尼亚等多个国家 ✨</p><p>您将游览希腊卡瓦拉与塞萨洛尼基、北马其顿斯科普里以及美丽的奥赫里德湖等著名历史城市与地标 🏞️</p><p>接着前往阿尔巴尼亚与黑山，感受地拉那的传统风情以及欧洲最美海湾之一——科托尔湾的壮丽景色 🌊</p><p>在克罗地亚和波黑，您将探索著名的杜布罗夫尼克古城以及莫斯塔尔历史古桥 🏰</p><p>旅程还将带您前往塞尔维亚贝尔格莱德、罗马尼亚童话般的锡比乌古城，以及著名的德古拉城堡——特兰西瓦尼亚布兰城堡 🧛</p><p>最后以伊斯坦布尔城市观光结束旅程，参观加拉塔塔和塔克西姆广场，感受亚欧文化交融的魅力 ✨</p><p>✧ 黑山科托尔湾 🌊<br>✧ 克罗地亚杜布罗夫尼克古城 🏰<br>✧ 特兰西瓦尼亚布兰城堡 🧛<br>✧ 北马其顿奥赫里德湖 🏞️<br>✧ 伊斯坦布尔 &amp; 塔克西姆广场 🇹🇷</p><p>一次融合文化、历史、自然与经典欧洲古城的难忘多国之旅 ✨</p>', 29350000.00, NULL, 15, 13, '[\"19 Juni \\u2013 3 Juli 2026\",\"27 Juni \\u2013 3 Juli 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"eb29d4bd8432b4d2a1c01e632314af04c\"><p>Tiket internasional : JAKARTA – ISTANBUL | ISTANBUL – JAKARTA By EMIRATES Economy Class (Non Refundable, Non Re-Routeable, Non Endorsable)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e1c390b1d2e5b5125a8d03bac2301474b\"><p>Bagasi sesuai dengan peraturan penerbangan ( 25/30 kg)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e4287aacdfa5d2002d2d6689a9f10a7ba\"><p>Akomodasi Hotel Bintang 3* yang nyaman selama 7 malam ( based on Twin Sharing) Base on availability &amp; confirmations in final itinerary&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e30a7ed7ea38c588a6c7e8e697f7d2289\"><p>Transportasi bus ber AC 49/55 seater&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ee42ba434f50557ed4302872fdd722f5a\"><p>Fuel surcharge, airport tax Jakarta&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e637fe434ade7af6139f4cf4e6ee2eec8\">Tour Leader dari Jakarta</li></ul>', '<ul><li data-list-item-id=\"edda2c9af59db26bf9d1a8c3596ab8eab\"><p>Visa Schengen : 4.000.000/Pax (Non Refund)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e1f7779483d8979806e1be2b536158d53\"><p>Internasional Taxes &amp; Surcharges : Rp 2.850.000/Pax (Wajib) &nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"efe13139006fd32ef5d3837bb3de2b63e\"><p>Tipping TL, driver, : IDR 2.000.000 /Pax (Wajib)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ef42f3fa7e7084196a4856286fd0321c8\"><p>Travel Insurance: IDR 850.000 /Pax (Wajib)&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e5ae055013446b2ce40162e663eeb6088\"><p>City tax : IDR 1.900.000/ pax (Wajib) &nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"eae13b57e5c31de2f46f1413fd4a7805b\"><p>Optional Tour 7. Lunch &amp; Dinner&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"ea0ff0878331505e3663a51eac9cd9afa\"><p>Pengeluaran pribadi : Laundry, phone, minibar, dll&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"e1532a27fc6bf715449830a985da4491c\"><p>Pengurusan dokumen perjalanan : Passpor, Visa, dll&nbsp;</p><p>&nbsp;</p></li><li data-list-item-id=\"eb2a748201d2f6a036c80b3202f0a19c3\">Biaya kelebihan bagasi, Biaya extend</li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage', 0, NULL, '2026-05-13 08:59:28', '2026-05-15 08:10:22'),
(77, 26, '8D6N Beijing Huangshan Wangxiangu Shanghai', NULL, '8d6n-beijing-huangshan-wangxiangu-shanghai', '<h3>BEIJING – HUANGSHAN – WANGXIANGU – HANGZHOU – SHANGHAI 8D6N ✨</h3><p>Nikmati perjalanan seru menjelajahi perpaduan sejarah, budaya klasik, panorama alam, hingga kota modern terbaik di Tiongkok dalam satu perjalanan yang lengkap 🌏</p><p>Perjalanan dimulai dari Surabaya dan Jakarta menuju Beijing dengan Singapore Airlines. Setibanya di Beijing, Anda akan diajak mengunjungi berbagai landmark ikonik seperti Tiananmen Square dan Forbidden City, istana megah yang pernah menjadi tempat tinggal para Kaisar Tiongkok selama ratusan tahun 🏯</p><p>Perjalanan dilanjutkan menuju Huangshan menggunakan Bullet Train untuk menikmati keindahan kota pegunungan yang terkenal dengan panorama alamnya yang luar biasa. Anda juga akan mengunjungi Tunxi Old Street dan Liyang in Lane yang penuh dengan nuansa tradisional khas China kuno ✨</p><p>Di Huangshan, Anda akan menikmati pengalaman menaiki Cable Car menuju pegunungan Huangshan yang terkenal sebagai salah satu gunung terindah di Tiongkok 🌄</p><p>Petualangan berlanjut menuju Shangrao untuk menikmati suasana malam romantis di Wangxian Valley, desa cantik yang terkenal dengan pemandangan lampu malam bak negeri para peri 🏮</p><p>Perjalanan kemudian dilanjutkan ke Hangzhou untuk menikmati keindahan West Lake dengan pengalaman naik perahu sambil menikmati panorama danau yang terkenal sebagai inspirasi para pujangga dan seniman Tiongkok 🚤</p><p>Di Shanghai, Anda akan diajak mengunjungi berbagai destinasi populer seperti Tianzifang, Nanjing Road, The Bund, Wukang Street, Chenghuang Market, hingga Xintiandi yang memadukan suasana modern dan klasik kota metropolitan terbesar di China 🌃</p><p>✧ Forbidden City Beijing 🏯<br>✧ Huangshan Mountain &amp; Cable Car 🌄<br>✧ Wangxian Valley Night View 🏮<br>✧ West Lake Hangzhou 🚤<br>✧ The Bund Shanghai 🌃</p><p>Perjalanan lengkap yang memadukan wisata budaya, sejarah, alam, kuliner, bullet train experience, dan city tour modern dalam satu pengalaman liburan yang berkesan di Tiongkok ✨</p>', '<h3>BEIJING – HUANGSHAN – WANGXIANGU – HANGZHOU – SHANGHAI 8D6N ✨</h3><p>Enjoy an exciting journey exploring the perfect blend of history, traditional culture, breathtaking natural scenery, and modern cities across China in one unforgettable trip 🌏</p><p>The journey begins from Surabaya and Jakarta to Beijing with Singapore Airlines. Upon arrival in Beijing, you will visit iconic landmarks such as Tiananmen Square and the Forbidden City, the magnificent palace that served as the residence of Chinese emperors for centuries 🏯</p><p>The trip continues to Huangshan by Bullet Train, where you can admire the beauty of this mountain city famous for its stunning landscapes. You will also visit Tunxi Old Street and Liyang in Lane, both rich in traditional Chinese atmosphere ✨</p><p>In Huangshan, enjoy the unforgettable experience of riding a Cable Car to the famous Huangshan Mountain, known as one of the most beautiful mountains in China 🌄</p><p>The adventure continues to Shangrao to experience the magical night scenery of Wangxian Valley, a beautiful village known for its fairy-tale atmosphere and glowing night lights 🏮</p><p>The journey then proceeds to Hangzhou, where you will enjoy the beauty of West Lake with a relaxing boat ride surrounded by picturesque scenery that has inspired Chinese poets and artists for centuries 🚤</p><p>In Shanghai, you will explore popular attractions such as Tianzifang, Nanjing Road, The Bund, Wukang Street, Chenghuang Market, and Xintiandi, where modern lifestyle meets classic Chinese architecture 🌃</p><p>✧ Forbidden City Beijing 🏯<br>✧ Huangshan Mountain &amp; Cable Car 🌄<br>✧ Wangxian Valley Night View 🏮<br>✧ West Lake Hangzhou 🚤<br>✧ The Bund Shanghai 🌃</p><p>A complete journey combining culture, history, natural beauty, culinary experiences, bullet train adventures, and modern city tours into one memorable holiday in China ✨</p>', '<h3>베이징 – 황산 – 왕셴구 – 항저우 – 상하이 8일 6박 ✨</h3><p>중국의 역사, 전통 문화, 아름다운 자연경관, 그리고 현대적인 도시를 한 번에 즐길 수 있는 특별한 여행을 만나보세요 🌏</p><p>여행은 싱가포르항공을 이용하여 수라바야와 자카르타에서 베이징으로 출발하며 시작됩니다. 베이징 도착 후에는 천안문 광장과 자금성 등 중국의 대표적인 랜드마크를 방문합니다 🏯</p><p>이후 고속열차를 타고 황산으로 이동하여 아름다운 자연 풍경을 감상합니다. 또한 전통적인 중국 분위기가 가득한 툰시 올드 스트리트와 리양 인 레인을 방문합니다 ✨</p><p>황산에서는 케이블카를 타고 중국에서 가장 아름다운 산 중 하나로 꼽히는 황산의 절경을 감상할 수 있습니다 🌄</p><p>여행은 계속해서 상라오의 왕셴구로 이어지며, 마치 동화 속 마을 같은 아름다운 야경과 전통적인 분위기를 즐길 수 있습니다 🏮</p><p>항저우에서는 아름다운 서호에서 보트를 타며 중국 시인과 예술가들에게 영감을 준 환상적인 풍경을 감상합니다 🚤</p><p>상하이에서는 톈즈팡, 난징루, 와이탄, 우캉루, 청황 시장, 신천지 등 현대와 전통이 조화를 이루는 명소들을 방문합니다 🌃</p><p>✧ 베이징 자금성 🏯<br>✧ 황산 &amp; 케이블카 🌄<br>✧ 왕셴구 야경 🏮<br>✧ 항저우 서호 🚤<br>✧ 상하이 와이탄 🌃</p><p>문화, 역사, 자연, 미식, 고속열차 체험, 그리고 현대 도시 관광이 어우러진 특별한 중국 여행을 경험해보세요 ✨</p>', '<h3>北京 – 黄山 – 望仙谷 – 杭州 – 上海 8天6晚 ✨</h3><p>开启一段精彩难忘的中国之旅，感受历史文化、壮丽自然风光与现代都市魅力的完美结合 🌏</p><p>旅程从泗水和雅加达搭乘新加坡航空飞往北京开始。抵达北京后，您将参观著名景点天安门广场和故宫，这座宏伟的皇宫曾是中国历代皇帝的居所 🏯</p><p>随后乘坐高铁前往黄山，欣赏这座以壮丽山景闻名的城市。您还将游览充满传统中国风情的屯溪老街和黎阳in巷 ✨</p><p>在黄山，您将体验搭乘缆车登上黄山，欣赏中国最著名、最美丽的山岳风景之一 🌄</p><p>接着前往上饶，游览如梦似幻的望仙谷，欣赏宛如仙境般的夜景与灯光 🏮</p><p>随后前往杭州，在西湖乘船游览，感受这片曾激发无数中国诗人与艺术家灵感的美丽湖景 🚤</p><p>在上海，您将游览田子坊、南京路、外滩、武康路、城隍庙以及新天地，体验现代都市与传统文化交融的魅力 🌃</p><p>✧ 北京故宫 🏯<br>✧ 黄山 &amp; 缆车体验 🌄<br>✧ 望仙谷夜景 🏮<br>✧ 杭州西湖 🚤<br>✧ 上海外滩 🌃</p><p>一次融合文化、历史、自然风光、美食、高铁体验与现代都市观光的精彩中国之旅 ✨</p>', 18249000.00, NULL, 8, 6, '[\"5, 10, 14, 17, 21, 24, 28 Juli 2026\",\"4, 7, 12, 15, 18, 21, 28 Agustus 2026\",\"5, 8, 11, 15 September 2026\",\"8, 12, 15, 18, 22, 25 Juli 2026\",\"5, 8, 12, 22, 26 Agustus 2026\",\"2, 6, 12, 16, 17 September 2026\"]', NULL, NULL, '<ul><li data-list-item-id=\"e3ea2be6bda07c7f91b5dfd03f01d5014\"><p style=\"text-align:justify;\">Tiket Ekonomi Singapore Airlines sesuai rute dengan bagasi 25kg/org</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"e124876517b7dacd962b50fb4a5f02af5\"><p style=\"text-align:justify;\">&nbsp;Akomodasi, Makan &amp; Tour sesuai jadwal acara</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eee33e6e5ddd722512d83863e643e5b23\"><p style=\"text-align:justify;\">Tiket masuk lokasi wisata sesuai jadwal acara</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e659658e1abfc62d9ed15f2d142953f1d\"><p style=\"text-align:justify;\">Tiket masuk pertunjukan sesuai jadwal</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"e5460e76a273b3add547055bcefae429a\"><p style=\"text-align:justify;\">Asuransi Perjalanan dari Great Eastern Insurance</p><p style=\"text-align:justify;\">&nbsp;&nbsp;</p></li><li data-list-item-id=\"e332e5c845a5cffae8ec834f956710c7d\"><p style=\"text-align:justify;\">PPn 1%.</p></li></ul>', '<ul><li data-list-item-id=\"ec7be72745baf8d8acc42d7ce619444be\"><p style=\"text-align:justify;\">Biaya pengurusan Visa China</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"eab9f9dadff93d7042844faca5f6f3922\"><p style=\"text-align:justify;\">Tips Guide dan Driver</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"ef1af8f949ee7f6ca11def9af097e94b7\"><p style=\"text-align:justify;\">Pengeluaran Pribadi seperti Mini Bar, Telepon, Laundry dll.</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"ed2ff34a6a9163b97ec741a8d8ef52c1b\"><p style=\"text-align:justify;\">Tips Porter di hotel, airport &amp; statsiun kereta,</p><p style=\"text-align:justify;\">&nbsp;&nbsp;</p></li><li data-list-item-id=\"e0789e669018bc1913732b6f40f453b83\"><p style=\"text-align:justify;\">Tour, Transportasi dan Makan tambahan di luar jadwal acara.</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage', 0, NULL, '2026-05-15 04:06:02', '2026-05-16 01:41:49'),
(78, 26, '8D6N Beijing Universal Studio Shanghai Disneyland', NULL, '8d6n-beijing-universal-studio-shanghai-disneyland', '<h3>BEIJING – SHANGHAI + UNIVERSAL STUDIO &amp; DISNEYLAND 8D6N ✨</h3><p>Nikmati pengalaman liburan seru menjelajahi dua kota terbesar di Tiongkok dengan perpaduan wisata sejarah, budaya modern, taman hiburan kelas dunia, hingga pengalaman bullet train yang berkesan 🌏</p><p>Perjalanan dimulai dari Surabaya dan Jakarta menuju Beijing dengan transit di Singapore menggunakan Singapore Airlines. Setibanya di Beijing, Anda akan diajak mengunjungi berbagai landmark ikonik seperti Tiananmen Square dan Forbidden City, istana megah peninggalan kekaisaran Tiongkok yang telah berdiri selama ratusan tahun 🏯</p><p>Petualangan di Beijing dilanjutkan dengan mengunjungi Juyongguan Great Wall, salah satu bagian terkenal dari Tembok Besar China yang menjadi simbol keagungan Dinasti Ming. Anda juga akan menikmati photo stop di Bird Nest dan Water Cube, ikon Olimpiade Beijing 2008 ✨</p><p>Perjalanan semakin seru dengan kesempatan menikmati Universal Studios Beijing, taman hiburan terbesar Universal Studios di dunia dengan berbagai wahana spektakuler dan area hiburan modern 🎢</p><p>Selanjutnya perjalanan dilanjutkan menuju Shanghai menggunakan Bullet Train untuk menikmati pengalaman kereta cepat modern di Tiongkok 🚄</p><p>Di Shanghai, Anda akan menikmati city tour ke berbagai destinasi populer seperti Nanjing Road, The Bund, Wukang Street, Chenghuang Market, Xintiandi, hingga Zhangyuan Shikumen yang memadukan nuansa modern dan klasik kota metropolitan Shanghai 🌃</p><p>Liburan semakin lengkap dengan kunjungan ke Shanghai Disneyland, tempat terbaik untuk menikmati dunia fantasi Disney dengan berbagai atraksi dan hiburan yang menarik untuk segala usia ✨</p><p>✧ Forbidden City Beijing 🏯<br>✧ Juyongguan Great Wall 🏔️<br>✧ Universal Studios Beijing 🎢<br>✧ Shanghai Disneyland ✨<br>✧ The Bund Shanghai 🌃</p><p>Perjalanan lengkap yang memadukan wisata sejarah, budaya, hiburan modern, shopping, kuliner khas Tiongkok, hingga pengalaman taman hiburan kelas dunia dalam satu liburan tak terlupakan ✨</p>', '<h3>BEIJING – SHANGHAI + UNIVERSAL STUDIO &amp; DISNEYLAND 8D6N ✨</h3><p>Enjoy an exciting holiday exploring two of China’s biggest cities with a perfect combination of history, modern culture, world-class theme parks, and unforgettable bullet train experiences 🌏</p><p>The journey begins from Surabaya and Jakarta to Beijing via Singapore with Singapore Airlines. Upon arrival in Beijing, you will visit iconic landmarks such as Tiananmen Square and the Forbidden City, the magnificent imperial palace that stood as the home of Chinese emperors for centuries 🏯</p><p>Your Beijing adventure continues with a visit to Juyongguan Great Wall, one of the most famous sections of the Great Wall of China and a symbol of the Ming Dynasty’s glory. You will also enjoy photo stops at the Bird’s Nest and Water Cube, the famous landmarks of the 2008 Beijing Olympics ✨</p><p>The trip becomes even more exciting with the opportunity to experience Universal Studios Beijing, the largest Universal Studios theme park in the world, featuring spectacular rides and entertainment 🎢</p><p>The journey then continues to Shanghai by Bullet Train, offering you a chance to experience China’s modern high-speed railway 🚄</p><p>In Shanghai, you will explore popular attractions such as Nanjing Road, The Bund, Wukang Street, Chenghuang Market, Xintiandi, and Zhangyuan Shikumen, where modern lifestyle blends beautifully with classic architecture 🌃</p><p>The holiday is completed with a visit to Shanghai Disneyland, the perfect destination to enjoy the magical world of Disney with attractions and entertainment suitable for all ages ✨</p><p>✧ Forbidden City Beijing 🏯<br>✧ Juyongguan Great Wall 🏔️<br>✧ Universal Studios Beijing 🎢<br>✧ Shanghai Disneyland ✨<br>✧ The Bund Shanghai 🌃</p><p>A complete journey combining history, culture, modern entertainment, shopping, Chinese cuisine, and world-class theme park experiences in one unforgettable vacation ✨</p>', '<h3>베이징 – 상하이 + 유니버설 스튜디오 &amp; 디즈니랜드 8일 6박 ✨</h3><p>중국의 대표적인 두 대도시를 여행하며 역사, 현대 문화, 세계적인 테마파크, 그리고 고속열차 체험까지 즐길 수 있는 특별한 여행을 만나보세요 🌏</p><p>여행은 싱가포르항공을 이용해 수라바야와 자카르타에서 베이징으로 출발하며 시작됩니다. 베이징 도착 후 천안문 광장과 자금성 등 중국을 대표하는 역사 명소를 방문합니다 🏯</p><p>이어지는 일정에서는 만리장성의 유명 구간인 쥐용관 장성을 방문하여 웅장한 역사와 아름다운 풍경을 감상합니다. 또한 2008 베이징 올림픽의 상징인 버드네스트와 워터큐브에서 포토 스톱을 즐깁니다 ✨</p><p>이후 세계 최대 규모의 유니버설 스튜디오인 베이징 유니버설 스튜디오를 방문하여 다양한 어트랙션과 엔터테인먼트를 경험할 수 있습니다 🎢</p><p>다음으로 중국의 현대적인 고속철도인 불릿트레인을 타고 상하이로 이동합니다 🚄</p><p>상하이에서는 난징루, 와이탄, 우캉루, 청황시장, 신천지, 장위안 스쿠먼 등 현대와 전통이 조화를 이루는 명소들을 둘러봅니다 🌃</p><p>여행의 마지막 하이라이트는 상하이 디즈니랜드 방문으로, 남녀노소 모두가 즐길 수 있는 디즈니의 환상적인 세계를 경험할 수 있습니다 ✨</p><p>✧ 베이징 자금성 🏯<br>✧ 쥐용관 만리장성 🏔️<br>✧ 베이징 유니버설 스튜디오 🎢<br>✧ 상하이 디즈니랜드 ✨<br>✧ 상하이 와이탄 🌃</p><p>역사, 문화, 쇼핑, 현대적인 엔터테인먼트, 중국 미식, 그리고 세계적인 테마파크를 모두 즐길 수 있는 잊지 못할 중국 여행입니다 ✨</p>', '<h3>北京 – 上海 + 环球影城 &amp; 迪士尼乐园 8天6晚 ✨</h3><p>开启一段精彩的中国之旅，探索中国两大著名城市，感受历史文化、现代都市、世界级主题乐园以及高铁体验的完美结合 🌏</p><p>旅程从泗水和雅加达出发，搭乘新加坡航空经新加坡转机前往北京。抵达北京后，您将参观著名的天安门广场和故宫，这座宏伟的皇宫曾是中国历代皇帝的居所 🏯</p><p>随后您将前往居庸关长城，这是中国长城最著名的关口之一，也是明朝辉煌历史的象征。您还将参观2008年北京奥运会地标——鸟巢和水立方 ✨</p><p>旅程的精彩部分还包括游览北京环球影城，这是全球最大的环球影城主题乐园，拥有丰富刺激的游乐设施和娱乐项目 🎢</p><p>接着搭乘中国高速列车前往上海，体验现代化高铁之旅 🚄</p><p>在上海，您将游览南京路、外滩、武康路、城隍庙、新天地以及张园石库门等热门景点，感受现代都市与传统建筑相结合的魅力 🌃</p><p>旅程最后，您将前往上海迪士尼乐园，尽情体验梦幻般的迪士尼世界与丰富多彩的娱乐项目 ✨</p><p>✧ 北京故宫 🏯<br>✧ 居庸关长城 🏔️<br>✧ 北京环球影城 🎢<br>✧ 上海迪士尼乐园 ✨<br>✧ 上海外滩 🌃</p><p>一次融合历史、文化、美食、购物、现代娱乐以及世界级主题乐园体验的难忘中国之旅 ✨</p>', 16599000.00, NULL, 8, 6, '[\"12 Juli 2026\",\"25 Juli 2026\"]', NULL, NULL, '<p style=\"text-align:justify;\">&nbsp;</p><ul><li data-list-item-id=\"edf72023d6cc4737b6817d85978a4f19f\"><p style=\"text-align:justify;\">Tiket Ekonomi Singapore Airlines sesuai rute dengan bagasi 25kg/org</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e193a9dac989332c0cd4f6f6b8707d202\"><p style=\"text-align:justify;\">Akomodasi, Makan &amp; Tour sesuai jadwal acara</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"ef786b0e842e34953c3a8cf63d3a6d17b\"><p style=\"text-align:justify;\">Tiket masuk lokasi wisata sesuai jadwal acara</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"ee07033508daefc797f6b7ed7c5ac081e\"><p style=\"text-align:justify;\">Tiket masuk pertunjukan sesuai jadwal</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e7bd16ec45b436a9a6657aed5957151d9\"><p style=\"text-align:justify;\">Asuransi Perjalanan dari Great Eastern Insurance</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"eced73c4ded689b779b3d6d07ce8c12e2\"><p style=\"text-align:justify;\">PPn 1%.</p></li></ul>', '<p style=\"text-align:justify;\">&nbsp;&nbsp;</p><ul><li data-list-item-id=\"eca6a3a34600d1a9d087cb12a209f2ba6\"><p style=\"text-align:justify;\">Biaya pengurusan Visa China</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e0f7a3e039740db39aa3b82a86c396fbd\"><p style=\"text-align:justify;\">Tips Guide &amp; Driver</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"e6ed5aef6df1a77eadc7432db9bbabf38\"><p style=\"text-align:justify;\">Pengeluaran Pribadi seperti Mini Bar, Telepon, Laundry dll.</p><p style=\"text-align:justify;\">&nbsp;</p></li><li data-list-item-id=\"eac15ef93063aad8d222ffc21a8ca8c4b\"><p style=\"text-align:justify;\">Tips Porter di hotel, airport &amp; statsiun kereta,</p><p style=\"text-align:justify;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p></li><li data-list-item-id=\"e7db89927f7b151f612ca5189daeccc41\"><p style=\"text-align:justify;\">Tour, Transportasi dan Makan tambahan di luar jadwal acara.</p></li></ul>', NULL, NULL, NULL, 'https://api.welcomemanado.my.id/storage/tours/international/itineraries/GVC3qRaTid7sD9BYyDPkB0KIY5jftB3KDBPKeSmW.pdf', 0, NULL, '2026-05-15 06:57:58', '2026-05-16 02:04:59');
