(1481, 'App\\Models\\InternationalTour', 46, 5, 'MURMANSK – SAAMI VILLAGE (B)', '<ul><li data-list-item-id=\"e25c8e0f8092bcbebe157a805785bbf8a\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e014c7b7e8e39bbccd2950f4efd95f651\">Di Murmansk anda akan mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e01c9241b80d0cdd33d68a4f8a232e73e\"><strong>Historical Lenin Ice Breaker</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ec2c693337d819f6924c973037f1067cc\"><strong>Saami Village</strong></li></ul></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e9e64f052b778aad9d5c8f9cc289dc49f\"><strong>HUSKY SLEDDING &amp; SNOWMOBILE (Optional)</strong></li><li data-list-item-id=\"ed69a5a4bb9068fddf08d8c07f6327a1b\">Back to Hotel 69 Pararel or Similar (2*)</li></ul>', NULL, NULL, '2026-04-27 06:40:58', '2026-04-27 06:40:58'),
(1482, 'App\\Models\\InternationalTour', 46, 6, 'MURMANSK – ST. PETERSBURG (B)', '<ul><li data-list-item-id=\"e3cb650a702079bf6e34e1e621e8eb95e\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e0be0d88c4dec11fc23260a2cbdb6920a\">Pagi hari Anda akan Check Out Hotel dan akan diantar menuju St. Petersburg by <strong>Domestic Flight (Sudah termasuk Tiket Pesawat Tanpa Bagasi)</strong></li><li data-list-item-id=\"e3addb2e1af20098da83f30d723b5e30f\">Tiba di St. Petersburg</li><li data-list-item-id=\"e2c5ea68ebdbaca33b546da0e6311ab1c\">Mengunjungi Peterhof Palace</li><li data-list-item-id=\"eade05ba21d2b77947f4138f12f3ccad2\">Check in Hotel Ibis St Petersburg Center or Similar (3*)</li></ul>', NULL, NULL, '2026-04-27 06:40:58', '2026-04-27 06:40:58'),
(1483, 'App\\Models\\InternationalTour', 46, 7, 'ST. PETERSBURG (B)', '<ul><li data-list-item-id=\"e2780df6f8572899444d49ccab788625f\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e5387db9e1925bd14a154ca9769c941a4\">Hari ini Anda akan mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e5b66228504e781953cad46e4ab325fda\"><strong>Kazan Cathedral</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e5e30d25a6d6cc34573267063ebf0a8f2\"><strong>Chruch of Savior on Blood</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e136eb4caee3038d754c43e9d9c99edac\"><strong>Hermintage Museum (Exclude Ticket)</strong></li><li data-list-item-id=\"ee5fb347eecab24a9b2480ae58002ae52\">Melewati <strong>Palace Square</strong></li></ul></li><li data-list-item-id=\"e937ae5fd10469a5b51950c90bd8c9305\">Back to Hotel Ibis St Petersburg Center or Similar (3*)</li></ul>', NULL, NULL, '2026-04-27 06:40:58', '2026-04-27 06:40:58'),
(1484, 'App\\Models\\InternationalTour', 46, 8, 'ST. PETERSBURG – MOSCOW (B)', '<ul><li data-list-item-id=\"e9a10b827386bd645d661ade8a79eca63\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"eb5356e323ee2325cf2c1363ac11fc37e\">Mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e7f75dba6c2987c563a80e1186e375715\"><strong>St. Isaac Cathedral</strong></li><li data-list-item-id=\"e7cf2310cc02680db428f0cb74b2b5b66\">Berfoto di <strong>Masjid Biru/ Masjid Soekarno</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0e80a0b1c22125527109c38abb19197f\"><strong>Peter Paul Firtress</strong></li></ul></li><li data-list-item-id=\"eb0fc0e618d3fad2b244d9f89d27e3969\">Selanjutnya anda akan diantar menuju Stasiun untuk perjalanan menuju Moscow (<strong>Sapsan Tarin/ Include Ticket</strong>)</li><li data-list-item-id=\"e84b9c0eb14c4aa371b187920ed7038de\">Tiba di Moscow</li><li data-list-item-id=\"e9f60fa1c34b53bb46fb36a62304b76da\">Check in Hotel Beta Izmailovo or Similar (3*)</li></ul>', NULL, NULL, '2026-04-27 06:40:58', '2026-04-27 06:40:58'),
