(1581, 'App\\Models\\InternationalTour', 48, 11, 'SIBIU – BRAN – BUCHAREST  ( B )', '<ul><li data-list-item-id=\"ef3576e8d5805de4f89f3ccc27916a90d\">Breakfast di Hotel</li><li data-list-item-id=\"e257cb2774454b6b9e7d2680cbdca1241\">Transfer to <strong>Bran Transylvania</strong></li><li data-list-item-id=\"eadabc8f9df26ffd32deb1ede1b78ab8e\">Mengunjungi <strong>Bran Castle</strong></li><li data-list-item-id=\"e5ef6898eed11f2f2cb2bf7b0a98f2964\">Transfer to <strong>Bucharest</strong></li><li data-list-item-id=\"ee9e6615fec7e47a6d80b907e844e94f8\">Mengunjungi <strong>House of People (Gedung Parlement)</strong></li><li data-list-item-id=\"e66b9d29aead8905f5f273b8f10e0f0ee\">&nbsp;Berfoto di <strong>Archul De Triumf</strong></li><li data-list-item-id=\"e1089c31dbb5fd98b5d1bf424d44e7b07\">Mengunjungi <strong>Revolution Square</strong></li><li data-list-item-id=\"edbffa161315f01f7b52a7659aa39b168\">Check in Hotel Hotel : ibis Styles Bucharest City Center or Similar (3*)</li></ul>', NULL, NULL, '2026-04-27 07:49:49', '2026-04-27 07:49:49'),
