(1583, 'App\\Models\\InternationalTour', 48, 13, 'SOFIA – PLOVDIV – ISTANBUL  ( B )', '<ul><li data-list-item-id=\"ee7c9950ab5c1563f708d1918f633219d\">Breakfast di hotel</li><li data-list-item-id=\"e85ad57ce87fd02b35f2de9f1395a863f\">Mengunjungi <strong>Old Town of Plovdiv &amp; Ancient Theatre of Philippopolis</strong></li><li data-list-item-id=\"e00164d1c430dfdca3e1ca8f7d0c0ca91\">Transfer to <strong>Istanbul</strong></li><li data-list-item-id=\"e0f0c90cd2f503fce5fbd3da7e054147d\">Check in Hotel Hotel : Gonen Hotel Istanbul or Similar (4*)</li></ul>', NULL, NULL, '2026-04-27 07:49:49', '2026-04-27 07:49:49'),
(1584, 'App\\Models\\InternationalTour', 48, 14, 'ISTANBUL – TRANSFER TO AIRPORT ( B )', '<ul><li data-list-item-id=\"ea1810cc75b6000569542bca0c240f3ce\">Breakfast di hotel</li><li data-list-item-id=\"e95917a9c3535f876c66b197ad31846a8\">Check out Hotel</li><li data-list-item-id=\"ed1035c5c39b9a8ba7ed06187420c5add\">Berfoto di <strong>Galata Tower</strong></li><li data-list-item-id=\"ecf73ffdf7d29905209e49fa680ecc507\">Mengunjungi <strong>Taksim Square</strong></li><li data-list-item-id=\"e8fec39ffa093d642a0dbdab88bfa6951\">Selanjutnya Anda akan diantar ke Bandara untuk Penerbangan kembali ke Indonesia dan Transit</li></ul>', NULL, NULL, '2026-04-27 07:49:49', '2026-04-27 07:49:49'),
(1585, 'App\\Models\\InternationalTour', 48, 15, 'TIBA DI JAKARTA', '<ul><li data-list-item-id=\"eabff5d729e843867d78f5009136756f6\">Tiba di Jakarta dengan selamat. Semoga bertemu bersama Welcome Manado Tours dalam trip berikutnya.</li></ul><p><br>&nbsp;</p>', NULL, NULL, '2026-04-27 07:49:49', '2026-04-27 07:49:49'),
(1642, 'App\\Models\\InternationalTour', 49, 1, 'JAKARTA – ZURICH', '<ul><li data-list-item-id=\"e4a28e4ec221bc44c4ad3878799001a50\">Berkumpul di Bandara Soekarno Hatta 4 jam sebelum keberangkatan</li><li data-list-item-id=\"edb9acbdb22d876b94b3f512eb2a5acc0\">Check in &amp; bagasi diurus oleh Welcome Manado Tours</li><li data-list-item-id=\"e5e838acb80e34bb9ce40fdad380768f9\">Penerbangan dengan Turkish Airways or Similar Airlines</li><li data-list-item-id=\"e9023acdd67f2f04a6e3a0758ae7ea826\">Makan dan Minum di Pesawat</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1643, 'App\\Models\\InternationalTour', 49, 2, 'ZURICH – RHINE FALLS – TITISEE – MONTREUX', '<ul><li data-list-item-id=\"e9761f0e252022b14e1331ba4aa4b8ab9\">Tiba di Zurich Airport</li><li data-list-item-id=\"ec9b0649f166d6dcc132f69d310c42f41\">Berfoto di <strong>Rhine Falls</strong> (Air terjun terbesar di Eropa)</li><li data-list-item-id=\"eb37229b8ee1a263214bdb3e53d31e36c\">Mengunjungi <strong>Lake Titisee</strong></li><li data-list-item-id=\"e097f4e35e3056820bafd449eea9984bc\">Perjalanan menuju Montreux</li><li data-list-item-id=\"ea114b02b137f7cba303129642d4d2eb1\">Check in Hotel 4*/3* or Similar</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1644, 'App\\Models\\InternationalTour', 49, 3, 'MONTREUX – GENEVA – ANNECY (B)', '<ul><li data-list-item-id=\"e2293dadae4a0203855f5dcfbbd17e1f3\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"ef4e31375aed0d6eec00f7829ae7a22a5\">Di Montreux City Centre Anda akan mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e87978ec07e2f92f35cb708d3549812a4\"><strong>Lake Geneva Promenade</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e62ab80a94e78c7829a8e83443045927b\"><strong>Chilon Castle</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"eb725adb81228aee4e33f68c6b7fbf481\"><strong>Freddie Mercury Statue</strong></li></ul></li><li data-list-item-id=\"ec65eea04744566786fef22950e735d23\"><p>Transfer to Geneva</p><p>Di Geneva Anda akan mengunjungi:</p><ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4507c0d2902260d783234c08e5079893\"><strong>Lake Geneva</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e325ea80a49de5719a5ac2ce9c77aee48\"><strong>The Flower Clock</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e66dfb4142dc22f6d8387ffee5760ea65\"><strong>The Jet d’Eau</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e6e601f6bb3c1bbe41648aaca3c66ecbf\"><strong>Red Cross Building</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e678f871918673f80678601a06fa87141\"><strong>UN PBB Building</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e8cab89d5d8e113d0de42011996c5f227\"><strong>Maison Cailler</strong></li><li data-list-item-id=\"eba90698ac2a24f67dd71cd63418b6751\">Setelahnya Anda akan diantar ke Kota Bern</li><li data-list-item-id=\"e080b79fed45f99e18f8f6b03239bb701\">Di Kota Bern Anda akan mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e378cfb8207faa41065ed52aa3db4231b\"><strong>Bern City Centre</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e8dfc766391ea7d305bbbe7143d9a34b4\"><strong>Sungai Aare</strong></li></ul></li><li data-list-item-id=\"e1c9c8dc71d7fb4f00947219239410fdb\">Check in Hotel 4*/3* or Similar</li></ul></li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1645, 'App\\Models\\InternationalTour', 49, 4, 'ANNECY – CHAMONIX – MONT BLANC (B)', '<ul><li data-list-item-id=\"e14bdf88dc00044453f4294c991d465bc\">Sarapan Pagi di Breakfast</li><li data-list-item-id=\"e5b323f66cfadea13eba6e578581593b3\">Mengunjungi <strong>Lake Annecy</strong></li><li data-list-item-id=\"e58c7514c02cca9d12b004f43d3489447\">Mengunjungi <strong>Jardins de I’Europe</strong></li><li data-list-item-id=\"e685e7fa78cd85afcf17dfc06d1616233\">Mengunjungi <strong>Pont des Amours</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e52fee01a376a7cd14d03b0f3e2350389\"><strong>Chamonix City Centre</strong></li><li data-list-item-id=\"e6f75293aa1819f84e6415bb267ab406f\">Mencoba naik <strong>Toboggan Alpine Coaster di Chamonix (Mont Blanc)</strong></li><li data-list-item-id=\"e747c856cadf7cd8c630a08824c368ee4\">Check in Hotel 4*/3* or Similar</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1646, 'App\\Models\\InternationalTour', 49, 5, 'CHAMONIX – TASCH – ZERMAT – GORNERGRAT – ZERMAT (B)', '<ul><li data-list-item-id=\"ecd833d334f6103cb89d0142f1456993b\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"eabf33d7d42507e596824482cd8dca529\">Hari ini anda akan melakukan perjalanan menuju Zermat dengan <strong>Panoramic Train</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"efba06944c647c9e8487e05de0d55efe4\"><strong>Zermat Village (Car Free)</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e6435ced40225f391b0a822e12f133587\"><strong>Panoramic Train ke Gornergrat (Optional)</strong></li></ul><p>Check in Hotel 4*/3* or Similar</p>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1647, 'App\\Models\\InternationalTour', 49, 6, 'ZERMAT – GRUYERES – BERN (B)', '<ul><li data-list-item-id=\"e7346bf4f649b4fec0a11265501e8363b\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e30e2520671adb4ffb4f87e3d1ab982c5\">Di Gruyeres Anda akan mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"e2761114a6779fd9321fb7d61ae80449b\"><strong>Chateau de Gruyeres</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e80ed7cf80f9fd0f2b4a9b000f8f631ac\"><strong>Pabrik &amp; Museum Keju Gruyere</strong></li></ul></li><li data-list-item-id=\"e522afd27671560ea3ba258502561f074\">Mengunjungi <strong>Bahnhofstrasse</strong></li><li data-list-item-id=\"e5d08f9eda1d9ef9a4c68af402b145f15\">Mengunjungi <strong>Lake Zurich</strong></li><li data-list-item-id=\"e486c9b114bd62c2ed93d633985fd2469\">Check in Hotel 4*/3* or Similar</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1648, 'App\\Models\\InternationalTour', 49, 7, 'BERN – GRINDELWALD – JUNGFRAUJOCH – LAUTERBRUNNEN – ZURICH (B)', '<ul><li data-list-item-id=\"e213faf0e71b863c5365f33363b23c72c\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e551501cf0e053ba13b3c60ab634022e8\">Di Grindelwald Anda akan Mengunjungi :<ul><li class=\"ck-list-marker-bold\" data-list-item-id=\"efeeccd24f9e219964fc571e5a10e4800\"><strong>Grindelwald City Centre</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e3dc90fc9b651deb585ab9ba8c628a1f6\"><strong>Jungfraujoch Top Of Europe (Optional)</strong></li></ul></li><li data-list-item-id=\"ef44cf82dbb40ef8b4cafb7941ef7eb8f\">Selanjutnya Anda akan menuju Lauterbrunnen</li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e4c229ae5b42b77c17f8e19df50296725\"><strong>Lauterbrunnen Village &amp; City Centre</strong></li><li data-list-item-id=\"efa8cb489eff376bb8595d9bbabbdeaf1\">Check in Hotel 4*/3* or Similar Check in Hotel</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1649, 'App\\Models\\InternationalTour', 49, 8, 'ZURICH – LUCERNE – ZURICH (B)', '<ul><li data-list-item-id=\"eba2cd8cf9ec8fbff6df6269d3c0edc01\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"eae215912e5f2525ef9eb2cf7a818591d\">Hari ini Anda Mengunjungi <strong>Chapel Bridge</strong></li><li data-list-item-id=\"ec43fd014abecc489dae82828837d5535\">Mengunjungi <strong>Lucerne City Centre</strong></li><li data-list-item-id=\"e20def197e4dbf444c8f3cb45369b3bcf\">Mengunjungi <strong>Lake Lucerne</strong></li><li data-list-item-id=\"e420df5063f0464cb5e7132f8b431c410\">Selanjutnya Anda akan menuju Zurich</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1650, 'App\\Models\\InternationalTour', 49, 9, 'ZURICH - LUGANO - MILAN (B)', '<ul><li data-list-item-id=\"ecab4339756498b2dde11129351339f20\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e31dff308fcc61e78c56c553b6738d612\">Mengunjungi <strong>Lugano City Centre</strong></li><li data-list-item-id=\"e5daa6f6f2abfdd098d4db003e9608bad\">Mengunjungi <strong>Lake Lugano</strong></li><li data-list-item-id=\"e26a4c6a05bc4aacfe7955f235dfa1e29\">Perjalanan menuju Milan</li><li data-list-item-id=\"e2e1370ae38cb1ec57f826fc1dde6e4bd\">Mengunjungi <strong>Duomo di Milano</strong></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e2d35b4fba8ae249f287e833730d05955\"><strong>Mengunjungi Galleria Vittorio Emanuele II</strong></li></ul><p>Check in Hotel 4*/3* or Similar</p>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1651, 'App\\Models\\InternationalTour', 49, 10, 'MILAN - JAKARTA', '<ul><li data-list-item-id=\"ef1e9b5f1325d0594e0fea03c1c77feb1\">Sarapan Pagi di Hotel</li><li data-list-item-id=\"e03f5746c2827d3df2a57a927422cd8ec\">Pagi hari ini Anda check out dan akan diantar ke Bandara untuk Penerbangan kembali ke Indonesia</li></ul>', NULL, NULL, '2026-04-27 08:44:34', '2026-04-27 08:44:34'),
(1670, 'App\\Models\\InternationalTour', 37, 1, 'JAKARTA – INCHEON (MEALS ON BOARD)', '<p>Malam ini kita berkumpul di Bandara Soekarno-Hatta terminal 3 Ultimate untuk berangkat menuju ke Incheon Maskapai bintang 5 versi Skytrax.</p><p>Bermalam di pesawat</p>', NULL, NULL, '2026-04-27 08:57:43', '2026-04-27 08:57:43'),
(1671, 'App\\Models\\InternationalTour', 37, 2, 'INCHEON – NAMI ISLAND – MT SORAK (MAKAN PAGI DI PESAWAT, MAKAN SIANG, MAKAN MALAM)', '<p>Setiba di Incheon disambut Guide berbahasa Indonesia yang ramah kemudian kita akan langsung mengunjungi Pocheon Bidulginang Falls atau Ski Resort (Tidak termasuk perlengkapan dan pakaian ski pada periode Desember-Februari). Dilanjutkan menuju Nami Island yang merupakan tempat syuting “Winter Sonata” serial drama Korea yang mendunia. Dilanjutkan menuju Mt Sorak. Check in hotel istirahat.</p><p>Bermalam di hotel/Condotel setaraf *** area Gangwon</p>', NULL, NULL, '2026-04-27 08:57:43', '2026-04-27 08:57:43'),
(1672, 'App\\Models\\InternationalTour', 37, 3, 'MT SORAK – SEOUL (MAKAN PAGI, MAKAN SIANG)', '<p>Sarapan pagi di hotel. Lalu kita akan tour menuju Gunung Sorak mengunjungi Gwongeumseong Fortress Hill (termasuk cable car), Great Bronze Buddha Statue, Sinheungsa Temple. Setelah selesai kita akan diberi kesempatan untuk mengetahui proses pembuatan rumput laut dan langsung mencicipinya, kita juga akan belajar membuat kimbap, Melewati Cheonggyecheon Stream, Dilanjutkan shopping di Dongdaemun.</p><p>Bermalam di Hotel setaraf ***</p>', NULL, NULL, '2026-04-27 08:57:43', '2026-04-27 08:57:43'),
(1673, 'App\\Models\\InternationalTour', 37, 4, 'SEOUL CITY TOUR (MAKAN PAGI, MAKAN SIANG)', '<p>Sarapan pagi di hotel, hari ini kita akan memiliki kesempatan mengunjungi pusat kosmetik local Korea. Hari ini kita juga akan mengunjungi Eunpyeong Hanok Village. Selanjutnya kita mengunjungi Itaewon Mosque dan dapat shalat sejenak di masjid terkenal di Korea, bagi yang non-Muslim dapat berjalan-jalan di jalanan Itaewon yang sangat terkenal pada drama “Itaewon Class”. Setelah itu bagi penggemar K-Pop kita akan mengunjungi pusat K-Pop, yaitu COEX Mall, disini kita dapat menikmari panorama perpustakaan di dalam mall yang banyak di kita lihat di film drama korea, Starfield Library dan Gangnam Style Statue. Di malam hari kita akan berbelanja di Hongdae Youth Avenue.</p><p>Bermalam di Hotel *** / similar</p>', NULL, NULL, '2026-04-27 08:57:44', '2026-04-27 08:57:44'),
(1674, 'App\\Models\\InternationalTour', 37, 5, 'SEOUL CITY TOUR (MAKAN PAGI, MAKAN SIANG)', '<p>Sarapan pagi di hotel, kita akan melewati Blue House, kemudian mengunjungi dan akan mencoba menggunakan Hanbok (Baju tradisional korea) di Gyeongbok Palace. Hari ini juga kita akan shopping tour di Amethyst Showcase, Ginseng Center,, Red Pine Shop, Duty Free Shop, hari ini juga kita dapat mengunjungi ikon kota Seoul N Seoul Tower &amp; Love Lock disini ada dapat meletakkan gembok cinta anda disini dan Pshopping di Myeongdong Street.</p><p>Bermalam di Hotel *** / similar</p>', NULL, NULL, '2026-04-27 08:57:44', '2026-04-27 08:57:44'),
(1675, 'App\\Models\\InternationalTour', 37, 6, 'SEOUL – JAKARTA (MAKAN PAGI, MEALS ON BOARD)', '<p>Sarapan pagi, lalu mengunjungi Local Supermarket untuk berbelanja oleh-oleh sebelum ke Incheon Airport. Tiba waktunya diantar ke Airport untuk kembali ke Jakarta, dan sampai jumpa di tour selanjutnya bersama kami.</p>', NULL, NULL, '2026-04-27 08:57:44', '2026-04-27 08:57:44'),
(1888, 'App\\Models\\InternationalTour', 50, 1, 'JAKARTA - SYDNEY', '<p style=\"text-align:justify;\">Malam ini kita berkumpul di Bandara Soekarno-Hatta terminal 3 Ultimate untuk berangkat menuju ke Incheon dengan Maskapai bintang 5 versi Skytrax dengan penerbangan langsung.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel</i>***/similar</p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1889, 'App\\Models\\InternationalTour', 50, 2, 'SYDNEY CITY TOUR', '<p style=\"text-align:justify;\">Setiba di Sydney, Australia, kita akan ke mengunjungi <i>Icon </i>dari Kota Sydney<i>, <strong>Sydney Opera House</strong></i><strong>, </strong>gedung serbaguna yang digunakan untuk Kegiatan seni dengan arsitektur terkenal dari abad 20. Kemudian kita akan berkeliling menuju <i><strong>The Rocks &amp; Circular Quay</strong></i><strong>, </strong>kawasan<strong> </strong>area di bawah jembatan <i><strong>Sydney Harbor Bridge</strong></i><strong> </strong>yang terletak di pinggir Pelabuhan Sydney yang terkenal dengan perbelanjaan fashion dan makanan. Dilanjutkan dengan kunjungan ke <i><strong>Royal Botanical Garden</strong></i><strong> </strong>dan <i><strong>Mrs. Macquarie’s Chair</strong></i><strong>, </strong>sebuah bangku yang diukir dari batu oleh para tahanan di zaman itu sebagai sebuah peringatan dari Pemimpin Australia saat itu untuk istrinya. Di Perjalanan menuju <i><strong>Bondi Beach</strong></i><strong>, </strong>kita akan menuju <i><strong>The Gap</strong></i><strong>, </strong>sebuah Jurang yang terbentuk secara alami dengan pemandangan Laut yang indah. Malam hari kita menuju <i><strong>QVB Mall.</strong></i><strong> </strong><i>Check in hotel</i> dan istirahat.&nbsp;</p><p><i>Bermalam di Hotel</i>***/similar</p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1890, 'App\\Models\\InternationalTour', 50, 3, 'SYDNEY FREE DAY (MAKAN PAGI)', '<p style=\"text-align:justify;\">Sarapan pagi di Hotel, kita mendapatkan waktu bebas untuk <i>explore </i>Kota Sydney seharian<i><strong>.</strong></i><strong> </strong>Kembali ke<i> </i>hotel dan istirahat<strong>.&nbsp;(</strong><i><strong>No Guide, No Transport, No Tour Leader)</strong></i></p><p style=\"text-align:justify;\"><i>Bermalam di Hotel</i>***/similar</p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1891, 'App\\Models\\InternationalTour', 50, 4, 'SYDNEY - MELBOURNE (MAKAN PAGI)', '<p style=\"text-align:justify;\"><strong>DOMESTIC FLIGHT</strong></p><p style=\"text-align:justify;\">Sarapan pagi dengan <i>Box Meal, </i>Kita <i>Check-out </i>Hotel dan menuju <i>Airport </i>untuk penerbangan menuju <strong>Kota Melbourne</strong><i>. </i>Setibanya di Melbourne, kita menuju <i><strong>Parliament House Melbourne</strong></i><strong> </strong>(<i>Photostop), <strong>St. Patrick Cathedral</strong></i><strong> </strong><i>(Photostop), <strong>Fitzroy Garden</strong></i><strong>, </strong>sebuah taman seluas 26 Hektar yang dibuat dengan desain era Ratu Victoria. Sore hari kita menuju <i><strong>Shrine of Remembrance</strong></i><strong>, </strong>sebuah monumen pahlawan dengan gaya arsitektur Yunani dan digunakan untuk memperingati dan menghormati para pahlawan yang gugur di Perang Dunia I, tapi sekarang digunakan untuk mengenang pahlawan di semua medan perang yang pernah ada. Setelah itu kita menuju <i><strong>St. Kilda Beach</strong></i><strong> </strong>untuk menikmati suasana pantai dan dapat melihat kumpulin Pondok warna warni di pantainya. <i>Check-in</i> hotel dan istirahat</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel</i>***/similar</p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1892, 'App\\Models\\InternationalTour', 50, 5, 'MELBOURNE CITY TOUR (MAKAN PAGI)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, kita akan mengunjungi <i>Queen Victoria Market</i> untuk melihat suasana pasar dan berbelanja. Dilanjutkan dengan kunjungan menuju <i>Islamic Council of Victoria</i>. Kemudian kita akan menuju <i>Moonlit Sanctuary,</i> disini kita dapat melihat Kangguru dan Koala, Binatang asli khas Australia. Dilanjutkan dengan perjalanan menuju <i>The Nobbies</i>, tempat yang berada di ujung tebing pantai dan digunakan untuk mengamati koloni Anjing Laut oleh para pengamat. Disini kita juga dapat menikmati ‘<i>Penguin Parade’. </i>Kembali ke hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel</i> setaraf ***</p><p style=\"text-align:justify;\"><i>(Jika tiket Phillip Island habis saat group closing, maka dapat digantikan dengan Sovereign Hill atau Great Ocean atau lainnya, sesuai dengan kebijakan penyelenggara yang diumumkan saat final confirmation, dan tidak bisa diganggu gugat)&nbsp;</i></p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1893, 'App\\Models\\InternationalTour', 50, 6, 'MELBOURNE FREE DAY (MAKAN PAGI)', '<p style=\"text-align:justify;\">Sarapan pagi di Hotel, kita mendapatkan waktu bebas untuk <i>explore </i>Kota Melbourne seharian<i>.</i> Kembali ke<i> </i>hotel dan istirahat.&nbsp;(<i>No Guide, No Transport, No Tour Leader)</i></p><p style=\"text-align:justify;\"><i><strong>Bermalam di Hotel</strong></i><strong> setaraf ***</strong></p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(1894, 'App\\Models\\InternationalTour', 50, 7, 'MELBOURNE – DEPARTURE (MAKAN PAGI)', '<p style=\"text-align:justify;\">Sarapan Pagi di Hotel, tiba waktunya diantar ke Airport untuk kembali ke Jakarta. Berakhirlah tour yang berkesan ini dan sampai jumpa di tour selanjutnya bersama kami.</p>', NULL, NULL, '2026-04-28 05:35:36', '2026-04-28 05:35:36'),
(2086, 'App\\Models\\InternationalTour', 54, 1, 'JAKARTA – HONGKONG - SHENZHEN (MAKAN MALAM)', '<p style=\"text-align:justify;\">Pagi ini kita berkumpul di <strong>Bandara Soekarno-Hatta terminal 3 Ultimate</strong> untuk berangkat menuju ke <strong>Hongkong</strong> dengan <strong>Malaysia Airlines</strong>. Setiba <strong>di Bandara Chek Lap Kok</strong>, <strong>Hongkong</strong>, kita disambut oleh Guide berbahasa Indonesia yang ramah, Kita akan mengunjungi <strong>Victoria Peak </strong>dengan bus, untuk menikmati panorama kota dari ketinggian. Kemudian menuju <strong>Golden Bauhinia Square</strong>, lokasi favorit untuk berfoto dengan latar pelabuhan yang indah. Setelah itu itu kita berkesempatan mengunjungi <strong>Avenue of Star </strong>yang merupakan area tempat penghormatan kepada para seniman &amp; selebritas Hong Kong. Kemudian, kita akan menuju <strong>TST</strong> <strong>Clock Tower</strong>. Perjalanan menuju Shenzhen, check-in hotel dan istirahat.</p><p><i>Menginap di hotel *4 Lokal atau *3 setaraf</i></p>', NULL, NULL, '2026-04-28 09:02:31', '2026-04-28 09:02:31'),
(2087, 'App\\Models\\InternationalTour', 54, 2, 'SHENZHEN - GUANGZHOU (MAKAN PAGI, MAKAN SIANG)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel. Kita akan menuju ke <strong>Jade Shop</strong>, dan juga <strong>Herbs</strong> <strong>Shop</strong>. Photo stop di <strong>Civic Center. </strong>Kemudian mengunjungi <strong>Melania Town</strong>, kawasan wisata bernuansa Eropa. Setelah itu melanjutkan perjalanan menuju Guangzhou, dan mengunjungi <strong>Haixinsha Square Asian Games Park</strong>, kawasan modern yang menjadi lokasi pembukaan Asian Games 2010, dengan pemandangan indah Sungai Pearl. Menuju <strong>Huacheng Square</strong>, alun-alun modern yang menjadi pusat kota baru dan dikelilingi bangunan-bangunan ikonik Guangzhou. Check-in hotel istirahat.</p><p><i>Menginap di hotel *4 Lokal atau *3 setaraf</i></p>', NULL, NULL, '2026-04-28 09:02:31', '2026-04-28 09:02:31'),
(2088, 'App\\Models\\InternationalTour', 54, 3, 'GUANGZHOU – FOSHAN – ZHUHAI (MAKAN PAGI, MAKAN SIANG)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel. Hari ini kita akan mengunjungi <strong>Yuexiu Park</strong>, taman terbesar di kota dengan suasana hijau yang asri. Kemudian kita akan menuju Foshan dengan bus, mengunjungi <strong>Ancestral Temple</strong>, dan <strong>Huang Fei Hong Memorial Hall</strong>, tempat yang didedikasikan untuk legenda bela diri Tiongkok Huang Feihong. Kita juga akan mengunjungi <strong>Grand Arch</strong>, dan <strong>Fengjian Water Town</strong>, desa air tradisional dengan kanal-kanal tenang, jembatan batu kuno, dan suasana klasik yang memberikan pengalaman seperti kembali ke masa lalu. Terakhir, kita menuju Zhuhai dengan bus, check-in hotel dan istirahat.</p><p><i>Menginap di hotel *4 Lokal atau *3 setaraf</i></p><p style=\"text-align:justify;\">&nbsp;</p>', NULL, NULL, '2026-04-28 09:02:31', '2026-04-28 09:02:31'),
(2089, 'App\\Models\\InternationalTour', 54, 4, 'ZHUHAI – MACAU – ZHUHAI (MAKAN PAGI, MAKAN SIANG)', '<p style=\"text-align:justify;\">Sarapan Pagi di hotel. Hari ini kita akan berkunjung ke <strong>Fishing Girl Statue </strong>yang merupakan <i>landmark </i>kota Zhuhai, setelah puas berfoto kita akan bisa menyusuri <strong>Zhuhai Lover Road</strong> sambil menikmati pemandangan laut didekatnya. Kemudian berbelanja di <strong>Silk Shop </strong>dan <strong>Latex Shop</strong>. Setelah itu, kita akan menuju Macau untuk city tour, mengunjungi <strong>Senado Square</strong>, alun-alun ikonik dengan lantai mosaik bergelombang khas Portugis, dikelilingi bangunan bersejarah dan toko-toko menarik. Setelah itu menuju reruntuhan <strong>St Paul </strong>yang memiliki daya tarik arsitektur yang unik dari sisa fasad gereja Katolik yang dibangun pada abad ke-16. Terakhir, kita akan mengunjungi <strong>Venetian Shopping Arcade </strong>yang merupakan area resort dan belanja bernuansa kota Venice di Italia. Kembali menuju Zhuhai dan istirahat.</p><p><i>Menginap di hotel *4 Lokal atau *3 setaraf</i></p>', NULL, NULL, '2026-04-28 09:02:31', '2026-04-28 09:02:31'),
(2090, 'App\\Models\\InternationalTour', 54, 5, 'ZHUHAI - HONGKONG - JAKARTA (MAKAN PAGI)', '<p style=\"text-align:justify;\">Sarapan Pagi. Kita akan melakukan perjalanan kembali menuju Hong Kong International Airport menggunakan golden shuttle bus via HZM Bridge, untuk penerbangan kembali ke Jakarta. Sampai jumpa di tour selanjutnya bersama kami.</p>', NULL, NULL, '2026-04-28 09:02:31', '2026-04-28 09:02:31'),
(2109, 'App\\Models\\InternationalTour', 51, 1, 'JAKARTA – DUBAI', '<p style=\"text-align:justify;\">Berkumpul di Terminal 3 Bandara Internasional Soekarno Hatta 3 Jam sebelum keberangkatan. Proses check in dan bagasi. Penerbangan menuju Dubai dengan EK 357 ETD 17.40, tiba di Dubai ETA 22.30. Proses Imigrasi. Di jemput oleh pemandu lokal kami di area luar kedatangan. Menuju Hotel, check in dan beristirahat. Bermalam di Dubai</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2110, 'App\\Models\\InternationalTour', 51, 2, 'FREE PROGRAM DUBAI (MP)', '<p style=\"text-align:justify;\">Setelah Sarapan pagi. Acara Bebas. Berisitirahat dan bermalam di Dubai.</p><p style=\"text-align:justify;\"><strong>Rekomendasi aktivitas: Desert Safari Optional Tour: Desert Safari includes entertainment and buffet dinner USD 75/pax</strong></p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2111, 'App\\Models\\InternationalTour', 51, 3, 'DUBAI – ISTANBUL (MP, MS)', '<p style=\"text-align:justify;\">Setelah Sarapan, program bebas sampai waktunya check out dan di jemput untuk makan siang di restoran. Photostop Dubai Frame, Museum of the Future. Diantar menuju Dubai Mall untuk program bebas dan berphoto dengan latar belakang Burj Khalifa. Waktunya berkumpul untuk diantar menuju bandara. Penerbangan menuju Istanbul dengan EK 117 ETD 18.00. Tiba di Istanbul ETA 21.35. Setelah proses Imigrasi dan pengambilan bagasi, bertemu dengan local guide. Diantar menuju Hotel, check in, beristirahat dan bermalam di Istanbul</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2112, 'App\\Models\\InternationalTour', 51, 4, 'ISTANBUL – BURSA – KUSADASI (MP, MS, MM)', '<p style=\"text-align:justify;\">Sarapan dan check out hotel. Menuju kota Bursa melalui Jembatan Osmangazi. Mengunjungi toko oleh oleh manisan khas Turki, Turkish Delight dan Mengunjungi Grand Mosque dan Tophane Hill. Makan siang di restaurant. Perjalanan menuju Kusadasi, menuju hotel, check in dan beristirahat. Bermalam di Kusadasi</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2113, 'App\\Models\\InternationalTour', 51, 5, 'KUSADASI – PAMUKKALE (MP, MS, MM)', '<p style=\"text-align:justify;\">Setelah Sarapan dan check out hotel. Kita akan menuju Outlet jaket kulit dan menikmati fashion show outlet Jaket kulit buatan Turki (Turkish Leather Outlet). Lalu mengunjungi kota tua Ephesus. Setelah menjelajah kota tua dan menikmati situs peninggalan Romawi Kuno. Makan siang di restoran. Perjalanan menuju Pamukkale. Tiba di Pamukkale. Photo stop di taman angsa, dengan latar belakang Trevertine Pamukkale. Acara bebas hingga waktunya berkumpul untuk kembali ke hotel. Tiba di hotel, check in, makan malam dan beristirahat. Bermalam di Pamukkale.</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2114, 'App\\Models\\InternationalTour', 51, 6, 'PAMUKKALE – CAPPADOCIA (MP, MS, MM)', '<p style=\"text-align:justify;\">Setelah Sarapan dan check out hotel, mengunjungi Textile Outlet. Perjalanan menuju Cappadocia, singgah di kota Konya untuk makan siang. Melanjutkan perjalanan. Photo stop di Sultanhani Caravanserai. Melanjutkan perjalanan. Tiba di Cappadocia, menuju hotel, check in dan makan malam di hotel. Bermalam di Cappadocia.</p><p style=\"text-align:justify;\">&nbsp;</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2115, 'App\\Models\\InternationalTour', 51, 7, 'CAPPADOCIA (MP, MS, MM)', '<p style=\"text-align:justify;\">(Optional Balon Udara) Setelah sarapan di hotel, City tour Cappadocia mengunjungi kota bawah tanah, Outlet dan show room pembuatan gerabah khas Cappadocia Avanos Pottery Village. Makan siang di restaurant. Dilanjutkan Photo stop di Pigeon Valley, Goreme Valley dan Uchisar Castle Village. Mengunjungi Outlet dan showroom karpet buatan tangan khas Turki. Kembali ke hotel. (Optional tour Jeep Safari). Makan malam di hotel. Bermalam di Cappadocia</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2116, 'App\\Models\\InternationalTour', 51, 8, 'CAPPADOCIA – ISTANBUL (MP, MS, MM)', '<p style=\"text-align:justify;\">Setelah sarapan pagi dan check out hotel, kita akan menuju Istanbul. Singgah di Salt Lake (Danau Garam) dan makan siang di restoran. Melanjutkan perjalanan. Tiba di Istanbul. Makan malam di Restaurant. Menuju Hotel, Check in hotel, beristirahat. Bermalam di Istanbul.</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2117, 'App\\Models\\InternationalTour', 51, 9, 'FREE PROGRAM ISTANBUL (MP)', '<p style=\"text-align:justify;\">Setelah Sarapan pagi. Acara Bebas. Berisitirahat dan bermalam di Istanbul.</p><p style=\"text-align:justify;\"><strong>Optional:</strong></p><p style=\"text-align:justify;\">Taksim Square, Istiklal Street, Galata Tower, Spice Bazaar</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2118, 'App\\Models\\InternationalTour', 51, 10, 'ISTANBUL – AIRPORT – DUBAI (MP, MS)', '<p style=\"text-align:justify;\">Setelah sarapan pagi dan check out hotel. Menuju kota Tua Istanbul. Mengunjungi Blue Mosque dan Hippodrome. Berfoto di halaman depan istana Topkapi dan di depan Masjid Hagia Sophia. Makan siang di restoran. Kita akan menikmati keindahan selat Bosphorus dengan Cruise. Lalu akan diantar menuju Airport, penerbangan menuju Dubai.</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2119, 'App\\Models\\InternationalTour', 51, 11, 'DUBAI – TIBA DI JAKARTA', '<p style=\"text-align:justify;\">Melanjutkan penerbangan menuju Jakarta dengan EK 356 ETD 04.05, tiba di Jakarta ETA 15.40. Program selesai.</p>', NULL, NULL, '2026-04-29 02:59:04', '2026-04-29 02:59:04'),
(2120, 'App\\Models\\InternationalTour', 52, 1, 'JAKARTA', '<p style=\"text-align:justify;\">Berkumpul di Terminal 3 Bandara Internasional Soekarno Hatta 3 Jam sebelum keberangkatan. Proses check in dan bagasi.</p>', NULL, NULL, '2026-04-29 02:59:57', '2026-04-29 02:59:57'),
(2121, 'App\\Models\\InternationalTour', 52, 2, 'JAKARTA – DUBAI – ISTANBUL – BURSA (MM)', '<p>Penerbangan menuju Istanbul via Dubai EK 359 ETD 00.45. Tiba di Dubai ETA 05:30. Melanjutkan Penerbangan menuju Istanbul dengan EK 123 ETD 10.40. Tiba di Istanbul ETA 14.25. Setelah proses imigrasi dan bagasi selesai, menuju Hall kedatangan. Dijemput oleh local guide. Kita akan menikmati keindahan selat Bosphorus dengan Cruise. Menuju kota Bursa melalui Jembatan Osmangazi. Tiba di Hotel, Check in, Makan malam, Beristirahat dan bermalam di Bursa</p>', NULL, NULL, '2026-04-29 02:59:57', '2026-04-29 02:59:57'),
