(2127, 'App\\Models\\InternationalTour', 52, 8, 'FREE PROGRAM ISTANBUL (MP)', '<p style=\"text-align:justify;\">Setelah Sarapan. Acara Bebas. Berisitirahat dan bermalam di Istanbul.</p><p style=\"text-align:justify;\"><strong>Optional:</strong></p><p style=\"text-align:justify;\">Taksim Square, Istiklal Street, Galata Tower, Spice Bazaar</p>', NULL, NULL, '2026-04-29 02:59:58', '2026-04-29 02:59:58'),
(2128, 'App\\Models\\InternationalTour', 52, 9, 'ISTANBUL – AIRPORT (MP, MS)', '<p style=\"text-align:justify;\">Setelah sarapan dan check out hotel. Menuju Kota Tua Istanbul. Photo stop di depan Gerbang pintu utama Topkapi dan photostop di depan Masjid Hagia Sophia. Mengunjungi Blue Mosque dan Hippodrome. Makan siang di restoran. Mengunjungi Grand Bazaar, acara bebas hingga waktunya diantar menuju Airport, penerbangan menuju Dubai EK 122 ETD 19.35</p>', NULL, NULL, '2026-04-29 02:59:58', '2026-04-29 02:59:58'),
(2129, 'App\\Models\\InternationalTour', 52, 10, 'DUBAI – TIBA DI JAKARTA', '<p style=\"text-align:justify;\">Tiba di Dubai ETA 01.00. Melanjutkan penerbangan menuju Jakarta dengan EK 356 ETD 04.05, tiba di Jakarta ETA 15.40. Program selesai.</p>', NULL, NULL, '2026-04-29 02:59:58', '2026-04-29 02:59:58'),
