(2131, 'App\\Models\\InternationalTour', 53, 2, 'JAKARTA – DUBAI – ISTANBUL – BURSA (MM)', '<p style=\"text-align:justify;\">Penerbangan menuju Istanbul via Dubai EK 359 ETD 00.45. Tiba di Dubai ETA 05:30. Melanjutkan Penerbangan menuju Istanbul dengan EK 123 ETD 10.40. Tiba di Istanbul ETA 14.25. Setelah proses imigrasi dan bagasi selesai, menuju Hall kedatangan. Dijemput oleh local guide. Kita akan menikmati keindahan selat Bosphorus dengan Cruise. Menuju kota Bursa melalui Jembatan Osmangazi. Tiba di Hotel, Check in, Makan malam, Beristirahat dan bermalam di Bursa</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2132, 'App\\Models\\InternationalTour', 53, 3, 'BURSA – KUSADASI (MP, MS, MM)', '<p style=\"text-align:justify;\">Sarapan dan check out hotel. Mengunjungi toko oleh oleh manisan khas Turki, Turkish Delight dan Mengunjungi Grand Mosque dan Tophane Hill. Makan siang di restoran. Perjalanan menuju Kusadasi, menuju hotel, check in dan beristirahat. Bermalam di Kusadasi</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2133, 'App\\Models\\InternationalTour', 53, 4, 'KUSADASI – PAMUKKALE (MP, MS, MM)', '<p style=\"text-align:justify;\">Setelah Sarapan dan check out hotel. Kita akan menuju Outlet jaket kulit dan menikmati fashion show outlet Jaket kulit buatan Turki (Turkish Leather Outlet). Lalu mengunjungi kota tua Ephesus. Setelah menjelajah kota tua dan menikmati situs peninggalan Romawi Kuno. Makan siang di restoran. Perjalanan menuju Pamukkale. Tiba di Pamukkale. Photo stop di taman angsa, dengan latar belakang Trevertine Pamukkale. Acara bebas hingga waktunya berkumpul untuk kembali ke hotel. Tiba di hotel, check in, makan malam dan beristirahat. Bermalam di Pamukkale.</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2134, 'App\\Models\\InternationalTour', 53, 5, 'PAMUKKALE – CAPPADOCIA (MP, MS, MM)', '<p style=\"text-align:justify;\">Setelah Sarapan dan check out hotel, mengunjungi Textile Outlet. Perjalanan menuju Cappadocia, singgah di kota Konya untuk makan siang. Melanjutkan perjalanan. Photo stop di Sultanhani Caravanserai. Melanjutkan perjalanan. Tiba di Cappadocia, menuju hotel, check in dan makan malam di hotel. Bermalam di Cappadocia.</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2135, 'App\\Models\\InternationalTour', 53, 6, 'CAPPADOCIA (MP, MS, MM)', '<p>Setelah sarapan di hotel, City tour Cappadocia mengunjungi kota bawah tanah, Outlet dan show room pembuatan gerabah khas Cappadocia Avanos Pottery Village. Makan siang di restoran. Dilanjutkan Photo stop di Pigeon Valley, Goreme Valley dan Uchisar Castle Village. Mengunjungi Outlet dan showroom karpet buatan tangan khas Turki. Kembali ke hotel. (Optional tour Jeep Safari). Makan malam di hotel. Bermalam di Cappadocia</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2136, 'App\\Models\\InternationalTour', 53, 7, 'CAPPADOCIA – ISTANBUL (MP, MS, MM)', '<p>Setelah sarapan dan check out hotel, kita akan menuju Istanbul. Singgah di Salt Lake (Danau Garam) dan makan siang di restoran. Melanjutkan perjalanan. Tiba di Istanbul. Makan malam di restoran. Menuju Hotel, Check in hotel, beristirahat. Bermalam di Istanbul.</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2137, 'App\\Models\\InternationalTour', 53, 8, 'FREE PROGRAM ISTANBUL (MP)', '<p style=\"text-align:justify;\">Setelah Sarapan. Acara Bebas. Berisitirahat dan bermalam di Istanbul.</p><p style=\"text-align:justify;\"><strong>Optional:</strong></p><p style=\"text-align:justify;\">Taksim Square, Istiklal Street, Galata Tower, Spice Bazaar</p><p style=\"text-align:justify;\">&nbsp;</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2138, 'App\\Models\\InternationalTour', 53, 9, 'ISTANBUL – AIRPORT (MP, MS)', '<p style=\"text-align:justify;\">Setelah sarapan dan check out hotel. Menuju Kota Tua Istanbul. Photo stop di depan Gerbang pintu utama Topkapi dan photostop di depan Masjid Hagia Sophia. Mengunjungi Blue Mosque dan Hippodrome. Makan siang di restoran. Mengunjungi Grand Bazaar, acara bebas hingga waktunya diantar menuju Airport, penerbangan menuju Dubai EK 122 ETD 19.35</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2139, 'App\\Models\\InternationalTour', 53, 10, 'DUBAI – TIBA DI JAKARTA', '<p style=\"text-align:justify;\">Tiba di Dubai ETA 01.00. Melanjutkan penerbangan menuju Jakarta dengan EK 356 ETD 04.05, tiba di Jakarta ETA 15.40. Program selesai.</p>', NULL, NULL, '2026-04-29 03:00:20', '2026-04-29 03:00:20'),
(2189, 'App\\Models\\InternationalTour', 56, 1, 'ARR - BANGKOK | NO MEALS', '<p>Pick up at the airport, Transfer to check in hotel, overnight at Bangkok</p>', NULL, NULL, '2026-04-29 04:05:05', '2026-04-29 04:05:05'),
(2190, 'App\\Models\\InternationalTour', 56, 2, 'BANGKOK DREAM WORLD | BREAKFAST/LUNCH', '<p style=\"text-align:justify;\">ABF at Hotel, <strong>Dream World Happy Land Bangkok (Include unlimited Time: Dream Garden, Fantasy Land, Adventure Land, Plaza, Snow Town)</strong>, lunch at Dream World, MBK Shopping Mall (Siam Square Walking Street walk by own), Jodd Fairs Night Market, Dinner by own at Jodd Fairs Night Market, back to hotel</p>', NULL, NULL, '2026-04-29 04:05:05', '2026-04-29 04:05:05'),
(2191, 'App\\Models\\InternationalTour', 56, 3, 'BANGKOK CITY TOUR | BREAKFAST/LUNCH/DINNER', '<p style=\"text-align:justify;\">Breakfast at Hotel, Dried Food, Honey Bee Farm, <strong>Wat Arun </strong>(Temple of Dawn), <strong>Chaophraya River </strong>sightseeing with Tourist Boat (around 10-15 minutes), Lunch at <strong>Local Restaurant, </strong>Gems Gallery, <strong>Platinum Fashion Mall</strong>, Dinner at Local Restaurant<strong>, </strong>optional Calypso Cabaret Show at Asiatique the Riverfront Night Market, Back to Hotel</p>', NULL, NULL, '2026-04-29 04:05:05', '2026-04-29 04:05:05'),
(2192, 'App\\Models\\InternationalTour', 56, 4, 'DEPARTURES | BREAKFAST', '<p>ABF at Hotel, free time until transfer to the airport</p>', NULL, NULL, '2026-04-29 04:05:05', '2026-04-29 04:05:05'),
(2193, 'App\\Models\\InternationalTour', 55, 1, 'ARR - BANGKOK | NO MEALS', '<p>Pick up at the airport, Transfer to check in hotel, overnight at Bangkok</p>', NULL, NULL, '2026-04-29 04:05:42', '2026-04-29 04:05:42'),
(2194, 'App\\Models\\InternationalTour', 55, 2, 'BANGKOK - AYUTTHAYA - BANGKOK | BREAKFAST/LUNCH', '<p style=\"text-align:justify;\">ABF at Hotel, transfer to Ayutthaya (Historical Park of Thailand) Free E-Scooter Explore<strong>, Wat Chai Watthanaram, Wat Mahathat, </strong>Lunch at local restaurant, back Bangkok, Erawadee Herb Shop, <strong>Jodd Fairs Night Market, </strong>Dinner by own at <strong>Jodd Fairs Night Market</strong>, back to hotel.</p>', NULL, NULL, '2026-04-29 04:05:42', '2026-04-29 04:05:42'),
(2195, 'App\\Models\\InternationalTour', 55, 3, 'BANGKOK CITY TOUR | BREAKFAST/LUNCH/DINNER', '<p style=\"text-align:justify;\">Breakfast at Hotel, Dried Food, Honey Bee Farm, <strong>Wat Arun </strong>(Temple of Dawn), <strong>Chaophraya River </strong>sightseeing with Tourist Boat (around 10-15 minutes), Lunch at <strong>Local Restaurant, </strong>Gems Gallery, <strong>Platinum Fashion Mall</strong>, Dinner at Local Restaurant<strong>, </strong>optional Calypso Cabaret Show at Asiatique the Riverfront Night Market, Back to Hotel.</p>', NULL, NULL, '2026-04-29 04:05:42', '2026-04-29 04:05:42'),
