(2365, 'App\\Models\\InternationalTour', 64, 4, 'BANGKOK - KANCHANABURI- BANGKOK | BREAKFAST/LUNCH', '<p style=\"text-align:justify;\">ABF at Hotel, transfer to Kanchanaburi, <strong>Kanchanaburi Skywalk, Dead Railway</strong>, Take a train to <strong>Tham Krasae Bridge</strong>, lunch at local restaurant, Transfer to <strong>Kanchanaburi Safari Park </strong>(include Elephant Show and interact with Giraffe), Back Bangkok, Dinner by own expense at <strong>Jodd Fairs Nighl Market</strong>, back to hotel</p>', NULL, NULL, '2026-04-30 05:48:32', '2026-04-30 05:48:32'),
(2366, 'App\\Models\\InternationalTour', 64, 5, 'DEPARTURES | BREAKFAST', '<p style=\"text-align:justify;\">ABF at Hotel, free time until transfer to the airport</p>', NULL, NULL, '2026-04-30 05:48:32', '2026-04-30 05:48:32'),
