(2524, 'App\\Models\\InternationalTour', 66, 2, 'BANGKOK - PATTAYA | BREAKFAST/LUNCH/DINNER', '<p>Breakfast at Hotel, Check out from hotel, Visit Honey Bee farm, <strong>Great and Grand Sweet Destination</strong>, Bus tour to <strong>The Valley of Dinosaurs (Dinosaurs Park)</strong>, <strong>Nongnooch Village (Include Thai Culture and Elephant Show) </strong>Lunch buffet at Nongnooch Village, <strong>Laser Buddha Hill, </strong>Erawadee Herb Shop, Pattaya Beach at <strong>Hard Rock Cafe</strong>, optional cabaret show, Dinner at Local restaurant, Check in hotel at Pattaya.</p>', NULL, NULL, '2026-05-02 14:10:14', '2026-05-02 14:10:14'),
(2525, 'App\\Models\\InternationalTour', 66, 3, 'PATTAYA | BREAKFAST/LUNCH', '<p>ABF at Hotel, transfer to the Beach, take Speed Boat to <strong>Coral Island </strong>(15-20 mins), enjoy on the beach, additional watersport (snorkeling, parasailing, jet ski, banana boat) at Coral Island, transfer back to hotel, sightseeing Pattaya City with songthew, visit <strong>3D Art in Paradise</strong>, shopping at <strong>Terminal 21 Pattaya, </strong>enjoy night live at <strong>Pattaya Walking Street </strong>and Dinner at walking street (with own expense), back to hotel.</p>', NULL, NULL, '2026-05-02 14:10:14', '2026-05-02 14:10:14'),
(2526, 'App\\Models\\InternationalTour', 66, 4, 'PATTAYA - BANGKOK | BREAKFAST/LUNCH COUPON', '<p>ABF at hotel, check out from hotel, Back to Bangkok, Gems Gallery Museum of The Stone with Train Ride, back Bangkok, Dried Food local Product Center, <strong>Platinum Fashion Mall</strong>, Lunch at Platinum Mall by Coupon <strong>THB150/pax</strong>, <strong>Wat Arun </strong>(Temple of Dawn), <strong>Chaophraya River </strong>sightseeing with <strong>Tourist Boat </strong>to <strong>Icon Siam Mall &amp; Sook Siam Floating Market in The Mall</strong>, Dinner by own expense at <strong>Asia Tique the Riverfront Night Market</strong>, transfer to check in hotel at the Bangkok.</p>', NULL, NULL, '2026-05-02 14:10:14', '2026-05-02 14:10:14'),
