(2537, 'App\\Models\\InternationalTour', 67, 2, 'BANGKOK CITY TOUR | BREAKFAST', '<p>Breakfast at Hotel, Dried Food, Honey Bee Farm, <strong>Wat Arun </strong>(exclude entrance fee ticket &amp; boat), Lunch by own expense, Gems Gallery, <strong>Platinum Fashion Mall, </strong>Dinner by own expense at <strong>Asiatique Riverfront Night Market</strong>, Back to Hotel</p>', NULL, NULL, '2026-05-02 14:54:48', '2026-05-02 14:54:48'),
(2538, 'App\\Models\\InternationalTour', 67, 3, 'BANGKOK FREE EASY | BREAKFAST', '<p>Breakfast at Hotel, Free &amp; Easy at the Hotel (No Service &amp; No Guide)</p><p>Additional One Day Tour</p>', NULL, NULL, '2026-05-02 14:54:48', '2026-05-02 14:54:48'),
(2539, 'App\\Models\\InternationalTour', 67, 4, 'DEPARTURES | BREAKFAST', '<p>ABF at Hotel, free time until transfer to the airport</p>', NULL, NULL, '2026-05-02 14:54:49', '2026-05-02 14:54:49'),
(2548, 'App\\Models\\InternationalTour', 68, 1, 'ARR - BANGKOK | NO MEALS', '<p>Pick up at the airport, Transfer to check in hotel, overnight in Bangkok</p>', NULL, NULL, '2026-05-02 16:55:48', '2026-05-02 16:55:48'),
(2549, 'App\\Models\\InternationalTour', 68, 2, 'BANGKOK CITY TOUR | BREAKFAST/LUNCH', '<p style=\"text-align:justify;\">Breakfast at Hotel, Dried Food, Honey Bee Farm, <strong>Wat Arun </strong>(Temple of Dawn), <strong>Chaophraya River </strong>sightseeing with Tourist Boat (arround 10-15 minutes), Lunch at local restaurant, Gems Gallery, <strong>Platinum Fashion Mall, </strong>Dinner by own expense at <strong>Asiatique Riverfront Night Market</strong>, Back to Hotel</p>', NULL, NULL, '2026-05-02 16:55:48', '2026-05-02 16:55:48'),
(2550, 'App\\Models\\InternationalTour', 68, 3, 'BANGKOK EXPLORE HIDDEN GEM | BREAKFAST/LUNCH', '<p style=\"text-align:justify;\">Breakfast at Hotel, Erawadee Herb Shop, <strong>E-Scooter Tour explore Hidden Gem of Thailand, </strong>Talat Noi Street Art, Mother Roaster Cafe, Chocolate Cafe, Hong Sieng Kong Cafe (exclude entrance coupon), Chinatown Bangkok, <strong>Song Wat Walking Street (</strong>Hidden Historic Road), Lunch at local restaurant, <strong>Chatuchak Market </strong>(The Biggest Market in Thailand), <strong>Icon Siam G Sook Siam Floating Market in The Mall</strong>, dinner by own expense (optional Dinner Cruise), back to Hotel.</p>', NULL, NULL, '2026-05-02 16:55:48', '2026-05-02 16:55:48'),
(2551, 'App\\Models\\InternationalTour', 68, 4, 'DEPARTURES | BREAKFAST', '<p style=\"text-align:justify;\">ABF at Hotel, free time until transfer to the airport</p>', NULL, NULL, '2026-05-02 16:55:48', '2026-05-02 16:55:48'),
(2735, 'App\\Models\\ManadoTour', 25, 1, 'ARRIVAL – MINAHASA HIGHLAND  – TANGKOKO NATURE RESERVE PARK', '<p style=\"text-align:justify;\">Arrival at Manado in the morning. Meet our guide, then proceed to the <strong>Mt. Mahawu crater</strong>. After a 10-minute hike to the crater\'s rim, you\'ll be rewarded with a breathtaking view of Tomohon and Manado, as well as the islands beyond. After that visit <strong>Woloan village</strong>, the center of the knock-down traditional home business, and make a stop at the <strong>Pagoda Buddhist Temple</strong>, which is a photo stop with a scenic backdrop of Mt. Lokon. Chilling down at <strong>Linow Lake\'s</strong> gorgeous multi-color to enjoy the afternoon at a nice restaurant by the lake sipping coffee or tea.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The trek continues to the <strong>Waruga Sawangan</strong>, with a halt at the ancient Minahasa People\'s Tomb (Giant Stone Ages). Take the road to Tangkoko. (If you arrive in the afternoon, skip the Minahasa Highland trip and go straight to Batu Putih village in Tangkoko). Tangkoko Homestay is where you will spend the night.&nbsp;</p>', NULL, 'Dinner', '2026-05-03 01:40:40', '2026-05-03 01:40:40'),
(2736, 'App\\Models\\ManadoTour', 25, 2, 'FULL DAY TANGKOKO TOUR', '<p style=\"text-align:justify;\">After finishing breakfast at the homestay, start to explore the endemic species of North Sulawesi at the Tangkoko Nature Reserve. Search for the Black Crested Macaque (Black Monkey indigenous to North Sulawesi), the Tarsier Spectrum (the world’s smallest primate), Cuscus bear, and lots of birds.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The national park is home to the world\'s highest population of hornbills, including the rhinoceros hornbill. After lunch we\'ll go on another excursion into Tangkoko\'s jungle in the afternoon. Overnight at homestay.&nbsp;</p>', NULL, 'Breakfast / Lunch / Dinner', '2026-05-03 01:40:40', '2026-05-03 01:40:40'),
(2737, 'App\\Models\\ManadoTour', 25, 3, 'TRANSFER OUT TO AIRPORT', '<p style=\"text-align:justify;\">After breakfast at the hotel, check-out. Make a visit in town for souvenir shopping if time allows. Next, you will be escorted by our tour guide to the airport for transfer out. Tour is over, Thank you.&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:40:40', '2026-05-03 01:40:40'),
(2738, 'App\\Models\\ManadoTour', 24, 1, 'ARRIVAL – TUNAN WATERFALL  – TANGKOKO NATURE RESERVE PARK', '<p style=\"text-align:justify;\">Arrival at Manado in the morning. Meet our guide, then proceed to the picked up to go to <strong>Tunan Waterfall</strong>, this waterfall is in <strong>Talawan Village</strong>. The source of the <strong>Tunan Waterfall</strong> comes from the river above the mountain which flows quite rapidly through steep cliffs with a cliff height of approximately 86 meters. The atmosphere of the natural forest that is still pristine and natural adds to the beauty around the <strong>Tunan Waterfall</strong> Nature Tourism object.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">We drive right to <strong>Tangkoko National Park</strong> (If you arrive in the afternoon, skip the Tunan Waterfall trip and go straight to Batu Putih village in Tangkoko). At the end of the afternoon, a short hike in the forest in search of the big star of the park: the Tarsier Spectrum, the smallest mammal on the planet. Tangkoko Homestay is where you will spend the night.</p>', NULL, 'Dinner', '2026-05-03 01:40:53', '2026-05-03 01:40:53'),
(2739, 'App\\Models\\ManadoTour', 24, 2, 'FULL DAY TANGKOKO TOUR', '<p style=\"text-align:justify;\">After finishing breakfast at the homestay, start to explore the endemic species of North Sulawesi at the Tangkoko Nature Reserve. Search for the Black Crested Macaque (Black Monkey indigenous to North Sulawesi), another Tarsier Spectrum (the world’s smallest primate), Cuscus bear, and lots of birds. The national park is home to the world\'s highest population of hornbills, including the rhinoceros hornbill. After lunch we\'ll go on another excursion into Tangkoko\'s jungle in the afternoon. Overnight at homestay.&nbsp;</p>', NULL, 'Breakfast / Lunch / Dinner', '2026-05-03 01:40:53', '2026-05-03 01:40:53'),
(2740, 'App\\Models\\ManadoTour', 24, 3, 'WARUGA SAWANGAN – MINAHASA HIGHLAND TOUR', '<p style=\"text-align:justify;\">After breakfast, check out and drive to the highlands, then proceed to the <strong>Waruga Sawangan</strong>, with a halt at the ancient Minahasa People\'s Tomb (Giant Stone Ages). Having lunch at <strong>Tondano Lake</strong>. Proceed to Tomohon to see the <strong>traditional market</strong>, after that <strong>Woloan Village</strong> knock-down wooden house industry (locals here create exquisite Minahasa-style wooden homes that are disassembled and shipped out of their village), and <strong>Kai’santi Tomohon</strong> which is a photo stop with a scenic backdrop of Mt. Lokon &amp; green rice fields.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">We spend the afternoon at <strong>Linow Lake</strong> drinking coffee or tea. check in to your room in a resort in Tomohon.&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:40:53', '2026-05-03 01:40:53'),
(2741, 'App\\Models\\ManadoTour', 24, 4, 'MT. MAHAWU - TRANSFER OUT TO AIRPORT', '<p style=\"text-align:justify;\">After breakfast at the hotel, check-out. Meet our guide, then proceed to the <strong>Mt. Mahawu crater</strong>. After a 10-minute hike to the crater\'s rim, you\'ll be rewarded with a breathtaking view of Tomohon and Manado, as well as the islands beyond, at the crater\'s bottom, visitors can see a steaming lake and smell sulfur from the pools. Next, you will be escorted by our tour guide to the airport for transfer out.&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:40:53', '2026-05-03 01:40:53'),
(2742, 'App\\Models\\ManadoTour', 23, 1, 'ARRIVAL – Explore TUNAN WATERFALL', '<p style=\"text-align:justify;\">Arrival at Manado in the morning. Meet our guide, then proceed to the picked up to go to&nbsp;<strong>Tunan Waterfall</strong>, this waterfall is in&nbsp;<strong>Talawan Village</strong>. The source of the&nbsp;<strong>Tunan Waterfall</strong>&nbsp;comes from the river above the mountain which flows quite rapidly through steep cliffs with a cliff height of approximately 86 meters. The atmosphere of the natural forest that is still pristine and natural adds to the beauty around the&nbsp;<strong>Tunan Waterfall</strong>&nbsp;Nature Tourism object.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">&nbsp;We drive right to&nbsp;<strong>Tangkoko National Park</strong>&nbsp;<i>(if you arrive in the afternoon, skip the Tunan Waterfall trip and go straight to Batu Putih village in Tangkoko)</i>. At the end of the afternoon, a short hike in the forest in search of the big star of the park: the Tarsier Spectrum, the smallest mammal on the planet. Tangkoko Sanctuary Villa is where you will spend the night.</p>', NULL, 'Dinner', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2743, 'App\\Models\\ManadoTour', 23, 2, 'FULL DAY TANGKOKO TOUR', '<p style=\"text-align:justify;\">After finishing breakfast at the homestay, start to explore the endemic species of North Sulawesi at the Tangkoko Nature Reserve. Search for the Black Crested Macaque (Black Monkey indigenous to North Sulawesi), another Tarsier Spectrum (the world’s smallest primate), Cuscus bear, and lots of birds. The national park is home to the world\'s highest population of hornbills, including the rhinoceros hornbill.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">After lunch we\'ll go on another excursion into Tangkoko\'s jungle in the afternoon. Overnight at homestay.&nbsp;</p>', NULL, 'Breakfast / Lunch / Dinner', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2744, 'App\\Models\\ManadoTour', 23, 3, 'WARUGA SAWANGAN – MINAHASA HIGHLAND TOUR', '<p style=\"text-align:justify;\">After breakfast, check out and drive to the highlands, then proceed to the&nbsp;<strong>Waruga Sawangan</strong>, with a halt at the ancient Minahasa People\'s Tomb (Giant Stone Ages). Having lunch at&nbsp;<strong>Tondano Lake</strong>. Proceed to Tomohon to see the&nbsp;<strong>traditional market</strong>, after that&nbsp;<strong>Woloan Village</strong>&nbsp;knock-down wooden house industry (locals here create exquisite Minahasa-style wooden homes that are disassembled and shipped out of their village), and&nbsp;<strong>Kai’santi Tomohon</strong>&nbsp;which is a photo stop with a scenic backdrop of Mt. Lokon &amp; green rice fields.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">We spend the afternoon at&nbsp;<strong>Linow Lake</strong>&nbsp;drinking coffee or tea. check in to your room in a resort in Tomohon.&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2745, 'App\\Models\\ManadoTour', 23, 4, 'Mt. MAHAWU TREKKING – BUNAKEN ISLAND', '<p style=\"text-align:justify;\">After breakfast at the hotel, check-out. Meet our guide, then proceed to the&nbsp;<strong>Mt. Mahawu crater</strong>. After a 10-minute hike to the crater\'s rim, you\'ll be rewarded with a breathtaking view of Tomohon and Manado, as well as the islands beyond, at the crater\'s bottom, visitors can see a steaming lake and smell sulfur from the pools. After lunch, transfer by boat to the island of Bunaken (approximately 45 minutes by boat).&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>Bunaken Marine Park</strong>&nbsp;is a marine park in North Sulawesi, Indonesia, east of Bunaken Island. This marine park is well-known for its breathtaking underwater scenery. Bunaken Marine Park, with an area of roughly 89,065 hectares, is a popular destination for divers and snorkelers from all over the world. Lodging will be provided at Resorts on Bunaken Island&nbsp;</p>', NULL, 'Breakfast / Dinner', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2746, 'App\\Models\\ManadoTour', 23, 5, 'BUNAKEN ISLAND (SWIMMING / SNORKELING)', '<p style=\"text-align:justify;\">We freely enjoy the pleasures of the sea in one of Indonesia\'s most gorgeous snorkeling sites. We\'re in the midst of a magnificent ecosystem with over 500 coral types and approximately 1,500 fish species, harmless reef sharks, and Turtles are frequently spotted surrounding the island.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>Note:</strong> <i>as an option, it is possible to rent snorkeling equipment and do it from the beach or book a boat trip. Diving outings are also possible (reservation and payment on site)&nbsp;</i></p>', NULL, 'Breakfast / Lunch / Dinner', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2747, 'App\\Models\\ManadoTour', 23, 6, 'TRANSFER OUT TO AIRPORT', '<p style=\"text-align:justify;\">After breakfast at the hotel, check-out. Transfer by boat to Manado, Next, you will be escorted by our tour guide to the airport for transfer out. Tour is over, Thank you.&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:41:05', '2026-05-03 01:41:05'),
(2748, 'App\\Models\\ManadoTour', 22, 1, 'Itinerary', '<p style=\"text-align:justify;\">Tour participants will be picked up by the tour guide at the pick-up point and will immediately begin the City Tour: heading to the city center of Manado, the Chinatown area, and the <strong>Ban Hin Kiong Temple</strong> (the oldest temple in Manado, built in the 18th century, approximately 300 years old).&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The tour will also pass by the <strong>Sentrum Church</strong> (the first Protestant church in North Sulawesi, a remnant from the Dutch colonial era) and the World War II Monument (a reminder of the destruction of Manado city in 1942 by Japanese soldiers). Lunch will be served at a <strong>local restaurant with a specialty Tuna dish</strong>, cooked in the traditional Manado style.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, the tour will head to the Ring Road Citra Land area to get a closer look at the charm of the <strong>Jesus Blessing Monument</strong> – a statue of Jesus built in a floating position, facing the city of Manado. Then, the tour will continue to <strong>Makatete Hill</strong> – a hilltop at an elevation of 200 meters above sea level, offering views of Manado city, Manado Island, Bunaken Island, Siladen Island, vast stretches of the sea, and the Klabat Mountain, the highest mountain in North Sulawesi.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Dinner is optional. After dinner, participants will be dropped back off at the pick-up point. The tour concludes.</p>', NULL, 'Lunch', '2026-05-03 01:41:19', '2026-05-03 01:41:19'),
(2749, 'App\\Models\\ManadoTour', 21, 1, 'Itinerary', '<p style=\"text-align:justify;\">Meet &amp; greet at 08:00 AM with the tour guide at <strong>Megamas Pier </strong>for a day tour to <strong>Bunaken Island</strong>. From Megamas Pier, cross to <strong>Bunaken Island </strong>by boat (approximately 30 minutes). Currently, Bunaken has been beautifully revitalized with its new and more representative <strong>Bunaken Tourism Pier (New Bunaken)</strong>, where participants can capture stunning photos and videos with scenic island views.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Discover the underwater beauty of Bunaken Marine Park, home to vibrant coral reefs and colorful tropical fish, through <i>optional </i>snorkeling or diving activities. Participants may also enjoy free time to relax and explore the island’s serene beach atmosphere. Lunch will be served at a local beachfront restaurant.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">After lunch, enjoy more free leisure time or continue snorkeling/diving (optional). In the afternoon, return to Megamas Pier, Manado. End of tour.</p>', NULL, 'Lunch', '2026-05-03 01:41:32', '2026-05-03 01:41:32'),
(2750, 'App\\Models\\ManadoTour', 20, 1, 'Itinerary', '<p style=\"text-align:justify;\">The tour participants will be picked up in the morning by the tour guide for a journey to the <strong>Minahasa Highlands</strong>, passing through the <strong>Tinoor</strong> area where participants can enjoy a view of Manado city from an elevation of 500 meters. Upon arrival in Tomohon, the group will visit <strong>Taman Wisata Pelangi</strong>, where they can admire the beauty of various colorful flowers.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The next stop is the <strong>Tomohon Extreme Market</strong>, where participants can get a close look at various types of wild animal meat, such as<i><strong> paniki (bat), forest rats, snakes, and other wild animals</strong></i>. At a different location, participants will also have the chance to witness the <strong>live cooking </strong>process of traditional Manado cakes like <strong>cucur, apang gula merah, dodol</strong>, and other local sweet treats.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Next, the tour heads to the <strong>Aren forest</strong> with Instagram-worthy photo spots at <strong>Tuur Maasering</strong>. In addition to the interesting photo spots, participants will also observe the process of making the <i><strong>local liquor </strong></i><strong>\'Cap Tikus\'</strong>, which is produced through the fermentation and distillation of sap from the Aren tree.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Lunch will be served at a local restaurant by <strong>Lake Tondano</strong>. After lunch, the journey continues to <strong>Bukit Kasih</strong>, a unique natural attraction featuring active sulfur craters and stairways leading to the hilltop, offering scenic views and a distinctive cultural experience. The area also has natural sulfur hot springs where guests may swim or soak their feet for relaxation (optional).&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The journey continues to <strong>Lake Linow</strong>, a sulfur lake known for its changing watercolors and beautiful, tranquil scenery (served with coffee or tea). Afterward, return to Manado City. Dinner is optional. After dinner, participants will be transferred back to the designated drop-off point. Tour ends.</p>', NULL, 'Lunch', '2026-05-03 01:41:45', '2026-05-03 01:41:45'),
(2751, 'App\\Models\\ManadoTour', 19, 1, 'Itinerary', '<p style=\"text-align:justify;\">Participants will be picked up at the meeting point in the morning and transferred to the <strong>Rafting Location </strong>in <strong>Timbukar Village,</strong> Sonder. Before starting the rafting activity, participants will receive a short training session, including basic movements and safety instructions to maintain balance while on the rubber boat.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">During the rafting trip, participants will be accompanied by two experienced rafting guides equipped with internationally standardized safety gear. While navigating the exciting rapids of the Nimanga River, participants can also enjoy the stunning natural scenery along the way for approximately 90 minutes.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, return to Manado city and drop off at the meeting point. Tour ends.</p>', NULL, 'No Meals', '2026-05-03 01:41:58', '2026-05-03 01:41:58'),
(2752, 'App\\Models\\ManadoTour', 18, 1, 'Itinerary', '<p style=\"text-align:justify;\">Participants will be picked up in the morning for a tour to <strong>Mount Mahawu</strong>, located approximately 1 hour and 15 minutes from Manado city. Mount Mahawu is a popular attraction for tourists and hikers visiting Manado. The hiking trail consists of around 150 cemented steps, making the climb relatively easy. Along the way, participants will find metal railings that can be used for support during the ascent. Upon reaching the summit, participants can enjoy stunning panoramic views of Manado Tua Island, Bunaken, and Manado city.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The tour then continues to <strong>Tetetana Hill</strong> <strong>Peak</strong>, a newly developed tourist destination in Tomohon. In addition to offering panoramic views of four regions across North Sulawesi Province, visitors can also enjoy the beauty of the hill, surrounded by colorful flower gardens.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, the group will head to a local restaurant for lunch. Following lunch, participants will return to Manado city and be dropped off at the designated pick-up point. End of tour.</p>', NULL, 'Lunch', '2026-05-03 01:42:18', '2026-05-03 01:42:18'),
(2753, 'App\\Models\\ManadoTour', 17, 1, 'Itinerary', '<p style=\"text-align:justify;\"><strong>Mount Lokon</strong> is one of the largest mountains in Tomohon and is an active volcano standing at an elevation of 1,580 meters above sea level. True to its name, “Lokon” means the oldest and the greatest. Its active crater, known as <strong>Tompaluan Crater</strong>, is located at the mountain’s base.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">From the pick-up point, you will drive to Tomohon or the foothills of Mount Lokon (approximately 1 hour and 30 minutes), then continue with a hike of about 2 hours to reach the crater rim. Currently, the trek does not go beyond the crater, which lies about halfway to the summit.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Mount Lokon offers spectacular natural scenery and a thrilling challenge for hikers. Along the trail, you can enjoy breathtaking views, including the beautiful panorama of Tomohon city.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">After the trekking adventure, proceed to a local restaurant for lunch. Following lunch, return to Manado city and drop off at the designated point. End of tour.</p>', NULL, 'Lunch', '2026-05-03 01:42:32', '2026-05-03 01:42:32'),
(2754, 'App\\Models\\ManadoTour', 16, 1, 'Itinerary', '<p style=\"text-align:justify;\">All participants will be picked up for a trip to <strong>Tunan Waterfall</strong>, located in <strong>Talawaan Village</strong>. The water source of Tunan Waterfall originates from a mountain river that flows forcefully down a steep cliff about <strong>86 meters high</strong>. The pristine forest and natural surroundings enhance the beauty of this scenic natural attraction.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, participants will enjoy lunch at a local restaurant. The journey then continues to the <strong>Tangkoko Nature Reserve</strong>. Sit back and relax while enjoying the beautiful scenery as you pass through small villages on the way to one of Indonesia’s most important conservation areas.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Located about <strong>20 kilometers northwest of Bitung</strong>, the reserve lies among hills and valleys. Upon arrival, you will be greeted by a<strong> local park ranger</strong>, who will guide you through the forest in search of various wildlife species roaming freely in their natural habitat. Keep your camera ready—you may encounter the <strong>Sulawesi Black Crested Macaque (Yaki)</strong>, <strong>the Tarsius Tarsier (the world’s smallest primate)</strong>, as well as <strong>Hornbills</strong> and <strong>Cuscus (large-eyed marsupials)</strong>.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">After the wildlife exploration, return to Manado. End of tour.</p>', NULL, 'Lunch', '2026-05-03 01:42:49', '2026-05-03 01:42:49'),
(2755, 'App\\Models\\ManadoTour', 15, 1, 'Itinerary', '<p style=\"text-align:justify;\">Participants will be picked up in the morning for a tour to Rap-Rap Beach. Upon arrival, participants will enjoy a unique experience at the stunning Rap-Rap Beach, starting with a canoe ride through the calm waters surrounding the lush mangrove forest. Within minutes, participants will embark on an exciting search for the <strong>Tarsius</strong>, a fascinating tiny primate often found among the mangrove trees.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The serene natural atmosphere and the sounds of the forest accompany this journey, creating an unforgettable moment amid the beauty of North Sulawesi’s nature. When spotting the <strong>Tarsius</strong>, participants are free to take photos and capture the moment.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, the tour continues back to the Rap-Rap shoreline before heading to the highlands of Mount Tumpa, where participants can witness a beautiful <strong>sunset</strong> view from the foothills while enjoying <strong>various traditional Manado snacks</strong> such as pisang goreng sambal roa, batata goreng gula merah, and es kacang brenebon <i>(optional, at personal expense)</i>. Afterward, participants will be transferred back to the meeting point. End of tour.</p>', NULL, 'No Meals', '2026-05-03 01:43:01', '2026-05-03 01:43:01'),
(2756, 'App\\Models\\ManadoTour', 14, 1, 'Itinerary', '<p style=\"text-align:justify;\">Meet &amp; greet at Mount Tumpa at 10:00 AM.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Paragliding at <strong>Mount Tumpa </strong>is an unforgettable experience for adventure enthusiasts and nature lovers alike. Flying at an altitude of around 1,000 meters, you will feel the thrilling sensation of soaring freely like a bird while enjoying breathtaking views of the mountain landscape, lush green forests, and the crystal-clear blue sea below.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The paragliding site at Mount Tumpa is also a safe and ideal place for both beginners and those looking to improve their paragliding skills, thanks to its stable weather conditions and gentle winds. You will be accompanied by professional paragliding instructors and provided with proper safety equipment.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Paragliding at Mount Tumpa is a thrilling yet beautiful experience that will make your trip to Manado truly unforgettable.</p>', NULL, 'No Meal', '2026-05-03 01:43:16', '2026-05-03 01:43:16'),
(2757, 'App\\Models\\ManadoTour', 13, 1, 'ARRIVAL – MANADO CITY TOUR – MAKATETE HILL – SUN BAE MANADO', '<p style=\"text-align:justify;\">Upon arrival at Sam Ratulangi Airport Manado, the group will be welcomed by the tour guide and begin a city tour of Manado. Visit the city center, <strong>Chinatown</strong>, and <strong>Ban Hin Kiong Temple</strong> - the oldest temple in Manado, built in the 18th century (±300 years old). Continue by passing <strong>Sentrum Church</strong>, the first Protestant church in North Sulawesi from the Dutch era, and the <strong>World War II Monument</strong>, which marks the destruction of Manado in 1942 by Japanese forces.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The tour then proceeds to the Ring Road area of <strong>CitraLand</strong> to see the <strong>Blessing Jesus Monument</strong>, a statue of Jesus built in a unique forward-leaning position overlooking Manado City. After that, visit <strong>Makatete Hill</strong> - located at 200 meters above sea level, offering panoramic views of Manado City, <strong>Manado Tua Island</strong>, <strong>Bunaken Island</strong>, <strong>Siladen Island</strong>, the open sea, and <strong>Mount Klabat</strong>, the highest peak in North Sulawesi.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Dinner will be optional at a local restaurant. After dinner, visit <strong>SunBae</strong>, one of Manado’s trendy seaside hangout spots, where guests may enjoy the evening atmosphere along with various snacks and drinks from numerous food stalls (optional). Afterwards, transfer to the hotel for check-in and rest.</p>', NULL, 'No Meals', '2026-05-03 01:43:32', '2026-05-03 01:43:32'),
(2758, 'App\\Models\\ManadoTour', 13, 2, 'BUNAKEN SIGHTSEEING TOUR – LOCAL COFFEE PRODUCTION HOUSE – SHOPPING TOUR', '<p style=\"text-align:justify;\">After breakfast at the hotel, the tour participants will be picked up by the guide and head to <strong>Bunaken Island</strong>. From the hotel, transfer to Megamas Pier and cross to Bunaken by boat for approximately 30 minutes. Bunaken Island now features the newly developed <strong>Bunaken Tourism Pier (New Bunaken)</strong>, offering a more charming and photogenic spot for photos and videos.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterwards, the tour participants will be taken to explore the beauty of <strong>Bunaken Marine Park</strong>, renowned for its colorful coral reefs and diverse tropical marine life. Participants may enjoy <i>optional</i><strong> snorkeling or diving</strong> activities, or simply take a leisurely walk while relaxing and enjoying the beach atmosphere of Bunaken. Optional lunch at a local restaurant. After lunch, guests will have additional free time for optional snorkeling/diving.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Return to Megamas Pier and proceed to visit a <strong>local coffee production house</strong>, where participants can taste the authentic flavors of North Sulawesi coffee. Afterwards, continue to a <strong>souvenir shopping area</strong> offering a wide variety of Manado specialties (or return to the hotel first and be picked up again before dinner). Optional dinner at a local restaurant, followed by transfer back to the hotel.</p>', NULL, 'Breakfast', '2026-05-03 01:43:32', '2026-05-03 01:43:32'),
(2759, 'App\\Models\\ManadoTour', 13, 3, 'TRANSFER OUT – DEPARTURE', '<p style=\"text-align:justify;\">After breakfast and completing the hotel check-out process, the tour participants will be picked up by the guide and transferred directly to the airport for their return flight. Tour ends.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:43:32', '2026-05-03 01:43:32'),
(2760, 'App\\Models\\ManadoTour', 12, 1, 'ARRIVAL – MANADO CITY TOUR – MAKATETE HILL – SUN BAE MANADO', '<p style=\"text-align:justify;\">Upon arrival at Sam Ratulangi Airport Manado, the group will be welcomed by the tour guide and begin a city tour of Manado. Visit the city center, <strong>Chinatown</strong>, and <strong>Ban Hin Kiong Temple</strong> - the oldest temple in Manado, built in the 18th century (±300 years old). Continue by passing <strong>Sentrum Church</strong>, the first Protestant church in North Sulawesi from the Dutch era, and the <strong>World War II Monument</strong>, which marks the destruction of Manado in 1942 by Japanese forces.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The tour then proceeds to the Ring Road area of <strong>CitraLand</strong> to see the <strong>Blessing Jesus Monument</strong>, a statue of Jesus built in a unique forward-leaning position overlooking Manado City. After that, visit <strong>Makatete Hill</strong> - located at 200 meters above sea level, offering panoramic views of Manado City, <strong>Manado Tua Island</strong>, <strong>Bunaken Island</strong>, <strong>Siladen Island</strong>, the open sea, and <strong>Mount Klabat</strong>, the highest peak in North Sulawesi.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Dinner will be optional at a local restaurant. After dinner, visit <strong>SunBae</strong>, one of Manado’s trendy seaside hangout spots, where guests may enjoy the evening atmosphere along with various snacks and drinks from numerous food stalls (optional). Afterwards, transfer to the hotel for check-in and rest.</p>', NULL, 'No Meals', '2026-05-03 01:43:45', '2026-05-03 01:43:45');
INSERT INTO `itineraries` (`id`, `itinerable_type`, `itinerable_id`, `day_number`, `title`, `description`, `hotel_info`, `meals_info`, `created_at`, `updated_at`) VALUES
(2761, 'App\\Models\\ManadoTour', 12, 2, 'MINAHASA HIGHLAND TOUR', '<p style=\"text-align:justify;\">After breakfast at the hotel, the participants will be picked up by the tour guide for a full-day excursion to the <strong>Minahasa Highlands</strong>, passing through the Tinoor area where guests can enjoy panoramic views of Manado City from an altitude of 500 meters.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Upon arrival in Tomohon, visit the <strong>Pelangi Tourism Park</strong>, where participants can admire the beauty of various colorful flowers. Continue to the <strong>Tomohon Extreme Market</strong>, where guests can see a variety of wild meats such as bats, forest rats, snakes, and other exotic animals. At a separate spot, guests may also witness the <strong>live cooking</strong> process of Manado traditional snacks such as <i>kue cucur</i>, <i>apang gula merah</i>, <i>dodol</i>, and other local delicacies.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">The tour continues to <strong>Tuur Maasering</strong>, a forest of aren (palm) trees featuring several Instagrammable photo spots. Here, participants can also observe the traditional production of the local liquor <strong>“Cap Tikus,”</strong> made through the fermentation and distillation of aren tree sap.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Optional lunch at a local restaurant. After lunch, the journey continues to <strong>Bukit Kasih</strong>, a unique natural attraction featuring active sulfur craters and stairways leading to the hilltop, offering scenic views and a distinctive cultural experience. The area also has natural sulfur hot springs where guests may swim or soak their feet for relaxation (optional).</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Next, visit <strong>Lake Linow</strong>, a sulfur lake famous for its ever-changing water colors and beautiful scenery, where coffee or tea will be served. Return to Manado City. Optional dinner at a local restaurant, followed by transfer back to the hotel.</p>', NULL, 'Breakfast', '2026-05-03 01:43:45', '2026-05-03 01:43:45'),
(2762, 'App\\Models\\ManadoTour', 12, 3, 'TRANSFER OUT – DEPARTURE', '<p style=\"text-align:justify;\">After breakfast and completing the hotel check-out process, the tour participants will be picked up by the guide and transferred directly to the airport for their return flight. Tour ends.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>', NULL, 'Breakfast', '2026-05-03 01:43:45', '2026-05-03 01:43:45'),
