(2905, 'App\\Models\\InternationalTour', 69, 1, 'JAKARTA – NEW YORK', '<ul><li data-list-item-id=\"e281dcae08fc7f8da2a9c58bf202d30b3\"><p style=\"text-align:justify;\">Hari ini berkumpul di bandara internasional Soekarno Hatta 4 jam sebelum keberangkatan</p></li><li data-list-item-id=\"e3faacaac54ce0d40ec53422b900d63cb\"><p style=\"text-align:justify;\">Check in &amp; Bagasi diurus oleh Welcome Manado Tours</p></li><li data-list-item-id=\"e8aa252c1a91f20510446557cc388602e\"><p style=\"text-align:justify;\">Penerbangan dengan Turkies Airlines atau maskapai serupa dan<strong> </strong>transit</p></li><li data-list-item-id=\"e044b987dfbcfeecc34a77b0303ed64e3\"><p style=\"text-align:justify;\">Penerbangan lanjutan menuju New York</p></li><li data-list-item-id=\"ef2ce465f140361bc58e691e342a1739b\"><p style=\"text-align:justify;\">Makan dan minum disediakan di pesawat</p></li></ul>', NULL, NULL, '2026-05-11 08:38:30', '2026-05-11 08:38:30'),
(2906, 'App\\Models\\InternationalTour', 69, 2, 'ARRIVE IN NEW YORK  (No Meals)', '<ul><li data-list-item-id=\"ed3ef58cb09af7b55aef2f55a2eda64c5\"><p style=\"text-align:justify;\">Tiba di <strong>JFK/Newmark Liberty International Airport</strong></p></li><li data-list-item-id=\"e4111de1b4e93aa528503ff9979b1f5c2\"><p style=\"text-align:justify;\">Berfoto di <strong>UN Building</strong>, <strong>Rockerfellar</strong></p></li><li data-list-item-id=\"e1759cf566017f9bc1632e9960259f53e\"><p style=\"text-align:justify;\">Mengunjungi <strong>Ground Zero</strong>, <strong>Trinity Chruch</strong>, <strong>Wallstreet</strong></p></li><li data-list-item-id=\"ed54f41a168174e443f4d08990fbf507e\"><p style=\"text-align:justify;\">Check in Hotel : La Quinta Clifton Rutherford or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:30', '2026-05-11 08:38:30'),
(2907, 'App\\Models\\InternationalTour', 69, 3, 'NEW YORK (B)', '<ul><li data-list-item-id=\"ea195f42ced5c7e52b07ade722abf4879\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p><p style=\"text-align:justify;\">New York City tour :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"edb57787e87cff561ba32effae142842d\"><p style=\"text-align:justify;\"><strong>Liberty Cruise</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ec2b9ceb2d051f25d66c8e164e59778e1\"><p style=\"text-align:justify;\"><strong>Empire State Building</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ecabbc43a8330596c9dee60ddcae7a8d0\"><p style=\"text-align:justify;\"><strong>5th Avenue</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e02e5e21a3dd31c0252e17eb519ec82ce\"><p style=\"text-align:justify;\"><strong>Time Square</strong></p></li><li data-list-item-id=\"e873ccf425df9fd19a15cff9836362f14\"><p style=\"text-align:justify;\">Check in Hotel : La Quinta Clifton Rutherford or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:30', '2026-05-11 08:38:30'),
(2908, 'App\\Models\\InternationalTour', 69, 4, 'NEW YORK – WOODBURRY OUTLET – BOSTON (B)', '<ul><li data-list-item-id=\"ece88ac880cf443e14e4f6b1aa9c2d5f1\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p></li><li data-list-item-id=\"e602075e41b3d8490034754d1cf1676c8\"><p style=\"text-align:justify;\">Transfer to <strong>Woodburry Common Premium Outlet</strong></p></li><li data-list-item-id=\"eea3c7cb31105400ca6571ad52025d214\"><p style=\"text-align:justify;\">Free time for shopping</p></li><li data-list-item-id=\"e294d19a863033777a909ed9c20f578e1\"><p style=\"text-align:justify;\">Perjalanan menuju <strong>Boston</strong></p></li><li data-list-item-id=\"e9b8a95a30e686771d8634b739e45135a\"><p style=\"text-align:justify;\">Check in Hotel : Holiday Inn Boston Logan Airport or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:30', '2026-05-11 08:38:30'),
