(2910, 'App\\Models\\InternationalTour', 69, 6, 'MONTREAL – QUEBEC – MONTREAL (B)', '<ul><li data-list-item-id=\"e3b817e67b25f4d3a510a8daa4fab5faf\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p><p style=\"text-align:justify;\"><strong>Quebec</strong> City Tour :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e6f1c195374b0c73b7dfbe5e53fbf3dee\"><p style=\"text-align:justify;\"><strong>City Hall</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"eb453a5ccd9e97dbc18e167af3948a610\"><p style=\"text-align:justify;\"><strong>Citadelle</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e0ae6e302e5c6df7b7a12a676b5abebf8\"><p style=\"text-align:justify;\"><strong>Chateu Fronteac</strong></p><p style=\"text-align:justify;\">Kembali ke Montreal</p></li><li data-list-item-id=\"ee032194b25d536ba510d60d3de408d73\"><p style=\"text-align:justify;\"><strong>Montreal</strong> City Tour :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e23e679248cb7f15a3c773f8902250f45\"><p style=\"text-align:justify;\"><strong>Old Town</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ef688b13ecd8a683caa4ddf43eb3cc885\"><p style=\"text-align:justify;\"><strong>Notredame</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e2b30de2bec40adadcfacee36328879db\"><p style=\"text-align:justify;\"><strong>City Hall</strong></p></li><li data-list-item-id=\"eb50da1a084312c2451d924c390b5fe81\"><p style=\"text-align:justify;\">Check in Hotel : Holiday Inn Montreal-Longueil or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2911, 'App\\Models\\InternationalTour', 69, 7, 'MONTREAL – OTTAWA – TORONTO (B)', '<ul><li data-list-item-id=\"edcedbdb147f6cbba6e11088569fbc77d\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p><p style=\"text-align:justify;\">Perjalanan menuju Ottawa dan mengunjungi :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ed79b48c8b16f894507e3115e8ea4cca9\"><p style=\"text-align:justify;\"><strong>Parliament Hill &amp; Building</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e591114af743afdb6d66f1a0144f0b3d2\"><p style=\"text-align:justify;\"><strong>Ottawa Memorial</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e1dfe660c40426f1efc016389800dd074\"><p style=\"text-align:justify;\"><strong>Embassy District</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e6b318d8e74c515d270acb566fabcec3f\"><p style=\"text-align:justify;\"><strong>Rideau Canal</strong></p><p style=\"text-align:justify;\">Perjalanan menuju <strong>Toronto</strong></p></li><li data-list-item-id=\"e4e2049dd7a249a5791f5f8560274a41e\"><p style=\"text-align:justify;\">Check in Hotel<strong> : </strong>Holiday Inn Mississauga Toronto West or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2912, 'App\\Models\\InternationalTour', 69, 8, 'TORONTO – NIAGARA FALLS CANADA SIDE – NEW YORK (NIAGARA) (B)', '<ul><li data-list-item-id=\"e2419fa9f82c1bbe918e77b99dd21cf04\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p><p style=\"text-align:justify;\">Toronto City Tour :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ebd638477048f2ca21e4e4ca55c84fce9\"><p style=\"text-align:justify;\"><strong>CN Tower</strong></p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"e9ccab3568c68cad1406df9543c7cb3bd\"><p style=\"text-align:justify;\"><strong>City Hall</strong></p><p style=\"text-align:justify;\">Perjalanan menuju Niagara Falls Canada Side</p></li><li data-list-item-id=\"ea250a4e94d1c63815cb9f0c09dc18eec\"><p style=\"text-align:justify;\">Mengunjungi <strong>Niagara Canada Side Free Program</strong></p></li><li data-list-item-id=\"ec60328b7eab3de5839690c4038ec1f14\"><p style=\"text-align:justify;\">Mengunjungi <strong>Niagara Falls Factory Outlet USA Side</strong></p></li><li data-list-item-id=\"eb6f071145c41fa53fca7091efcde167d\"><p style=\"text-align:justify;\">Check in Hotel : Holiday Inn Express &amp; Suites Niagara or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2913, 'App\\Models\\InternationalTour', 69, 9, 'NIAGARA – BALTIMORE (B)', '<ul><li data-list-item-id=\"e5fe7db42475302d2567427ca6becb35e\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p></li><li data-list-item-id=\"e82e1576d6f301705b7ca555b98eb69e0\"><p style=\"text-align:justify;\">Perjalanan menuju <strong>Baltimore</strong></p></li><li data-list-item-id=\"e4a2e985d76831e435548b14bbc8a87e7\"><p style=\"text-align:justify;\">Check in Hotel : Holiday Inn Express &amp; Suites Baltimore West Catonsville or Somilar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2914, 'App\\Models\\InternationalTour', 69, 10, 'BALTIMORE – WASHINGTON DC – NEW YORK (B)', '<ul><li data-list-item-id=\"ef9124ce842ab16c1b4367b3e03df99b7\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p><p style=\"text-align:justify;\">Washington DC City Tour :</p></li><li class=\"ck-list-marker-bold\" data-list-item-id=\"ec837b145f9dd6f481b451ade90bb2eda\"><p style=\"text-align:justify;\"><strong>Washington Monument, White House, Lincoln Memorial, Vietnam War, Korean War, Capitol Hill</strong></p><p style=\"text-align:justify;\">Perjalanan menuju New York</p></li><li data-list-item-id=\"efe5fbba19adb1239c66c8eaea35b951a\"><p style=\"text-align:justify;\">Check in Hotel : La Quinta Clifton Rutherford or Similar (*3)</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2915, 'App\\Models\\InternationalTour', 69, 11, 'NEW YORK – JAKARTA (B)', '<ul><li data-list-item-id=\"e18a459c32b01fa077f46e23b615b6163\"><p style=\"text-align:justify;\">Sarapan Pagi di Hotel</p></li><li data-list-item-id=\"efc443e8ecee006b9211803e57c325553\"><p style=\"text-align:justify;\">Pagi ini Anda akan check out dan akan diantar ke Bandara untuk Penerbangan Kembali ke Jakarta Indonesia</p></li></ul>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2916, 'App\\Models\\InternationalTour', 69, 12, 'ARRIVE IN JAKARTA', '<p style=\"text-align:justify;\">Tiba di Jakarta. Semoga perjalanan ini mengesankan.</p>', NULL, NULL, '2026-05-11 08:38:31', '2026-05-11 08:38:31'),
(2980, 'App\\Models\\InternationalTour', 70, 1, 'JAKARTA – DEPARTURE BEIJING  (MEALS ON BOARD)', '<p>Hari ini kita berkumpul di Bandara Soekarno-Hatta terminal 3 Ultimate untuk berangkat menuju ke Beijing dengan Malaysia Airlines. Bermalam di pesawat</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2981, 'App\\Models\\InternationalTour', 70, 2, 'BEIJING (MAKAN SIANG)', '<p>Setelah sampai di Beijing, kita akan disambut oleh Guide yang ramah dan kita akan mengunjungi Temple of Heaven merupakan kuil dengan arsitektur yang khas dan megah, Kemudian dilanjutkan menuju Tian An Men Square yang merupakan lapangan terluas di dunia, selanjutnya kita akan menuju Wangfujing Street untuk berbelanja. Check-in Hotel Istirahat. Bermalam di Hotel *3 atau *4 local / similar</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2982, 'App\\Models\\InternationalTour', 70, 3, 'BEIJING (MAKAN PAGI)', '<p>Sarapan pagi di hotel. Kita akan mengunjungi Universal Studios Beijing yang merupakan taman hiburan Universal Studios pertama yang dibangun di Tiongkok, memiliki beragam area bertema, seperti Hollywood, Jurassic World Isla Nublar, Kung Fu Panda Land of Awesomeness, The Wizarding World of Harry Potter, dan masih banyak lainnya, yang Setiap area menawarkan pengalaman unik dengan wahana, pertunjukan, dan restoran yang terinspirasi dari film-film populer yang dapat dinikmati untuk segala usia, dengan memberikan petualangan luar biasa yang menyenangkan. Check-in Hotel istirahat. Bermalam di Hotel *3 atau *4 local / similar</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2983, 'App\\Models\\InternationalTour', 70, 4, 'BEIJING (MAKAN PAGI, MAKAN SIANG, MAKAN MALAM)', '<p>Sarapan pagi di hotel. Kita akan mengunjungi Juyongguan Great Wall, tembok terpanjang didunia dan termasuk salah satu keajaiban dunia. Dilanjutkan menuju Beijing Stadium Nasional atau yang dikenal dengan Bird’s Nest (PhotoStop) &amp; Water Cube National Aquatics Center (Outlook), kemudian kita menuju Xiushui Market dan kita akan mencoba makanan khas dari negara China yaitu bebek Peking. Check-in Hotel istirahat. Bermalam di Hotel *3 atau *4 local / similar</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2984, 'App\\Models\\InternationalTour', 70, 5, 'BEIJING - SUZHOU - HANGZHOU (MAKAN PAGI, MAKAN MALAM)', '<p>Sarapan pagi di hotel, Kita akan menuju Suzhou menggunakan Bullet Train. Setibanya di Suzhou, kita akan menuju Oriental Gate (Photo stop) Gedung pencakar langit yang ikonik, dilanjutkan menuju Jinji Lake, danau terbesar di kota China. Melanjutkan perjalanan menuju Hangzhou dan mengunjungi Hefang Street jalan bersejarah di Hangzhou menawarkan pengalaman berjalan kaki yang unik dengan suasana santai sambil belanja serta menikmati kuliner lokal. Check-in Hotel istirahat. Bermalam di Hotel *3 atau *4 local / similar</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2985, 'App\\Models\\InternationalTour', 70, 6, 'HANGZHOU –WUZHEN – SHANGHAI (MAKAN PAGI, MAKAN SIANG, MAKAN MALAM)', '<p>Sarapan pagi di hotel, kita akan mengunjungi West Lake menggunakan Kapal, kemudian kita akan menikmati keindahan dan ketenangan panorama west lake di Su Di. Dilanjutkan mengunjungi Wuzhen East Gate (Exclude rowing boat) yang merupakan salah satu pintu masuk utama ke kawasan Wuzhen yang menggambarkan pesona tradisional dan kaya akan budaya, Kemudian mengunjungi Chenghuang Market tempat beragam kuliner khas Shanghai dan souvenir yang dapat dibeli untuk oleh-oleh. Check-in Hotel istirahat. Bermalam di Hotel *3 atau *4 local / similar</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2986, 'App\\Models\\InternationalTour', 70, 7, 'SHANGHAI (MAKAN PAGI, MAKAN SIANG)', '<p>Sarapan pagi di hotel. Kemudian kita akan menuju The Bund yang merupakan simbol dari kota Shanghai, kemudian menuju Nanjing Road untuk berbelanja. Dilanjutkan perjalanan menuju airport.</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(2987, 'App\\Models\\InternationalTour', 70, 8, 'SHANGHAI – DEPARTURE (MEALS ON BOARD)', '<p>Hari ini kita akan kembali ke tanah air tercinta. Berakhirlah tour yang berkesan ini dan sampai jumpa di tour selanjutnya bersama kami.</p>', NULL, NULL, '2026-05-12 03:36:23', '2026-05-12 03:36:23'),
(3038, 'App\\Models\\InternationalTour', 71, 1, 'JAKARTA – SINGAPORE (MEALS ON BOARD)', '<p style=\"text-align:justify;\">Malam ini kita berkumpul di Bandara Soekarno-Hatta terminal 3 Ultimate untuk berangkat menuju Turkiye dengan Singapore Airlines (<i>Premium Airlines</i>).</p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3039, 'App\\Models\\InternationalTour', 71, 2, 'SINGAPORE - İSTANBUL – BURSA (MAKAN SIANG, makan malam)', '<p style=\"text-align:justify;\">Setiba di Istanbul, kita akan disambut oleh guide berbahasa Indonesia yang ramah, dan kita akan melanjutkan perjalanan menuju <i>Blue Mosque</i>, masjid dengan 6 menara dan berwarnakan biru yang menampilkan citra bangunan yang unik dan mengunjungi area <i>Hippodrome Square</i>. Kemduain kita akan berfoto di depan <i>Topkapi Palace (Photostop), </i>sebuah museum dan juga sebuah perpustakaan yang dibuat pada tahun 1465 M. Sore hari, kita akan berfoto di depan <i>Hagia Sophia Mosque </i>dan melanjutkan perjalanan menuju Bursa. <i>Check-in </i>Hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3040, 'App\\Models\\InternationalTour', 71, 3, 'BURSA - KUSADASI (makan pagi, makan siang, makan malam)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, kita akan menuju <i>Turkish Delight Shop</i>, untuk membeli oleh-oleh khas Turkiye. Kemudian mengunjungi <i>Tophane Clock Tower, </i>sebuah ikon menara jam yang dibuat pada abad ke-19, disini peserta dapat melihat kuburan dari pendiri Kerajaan Turki di masa lampau. Setelah itu kita menuju <i>Grand Mosque</i>, masjid bersejarah bergaya Ottoman dengan 20 kubah dan interior kaligrafi yang indah. Kita juga akan berbelanja di <i>Silk Market</i>, sebelum melanjutkan perjalanan menuju Kota Kusadasi. <i>Check-in </i>Hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3041, 'App\\Models\\InternationalTour', 71, 4, 'KUSADASI - PAMUKKALE (makan pagi, makan siang, makan malam)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, kita akan menuju <i>Sirince Village </i>sebuah Desa kecil di Kusadasi, yang terkenal dengan kebun anggur dan <i>Olive Oil-</i>nya. Kemudian kita akan menuju <i>Turkish Leather Shop, </i>sebuah toko tas kulit yang menjadi ikon dari Turkiye. Siang hari, perjalanan menuju Kota Pamukkale dan menuju <i>Natural Park &amp; Observation Point (Photostop), </i>disini peserta dapat berfoto pemandangan alam berupa batuan kapur putih yang cantik. Kemudian mengunjungi <i>Cotton Castle</i> (<i>Photostop</i>), area teras travertine putih alami berisi kolam air panas yang tampak seperti kastil kapas dan menjadi salah satu keajaiban alam paling terkenal di Turki. <i>Check-in </i>Hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3042, 'App\\Models\\InternationalTour', 71, 5, 'PAMUKKALE - CAPPADOCIA (makan pagi, makan siang, makan malam)', '<p>Sarapan pagi di hotel. Kita akan memulai hari dengan berbelanja di <i>Textile Outlet Shop</i>. Kemudian mengunjungi <i>Sultanhani Caravanserai</i> <i>(Photostop), </i>sebuah komplek di dekat Kota Konya, yang menjadi pusat dari jalur perdagangan modern/ <i>Modern Silkroad</i>. Melanjutkan perjalanan menuju Cappadocia, <i>Check-in </i>Hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3043, 'App\\Models\\InternationalTour', 71, 6, 'CAPPADOCIA (makan pagi, makan siang, makan malam)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, Kita akan menuju <i>Pigeon Valley &amp; Uchisar Castle</i>, yang menawarkan pemandangan lembah unik dengan rumah burung merpati di tebing batu serta benteng alami tertinggi di Cappadocia. Kemudian mengunjungi <i>Goreme Valley &amp; Panorama</i>, sebuah desa yang dibangun di tengah tengah formasi batuan yang cantik dengan bangunannya yang unik. Selanjutnya, berkunjung ke <i>Avanos Village &amp; Pottery Shop</i>, sebuah kota kecil yang penuh dengan kerajinan berbahan dasar tanah liat, yang ikonik di kota ini. Kita akan berbelanja di <i>Turkish Carpets &amp; Jewelry Shop</i>, sebelum check-in hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3044, 'App\\Models\\InternationalTour', 71, 7, 'CAPPADOCIA – ISTANBUL (makan pagi, makan siang, makan malam)', '<p>Sarapan pagi di hotel. Hari ini kita akan memulai perjalanan dengan mengunjungi <i>Salt Lake </i>(<i>Photostop)</i>, sebuah danau garam yang menempati luas di dataran tinggi Turki yang gersang, sekitar 65mil (105 km) timur laut Konya. Disini, kita dapat berfoto dengan pemandangan danau yang sangat indah. Kemudian kita akan melanjutkan perjalanan menuju Istanbul. <i>Check-in </i>Hotel dan istirahat.</p><p style=\"text-align:justify;\">Kembali ke hotel &amp; istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3045, 'App\\Models\\InternationalTour', 71, 8, 'ISTANBUL (makan pagi)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel. Kita akan mengunjungi <i>Ortakoy Village, </i>sebuah desa di Turki yang terletak di daratan benua Eropa dan dahulu menjadi pusat nelayan bagi kerajaan Turki. Kita akan menikmati pengalaman dengan <i>Bosphorus Cruise</i>, menyusuri Selat Bosphorus yang menawarkan pemandangan istana Ottoman, masjid megah, dan panorama unik antara benua Eropa dan Asia.<i> </i>Kemudian, kita akan berkeliling di <i>Taksim Square </i>yang menjadi pusat paduan budaya dan tradisi Asia dan Eropa. Kembali ke hotel dan istirahat.</p><p style=\"text-align:justify;\"><i>Bermalam di Hotel *4 / similar</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3046, 'App\\Models\\InternationalTour', 71, 9, 'ISTANBUL – SINGAPORE (makan pagi)', '<p style=\"text-align:justify;\">Sarapan pagi di hotel. Hari ini kita akan menuju bandara Istanbul untuk penerbangan kembali ke tanah air tercinta, via Singapore.</p><p style=\"text-align:justify;\"><i>Bermalam di pesawat</i></p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52');
INSERT INTO `itineraries` (`id`, `itinerable_type`, `itinerable_id`, `day_number`, `title`, `description`, `hotel_info`, `meals_info`, `created_at`, `updated_at`) VALUES
(3047, 'App\\Models\\InternationalTour', 71, 10, 'SINGAPORE – JAKARTA (meals on board)', '<p>Hari ini, kita akan melanjutkan penerbangan menuju Jakarta, terima kasih telah mengikuti <i>tour </i>kami, sampai jumpa di perjalanan selanjutnya.</p>', NULL, NULL, '2026-05-12 06:57:52', '2026-05-12 06:57:52'),
(3224, 'App\\Models\\InternationalTour', 72, 1, 'MANADO - GUANGZHOU', '<p>Tiba di Guangzhou bertemu dengan guide tour (tiba hari jumat), Transfer ke Hotel untuk check in</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3225, 'App\\Models\\InternationalTour', 72, 2, 'GUANGZHOU - CHONGQING', '<p>Transfer ke Chongqing dengan bullet train (G4012: 12.25-18.53) (makan siang tidak termasuk saat di stasiun), mengunjungi Jiefangbei Street, Kuixing Lou Building 22nd floor, mengunjungi Hongya Cave.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3226, 'App\\Models\\InternationalTour', 72, 3, 'CHONGQING', '<p>Mengunjungi Liziba Light Railway Photo stop, lalu mengunjungi Ciqikou Ancient Town, Menonton Chongqing 1949 Performance Show, makan malam spesial di PIPAYUAN HOT PОТ.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3227, 'App\\Models\\InternationalTour', 72, 4, 'CHONGQING - HUAI HUA - PHOENIX TOWN - JISHOU', '<p>Transfer ke Huai Hua dengan Bullet train, lalu transfer ke Fenghuang Phoenix Town dengan bus, Fenghuang Ancient city di Hongqiao, melihat Tuojiang Scenery: Skipping stones, Stone Street, North Gate Tower, menikmati Fenghuang City Night.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3228, 'App\\Models\\InternationalTour', 72, 5, 'JISHOU - ZHANGJIAJIE', '<p>Mengunjungi Zhangjiajie National Park, Tianzi Mountain, Bailong Lift Elevator Yuanjiajie, Avatar Mountain (Hallelujah Mountain).</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3229, 'App\\Models\\InternationalTour', 72, 6, 'ZHANGJIAJIE', '<p>Jinbianxi Scenic Area Golden Whip Stream, Junsheng Sandstone Painting Academy, makan malam BBQ Korea (Pilihan Paket Tour Tambahan: Grand Canyon Glass Bridge).</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3230, 'App\\Models\\InternationalTour', 72, 7, 'ZHANGJIAJIE', '<p>(Pilihan Paket Tour Tambahan: Tianmen Mountain (termasuk Cable Car), Glass Plank, Tianmen Cave (termasuk eskalator).</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3231, 'App\\Models\\InternationalTour', 72, 8, 'ZHANGJIAJIE - GUANGZHOU', '<p>Transfer ke Guangzhou dengan bullet train (G6151: 09.50-15.34), waktu bebas, makan malam dengan rencana sendiri.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3232, 'App\\Models\\InternationalTour', 72, 9, 'GUANGZHOU', '<p>Mengunjungi YueXiu Park, Mengunjungi Five Rams Statue, mengunjungi TV Tower Photo stop, waktu bebas Beijing Road Shop, makan malam dengan rencana sendiri.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3233, 'App\\Models\\InternationalTour', 72, 10, 'GUANGZHOU - MANADO', '<p>Sarapan di Hotel dan checkout, Transfer ke Bandara untuk departure, sampai di Manado.</p>', NULL, NULL, '2026-05-13 06:03:47', '2026-05-13 06:03:47'),
(3242, 'App\\Models\\InternationalTour', 73, 1, 'MANADO - GUANGZHOU', '<p>Sampai di Guangzhou dan bertemu guide, Transfer ke hotel untuk check in</p>', NULL, NULL, '2026-05-13 06:23:56', '2026-05-13 06:23:56'),
(3243, 'App\\Models\\InternationalTour', 73, 2, 'GUANGZHOU - SHENZHEN', '<p>Sarapan di Hotel dan checkout, Haixinsha Asian Games Theme Park, Canton Tower (outside view), Beijing Road Pedestrian Street, Yongqingfang Ancient Town, Transfer ke Shenzhen</p>', NULL, NULL, '2026-05-13 06:23:56', '2026-05-13 06:23:56'),
(3244, 'App\\Models\\InternationalTour', 73, 3, 'SHENZHEN', '<p>Sarapan di Hotel, Tibetan Medicine Hall, Shenzhen OH Bay Park, Bay Glory Ferris Wheel, Twin Tower &amp; Diwang Building (outside view). (Pilihan Paket Tour Tambahan: Window of the World Park)</p>', NULL, NULL, '2026-05-13 06:23:56', '2026-05-13 06:23:56'),
