(3555, 'App\\Models\\InternationalTour', 76, 9, 'SARAJEVO – BELGRADE ( B )', '<ul><li data-list-item-id=\"eb4a8a72ab792b05cafbb1fa46289ddde\">Breakfast di Hotel</li><li data-list-item-id=\"e547374a27fc00abdd58100ef7c947805\">Melanjutkan perjalananan menuju <strong>Belgrade </strong>(Melewati Zvornik - Sebia)</li><li data-list-item-id=\"e20be45a7226f7067b827f489137a6fc5\">Mengujungi <strong>Belgrade Fortress &amp; Saint Mark\'s Church</strong></li><li data-list-item-id=\"eb705985b9a85a9eb2595d14295ad2cdb\">Menjungi <strong>Republic Square, Muzej Nikole Tesle</strong></li><li data-list-item-id=\"e829c1d9af2e14087938684ae8efd7c6a\">Check in Hotel : Mark Hotel Belgrade or Similar (3*)</li></ul>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
