(3557, 'App\\Models\\InternationalTour', 76, 11, 'SIBIU – BRAN – BUCHAREST  ( B )', '<ul><li data-list-item-id=\"e30afd90b0a9e8e9436d542a656945d4d\">Breakfast di Hotel</li><li data-list-item-id=\"e12609aa76e3ae50e231dbd8aa9ea7d9e\">Transfer to <strong>Bran Transylvania</strong></li><li data-list-item-id=\"e10e02f3dbf1d0d6cea991a095adb0d60\">Mengunjungi <strong>Bran Castle</strong></li><li data-list-item-id=\"ea7a6706c9a3340b0b44e4f7d5a3351ac\">Transfer to <strong>Bucharest</strong></li><li data-list-item-id=\"e89e891285090d84a974d3d7a49507806\">Mengunjungi <strong>House of People (Gedung Parlement)</strong></li><li data-list-item-id=\"e333a75ff80b62a91435300121284690c\">&nbsp;Berfoto di <strong>Archul De Triumf</strong></li><li data-list-item-id=\"ea0f11d4533c322c14f9c8c3ffa417e56\">Mengunjungi <strong>Revolution Square</strong></li><li data-list-item-id=\"ee4038a5ed7e489ae7ab2987230ba4d55\">Check in Hotel Hotel : ibis Styles Bucharest City Center or Similar (3*)</li></ul>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
(3558, 'App\\Models\\InternationalTour', 76, 12, 'BUCHAREST – SOFIA (Bulgaria)  ( B )', '<ul><li data-list-item-id=\"e3aa61b76d3ec7fef9b20f1c0386c286a\">Breakfast di Hotel</li><li data-list-item-id=\"edf124d24bffe765f5dde8e73dd164505\">Transfer to Sofia</li><li data-list-item-id=\"e30b3642803e4061c6364e3e07239300d\">&nbsp;Berfoto di <strong>Patriarchal Cathedral St.Alexander Nevsky</strong></li><li data-list-item-id=\"e5dc09c140a4f68b57bcf4eda640e0d92\">&nbsp;Berfoto di <strong>Golden Dome</strong></li><li data-list-item-id=\"e4477ea79eee6c350b10972507a1a8c7d\">Mengunjungi <strong>Vitosha Boulevard</strong></li><li data-list-item-id=\"e3926b6a9f8822bb642eb684373e73173\">Check in Hotel Hotel : Grami Hotel Sofia or Similar (3*)</li></ul>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
(3559, 'App\\Models\\InternationalTour', 76, 13, 'SOFIA – PLOVDIV – ISTANBUL  ( B )', '<ul><li data-list-item-id=\"e772cddda6895c64a5287af65affc8291\">Breakfast di hotel</li><li data-list-item-id=\"e437dc7505061d129d22d8782602119d7\">Mengunjungi <strong>Old Town of Plovdiv &amp; Ancient Theatre of Philippopolis</strong></li><li data-list-item-id=\"ee2d2914880d4bbc2d3d83928aedf65a6\">Transfer to <strong>Istanbul</strong></li><li data-list-item-id=\"e3314ba3cec8500d05e04dd82841f697f\">Check in Hotel Hotel : Gonen Hotel Istanbul or Similar (4*)</li></ul>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
(3560, 'App\\Models\\InternationalTour', 76, 14, 'ISTANBUL – TRANSFER TO AIRPORT ( B )', '<ul><li data-list-item-id=\"ec0cc18b7d9442678586a9bd2f8bb4d5d\">Breakfast di hotel</li><li data-list-item-id=\"efaef7f33b5f7b56c1dcad71dcfc0c8d9\">Check out Hotel</li><li data-list-item-id=\"ec565e866f612517c7ec713629e3392ce\">Berfoto di <strong>Galata Tower</strong></li><li data-list-item-id=\"e2f7576b97fb295503fdb93edfc84f733\">Mengunjungi <strong>Taksim Square</strong></li><li data-list-item-id=\"e1ac9ceadb6ba5fc47ab708c759a43bc3\">Selanjutnya Anda akan diantar ke Bandara untuk Penerbangan kembali ke Indonesia dan Transit</li></ul>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
(3561, 'App\\Models\\InternationalTour', 76, 15, 'TIBA DI JAKARTA', '<ul><li data-list-item-id=\"ed2a965fb73e02542eb4836fbf09a8d1c\">Tiba di Jakarta dengan selamat. Semoga bertemu bersama Welcome Manado Tours dalam trip berikutnya.</li></ul><p><br>&nbsp;</p>', NULL, NULL, '2026-05-15 08:10:22', '2026-05-15 08:10:22'),
(3602, 'App\\Models\\InternationalTour', 77, 1, 'SURABAYA/JAKARTA - SINGAPORE - BEIJING', '<p style=\"text-align:justify;\">Peserta tour dari Surabaya dan Jakarta akan berangkat menuju Beijing dengan terlebih dahulu transit di Singapore. Setibanya di Bejing akan di antar menuju Hotel untuk persiapan Tour esok hari.</p>', NULL, NULL, '2026-05-16 01:41:49', '2026-05-16 01:41:49'),
(3603, 'App\\Models\\InternationalTour', 77, 2, 'BEIJING CITY TOUR (BLD)', '<p style=\"text-align:justify;\">Setelah bersantap pagi, tour Beijing hari ini diawali dengan mengunjungi&nbsp; <strong>Tiananmen Square</strong>. Lapangan seluas 44hektar ini adalah warisan masa kejayaan Mao Zedong pendiri negara Tiongkok. Kemudian berlanjut menuju <strong>Forbidden City</strong> yang terletak persis di seberang Tiananmen Square,yang merupakan istana yang pernah di tinggali oleh 24 kaisar yang pernah berkuasa di Tiongkok, dalam kurun waktu 492 tahun. (Bila tidak memungkinkan akan diganti dengan mengunjungi Temple of Heaven). Selanjutnya acara tour hari ini akan berakhir di <strong>Wangfujing</strong> di mana Anda bisa berbelanja souvenier maupun makanan tradisional sebelum makan malam bersama dengan menu special <strong>Peking Duck Dinner</strong>.</p><p style=\"text-align:justify;\"><strong>SHOP: Tongrentang</strong></p>', NULL, NULL, '2026-05-16 01:41:49', '2026-05-16 01:41:49'),
(3604, 'App\\Models\\InternationalTour', 77, 3, 'BEIJING - HUANGSHAN (BD)', '<p style=\"text-align:justify;\">Perjalanan Anda hari ini dilanjutkan dengan menggunakan Bullet Train menuju <strong>Huangshan</strong> yang memiliki keindahan alam dan juga terkenal karena konon merupakan tempat dimana Kaisar Huang menemukan keabadian. Sebelum mendaki puncak Huangshan, Anda akan terlebih dahulu diajak untuk mengunjungi <strong>Tunxi Old Street,</strong> sebuah area bersejarah yang memiliki koleksi lebih dari 300 gedung dengan arsitektus Hui-Style yang telah berusia ratusan tahun. Kemudian menuju <strong>Liyang in Lane</strong>, yang telah berhasil mempertahankan diri sebagai pusat perdagangan selama 1.800 tahun selama Dynasty Ming, Qing, Tang dan Song.</p><p><strong>SHOP: Latex &amp; Baoshutang</strong></p>', NULL, NULL, '2026-05-16 01:41:49', '2026-05-16 01:41:49'),
(3605, 'App\\Models\\InternationalTour', 77, 4, 'HUANGSHAN - SHANGRAO (BLD)', '<p style=\"text-align:justify;\">Di Huangshan hari ini, Anda akan dibuat terkagum dengan keindahan alam <strong>Huangshan</strong> yang konon katanya menyimpan rahasia obat awet muda dari Kaisar Huang. Untuk naik menuju puncaknya Anda akan diajak untuk menggunakan Cable Car sehingga kecantikan gunung Huangsahn akan lebih dapat Anda nikmati. Setelah itu perjalanan di lanjutkan menuju ke Shangrao dengan menggunakan Tourist Bus untuk melihat dari dekat kota tempat tinggal para peri di <strong>Wangxian Village</strong> saat waktu malam.</p>', NULL, NULL, '2026-05-16 01:41:49', '2026-05-16 01:41:49'),
(3606, 'App\\Models\\InternationalTour', 77, 5, 'SHANGRAO - HANGZHOU (BD)', '<p style=\"text-align:justify;\">Dengan menggunakan Bullet Train, Anda akan melanjutkan perjalanan menuju ke Hangzhou untuk mengunjungi <strong>West Lake</strong>, danau yang sejak jaman dahulu menjadi inspirasi para pujangga dan juga seniman China karena keindahannya. Dan di sini Anda akan diajak sejenak berperahu untuk lebih menikmati kecantikan alam West Lake dengan belaian semilir angin danau.</p><p style=\"text-align:justify;\"><strong>SHOP: Jewelry</strong></p>', NULL, NULL, '2026-05-16 01:41:49', '2026-05-16 01:41:49'),
(3607, 'App\\Models\\InternationalTour', 77, 6, 'HANGZHOU - SHANGHAI (BLD)', '<p style=\"text-align:justify;\">Acara tour Anda hari ini dilanjutkan dari kota Hangzhou menuju Shanghai. Sesampainya di Shanghai, Anda akan diajak mengunjungi Tianzifang dan <strong>Nanjing Road</strong> yang akan memuaskan keinginan shopping Anda, mulai dari berbagai produk branded hingga oleh-oleh tradisional bergaya oriental. Perjalanan kemudian ditutup dengan mengunjungi <strong>The Bund</strong>, ikon wisata tepi Sungai Huangpu yang menawarkan panorama gemerlap kota Shanghai yang memukau.</p><p><strong>SHOP: Silk</strong></p>', NULL, NULL, '2026-05-16 01:41:50', '2026-05-16 01:41:50'),
(3608, 'App\\Models\\InternationalTour', 77, 7, 'SHANGHAI - AIRPORT (BL)', '<p>Di hari terakhir kunjungan Anda di Shanghai ini, masih ada beberapa tempat menarik yang akan Anda kunjungi diantaranya, <strong>Wukang Street</strong> – Sebuah Area yang sangat kental dengan arsitektur perancis pernah menjadi tempat tinggal dan juga pusat bisnis warga Perancis di masanya. Selanjutnya menuju <strong>Chenghuang Market</strong> area perbelanjaan dengan arsitektur oriental lama yang kental. Dan sebelum menuju Airport masih ada dua lokasi lain yang akan Anda kunjungi yaitu <strong>Starbuck Roastery</strong> – yang akan menyuguhkan kepiawaian mereka dalam mengolah kopi dan <strong>Xintiandi</strong> tempat perbelanjaan dan hiburan modern yang dipadu dengan gaya arsitektur campuran Oriental Eropa.</p>', NULL, NULL, '2026-05-16 01:41:50', '2026-05-16 01:41:50'),
(3609, 'App\\Models\\InternationalTour', 77, 8, 'SHANGHAI – SINGAPORE – SURABAYA/JAKARTA', '<p>Home Sweet Home, Selamat datang kembali di Tanah Air</p>', NULL, NULL, '2026-05-16 01:41:50', '2026-05-16 01:41:50'),
(3610, 'App\\Models\\InternationalTour', 78, 1, 'SURABAYA/JAKARTA - SINGAPORE - BEIJING', '<p style=\"text-align:justify;\">Peserta tour dari Surabaya akan berangkat menuju Beijing dengan terlebih dahulu transit di Singapore. Setibanya di Bejing akan di antar menuju Hotel untuk persiapan Tour esok hari.</p>', NULL, NULL, '2026-05-16 02:04:59', '2026-05-16 02:04:59'),
(3611, 'App\\Models\\InternationalTour', 78, 2, 'BEIJING CITY TOUR (BLD)', '<p style=\"text-align:justify;\">Setelah bersantap pagi, tour Beijing hari ini diawali dengan mengunjungi <strong>Tiananmen Square</strong>. Lapangan seluas 44 hektar ini merupakan warisan masa kejayaan Mao Zedong, pendiri negara Tiongkok modern. Kemudian perjalanan dilanjutkan menuju <strong>Forbidden City</strong> yang terletak tepat di seberang <strong>Tiananmen Square</strong>, istana megah yang pernah dihuni oleh 24 kaisar Tiongkok selama kurang lebih 492 tahun. Selanjutnya Anda akan diajak menuju <strong>Wangfujing</strong> untuk berbelanja souvenir maupun mencicipi makanan tradisional. Hari ini juga Anda akan menikmati menu spesial <strong>Peking Duck</strong> sebagai bagian dari perjalanan tour di Beijing.</p><p><strong>SHOP: Tongrentang</strong></p>', NULL, NULL, '2026-05-16 02:04:59', '2026-05-16 02:04:59'),
(3612, 'App\\Models\\InternationalTour', 78, 3, 'BEIJING CITY TOUR (BLD)', '<p style=\"text-align:justify;\">Setelah bersantap pagi di hotel, Anda akan di ajak berkunjung menuju salah satu gerbang Great Wall, yang merupakan legacy dari Dynasty Ming yaitu <strong>Juyongguan</strong>, dimana gerbang yang juga berfungsi sebagai markas militer ini adalah pintu yang langsung menuju ke Beijing. Kemudian foto stop di <strong>Birdnest dan Water Cube</strong> yang merupakan landmark kota Beijing saat memeriahkan Olimpiade 2008.&nbsp;</p><p><strong>SHOP: Latex, Baoshutang</strong></p>', NULL, NULL, '2026-05-16 02:04:59', '2026-05-16 02:04:59'),
(3613, 'App\\Models\\InternationalTour', 78, 4, 'BEIJING UNIVERSAL STUDIO (B)', '<p style=\"text-align:justify;\">Acara di Beijing hari ini adalah mengunjungi Universal Studio Beijing yang baru saja di resmikan pada akhir tahun 2021 silam. Anda dapat mengunjungi CityWalk di depan Universal Studio yang menyediakan berbagai macam pilihan makanan dan juga toko-toko untuk berbelanja.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>BAGI YANG MASUK KE DALAM UNIVERSAL STUDIO BEIJING :</strong></p><p style=\"text-align:justify;\">Anda dapat memuaskan diri berkunjung ke Universal Studio Beijing yang merupakan Universal Studio terbesar di dunia dengan beragam permainan. Dan anda akan dijemput kembali malam hari sekitar pukul 21.00 untuk kembali ke hotel.</p><p style=\"text-align:justify;\">(Ticket masuk Universal Studio belum termasuk dalam harga tour ini, dan tidak disediakan makan siang &amp; makan malam untuk hari ini bagi yang masuk/bermain di Universal Studio)</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>BAGI YANG TIDAK MASUK KE DALAM UNIVERSAL STUDIO BEIJING :</strong></p><p style=\"text-align:justify;\">Jangan kawatir karena tour akan dilanjutkan dengan mengunjungi <strong>City Library, </strong>sebuah perpustakaan yang memiliki koleksi buku dan juga ruangan baca terluas di dunia dengan koleksi buku lebih dari 8juta buku dari berbagai Bahasa. Selanjutnya menuju <strong>Scitech Premium Outlet</strong>, yang akan menjadi surga berbelanja Anda dengan tag line mereka yang terkenal “Big Brand Small Price”. Menjelang malam kembali ke Beijing Universal Studio untuk menjemput tamu yang masuk/bermain di Universal Studio, kemudian kembali ke hotel. (makan siang dan makan malam tidak tersedia hari ini, anda dapat menikmati pilihan makanan Anda di banyak restoran di Citywalk depan Universal Studio)</p>', NULL, NULL, '2026-05-16 02:04:59', '2026-05-16 02:04:59'),
(3614, 'App\\Models\\InternationalTour', 78, 5, 'BEIJING - SHANGHAI (BD)', '<p>Perjalanan hari ini dilanjutkan menuju Shanghai dengan menggunakan Bullet Train. Setibanya di Shanghai, Anda akan diajak berbelanja oleh-oleh di <strong>Nanjing Roa</strong>d, area perbelanjaan sepanjang lebih dari 5 km yang tentunya akan memuaskan keinginan berbelanja Anda. Setelah itu, perjalanan dilanjutkan menuju <strong>The Bund</strong>, destinasi ikonik yang tidak boleh dilewatkan. Dari salah satu tepian The Bund yang dipisahkan oleh Sungai Huangpu, Anda dapat menyaksikan gemerlap kota Shanghai serta menara TV Pearl Tower yang menjulang megah.</p>', NULL, NULL, '2026-05-16 02:04:59', '2026-05-16 02:04:59'),
(3615, 'App\\Models\\InternationalTour', 78, 6, 'SHANGHAI DISNEYLAND (B)', '<p style=\"text-align:justify;\">Hari ini saatnya memanjakan fantasi Anda di Shanghai Disneyland.</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>BAGI YANG MASUK KE DALAM SHANGHAI DISNEYLAND :</strong></p><p style=\"text-align:justify;\">Anda dapat memuaskan diri berkunjung ke Shanghai Disneyland yang merupakan Universal Studio terbesar di dunia dengan beragam permainan. Dan anda akan dijemput kembali malam hari untuk kembali ke hotel.</p><p style=\"text-align:justify;\">(Ticket masuk Shanghai Disneyland belum termasuk dalam harga tour ini, dan tidak disediakan makan siang &amp; makan malam untuk hari ini bagi yang masuk/bermain di Shanghai Disneyland)</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\"><strong>BAGI YANG TIDAK MASUK KE DALAM SHANGHAI DISNEYLAND :</strong></p><p style=\"text-align:justify;\">Seharian ini Anda akan di bawa mengeksplor <strong>Florentia Village</strong>, sebuah shopping area yang akan memuaskan Anda berbelanja dan juga menikmati keindahan arsitektur lokasi nya yang akan membawa Anda seolah berbelanjadi di Eropa. Petang harinya kembali ke Shanghai Disneyland untuk menjemput tamu yang masuk/bermain di Universal Studio, kemudian kembali ke hotel.</p><p style=\"text-align:justify;\">(makan siang dan makan&nbsp; malam tidak tersedia hari ini, anda dapat menikmati pilihan makanan anda di banyak restoran di depan Shanghai Disneyland).</p><p><strong>SHOP: Silk</strong></p>', NULL, NULL, '2026-05-16 02:05:00', '2026-05-16 02:05:00'),
(3616, 'App\\Models\\InternationalTour', 78, 7, 'SHANGHAI - AIRPORT (BL)', '<p style=\"text-align:justify;\">Di hari terakhir kunjungan Anda di Shanghai ini, masih ada beberapa tempat menarik yang akan Anda kunjungi diantaranya, <strong>Wukang Street</strong> – Sebuah Area yang sangat kental dengan arsitektur perancis pernah menjadi tempat tinggal dan juga pusat bisnis warga Perancis di masanya. Selanjutnya menuju <strong>Chenghuang Market</strong> area perbelanjaan dengan arsitektur oriental lama yang kental. Dan sebelum menuju Airport masih ada tiga lokasi lain yang akan Anda kunjungi yaitu <strong>Starbuck Roastery</strong> – yang akan menyuguhkan kepiawaian mereka dalam mengolah kopi, <strong>Xintiandi</strong> tempat perbelanjaan dan hiburan modern yang dipadu dengan gaya arsitektur campuran Oriental Eropa serta menuju ke <strong>Zhangyuan Shikumen</strong> Shanghai.</p><p><strong>SHOP: Jewelry</strong></p>', NULL, NULL, '2026-05-16 02:05:00', '2026-05-16 02:05:00'),
(3617, 'App\\Models\\InternationalTour', 78, 8, 'SHANGHAI – SINGAPORE – SURABAYA/JAKARTA', '<p>Home Sweet Home, Selamat datang kembali di Tanah Air.</p>', NULL, NULL, '2026-05-16 02:05:00', '2026-05-16 02:05:00'),
(3868, 'App\\Models\\IndonesiaDestination', 73, 1, 'DETAIL ITINERARY', '<p style=\"text-align:justify;\">Perjalanan dimulai pada pukul 09.00 pagi dengan penjemputan di hotel oleh tim profesional kami. Anda akan disambut dengan layanan ramah dan perjalanan dimulai menuju Desa Sukarara, sebuah desa yang terkenal sebagai pusat tenun tradisional khas Lombok. Di sini, Anda dapat melihat langsung proses pembuatan kain tenun secara tradisional yang diwariskan secara turun-temurun oleh masyarakat setempat.</p><p style=\"text-align:justify;\"><br><br>Perjalanan dilanjutkan menuju Desa Adat Rambitan Sade pada pukul 11.00, di mana Anda akan diajak untuk mengenal lebih dekat kehidupan dan budaya suku Sasak. Anda akan melihat rumah adat yang unik serta mendengar cerita mengenai tradisi dan kehidupan masyarakat lokal yang masih sangat terjaga hingga saat ini.</p><p style=\"text-align:justify;\"><br><br>Memasuki waktu makan siang sekitar pukul 12.30, Anda akan menikmati hidangan lokal di kawasan Kuta Mandalika.</p><p style=\"text-align:justify;\"><br><br>Setelah makan siang, perjalanan berlanjut ke Mandalika International Circuit pada pukul 13.30. Di sini Anda dapat memilih salah satu aktivitas seru seperti bersepeda mengelilingi sirkuit, mencoba drift kart yang memacu adrenalin, atau merasakan pengalaman berkendara motor ADV di lintasan balap berstandar internasional (dengan tambahan biaya).</p><h2>&nbsp;</h2><h2>MANDALIKA CIRCUIT ACTIVITIES (Choose 1)</h2><ul><li data-list-item-id=\"ef8957a48a1ceac8eb6fbb46b3e8d3b39\">Bike Experience – Ride around the circuit</li><li data-list-item-id=\"e2a4cabef67c550ff9817a7481b306e6a\">Drift Kart – Feel the adrenaline on 4 wheels</li><li data-list-item-id=\"e7f7e637202d656920820d2466de4b7d3\">ADV Ride – Explore the circuit with motorbike (Additional charge)<br>&nbsp;</li></ul><p style=\"text-align:justify;\">Pada sore hari sekitar pukul 15.30, Anda akan diajak menuju Pantai Tanjung Aan yang terkenal dengan pasir putihnya yang halus dan pemandangan laut yang jernih. Tempat ini sangat cocok untuk bersantai, berfoto, atau sekadar menikmati keindahan alam Lombok.</p><p style=\"text-align:justify;\"><br><br>Perjalanan dilanjutkan menuju Bukit Merese pada pukul 16.30, salah satu spot terbaik untuk menikmati panorama sunset di Lombok Selatan. Dari atas bukit, Anda akan disuguhkan pemandangan laut yang luas dengan langit senja yang memukau.</p><p style=\"text-align:justify;\"><br><br>Setelah menikmati matahari terbenam, perjalanan kembali ke hotel sekitar pukul 18.00, menutup hari dengan pengalaman yang tak terlupakan di Lombok.</p><p><br>&nbsp;</p>', NULL, 'Lunch', '2026-05-22 14:05:58', '2026-05-22 14:05:58'),
(4002, 'App\\Models\\ManadoTour', 26, 1, 'ITINERARY', '<p style=\"text-align:justify;\">Meet &amp; greet at 08:00 AM with the tour guide at <strong>Megamas Pier </strong>for a day tour of <strong>Island Hopping. </strong>From Megamas Pier, cross to <strong>Bunaken Island </strong>by boat (approximately 30 minutes).&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Upon arrival, guests will visit <strong>Bunaken Marine Park</strong>, renowned for its stunning coral reefs and thousands of colorful fish species surrounding <strong>Bunaken Island</strong>. <strong>Bunaken Island</strong> now features a more attractive and well-developed area, including the <strong>Bunaken Tourism Pier</strong>, where participants can take photos with family and friends.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Afterward, guests may enjoy optional snorkeling or diving activities; they can also swim while feeding fish directly by hand. Lunch will be served at a local restaurant on <strong>Bunaken Island</strong>.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">After lunch, proceed to visit <strong>Siladen Island</strong> and the <strong>Nain Sandbank</strong>. On each island, participants can capture moments through photos or videos, take a walk, and enjoy the natural beauty of <strong>Siladen Island</strong> and the <strong>Nain Sandbank</strong>.&nbsp;</p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">In the afternoon, return to Megamas Pier, Manado. End of tour.</p>', NULL, 'Lunch', '2026-05-28 11:34:24', '2026-05-28 11:34:24'),
(4188, 'App\\Models\\IndonesiaDestination', 86, 1, 'AIRPORT - BATUSANGKAR - PAYAKUMBUH', '<p style=\"text-align:justify;\">Tiba di Bandara International Minangkabau, Anda akan di jemput oleh&nbsp; perwakilan Kami. Setelah pengurusan bagasi menuju Bukittinggi via <strong>Lembah Anai, </strong>berhenti sejenak di <strong>Air Terjun Lembah Anai</strong> yang diyakini bisa membuat awet muda.</p><p style=\"text-align:justify;\">Kemudian mengunjungi <strong>Minangkabau Village</strong> yang merupakan <strong>Pusat Dokumentasi Minangkabau, </strong>singgah melihat kerajinan Kulit Khas Padang Panjang di outlet<strong> Minang Kayo</strong></p><p style=\"text-align:justify;\">Makan siang di local restaurant (<strong>Sate Mak Syukur/ Pondok Baselo Baramas/ Pak Datuk Resto). </strong>Setelah makan siang kita menuju <strong>Desa Pariangan yang dinobatkan sebagai Desa Terindah di dunia.</strong></p><p style=\"text-align:justify;\">Setelah itu menuju <strong>Istana pagaruyung</strong> yang merupakan pusat pemerintahan Kerajaan Minangkabau pada masa dahulunya, singgah di <strong>Home Industri Kiniko</strong> untuk melihat pembuatan Kopi &amp; Pisang Salai Khas Minang</p><p style=\"text-align:justify;\">Kemudian menuju <strong>Payakumbuh, </strong>makan malam di lokal restaurant <strong>(Pongek Situjuah Resto). </strong>Check In Hotel &amp; Istirahat.</p><p style=\"text-align:justify;\">Hotel/ Homestay di area Lembah Harau yang dikelilingi Bukit Kapur dan Air Terjun</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:18:30', '2026-05-29 12:18:30'),
(4189, 'App\\Models\\IndonesiaDestination', 86, 2, 'PAYAKUMBUH - BUKITTINGGI', '<p style=\"text-align:justify;\">Sarapan pagi di hotel &amp; Check Out Hotel. City tour&nbsp; Payakumbuh dengan mengunjungi : <strong>Air Terjun Lembah Harau dan Kelok 9. </strong>Setelah itu menuju Bukittinggi, melihat pembuatan Rendang khas minang di Outlet <strong>Rendang Uni Adek. </strong>Singgah di tempat pembuatan Kerupuk Sanjai di sentral oleh-oleh <strong>Ummi Aufa Hakim.</strong></p><p style=\"text-align:justify;\">Makan siang di lokal restaurant <strong>(Lapau Kapau/ Sederhana Resto/ Gon Raya Resto). </strong>Setelah makan siang kemudian city tour Bukittinggi dengan mengunjungi : <strong>Taman Panorama Baru, Rumah Kelahiran Bung Hatta, Jam Gadang, Pasar Atas</strong></p><p style=\"text-align:justify;\">Makan malam di lokal restaurant <strong>(CK Cafe/ Pauh Pariaman/ Sederhana Resto). </strong>Check In Hotel &amp; Istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:18:30', '2026-05-29 12:18:30'),
(4190, 'App\\Models\\IndonesiaDestination', 86, 3, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi di hotel dan check out hotel. Diantar menuju Bandara Internasional Minangkabau, Tour selesai, sampai jumpa pada trip berikutnya.</p>', NULL, 'Breakfast', '2026-05-29 12:18:30', '2026-05-29 12:18:30'),
(4191, 'App\\Models\\IndonesiaDestination', 85, 1, 'AIRPORT - SAWAHLUNTO', '<p style=\"text-align:justify;\">Tiba di Bandara <strong>Internasional Minangkabau</strong> anda akan disambut oleh perwakilan kami, Makan siang di local restaurant (<strong>RM Pasir Pariaman/ RM Lamun Ombak/ Ikan Bakar Khatib</strong>).</p><p style=\"text-align:justify;\">Menuju <strong>Kota Sawahlunto</strong> melewati <strong>Sitinjau Laut</strong> menyaksikan pemandangan menghadap <strong>Samudera Hindia. </strong>City tour Sawahlunto dengan mengunjungi : <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://pelangiholiday.wordpress.com/2011/05/10/objek-wisata-lubang-mbah-suro/attachment/08052011139/\"><strong>Lobang Mbah Suro, Museum</strong></a><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://pelangiholiday.wordpress.com/2010/09/10/wisata-kota-tua-sawahlunto-museum-kereta-api/\"><strong> Kereta Api, Goedang Ransum </strong>dan<strong> Bukit Cemara.</strong></a></p><p style=\"text-align:justify;\">Makan malam di local restaurant. Check in hotel &amp; Istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:19:47', '2026-05-29 12:19:47'),
(4192, 'App\\Models\\IndonesiaDestination', 85, 2, 'SAWAHLUNTO - BATUSANGKAR - HARAU - BUKITTINGGI', '<p style=\"text-align:justify;\">Setelah sarapan pagi dan check out hotel, menuju Batusangkar dan mengunjungi <strong>Danau Singkarak </strong>merupakan danau terbesar di Sumatera Setelah Danau Toba. Selanjutnya Mengunjungi <strong>Istana Pagaruyung </strong>yang merupakan pusat pemerintahan Minangkabau pada masa dahulunya.</p><p style=\"text-align:justify;\">Makan siang di Local Restaurant (<strong>Restoran Pondok Flora/ Sawah Laman). </strong>Setelah makan siang menuju tempat pembuatan makanan &amp; minuman tradisional Minang <strong>KINIKO</strong> home industri. Dilanjutkan Menuju Payakumbuh untuk mengunjungi <strong>Lembah Harau</strong> dan <strong>Kelok 9.</strong></p><p style=\"text-align:justify;\">Setelah itu kita Menuju Bukittinggi, mengunjungi <strong>tempat Pembuatan</strong> Rendang di Sentral Rendang Uni Adek. Singgah di tempat pembuatan Sanjai khas Sumatra Barat di Pusat Oleh - Oleh <strong>Ummi Aufa Hakim</strong></p><p style=\"text-align:justify;\">Makan malam di local restaurant <strong>(Sederhana Restaurant/ Family Restaurant/ CK Center Café/ Pauh Piaman/ Lapau Kapau). </strong>Check in hotel &amp; Istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:19:47', '2026-05-29 12:19:47'),
(4193, 'App\\Models\\IndonesiaDestination', 85, 3, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi dan check out hotel. City tour Bukittinggi mengunjungi : <strong>Taman Panorama Baru, Rumah Kelahiran Bung Hatta, Jam Gadang dan Pasar Atas, </strong>melihat pembuatan<strong> </strong>Songket Khas Sumatera Barat di <strong>Desa Pandai Sikek. </strong>Menikmati <strong>Bika Talago, </strong>panganan khas Minang</p><p style=\"text-align:justify;\">Makan siang di local restaurant<strong> ( Aia Badarun/ Pondok Baselo Baramas/ Sate Mak Syukur). </strong>Setelah makan siang mampir di <strong>Air Terjun Lembah Anai</strong> (jika waktu memungkinkan). Diantar menuju Bandara Internasional Minangkabau dan tour berakhir. Sampai jumpa pada tour berikutnya.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 12:19:47', '2026-05-29 12:19:47');
INSERT INTO `itineraries` (`id`, `itinerable_type`, `itinerable_id`, `day_number`, `title`, `description`, `hotel_info`, `meals_info`, `created_at`, `updated_at`) VALUES
(4194, 'App\\Models\\IndonesiaDestination', 84, 1, 'AIRPORT - BUKITTINGGI', '<p style=\"text-align:justify;\">Tiba di Bandara International Minangkabau, anda akan dijemput oleh&nbsp; perwakilan Kami. Setelah pengurusan bagasi menuju Bukittinggi via Lembah Anai, berhenti sejenak di <strong>Air Terjun Lembah Anai </strong>yang diyakini bisa membuat awet muda.</p><p style=\"text-align:justify;\">Kemudian mengunjungi <strong>Minangkabau Village </strong>yang merupakan Pusat Dokumentasi Minangkabau, mengunjungi <strong>Pusat Kerajinan Kulit </strong>di Outlet <strong>Minang Kayo</strong></p><p style=\"text-align:justify;\">Makan siang di Lokal Restaurant<strong> Pondok Baselo Baramas/ Sate Mak Syukur. </strong>Setelah itu menuju Bukit Tinggi, di perjalanan berhenti di <strong>Desa Pandai Sikek </strong>yang merupakan Desa penghasil Tenunan dan ukiran kayu khas Minangkabau, menuju Sentral <strong>Rendang Uni Adek </strong>untuk melihat pembuatan rendang khas Minang.</p><p style=\"text-align:justify;\">Tiba di Bukittinggi, makan malam di <strong>(Sederhana Restaurant/ CK Center Cafe/ Lapau Kapau). </strong>Check in hotel &amp; Istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:22:15', '2026-05-29 12:22:15'),
(4195, 'App\\Models\\IndonesiaDestination', 84, 2, 'PAYAKUMBUH - MINANGKABAU TOUR', '<p>Sarapan pagi di hotel, menuju <strong>Panorama Baru</strong> untuk melihat sunrise. Kemudian mengunjungi <strong>Rumah Kelahiran Bung Hatta, </strong>dilanjutkan dengan melihat pembuatan kerupuk Sanjai di Pusat oleh-oleh <strong>Ummi Aufa Hakim.</strong></p><p>Setelah itu menuju<strong> Payakumbuh </strong>untuk mengunjungi <strong>Lembah Harau </strong>dan<strong> Kelok 9. </strong>Makan siang dilokal restaurant, dilanjutkan menuju <strong>Batusangkar via Tabek Patah. </strong>Mengunjungi <strong>Home Industri Kiniko </strong>untuk melihat pembuatan Kopi dan Pisang Salai Khas Minang</p><p style=\"text-align:justify;\">Setelah itu menuju <strong>Istana Pagaruyung </strong>yang merupakan&nbsp;&nbsp; pusat&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; pemerintahan Minangkabau pada masa dahulunya. Mampir di <strong>Desa Pariangan </strong>yang merupakan desa terindah di dunia.</p><p style=\"text-align:justify;\">Kembali ke Bukittinggi melewati Padang Panjang dan berhenti di Koto Baru untuk menikmati <strong>Bika Talago. </strong>Makan malam di <strong>Sederhana Restaurant/ Family Restaurant/ CK Center Cafe/ Lapau Kapau). </strong>Diantar menuju ke hotel &amp; Istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:22:15', '2026-05-29 12:22:15'),
(4196, 'App\\Models\\IndonesiaDestination', 84, 3, 'BUKITTINGGI - MANINJAU - PADANG', '<p style=\"text-align:justify;\">Setelah sarapan pagi &amp; check out hotel, kemudian menuju <strong>Desa Koto Gadang </strong>yang terkenal dengan kerajinan perak khas Sumatera Barat. Dilanjutkan menuju <strong>Kenagarian Lawang </strong>untuk melihat pembuatan Gula tebu yang masih alami.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan menuju <strong>Lawang Park </strong>untuk melihat keindahan <strong>Danau Maninjau </strong>dari Ketinggian. Singgah di <strong>Museum Buya Hamka</strong></p><p style=\"text-align:justify;\">Makan siang di <strong>Eni Restaurant</strong>/ <strong>Batu Lambuik Resto. </strong>Setelah makan siang<strong> </strong>Menuju Kota Padang, tiba di Padang, City Tour dengan mengunjungi <strong>Masjid Raya Sumatera Barat Kota Lama Padang, Perkampungan Cina, Jembatan Siti Nurbaya, Pelabuhan Teluk Bayur </strong>dan melihat sunset di <strong>Pantai padang</strong>.</p><p style=\"text-align:justify;\">Makan malam di (<strong>Lamun Ombak / Ikan Bakar Khatib/ Sederhana Restaurant). </strong>Check in hotel dan istirahat</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:22:15', '2026-05-29 12:22:15'),
(4197, 'App\\Models\\IndonesiaDestination', 84, 4, 'PADANG - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi &amp; check out hotel. Diantar menuju Bandara International Minangkabau, Tour Selesai. Sampai Jumpa Pada trip Berikutnya</p>', NULL, 'Breakfast', '2026-05-29 12:22:15', '2026-05-29 12:22:15'),
(4198, 'App\\Models\\IndonesiaDestination', 83, 1, 'AIRPORT - KAWASAN MANDEH - PADANG', '<p style=\"text-align:justify;\">Tiba di <strong>Bandara Internasional Minangkabau, </strong>anda akan dijemput oleh perwakilan kami. Menuju Pelabuhan untuk menyeberang ke <strong>Kawasan Mandeh</strong>. Pertama kita akan mengunjungi <strong>Pulau Setan </strong>untuk melakukan permainan air seperti Banana Boat, Rolling Donut, Jet Ski Air, dan berenang (atas biaya sendiri).</p><p style=\"text-align:justify;\">Makan siang Buffet/ Box, setelah itu menuju <strong>Pulau Sironjong</strong> untuk Snorkeling dan <strong>Cliff Jumping. </strong>Kemudian menyusuri <strong>Hutan Mangrove</strong> untuk menuju ke&nbsp; <strong>Sungai Gemuruh</strong> untuk mandi dan bersih-bersih</p><p style=\"text-align:justify;\">Kembali ke dermaga, menuju Padang dan melihat SunSet di Pelabuhan <strong>Teluk Bayur</strong>. Makan malam di <strong>Rumah Makan Ikan Bakar Khatib</strong></p>', NULL, 'Lunch/Dinner', '2026-05-29 12:23:18', '2026-05-29 12:23:18'),
(4199, 'App\\Models\\IndonesiaDestination', 83, 2, 'PADANG - BUKITTINGGI', '<p>Sarapan Pagi dan check out hotel, City tour Kota Padang dengan mengunjungi&nbsp; <strong>Kota Lama Padang</strong>, <strong>Perkampungan Cina, Jembatan Siti Nurbaya, Pantai Padang, dan Masjid Raya Sumatera Barat</strong>.</p><p>Setelah itu menuju Bukittinggi via <strong>Lembah Anai</strong>. Diperjalanan berhenti di <strong>Air Terjun Lembah Anai</strong> untuk menikmati keindahan dan kesejukan air nya yang diyakini bisa membuat kita awet muda.</p><p>Setelah itu mampir di Minang Kayo untuk melihat kerajinan Kulit Khas Sumatera Barat, kemudian dilanjutkan menuju <strong>Minangkabau Village yang merupakan Pusat Dokumentasi Minangkabau.</strong></p><p>Makan siang Bajamba di Pondok <strong>Baselo Baramas / makan sate Mak Syukur. </strong>Setelah makan siang kita mengunjungi <strong>Bika Talago</strong> tempat pembuatan <strong>Bika</strong> yaitu makanan khas minang yang terbuat dari tepung beras. Menuju ke <strong>Pandai Sikek </strong>yang merupakan desa penghasil Songket khas Minang, melihat <strong>pembuatan Rendang</strong> di Outlet <strong>Rendang Uni Adek</strong></p><p>Tiba di Bukittinggi, mengunjungi Panorama Ngarai Sianok, free program di Jam Gadang dan Pasar Atas. Makan malam dilokal restaurant (<strong>Sederhana Restaurant/ Family Restaurant/ Pauh Piaman Restaurant / Gon Raya Restaurant). </strong>Check in Hotel &amp; istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:23:18', '2026-05-29 12:23:18'),
(4200, 'App\\Models\\IndonesiaDestination', 83, 3, 'PAYAKUMBUH - MINANGKABAU TOUR', '<p>Sarapan pagi di hotel. Tour diawali dengan menuju <strong>Panorama Baru </strong>untuk melihat sunrise, Kemudian mengunjungi <strong>Rumah Kelahiran Bung Hatta </strong>dan foto stop di<strong> Jam Gadang</strong></p><p>Perjalanan dilanjutkan menuju <strong>Payakumbuh</strong>, mengunjungi <strong>Lembah Harau</strong> yang terkenal dengan <strong>Air Terjun</strong> yang dikelilingi Tebing-tebing yang indah. Selanjutnya menuju <strong>Kelok 9</strong> yang merupakan proyek flyover terbesar di Sumatera Barat.</p><p>Makan siang di Rumah makan <strong>Pongek Situjuah</strong>. Setelah itu menuju Batusangkar mengunjungi <strong>Istana Pagaruyung</strong> yang merupakan Pusat Pemerintahan Minangkabau pada dahulunya. Singgah di <strong>Desa Pariangan</strong> yang merupakan Desa Terindah di Dunia.</p><p>Kembali ke Bukittinggi, melihat pembuatan Sanjai, makanan khas dari Bukittinggi di <strong>Pusat oleh-oleh Ummi Aufa Hakim. </strong>Makan malam di <strong>Family Benteng/ Sederhana Restaurant/ CK Cafe/ Gon Raya Lamo. </strong>Kembali ke hotel &amp; Istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:23:18', '2026-05-29 12:23:18'),
(4201, 'App\\Models\\IndonesiaDestination', 83, 4, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Setelah sarapan pagi &amp; check out hotel. Diantar Menuju Bandara<strong> Internasional Minangkabau</strong>, tour berakhir. Sampai jumpa pada tour berikutnya&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 12:23:18', '2026-05-29 12:23:18'),
(4210, 'App\\Models\\IndonesiaDestination', 82, 1, 'AIRPORT - ALAHAN PANJANG', '<p style=\"text-align:justify;\">Tiba di Bandara International Minangkabau, anda akan dijemput oleh&nbsp; perwakilan Kami. Setelah pengurusan bagasi menuju <strong>Alahan Panjang via Panorama Sitinjau Lauik. </strong>Photo stop di <strong>Perkebunan Teh, </strong>selanjutnya makan siang di lokal restaurant. Selesai makan siang peserta tour yang beragama muslim bisa melaksanakan Shalat di <strong>Masjid Ummi.</strong></p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Melihat keindahan<strong> Danau Diatas dan Danau di Bawah. </strong>Check in Hotel, menikmati Fasilitas Hotel. Makan Malam di local restaurant. Free program</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:27:08', '2026-05-29 12:27:08'),
(4211, 'App\\Models\\IndonesiaDestination', 82, 2, 'ALAHAN PANJANG - BATUSANGKAR - BUKITTINGGI', '<p style=\"text-align:justify;\">Sarapan pagi dan Check Out hotel, menuju Batusangkar via Danau Singkarak. Photo Stop di Tepian <strong>Danau Singkarak</strong></p><p style=\"text-align:justify;\">Setelah itu menuju Batusangkar, mengunjungi <strong>Istana Pagaruyung</strong> yang merupakan Pusat Pemerintahan Minangkabau pada masa dahulunya</p><p style=\"text-align:justify;\">Makan siang di <strong>Pondok Flora Restaurant, </strong>selanjutnya menuju Payakumbuh untuk mengunjungi <strong>Lembah Harau</strong> dan <strong>Kelok 9.</strong></p><p style=\"text-align:justify;\">Perjalanan dilanjutkan menuju Bukittinggi, melihat <strong>pembuatan Kerupuk Sanjai</strong>&nbsp; khas Bukittinggi di <strong>Pusat oleh-oleh Ummi Aufa Hakim. </strong>Makan malam di local restaurant (<strong>Sederhana Resto/ Gon Raya Resto/ Simpang Raya Resto/ Pauh Piaman Resto/ Family Benteng Resto/ Lapau Kapau</strong>).</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:27:08', '2026-05-29 12:27:08'),
(4212, 'App\\Models\\IndonesiaDestination', 82, 3, 'BUKITTINGGI - MANINJAU', '<p style=\"text-align:justify;\">Setelah sarapan pagi tour diawali dengan menuju <strong>Taman Panorama Baru, Photo Stop di Jam Gadang. </strong>Perjalanan di lanjutkan mengunjungi desa Koto Gadang, untuk melihat pembuatan perak Khas Sumatera Barat.</p><p style=\"text-align:justify;\">Setelah itu kita akan melihat pembuatan Gula Tebu di <strong>Desa Matur</strong> yang masih menggunakan tenaga Kerbau. Kemudian menuju ke <strong>Lawang Park</strong> untuk melihat keindahan Danau Maninjau dari Ketinggian.</p><p style=\"text-align:justify;\">Selanjutnya kunjungan ke <strong>Museum Buya Hamka</strong> (NB: hanya untuk group dibawah 30 pax), Dilanjutkan menuju tempat pembuatan makanan khas Sumatera Barat di sentral oleh-oleh<strong> Rendang Uni Adek.</strong></p><p style=\"text-align:justify;\">Makan malam di local restaurant <strong>Sederhana Resto/ Gon Raya Resto/ Simpang Raya Resto/ Pauh Piaman Resto/ Family Benteng Resto/ Lapau Kapau</strong>). Kembali ke hotel dan beristirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:27:08', '2026-05-29 12:27:08'),
(4213, 'App\\Models\\IndonesiaDestination', 82, 4, 'BUKITTINGGI - PADANG - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi &amp; check out hotel. Pertama kita akan mengunjungi <strong>Pusat Kerajinan Kulit </strong>di Outlet <strong>Minang Kayo. </strong>Setelah itu menuju kota Padang.</p><p style=\"text-align:justify;\">Tiba di Kota Padang City Tour dengan mengunjungi <strong>Masjid Raya Sumatera Barat</strong> <strong>Kota Lama Padang, Perkampungan Cina, Jembatan Siti Nurbaya, Pantai padang.</strong></p><p style=\"text-align:justify;\">Menuju Bandara Internasional Minangkabau, tour berakhir. Sampai jumpa pada tour berikutnya&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 12:27:08', '2026-05-29 12:27:08'),
(4214, 'App\\Models\\IndonesiaDestination', 81, 1, 'AIRPORT - ALAHAN PANJANG', '<p style=\"text-align:justify;\">Tiba di Bandara International Minangkabau, anda akan dijemput oleh&nbsp; perwakilan Kami. Setelah pengurusan bagasi menuju <strong>Alahan Panjang via Panorama Sitinjau Lauik. </strong>Photo stop di <strong>Perkebunan Teh, </strong>selanjutnya makan siang di lokal restaurant. Selesai makan siang peserta tour yang beragama muslim bisa melaksanakan Shalat di <strong>Masjid Ummi.</strong></p><p style=\"text-align:justify;\">&nbsp;</p><p style=\"text-align:justify;\">Melihat keindahan<strong> Danau Diatas dan Danau di Bawah. </strong>Check in Hotel, menikmati Fasilitas Hotel. Makan Malam di local restaurant. Free program</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:28:23', '2026-05-29 12:28:23'),
(4215, 'App\\Models\\IndonesiaDestination', 81, 2, 'ALAHAN PANJANG - BATUSANGKAR - PAYAKUMBUH - BUKITTINGGI', '<p style=\"text-align:justify;\">Sarapan pagi dan Check Out hotel, kita menuju Batusangkar via Danau Singkarak. Photo Stop di Tepian <strong>Danau Singkarak.</strong></p><p style=\"text-align:justify;\">Perjalanan dilanjutkan menuju Batusangkar, <strong>Istana Pagaruyung</strong> yang terkenal dengan Pusat kerajaan Minangkabau pada masa dahulunya.&nbsp;</p><p style=\"text-align:justify;\">Makan siang dilokal restaurant, setelah makan kemudian menuju <strong>Payakumbuh</strong>, mengunjungi <strong>Rumah Godang Baringin.&nbsp;</strong></p><p style=\"text-align:justify;\">Selanjutnya mengunjungi <strong>Lembah Harau</strong> untuk melihat air terjun dan Batu Granit yang mempesona, kemudian mengunjungi <strong>Kelok 9.</strong></p><p style=\"text-align:justify;\">Menuju Bukittinggi, makan malam dilokal restaurant. Check in hotel dan istirahat</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:28:23', '2026-05-29 12:28:23'),
(4216, 'App\\Models\\IndonesiaDestination', 81, 3, 'BUKITTINGGI - MANINJAU', '<p style=\"text-align:justify;\">Setelah sarapan pagi tour diawali dengan menuju ke <strong>Panorama Baru</strong> untuk melihat Sunrise, setelah itu mengunjungi desa <strong>Koto Gadang</strong>, untuk melihat pembuatan perak Khas Sumatera Barat.</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan melihat pembuatan Gula Tebu di <strong>Desa Matur</strong> yang masih menggunakan tenaga Kerbau, kemudian menuju ke <strong>Lawang Park</strong> untuk melihat keindahan Danau Maninjau dari Ketinggian.</p><p style=\"text-align:justify;\">Selanjutnya kunjungan ke <strong>Museum Buya Hamka</strong> (NB: hanya untuk group dibawah 30 pax). Makan siang di <strong>Batu Lambuik</strong> Restaurant Atau <strong>Rumah Makan Eni.</strong></p><p style=\"text-align:justify;\">Kembali ke Bukittinggi, free Program di <strong>Jam Gadang &amp; Pasar Atas. </strong>Makan malam di local restaurant Sederhana Resto/ Gon Raya Resto/ Simpang Raya Resto/ Pauh Piaman Resto/ Family Benteng Resto/ Lapau Kapau). Kembali ke hotel.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:28:23', '2026-05-29 12:28:23'),
(4217, 'App\\Models\\IndonesiaDestination', 81, 4, 'BUKITTINGGI - PADANG', '<p style=\"text-align:justify;\">Sarapan pagi &amp; check out hotel. Menuju Belanja oleh-oleh di <strong>Sentral Ummi Aufa Hakim </strong>dan <strong>Rendang Uni Adek</strong> yang terkenal dengan Rendang nya.</p><p style=\"text-align:justify;\">Setelah itu dilanjutkan menuju ke kota Padang via <strong>Air terjun Lembah Anai</strong>, berhenti sejenak untuk menikmati kesejukan Air Terjun. Melanjutkan perjalanan ke Kota Padang.</p><p style=\"text-align:justify;\">Makan siang dilokal restaurant, tiba di Kota Padang City Tour dengan mengunjungi <strong>Masjid Raya Sumatera Barat</strong> <strong>Kota Lama Padang, Perkampungan Cina, Jembatan Siti Nurbaya, Pantai padang.</strong></p><p style=\"text-align:justify;\">Makan malam dilokal restaurant, kemudian check in hotel dan istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:28:23', '2026-05-29 12:28:23'),
(4218, 'App\\Models\\IndonesiaDestination', 81, 5, 'PADANG - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi di hotel dan check out, setelah itu menuju Bandara Internasional Minangkabau. Check in dan tour selesai, sampai jumpa pada tour selanjutnya.</p>', NULL, 'Breakfast', '2026-05-29 12:28:23', '2026-05-29 12:28:23'),
(4219, 'App\\Models\\IndonesiaDestination', 87, 1, 'AIRPORT - BUKITTINGGI', '<p style=\"text-align:justify;\">Tiba di Bandara Internasional Minangkabau, anda akan jemput oleh perwakilan Kami. Berhenti sejenak di <strong>Air Terjun Lembah Anai</strong> yang diyakini bisa membuat awet muda, kemudian mengunjungi <strong>Minangkabau Village</strong> yang merupakan Pusat Dokumentasi Minangkabau.</p><p style=\"text-align:justify;\">Makan siang di Lokal restaurant <strong>(Rm Baramas / Sate Mak Syukur). </strong>Setelah makan siang menuju ke Koto Baru untuk menikmati Bika, Jajanan khas Minang yang terbuat dari tepung beras. Menuju <strong>Desa Pandai Sikek</strong> yang merupakan penghasil Songket Khas Minang.</p><p style=\"text-align:justify;\">Makan malam di local restaurant <strong>(Sederhana Restaurant/ Family Restaurant/ CK Center Café). </strong>Check in Hotel &amp; istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:43:37', '2026-05-29 12:43:37'),
(4220, 'App\\Models\\IndonesiaDestination', 87, 2, 'BUKITTINGGI - BATUSANGKAR - BUKITTINGGI', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, mengunjungi <strong>Istana Pagaruyung</strong> yang merupakan Pusat Pemerintahan Minangkabau pada zaman dahulunya. Kemudian menuju lokasi <strong>Pacu Jawi </strong>untuk menyasikan pertandingan Pacu Jawi.&nbsp;</p><p style=\"text-align:justify;\">Makan siang (lunch box), setelah makan siang kita menuju ke Pusat oleh-oleh <strong>Ummi Aufa Hakim</strong> dan <strong>Randang Uni Adek. </strong>Kemudian Free program di Jam Gadang dan Pasar Atas.</p><p style=\"text-align:justify;\">Makan malam di local restaurant <strong>(Sederhana Restaurant/ Family Restaurant/ CK Center Café/). </strong>Kembali ke hotel &amp; istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:43:37', '2026-05-29 12:43:37'),
(4221, 'App\\Models\\IndonesiaDestination', 87, 3, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Setelah sarapan pagi, check out hotel. Diantar menuju Bandara Internasional Minangkabau dan tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 12:43:37', '2026-05-29 12:43:37'),
(4225, 'App\\Models\\IndonesiaDestination', 88, 1, 'AIRPORT - BUKITTINGGI', '<p style=\"text-align:justify;\">Tiba di <strong>Bandara</strong> <strong>Internasional Minangkabau</strong> anda akan disambut oleh perwakilan kami, selanjutnya menuju Bukittinggi via <strong>Lembah Anai</strong> yang terkenal dengan keindahan dan Air terjun nya yang diyakini bisa membuat kita awet muda.</p><p style=\"text-align:justify;\">Berikutnya mengunjungi <strong>Minangkabau Village,</strong> yang merupakan pusat dokumentasi dan informasi Minangkabau. Setelah itu mampir melihat hasil kerajinan kulit Khas dari Padang Panjang di Outlet <strong>Minang Kayo</strong>.</p><p style=\"text-align:justify;\">Makan siang di <strong>Pondok Baselo Baramas/ Sate Mak Syukur Padang Panjang. </strong>Setelah makan siang kita menuju ke desa <strong>Pandai Sikek</strong> yang terkenal dengan <strong>Tenunan Songket</strong> dan <strong>Ukiran tradisional Minangkabau. </strong>Menuju Sentral <strong>Rendang Uni Adek</strong> untuk melihat proses pembuatan rendang khas Sumatera Barat</p><p style=\"text-align:justify;\">Makan malam di Lokal Restaurant <strong>(Sederhana Restaurant/ Lapau Kapau/ CK Center Café/ Mekar Sari). </strong>Check in hotel dan istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 12:58:11', '2026-05-29 12:58:11'),
(4226, 'App\\Models\\IndonesiaDestination', 88, 2, 'PALUPUAH - PAYAKUMBUH', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, menuju <strong>Nagari Palupuah</strong> untuk melihat <strong>Bunga Rafflesia </strong>atau yang dikenal dengan sebutan Bunga Bangkai, yang merupakan salah satu bunga langka</p><p style=\"text-align:justify;\">Kemudian mengunjungi <strong>Rafflesia Luwak Coffee</strong> yang di olah secara tradisional (Additional). Makan siang dilokal restaurant</p><p style=\"text-align:justify;\">Kembali ke Bukittinggi. City tour dengan mengunjungi<strong> Jam Gadang</strong> dan <strong>Pasar Atas, </strong>kemudian mengunjungi <strong>Rumah Kelahiran Bung Hatta</strong></p><p style=\"text-align:justify;\">Makan malam dilokal restaurant, kembali ke hotel dan istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 12:58:11', '2026-05-29 12:58:11'),
(4227, 'App\\Models\\IndonesiaDestination', 88, 3, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi dan check out hotel. Melihat <strong>pembuatan Kerupuk Sanjai</strong>&nbsp; khas Bukittinggi di <strong>Pusat oleh-oleh Ummi Aufa Hakim</strong></p><p style=\"text-align:justify;\">Setelah itu diantar menuju Airport dan tour berakhir. Sampai jumpa pada tour berikutnya.</p>', NULL, 'Breakfast', '2026-05-29 12:58:11', '2026-05-29 12:58:11'),
(4228, 'App\\Models\\IndonesiaDestination', 89, 1, 'AIRPORT - BUKITTINGGI', '<p style=\"text-align:justify;\">Tiba di <strong>Bandara</strong> <strong>Internasional Minangkabau</strong> anda akan disambut oleh perwakilan kami, selanjutnya menuju Bukittinggi via <strong>Lembah Anai</strong> yang terkenal dengan keindahan dan Air terjun nya yang diyakini bisa membuat kita awet muda.</p><p style=\"text-align:justify;\">Berikutnya mengunjungi <strong>Minangkabau Village,</strong> yang merupakan pusat dokumentasi dan informasi Minangkabau. Singgah untuk melihat hasil kerajinan kulit Khas dari Padang Panjang di Outlet <strong>Minang Kayo</strong>.</p><p style=\"text-align:justify;\">Makan siang di <strong>Pondok Baselo Baramas/ Sate Mak Syukur Padang Panjang. </strong>Setelah makan siang kita menuju ke desa <strong>Pandai Sikek</strong> yang terkenal dengan <strong>Tenunan Songket</strong> dan <strong>Ukiran tradisional Minangkabau. </strong>Menuju Sentral <strong>Rendang Uni Adek</strong> untuk melihat proses pembuatan rendang khas Sumatera Barat</p><p style=\"text-align:justify;\">Makan malam di Lokal Restaurant <strong>(Sederhana Restaurant/ Lapau Kapau/ Familly Restaurant/ CK Center Café/ Mekar Sari). </strong>Check in hotel dan istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:11:18', '2026-05-29 13:11:18'),
(4229, 'App\\Models\\IndonesiaDestination', 89, 2, 'PAYAKUMBUH - MINANGKABAU TOUR', '<p style=\"text-align:justify;\">Sarapan pagi di hotel, menuju <strong>Payakumbuh</strong> untuk mengunjungi <strong>Lembah Harau</strong> yang terkenal dengan <strong>tebing batu granit</strong> dan <strong>Air Terjunnya</strong> yang mempesona. Dilanjutkan menuju <strong>Kelok 9</strong> yang merupakan proyek flyover terbesar di Sumatera Barat.</p><p style=\"text-align:justify;\">Makan siang di lokal restaurant <strong>(RM Pongek Situjuah). </strong>Setelah makan siang menuju <strong>Batusangkar</strong> dan singgah di <strong>Home Industri Kiniko</strong> yaitu tempat pembuatan makanan dan minuman khas Sumatera Barat.</p><p style=\"text-align:justify;\">Selanjutnya menuju <strong>Istana Pagaruyung</strong> yaitu Pusat Pemerintahan Minangkabau pada masa dahulunya. Menuju <strong>Desa Pariangan</strong> atau yang lebih dikenal dengan Desa Terindah di Dunia. Melihat pembuatan <strong>Bika Talago</strong> dan menikmati Kawa Daun/ minuman khas Minang, sembari melihat keindahan Danau Buatan yang berlatar belakang Gunung Merapi.</p><p style=\"text-align:justify;\">Kembali ke Bukittinggi, singgah di Tempat pembuatan Sanjai dan Pusat Oleh-oleh <strong>Ummi Aufa Hakim. </strong>Makan Malam di lokal restaurant <strong>(Sederhana Restaurant/ Lapau Kapau/ Familly Restaurant/ CK Center Café/ Mekar Sari). </strong>Kembali ke hotel &amp; istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:11:18', '2026-05-29 13:11:18'),
(4230, 'App\\Models\\IndonesiaDestination', 89, 3, 'BUKITTINGGI - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi dan check out hotel. City tour Bukittinggi mengunjungi <strong>Taman Panorama Baru, Rumah Kelahiran Bung Hatta, Jam Gadang dan Pasar Atas. </strong>Setelah itu diantar menuju Bandara Internasional Minangkabau dan tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:11:18', '2026-05-29 13:11:18'),
(4231, 'App\\Models\\IndonesiaDestination', 90, 1, 'AIRPORT - BUKITTINGGI', '<p style=\"text-align:justify;\">Tiba di <strong>Bandara</strong> <strong>Internasional Minangkabau</strong> anda akan disambut oleh perwakilan kami, selanjutnya menuju Bukittinggi via <strong>Lembah Anai</strong> yang terkenal dengan keindahan dan Air terjun nya yang diyakini bisa membuat kita awet muda.</p><p style=\"text-align:justify;\">Berikutnya mengunjungi <strong>Minangkabau Village,</strong> yang merupakan pusat dokumentasi dan informasi Minangkabau. Singgah untuk melihat hasil kerajinan kulit Khas dari Padang Panjang di Outlet <strong>Minang Kayo</strong>.</p><p style=\"text-align:justify;\">Makan siang di <strong>Pondok Baselo Baramas/ Sate Mak Syukur Padang Panjang. </strong>Setelah makan siang kita menuju ke desa <strong>Pandai Sikek</strong> yang terkenal dengan <strong>Tenunan Songket</strong> dan <strong>Ukiran tradisional Minangkabau. </strong>Menuju Sentral <strong>Rendang Uni Adek</strong> untuk melihat proses pembuatan rendang khas Sumatera Barat</p><p style=\"text-align:justify;\">Makan malam di Lokal Restaurant <strong>(Sederhana Restaurant/ Lapau Kapau/ CK Center Café/ Mekar Sari). </strong>Check in hotel dan istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:28:10', '2026-05-29 13:28:10'),
(4232, 'App\\Models\\IndonesiaDestination', 90, 2, 'PAYAKUMBUH - MINANGKABAU TOUR - PADANG', '<p style=\"text-align:justify;\">Sarapan pagi di hotel dan Check Out Hotel. City tour Bukittinggi mengunjungi : <strong>Taman Panorama Baru, Rumah Kelahiran Bung Hatta, Jam Gadang </strong>dan<strong> Pasar atas. </strong>Menuju <strong>Payakumbuh</strong> untuk mengunjungi <strong>Lembah Harau</strong> yang terkenal dengan <strong>tebing batu granit</strong> dan <strong>Air Terjunnya</strong> yang mempesona</p><p style=\"text-align:justify;\">Makan siang di lokal restaurant <strong>(RM Pongek Situjuah). </strong>Setelah makan siang kita menuju <strong>Istana Pagaruyung</strong> yaitu Pusat Pemerintahan Minangkabau pada masa dahulunya.</p><p style=\"text-align:justify;\">Perjalanan selanjutnya menuju Padang, singgah di Tempat pembuatan Sanjai dan Pusat Oleh-oleh <strong>Ummi Aufa Hakim di Padang. </strong>Makan Malam di Ikan Bakar Khatib, setelah makan malam diantar menuju Hotel. Check in hotel dan istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:28:10', '2026-05-29 13:28:10'),
(4233, 'App\\Models\\IndonesiaDestination', 90, 3, 'PADANG - AIRPORT', '<p style=\"text-align:justify;\">Sarapan pagi dan check out hotel. City Tour Padang dengan mengunjungi : <strong>Masjid Raya Sumatera Barat, Perkampungan cina, Kota lama Padang, Jembatan Siti Nurbaya, dan Pantai Padang.&nbsp;</strong></p><p style=\"text-align:justify;\">Setelah itu diantar menuju Bandara Internasional Minangkabau dan tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:28:10', '2026-05-29 13:28:10'),
(4234, 'App\\Models\\IndonesiaDestination', 80, 1, 'ARRIVAL CGK – TRANSFER BANDUNG', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrival at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet and greet with our team. Proceed to Bandung via Cipularang Tol. Half day Bandung city tour or shopping program if time permits* (subject to arrival time).&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant, evening check in hotel. Free program.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:29:17', '2026-05-29 13:29:17'),
(4235, 'App\\Models\\IndonesiaDestination', 80, 2, 'NORTHERN BANDUNG AREA – LEMBANG TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day tour to Northern Bandung area (Lembang) visiting <strong>Tangkuban Perahu, Floating Market* or Farmhouse*</strong> (*choose one), and <strong>The Great Asia Africa</strong>. Continue shopping at <strong>Karma or Rumah Mode Factory Outlet</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:29:17', '2026-05-29 13:29:17'),
(4236, 'App\\Models\\IndonesiaDestination', 80, 3, 'SOUTHERN BANDUNG AREA – CIWIDEY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day tour to Southern Bandung area (Ciwidey) visiting <strong>Kawah Putih, Glamping Lakeside, and Rengganis Suspension Bridge</strong>. Continue shopping at <strong>Cibaduyut Leather Center</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:29:17', '2026-05-29 13:29:17'),
(4237, 'App\\Models\\IndonesiaDestination', 80, 4, 'BANDUNG – JAKARTA BY WHOOSH – DEPARTURE CGK', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Shopping for Bandung local souvenirs at <strong>Kartika Sari, Prima Rasa, or Kunafe</strong>. Lunch at local restaurant. Transfer to Bandung Whoosh Station and proceed to Jakarta by Whoosh High Speed Train.&nbsp;</p><p style=\"text-align:justify;\">Upon arrival in Jakarta, transfer to <strong>Soekarno Hatta International Airport (CGK)</strong>. End of services</p><p style=\"text-align:justify;\"><strong>*Transfer schedule will be adjusted according to flight departure time.</strong></p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:29:17', '2026-05-29 13:29:17'),
(4238, 'App\\Models\\IndonesiaDestination', 79, 1, 'ARRIVAL CGK – TRANSFER BANDUNG', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrival at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet and greet with our team. Proceed to Bandung via Cipularang Tol. Half day Bandung city tour or shopping program if time permits* (subject to arrival time).&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant, evening check in hotel. Free program.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:29:41', '2026-05-29 13:29:41'),
(4239, 'App\\Models\\IndonesiaDestination', 79, 2, 'SOUTHERN BANDUNG AREA – CIWIDEY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day tour to Southern Bandung area (Ciwidey) visiting <strong>Kawah Putih, Glamping Lakeside, and Rengganis Suspension Bridge</strong>. Continue shopping at <strong>Cibaduyut Leather Center</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:29:41', '2026-05-29 13:29:41'),
(4240, 'App\\Models\\IndonesiaDestination', 79, 3, 'FULLDAY SHOPPING TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day shopping tour visiting <strong>Pasar Baru Trade Center, Toko Tiga, and Factory Outlet at Riau or Dago area</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:29:41', '2026-05-29 13:29:41'),
(4241, 'App\\Models\\IndonesiaDestination', 79, 4, 'BANDUNG – JAKARTA BY WHOOSH – DEPARTURE CGK', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Shopping for Bandung local souvenirs at <strong>Kartika Sari, Prima Rasa, or Kunafe</strong>. Lunch at local restaurant. Transfer to Bandung Whoosh Station and proceed to Jakarta by <strong>Whoosh High Speed Train</strong>.&nbsp;</p><p style=\"text-align:justify;\">Upon arrival in Jakarta, transfer to <strong>Soekarno Hatta International Airport (CGK)</strong>. End of services</p><p style=\"text-align:justify;\"><strong>*Transfer schedule will be adjusted according to flight departure time.</strong></p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:29:41', '2026-05-29 13:29:41'),
(4242, 'App\\Models\\IndonesiaDestination', 78, 1, 'ARRIVAL CGK – TRANSFER BANDUNG', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrival at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet and greet with our team. Proceed to Bandung via Cipularang Tol. Half day Bandung city tour or shopping program if time permits* (subject to arrival time).&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant, evening check in hotel. Free program.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:30:08', '2026-05-29 13:30:08'),
(4243, 'App\\Models\\IndonesiaDestination', 78, 2, 'NORTHERN BANDUNG AREA – LEMBANG TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day tour to Northern Bandung area (Lembang) visiting <strong>Tangkuban Perahu, Floating Market* or Farmhouse*</strong> (*choose one), and <strong>The Great Asia Africa</strong>. Continue shopping at <strong>Karma or Rumah Mode Factory Outlet</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:30:08', '2026-05-29 13:30:08'),
(4244, 'App\\Models\\IndonesiaDestination', 78, 3, 'FULLDAY SHOPPING TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day shopping tour visiting <strong>Pasar Baru Trade Center, Toko Tiga, and Factory Outlet at Riau or Dago area</strong>.&nbsp;</p><p style=\"text-align:justify;\">Lunch and dinner at local restaurant. Back to hotel and free program.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:30:08', '2026-05-29 13:30:08'),
(4245, 'App\\Models\\IndonesiaDestination', 78, 4, 'BANDUNG – JAKARTA BY WHOOSH – DEPARTURE CGK', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Shopping for Bandung local souvenirs at <strong>Kartika Sari, Prima Rasa, or Kunafe</strong>. Lunch at local restaurant. Transfer to Bandung Whoosh Station and proceed to Jakarta by Whoosh High Speed Train.&nbsp;</p><p style=\"text-align:justify;\">Upon arrival in Jakarta, transfer to <strong>Soekarno Hatta International Airport (CGK)</strong>. End of services</p><p style=\"text-align:justify;\"><strong>*Transfer schedule will be adjusted according to flight departure time.</strong></p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:30:08', '2026-05-29 13:30:08'),
(4246, 'App\\Models\\IndonesiaDestination', 77, 1, 'ARRIVAL SOEKARNO HATTA AIRPORT – KEBUN RAYA – HOTEL', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrived at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet with our team. Visiting <strong>Kebun Raya Bogor</strong>, photo stop around <strong>President Palace</strong>, and shopping at <strong>Tajur Factory Outlet</strong>.&nbsp;</p><p style=\"text-align:justify;\">Transfer to hotel then check in, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:30:45', '2026-05-29 13:30:45'),
(4247, 'App\\Models\\IndonesiaDestination', 77, 2, 'BOGOR CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Photo stop at <strong>Tea Plantation</strong>, then full day tour visiting <strong>Taman Safari Indonesia</strong>. Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:30:45', '2026-05-29 13:30:45'),
(4248, 'App\\Models\\IndonesiaDestination', 77, 3, 'BOGOR – OUT', '<p style=\"text-align:justify;\">Breakfast at hotel, then check out. Proceed to <strong>Soekarno Hatta International Airport</strong>. Lunch at local restaurant. End of services.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:30:45', '2026-05-29 13:30:45'),
(4249, 'App\\Models\\IndonesiaDestination', 76, 1, 'ARRIVAL SOEKARNO HATTA AIRPORT – KEBUN RAYA – HOTEL', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrived at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet with our team. Visiting <strong>Kebun Raya Bogor</strong>, photo stop around <strong>President Palace</strong>, and shopping at <strong>Tajur Factory Outlet</strong>.&nbsp;</p><p style=\"text-align:justify;\">Transfer to hotel then check in, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:31:24', '2026-05-29 13:31:24'),
(4250, 'App\\Models\\IndonesiaDestination', 76, 2, 'BOGOR CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Photo stop at <strong>Tea Plantation</strong>, then full day tour visiting <strong>Taman Safari Indonesia</strong>. Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:31:24', '2026-05-29 13:31:24'),
(4251, 'App\\Models\\IndonesiaDestination', 76, 3, 'BOGOR – BANDUNG CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Proceed to Bandung. Upon arrival, visiting <strong>Floating Market* or Farmhouse*</strong> (*choose one), then Bandung city tour visiting <strong>Jalan Asia Afrika, Alun-Alun Bandung, and Jalan Braga</strong>.&nbsp;</p><p style=\"text-align:justify;\">Check in hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:31:24', '2026-05-29 13:31:24'),
(4252, 'App\\Models\\IndonesiaDestination', 76, 4, 'SOUTH OF BANDUNG TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day tour visiting <strong>Kawah Putih, Glamping Lakeside, and Ranca Upas</strong>. Shopping at <strong>Grutty Cibaduyut</strong>.&nbsp;</p><p style=\"text-align:justify;\">Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:31:24', '2026-05-29 13:31:24'),
(4253, 'App\\Models\\IndonesiaDestination', 76, 5, 'BANDUNG – SOEKARNO HATTA AIRPORT', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Transfer to Jakarta via Cipularang Tol. Lunch at local restaurant. Arrived at <strong>Soekarno Hatta International Airport (CGK)</strong>. End of services.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:31:24', '2026-05-29 13:31:24'),
(4254, 'App\\Models\\IndonesiaDestination', 75, 1, 'ARRIVAL CGK – PIK 2 – HOTEL', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrived at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet with our team. Proceed to visit <strong>PIK 2 area</strong>.&nbsp;</p><p style=\"text-align:justify;\">Transfer to hotel and check in, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Lunch/Dinner', '2026-05-29 13:31:48', '2026-05-29 13:31:48'),
(4255, 'App\\Models\\IndonesiaDestination', 75, 2, 'JAKARTA CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day Jakarta city tour visiting <strong>Taman Mini Indonesia Indah (TMII)</strong>. Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:31:48', '2026-05-29 13:31:48'),
(4256, 'App\\Models\\IndonesiaDestination', 75, 3, 'JAKARTA CITY TOUR – DEPARTURE', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Continue Jakarta city tour visiting <strong>Monas, Istiqlal Mosque, Cathedral Church, and photo stop at Istana Negara</strong>. Shopping at <strong>Mangga Dua Square</strong>.&nbsp;</p><p style=\"text-align:justify;\">Proceed to Soekarno Hatta International Airport (CGK). End of services.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:31:48', '2026-05-29 13:31:48'),
(4257, 'App\\Models\\IndonesiaDestination', 74, 1, 'ARRIVAL CGK – PIK 2 – HOTEL', '<p style=\"text-align:justify;\">Welcome back to Indonesia! Arrived at <strong>Soekarno Hatta International Airport (CGK) Jakarta</strong>, meet with our team. Proceed to visit <strong>PIK 2 area</strong>.&nbsp;</p><p style=\"text-align:justify;\">Transfer to hotel and check in, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Lunch / Dinner', '2026-05-29 13:32:11', '2026-05-29 13:32:11'),
(4258, 'App\\Models\\IndonesiaDestination', 74, 2, 'JAKARTA CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Full day Jakarta city tour visiting <strong>Taman Mini Indonesia Indah (TMII)</strong>. Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:32:11', '2026-05-29 13:32:11'),
(4259, 'App\\Models\\IndonesiaDestination', 74, 3, 'JAKARTA CITY TOUR', '<p style=\"text-align:justify;\">Breakfast at hotel. Continue Jakarta city tour visiting <strong>Kota Tua, Sunda Kelapa Harbor, and Museum Bank Indonesia</strong>. Shopping at <strong>Thamrin City</strong>. Back to hotel, free program. Lunch and dinner at local restaurant.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:32:11', '2026-05-29 13:32:11'),
(4260, 'App\\Models\\IndonesiaDestination', 74, 4, 'JAKARTA CITY TOUR – DEPARTURE', '<p style=\"text-align:justify;\">Breakfast at hotel and check out. Continue Jakarta city tour visiting <strong>Monas, Istiqlal Mosque, Cathedral Church, and photo stop at Istana Negara</strong>. Shopping at <strong>Mangga Dua Square</strong>.&nbsp;</p><p style=\"text-align:justify;\">Proceed to Soekarno Hatta International Airport (CGK). End of services.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:32:11', '2026-05-29 13:32:11'),
(4330, 'App\\Models\\IndonesiaDestination', 72, 1, 'ITINERARY FULLDAY TOUR', '<p style=\"text-align:justify;\">Perjalanan dimulai pukul 07.00 dengan penjemputan di hotel dan <i>briefing</i> persiapan di Bukit Paralayang. Agenda utama adalah <strong>Paragliding Flight</strong> pada pukul 08.30 untuk menikmati terbang tandem bersama instruktur profesional dengan panorama pantai selatan dari ketinggian.&nbsp;</p><p style=\"text-align:justify;\">Setelah istirahat dan sesi foto, perjalanan dilanjutkan mengunjungi <strong>Pantai Tanjung Aan</strong> dan <strong>Bukit Merese</strong>.</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, Anda akan diajak mengenal budaya suku Sasak di <strong>Desa Adat Sade</strong>.&nbsp;</p><p style=\"text-align:justify;\">Menjelang sore, tour ditutup dengan mengunjungi <strong>Pantai Selong Belanak</strong> dan <strong>Pantai Mawi</strong> sebelum akhirnya kembali ke hotel pada pukul 16.30.</p>', NULL, 'Lunch', '2026-05-29 13:44:59', '2026-05-29 13:44:59'),
(4331, 'App\\Models\\IndonesiaDestination', 71, 1, 'ITINERARY HALF DAY TOUR', '<p style=\"text-align:justify;\">Perjalanan dimulai pukul 08.30 dengan penjemputan peserta di area Hotel, Senggigi, Mataram, atau Mandalika. Setelah penjemputan, tim akan mengantar Anda menuju lokasi <i>off road</i> pilihan, yaitu <strong>Gunung Tunak, Benang Setokel, </strong>atau <strong>Kawasan Gunung Jae.</strong></p><p style=\"text-align:justify;\">Kegiatan dilanjutkan dengan sesi <i>explore &amp; adventure</i> menggunakan unit <i>Double Cabin</i> untuk menikmati pengalaman petualangan di alam terbuka.&nbsp;</p><p style=\"text-align:justify;\">Setelah puas berpetualang, Anda akan diajak menikmati makan siang di restoran lokal pada pukul 12.00 sebelum melakukan perjalanan kembali dan pengantaran ke hotel pada pukul 13.30. Durasi maksimal program ini adalah 5 jam.</p>', NULL, 'Lunch', '2026-05-29 13:45:18', '2026-05-29 13:45:18'),
(4332, 'App\\Models\\IndonesiaDestination', 70, 1, 'ITINERARY FULLDAY TOUR', '<p style=\"text-align:justify;\">Perjalanan dimulai pada pukul 08.30 dengan penjemputan peserta di area Hotel, Senggigi, Mataram, atau Mandalika. Peserta akan langsung diajak menikmati sensasi berkendara <i>off road</i> menuju lokasi pilihan utama. Pada pukul 12.30, agenda dilanjutkan dengan menikmati makan siang di <strong>RESTAURANT TUNAK COTTAGE</strong>.</p><p style=\"text-align:justify;\">Setelah makan siang, petualangan berlanjut pada pukul 15.00 menuju kawasan <strong>SARI GOANG TUNAK</strong>, dilanjutkan dengan perjalanan menuju area <strong>TEBING</strong> pada pukul 16.00 untuk mengeksplorasi keindahan alam pesisir dari ketinggian.&nbsp;</p><p style=\"text-align:justify;\">Menjelang sore hari pukul 17.30, Anda akan disuguhkan pemandangan <strong>SUNSET</strong> yang memukau sebelum akhirnya seluruh rangkaian program selesai dan peserta diantar kembali pada pukul 19.00.</p><h3 style=\"text-align:justify;\"><strong>PILIHAN LOKASI:</strong></h3><p style=\"text-align:justify;\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; GUNUNG TUNAK</p><p style=\"text-align:justify;\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; BENANG SETOKEL</p><p style=\"text-align:justify;\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; KAWASAN GUNUNG JAE</p>', NULL, 'Lunch', '2026-05-29 13:45:40', '2026-05-29 13:45:40'),
(4333, 'App\\Models\\IndonesiaDestination', 69, 1, 'AIRPORT – SASAK MANDALIKA – HOTEL', '<p style=\"text-align:justify;\">Setibanya di <strong>Lombok</strong>, Anda akan dijemput oleh tim kami untuk memulai perjalanan. Destinasi pertama adalah <strong>Kawasan Mandalika</strong> dan <strong>Bukit Merese</strong> di mana Anda bisa menyaksikan panorama <strong>Teluk Mandalika</strong> yang memukau dari ketinggian. Kita juga akan singgah sejenak di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi perhelatan MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, nikmati <strong>Makan Siang</strong> di restoran lokal di kawasan <strong>Mandalika</strong>. Perjalanan berlanjut menuju <strong>Desa Tradisional Sade</strong>, desa peninggalan suku Sasak yang masih sangat terjaga adat dan budayanya.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak menuju hotel di kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk <i>check-in</i> dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:45:59', '2026-05-29 13:45:59'),
(4334, 'App\\Models\\IndonesiaDestination', 69, 2, 'PINK BEACH & SURROUND', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda akan dijemput menuju <strong>Pelabuhan Tanjung Luar</strong> untuk eksplorasi pantai menggunakan <i>boat</i>. Kita akan mengunjungi <strong>Pulau Pasir</strong>, sebuah fenomena alam unik yang muncul tergantung pasang surut air laut.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Gili Petelu</strong> untuk aktivitas <i>snorkeling</i> bersama ikan-ikan karang yang jinak. Puncaknya, kita akan menuju <strong>Pantai Tangsi</strong> atau <strong>Pantai Pink</strong>. Di sini Anda bisa menaiki bukit untuk melihat panorama nan luas serta menikmati <strong>Makan Siang</strong> di tepi pantai dengan konsep piknik menu ikan bakar segar.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita kembali ke daratan melalui <strong>Tanjung Luar</strong> dan bertolak ke hotel untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:45:59', '2026-05-29 13:45:59'),
(4335, 'App\\Models\\IndonesiaDestination', 69, 3, 'CHECK OUT HOTEL – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda memiliki waktu bebas (<i>free &amp; easy</i>) hingga saatnya <i>check-out</i>. Jadwal kepulangan akan menyesuaikan dengan jam penerbangan Anda, diantar menuju <strong>Bandara</strong> untuk perjalanan pulang. Acara tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:45:59', '2026-05-29 13:45:59'),
(4336, 'App\\Models\\IndonesiaDestination', 68, 1, 'AIRPORT – DESA SADE – MANDALIKA – BUKIT MERESE – HOTEL', '<p style=\"text-align:justify;\">Setibanya di Bandara, Anda akan disambut oleh tim kami untuk memulai perjalanan budaya mengunjungi <strong>DESA SUKU SASAK SADE</strong>.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan menuju kawasan <strong>MANDALIKA</strong> untuk melihat sirkuit internasional dan menikmati pemandangan laut yang ikonik dari atas <strong>BUKIT MERESE</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, Anda akan diantar menuju hotel untuk proses <i>check-in</i> dan beristirahat.&nbsp;</p>', NULL, 'Lunch', '2026-05-29 13:46:19', '2026-05-29 13:46:19'),
(4337, 'App\\Models\\IndonesiaDestination', 68, 2, 'GILI AIR & GILI TRAWANGAN', '<p style=\"text-align:justify;\">Setelah sarapan pagi di hotel, agenda hari kedua difokuskan pada pengalaman bahari mengunjungi pulau-pulau eksotis. Anda akan diajak melakukan aktivitas <strong>SNORKELING</strong> di perairan jernih <strong>GILI AIR</strong> untuk melihat keindahan bawah laut.</p><p style=\"text-align:justify;\">Kemudian dilanjutkan menuju <strong>GILI TRAWANGAN</strong>. Di Gili Trawangan, Anda diberikan waktu bebas (<i>free time</i>) untuk mengeksplorasi pulau sebelum kembali ke hotel pada sore hari.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:46:19', '2026-05-29 13:46:19'),
(4338, 'App\\Models\\IndonesiaDestination', 68, 3, 'CHECK OUT HOTEL – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Menikmati sarapan pagi dan waktu santai di hotel sebelum proses <i>check-out</i>. Tim kami akan menjemput dan mengantar Anda kembali menuju Bandara untuk perjalanan pulang. Program tour selesai.</p>', NULL, 'Breakfast', '2026-05-29 13:46:19', '2026-05-29 13:46:19');
INSERT INTO `itineraries` (`id`, `itinerable_type`, `itinerable_id`, `day_number`, `title`, `description`, `hotel_info`, `meals_info`, `created_at`, `updated_at`) VALUES
(4339, 'App\\Models\\IndonesiaDestination', 67, 1, 'AIRPORT – SASAK MANDALIKA – HOTEL', '<p style=\"text-align:justify;\">Setibanya <strong>di Lombok</strong>, Anda akan dijemput oleh tim kami untuk memulai petualangan. Perjalanan dilanjutkan menuju <strong>Kawasan Mandalika</strong> dan <strong>Bukit Merese</strong> untuk menyaksikan panorama <strong>Teluk Mandalika</strong> dari atas bukit yang memukau. Kita juga akan singgah di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi perhelatan MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, nikmati <strong>Makan Siang</strong> di restoran lokal di kawasan <strong>Mandalika</strong>. Perjalanan berlanjut ke <strong>Desa Tradisional Sade</strong>, sebuah desa peninggalan suku Sasak yang masih&nbsp; kental dengan adat dan budayanya.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita bertolak ke kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:46:41', '2026-05-29 13:46:41'),
(4340, 'App\\Models\\IndonesiaDestination', 67, 2, 'GILI NANGGU', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda akan berangkat menuju Pelabuhan Tawun Sekotong. Menggunakan <i>boat</i> wisata, kita akan menyeberang menuju <strong>Gili Nanggu</strong> untuk aktivitas <i>snorkeling</i> sambil <i>fish feeding</i>.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Gili Tangkong</strong> untuk menikmati <strong>Makan Siang</strong> di restoran lokal, disusul dengan kunjungan ke <strong>Gili Kedis</strong> untuk acara bebas.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak kembali ke daratan melalui <strong>Pelabuhan Tawun</strong> dan kembali menuju hotel di kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:46:41', '2026-05-29 13:46:41'),
(4341, 'App\\Models\\IndonesiaDestination', 67, 3, 'CHECK OUT HOTEL – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda memiliki waktu bebas hingga saatnya <i>check-out</i>. Diantar menuju <strong>Bandara</strong> untuk perjalanan pulang. Acara tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:46:41', '2026-05-29 13:46:41'),
(4342, 'App\\Models\\IndonesiaDestination', 66, 1, 'AIRPORT - SASAK MANDALIKA - HOTEL', '<p style=\"text-align:justify;\">Setibanya di Lombok, Anda akan disambut oleh tim kami di bandara untuk memulai perjalanan menuju Kawasan Mandalika. Destinasi pertama adalah <strong>Bukit Merese</strong>, di mana Anda dapat menyaksikan panorama indah Teluk Mandalika dari ketinggian, dilanjutkan dengan kunjungan ke <strong>Sirkuit Mandalika</strong> untuk melihat lokasi penyelenggaraan MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, perjalanan diteruskan ke <strong>Desa Tradisional SADE</strong> untuk melihat lebih dekat kehidupan suku Sasak yang masih memegang teguh adat dan budayanya.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak menuju kawasan Senggigi untuk proses <i>check-in</i> hotel dan beristirahat.&nbsp;</p>', NULL, 'Lunch', '2026-05-29 13:47:02', '2026-05-29 13:47:02'),
(4343, 'App\\Models\\IndonesiaDestination', 66, 2, 'GILI AIR & TRAWANGAN', '<p style=\"text-align:justify;\">Setelah sarapan pagi di hotel, perjalanan dimulai menuju Pelabuhan Teluk Nare untuk menyeberang menggunakan kapal wisata menuju <strong>Gili Air</strong>. Sesampainya di sana, Anda dapat menikmati aktivitas <i>snorkeling</i> dan <i>fish feeding</i> hingga menjelang siang, sebelum melanjutkan perjalanan ke <strong>Gili Trawangan</strong>.&nbsp;</p><p style=\"text-align:justify;\">Di Gili Trawangan, Anda akan menikmati makan siang di restoran lokal dan diberikan waktu bebas hingga sore hari untuk mengeksplorasi pulau.&nbsp;</p><p style=\"text-align:justify;\">Pukul 15.00, kita akan kembali ke Teluk Nare dan melanjutkan perjalanan menuju hotel melalui Mataram atau Senggigi untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:47:02', '2026-05-29 13:47:02'),
(4344, 'App\\Models\\IndonesiaDestination', 66, 3, 'CHECK OUT HOTEL - TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah sarapan pagi dan menikmati waktu bebas, Anda akan melakukan proses <i>check-out</i> hotel yang disesuaikan dengan jadwal penerbangan. Diantar menuju bandara untuk perjalanan pulang. Tour selesai!</p>', NULL, 'Breakfast', '2026-05-29 13:47:03', '2026-05-29 13:47:03'),
(4345, 'App\\Models\\IndonesiaDestination', 65, 1, 'AIRPORT – SASAK MANDALIKA – HOTEL', '<p style=\"text-align:justify;\">Setibanya di <strong>Lombok</strong>, Anda akan dijemput oleh tim kami untuk memulai petualangan. Perjalanan pertama menuju <strong>Kawasan Mandalika</strong> dan <strong>Bukit Merese</strong> untuk menyaksikan panorama <strong>Teluk Mandalika</strong> dari ketinggian yang memukau. Kita juga akan singgah di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi perhelatan MotoGP yang ikonik.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan menikmati <strong>Makan Siang</strong> di restoran lokal di kawasan <strong>Mandalika</strong>. Perjalanan dilanjutkan ke <strong>Desa Tradisional Sade</strong>, sebuah desa adat suku Sasak yang masih terjaga keaslian budaya dan bangunannya.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak ke kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:47:30', '2026-05-29 13:47:30'),
(4346, 'App\\Models\\IndonesiaDestination', 65, 2, 'GILI TRAWANGAN', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda akan berangkat menuju <strong>Pelabuhan Teluk Nare</strong>. Dengan menggunakan <i>boat</i> wisata, kita akan menyeberang menuju <strong>Gili Air</strong> untuk aktivitas <i>snorkeling</i> dan <i>fish feeding</i> hingga menjelang tengah hari.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Gili Trawangan</strong>, di mana Anda akan menikmati <strong>Makan Siang</strong> di restoran lokal. Di sini, Anda memiliki acara bebas untuk mengeksplorasi pulau hingga sore hari.&nbsp;</p><p style=\"text-align:justify;\">Pukul 15.00, kita akan kembali menyeberang ke <strong>Teluk Nare</strong> dan melanjutkan perjalanan darat menuju hotel di kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk beristirahat.&nbsp;</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:47:31', '2026-05-29 13:47:31'),
(4347, 'App\\Models\\IndonesiaDestination', 65, 3, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Dijemput di hotel, perjalanan dimulai menuju <strong>Taman Wisata Rinjani</strong> melalui jalur Aikmel. Kita akan singgah di <strong>Pusuk Pass Sembalun</strong> untuk berfoto dengan latar hutan Lindung Rinjani sebelum menuju <strong>Lembah Sembalun</strong>. Setibanya di sana, Anda akan diajak <i>soft hiking</i> ke <strong>Bukit Selong</strong> untuk melihat hamparan sawah berwarna-warni, serta mengunjungi <strong>Bukit 360</strong> dan <strong>Pamendangan Sajang</strong> untuk menikmati kemegahan <strong>Gunung Rinjani</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah puas berfoto, Anda akan menikmati <strong>Makan Siang</strong> di restoran lokal. Sore harinya, kita kembali menuju <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk waktu bebas dan istirahat di hotel.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:47:31', '2026-05-29 13:47:31'),
(4348, 'App\\Models\\IndonesiaDestination', 65, 4, 'CHECK OUT HOTEL – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda memiliki waktu bebas hingga saatnya <i>check-out</i>. Diantar menuju <strong>Bandara</strong> untuk kembali ke kota asal. Acara tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:47:31', '2026-05-29 13:47:31'),
(4349, 'App\\Models\\IndonesiaDestination', 64, 1, 'AIRPORT - SASAK MANDALIKA - HOTEL', '<p style=\"text-align:justify;\">Setibanya di Lombok, Anda akan disambut oleh tim kami di bandara untuk memulai perjalanan menuju Kawasan Mandalika. Destinasi pertama adalah <strong>Bukit Merese</strong>, di mana Anda dapat menyaksikan panorama Teluk Mandalika yang menakjubkan dari ketinggian, serta singgah di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi penyelenggaraan balap MOTO GP.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal kawasan Mandalika, perjalanan dilanjutkan ke <strong>Desa Tradisional SADE</strong> untuk mengenal lebih dekat budaya suku Sasak yang masih terjaga keasliannya.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya, kita akan bertolak menuju kawasan Senggigi untuk proses <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:48:07', '2026-05-29 13:48:07'),
(4350, 'App\\Models\\IndonesiaDestination', 64, 2, 'GILI NANGGU', '<p style=\"text-align:justify;\">Setelah menikmati sarapan pagi di hotel, Anda akan berangkat menuju Pelabuhan Tawun Sekotong. Menggunakan <i>boat</i> wisata, kita akan menyeberang menuju <strong>Gili Nanggu</strong> untuk aktivitas <i>snorkeling</i> sambil <i>fish feeding</i>.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Gili Tangkong</strong> untuk menikmati makan siang di restoran lokal, disusul dengan kunjungan ke <strong>Gili Kedis</strong> untuk acara bebas.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak kembali ke daratan melalui Pelabuhan Tawun dan kembali menuju hotel di kawasan Mataram atau Senggigi untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:48:07', '2026-05-29 13:48:07'),
(4351, 'App\\Models\\IndonesiaDestination', 64, 3, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Pagi hari, tim akan menjemput Anda di hotel untuk berangkat menuju <strong>Taman Wisata Rinjani</strong> melalui jalur Aikmel.&nbsp;</p><p style=\"text-align:justify;\">Kita akan singgah sejenak di <strong>Pusuk Pass Sembalun</strong> untuk menikmati keindahan hutan Rinjani sebelum melakukan <i>soft hiking</i> ke <strong>Bukit Selong</strong>. Dari ketinggian tersebut, Anda akan disuguhi panorama Lembah Sembalun dengan latar hamparan sawah berwarna-warni yang dikelilingi pegunungan. Perjalanan berlanjut ke <strong>Bukit 360</strong> dan <strong>Pamendangan Sajang</strong> untuk menyaksikan kemegahan <strong>Gunung Rinjani</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang dan beristirahat, kita akan kembali ke hotel untuk beristirahat atau menikmati acara bebas.&nbsp;</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:48:07', '2026-05-29 13:48:07'),
(4352, 'App\\Models\\IndonesiaDestination', 64, 4, 'CHECK OUT HOTEL - TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Mengawali hari terakhir, Anda dapat menikmati sarapan pagi di hotel dan waktu santai. Tim kami akan mengantar Anda menuju Bandara untuk tujuan selanjutnya. Seluruh rangkaian tour berakhir di sini.</p>', NULL, 'Breakfast', '2026-05-29 13:48:07', '2026-05-29 13:48:07'),
(4353, 'App\\Models\\IndonesiaDestination', 63, 1, 'AIRPORT - SASAK MANDALIKA - HOTEL', '<p style=\"text-align:justify;\">Setibanya di Lombok, Anda akan disambut oleh tim kami dan langsung memulai perjalanan menuju Kawasan Mandalika.&nbsp;</p><p style=\"text-align:justify;\">Destinasi pertama adalah <strong>Bukit Merese</strong> untuk menyaksikan panorama Teluk Mandalika dari ketinggian, dilanjutkan dengan kunjungan ke <strong>Sirkuit Mandalika</strong> yang merupakan lokasi balap MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, Anda akan diajak mengunjungi <strong>Desa Tradisional SADE</strong> untuk melihat keunikan budaya suku Sasak yang masih terjaga dengan baik.&nbsp;</p><p style=\"text-align:justify;\">Hari ditutup dengan perjalanan menuju kawasan Senggigi untuk proses <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:48:34', '2026-05-29 13:48:34'),
(4354, 'App\\Models\\IndonesiaDestination', 63, 2, 'PINK BEACH & SURROUND', '<p style=\"text-align:justify;\">Setelah sarapan pagi, perjalanan dimulai menuju <strong>Pelabuhan Tanjung Luar</strong> untuk menyeberang menuju kawasan Pantai Pink.&nbsp;</p><p style=\"text-align:justify;\">Agenda pertama adalah mengunjungi <strong>Pulau Pasir</strong> (tergantung kondisi pasang surut) untuk berfoto di tengah laut, kemudian dilanjutkan ke <strong>Gili Petelu</strong> untuk aktivitas <i>snorkeling</i> dan memberi makan ikan karang.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya, Anda akan menuju <strong>Pantai Tangsi</strong> atau <strong>Pantai Pink</strong> untuk mendaki bukit dan menikmati pemandangan laut yang luas sambil menyantap makan siang dengan konsep piknik ikan bakar di lokasi. Sore harinya, kita akan bertolak kembali ke pelabuhan dan diantar menuju hotel untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:48:34', '2026-05-29 13:48:34'),
(4355, 'App\\Models\\IndonesiaDestination', 63, 3, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Pagi hari dimulai dengan perjalanan menuju <strong>Taman Wisata Rinjani</strong> melalui jalur Aikmel. Anda akan singgah di <strong>Pusuk Pass Sembalun</strong> untuk menikmati keasrian hutan Rinjani sebelum melanjutkan perjalanan menuju <strong>Bukit Selong</strong> untuk melakukan <i>soft hiking</i> dan berfoto dengan latar hamparan sawah warna-warni yang memukau.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Bukit 360</strong> dan <strong>Pamendangan Sajang</strong> untuk menyaksikan kemegahan <strong>Gunung Rinjani</strong>. Setelah makan siang di restoran lokal, Anda akan diantar kembali menuju Mataram atau Senggigi untuk menikmati acara bebas di hotel.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:48:36', '2026-05-29 13:48:36'),
(4356, 'App\\Models\\IndonesiaDestination', 63, 4, 'CHECK OUT HOTEL - TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah sarapan dan menikmati waktu santai, Anda akan melakukan proses <i>check-out</i> hotel yang disesuaikan dengan jadwal penerbangan. Tour selesai!</p>', NULL, 'Breakfast', '2026-05-29 13:48:36', '2026-05-29 13:48:36'),
(4357, 'App\\Models\\IndonesiaDestination', 62, 1, 'ARRIVAL & PREPARATION', '<p style=\"text-align:justify;\">Setibanya di Bandara Internasional Lombok, Anda akan disambut hangat oleh tim kami dan langsung diantar menuju <strong>Desa Sembalun</strong> untuk melakukan proses <i>check-in</i> di homestay atau guesthouse yang telah disediakan.&nbsp;</p><p style=\"text-align:justify;\">Agenda hari pertama ini difokuskan sepenuhnya pada persiapan fisik dan mental; Anda akan mengikuti sesi <i>briefing</i> mendalam bersama <i>guide</i> profesional untuk memahami rute serta aturan keselamatan.&nbsp;</p><p style=\"text-align:justify;\">Tim juga akan melakukan pengecekan menyeluruh terhadap seluruh perlengkapan dan logistik guna memastikan kenyamanan maksimal sebelum Anda beristirahat untuk memulai pendakian esok hari.</p>', NULL, NULL, '2026-05-29 13:49:08', '2026-05-29 13:49:08'),
(4358, 'App\\Models\\IndonesiaDestination', 62, 2, 'SEMBALUN – PLAWANGAN SEMBALUN', '<p style=\"text-align:justify;\">Petualangan dimulai pagi hari dari titik awal pendakian di ketinggian ±1.150 mdpl. Anda akan melintasi jalur sabana yang luas melalui Pos 1, Pos 2, hingga tiba di Pos 3 untuk beristirahat sejenak sambil menikmati makan siang di alam terbuka.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan kemudian berlanjut dengan tantangan menanjak menuju <strong>Plawangan Sembalun</strong> yang berada di ketinggian 2.639 mdpl.&nbsp;</p><p style=\"text-align:justify;\">Dengan estimasi waktu tempuh 7-8 jam, Anda akan tiba di area perkemahan tepat waktu untuk menyaksikan kemegahan <strong>Danau Segara Anak</strong> dari ketinggian sebelum menutup hari dengan makan malam hangat di bawah langit berbintang.</p>', NULL, NULL, '2026-05-29 13:49:08', '2026-05-29 13:49:08'),
(4359, 'App\\Models\\IndonesiaDestination', 62, 3, 'SUMMIT ATTACK – DANAU SEGARA ANAK', '<p style=\"text-align:justify;\">Hari yang paling dinantikan dimulai pada pukul 02.00 dini hari untuk melakukan <i>summit attack</i> menuju <strong>Puncak Rinjani</strong> di ketinggian 3.726 mdpl. Di titik tertinggi ini, Anda akan disuguhi panorama matahari terbit yang spektakuler dengan latar belakang Gunung Agung di Bali dan Gunung Tambora di Sumbawa.&nbsp;</p><p style=\"text-align:justify;\">Setelah momen tersebut, Anda akan turun kembali ke Plawangan untuk sarapan, lalu melanjutkan perjalanan menuju bibir <strong>Danau Segara Anak</strong>. Setibanya di sana, Anda bisa merelaksasi otot-otot yang lelah di <strong>Air Panas Alami</strong> sebelum bermalam di area <i>camping</i> yang tenang di pinggir danau.</p>', NULL, NULL, '2026-05-29 13:49:08', '2026-05-29 13:49:08'),
(4360, 'App\\Models\\IndonesiaDestination', 62, 4, 'DANAU SEGARA ANAK – TOREAN (EXIT)', '<p style=\"text-align:justify;\">Setelah menikmati sarapan pagi dengan pemandangan danau yang tenang, perjalanan pulang akan dilakukan melalui <strong>Jalur Torean</strong>. Jalur ini dikenal sebagai rute paling eksotis karena menawarkan pemandangan yang berbeda drastis, yakni berupa <strong>Lembah Hijau</strong>, aliran sungai yang jernih, serta deretan <strong>Air Terjun</strong> yang sangat ikonik.&nbsp;</p><p style=\"text-align:justify;\">Dengan estimasi waktu perjalanan sekitar 7-8 jam, rute ini akan membawa Anda hingga mencapai titik akhir di Desa Torean. Dari sana, tim kami telah siap melakukan transfer menuju hotel atau langsung ke Bandara untuk perjalanan pulang. Tour selesai!</p>', NULL, NULL, '2026-05-29 13:49:08', '2026-05-29 13:49:08'),
(4361, 'App\\Models\\IndonesiaDestination', 61, 1, 'AIRPORT – SASAK MANDALIKA – HOTEL', '<p style=\"text-align:justify;\">Setibanya di <strong>Lombok</strong>, Anda akan dijemput oleh tim kami untuk memulai petualangan. Perjalanan dilanjutkan menuju <strong>Kawasan Mandalika</strong> dan <strong>Bukit Merese</strong> untuk menyaksikan panorama <strong>Teluk Mandalika</strong> dari atas bukit yang memukau. Kita juga akan singgah di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi perhelatan MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, nikmati <strong>Makan Siang</strong> di restoran lokal di kawasan <strong>Mandalika</strong>. Perjalanan berlanjut ke <strong>Desa Tradisional Sade</strong>, sebuah desa peninggalan suku Sasak yang masih kental dengan adat dan budayanya.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita bertolak ke kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:49:39', '2026-05-29 13:49:39'),
(4362, 'App\\Models\\IndonesiaDestination', 61, 2, 'GILI TRAWANGAN', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda akan berangkat menuju <strong>Pelabuhan Teluk Nare</strong>. Menggunakan <i>boat</i> wisata, kita akan menyeberang menuju <strong>Gili Air</strong> untuk aktivitas <i>snorkeling</i> sambil <i>fish feeding</i>.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan ke <strong>Gili Trawangan</strong> untuk menikmati <strong>Makan Siang</strong> di restoran lokal. Di sini, Anda memiliki acara bebas untuk mengeksplorasi keindahan pulau hingga sore hari. Pukul 15.00, kita akan bertolak kembali ke <strong>Teluk Nare</strong> dan melanjutkan perjalanan darat menuju hotel di kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:49:39', '2026-05-29 13:49:39'),
(4363, 'App\\Models\\IndonesiaDestination', 61, 3, 'PINK BEACH & SURROUND', '<p style=\"text-align:justify;\">Setelah <strong>Sarapan Pagi</strong> di hotel, Anda akan dijemput menuju <strong>Pelabuhan Tanjung Luar</strong> untuk eksplorasi pantai menggunakan <i>boat</i>. Destinasi pertama adalah <strong>Pulau Pasir</strong>, hamparan pasir di tengah laut yang unik (tergantung pasang surut air laut).&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Gili Petelu</strong> untuk <i>snorkeling</i> dan bermain bersama ikan karang. Puncaknya, kita akan mengunjungi <strong>Pantai Tangsi</strong> atau yang lebih dikenal sebagai <strong>Pantai Pink</strong>, di mana Anda bisa mendaki bukit untuk melihat panorama yang indah.&nbsp;</p><p style=\"text-align:justify;\"><strong>Makan Siang</strong> akan disajikan di tepi pantai dengan konsep piknik menu ikan bakar segar. Sore harinya, kita kembali ke daratan dan beristirahat di hotel.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:49:39', '2026-05-29 13:49:39'),
(4364, 'App\\Models\\IndonesiaDestination', 61, 4, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Menikmati <strong>Sarapan Pagi</strong> di hotel, lalu kita berangkat menuju kawasan <strong>Taman Wisata Rinjani</strong> melalui jalur Aikmel.&nbsp;</p><p style=\"text-align:justify;\">Kita akan singgah di <strong>Pusuk Pass Sembalun</strong> untuk menikmati udara segar dan foto sesi sebelum menuju <strong>Lembah Sembalun</strong>. Setibanya di sana, Anda akan diajak <i>soft hiking</i> ke <strong>Bukit Selong</strong> untuk melihat pemandangan sawah warna-warni yang dikelilingi pegunungan.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan berlanjut ke <strong>Bukit 360</strong> dan <strong>Pamendangan Sajang</strong> untuk menyaksikan kemegahan <strong>Gunung Rinjani</strong>. Setelah menikmati <strong>Makan Siang</strong> di restoran lokal, kita kembali ke kawasan kota untuk beristirahat.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:49:39', '2026-05-29 13:49:39'),
(4365, 'App\\Models\\IndonesiaDestination', 61, 5, 'CHECK OUT HOTEL – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah <strong>Sarapan Pagi</strong>, Anda memiliki waktu bebas hingga saatnya <i>check-out</i> hotel. Sesuai jadwal penerbangan, Acara tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:49:39', '2026-05-29 13:49:39'),
(4366, 'App\\Models\\IndonesiaDestination', 60, 1, 'AIRPORT - SASAK MANDALIKA - HOTEL', '<p style=\"text-align:justify;\">Setibanya di Lombok, Anda akan disambut oleh tim kami di bandara untuk memulai petualangan menuju Kawasan Mandalika. Perjalanan diawali dengan mengunjungi <strong>Bukit Merese</strong> untuk menyaksikan panorama Teluk Mandalika yang memukau dari ketinggian, serta singgah di <strong>Sirkuit Mandalika</strong> untuk melihat lokasi penyelenggaraan MotoGP.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, agenda dilanjutkan menuju <strong>Desa Tradisional SADE</strong>, sebuah desa adat suku Sasak yang masih memegang teguh warisan budaya leluhur.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan bertolak menuju kawasan Mataram atau Senggigi untuk proses <i>check-in</i> hotel dan beristirahat.</p>', NULL, 'Lunch', '2026-05-29 13:50:07', '2026-05-29 13:50:07'),
(4367, 'App\\Models\\IndonesiaDestination', 60, 2, 'GILI NANGGU TOUR', '<p style=\"text-align:justify;\">Setelah sarapan pagi di hotel, perjalanan dimulai menuju Pelabuhan Tawun Sekotong untuk menyeberang menggunakan kapal wisata ke <strong>Gili Nanggu</strong>. Di sini, Anda dapat menikmati aktivitas <i>snorkeling</i> dan <i>fish feeding</i> hingga menjelang siang sebelum melanjutkan perjalanan ke <strong>Gili Tangkong</strong> untuk makan siang di restoran lokal.&nbsp;</p><p style=\"text-align:justify;\">Destinasi berikutnya adalah <strong>Gili Kedis</strong>, di mana Anda diberikan waktu bebas untuk mengeksplorasi pulau kecil yang eksotis ini.&nbsp;</p><p style=\"text-align:justify;\">Pada sore hari, kita akan kembali ke pelabuhan dan melanjutkan perjalanan pulang ke hotel di Mataram atau Senggigi.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:07', '2026-05-29 13:50:07'),
(4368, 'App\\Models\\IndonesiaDestination', 60, 3, 'PINK BEACH & SURROUND', '<p style=\"text-align:justify;\">Agenda hari ketiga dimulai dengan perjalanan menuju <strong>Pelabuhan Tanjung Luar</strong> untuk mengeksplorasi kawasan Pantai Pink.&nbsp;</p><p style=\"text-align:justify;\">Destinasi pertama adalah <strong>Pulau Pasir</strong> (tergantung kondisi pasang surut) dan <strong>Gili Petelu</strong> untuk aktivitas <i>snorkeling</i> sambil memberi makan ikan karang.&nbsp;</p><p style=\"text-align:justify;\">Petualangan berlanjut ke <strong>Pantai Tangsi</strong> atau <strong>Pantai Pink</strong>, di mana Anda bisa mendaki bukit untuk menyaksikan pemandangan laut yang luas dan indah. Makan siang akan disajikan di tepi pantai dengan konsep piknik ikan bakar segar sebelum kembali ke daratan utama pada sore hari.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:08', '2026-05-29 13:50:08'),
(4369, 'App\\Models\\IndonesiaDestination', 60, 4, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Pagi hari, tim akan menjemput Anda untuk menuju kawasan <strong>Taman Wisata Rinjani</strong> melalui jalur Aikmel. Perjalanan ini akan melewati <strong>Pusuk Pass Sembalun</strong> untuk menikmati suasana hutan lindung yang asri sebelum sampai di lembah. Anda akan melakukan <i>soft hiking</i> menuju <strong>Bukit Selong</strong> untuk menyaksikan panorama persawahan warna-warni yang dikelilingi pegunungan, serta mengunjungi <strong>Bukit 360</strong> dan <strong>Pamendangan Sajang</strong> untuk melihat kemegahan Gunung Rinjani.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang dan beristirahat, kita akan kembali menuju kawasan kota untuk beristirahat di hotel.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:08', '2026-05-29 13:50:08'),
(4370, 'App\\Models\\IndonesiaDestination', 60, 5, 'CHECK OUT HOTEL - TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah sarapan pagi dan menikmati waktu bebas, Anda akan melakukan proses <i>check-out</i> hotel yang disesuaikan dengan jadwal penerbangan. Tour selesai!</p>', NULL, 'Breakfast', '2026-05-29 13:50:08', '2026-05-29 13:50:08'),
(4371, 'App\\Models\\IndonesiaDestination', 59, 1, 'AIRPORT – SENGGIGI', '<p style=\"text-align:justify;\">Setibanya di <strong>Lombok</strong>, Anda akan disambut dan dijemput oleh tim kami. Mengawali perjalanan, kita akan langsung menuju restoran lokal untuk menikmati <strong>Makan Siang</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, perjalanan dilanjutkan menuju kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk proses <i>check-in</i> hotel. Sisa hari dapat Anda gunakan untuk beristirahat dan bersantai di sekitar hotel.</p>', NULL, 'Lunch', '2026-05-29 13:50:35', '2026-05-29 13:50:35'),
(4372, 'App\\Models\\IndonesiaDestination', 59, 2, 'GILI TRAWANGAN', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, agenda hari ini dimulai dengan <i>check-out</i> dan bertolak menuju <strong>Pelabuhan Teluk Nare</strong>. Menggunakan <i>speed boat</i>, kita akan menyeberang menuju <strong>Gili Trawangan</strong>. Setibanya di sana, Anda akan menikmati <strong>Makan Siang</strong> di restoran lokal.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya, Anda akan melakukan proses <i>check-in</i> di hotel area <strong>Gili Trawangan</strong> dan bebas menikmati suasana pulau yang eksotis hingga waktu menginap tiba.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:35', '2026-05-29 13:50:35'),
(4373, 'App\\Models\\IndonesiaDestination', 59, 3, 'SEMBALUN', '<p style=\"text-align:justify;\">Menikmati <strong>Sarapan Pagi</strong> di hotel, kemudian melakukan <i>check-out</i> untuk menyeberang kembali ke <strong>Teluk Nare</strong>. Perjalanan dilanjutkan menuju kawasan <strong>Taman Wisata Rinjani</strong> melalui jalur utara Bayan yang asri. Sesampainya di <strong>Sembalun</strong>, kita akan menikmati <strong>Makan Siang</strong> di restoran lokal sebelum <i>check-in</i> hotel.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan melakukan <i>soft hiking</i> ke <strong>Bukit Selong</strong> untuk menyaksikan panorama <strong>Lembah Sembalun</strong> dengan latar hamparan sawah berwarna-warni yang mempesona.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:35', '2026-05-29 13:50:35'),
(4374, 'App\\Models\\IndonesiaDestination', 59, 4, 'MANDALIKA', '<p style=\"text-align:justify;\">Setelah <strong>Sarapan Pagi</strong> dan <i>check-out</i>, kita akan menuju <strong>Pusuk Pass Sembalun</strong> untuk sesi foto dengan pemandangan hutan Rinjani yang indah. Perjalanan berlanjut ke kawasan <strong>Pantai Mandalika</strong>, diawali dengan <strong>Makan Siang</strong> di Kota Praya.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya, kita akan mengeksplorasi <strong>Pantai Tanjung Aan</strong> yang berpasir putih dan mendaki <strong>Bukit Merese</strong> untuk melihat panorama <strong>Teluk Mandalika</strong>.&nbsp;</p><p style=\"text-align:justify;\">Sebelum menuju hotel, kita akan singgah di <strong>Sirkuit Mandalika</strong> untuk melihat tempat pelaksanaan MotoGP.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:50:35', '2026-05-29 13:50:35'),
(4375, 'App\\Models\\IndonesiaDestination', 59, 5, 'CHECK OUT – TRANSFER AIRPORT', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, Anda memiliki waktu bebas hingga saatnya <i>check-out</i>. Sebelum menuju bandara, kita akan menyempatkan diri mengunjungi <strong>Desa Tradisional Sade</strong> untuk melihat keunikan budaya suku Sasak.&nbsp;</p><p style=\"text-align:justify;\">Terakhir, Anda akan diantar menuju <strong>Bandara</strong> sesuai jadwal penerbangan. Acara tour berakhir.</p>', NULL, 'Breakfast', '2026-05-29 13:50:35', '2026-05-29 13:50:35'),
(4376, 'App\\Models\\IndonesiaDestination', 58, 1, 'ARRIVAL LOMBOK – SENGGIGI', '<p style=\"text-align:justify;\">Setibanya di <strong>Lombok</strong>, Anda akan disambut dan dijemput oleh tim kami. Mengawali perjalanan, kita akan langsung menuju restoran lokal untuk menikmati <strong>Makan Siang</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, perjalanan dilanjutkan menuju kawasan <strong>Mataram</strong> atau <strong>Senggigi</strong> untuk proses <i>check-in</i> hotel. Sisa hari dapat Anda gunakan untuk beristirahat dan bersantai di sekitar hotel.</p>', NULL, 'Lunch', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4377, 'App\\Models\\IndonesiaDestination', 58, 2, 'ISLAND HOPPING 3 GILI', '<p style=\"text-align:justify;\">Setelah menikmati <strong>Sarapan Pagi</strong> di hotel, agenda hari ini adalah mengeksplorasi keindahan bawah laut. Kita akan menuju pelabuhan untuk menyeberang menggunakan <i>boat</i> wisata ke <strong>Gili Trawangan, Gili Meno, dan Gili Air</strong>. Anda dapat menikmati aktivitas <i>snorkeling</i> atau sekadar bersantai menikmati suasana pulau yang eksotis.&nbsp;</p><p style=\"text-align:justify;\"><strong>Makan Siang</strong> akan disajikan di restoran lokal di salah satu pulau. Sore harinya, kembali ke hotel di kawasan Senggigi.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4378, 'App\\Models\\IndonesiaDestination', 58, 3, 'EXOTIC SEMBALUN', '<p style=\"text-align:justify;\">Menikmati <strong>Sarapan Pagi</strong> di hotel, kemudian melakukan <i>check-out</i>. Perjalanan dilanjutkan menuju kawasan <strong>Taman Wisata Rinjani</strong> melalui jalur utara yang asri. Sesampainya di <strong>Sembalun</strong>, kita akan menikmati <strong>Makan Siang</strong> di restoran lokal sebelum <i>check-in</i> hotel.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan melakukan <i>soft hiking</i> ke <strong>Bukit Selong</strong> untuk menyaksikan panorama Lembah Sembalun yang mempesona.&nbsp;</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4379, 'App\\Models\\IndonesiaDestination', 58, 4, 'KENAWA ISLAND – START LIVE ON BOARD', '<p style=\"text-align:justify;\">Setelah <strong>Sarapan Pagi</strong> dan <i>check-out</i>, kita menuju pelabuhan untuk menyeberang ke <strong>Pulau Kenawa</strong>. Anda dapat mendaki bukit kecil untuk melihat pemandangan laut yang jernih dan padang savana.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya, kita akan memulai pengalaman menginap di atas kapal (<strong>Live on Board</strong>) untuk memulai pelayaran menuju arah timur. Makan siang dan makan malam disajikan di atas kapal.&nbsp;</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4380, 'App\\Models\\IndonesiaDestination', 58, 5, 'WHALE SHARK EXPERIENCE – TAMBORA', '<p style=\"text-align:justify;\">Dini hari, kapal akan tiba di titik pengamatan <strong>Hiu Paus (Whale Shark)</strong> di perairan Sumbawa. Anda berkesempatan untuk berenang bersama ikan raksasa yang jinak ini.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, perjalanan berlanjut menyisir pesisir utara Sumbawa dengan latar belakang <strong>Gunung Tambora</strong> yang megah. Aktivitas santai dan makan seharian dilakukan di atas kapal.</p>', NULL, NULL, '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4381, 'App\\Models\\IndonesiaDestination', 58, 6, 'PADAR ISLAND – PINK BEACH – KOMODO', '<p style=\"text-align:justify;\">Kapal akan memasuki kawasan <strong>Taman Nasional Komodo</strong>. Agenda hari ini dimulai dengan <i>hiking</i> di <strong>Pulau Padar</strong> untuk melihat panorama tiga teluk yang ikonik. Selanjutnya, kita akan bersantai di <strong>Pink Beach</strong> dan mengunjungi <strong>Pulau Komodo</strong> untuk melihat habitat asli Komodo Dragon didampingi oleh <i>Ranger</i>.&nbsp;</p><p style=\"text-align:justify;\">Bermalam di kapal di sekitar area Taman Nasional.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4382, 'App\\Models\\IndonesiaDestination', 58, 7, 'MANJARITE – KELOR – LABUAN BAJO', '<p style=\"text-align:justify;\">Setelah <strong>Sarapan Pagi</strong>, kita akan mengunjungi <strong>Manjarite</strong> untuk <i>snorkeling</i> dan <strong>Pulau Kelor</strong> untuk menikmati pemandangan terakhir sebelum merapat di pelabuhan.&nbsp;</p><p style=\"text-align:justify;\">Setibanya di <strong>Labuan Bajo</strong>, tim kami akan mengantar Anda menuju Bandara atau hotel sesuai jadwal. Seluruh rangkaian tour berakhir di sini.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 13:51:05', '2026-05-29 13:51:05'),
(4420, 'App\\Models\\IndonesiaDestination', 13, 1, 'Makassar – Bantaeng Tana Beru - Bira', '<p style=\"text-align:justify;\">Upon arrival at <strong>Sultan Hasanuddin International Airport Makassar</strong>, meeting services. Afterwards, drive to <strong>Tanjung Bira</strong> for approximately 6 hours. Driving south from Makassar, you will pass the ethnic of Makassar area.&nbsp;</p><p style=\"text-align:justify;\">While passing Jeneponto Regency, you could see the salt farm along the way. We will stop at <strong>Bisappu Waterfall</strong> at Bantaeng Regency.&nbsp;</p><p style=\"text-align:justify;\">Continue driving, then another stop at Tana Beru to see the famous <strong>Bugis-Makassar Phinisi Boat Builders</strong>. In the afternoon arrive at Bira, the beautiful white sandy beach, free program until dinner time. overnight at hotel.</p>', NULL, 'No Meal', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4421, 'App\\Models\\IndonesiaDestination', 13, 2, 'Bira  (free program)', '<p style=\"text-align:justify;\">Breakfast at hotel, afterwards free program on your own. You could do water activities such as banana boat, snorkeling, or rent a boat to visit <strong>Liukang Island</strong> located at the opposite side of the main island. &nbsp;</p><p style=\"text-align:justify;\">Liukang Island is also known as the breeding place for the green turtle, and you can have swim together with the turtles.&nbsp; overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4422, 'App\\Models\\IndonesiaDestination', 13, 3, 'Bira – Watampone - Sengkang', '<p style=\"text-align:justify;\">After breakfast, drive to <strong>Sengkang</strong> which is located in the centre of the Bugis Kingdom. Stop will be made at Watampone to visit the <strong>Museum of Andi Mappasisi</strong> to see the collections of the former Bugis Royalties, with one of their most famous Kings “Arung Pallakka”.&nbsp;</p><p style=\"text-align:justify;\">In the afternoon arrive in Sengkang, then we will cross the Lake Tempe to visit the <strong>Floating Village</strong></p><p style=\"text-align:justify;\">(Note: Tempe Lake might be shallow in dry season due to lack of rainfall. If the lake is too shallow, we will not be able to cross the lake). overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4423, 'App\\Models\\IndonesiaDestination', 13, 4, 'Sengkang – Palopo – Toraja', '<p style=\"text-align:justify;\">After breakfast, we will visit a <strong>traditional Bugis Silk Weaving Centre</strong>. Then, continue driving to <strong>Toraja</strong> via Palopo. Palopo is a small Moslem port. It is also known as the oldest harbour in Indonesia, continue driving up to Toraja.&nbsp;</p><p style=\"text-align:justify;\">Along the way you will be able to enjoy spectacular view. In the late afternoon arrive at Toraja. overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4424, 'App\\Models\\IndonesiaDestination', 13, 5, 'Toraja tour (Lemo, Kambira, Londa, Kete Kesu)', '<p style=\"text-align:justify;\">After breakfast, a full day tour exploring Toraja. First, we will visit Lemo to see rows of <strong>TauTau Statues</strong> and The <strong>Hanging Graves</strong>.&nbsp;</p><p style=\"text-align:justify;\">Onwards to Kambira to discover the secret of the Baby Tree. visiting Londa, to see an Ancient Grave where the deceased are entombed. At <strong>Kete Kesu </strong>one of the oldest Torajan villages, we can see Tongkonan and Old Rice Barns, also famous for its traditional colourful woodcarving.</p><p style=\"text-align:justify;\">Overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4425, 'App\\Models\\IndonesiaDestination', 13, 6, 'Toraja tour (Batutumonga – short walking - Bori)', '<p style=\"text-align:justify;\">After breakfast, we set out on a trip to <strong>Batutumonga</strong>, enjoying superb views over <strong>Rantepao</strong> and surrounding valleys from the top of <strong>Toraja</strong>. Then we will do a short walking for approximately 2 hours passing thru the rice field, local village where you can also see the daily life of the people in Toraja.&nbsp;</p><p style=\"text-align:justify;\">Next, we will continue to visit <strong>Bori the Megalith area</strong>. This area symbolizes the great funeral ceremonies, which is held in the past. overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4426, 'App\\Models\\IndonesiaDestination', 13, 7, 'Toraja – Makassar', '<p style=\"text-align:justify;\">After breakfast, drive back to Makassar. We will stop at <strong>Puncak Lakawan</strong> which is known as Erotic Mountain. Arrival in the afternoon at Makassar. Overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4427, 'App\\Models\\IndonesiaDestination', 13, 8, 'Hotel - Fort Rotterdam – Makassar  Airport', '<p style=\"text-align:justify;\">After breakfast, if time allows, we will take you for a short city tour to visit <strong>Fort Rotterdam</strong>, the Old Dutch Fortress located right in front of Losari Beach. Then transfer directly to <strong>Sultan Hasanuddin International Airport</strong> to catch your flight for your next destination.</p>', NULL, 'Breakfast', '2026-05-29 13:55:16', '2026-05-29 13:55:16'),
(4471, 'App\\Models\\IndonesiaDestination', 36, 1, 'KNO - PARAPAT - SAMOSIR ISLAND -> ARR FLIGHT MUST BE IN THE MORNING BEFORE 11 AM', '<p>KNO - Parapat ±170 km ±&nbsp;4 hrs / Parapat - Samosir by&nbsp;ferry 1 hour.</p><p style=\"text-align:justify;\">Arrive at airport, meet and greet at the airport then depart for <strong>Parapat</strong> – famous mountain and lake resort on the east shore of the <strong>immense</strong> <strong>volcanic Lake Toba</strong>,&nbsp;about 175 km from airport.&nbsp;&nbsp;</p><p style=\"text-align:justify;\">En route, first hour pass by several small towns and then followed by vast view of rubber, oil palm plantations, paddy terraces, etc. Stopover at <strong>Paten</strong>, local&nbsp;snack&nbsp;shop for toilet break.&nbsp;</p><p style=\"text-align:justify;\">Arrive in <strong>Parapat</strong>, cross over to <strong>Samosir Island</strong>, an island in the middle of Lake Toba in 45 mins by public&nbsp;ferry. Check in hotel.</p>', NULL, 'No Meals', '2026-05-29 14:07:35', '2026-05-29 14:07:35'),
(4472, 'App\\Models\\IndonesiaDestination', 36, 2, 'SAMOSIR ISLAND TOUR HALFDAY BY BOAT', '<p style=\"text-align:justify;\">After breakfast start on Samosir Tour halfday by <strong>motorboat</strong>. Visit the <strong>Tomb of King Sidabutar and Batak Toba Village at Tomok</strong>.&nbsp;</p><p style=\"text-align:justify;\">Then to <strong>Ambarita</strong>, a traditional village with ancient megalithic furniture in front of the traditional house.&nbsp;</p><p style=\"text-align:justify;\">Back to hotel. Rest of the day free on own activities to explore the beauty of <strong>Samosir Island</strong>. You can walk around the island, rent bicycles (own expenses) or just swimming and sunbathing.</p>', NULL, 'Breakfast', '2026-05-29 14:07:35', '2026-05-29 14:07:35'),
(4473, 'App\\Models\\IndonesiaDestination', 36, 3, 'SAMOSIR ISLAND - PARAPAT - BRASTAGI', '<p style=\"text-align:justify;\">Samosir - Parapat by ferry ± 1 hour; Parapat - Brastagi ± 140 km ± 4 hrs</p><p style=\"text-align:justify;\">After breakfast free time at <strong>Samosir</strong>. Noon cross back to Parapat by public ferry then depart for Brastagi via the <strong>Ring Road of Lake Toba</strong>.&nbsp;</p><p style=\"text-align:justify;\">En route pass by pine tree plantation, the magnificent scenery of Lake Toba, fertile vegetable and fruit farms. Visit the <strong>slender Sipiso-piso Waterfall</strong> which drops into Lake Toba from hundreds of meter height.&nbsp;</p><p style=\"text-align:justify;\">Arrive in <strong>Brastagi</strong>, a refreshing mountain resort dominated by two active volcanoes, check in hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:07:35', '2026-05-29 14:07:35'),
(4474, 'App\\Models\\IndonesiaDestination', 36, 4, 'BRASTAGI - MEDAN', '<p style=\"text-align:justify;\">After breakfast,&nbsp;visit the fruit market of <strong>Brastagi</strong>.&nbsp;Depart for Medan via some part of the lush tropical <strong>rain forest of Sumatra</strong> in three hours\' time.&nbsp;</p><p style=\"text-align:justify;\">Visit <strong>Taman Lumbini, Golden Swedagon Pagoda</strong>. Continue for Medan via Sibolangit.&nbsp;</p><p style=\"text-align:justify;\">Arrive in Medan, city tour of Medan. Visit the <strong>temple of East Mountain</strong>, a Chinese Temple with its unique characteristic and Maimoon Palace of old Deli Sultanate. Check in hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:07:35', '2026-05-29 14:07:35'),
(4475, 'App\\Models\\IndonesiaDestination', 36, 5, 'TRANSFER OUT', '<p>Medan - Airport ± 40 km ± 60-90 mins</p><p style=\"text-align:justify;\">After breakfast free on own activity until time to be transferred to airport for dept. Based on current traffic we always trsf clients&nbsp;4 hours before dept time.</p>', NULL, 'Breakfast', '2026-05-29 14:07:35', '2026-05-29 14:07:35'),
(4480, 'App\\Models\\IndonesiaDestination', 34, 1, 'KUALA NAMU - MEDAN – BOHOROK / BUKIT LAWANG', '<p style=\"text-align:justify;\">Arrive at <strong>Medan Kuala Namu airport</strong> before&nbsp;12 pm, meet and greet then drive to north-westward for about&nbsp;3,5 hours to <strong>Bohorok</strong>, <strong>orang utan center</strong>.&nbsp;</p><p style=\"text-align:justify;\">En route passing through several small towns followed by vast view of rubber and oil palm plantations with some countryside landscape. Stop to see palm oil plantation from outside. If it’s in season you can stop to see local <strong>“rambutan”</strong> and <strong>cacao garden</strong>, also stop to see local market in Kuala.&nbsp;</p><p style=\"text-align:justify;\">Arrive in Bohorok, check-in at hotel.&nbsp;</p>', NULL, 'No Meals', '2026-05-29 14:10:09', '2026-05-29 14:10:09'),
(4481, 'App\\Models\\IndonesiaDestination', 34, 2, 'BOHOROK TREK 3 HRS TO SEE THE ORANG UTANS', '<p style=\"text-align:justify;\">After breakfast,&nbsp;start on a 3-hour jungle trekking where you can see the semi or wild <strong>Orangutans.</strong> Steep, slopes and dense vegetation will bring you to the excitement of the <strong>Sumatra rainforest</strong>.&nbsp;</p><p style=\"text-align:justify;\">Here you have the opportunity to see several <strong>species of indigenous flora and fauna</strong>. If you are lucky, you may encounter Orang Utan, leaf monkey, macaque, gibbons, siamang and abundant bird life. Walkers must be fit and have suitable, large profile shoes. Trekking pace will be adjusted with clients\'s stamina.&nbsp;</p><p style=\"text-align:justify;\">Back to hotel. Rest of the day free program. Additional trekking to be paid on the spot.</p>', NULL, 'Breakfast', '2026-05-29 14:10:09', '2026-05-29 14:10:09'),
(4482, 'App\\Models\\IndonesiaDestination', 34, 3, 'BUKIT LAWANG - MEDAN - KNO APT ± 5 HRS DRIVE', '<p style=\"text-align:justify;\">After breakfast, free on own. Return to <strong>Medan</strong> via plantation road in about 3 hrs drive. Arrive in Medan, continue about 90 mins drive time to airport for departure to your next destination.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:10:09', '2026-05-29 14:10:09'),
(4483, 'App\\Models\\IndonesiaDestination', 33, 1, 'ARRIVAL - TRANSFER TO HOTEL', '<p style=\"text-align:justify;\">Upon arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to hotel for check in. Dinner will be served at local restaurant (Optional).</p>', NULL, 'NO MEALS', '2026-05-29 14:12:19', '2026-05-29 14:12:19'),
(4484, 'App\\Models\\IndonesiaDestination', 33, 2, 'JOGJA – SEMARANG', '<p style=\"text-align:justify;\">After breakfast at hotel, we will take you to Semarang around 4 hours driving. Arrive Semarang, enjoy sightseeing in <strong>Sam Po Khong Temple</strong> was built to commemorate Admiral Zheng He (Cheng Ho) expedition from China to Southeast Asia with acculturation of Moslem and Chinese culture.&nbsp;</p><p style=\"text-align:justify;\">Continue to <strong>Lawang Sewu</strong> was built in 1904, originally was the administrative office of the Dutch Railway Company. Lawang in Javanese language means doors and Sewu means thousand. Therefore, since the building has many doors, it is called Lawang Sewu.&nbsp;</p><p style=\"text-align:justify;\">Next, we will go to <strong>Kota Lama</strong> as the Old town of Semarang where you can see old building with European architecture built in the Butch colonial era (Kota Lama). Here you can see the round-shaped dome, so called <strong>Gereja Blenduk</strong> (Belnduk Church) which was built in 1753.&nbsp;</p><p style=\"text-align:justify;\">Back to hotel in Jogja, free program. Dinner will be served at local restaurant (Optional).&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:12:19', '2026-05-29 14:12:19'),
(4485, 'App\\Models\\IndonesiaDestination', 33, 3, 'LAVA TOUR - BOROBUDUR', '<p style=\"text-align:justify;\">After breakfast at hotel, to enjoy <strong>Lava tour</strong> by riding 4x4 Wheel drive Jeep visiting three main points: ruin houses museum, alien rock, and bunker Kaliadem.&nbsp;</p><p style=\"text-align:justify;\">Lunch at local restaurant (Optional), visit <strong>Borobudur Temple</strong> as the world’s largest Buddhist Temple, built in 9th Century during the Sailendra Dynasty and has been listed as a UNESCO World Heritage Site.&nbsp;</p><p style=\"text-align:justify;\">Continue to <strong>Candi Mendut</strong> (Mendut Temple) is older than Candi Borobudur there are story of children in it walls, then direct to <strong>Candi Pawon</strong> (Pawon temple) it\'s not a grave but a place to keep King Indra’s weapon namely Vajranala.&nbsp;</p><p style=\"text-align:justify;\">Dinner at local restaurant (Optional), back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:12:19', '2026-05-29 14:12:19'),
(4486, 'App\\Models\\IndonesiaDestination', 33, 4, 'CITY TOUR – PINE FOREST – HEHA SKYVIEW', '<p style=\"text-align:justify;\">After breakfast at hotel, we will go to <strong>Sultan Palace</strong> which still today considered the highestranking court of Indonesia where old custom of courtesy is still practiced.&nbsp;</p><p style=\"text-align:justify;\">Not far from the Palace, proceed to <strong>Taman Sari Watercastle </strong>is a recreation garden for Sri Sultan’s family. Lunch at local restaurant (Optional).&nbsp;</p><p style=\"text-align:justify;\">Then continue to <strong>Pengger Pine Forest</strong> with the most iconic spoto foto of Giant Hand Shaped Wooden Platform (personal account).&nbsp;</p><p style=\"text-align:justify;\">Drive to <strong>Heha Skyview</strong>, tourist destination with Yogyakarta view. This destination equipped with several instagramable spot foto (personal account). Back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:12:19', '2026-05-29 14:12:19'),
(4487, 'App\\Models\\IndonesiaDestination', 33, 5, 'TRANSFER OUT', '<p>After breakfast at hotel, visit. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:12:19', '2026-05-29 14:12:19');
INSERT INTO `itineraries` (`id`, `itinerable_type`, `itinerable_id`, `day_number`, `title`, `description`, `hotel_info`, `meals_info`, `created_at`, `updated_at`) VALUES
(4488, 'App\\Models\\IndonesiaDestination', 32, 1, 'ARRIVAL - KOTAGEDE -   MALIOBORO', '<p style=\"text-align:justify;\">Upon arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to Kotagede , silver made centre and the old centre of Mataram Yogyakarta.&nbsp;</p><p style=\"text-align:justify;\">Then continue to <strong>Malioboro</strong> as a shopping street where you can buy special foods, clothes, or souvenirs from Jogja.&nbsp;</p><p style=\"text-align:justify;\">Check in hotel, free program. Lunch and dinner will be served at local restaurant (Optional).</p>', NULL, 'No Meals', '2026-05-29 14:13:27', '2026-05-29 14:13:27'),
(4489, 'App\\Models\\IndonesiaDestination', 32, 2, 'DIENG TOUR', '<p style=\"text-align:justify;\">After breakfast at hotel, continue to Dieng Plateu around 3 – 4 hours driving.&nbsp; Continue to <strong>Arjuna Temple Complex</strong>.&nbsp;</p><p style=\"text-align:justify;\">Then, visit <strong>Sikidang Crater </strong>is literally a pond full of boiling acid mud spewing out thick sulphury smoke. Afterwards, enjoy the beauty of <strong>Color Lake</strong>.&nbsp;</p><p style=\"text-align:justify;\">Back to hotel Jogja, free program. Lunch and dinner will be served at local restaurant (Optional).</p>', NULL, 'Breakfast', '2026-05-29 14:13:27', '2026-05-29 14:13:27'),
(4490, 'App\\Models\\IndonesiaDestination', 32, 3, 'BOROBUDUR – CYCLING TOUR', '<p style=\"text-align:justify;\">After breakfast at hotel, we will go to, continue <strong>Stepping up to Borobudur Temple structure floor, </strong>built in 9th Century during the Sailendra Dynasty and has been listed as a UNESCO World Heritage Site.&nbsp;</p><p style=\"text-align:justify;\">Next, visit <strong>Candi Mendut</strong> (Mendut Temple) is older than Candi Borobudur there are story of children in it walls, then direct to <strong>Candi Pawon</strong> (Pawon temple) it\'s not a grave but a place to keep King Indra’s weapon namely Vajranala. Lunch at local resto (Optional).&nbsp;</p><p style=\"text-align:justify;\">Back to Yogyakarta, for next activities <i><strong>Cycling Arround Village, </strong></i>seeing the villager’s activities and stop at photospot and local home industry.<i><strong>&nbsp;</strong></i></p><p style=\"text-align:justify;\">Dinner at local restaurant (Optional), back to hotel, free program.</p>', NULL, 'Breakfast', '2026-05-29 14:13:27', '2026-05-29 14:13:27'),
(4491, 'App\\Models\\IndonesiaDestination', 32, 4, 'CITY TOUR – PINE FOREST – HEHA SKYVIEW', '<p style=\"text-align:justify;\">After breakfast at hotel, we will go to <strong>Sultan Palace</strong> which still today considered the highest-ranking court of Indonesia where old custom of courtesy is still practiced.&nbsp;</p><p style=\"text-align:justify;\">Not far from the Palace, proceed to <strong>Taman Sari Watercastle </strong>is a recreation garden for Sri Sultan’s family. Lunch at local restaurant (Optional).&nbsp;</p><p style=\"text-align:justify;\">Then continue to <strong>Pengger Pine Forest</strong> with the most iconic spoto foto of Giant Hand Shaped Wooden Platform (personal account).&nbsp;</p><p style=\"text-align:justify;\">Drive to <strong>Heha Skyview</strong>, tourist destination with Yogyakarta view. This destination equipped with several instagramable spot foto (personal account). Back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:13:27', '2026-05-29 14:13:27'),
(4492, 'App\\Models\\IndonesiaDestination', 32, 5, 'TRANSFER OUT', '<p style=\"text-align:justify;\">After breakfast at hotel, visit. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:13:27', '2026-05-29 14:13:27'),
(4493, 'App\\Models\\IndonesiaDestination', 31, 1, 'ARRIVAL - BOROBUDUR', '<p style=\"text-align:justify;\">Arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to continue stepping up to<strong> Borobudur Temple structure floor, </strong>built in 9th Century during the Sailendra Dynasty and has been listed as a UNESCO World Heritage Site.&nbsp;</p><p style=\"text-align:justify;\">Check in hotel, free program. Lunch and dinner will be served at local restaurant (Optional).</p>', NULL, 'No Meals', '2026-05-29 14:14:26', '2026-05-29 14:14:26'),
(4494, 'App\\Models\\IndonesiaDestination', 31, 2, 'SHORT BATIK COURSE – CYCLING TOUR', '<p style=\"text-align:justify;\">After breakfast at hotel, we will take you to Giriloyo, Batik Short Course at Giriloyo. Lunch at local restaurant/traditionally.&nbsp;</p><p style=\"text-align:justify;\">Back to Yogyakarta, continue for <strong>Prambanan Village Tour</strong> using Bicycle. You will continue to see several traditional home industries and stop for photo spot.</p><p style=\"text-align:justify;\">Dinner at local restaurant (Optional), back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast/Lunch', '2026-05-29 14:14:26', '2026-05-29 14:14:26'),
(4495, 'App\\Models\\IndonesiaDestination', 31, 3, 'JOMBLANG CAVE - TIMANG', '<p style=\"text-align:justify;\">Early&nbsp;<strong><u> </u></strong>breakfast at hotel, we have to get Jomblang Cave at 09.00 in the morning. Activities to explore&nbsp; <strong>Cave Jomblang</strong>&nbsp; using Single Rope Technique which is helped by professional tenant. Enjoy the cave by exploring stalactites and stalagmite in it. Lunch traditionally.&nbsp;</p><p style=\"text-align:justify;\">Continue to go to&nbsp; <strong>Timang Beach</strong> that is famous for its traditional gondola, formerly used for local fishermen to get lobsters. Now, it is open for tourist as an optional gondola or bridge (personal account).&nbsp;</p><p style=\"text-align:justify;\">Back to Yogyakarta, dinner at local restaurant (Optional), back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast/Lunch', '2026-05-29 14:14:26', '2026-05-29 14:14:26'),
(4496, 'App\\Models\\IndonesiaDestination', 31, 4, 'TRANSFER OUT', '<p style=\"text-align:justify;\">After breakfast at hotel, check out procedure. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:14:26', '2026-05-29 14:14:26'),
(4497, 'App\\Models\\IndonesiaDestination', 30, 1, 'ARRIVAL - PARANGTRITIS – OBELIX SEAVIEW', '<p style=\"text-align:justify;\">Arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to <strong>Parangtritis Beach</strong>.&nbsp;</p><p style=\"text-align:justify;\">Then, visit <strong>Gumuk Pasir sand dune</strong> is rare phenomenon, only few in the world. They are a very high sedimentation of sand coming from <strong>Merapi and Merbabu mountains</strong> forming like a desert.&nbsp;</p><p style=\"text-align:justify;\">Next, enjoy sunset from <strong>Obelix Seaview</strong> with Hindian Ocean panorama. Check in hotel, free program. Lunch and dinner will be served at local restaurant (Optional).</p>', NULL, 'No Meals', '2026-05-29 14:15:41', '2026-05-29 14:15:41'),
(4498, 'App\\Models\\IndonesiaDestination', 30, 2, 'LAVA TOUR – BOROBUDUR - MALIOBORO', '<p style=\"text-align:justify;\">After breakfast at hotel, we will take you to Merapi Mountain to enjoy <strong>Lava Tour </strong>by riding jeep 4x4 WD visiting ruin houses museum caused by Merapi eruption in 2010, “alien stone”,<strong> </strong>and bunker. Lunch at local restaurant (Optional).&nbsp;</p><p style=\"text-align:justify;\">Continue up to stepping<strong> Borobudur Temple structure floor, </strong>built in 9th Century during the Sailendra Dynasty and has been listed as a UNESCO World Heritage Site.&nbsp;</p><p style=\"text-align:justify;\">Free shopping at <strong>Malioboro Street</strong>. &nbsp;Dinner at local restaurant (Optional), back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:15:41', '2026-05-29 14:15:41'),
(4499, 'App\\Models\\IndonesiaDestination', 30, 3, 'TIMANG – BREKSI', '<p style=\"text-align:justify;\">After breakfast at hotel, visit <strong>Timang Beach</strong> that is famous for its traditional gondola, formerly used for local fishermen to get lobsters. Now, it is open for tourist as an optional gondola or bridge (personal account).&nbsp;</p><p style=\"text-align:justify;\">Next, we take you to <strong>Breksi Cliff</strong> as the ruin of limestone mining that remains beautiful giant cliff.&nbsp;</p><p style=\"text-align:justify;\">Dinner at local restaurant (Optional), back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:15:41', '2026-05-29 14:15:41'),
(4500, 'App\\Models\\IndonesiaDestination', 30, 4, 'TRANSFER OUT', '<p style=\"text-align:justify;\">After breakfast at hotel, check out procedure. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:15:42', '2026-05-29 14:15:42'),
(4532, 'App\\Models\\IndonesiaDestination', 21, 1, 'ARRIVAL - PARANGTRITIS – OBELIX SEAVIEW', '<p style=\"text-align:justify;\">Arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to&nbsp; <strong>Parangtritis Beach</strong>.&nbsp;</p><p style=\"text-align:justify;\">Then, visit <strong>Gumuk Pasir sand dune</strong> is rare phenomenon, only few in the world. They are a very high sedimentation of sand coming from <strong>Merapi and Merbabu mountains</strong> forming like a desert.&nbsp;</p><p style=\"text-align:justify;\">Next, enjoy sunset from <strong>Obelix Seaview</strong> with Hindian Ocean panorama. Check in hotel, free program. Lunch and dinner will be served at local restaurant (Optional).</p>', NULL, 'No Meals', '2026-05-29 14:25:11', '2026-05-29 14:25:11'),
(4533, 'App\\Models\\IndonesiaDestination', 21, 2, 'LAVA TOUR – PICTNIQ LAND JOGJA – MALIOBORO', '<p style=\"text-align:justify;\">After breakfast at hotel, we take you to enjoy <strong>Lava Tour in Merapi Mountain</strong> by riding jeep 4x4 WD visiting ruin houses museum caused by Merapi eruption in 2010, “alien stone”,<strong> </strong>and bunker.&nbsp;</p><p style=\"text-align:justify;\">Lunch at local restaurant (Optional), continue <i><strong>Pictniq Land Jogja</strong></i><strong>,</strong> the newest destination Instagram able at Jogja. Free shopping at <strong>Malioboro Street</strong>. Back to hotel, free program.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:25:11', '2026-05-29 14:25:11'),
(4534, 'App\\Models\\IndonesiaDestination', 21, 3, 'TRANSFER OUT', '<p style=\"text-align:justify;\">After breakfast at hotel, check out procedure. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:25:11', '2026-05-29 14:25:11'),
(4535, 'App\\Models\\IndonesiaDestination', 20, 1, 'Arrival - BOROBUDUR', '<p style=\"text-align:justify;\">Upon arrival at Yogyakarta Airport, you will be picked up by our representative. Straight, we will take you to <strong>Borobudur</strong>. we will take you to <strong>Borobudur Temple until its structure floor, </strong>built in 9th Century during the Sailendra Dynasty and has been listed as a UNESCO World Heritage Site.&nbsp;</p><p style=\"text-align:justify;\">Continue to <strong>Candi Mendut</strong> (Mendut Temple) is older than Candi Borobudur there are story of children in it walls and <strong>Candi Pawon</strong> (Pawon temple) it\'s not a grave but a place to keep King Indra’s weapon namely Vajranala.&nbsp;</p><p style=\"text-align:justify;\">Check in hotel, free program. Lunch and dinner will be served at local restaurant.</p>', NULL, 'No Meals', '2026-05-29 14:26:23', '2026-05-29 14:26:23'),
(4536, 'App\\Models\\IndonesiaDestination', 20, 2, 'CITY TOUR - PRAMBANAN', '<p style=\"text-align:justify;\">After breakfast at hotel, we will take you to <strong>Sultan Palace</strong> which still today considered the highest-ranking court of Indonesia where old custom of courtesy is still practiced.&nbsp;</p><p style=\"text-align:justify;\">Not far from the Palace, proceed to <strong>Taman Sari Watercastle </strong>is a recreation garden for Sri Sultan’s family. There is a pool that was once used as a bath for the king\'s concubines. Lunch at local restaurant (Optional).&nbsp;</p><p style=\"text-align:justify;\">Continue to <strong>Prambanan Temple</strong> built in the 10th century, this is the largest temple compound dedicated to Shiva in Indonesia.&nbsp;</p><p style=\"text-align:justify;\">Dinner at local restaurant (Optional), back to hotel, free program.</p>', NULL, 'Breakfast', '2026-05-29 14:26:23', '2026-05-29 14:26:23'),
(4537, 'App\\Models\\IndonesiaDestination', 20, 3, 'TRANSFER OUT', '<p style=\"text-align:justify;\">After breakfast at hotel, check out procedure. Transfer to airport to leave Jogja.</p>', NULL, 'Breakfast', '2026-05-29 14:26:23', '2026-05-29 14:26:23'),
(4548, 'App\\Models\\IndonesiaDestination', 14, 1, 'Arrival Makassar – City Tour', '<p style=\"text-align:justify;\">Upon arrival at <strong>Sultan Hasanuddin International Airport</strong> Makassar, meeting services.&nbsp;</p><p style=\"text-align:justify;\">Afterwards, we continue for a short city tour in Makassar by visiting <strong>Paotere Harbour</strong> to see the traditional harbour of Bugis-Makassarese sailors.&nbsp;</p><p style=\"text-align:justify;\">Then, proceed to <strong>Fort Rotterdam</strong>, the Old Dutch Fortress. In the late afternoon we will visit <strong>“Anjungan Pantai Losari Makassar”</strong> the Boulevard and the icon of Makassar where you enjoy the Sunset (if the weather allows). Overnight at hotel.</p>', NULL, 'No Meal', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4549, 'App\\Models\\IndonesiaDestination', 14, 2, 'Makassar  (Rammang-Rammang Tour)', '<p style=\"text-align:justify;\">Today, full day tour will be started by visiting <strong>Rammang-rammang the limestone valley</strong>, located in <strong>Maros Regency</strong>, taking for approximately 90 minutes\' drive from downtown.&nbsp;</p><p style=\"text-align:justify;\">The <strong>karst mountains</strong> are surrounded by beautiful <strong>rice fields</strong> (the rice fields look nicer from May till August). Afterwards, we will take you to explore the karst mountain formation using small wooden boat at the Pute River. If you are lucky, you could also see the real endemic from the forest such as birds and monkeys.&nbsp;</p><p style=\"text-align:justify;\">We will also take you for a walk to visit the pre-historic cave, where you can see the pre-historic paintings, then short explore inside the cave to see the stalactite and stalagmite.</p><p style=\"text-align:justify;\">Break and lunch will be taken at the <strong>Kampung Berua</strong>, afternoon we will have a little walk at <strong>the Stone Garden of Rammang-Rammang</strong>. Then, drive back to Makassar. Overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4550, 'App\\Models\\IndonesiaDestination', 14, 3, 'Makassar – Pare-Pare - Toraja', '<p style=\"text-align:justify;\">After breakfast, set out on a picturesque drive to Toraja for approximately 8 hours\' drive, passing thru the Buginese area.&nbsp;</p><p style=\"text-align:justify;\">Stopover in <strong>Pare-Pare</strong>, the harbour city between Makassar and Toraja. continue driving to Toraja precedes a scenic drive with many photo-stops enroute.</p><p style=\"text-align:justify;\">Afternoon stop at <strong>Puncak Lakawan</strong> which is also known as erotic mountain. In the late afternoon arrive at <strong>Rantepao</strong>, Toraja. overnight at the hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4551, 'App\\Models\\IndonesiaDestination', 14, 4, 'Toraja tour  (Lemo, Kambira, Londa, Kete Kesu)', '<p style=\"text-align:justify;\">After breakfast, a full day tour exploring Toraja. First, we will visit <strong>Lemo</strong> to see rows of <strong>tau-tau statues and the hanging graves</strong>.&nbsp;</p><p style=\"text-align:justify;\">Onwards to <strong>Kambira</strong> to discover the secret of the baby tree. visiting <strong>Londa</strong>, to see an ancient grave where the deceased are entombed.&nbsp;</p><p style=\"text-align:justify;\">At <strong>Kete Kesu</strong> one of the oldest torajan villages, we can see tongkonan and old rice barns, also famous for its traditional colourful woodcarving. overnight at hotel.&nbsp;</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4552, 'App\\Models\\IndonesiaDestination', 14, 5, 'Toraja tour (Batutumonga – short walking - Bori)', '<p style=\"text-align:justify;\">After breakfast, we set out on a trip to <strong>Batutumonga</strong>, enjoying superb views over <strong>Rantepao</strong> and surrounding valleys from the top of Toraja.&nbsp;</p><p style=\"text-align:justify;\">Then we will do a short walking for approximately 2 hours passing thru the rice field, local village where you can also see the daily life of the people in Toraja.&nbsp;</p><p style=\"text-align:justify;\">Next, we will continue to visit <strong>Bori the Megalith area</strong>. This area symbolizes the great funeral ceremonies, which is held in the past. overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4553, 'App\\Models\\IndonesiaDestination', 14, 6, 'Toraja – Palopo - Sengkang', '<p style=\"text-align:justify;\">After breakfast, depart to <strong>Sengkang</strong> via Palopo. On the road to <strong>Palopo</strong>, we could see beautiful panorama of the rain forest. Palopo is a small Muslim port known as the oldest harbour in Indonesia. You could also find the oldest mosque in Indonesia here.&nbsp;</p><p style=\"text-align:justify;\">Then, continue driving to <strong>Sengkang</strong>. In the afternoon we will cross <strong>Lake Tempe</strong> to visit the <strong>Floating Village</strong> (Note: Tempe Lake might be shallow in dry season due to lack of rainfall. If the lake is too shallow, we will not be able to cross the lake). overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4554, 'App\\Models\\IndonesiaDestination', 14, 7, 'Sengkang - Bira', '<p style=\"text-align:justify;\">After breakfast, drive to <strong>Bira</strong> for approximately 6 hours. We will stop at Traditional <strong>Bugis Silk Weaving Centre</strong>.&nbsp;</p><p style=\"text-align:justify;\">Then, continue driving to <strong>Bira via Watampone</strong>, where we will visit <strong>Museum of Andi Mappasisi</strong> &nbsp;to see the collections of the former Bugis Royalties and from one of their most famous Kings “Arung Palakka”.</p><p style=\"text-align:justify;\">In the afternoon arrive at Bira. Free program.&nbsp; overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4555, 'App\\Models\\IndonesiaDestination', 14, 8, 'Bira explore  (Tana beru, Kajang village)', '<p style=\"text-align:justify;\">After breakfast, free for your own leisure at beautiful white sandy beach of <strong>Bira</strong>. In the afternoon drive to <strong>Tana &nbsp;Beru</strong> to see the famous Bugis-Makassar Phinisi Boat Builders.&nbsp;</p><p style=\"text-align:justify;\">We will also visit the forest area of “Kajang Tribe”, the sub-ethnic to Makassar ethnic groups, who inhabited a particular area in the forest. If you would like to enter the village and meet the leader of the tribe called “Ammatoa”, you have to wear the black outfit or rent the traditional clothes at the outside of the village with the <strong>bare foot</strong> to enter the village and pay directly some donation for the leader and locals (depending to the negotiation on the spot).&nbsp;</p><p style=\"text-align:justify;\">In the afternoon, free program. overnight at hotel.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4556, 'App\\Models\\IndonesiaDestination', 14, 9, 'Bira – Makassar Airport', '<p style=\"text-align:justify;\">After breakfast, drive back to Makassar for approximately 6 hours. While passing <strong>Jeneponto Regency</strong>, you could see the salt farm along the way.&nbsp; If we do have time short stop at <strong>Balla Lompoa Museum</strong>, which is the traditional house Gowa Kingdom during colonial time, where you can see some collections from one of the most famous King of Gowa “Sultan Hasanuddin”.</p><p style=\"text-align:justify;\">Then, transfer directly to the <strong>Sultan Hasanuddin International Airport</strong> to catch your flight to the next destination.</p>', NULL, 'Breakfast', '2026-05-29 14:28:30', '2026-05-29 14:28:30'),
(4579, 'App\\Models\\IndonesiaDestination', 19, 1, 'Arrival - Luwuk – Banggai Kepulauan', '<p style=\"text-align:justify;\">Setibanya di Bandara Syukuran Aminuddin Amir Luwuk, peserta tour akan disambut dan langsung diantar menuju restoran lokal untuk makan siang.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan mengunjungi <strong>Air Terjun Piala</strong> – air terjun unik dengan formasi bertingkat menyerupai tangga alami &amp; dikelilingi dengan pepohonan hijau yang asri serta aliran air jernih yang menyegarkan.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, menuju ke dermaga untuk penyeberangan ke <strong>Banggai Kepulauan</strong> menggunakan kapal ferry. Tiba di Banggai Kepulauan, makan malam di restoran lokal lalu menuju penginapan untuk beristirahat.</p><p><strong>Bermalam di Banggai Kepulauan</strong></p>', NULL, 'Lunch/Dinner', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4580, 'App\\Models\\IndonesiaDestination', 19, 2, 'Banggai Kepulauan (Paisupok – Paisu Batango – Kawalu Bay – Ndulubas)', '<p style=\"text-align:justify;\">Setelah sarapan pagi, peserta tour dijemput untuk memulai tour di Banggai Kepulauan dengan mengunjungi <strong>Danau Paisupok</strong> – danau alami berair biru kehijauan dengan dasar yang terlihat jelas.&nbsp;</p><p style=\"text-align:justify;\">Selanjutnya menuju Paisu Batango untuk makan siang (lunch box) sambil menikmati suasana alam di tepian laut dengan kolam alami jernih berwarna biru kehijauan yang tenang serta suasana yang sejuk.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan ke <strong>Kawalu Bay</strong> dan <strong>Ndulubas</strong> untuk menikmati keindahan bawah laut dengan aktivitas snorkeling <i>(sudah termasuk alat snorkeling)</i>. Makan malam disediakan di restoran lokal.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan malam, kembali ke penginapan untuk beristirahat.</p><p style=\"text-align:justify;\"><strong>Bermalam di Banggai Kepulauan</strong></p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4581, 'App\\Models\\IndonesiaDestination', 19, 3, 'Banggai Laut (Tanjung Gundul – Pantai Pasir Panjang – Pantai Oyama – Pantai Bontolan)', '<p style=\"text-align:justify;\">Setelah sarapan pagi, peserta tour memulai perjalanan ke <strong>Banggai Laut </strong>menggunakan speedboat; perjalanan diawali ke <strong>Tanjung Gundul</strong> yang menawarkan panorama laut indah dengan tebing unik berlubang alami, cocok sebagai spot foto dan tempat bersantai menikmati suasana pantai yang tenang.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan selanjutnya menuju <strong>Pantai</strong> <strong>Pasir Panjang </strong>yang dikenal dengan hamparan pasir putihnya yang luas dan indah. Selanjutnya, peserta tour diajak mengunjungi <strong>Pantai</strong> <strong>Oyama </strong>yang menawarkan kejernihan air laut serta suasana yang tenang cocok untuk bersantai dan menikmati keindahan alam.&nbsp;</p><p style=\"text-align:justify;\">Kemudian menuju ke <strong>Pantai Bontolan </strong><i>(makan siang – lunch box)</i>, dimana peserta tour dapat mengeksplorasi pesona bawah laut yang memukau dengan melihat ikan endemik yaitu <strong>Cardinal Fish </strong><i>(sudah termasuk alat snorkeling)</i>. Menjelang sore hari, kembali ke Banggai Kepulauan, makan malam di restoran lokal, lalu menuju penginapan untuk beristirahat.</p><p><strong>Bermalam di Banggai Kepulauan</strong></p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4582, 'App\\Models\\IndonesiaDestination', 19, 4, 'Banggai Kepulauan (Pantai Mandel – Pantai Pompon – Pulau Bobilon) – Luwuk', '<p style=\"text-align:justify;\">Setelah sarapan pagi &amp; check out dari penginapan, peserta tour dijemput dan diantar perjalanan menuju <strong>Pantai</strong> <strong>Mandel </strong>untuk menikmati keindahan alam serta suasana pantai yang tenang dan menyegarkan.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan kemudian dilanjutkan ke <strong>Pantai</strong> <strong>Pompon </strong>yang menawarkan pesona pantai yang masih alami dan cocok untuk bersantai sambil menikmati panorama laut. Dari Pantai Pompon, peserta tour dapat menyeberang ke <strong>Pulau</strong> <strong>Bobilon </strong>menggunakan boat kecil dan melakukan aktivitas snorkeling <i>(sudah termasuk alat snorkeling)</i>.&nbsp;</p><p style=\"text-align:justify;\">Pelayanan makan siang disediakan di lokal restoran. Menjelang sore hari, kembali ke Luwuk menggunakan kapal ferry. Setibanya di Luwuk, menuju restoran lokal untuk makan malam, dan setelah makan malam diantar ke hotel untuk proses check-in dan beristirahat.</p><p><strong>Bermalam di Luwuk</strong></p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4583, 'App\\Models\\IndonesiaDestination', 19, 5, 'Explore Luwuk (Pulau Dua – Air Terjun Kamumu – Bukit Keles)', '<p style=\"text-align:justify;\">Setelah sarapan pagi, peserta tour dijemput untuk tour menuju ke <strong>Pulau Dua</strong> untuk menikmati keindahan pulau eksotis dengan hamparan pasir putih &amp; air laut jernih berwarna biru kehijauan. Di lokasi ini, peserta dapat bersantai di pantai, berenang, snorkeling <i>(peralatan snorkeling optional)</i>, hingga berburu spot foto terbaik dari area perbukitan yang ikonik <i>(mengguakan perahu sampan untuk ke lokasi jalan menuju perbukitan)</i>. Jika beruntung, peserta juga dapat menyaksikan lumba-lumba yang melintas di perairan sekitar pulau.</p><p style=\"text-align:justify;\">Makan siang akan disajikan dalam bentuk <i>lunch box</i> untuk dinikmati dalam perjalanan atau di area Pulau Dua. Kemudian menuju ke <strong>Air Terjun Kamumu</strong> – air terjun bertingkat yang mengalir di antara bebatuan alami, dikelilingi hutan hijau yang masih asri, serta menghadirkan suasana sejuk dan tenang yang cocok untuk bersantai, bermain air, dan menikmati keindahan alam. &nbsp;</p><p style=\"text-align:justify;\">Sore hari menuju ke <strong>Bukit Keles</strong> – bukit yang dikenal indah saat menjelang malam ketika lampu-lampu kota Luwuk mulai menyala, menciptakan pemandangan <i><strong>city light</strong></i> yang memukau dari ketinggian (disediakan pisang goreng &amp; kopi/teh). Pelayanan makan malam disediakan di restoran lokal. Setelah makan malam, peserta tour diantar menuju hotel untuk proses check in &amp; beristirahat.</p><p><strong>Bermalam di Luwuk</strong></p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4584, 'App\\Models\\IndonesiaDestination', 19, 6, 'Luwuk- Transfer Out', '<p style=\"text-align:justify;\">Setelah <strong>sarapan pagi &amp; proses check-out</strong> hotel, peserta tour diantar ke Bandara untuk penerbangan kembali. Tour selesai.</p>', NULL, 'Breakfast', '2026-05-29 14:32:58', '2026-05-29 14:32:58'),
(4590, 'App\\Models\\IndonesiaDestination', 17, 1, 'Arrival - Luwuk – Banggai Kepulauan', '<p style=\"text-align:justify;\">Setibanya di Bandara Syukuran Aminuddin Amir Luwuk, peserta tour akan disambut dan langsung diantar menuju restoran lokal untuk makan siang.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dilanjutkan mengunjungi <strong>Air Terjun Piala</strong> – air terjun unik dengan formasi bertingkat menyerupai tangga alami &amp; dikelilingi dengan pepohonan hijau yang asri serta aliran air jernih yang menyegarkan.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, menuju ke dermaga untuk penyeberangan ke <strong>Banggai Kepulauan</strong> menggunakan kapal ferry. Tiba di Banggai Kepulauan, makan malam di restoran lokal lalu menuju penginapan untuk beristirahat.</p><p><strong>Bermalam di Banggai Kepulauan</strong></p>', NULL, 'Lunch / Dinner', '2026-05-29 14:34:20', '2026-05-29 14:34:20'),
