(4631, 'App\\Models\\IndonesiaDestination', 51, 3, 'LEEBONG ISLAND', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan diantar menuju Dermaga Tanjung Ru untuk menyeberang ke <strong>Pulau Leebong</strong> menggunakan kapal tradisional, di mana Anda akan melewati kawasan <i>mangrove</i> dan <strong>Pulau Pasir</strong> (tergantung kondisi cuaca).&nbsp;</p><p style=\"text-align:justify;\">Di Pulau Leebong, Anda bebas menikmati berbagai aktivitas seperti bersepeda, tenis meja, <i>kayaking</i>, <i>stand paddling</i>, voli pantai, hingga karaoke.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang di restoran pulau dan bersantai di <strong>Chicas Beach</strong>, kita akan kembali ke Tanjung Pandan pada sore hari untuk makan malam dan beristirahat di hotel.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:46:19', '2026-05-29 14:46:19'),
(4632, 'App\\Models\\IndonesiaDestination', 51, 4, 'ISLAND HOPPING', '<p style=\"text-align:justify;\">Agenda hari keempat adalah menjelajahi pulau-pulau ikonik Belitung dimulai dari <strong>Pantai Tanjung Kelayang</strong>. Anda akan mengunjungi <strong>Garuda Head’s Rock</strong>, <strong>Pulau Pasir</strong>, <strong>Pulau Batu Berlayar</strong>, dan <strong>Pulau Lengkuas</strong> untuk aktivitas <i>snorkeling</i>.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang, petualangan berlanjut ke <strong>Pulau Kelayang Besar</strong> untuk melihat <strong>Goa Kelayang</strong>.&nbsp;</p><p style=\"text-align:justify;\">Kembali ke daratan, Anda akan mengunjungi <strong>Pantai Tanjung Tinggi (Laskar Pelangi)</strong> dan berbelanja di pusat oleh-oleh khas Belitung, disusul makan malam sebelum kembali ke hotel.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:46:19', '2026-05-29 14:46:19'),
(4633, 'App\\Models\\IndonesiaDestination', 51, 5, 'CITY TOUR – KULINER (BELITUNG NOODLES)', '<p style=\"text-align:justify;\">Setelah sarapan dan <i>check-out</i>, Anda akan diajak mengunjungi <strong>Pantai Tanjung Pendam</strong>, menikmati sajian tradisional <strong>Mie Belitung</strong> dan <strong>Es Jeruk Konci</strong>, serta mengunjungi <strong>Rumah Adat Belitung</strong> dan <strong>Danau Kaolin</strong> sebelum langsung diantar menuju Bandara untuk penerbangan pulang. Tour selesai.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 14:46:19', '2026-05-29 14:46:19'),
(4634, 'App\\Models\\IndonesiaDestination', 50, 1, 'EAST BELITUNG', '<p style=\"text-align:justify;\">Setibanya di Bandara Tanjung Pandan, tim kami akan menjemput Anda dengan <i>welcome snack</i> sebelum melanjutkan perjalanan menuju Belitung Timur.&nbsp;</p><p style=\"text-align:justify;\">Anda akan mengunjungi <strong>Replika SD Laskar Pelangi</strong>, melakukan sesi foto di <strong>Museum Kata Andrea Hirata</strong>, serta mengeksplorasi <strong>Kampoeng Fifi</strong> dan <strong>Galeri Batik Daun Simpor</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, Anda akan diajak menikmati pemandangan indah dari <strong>Bukit Samak</strong>.&nbsp;</p><p style=\"text-align:justify;\">Sore harinya, kita akan menuju hotel untuk proses <i>check-in</i> setelah menyantap makan malam di restoran lokal.</p>', NULL, 'Lunch/Dinner', '2026-05-29 14:47:12', '2026-05-29 14:47:12'),
(4635, 'App\\Models\\IndonesiaDestination', 50, 2, 'SOUTH BELITUNG', '<p style=\"text-align:justify;\">Setelah sarapan di hotel, perjalanan dilanjutkan menuju wilayah Belitung Selatan untuk melihat batu granit raksasa <strong>Batu Baginde</strong>.&nbsp;</p><p style=\"text-align:justify;\">Anda akan diajak bersantai di <strong>Pantai Penyabong</strong> dan <strong>Pantai Teluk Gembira</strong> setelah menikmati makan siang khas lokal.&nbsp;</p><p style=\"text-align:justify;\">Rangkaian hari kedua ditutup dengan makan malam di restoran lokal dan kembali ke hotel untuk beristirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:12', '2026-05-29 14:47:12'),
(4636, 'App\\Models\\IndonesiaDestination', 50, 3, '- PERAMUN HILL -', '<p style=\"text-align:justify;\">Agenda hari ini berfokus pada wisata alam dengan mengikuti <strong>Peramun Hill Trekking Package</strong> yang dimulai dari pukul 09.00 pagi. Anda akan melakukan aktivitas <i>trekking</i>, berfoto di <strong>Twin Rock</strong> dan <strong>Ampar Rock</strong>, serta menikmati pemandangan dari puncak bukit.&nbsp;</p><p style=\"text-align:justify;\">Setelah <i>check-out</i> dari lokasi bukit, perjalanan berlanjut mengunjungi <strong>Desa Bali</strong>, makan siang, lalu kembali ke kota untuk menikmati suasana di <strong>Pantai Tanjung Pendam</strong>.&nbsp;</p><p style=\"text-align:justify;\">Hari berakhir dengan makan malam dan waktu bebas di hotel.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:12', '2026-05-29 14:47:12'),
(4637, 'App\\Models\\IndonesiaDestination', 50, 4, 'ISLAND HOPPING', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan bersiap untuk <i>island hopping</i> dari <strong>Pantai Tanjung Kelayang</strong>.&nbsp;</p><p style=\"text-align:justify;\">Destinasi yang dikunjungi mencakup <strong>Garuda Head’s Rock</strong>, <strong>Pulau Pasir</strong>, <strong>Pulau Batu Berlayar</strong>, serta <strong>Pulau Lengkuas</strong> untuk kegiatan <i>snorkeling</i>.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan diteruskan ke <strong>Pulau Kelayang Besar</strong> dan <strong>Goa Kelayang</strong>. Sore harinya, Anda dapat menikmati <strong>Pantai Tanjung Tinggi (Laskar Pelangi)</strong> dan berbelanja di pusat oleh-oleh sebelum makan malam.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:12', '2026-05-29 14:47:12'),
(4638, 'App\\Models\\IndonesiaDestination', 50, 5, 'CITY TOUR – KULINER (BELITUNG NOODLES)', '<p style=\"text-align:justify;\">Setelah sarapan dan <i>check-out</i>, Anda akan diajak mencicipi hidangan tradisional <strong>Mie Belitung</strong> dan <strong>Es Jeruk Konci</strong>, mengunjungi <strong>Rumah Adat Belitung</strong>, serta <strong>Danau Kaolin</strong> sebelum langsung diantar menuju Bandara. Tour selesai.</p>', NULL, 'Breakfast/Lunch', '2026-05-29 14:47:12', '2026-05-29 14:47:12'),
(4639, 'App\\Models\\IndonesiaDestination', 49, 1, 'EAST BELITUNG', '<p style=\"text-align:justify;\">Setibanya Anda di Bandara Tanjung Pandan, tim kami akan menyambut dengan <i>welcome snack</i> dan langsung mengantar Anda menuju wilayah Belitung Timur.&nbsp;</p><p style=\"text-align:justify;\">Perjalanan dimulai dengan mengunjungi <strong>Replika SD Laskar Pelangi</strong>, melakukan sesi foto di <strong>Museum Kata Andrea Hirata</strong>, serta mengeksplorasi <strong>Kampoeng Fifi</strong> (dahulu dikenal sebagai Kampoeng Ahok) dan <strong>Galeri Batik Daun Simpor</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah menikmati makan siang di restoran lokal, Anda akan diajak menikmati pemandangan dari <strong>Bukit Samak</strong> sebelum ditutup dengan makan malam dan proses <i>check-in</i> hotel.</p>', NULL, 'Lunch/Dinner', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4640, 'App\\Models\\IndonesiaDestination', 49, 2, 'SOUTH BELITUNG', '<p style=\"text-align:justify;\">Setelah sarapan di hotel, perjalanan dilanjutkan menuju Belitung Selatan untuk melihat kemegahan batu granit raksasa <strong>Batu Baginde</strong>.&nbsp;</p><p style=\"text-align:justify;\">Anda akan diajak menikmati suasana pantai di <strong>Pantai Penyabong</strong> dan <strong>Pantai Teluk Gembira</strong> setelah menyantap makan siang khas lokal.&nbsp;</p><p style=\"text-align:justify;\">Rangkaian hari kedua berakhir dengan makan malam di restoran lokal sebelum kembali ke hotel untuk beristirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4641, 'App\\Models\\IndonesiaDestination', 49, 3, 'LEEBONG ISLAND', '<p style=\"text-align:justify;\">Agenda hari ini adalah mengunjungi <strong>Pulau Leebong</strong> yang eksotis dengan menyeberang menggunakan kapal tradisional dari Dermaga Tanjung Ru.&nbsp;</p><p style=\"text-align:justify;\">Dalam perjalanan, Anda akan melewati kawasan <i>mangrove</i> dan <strong>Pulau Pasir</strong> yang dipenuhi bintang laut jika cuaca memungkinkan. Di pulau ini, Anda bebas beraktivitas seperti bersepeda, bermain voli pantai, <i>kayaking</i>, hingga karaoke, diikuti makan siang di restoran pulau dan bersantai di <strong>Chicas Beach</strong>.&nbsp;</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4642, 'App\\Models\\IndonesiaDestination', 49, 4, '- PERAMUN HILL -', '<p style=\"text-align:justify;\">Hari keempat dimulai dengan <strong>Peramun Hill Trekking Package</strong>, di mana Anda akan melakukan aktivitas <i>trekking</i> menuju puncak untuk menikmati pemandangan indah serta berfoto di <strong>Twin Rock</strong> dan <strong>Ampar Rock</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, perjalanan dilanjutkan mengunjungi <strong>Desa Bali</strong>, menikmati suasana di <strong>Pantai Tanjung Pendam</strong>, dan menyantap makan malam di restoran lokal sebelum kembali ke hotel.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4643, 'App\\Models\\IndonesiaDestination', 49, 5, 'ISLAND HOPPING', '<p style=\"text-align:justify;\">Persiapkan diri Anda untuk menjelajahi pulau-pulau ikonik Belitung dimulai dari <strong>Pantai Tanjung Kelayang</strong>. Destinasi yang dikunjungi mencakup <strong>Garuda Head’s Rock</strong>, <strong>Pulau Pasir</strong>, <strong>Pulau Batu Berlayar</strong>, serta aktivitas <i>snorkeling</i> di <strong>Pulau Lengkuas</strong>.&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang, petualangan diteruskan ke <strong>Pulau Kelayang Besar</strong> dan <strong>Goa Kelayang</strong>, lalu ditutup dengan kunjungan ke <strong>Pantai Tanjung Tinggi</strong> dan berbelanja oleh-oleh.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4644, 'App\\Models\\IndonesiaDestination', 49, 6, 'CITY TOUR – KULINER (BELITUNG NOODLES)', '<p style=\"text-align:justify;\">Setelah sarapan dan <i>check-out</i>, Anda akan diajak mengunjungi <strong>Pantai Tanjung Pendam</strong>, menikmati sajian tradisional <strong>Mie Belitung</strong> dan <strong>Es Jeruk Konci</strong>, serta mengunjungi <strong>Rumah Adat Belitung</strong> dan <strong>Danau Kaolin</strong> sebelum langsung diantar menuju Bandara. Tour selesai!</p>', NULL, 'Breakfast/Lunch', '2026-05-29 14:47:55', '2026-05-29 14:47:55'),
(4645, 'App\\Models\\IndonesiaDestination', 46, 1, 'ARRIVAL - SUMBA BARAT', '<p style=\"text-align:justify;\">Tibanya di <i><strong>Bandara Tambolaka, </strong></i>Anda akan disambut oleh guide kami. Setelah itu, Anda akan menuju resto lokal untuk makan siang.&nbsp;&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang, Anda akan menuju <i><strong>Rumah Budaya. </strong></i>Di rumah budaya ini, Anda akan diperkenalkan sejarah Sumba.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan menuju <i><strong>Bukit Lendongara. </strong></i>Dibukit ini anda akan disuguhi pemandangan perbukitan yang ditumbuhi rerumputan bak layaknya seperti dalam film teletubis.&nbsp;</p><p style=\"text-align:justify;\">Dan dilanjutkan, ke <i><strong>Pantai Mananga Aba atau Pantai Kita.</strong></i> Di pantai ini, Anda akan disuguhi bentangan pasir putih meluas dan suasana pantai yang sunyi dan tenang.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, check in hotel untuk istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 14:48:41', '2026-05-29 14:48:41'),
(4646, 'App\\Models\\IndonesiaDestination', 46, 2, 'SUMBA BARAT', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan diajak untuk full day tour dimulai dari <i><strong>rumah adat ratenggaro</strong></i>. Dan dilanjutkan menuju <i><strong>Danau Waekuri.</strong></i> Danau Waekuri merupakan salah satu landmark dari Sumba, danau yang sangat luas dan airnya adalah air payau.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, kembali ke hotel untuk istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:48:41', '2026-05-29 14:48:41'),
(4647, 'App\\Models\\IndonesiaDestination', 46, 3, 'SUMBA BARAT', '<p style=\"text-align:justify;\">Setelah sarapan, anda akan diajak full day tour dimulai dari <i><strong>Waikelo Sawah. </strong></i>Waikelo Sawah ini merupakan sumber mata air yang tidak pernah kering di Sumba. Waikelo Sawah ini dirancang untuk tujuan irigasi dan pembangkit listrik tenaga air. Waikelo Sawah ini berbentuk gua alami selebar 4 Meter dengan ketinggian 3 Meter yang dimulut guanya membentuk sebuah kolam dengan air yang sangat jernih.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, anda akan menuju <i><strong>Pantai Marosi</strong></i>. Pantai Marosi ini memiliki keunikan sendiri yaitu memiliki batu karang besar yang menjorok ke laut ditambah dengan bebatuan yang seakan tersangkut di tengah pasir yang membuat pantai ini memiliki&nbsp; ciri khas sendiri.&nbsp;</p><p style=\"text-align:justify;\">Berikut anda akan menuju <i><strong>Pantai Kerewei. </strong></i>Disini anda akan bersantai dan melihat indahnya pantai ini.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, kembali ke hotel untuk istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:48:41', '2026-05-29 14:48:41'),
(4648, 'App\\Models\\IndonesiaDestination', 46, 4, 'SUMBA BARAT - SUMBA TIMUR', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan check out dari Sumba Barat dan Anda akan menuju <i><strong>Kampung Praijing.</strong></i> Kampung Praijing ini merupakan kampung adat yang paling terkenal di Sumba Barat. Di Kampung ini terdapat 38 rumah tradisional khas Sumba.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan menuju <i><strong>Air Terjun Lapopu.</strong></i> Air Tejun Lapopu ini merupakan air terjun tertinggi di NTT. Dan dilanjutkan menuju <i><strong>Bukit Wairinding.</strong></i> &nbsp;Bukit Wairinding ini merupakan salah satu tempat terbaik untuk menikmati Sumba&nbsp;&nbsp; Timur dari ketinggian. Hamparan padang savana yang terhampar luas berwarna kuning saat musim kemarau dan berwarna hijau pada saat musin hujan.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, check in hotel untuk istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:48:41', '2026-05-29 14:48:41'),
(4649, 'App\\Models\\IndonesiaDestination', 46, 5, 'SUMBA TIMUR', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan diajak full day tour dimulai dari <i><strong>Bukit Tanarara</strong></i>. Tanarara adalah perbukitan berselimut rumput dan disatu titik di puncak Bukit Tanarara ada kubur batu yang diberi ukiran khas Sumba.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, mengunjungi <i><strong>Air Terjun Waimarang.</strong></i> Air Terjun Waimarang ini memiliki ketinggian sekitar 2 Meter dan dibagian bawahnya ada sebuah kolam yang dikelilingi tebing, seperti kolam renang.&nbsp;</p><p style=\"text-align:justify;\">Dan setelah itu, Anda akan diajak untuk mengunjungi <i><strong>pusat toko oleh-oleh khas Sumba</strong></i> dilanjutkan menuju <i><strong>Pantai Walakiri.</strong></i> Di pantai ini anda akan disuguhi deretan pohon kelapa dipinggirnya, dengan hamparan pasir putih yang luas dan lautnya yang biru dan di sebelah baratnya terdapat pohon bakau yang tersusun rapi yang dapat dijadikan spot foto terbaik.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, kembali ke hotel untuk istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:48:41', '2026-05-29 14:48:41'),
(4650, 'App\\Models\\IndonesiaDestination', 46, 6, 'TRANSFER OUT', '<p style=\"text-align:justify;\">Setelah sarapan, Anda akan check out<i><strong>.</strong></i> Dan setelah itu, anda akan diantar menuju bandara dan trip selesai.</p>', NULL, 'Breakfast', '2026-05-29 14:48:42', '2026-05-29 14:48:42'),
(4651, 'App\\Models\\IndonesiaDestination', 45, 1, 'ARRIVAL - SUMBA BARAT', '<p style=\"text-align:justify;\">Tibanya di <i><strong>Bandara Tambolaka, </strong></i>Anda akan disambut oleh guide kami. Setelah itu, Anda akan menuju resto lokal untuk makan siang.&nbsp;&nbsp;</p><p style=\"text-align:justify;\">Setelah makan siang, Anda akan menuju <i><strong>Rumah Budaya. </strong></i>Di rumah budaya ini, Anda akan diperkenalkan sejarah Sumba.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan menuju <i><strong>Bukit Lendongara. </strong></i>Dibukit ini anda akan disuguhi pemandangan perbukitan yang ditumbuhi rerumputan bak layaknya seperti dalam film teletubis.&nbsp;</p><p style=\"text-align:justify;\">Dan dilanjutkan, ke <i><strong>Pantai Mananga Aba atau Pantai Kita.</strong></i> Di pantai ini, Anda akan disuguhi bentangan pasir putih meluas dan suasana pantai yang sunyi dan tenang.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, Anda akan makan malam di resto lokal. Setelah makan malam, check in hotel untuk istirahat.</p>', NULL, 'Lunch/Dinner', '2026-05-29 14:50:06', '2026-05-29 14:50:06'),
(4652, 'App\\Models\\IndonesiaDestination', 45, 2, 'SUMBA BARAT', '<p style=\"text-align:justify;\">Pagi ini setelah sarapan pagi di hotel kita akan menuju <i><strong>Rumah Adat Ratenggaro</strong></i>,rumah adat dengan menara2 yang sangat tinggi dengan view pemandangan laut dan selanjutnya menuju <i><strong>Pantai Pero.&nbsp;</strong></i></p><p style=\"text-align:justify;\">Makan siang di resto local, setelah makan siang tour dilanjutkan menuju <i><strong>Danau Waekuri.</strong></i> Danau Waekuri merupakan salah satu landmark dari Sumba, danau yang sangat luas dan airnya adalah air payau.&nbsp;</p><p style=\"text-align:justify;\">Setelah itu, menuju pantai mandorak. Setelah menimati pantai Anda akan makan malam di resto lokal. Setelah makan malam, kembali ke hotel untuk istirahat.</p>', NULL, 'Breakfast/Lunch/Dinner', '2026-05-29 14:50:06', '2026-05-29 14:50:06'),
