INSERT INTO `transportations` (`id`, `name`, `type`, `price`, `available`, `image_url`, `images`, `description`, `description_en`, `description_ko`, `description_zh`, `created_at`, `updated_at`) VALUES
(5, 'Toyota Avanza', 'Mini MVP', 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/O0ysA4DZ2ZXm0Ml0u7YOVwPSy7cDfV0ZevV23cmc.jpg', NULL, 'Toyota Avanza dikenal sebagai “mobil sejuta umat” yang telah menjadi andalan keluarga Indonesia—praktis, tangguh, dan selalu siap menemani setiap perjalanan Anda.', 'Toyota Avanza is widely known as the “car for everyone,” a trusted choice for Indonesian families—practical, durable, and always ready to accompany every journey.', 'Toyota Avanza는 “모두를 위한 자동차”로 잘 알려져 있으며, 인도네시아 가족들에게 오랫동안 사랑받아온 실용적이고 내구성 있는 차량입니다.', 'Toyota Avanza 被誉为“国民之车”，是深受印尼家庭信赖的选择——实用、耐用，并随时陪伴每一段旅程。', '2026-04-22 01:41:32', '2026-04-27 03:04:43'),
(6, 'Toyota Innova Reborn', 'Mini MVP', 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/paLQNHZ1tEoZHQ6ZsjnAOelVzc8WWz2OeuCyPNc3.png', NULL, 'Toyota Innova Reborn adalah simbol kenyamanan dan ketangguhan yang telah dipercaya oleh jutaan keluarga Indonesia—sebuah MPV legendaris yang terus berevolusi mengikuti kebutuhan zaman.', 'Toyota Innova Reborn is a symbol of comfort and reliability that has been trusted by millions of Indonesian families—a legendary MPV that continues to evolve with the times.', 'Toyota Innova Reborn은 수많은 인도네시아 가족들에게 신뢰받아 온 편안함과 내구성의 상징으로, 시대에 맞춰 끊임없이 진화하는 전설적인 MPV입니다.', 'Toyota Innova Reborn 是舒适与可靠性的象征，深受数百万印尼家庭的信赖，是一款不断与时代同步进化的经典MPV。', '2026-04-22 01:42:38', '2026-04-27 07:15:36'),
(7, 'Toyota Innova Zenix', NULL, 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/gzA7mD4myvjla0Lu0U6NPxAg8nbEH8xKUK9QKNiA.jpg', '[\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/gzA7mD4myvjla0Lu0U6NPxAg8nbEH8xKUK9QKNiA.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/jr4jNKl3PT07iN8J9zofSVp96DrXi0RD4XNRmkHK.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/H403yKl9txr9C4ol9TpDYigPqf7Fum7e0ywhJSO0.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/cHPSa9XkH5BTVcTF5eMnqcl7FwNh2DY20tJ4Ra0w.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/eyiG1W51oMGoyim7YTwT3FzCa06qNcJ6F1LWUuMl.jpg\"]', 'Toyota Innova Zenix hadir sebagai MPV modern yang memadukan kemewahan, kenyamanan, dan teknologi dalam satu kendaraan elegan—pilihan tepat untuk keluarga, perjalanan bisnis, hingga layanan premium.', 'The Toyota Innova Zenix comes as a modern MPV that combines luxury, comfort, and technology in one elegant vehicle—making it the perfect choice for families, business trips, and premium services', 'Toyota Innova Zenix는 고급스러움, 편안함, 그리고 첨단 기술을 하나로 결합한 현대적인 MPV로, 가족 여행, 비즈니스 출장, 프리미엄 서비스에 모두 적합한 최고의 선택입니다', 'Toyota Innova Zenix 是一款融合豪华、舒适与先进科技于一体的现代MPV，是家庭出行、商务旅行以及高端服务的理想之选。', '2026-04-22 01:44:23', '2026-05-21 06:00:43'),
(8, 'Hiace Commuter', NULL, 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/l1mNPyOtRAT74TQLbZqP7w4CLkoj7LHlvDVefua4.jpg', NULL, 'Toyota Hiace adalah pilihan sempurna bagi Anda yang menginginkan perjalanan nyaman, aman, dan berkelas—baik untuk liburan keluarga, perjalanan bisnis, maupun tour rombongan. Dengan desain eksterior yang modern dan profesional, Toyota Hiace memberikan kesan eksklusif sejak pandangan pertama.', 'The Toyota Hiace is the perfect choice for those seeking a comfortable, safe, and premium travel experience—whether for family trips, business journeys, or group tours. With its modern and professional exterior design, it creates an exclusive impression from the very first glance.', 'Toyota Hiace는 가족 여행, 비즈니스 출장, 단체 투어 등 다양한 상황에서 편안하고 안전하며 품격 있는 이동을 원하는 분들에게 완벽한 선택입니다. 현대적이고 세련된 외관 디자인은 첫인상부터 고급스러운 분위기를 선사합니다.', 'Toyota Hiace 是追求舒适、安全与高品质出行体验的理想之选，无论是家庭旅行、商务出行还是团队旅游都非常适合。其现代且专业的外观设计，从第一眼便展现出高端与尊贵的气质。', '2026-04-22 01:44:48', '2026-04-27 02:35:12'),
(9, 'BUS 30/33 SEATER', NULL, 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/RaHMZ3XH9EwD7g7n6SNdba5yFbLI6P0IIfpbgmn4.jpg', '[\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/RaHMZ3XH9EwD7g7n6SNdba5yFbLI6P0IIfpbgmn4.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/TbffD4W9VLX3iiMbf650oMl25sWHJC4rgOzuiQnw.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/HOUCzZuzHvEmdXm9LYD2lgjKw1AWFvgJ3EFTXyxr.jpg\"]', 'Bus Pariwisata adalah pilihan ideal untuk perjalanan yang nyaman, aman, dan penuh kesan—baik untuk liburan keluarga besar, perjalanan perusahaan, study tour, maupun rombongan wisata. Dengan desain modern dan tampilan yang elegan, bus ini memberikan kesan profesional sekaligus meyakinkan sejak awal perjalanan dimulai.', 'Tourist Bus is the ideal choice for a comfortable, safe, and memorable journey—whether for large family vacations, corporate trips, study tours, or group travel. With its modern design and elegant appearance, it creates a professional and վստահ impression from the very beginning of the trip.', '**관광 버스 (Tourist Bus)**는 대가족 여행, 기업 출장, 수학여행, 단체 관광 등 다양한 상황에서 편안하고 안전하며 기억에 남는 이동을 위한 최고의 선택입니다. 현대적이고 세련된 디자인은 여행의 시작부터 전문적이고 신뢰감 있는 이미지를 제공합니다.', '旅游巴士（Tourist Bus）**是实现舒适、安全且难忘旅程的理想之选，无论是大家庭出游、企业活动、研学旅行还是团队旅游都非常适合。其现代且优雅的外观设计，从旅程开始就展现出专业与可靠的形象', '2026-04-22 01:45:11', '2026-05-29 08:47:51'),
(10, 'TOYOTA ALPHARD', 'MPV premium', 0, 1, 'https://api.welcomemanado.my.id/storage/transportations/KVJqrWYnQOVTwan8MhyzWChBoizsAoCwKfBqmor8.jpg', '[\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/KVJqrWYnQOVTwan8MhyzWChBoizsAoCwKfBqmor8.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/p31BwFiGNSEV6ZfH4KA2RSj61vEZWjMWJ2GX7Rtp.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/UsvK7xeZUNmWN8qZu634NGa3uHHQTo30r7yGn7V6.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/lx608st8ea7tvZ4ce1TerCSHOYcz7fwBNVvo4yBh.jpg\",\"https:\\/\\/api.welcomemanado.my.id\\/storage\\/transportations\\/2JpDgRH8NmdMNM6xjrXVyRg9ZADj5ubsNWqriysL.jpg\"]', 'Toyota Alphard adalah mobil MPV premium dari Toyota yang terkenal karena kenyamanan dan interior mewahnya. Mobil ini sering digunakan untuk keluarga besar, perjalanan bisnis, hingga kendaraan pejabat karena kabinnya sangat luas dan nyaman.', 'The Toyota Alphard is a premium MPV from Toyota, well known for its comfort and luxurious interior. This vehicle is often used by large families, for business trips, and even as an official car because of its spacious and comfortable cabin.', 'Toyota Alphard는 편안함과 고급스러운 실내로 유명한 토요타의 프리미엄 MPV입니다. 넓고 안락한 실내 공간 덕분에 대가족, 비즈니스 출장, 그리고 의전 차량으로 자주 사용됩니다.', 'Toyota Alphard 是丰田旗下的高端 MPV，以舒适性和豪华内饰而闻名。由于车内空间宽敞且乘坐舒适，这款车经常被大家庭、商务出行以及公务接待使用。', '2026-05-15 02:54:36', '2026-05-29 08:46:47');
