INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(3, 'culture', NULL, 'TARIAN MAENGKET', 'MAENGKET DANCE', '마엥켓 춤', '马恩凯特舞蹈', '<p style=\"text-align:justify;\">Tari Maengket berasal dari Minahasa, Sulawesi Utara, dan telah ada sejak ratusan tahun lalu. Pada awalnya, tarian ini dipentaskan sebagai ungkapan syukur setelah panen padi, di mana masyarakat berkumpul untuk merayakan hasil panen dan berterima kasih kepada Tuhan. Kata “Maengket” berasal dari “engket” yang berarti mengangkat, melambangkan semangat dan kebersamaan. Seiring waktu, Tari Maengket berkembang menjadi tarian tradisional yang ditampilkan dalam berbagai acara adat dan budaya.</p>', '<p style=\"text-align:justify;\">Maengket Dance is a traditional dance from Minahasa, North Sulawesi, dating back hundreds of years. Originally, it was performed as an expression of gratitude after the rice harvest, when communities gathered to celebrate and thank God. The word “Maengket” comes from “engket,” meaning “to lift,” symbolizing spirit and unity. Over time, the dance evolved into a cultural performance presented at various traditional and ceremonial events.</p>', '<p style=\"text-align:justify;\">마엥켓 춤(Maengket Dance)은 인도네시아 북술라웨시 미나하사 지역에서 유래한 전통 춤으로, 수백 년의 역사를 가지고 있습니다. 원래는 벼 수확 후 감사의 의미로 마을 사람들이 함께 모여 하나님께 감사를 드리며 공연되었습니다. “마엥켓”이라는 이름은 “들어 올리다”라는 뜻의 “engket”에서 유래하여, 열정과 공동체 정신을 상징합니다. 시간이 지나면서 다양한 전통 행사에서 공연되는 문화 춤으로 발전했습니다.</p>', '<p style=\"text-align:justify;\">马恩格舞（Maengket Dance）是来自印度尼西亚北苏拉威西米纳哈萨地区的传统舞蹈，已有数百年历史。最初，它是在水稻丰收后作为感恩仪式表演，人们聚在一起庆祝并向上帝表达感谢。“Maengket”一词来源于“engket”，意为“举起”，象征着精神与团结。随着时间的发展，这种舞蹈逐渐成为在各种传统和文化活动中表演的艺术形式。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/E2uvXcmJXtJyQWKTe6lPKc7zpVzEC9G4xPBBeq0C.png', 3, 1, '2026-04-11 09:47:40', '2026-05-26 03:02:07'),
(4, 'culture', NULL, 'MUSIK KOLINTANG', 'KOLINTANG MUSIC', '콜린탕 음악', '科林塘音乐', '<p style=\"text-align:justify;\">Kolintang berasal dari tanah Minahasa, Sulawesi Utara. Nama “kolintang” diyakini berasal dari bunyi alat ini: “tong ting tang”. Pada zaman dahulu, kolintang digunakan dalam upacara adat untuk memanggil roh leluhur dan sebagai sarana komunikasi spiritual.&nbsp;</p><p style=\"text-align:justify;\">Awalnya, alat ini dibuat dari kayu lokal ringan dan dimainkan secara sederhana. Namun setelah masuknya pengaruh agama Kristen pada abad ke-19, fungsi kolintang mulai berubah. Musik ini tidak lagi digunakan untuk ritual, tetapi berkembang menjadi hiburan dan pertunjukan.&nbsp;</p><p style=\"text-align:justify;\">Pada abad ke-20, kolintang mengalami modernisasi. Nada-nadanya disusun seperti alat musik Barat, sehingga bisa memainkan lagu nasional hingga internasional. Kini, kolintang menjadi simbol budaya Sulawesi Utara dan sering dipentaskan di berbagai acara, bahkan hingga mancanegara.</p>', '<p style=\"text-align:justify;\">Kolintang originates from the land of Minahasa in North Sulawesi, Indonesia. The name “kolintang” is believed to come from the sound produced by the instrument: “tong ting tang.” In ancient times, kolintang was used in traditional ceremonies to call upon ancestral spirits and as a means of spiritual communication.</p><p style=\"text-align:justify;\">Initially, this instrument was made from lightweight local wood and played in a simple manner. However, after the influence of Christianity entered the region in the 19th century, the function of kolintang began to change. The music was no longer used for rituals, but instead developed into entertainment and stage performances.</p><p style=\"text-align:justify;\">In the 20th century, kolintang underwent modernization. Its tones were arranged similarly to Western musical instruments, allowing it to perform national and international songs. Today, kolintang has become a cultural symbol of North Sulawesi and is frequently performed at various events, even on international stages</p>', '<p style=\"text-align:justify;\">콜린탕(Kolintang)은 인도네시아 북술라웨시의 미나하사 지역에서 유래한 전통 악기입니다. “콜린탕”이라는 이름은 이 악기에서 나는 소리인 “통 팅 탕(tong ting tang)”에서 비롯되었다고 전해집니다. 옛날에는 콜린탕이 조상신을 부르고 영적인 소통을 위한 전통 의식에서 사용되었습니다.</p><p style=\"text-align:justify;\">처음에는 가벼운 현지 목재로 만들어졌으며 단순한 방식으로 연주되었습니다. 그러나 19세기에 기독교의 영향이 들어오면서 콜린탕의 역할도 변화하기 시작했습니다. 더 이상 의식용 음악으로 사용되지 않고, 오락과 공연 예술로 발전하게 되었습니다.</p><p style=\"text-align:justify;\">20세기에 들어 콜린탕은 현대화를 거쳤습니다. 음계가 서양 악기처럼 정리되어 국가적인 노래뿐 아니라 국제적인 곡들도 연주할 수 있게 되었습니다. 오늘날 콜린탕은 북술라웨시의 문화적 상징이 되었으며, 다양한 행사와 국제 무대에서도 자주 공연되고 있습니다.</p>', '<p style=\"text-align:justify;\">科林唐（Kolintang）起源于印度尼西亚北苏拉威西的米纳哈萨地区。“Kolintang”这一名称被认为来源于这种乐器发出的声音：“tong ting tang”。在古代，科林唐被用于传统仪式中，用来召唤祖先灵魂，并作为精神交流的媒介。</p><p style=\"text-align:justify;\">最初，这种乐器由当地轻质木材制成，演奏方式也较为简单。然而，随着19世纪基督教影响的传入，科林唐的功能开始发生变化。它不再用于宗教仪式，而逐渐发展成为娱乐和舞台表演音乐。</p><p style=\"text-align:justify;\">到了20世纪，科林唐经历了现代化发展。它的音阶被重新编排得类似西方乐器，因此能够演奏印尼国内乃至国际歌曲。如今，科林唐已成为北苏拉威西的重要文化象征，并经常在各种活动中演出，甚至登上国际舞台。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/wkWmGMFMpkjku2encWDlVxUQmOH6guqhjGBqz0d2.jpg', 6, 1, '2026-04-11 09:47:40', '2026-05-26 03:26:47'),
(14, 'food', 'breakfast', 'Tinutuan (Bubur Manado)', 'Tinutuan (Bubur Manado)', '마나도 죽', '美纳多粥', '<p style=\"text-align:justify;\">Tinutuan, atau yang dikenal juga sebagai bubur Manado, adalah sajian khas yang merepresentasikan kekayaan rasa dan budaya dari Manado. Hidangan ini bukan sekadar makanan, melainkan pengalaman kuliner yang hangat, sehat, dan penuh warna. Terbuat dari perpaduan beras yang dimasak hingga lembut dengan aneka sayuran segar seperti labu kuning, bayam, kangkung, jagung, dan daun kemangi, tinutuan menghadirkan cita rasa yang ringan namun kaya. Teksturnya yang lembut berpadu dengan kesegaran sayuran menciptakan harmoni rasa yang menenangkan dan menyehatkan. Yang membuat tinutuan semakin istimewa adalah pelengkapnya—biasanya disajikan dengan ikan asin, tahu, tempe goreng, serta sambal roa yang khas, memberikan sentuhan gurih dan sedikit pedas yang menggugah selera. Kombinasi ini menjadikan setiap suapan terasa lengkap dan memuaskan. Selain lezat, tinutuan juga dikenal sebagai makanan sehat karena kaya akan serat dan nutrisi, menjadikannya pilihan sempurna untuk sarapan atau menu ringan yang mengenyangkan tanpa rasa bersalah. Dengan warna-warni alami, rasa yang autentik, dan nilai tradisional yang kuat, tinutuan bukan hanya hidangan—melainkan cerminan gaya hidup sehat dan kekayaan kuliner khas Sulawesi Utara yang patut dinikmati.</p>', '<p style=\"text-align:justify;\">Tinutuan, also known as Manado porridge, is a traditional dish that reflects the rich flavors and culture of Manado. More than just a meal, it is a warm, healthy, and colorful culinary experience. Made from rice cooked until soft and combined with fresh vegetables such as pumpkin, spinach, water spinach, corn, and basil leaves, tinutuan offers a light yet flavorful taste. Its smooth texture blends perfectly with the freshness of the vegetables, creating a comforting and nourishing dish. What makes tinutuan even more special are its side dishes—commonly served with salted fish, fried tofu, tempeh, and the iconic spicy roa chili sauce, adding a savory and slightly spicy kick that enhances every bite. Beyond its delicious taste, tinutuan is also known as a healthy dish rich in fiber and nutrients, making it an ideal choice for breakfast or a light yet satisfying meal. With its natural colors, authentic flavors, and strong cultural roots, tinutuan is not just food—it’s a reflection of a healthy lifestyle and the culinary richness of North Sulawesi.</p>', 'Tinutuan(마나도 죽)은 Manado의 풍부한 맛과 문화를 담고 있는 전통 요리입니다. 단순한 음식이 아니라 따뜻하고 건강하며 다채로운 미식 경험을 제공합니다.\r\n\r\n부드럽게 끓인 쌀에 단호박, 시금치, 공심채, 옥수수, 바질 잎 등 신선한 채소를 더해 가볍지만 깊은 맛을 느낄 수 있습니다. 부드러운 식감과 신선한 채소의 조화가 편안하면서도 영양 가득한 한 그릇을 완성합니다.\r\n\r\n또한 짭짤한 생선, 튀긴 두부와 템페, 그리고 매콤한 로아 삼발과 함께 제공되어 감칠맛과 약간의 매운맛이 더해져 더욱 풍성한 맛을 즐길 수 있습니다.\r\n\r\n맛뿐만 아니라 식이섬유와 영양소가 풍부해 건강식으로도 잘 알려져 있으며, 아침 식사나 가벼운 한 끼로 안성맞춤입니다.\r\n\r\n자연스러운 색감과 정통의 맛, 그리고 깊은 문화적 의미를 담은 Tinutuan은 단순한 음식이 아닌 건강한 라이프스타일과 북술라웨시의 풍부한 미식 문화를 보여주는 대표적인 요리입니다.', 'Tinutuan（马纳多粥）是来自 Manado 的传统美食，展现了当地丰富的风味与文化。这不仅是一道食物，更是一种温暖、健康且色彩丰富的美食体验。\r\n它由煮至软糯的米饭搭配新鲜蔬菜制成，如南瓜、菠菜、空心菜、玉米和罗勒叶，口感清淡却层次丰富。细腻的质地与蔬菜的清新完美融合，带来舒适又营养的享受。\r\nTinutuan 的特别之处还在于其配菜——通常搭配咸鱼、炸豆腐、天贝以及特色的辣味罗阿酱，为整体口感增添咸香与微辣的风味，让每一口都更加美味。\r\n除了美味之外，这道菜富含膳食纤维和营养成分，是非常健康的选择，适合作为早餐或轻盈却有饱腹感的一餐。\r\n凭借其自然的色彩、地道的风味以及深厚的文化底蕴，Tinutuan 不仅是一道美食，更是健康生活方式和北苏拉威西丰富饮食文化的体现。', 'https://api.welcomemanado.my.id/storage/travel-info/42US6wT0UILwK3QZFaeubniy1ASNO8Jkv8pHKDfL.webp', 1, 1, '2026-04-11 09:47:40', '2026-04-28 02:41:37'),
(22, 'shopping', 'center', 'Mega Mall', 'Mega Mall', '메가 몰', '大型购物中心', '<p style=\"text-align:justify;\">Mall pertama di Manado yang dibangun tahun 2004, Megamall Manado merupakan salah satu pusat perbelanjaan paling ikonik di Kota Manado yang menghadirkan perpaduan antara gaya hidup modern, hiburan, kuliner, dan suasana tepi laut yang memikat. Terletak strategis di kawasan Boulevard Manado, pusat perbelanjaan ini menjadi destinasi favorit bagi wisatawan maupun masyarakat lokal untuk berbelanja, bersantai, hingga menikmati panorama Teluk Manado yang indah.</p><p style=\"text-align:justify;\">Megamall Manado menawarkan beragam tenant mulai dari fashion, kebutuhan sehari-hari, gadget, hingga pusat hiburan keluarga. Suasana mall yang ramai namun nyaman menjadikannya tempat ideal untuk menghabiskan waktu bersama keluarga, pasangan, maupun teman.</p><p style=\"text-align:justify;\">Salah satu daya tarik utamanya adalah area yang menghadap langsung ke laut, memberikan pengalaman berbelanja dengan nuansa tropis khas Manado. Saat sore hari, pengunjung dapat menikmati pemandangan matahari terbenam yang memukau sambil menikmati aneka kuliner lokal maupun internasional di café dan restoran sekitar mall.</p><p style=\"text-align:justify;\">Tidak hanya sebagai pusat belanja, Megamall Manado juga menjadi pusat aktivitas kota dengan berbagai event, hiburan musik, hingga festival yang sering digelar sepanjang tahun. Lokasinya yang dekat dengan hotel, pusat bisnis, dan kawasan wisata membuatnya menjadi salah satu landmark penting di Manado.</p><p style=\"text-align:justify;\">Dengan kombinasi lengkap antara hiburan, kuliner, belanja, dan panorama laut yang menawan, Megamall Manado menghadirkan pengalaman urban lifestyle yang modern namun tetap terasa santai dan khas Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">The first mall in Manado built in 2004, Megamall Manado is one of the most iconic shopping destinations in Manado, offering a perfect blend of modern lifestyle, entertainment, culinary experiences, and stunning seaside views. Strategically located along Manado Boulevard, this shopping center has become a favorite destination for both tourists and locals to shop, relax, and enjoy the beautiful scenery of Manado Bay.</p><p style=\"text-align:justify;\">Megamall Manado features a wide variety of tenants, ranging from fashion outlets, daily necessities, and gadget stores to family entertainment centers. Its lively yet comfortable atmosphere makes it an ideal place to spend quality time with family, friends, or loved ones.</p><p style=\"text-align:justify;\">One of its main attractions is the seaside area overlooking the ocean, creating a unique shopping experience with Manado’s tropical ambiance. In the afternoon, visitors can enjoy breathtaking sunset views while savoring local and international culinary delights at the surrounding cafés and restaurants.</p><p style=\"text-align:justify;\">More than just a shopping center, Megamall Manado also serves as a vibrant hub for city activities, frequently hosting events, live entertainment, and festivals throughout the year. Its strategic location near hotels, business districts, and tourist attractions makes it one of the important landmarks in Manado.</p><p style=\"text-align:justify;\">With its perfect combination of shopping, entertainment, dining, and scenic ocean views, Megamall Manado offers a modern urban lifestyle experience with the relaxing charm of North Sulawesi.</p>', '<p style=\"text-align:justify;\">2004년에 건설된 마나도 최초의 쇼핑몰. Megamall Manado는 현대적인 라이프스타일, 엔터테인먼트, 미식 경험, 그리고 아름다운 해안 풍경이 조화를 이루는 마나도의 대표적인 쇼핑몰 중 하나입니다. 마나도 블러바드 지역에 위치해 있어 관광객과 현지 주민 모두에게 쇼핑과 휴식, 그리고 아름다운 마나도 만의 경치를 즐길 수 있는 인기 명소로 사랑받고 있습니다.</p><p style=\"text-align:justify;\">Megamall Manado에는 패션 매장, 생활용품점, 전자기기 매장부터 가족형 엔터테인먼트 시설까지 다양한 테넌트가 입점해 있습니다. 활기차면서도 편안한 분위기로 가족, 친구, 연인과 함께 시간을 보내기에 이상적인 장소입니다.</p><p style=\"text-align:justify;\">특히 바다를 바로 바라볼 수 있는 공간은 이곳의 가장 큰 매력 중 하나로, 마나도 특유의 열대 분위기 속에서 특별한 쇼핑 경험을 제공합니다. 오후에는 주변 카페와 레스토랑에서 현지 및 세계 각국의 음식을 즐기며 아름다운 석양을 감상할 수 있습니다.</p><p style=\"text-align:justify;\">Megamall Manado는 단순한 쇼핑센터를 넘어 다양한 이벤트, 공연, 축제가 열리는 도시 문화의 중심지 역할도 하고 있습니다. 또한 호텔, 비즈니스 지역, 관광지와 가까워 마나도의 주요 랜드마크 중 하나로 자리 잡고 있습니다.</p><p style=\"text-align:justify;\">쇼핑, 미식, 엔터테인먼트, 그리고 아름다운 바다 전망이 어우러진 Megamall Manado는 북술라웨시만의 여유로운 매력을 담은 현대적인 도시 라이프스타일 경험을 선사합니다.</p>', '<p style=\"text-align:justify;\">2004年建成的美纳多第一家购物中心。Megamall Manado是万鸦老最具代表性的购物中心之一，将现代生活方式、娱乐、美食体验以及迷人的海景完美结合。购物中心位于万鸦老海滨大道（Boulevard）黄金地段，成为当地居民和游客购物、休闲以及欣赏万鸦老湾美景的热门目的地。</p><p style=\"text-align:justify;\">Megamall Manado汇集了丰富多样的商店与设施，包括时尚品牌店、生活用品店、电子产品商店以及家庭娱乐中心。热闹而舒适的氛围，使其成为与家人、朋友或伴侣共度时光的理想场所。</p><p style=\"text-align:justify;\">其中最大的亮点之一便是面向大海的区域，让游客在充满热带风情的环境中享受独特的购物体验。傍晚时分，游客还可以在周边咖啡馆与餐厅品尝当地及国际美食，同时欣赏令人惊叹的海上日落景色。</p><p style=\"text-align:justify;\">Megamall Manado不仅仅是购物中心，同时也是城市活动的重要中心，经常举办各种活动、现场表演以及节庆活动。其靠近酒店、商业区和旅游景点的优越位置，也使其成为万鸦老的重要地标之一。</p><p style=\"text-align:justify;\">凭借购物、美食、娱乐以及迷人海景的完美结合，Megamall Manado为游客带来兼具现代都市氛围与北苏拉威西悠闲魅力的独特体验。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/J49on2rleAhjucf6o06nnbAEI9UAZgBCf4nlWy8d.png', 1, 1, '2026-04-11 09:47:40', '2026-05-13 02:28:18'),
(23, 'shopping', 'center', 'Manado Town Square (Mantos)', 'Manado Town Square (Mantos)', '마나도 타운 스퀘어', '美纳多城市广场', '<p style=\"text-align:justify;\">Manado Town Square atau yang lebih dikenal dengan sebutan Mantos merupakan salah satu pusat gaya hidup dan hiburan paling populer di Kota Manado. Dengan konsep modern yang dipadukan suasana santai khas kota pesisir, Mantos menjadi destinasi favorit masyarakat lokal maupun wisatawan untuk berbelanja, bersantai, menikmati kuliner, hingga berkumpul bersama keluarga dan teman.</p><p style=\"text-align:justify;\">Terletak strategis di kawasan Boulevard Manado, Manado Town Square menawarkan pengalaman berbelanja yang lengkap dengan berbagai tenant fashion, lifestyle, elektronik, supermarket, hingga hiburan keluarga. Area mall yang luas dan nyaman membuat pengunjung dapat menikmati suasana yang hidup namun tetap menyenangkan.</p><p style=\"text-align:justify;\">Salah satu daya tarik utama Manado Town Square adalah pilihan kulinernya yang sangat beragam. Mulai dari restoran lokal khas Sulawesi Utara hingga café dan restoran internasional, semuanya hadir dalam suasana modern yang cocok untuk bersantai maupun menikmati waktu bersama orang terdekat.</p><p style=\"text-align:justify;\">Selain menjadi pusat perbelanjaan, Mantos juga dikenal sebagai pusat aktivitas dan hiburan kota. Berbagai event, konser musik, pameran, hingga festival sering diadakan di area ini, menjadikannya tempat yang selalu ramai dan penuh energi.</p><p style=\"text-align:justify;\">Dengan desain bangunan modern, lokasi strategis, serta atmosfer yang dinamis dan nyaman, Manado Town Square menghadirkan pengalaman urban lifestyle yang lengkap di jantung Kota Manado. Tempat ini bukan hanya sekadar pusat belanja, tetapi juga menjadi simbol gaya hidup modern masyarakat Manado yang aktif dan penuh semangat.</p>', '<p style=\"text-align:justify;\">Manado Town Square, commonly known as Mantos, is one of the most popular lifestyle and entertainment destinations in Manado. Combining a modern shopping concept with the relaxed atmosphere of a coastal city, Mantos has become a favorite destination for both locals and tourists to shop, relax, enjoy culinary experiences, and spend quality time with family and friends.</p><p style=\"text-align:justify;\">Strategically located along Manado Boulevard, Manado Town Square offers a complete shopping experience with a wide range of fashion stores, lifestyle outlets, electronics shops, supermarkets, and family entertainment facilities. Its spacious and comfortable environment allows visitors to enjoy a vibrant yet pleasant atmosphere.</p><p style=\"text-align:justify;\">One of the main attractions of Manado Town Square is its diverse culinary selection. From authentic North Sulawesi local cuisine to international cafés and restaurants, visitors can enjoy a modern dining experience perfect for relaxing or gathering with loved ones.</p><p style=\"text-align:justify;\">More than just a shopping center, Mantos is also known as a hub for entertainment and city activities. Various events, music concerts, exhibitions, and festivals are frequently held here, making it a lively destination filled with energy throughout the year.</p><p style=\"text-align:justify;\">With its modern architecture, strategic location, and dynamic yet comfortable atmosphere, Manado Town Square offers a complete urban lifestyle experience in the heart of Manado. It is not only a shopping destination, but also a symbol of the modern and vibrant lifestyle of the people of Manado.</p>', '<p style=\"text-align:justify;\">Manado Town Square는 현지인들에게 “만토스(Mantos)”라는 이름으로 더 잘 알려져 있으며, 마나도를 대표하는 인기 라이프스타일 및 엔터테인먼트 공간 중 하나입니다. 현대적인 쇼핑몰 콘셉트와 해안 도시 특유의 여유로운 분위기가 조화를 이루어, 쇼핑과 휴식, 미식 경험, 가족 및 친구들과의 시간을 즐기기에 최적의 장소로 사랑받고 있습니다.</p><p style=\"text-align:justify;\">마나도 블러바드 중심에 위치한 Manado Town Square는 패션 매장, 라이프스타일 숍, 전자제품 매장, 슈퍼마켓, 가족형 엔터테인먼트 시설 등 다양한 공간을 갖추고 있어 완성도 높은 쇼핑 경험을 제공합니다. 넓고 쾌적한 공간은 활기차면서도 편안한 분위기를 선사합니다.</p><p style=\"text-align:justify;\">특히 다양한 미식 공간은 이곳의 가장 큰 매력 중 하나입니다. 북술라웨시 전통 음식부터 세계 각국의 레스토랑과 카페까지 다양하게 마련되어 있어, 여유롭게 식사를 즐기거나 소중한 사람들과 시간을 보내기에 좋습니다.</p><p style=\"text-align:justify;\">또한 Mantos는 단순한 쇼핑몰을 넘어 도시 문화와 엔터테인먼트의 중심지로도 유명합니다. 각종 이벤트, 음악 공연, 전시회, 축제 등이 자주 열려 언제나 활기와 에너지가 넘치는 장소입니다.</p><p style=\"text-align:justify;\">현대적인 건축 디자인과 뛰어난 접근성, 그리고 역동적이면서도 편안한 분위기를 갖춘 Manado Town Square는 마나도 중심부에서 완벽한 도시 라이프스타일 경험을 제공합니다. 이곳은 단순한 쇼핑 공간이 아니라, 현대적이고 활기찬 마나도 사람들의 라이프스타일을 상징하는 랜드마크입니다.</p>', '<p style=\"text-align:justify;\">Manado Town Square，当地人通常简称为“Mantos”，是万鸦老最受欢迎的生活方式与娱乐中心之一。这里将现代购物理念与海滨城市轻松悠闲的氛围完美结合，成为当地居民和游客购物、休闲、美食体验以及与家人朋友相聚的热门场所。</p><p style=\"text-align:justify;\">Manado Town Square 位于万鸦老 Boulevard 黄金地段，拥有丰富多样的商店与设施，包括时尚品牌店、生活方式商店、电子产品店、超市以及家庭娱乐设施，为游客提供完整而舒适的购物体验。宽敞明亮的环境也让整个购物氛围更加轻松愉快。</p><p style=\"text-align:justify;\">这里最大的亮点之一便是丰富的美食选择。从北苏拉威西传统特色料理，到国际化餐厅与咖啡馆，游客可以在现代舒适的环境中享受美食，非常适合与亲友共度美好时光。</p><p style=\"text-align:justify;\">除了购物中心的功能之外，Mantos 还是万鸦老城市娱乐与活动的重要中心。这里经常举办各种活动、音乐演出、展览以及节庆活动，因此始终充满活力与热闹氛围。</p><p style=\"text-align:justify;\">凭借现代化建筑设计、优越的地理位置，以及充满活力却依然舒适的环境，Manado Town Square 为游客带来完整的都市生活体验。这里不仅仅是购物场所，更是万鸦老现代生活方式与城市活力的重要象征。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/ZeeTMwIwkzACwWdFVr2ezNkQzqJaF8FgyiDmBYzB.png', 2, 1, '2026-04-11 09:47:40', '2026-05-29 08:36:19'),
(24, 'shopping', 'center', 'IT Center Manado', 'IT Center Manado', 'IT 센터 마나도', 'IT中心美纳多', '<p style=\"text-align:justify;\">IT Center Manado merupakan pusat teknologi dan gaya hidup digital terbesar di Kota Manado yang menjadi destinasi utama bagi pecinta gadget, elektronik, dan kebutuhan teknologi modern. Dikenal sebagai pusat techno &amp; lifestyle, IT Center menghadirkan pengalaman berbelanja yang lengkap dengan berbagai pilihan produk teknologi terkini dalam satu lokasi strategis di pusat kota.</p><p style=\"text-align:justify;\">Di dalam IT Center, pengunjung dapat menemukan beragam toko yang menawarkan smartphone terbaru, laptop, komputer gaming, aksesoris gadget, perangkat elektronik, kamera, hingga berbagai kebutuhan digital lainnya dari merek-merek ternama. Tempat ini menjadi pilihan favorit masyarakat Manado untuk mencari teknologi terbaru dengan pilihan produk yang lengkap dan harga yang kompetitif.</p><p style=\"text-align:justify;\">Tidak hanya menjadi pusat belanja elektronik, IT Center juga menghadirkan suasana modern dan dinamis yang mencerminkan perkembangan gaya hidup digital masa kini. Berbagai café, area kuliner, dan spot berkumpul membuat pengunjung dapat menikmati pengalaman berbelanja yang nyaman sekaligus santai.</p><p style=\"text-align:justify;\">Lokasinya yang strategis dan mudah dijangkau menjadikan IT Center sebagai salah satu landmark modern di Manado, khususnya bagi generasi muda, pelaku bisnis, hingga wisatawan yang membutuhkan akses cepat terhadap teknologi dan kebutuhan digital.</p><p style=\"text-align:justify;\">Dengan konsep modern, pilihan tenant teknologi yang lengkap, dan atmosfer urban yang energik, IT Center Manado menjadi simbol perkembangan teknologi dan pusat aktivitas digital di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">IT Center Manado is the largest technology and digital lifestyle center in Manado, serving as the main destination for gadget enthusiasts, electronics shoppers, and modern technology needs. Known as a techno &amp; lifestyle hub, IT Center offers a complete shopping experience with a wide range of the latest technology products in one strategic location in the heart of the city.</p><p style=\"text-align:justify;\">Inside IT Center, visitors can find various stores offering the latest smartphones, laptops, gaming computers, gadget accessories, electronic devices, cameras, and many other digital products from well-known brands. It has become a favorite destination for the people of Manado to explore the newest technology with extensive product choices and competitive prices.</p><p style=\"text-align:justify;\">More than just an electronics shopping center, IT Center also presents a modern and dynamic atmosphere that reflects today’s digital lifestyle. Various cafés, culinary spots, and gathering areas allow visitors to enjoy a comfortable and relaxing shopping experience.</p><p style=\"text-align:justify;\">Its strategic and easily accessible location makes IT Center one of Manado’s modern landmarks, especially for young people, business professionals, and tourists who need quick access to technology and digital services.</p><p style=\"text-align:justify;\">With its modern concept, complete technology tenants, and energetic urban atmosphere, IT Center Manado has become a symbol of technological growth and a center of digital activity in North Sulawesi.</p>', '<p style=\"text-align:justify;\">IT Center Manado는 마나도 최대의 기술 및 디지털 라이프스타일 중심지로, 최신 전자기기와 IT 제품을 찾는 사람들에게 가장 인기 있는 장소입니다. “테크노 &amp; 라이프스타일 허브”로 알려진 이곳은 도시 중심부의 편리한 위치에서 최신 기술 제품을 한곳에서 만나볼 수 있는 완벽한 쇼핑 경험을 제공합니다.</p><p style=\"text-align:justify;\">IT Center 내부에는 최신 스마트폰, 노트북, 게이밍 컴퓨터, 전자기기 액세서리, 카메라 및 다양한 디지털 제품을 판매하는 수많은 매장이 입점해 있습니다. 다양한 브랜드와 경쟁력 있는 가격으로 마나도 시민들에게 최신 기술을 경험할 수 있는 대표적인 쇼핑 명소로 자리 잡고 있습니다.</p><p style=\"text-align:justify;\">이곳은 단순한 전자제품 쇼핑센터를 넘어 현대적이고 역동적인 분위기를 갖춘 공간으로, 오늘날의 디지털 라이프스타일을 잘 보여줍니다. 다양한 카페와 음식점, 휴식 공간이 마련되어 있어 방문객들은 편안하고 여유로운 시간을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">또한 접근성이 뛰어난 전략적인 위치 덕분에 IT Center는 젊은 세대, 비즈니스 관계자, 관광객들에게 중요한 도시 랜드마크로 알려져 있습니다.</p><p style=\"text-align:justify;\">현대적인 콘셉트, 다양한 IT 전문 매장, 그리고 활기찬 도시 분위기를 갖춘 IT Center Manado는 북술라웨시의 기술 발전과 디지털 활동의 중심지를 상징하는 공간입니다.</p>', '<p style=\"text-align:justify;\">IT Center Manado是万鸦老最大的科技与数字生活中心，也是当地电子产品、数码设备及现代科技需求的主要目的地。作为著名的“科技与生活方式中心”，IT Center 在市中心优越地段，为游客提供一站式现代科技购物体验。</p><p style=\"text-align:justify;\">在 IT Center 内，游客可以找到各种销售最新智能手机、笔记本电脑、游戏电脑、数码配件、电子设备、相机以及其他数字产品的商店，汇聚了众多知名品牌。这里已成为万鸦老市民寻找最新科技产品和享受多样化选择的重要购物中心。</p><p style=\"text-align:justify;\">除了电子产品购物中心之外，IT Center 还拥有现代且充满活力的氛围，充分体现了当代数字化生活方式。各种咖啡馆、美食区以及休闲聚会空间，让游客在购物之余也能享受轻松舒适的体验。</p><p style=\"text-align:justify;\">其优越且交通便利的地理位置，使 IT Center 成为万鸦老的重要现代地标之一，尤其受到年轻人、商务人士以及游客的欢迎，他们可以在这里快速获取科技与数字服务需求。</p><p style=\"text-align:justify;\">凭借现代化概念、丰富齐全的科技商户以及充满活力的都市氛围，IT Center Manado 已成为北苏拉威西科技发展与数字活动的重要象征。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/u5mTxEfpQFqBD8kZCwMvxTkAYn4ZzYiChCq2F5zW.png', 3, 1, '2026-04-11 09:47:40', '2026-05-13 03:14:28'),
(25, 'shopping', 'souvenir', 'Grand Merciful Building', 'Grand Merciful Building', '그랜드 머시풀 빌딩', '大仁慈大厦', '<p style=\"text-align:justify;\">Grand Merciful Building merupakan salah satu bangunan ikonik di Kota Manado yang memadukan arsitektur modern dengan sentuhan desain klasik yang elegan. Dengan tampilan bangunan yang unik dan mudah dikenali, Grand Merciful Building menghadirkan kesan eksklusif sekaligus berkelas di tengah perkembangan kawasan bisnis kota.</p><p style=\"text-align:justify;\">Bangunan ini dikenal dengan fasad modern berpadu nuansa artistik pada menara bergaya klasik yang menjadi daya tarik utamanya. Perpaduan warna, detail arsitektur, serta desain bangunan yang megah menciptakan karakter visual yang berbeda dibandingkan bangunan lain di sekitarnya.</p><p style=\"text-align:justify;\">Terletak di lokasi strategis di Manado, Grand Merciful Building menjadi pusat aktivitas bisnis, perkantoran, maupun berbagai kegiatan komersial lainnya. Lingkungannya yang mudah diakses menjadikan bangunan ini ideal untuk berbagai kebutuhan usaha dan aktivitas profesional.</p><p style=\"text-align:justify;\">Selain fungsi bisnisnya, Grand Merciful Building juga sering menarik perhatian karena tampilannya yang fotogenik dan modern. Kombinasi desain elegan, suasana urban, dan nuansa eksklusif menjadikannya salah satu landmark menarik yang mempercantik wajah Kota Manado.</p><p style=\"text-align:justify;\">Dengan konsep arsitektur yang unik, atmosfer profesional, dan lokasi yang strategis, Grand Merciful Building menghadirkan simbol modernitas dan perkembangan bisnis di Sulawesi Utara.</p><p style=\"text-align:justify;\">&nbsp;</p>', '<p style=\"text-align:justify;\">Grand Merciful Building is one of the iconic buildings in Manado, combining modern architecture with elegant classical design elements. With its unique and recognizable appearance, Grand Merciful Building presents an exclusive and sophisticated atmosphere amid the city’s growing business district.</p><p style=\"text-align:justify;\">The building is well known for its modern façade blended with an artistic classical-style tower that serves as its main attraction. The combination of colors, architectural details, and grand design creates a distinctive visual character that stands out from surrounding buildings.</p><p style=\"text-align:justify;\">Strategically located in Manado, Grand Merciful Building serves as a center for business activities, offices, and various commercial purposes. Its accessible location makes it ideal for professional activities and business needs.</p><p style=\"text-align:justify;\">Beyond its business function, Grand Merciful Building also attracts attention because of its photogenic and modern appearance. The blend of elegant architecture, urban atmosphere, and exclusive ambiance makes it one of the landmarks that enhances the beauty of Manado City.</p><p style=\"text-align:justify;\">With its unique architectural concept, professional atmosphere, and strategic location, Grand Merciful Building represents a symbol of modernity and business growth in North Sulawesi.</p>', '<p style=\"text-align:justify;\">Grand Merciful Building는 현대적인 건축 양식과 우아한 클래식 디자인 요소가 조화를 이루는 마나도의 대표적인 랜드마크 건물 중 하나입니다. 독특하고 눈에 띄는 외관을 통해 도시의 발전하는 비즈니스 중심지 속에서 고급스럽고 세련된 분위기를 선사합니다.</p><p style=\"text-align:justify;\">이 건물은 현대적인 외관과 예술적인 클래식 스타일의 타워가 조화를 이루는 것이 가장 큰 특징입니다. 색감, 건축 디테일, 웅장한 디자인이 어우러져 주변 건물들과 차별화된 독특한 시각적 매력을 만들어냅니다.</p><p style=\"text-align:justify;\">마나도의 전략적인 위치에 자리한 Grand Merciful Building은 비즈니스 활동, 사무 공간, 그리고 다양한 상업 활동의 중심지 역할을 하고 있습니다. 접근성이 뛰어나 전문적인 업무와 비즈니스 활동에 매우 적합한 장소입니다.</p><p style=\"text-align:justify;\">비즈니스 기능뿐만 아니라, 세련되고 포토제닉한 외관 덕분에 많은 사람들의 관심을 끌고 있습니다. 우아한 건축미와 도시적인 분위기, 그리고 고급스러운 감성이 조화를 이루어 마나도의 도시 경관을 더욱 아름답게 만드는 랜드마크로 자리 잡고 있습니다.</p><p style=\"text-align:justify;\">독창적인 건축 콘셉트와 전문적인 분위기, 그리고 뛰어난 입지를 갖춘 Grand Merciful Building은 북술라웨시의 현대성과 비즈니스 발전을 상징하는 건물입니다.</p>', '<p>Grand Merciful Building是万鸦老具有代表性的地标建筑之一，将现代建筑风格与优雅的古典设计元素完美结合。其独特且醒目的外观，在城市不断发展的商业区中展现出高端与精致的氛围。</p><p>这座建筑以现代化外立面与富有艺术感的古典风格塔楼相结合而闻名，成为其最吸引人的特色。色彩搭配、建筑细节以及宏伟设计共同塑造出与周边建筑截然不同的视觉魅力。</p><p>Grand Merciful Building 位于万鸦老的战略性地段，是商务活动、办公空间以及各种商业用途的重要中心。便利的交通与优越的位置，使其非常适合专业办公及商业活动需求。</p><p>除了商业功能之外，这座建筑也因其现代且极具摄影感的外观而备受关注。优雅的建筑设计、都市氛围以及高端感，使其成为点缀万鸦老城市景观的重要地标之一。</p><p>凭借独特的建筑理念、专业氛围以及优越地理位置，Grand Merciful Building 已成为北苏拉威西现代化与商业发展的象征。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/j3uB8qOq5vMyZxDod9ognM83T8MG2eUIzK7FQrOm.png', 5, 1, '2026-04-11 09:47:40', '2026-05-13 05:42:35'),
(26, 'shopping', 'souvenir', 'UD Kawanua', 'UD Kawanua', 'UD 카와누아', 'UD卡瓦努阿', '<p style=\"text-align:justify;\">Di jantung Kota Manado, Kawanua Souvenir hadir sebagai destinasi belanja khas yang memadukan budaya, cita rasa, dan keramahtamahan Sulawesi Utara dalam satu tempat. Dengan tampilan toko yang hangat dan nyaman, Kawanua menjadi pilihan favorit wisatawan maupun warga lokal untuk mencari oleh-oleh khas Manado yang autentik dan berkualitas.</p><p style=\"text-align:justify;\">Beragam produk khas tersedia lengkap, mulai dari kain dan busana bercorak tradisional, aneka camilan khas, hingga kuliner legendaris seperti Klappertaart yang menjadi favorit banyak pengunjung. Setiap sudut toko menghadirkan nuansa khas Kawanua yang kental—sederhana, hangat, dan penuh rasa kekeluargaan.</p><p style=\"text-align:justify;\">Lebih dari sekadar toko oleh-oleh, Kawanua Souvenir menjadi tempat yang memperkenalkan kekayaan budaya dan rasa dari tanah Minahasa kepada siapa saja yang datang. Pelayanan yang ramah, pilihan produk yang beragam, dan suasana yang nyaman membuat setiap kunjungan terasa menyenangkan dan berkesan.</p><p style=\"text-align:justify;\">Bagi para pelancong, Kawanua Souvenir bukan hanya tempat berbelanja, tetapi juga tempat membawa pulang kenangan tentang Manado—dalam bentuk rasa, karya, dan cerita yang khas dari bumi Nyiur Melambai.</p>', '<p style=\"text-align:justify;\">In the heart of Manado, Kawanua Souvenir stands as a shopping destination that beautifully combines the culture, flavors, and hospitality of North Sulawesi in one place. With its warm and welcoming atmosphere, Kawanua has become a favorite destination for both tourists and locals seeking authentic and high-quality Manado souvenirs.</p><p style=\"text-align:justify;\">A wide variety of local products can be found here, ranging from traditional fabrics and clothing to delicious local snacks and iconic culinary specialties such as Klappertaart, a beloved favorite among visitors. Every corner of the store reflects the spirit of Kawanua culture—simple, warm, and full of hospitality.</p><p style=\"text-align:justify;\">More than just a souvenir shop, Kawanua Souvenir introduces the richness of Minahasan culture and taste to everyone who visits. Friendly service, diverse product selections, and a comfortable atmosphere make every visit enjoyable and memorable.</p><p style=\"text-align:justify;\">For travelers, Kawanua Souvenir is not only a place to shop, but also a place to bring home memories of Manado—through flavors, crafts, and stories from the land of Nyiur Melambai.</p>', '<p style=\"text-align:justify;\">마나도의 중심부에 위치한 카와누아 수베니르는 북술라웨시의 문화, 맛, 그리고 따뜻한 환대를 한곳에서 경험할 수 있는 특별한 쇼핑 명소입니다. 아늑하고 편안한 분위기의 이곳은 정통 마나도 기념품을 찾는 관광객과 현지인들에게 사랑받는 장소입니다.</p><p style=\"text-align:justify;\">전통 문양의 의류와 직물부터 다양한 지역 간식, 그리고 많은 사람들에게 인기 있는 대표 디저트 클라페르타르트(Klappertaart)까지 다양한 특산품을 만나볼 수 있습니다. 매장 곳곳에서는 소박하면서도 따뜻한 카와누아 문화의 정취를 느낄 수 있습니다.</p><p style=\"text-align:justify;\">카와누아 수베니르는 단순한 기념품 가게가 아니라, 미나하사 지역의 풍부한 문화와 맛을 소개하는 공간입니다. 친절한 서비스와 다양한 상품, 그리고 편안한 분위기는 방문객들에게 즐겁고 특별한 경험을 선사합니다.</p><p style=\"text-align:justify;\">여행객들에게 카와누아 수베니르는 단순히 쇼핑을 하는 장소가 아니라, 마나도의 맛과 공예품, 그리고 이야기를 추억으로 담아가는 특별한 공간입니다.</p>', '<p style=\"text-align:justify;\">位于万鸦老市中心的 Kawanua Souvenir，是一家融合了北苏拉威西文化、美食与热情好客精神的特色纪念品商店。温馨舒适的环境，使这里成为游客和当地居民寻找正宗万鸦老特色伴手礼的热门地点。</p><p style=\"text-align:justify;\">店内提供丰富多样的本地特色商品，包括传统服饰与布料、各式地方小吃，以及深受游客喜爱的经典甜点——Klappertaart。店铺的每一个角落，都散发着浓厚的 Kawanua 文化气息，简单、温暖而充满人情味。</p><p style=\"text-align:justify;\">Kawanua Souvenir 不仅仅是一家纪念品商店，更是向访客展示米纳哈萨文化与风味魅力的窗口。友善的服务、多样化的商品选择以及舒适的购物氛围，让每一次到访都变得愉快而难忘。</p><p style=\"text-align:justify;\">对于旅行者来说，Kawanua Souvenir 不只是购物的地方，更是把万鸦老的味道、工艺与故事带回家的珍贵回忆。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/EVEYN83C0KzExIzXPcOtiaZOGVcG7h6KOac9VfGr.png', 8, 1, '2026-04-11 09:47:40', '2026-05-13 06:30:28'),
(27, 'shopping', 'minahasa', 'Desa Tinoor', 'Tinoor Village', '티누르 마을', '蒂努尔村', '<p style=\"text-align:justify;\">Di sepanjang jalan berkelok di Desa Kinilow, deretan kios bambu berdiri sederhana namun penuh kehidupan. Anyaman bambu yang tergantung rapi—mulai dari bakul, tudung saji, keranjang, hingga hiasan rumah—menjadi bukti ketelatenan tangan-tangan pengrajin lokal yang menjaga warisan budaya turun-temurun. Aroma bambu yang khas berpadu dengan suasana desa yang sejuk menghadirkan pengalaman yang hangat dan autentik bagi siapa saja yang melintas.</p><p style=\"text-align:justify;\">Para pengrajin di Kinilow tidak sekadar membuat kerajinan, tetapi juga merawat identitas desa mereka. Setiap anyaman memiliki cerita: tentang kesabaran, keterampilan, dan kreativitas yang diwariskan dari generasi ke generasi. Dengan teknik tradisional yang masih dipertahankan, mereka mampu mengubah bambu sederhana menjadi karya bernilai seni tinggi sekaligus bernilai ekonomi.</p><p style=\"text-align:justify;\">Keunikan kerajinan bambu Kinilow terletak pada detail anyamannya yang rapi dan kuat. Produk-produk ini bukan hanya digunakan dalam kehidupan sehari-hari, tetapi juga menjadi daya tarik wisata dan buah tangan khas daerah. Di balik kesederhanaannya, para pengrajin bambu Kinilow menunjukkan bahwa kearifan lokal dapat terus hidup dan berkembang di tengah zaman modern.</p><p style=\"text-align:justify;\">Desa Kinilow pun terasa seperti galeri alam terbuka—tempat di mana kreativitas tumbuh dari alam, dan budaya tetap berdenyut melalui setiap helai bambu yang dianyam dengan cinta.</p>', '<p style=\"text-align:justify;\">Along the winding roads of Kinilow Village, rows of humble bamboo stalls stand full of life and tradition. Neatly displayed woven bamboo crafts—ranging from baskets, food covers, and containers to home decorations—reflect the dedication and craftsmanship of local artisans who continue to preserve their cultural heritage from generation to generation. The natural scent of bamboo combined with the cool village atmosphere creates a warm and authentic experience for every visitor.</p><p style=\"text-align:justify;\">The craftsmen of Kinilow do more than create handmade products; they preserve the identity of their village. Every woven piece tells a story of patience, skill, and creativity passed down through the years. Using traditional techniques that remain carefully maintained, they transform simple bamboo into artistic creations with both cultural and economic value.</p><p style=\"text-align:justify;\">The uniqueness of Kinilow bamboo crafts lies in their detailed, strong, and elegant weaving patterns. These products are not only useful in everyday life but have also become popular souvenirs and tourist attractions. Behind their simplicity, the bamboo artisans of Kinilow prove that local wisdom and tradition can continue to thrive in the modern world.</p><p style=\"text-align:justify;\">Kinilow Village feels like an open-air gallery, where creativity grows from nature and culture lives on through every strand of bamboo woven with love.</p>', '<p style=\"text-align:justify;\">키닐로우 마을의 구불구불한 길을 따라가다 보면, 소박하지만 생동감 넘치는 대나무 공예 상점들이 줄지어 서 있습니다. 바구니, 음식 덮개, 생활용품, 그리고 다양한 장식품까지 정성스럽게 엮어진 대나무 공예품들은 세대를 이어 전통을 지켜온 장인들의 손길과 열정을 보여줍니다. 대나무 특유의 향기와 시원한 마을의 분위기가 어우러져 방문객들에게 따뜻하고 진정성 있는 경험을 선사합니다.</p><p style=\"text-align:justify;\">키닐로우의 장인들은 단순히 공예품을 만드는 것이 아니라, 마을의 정체성과 문화를 지켜가고 있습니다. 하나하나의 대나무 엮음에는 인내와 기술, 그리고 오랜 세월 이어져 온 창의성이 담겨 있습니다. 전통적인 기법을 유지하며 평범한 대나무를 예술적 가치와 경제적 가치를 지닌 작품으로 탄생시키고 있습니다.</p><p style=\"text-align:justify;\">키닐로우 대나무 공예의 특별함은 섬세하고 견고한 짜임에 있습니다. 이 공예품들은 일상생활에서 유용하게 사용될 뿐 아니라, 지역을 대표하는 기념품이자 관광 명소로도 사랑받고 있습니다. 소박함 속에서도 키닐로우의 대나무 장인들은 지역의 지혜와 전통이 현대 속에서도 계속 살아 숨 쉴 수 있음을 보여줍니다.</p><p style=\"text-align:justify;\">키닐로우 마을은 마치 자연 속의 야외 갤러리와 같습니다. 자연에서 피어난 창의성과 대나무 한 올 한 올에 담긴 문화의 숨결이 살아 있는 곳입니다.</p>', '<p style=\"text-align:justify;\">沿着基尼洛村蜿蜒的道路，一排排朴素而充满生机的竹编小店映入眼帘。整齐悬挂的竹编工艺品——从篮子、食物罩、收纳器具到家居装饰——展现了当地工匠代代相传的精湛技艺与文化传承。竹子的清香与宁静凉爽的乡村氛围交织在一起，为每一位到访者带来温暖而真实的体验。</p><p style=\"text-align:justify;\">基尼洛村的工匠们不仅仅是在制作手工艺品，更是在守护村庄的文化与身份。每一件竹编作品都蕴含着耐心、技巧以及世代流传的创造力。他们坚持传统编织工艺，将普通的竹子变成兼具艺术价值与经济价值的精美作品。</p><p style=\"text-align:justify;\">基尼洛竹编工艺最大的特色，在于其细致、坚固而优雅的编织纹理。这些产品不仅实用于日常生活，也成为深受游客喜爱的特色纪念品和文化旅游亮点。在这些朴实无华的作品背后，基尼洛的竹编工匠向世人证明：地方智慧与传统文化，依然能够在现代社会中持续绽放光彩。</p><p style=\"text-align:justify;\">基尼洛村宛如一座露天艺术馆，在这里，创意源于自然，文化通过每一根用心编织的竹条得以延续。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/Dr7l0L4QHNENKdRpwv4ErqIgggPDUKKxKTmCPoXy.png', 7, 1, '2026-04-11 09:47:40', '2026-05-13 06:03:51'),
(28, 'shopping', 'minahasa', 'Pasar Beriman Tomohon', 'Tomohon Extreme Market', '토모혼 익스트림 시장', '托莫洪极端市场', '<p style=\"text-align:justify;\">Pasar Beriman Tomohon dikenal sebagai salah satu pasar tradisional paling unik di Indonesia karena menawarkan pengalaman budaya kuliner yang berbeda dari kebanyakan pasar pada umumnya. Selain menjual hasil bumi, rempah-rempah, bunga, dan berbagai produk lokal khas Minahasa, pasar ini juga terkenal dengan penjualan berbagai jenis daging yang dianggap ekstrem oleh banyak wisatawan.</p><p style=\"text-align:justify;\">Di area tertentu pasar, pengunjung dapat menemukan berbagai pilihan daging yang merupakan bagian dari tradisi kuliner masyarakat lokal Sulawesi Utara. Keberadaan produk-produk tersebut mencerminkan keragaman budaya dan kebiasaan kuliner yang telah berkembang turun-temurun di sebagian masyarakat Minahasa.</p><p style=\"text-align:justify;\">Bagi wisatawan, pengalaman mengunjungi Pasar Beriman sering kali menghadirkan perpaduan rasa penasaran, kejutan, sekaligus ketertarikan budaya. Suasana pasar yang ramai, interaksi pedagang yang aktif, serta beragam komoditas unik menjadikan tempat ini salah satu destinasi wisata budaya yang paling banyak diperbincangkan di Tomohon.</p><p style=\"text-align:justify;\">Terletak di kota pegunungan yang sejuk dengan latar panorama alam khas Tomohon, pasar ini menawarkan pengalaman autentik untuk melihat langsung sisi kehidupan tradisional masyarakat lokal. Banyak wisatawan domestik maupun mancanegara datang untuk memahami lebih dekat budaya kuliner ekstrem yang menjadi bagian dari identitas sebagian masyarakat setempat.</p><p style=\"text-align:justify;\">Meski dikenal kontroversial bagi sebagian orang, Pasar Beriman Tomohon tetap menjadi simbol keberagaman tradisi dan budaya kuliner di Sulawesi Utara, sekaligus mencerminkan kuatnya warisan budaya lokal yang masih bertahan hingga kini.</p>', '<p style=\"text-align:justify;\">Pasar Beriman Tomohon is known as one of the most unique traditional markets in Indonesia because it offers a cultural and culinary experience unlike most markets. In addition to selling fresh produce, spices, flowers, and various local Minahasan products, the market is also famous for offering a variety of meats considered exotic or extreme by many visitors.</p><p style=\"text-align:justify;\">In certain sections of the market, visitors can find different kinds of meat that are part of the traditional culinary culture of some local communities in North Sulawesi. The presence of these products reflects the diversity of cultural traditions and culinary practices that have been passed down through generations within parts of Minahasan society.</p><p style=\"text-align:justify;\">For tourists, visiting Pasar Beriman often brings a mixture of curiosity, surprise, and cultural fascination. The lively atmosphere, active interactions between traders and buyers, and the wide range of unusual products make this market one of the most talked-about cultural destinations in Tomohon.</p><p style=\"text-align:justify;\">Located in the cool highlands of Tomohon and surrounded by beautiful mountain scenery, the market offers an authentic opportunity to observe the traditional lifestyle of the local community firsthand. Many domestic and international tourists visit to gain a deeper understanding of the region’s distinctive culinary traditions.</p><p style=\"text-align:justify;\">Although considered controversial by some people, Pasar Beriman Tomohon remains a symbol of the diversity of traditions and culinary culture in North Sulawesi, while also reflecting the strong local heritage that continues to survive today.</p>', '<p style=\"text-align:justify;\">Pasar Beriman Tomohon는 일반적인 시장과는 다른 독특한 문화 및 음식 경험을 제공하는 곳으로, 인도네시아에서 가장 특별한 전통시장 중 하나로 알려져 있습니다. 신선한 농산물, 향신료, 꽃, 그리고 다양한 미나하사 지역 특산품뿐만 아니라, 많은 방문객들에게 이색적이거나 독특하게 여겨지는 다양한 육류를 판매하는 것으로도 유명합니다.</p><p style=\"text-align:justify;\">시장 일부 구역에서는 북술라웨시 지역 일부 주민들의 전통 식문화와 관련된 다양한 종류의 고기를 볼 수 있습니다. 이러한 상품들은 세대를 거쳐 이어져 온 미나하사 사회의 독특한 문화적 전통과 음식 문화를 보여줍니다.</p><p style=\"text-align:justify;\">관광객들에게 Pasar Beriman 방문은 호기심과 놀라움, 그리고 문화적 흥미를 동시에 느끼게 하는 특별한 경험입니다. 활기찬 시장 분위기, 상인들과의 생동감 있는 교류, 그리고 다양한 독특한 상품들은 이곳을 토모혼에서 가장 화제가 되는 문화 관광지 중 하나로 만들고 있습니다.</p><p style=\"text-align:justify;\">시원한 기후의 산악 도시 토모혼에 위치한 이 시장은 아름다운 산 풍경 속에서 지역 주민들의 전통적인 삶의 모습을 직접 경험할 수 있는 장소입니다. 국내외 관광객들은 이 지역만의 독특한 음식 문화를 더 깊이 이해하기 위해 이곳을 방문합니다.</p><p style=\"text-align:justify;\">일부 사람들에게는 논란의 대상이 되기도 하지만, Pasar Beriman Tomohon은 여전히 북술라웨시의 다양한 전통과 음식 문화를 상징하는 장소이며, 오늘날까지 이어져 오는 강한 지역 문화유산을 보여주는 공간입니다.</p>', '<p style=\"text-align:justify;\">Pasar Beriman Tomohon被认为是印度尼西亚最独特的传统市场之一，因为这里提供了与普通市场截然不同的文化与美食体验。除了出售新鲜蔬菜、水果、香料、鲜花以及各种米纳哈萨特色产品外，这里还因售卖一些被许多游客视为“特别”或“另类”的肉类而闻名。</p><p style=\"text-align:justify;\">在市场的部分区域，游客可以看到一些属于北苏拉威西当地传统饮食文化中的肉类产品。这些商品反映了米纳哈萨部分社区代代相传的饮食传统与文化多样性。</p><p style=\"text-align:justify;\">对于游客而言，参观 Pasar Beriman 往往会带来好奇、惊讶以及浓厚的文化体验。热闹的市场氛围、商贩之间充满活力的互动，以及各种独特商品，使这里成为托莫洪最受关注的文化旅游目的地之一。</p><p style=\"text-align:justify;\">市场位于气候凉爽、被群山环绕的托莫洪市，为游客提供了一个近距离观察当地传统生活方式的真实机会。许多国内外游客来到这里，希望更深入地了解当地独特的饮食文化传统。</p><p style=\"text-align:justify;\">尽管对于部分人来说具有一定争议性，但 Pasar Beriman Tomohon 依然是北苏拉威西多元传统与饮食文化的重要象征，同时也体现了当地文化遗产至今依然被保留与传承。</p><p style=\"text-align:justify;\">&nbsp;</p>', NULL, 6, 1, '2026-04-11 09:47:40', '2026-05-13 05:54:39'),
(29, 'guide', NULL, 'PULAU BUNAKEN', 'Bunaken & Siladen Island', '부나켄 & 실라덴 섬', '布纳肯和西拉登岛', '<p style=\"text-align:justify;\">Taman Nasional Bunaken adalah salah satu taman laut paling terkenal di Indonesia yang terletak di Teluk Manado, dekat kota Manado di provinsi Sulawesi Utara. Kawasan ini mulai dikenal luas oleh para penyelam dunia sejak tahun 1980-an dan kemudian secara resmi ditetapkan sebagai taman nasional pada tahun 1991 untuk melindungi keindahan dan keanekaragaman hayati lautnya.&nbsp;<br><br>Bunaken memiliki beberapa pulau utama seperti Pulau Bunaken, Manado Tua, Siladen, Mantehage, dan Nain yang dikelilingi perairan jernih dengan pemandangan alam tropis yang memukau. Keistimewaan Bunaken terletak pada kekayaan bawah lautnya. Di sini terdapat ratusan jenis terumbu karang dan ribuan spesies ikan tropis yang berwarna-warni, termasuk penyu laut, ikan napoleon, hingga berbagai biota laut unik lainnya.&nbsp;<br><br>Bunaken juga terkenal dengan dinding karang vertikal (wall diving) yang menjulang hingga puluhan meter ke dalam laut, menjadikannya salah satu lokasi menyelam terbaik di dunia. Bagi wisatawan yang ingin menikmati keindahan bawah laut tanpa harus menyelam terlalu dalam, snorkeling menjadi aktivitas yang sangat populer karena air lautnya sangat jernih sehingga ikan dan terumbu karang dapat terlihat jelas dari permukaan.&nbsp;<br><br>Sementara itu, bagi pecinta petualangan, diving (menyelam) di Bunaken menawarkan pengalaman luar biasa menjelajahi taman karang yang luas, bertemu berbagai spesies laut, serta menikmati pemandangan bawah laut yang spektakuler. Dengan keindahan alam, kehidupan laut yang kaya, dan suasana tropis yang menenangkan, Bunaken menjadi destinasi wisata yang sangat menarik bagi wisatawan dari berbagai negara.</p>', '<p style=\"text-align:justify;\">Bunaken National Park is one of the most famous marine parks in Indonesia, located in Manado Bay near the city of Manado in North Sulawesi Province. This area began to gain worldwide recognition among divers in the 1980s and was officially designated as a national park in 1991 to protect its extraordinary marine beauty and biodiversity.</p><p style=\"text-align:justify;\">Bunaken consists of several main islands such as Bunaken Island, Manado Tua, Siladen, Mantehage, and Nain, all surrounded by crystal-clear waters and stunning tropical scenery. The main attraction of Bunaken lies in its rich underwater ecosystem. The area is home to hundreds of coral reef species and thousands of colorful tropical fish, including sea turtles, Napoleon wrasse, and many other unique marine creatures.</p><p style=\"text-align:justify;\">Bunaken is also famous for its spectacular vertical coral walls, known as wall diving sites, which descend dozens of meters into the sea, making it one of the best diving destinations in the world. For tourists who prefer enjoying the underwater beauty without diving too deep, snorkeling is a very popular activity because the seawater is so clear that fish and coral reefs can easily be seen from the surface.</p><p style=\"text-align:justify;\">Meanwhile, for adventure lovers, diving in Bunaken offers an unforgettable experience of exploring vast coral gardens, encountering diverse marine species, and witnessing breathtaking underwater landscapes. With its natural beauty, rich marine life, and peaceful tropical atmosphere, Bunaken has become a highly attractive tourist destination for visitors from around the world.</p>', '<p style=\"text-align:justify;\">Bunaken National Park은 인도네시아에서 가장 유명한 해양 국립공원 중 하나로, 북술라웨시 주의 Manado 근처 마나도 만에 위치해 있습니다. 이 지역은 1980년대부터 세계 다이버들 사이에서 널리 알려지기 시작했으며, 해양의 아름다움과 생물 다양성을 보호하기 위해 1991년에 공식적으로 국립공원으로 지정되었습니다.</p><p style=\"text-align:justify;\">부나켄에는 부나켄 섬, 마나도 투아, 실라덴, 만테하게, 나인 등의 주요 섬들이 있으며, 맑고 투명한 바다와 아름다운 열대 풍경으로 둘러싸여 있습니다. 부나켄의 가장 큰 매력은 풍부한 해양 생태계에 있습니다. 이곳에는 수백 종의 산호초와 수천 종의 형형색색 열대어가 서식하고 있으며, 바다거북, 나폴레옹피시 그리고 다양한 희귀 해양 생물도 볼 수 있습니다.</p><p style=\"text-align:justify;\">부나켄은 수십 미터 아래까지 이어지는 수직 산호 절벽인 ‘월 다이빙(Wall Diving)’으로도 유명하며, 세계 최고의 다이빙 명소 중 하나로 손꼽힙니다. 깊이 잠수하지 않고도 바닷속의 아름다움을 즐기고 싶은 관광객들에게는 스노클링이 매우 인기 있는 활동입니다. 바닷물이 매우 맑아 수면 위에서도 물고기와 산호초를 선명하게 볼 수 있기 때문입니다.</p><p style=\"text-align:justify;\">또한 모험을 좋아하는 사람들에게 부나켄 다이빙은 광활한 산호 정원을 탐험하고, 다양한 해양 생물을 만나며, 환상적인 해저 풍경을 감상할 수 있는 특별한 경험을 제공합니다. 아름다운 자연, 풍부한 해양 생물, 그리고 평화로운 열대 분위기를 가진 부나켄은 세계 각국의 관광객들에게 매우 매력적인 여행지로 사랑받고 있습니다.</p>', '<p style=\"text-align:justify;\">Bunaken National Park 是印度尼西亚最著名的海洋国家公园之一，位于北苏拉威西省 Manado 附近的马纳多湾。自20世纪80年代以来，这里便开始受到世界各地潜水爱好者的关注，并于1991年正式被指定为国家公园，以保护其美丽的海洋景观和丰富的海洋生物多样性。</p><p style=\"text-align:justify;\">布纳肯拥有多个主要岛屿，包括布纳肯岛、马纳多图阿岛、锡拉登岛、曼特哈格岛和奈恩岛，四周环绕着清澈透明的海水和迷人的热带风光。布纳肯最大的特色在于其丰富的海底生态系统。这里拥有数百种珊瑚和数千种色彩斑斓的热带鱼类，其中包括海龟、拿破仑鱼以及许多独特的海洋生物。</p><p style=\"text-align:justify;\">布纳肯还因其壮观的垂直珊瑚峭壁（Wall Diving）而闻名，这些珊瑚墙可向海底延伸数十米，因此被认为是世界最佳潜水地点之一。对于不想深潜的游客来说，浮潜也是非常受欢迎的活动，因为这里的海水极其清澈，即使在水面上也能清楚地看到鱼儿和珊瑚礁。</p><p style=\"text-align:justify;\">与此同时，对于热爱冒险的人来说，在布纳肯潜水将带来难忘的体验：探索广阔的珊瑚花园、邂逅各种海洋生物，并欣赏壮丽的海底景观。凭借其优美的自然环境、丰富的海洋生物以及宁静的热带氛围，布纳肯已成为吸引世界各地游客的重要旅游胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/gwJ4FknCDMXz0r70NDVaBXOyV49kktHyc9EjbYVP.png', 1, 1, '2026-04-11 09:47:40', '2026-05-13 08:05:30');
INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(31, 'guide', NULL, 'KLENTENG BAN HIN KIONGK', 'Chinese Temple Ban Hin Kiong', '반힌키옹 사원', '万兴宫', '<p style=\"text-align:justify;\">Klenteng Ban Hin Kiong adalah klenteng tertua dan paling terkenal di kota Manado, provinsi Sulawesi Utara. Klenteng ini terletak di kawasan pecinan Manado dan menjadi pusat kegiatan keagamaan serta budaya bagi masyarakat Tionghoa di daerah tersebut.&nbsp;</p><p style=\"text-align:justify;\">Nama Ban Hin Kiong sendiri memiliki arti Istana Berkah Surgawi, yang melambangkan harapan akan keberkahan dan perlindungan dari para dewa. Klenteng ini didirikan sekitar awal abad ke-19, sekitar tahun 1817, oleh komunitas Tionghoa yang tinggal di Manado.&nbsp;</p><p style=\"text-align:justify;\">Awalnya bangunan klenteng dibuat secara sederhana dari kayu dan bambu. Seiring berjalannya waktu, klenteng ini beberapa kali mengalami renovasi dan pembangunan kembali, terutama setelah mengalami kerusakan akibat kebakaran pada masa lalu. Namun hingga sekarang, Klenteng Ban Hin Kiong tetap berdiri megah dan menjadi simbol penting sejarah serta keberadaan masyarakat Tionghoa di Manado.&nbsp;</p><p style=\"text-align:justify;\">Di dalam klenteng ini terdapat berbagai altar pemujaan bagi dewa-dewi dalam kepercayaan Taoisme dan Buddha. Klenteng ini juga menjadi pusat perayaan berbagai festival besar seperti Tahun Baru Imlek dan Cap Go Meh, di mana ribuan masyarakat dan wisatawan datang untuk menyaksikan berbagai pertunjukan budaya seperti barongsai dan ritual keagamaan.&nbsp;</p><p style=\"text-align:justify;\">Dengan arsitektur tradisional Tiongkok yang indah serta nilai sejarah yang kuat, Klenteng Ban Hin Kiong menjadi salah satu tempat wisata budaya dan religi yang menarik untuk dikunjungi di Manado.</p>', '<p style=\"text-align:justify;\">Klenteng Ban Hin Kiong is the oldest and most famous Chinese temple in the city of Manado, located in North Sulawesi. The temple is situated in Manado’s Chinatown area and serves as an important center of religious and cultural activities for the local Chinese community.</p><p style=\"text-align:justify;\">The name Ban Hin Kiong itself means “Palace of Heavenly Blessings,” symbolizing hopes for blessings and protection from the gods. The temple was established around the early 19th century, approximately in 1817, by the Chinese community living in Manado.</p><p style=\"text-align:justify;\">Originally, the temple was built simply using wood and bamboo. Over time, it underwent several renovations and reconstructions, especially after suffering damage from fires in the past. Nevertheless, Ban Hin Kiong Temple still stands magnificently today and remains an important symbol of the history and presence of the Chinese community in Manado.</p><p style=\"text-align:justify;\">Inside the temple are various altars dedicated to deities in Taoist and Buddhist beliefs. The temple also becomes the center of major celebrations such as Chinese New Year and Cap Go Meh, where thousands of local residents and tourists gather to enjoy cultural performances like lion dances and religious rituals.</p><p style=\"text-align:justify;\">With its beautiful traditional Chinese architecture and strong historical value, Ban Hin Kiong Temple has become one of the most attractive cultural and religious tourist destinations in Manado.</p>', '<p style=\"text-align:justify;\">Klenteng Ban Hin Kiong은 Manado 시에서 가장 오래되고 가장 유명한 사원으로, North Sulawesi 주에 위치해 있습니다. 이 사원은 마나도의 차이나타운 지역에 자리하고 있으며, 현지 화교 사회의 종교 및 문화 활동의 중심지 역할을 하고 있습니다.</p><p style=\"text-align:justify;\">반힌키옹(Ban Hin Kiong)이라는 이름은 “천상의 축복의 궁전”이라는 의미를 가지고 있으며, 신들의 축복과 보호를 바라는 희망을 상징합니다. 이 사원은 1817년경, 마나도에 거주하던 화교 공동체에 의해 세워졌습니다.</p><p style=\"text-align:justify;\">초기의 사원 건물은 나무와 대나무로 소박하게 지어졌습니다. 시간이 흐르면서 여러 차례 보수와 재건이 이루어졌으며, 특히 과거 화재로 인한 피해 이후 복원 작업이 진행되었습니다. 그럼에도 불구하고 반힌키옹 사원은 오늘날까지 웅장하게 남아 있으며, 마나도 화교 사회의 역사와 존재를 상징하는 중요한 장소로 자리하고 있습니다.</p><p style=\"text-align:justify;\">사원 내부에는 도교와 불교 신앙의 여러 신들을 모시는 제단들이 마련되어 있습니다. 또한 이곳은 음력설과 캡고메(Cap Go Meh) 같은 대규모 축제의 중심지로, 수천 명의 지역 주민과 관광객들이 사자춤 공연과 종교 의식을 보기 위해 방문합니다.</p><p style=\"text-align:justify;\">아름다운 중국 전통 건축양식과 깊은 역사적 가치를 지닌 반힌키옹 사원은 마나도의 대표적인 문화 및 종교 관광지 중 하나입니다.</p>', '<p style=\"text-align:justify;\">Klenteng Ban Hin Kiong 是位于印度尼西亚North Sulawesi省Manado市最古老、最著名的华人庙宇。这座庙宇位于马纳多唐人街地区，是当地华人社区宗教与文化活动的重要中心。</p><p style=\"text-align:justify;\">“Ban Hin Kiong” 的意思是“天赐福宫”，象征着对神明赐福与庇佑的祈愿。该庙宇大约建于19世纪初，即1817年前后，由居住在马纳多的华人社区建立。</p><p style=\"text-align:justify;\">最初，庙宇仅以木材和竹子简单建成。随着时间推移，庙宇经历了多次翻修和重建，特别是在过去遭遇火灾损坏之后。然而直到今天，Ban Hin Kiong 依然庄严宏伟地矗立着，成为马纳多华人历史与文化的重要象征。</p><p style=\"text-align:justify;\">庙内设有多个供奉道教与佛教神明的祭坛。同时，这里也是春节和元宵节（Cap Go Meh）等大型庆典活动的中心，每年都会吸引成千上万的居民与游客前来观赏舞狮表演及宗教仪式。</p><p style=\"text-align:justify;\">凭借精美的中国传统建筑风格以及深厚的历史价值，Ban Hin Kiong 庙已成为马纳多最具吸引力的文化与宗教旅游景点之一。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/uUQXz4NjQRviF2fyjKoR8Z4PLhRKtCbKlblSAqin.jpg', 9, 1, '2026-04-11 09:47:40', '2026-05-14 15:11:56'),
(32, 'guide', NULL, 'DANAU LINOW', 'Linow Lake', '리노우 호수', '利诺湖', '<p style=\"text-align:justify;\">Danau Linow adalah salah satu destinasi wisata alam yang unik dan menakjubkan di Tomohon, tidak jauh dari kota Manado di provinsi Sulawesi Utara. Danau ini terkenal karena fenomena alamnya yang sangat menarik, yaitu warna air danau yang dapat berubah-ubah.&nbsp;</p><p style=\"text-align:justify;\">Dalam kondisi tertentu, air danau dapat terlihat berwarna biru, hijau, hingga kecokelatan, tergantung pada kandungan mineral, pantulan cahaya matahari, dan aktivitas vulkanik di sekitarnya. Danau Linow terbentuk dari aktivitas vulkanik gunung berapi di wilayah tersebut, sehingga di beberapa bagian danau pengunjung dapat melihat uap panas dan aroma belerang yang keluar dari permukaan air.&nbsp;</p><p style=\"text-align:justify;\">Fenomena ini menjadikan Danau Linow sebagai salah satu danau vulkanik yang unik di Indonesia. Selain keindahan alamnya, tempat ini juga menjadi lokasi favorit wisatawan untuk bersantai, menikmati pemandangan, dan berfoto. Di sekitar danau terdapat area kafe dan tempat duduk yang memungkinkan pengunjung menikmati panorama danau sambil menyeruput kopi atau teh hangat.&nbsp;</p><p style=\"text-align:justify;\">Dengan latar belakang pegunungan yang hijau, udara sejuk khas Tomohon, serta pemandangan danau yang eksotis, Danau Linow menjadi destinasi yang sangat menarik dan wajib dikunjungi ketika berada di Sulawesi Utara</p>', '<p style=\"text-align:justify;\">Danau Linow is one of the most unique and breathtaking natural tourist destinations in Tomohon, located not far from Manado in North Sulawesi. The lake is famous for its fascinating natural phenomenon where the color of the water changes over time.</p><p style=\"text-align:justify;\">Under certain conditions, the lake water can appear blue, green, or even brownish, depending on the mineral content, sunlight reflection, and volcanic activity around the area. Lake Linow was formed through volcanic activity from the surrounding volcanoes, and in some parts of the lake visitors can see hot steam and smell sulfur rising from the water’s surface.</p><p style=\"text-align:justify;\">This phenomenon makes Lake Linow one of the most unique volcanic lakes in Indonesia. Besides its natural beauty, the place is also a favorite destination for visitors to relax, enjoy the scenery, and take photographs. Around the lake, there are cafés and seating areas where visitors can admire the panoramic view while enjoying a warm cup of coffee or tea.</p><p style=\"text-align:justify;\">With its green mountain backdrop, cool Tomohon air, and exotic lake scenery, Lake Linow is a truly attractive destination and a must-visit place when traveling in North Sulawesi.</p>', '<p style=\"text-align:justify;\">Danau Linow는 North Sulawesi의 Tomohon에 위치한 매우 독특하고 아름다운 자연 관광지로, Manado에서 멀지 않은 곳에 있습니다. 이 호수는 물의 색이 변화하는 신비로운 자연 현상으로 유명합니다.</p><p style=\"text-align:justify;\">특정한 조건에서는 호수의 물빛이 파란색, 초록색, 또는 갈색으로 보이기도 하는데, 이는 광물 성분, 햇빛의 반사, 그리고 주변 화산 활동의 영향 때문입니다. 리노우 호수는 이 지역의 화산 활동으로 형성된 화산호이며, 일부 지역에서는 뜨거운 수증기와 유황 냄새가 수면 위로 올라오는 모습을 볼 수 있습니다.</p><p style=\"text-align:justify;\">이러한 현상 덕분에 리노우 호수는 인도네시아에서 가장 독특한 화산호 중 하나로 알려져 있습니다. 아름다운 자연경관뿐만 아니라, 이곳은 휴식을 취하고 풍경을 감상하며 사진을 찍기 좋은 장소로도 많은 관광객들에게 사랑받고 있습니다. 호수 주변에는 카페와 휴식 공간이 마련되어 있어 방문객들은 따뜻한 커피나 차를 마시며 아름다운 호수 전경을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">푸른 산을 배경으로 한 아름다운 풍경, 토모혼 특유의 시원한 공기, 그리고 이국적인 호수의 모습은 리노우 호수를 북술라웨시에서 꼭 방문해야 할 매력적인 여행지로 만들어 줍니다.</p>', '<p style=\"text-align:justify;\">Danau Linow 是位于印度尼西亚North Sulawesi省Tomohon的一处独特而迷人的自然旅游景点，距离Manado市不远。该湖最著名的特点是湖水颜色会不断变化的自然现象。</p><p style=\"text-align:justify;\">在不同条件下，湖水可能呈现蓝色、绿色甚至棕色，这取决于湖中的矿物质含量、阳光反射以及周围的火山活动。Linow 湖是由当地火山活动形成的火山湖，因此在湖的部分区域，游客还可以看到热气从水面升起，并闻到硫磺的气味。</p><p style=\"text-align:justify;\">这一独特现象使 Linow 湖成为印度尼西亚最特别的火山湖之一。除了迷人的自然景观外，这里也是游客放松身心、欣赏风景和拍照打卡的热门地点。湖边设有咖啡馆和休息区，游客可以一边欣赏湖景，一边享用热咖啡或热茶。</p><p style=\"text-align:justify;\">翠绿的群山背景、Tomohon 凉爽宜人的空气，以及充满异国风情的湖泊景色，使 Linow 湖成为来到北苏拉威西时不可错过的旅游胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/Xl3AEzjoJ4SMHnf76b4cIFpEopqJkKbaLcGETCEq.jpg', 14, 1, '2026-04-11 09:47:41', '2026-05-15 01:54:26'),
(33, 'guide', NULL, 'CAGAR ALAM TANGKOKO', 'Tangkoko Nature Reserve', '탕코코 자연보호구역', '坦科科自然保护区', '<p style=\"text-align:justify;\">Cagar Alam Tangkoko Batuangus adalah kawasan konservasi hutan tropis di Sulawesi Utara yang terkenal dengan keanekaragaman hayati dan satwa endemik. Lokasinya berada di dekat Kota Bitung dan menjadi salah satu destinasi wisata alam dan penelitian penting di Indonesia.</p><p style=\"text-align:justify;\">Cagar alam ini menjadi habitat bagi berbagai satwa khas Sulawesi seperti tarsius (primata terkecil di dunia), monyet hitam Sulawesi (yaki), babirusa, burung rangkong, serta berbagai jenis burung dan reptil endemik lainnya. Tangkoko berperan penting dalam pelestarian ekosistem hutan dan satwa langka.</p>', '<p style=\"text-align:justify;\">Cagar Alam Tangkoko Batuangus is a tropical forest conservation area in North Sulawesi, Indonesia, known for its rich biodiversity and endemic wildlife. Located near Bitung City, it is an important destination for eco-tourism and scientific research.</p><p style=\"text-align:justify;\">The reserve is home to unique species such as the tarsier (the world’s smallest primate), the Sulawesi crested macaque (yaki), babirusa, hornbills, and various endemic birds and reptiles. Tangkoko plays a vital role in protecting forest ecosystems and endangered wildlife.</p>', '<p style=\"text-align:justify;\">탕코코 자연보호구역 바투앙구스는 인도네시아 북술라웨시에 위치한 열대림 보호구역으로, 풍부한 생물 다양성과 고유 야생동물로 유명합니다. 비퉁 시 인근에 위치하며 생태 관광과 연구의 중요한 장소입니다.</p><p style=\"text-align:justify;\">이 보호구역에는 세계에서 가장 작은 영장류인 타르시어, 술라웨시 검은원숭이(야키), 바비루사, 뿔새, 그리고 다양한 조류와 파충류가 서식합니다. 탕코코는 희귀 야생동물과 숲 생태계 보전에 중요한 역할을 합니다.</p>', '<p style=\"text-align:justify;\">Tangkoko Batuangus自然保护区是位于印度尼西亚北苏拉威西的热带森林保护区，以丰富的生物多样性和特有野生动物而闻名。它靠近比通市，是重要的生态旅游和科研目的地。</p><p style=\"text-align:justify;\">该保护区栖息着多种特有物种，如世界上最小的灵长类动物——眼镜猴、苏拉威西黑猕猴（雅基）、鹿豚、犀鸟以及多种特有鸟类和爬行动物。塘科科在保护森林生态系统和濒危物种方面发挥着重要作用。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/t5UoYI2HMvNrM4zJ3Dhlajx3dSOTBEe1He3kJVeG.png', 21, 1, '2026-04-11 09:47:41', '2026-05-20 06:11:52'),
(34, 'guide', NULL, 'DANAU TONDANO', 'Tondano Lake', '톤다노 호수', '通达诺湖', '<p style=\"text-align:justify;\">Danau Tondano adalah danau terbesar di Provinsi Sulawesi Utara yang terletak di Kabupaten Minahasa, sekitar 35–36 km dari Kota Manado pada ketinggian sekitar 600 meter di atas permukaan laut. Danau ini memiliki luas sekitar 4.200 hektare dan dikelilingi oleh pegunungan seperti Gunung Lembean, Kaweng, Tampusu, dan Masarang.</p><p style=\"text-align:justify;\">Secara geologis, Danau Tondano terbentuk dari kaldera gunung berapi purba akibat letusan besar jutaan tahun lalu yang membentuk cekungan luas di wilayah Minahasa. Cekungan tersebut kemudian terisi air dan menjadi danau yang dikenal sekarang.</p><p style=\"text-align:justify;\">Sejak dahulu, Danau Tondano memiliki peran penting bagi masyarakat sekitar sebagai sumber air, tempat perikanan, pertanian, serta jalur kehidupan masyarakat Minahasa. Saat ini, danau ini juga menjadi salah satu destinasi wisata alam terkenal di Sulawesi Utara dengan pemandangan pegunungan dan desa-desa di sekitarnya.</p>', '<p style=\"text-align:justify;\">Lake Tondano is the largest lake in North Sulawesi, located in Minahasa Regency about 35–36 km from Manado at an elevation of around 600 meters above sea level. The lake covers approximately 4,200 hectares and is surrounded by mountains such as Mount Lembean, Kaweng, Tampusu, and Masarang.</p><p style=\"text-align:justify;\">Geologically, Lake Tondano was formed from an ancient volcanic caldera created by a massive eruption millions of years ago. The large basin produced by this eruption gradually filled with water, forming the lake that exists today.</p><p style=\"text-align:justify;\">Historically, the lake has been an important natural resource for the Minahasa community, supporting fishing, agriculture, and local livelihoods. Today, it is also a popular nature tourism destination known for its scenic landscapes and surrounding villages.</p>', '<p style=\"text-align:justify;\">톤다노 호수는 인도네시아 북술라웨시 미나하사 지역에 위치한 가장 큰 호수로, 마나도에서 약 35~36km 떨어져 있으며 해발 약 600m 높이에 있습니다. 호수의 면적은 약 4,200헥타르이며 렘베안산, 카웽산, 탐푸수산, 마사랑산 등 여러 산으로 둘러싸여 있습니다.</p><p style=\"text-align:justify;\">지질학적으로 이 호수는 수백만 년 전 거대한 화산 폭발로 형성된 칼데라에서 만들어졌습니다. 이 화산 분화로 생긴 넓은 분지가 물로 채워지면서 현재의 톤다노 호수가 형성되었습니다.</p><p style=\"text-align:justify;\">톤다노 호수는 오래전부터 미나하사 지역 주민들의 어업, 농업, 생활에 중요한 역할을 해 왔으며, 오늘날에는 아름다운 자연 경관을 가진 관광지로도 유명합니다.</p>', '<p style=\"text-align:justify;\">托纳多湖位于印度尼西亚北苏拉威西省米纳哈萨地区，是该省最大的湖泊，距离马纳多约35–36公里，海拔约600米。湖泊面积约4,200公顷，四周被伦贝安山、卡文山、坦普苏山和马萨朗山等群山环绕。</p><p style=\"text-align:justify;\">从地质角度看，托纳多湖形成于数百万年前一次巨大的火山喷发所形成的火山口盆地（卡尔德拉）。随着时间推移，这个盆地逐渐积水，最终形成了今天的湖泊。</p><p style=\"text-align:justify;\">历史上，该湖一直是米纳哈萨地区居民的重要自然资源，为渔业、农业和当地生活提供支持。如今，它也是北苏拉威西著名的自然旅游景点之一。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/8RsKFXPBRpd0sSOvmSRr9LleSdhFZJpO9hH9yKgJ.jpg', 19, 1, '2026-04-11 09:47:41', '2026-05-20 06:02:22'),
(35, 'guide', NULL, 'AIR TERJUN TUNAN', 'Waterfall Tunan', '투난 폭포', '图南瀑布', '<p style=\"text-align:justify;\">Air Terjun Tunan adalah salah satu air terjun yang paling indah di Sulawesi Utara, terletak di desa Talawaan tidak jauh dari kota Manado. Air terjun ini berada di tengah kawasan hutan yang masih alami, sehingga pengunjung dapat merasakan suasana alam yang sangat segar, tenang, dan menenangkan. Air Terjun Tunan memiliki ketinggian sekitar 80 meter, dengan aliran air yang jatuh deras dari tebing batu yang tinggi dan dikelilingi pepohonan hijau yang rimbun.&nbsp;</p><p style=\"text-align:justify;\">Pemandangan ini menciptakan panorama alam yang sangat menakjubkan dan menjadi salah satu spot favorit bagi pecinta alam dan fotografer. Untuk mencapai air terjun ini, pengunjung perlu berjalan kaki melalui jalur hutan yang asri. Sepanjang perjalanan, wisatawan akan menikmati suara alam, udara segar, serta pemandangan hutan tropis yang indah. Ketika tiba di lokasi, pengunjung dapat merasakan percikan air yang menyegarkan serta menikmati keindahan air terjun dari dekat.&nbsp;</p><p style=\"text-align:justify;\">Dengan suasana yang masih alami, pemandangan yang spektakuler, serta udara yang sejuk, Air Terjun Tunan menjadi destinasi yang sempurna bagi wisatawan yang ingin merasakan petualangan alam dan menikmati keindahan tersembunyi di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Air Terjun Tunan is one of the most beautiful waterfalls in North Sulawesi, located in the village of Talawaan not far from Manado. The waterfall is surrounded by a pristine natural forest, allowing visitors to experience a fresh, peaceful, and calming atmosphere.</p><p style=\"text-align:justify;\">Tunan Waterfall has a height of approximately 80 meters, with powerful streams of water cascading down steep rocky cliffs surrounded by lush green trees. This scenery creates a truly breathtaking natural panorama and makes the waterfall a favorite destination for nature lovers and photographers.</p><p style=\"text-align:justify;\">To reach the waterfall, visitors need to walk through a beautiful forest trail. Along the journey, travelers can enjoy the sounds of nature, fresh mountain air, and the beauty of the tropical forest scenery. Upon arriving at the site, visitors can feel the refreshing mist of the waterfall and admire its beauty up close.</p><p style=\"text-align:justify;\">With its untouched natural atmosphere, spectacular scenery, and cool fresh air, Tunan Waterfall is a perfect destination for travelers who want to experience nature adventures and discover the hidden beauty of North Sulawesi.</p>', '<p style=\"text-align:justify;\">Air Terjun Tunan은 North Sulawesi에서 가장 아름다운 폭포 중 하나로, Manado에서 멀지 않은 Talawaan 마을에 위치해 있습니다. 이 폭포는 자연 그대로의 숲 한가운데에 자리하고 있어 방문객들은 매우 상쾌하고 평화로우며 편안한 자연의 분위기를 느낄 수 있습니다.</p><p style=\"text-align:justify;\">투난 폭포는 약 80미터 높이로, 거대한 물줄기가 높은 바위 절벽 아래로 힘차게 떨어지며 주변은 울창한 초록빛 나무들로 둘러싸여 있습니다. 이러한 풍경은 매우 아름다운 자연 파노라마를 만들어내며 자연 애호가와 사진작가들에게 인기 있는 명소가 되고 있습니다.</p><p style=\"text-align:justify;\">폭포에 도착하기 위해서는 아름다운 숲길을 따라 걸어가야 합니다. 여행 중에는 자연의 소리, 신선한 공기, 그리고 아름다운 열대우림 풍경을 즐길 수 있습니다. 현장에 도착하면 시원한 물안개를 느끼며 가까이에서 폭포의 웅장한 아름다움을 감상할 수 있습니다.</p><p style=\"text-align:justify;\">자연 그대로의 분위기와 장엄한 풍경, 시원한 공기를 갖춘 투난 폭포는 자연 속 모험을 즐기고 북술라웨시의 숨겨진 아름다움을 경험하고 싶은 여행객들에게 완벽한 여행지입니다.</p>', '<p style=\"text-align:justify;\">Air Terjun Tunan 是印度尼西亚North Sulawesi最美丽的瀑布之一，位于距离Manado不远的 Talawaan 村。瀑布坐落在一片原始森林之中，游客可以感受到清新、宁静且令人放松的大自然氛围。</p><p style=\"text-align:justify;\">Tunan 瀑布高约80米，湍急的水流从高耸的岩石峭壁飞流直下，周围环绕着茂密翠绿的树林。这样的景观形成了令人惊叹的自然全景，也使这里成为大自然爱好者和摄影师最喜爱的地点之一。</p><p style=\"text-align:justify;\">前往瀑布需要穿过一条优美的森林步道。沿途游客可以聆听大自然的声音，呼吸新鲜空气，并欣赏美丽的热带雨林景色。当到达瀑布时，游客能够感受到清凉的水雾，并近距离欣赏瀑布壮观的美景。</p><p style=\"text-align:justify;\">凭借原始自然的环境、壮丽的景观以及凉爽清新的空气，Tunan 瀑布成为喜爱自然探险、探索北苏拉威西隐藏之美游客的理想旅游目的地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/YvqlK2kJOnPeFT3UtNb4NNuvzrzV51U8yrlLJZrW.jpg', 11, 1, '2026-04-11 09:47:41', '2026-05-15 01:30:21'),
(36, 'guide', NULL, 'PAGODA EKAYANA', 'Pagoda Ekayana', '에카야나 탑', '一乘宝塔', 'Pagoda Ekayana Tomohon adalah salah satu tempat wisata religi dan budaya yang sangat menarik di kota Tomohon, provinsi Sulawesi Utara. Pagoda ini dikenal sebagai salah satu pagoda Buddha terbesar dan paling indah di wilayah Indonesia timur, dengan arsitektur yang megah dan penuh warna khas budaya Tiongkok.\n\nPagoda ini memiliki beberapa tingkat bangunan dengan atap bertingkat yang dihiasi ornamen tradisional serta warna merah dan emas yang mencolok, melambangkan keberuntungan dan kemakmuran. Di dalam kawasan pagoda terdapat berbagai patung Buddha serta tempat ibadah yang digunakan oleh umat Buddha untuk berdoa dan melakukan meditasi.\n\nSelain sebagai tempat ibadah, Pagoda Ekayana juga menjadi destinasi wisata yang populer bagi wisatawan yang ingin menikmati keindahan arsitektur, belajar tentang budaya Buddha, serta mengambil foto dengan latar belakang bangunan yang sangat indah. Dari area sekitar pagoda, pengunjung juga dapat menikmati suasana kota Tomohon yang sejuk dengan pemandangan alam yang menenangkan.\n\nDengan perpaduan antara nilai spiritual, arsitektur yang megah, serta suasana yang damai, Pagoda Ekayana Tomohon menjadi salah satu tempat yang sangat menarik untuk dikunjungi ketika berada di Sulawesi Utara.', 'Pagoda Ekayana Tomohon is one of the most beautiful religious and cultural attractions in the city of Tomohon, located in Sulawesi Utara, Indonesia. The pagoda is known as one of the largest and most impressive Buddhist pagodas in eastern Indonesia, featuring magnificent architecture inspired by traditional Chinese design.\n\nThe pagoda has multiple levels with tiered roofs decorated with traditional ornaments and bright red and gold colors, which symbolize prosperity and good fortune. Within the complex, visitors can find several Buddha statues and prayer halls used by Buddhists for worship and meditation.\n\nBesides serving as a place of worship, Ekayana Pagoda is also a popular destination for tourists who wish to admire its beautiful architecture, learn about Buddhist culture, and take memorable photographs with the impressive pagoda as a backdrop. The surrounding area also offers a peaceful atmosphere and the cool climate of Tomohon.\n\nWith its combination of spiritual value, stunning architecture, and tranquil surroundings, Pagoda Ekayana Tomohon is a fascinating place to visit while exploring North Sulawesi.', 'Pagoda Ekayana Tomohon은 인도네시아 Sulawesi Utara의 Tomohon에 위치한 매우 아름다운 불교 사원 중 하나로, 종교적·문화적 관광지로도 유명합니다. 이 파고다는 중국 전통 건축 양식에서 영감을 받은 웅장한 구조로 동부 인도네시아에서 가장 인상적인 불교 건축물 중 하나로 알려져 있습니다.\n\n이 파고다는 여러 층으로 이루어져 있으며, 층층이 올라가는 지붕과 화려한 장식이 특징입니다. 특히 붉은색과 금색의 색상은 행운과 번영을 상징합니다. 사원 내부에는 다양한 불상과 기도 공간이 있어 불교 신자들이 기도와 명상을 할 수 있는 장소로 사용됩니다.\n\n또한 이곳은 관광객들에게도 인기 있는 장소로, 아름다운 건축물을 감상하고 불교 문화를 체험하며 사진을 찍기에 좋은 곳입니다. 주변에는 시원한 공기와 평화로운 분위기의 톰혼 도시 풍경도 함께 즐길 수 있습니다.\n\n영적인 의미와 아름다운 건축, 그리고 평화로운 환경이 어우러진 Ekayana 파고다는 북술라웨시에서 꼭 방문해 볼 만한 매력적인 관광지입니다.', 'Pagoda Ekayana Tomohon 是位于印度尼西亚 Sulawesi Utara Tomohon 的一座非常著名的佛教寺庙，也是当地重要的宗教与文化旅游景点之一。这座宝塔以其宏伟的建筑和浓厚的中国传统风格而闻名，被认为是印度尼西亚东部最美丽的佛教建筑之一。\n\n宝塔由多层结构组成，屋顶层层叠叠，并装饰着传统的中国式装饰。整座建筑以红色和金色为主色调，这两种颜色象征着好运、繁荣与幸福。在寺庙内部，游客可以看到多尊佛像以及供信徒祈祷和冥想的礼佛空间。\n\n除了宗教功能之外，Ekayana 宝塔也吸引了许多游客前来参观。游客可以欣赏精美的建筑设计，了解佛教文化，并在壮观的宝塔前拍照留念。这里宁静的环境以及 Tomohon 凉爽的气候也让游客能够享受轻松愉快的旅行体验。\n\n凭借其精神意义、壮丽的建筑以及宁静的氛围，Ekayana 宝塔已经成为北苏拉威西非常值得参观的旅游景点之一', NULL, 15, 1, '2026-04-11 09:47:41', '2026-04-27 08:40:37'),
(37, 'guide', NULL, 'MAKATETE HILLS', 'Makatete Hills', '마카테테 힐스', '马卡特特山', '<p style=\"text-align:justify;\">Makatete Hills adalah salah satu destinasi wisata alam yang indah yang terletak di desa Warembungan, tidak jauh dari kota Manado di provinsi Sulawesi Utara. Tempat ini terkenal dengan pemandangan perbukitan hijau yang luas serta udara pegunungan yang sejuk dan menyegarkan.&nbsp;</p><p style=\"text-align:justify;\">Dari puncak Makatete Hills, pengunjung dapat menikmati panorama yang sangat menakjubkan. Dari tempat ini terlihat kota Manado yang membentang luas, laut biru yang indah, serta siluet megah dari Pulau Manado Tua di kejauhan. Kombinasi antara pemandangan kota, laut, dan pegunungan menciptakan panorama alam yang sangat memukau dan menjadi spot favorit bagi wisatawan untuk berfoto. Salah satu momen paling istimewa di Makatete Hills adalah saat matahari terbenam (sunset).&nbsp;</p><p style=\"text-align:justify;\">Ketika matahari perlahan tenggelam di balik laut dan perbukitan, langit akan berubah menjadi warna jingga, merah, dan keemasan yang sangat indah. Suasana yang tenang, udara segar, serta pemandangan alam yang spektakuler membuat Makatete Hills menjadi tempat yang sempurna untuk bersantai dan menikmati keindahan alam Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Makatete Hills is one of the beautiful natural tourist destinations located in the village of Warembungan, not far from Manado in North Sulawesi. This place is well known for its vast green hills and cool, refreshing mountain air.</p><p style=\"text-align:justify;\">From the top of Makatete Hills, visitors can enjoy a truly breathtaking panorama. From this viewpoint, you can see the wide expanse of Manado city, the beautiful blue sea, and the majestic silhouette of Manado Tua Island in the distance. The combination of city views, ocean scenery, and mountain landscapes creates a stunning natural panorama and makes this place a favorite photo spot for tourists.</p><p style=\"text-align:justify;\">One of the most special moments at Makatete Hills is during sunset. As the sun slowly sets behind the sea and hills, the sky transforms into beautiful shades of orange, red, and gold. The peaceful atmosphere, fresh air, and spectacular scenery make Makatete Hills a perfect place to relax and enjoy the natural beauty of North Sulawesi.</p><h2 style=\"text-align:justify;\">한국어 (Korean)</h2>', '<p style=\"text-align:justify;\">Makatete Hills는 North Sulawesi의 Manado 근처 Warembungan 마을에 위치한 아름다운 자연 관광지 중 하나입니다. 이곳은 넓게 펼쳐진 푸른 언덕과 시원하고 상쾌한 산 공기로 유명합니다.</p><p style=\"text-align:justify;\">마카테테 힐스 정상에서는 정말 놀라운 파노라마 풍경을 감상할 수 있습니다. 이곳에서는 넓게 펼쳐진 마나도 시내, 아름다운 푸른 바다, 그리고 멀리 보이는 웅장한 Manado Tua 섬의 실루엣을 한눈에 볼 수 있습니다. 도시 풍경, 바다, 산의 조화는 매우 아름다운 자연 경관을 만들어내며, 관광객들에게 인기 있는 사진 촬영 명소가 되고 있습니다.</p><p style=\"text-align:justify;\">마카테테 힐스에서 가장 특별한 순간 중 하나는 일몰 시간입니다. 해가 바다와 언덕 뒤로 천천히 지면서 하늘은 주황색, 붉은색, 황금빛으로 물들어 매우 아름다운 풍경을 만들어냅니다. 평화로운 분위기와 신선한 공기, 그리고 장엄한 자연 풍경은 마카테테 힐스를 휴식과 함께 북술라웨시의 아름다움을 즐기기에 완벽한 장소로 만들어 줍니다.</p>', '<p style=\"text-align:justify;\">Makatete Hills 是位于印度尼西亚North Sulawesi省、靠近Manado市 Warembungan 村的一处美丽自然旅游景点。这里以广阔翠绿的山丘以及凉爽清新的山间空气而闻名。</p><p style=\"text-align:justify;\">站在 Makatete Hills 的山顶，游客可以欣赏到令人惊叹的全景风光。从这里可以俯瞰广阔的马纳多市区、美丽的蓝色海洋，以及远处雄伟的Manado Tua岛轮廓。城市、海洋与山脉景观的完美结合，形成了极具魅力的自然全景，也使这里成为游客最喜爱的拍照打卡地点之一。</p><p style=\"text-align:justify;\">Makatete Hills 最特别的时刻之一就是日落时分。当太阳缓缓沉入海平面与群山之后，天空会变成绚丽的橙色、红色与金黄色，景色十分迷人。宁静的氛围、清新的空气以及壮丽的自然风光，使 Makatete Hills 成为放松身心、感受北苏拉威西自然之美的理想之地。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/lYTLQ2fRh6pDimjDl2PSiAhU5KUZT0nlepp3uCUo.webp', 10, 1, '2026-04-11 09:47:41', '2026-05-15 01:25:02'),
(38, 'guide', NULL, 'Patung Yesus (Pulau Lembeh)', 'Statue of Jesus (Lembeh)', '예수 동상 (렘베)', '耶稣雕像（蓝碧岛）', '<p style=\"text-align:justify;\">Patung Yesus Pulau Lembeh merupakan salah satu ikon religi dan wisata yang menarik di Pulau Lembeh, sebuah pulau indah yang terletak di dekat kota Bitung, North Sulawesi. Patung ini berdiri megah menghadap laut, seolah menyambut dan memberkati setiap orang yang datang ke Pulau Lembeh.</p><p style=\"text-align:justify;\">Dengan posisi tangan terbuka dan ekspresi yang tenang, patung Yesus ini menghadirkan suasana damai dan penuh keteduhan. Lokasinya yang berada di kawasan pesisir membuat pemandangan di sekitar patung terlihat sangat memukau. Hamparan laut biru yang luas, angin sepoi-sepoi, serta panorama pulau-pulau kecil di kejauhan menciptakan suasana yang menenangkan dan penuh keindahan alami.</p><p style=\"text-align:justify;\">Saat matahari terbit maupun terbenam, area sekitar patung menjadi semakin indah dengan cahaya keemasan yang menyinari laut dan langit. Banyak wisatawan datang untuk berfoto, menikmati suasana tenang, atau sekadar duduk menikmati keindahan alam Pulau Lembeh.</p><p style=\"text-align:justify;\">Selain menjadi simbol keagamaan, Patung Yesus Pulau Lembeh juga melambangkan harapan, kedamaian, dan keramahan masyarakat Sulawesi Utara. Dengan perpaduan antara nilai spiritual dan panorama alam tropis yang eksotis, tempat ini menjadi salah satu destinasi yang menarik untuk dikunjungi ketika berada di Bitung dan Pulau Lembeh.</p>', '<p style=\"text-align:justify;\">Patung Yesus Pulau Lembeh is one of the most fascinating religious and tourist landmarks on Pulau Lembeh, a beautiful island located near the city of Bitung in North Sulawesi. The statue stands majestically facing the sea, as if welcoming and blessing everyone who arrives on Lembeh Island.</p><p style=\"text-align:justify;\">With its open arms and peaceful expression, the statue creates a calm and comforting atmosphere. Its coastal location offers breathtaking scenery, featuring the vast blue ocean, gentle sea breeze, and beautiful views of small islands in the distance, creating a relaxing and naturally beautiful environment.</p><p style=\"text-align:justify;\">During sunrise and sunset, the area around the statue becomes even more stunning as golden light illuminates the sea and sky. Many visitors come to take photos, enjoy the peaceful surroundings, or simply relax while admiring the beauty of Lembeh Island.</p><p style=\"text-align:justify;\">Beyond its religious significance, the Jesus Statue of Lembeh Island also symbolizes hope, peace, and the warm hospitality of the people of North Sulawesi. Combining spiritual value with exotic tropical scenery, this destination has become one of the most attractive places to visit in Bitung and Lembeh Island.</p>', '<p style=\"text-align:justify;\">Patung Yesus Pulau Lembeh는 North Sulawesi의 Bitung 근처에 위치한 아름다운 섬인 Pulau Lembeh의 대표적인 종교 및 관광 명소 중 하나입니다. 이 동상은 바다를 향해 웅장하게 서 있으며, 마치 렘베 섬을 방문하는 모든 사람들을 환영하고 축복하는 듯한 모습을 보여줍니다.</p><p style=\"text-align:justify;\">두 팔을 활짝 펼치고 평온한 표정을 짓고 있는 이 예수상은 차분하고 평화로운 분위기를 만들어냅니다. 해안가에 위치해 있어 주변 풍경 또한 매우 아름다우며, 넓게 펼쳐진 푸른 바다와 시원한 바닷바람, 그리고 멀리 보이는 작은 섬들의 풍경이 어우러져 편안하고 아름다운 자연의 분위기를 선사합니다.</p><p style=\"text-align:justify;\">특히 일출과 일몰 시간에는 황금빛 햇살이 바다와 하늘을 비추며 주변 풍경을 더욱 아름답게 만듭니다. 많은 관광객들이 사진을 찍거나 조용한 분위기를 즐기며 렘베 섬의 아름다움을 감상하기 위해 이곳을 찾습니다.</p><p style=\"text-align:justify;\">종교적인 의미뿐만 아니라, 렘베 섬의 예수상은 희망과 평화, 그리고 북술라웨시 사람들의 따뜻한 환대의 상징이기도 합니다. 영적인 가치와 이국적인 열대 자연 풍경이 조화를 이루는 이곳은 비퉁과 렘베 섬에서 꼭 방문해야 할 매력적인 여행지 중 하나입니다.</p>', '<p style=\"text-align:justify;\">Patung Yesus Pulau Lembeh 是位于印度尼西亚North Sulawesi省、靠近Bitung市的Pulau Lembeh岛上一座极具吸引力的宗教与旅游地标。这座耶稣雕像面向大海庄严矗立，仿佛正在欢迎并祝福每一位来到 Lembeh 岛的游客。</p><p style=\"text-align:justify;\">雕像张开双臂，神情宁静祥和，为这里营造出平静而温暖的氛围。由于位于海边，周围景色十分迷人，辽阔的蓝色海洋、轻柔的海风，以及远处小岛的美丽景观，共同构成了令人放松的热带自然风光。</p><p style=\"text-align:justify;\">在日出和日落时分，金色阳光洒在海面与天空上，使雕像周围的景色更加壮丽迷人。许多游客来到这里拍照、享受宁静氛围，或静静欣赏 Lembeh 岛的自然之美。</p><p style=\"text-align:justify;\">除了宗教意义之外，Lembeh 岛的耶稣雕像也象征着希望、和平以及北苏拉威西人民的热情友好。融合了精神价值与异国热带海岛风光，这里已成为 Bitung 和 Lembeh 岛最值得一游的旅游景点之一。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/lf2cfZDVokZSGcNc4guG90KIpICZt7pfK5GehggZ.png', 23, 1, '2026-04-11 09:47:41', '2026-05-20 06:17:06'),
(39, 'guide', NULL, 'MONUMEN TRIKORA', 'Trikora Monument', '트리코라 기념비', '三角勋章纪念碑', '<p style=\"text-align:justify;\">Monumen Trikora Selat Lembeh terletak di kawasan Selat Lembeh, dekat Kota Bitung, Sulawesi Utara. Monumen ini dibangun untuk mengenang <strong>Operasi Trikora (Tri Komando Rakyat)</strong> yang dicanangkan Presiden Soekarno pada tahun 1961.</p><p style=\"text-align:justify;\">Operasi Trikora bertujuan untuk merebut kembali Irian Barat (Papua Barat) dari Belanda dan mengintegrasikannya ke dalam wilayah Indonesia. Monumen ini menjadi simbol perjuangan dan semangat persatuan bangsa Indonesia dalam mempertahankan kedaulatan negara.</p>', '<p style=\"text-align:justify;\">The Trikora Monument in Lembeh Strait is located near Bitung City, North Sulawesi. It was built to commemorate the <strong>Trikora Operation (People’s Triple Command)</strong> declared by President Sukarno in 1961.</p><p style=\"text-align:justify;\">The Trikora campaign aimed to reclaim West Irian (West Papua) from Dutch control and integrate it into Indonesia. The monument stands as a symbol of national struggle and unity in defending Indonesia’s sovereignty.</p>', '<p style=\"text-align:justify;\">렘베 해협의 트리코라 기념비는 북술라웨시 비퉁 인근에 위치해 있습니다. 이 기념비는 1961년 수카르노 대통령이 선포한 **트리코라 작전(국민 삼중 명령)**을 기념하기 위해 세워졌습니다.</p><p style=\"text-align:justify;\">트리코라 작전은 네덜란드로부터 서이리안(서파푸아)을 되찾아 인도네시아에 통합하는 것을 목표로 했습니다. 이 기념비는 국가 주권을 지키기 위한 투쟁과 단결의 상징입니다.</p>', '<p style=\"text-align:justify;\">伦贝海峡的特里科拉纪念碑位于北苏拉威西省比通附近。该纪念碑是为了纪念1961年苏加诺总统宣布的**特里科拉行动（三重人民指令）**而建立的。</p><p style=\"text-align:justify;\">特里科拉行动旨在从荷兰手中收回西伊里安（西巴布亚），并将其纳入印度尼西亚版图。该纪念碑象征着印尼人民维护国家主权的斗争与团结精神。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/lTNtfyOUNfRCcL94W0eMOWSTyyXa5xEDfw3HHmOq.png', 22, 1, '2026-04-11 09:47:41', '2026-05-20 06:15:55'),
(40, 'guide', NULL, 'BUKIT DOA MAHAWU / CHAPEL ALAMANDA', 'Alamanda Chapel', '알라만다 채플', '阿拉曼达教堂', '<p style=\"text-align:justify;\">Bukit Doa Mahawu merupakan salah satu destinasi wisata rohani dan alam yang menawan di Sulawesi Utara. Terletak di kawasan pegunungan yang sejuk dan asri, tempat ini menawarkan suasana damai yang sangat cocok untuk berdoa, refleksi diri, dan menikmati keindahan alam.</p><p style=\"text-align:justify;\">Bukit Doa Mahawu dikelilingi oleh hamparan hijau perbukitan, pepohonan rindang, dan udara segar khas pegunungan Tomohon. Dari kawasan ini, pengunjung dapat menikmati panorama alam yang indah dengan latar pegunungan dan langit biru yang menenangkan. Suasana tenang dan jauh dari keramaian membuat tempat ini menjadi lokasi favorit bagi wisatawan yang ingin mencari ketenangan hati dan kedamaian.</p><p style=\"text-align:justify;\">Salah satu daya tarik utama Bukit Doa Mahawu adalah bangunan kapel yang unik dan artistik, berdiri harmonis di tengah alam hijau. Desain arsitekturnya yang sederhana namun elegan menciptakan nuansa spiritual yang kuat sekaligus memanjakan mata para pengunjung. Tempat ini sering digunakan untuk kegiatan ibadah, retret rohani, hingga wisata religi.</p><p style=\"text-align:justify;\">Selain sebagai tempat doa dan refleksi, Bukit Doa Mahawu juga menjadi spot favorit untuk fotografi karena memiliki pemandangan alam yang sangat indah, terutama saat pagi dan sore hari. Cahaya matahari yang menyinari bukit hijau menciptakan panorama yang memukau dan memberikan pengalaman yang menenangkan bagi siapa saja yang datang berkunjung.</p>', '<p style=\"text-align:justify;\">Bukit Doa Mahawu is one of the most beautiful spiritual and nature tourism destinations in North Sulawesi. Located in a cool and peaceful mountainous area, this place offers a serene atmosphere that is perfect for prayer, self-reflection, and enjoying the beauty of nature.</p><p style=\"text-align:justify;\">Bukit Doa Mahawu is surrounded by lush green hills, shady trees, and the refreshing mountain air of Tomohon. From this area, visitors can enjoy breathtaking natural panoramas with mountain views and calming blue skies. The peaceful atmosphere, far away from the noise of the city, makes this place a favorite destination for those seeking inner peace and tranquility.</p><p style=\"text-align:justify;\">One of the main attractions of Bukit Doa Mahawu is its unique and artistic chapel, which stands harmoniously amid the green landscape. Its simple yet elegant architectural design creates a strong spiritual ambiance while also delighting visitors with its beauty. The place is often used for worship activities, spiritual retreats, and religious tourism.</p><p style=\"text-align:justify;\">Besides being a place for prayer and reflection, Bukit Doa Mahawu is also a favorite photography spot because of its stunning natural scenery, especially during sunrise and sunset. The sunlight shining across the green hills creates a mesmerizing panorama and offers a calming experience for everyone who visits.</p>', '<p style=\"text-align:justify;\">마하우 기도의 언덕은 북술라웨시에서 가장 아름다운 자연·종교 관광지 중 하나입니다. 시원하고 평화로운 산악 지역에 위치한 이곳은 기도와 자기 성찰, 그리고 자연의 아름다움을 즐기기에 완벽한 분위기를 제공합니다.</p><p style=\"text-align:justify;\">마하우 기도의 언덕은 푸른 언덕과 울창한 나무들, 그리고 토모혼 특유의 상쾌한 산 공기로 둘러싸여 있습니다. 방문객들은 이곳에서 산과 푸른 하늘이 어우러진 아름다운 자연 경관을 감상할 수 있습니다. 도시의 소음에서 벗어난 조용한 분위기는 마음의 평화와 안정을 찾는 사람들에게 매우 사랑받는 장소입니다.</p><p style=\"text-align:justify;\">이곳의 가장 큰 매력 중 하나는 자연 속에 조화롭게 자리 잡은 독특하고 예술적인 예배당입니다. 단순하면서도 우아한 건축 디자인은 깊은 영적인 분위기를 만들어내며 방문객들에게 아름다운 풍경을 선사합니다. 이곳은 예배, 영성 수련회, 종교 관광 장소로 자주 이용됩니다.</p><p style=\"text-align:justify;\">또한 마하우 기도의 언덕은 기도와 명상의 장소일 뿐만 아니라 아름다운 풍경 덕분에 사진 촬영 명소로도 유명합니다. 특히 아침과 저녁 시간대에는 햇빛이 초록빛 언덕을 비추며 환상적인 풍경을 만들어 방문객들에게 평온하고 특별한 경험을 선사합니다.</p>', '<p style=\"text-align:justify;\">马哈乌祈祷山是北苏拉威西最迷人的宗教与自然旅游景点之一。这里位于凉爽宁静的山区环境中，为游客提供了一个适合祈祷、沉思以及欣赏自然美景的平和氛围。</p><p style=\"text-align:justify;\">马哈乌祈祷山被翠绿的山丘、茂密的树木以及托莫洪清新的山间空气所环绕。游客可以在这里欣赏到壮丽的山景与宁静的蓝天全景。远离城市喧嚣的安静环境，使这里成为人们寻找内心平静与放松的理想之地。</p><p style=\"text-align:justify;\">马哈乌祈祷山最吸引人的特色之一，是那座独特而富有艺术感的小教堂，它与周围的绿色自然景观完美融合。其简约而优雅的建筑设计营造出浓厚的宗教氛围，同时也让游客感受到视觉上的美感。这里经常被用于礼拜活动、灵修 retreat 以及宗教旅游。</p><p style=\"text-align:justify;\">除了作为祈祷与沉思的场所之外，马哈乌祈祷山也是著名的摄影打卡地点，尤其是在清晨和傍晚时分。阳光洒落在绿色山丘上的景色格外迷人，为每一位到访者带来宁静而难忘的体验。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/o9OKuh65hV2zulmyDCwKRUEHnXSHlv1VmNei7U9J.png', 18, 1, '2026-04-11 09:47:41', '2026-05-20 05:51:43'),
(41, 'guide', NULL, 'BUKIT KASIH', 'The Hill of Love', '사랑의 언덕', '爱之丘', '<p style=\"text-align:justify;\">Bukit Kasih Kanonang merupakan salah satu destinasi wisata religi dan alam paling terkenal di Sulawesi Utara yang menawarkan perpaduan keindahan pegunungan, udara sejuk, serta pesan toleransi antarumat beragama. Terletak di kawasan Kanonang, Minahasa, tempat ini menjadi simbol kerukunan dan persatuan masyarakat Sulawesi Utara yang hidup berdampingan dalam keberagaman.</p><p style=\"text-align:justify;\">Bukit Kasih dikelilingi oleh perbukitan hijau yang indah dan sumber uap panas alami yang berasal dari aktivitas geothermal di daerah tersebut. Kabut tipis yang sering muncul di antara pepohonan menciptakan suasana yang tenang, sejuk, dan menenangkan bagi setiap pengunjung.</p><p style=\"text-align:justify;\">Salah satu daya tarik utama Bukit Kasih adalah keberadaan lima rumah ibadah yang melambangkan keharmonisan agama-agama di Indonesia. Pengunjung dapat melihat simbol toleransi yang kuat melalui berdirinya tempat ibadah yang saling berdampingan di kawasan ini. Selain itu, terdapat tangga menuju puncak bukit yang menawarkan panorama alam spektakuler dari ketinggian.</p><p style=\"text-align:justify;\">Di area Bukit Kasih juga terdapat monumen serta lokasi yang dipercaya berkaitan dengan sejarah dan budaya masyarakat Minahasa. Perpaduan antara wisata alam, religi, dan budaya membuat Bukit Kasih menjadi destinasi yang tidak hanya indah untuk dikunjungi, tetapi juga memberikan pengalaman penuh makna tentang persatuan, kedamaian, dan keberagaman.</p><p style=\"text-align:justify;\">&nbsp;</p>', '<p style=\"text-align:justify;\">Bukit Kasih Kanonang is one of the most famous religious and natural tourism destinations in North Sulawesi, offering a beautiful combination of mountain scenery, cool fresh air, and a strong message of interfaith harmony. Located in Kanonang, Minahasa, this place symbolizes the unity and peaceful coexistence of the diverse communities in North Sulawesi.</p><p style=\"text-align:justify;\">Bukit Kasih is surrounded by lush green hills and natural hot steam sources produced by geothermal activity in the area. The thin mist that often appears among the trees creates a calm, cool, and peaceful atmosphere for visitors.</p><p style=\"text-align:justify;\">One of the main attractions of Bukit Kasih is the presence of five houses of worship that symbolize religious harmony in Indonesia. Visitors can witness a strong spirit of tolerance through the existence of different places of worship standing side by side in this area. In addition, there are stairways leading to the top of the hill, where visitors can enjoy spectacular panoramic views from above.</p><p style=\"text-align:justify;\">The Bukit Kasih area also features monuments and locations connected to the history and culture of the Minahasan people. The combination of nature, religious values, and cultural heritage makes Bukit Kasih not only a beautiful destination to visit, but also a meaningful place that reflects unity, peace, and diversity.</p>', '<p style=\"text-align:justify;\">부킷 카시 카논앙은 아름다운 산 풍경과 시원한 공기, 그리고 종교 간 화합의 메시지를 함께 느낄 수 있는 북술라웨시의 대표적인 자연·종교 관광지입니다. 미나하사 카논앙 지역에 위치한 이곳은 다양한 종교와 문화가 조화롭게 공존하는 북술라웨시 사람들의 화합과 평화를 상징합니다.</p><p style=\"text-align:justify;\">부킷 카시는 푸른 언덕과 지열 활동으로 인해 발생하는 천연 온천 증기로 둘러싸여 있습니다. 숲 사이로 피어오르는 옅은 안개는 방문객들에게 차분하고 평화로운 분위기를 선사합니다.</p><p style=\"text-align:justify;\">이곳의 가장 큰 매력 중 하나는 인도네시아의 종교 화합을 상징하는 다섯 개의 예배 장소입니다. 서로 다른 종교의 예배당이 나란히 자리하고 있어 강한 관용과 화합의 의미를 보여줍니다. 또한 언덕 정상으로 이어지는 계단을 따라 올라가면 아름다운 자연 파노라마를 감상할 수 있습니다.</p><p style=\"text-align:justify;\">부킷 카시 지역에는 미나하사 사람들의 역사와 문화와 관련된 기념물과 장소들도 있습니다. 자연, 종교, 문화가 조화를 이루는 부킷 카시는 단순한 관광지를 넘어 평화와 다양성, 그리고 화합의 가치를 느낄 수 있는 특별한 장소입니다.</p>', '<p style=\"text-align:justify;\">卡农昂爱之山是北苏拉威西最著名的宗教与自然旅游景点之一，这里融合了壮丽的山景、清新的空气以及不同宗教和谐共处的深刻意义。它位于米纳哈萨的卡农昂地区，是北苏拉威西多元社会团结与和平共存的重要象征。</p><p style=\"text-align:justify;\">爱之山四周环绕着翠绿的山丘，并拥有因地热活动而形成的天然热蒸汽。树林间经常出现的薄雾，为这里营造出宁静、清凉而祥和的氛围。</p><p style=\"text-align:justify;\">爱之山最吸引人的特色之一，是这里建有五座不同宗教的礼拜场所，象征着印度尼西亚宗教之间的和谐与包容。游客可以亲身感受到不同宗教建筑并肩而立所展现出的团结精神。此外，通往山顶的阶梯还能让游客欣赏到壮观的高山全景。</p><p style=\"text-align:justify;\">在爱之山景区内，还设有与米纳哈萨历史和文化相关的纪念碑与重要地点。自然风光、宗教价值与文化遗产的结合，使爱之山不仅是一个美丽的旅游胜地，更是一个能够让人感受到和平、团结与多元文化意义的特别地方。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/9zlxTEzQ4ChQZD1qZu32RRjC1NdacnsON6u4TqFJ.png', 26, 1, '2026-04-11 09:47:41', '2026-05-20 04:30:36'),
(42, 'guide', NULL, 'Gunung Mahawu', 'Mount Mahawu', '마하우 산', '马哈武火山', '<p style=\"text-align:justify;\">Gunung Mahawu adalah salah satu destinasi alam paling memukau di Sulawesi Utara yang menawarkan keindahan panorama pegunungan, udara sejuk, dan pengalaman wisata yang menenangkan. Gunung ini berada di kawasan Tomohon dan terkenal dengan kawahnya yang luas serta pemandangan spektakuler yang dapat dinikmati langsung dari puncaknya.</p><p style=\"text-align:justify;\">Dari atas Gunung Mahawu, pengunjung dapat menyaksikan hamparan hijau pegunungan, Kota Tomohon yang indah, hingga birunya Laut Sulawesi di kejauhan. Kabut tipis yang sering menyelimuti area pegunungan membuat suasana terasa begitu damai dan menawan, terutama saat pagi hari.</p><p style=\"text-align:justify;\">Salah satu daya tarik utama Gunung Mahawu adalah jalur pendakiannya yang relatif mudah dan ramah bagi wisatawan. Dengan tangga dan jalur yang sudah tertata, pengunjung dapat mencapai puncak tanpa harus melakukan pendakian ekstrem. Setibanya di atas, panorama kawah aktif dengan bebatuan alami dan asap belerang menciptakan pemandangan eksotis yang memanjakan mata.</p><p style=\"text-align:justify;\">Gunung Mahawu juga menjadi tempat favorit untuk menikmati sunrise dan fotografi alam. Cahaya matahari yang perlahan muncul di balik pegunungan menciptakan warna langit yang dramatis dan sangat indah untuk diabadikan. Keindahan alamnya menjadikan Gunung Mahawu sebagai destinasi wisata yang wajib dikunjungi bagi pecinta petualangan, fotografi, maupun wisata alam yang ingin menikmati pesona Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Mount Mahawu is one of the most stunning natural destinations in North Sulawesi, offering breathtaking mountain scenery, cool fresh air, and a peaceful travel experience. Located in the Tomohon area, this mountain is famous for its wide crater and spectacular panoramic views that can be enjoyed directly from the summit.</p><p style=\"text-align:justify;\">From the top of Mount Mahawu, visitors can witness the lush green mountains, the beautiful city of Tomohon, and even the blue waters of the Sulawesi Sea in the distance. The thin mist that often surrounds the mountain creates a calm and enchanting atmosphere, especially in the morning.</p><p style=\"text-align:justify;\">One of the main attractions of Mount Mahawu is its relatively easy hiking trail, making it suitable for many visitors. With well-arranged stairs and pathways, tourists can reach the summit without extreme climbing. At the top, the active crater with natural rock formations and sulfuric steam creates an exotic and unforgettable landscape.</p><p style=\"text-align:justify;\">Mount Mahawu is also a favorite spot for enjoying sunrise views and nature photography. The sunlight slowly rising behind the mountains creates dramatic sky colors that are truly mesmerizing. Its natural beauty makes Mount Mahawu a must-visit destination for adventure seekers, photographers, and nature lovers who want to experience the charm of North Sulawesi.</p>', '<p style=\"text-align:justify;\">마하우 산은 아름다운 산 풍경과 시원한 공기, 그리고 평화로운 여행 분위기를 제공하는 북술라웨시의 대표적인 자연 관광지입니다. 토모혼 지역에 위치한 이 산은 넓은 분화구와 정상에서 감상할 수 있는 환상적인 전망으로 유명합니다.</p><p style=\"text-align:justify;\">마하우 산 정상에서는 푸른 산맥과 아름다운 토모혼 시내, 그리고 멀리 펼쳐진 술라웨시 바다까지 감상할 수 있습니다. 산을 둘러싸는 옅은 안개는 특히 아침 시간에 더욱 신비롭고 평온한 분위기를 만들어 줍니다.</p><p style=\"text-align:justify;\">마하우 산의 가장 큰 매력 중 하나는 비교적 쉬운 등산 코스입니다. 잘 정비된 계단과 길 덕분에 누구나 무리 없이 정상까지 올라갈 수 있습니다. 정상에 도착하면 자연 암석과 유황 연기가 어우러진 활화산 분화구의 이국적인 풍경이 방문객들의 눈길을 사로잡습니다.</p><p style=\"text-align:justify;\">또한 마하우 산은 일출 감상과 자연 사진 촬영 명소로도 유명합니다. 산 뒤로 떠오르는 태양빛이 하늘을 아름답고 드라마틱한 색으로 물들이며 잊지 못할 장면을 선사합니다. 이러한 자연의 아름다움 덕분에 마하우 산은 모험을 좋아하는 여행객과 사진작가, 그리고 자연을 사랑하는 사람들에게 꼭 방문해야 할 명소로 손꼽힙니다.</p>', '<p style=\"text-align:justify;\">马哈乌火山是北苏拉威西最迷人的自然旅游景点之一，以壮丽的山景、清新的空气以及宁静的氛围而闻名。它位于托莫洪地区，以宽广的火山口和山顶壮观的全景风光吸引着众多游客。</p><p style=\"text-align:justify;\">站在马哈乌火山山顶，游客可以欣赏到连绵起伏的绿色山脉、美丽的托莫洪市景，以及远处蔚蓝的苏拉威西海。环绕山间的薄雾，尤其是在清晨时分，为这里增添了神秘而宁静的气息。</p><p style=\"text-align:justify;\">马哈乌火山最大的魅力之一是其相对轻松的登山路线。由于设有完善的阶梯和步道，游客无需进行艰难攀登便可到达山顶。到达顶峰后，活火山口、天然岩石以及硫磺蒸汽交织而成的景色，展现出独特而震撼的自然之美。</p><p style=\"text-align:justify;\">此外，马哈乌火山也是欣赏日出和拍摄自然风光的热门地点。太阳缓缓从群山后升起时，天空会呈现出迷人的色彩变化，令人叹为观止。其独特的自然魅力，使马哈乌火山成为冒险爱好者、摄影师以及热爱大自然游客不可错过的旅游胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/iQom9XWiFngiluC3jVqSWYo8ha5ksLVRmBwyCnLt.png', 24, 1, '2026-04-11 09:47:41', '2026-05-20 04:01:55'),
(43, 'guide', NULL, 'DESA WOLOWAN', 'Woloan Village', '월로안 마을', '沃罗安村', '<p style=\"text-align:justify;\">Desa Woloan adalah sebuah desa yang terkenal sebagai pusat industri rumah panggung kayu tradisional Minahasa di Tomohon, provinsi Sulawesi Utara. Desa ini telah lama dikenal sebagai tempat para pengrajin lokal membuat rumah kayu khas Minahasa yang unik, indah, dan memiliki nilai budaya tinggi. Keunikan rumah panggung dari Woloan terletak pada sistem konstruksi yang dapat dibongkar dan dipasang kembali.&nbsp;</p><p style=\"text-align:justify;\">Rumah-rumah ini dibuat dari kayu pilihan dengan teknik pertukangan tradisional yang diwariskan secara turun-temurun. Karena desainnya yang fleksibel, rumah dapat dipindahkan ke lokasi lain setelah dibongkar, lalu dirakit kembali tanpa kehilangan kekuatan strukturnya. Selain terkenal di Sulawesi Utara, rumah kayu Woloan juga telah dikirim ke berbagai daerah di Indonesia bahkan hingga ke luar negeri.&nbsp;</p><p style=\"text-align:justify;\">Wisatawan yang berkunjung ke desa ini dapat melihat langsung proses pembuatan rumah, mengagumi detail ukiran kayu yang indah, serta merasakan kekayaan budaya arsitektur tradisional Minahasa. Desa Woloan menjadi tempat yang menarik untuk mengenal kearifan lokal sekaligus melihat bagaimana tradisi dan keterampilan masyarakat tetap hidup hingga saat ini.</p>', '<p style=\"text-align:justify;\">Woloan Village is a village well known as the center of the traditional Minahasan wooden stilt house industry in Tomohon, North Sulawesi. For many years, this village has been recognized as the home of local craftsmen who build unique and beautiful Minahasan wooden houses with high cultural value. One of the most distinctive features of Woloan stilt houses is their construction system, which allows them to be dismantled and reassembled.</p><p style=\"text-align:justify;\">These houses are made from selected quality wood using traditional carpentry techniques passed down through generations. Because of their flexible design, the houses can be moved to another location after being dismantled and then rebuilt without losing their structural strength. In addition to being famous throughout North Sulawesi, Woloan wooden houses have also been shipped to many regions across Indonesia and even overseas.</p><p style=\"text-align:justify;\">Visitors to the village can directly observe the house-building process, admire the intricate wooden carvings, and experience the richness of traditional Minahasan architecture. Woloan Village is an interesting destination to learn about local wisdom while witnessing how the community continues to preserve its traditions and craftsmanship to this day.</p>', '<p style=\"text-align:justify;\">워로안 마을은 북술라웨시 토모혼에 위치한 미나하사 전통 목조 가옥 산업의 중심지로 유명한 마을입니다. 이곳은 오랫동안 지역 장인들이 독특하고 아름다우며 높은 문화적 가치를 지닌 미나하사 전통 가옥을 제작하는 장소로 알려져 있습니다. 워로안 전통 가옥의 가장 큰 특징은 분해와 재조립이 가능한 독특한 건축 방식입니다.</p><p style=\"text-align:justify;\">이 집들은 엄선된 목재와 세대를 거쳐 전해 내려오는 전통 목공 기술로 만들어집니다. 유연한 구조 덕분에 집을 해체하여 다른 장소로 옮긴 후 다시 조립할 수 있으며, 구조적인 강도도 그대로 유지됩니다. 워로안 목조 가옥은 북술라웨시뿐만 아니라 인도네시아 여러 지역과 해외로도 수출되고 있습니다.</p><p style=\"text-align:justify;\">이 마을을 방문하는 관광객들은 집이 만들어지는 과정을 직접 볼 수 있으며, 아름다운 목조 조각의 세밀한 장식을 감상하고 미나하사 전통 건축의 풍부한 문화를 체험할 수 있습니다. 워로안 마을은 지역의 지혜를 배우고, 오늘날까지 이어지는 전통과 장인 정신을 느낄 수 있는 매력적인 관광지입니다.</p>', '<p style=\"text-align:justify;\">沃洛安村是印度尼西亚北苏拉威西托莫洪著名的米纳哈萨传统高脚木屋工业中心。多年来，这里一直以当地工匠制作独特、美丽且具有高度文化价值的米纳哈萨传统木屋而闻名。沃洛安高脚木屋最特别之处在于其可拆卸和重新组装的建筑结构。</p><p style=\"text-align:justify;\">这些房屋采用优质木材建造，并使用代代相传的传统木工技术完成。由于设计灵活，房屋可以在拆卸后搬迁到其他地点，再重新组装，同时依然保持坚固的结构。除了在北苏拉威西广受欢迎之外，沃洛安木屋还被运送到印度尼西亚各地，甚至出口到海外。</p><p style=\"text-align:justify;\">来到这里的游客可以亲眼观看木屋制作过程，欣赏精美细致的木雕装饰，并感受米纳哈萨传统建筑文化的独特魅力。沃洛安村是一个非常有吸引力的旅游目的地，让人们能够了解当地智慧，同时见证当地社区如何一直保留并传承他们的传统与工艺。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/UdjL782uPhJfr4sPpQySihToRKUHZXJGrdcTXWFF.png', 25, 1, '2026-04-11 09:47:41', '2026-05-20 04:08:18');
INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(44, 'guide', NULL, 'WARUGA SAWANGAN ( MAKAM BATU )', 'WARUGA (Stone Graves)', '와루가 (돌무덤)', '瓦鲁加（石棺）', '<p style=\"text-align:justify;\">Waruga Sawangan merupakan salah satu situs budaya dan sejarah paling unik di Sulawesi Utara yang menyimpan jejak peradaban kuno suku Minahasa. Tempat ini dikenal sebagai kompleks makam batu tradisional peninggalan leluhur Minahasa yang memiliki nilai sejarah, budaya, dan spiritual yang sangat tinggi.</p><p style=\"text-align:justify;\">Waruga adalah kuburan batu berbentuk kotak dengan penutup menyerupai atap rumah tradisional. Setiap waruga dihiasi ukiran khas yang menggambarkan status sosial, pekerjaan, maupun kisah kehidupan orang yang dimakamkan di dalamnya. Keunikan bentuk dan detail ukiran tersebut menjadikan Waruga Sawangan sebagai warisan budaya yang sangat menarik untuk dipelajari.</p><p style=\"text-align:justify;\">Berada di tengah suasana alam yang hijau dan tenang, Waruga Sawangan menghadirkan nuansa mistis sekaligus memikat. Deretan waruga batu yang tersusun rapi memberikan pengalaman berbeda bagi wisatawan yang ingin mengenal lebih dekat tradisi dan filosofi kehidupan masyarakat Minahasa zaman dahulu.</p><p style=\"text-align:justify;\">Selain menjadi destinasi wisata sejarah, Waruga Sawangan juga merupakan simbol penghormatan masyarakat Minahasa terhadap leluhur mereka. Tempat ini mengajarkan tentang pentingnya menjaga tradisi, menghormati sejarah, dan melestarikan budaya lokal yang telah diwariskan turun-temurun. Dengan keunikan dan nilai budayanya, Waruga Sawangan menjadi destinasi wisata budaya yang wajib dikunjungi saat berada di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Waruga Sawangan is one of the most unique cultural and historical sites in North Sulawesi, preserving the traces of the ancient Minahasan civilization. This place is known as a traditional stone burial complex inherited from the ancestors of the Minahasa people, carrying high historical, cultural, and spiritual value.</p><p style=\"text-align:justify;\">Waruga are stone tombs shaped like square chests with lids resembling traditional house roofs. Each waruga is decorated with distinctive carvings that represent social status, occupation, or stories from the life of the person buried inside. The uniqueness of their shapes and detailed carvings makes Waruga Sawangan a fascinating cultural heritage site to explore.</p><p style=\"text-align:justify;\">Surrounded by lush greenery and a peaceful atmosphere, Waruga Sawangan offers a mystical yet captivating ambiance. The neatly arranged rows of stone waruga provide visitors with a unique experience to learn more about the traditions and philosophy of life of the ancient Minahasan people.</p><p style=\"text-align:justify;\">Besides being a historical tourism destination, Waruga Sawangan is also a symbol of the Minahasan people’s respect for their ancestors. This place teaches the importance of preserving traditions, honoring history, and protecting local culture passed down through generations. With its uniqueness and cultural significance, Waruga Sawangan is a must-visit cultural destination in North Sulawesi.</p>', '<p style=\"text-align:justify;\">와루가 사왕안은 북술라웨시에서 가장 독특한 문화·역사 유적지 중 하나로, 고대 미나하사 문명의 흔적을 간직하고 있는 곳입니다. 이곳은 미나하사 조상들의 전통 석관 무덤 단지로 알려져 있으며, 높은 역사적·문화적·영적 가치를 지니고 있습니다.</p><p style=\"text-align:justify;\">와루가는 전통 가옥의 지붕 모양을 한 덮개가 있는 네모난 돌무덤입니다. 각각의 와루가에는 사회적 지위, 직업, 혹은 묻힌 사람의 삶의 이야기를 나타내는 독특한 조각이 새겨져 있습니다. 이러한 독창적인 형태와 섬세한 조각은 와루가 사왕안을 매우 흥미로운 문화유산으로 만들어 줍니다.</p><p style=\"text-align:justify;\">푸른 자연과 조용한 분위기 속에 자리한 와루가 사왕안은 신비롭고 매력적인 분위기를 자아냅니다. 질서 있게 배치된 돌무덤들은 방문객들에게 옛 미나하사 사람들의 전통과 삶의 철학을 더욱 가까이에서 이해할 수 있는 특별한 경험을 제공합니다.</p><p style=\"text-align:justify;\">와루가 사왕안은 역사 관광지일 뿐만 아니라, 미나하사 사람들이 조상을 존경하는 마음을 상징하는 장소이기도 합니다. 이곳은 전통을 지키고 역사를 존중하며 세대를 거쳐 내려온 지역 문화를 보존하는 중요성을 알려줍니다. 독특한 매력과 문화적 가치 덕분에 와루가 사왕안은 북술라웨시에서 꼭 방문해야 할 문화 관광지로 손꼽힙니다.</p>', '<p style=\"text-align:justify;\">萨旺安瓦鲁加石墓是北苏拉威西最独特的文化与历史遗址之一，保存着古代米纳哈萨文明的重要痕迹。这里被称为米纳哈萨祖先留下的传统石墓群，具有极高的历史、文化和精神价值。</p><p style=\"text-align:justify;\">瓦鲁加（Waruga）是一种方形石墓，其顶部形状类似传统房屋的屋顶。每一座瓦鲁加都雕刻着独特的图案，用来象征墓主人生前的社会地位、职业或人生故事。其独特的造型与精美的雕刻，使萨旺安瓦鲁加石墓成为极具吸引力的文化遗产。</p><p style=\"text-align:justify;\">在绿意盎然且宁静的自然环境中，萨旺安瓦鲁加石墓散发出神秘而迷人的氛围。整齐排列的石墓群，让游客能够更深入地了解古代米纳哈萨人的传统文化与生活哲学。</p><p style=\"text-align:justify;\">除了是著名的历史旅游景点之外，萨旺安瓦鲁加石墓也是米纳哈萨人民尊敬祖先的重要象征。这里传达了保护传统、尊重历史以及传承地方文化的重要意义。凭借其独特魅力与深厚文化价值，萨旺安瓦鲁加石墓成为来到北苏拉威西时不可错过的文化旅游胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/biY29yqPHaC8kHtcCTkLNHLqtQ4V9c85MccmiEJV.png', 16, 1, '2026-04-11 09:47:41', '2026-05-20 04:13:56'),
(45, 'guide', NULL, 'Rafting Timbukar', 'Rafting Timbukar', '팀부카르 래프팅', '廷布卡尔漂流', '<p style=\"text-align:justify;\">Rafting Timbukar Sonder merupakan salah satu destinasi wisata petualangan paling seru di Sulawesi Utara yang menawarkan pengalaman arung jeram di tengah keindahan alam tropis Minahasa. Berlokasi di kawasan Sonder, tempat ini terkenal dengan aliran sungainya yang jernih, deras, dan dikelilingi hutan hijau yang masih alami.</p><p style=\"text-align:justify;\">Sensasi rafting di Timbukar memberikan perpaduan antara tantangan, adrenalin, dan keindahan alam yang memukau. Pengunjung akan diajak menyusuri sungai berbatu dengan arus yang menantang sambil menikmati udara segar dan suara alam yang menenangkan. Percikan air sungai, bebatuan alami, dan panorama pepohonan tropis menciptakan pengalaman petualangan yang tidak terlupakan.</p><p style=\"text-align:justify;\">Rafting Timbukar juga cocok dinikmati bersama keluarga, teman, maupun rombongan wisata. Selain menawarkan jalur arung jeram yang aman dengan pemandu profesional, tempat ini juga menjadi pilihan favorit bagi pecinta olahraga outdoor dan wisata alam.</p><p style=\"text-align:justify;\">Di sepanjang perjalanan, wisatawan dapat merasakan suasana alam Minahasa yang masih asri dan jauh dari hiruk-pikuk perkotaan. Keindahan sungai yang mengalir di antara bebatuan besar dan hutan tropis membuat Rafting Timbukar Sonder menjadi destinasi sempurna bagi siapa saja yang ingin menikmati petualangan seru sekaligus merasakan kedamaian alam Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Rafting Timbukar Sonder is one of the most exciting adventure tourism destinations in North Sulawesi, offering an unforgettable white-water rafting experience surrounded by the tropical beauty of Minahasa. Located in the Sonder area, this destination is famous for its clear and fast-flowing river, surrounded by lush and untouched green forests.</p><p style=\"text-align:justify;\">Rafting in Timbukar combines challenge, adrenaline, and breathtaking natural scenery. Visitors are invited to navigate through rocky river currents while enjoying the fresh air and the calming sounds of nature. The splashing river water, natural rock formations, and panoramic tropical forest views create a truly unforgettable adventure experience.</p><p style=\"text-align:justify;\">Rafting Timbukar is also suitable for families, friends, and group travelers. In addition to offering safe rafting routes guided by professional instructors, this place is a favorite destination for outdoor sports enthusiasts and nature lovers.</p><p style=\"text-align:justify;\">Along the journey, visitors can experience the unspoiled beauty of Minahasan nature, far away from the noise of the city. The stunning river flowing between giant rocks and tropical forests makes Rafting Timbukar Sonder a perfect destination for anyone seeking both thrilling adventure and the peaceful atmosphere of North Sulawesi’s natural beauty.</p>', '<p style=\"text-align:justify;\">팀부카르 손데르 래프팅은 북술라웨시에서 가장 흥미로운 모험 관광지 중 하나로, 아름다운 미나하사의 열대 자연 속에서 짜릿한 래프팅 체험을 제공합니다. 손데르 지역에 위치한 이곳은 맑고 빠르게 흐르는 강과 울창한 열대 숲으로 둘러싸인 자연경관으로 유명합니다.</p><p style=\"text-align:justify;\">팀부카르 래프팅은 도전과 스릴, 그리고 아름다운 자연 풍경을 동시에 즐길 수 있는 특별한 경험을 선사합니다. 방문객들은 바위가 많은 강물을 따라 내려가며 신선한 공기와 자연의 소리를 만끽할 수 있습니다. 거센 물살과 자연 암석, 푸른 숲의 풍경은 잊지 못할 모험의 순간을 만들어 줍니다.</p><p style=\"text-align:justify;\">또한 팀부카르 래프팅은 가족, 친구, 단체 여행객 모두가 함께 즐기기에 적합합니다. 전문 가이드가 안전하게 진행하기 때문에 야외 스포츠와 자연을 좋아하는 사람들에게 인기 있는 관광지입니다.</p><p style=\"text-align:justify;\">여행 내내 방문객들은 도시의 소음에서 벗어나 미나하사의 깨끗하고 아름다운 자연을 가까이에서 느낄 수 있습니다. 거대한 바위 사이를 흐르는 강과 열대 숲의 풍경은 팀부카르 손데르 래프팅을 스릴과 평온함을 동시에 경험할 수 있는 완벽한 여행지로 만들어 줍니다.</p>', '<p style=\"text-align:justify;\">廷布卡尔松德漂流是北苏拉威西最刺激的冒险旅游目的地之一，为游客提供在米纳哈萨热带自然风光中的激流漂流体验。这里位于松德地区，以清澈湍急的河流以及四周郁郁葱葱的原始森林而闻名。</p><p style=\"text-align:justify;\">廷布卡尔漂流将挑战、刺激与壮丽自然景观完美结合。游客将沿着布满岩石的河道顺流而下，在享受清新空气的同时，聆听大自然的声音。飞溅的河水、天然巨石以及热带森林的全景风光，共同营造出令人难忘的探险体验。</p><p style=\"text-align:justify;\">廷布卡尔漂流也非常适合家庭、朋友以及团体游客一起体验。这里不仅拥有由专业向导带领的安全漂流路线，也成为户外运动爱好者和自然爱好者最喜爱的旅游地点之一。</p><p style=\"text-align:justify;\">在整个漂流过程中，游客能够感受到远离城市喧嚣的米纳哈萨原始自然之美。河流在巨石与热带森林之间奔流而过，使廷布卡尔松德漂流成为一个既能体验刺激冒险，又能感受北苏拉威西宁静自然氛围的完美旅游。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/lw3jbCljheZAKEODIgZCQKn1FDTnMrxFVVM6HY2O.png', 17, 1, '2026-04-11 09:47:41', '2026-05-20 04:43:11'),
(46, 'guide', NULL, 'Golf Resort Kawanua', 'Golf Resort Kawanua', '카와누아 골프 리조트', '卡瓦努阿高尔夫度假村', '<p style=\"text-align:justify;\">Kawanua Golf Resort merupakan salah satu destinasi wisata olahraga dan rekreasi eksklusif di Sulawesi Utara yang menawarkan perpaduan sempurna antara kemewahan, ketenangan, dan keindahan alam tropis. Dikelilingi hamparan hijau yang luas dengan panorama pegunungan yang memukau, tempat ini menjadi pilihan favorit bagi pecinta golf maupun wisatawan yang ingin menikmati suasana santai dan elegan.</p><p style=\"text-align:justify;\">Lapangan golf di Kawanua Golf Resort dirancang dengan lanskap yang indah dan menantang, memberikan pengalaman bermain golf yang menyenangkan bagi pemula maupun pemain profesional. Udara segar khas Sulawesi Utara serta suasana yang tenang membuat setiap permainan terasa lebih nyaman dan berkesan.</p><p style=\"text-align:justify;\">Selain fasilitas golf, resort ini juga menawarkan area rekreasi dan tempat bersantai yang nyaman dengan pemandangan alam yang memanjakan mata. Kombinasi antara arsitektur modern, area hijau yang luas, dan langit biru menciptakan suasana eksklusif namun tetap menyatu dengan alam.</p><p style=\"text-align:justify;\">Kawanua Golf Resort juga menjadi tempat yang ideal untuk menikmati waktu bersama keluarga, teman, maupun rekan bisnis. Keindahan alam, fasilitas lengkap, dan suasana yang damai menjadikan tempat ini sebagai destinasi sempurna untuk relaksasi, olahraga, dan menikmati pesona alam Sulawesi Utara dalam nuansa yang mewah dan berkelas.</p>', '<p style=\"text-align:justify;\">Kawanua Golf Resort is one of the most exclusive sports and leisure destinations in North Sulawesi, offering a perfect combination of luxury, tranquility, and tropical natural beauty. Surrounded by vast green landscapes and stunning mountain views, this resort is a favorite destination for golf enthusiasts and travelers seeking a relaxing and elegant atmosphere.</p><p style=\"text-align:justify;\">The golf course at Kawanua Golf Resort is beautifully designed with challenging landscapes, providing an enjoyable playing experience for both beginners and professional golfers. The fresh air of North Sulawesi and the peaceful surroundings make every game feel comfortable and memorable.</p><p style=\"text-align:justify;\">In addition to its golf facilities, the resort also offers comfortable recreational areas and relaxing spaces with breathtaking natural scenery. The combination of modern architecture, wide green spaces, and blue skies creates an exclusive atmosphere that remains harmoniously connected with nature.</p><p style=\"text-align:justify;\">Kawanua Golf Resort is also an ideal place to spend quality time with family, friends, or business partners. Its natural beauty, complete facilities, and peaceful ambiance make this resort a perfect destination for relaxation, sports, and enjoying the charm of North Sulawesi in a luxurious and classy setting.</p>', '<p style=\"text-align:justify;\">카와누아 골프 리조트은 럭셔리함과 평온함, 그리고 열대 자연의 아름다움이 완벽하게 조화를 이루는 북술라웨시의 대표적인 스포츠·휴양 리조트입니다. 넓은 초록빛 골프 코스와 아름다운 산 풍경으로 둘러싸여 있어 골프 애호가와 여유롭고 품격 있는 휴식을 원하는 여행객들에게 사랑받는 장소입니다.</p><p style=\"text-align:justify;\">카와누아 골프 리조트의 골프장은 아름답고 도전적인 코스로 설계되어 초보자부터 프로 선수까지 모두 즐겁게 플레이할 수 있습니다. 북술라웨시 특유의 상쾌한 공기와 조용한 분위기는 라운딩을 더욱 편안하고 특별하게 만들어 줍니다.</p><p style=\"text-align:justify;\">골프 시설 외에도 리조트에는 아름다운 자연 경관을 감상할 수 있는 휴식 공간과 레크리에이션 시설이 마련되어 있습니다. 현대적인 건축 디자인과 넓은 녹지, 그리고 푸른 하늘이 어우러져 자연과 조화를 이루는 고급스러운 분위기를 선사합니다.</p><p style=\"text-align:justify;\">카와누아 골프 리조트는 가족, 친구, 비즈니스 파트너와 함께 특별한 시간을 보내기에도 이상적인 장소입니다. 아름다운 자연과 완벽한 시설, 평화로운 분위기는 이곳을 휴식과 스포츠, 그리고 북술라웨시의 매력을 품격 있게 즐길 수 있는 최고의 여행지로 만들어 줍니다.</p>', '<p style=\"text-align:justify;\">卡瓦努阿高尔夫度假村是北苏拉威西最豪华的运动与休闲旅游胜地之一，这里完美结合了奢华、宁静以及热带自然风光。度假村四周被广阔的绿色草坪和壮丽的山景环绕，是高尔夫爱好者以及追求优雅休闲氛围游客的理想之地。</p><p style=\"text-align:justify;\">卡瓦努阿高尔夫度假村的高尔夫球场设计优美且富有挑战性，无论是初学者还是专业球员，都能在这里享受愉快的挥杆体验。北苏拉威西清新的空气与宁静的环境，让每一场比赛都更加舒适且难忘。</p><p style=\"text-align:justify;\">除了高尔夫设施之外，度假村还提供舒适的休闲区域和放松空间，游客可以欣赏迷人的自然景观。现代化建筑、宽阔的绿色空间以及蔚蓝天空相结合，营造出既豪华又与自然和谐融合的氛围。</p><p style=\"text-align:justify;\">卡瓦努阿高尔夫度假村也是与家人、朋友或商务伙伴共度美好时光的理想场所。这里拥有优美的自然环境、完善的设施以及宁静的氛围，使其成为放松身心、体验运动乐趣以及感受北苏拉威西魅力的完美度假胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/kBgGVIOGIz5DoPuZrgm8kw2FQNo1nRma3gW9j4zM.png', 27, 1, '2026-04-11 09:47:41', '2026-05-20 06:00:12'),
(47, 'guide', NULL, 'Museum Negeri', 'The Provincial Museum', '북술라웨시 박물관', '省博物馆', '<p style=\"text-align:justify;\">Museum Negeri Provinsi Sulawesi Utara merupakan salah satu destinasi wisata budaya dan sejarah yang penting di Sulawesi Utara. Museum ini menjadi tempat yang menyimpan berbagai koleksi berharga tentang sejarah, budaya, tradisi, serta kehidupan masyarakat Sulawesi Utara dari masa ke masa.</p><p style=\"text-align:justify;\">Di dalam museum, pengunjung dapat menemukan beragam benda bersejarah seperti pakaian adat, senjata tradisional, alat musik khas daerah, hingga peninggalan arkeologi dan etnografi dari berbagai suku di Sulawesi Utara. Setiap koleksi memiliki nilai budaya yang tinggi dan menggambarkan kekayaan warisan leluhur masyarakat Minahasa, Bolaang Mongondow, Sangihe, Talaud, dan daerah lainnya.</p><p style=\"text-align:justify;\">Museum Sulawesi Utara juga menghadirkan suasana edukatif yang menarik bagi wisatawan maupun pelajar yang ingin mengenal lebih dekat sejarah dan budaya lokal. Tata ruang koleksi yang tertata rapi membuat pengunjung dapat menikmati perjalanan sejarah dengan nyaman sambil mempelajari perkembangan budaya masyarakat Sulawesi Utara.</p><p style=\"text-align:justify;\">Selain sebagai tempat penyimpanan benda bersejarah, museum ini juga menjadi simbol pelestarian budaya daerah. Keberadaan Museum Sulawesi Utara membantu generasi muda untuk tetap mengenal identitas budaya mereka serta menjaga nilai-nilai tradisi yang diwariskan secara turun-temurun. Dengan koleksi yang unik dan kaya akan cerita sejarah, Museum Sulawesi Utara menjadi destinasi wisata edukasi yang menarik dan penuh wawasan.</p><p style=\"text-align:justify;\">&nbsp;</p>', '<p style=\"text-align:justify;\">North Sulawesi State Museum is one of the most important cultural and historical tourism destinations in North Sulawesi. The museum serves as a place that preserves valuable collections related to the history, culture, traditions, and way of life of the people of North Sulawesi throughout different periods of time.</p><p style=\"text-align:justify;\">Inside the museum, visitors can discover a wide range of historical objects such as traditional clothing, traditional weapons, regional musical instruments, as well as archaeological and ethnographic artifacts from various ethnic groups in North Sulawesi. Each collection holds significant cultural value and reflects the rich heritage of the Minahasa, Bolaang Mongondow, Sangihe, Talaud, and other communities in the region.</p><p style=\"text-align:justify;\">The North Sulawesi Museum also provides an engaging educational atmosphere for tourists and students who wish to learn more about local history and culture. The well-organized exhibition layout allows visitors to comfortably enjoy a journey through history while understanding the cultural development of North Sulawesi society.</p><p style=\"text-align:justify;\">Besides functioning as a place to preserve historical artifacts, the museum also symbolizes the preservation of regional culture. The existence of the North Sulawesi Museum helps younger generations remain connected to their cultural identity and continue preserving traditional values passed down through generations. With its unique collections and rich historical stories, the North Sulawesi Museum is an educational tourism destination full of insight and cultural charm.</p>', '<p style=\"text-align:justify;\">북술라웨시 주립 박물관은 북술라웨시에서 가장 중요한 문화·역사 관광지 중 하나입니다. 이 박물관은 북술라웨시 사람들의 역사와 문화, 전통, 그리고 삶의 방식을 담은 귀중한 유물들을 보존하고 전시하는 장소입니다.</p><p style=\"text-align:justify;\">박물관 내부에는 전통 의상, 전통 무기, 지역 악기뿐만 아니라 다양한 민족의 고고학 및 민속학 유물들이 전시되어 있습니다. 각각의 소장품은 높은 문화적 가치를 지니고 있으며, 미나하사, 볼랑 몽곤도우, 상이헤, 탈라우드 등 북술라웨시 여러 지역 공동체의 풍부한 유산을 보여줍니다.</p><p style=\"text-align:justify;\">북술라웨시 박물관은 지역 역사와 문화를 배우고자 하는 관광객과 학생들에게 흥미로운 교육적 경험을 제공합니다. 잘 정리된 전시 공간 덕분에 방문객들은 편안하게 역사 여행을 즐기며 북술라웨시 사회와 문화의 발전 과정을 이해할 수 있습니다.</p><p style=\"text-align:justify;\">또한 이 박물관은 단순한 유물 보관 장소를 넘어 지역 문화 보존의 상징적인 역할도 하고 있습니다. 북술라웨시 박물관은 젊은 세대가 자신의 문화적 정체성을 이해하고, 세대를 거쳐 이어져 온 전통적 가치를 지켜 나갈 수 있도록 돕고 있습니다. 독특한 소장품과 풍부한 역사 이야기를 가진 이 박물관은 지식과 문화적 매력이 가득한 교육 관광지입니다.</p>', '<p style=\"text-align:justify;\">北苏拉威西州立博物馆是北苏拉威西最重要的文化与历史旅游景点之一。该博物馆收藏并展示了有关北苏拉威西人民历史、文化、传统以及生活方式的大量珍贵文物。</p><p style=\"text-align:justify;\">在博物馆内，游客可以看到各种历史文物，例如传统服饰、传统武器、地方乐器，以及来自北苏拉威西不同民族的考古和民族学藏品。每一件藏品都具有重要的文化价值，展现了米纳哈萨、博朗蒙贡多、桑义赫、塔劳德等地区丰富的文化遗产。</p><p style=\"text-align:justify;\">北苏拉威西博物馆也为游客和学生提供了富有教育意义的参观体验，让人们能够更加深入地了解当地的历史与文化。整齐有序的展览布局，使游客能够舒适地欣赏历史发展的过程，同时了解北苏拉威西社会文化的演变。</p><p style=\"text-align:justify;\">除了作为历史文物保存场所之外，这座博物馆也是保护地方文化的重要象征。北苏拉威西州立博物馆帮助年轻一代继续认识自己的文化身份，并传承世代流传下来的传统价值观。凭借独特的馆藏与丰富的历史故事，这里成为一个充满知识与文化魅力的教育旅游胜地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/E8FCLhbHYtQAWo1FuAuZZwZDizKK8d6bgTb0lrSu.png', 28, 1, '2026-04-11 09:47:41', '2026-05-20 06:07:37'),
(48, 'guide', NULL, 'GOA JEPANG', 'Japanese Cave', '일본 동굴', '日本洞穴', '<p style=\"text-align:justify;\">Goa Jepang Tonsea di Minahasa, Sulawesi Utara, adalah peninggalan Perang Dunia II (1942–1945) pada masa pendudukan Jepang. Goa ini dibangun sebagai bunker pertahanan dengan menggali bukit menggunakan tenaga kerja paksa (romusha). Fungsinya sebagai markas militer, tempat perlindungan, penyimpanan logistik, dan jalur evakuasi. Saat ini, Goa Jepang Tonsea menjadi situs sejarah dan objek wisata edukasi.</p>', '<p style=\"text-align:justify;\">The Japanese Cave of Tonsea in Minahasa, North Sulawesi, is a relic from World War II (1942–1945) during the Japanese occupation. The cave was built as a defensive bunker by excavating hills using forced labor (romusha). It functioned as a military headquarters, shelter, logistics storage area, and evacuation route. Today, the Tonsea Japanese Cave has become a historical site and an educational tourist attraction.</p>', '<p style=\"text-align:justify;\">톤세아 일본 동굴은 북술라웨시 미나하사의 제2차 세계대전(1942–1945) 일본 점령 시기의 유적입니다. 강제 노동(로무샤)을 이용해 언덕을 파서 만든 방어용 벙커로, 군사 기지, 피난처, 물자 저장소, 탈출 통로로 사용되었습니다. 현재는 역사 유적지이자 교육 관광지입니다.</p>', '<p style=\"text-align:justify;\">托恩塞亚日本洞穴位于北苏拉威西省米纳哈萨，是第二次世界大战（1942–1945）日本占领时期的遗迹。该洞穴由强制劳工（罗姆沙）开凿山体建成防御掩体，曾作为军事基地、避难所、物资储存地和撤退通道。如今，它是历史遗址和教育旅游景点。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/UN2MBDgjjOZG17IGAYjXR3vi44JuEasOI2DB6IPu.png', 20, 1, '2026-04-11 09:47:41', '2026-05-26 02:23:24'),
(49, 'culture', NULL, 'TARIAN KABASARAN', 'Kabasaran Dance', '카바사란 춤', '卡巴萨兰舞', '<p style=\"text-align:justify;\">Tari Kabasaran adalah tarian perang khas Minahasa, Sulawesi Utara, yang penuh kekuatan dan keberanian. Dahulu, tarian ini dibawakan oleh para prajurit sebagai simbol kesiapan dalam menghadapi pertempuran. Gerakannya tegas, enerjik, dan penuh semangat, menggambarkan jiwa ksatria masyarakat Minahasa. Nama “Kabasaran” berasal dari kata “wasal” yang berarti mengikuti atau meniru gerakan pemimpin perang. Para penari mengenakan pakaian merah mencolok, senjata tradisional seperti pedang (santi) dan tombak, serta topi khas berbentuk runcing. Dentuman gong dan tabuhan tambur mengiringi setiap langkah, menciptakan suasana yang megah dan menggugah adrenalin. Kini, Tari Kabasaran tidak hanya menjadi simbol keberanian, tetapi juga daya tarik budaya yang memukau wisatawan. Pertunjukannya sering hadir dalam festival, penyambutan tamu, hingga acara adat—memberikan pengalaman yang tak terlupakan.</p>', '<p style=\"text-align:justify;\">Kabasaran Dance is a powerful traditional war dance from Minahasa, North Sulawesi, known for its intensity and heroic spirit. In the past, it was performed by warriors as a symbol of readiness for battle. The movements are firm, dynamic, and full of energy, reflecting the bravery of the Minahasan people. The name “Kabasaran” is believed to come from a word meaning “to follow or imitate the leader’s movements.” Dancers wear striking red costumes, carry traditional weapons such as swords (santi) and spears, and don unique pointed hats. The rhythmic beats of gongs and drums create a dramatic and thrilling atmosphere. Today, Kabasaran Dance has transformed into a captivating cultural performance, often showcased at festivals, welcoming ceremonies, and traditional events—offering visitors an unforgettable glimpse into Minahasa’s warrior heritage.</p>', '<p style=\"text-align:justify;\">카바사란 춤(Kabasaran Dance)은 인도네시아 북술라웨시 미나하사 지역의 전통 전쟁 춤으로, 강인함과 용맹함을 상징합니다. 과거에는 전사들이 전투에 나서기 전 준비를 나타내기 위해 추었던 춤입니다. 동작은 힘차고 역동적이며, 미나하사 사람들의 용기를 표현합니다. “카바사란”이라는 이름은 전쟁 지도자의 동작을 따르거나 모방한다는 의미에서 유래되었습니다. 무용수들은 붉은 전통 의상을 입고, 검과 창 같은 전통 무기를 들며, 뾰족한 모자를 착용합니다. 북과 공의 강렬한 리듬이 더해져 긴장감 넘치는 분위기를 만들어냅니다. 현재 이 춤은 문화 공연으로 발전하여 축제, 환영 행사, 전통 의식 등에서 자주 선보이며 관광객들에게 강렬한 인상을 남깁니다.</p>', '<p style=\"text-align:justify;\">卡巴萨兰舞（Kabasaran Dance）是来自印度尼西亚北苏拉威西米纳哈萨地区的一种传统战舞，以其力量与勇气而闻名。过去，这种舞蹈由战士表演，象征着迎接战斗的准备。 舞蹈动作有力而充满节奏感，展现了米纳哈萨人民的英雄精神。“Kabasaran”一词被认为源于“跟随或模仿领袖动作”的含义。舞者身穿鲜艳的红色服装，手持传统武器如剑和长矛，并佩戴独特的尖顶帽。在锣和鼓的伴奏下，整个表演充满震撼与激情。 如今，卡巴萨兰舞已成为极具吸引力的文化表演，经常出现在节日、欢迎仪式和传统活动中，为游客带来难忘的文化体验。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/zztC2p1VghPoMkMXygRZ1WaYbRJTpgXBiJ0zkozx.png', 2, 1, '2026-04-25 14:24:58', '2026-05-26 03:00:09'),
(50, 'culture', NULL, 'TARIAN KATRILI', 'Katrili Dance', '카트릴리 춤', '卡特里利舞', '<p style=\"text-align:justify;\">Tari Katrili adalah tarian tradisional dari Minahasa, Sulawesi Utara, yang mendapat pengaruh kuat dari budaya Eropa, khususnya pada masa kolonial. Tarian ini berkembang dari dansa sosial seperti quadrille yang diperkenalkan oleh bangsa Spanyol dan Belanda kepada masyarakat setempat. Seiring waktu, masyarakat Minahasa mengadaptasi tarian ini dengan sentuhan lokal, baik dari segi gerakan, musik, maupun nilai budaya. Tari Katrili kemudian menjadi simbol pergaulan, kebersamaan, dan keanggunan, yang sering ditampilkan dalam acara pernikahan, pesta, dan penyambutan tamu.</p>', '<p style=\"text-align:justify;\">Katrili Dance is a traditional dance from Minahasa, North Sulawesi, strongly influenced by European culture during the colonial era. It originated from social dances such as the quadrille, introduced by the Spanish and Dutch to the local community. Over time, the Minahasan people adapted the dance by adding local elements in movement, music, and cultural meaning. Katrili Dance became a symbol of social interaction, harmony, and elegance, and is often performed at weddings, celebrations, and welcoming ceremonies.</p>', '<p style=\"text-align:justify;\">카트릴리 춤(Katrili Dance)은 인도네시아 북술라웨시 미나하사 지역의 전통 춤으로, 식민지 시대 유럽 문화의 영향을 크게 받았습니다. 이 춤은 스페인과 네덜란드에 의해 전해진 사교 춤인 쿼드릴(quadrille)에서 유래되었습니다. 시간이 지나면서 미나하사 사람들은 이 춤에 지역적 요소를 더해 독특한 형태로 발전시켰습니다. 카트릴리 춤은 사교, 조화, 우아함을 상징하며, 결혼식, 축제, 환영 행사에서 자주 공연됩니다.</p>', '<p style=\"text-align:justify;\">卡特里利舞（Katrili Dance）是来自印度尼西亚北苏拉威西米纳哈萨地区的一种传统舞蹈，深受殖民时期欧洲文化的影响。它起源于西班牙和荷兰人带来的社交舞——四对舞（quadrille）。 随着时间的发展，米纳哈萨人民将本地文化元素融入其中，使其形成独特风格。卡特里利舞象征着社交、和谐与优雅，常在婚礼、庆典和迎宾活动中表演，深受游客喜爱。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/6Y0MO7gakvBGK5ECrRW7Glb962UMnOVGEUhQrWW1.jpg', 13, 1, '2026-04-25 14:28:58', '2026-05-26 03:01:32'),
(51, 'culture', NULL, 'TARI TUMATENDEN', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Tari Tumatenden adalah tarian tradisional dari Minahasa, Sulawesi Utara, yang berasal dari legenda rakyat yang penuh makna tentang cinta, pengorbanan, dan kehidupan manusia. Dalam cerita rakyatnya, Tumatenden berkisah tentang seorang pria yang jatuh cinta pada seorang wanita dari dunia gaib. Hubungan mereka menggambarkan pertemuan dua dunia—manusia dan alam spiritual—yang kemudian menjadi simbol bahwa cinta dan kehidupan selalu memiliki batas dan aturan yang harus dihormati. Tari ini kemudian diciptakan untuk menceritakan kembali kisah tersebut melalui gerakan yang lembut, ekspresif, dan penuh emosi. Setiap gerakan dalam Tari Tumatenden menggambarkan perjalanan cinta, kerinduan, serta pesan moral tentang menghargai kehidupan dan keseimbangan alam. Kini, Tari Tumatenden tidak hanya menjadi pertunjukan budaya, tetapi juga daya tarik wisata yang memperkenalkan kekayaan cerita rakyat Minahasa kepada dunia. Wisatawan dapat merasakan nuansa mistis sekaligus romantis yang membuat tarian ini berbeda dari tarian tradisional lainnya di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Tari Tumatenden is a traditional dance from Minahasa, North Sulawesi, inspired by a powerful folk legend about love, sacrifice, and human life. The story tells of a man who falls in love with a woman from a mystical world. Their relationship represents the meeting between two realms—human and spiritual—symbolizing that love and life always have boundaries and rules that must be respected. This dance was created to retell the story through soft, expressive, and emotional movements. Each gesture reflects a journey of love, longing, and a moral message about respecting life and maintaining balance with nature. Today, Tari Tumatenden is not only a cultural performance but also a tourist attraction that introduces the rich folklore of Minahasa to the world. Visitors can feel its mystical and romantic atmosphere, making it unique among traditional dances in North Sulawesi.</p>', '<p style=\"text-align:justify;\">Tari Tumatenden은 인도네시아 북술라웨시 미나하사 지역의 전통 춤으로, 사랑, 희생, 인간 삶에 대한 민간 전설에서 유래했습니다. 이 이야기는 한 남성이 신비로운 세계의 여인과 사랑에 빠지는 내용을 담고 있으며, 인간 세계와 영적 세계의 만남을 상징합니다. 이는 사랑과 삶에는 반드시 지켜야 할 경계와 규칙이 있음을 의미합니다. 이 전설을 표현하기 위해 만들어진 이 춤은 부드럽고 감정적인 움직임이 특징입니다. 각 동작은 사랑의 여정, 그리움, 그리고 자연과 삶의 균형을 존중해야 한다는 메시지를 담고 있습니다. 현재 이 춤은 문화 공연을 넘어, 미나하사의 풍부한 민속 이야기를 세계에 소개하는 관광 자원으로 자리 잡고 있으며, 신비롭고 로맨틱한 분위기를 느낄 수 있는 특별한 공연입니다.</p>', '<p style=\"text-align:justify;\">Tari Tumatenden是来自印度尼西亚北苏拉威西米纳哈萨地区的一种传统舞蹈，源自一个关于爱情、牺牲与人生意义的民间传说。 故事讲述一名男子爱上了来自神秘世界的女子，他们的关系象征着人类世界与精神世界的相遇，寓意着爱情与人生都存在必须遵守的界限与规则。 该舞蹈通过柔美、富有表现力和情感丰富的动作来讲述这一故事，每一个动作都展现了爱情的旅程、思念之情，以及尊重生命与自然平衡的寓意。 如今，Tari Tumatenden不仅是一种文化表演，也成为向世界介绍米纳哈萨丰富民间故事的重要旅游项目。游客可以感受到其神秘而浪漫的氛围，使其在北苏拉威西传统舞蹈中独具特色。</p>', NULL, 4, 1, '2026-04-25 14:38:45', '2026-05-26 03:02:44'),
(52, 'culture', NULL, 'ALAT MUSIC GONG DAN TAMBUR', 'Gongs and traditional drums (tambur)', '북술라웨시 미나하사 지역에서 사용되는 징(Gong)과 전통 북(Tambur)', '锣（Gong）和传统鼓（Tambur）', 'Gong dan tambur merupakan alat musik tradisional penting dalam budaya Minahasa, Sulawesi Utara. Sejak zaman dahulu, kedua alat ini digunakan dalam upacara adat, ritual, dan pertunjukan perang seperti Tari Kabasaran.\n\nGong dipercaya berasal dari pengaruh budaya Asia Timur dan menyebar ke Nusantara melalui jalur perdagangan. Sementara tambur (gendang tradisional) berkembang dari kebutuhan masyarakat lokal untuk menciptakan ritme dalam tarian dan ritual.\n\nDalam sejarahnya, bunyi gong melambangkan kekuatan dan kebesaran, sedangkan tambur memberi irama semangat dan energi. Kombinasi keduanya menciptakan suasana sakral sekaligus penuh semangat dalam setiap pertunjukan budaya Minahasa.', 'Gongs and traditional drums (tambur) are important musical instruments in Minahasan culture, North Sulawesi. In ancient times, they were used in rituals, traditional ceremonies, and war dances such as the Kabasaran Dance.\n\nThe gong is believed to have originated from East Asian influence and spread to the Indonesian archipelago through trade routes. The tambur (traditional drum), on the other hand, developed locally as a way to create rhythm for dances and ceremonies.\n\nHistorically, the sound of the gong represents power and grandeur, while the drum provides rhythm, energy, and spirit. Together, they create a sacred and energetic atmosphere in Minahasan cultural performances.', '북술라웨시 미나하사 지역에서 사용되는 징(Gong)과 전통 북(Tambur)은 중요한 전통 악기입니다. 과거에는 의식, 전통 행사, 그리고 카바사란 춤과 같은 전쟁 춤에서 사용되었습니다.\n\n징은 동아시아 문화의 영향을 받아 무역을 통해 인도네시아로 전해진 것으로 알려져 있습니다. 반면 북은 지역 사회에서 춤과 의식의 리듬을 만들기 위해 발전한 전통 악기입니다.\n\n역사적으로 징의 소리는 힘과 권위를 상징하며, 북은 에너지와 리듬을 제공합니다. 두 악기의 조합은 미나하사 문화 공연에서 신성하면서도 역동적인 분위기를 만들어냅니다.', '锣（Gong）和传统鼓（Tambur）是印度尼西亚北苏拉威西米纳哈萨文化中的重要乐器。在古代，它们被用于仪式、传统庆典以及卡巴萨兰战舞等表演中。\n\n锣被认为受到东亚文化影响，通过贸易路线传播到群岛地区。而鼓则是当地文化发展而来的，用于为舞蹈和仪式提供节奏。\n\n在历史上，锣的声音象征力量与庄严，而鼓则带来节奏与活力。两者结合，使米纳哈萨的文化表演充满神圣与激情的氛围。', NULL, 5, 1, '2026-04-25 14:44:51', '2026-04-25 14:44:51'),
(53, 'culture', NULL, 'ALAT MUSIK TAMBOR/TALINGA', NULL, NULL, NULL, 'Gendang Tradisional Minahasa, yang sering disebut Talinga atau Tambor, adalah alat musik penting dalam budaya Sulawesi Utara. Sejak dahulu, gendang ini digunakan untuk mengiringi tarian adat seperti Kabasaran dan Maengket, serta berbagai upacara tradisional.\n\nBunyi gendang yang kuat dan berirama dipercaya mampu membangkitkan semangat para penari dan masyarakat. Dalam sejarahnya, tambor bukan hanya alat musik, tetapi juga simbol kebersamaan dan energi kehidupan masyarakat Minahasa.\n\nSetiap pukulan gendang menciptakan ritme yang dinamis, membuat pertunjukan terasa hidup, penuh semangat, dan menggetarkan suasana.', 'The traditional Minahasan drum, known as Talinga or Tambor, is an important musical instrument in North Sulawesi culture. It has long been used to accompany traditional dances such as Kabasaran and Maengket, as well as various cultural ceremonies.\n\nIts strong and rhythmic sound is believed to inspire energy and spirit among dancers and the community. Historically, the tambor is not just a musical instrument, but also a symbol of unity and the life force of the Minahasan people.\n\nEach drumbeat creates a dynamic rhythm, making performances feel alive, powerful, and emotionally engaging.', '미나하사 전통 북인 **탈링가(Talinga) 또는 탐보르(Tambor)**는 북술라웨시 문화에서 중요한 악기입니다. 이 북은 카바사란과 마엥켓 같은 전통 춤과 다양한 의식에서 오랫동안 사용되어 왔습니다.\n\n강하고 리드미컬한 북소리는 무용수와 공동체에 활력을 불어넣는다고 여겨집니다. 역사적으로 탐보르는 단순한 악기가 아니라 미나하사 사람들의 단결과 생명력을 상징하는 존재입니다.\n\n북의 한 번의 타격은 역동적인 리듬을 만들어 공연을 생동감 있고 강렬하게 만듭니다.', '米纳哈萨传统鼓，被称为Talinga或Tambor，是北苏拉威西文化中的重要乐器。它长期用于伴奏卡巴萨兰舞、马恩格特舞以及各种传统仪式。\n\n其强劲而富有节奏感的鼓声被认为能够激发舞者和人们的精神与活力。在历史上，Tambor不仅是一种乐器，更象征着米纳哈萨人民的团结与生命力量。\n\n每一次击鼓都创造出充满活力的节奏，使表演更加生动、震撼且富有感染力。', NULL, 7, 1, '2026-04-25 14:50:27', '2026-04-25 14:50:27'),
(54, 'culture', NULL, 'ALAT MUSIK BAMBU', NULL, NULL, NULL, 'Alat musik bambu adalah salah satu warisan musik tradisional di Sulawesi Utara yang dibuat dari batang bambu alami. Alat musik ini menghasilkan suara yang lembut, alami, dan menenangkan.\n\nDi Minahasa, bambu sering dijadikan suling atau alat musik tiup yang dimainkan dalam berbagai acara adat, tarian, dan hiburan rakyat. Suaranya menggambarkan suasana alam pegunungan dan kehidupan masyarakat yang dekat dengan alam.\n\nSelain suling bambu, ada juga variasi alat musik bambu lain yang dipukul atau digoyangkan untuk menghasilkan ritme sederhana. Alat musik ini mencerminkan kreativitas masyarakat dalam memanfaatkan alam sekitar menjadi seni musik yang indah.', 'Bamboo musical instruments are part of the traditional musical heritage of North Sulawesi, especially in Minahasa. They are made from natural bamboo stems and produce soft, natural, and calming sounds.\n\nIn Minahasa, bamboo is commonly crafted into flutes and wind instruments used in traditional ceremonies, dances, and folk entertainment. The sound reflects the peaceful atmosphere of the mountains and the close relationship between the people and nature.\n\nBesides flutes, some bamboo instruments are also struck or shaken to create simple rhythmic sounds. These instruments highlight the creativity of local communities in transforming natural materials into beautiful music.', '대나무 악기는 북술라웨시, 특히 미나하사 지역의 전통 음악 유산 중 하나입니다. 자연 대나무로 만들어지며 부드럽고 자연스럽고 편안한 소리를 냅니다.\n\n미나하사에서는 대나무로 만든 피리나 관악기가 전통 의식, 춤 공연, 민속 행사에서 자주 사용됩니다. 그 소리는 산악 지역의 평화로운 자연과 사람들의 자연과의 조화를 표현합니다.\n\n또한 일부 대나무 악기는 두드리거나 흔들어 간단한 리듬을 만들기도 합니다. 이는 자연 재료를 활용해 아름다운 음악을 만들어내는 지역 주민들의 창의성을 보여줍니다.', '竹制乐器是北苏拉威西，尤其是米纳哈萨地区的传统音乐遗产之一。它们由天然竹子制成，发出柔和、自然且令人放松的声音。\n\n在米纳哈萨，竹子常被制作成笛子等吹奏乐器，用于传统仪式、舞蹈和民间表演。其声音体现了山区宁静的自然环境以及人们与自然的紧密联系。\n\n此外，还有一些竹制乐器通过敲击或摇动产生简单节奏。这些乐器展现了当地人民将自然材料转化为艺术音乐的创造力。', NULL, 8, 1, '2026-04-25 14:55:05', '2026-04-25 14:55:05'),
(55, 'culture', NULL, 'ADAT PERKAWINAN MINAHASA (MAPALUS & SOMBA’)', NULL, NULL, NULL, 'Adat Perkawinan Minahasa adalah tradisi pernikahan yang sudah ada sejak zaman leluhur Minahasa. Dahulu, pernikahan bukan hanya menyatukan dua orang, tetapi juga dua keluarga besar dan bahkan seluruh komunitas.\n\nDalam sejarahnya, masyarakat Minahasa menerapkan nilai mapalus, yaitu kerja sama dan gotong royong dalam setiap persiapan pernikahan, mulai dari membangun rumah, menyiapkan makanan, hingga pelaksanaan acara. Sedangkan somba’ menggambarkan rasa hormat dan penghargaan terhadap keluarga dan tamu.\n\nUpacara ini biasanya diiringi musik kolintang, tarian tradisional, dan pakaian adat yang meriah, mencerminkan kebersamaan, kehormatan, dan sukacita masyarakat Minahasa.', 'Minahasan Wedding Tradition is a traditional marriage custom that has existed since the ancestral times of the Minahasan people. In the past, marriage was not only the union of two individuals but also the joining of two families and the wider community.\n\nHistorically, the Minahasan people practiced mapalus, a system of cooperation and mutual help in preparing weddings, from building houses to preparing food and organizing the ceremony. Meanwhile, somba’ represents respect and honor toward families and guests.\n\nThe ceremony is often accompanied by kolintang music, traditional dances, and colorful traditional attire, reflecting unity, respect, and joy in Minahasan culture.', '미나하사 결혼 전통은 미나하사 조상 시대부터 이어져 온 전통 혼례 문화입니다. 과거에는 결혼이 두 사람뿐만 아니라 두 가족과 공동체 전체를 하나로 연결하는 중요한 행사였습니다.\n\n역사적으로 미나하사 사람들은 **마팔루스(Mapalus)**라는 협력과 상호부조 문화를 통해 결혼 준비를 함께 했습니다. 집을 짓고 음식을 준비하며 모든 과정을 공동체가 함께했습니다. 또한 **솜바(Somba’)**는 가족과 손님에 대한 존중과 예의를 의미합니다.\n\n이 의식은 콜린탕 음악, 전통 춤, 화려한 전통 의상과 함께 진행되며, 공동체의 화합과 기쁨을 상징합니다.', '米纳哈萨婚礼传统是米纳哈萨祖先时期就存在的传统婚礼习俗。在过去，婚礼不仅是两个人的结合，更是两个家庭乃至整个社区的联合。\n\n在历史上，米纳哈萨人民实行**Mapalus（互助合作）制度，在婚礼准备过程中共同协作，包括建房、准备食物和组织仪式等。而Somba’**则代表对家人和宾客的尊重与礼仪。\n\n婚礼通常伴随着科林当音乐、传统舞蹈和华丽的民族服饰，展现了米纳哈萨文化中的团结、尊重与喜悦。', NULL, 9, 1, '2026-04-25 15:02:34', '2026-04-25 15:03:45'),
(56, 'culture', NULL, 'MAPALUS ( GOTONG ROYONG TRADISIONAL MINAHASA)', NULL, NULL, NULL, 'Mapalus adalah sistem gotong royong tradisional masyarakat Minahasa yang sudah ada sejak zaman leluhur. Mapalus bukan sekadar kerja bersama, tetapi juga simbol persaudaraan, solidaritas, dan rasa saling memiliki.\n\nDalam sejarahnya, Mapalus digunakan untuk berbagai kegiatan penting seperti bertani, membuka ladang, membangun rumah, hingga mempersiapkan acara adat. Semua pekerjaan dilakukan secara bersama-sama tanpa mengharapkan imbalan pribadi, karena yang diutamakan adalah kebersamaan.\n\nTradisi ini mencerminkan nilai kehidupan masyarakat Minahasa yang kuat dalam persatuan dan kepedulian sosial. Hingga saat ini, Mapalus masih menjadi bagian penting dalam kehidupan budaya dan sering dijadikan inspirasi dalam kegiatan sosial modern.', 'Mapalus is a traditional system of mutual cooperation in Minahasan society that has existed since ancestral times. It is more than just working together—it represents brotherhood, solidarity, and a strong sense of community.\n\nHistorically, Mapalus was used in various important activities such as farming, clearing land, building houses, and preparing traditional ceremonies. All tasks were done collectively without personal gain, as unity was the main value.\n\nThis tradition reflects the Minahasan people’s strong social bond and sense of togetherness. Today, Mapalus remains an important cultural value and continues to inspire modern community cooperation.', '마팔루스는 미나하사 사회에서 조상 때부터 이어져 온 전통적인 협동 시스템입니다. 단순한 공동 작업이 아니라 형제애, 연대, 공동체 정신을 상징합니다.\n\n역사적으로 마팔루스는 농사, 밭 개간, 집 짓기, 전통 행사 준비 등 다양한 활동에 사용되었습니다. 모든 작업은 개인적인 이익이 아닌 공동체의 협력을 중심으로 이루어졌습니다.\n\n이 전통은 미나하사 사람들의 강한 결속력과 사회적 배려를 보여주며, 오늘날에도 중요한 문화 가치로 이어지고 있습니다.', 'Mapalus是米纳哈萨社会自祖先时期延续下来的传统互助合作制度。它不仅仅是一起工作，更象征着兄弟情谊、团结和社区精神。\n\n在历史上，Mapalus被用于农业劳作、开垦土地、建造房屋以及准备传统仪式等活动。所有工作都是集体完成的，不以个人利益为目的，而是以团结为核心价值。\n\n这一传统体现了米纳哈萨人民强烈的社会凝聚力与互助精神，如今仍然是重要的文化价值，并影响着现代社会的合作方式。', NULL, 10, 1, '2026-04-25 15:07:16', '2026-04-25 15:07:16'),
(57, 'culture', NULL, 'ADAT TONAAS (PEMIMPIN ADAT MINAHASA)', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Tonaas adalah gelar untuk pemimpin adat atau tokoh yang dihormati dalam masyarakat Minahasa sejak zaman leluhur. Pada masa lalu, Tonaas bukan hanya seorang pemimpin, tetapi juga seorang pelindung, penasihat, dan penjaga nilai-nilai budaya. Sejarah Tonaas berawal dari kebutuhan masyarakat Minahasa untuk memiliki figur yang mampu memimpin dalam perang, mengatur kehidupan sosial, serta menjaga keseimbangan adat dan alam. Seorang Tonaas dipilih berdasarkan keberanian, kebijaksanaan, dan kemampuan spiritualnya. Hingga kini, konsep Tonaas masih dihormati sebagai simbol kepemimpinan tradisional yang menjunjung tinggi nilai kehormatan, kebersamaan, dan tanggung jawab sosial dalam budaya Minahasa.</p>', '<p style=\"text-align:justify;\">Tonaas is a traditional title for respected leaders in Minahasan society that has existed since ancestral times. In the past, a Tonaas was not only a leader but also a protector, advisor, and guardian of cultural values. Historically, the role of Tonaas emerged from the need for a figure who could lead in times of war, manage social life, and maintain balance between tradition and nature. A Tonaas was chosen based on bravery, wisdom, and spiritual strength. Today, the concept of Tonaas is still respected as a symbol of traditional leadership that upholds honor, unity, and social responsibility in Minahasan culture.</p>', '<p style=\"text-align:justify;\">토나아스는 미나하사 사회에서 조상 시대부터 이어져 온 전통적인 지도자 칭호입니다. 과거의 토나아스는 단순한 지도자가 아니라 공동체를 보호하고 문화적 가치를 지키는 역할을 했습니다. 역사적으로 토나아스는 전쟁 시 지휘, 사회 질서 유지, 그리고 자연과 전통의 균형을 관리하기 위해 필요했습니다. 용기, 지혜, 그리고 영적인 능력을 기준으로 선출되었습니다. 오늘날에도 토나아스는 명예, 단결, 그리고 사회적 책임을 상징하는 전통 지도자의 개념으로 존중받고 있습니다.</p>', '<p style=\"text-align:justify;\">Tonaas是米纳哈萨社会自祖先时期以来使用的传统领袖称号。在过去，Tonaas不仅是领导者，还是社区的保护者、顾问以及文化价值的守护者。 在历史上，这一角色的出现是为了满足战争指挥、社会管理以及维护传统与自然平衡的需要。Tonaas通常根据勇气、智慧和精神力量被选出。 如今，Tonaas仍然被视为传统领导力的象征，代表着尊严、团结与社会责任，在米纳哈萨文化中备受尊重。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/X3oU7KeX1LafGzKCjWUvKy5IFTr8a79n5ZuVuQdR.png', 1, 1, '2026-04-25 15:10:14', '2026-05-26 02:59:11'),
(58, 'culture', NULL, 'TULUDE', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Upacara Tulude adalah upacara adat masyarakat Sangihe dan Talaud di Sulawesi Utara yang dilaksanakan sebagai ungkapan syukur kepada Tuhan atas penyertaan selama satu tahun. Sejarah Tulude berakar dari tradisi leluhur yang menggabungkan unsur budaya lokal dan nilai spiritual.&nbsp;</p><p style=\"text-align:justify;\">Dahulu, masyarakat mengadakan Tulude sebagai momen untuk menutup tahun lama dan menyambut tahun baru dengan doa, syukur, serta harapan baru. Dalam pelaksanaannya, Tulude biasanya diiringi tarian tradisional, musik bambu, serta prosesi pemotongan kue adat bernama “tamo”. Upacara ini mencerminkan rasa syukur, kebersamaan, dan harapan akan kehidupan yang lebih baik.</p>', '<p>Tulude Ceremony is a traditional ceremony of the Sangihe and Talaud communities in North Sulawesi, held as an expression of gratitude to God for blessings throughout the year. Historically, Tulude originates from ancestral traditions that combine local culture with spiritual values.</p><p>It was held to close the past year and welcome the new year with prayers, gratitude, and hope. The ceremony features traditional dances, bamboo music, and the cutting of a traditional cake called “tamo.” It symbolizes gratitude, unity, and hope for a better future.</p>', '툴루데 의식는 인도네시아 북술라웨시 상이헤와 탈라우드 지역 사람들의 전통 의식으로, 한 해 동안의 축복에 대해 신에게 감사하는 행사입니다.\r\n\r\n역사적으로 이 의식은 지역 전통과 영적 가치가 결합된 조상들의 문화에서 비롯되었습니다. 과거 사람들은 한 해를 마무리하고 새해를 맞이하며 기도와 감사, 희망을 표현하기 위해 Tulude를 진행했습니다.\r\n\r\n의식에서는 전통 춤, 대나무 음악, 그리고 “타모”라는 전통 케이크를 자르는 행사가 포함됩니다. 이는 감사, 단결, 그리고 더 나은 미래에 대한 희망을 상징합니다.', '图鲁德仪式是北苏拉威西萨金海和塔劳德地区人民的传统仪式，用来向上帝表达一年平安与祝福的感恩之情。\r\n\r\n从历史上看，Tulude起源于祖先传统，将地方文化与精神信仰相结合。人们通过这一仪式告别旧年、迎接新年，并表达祈祷、感恩与希望。\r\n\r\n仪式通常包括传统舞蹈、竹制音乐，以及切分名为“tamo”的传统蛋糕。它象征着感恩、团结与对美好未来的期待。', 'https://api.welcomemanado.my.id/storage/travel-info/qrpZBYgrL0jHUVFDuh0xdScJMFd5WctBaiwpEAq2.png', 12, 1, '2026-04-25 15:12:34', '2026-05-26 02:58:27'),
(59, 'culture', NULL, 'MASAMPER', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Masamper adalah seni tradisional masyarakat Sangihe dan Talaud berupa nyanyian berkelompok yang dilakukan secara bersahut-sahutan dengan iringan gerakan sederhana. Tradisi ini sudah ada sejak zaman leluhur dan awalnya digunakan dalam upacara adat, kegiatan sosial, serta acara keagamaan sebagai bentuk ungkapan rasa syukur dan kebersamaan. Seiring waktu, Masamper berkembang menjadi pertunjukan budaya dan lomba yang menampilkan kekompakan, harmoni suara, serta nilai-nilai persaudaraan masyarakat Sangihe yang kuat.</p>', '<p style=\"text-align:justify;\">Masamper is a traditional performing art from the Sangihe and Talaud communities, featuring group singing in a call-and-response style with simple movements. It dates back to ancestral times and was originally performed in traditional ceremonies, social gatherings, and religious events as an expression of gratitude and unity. Over time, Masamper has evolved into a cultural performance and competition that showcases harmony, vocal coordination, and the strong sense of togetherness among the Sangihe people.</p>', '<p style=\"text-align:justify;\">마삼퍼는 인도네시아 북술라웨시 상이헤와 탈라우드 지역 사람들의 전통 예술로, 여러 사람이 함께 노래를 주고받으며 간단한 동작을 하는 공연입니다. 이 전통은 조상 시대부터 이어져 왔으며, 원래는 전통 의식, 사회 행사, 종교 행사에서 감사와 단결을 표현하기 위해 사용되었습니다. 현재 마삼퍼는 문화 공연과 경연 대회로 발전하여 공동체의 화합과 조화를 보여주는 중요한 문화유산이 되었습니다.</p>', '<p style=\"text-align:justify;\">马桑佩尔是萨金海和塔劳德群岛人民的传统艺术形式，特点是多人进行对唱式歌唱并配合简单动作。这一传统起源于祖先时期，最初用于传统仪式、社交活动和宗教场合，以表达感恩与团结。如今，马桑佩尔已发展为文化表演和比赛形式，展现了萨金海人民的和谐、默契以及深厚的社区精神。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/ZBleo6x9MYkdj97JmhVuwboUk0JLLr9GuRP816D3.png', 11, 1, '2026-04-25 15:18:25', '2026-05-26 02:56:40'),
(60, 'guide', NULL, 'PULAU SILADEN', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Pulau Siladen adalah salah satu pulau kecil yang indah di kawasan Taman Nasional Bunaken, yang terletak di Teluk Manado dekat kota Manado di provinsi Sulawesi Utara. Pulau ini terkenal dengan suasananya yang tenang, pantai berpasir putih yang bersih, serta air laut yang sangat jernih dengan gradasi warna biru dan hijau yang memukau.&nbsp;</p><p style=\"text-align:justify;\">Pulau Siladen menjadi destinasi favorit wisatawan yang ingin menikmati keindahan laut tropis dengan suasana yang lebih santai dan eksklusif. Di sekitar pulau ini terdapat terumbu karang yang sangat indah serta berbagai jenis ikan tropis yang berwarna-warni. Aktivitas yang paling populer di sini adalah snorkeling dan diving, karena wisatawan dapat dengan mudah melihat penyu laut, karang yang sehat, serta kehidupan bawah laut yang kaya.&nbsp;</p><p style=\"text-align:justify;\">Selain itu, wisatawan juga dapat berjalan santai di sepanjang pantai, menikmati pemandangan matahari terbenam yang indah, atau menginap di resort-resort kecil yang nyaman. Dengan alam yang masih alami dan suasana yang damai, Pulau Siladen menjadi tempat yang sempurna untuk bersantai sekaligus menikmati keindahan laut Bunaken.</p>', '<p style=\"text-align:justify;\">Siladen Island is one of the beautiful small islands located within the Bunaken National Park area, situated in Manado Bay near the city of Manado in North Sulawesi Province. The island is well known for its peaceful atmosphere, clean white sandy beaches, and crystal-clear seawater with stunning shades of blue and green.</p><p style=\"text-align:justify;\">Siladen Island is a favorite destination for tourists who want to enjoy the beauty of the tropical sea in a more relaxed and exclusive setting. Around the island, there are beautiful coral reefs and many species of colorful tropical fish. The most popular activities here are snorkeling and diving, as visitors can easily spot sea turtles, healthy coral reefs, and rich marine life.</p><p style=\"text-align:justify;\">In addition, tourists can take relaxing walks along the beach, enjoy breathtaking sunset views, or stay in cozy small resorts on the island. With its unspoiled natural beauty and tranquil atmosphere, Siladen Island is the perfect place to relax while enjoying the beauty of Bunaken’s marine environment.</p>', '<p style=\"text-align:justify;\">Siladen Island은 Bunaken National Park 지역에 위치한 아름다운 작은 섬 중 하나로, 북술라웨시 주의 Manado 근처 마나도 만에 자리하고 있습니다. 이 섬은 평화로운 분위기, 깨끗한 백사장, 그리고 푸른색과 초록색이 어우러진 매우 맑은 바다로 유명합니다.</p><p style=\"text-align:justify;\">실라덴 섬은 보다 여유롭고 프라이빗한 분위기 속에서 열대 바다의 아름다움을 즐기고 싶은 관광객들에게 인기 있는 여행지입니다. 섬 주변에는 아름다운 산호초와 형형색색의 열대어들이 서식하고 있습니다. 이곳에서 가장 인기 있는 활동은 스노클링과 다이빙이며, 관광객들은 바다거북, 건강한 산호초, 그리고 풍부한 해양 생물을 쉽게 볼 수 있습니다.</p><p style=\"text-align:justify;\">또한 관광객들은 해변을 따라 산책을 하거나 아름다운 석양을 감상할 수 있으며, 아늑한 작은 리조트에서 머물 수도 있습니다. 자연 그대로의 아름다움과 평온한 분위기를 가진 실라덴 섬은 휴식을 취하면서 부나켄 바다의 아름다움을 즐기기에 완벽한 장소입니다.</p>', '<p style=\"text-align:justify;\">Siladen Island 是位于 Bunaken National Park 区域内的一座美丽小岛，坐落于北苏拉威西省 Manado 附近的马纳多湾。该岛以宁静的氛围、洁白的沙滩以及清澈透明、呈现迷人蓝绿色渐变的海水而闻名。</p><p style=\"text-align:justify;\">西拉登岛是许多游客喜爱的旅游目的地，特别适合那些希望在更加轻松和私密的环境中享受热带海洋美景的人。岛屿周围拥有非常美丽的珊瑚礁以及各种色彩斑斓的热带鱼类。这里最受欢迎的活动是浮潜和潜水，游客可以轻松看到海龟、健康的珊瑚礁以及丰富的海洋生物。</p><p style=\"text-align:justify;\">此外，游客还可以沿着海滩悠闲散步、欣赏美丽的日落，或入住舒适的小型度假村。凭借原始自然的环境和宁静祥和的氛围，西拉登岛成为放松身心并欣赏布纳肯海洋之美的理想之地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/llxT2Vrg8GCDRBqnjIuF5spPK04bkvBlSM5wmCsH.png', 2, 1, '2026-04-27 07:44:21', '2026-05-13 08:08:24');
INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(61, 'guide', NULL, 'PULAU NAIN', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Pulau Nain adalah salah satu pulau yang berada di kawasan Taman Nasional Bunaken, yang terletak di Teluk Manado dekat kota Manado di provinsi Sulawesi Utara. Pulau ini dikenal sebagai salah satu tempat yang masih sangat alami dengan pemandangan laut yang jernih, desa nelayan yang ramah, serta panorama pulau-pulau kecil yang indah di sekitarnya.&nbsp;</p><p style=\"text-align:justify;\">Suasana di Pulau Nain sangat tenang dan cocok bagi wisatawan yang ingin merasakan kehidupan pulau tropis yang sederhana namun memikat. Salah satu daya tarik unik di Pulau Nain adalah pasir timbul yang sangat indah. Pasir timbul ini akan muncul ketika air laut surut dan perlahan menghilang ketika air laut pasang.&nbsp;</p><p style=\"text-align:justify;\">Fenomena ini membuat hamparan pasir putih terlihat seperti pulau kecil yang muncul di tengah laut. Saat air sedang surut, wisatawan bisa berjalan di atas pasir putih yang luas, berfoto dengan latar laut biru yang jernih, serta menikmati pemandangan laut yang sangat memukau. Perubahan bentuk pasir yang mengikuti level air laut membuat pengalaman berkunjung ke tempat ini selalu terasa berbeda dan menarik.&nbsp;</p><p style=\"text-align:justify;\">Selain itu, perairan di sekitar Pulau Nain juga sangat cocok untuk snorkeling karena memiliki terumbu karang yang indah dan berbagai jenis ikan tropis. Keindahan alam yang masih alami, pasir timbul yang unik, serta suasana pulau yang tenang menjadikan Pulau Nain sebagai destinasi yang sempurna bagi wisatawan yang ingin menikmati keajaiban alam laut di Bunaken.</p>', '<p style=\"text-align:justify;\">Nain Island is one of the islands located within the Bunaken National Park area, situated in Manado Bay near the city of Manado in North Sulawesi Province. The island is known as one of the most unspoiled places in the region, featuring crystal-clear waters, friendly fishing villages, and beautiful views of the surrounding small islands.</p><p style=\"text-align:justify;\">The atmosphere on Nain Island is very peaceful and perfect for travelers who want to experience the charm of simple tropical island life. One of the island’s most unique attractions is its beautiful sandbar. This sandbar appears when the sea level is low and gradually disappears again when the tide rises.</p><p style=\"text-align:justify;\">This natural phenomenon creates the impression of a small white sandy island emerging in the middle of the sea. During low tide, visitors can walk across the wide stretch of white sand, take photos with the clear blue ocean as a backdrop, and enjoy the breathtaking sea views. Because the shape of the sandbar changes depending on the sea level, every visit offers a different and memorable experience.</p><p style=\"text-align:justify;\">In addition, the waters around Nain Island are also ideal for snorkeling, thanks to their beautiful coral reefs and colorful tropical fish. Its pristine natural beauty, unique sandbar, and peaceful island atmosphere make Nain Island a perfect destination for travelers who want to experience the marine wonders of Bunaken.</p>', '<p style=\"text-align:justify;\">Nain Island은 Bunaken National Park 지역에 위치한 섬 중 하나로, 북술라웨시 주의 Manado 근처 마나도 만에 자리하고 있습니다. 이 섬은 매우 자연 그대로의 아름다움을 간직한 곳으로 알려져 있으며, 맑고 투명한 바다, 친절한 어촌 마을, 그리고 주변의 아름다운 작은 섬 풍경이 특징입니다.</p><p style=\"text-align:justify;\">나인 섬의 분위기는 매우 평화롭고 조용하여 단순하면서도 매력적인 열대 섬의 삶을 경험하고 싶은 여행객들에게 잘 어울립니다. 이 섬의 가장 독특한 매력 중 하나는 아름다운 샌드바(모래톱)입니다. 이 모래톱은 바닷물이 빠질 때 나타나고, 밀물이 들어오면 다시 천천히 사라집니다.</p><p style=\"text-align:justify;\">이 자연 현상은 마치 바다 한가운데 작은 하얀 섬이 떠오른 듯한 장관을 만들어 냅니다. 썰물 때에는 관광객들이 넓은 백사장을 걸을 수 있으며, 맑고 푸른 바다를 배경으로 사진을 찍고 아름다운 해양 풍경을 감상할 수 있습니다. 바닷물의 높이에 따라 모래톱의 형태가 계속 변하기 때문에 방문할 때마다 새로운 경험을 할 수 있습니다.</p><p style=\"text-align:justify;\">또한 나인 섬 주변 바다는 아름다운 산호초와 다양한 열대어가 서식하고 있어 스노클링을 즐기기에도 매우 좋습니다. 자연 그대로의 아름다움, 독특한 모래톱, 그리고 평온한 섬 분위기를 가진 나인 섬은 부나켄의 해양 자연을 즐기고 싶은 여행객들에게 완벽한 여행지입니다.</p>', '<p style=\"text-align:justify;\">Nain Island 是位于 Bunaken National Park 区域内的一座岛屿，坐落于北苏拉威西省 Manado 附近的马纳多湾。该岛以其原始自然风光而闻名，拥有清澈透明的海水、友善的渔村，以及周围美丽的小岛景观。</p><p style=\"text-align:justify;\">奈恩岛的氛围十分宁静，非常适合希望体验简单而迷人的热带岛屿生活的游客。奈恩岛最独特的景点之一是非常美丽的沙洲。沙洲会在海水退潮时显现出来，而在涨潮时又会慢慢消失。</p><p style=\"text-align:justify;\">这一自然现象使大片白色沙滩仿佛变成漂浮在海中央的小岛。当海水退潮时，游客可以在宽广的白沙上漫步，以清澈湛蓝的大海为背景拍照，并欣赏令人惊叹的海景。由于沙洲的形状会随着海水潮位变化，因此每一次到访都会带来不同而有趣的体验。</p><p style=\"text-align:justify;\">此外，奈恩岛周围的海域也非常适合浮潜，这里拥有美丽的珊瑚礁和各种热带鱼类。原始自然的美景、独特的沙洲以及宁静的岛屿氛围，使奈恩岛成为想要体验布纳肯海洋奇观游客的理想旅游目的地。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/Tu8KiQpVvNLukg19RFr4mworQQkT02hq9684ELiY.png', 3, 1, '2026-04-27 07:47:55', '2026-05-13 08:10:47'),
(62, 'guide', NULL, 'PULAU MANTEHAGE', 'Mantehage Island', '만테하게 섬', '曼特哈格岛', '<p style=\"text-align:justify;\">Pulau Mantehage adalah salah satu pulau yang berada di kawasan Taman Nasional Bunaken di Teluk Manado, dekat kota Manado di provinsi Sulawesi Utara. Pulau ini terkenal dengan keindahan alamnya yang masih sangat alami serta kawasan hutan mangrove yang luas yang menjadi rumah bagi berbagai jenis burung, ikan, dan biota laut lainnya.&nbsp;</p><p style=\"text-align:justify;\">Suasana di Pulau Mantehage sangat tenang dan memberikan pengalaman berbeda bagi wisatawan yang ingin menikmati alam tropis yang masih asri. Salah satu daya tarik utama Pulau Mantehage adalah hutan mangrove yang sangat luas dan indah, yang menjadi salah satu ekosistem penting di kawasan Bunaken. Wisatawan dapat menjelajahi kawasan ini dengan perahu kecil sambil menikmati pemandangan akar-akar mangrove yang unik serta kehidupan satwa di sekitarnya.&nbsp;</p><p style=\"text-align:justify;\">Selain itu, perairan di sekitar pulau juga cocok untuk snorkeling, karena memiliki terumbu karang yang indah serta berbagai jenis ikan tropis yang berwarna-warni. Pulau ini juga memiliki desa-desa kecil dengan masyarakat yang ramah, sehingga wisatawan dapat melihat langsung kehidupan tradisional masyarakat pesisir.&nbsp;</p><p style=\"text-align:justify;\">Dengan kombinasi antara hutan mangrove yang eksotis, laut yang jernih, serta suasana pulau yang damai, Pulau Mantehage menjadi destinasi yang sangat menarik bagi wisatawan yang ingin merasakan sisi lain dari keindahan Bunaken.</p>', '<p style=\"text-align:justify;\">Mantehage Island is one of the islands located within the Bunaken National Park area in Manado Bay, near the city of Manado in North Sulawesi Province. The island is famous for its pristine natural beauty and its vast mangrove forests, which serve as habitats for various species of birds, fish, and other marine life.</p><p style=\"text-align:justify;\">The atmosphere on Mantehage Island is very peaceful and offers a unique experience for travelers who wish to enjoy unspoiled tropical nature. One of the island’s main attractions is its extensive and beautiful mangrove forest, which is considered one of the important ecosystems within the Bunaken area. Visitors can explore this area by small boat while admiring the unique mangrove roots and observing the wildlife living around them.</p><p style=\"text-align:justify;\">In addition, the waters surrounding the island are also ideal for snorkeling, thanks to their beautiful coral reefs and colorful tropical fish. The island is also home to small villages with friendly local communities, allowing visitors to experience the traditional lifestyle of coastal residents firsthand.</p><p style=\"text-align:justify;\">With its combination of exotic mangrove forests, crystal-clear waters, and peaceful island atmosphere, Mantehage Island has become a very attractive destination for travelers who want to discover another side of Bunaken’s natural beauty.</p>', '<p style=\"text-align:justify;\">Mantehage Island은 Bunaken National Park 지역인 마나도 만에 위치한 섬 중 하나로, 북술라웨시 주의 Manado 근처에 자리하고 있습니다. 이 섬은 자연 그대로의 아름다운 풍경과 넓은 맹그로브 숲으로 유명하며, 이곳은 다양한 새, 물고기, 그리고 여러 해양 생물들의 서식지가 되고 있습니다.</p><p style=\"text-align:justify;\">만테하게 섬의 분위기는 매우 평화롭고 조용하여, 자연 그대로의 열대 환경을 즐기고 싶은 여행객들에게 특별한 경험을 제공합니다. 이 섬의 가장 큰 매력 중 하나는 매우 넓고 아름다운 맹그로브 숲으로, 부나켄 지역의 중요한 생태계 중 하나로 알려져 있습니다. 관광객들은 작은 배를 타고 이 지역을 탐험하면서 독특한 맹그로브 뿌리와 주변 야생동물을 감상할 수 있습니다.</p><p style=\"text-align:justify;\">또한 섬 주변 바다는 아름다운 산호초와 형형색색의 열대어가 풍부하여 스노클링을 즐기기에 매우 적합합니다. 섬에는 친절한 주민들이 사는 작은 마을들도 있어, 방문객들은 해안 지역 주민들의 전통적인 생활 모습을 직접 경험할 수 있습니다.</p><p style=\"text-align:justify;\">이국적인 맹그로브 숲, 맑고 깨끗한 바다, 그리고 평온한 섬 분위기가 어우러진 만테하게 섬은 부나켄의 또 다른 아름다움을 경험하고 싶은 여행객들에게 매우 매력적인 여행지입니다.</p>', '<p style=\"text-align:justify;\">Mantehage Island 是位于 Bunaken National Park 区域内的一座岛屿，坐落于北苏拉威西省 Manado 附近的马纳多湾。该岛以其原始自然风光以及广阔的红树林而闻名，这些红树林是多种鸟类、鱼类和其他海洋生物的重要栖息地。</p><p style=\"text-align:justify;\">曼特哈格岛的氛围十分宁静，为希望感受原生态热带自然风光的游客提供了独特的体验。岛上最主要的景点之一是面积广阔且美丽的红树林，这也是布纳肯地区重要的生态系统之一。游客可以乘坐小船穿梭于红树林之间，欣赏独特的红树林根系以及周围丰富的野生动物。</p><p style=\"text-align:justify;\">此外，岛屿周围的海域也非常适合浮潜，因为这里拥有美丽的珊瑚礁和色彩斑斓的热带鱼类。岛上还有一些小村庄，居民热情友好，游客可以近距离感受沿海居民的传统生活方式。</p><p style=\"text-align:justify;\">异国风情的红树林、清澈透明的海水以及宁静祥和的岛屿氛围，使曼特哈格岛成为想要体验布纳肯另一面自然之美游客的理想旅游目的地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/BzLr56CJIyuCruZFvKq2Jv6ZvIKHpFyZTI8rQbxi.png', 4, 1, '2026-04-27 07:50:15', '2026-05-13 08:17:24'),
(63, 'guide', NULL, 'PULAU LEMBEH', 'Lembeh Island', '렘베 섬', '蓝碧岛', '<p style=\"text-align:justify;\">Pulau Lembeh adalah sebuah pulau yang terletak di sebelah timur kota Bitung di provinsi Sulawesi Utara. Pulau ini dipisahkan dari daratan utama Sulawesi oleh sebuah selat sempit yang dikenal sebagai Selat Lembeh. Kawasan ini terkenal di dunia sebagai salah satu lokasi muck diving terbaik, yaitu jenis penyelaman untuk menemukan berbagai makhluk laut unik yang hidup di dasar pasir vulkanik.&nbsp;</p><p style=\"text-align:justify;\">Pulau Lembeh menjadi surga bagi para penyelam dan fotografer bawah laut karena memiliki keanekaragaman biota laut yang sangat unik. Di perairan sekitar pulau ini, wisatawan dapat menemukan berbagai spesies langka seperti kuda laut pygmy, gurita mimik, ikan frogfish, nudibranch berwarna-warni, hingga berbagai jenis udang dan kepiting kecil yang jarang ditemukan di tempat lain.&nbsp;</p><p style=\"text-align:justify;\">Karena keunikannya, banyak penyelam dari berbagai negara datang ke Lembeh khusus untuk melakukan fotografi makro bawah laut. Selain aktivitas diving, Pulau Lembeh juga memiliki pemandangan alam yang indah dengan desa-desa nelayan yang ramah, pantai yang tenang, serta resort-resort kecil yang menawarkan pengalaman menginap dengan suasana tropis yang damai.&nbsp;</p><p style=\"text-align:justify;\">Dengan kekayaan kehidupan laut yang luar biasa dan suasana alam yang masih alami, Pulau Lembeh menjadi salah satu destinasi wisata bahari yang sangat menarik di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Lembeh Island is an island located to the east of the city of Bitung in North Sulawesi Province. The island is separated from the mainland of Sulawesi by a narrow strait known as the Lembeh Strait. This area is world-famous as one of the best muck diving destinations, a type of diving focused on discovering unique marine creatures that live on volcanic sandy seabeds.</p><p style=\"text-align:justify;\">Lembeh Island is considered a paradise for divers and underwater photographers because of its extraordinary diversity of unique marine life. In the waters surrounding the island, visitors can find rare species such as pygmy seahorses, mimic octopuses, frogfish, colorful nudibranchs, as well as various types of tiny shrimp and crabs that are rarely seen elsewhere.</p><p style=\"text-align:justify;\">Due to its uniqueness, many divers from around the world come to Lembeh specifically for underwater macro photography. Besides diving activities, Lembeh Island also offers beautiful natural scenery with friendly fishing villages, peaceful beaches, and small resorts that provide a relaxing tropical stay experience.</p><p style=\"text-align:justify;\">With its incredible marine biodiversity and pristine natural atmosphere, Lembeh Island has become one of the most fascinating marine tourism destinations in North Sulawesi.</p>', '<p style=\"text-align:justify;\">Lembeh Island은 북술라웨시 주의 Bitung 동쪽에 위치한 섬입니다. 이 섬은 렘베 해협(Lembeh Strait)이라고 불리는 좁은 해협에 의해 술라웨시 본토와 분리되어 있습니다. 이 지역은 화산 모래 바닥에 서식하는 독특한 해양 생물을 찾는 ‘머크 다이빙(Muck Diving)’의 세계적인 명소로 유명합니다.</p><p style=\"text-align:justify;\">렘베 섬은 매우 독특한 해양 생물 다양성 덕분에 다이버들과 수중 사진작가들에게 천국 같은 장소로 알려져 있습니다. 이 주변 바다에서는 피그미 해마, 미믹 문어, 프로그피시, 형형색색의 누디브랜치(갯민숭달팽이), 그리고 다른 곳에서는 보기 힘든 다양한 작은 새우와 게 등을 발견할 수 있습니다.</p><p style=\"text-align:justify;\">이러한 특별함 때문에 세계 각국의 다이버들이 수중 매크로 사진 촬영을 위해 렘베를 방문합니다. 다이빙 외에도 렘베 섬은 아름다운 자연 풍경, 친절한 어촌 마을, 평화로운 해변, 그리고 편안한 열대 분위기의 작은 리조트들로도 유명합니다.</p><p style=\"text-align:justify;\">풍부한 해양 생태계와 자연 그대로의 아름다운 분위기를 가진 렘베 섬은 북술라웨시의 가장 매력적인 해양 관광지 중 하나로 손꼽힙니다.</p>', '<p style=\"text-align:justify;\">Lembeh Island 位于北苏拉威西省 Bitung 东部。该岛与苏拉威西大陆之间被一条狭窄的海峡分隔，这条海峡被称为“蓝碧海峡（Lembeh Strait）”。这里以世界顶级“垃圾潜水（Muck Diving）”地点而闻名，这种潜水方式主要是在火山沙海底寻找各种独特的海洋生物。</p><p style=\"text-align:justify;\">蓝碧岛因其极其丰富且独特的海洋生物而成为潜水员和水下摄影师的天堂。在岛屿周围海域，游客可以发现许多罕见物种，例如侏儒海马、拟态章鱼、躄鱼（Frogfish）、色彩鲜艳的海蛞蝓（Nudibranch），以及各种在其他地方很少见到的小型虾类和螃蟹。</p><p style=\"text-align:justify;\">由于这里独特的海洋生态，许多来自世界各地的潜水爱好者专程来到蓝碧岛进行水下微距摄影。除了潜水活动之外，蓝碧岛还拥有优美的自然景观、友善的渔村、宁静的海滩，以及提供悠闲热带住宿体验的小型度假村。</p><p style=\"text-align:justify;\">凭借丰富惊人的海洋生物资源以及原始自然的环境，蓝碧岛已成为北苏拉威西最迷人的海洋旅游目的地之一。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/Q8AGeyu9MT2yMCAY0x5QH8RPkAN7gDcs4B82z0li.png', 5, 1, '2026-04-27 07:54:53', '2026-05-13 08:29:21'),
(64, 'guide', NULL, 'PULAU LIHAGA', 'Lihaga Island', '리하가 섬', '利哈加岛', '<p style=\"text-align:justify;\">Pulau Lihaga adalah sebuah pulau kecil yang indah yang terletak di wilayah Likupang, sekitar satu jam perjalanan dari kota Manado di provinsi Sulawesi Utara. Pulau ini terkenal dengan pantai berpasir putih yang sangat halus, air laut yang jernih berwarna biru kehijauan, serta pemandangan alam tropis yang masih alami dan menenangkan.&nbsp;</p><p style=\"text-align:justify;\">Pulau Lihaga merupakan destinasi wisata yang sangat populer bagi wisatawan yang ingin menikmati keindahan pantai tropis yang bersih dan tenang. Di sekitar pulau ini, wisatawan dapat menikmati berbagai aktivitas seperti berenang, snorkeling, berjemur di pantai, serta berjalan mengelilingi pulau sambil menikmati panorama laut yang indah. Air laut yang sangat jernih membuat wisatawan dapat dengan mudah melihat ikan-ikan kecil dan terumbu karang di dekat pantai.</p>', '<p style=\"text-align:justify;\">Lihaga Island is a beautiful small island located in the Likupang area, about one hour from the city of Manado in North Sulawesi Province. The island is famous for its soft white sandy beaches, crystal-clear turquoise waters, and peaceful tropical scenery that remains largely untouched by modern development.</p><p style=\"text-align:justify;\">Lihaga Island is a very popular destination for travelers who want to enjoy the beauty of a clean and tranquil tropical beach. Around the island, visitors can enjoy various activities such as swimming, snorkeling, sunbathing on the beach, and walking around the island while admiring the beautiful ocean views. The exceptionally clear seawater allows tourists to easily see small fish and coral reefs near the shore.</p>', '<p style=\"text-align:justify;\">Lihaga Island은 북술라웨시 주 Manado 에서 약 1시간 거리에 있는 리쿠팡(Likupang) 지역에 위치한 아름다운 작은 섬입니다. 이 섬은 매우 부드러운 백사장, 맑고 푸른 에메랄드빛 바다, 그리고 자연 그대로의 평화로운 열대 풍경으로 유명합니다.</p><p style=\"text-align:justify;\">리하가 섬은 깨끗하고 조용한 열대 해변의 아름다움을 즐기고 싶은 관광객들에게 매우 인기 있는 여행지입니다. 이 섬에서는 수영, 스노클링, 해변에서 일광욕, 그리고 아름다운 바다 풍경을 감상하며 섬 주변을 산책하는 등 다양한 활동을 즐길 수 있습니다. 특히 바닷물이 매우 맑아 해변 가까이에서도 작은 물고기들과 산호초를 쉽게 볼 수 있습니다.</p>', '<p style=\"text-align:justify;\">Lihaga Island 是位于北苏拉威西省 Likupang 地区的一座美丽小岛，距离 Manado 大约一小时车程。该岛以细腻洁白的沙滩、清澈见底的蓝绿色海水，以及宁静原始的热带自然风光而闻名。</p><p style=\"text-align:justify;\">利哈加岛是非常受欢迎的旅游目的地，特别适合想要享受干净宁静热带海滩的游客。在岛屿周围，游客可以进行游泳、浮潜、海边日光浴，以及环岛漫步欣赏美丽海景等活动。由于海水非常清澈，游客甚至可以轻松看到靠近海岸的小鱼和珊瑚礁。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/5GOuSW1gzuzyerygz5kELp6fpzTLEUJOBnvlcrN7.png', 6, 1, '2026-04-27 07:59:23', '2026-05-13 08:39:39'),
(65, 'guide', NULL, 'PULAU GANGGA', 'Gangga Island', '강가 섬', '岗嘎岛', '<p style=\"text-align:justify;\">Pulau Gangga adalah sebuah pulau indah yang terletak di wilayah utara Sulawesi Utara, tidak jauh dari kota Manado dan berada di dekat kawasan Taman Nasional Bunaken. Pulau ini terkenal dengan pantai berpasir putih yang bersih, air laut yang sangat jernih, serta suasana tropis yang tenang dan alami.&nbsp;</p><p style=\"text-align:justify;\">Pulau Gangga juga dikelilingi oleh pemandangan laut biru yang luas dan beberapa pulau kecil yang membuat panorama alamnya terlihat sangat memukau. Di Pulau Gangga, wisatawan dapat menikmati berbagai aktivitas menarik seperti snorkeling dan diving, karena perairan di sekitar pulau memiliki terumbu karang yang indah dan beragam jenis ikan tropis.&nbsp;</p><p style=\"text-align:justify;\">Selain itu, wisatawan juga dapat berenang, berjalan santai di sepanjang pantai, menikmati matahari terbenam, atau menjelajahi desa lokal untuk melihat kehidupan masyarakat pulau yang ramah. Beberapa resort di pulau ini juga menawarkan pengalaman menginap yang nyaman dengan pemandangan laut yang indah.&nbsp;</p><p style=\"text-align:justify;\">Dengan keindahan alam yang masih alami, kehidupan laut yang kaya, serta suasana yang damai, Pulau Gangga menjadi destinasi yang sempurna bagi wisatawan yang ingin bersantai sekaligus menikmati keindahan laut tropis di Sulawesi Utara.</p>', '<p style=\"text-align:justify;\">Gangga Island is a beautiful island located in the northern part of North Sulawesi, not far from the city of Manado and close to the Bunaken National Park area. The island is famous for its clean white sandy beaches, crystal-clear seawater, and peaceful tropical atmosphere.</p><p style=\"text-align:justify;\">Gangga Island is also surrounded by vast blue ocean views and several small islands, creating breathtaking natural scenery. On Gangga Island, visitors can enjoy various exciting activities such as snorkeling and diving, since the waters around the island are rich with beautiful coral reefs and many species of tropical fish.</p><p style=\"text-align:justify;\">In addition, tourists can swim, take relaxing walks along the beach, enjoy beautiful sunsets, or explore local villages to experience the friendly lifestyle of the island community. Several resorts on the island also offer comfortable accommodations with stunning ocean views.</p><p style=\"text-align:justify;\">With its pristine natural beauty, rich marine life, and tranquil atmosphere, Gangga Island has become a perfect destination for travelers who want to relax while enjoying the beauty of the tropical sea in North Sulawesi.</p>', '<p style=\"text-align:justify;\">Gangga Island은 북술라웨시 북부 지역에 위치한 아름다운 섬으로, Manado 에서 멀지 않으며 Bunaken National Park 근처에 자리하고 있습니다. 이 섬은 깨끗한 백사장, 매우 맑은 바닷물, 그리고 평화롭고 자연적인 열대 분위기로 유명합니다.</p><p style=\"text-align:justify;\">강가 섬은 넓고 푸른 바다와 주변의 작은 섬들로 둘러싸여 있어 매우 아름다운 자연 경관을 자랑합니다. 이곳에서는 아름다운 산호초와 다양한 열대어가 서식하고 있어 스노클링과 다이빙 같은 활동을 즐기기에 매우 좋습니다.</p><p style=\"text-align:justify;\">또한 관광객들은 수영을 하거나 해변을 따라 산책하고, 아름다운 석양을 감상하거나, 현지 마을을 방문해 친절한 섬 주민들의 생활을 경험할 수도 있습니다. 섬의 여러 리조트에서는 아름다운 바다 전망과 함께 편안한 숙박 경험도 제공합니다.</p><p style=\"text-align:justify;\">자연 그대로의 아름다움, 풍부한 해양 생태계, 그리고 평온한 분위기를 가진 강가 섬은 북술라웨시의 열대 바다를 즐기며 휴식을 원하는 여행객들에게 완벽한 여행지입니다.</p>', '<p style=\"text-align:justify;\">Gangga Island 是位于北苏拉威西北部的一座美丽岛屿，距离 Manado 不远，并靠近 Bunaken National Park 区域。该岛以洁白干净的沙滩、清澈透明的海水以及宁静自然的热带氛围而闻名。</p><p style=\"text-align:justify;\">岗嘎岛四周被广阔的蓝色海洋和数座小岛环绕，形成令人惊叹的自然景观。在这里，游客可以体验浮潜和潜水等丰富活动，因为岛屿周围海域拥有美丽的珊瑚礁和各种热带鱼类。</p><p style=\"text-align:justify;\">此外，游客还可以游泳、沿着海滩悠闲散步、欣赏迷人的日落，或前往当地村庄体验友善岛民的生活方式。岛上的一些度假村还提供舒适的住宿，并拥有绝美的海景。</p><p style=\"text-align:justify;\">凭借原始自然的美景、丰富的海洋生态以及宁静祥和的氛围，岗嘎岛成为希望在北苏拉威西享受热带海洋与放松身心游客的理想旅游目的地。</p>', 'https://api.welcomemanado.my.id/storage', 7, 1, '2026-04-27 08:02:33', '2026-05-14 15:00:21'),
(66, 'guide', NULL, 'PULAU BANGKA', NULL, NULL, NULL, 'Pulau Bangka adalah sebuah pulau indah yang terletak di bagian utara Sulawesi Utara, tidak jauh dari kota Manado dan dekat dengan kawasan Likupang. Pulau ini dikenal sebagai salah satu destinasi wisata bahari yang menakjubkan dengan pantai berpasir putih, air laut yang jernih berwarna biru kehijauan, serta pemandangan alam tropis yang masih sangat alami.\n\nPulau Bangka terkenal di kalangan wisatawan dan penyelam karena memiliki terumbu karang yang sangat indah dan beragam kehidupan laut. Perairan di sekitar pulau ini menjadi tempat yang sangat baik untuk snorkeling dan diving, di mana wisatawan dapat melihat berbagai jenis ikan tropis, karang yang berwarna-warni, hingga penyu laut. Selain itu, Pulau Bangka juga menawarkan pemandangan laut yang luas serta suasana yang tenang, jauh dari keramaian kota.\n\nDi pulau ini, wisatawan dapat melakukan berbagai aktivitas seperti berenang, snorkeling, diving, berjalan santai di sepanjang pantai, menikmati matahari terbenam, atau bersantai di resort-resort tropis yang menghadap langsung ke laut. Dengan keindahan alam yang masih alami, air laut yang jernih, dan kehidupan laut yang kaya, Pulau Bangka menjadi salah satu tempat yang sangat menarik untuk menikmati pesona laut di Sulawesi Utara.', 'Pulau Bangka is a beautiful island located in the northern part of Sulawesi Utara, not far from the city of Manado and close to the Likupang area. The island is well known for its stunning marine scenery, featuring white sandy beaches, crystal-clear turquoise waters, and pristine tropical landscapes.\n\nPulau Bangka is especially popular among divers and marine tourism enthusiasts because of its rich coral reefs and diverse marine life. The surrounding waters are perfect for snorkeling and diving, where visitors can observe colorful coral reefs, tropical fish, and sometimes even sea turtles. The island also offers wide ocean views and a peaceful environment, making it a perfect escape from the busy city life.\n\nVisitors to Bangka Island can enjoy various activities such as swimming, snorkeling, diving, walking along the beach, watching spectacular sunsets, or relaxing at tropical resorts that face the beautiful ocean. With its untouched natural beauty and vibrant marine ecosystem, Pulau Bangka is a wonderful destination to experience the tropical sea of North Sulawesi.', 'Pulau Bangka는 인도네시아 Sulawesi Utara 북쪽에 위치한 아름다운 섬으로, Manado에서 가까우며 Likupang 지역과도 인접해 있습니다. 이 섬은 하얀 모래 해변과 맑은 청록색 바다, 그리고 자연 그대로의 열대 풍경으로 유명한 해양 관광지입니다.\n\n방카 섬은 특히 아름다운 산호초와 다양한 해양 생물로 유명하여 많은 다이버와 관광객들이 방문합니다. 섬 주변 바다는 스노클링과 스쿠버 다이빙을 즐기기에 매우 좋은 환경을 가지고 있으며, 화려한 산호초와 열대어, 때로는 바다거북도 볼 수 있습니다. 또한 넓게 펼쳐진 바다 전망과 평화로운 분위기로 도시의 번잡함에서 벗어나 휴식을 취하기에 좋은 장소입니다.\n\n관광객들은 이곳에서 수영, 스노클링, 다이빙, 해변 산책, 아름다운 일몰 감상, 또는 바다를 바라보는 리조트에서 휴식을 즐길 수 있습니다. 자연 그대로의 아름다움과 풍부한 해양 생태계를 가진 방카 섬은 북술라웨시 바다의 매력을 경험할 수 있는 훌륭한 여행지입니다.', 'Pulau Bangka 是位于印度尼西亚 Sulawesi Utara 北部的一座美丽岛屿，距离 Manado 不远，并靠近 Likupang 地区。这里以洁白的沙滩、清澈的碧蓝海水以及原始的热带自然景观而闻名，是一个非常迷人的海岛旅游目的地。\n\n邦加岛因其 丰富的珊瑚礁和多样的海洋生物 而受到潜水爱好者和游客的喜爱。岛屿周围的海域非常适合 浮潜和潜水，游客可以看到色彩斑斓的珊瑚、各种热带鱼类，有时还能看到海龟。这里宽阔的海景和宁静的环境也让游客能够远离城市的喧嚣，享受轻松的海岛时光。\n\n来到邦加岛，游客可以体验 游泳、浮潜、潜水、在海滩散步、欣赏壮丽的日落，或在面向大海的度假村放松休息。凭借原始自然的环境和丰富的海洋生态，邦加岛成为体验北苏拉威西热带海洋之美的理想旅游胜地。', NULL, 8, 1, '2026-04-27 08:04:30', '2026-04-27 08:04:30'),
(67, 'guide', NULL, 'MONUMEN PATUNG YESUS MEMBERKATI', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Patung Yesus Memberkati adalah salah satu monumen paling ikonik di kota Manado, yang terletak di kawasan Citraland Manado, provinsi Sulawesi Utara. Patung megah ini menggambarkan Yesus Kristus dengan kedua tangan terbuka seolah sedang memberkati kota Manado dan seluruh masyarakatnya. Dengan posisi tubuh yang sedikit condong ke depan, patung ini terlihat seperti sedang terbang dari langit untuk memberkati dunia, sehingga sering dijuluki sebagai “Flying Jesus Statue”.&nbsp;</p><p style=\"text-align:justify;\">Monumen ini memiliki tinggi sekitar 50 meter termasuk penyangganya, dengan 30 meter tinggi patung dan 20 meter bagian pedestal. Ketika selesai dibangun pada tahun 2010, patung ini dikenal sebagai patung Yesus tertinggi ke-2 di Asia dan ke-4 tertinggi di dunia. Selain nilai religiusnya yang kuat, Patung Yesus Memberkati juga menjadi simbol perdamaian dan persaudaraan masyarakat Sulawesi Utara.&nbsp;</p><p style=\"text-align:justify;\">Dari area sekitar monumen, pengunjung dapat menikmati panorama indah kota Manado, laut biru yang luas, serta pegunungan di sekitarnya. Dengan desain yang unik, makna spiritual yang mendalam, dan pemandangan yang menakjubkan, monumen ini menjadi salah satu destinasi wisata yang paling terkenal dan wajib dikunjungi di Manado.</p>', '<p style=\"text-align:justify;\">Patung Yesus Memberkati is one of the most iconic monuments in the city of Manado, located in the Citraland Manado area of North Sulawesi. This magnificent statue depicts Jesus Christ with both arms open, as if blessing the city of Manado and all of its people. With its body leaning slightly forward, the statue appears to be flying from the sky to bless the world, which is why it is often called the “Flying Jesus Statue.”</p><p style=\"text-align:justify;\">The monument stands approximately 50 meters tall including its pedestal, consisting of a 30-meter statue and a 20-meter supporting base. When it was completed in 2010, it was recognized as the second tallest Jesus statue in Asia and the fourth tallest in the world. Beyond its strong religious significance, the Blessing Jesus Statue also symbolizes peace and unity among the people of North Sulawesi.</p><p style=\"text-align:justify;\">From the surrounding area of the monument, visitors can enjoy beautiful panoramic views of Manado city, the vast blue sea, and the surrounding mountains. With its unique design, deep spiritual meaning, and breathtaking scenery, this monument has become one of the most famous and must-visit tourist destinations in Manado.</p>', '<p style=\"text-align:justify;\">Patung Yesus Memberkati는 North Sulawesi의 Citraland Manado 지역에 위치한 Manado 시의 가장 상징적인 기념물 중 하나입니다. 이 웅장한 동상은 두 팔을 활짝 펼친 예수 그리스도의 모습을 표현하고 있으며, 마치 마나도 도시와 모든 사람들을 축복하는 듯한 모습입니다. 몸이 약간 앞으로 기울어진 형태 덕분에 하늘에서 날아와 세상을 축복하는 것처럼 보이며, 그래서 “Flying Jesus Statue”라는 별명으로도 불립니다.</p><p style=\"text-align:justify;\">이 기념물은 받침대를 포함하여 약 50미터 높이로, 동상 자체는 30미터이고 받침대는 20미터입니다. 2010년에 완공되었을 당시, 이 동상은 아시아에서 두 번째로 높은 예수상이며 세계에서 네 번째로 높은 예수상으로 알려졌습니다. 강한 종교적 의미뿐만 아니라, 축복의 예수상은 북술라웨시 사람들의 평화와 화합을 상징하기도 합니다.</p><p style=\"text-align:justify;\">기념물 주변에서는 마나도 시내, 넓고 푸른 바다, 그리고 주변 산들의 아름다운 전경을 감상할 수 있습니다. 독특한 디자인과 깊은 영적 의미, 그리고 아름다운 풍경을 갖춘 이 기념물은 마나도의 가장 유명하고 꼭 방문해야 할 관광지 중 하나가 되었습니다.</p>', '<p style=\"text-align:justify;\">Patung Yesus Memberkati 是位于印度尼西亚North Sulawesi省 Citraland Manado 区域内、Manado市最具代表性的地标之一。这座宏伟的雕像描绘了双手张开的耶稣基督，仿佛正在祝福马纳多市及其所有人民。由于雕像身体略微向前倾斜，看起来像是从天空飞来祝福世界，因此也被称为“飞翔的耶稣雕像（Flying Jesus Statue）”。</p><p style=\"text-align:justify;\">这座纪念碑连同底座总高约50米，其中雕像本身高30米，底座高20米。2010年建成时，它被认为是亚洲第二高、世界第四高的耶稣雕像。除了深厚的宗教意义之外，祝福耶稣雕像也象征着北苏拉威西人民之间的和平与团结。</p><p style=\"text-align:justify;\">在纪念碑周围，游客可以欣赏到马纳多市区、辽阔的蓝色海洋以及周边群山的壮丽景色。凭借独特的设计、深刻的精神意义以及令人惊叹的自然风光，这座纪念碑已成为马纳多最著名、最值得参观的旅游景点之一。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/ejQFMizpqLZrYa699GK0xNwOdGgIm6L2fM2pea4D.png', 12, 1, '2026-04-27 08:29:13', '2026-05-15 01:33:27'),
(68, 'guide', NULL, 'GEREJA SENTRUM', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Gereja Sentrum Manado adalah salah satu gereja Protestan tertua dan paling bersejarah di kota Manado, provinsi Sulawesi Utara. Gereja ini menjadi simbol penting perkembangan agama Kristen di wilayah Minahasa dan Manado sejak masa kolonial.&nbsp;</p><p style=\"text-align:justify;\">Sejarah Gereja Sentrum bermula pada abad ke-19 ketika para misionaris dari Nederlandsch Zendeling Genootschap (NZG) datang ke Minahasa untuk menyebarkan ajaran Kristen.&nbsp;</p><p style=\"text-align:justify;\">Gereja ini mulai dibangun sekitar tahun 1830-an dan kemudian berkembang menjadi pusat kegiatan jemaat Protestan di kota Manado. Selama perjalanan sejarahnya, bangunan gereja ini beberapa kali mengalami renovasi dan pembangunan kembali untuk menyesuaikan dengan pertumbuhan jemaat. Arsitektur Gereja Sentrum memiliki gaya klasik Eropa yang sederhana namun elegan, dengan menara gereja yang menjadi ciri khasnya.&nbsp;</p><p style=\"text-align:justify;\">Hingga saat ini, gereja ini masih aktif digunakan untuk ibadah oleh jemaat dari Gereja Masehi Injili di Minahasa (GMIM). Selain sebagai tempat ibadah, Gereja Sentrum juga menjadi salah satu landmark sejarah dan budaya yang menunjukkan kuatnya pengaruh Kekristenan dalam kehidupan masyarakat Manado.</p>', '<p>Gereja Sentrum Manado is one of the oldest and most historic Protestant churches in the city of Manado, located in North Sulawesi. The church has become an important symbol of the development of Christianity in the Minahasa and Manado regions since the colonial era.</p><p>The history of Sentrum Church began in the 19th century when missionaries from the Nederlandsch Zendeling Genootschap (NZG) came to Minahasa to spread Christian teachings.</p><p>The church began to be built around the 1830s and later developed into the center of Protestant congregation activities in Manado. Throughout its history, the church building underwent several renovations and reconstructions to accommodate the growing number of worshippers. The architecture of Sentrum Church reflects a simple yet elegant European classical style, with its church tower becoming one of its most recognizable features.</p><p>Until today, the church is still actively used for worship services by the congregation of Gereja Masehi Injili di Minahasa (GMIM). Besides functioning as a place of worship, Sentrum Church is also an important historical and cultural landmark that reflects the strong influence of Christianity in the lives of the people of Manado.</p>', '<p style=\"text-align:justify;\">Gereja Sentrum Manado는 North Sulawesi의 Manado에 위치한 가장 오래되고 역사적인 개신교 교회 중 하나입니다. 이 교회는 식민지 시대 이후 미나하사와 마나도 지역에서 기독교 발전의 중요한 상징이 되었습니다.</p><p style=\"text-align:justify;\">센트룸 교회의 역사는 19세기, 네덜란드 선교 단체인 Nederlandsch Zendeling Genootschap(NZG)의 선교사들이 기독교를 전파하기 위해 미나하사 지역에 도착하면서 시작되었습니다.</p><p style=\"text-align:justify;\">교회는 1830년대경 건축되기 시작했으며, 이후 마나도 지역 개신교 신자들의 중심 예배 장소로 발전하였습니다. 역사 속에서 교회 건물은 증가하는 신도 수에 맞추기 위해 여러 차례 보수와 재건을 거쳤습니다. 센트룸 교회의 건축 양식은 단순하면서도 우아한 유럽 고전 양식을 보여주며, 특히 교회 탑은 이 교회의 대표적인 특징으로 알려져 있습니다.</p><p style=\"text-align:justify;\">현재까지도 이 교회는 Gereja Masehi Injili di Minahasa (GMIM) 교단 신자들의 예배 장소로 활발히 사용되고 있습니다. 예배 장소일 뿐만 아니라, 센트룸 교회는 마나도 사회 속에서 기독교의 강한 영향력을 보여주는 중요한 역사·문화적 랜드마크이기도 합니다.</p>', '<p style=\"text-align:justify;\">Gereja Sentrum Manado 是位于印度尼西亚North Sulawesi省Manado市最古老、最具历史意义的新教教堂之一。自殖民时期以来，这座教堂一直是米纳哈萨（Minahasa）和马纳多地区基督教发展的重要象征。</p><p style=\"text-align:justify;\">Sentrum 教堂的历史始于19世纪，当时来自 Nederlandsch Zendeling Genootschap（NZG）的传教士来到米纳哈萨地区传播基督教教义。</p><p style=\"text-align:justify;\">这座教堂大约于1830年代开始建造，后来逐渐发展成为马纳多市新教教徒活动的中心。在其历史发展过程中，教堂曾多次进行翻修和重建，以适应不断增长的信徒人数。Sentrum 教堂的建筑风格采用简洁而优雅的欧洲古典设计，其中教堂塔楼是最具代表性的特色之一。</p><p style=\"text-align:justify;\">直到今天，这座教堂仍然由Gereja Masehi Injili di Minahasa (GMIM)的会众积极用于礼拜活动。除了作为宗教礼拜场所之外，Sentrum 教堂也是一处重要的历史与文化地标，展现了基督教在马纳多人生活中的深远影响。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/eSJTIPY4qNSuOXuT6obPTwqMvlZSb5bEmXlev6H3.png', 13, 1, '2026-04-27 08:33:54', '2026-05-15 01:37:25'),
(69, 'food', 'main', 'Cakalang Fufu', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Cakalang fufu adalah salah satu ikon kuliner khas dari Sulawesi Utara yang begitu menggoda sejak pertama kali dilihat—apalagi saat aromanya mulai tercium. Ikan cakalang segar diasapi secara tradisional di atas bara kayu selama berjam-jam, menghasilkan warna cokelat keemasan yang mengilap dengan tekstur daging yang padat namun tetap lembut.</p><p style=\"text-align:justify;\">Keunikan cakalang fufu terletak pada proses pengasapannya. Ikan dibelah, dibersihkan, lalu dijepit dengan bambu sebelum diasapi perlahan. Asap dari kayu pilihan memberikan cita rasa khas: gurih, sedikit smoky, dan kaya rasa alami laut. Semakin lama diasapi, semakin dalam pula karakter rasanya—membuat setiap suapan terasa autentik dan berkelas.</p><p style=\"text-align:justify;\">Saat disantap, cakalang fufu sering dipadukan dengan sambal dabu-dabu yang segar dan pedas, nasi hangat, serta lalapan sederhana. Perpaduan ini menciptakan harmoni rasa yang sulit dilupakan: pedas, asam, gurih, dan sedikit manis berpadu sempurna di lidah.</p><p style=\"text-align:justify;\">Tak hanya lezat, cakalang fufu juga mencerminkan budaya pesisir masyarakat Sulawesi Utara—tentang kesederhanaan, kearifan lokal, dan kekayaan hasil laut. Hidangan ini bukan sekadar makanan, melainkan pengalaman rasa yang membawa siapa pun lebih dekat dengan jiwa dan tradisi daerahnya.</p>', '<p style=\"text-align:justify;\">Cakalang fufu is one of the iconic culinary specialties from North Sulawesi that instantly captivates both the eyes and the senses—especially once its aroma fills the air. Made from fresh skipjack tuna, the fish is traditionally smoked over wood fire for hours, resulting in a beautiful golden-brown color with a firm yet tender texture.</p><p style=\"text-align:justify;\">What makes cakalang fufu truly unique is its smoking process. The fish is split, cleaned, and clamped with bamboo before being slowly smoked. The wood smoke infuses it with a rich, savory, and slightly smoky flavor that highlights the natural taste of the sea. The longer it is smoked, the deeper and more complex the flavor becomes.</p><p style=\"text-align:justify;\">It is commonly served with spicy and refreshing dabu-dabu sambal, warm rice, and fresh vegetables. This combination creates a perfect harmony of flavors—spicy, tangy, savory, and slightly sweet.</p><p style=\"text-align:justify;\">More than just a dish, cakalang fufu represents the coastal culture of North Sulawesi—simple, authentic, and deeply connected to the richness of the ocean.</p>', '<p style=\"text-align:justify;\">Cakalang fufu는 북술라웨시를 대표하는 전통 요리로, 처음 보는 순간부터 시각과 후각을 사로잡는 매력을 지니고 있습니다. 신선한 가다랑어를 사용하여 전통 방식으로 장시간 나무 연기에 훈제해 황금빛 갈색과 쫄깃하면서도 부드러운 식감을 만들어냅니다.</p><p style=\"text-align:justify;\">이 요리의 가장 큰 특징은 바로 훈제 과정입니다. 생선을 반으로 갈라 깨끗이 손질한 뒤 대나무로 고정하여 천천히 훈제합니다. 나무 연기가 스며들면서 깊고 풍부한 감칠맛과 은은한 스모키 향이 더해집니다. 훈제 시간이 길어질수록 맛은 더욱 깊어집니다.</p><p style=\"text-align:justify;\">보통 매콤하고 상큼한 다부다부 삼발, 따뜻한 밥, 신선한 채소와 함께 제공됩니다. 이 조합은 매운맛, 신맛, 감칠맛, 그리고 약간의 단맛이 어우러진 완벽한 조화를 만들어냅니다.</p><p style=\"text-align:justify;\">Cakalang fufu는 단순한 음식이 아니라 북술라웨시 해안 지역의 문화와 전통, 그리고 바다의 풍요로움을 담고 있는 특별한 요리입니다.</p>', '<p style=\"text-align:justify;\">Cakalang fufu 是来自北苏拉威西的标志性美食之一，从外观到香气都令人难以抗拒。它选用新鲜的鲣鱼，经过传统木火长时间熏制，呈现出诱人的金棕色，同时保持紧实却柔嫩的口感。</p><p style=\"text-align:justify;\">这种美食的独特之处在于其熏制工艺。鱼被剖开、清洗后，用竹子夹住并慢慢熏制。木烟赋予其浓郁的鲜味和淡淡的烟熏香气，完美保留了海洋的天然风味。熏制时间越长，味道越加深厚。</p><p style=\"text-align:justify;\">通常搭配辛辣清新的达布达布辣酱、热米饭以及新鲜蔬菜一起食用，形成辛辣、酸爽、鲜美与微甜的完美平衡。</p><p style=\"text-align:justify;\">Cakalang fufu不仅是一道美食，更体现了北苏拉威西沿海地区的文化与传统，以及丰富的海洋资源。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/WY3vZiP1RoV4D7NQcMQQ3ewyHaDl3RJlxGy91Oby.jpg', 2, 1, '2026-04-28 01:51:04', '2026-04-28 02:50:00'),
(70, 'food', 'main', 'Ayam dan ikan Woku', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Ayam dan ikan woku adalah dua hidangan khas dari Sulawesi Utara yang menghadirkan ledakan rasa dalam setiap suapan—kaya rempah, segar, dan begitu menggugah selera.</p><p style=\"text-align:justify;\">Woku sendiri adalah teknik memasak tradisional yang menggunakan campuran bumbu khas seperti kunyit, jahe, serai, daun jeruk, daun kunyit, dan kemangi. Semua bahan ini berpadu menciptakan kuah kuning keemasan yang harum, dengan cita rasa pedas, segar, dan sedikit asam yang sangat khas.</p><p style=\"text-align:justify;\">Pada ayam woku, potongan ayam dimasak hingga empuk dan meresap sempurna dalam bumbu. Dagingnya juicy dengan lapisan rasa yang dalam, membuat setiap gigitan terasa hangat dan memuaskan. Sementara itu, ikan woku—biasanya menggunakan ikan laut segar seperti kakap atau tuna—memberikan sensasi yang lebih ringan namun tetap kaya rasa. Daging ikan yang lembut berpadu dengan bumbu woku yang meresap hingga ke dalam, menghadirkan kesegaran khas hidangan pesisir.</p><p style=\"text-align:justify;\">Aroma daun kemangi dan rempah yang kuat menjadi ciri utama yang langsung menggoda selera bahkan sebelum makanan tersaji di meja. Disajikan dengan nasi putih hangat, ayam dan ikan woku menciptakan perpaduan sempurna antara gurih, pedas, dan segar.</p><p style=\"text-align:justify;\">Lebih dari sekadar hidangan, ayam dan ikan woku mencerminkan karakter kuliner Sulawesi Utara yang berani, kaya rasa, dan penuh semangat—sebuah pengalaman kuliner yang tak hanya mengenyangkan, tetapi juga meninggalkan kesan mendalam.</p>', '<p>Chicken and fish woku are two signature dishes from North Sulawesi that deliver an explosion of flavors in every bite—rich in spices, fresh, and incredibly appetizing.</p><p>Woku is a traditional cooking method that uses a vibrant blend of spices such as turmeric, ginger, lemongrass, kaffir lime leaves, turmeric leaves, and basil. These ingredients come together to create a fragrant golden-yellow sauce with a distinctive taste—spicy, fresh, and slightly tangy.</p><p>In chicken woku, tender pieces of chicken are cooked until perfectly infused with the spices. The meat becomes juicy and full of deep flavor, making each bite warm and satisfying. Meanwhile, fish woku—often prepared with fresh seafood like snapper or tuna—offers a lighter yet equally flavorful experience. The soft fish absorbs the rich spices, creating a refreshing taste typical of coastal cuisine.</p><p>The aroma of basil and spices is unmistakable, instantly stimulating the appetite even before the dish is served. Paired with warm steamed rice, chicken and fish woku offer a perfect harmony of savory, spicy, and fresh flavors.</p><p>More than just food, these dishes reflect the bold, vibrant, and spirited culinary identity of North Sulawesi—an unforgettable taste experience.</p>', '<p>아얌 워쿠(닭고기)와 이칸 워쿠(생선)는 북술라웨시를 대표하는 요리로, 한 입마다 풍부한 향신료와 신선함이 어우러진 강렬한 맛을 선사합니다.</p><p>워쿠는 강황, 생강, 레몬그라스, 카피르 라임 잎, 강황 잎, 바질 등 다양한 향신료를 사용하는 전통 조리법입니다. 이 재료들이 어우러져 향긋한 황금빛 소스를 만들며, 매콤하고 상큼하며 약간의 산미가 있는 독특한 맛을 냅니다.</p><p>닭고기 워쿠는 부드러운 닭고기가 양념에 깊이 배어들어 육즙이 풍부하고 깊은 맛을 자랑합니다. 반면 생선 워쿠는 신선한 생선(도미나 참치 등)을 사용하여 더 가볍지만 여전히 풍부한 맛을 제공합니다. 부드러운 생선 살에 향신료가 스며들어 해안 지역 특유의 신선한 풍미를 느낄 수 있습니다.</p><p>바질과 향신료의 향은 요리가 나오기 전부터 식욕을 자극합니다. 따뜻한 밥과 함께 먹으면 짭짤함, 매운맛, 상큼함이 완벽한 조화를 이룹니다.</p><p>이 요리들은 단순한 음식이 아니라 북술라웨시의 대담하고 활기찬 미식 문화를 잘 보여주는 특별한 경험입니다.</p>', '<p>鸡肉和鱼肉Woku是来自北苏拉威西的两道代表性美食，每一口都带来浓郁香料与清新风味的完美爆发。</p><p>Woku是一种传统烹饪方式，使用姜黄、生姜、香茅、卡菲尔酸橙叶、姜黄叶和罗勒等多种香料。这些食材融合在一起，形成香气浓郁的金黄色酱汁，口味辛辣、清新且略带酸味。</p><p>鸡肉Woku中，鲜嫩的鸡肉被慢慢炖煮，充分吸收香料的精华，口感多汁且味道浓郁。鱼肉Woku则通常选用新鲜的海鱼，如鲷鱼或金枪鱼，口感更清爽却同样丰富。鱼肉鲜嫩，与香料完美融合，展现出典型的海岸风味。</p><p>罗勒与香料的香气在上桌前就已令人食欲大开。搭配热腾腾的白米饭，形成咸香、辛辣与清新的完美平衡。</p><p>这两道菜不仅仅是美食，更体现了北苏拉威西大胆、丰富且充满活力的饮食文化。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/WJD3uGBpw8V2vQviFWaGdyyx6eodW6TwkDFzNIm4.webp', 3, 1, '2026-04-28 02:01:05', '2026-04-28 05:41:22'),
(71, 'food', 'main', 'Tinoransak', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Tinoransak adalah salah satu hidangan khas dari Sulawesi Utara yang dikenal dengan cita rasa kuat, kaya rempah, dan tampilan yang menggoda. Hidangan ini biasanya menggunakan daging—sering kali daging babi—yang dimasak bersama aneka bumbu seperti cabai, bawang, serai, daun jeruk, dan berbagai rempah lokal lainnya.</p><p style=\"text-align:justify;\">Proses memasaknya membuat bumbu meresap sempurna hingga ke dalam serat daging, menghasilkan rasa pedas gurih yang intens dengan sentuhan aroma herbal yang khas. Kuahnya cenderung kental dan berwarna kemerahan, mencerminkan kekayaan bumbu yang digunakan. Setiap suapan menghadirkan sensasi hangat, pedas, dan penuh karakter.</p><p style=\"text-align:justify;\">Tinoransak biasanya disajikan dalam berbagai acara keluarga maupun perayaan adat, menjadi simbol kebersamaan dan kekayaan tradisi kuliner masyarakat Sulawesi Utara. Disantap bersama nasi hangat, hidangan ini menghadirkan pengalaman rasa yang autentik dan tak terlupakan.</p>', '<p style=\"text-align:justify;\">Tinoransak is a traditional dish from North Sulawesi, known for its bold flavors, rich spices, and visually enticing appearance. It is typically made with meat—often pork—cooked with a variety of spices such as chili, garlic, lemongrass, kaffir lime leaves, and other local herbs.</p><p style=\"text-align:justify;\">The cooking process allows the spices to deeply penetrate the meat, resulting in an intense savory and spicy flavor with a distinctive herbal aroma. The sauce is usually thick and reddish in color, reflecting the richness of the seasoning. Each bite delivers warmth, spice, and depth of character.</p><p style=\"text-align:justify;\">Tinoransak is often served during family gatherings and traditional celebrations, symbolizing togetherness and the richness of North Sulawesi’s culinary heritage. Enjoyed with warm rice, it offers an authentic and unforgettable taste experience.</p>', '<p style=\"text-align:justify;\">Tinoransak은 북술라웨시의 대표적인 전통 요리로, 강렬한 맛과 풍부한 향신료, 그리고 매력적인 비주얼로 유명합니다. 이 요리는 보통 돼지고기를 사용하며, 고추, 마늘, 레몬그라스, 카피르 라임 잎 등 다양한 향신료와 함께 조리됩니다.</p><p style=\"text-align:justify;\">조리 과정에서 양념이 고기에 깊이 스며들어 진하고 매콤한 맛과 독특한 허브 향을 만들어냅니다. 소스는 일반적으로 걸쭉하고 붉은 색을 띠며, 풍부한 향신료의 사용을 잘 보여줍니다. 한 입마다 따뜻함과 매운맛, 깊은 풍미를 느낄 수 있습니다.</p><p style=\"text-align:justify;\">Tinoransak은 가족 모임이나 전통 행사에서 자주 제공되며, 공동체의 유대감과 북술라웨시 음식 문화의 풍요로움을 상징합니다. 따뜻한 밥과 함께 즐기면 더욱 특별한 미식 경험을 선사합니다.</p>', '<p style=\"text-align:justify;\">Tinoransak是来自北苏拉威西的一道传统美食，以其浓郁的风味、丰富的香料和诱人的外观而闻名。它通常以肉类（多为猪肉）为主料，搭配辣椒、大蒜、香茅、卡菲尔酸橙叶等多种本地香料烹制而成。</p><p style=\"text-align:justify;\">在烹饪过程中，香料充分渗入肉中，使其味道浓郁辛辣，并带有独特的草本香气。酱汁通常浓稠呈红色，体现了调料的丰富层次。每一口都带来温暖、辛辣与深厚的风味体验。</p><p style=\"text-align:justify;\">Tinoransak常在家庭聚会或传统庆典中出现，象征着团结与北苏拉威西丰富的饮食文化。搭配热米饭食用，更能体现其地道而难忘的美味。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/KIucRY5Q0W2m8Mera63jADr2K3tuJPUSWUAjvXxd.webp', 4, 1, '2026-04-28 02:04:31', '2026-04-28 06:58:20'),
(72, 'food', 'main', 'Sup Brenebon', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Sup brenebon adalah salah satu hidangan legendaris dari Sulawesi Utara yang terkenal dengan cita rasa hangat, kaya, dan begitu menenangkan. Nama “brenebon” sendiri berasal dari bahasa Belanda <i>bruine bonen</i> yang berarti kacang merah, mencerminkan sejarah panjang pengaruh kuliner di daerah ini.</p><p style=\"text-align:justify;\">Hidangan ini terbuat dari kacang merah yang dimasak perlahan bersama daging—biasanya daging babi atau sapi—hingga menghasilkan kuah yang gurih, kental, dan penuh rasa. Bumbu sederhana seperti bawang putih, bawang merah, pala, dan merica berpadu sempurna, menciptakan aroma khas yang menggugah selera.</p><p style=\"text-align:justify;\">Tekstur kacang merah yang lembut berpadu dengan potongan daging yang empuk memberikan sensasi makan yang kaya dan memuaskan. Sup ini biasanya disajikan panas, sering kali dilengkapi dengan nasi putih hangat atau roti, menjadikannya hidangan yang sempurna untuk dinikmati kapan saja, terutama saat cuaca sejuk.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan, sup brenebon mencerminkan perpaduan budaya dan tradisi yang unik di Sulawesi Utara—sebuah hidangan klasik yang selalu menghadirkan rasa rumah dalam setiap sendoknya.</p>', '<p style=\"text-align:justify;\">Brenebon soup is one of the legendary dishes from North Sulawesi, known for its warm, rich, and comforting flavors. The name “brenebon” comes from the Dutch term <i>bruine bonen</i>, meaning red beans, reflecting the region’s historical culinary influences.</p><p style=\"text-align:justify;\">This dish is made from red beans slowly cooked with meat—typically pork or beef—resulting in a savory, thick, and flavorful broth. Simple spices such as garlic, shallots, nutmeg, and pepper blend beautifully, creating a distinctive and appetizing aroma.</p><p style=\"text-align:justify;\">The soft texture of the beans combined with tender pieces of meat creates a hearty and satisfying experience. Usually served hot, often accompanied by steamed rice or bread, this soup is perfect for any time of the day, especially in cooler weather.</p><p style=\"text-align:justify;\">More than just a meal, brenebon soup represents the unique blend of cultures and traditions in North Sulawesi—a classic dish that brings a sense of home in every spoonful.</p>', '<p style=\"text-align:justify;\">브레네본 수프는 북술라웨시를 대표하는 전통 요리 중 하나로, 따뜻하고 깊으며 편안한 맛으로 유명합니다. “브레네본”이라는 이름은 네덜란드어 <i>bruine bonen</i>(붉은 콩)에서 유래되어, 이 지역의 역사적 음식 문화를 보여줍니다.</p><p style=\"text-align:justify;\">이 요리는 붉은 콩과 고기(주로 돼지고기 또는 소고기)를 함께 천천히 끓여 만들어지며, 진하고 깊은 맛의 국물을 완성합니다. 마늘, 샬롯, 육두구, 후추 등의 향신료가 조화롭게 어우러져 식욕을 돋우는 향을 만들어냅니다.</p><p style=\"text-align:justify;\">부드러운 콩과 연한 고기의 조합은 든든하고 만족스러운 식감을 제공합니다. 보통 따뜻하게 제공되며, 밥이나 빵과 함께 먹으면 더욱 좋습니다. 특히 서늘한 날씨에 잘 어울리는 음식입니다.</p><p style=\"text-align:justify;\">브레네본 수프는 단순한 요리를 넘어 북술라웨시의 다양한 문화와 전통이 어우러진 상징적인 음식으로, 한 숟가락마다 따뜻한 정서를 전해줍니다.</p>', '<p style=\"text-align:justify;\">Brenebon汤是来自北苏拉威西的一道经典美食，以其温暖、浓郁且令人舒适的口感而闻名。“Brenebon”一词源自荷兰语 <i>bruine bonen</i>，意为红豆，体现了当地悠久的历史与饮食文化影响。</p><p style=\"text-align:justify;\">这道菜以红豆为主要材料，与肉类（通常是猪肉或牛肉）一起慢火炖煮，形成浓厚鲜美的汤底。大蒜、红葱、肉豆蔻和胡椒等简单香料完美融合，散发出诱人的香气。</p><p style=\"text-align:justify;\">柔软的红豆搭配嫩滑的肉块，带来丰富而满足的口感体验。通常趁热食用，常配米饭或面包，是任何时候都适合享用的佳肴，尤其在凉爽天气中更显美味。</p><p style=\"text-align:justify;\">Brenebon汤不仅是一道美食，更体现了北苏拉威西多元文化的融合，是一道每一口都充满温暖与家的味道的经典料理。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/PmCluT3aawaAJFonXsbFAihzz8o4Z3dOGWdms1e7.webp', 5, 1, '2026-04-28 02:11:22', '2026-04-28 05:45:43'),
(73, 'food', 'main', 'Rica - Rica', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Rica-rica adalah salah satu hidangan paling ikonik dari Sulawesi Utara yang terkenal dengan rasa pedasnya yang berani dan menggugah selera. Nama “rica” sendiri berarti cabai, yang langsung mencerminkan karakter utama dari masakan ini: pedas, segar, dan penuh semangat.</p><p style=\"text-align:justify;\">Hidangan rica-rica biasanya menggunakan bahan utama seperti babi, ayam, ikan, bebek, atau bahkan seafood, yang dimasak dengan bumbu khas berupa cabai merah, bawang merah, bawang putih, jahe, serai, dan daun jeruk. Perpaduan bumbu ini menghasilkan aroma harum yang kuat dengan rasa pedas yang tajam namun tetap seimbang oleh sentuhan segar dari rempah-rempah.</p><p style=\"text-align:justify;\">Daging yang dimasak dengan teknik rica-rica menjadi empuk dan meresap sempurna dengan bumbu, menciptakan sensasi rasa yang intens di setiap gigitan. Biasanya disajikan dengan nasi putih hangat, rica-rica memberikan pengalaman kuliner yang menggugah, memadukan pedas, gurih, dan segar dalam satu hidangan.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan, rica-rica mencerminkan karakter masyarakat Sulawesi Utara yang berani, ekspresif, dan penuh energi—sebuah hidangan yang selalu meninggalkan kesan kuat bagi siapa pun yang mencicipinya.</p>', '<p style=\"text-align:justify;\">Rica-rica is one of the most iconic dishes from North Sulawesi, famous for its bold spiciness and mouthwatering flavor. The word “rica” means chili, which perfectly represents the essence of this dish: spicy, fresh, and full of character.</p><p style=\"text-align:justify;\">Rica-rica is typically made with ingredients such as pork, chicken, fish, duck, or seafood, cooked in a rich blend of spices including red chili, shallots, garlic, ginger, lemongrass, and kaffir lime leaves. This combination creates a strong, fragrant aroma with a sharp spiciness balanced by the freshness of herbs.</p><p style=\"text-align:justify;\">The meat is cooked until tender and fully infused with the spices, delivering an intense burst of flavor in every bite. Usually served with warm steamed rice, rica-rica offers an exciting culinary experience that combines heat, savoriness, and freshness.</p><p style=\"text-align:justify;\">More than just a dish, rica-rica reflects the bold, expressive, and energetic spirit of North Sulawesi’s people—leaving a lasting impression on anyone who tastes it.</p>', '<p style=\"text-align:justify;\">리카리카는 북술라웨시를 대표하는 요리 중 하나로, 강렬한 매운맛과 식욕을 자극하는 풍미로 유명합니다. “리카(rica)”는 고추를 의미하며, 이 요리의 핵심인 매콤하고 신선하며 개성 있는 맛을 잘 보여줍니다.</p><p style=\"text-align:justify;\">이 요리는 닭고기, 생선, 오리 또는 해산물 등을 주재료로 하여 고추, 샬롯, 마늘, 생강, 레몬그라스, 카피르 라임 잎 등 다양한 향신료와 함께 조리됩니다. 이러한 재료들이 어우러져 강렬한 향과 함께 매콤하면서도 신선한 맛을 만들어냅니다.</p><p style=\"text-align:justify;\">고기는 부드럽게 익으면서 양념이 깊이 스며들어 한 입마다 강렬한 풍미를 선사합니다. 따뜻한 밥과 함께 제공되는 경우가 많으며, 매운맛과 감칠맛, 신선함이 조화를 이루는 특별한 미식 경험을 제공합니다.</p><p style=\"text-align:justify;\">리카리카는 단순한 음식이 아니라 북술라웨시 사람들의 대담하고 활기찬 성격을 담은 요리로, 누구에게나 강렬한 인상을 남깁니다.</p>', '<p style=\"text-align:justify;\">Rica-rica是来自北苏拉威西的一道标志性美食，以其浓烈的辣味和令人垂涎的风味而闻名。“Rica”意为辣椒，完美体现了这道菜的核心特点：辛辣、清新且充满个性。</p><p style=\"text-align:justify;\">Rica-rica通常选用鸡肉、鱼肉、鸭肉或海鲜为主料，搭配红辣椒、红葱、大蒜、生姜、香茅和卡菲尔酸橙叶等香料烹制而成。这些香料融合在一起，形成浓郁的香气和鲜明的辣味，同时又带有清新的草本气息。</p><p style=\"text-align:justify;\">肉质被炖煮得柔软入味，充分吸收香料，每一口都带来强烈而丰富的味觉体验。通常搭配热腾腾的白米饭一起食用，呈现出辣味、鲜味与清新感的完美结合。</p><p style=\"text-align:justify;\">Rica-rica不仅是一道美食，更体现了北苏拉威西人民大胆、热情且充满活力的性格，是一道令人难忘的经典佳肴。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/EX77fAj6z6KuGE3z29UJ3WKaWIc2lT7lkph7HJLA.webp', 6, 1, '2026-04-28 02:16:24', '2026-04-28 05:48:36');
INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(74, 'food', 'main', 'Rahan Tuna Bakar', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Rahang tuna bakar adalah salah satu hidangan khas dari Sulawesi Utara yang terkenal dengan cita rasa gurih, tekstur lembut, dan sensasi smoky yang menggoda. Menggunakan bagian rahang ikan tuna yang kaya daging dan lemak alami, hidangan ini menawarkan pengalaman makan yang unik dan memuaskan.</p><p style=\"text-align:justify;\">Rahang tuna dipanggang di atas bara api hingga bagian luarnya sedikit garing sementara bagian dalamnya tetap juicy dan lembut. Proses pembakaran ini menghasilkan aroma khas yang harum, berpadu sempurna dengan bumbu sederhana seperti kecap, bawang putih, dan perasan jeruk nipis.</p><p style=\"text-align:justify;\">Saat disantap, dagingnya terasa tebal, lembut, dan kaya rasa, dengan sentuhan gurih alami dari laut. Biasanya disajikan dengan sambal dabu-dabu yang segar dan pedas, serta nasi putih hangat, menciptakan perpaduan rasa yang seimbang antara smoky, pedas, asam, dan gurih.</p><p style=\"text-align:justify;\">Rahang tuna bakar bukan sekadar hidangan laut biasa, melainkan representasi kekayaan bahari Sulawesi Utara yang diolah dengan cara sederhana namun penuh cita rasa—sebuah sajian istimewa yang memanjakan lidah.</p>', '<p style=\"text-align:justify;\">Grilled tuna jaw is a signature dish from North Sulawesi, celebrated for its savory flavor, tender texture, and irresistible smoky aroma. Made from the jaw portion of tuna, which is rich in meat and natural fats, this dish offers a unique and satisfying dining experience.</p><p style=\"text-align:justify;\">The tuna jaw is grilled over hot charcoal until the outside is slightly crispy while the inside remains juicy and tender. This grilling process creates a distinctive fragrance, perfectly complemented by simple seasonings such as soy sauce, garlic, and a squeeze of lime.</p><p style=\"text-align:justify;\">When enjoyed, the meat is thick, soft, and full of flavor, with a natural savory taste from the sea. It is commonly served with fresh and spicy dabu-dabu sambal and warm steamed rice, creating a perfect balance of smoky, spicy, tangy, and savory flavors.</p><p style=\"text-align:justify;\">More than just seafood, grilled tuna jaw represents the rich marine heritage of North Sulawesi—prepared simply yet bursting with flavor, making it a truly special dish.</p>', '<p style=\"text-align:justify;\">참치 턱 구이는 북술라웨시의 대표적인 요리로, 고소한 맛과 부드러운 식감, 그리고 매력적인 훈제 향으로 사랑받고 있습니다. 참치의 턱 부위는 살과 지방이 풍부하여 독특하고 만족스러운 식사 경험을 제공합니다.</p><p style=\"text-align:justify;\">참치 턱은 숯불 위에서 구워 겉은 살짝 바삭하고 속은 촉촉하고 부드럽게 완성됩니다. 이 과정에서 특유의 향긋한 향이 살아나며, 간장, 마늘, 라임즙과 같은 간단한 양념과 잘 어우러집니다.</p><p style=\"text-align:justify;\">한입 먹으면 두툼하고 부드러운 식감과 함께 바다의 자연스러운 감칠맛이 느껴집니다. 보통 매콤하고 상큼한 다부다부 삼발과 따뜻한 밥과 함께 제공되어, 훈제 향, 매운맛, 상큼함, 고소함이 완벽한 조화를 이룹니다.</p><p style=\"text-align:justify;\">참치 턱 구이는 단순한 해산물 요리를 넘어 북술라웨시의 풍부한 해양 자원을 담은 특별한 요리입니다.</p>', '<p style=\"text-align:justify;\">烤金枪鱼下巴是来自北苏拉威西的一道特色美食，以其鲜美的口感、柔嫩的肉质和诱人的烟熏香气而闻名。选用金枪鱼的下巴部位，这一部分富含肉质与天然油脂，带来独特而满足的味觉体验。</p><p style=\"text-align:justify;\">金枪鱼下巴在炭火上慢慢烤制，外层微微酥脆，内部依然多汁柔嫩。烧烤过程中散发出的香气与简单的调味（如酱油、大蒜和柠檬汁）完美融合。</p><p style=\"text-align:justify;\">入口时，肉质厚实柔软，充满海洋的天然鲜味。通常搭配清新辛辣的达布达布辣酱和热米饭一起食用，形成烟熏、辛辣、酸爽与鲜美的完美平衡。</p><p style=\"text-align:justify;\">烤金枪鱼下巴不仅是一道海鲜料理，更体现了北苏拉威西丰富的海洋资源与简约却充满风味的烹饪艺术。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/5Gz21Jtx5US2bFQnTSK26YkVxVufDe2Rx1LtQWVQ.jpg', 8, 1, '2026-04-28 02:19:17', '2026-04-28 05:51:19'),
(75, 'food', 'main', 'Pampis', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Pampis adalah salah satu hidangan khas dari Sulawesi Utara yang sederhana namun kaya rasa dan sangat menggugah selera. Hidangan ini biasanya terbuat dari ikan cakalang yang disuwir halus, lalu dimasak dengan bumbu khas yang kaya rempah.</p><p style=\"text-align:justify;\">Perpaduan cabai, bawang merah, bawang putih, daun jeruk, dan kemangi menciptakan aroma harum yang kuat dan menggoda. Proses memasaknya membuat bumbu meresap sempurna ke dalam serat ikan, menghasilkan cita rasa pedas, gurih, dan sedikit segar yang khas.</p><p style=\"text-align:justify;\">Teksturnya yang kering namun lembut menjadikan pampis sangat nikmat disantap dengan nasi putih hangat. Sering kali juga dipadukan dengan sambal tambahan atau lalapan, memperkaya pengalaman rasa di setiap suapan.</p><p style=\"text-align:justify;\">Pampis bukan hanya sekadar lauk, tetapi juga cerminan kreativitas masyarakat pesisir dalam mengolah hasil laut menjadi hidangan yang praktis, lezat, dan penuh karakter.</p>', '<p style=\"text-align:justify;\">Pampis is a traditional dish from North Sulawesi that is simple yet rich in flavor and highly appetizing. It is typically made from shredded skipjack tuna, cooked with a blend of aromatic spices.</p><p style=\"text-align:justify;\">A combination of chili, shallots, garlic, kaffir lime leaves, and basil creates a strong and enticing aroma. The cooking process allows the spices to fully absorb into the fish, resulting in a distinctive taste that is spicy, savory, and slightly fresh.</p><p style=\"text-align:justify;\">Its texture is relatively dry yet tender, making pampis perfect to enjoy with warm steamed rice. It is often complemented with extra sambal or fresh vegetables, enhancing the overall flavor experience.</p><p style=\"text-align:justify;\">More than just a side dish, pampis reflects the creativity of coastal communities in transforming seafood into a practical, delicious, and character-rich cuisine.</p>', '<p style=\"text-align:justify;\">팜피스는 북술라웨시의 대표적인 요리로, 단순하면서도 풍부한 맛과 식욕을 자극하는 매력을 지니고 있습니다. 이 요리는 주로 가다랑어를 잘게 찢어 다양한 향신료와 함께 조리하여 만듭니다.</p><p style=\"text-align:justify;\">고추, 샬롯, 마늘, 카피르 라임 잎, 바질이 어우러져 강하고 매혹적인 향을 만들어냅니다. 조리 과정에서 양념이 생선에 깊이 스며들어 매콤하고 고소하며 약간 상큼한 맛을 완성합니다.</p><p style=\"text-align:justify;\">식감은 비교적 건조하지만 부드러워 따뜻한 밥과 함께 먹기에 매우 잘 어울립니다. 종종 추가 삼발이나 신선한 채소와 함께 제공되어 더욱 풍부한 맛을 즐길 수 있습니다.</p><p style=\"text-align:justify;\">팜피스는 단순한 반찬을 넘어, 해안 지역 사람들의 창의성과 바다의 풍요로움을 담은 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">Pampis是来自北苏拉威西的一道传统美食，虽然做法简单，却拥有丰富而诱人的风味。它通常以撕碎的鲣鱼为主要原料，搭配多种香料烹制而成。</p><p style=\"text-align:justify;\">辣椒、红葱、大蒜、卡菲尔酸橙叶和罗勒的结合，散发出浓郁而迷人的香气。在烹饪过程中，香料充分渗入鱼肉，使其呈现出辛辣、鲜美并略带清新的独特口感。</p><p style=\"text-align:justify;\">其质地偏干但依然柔软，非常适合搭配热米饭食用。通常还会搭配额外的辣酱或新鲜蔬菜，使味道更加丰富。</p><p style=\"text-align:justify;\">Pampis不仅是一道配菜，更体现了沿海居民将海鲜转化为美味佳肴的智慧与创造力。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/19xXeAqlWU39CLsOUAu4gl9IaDgJwWNmF9kLddoT.jpg', 7, 1, '2026-04-28 02:20:59', '2026-04-28 05:49:56'),
(76, 'food', 'breakfast', 'Nasi Kuning', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Nasi kuning adalah salah satu hidangan khas dari Sulawesi Utara yang tidak hanya menggugah selera, tetapi juga sarat makna budaya. Berwarna kuning cerah dari kunyit, nasi ini melambangkan kemakmuran, kebahagiaan, dan rasa syukur, sehingga sering hadir dalam berbagai perayaan dan momen istimewa.</p><p style=\"text-align:justify;\">Aroma harum santan yang dimasak bersama rempah seperti serai, daun pandan, dan daun salam menjadikan nasi kuning begitu khas dan menggoda. Teksturnya pulen dengan rasa gurih yang lembut, menjadikannya dasar sempurna untuk berbagai lauk pendamping.</p><p style=\"text-align:justify;\">Di Sulawesi Utara, nasi kuning biasanya disajikan dengan aneka pelengkap seperti ikan cakalang fufu, abon ikan, telur balado, sambal rica, serta mie goreng. Perpaduan ini menciptakan harmoni rasa yang kaya—gurih, pedas, dan sedikit manis—dalam satu sajian yang lengkap.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan, nasi kuning adalah simbol kebersamaan dan tradisi, menghadirkan kehangatan dalam setiap suapan dan menjadikannya salah satu kuliner yang tak terlupakan.</p>', '<p style=\"text-align:justify;\">Yellow rice is one of the traditional dishes from North Sulawesi that is not only delicious but also rich in cultural meaning. Its bright yellow color, derived from turmeric, symbolizes prosperity, happiness, and gratitude, making it a staple in celebrations and special occasions.</p><p style=\"text-align:justify;\">The fragrant aroma of coconut milk cooked with spices such as lemongrass, pandan leaves, and bay leaves gives the rice its distinctive and inviting scent. Its soft and fluffy texture, combined with a gentle savory taste, makes it the perfect base for various side dishes.</p><p style=\"text-align:justify;\">In North Sulawesi, yellow rice is typically served with a variety of accompaniments such as smoked skipjack tuna (cakalang fufu), shredded fish, spicy eggs, rica sambal, and fried noodles. This combination creates a rich harmony of flavors—savory, spicy, and slightly sweet—in one complete dish.</p><p style=\"text-align:justify;\">More than just food, yellow rice represents togetherness and tradition, bringing warmth in every bite and making it an unforgettable culinary experience.</p>', '<p style=\"text-align:justify;\">나시 쿠닝(노란 밥)은 북술라웨시의 대표적인 전통 음식으로, 맛뿐만 아니라 깊은 문화적 의미를 지니고 있습니다. 강황으로 물든 밝은 노란색은 번영, 행복, 그리고 감사의 의미를 담고 있어 다양한 행사와 특별한 날에 자주 등장합니다.</p><p style=\"text-align:justify;\">코코넛 밀크와 레몬그라스, 판단 잎, 월계수 잎 등의 향신료로 지은 밥은 향긋하고 매력적인 향을 자랑합니다. 부드럽고 찰진 식감과 은은한 고소한 맛은 다양한 반찬과 잘 어울립니다.</p><p style=\"text-align:justify;\">북술라웨시에서는 보통 훈제 가다랑어(차칼랑 푸푸), 생선 볶음, 매콤한 달걀, 리카 삼발, 볶음면 등과 함께 제공됩니다. 이 조합은 짭짤함, 매운맛, 그리고 약간의 단맛이 어우러진 풍부한 맛의 조화를 만들어냅니다.</p><p style=\"text-align:justify;\">나시 쿠닝은 단순한 음식이 아니라 공동체와 전통을 상징하며, 한 입마다 따뜻함을 전해주는 특별한 요리입니다.</p>', '<p style=\"text-align:justify;\">黄姜饭（Nasi Kuning）是来自北苏拉威西的一道传统美食，不仅美味，还蕴含着深厚的文化意义。其明亮的黄色来自姜黄，象征着繁荣、幸福与感恩，因此常出现在各种庆典和重要场合。</p><p style=\"text-align:justify;\">用椰奶搭配香茅、班兰叶和月桂叶一起烹煮，使米饭散发出浓郁而迷人的香气。米饭口感松软香糯，带有淡淡的咸香，非常适合作为多种配菜的基础。</p><p style=\"text-align:justify;\">在北苏拉威西，黄姜饭通常搭配烟熏鲣鱼、鱼松、辣味鸡蛋、rica辣酱以及炒面等配菜食用。这些搭配带来咸香、辛辣与微甜的丰富层次，形成一份完整而美味的餐点。</p><p style=\"text-align:justify;\">黄姜饭不仅是一道美食，更象征着团聚与传统，在每一口中都传递出温暖与幸福的味道。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/4h15IDVYyZ8SHNdb0NBxbmMq56owVR8yQz8YFxsN.jpg', 9, 1, '2026-04-28 02:25:16', '2026-04-28 06:21:02'),
(77, 'food', 'main', 'Ikan Woku Belanga', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Ikan woku belanga adalah salah satu hidangan khas dari Sulawesi Utara yang terkenal dengan cita rasa segar, pedas, dan kaya rempah. Kata “belanga” merujuk pada cara memasaknya menggunakan wadah tradisional, yang membantu menjaga keaslian rasa dan aroma bumbu tetap kuat dan meresap.</p><p style=\"text-align:justify;\">Hidangan ini biasanya menggunakan ikan laut segar seperti kakap, kerapu, atau tuna, yang dimasak dalam kuah kuning kaya rempah. Bumbu khas woku seperti kunyit, jahe, serai, daun jeruk, daun kunyit, cabai, dan kemangi berpadu menciptakan aroma harum yang sangat menggoda.</p><p style=\"text-align:justify;\">Kuahnya yang segar dengan perpaduan rasa pedas, gurih, dan sedikit asam meresap hingga ke dalam daging ikan yang lembut. Setiap suapan menghadirkan sensasi rasa yang hidup dan menyegarkan, khas masakan pesisir.</p><p style=\"text-align:justify;\">Disajikan dengan nasi putih hangat, ikan woku belanga menjadi hidangan yang sempurna—menghadirkan kehangatan, kekayaan rasa, dan keaslian tradisi kuliner Sulawesi Utara dalam satu sajian yang memikat.</p>', '<p style=\"text-align:justify;\">Ikan woku belanga is a traditional dish from North Sulawesi, known for its fresh, spicy, and richly spiced flavors. The word “belanga” refers to the traditional pot used in cooking, which helps preserve the authentic taste and aroma of the spices.</p><p style=\"text-align:justify;\">This dish typically uses fresh seafood such as snapper, grouper, or tuna, cooked in a vibrant yellow, spice-rich broth. Signature woku ingredients like turmeric, ginger, lemongrass, kaffir lime leaves, turmeric leaves, chili, and basil create a wonderfully fragrant aroma.</p><p style=\"text-align:justify;\">The broth is fresh and flavorful, combining spicy, savory, and slightly tangy notes that soak deeply into the tender fish. Each bite delivers a lively and refreshing taste, characteristic of coastal cuisine.</p><p style=\"text-align:justify;\">Served with warm steamed rice, ikan woku belanga offers a perfect balance of warmth, bold flavors, and authentic culinary tradition from North Sulawesi.</p>', '<p style=\"text-align:justify;\">이칸 워쿠 블랑아는 북술라웨시의 대표적인 전통 요리로, 신선하고 매콤하며 향신료가 풍부한 맛이 특징입니다. “블랑아(belanga)”는 전통 냄비를 의미하며, 조리 과정에서 향신료의 풍미를 더욱 깊게 살려줍니다.</p><p style=\"text-align:justify;\">이 요리는 보통 도미, 그루퍼, 참치와 같은 신선한 생선을 사용하여 향신료가 가득한 노란 국물에 끓여냅니다. 강황, 생강, 레몬그라스, 카피르 라임 잎, 강황 잎, 고추, 바질 등 다양한 재료가 어우러져 향긋한 향을 만들어냅니다.</p><p style=\"text-align:justify;\">국물은 매콤하고 고소하며 약간의 산미가 조화를 이루며, 부드러운 생선 살에 깊이 스며듭니다. 한 입마다 상큼하고 생동감 있는 맛을 느낄 수 있어 해안 지역 요리의 매력을 잘 보여줍니다.</p><p style=\"text-align:justify;\">따뜻한 밥과 함께 제공되는 이칸 워쿠 블랑아는 북술라웨시의 전통과 풍부한 맛을 완벽하게 담아낸 특별한 요리입니다.</p>', '<p style=\"text-align:justify;\">Ikan Woku Belanga是来自北苏拉威西的一道传统美食，以其清新、辛辣且香料丰富的风味而闻名。“Belanga”指的是传统烹饪锅具，有助于保留食材与香料的原始风味。</p><p style=\"text-align:justify;\">这道菜通常选用新鲜海鱼，如鲷鱼、石斑鱼或金枪鱼，在金黄色、香料浓郁的汤汁中烹煮。姜黄、生姜、香茅、卡菲尔酸橙叶、姜黄叶、辣椒和罗勒等香料融合，散发出迷人的香气。</p><p style=\"text-align:justify;\">汤汁口感丰富，融合了辛辣、鲜美与微酸的味道，并充分渗透进柔嫩的鱼肉中。每一口都带来鲜活而清新的味觉体验，展现出典型的海岸风味。</p><p style=\"text-align:justify;\">搭配热米饭一起享用，Ikan Woku Belanga完美呈现了北苏拉威西的传统与丰富风味，是一道令人难忘的佳肴。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/f74wTdjpHsYllqJy67qr3ZXXWZ0690QUPFOEr7Jp.jpg', 10, 1, '2026-04-28 02:27:41', '2026-04-28 05:55:46'),
(78, 'food', 'main', 'Ikan tude woku daun', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Ikan tude woku daun adalah salah satu hidangan khas dari Sulawesi Utara yang terkenal dengan kesegaran rasa dan aroma rempah yang begitu menggoda. Ikan tude (sejenis ikan kembung lokal) yang segar menjadi bahan utama, dimasak dengan bumbu woku khas yang kaya akan rempah dan daun-daunan aromatik.</p><p style=\"text-align:justify;\">Keunikan “woku daun” terletak pada penggunaan daun kemangi, daun kunyit, daun jeruk, dan rempah lainnya yang melimpah, menciptakan aroma harum yang sangat khas dan segar. Ikan dimasak hingga bumbu meresap sempurna, menghasilkan perpaduan rasa pedas, gurih, dan sedikit asam yang seimbang.</p><p style=\"text-align:justify;\">Daging ikan tude yang lembut dan juicy berpadu dengan kuah berbumbu yang ringan namun penuh rasa, memberikan sensasi makan yang segar dan menggugah selera. Setiap suapan menghadirkan cita rasa alami laut yang diperkaya dengan kekayaan rempah khas Minahasa.</p><p style=\"text-align:justify;\">Disajikan dengan nasi putih hangat, ikan tude woku daun menjadi hidangan sederhana namun istimewa—mewakili kekayaan kuliner Sulawesi Utara yang segar, berani, dan penuh karakter.</p>', '<p style=\"text-align:justify;\">Ikan tude woku daun is a traditional dish from North Sulawesi, celebrated for its fresh taste and vibrant herbal aroma. The main ingredient is fresh tude fish (a type of local mackerel), cooked in a rich woku spice blend filled with aromatic leaves.</p><p style=\"text-align:justify;\">The uniqueness of “woku daun” lies in the generous use of herbs such as basil, turmeric leaves, kaffir lime leaves, and other spices, creating a distinctive and refreshing fragrance. The fish is cooked until the spices fully infuse the meat, resulting in a balanced combination of spicy, savory, and slightly tangy flavors.</p><p style=\"text-align:justify;\">The tender and juicy texture of the fish pairs beautifully with the light yet flavorful broth, offering a refreshing and appetizing experience. Each bite delivers the natural taste of the sea enhanced by the rich spices of Minahasan cuisine.</p><p style=\"text-align:justify;\">Served with warm steamed rice, ikan tude woku daun is a simple yet special dish that represents the fresh, bold, and flavorful culinary heritage of North Sulawesi.</p>', '<p style=\"text-align:justify;\">이칸 투데 워쿠 다운은 북술라웨시의 대표적인 요리로, 신선한 맛과 향긋한 허브 향이 특징입니다. 주재료인 투데 생선(고등어와 유사한 생선)을 다양한 향신료와 허브로 만든 워쿠 양념과 함께 조리합니다.</p><p style=\"text-align:justify;\">“워쿠 다운”의 가장 큰 특징은 바질, 강황 잎, 카피르 라임 잎 등 다양한 잎채소와 향신료를 풍부하게 사용하는 데 있습니다. 이로 인해 상쾌하고 독특한 향이 만들어지며, 양념이 생선에 깊이 스며들어 매콤하고 고소하며 약간 상큼한 맛을 완성합니다.</p><p style=\"text-align:justify;\">부드럽고 촉촉한 생선 살과 가볍지만 풍미 깊은 국물이 어우러져 신선하고 입맛을 돋우는 식감을 제공합니다. 한 입마다 바다의 자연스러운 맛과 미나하사 지역의 향신료 풍미를 동시에 느낄 수 있습니다.</p><p style=\"text-align:justify;\">따뜻한 밥과 함께 즐기면 더욱 완벽한 이 요리는 북술라웨시의 신선하고 풍부한 미식 문화를 잘 보여주는 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">Ikan Tude Woku Daun是来自北苏拉威西的一道特色美食，以其清新的口感和浓郁的草本香气而闻名。它以新鲜的tude鱼（类似鲭鱼）为主要食材，搭配富含香草叶的woku香料烹制而成。</p><p style=\"text-align:justify;\">“Woku Daun”的独特之处在于大量使用罗勒叶、姜黄叶、卡菲尔酸橙叶等香草，使菜肴散发出清新而独特的香气。鱼肉在烹煮过程中充分吸收香料，呈现出辛辣、鲜美并略带酸味的平衡口感。</p><p style=\"text-align:justify;\">鱼肉细嫩多汁，与清爽却层次丰富的汤汁相结合，带来清新开胃的味觉体验。每一口都融合了海洋的自然鲜味与米纳哈萨地区丰富的香料风味。</p><p style=\"text-align:justify;\">搭配热米饭一起享用，这道菜虽简单却极具特色，完美展现了北苏拉威西清新、浓郁且充满活力的饮食文化。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/88qKgCpagEIFVGXXBRerhStE0PfmHLDbt6ej7YXK.jpg', 11, 1, '2026-04-28 02:32:08', '2026-04-28 06:17:31'),
(79, 'food', 'main', 'Kuah Asang', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Kuah asang adalah salah satu hidangan khas dari Sulawesi Utara yang terkenal dengan cita rasa segar, asam, dan sedikit pedas yang begitu menggugah selera. Hidangan ini biasanya menggunakan ikan laut segar seperti kakap atau tuna, yang dimasak dalam kuah bening dengan perpaduan rempah dan bahan alami.</p><p style=\"text-align:justify;\">Keunikan kuah asang terletak pada rasa asam alaminya yang berasal dari belimbing wuluh atau jeruk nipis, dipadukan dengan cabai, bawang merah, bawang putih, jahe, dan daun kemangi. Kombinasi ini menciptakan aroma segar yang khas serta rasa yang ringan namun tetap kaya.</p><p style=\"text-align:justify;\">Daging ikan yang lembut berpadu dengan kuah yang menyegarkan memberikan sensasi makan yang ringan namun memuaskan. Setiap suapan menghadirkan keseimbangan rasa asam, pedas, dan gurih yang begitu nikmat, terutama saat disantap dengan nasi putih hangat.</p><p style=\"text-align:justify;\">Kuah asang bukan hanya sekadar hidangan, tetapi juga mencerminkan karakter kuliner Sulawesi Utara yang segar, sederhana, dan penuh cita rasa alami.</p>', '<p style=\"text-align:justify;\">Kuah asang is a traditional dish from North Sulawesi, known for its fresh, tangy, and slightly spicy flavor that is truly appetizing. This dish typically uses fresh seafood such as snapper or tuna, cooked in a clear broth infused with natural ingredients and spices.</p><p style=\"text-align:justify;\">What makes kuah asang unique is its natural sour taste, derived from bilimbi or lime, combined with chili, shallots, garlic, ginger, and basil. This blend creates a refreshing aroma and a light yet flavorful taste.</p><p style=\"text-align:justify;\">The tender fish pairs perfectly with the refreshing broth, offering a light but satisfying dining experience. Each spoonful delivers a balanced combination of tangy, spicy, and savory flavors, especially when enjoyed with warm steamed rice.</p><p style=\"text-align:justify;\">More than just a dish, kuah asang reflects the fresh, simple, and naturally rich culinary character of North Sulawesi.</p>', '<p style=\"text-align:justify;\">쿠아 아상은 북술라웨시의 대표적인 요리로, 상큼하고 새콤하며 약간 매콤한 맛이 특징입니다. 이 요리는 주로 도미나 참치와 같은 신선한 생선을 사용하여 맑은 국물과 함께 끓여 만듭니다.</p><p style=\"text-align:justify;\">쿠아 아상의 가장 큰 특징은 빌림비나 라임에서 나오는 자연스러운 신맛이며, 여기에 고추, 샬롯, 마늘, 생강, 바질이 더해져 상쾌한 향과 가볍지만 깊은 맛을 완성합니다.</p><p style=\"text-align:justify;\">부드러운 생선과 상큼한 국물이 어우러져 가볍지만 만족스러운 식사 경험을 제공합니다. 따뜻한 밥과 함께 먹으면 새콤함, 매운맛, 감칠맛이 조화를 이루는 훌륭한 맛을 느낄 수 있습니다.</p><p style=\"text-align:justify;\">쿠아 아상은 단순한 음식이 아니라 북술라웨시의 신선하고 자연스러운 미식 문화를 잘 보여주는 요리입니다.</p>', '<p style=\"text-align:justify;\">Kuah Asang是来自北苏拉威西的一道传统美食，以其清新、酸爽并略带辛辣的口味而闻名，十分开胃。它通常选用新鲜海鱼，如鲷鱼或金枪鱼，在清澈的汤中加入多种天然香料烹制而成。</p><p style=\"text-align:justify;\">这道菜的独特之处在于其天然的酸味，来自酸杨桃（belimbing wuluh）或青柠，再结合辣椒、红葱、大蒜、生姜和罗勒，形成清新怡人的香气与层次丰富的口感。</p><p style=\"text-align:justify;\">嫩滑的鱼肉与清爽的汤汁完美结合，带来轻盈却令人满足的用餐体验。每一口都呈现出酸、辣、鲜的平衡风味，搭配热米饭尤为美味。</p><p style=\"text-align:justify;\">Kuah Asang不仅是一道美食，更体现了北苏拉威西清新、自然且充满风味的饮食特色。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/x8HtpNpEtquNs6JCrczEctY3AMAc89mr8ou530rM.jpg', 12, 1, '2026-04-28 02:37:16', '2026-04-28 06:17:52'),
(80, 'food', 'dessert', 'Klapertart', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Klapertart adalah salah satu hidangan penutup legendaris dari Sulawesi Utara yang memadukan cita rasa lokal dengan sentuhan Eropa. Nama “klapertart” berasal dari bahasa Belanda, di mana <i>klapper</i> berarti kelapa dan <i>tart</i> merujuk pada hidangan pencuci mulut bergaya Barat.</p><p style=\"text-align:justify;\">Dessert ini dibuat dari kelapa muda segar yang dipadukan dengan susu, mentega, telur, dan gula, menghasilkan tekstur lembut, creamy, dan lumer di mulut. Biasanya diperkaya dengan tambahan kismis, kenari, atau kayu manis, yang memberikan lapisan rasa manis dan aroma yang semakin menggoda.</p><p style=\"text-align:justify;\">Klapertart bisa disajikan dalam dua versi: panggang dengan lapisan atas yang sedikit kecokelatan dan harum, atau dingin sebagai hidangan yang segar dan ringan. Kedua versi ini sama-sama menawarkan kenikmatan yang khas—perpaduan antara manis, gurih, dan aroma kelapa yang lembut.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan penutup, klapertart mencerminkan sejarah panjang akulturasi budaya di Sulawesi Utara, menghadirkan rasa klasik yang elegan dan tak lekang oleh waktu.</p>', '<p style=\"text-align:justify;\">Klapertart is a legendary dessert from North Sulawesi that beautifully blends local flavors with European influence. The name “klapertart” comes from the Dutch words <i>klapper</i> (coconut) and <i>tart</i>, referring to a Western-style dessert.</p><p style=\"text-align:justify;\">This treat is made from fresh young coconut combined with milk, butter, eggs, and sugar, creating a soft, creamy, and melt-in-your-mouth texture. It is often enriched with raisins, walnuts, or cinnamon, adding layers of sweetness and an inviting aroma.</p><p style=\"text-align:justify;\">Klapertart can be served in two styles: baked with a lightly browned, fragrant top layer, or chilled as a refreshing and light dessert. Both versions offer a unique indulgence—a perfect balance of sweetness, richness, and delicate coconut flavor.</p><p style=\"text-align:justify;\">More than just a dessert, klapertart reflects the rich cultural fusion of North Sulawesi, offering a timeless and elegant taste experience.</p>', '<p style=\"text-align:justify;\">클라페르타르트는 북술라웨시의 대표적인 디저트로, 현지의 풍미와 유럽식 디저트 문화가 조화를 이루는 특별한 음식입니다. “클라페르타르트”라는 이름은 네덜란드어 <i>klapper</i>(코코넛)와 <i>tart</i>(타르트)에서 유래되었습니다.</p><p style=\"text-align:justify;\">이 디저트는 신선한 어린 코코넛에 우유, 버터, 달걀, 설탕을 더해 만들어지며, 부드럽고 크리미하며 입안에서 녹는 식감을 자랑합니다. 건포도, 호두, 계피 등이 추가되어 달콤함과 향을 더욱 풍부하게 만들어 줍니다.</p><p style=\"text-align:justify;\">클라페르타르트는 살짝 구워 윗면이 노릇해진 따뜻한 버전이나, 차갑게 식혀 상큼하게 즐기는 두 가지 방식으로 제공됩니다. 두 가지 모두 달콤함과 고소함, 그리고 은은한 코코넛 향이 어우러진 매력을 지니고 있습니다.</p><p style=\"text-align:justify;\">이 디저트는 단순한 음식이 아니라 북술라웨시의 문화적 융합을 보여주는 상징적인 요리로, 세련되고 시대를 초월한 맛을 선사합니다.</p>', '<p style=\"text-align:justify;\">Klapertart是来自北苏拉威西的一款经典甜点，完美融合了当地风味与欧洲饮食文化。“Klapertart”一词源自荷兰语，其中 <i>klapper</i> 意为椰子，<i>tart</i> 指西式甜点。</p><p style=\"text-align:justify;\">这道甜点以新鲜嫩椰肉为主要原料，搭配牛奶、黄油、鸡蛋和糖制作而成，口感柔软细腻、香浓顺滑，入口即化。通常还会加入葡萄干、核桃或肉桂，为其增添丰富的层次感和诱人的香气。</p><p style=\"text-align:justify;\">Klapertart可以有两种享用方式：一种是烘烤后表面微微金黄、香气四溢；另一种是冷藏后食用，口感清爽轻盈。两种做法都展现了甜美、浓郁与椰香的完美平衡。</p><p style=\"text-align:justify;\">这不仅是一道甜点，更体现了北苏拉威西多元文化的融合，是一种优雅而经典、令人难忘的味觉体验。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/EXHwJJrxEZ8k7GXYcbtpuhQFfKuQXTncilRR9vND.jpg', 13, 1, '2026-04-28 02:57:12', '2026-04-28 02:57:12'),
(81, 'food', 'dessert', 'Nasi Jaha', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Nasi jaha adalah salah satu kuliner tradisional khas dari Sulawesi Utara yang sarat akan aroma rempah dan kehangatan budaya. Hidangan ini terbuat dari beras ketan yang dimasak bersama santan, jahe, dan sedikit garam, lalu dimasukkan ke dalam batang bambu dan dibakar perlahan di atas bara api.</p><p style=\"text-align:justify;\">Proses memasak di dalam bambu memberikan sentuhan unik: nasi menjadi pulen, harum, dan memiliki aroma khas dari perpaduan santan, jahe, serta asap bambu yang alami. Saat bambu dibelah, keluarlah nasi jaha yang padat namun lembut, dengan cita rasa gurih dan sedikit pedas hangat dari jahe.</p><p style=\"text-align:justify;\">Nasi jaha biasanya disajikan dalam potongan-potongan dan sering menjadi pelengkap hidangan lain seperti ikan bakar atau daging berbumbu khas. Selain itu, makanan ini juga kerap hadir dalam perayaan adat dan acara kebersamaan, melambangkan kehangatan dan tradisi masyarakat setempat.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan, nasi jaha adalah pengalaman rasa yang autentik—perpaduan sederhana bahan alami yang diolah dengan cara tradisional, menghasilkan cita rasa yang kaya dan tak terlupakan.</p>', '<p style=\"text-align:justify;\">Nasi jaha is a traditional delicacy from North Sulawesi, rich in spices and cultural warmth. It is made from glutinous rice cooked with coconut milk, ginger, and a pinch of salt, then placed inside bamboo tubes and slowly roasted over an open fire.</p><p style=\"text-align:justify;\">Cooking inside bamboo gives nasi jaha its distinctive character: the rice becomes soft, fragrant, and infused with the natural aroma of coconut milk, ginger, and smoky bamboo. When the bamboo is opened, it reveals compact yet tender rice with a savory taste and a gentle warmth from the ginger.</p><p style=\"text-align:justify;\">Nasi jaha is usually served in slices and often accompanies grilled fish or spiced meats. It is also commonly found in traditional ceremonies and communal celebrations, symbolizing togetherness and heritage.</p><p style=\"text-align:justify;\">More than just a dish, nasi jaha is an authentic culinary experience—simple ingredients transformed through traditional methods into something truly memorable.</p>', '<p style=\"text-align:justify;\">나시 자하는 북술라웨시의 전통 음식으로, 향신료의 향과 문화적 따뜻함이 담긴 특별한 요리입니다. 찹쌀을 코코넛 밀크, 생강, 소금과 함께 섞어 대나무 속에 넣은 뒤 숯불 위에서 천천히 구워 만듭니다.</p><p style=\"text-align:justify;\">대나무 안에서 조리되는 과정은 나시 자하만의 독특한 풍미를 만들어냅니다. 밥은 쫀득하고 향긋해지며, 코코넛과 생강, 그리고 은은한 대나무 향이 어우러집니다. 대나무를 열면 단단하면서도 부드러운 식감과 함께 고소하고 은은한 매운맛을 느낄 수 있습니다.</p><p style=\"text-align:justify;\">나시 자하는 보통 먹기 좋게 잘라 제공되며, 생선구이나 양념 고기와 함께 곁들여 먹습니다. 또한 전통 행사나 공동체 모임에서 자주 등장하며, 화합과 전통을 상징하는 음식입니다.</p><p style=\"text-align:justify;\">이 음식은 단순한 요리를 넘어 전통 방식으로 만들어진 진정한 미식 경험을 선사합니다.</p>', '<p style=\"text-align:justify;\">Nasi jaha是来自北苏拉威西的一道传统美食，充满香料气息与文化温度。它由糯米、椰奶、生姜和少许盐混合后，装入竹筒中，在炭火上慢慢烤制而成。</p><p style=\"text-align:justify;\">在竹筒中烹饪赋予了Nasi jaha独特的风味：米饭变得软糯香甜，并融合了椰奶、生姜以及竹子的自然烟熏香气。当竹筒被打开时，可以看到紧实却柔软的米饭，带有咸香和淡淡的姜辣温暖感。</p><p style=\"text-align:justify;\">Nasi jaha通常切成小段食用，常搭配烤鱼或香料肉类一起享用。此外，它也常出现在传统节庆和集体活动中，象征着团结与文化传承。</p><p style=\"text-align:justify;\">这不仅是一道美食，更是一种融合传统工艺与天然食材的独特味觉体验，令人难以忘怀。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/dSKRFEnXp5fmkLSdfLIubU6eixgQgXWAYbb5LWhO.jpg', 14, 1, '2026-04-28 03:03:13', '2026-04-28 03:03:13'),
(82, 'food', 'dessert', 'Panada', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Panada adalah salah satu camilan khas dari Sulawesi Utara yang sekilas menyerupai pastel, namun memiliki karakter rasa yang jauh lebih kaya dan unik. Kulitnya terbuat dari adonan tepung yang lembut, sedikit manis, dan digoreng hingga berwarna keemasan dengan tekstur renyah di luar namun tetap empuk di dalam.</p><p style=\"text-align:justify;\">Isi panada biasanya berupa ikan cakalang yang telah dimasak dengan bumbu khas seperti bawang, cabai, daun kemangi, dan perasan jeruk, menciptakan perpaduan rasa gurih, pedas, dan segar yang sangat menggugah selera. Aroma isian ikan yang harum langsung terasa begitu panada dibelah, membuat siapa pun sulit menolak kelezatannya.</p><p style=\"text-align:justify;\">Panada sering dinikmati sebagai camilan di berbagai kesempatan, baik sebagai teman minum teh maupun hidangan ringan saat berkumpul bersama keluarga. Rasanya yang khas mencerminkan kekayaan kuliner pesisir Sulawesi Utara yang penuh rempah dan cita rasa berani.</p><p style=\"text-align:justify;\">Lebih dari sekadar camilan, panada adalah representasi dari perpaduan budaya dan tradisi, menghadirkan rasa autentik yang sederhana namun begitu berkesan.</p>', '<p style=\"text-align:justify;\">Panada is a traditional snack from North Sulawesi that may resemble an empanada, but offers a much richer and more distinctive flavor. The outer dough is soft with a hint of sweetness, fried to a golden perfection—crispy on the outside yet tender on the inside.</p><p style=\"text-align:justify;\">The filling typically consists of skipjack tuna cooked with spices such as garlic, chili, basil, and a splash of citrus, creating a savory, spicy, and refreshing taste. Once opened, the fragrant fish filling releases an irresistible aroma.</p><p style=\"text-align:justify;\">Panada is commonly enjoyed as a snack for various occasions, whether as a companion to tea or as a light bite during gatherings. Its distinctive taste reflects the rich, spice-filled coastal cuisine of North Sulawesi.</p><p style=\"text-align:justify;\">More than just a snack, panada represents a blend of cultures and traditions, offering a simple yet memorable culinary experience.</p>', '<p style=\"text-align:justify;\">파나다는 북술라웨시의 대표적인 간식으로, 겉보기에는 파스텔이나 엠파나다와 비슷하지만 훨씬 더 풍부하고 독특한 맛을 자랑합니다. 반죽은 부드럽고 약간 달콤하며, 노릇하게 튀겨져 겉은 바삭하고 속은 촉촉한 식감을 제공합니다.</p><p style=\"text-align:justify;\">속재료는 주로 가다랑어로, 마늘, 고추, 바질, 감귤류 즙 등과 함께 조리되어 짭짤하면서도 매콤하고 상큼한 맛을 냅니다. 반으로 가르면 향긋한 생선 향이 퍼져 식욕을 자극합니다.</p><p style=\"text-align:justify;\">파나다는 차와 함께 즐기는 간식이나 모임에서의 가벼운 음식으로 자주 제공됩니다. 이 음식은 북술라웨시 해안 지역 특유의 풍부한 향신료와 대담한 맛을 잘 보여줍니다.</p><p style=\"text-align:justify;\">파나다는 단순한 간식을 넘어 다양한 문화가 어우러진 전통을 담은 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">Panada是来自北苏拉威西的一种传统小吃，外形类似馅饼，但风味更加丰富独特。外皮由柔软略带甜味的面团制成，炸至金黄色，外酥里嫩。</p><p style=\"text-align:justify;\">其内馅通常采用鲣鱼，搭配大蒜、辣椒、罗勒和少许柑橘汁调味，形成咸香、微辣且清新的口感。切开时，鱼馅的香气扑鼻而来，令人垂涎欲滴。</p><p style=\"text-align:justify;\">Panada常作为点心享用，无论是配茶还是聚会时的轻食都非常适合。它独特的风味体现了北苏拉威西沿海地区丰富的香料文化。</p><p style=\"text-align:justify;\">Panada不仅是一种小吃，更是融合多元文化与传统的美味代表，简单却令人难以忘怀。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/0SJKOJLfkoLBS34u40k5cwAWrHnn4XKBym6b5QHB.jpg', 15, 1, '2026-04-28 03:09:51', '2026-04-28 03:09:51'),
(83, 'food', 'dessert', 'Dodol', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Dodol khas Sulawesi Utara adalah camilan tradisional yang menghadirkan rasa manis legit dengan tekstur kenyal yang begitu khas. Terbuat dari campuran santan, gula merah, dan tepung ketan, dodol dimasak perlahan dalam waktu yang cukup lama hingga menghasilkan warna cokelat pekat dan rasa yang kaya.</p><p style=\"text-align:justify;\">Proses pembuatannya membutuhkan kesabaran dan ketelatenan, karena adonan harus terus diaduk agar menghasilkan tekstur yang halus dan tidak gosong. Aroma harum santan dan gula merah yang berpadu selama proses memasak menciptakan daya tarik tersendiri yang sulit dilupakan.</p><p style=\"text-align:justify;\">Saat dinikmati, dodol menawarkan sensasi lembut, lengket, dan manis yang pas—tidak berlebihan, tetapi cukup untuk memanjakan lidah. Biasanya dipotong kecil-kecil dan disajikan sebagai camilan atau hidangan khas saat perayaan dan acara keluarga.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan manis, dodol mencerminkan kehangatan tradisi dan kebersamaan masyarakat Sulawesi Utara, menghadirkan rasa nostalgia dalam setiap gigitannya.</p>', '<p style=\"text-align:justify;\">Dodol from North Sulawesi is a traditional sweet treat known for its rich caramel-like flavor and uniquely chewy texture. It is made from a mixture of coconut milk, palm sugar, and glutinous rice flour, slowly cooked over time until it develops a deep brown color and a complex taste.</p><p style=\"text-align:justify;\">The preparation requires patience and dedication, as the mixture must be continuously stirred to achieve a smooth texture and prevent burning. The aroma of coconut milk and palm sugar blending together during cooking creates an unforgettable fragrance.</p><p style=\"text-align:justify;\">When enjoyed, dodol offers a soft, sticky, and pleasantly sweet sensation—indulgent yet well-balanced. It is usually cut into small pieces and served as a snack or as a special treat during celebrations and family gatherings.</p><p style=\"text-align:justify;\">More than just a dessert, dodol represents warmth, tradition, and togetherness in North Sulawesi, bringing a sense of nostalgia in every bite.</p>', '<p style=\"text-align:justify;\">북술라웨시의 전통 간식인 도돌은 진한 단맛과 쫀득한 식감으로 사랑받는 디저트입니다. 코코넛 밀크, 팜슈가, 찹쌀가루를 섞어 오랜 시간 천천히 끓여 짙은 갈색과 깊은 풍미를 만들어냅니다.</p><p style=\"text-align:justify;\">이 음식은 조리 과정에서 계속 저어주어야 하기 때문에 인내와 정성이 필요합니다. 코코넛과 팜슈가가 어우러지며 퍼지는 향은 매우 매력적이고 기억에 남습니다.</p><p style=\"text-align:justify;\">도돌을 한 입 먹으면 부드럽고 끈적하며 달콤한 맛이 조화롭게 느껴집니다. 보통 작은 조각으로 잘라 간식이나 명절, 가족 모임에서 즐깁니다.</p><p style=\"text-align:justify;\">도돌은 단순한 디저트를 넘어 북술라웨시 사람들의 따뜻한 전통과 공동체 문화를 담고 있는 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">来自北苏拉威西的Dodol是一种传统甜点，以其浓郁的甜味和独特的Q弹口感而闻名。它由椰奶、红糖和糯米粉混合制成，经过长时间慢火熬煮，呈现出深棕色和丰富的层次风味。</p><p style=\"text-align:justify;\">制作过程需要耐心与细心，因为需要不断搅拌以确保口感顺滑且不焦糊。在烹煮过程中，椰奶与红糖融合散发出的香气令人难以忘怀。</p><p style=\"text-align:justify;\">品尝时，Dodol带来柔软、黏糯且甜而不腻的口感。通常被切成小块，作为零食或在节庆和家庭聚会中享用。</p><p style=\"text-align:justify;\">Dodol不仅是一种甜点，更体现了北苏拉威西的传统与人情味，每一口都充满温暖与回忆。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/nxokM1O4gu61t8pyvs7AXHs7xb8xsoRHQu8Xww8d.jpg', 16, 1, '2026-04-28 03:16:28', '2026-04-28 03:16:28'),
(84, 'food', 'dessert', 'Halua Kenari', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Halua kenari adalah salah satu camilan khas dari Sulawesi Utara yang menghadirkan perpaduan sempurna antara manis, gurih, dan tekstur renyah. Terbuat dari kacang kenari pilihan yang dipadukan dengan gula merah atau gula putih yang dimasak hingga mengaramel, camilan ini menawarkan cita rasa khas yang kaya dan menggoda.</p><p style=\"text-align:justify;\">Kacang kenari yang digunakan memberikan sensasi crunchy yang menyenangkan di setiap gigitan, sementara lapisan karamel yang membungkusnya menghadirkan rasa manis yang legit dan sedikit smoky. Aroma harum dari proses karamelisasi menciptakan daya tarik tersendiri yang langsung menggugah selera.</p><p style=\"text-align:justify;\">Halua kenari biasanya disajikan dalam potongan kecil dan sering hadir sebagai hidangan istimewa saat hari raya, acara keluarga, atau sebagai oleh-oleh khas daerah. Rasanya yang sederhana namun berkelas menjadikannya camilan yang disukai berbagai kalangan.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan ringan, halua kenari mencerminkan kekayaan hasil alam dan tradisi kuliner masyarakat Sulawesi Utara—sebuah perpaduan cita rasa lokal yang autentik dan berkesan.</p>', '<p style=\"text-align:justify;\">Halua kenari is a traditional delicacy from North Sulawesi that offers a delightful combination of sweetness, nuttiness, and crunch. It is made from selected kenari nuts coated in caramelized sugar—either palm sugar or white sugar—creating a rich and irresistible flavor.</p><p style=\"text-align:justify;\">The kenari nuts provide a satisfying crunchy texture in every bite, while the caramel coating adds a deep, sweet taste with a slight smoky note. The fragrant aroma from the caramelization process makes it even more enticing.</p><p style=\"text-align:justify;\">Halua kenari is usually served in small pieces and often enjoyed during festive occasions, family gatherings, or as a regional souvenir. Its simple yet refined taste makes it محبوب by many.</p><p style=\"text-align:justify;\">More than just a snack, halua kenari reflects the natural richness and culinary traditions of North Sulawesi—an authentic and memorable treat.</p>', '<p style=\"text-align:justify;\">할루아 케나리는 북술라웨시의 전통 간식으로, 달콤함과 고소함, 그리고 바삭한 식감이 조화를 이루는 매력적인 음식입니다. 엄선된 케나리 견과류에 설탕(팜슈가 또는 백설탕)을 입혀 카라멜화하여 깊고 풍부한 맛을 만들어냅니다.</p><p style=\"text-align:justify;\">케나리 견과는 씹을 때마다 바삭한 식감을 제공하며, 카라멜 코팅은 달콤하면서도 은은한 스모키 풍미를 더해줍니다. 카라멜이 만들어질 때 퍼지는 향은 식욕을 자극하는 중요한 요소입니다.</p><p style=\"text-align:justify;\">이 간식은 보통 작은 조각으로 제공되며, 명절이나 가족 모임, 또는 기념품으로 자주 즐겨집니다. 단순하지만 세련된 맛으로 많은 사람들에게 사랑받고 있습니다.</p><p style=\"text-align:justify;\">할루아 케나리는 단순한 간식을 넘어 북술라웨시의 자연과 전통을 담고 있는 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">Halua Kenari是来自北苏拉威西的一种传统小吃，融合了甜味、坚果香和酥脆口感。它由精选的肯纳里坚果（kenari nuts）裹上焦糖（红糖或白糖）制成，风味浓郁诱人。</p><p style=\"text-align:justify;\">坚果本身带来酥脆的口感，而外层的焦糖则增添了浓厚的甜味和淡淡的烟熏香气。焦糖制作过程中散发出的香味极具吸引力，让人食欲大开。</p><p style=\"text-align:justify;\">Halua Kenari通常被切成小块，在节庆、家庭聚会中食用，或作为地方特色伴手礼。其简单却精致的味道深受人们喜爱。</p><p style=\"text-align:justify;\">这不仅是一种小吃，更体现了北苏拉威西丰富的自然资源与传统饮食文化，是一种令人难忘的地道美味。</p><p style=\"text-align:justify;\">&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/8GDzqSG7cghctqF2cFUsWX34rHCc0Qxbmwr0d8jz.jpg', 17, 1, '2026-04-28 03:21:51', '2026-04-28 03:21:51'),
(85, 'food', 'dessert', 'Pisang goreng sambal Roa', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Pisang goreng sambal roa adalah salah satu kuliner unik dari Sulawesi Utara yang memadukan dua rasa yang tak biasa namun sangat menggoda: manis dan pedas. Pisang matang digoreng hingga berwarna keemasan dengan tekstur luar yang renyah dan bagian dalam yang lembut serta manis alami.</p><p style=\"text-align:justify;\">Keistimewaannya terletak pada sambal roa—sambal khas yang terbuat dari ikan roa asap yang dihaluskan bersama cabai, bawang, dan perasan jeruk. Sambal ini memiliki rasa pedas, gurih, dan aroma asap yang kuat, menciptakan kontras sempurna dengan manisnya pisang goreng.</p><p style=\"text-align:justify;\">Saat disantap bersama, kombinasi ini menghadirkan sensasi rasa yang unik: renyah, lembut, manis, pedas, dan smoky dalam satu gigitan. Hidangan ini sering dinikmati sebagai camilan atau sajian santai, namun selalu berhasil meninggalkan kesan yang berbeda dan berani.</p><p style=\"text-align:justify;\">Lebih dari sekadar makanan, pisang goreng sambal roa mencerminkan karakter kuliner Sulawesi Utara yang kreatif, berani memadukan rasa, dan penuh kejutan.</p>', '<p style=\"text-align:justify;\">Fried banana with roa sambal is a unique culinary specialty from North Sulawesi that combines two unexpected yet irresistible flavors: sweet and spicy. Ripe bananas are deep-fried to a golden perfection, offering a crispy exterior and a soft, naturally sweet interior.</p><p style=\"text-align:justify;\">The highlight lies in the roa sambal—a traditional chili paste made from smoked halfbeak fish, blended with chili, garlic, shallots, and a splash of citrus. This sambal delivers a bold combination of spicy, savory, and smoky flavors, perfectly contrasting with the sweetness of the banana.</p><p style=\"text-align:justify;\">When enjoyed together, the dish creates a remarkable taste experience: crispy, soft, sweet, spicy, and smoky all in one bite. It is often served as a snack or casual dish, yet always leaves a memorable impression.</p><p style=\"text-align:justify;\">More than just food, this dish reflects the creative and bold culinary identity of North Sulawesi.</p>', '<p style=\"text-align:justify;\">바나나 튀김과 로아 삼발은 북술라웨시의 독특한 요리로, 달콤함과 매콤함이라는 예상치 못한 조합이 매력적인 음식입니다. 잘 익은 바나나는 황금빛으로 바삭하게 튀겨져 겉은 바삭하고 속은 부드럽고 달콤한 식감을 제공합니다.</p><p style=\"text-align:justify;\">이 요리의 핵심은 로아 삼발입니다. 훈제된 하프비크 생선에 고추, 마늘, 샬롯, 감귤즙을 더해 만든 이 소스는 매콤하고 짭짤하며 스모키한 풍미를 자랑합니다. 이는 바나나의 달콤함과 완벽한 대비를 이룹니다.</p><p style=\"text-align:justify;\">함께 먹으면 바삭함, 부드러움, 달콤함, 매운맛, 그리고 훈제 향이 어우러진 특별한 맛을 경험할 수 있습니다. 간식이나 가벼운 요리로 즐기기에 좋으며, 독특한 인상을 남깁니다.</p><p style=\"text-align:justify;\">이 음식은 북술라웨시의 창의적이고 대담한 미식 문화를 잘 보여줍니다.</p>', '<p style=\"text-align:justify;\">炸香蕉配Roa辣酱是来自北苏拉威西的一道独特美食，将甜味与辣味巧妙结合。成熟的香蕉被炸至金黄色，外酥内软，带有天然的甜味。</p><p style=\"text-align:justify;\">这道菜的灵魂在于Roa辣酱，它由熏制的半嘴鱼与辣椒、大蒜、红葱和少许柑橘汁制成，具有辛辣、咸香和烟熏风味，与香蕉的甜味形成完美对比。</p><p style=\"text-align:justify;\">两者结合在一起，带来酥脆、柔软、甜美、辛辣与烟熏的多重口感体验。这道美食常作为小吃或休闲料理享用，但总能让人留下深刻印象。</p><p style=\"text-align:justify;\">它不仅是一道食物，更体现了北苏拉威西大胆创新、敢于融合风味的饮食文化。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/MqoivuwUBc1cX59eHobkx0mr259cjhEE4yi62os1.jpg', 18, 1, '2026-04-28 03:25:17', '2026-04-28 03:25:37'),
(86, 'food', 'dessert', 'Es Brenebon', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Es brenebon adalah salah satu hidangan penutup unik dari Sulawesi Utara yang menghadirkan sensasi manis, segar, dan berbeda dari dessert pada umumnya. Jika biasanya brenebon dikenal sebagai sup kacang merah yang gurih, versi es ini justru diolah menjadi sajian dingin yang manis dan menyegarkan.</p><p style=\"text-align:justify;\">Terbuat dari kacang merah yang dimasak hingga empuk, kemudian dipadukan dengan gula, santan atau susu, serta es batu, es brenebon menawarkan perpaduan rasa yang lembut dan nikmat. Tekstur kacang yang empuk berpadu dengan dinginnya es menciptakan sensasi kontras yang menyenangkan di setiap suapan.</p><p style=\"text-align:justify;\">Aromanya ringan namun menggoda, dengan rasa manis yang tidak berlebihan, menjadikannya cocok dinikmati sebagai penutup hidangan atau pelepas dahaga di cuaca panas. Terkadang, tambahan seperti vanila atau sirup memberikan sentuhan ekstra yang semakin memperkaya cita rasa.</p><p style=\"text-align:justify;\">Lebih dari sekadar minuman penutup, es brenebon mencerminkan kreativitas kuliner masyarakat Sulawesi Utara dalam mengolah bahan sederhana menjadi sajian yang unik, lezat, dan berkesan.</p>', '<p style=\"text-align:justify;\">Iced brenebon is a unique dessert from North Sulawesi that offers a sweet, refreshing twist on a traditional dish. While brenebon is typically known as a savory red bean soup, this version transforms it into a chilled, sweet treat.</p><p style=\"text-align:justify;\">It is made from red beans cooked until tender, then combined with sugar, coconut milk or milk, and ice cubes. The result is a smooth, enjoyable blend of flavors. The soft beans paired with the cold ice create a pleasant contrast in every bite.</p><p style=\"text-align:justify;\">Its aroma is light yet inviting, with a sweetness that is not overwhelming, making it perfect as a dessert or a refreshing drink in warm weather. Sometimes, additions like vanilla or syrup enhance its flavor even further.</p><p style=\"text-align:justify;\">More than just a dessert, iced brenebon reflects the culinary creativity of the people of North Sulawesi in turning simple ingredients into something unique and memorable.</p>', '<p style=\"text-align:justify;\">에스 브레네본은 북술라웨시의 독특한 디저트로, 달콤하고 시원한 맛을 선사합니다. 원래 짭짤한 붉은콩 수프로 알려진 브레네본을 차갑고 달콤한 디저트로 재해석한 음식입니다.</p><p style=\"text-align:justify;\">부드럽게 삶은 붉은 콩에 설탕, 코코넛 밀크 또는 우유, 그리고 얼음을 더해 만들어집니다. 부드러운 콩과 차가운 얼음의 조합이 입안에서 즐거운 대비를 만들어냅니다.</p><p style=\"text-align:justify;\">향은 은은하면서도 매력적이며, 과하지 않은 단맛으로 더운 날씨에 즐기기 좋은 디저트입니다. 바닐라나 시럽을 추가해 풍미를 더욱 풍부하게 하기도 합니다.</p><p style=\"text-align:justify;\">에스 브레네본은 단순한 디저트를 넘어 북술라웨시 사람들의 창의적인 음식 문화를 보여주는 특별한 음식입니다.</p>', '<p style=\"text-align:justify;\">冰镇Brenebon是来自北苏拉威西的一道独特甜品，为传统红豆料理带来清新甜美的全新演绎。原本以咸味红豆汤闻名的Brenebon，在这里被转化为冰凉的甜品。</p><p style=\"text-align:justify;\">它由煮至软糯的红豆搭配糖、椰奶或牛奶以及冰块制成，口感顺滑清爽。柔软的红豆与冰凉的口感形成鲜明对比，每一口都令人愉悦。</p><p style=\"text-align:justify;\">其香气清淡而诱人，甜味适中，非常适合作为餐后甜点或炎热天气中的解暑饮品。有时还会加入香草或糖浆，让风味更加丰富。</p><p style=\"text-align:justify;\">这不仅是一道甜品，更体现了北苏拉威西将简单食材转化为独特美味的创意与智慧。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/KojvYg0qRdpYwS4frD28JNLTTlogEgB7W5uSd7rw.jpg', 19, 1, '2026-04-28 03:32:27', '2026-04-28 03:32:27'),
(87, 'food', 'drinks', 'Cap Tikus', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Cap Tikus adalah minuman tradisional khas dari Sulawesi Utara yang memiliki karakter kuat dan sejarah panjang dalam budaya masyarakat setempat. Minuman ini merupakan hasil fermentasi dan penyulingan nira pohon aren, menghasilkan cairan bening dengan kadar alkohol yang cukup tinggi.</p><p style=\"text-align:justify;\">Proses pembuatannya masih banyak dilakukan secara tradisional, dimulai dari pengambilan nira segar hingga proses penyulingan yang teliti. Hasilnya adalah minuman dengan aroma khas yang tajam, rasa yang kuat, dan sensasi hangat yang langsung terasa saat diminum.</p><p style=\"text-align:justify;\">Cap Tikus sering dikaitkan dengan berbagai acara adat dan kebersamaan, menjadi simbol keakraban dan tradisi lokal. Meski memiliki cita rasa yang keras, bagi masyarakat setempat minuman ini mencerminkan identitas budaya dan warisan turun-temurun yang dijaga hingga kini.</p><p style=\"text-align:justify;\">Namun, karena kandungan alkoholnya yang tinggi, Cap Tikus sebaiknya dikonsumsi secara bijak dan bertanggung jawab.</p>', '<p style=\"text-align:justify;\">Cap Tikus is a traditional beverage from North Sulawesi, known for its strong character and deep cultural roots. It is made from fermented and distilled sap of the aren palm, resulting in a clear liquid with relatively high alcohol content.</p><p style=\"text-align:justify;\">The production process is often done traditionally, starting from collecting fresh sap to careful distillation. The result is a drink with a sharp aroma, bold flavor, and a warming sensation when consumed.</p><p style=\"text-align:justify;\">Cap Tikus is commonly associated with traditional ceremonies and social gatherings, symbolizing togetherness and local heritage. Despite its strong taste, it represents an important cultural identity passed down through generations.</p><p style=\"text-align:justify;\">Due to its high alcohol content, it should be consumed responsibly.</p>', '<p style=\"text-align:justify;\">캅 티쿠스는 북술라웨시의 전통 음료로, 강한 개성과 깊은 문화적 의미를 지니고 있습니다. 이 음료는 아렌 야자수 수액을 발효하고 증류하여 만들어지며, 투명한 색과 높은 알코올 도수를 특징으로 합니다.</p><p style=\"text-align:justify;\">제조 과정은 전통적인 방식으로 이루어지며, 신선한 수액 채취부터 정교한 증류 과정까지 포함됩니다. 완성된 음료는 강한 향과 진한 맛, 그리고 마셨을 때 따뜻한 느낌을 제공합니다.</p><p style=\"text-align:justify;\">캅 티쿠스는 전통 행사나 모임에서 자주 등장하며, 공동체의 유대감과 문화적 유산을 상징합니다. 강한 맛에도 불구하고 지역 주민들에게는 중요한 정체성을 나타내는 음료입니다.</p><p style=\"text-align:justify;\">알코올 함량이 높기 때문에 적절하고 책임감 있게 섭취하는 것이 중요합니다.</p>', '<p style=\"text-align:justify;\">Cap Tikus是来自北苏拉威西的一种传统饮品，以其浓烈的风味和深厚的文化背景而闻名。它由糖棕树的树汁经过发酵和蒸馏制成，呈透明状，酒精含量较高。</p><p style=\"text-align:justify;\">其制作过程多采用传统方法，从采集新鲜树汁到精细蒸馏，步骤严谨。成品具有强烈的香气、浓郁的口感，以及饮用时带来的温热感。</p><p style=\"text-align:justify;\">Cap Tikus常出现在传统仪式和社交场合中，象征着团结与文化传承。尽管口味较为强烈，但它承载着当地重要的文化身份与历史。</p><p style=\"text-align:justify;\">由于酒精含量较高，建议适量饮用。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/CH5ug9ymAaeDyF3qdmRLgG41VA4MQJvG92YyaFUa.jpg', 20, 1, '2026-04-28 03:36:21', '2026-04-28 03:36:21');
INSERT INTO `travel_info_items` (`id`, `type`, `category_key`, `title`, `title_en`, `title_ko`, `title_zh`, `description`, `description_en`, `description_ko`, `description_zh`, `image_url`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(88, 'shopping', 'center', 'Mega Trade Center', 'Mega Trade Center', 'Mega Trade Center', 'Mega Trade Center', '<p style=\"text-align:justify;\">Mega Trade Center atau yang lebih dikenal dengan sebutan MTC merupakan salah satu pusat perbelanjaan dan perdagangan modern paling ramai di Kota Manado. Dengan konsep pusat perdagangan terpadu, MTC menjadi destinasi favorit masyarakat untuk berbelanja kebutuhan elektronik, gadget, fashion, kuliner, hingga berbagai kebutuhan sehari-hari dalam satu lokasi yang strategis.</p><p style=\"text-align:justify;\">Terletak di kawasan pusat kota yang mudah dijangkau, Mega Trade Center menghadirkan suasana urban yang dinamis dengan aktivitas perdagangan yang selalu hidup sepanjang hari. Berbagai tenant ternama, toko retail, pusat teknologi, dan area hiburan menjadikan tempat ini sebagai salah satu pusat aktivitas ekonomi dan gaya hidup masyarakat Manado.</p><p style=\"text-align:justify;\">MTC juga dikenal sebagai salah satu pusat teknologi dan gadget yang populer di Manado. Pengunjung dapat menemukan berbagai pilihan smartphone terbaru, aksesoris elektronik, komputer, hingga kebutuhan digital lainnya dengan pilihan produk yang lengkap dan harga yang kompetitif.</p><p style=\"text-align:justify;\">Selain berbelanja, pengunjung juga dapat menikmati berbagai pilihan kuliner dan café yang menghadirkan suasana santai di tengah ramainya aktivitas kota. Kombinasi antara pusat belanja, hiburan, dan gaya hidup modern membuat MTC menjadi tempat yang cocok untuk berkumpul bersama keluarga maupun teman.</p><p style=\"text-align:justify;\">Dengan lokasi strategis, atmosfer modern, dan fasilitas yang lengkap, Mega Trade Center menjadi salah satu landmark perdagangan dan pusat gaya hidup modern yang terus berkembang di Kota Manado.</p><p style=\"text-align:justify;\">&nbsp;</p>', '<p>Mega Trade Center, commonly known as MTC, is one of the busiest modern shopping and commercial centers in Manado. With its integrated trade center concept, MTC has become a favorite destination for people to shop for electronics, gadgets, fashion, culinary delights, and daily necessities in one strategic location.</p><p>Located in the heart of the city and easily accessible, Mega Trade Center offers a dynamic urban atmosphere with vibrant commercial activities throughout the day. Various well-known tenants, retail stores, technology centers, and entertainment areas make it one of the main hubs for economic activity and modern lifestyle in Manado.</p><p>MTC is also widely recognized as one of the most popular technology and gadget centers in Manado. Visitors can find the latest smartphones, electronic accessories, computers, and various digital products with extensive selections and competitive prices.</p><p>Beyond shopping, visitors can also enjoy a variety of culinary spots and cafés that provide a relaxing atmosphere amid the busy city environment. The combination of shopping, entertainment, and modern lifestyle facilities makes MTC an ideal place to gather with family and friends.</p><p>With its strategic location, modern atmosphere, and complete facilities, Mega Trade Center has become one of the leading commercial landmarks and modern lifestyle destinations in Manado.</p>', '<p>Mega Trade Center는 현지에서 “MTC”로 잘 알려져 있으며, 마나도에서 가장 활기찬 현대식 쇼핑 및 상업 중심지 중 하나입니다. 통합형 쇼핑·무역센터 콘셉트를 바탕으로 전자제품, 스마트기기, 패션, 음식, 생활용품 등을 한곳에서 편리하게 쇼핑할 수 있어 많은 사람들에게 사랑받는 장소입니다.</p><p>도심 중심부의 접근성 좋은 위치에 자리한 Mega Trade Center는 하루 종일 활기찬 상업 활동이 이어지는 역동적인 도시 분위기를 제공합니다. 다양한 유명 브랜드 매장, 리테일 숍, IT 및 기술 매장, 엔터테인먼트 공간이 함께 어우러져 마나도의 경제 활동과 현대 라이프스타일의 중심지 역할을 하고 있습니다.</p><p>특히 MTC는 마나도에서 가장 인기 있는 IT 및 가젯 쇼핑 명소 중 하나로 유명합니다. 최신 스마트폰, 전자 액세서리, 컴퓨터 및 다양한 디지털 제품을 폭넓은 선택지와 경쟁력 있는 가격으로 만나볼 수 있습니다.</p><p>쇼핑뿐만 아니라 다양한 레스토랑과 카페도 마련되어 있어 분주한 도시 분위기 속에서도 편안하고 여유로운 시간을 즐길 수 있습니다. 쇼핑, 엔터테인먼트, 현대적인 라이프스타일 요소가 조화를 이루어 가족과 친구들이 함께 시간을 보내기에 좋은 장소입니다.</p><p>전략적인 위치와 현대적인 분위기, 그리고 다양한 시설을 갖춘 Mega Trade Center는 마나도의 대표적인 상업 랜드마크이자 현대 라이프스타일 중심지로 자리 잡고 있습니다.</p>', '<p>Mega Trade Center，简称“MTC”，是万鸦老最繁忙的现代购物与商业中心之一。凭借一体化商业中心概念，MTC 成为当地居民购买电子产品、数码设备、时尚商品、美食以及日常用品的热门目的地。</p><p>Mega Trade Center 位于市中心黄金地段，交通便利，全天充满活力与商业氛围。众多知名品牌商店、零售店、科技中心以及娱乐区域汇聚于此，使其成为万鸦老经济活动与现代生活方式的重要中心之一。</p><p>MTC 同时也是万鸦老最受欢迎的科技与数码购物中心之一。游客可以在这里找到最新款智能手机、电子配件、电脑以及各种数字产品，拥有丰富的选择和极具竞争力的价格。</p><p>除了购物之外，游客还可以在各种餐厅与咖啡馆中放松休闲，在繁忙的城市氛围中享受舒适时光。购物、娱乐与现代生活方式的完美结合，使 MTC 成为适合与家人朋友相聚的理想场所。</p><p>凭借优越的地理位置、现代化氛围以及完善的设施，Mega Trade Center 已成为万鸦老最具代表性的商业地标和现代生活方式中心之一。</p><p>&nbsp;</p>', 'https://api.welcomemanado.my.id/storage/travel-info/nJc3yxoC7Nx5eTgUKhDi6yewGgjLSE0fxvq80Kdz.png', 4, 1, '2026-05-13 05:42:08', '2026-05-13 05:42:08'),
(89, 'shopping', 'souvenir', 'Christine Klappertaart & Souvenir', 'Christine Klappertaart & Souvenir', 'Christine Klappertaart & Souvenir', 'Christine Klappertaart & Souvenir', '<p style=\"text-align:justify;\">Di Kota Manado, Christine Klappertaart &amp; Souvenir dikenal sebagai salah satu destinasi favorit untuk menikmati cita rasa khas Sulawesi Utara sekaligus berburu oleh-oleh berkualitas. Tempat ini menghadirkan perpaduan sempurna antara kuliner tradisional, suasana hangat, dan kekayaan budaya lokal yang membuat setiap pengunjung merasa dekat dengan keramahan khas Manado.</p><p style=\"text-align:justify;\">Produk andalannya, Klappertaart, menjadi ikon yang paling dicari wisatawan. Dibuat dari kelapa muda pilihan dengan tekstur lembut dan rasa manis yang khas, sajian ini menghadirkan cita rasa autentik warisan kuliner Belanda-Manado yang melegenda. Selain Klappertaart, tersedia juga berbagai makanan khas, camilan tradisional, kopi lokal, hingga souvenir unik yang merepresentasikan budaya Minahasa dan Sulawesi Utara.</p><p style=\"text-align:justify;\">Dengan tampilan toko yang nyaman dan lengkap, Christine Klappertaart &amp; Souvenir bukan sekadar tempat membeli oleh-oleh, tetapi juga ruang untuk merasakan pengalaman budaya lokal. Pelayanan yang ramah dan pilihan produk yang beragam membuat pengunjung betah menikmati suasana sambil memilih buah tangan terbaik untuk keluarga dan sahabat.</p><p style=\"text-align:justify;\">Bagi banyak wisatawan, berkunjung ke Christine Klappertaart &amp; Souvenir telah menjadi bagian dari perjalanan menikmati Manado. Tempat ini menghadirkan kenangan tentang rasa, tradisi, dan keramahan yang selalu ingin dibawa pulang dari bumi Nyiur Melambai.</p>', '<p style=\"text-align:justify;\">In the city of Manado, Christine Klappertaart &amp; Souvenir is known as one of the favorite destinations for enjoying the authentic flavors of North Sulawesi while shopping for high-quality souvenirs. This place offers a perfect blend of traditional cuisine, warm atmosphere, and rich local culture that makes every visitor feel welcomed by the genuine hospitality of Manado.</p><p style=\"text-align:justify;\">Its signature product, Klappertaart, has become the most sought-after delicacy among tourists. Made from selected young coconut with a soft texture and distinctive sweetness, this dessert presents the authentic taste of the legendary Dutch-Manado culinary heritage. In addition to Klappertaart, visitors can also find a variety of local snacks, traditional foods, local coffee, and unique souvenirs that represent the culture of Minahasa and North Sulawesi.</p><p style=\"text-align:justify;\">With its comfortable and well-organized store, Christine Klappertaart &amp; Souvenir is more than just a souvenir shop—it is a place to experience local culture. Friendly service and a wide selection of products allow visitors to enjoy the atmosphere while choosing the perfect gifts for family and friends.</p><p style=\"text-align:justify;\">For many travelers, visiting Christine Klappertaart &amp; Souvenir has become an essential part of experiencing Manado. It offers memories of flavor, tradition, and hospitality that visitors always want to take home from the land of Nyiur Melambai.</p>', '<p style=\"text-align:justify;\">마나도에 위치한 크리스틴 클라페르타르트 &amp; 수베니르는 북술라웨시의 대표적인 맛과 고품질 기념품을 함께 즐길 수 있는 인기 명소로 알려져 있습니다. 이곳은 전통 음식, 따뜻한 분위기, 그리고 풍부한 지역 문화를 아름답게 조화시켜 방문객들에게 마나도 특유의 환대와 정겨움을 선사합니다.</p><p style=\"text-align:justify;\">대표 메뉴인 클라페르타르트(Klappertaart)는 관광객들이 가장 많이 찾는 인기 디저트입니다. 신선한 어린 코코넛으로 만들어진 부드러운 식감과 달콤한 맛은 네덜란드와 마나도 문화가 어우러진 전통의 풍미를 그대로 담고 있습니다. 이외에도 다양한 지역 간식, 전통 음식, 현지 커피, 그리고 미나하사와 북술라웨시 문화를 담은 독특한 기념품들을 만나볼 수 있습니다.</p><p style=\"text-align:justify;\">편안하고 잘 정돈된 매장은 단순한 기념품 가게를 넘어 지역 문화를 체험할 수 있는 공간이 됩니다. 친절한 서비스와 다양한 상품들은 방문객들이 여유롭게 분위기를 즐기며 가족과 친구들을 위한 특별한 선물을 고를 수 있도록 합니다.</p><p style=\"text-align:justify;\">많은 여행객들에게 크리스틴 클라페르타르트 &amp; 수베니르 방문은 마나도 여행의 특별한 코스가 되었습니다. 이곳은 니우르 멜람바이의 땅에서 느낀 맛, 전통, 그리고 따뜻한 환대를 오래도록 기억하게 해주는 장소입니다.</p>', '<p style=\"text-align:justify;\">마나도에 위치한 크리스틴 클라페르타르트 &amp; 수베니르는 북술라웨시의 대표적인 맛과 고품질 기념품을 함께 즐길 수 있는 인기 명소로 알려져 있습니다. 이곳은 전통 음식, 따뜻한 분위기, 그리고 풍부한 지역 문화를 아름답게 조화시켜 방문객들에게 마나도 특유의 환대와 정겨움을 선사합니다.</p><p style=\"text-align:justify;\">대표 메뉴인 클라페르타르트(Klappertaart)는 관광객들이 가장 많이 찾는 인기 디저트입니다. 신선한 어린 코코넛으로 만들어진 부드러운 식감과 달콤한 맛은 네덜란드와 마나도 문화가 어우러진 전통의 풍미를 그대로 담고 있습니다. 이외에도 다양한 지역 간식, 전통 음식, 현지 커피, 그리고 미나하사와 북술라웨시 문화를 담은 독특한 기념품들을 만나볼 수 있습니다.</p><p style=\"text-align:justify;\">편안하고 잘 정돈된 매장은 단순한 기념품 가게를 넘어 지역 문화를 체험할 수 있는 공간이 됩니다. 친절한 서비스와 다양한 상품들은 방문객들이 여유롭게 분위기를 즐기며 가족과 친구들을 위한 특별한 선물을 고를 수 있도록 합니다.</p><p style=\"text-align:justify;\">많은 여행객들에게 크리스틴 클라페르타르트 &amp; 수베니르 방문은 마나도 여행의 특별한 코스가 되었습니다. 이곳은 니우르 멜람바이의 땅에서 느낀 맛, 전통, 그리고 따뜻한 환대를 오래도록 기억하게 해주는 장소입니다.</p>', 'https://api.welcomemanado.my.id/storage/travel-info/kqy0scseOD6yirVPOaIPZim38ErU41GVvpKplM62.png', 9, 1, '2026-05-13 06:48:25', '2026-05-13 06:48:41'),
(90, 'shopping', 'souvenir', 'Manado Souvenir', NULL, NULL, NULL, '<p style=\"text-align:justify;\">Manado Souvenir (Oleh-oleh Murah &amp; Lengkap sejak 2004) merupakan salah satu pusat oleh-oleh paling populer di Manado yang menjadi destinasi favorit wisatawan lokal maupun mancanegara. Berlokasi strategis di Jalan B.W. Lapian No. 25, toko ini dikenal sebagai tempat berburu oleh-oleh khas Sulawesi Utara dengan pilihan produk yang lengkap, harga terjangkau, dan suasana belanja yang nyaman.<br><br>Di dalam toko ini, pengunjung dapat menemukan beragam makanan khas Manado seperti klappertaart, sambal roa, bagea kenari, kacang goyang, halua, kukis koa, hingga aneka olahan ikan khas Sulawesi Utara. Tidak hanya kuliner, tersedia juga berbagai cinderamata unik seperti kain bentenan, kaos khas Manado, gantungan kunci etnik, kerajinan kayu kelapa, dan berbagai souvenir bernuansa budaya Minahasa.</p><p style=\"text-align:justify;\">Toko ini terkenal dengan pelayanan yang ramah dan proses packing yang praktis, sehingga wisatawan yang membeli dalam jumlah banyak tetap merasa nyaman saat membawa pulang oleh-oleh. Lokasinya yang berada di pusat kota membuat mudah dijangkau dan hampir selalu ramai dikunjungi wisatawan yang ingin membawa pulang cita rasa dan budaya khas Manado.</p><p style=\"text-align:justify;\">Bagi banyak wisatawan, berkunjung ke toko ini bukan sekadar berbelanja, tetapi juga menjadi pengalaman menikmati kekayaan budaya dan kuliner khas Sulawesi Utara dalam satu tempat yang lengkap dan berkesan.</p>', '<p style=\"text-align:justify;\">Manado Souvenir is one of the most popular souvenir centers in Manado and a favorite destination for both domestic and international tourists. Strategically located on Jl. B.W. Lapian No. 25, this store is well known as the perfect place to find authentic North Sulawesi souvenirs with complete product selections, affordable prices, and a comfortable shopping atmosphere.</p><p style=\"text-align:justify;\">Inside the store, visitors can discover a wide variety of Manado specialties such as klappertaart, roa chili sauce, bagea kenari cookies, candied peanuts, halua, koa cookies, and traditional smoked fish products. In addition to culinary delights, the shop also offers unique handicrafts including Bentenan fabrics, Manado-themed T-shirts, ethnic keychains, coconut wood crafts, and various souvenirs inspired by Minahasa culture.</p><p style=\"text-align:justify;\">The store is also famous for its friendly service and practical packing assistance, making it convenient for travelers who purchase souvenirs in large quantities. Its strategic location in the heart of the city makes Manado Souvenir an ideal stop before returning home while bringing unforgettable memories from North Sulawesi.</p>', '<p style=\"text-align:justify;\">Manado Souvenir 는 마나도에서 가장 유명한 기념품 전문점 중 하나로, 국내외 관광객들에게 사랑받는 인기 쇼핑 명소입니다. Jl. B.W. Lapian No.25에 위치한 이곳은 다양한 북술라웨시 특산품과 합리적인 가격, 편안한 쇼핑 분위기로 잘 알려져 있습니다.<br><br>매장 안에서는 클라페르타르트, 로아 삼발, 바게아 케나리 쿠키, 전통 땅콩 과자, 할루아, 코아 쿠키, 훈제 생선 등 다양한 마나도 전통 먹거리를 만날 수 있습니다. 또한 벤테난 전통 직물, 마나도 테마 티셔츠, 민족풍 열쇠고리, 코코넛 목재 공예품 등 미나하사 문화를 담은 다양한 기념품도 판매하고 있습니다.</p><p style=\"text-align:justify;\">친절한 서비스와 편리한 포장 서비스 덕분에 많은 양의 기념품을 구매하는 여행객들도 편안하게 쇼핑할 수 있습니다. 도심 중심에 위치해 있어 북술라웨시의 특별한 추억을 담아가기 위한 마지막 쇼핑 장소로도 매우 적합합니다.</p>', '<p style=\"text-align:justify;\">Manado Souvenir 是马纳多最受欢迎的纪念品商店之一，也是国内外游客喜爱的购物目的地。店铺位于 Jl. B.W. Lapian No.25，地理位置优越，以商品齐全、价格实惠以及舒适的购物环境而闻名。<br><br>在这里，游客可以找到各种马纳多特色美食，如椰奶蛋糕（Klappertaart）、Roa 辣椒酱、Bagea Kenari 饼干、花生糖、Halua、Koa 饼干以及传统熏鱼制品。除了美食之外，商店还提供丰富的特色手工艺品，包括 Bentenan 传统布料、马纳多主题 T 恤、民族风钥匙扣、椰木工艺品以及充满米纳哈萨文化特色的纪念品。</p><p style=\"text-align:justify;\">这里以热情友好的服务和便捷的打包服务而受到游客欢迎，即使购买大量商品也能轻松携带。位于市中心的优越位置，使 Manado Souvenir 成为游客离开北苏拉威西前购买伴手礼和留下美好回忆的理想之地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/kb0xMM6XtS1tNespbbBpVaat6WFr6RNThiUAEpAZ.png', 10, 1, '2026-05-13 07:33:13', '2026-05-13 07:33:13'),
(91, 'shopping', 'souvenir', 'Miens', 'Miens', 'Miens', 'Miens', '<p style=\"text-align:justify;\">Miens Souvenir merupakan salah satu pusat oleh-oleh terkenal di Manado yang menjadi destinasi favorit wisatawan untuk berburu buah tangan khas Sulawesi Utara. Dikenal dengan koleksi produknya yang lengkap dan berkualitas, Miens Souvenir menghadirkan pengalaman belanja yang nyaman dengan nuansa hangat khas Manado.</p><p style=\"text-align:justify;\">Di toko ini, pengunjung dapat menemukan berbagai makanan khas Manado seperti klappertaart, sambal roa, bagea, kacang goyang, cakalang fufu, serta aneka camilan tradisional khas Sulawesi Utara yang terkenal dengan cita rasa unik dan autentik. Selain kuliner, tersedia pula berbagai souvenir menarik seperti kain bentenan, kaos khas Manado, aksesori etnik, hingga kerajinan tangan bernuansa budaya Minahasa.</p><p style=\"text-align:justify;\">Miens Souvenir juga dikenal dengan penataan toko yang rapi, pilihan produk yang beragam, serta pelayanan yang ramah dan membantu. Kemasan produk yang modern membuat oleh-oleh lebih praktis dibawa bepergian maupun dijadikan hadiah untuk keluarga dan sahabat.</p><p style=\"text-align:justify;\">Bagi wisatawan yang ingin membawa pulang kenangan terbaik dari Sulawesi Utara, Miens Souvenir menjadi tempat yang tepat untuk menikmati perpaduan cita rasa lokal, budaya tradisional, dan pengalaman berbelanja yang menyenangkan dalam satu destinasi.</p>', '<p style=\"text-align:justify;\">Miens Souvenir is one of the well-known souvenir centers in Manado and a favorite destination for travelers looking for authentic North Sulawesi gifts and local specialties. Known for its wide variety of quality products, Miens Souvenir offers a comfortable shopping experience with the warm hospitality that Manado is famous for.</p><p style=\"text-align:justify;\">Visitors can find a variety of traditional Manado delicacies such as klappertaart, roa chili sauce, bagea cookies, candied peanuts, cakalang fufu, and many other authentic snacks from North Sulawesi known for their rich and unique flavors. Besides culinary products, the shop also offers beautiful souvenirs including Bentenan fabrics, Manado-themed T-shirts, ethnic accessories, and handicrafts inspired by Minahasa culture.</p><p style=\"text-align:justify;\">Miens Souvenir is also appreciated for its neat store layout, diverse product selection, and friendly customer service. The modern packaging makes the souvenirs practical to carry and perfect as gifts for family and friends.</p><p style=\"text-align:justify;\">For travelers who wish to bring home unforgettable memories from North Sulawesi, Miens Souvenir is the perfect place to enjoy a combination of local flavors, traditional culture, and a pleasant shopping experience.</p>', '<p style=\"text-align:justify;\">Miens Souvenir 는 Manado 에서 유명한 기념품 전문점 중 하나로, 북술라웨시의 특산품과 기념품을 찾는 여행객들에게 인기 있는 쇼핑 장소입니다. 다양한 고품질 상품과 마나도 특유의 따뜻한 환대로 편안한 쇼핑 경험을 제공합니다.</p><p style=\"text-align:justify;\">이곳에서는 클라페르타르트, 로아 삼발, 바게아 쿠키, 전통 땅콩 과자, 차칼랑 후푸 등 북술라웨시의 독특하고 풍부한 맛을 자랑하는 다양한 전통 먹거리를 만나볼 수 있습니다. 또한 벤테난 전통 직물, 마나도 테마 티셔츠, 민족풍 액세서리, 미나하사 문화에서 영감을 받은 수공예품 등 다양한 기념품도 판매하고 있습니다.</p><p style=\"text-align:justify;\">Miens Souvenir는 깔끔한 매장 구성과 다양한 상품, 친절한 서비스로도 잘 알려져 있습니다. 현대적인 포장 덕분에 여행 중에도 편리하게 휴대할 수 있으며 가족과 친구들을 위한 선물로도 좋습니다.</p><p style=\"text-align:justify;\">북술라웨시의 특별한 추억을 간직하고 싶은 여행객들에게 Miens Souvenir는 현지의 맛과 전통문화, 그리고 즐거운 쇼핑 경험을 모두 즐길 수 있는 완벽한 장소입니다.</p>', '<p style=\"text-align:justify;\">Miens Souvenir 是 Manado 著名的纪念品商店之一，也是游客寻找北苏拉威西特色伴手礼的热门购物地点。这里以丰富优质的商品和马纳多人热情友好的服务而闻名，为游客带来舒适愉快的购物体验。</p><p style=\"text-align:justify;\">游客可以在这里找到各种马纳多传统美食，如椰奶蛋糕（Klappertaart）、Roa 辣椒酱、Bagea 饼干、花生糖、Cakalang Fufu 熏鱼以及许多具有北苏拉威西特色的传统小吃，这些食品以浓郁独特的风味而受到欢迎。除了美食之外，店内还出售丰富的纪念品，包括 Bentenan 传统布料、马纳多主题 T 恤、民族风饰品以及充满米纳哈萨文化特色的手工艺品。</p><p style=\"text-align:justify;\">Miens Souvenir 还因店铺整洁、商品种类丰富以及热情周到的服务而深受游客喜爱。现代化包装让伴手礼更方便携带，也非常适合作为送给家人和朋友的礼物。</p><p style=\"text-align:justify;\">对于想把北苏拉威西美好回忆带回家的游客来说，Miens Souvenir 是一个能够同时体验当地美食、传统文化与愉快购物乐趣的理想之地。</p>', 'https://api.welcomemanado.my.id/storage/travel-info/e41brKUGui3YMC0MUw1hocWgAm4YUOuhPErJQ3d9.png', 11, 1, '2026-05-13 07:47:05', '2026-05-13 07:48:33');
